export interface PoemEntry {
  title: string
  author: string
  poem: string
}

export const poemLibrary: PoemEntry[] = [
  { title: '帝京篇十首 一', author: '太宗皇帝', poem: '秦川雄帝宅，函谷壮皇居。\n绮殿千寻起，离宫百雉余。\n连甍遥接汉，飞观迥凌虚。\n云日隐层阙，风烟出绮疎。' },
  { title: '帝京篇十首 二', author: '太宗皇帝', poem: '岩廊罢机务，崇文聊驻辇。\n玉匣启龙图，金绳披凤篆。\n韦编断仍续，缥帙舒还卷。\n对此乃淹留，欹案观坟典。' },
  { title: '帝京篇十首 三', author: '太宗皇帝', poem: '移步出词林，停舆欣武宴。\n雕弓写明月，骏马疑流电。\n惊雁落虚弦，啼猿悲急箭。\n阅赏诚多美，于兹乃忘倦。' },
  { title: '帝京篇十首 四', author: '太宗皇帝', poem: '鸣笳临乐馆，眺听欢芳节。\n急管韵朱弦，清歌凝白雪。\n彩凤肃来仪，玄鹤纷成列。\n去兹郑卫声，雅音方可悦。' },
  { title: '帝京篇十首 五', author: '太宗皇帝', poem: '芳辰追逸趣，禁苑信多奇。\n桥形通汉上，峰势接云危。\n烟霞交隐映，花鸟自参差。\n何如肆辙迹？万里赏瑶池。' },
  { title: '帝京篇十首 六', author: '太宗皇帝', poem: '飞盖去芳园，兰桡游翠渚。\n萍间日彩乱，荷处香风举。\n桂楫满中川，弦歌振长屿。\n岂必汾河曲，方为欢宴所。' },
  { title: '帝京篇十首 七', author: '太宗皇帝', poem: '落日双阙昏，回舆九重暮。\n长烟散初碧，皎月澄轻素。\n搴幌玩琴书，开轩引云雾。\n斜汉耿层阁，清风摇玉树。' },
  { title: '帝京篇十首 八', author: '太宗皇帝', poem: '欢乐难再逢，芳辰良可惜。\n玉酒泛云罍，兰殽陈绮席。\n千钟合尧禹，百兽谐金石。\n得志重寸阴，忘怀轻尺璧。' },
  { title: '帝京篇十首 九', author: '太宗皇帝', poem: '建章欢赏夕，二八尽妖妍。\n罗绮昭阳殿，芬芳玳瑁筵。\n珮移星正动，扇掩月初圆。\n无劳上悬圃，即此对神仙。' },
  { title: '帝京篇十首 十', author: '太宗皇帝', poem: '以兹游观极，悠然独长想。\n披卷览前踪，抚躬寻既往。\n望古茅茨约，瞻今兰殿广。\n人道恶高危，虚心戒盈荡。\n奉天竭诚敬，临民思惠养。\n纳善察忠谏，明科慎刑赏。\n六五诚难继，四三非易仰。\n广待淳化敷，方嗣云亭响。' },
  { title: '饮马长城窟行', author: '太宗皇帝', poem: '塞外悲风切，交河冰已结。\n瀚海百重波，阴山千里雪。\n迥戍危烽火，层峦引高节。\n悠悠卷斾旌，饮马出长城。\n寒沙连骑迹，朔吹断边声。\n胡尘清玉塞，羌笛韵金钲。\n绝漠干戈戢，车徒振原隰。\n都尉反龙堆，将军旋马邑。\n扬麾氛雾静，纪石功名立。\n荒裔一戎衣，灵台凯歌入。' },
  { title: '执契静三边', author: '太宗皇帝', poem: '执契静三边，持衡临万姓。\n玉彩辉关烛，金华流日镜。\n无为宇宙清，有美璇玑正。\n皎佩星连景，飘衣云结庆。\n戢武耀七德，升文辉九功。\n烟波澄旧碧，尘火息前红。\n霜野韬莲劒，关城罢月弓。\n钱缀榆天合，新城柳塞空。\n花销葱岭雪，縠尽流沙雾。\n秋驾转兢怀，春冰弥轸虑。\n书绝龙庭羽，烽休凤穴戍。\n衣宵寝二难，食旰餐三惧。\n翦暴兴先废，除凶存昔亡。\n圆盖归天壤，方舆入地荒。\n孔海池京邑，双河沼帝乡。\n循躬思励己，抚俗媿时康。\n元首伫盐梅，股肱惟辅弼。\n羽贤崆岭四，翼圣襄城七。\n浇俗庶反淳，替文聊就质。\n已知隆至道，共欢区宇一。' },
  { title: '正日临朝', author: '太宗皇帝', poem: '条风开献节，灰律动初阳。\n百蛮奉遐賮，万国朝未央。\n虽无舜禹迹，幸欣天地康。\n车轨同八表，书文混四方。\n赫奕俨冠盖，纷纶盛服章。\n羽旄飞驰道，钟鼓震岩廊。\n组练辉霞色，霜戟耀朝光。\n晨宵怀至理，终媿抚遐荒。' },
  { title: '幸武功庆善宫', author: '太宗皇帝', poem: '寿丘惟旧迹，酆邑乃前基。\n粤予承累圣，悬弧亦在兹。\n弱龄逢运改，提劒郁匡时。\n指麾八荒定，怀柔万国夷。\n梯山咸入款，驾海亦来思。\n单于陪武帐，日逐卫文㮰。\n端扆朝四岳，无为任百司。\n霜节明秋景，轻冰结水湄。\n芸黄徧原隰，禾颖积京畿。\n共乐还乡宴，欢比大风诗。' },
  { title: '重幸武功', author: '太宗皇帝', poem: '代马依朔吹，惊禽愁昔丛。\n况兹承眷德，怀旧感深衷。\n积善忻余庆，畅武悦成功。\n垂衣天下治，端拱车书同。\n白水巡前迹，丹陵幸旧宫。\n列筵欢故老，高宴聚新丰。\n驻跸抚田畯，回舆访牧童。\n瑞气萦丹阙，祥烟散碧空。\n孤屿含霜白，遥山带日红。\n于焉欢击筑，聊以咏南风。' },
  { title: '经破薛举战地', author: '太宗皇帝', poem: '昔年怀壮气，提戈初仗节。\n心随朗日高，志与秋霜洁。\n移锋惊电起，转战长河决。\n营碎落星沈，阵卷横云裂。\n一挥氛沴静，再举鲸鲵灭。\n于兹俯旧原，属目驻华轩。\n沈沙无故迹，减灶有残痕。\n浪霞穿水净，峰雾抱莲昏。\n世途亟流易，人事殊今昔。\n长想眺前踪，抚躬聊自适。' },
  { title: '过旧宅二首 一', author: '太宗皇帝', poem: '新丰停翠辇，谯邑驻鸣笳。\n园荒一径断，苔古半阶斜。\n前池消旧水，昔树发今花。\n一朝辞此地，四海遂为家。' },
  { title: '过旧宅二首 二', author: '太宗皇帝', poem: '金舆巡白水，玉辇驻新丰。\n纽落藤披架，花残菊破丛。\n叶铺荒草蔓，流竭半池空。\n纫珮兰凋径，舒圭叶翦桐。\n昔地一蕃内，今宅九围中。\n架海波澄镜，韬戈器反农。\n八表文同轨，无劳歌大风。' },
  { title: '还陕述怀', author: '太宗皇帝', poem: '慨然抚长劒，济世岂邀名。\n星旗纷电举，日羽肃天行。\n徧野屯万骑，临原驻五营。\n登山麾武节，背水纵神兵。\n在昔戎戈动，今来宇宙平。' },
  { title: '入潼关', author: '太宗皇帝', poem: '崤函称地险，襟带壮两京。\n霜峰直临道，冰河曲绕城。\n古木参差影，寒猿断续声。\n冠盖往来合，风尘朝夕惊。\n高谈先马度，伪晓预鸡鸣。\n弃𦈡怀远志，封泥负壮情。\n别有真人气，安知名不名。' },
  { title: '于北平作', author: '太宗皇帝', poem: '翠野驻戎轩，卢龙转征斾。\n遥山丽如绮，长流萦似带。\n海气百重楼，岩松千丈盖。' },
  { title: '辽城望月', author: '太宗皇帝', poem: '玄兔月初明，澄辉照辽碣。\n映云光暂隐，隔树花如缀。\n魄满桂枝圆，轮亏镜彩缺。\n临城却影散，带晕重围结。\n驻跸俯九都，停观妖氛灭。' },
  { title: '春日登陕州城楼俯眺原野回丹碧缀烟霞密翠斑红芳菲花柳即目川岫聊以命篇', author: '太宗皇帝', poem: '碧原开雾隰，绮岭峻霞城。\n烟峰高下翠，日浪浅深明。\n斑红粧橤树，圆青压溜荆。\n迹岩劳傅想，窥野访莘情。\n巨川何以济，舟楫伫时英。' },
  { title: '春日玄武门宴群臣', author: '太宗皇帝', poem: '韶光开令序，淑气动芳年。\n驻辇华林侧，高宴柏梁前。\n紫庭文珮满，丹墀衮绂连。\n九夷簉瑶席，五狄列琼筵。\n娱宾歌湛露，广乐奏钧天。\n清尊浮绿醑，雅曲韵朱弦。\n粤余君万国，还慙抚八埏。\n庶几保贞固，虚己厉求贤。' },
  { title: '登三台言志', author: '太宗皇帝', poem: '未央初壮汉，阿房昔侈秦。\n在危犹骋丽，居奢遂役人。\n岂如家四海，日宇罄朝伦。\n扇天裁户旧，砌地翦基新。\n引月擎宵桂，飘云逼曙鳞。\n露除光炫玉，霜阙映雕银。\n舞接花梁燕，歌迎鸟路尘。\n镜池波太液，庄苑丽宜春。\n作异甘泉日，停非路寝辰。\n念劳慙逸己，居旷返劳神。\n所欣成大厦，宏材伫渭滨。' },
  { title: '出猎', author: '太宗皇帝', poem: '楚王云梦泽，汉帝长杨宫。\n岂若因农暇，阅武出轘嵩。\n三驱陈锐卒，七萃列材雄。\n寒野霜氛白，平原烧火红。\n雕戈夏服箭，羽骑绿沈弓。\n怖兽潜幽壑，惊禽散翠空。\n长烟晦落景，灌木振严风。\n所为除民瘼，非是悦林丛。' },
  { title: '冬狩', author: '太宗皇帝', poem: '烈烈寒风起，惨惨飞云浮。\n霜浓凝广隰，冰厚结清流。\n金鞍移上苑，玉勒骋平畴。\n旌旗四望合，罝罗一面求。\n楚踣争兕殪，秦亡角鹿愁。\n兽忙投密树，鸿惊起砾洲。\n骑敛原尘静，戈回岭日收。\n心非洛汭逸，意在渭滨游。\n禽荒非所乐，抚辔更招忧。' },
  { title: '春日望海', author: '太宗皇帝', poem: '披襟眺沧海，凭轼玩春芳。\n积流横地纪，疎派引天潢。\n仙气凝三岭，和风扇八荒。\n拂潮云布色，穿浪日舒光。\n照岸花分彩，迷云雁断行。\n怀卑运深广，持满守灵长。\n有形非易测，无源讵可量。\n洪涛经变野，翠岛屡成桑。\n之罘思汉帝，碣石想秦皇。\n霓裳非本意，端拱且图王。' },
  { title: '临洛水', author: '太宗皇帝', poem: '春搜驰骏骨，总辔俯长河。\n霞处流萦锦，风前瀁卷罗。\n水花翻照树，堤兰倒插波。\n岂必汾阴曲，秋云发棹歌。' },
  { title: '望终南山', author: '太宗皇帝', poem: '重峦俯渭水，碧嶂插遥天。\n出红扶岭日，入翠贮岩烟。\n叠松朝若夜，复岫阙疑全。\n对此恬千虑，无劳访九仙。' },
  { title: '元日', author: '太宗皇帝', poem: '高轩暧春色，邃阁媚朝光。\n彤庭飞彩斾，翠幌曜明珰。\n恭己临四极，垂衣驭八荒。\n霜戟列丹陛，丝竹韵长廊。\n穆矣熏风茂，康哉帝道昌。\n继文遵后轨，循古鉴前王。\n草秀故春色，梅艳昔年粧。\n巨川思欲济，终以寄舟航。' },
  { title: '初春登楼即目观作述怀', author: '太宗皇帝', poem: '凭轩俯兰阁，眺瞩散灵襟。\n绮峰含翠雾，照日蕊红林。\n镂丹霞锦岫，残素雪斑岑。\n拂浪堤垂柳，娇花鸟续吟。\n连甍岂一拱，众干如千寻。\n明非独材力，终藉栋梁深。\n弥怀矜乐志，更惧戒盈心。\n媿制劳居逸，方规十产金。' },
  { title: '首春', author: '太宗皇帝', poem: '寒随穷律变，春逐鸟声开。\n初风飘带柳，晚雪间花梅。\n碧林青旧竹，绿沼翠新苔。\n芝田初雁去，绮树巧鸎来。' },
  { title: '初晴落景', author: '太宗皇帝', poem: '晚霞聊自怡，初晴弥可喜。\n日晃百花色，风动千林翠。\n池鱼跃不同，园鸟声还异。\n寄言博通者，知予物外志。' },
  { title: '初夏', author: '太宗皇帝', poem: '一朝春夏改，隔夜鸟花迁。\n阴阳深浅叶，晓夕重轻烟。\n哢鸎犹响殿，横丝正网天。\n珮高兰影接，绶细草纹连。\n碧鳞惊櫂侧，玄燕舞檐前。\n何必汾阳处，始复有山泉。' },
  { title: '度秋', author: '太宗皇帝', poem: '夏律昨留灰，秋箭今移晷。\n峨嵋岫初出，洞庭波渐起。\n桂白发幽岩，菊黄开灞涘。\n运流方可叹，含毫属微理。' },
  { title: '仪鸾殿早秋', author: '太宗皇帝', poem: '寒惊蓟门叶，秋发小山枝。\n松阴背日转，竹影避风移。\n提壶菊花岸，高兴芙蓉池。\n欲知凉气早，巢空燕不窥。' },
  { title: '秋日即目', author: '太宗皇帝', poem: '爽气浮丹阙，秋光澹紫宫。\n衣碎荷疎影，花明菊点丛。\n袍轻低草露，盖侧舞松风。\n散岫飘云叶，迷路飞烟鸿。\n砌冷兰凋佩，闺寒树陨桐。\n别鹤栖琴里，离猿啼峡中。\n落野飞星箭，弦虚半月弓。\n芳菲夕雾起，暮色满房栊。' },
  { title: '山阁晚秋', author: '太宗皇帝', poem: '山亭秋色满，岩牖凉风度。\n疎兰尚染烟，残菊犹承露。\n古石衣新苔，新巢封古树。\n历览情无极，咫尺输光暮。' },
  { title: '秋暮言志', author: '太宗皇帝', poem: '朝光浮烧野，霜华净碧空。\n结浪冰初镜，在迳菊方丛。\n约岭烟深翠，分旗霞散红。\n抽思滋泉侧，飞想傅岩中。' },
  { title: '喜雪', author: '太宗皇帝', poem: '碧昏朝合雾，丹卷暝韬霞。\n结叶繁云色，凝璚徧雪华。\n光楼皎若粉，映幕集疑沙。\n泛柳飞飞絮，粧梅片片花。\n照璧台圆月，飘珠箔穿露。\n瑶洁短长阶，玉藂高下树。\n映桐珪累白，萦峰莲抱素。\n断续气将沈，徘徊岁云暮。\n怀珍媿隐德，表瑞伫丰年。\n橤间飞禁苑，鹤处舞伊川。\n傥咏幽兰曲，同懽黄竹篇。' },
  { title: '秋日𢽾庾信体', author: '太宗皇帝', poem: '岭衔宵月桂，珠穿晓露丛。\n蝉啼觉树冷，萤火不温风。\n花生圆菊橤，荷尽戏鱼通。\n晨浦鸣飞雁，夕渚集栖鸿。\n飒飒高天吹，氛澄下炽空。' },
  { title: '赋尚书', author: '太宗皇帝', poem: '崇文时驻步，东观还停辇。\n辍膳玩三坟，晖灯披五典。\n寒心覩肉林，飞魄看沈湎。\n纵情昏主多，克己明君鲜。\n灭身资累恶，成名由积善。\n既承百王末，战兢随岁转。' },
  { title: '咏司马彪续汉志', author: '太宗皇帝', poem: '二仪初创象，三才乃分位。\n非惟树司牧，固亦垂文字。\n緜代更膺期，芳图无辍记。\n炎汉承君道，英谟纂神器。\n潜龙既可跃，逵兔奚难致。\n前史殚妙词，后昆沈雅思。\n书言扬盛迹，补阙兴洪志。\n川谷犹旧途，郡国开新意。\n梅山未觉朽，谷水谁云异。\n车服随名表，文物因时置。\n凤戟翼康衢，銮舆总柔辔。\n清浊必能澄，洪纤幸无弃。\n观仪不失序，遵礼方由事。\n政宣竹律和，时平玉条备。\n文囿雕奇彩，艺门蕴深致。\n云飞星共流，风扬月兼至。\n类禋遵令典，坛壝资良地。\n五胜竟无违，百司诚有庇。\n粤予承暇景，谈丛引泉秘。\n讨论穷义府，看核披经笥。\n大辨良难仰，小学终先匮。\n闻道谅知荣，含毫孰忘媿。' },
  { title: '咏风', author: '太宗皇帝', poem: '萧条起关塞，摇飏下蓬瀛。\n拂林花乱彩，响谷鸟分声。\n披云罗影散，泛水织文生。\n劳歌大风曲，威加四海清。' },
  { title: '咏雨', author: '太宗皇帝', poem: '罩云飘远岫，喷雨泛长河。\n低飞昏岭腹，斜足洒岩阿。\n泫丛珠缔叶，起溜镜图波。\n蒙柳添丝密，含吹织空罗。' },
  { title: '咏雪', author: '太宗皇帝', poem: '洁野凝晨曜，装墀带夕晖。\n集条分树玉，拂浪影泉玑。\n色洒妆台粉，花飘绮席衣。\n入扇萦离匣，点素皎残机。' },
  { title: '赋得夏首启节', author: '太宗皇帝', poem: '北阙三春晚，南荣九夏初。\n黄莺弄渐变，翠林花落余。\n瀑流还响谷，猿啼自应虚。\n早荷向心卷，长杨就影舒。\n此时欢不极，调轸坐相于。' },
  { title: '赋得白日半西山', author: '太宗皇帝', poem: '红轮不暂驻，乌飞岂复停。\n岑霞渐渐落，溪阴寸寸生。\n藿叶随光转，葵心逐照倾。\n晚烟含树色，栖鸟杂流声。' },
  { title: '置酒坐飞阁', author: '太宗皇帝', poem: '高轩临碧渚，飞檐迥架空。\n余花攒镂槛，残柳散雕栊。\n岸菊初含橤，园梨始带红。\n莫虑昆山暗，还共尽杯中。' },
  { title: '采芙蓉', author: '太宗皇帝', poem: '结伴戏方塘，携手上雕航。\n船移分细浪，风散动浮香。\n游鸎无定曲，惊凫有乱行。\n莲稀钏声断，水广櫂歌长。\n栖乌还密树，泛流归建章。' },
  { title: '赋得樱桃', author: '太宗皇帝', poem: '华林满芳景，洛阳徧阳春。\n朱颜含远日，翠色影长津。\n乔柯啭娇鸟，低枝映美人。\n昔作园中实，今来席上珍。' },
  { title: '赋得李', author: '太宗皇帝', poem: '玉衡流桂圃，成蹊正可寻。\n鸎啼密叶外，蝶戏脆花心。\n丽景光朝彩，轻霞散夕阴。\n暂顾晖章侧，还眺灵山林。' },
  { title: '赋得浮桥', author: '太宗皇帝', poem: '岸曲非千里，桥斜异七星。\n暂低逢辇度，还高值浪惊。\n水摇文鹢动，缆转锦花萦。\n远近随轮影，轻重应人行。' },
  { title: '谒幷州大兴国寺诗', author: '太宗皇帝', poem: '回銮游福地，极目玩芳晨。\n梵钟交二响，法日转双轮。\n宝刹遥承露，天花近足春。\n未佩兰犹小，无丝柳尚新。\n圆光低月殿，碎影乱风筠。\n对此留余想，超然离俗尘。' },
  { title: '咏兴国寺佛殿前幡', author: '太宗皇帝', poem: '拂霞疑电落，腾虚状写虹。\n屈伸烟雾里，低举白云中。\n纷披乍依迥，掣曳或随风。\n念兹轻薄质，无翅强摇空。' },
  { title: '望送魏征葬', author: '太宗皇帝', poem: '阊阖总金鞍，上林移玉辇。\n野郊怆新别，河桥非旧饯。\n惨日映峰沈，愁云随盖转。\n哀笳时断续，悲旌乍舒卷。\n望望情何极，浪浪泪空泫。\n无复昔时人，芳春共谁遣。' },
  { title: '伤辽东战亡', author: '太宗皇帝', poem: '凿门初奉律，仗战始临戎。\n振鳞方跃浪，骋翼正凌风。\n未展六奇术，先亏一篑功。\n防身岂乏智，殉命有余忠。' },
  { title: '月晦', author: '太宗皇帝', poem: '晦魄移中律，凝暄起丽城。\n罩云朝盖上，穿露晓珠呈。\n笑树花分色，啼枝鸟合声。\n披襟欢眺望，极目畅春情。' },
  { title: '秋日翠微宫', author: '太宗皇帝', poem: '秋光凝翠岭，凉吹肃离宫。\n荷疎一盖缺，树冷半帷空。\n侧阵移鸿影，圆花钉菊丛。\n摅怀俗尘外，高眺白云中。' },
  { title: '初秋夜坐', author: '太宗皇帝', poem: '斜廊连绮阁，初月照宵帏。\n塞冷鸿飞疾，园秋蝉噪迟。\n露结林疎叶，寒轻菊吐滋。\n愁心逢此节，长叹独含悲。' },
  { title: '秋日二首 一', author: '太宗皇帝', poem: '菊散金风起，荷疎玉露圆。\n将秋数行雁，离夏几林蝉。\n云凝愁半岭，霞碎缬高天。\n还似成都望，直见峨眉前。' },
  { title: '秋日二首 二', author: '太宗皇帝', poem: '爽气澄兰沼，秋风动桂林。\n露凝千片玉，菊散一丛金。\n日岫高低影，云空点缀阴。\n蓬瀛不可望，泉石且娱心。' },
  { title: '冬宵各为四韵', author: '太宗皇帝', poem: '雕宫静龙漏，绮阁宴公侯。\n珠帘烛燄动，绣柱月光浮。\n云起将歌发，风停与管遒。' },
  { title: '冬日临昆明池', author: '太宗皇帝', poem: '石鲸分玉溜，劫烬隐平沙。\n柳影冰无叶，梅心冻有花。\n寒野凝朝雾，霜天散夕霞。\n欢情犹未极，落景遽西斜。' },
  { title: '望雪', author: '太宗皇帝', poem: '冻云宵徧岭，素雪晓凝华。\n入牖千重碎，迎风一半斜。\n不妆空散粉，无树独飘花。\n萦空慙夕照，破彩谢晨霞。' },
  { title: '守岁', author: '太宗皇帝', poem: '暮景斜芳殿，年华丽绮宫。\n寒辞去冬雪，暖带入春风。\n阶馥舒梅素，盘花卷烛红。\n共欢新故岁，迎送一宵中。' },
  { title: '除夜', author: '太宗皇帝', poem: '岁阴穷暮纪，献节启新芳。\n冬尽今宵促，年开明日长。\n冰消出镜水，梅散入风香。\n对此欢终宴，倾壶待曙光。' },
  { title: '赋得含峰云', author: '太宗皇帝', poem: '翠楼含晓雾，莲峰带晚云。\n玉叶依岩聚，金枝触石分。\n横天结阵影，逐吹起罗文。\n非复阳台下，空将惑楚君。' },
  { title: '三层阁上置音声', author: '太宗皇帝', poem: '绮筵移暮景，紫阁引宵烟。\n隔栋歌尘合，分阶舞影连。\n声流三处管，响乱一重弦。\n不似秦楼上，吹箫空学仙。' },
  { title: '远山澄碧雾', author: '太宗皇帝', poem: '残云收翠岭，夕雾结长空。\n带岫凝全碧，障霞隐半红。\n髣髴分初月，飘飖度晓风。\n还因三里处，冠盖远相通。' },
  { title: '赋得花庭雾', author: '太宗皇帝', poem: '兰气已熏宫，新橤半粧丛。\n色含轻重雾，香引去来风。\n拂树浓舒碧，萦花薄蔽红。\n还当杂行雨，髣髴隐遥空。' },
  { title: '春池柳', author: '太宗皇帝', poem: '年柳变池台，隋堤曲直回。\n逐浪丝阴去，迎风带影来。\n疎黄一鸟弄，半翠几眉开。\n萦雪临春岸，参差间早梅。' },
  { title: '芳兰', author: '太宗皇帝', poem: '春晖开紫苑，淑景媚兰场。\n映庭含浅色，凝露泫浮光。\n日丽参差影，风传轻重香。\n会须君子折，佩里作芬芳。' },
  { title: '咏桃', author: '太宗皇帝', poem: '禁苑春晖丽，花蹊绮树妆。\n缀条深浅色，点露参差光。\n向日分千笑，迎风共一香。\n如何仙岭侧，独秀隐遥芳。' },
  { title: '赋帘', author: '太宗皇帝', poem: '参差垂玉阙，舒卷映兰宫。\n珠光摇素月，竹影乱清风。\n彩散银钩上，文斜桂户中。\n惟当杂罗绮，相与媚房栊。' },
  { title: '咏乌代陈师道', author: '太宗皇帝', poem: '凌晨丽城去，薄暮上林栖。\n辞枝枝暂起，停树树还低。\n向日终难托，迎风讵肯迷。\n只待纤纤手，曲里作宵啼。' },
  { title: '咏饮马', author: '太宗皇帝', poem: '骏骨饮长泾，奔流洒络缨。\n细纹连喷聚，乱荇绕蹄萦。\n水光鞍上侧，马影溜中横。\n翻似天池里，腾波龙种生。' },
  { title: '赋得残菊', author: '太宗皇帝', poem: '阶兰凝曙霜，岸菊照晨光。\n露浓晞晚笑，风劲浅残香。\n细叶凋轻翠，圆花飞碎黄。\n还持今岁色，复结后年芳。' },
  { title: '赋秋日悬清光赐房玄龄', author: '太宗皇帝', poem: '秋露凝高掌，朝光上翠微。\n参差丽双阙，照耀满重闱。\n仙驭随轮转，灵乌带影飞。\n临波无定彩，入隙有圆晖。\n还当葵藿志，倾叶自相依。' },
  { title: '琵琶', author: '太宗皇帝', poem: '半月无双影，全花有四时。\n摧藏千里态，掩抑几重悲。\n促节萦红袖，清音满翠帷。\n驶弹风响急，缓曲钏声迟。\n空余关陇恨，因此代相思。' },
  { title: '宴中山', author: '太宗皇帝', poem: '驱马出辽阳，万里转旗常。\n对敌六奇举，临戎八阵张。\n斩鲸澄碧海，卷雾扫扶桑。\n昔去兰萦翠，今来桂染芳。\n云芝浮碎叶，冰镜上朝光。\n回首长安道，方欢宴柏梁。' },
  { title: '饯中书侍郎来济', author: '太宗皇帝', poem: '暧暧去尘昏灞岸，飞飞轻盖指河梁。\n云峰衣结千重叶，雪岫花开几树妆。\n深悲黄鹤孤舟远，独叹青山别路长。\n聊将分袂沾巾泪，还用持添离席觞。' },
  { title: '于太原召侍臣赐宴守岁', author: '太宗皇帝', poem: '四时运灰琯，一夕变冬春。\n送寒余雪尽，迎岁早梅新。' },
  { title: '咏烛二首 一', author: '太宗皇帝', poem: '燄听风来动，花开不待春。\n镇下千行泪，非是为思人。' },
  { title: '咏烛二首 二', author: '太宗皇帝', poem: '九龙蟠燄动，四照逐花生。\n即此流高殿，堪持待月明。' },
  { title: '咏弓', author: '太宗皇帝', poem: '上弦明月半，激箭流星远。\n落雁带书惊，啼猿映枝转。' },
  { title: '赋得早雁出云鸣', author: '太宗皇帝', poem: '初秋玉露清，早雁出空鸣。\n隔云时乱影，因风乍含声。' },
  { title: '赋得临池柳', author: '太宗皇帝', poem: '岸曲丝阴聚，波移带影疎。\n还将眉里翠，来就镜中舒。' },
  { title: '赋得临池竹', author: '太宗皇帝', poem: '贞条障曲砌，翠叶贯寒霜。\n拂牖分龙影，临池待凤翔。' },
  { title: '赋得弱柳鸣秋蝉', author: '太宗皇帝', poem: '散影玉阶柳，含翠隐鸣蝉。\n微形藏叶里，乱响出风前。' },
  { title: '探得李', author: '太宗皇帝', poem: '盘根直盈渚，交干横倚天。\n舒华光四海，卷叶荫三川。' },
  { title: '咏小山', author: '太宗皇帝', poem: '近谷交萦橤，遥峰对出莲。\n径细无全磴，松小未含烟。' },
  { title: '赐萧瑀', author: '太宗皇帝', poem: '疾风知劲草，板荡识诚臣。\n勇夫安识义，智者必怀仁。' },
  { title: '赐房玄龄', author: '太宗皇帝', poem: '太液仙舟迥，西园隐上才。\n未晓征车度，鸡鸣关早开。' },
  { title: '辽东山夜临秋', author: '太宗皇帝', poem: '烟生遥岸隐，月落半崖阴。\n连山惊鸟乱，隔岫断猿吟。' },
  { title: '赐魏征诗', author: '太宗皇帝', poem: '醽醁胜兰生，翠涛过玉䪥。\n千日醉不醒，十年味不败。' },
  { title: '两仪殿赋柏梁体', author: '太宗皇帝', poem: '绝域降附天下平，八表无事悦圣情。\n云披雾敛天地明，登封日观禅云亭。\n太常具礼方告成。' },
  { title: '句', author: '太宗皇帝', poem: '雪耻酬百王，除凶报千古。\n昔乘匹马去，今驱万乘来。\n近日毛虽暖闻弦心已惊。' },
  { title: '太子纳妃太平公主出降', author: '高宗皇帝', poem: '龙楼光曙景，鲁馆启朝扉。\n艳日浓妆影，低星降婺辉。\n玉庭浮瑞色，银牓藻祥徽。\n云转花萦盖，霞飘叶缀旗。\n雕轩回翠陌，宝驾归丹殿。\n鸣珠佩晓衣，镂璧轮开扇。\n华冠列绮筵，兰醑申芳宴。\n环阶凤乐陈，玳席珍羞荐。\n蝶舞袖香新，歌分落素尘。\n欢凝欢懿戚，庆叶庆初姻。\n暑阑炎气息，凉早吹疎频。\n方期六合泰，共赏万年春。' },
  { title: '七夕宴悬圃二首 一', author: '高宗皇帝', poem: '羽盖飞天汉，凤驾越层峦。\n俱叹三秋阻，共敍一宵欢。\n璜亏夜月落，靥碎晓星残。\n谁能重操杼，纤手濯清澜。' },
  { title: '七夕宴悬圃二首 二', author: '高宗皇帝', poem: '霓裳转云路，凤驾俨天潢。\n亏星凋夜靥，残月落朝璜。\n促欢今夕促，长离别后长。\n轻梭聊驻织，掩泪独悲伤。' },
  { title: '过温汤', author: '高宗皇帝', poem: '温渚停仙跸，丰郊驻晓旌。\n路曲回输影，岩虚传漏声。\n暖溜惊湍驶，寒空碧雾轻。\n林黄疎叶下，野白曙霜明。\n眺听良无已，烟霞断续生。' },
  { title: '九月九日', author: '高宗皇帝', poem: '端居临玉扆，初律启金商。\n凤阙澄秋色，龙闱引夕凉。\n野净山气敛，林疎风露长。\n砌兰亏半影，岩桂发全香。\n满盖荷凋翠，圆花菊散黄。\n挥鞭争电烈，飞羽乱星光。\n柳空穿石碎，弦虚侧月张。\n怯猿啼落岫，惊雁断分行。\n斜轮低夕景，归斾拥通庄。' },
  { title: '谒慈恩寺题奘法师房', author: '高宗皇帝', poem: '停轩观福殿，游目眺皇畿。\n法轮含日转，花盖接云飞。\n翠烟香绮阁，丹霞光宝衣。\n幡虹遥合彩，定水迥分晖。\n萧然登十地，自得会三归。' },
  { title: '谒大慈恩寺', author: '高宗皇帝', poem: '日宫开万仞，月殿耸千寻。\n花盖飞团影，幡虹曳曲阴。\n绮霞遥笼帐，丛珠细网林。\n寥廓烟云表，超然物外心。' },
  { title: '守岁', author: '高宗皇帝', poem: '今宵冬律尽，来朝丽景新。\n花余凝地雪，条含煖吹分。\n绶吐芽犹嫩，冰□已镂津。\n薄红梅色冷，浅绿柳轻春。\n送迎交两节，暄寒变一辰。' },
  { title: '九月九日幸临渭亭登高得秋字', author: '中宗皇帝', poem: '九月正乘秋，三杯兴已周。\n泛桂迎尊满，吹花向酒浮。\n长房萸早熟，彭泽菊初收。' },
  { title: '登骊山高顶寓目', author: '中宗皇帝', poem: '四郊秦汉国，八水帝王都。\n阊阖雄里闬，城阙壮规模。\n贯渭称天邑，含岐实奥区。\n金门披玉馆，因此识皇图。' },
  { title: '幸秦始皇陵', author: '中宗皇帝', poem: '眷言君失德，骊邑想秦余。\n政烦方改篆，愚俗乃焚书。\n阿房久已灭，阁道遂成墟。\n欲厌东南气，翻伤掩鲍车。' },
  { title: '立春日游苑迎春', author: '中宗皇帝', poem: '神皐福地三秦邑，玉台金阙九仙家。\n寒光犹恋甘泉树，淑景偏临建始花。\n彩蝶黄鸎未歌舞，梅香柳色已矜夸。\n迎春正启流霞席，暂嘱曦轮勿遽斜。' },
  { title: '十月诞辰内殿宴群臣效柏梁体联句', author: '中宗皇帝', poem: '润色鸿业寄贤才，叨居右弼媿盐梅。\n运筹帷幄荷时来，职掌图籍滥蓬莱。\n两司谬忝谢钟裴，礼乐铨管效涓埃。\n陈师振旅清九垓，欣承顾问侍天杯。\n衔恩献寿梁柏台，黄缣青简奉康哉。\n鲰生侍从忝王枚，右掖司言实不才。\n宗伯秩礼天地开，帝歌难续仰昭回。\n微臣捧日变寒灰，远慙班左媿游陪。' },
  { title: '景龙四年正月五日移仗蓬莱宫御大明殿会吐蕃骑马之戏因重为柏梁体联句', author: '中宗皇帝', poem: '大明御宇临万方，顾慙内政翊陶唐。\n鸾鸣凤舞向平阳，秦楼鲁馆沐恩光。\n无心为子辄求郎，雄才七步谢陈王。\n当熊让辇媿前芳，再司铨筦恩可忘。\n文江学海思济航，万邦考绩臣所详。\n著作不休出中肠，权豪屏迹肃严霜。\n铸鼎开岳造明堂，玉醴由来献寿觞。' },
  { title: '石淙', author: '中宗皇帝', poem: '三阳本是标灵纪，二室由来独擅名。\n霞衣霞锦千般状，云峰云岫百重生。\n水炫珠光遇泉客，岩悬石镜厌山精。\n永愿乾坤符睿算，长居膝下属欢情。' },
  { title: '石淙', author: '睿宗皇帝', poem: '奇峰嶾嶙箕山北，秀崿岹峣嵩镇南。\n地首地肺何曾拟，天目天台倍觉慙。\n树影蒙茏鄣叠岫，波深汹涌落悬潭。\n□愿紫宸居得一，永欣丹扆御通三。' },
  { title: '过晋阳宫', author: '明皇帝', poem: '缅想封唐处，实惟建国初。\n俯察伊晋野，仰观乃参虚。\n井邑龙斯跃，城池凤翔余。\n林塘犹沛泽，台榭宛旧居。\n运革祚中否，时迁命兹符。\n顾循承丕构，怵惕多忧虞。\n尚恐威不逮，复虑化未孚。\n岂徒劳辙迹，所期训戎车。\n习俗问黎人，亲巡慰里闾。\n永言念成功，颂德临康衢。\n长怀经纶日，叹息履庭隅。\n艰难安可忘，欲去良踟蹰。' },
  { title: '行次成皋途经先圣擒建德之所缅思功业感而赋诗', author: '明皇帝', poem: '有隋政昏虐，群雄已交争。\n先圣按劒起，叱咤风云生。\n饮马河洛竭，作气嵩华惊。\n克敌睿图就，擒俘帝道亨。\n顾慙嗣宝历，恭承天下平。\n幸过翦鲸地，感慕神且英。' },
  { title: '校猎义成喜逢大雪率题九韵以示群官', author: '明皇帝', poem: '弧矢威天下，旌旗游近县。\n一面施鸟罗，三驱教人战。\n暮云成积雪，晓色开行殿。\n皓然原隰同，不觉林野变。\n北风勇士马，东日华组练。\n触地银麞出，连山缟鹿见。\n月兔落高矰，星狼下急箭。\n既欣盈尺兆，复忆磻谿便。\n岁丰将遇贤，俱荷皇天眷。' },
  { title: '赐诸州刺史以题座右', author: '明皇帝', poem: '眷言思共理，鉴梦想维良。\n猗欤此推择，声绩着周行。\n贤能既俟进，黎献实伫康。\n视人当如子，爱人亦如伤。\n讲学试诵论，阡陌劝耕桑。\n虚誉不可饰，清知不可忘。\n求名迹易见，安贞德自彰。\n讼狱必以情，教民贵有常。\n恤惸且存老，抚弱复绥强。\n勉哉各祗命，知予眷万方。' },
  { title: '送忠州太守康昭远等', author: '明皇帝', poem: '端拱临中枢，缅怀共予理。\n不有台阁英，孰振循良美。\n分符侯甸内，拜手明庭里。\n誓节期饮冰，调人方导水。\n嘉声驰九牧，惠化光千祀。\n时雨侔昔贤，芳猷贯前史。\n伫尔颂中和，吾将令卿士。' },
  { title: '送李邕之任滑台', author: '明皇帝', poem: '汉家重东郡，宛彼白马津。\n黎庶既蕃殖，临之劳近臣。\n远别初首路，今行方及春。\n课成应第一，良牧尔当仁。' },
  { title: '端午三殿宴群臣探得神字', author: '明皇帝', poem: '五月符天数，五音调夏钧。\n旧来传五日，无事不称神。\n穴枕通灵气，长丝续命人。\n四时花竞巧，九子粽争新。\n方殿临华节，圆宫宴雅臣。\n进对一言重，遒文六义陈。\n股肱良足咏，风化可还淳。' },
  { title: '温汤对雪', author: '明皇帝', poem: '北风吹同云，同云飞白雪。\n白雪乍回散，同云何惨烈。\n未见温泉冰，宁知火井灭。\n表瑞良在兹，庶几可怡悦。' },
  { title: '登蒲州逍遥楼', author: '明皇帝', poem: '长榆息烽火，高柳静风尘。\n卜征巡九洛，展豫出三秦。\n昔是潜龙地，今为上理辰。\n时平乘道泰，聊赏遇年春。\n黄河分地络，飞观接天津。\n一览遗芳翰，千载肃如神。' },
  { title: '经河上公庙', author: '明皇帝', poem: '昔闻有耆叟，河上独遗荣。\n迹与尘嚻隔，心将道德幷。\n讵以天地累，宁为宠辱惊。\n矫然翔寥廓，如何屈坚贞。\n玄玄妙门启，肃肃祠宇清。\n冥漠无先后，那能纪姓名。' },
  { title: '过王濬暮', author: '明皇帝', poem: '吴国分牛斗，晋室命龙骧。\n受任敌已灭，策勋名不彰。\n居美未尽善，矜功徒自伤。\n长戟今何在？孤坟此路傍。\n不观松柏茂，空余荆棘场。\n叹嗟悬劒陇，谁识梦刀祥。' },
  { title: '初入秦川路逢寒食', author: '明皇帝', poem: '洛阳芳树映天津，灞岸垂杨窣地新。\n直为经过行处乐，不知虚度两京春。\n去年余闰今春早，曙色和风着花草。\n可怜寒食与清明，光辉幷在长安道。\n自从关路入秦川，争道何人不戏鞭。\n公子途中妨蹴踘，佳人马上废秋千。\n渭水长桥今欲渡，葱葱渐见新丰树。\n远看骊岫入云霄，预想汤池起烟雾。\n烟雾氛氲水殿开，暂拂香轮归去来。\n今岁清明行已晚，明年寒食更相陪。' },
  { title: '春台望', author: '明皇帝', poem: '暇景属三春，高台聊四望。\n目极千里际，山川一何壮。\n太华见重岩，终南分叠嶂。\n郊原纷绮错，参差多异状。\n佳气满通沟，迟步入绮楼。\n初鸎一一鸣红树，归雁双双去绿洲。\n太液池中下黄鹤，昆明水上映牵牛。\n闻道汉家全盛日，别馆离宫趣非一。\n甘泉逶迤亘明光，五柞连延接未央。\n周庐徼道纵横转，飞阁回轩左右长。\n须念作劳居者逸，勿言我后焉能恤。\n为想雄豪壮柏梁，何如俭陋卑茅室。\n阳乌黯黯向山沈，夕鸟喧喧入上林。\n薄暮赏余回步辇，还念中人罢百金。' },
  { title: '过大哥宅探得歌字韵', author: '明皇帝', poem: '鲁卫情先重，亲贤爱转多。\n冕旒丰暇日，乘景暂经过。\n戚里申高宴，平台奏雅歌。\n复寻为善乐，方验保山河。' },
  { title: '同玉真公主过大哥山池', author: '明皇帝', poem: '地有招贤处，人传乐善名。\n鹜池临九达，龙岫对层城。\n桂月先秋冷，苹风向晚清。\n凤楼遥可见，仿佛玉箫声。' },
  { title: '经邹鲁祭孔子而叹之', author: '明皇帝', poem: '夫子何为者？栖栖一代中。\n地犹鄹氏邑，宅即鲁王宫。\n叹凤嗟身否，伤麟怨道穷。\n今看两楹奠，当与梦时同。' },
  { title: '惟此温泉是称愈疾岂予独受其福思与兆人共之乘暇巡游乃言其志', author: '明皇帝', poem: '桂殿与山连，兰汤涌自然。\n阴崖含秀色，温谷吐潺湲。\n绩为蠲邪着，功因养正宣。\n愿言将亿兆，同此共昌延。' },
  { title: '旋师喜捷', author: '明皇帝', poem: '边服胡尘起，长安汉将飞。\n龙蛇开阵法，貔虎振军威。\n诈虏脑涂地，征夫血染衣。\n今朝书奏入，明日凯歌归。' },
  { title: '过老子庙', author: '明皇帝', poem: '仙居怀圣德，灵庙肃神心。\n草合人踪断，尘浓鸟迹深。\n流沙丹灶没，关路紫烟沈。\n独伤千载后，空余松柏林。' },
  { title: '途次陕州', author: '明皇帝', poem: '境出三秦外，途分二陕中。\n山川入虞虢，风俗限西东。\n树古棠阴在，耕余让畔空。\n鸣笳从此去，行见洛阳宫。' },
  { title: '野次喜雪', author: '明皇帝', poem: '拂曙辟行宫，寒皋野望通。\n繁云低远岫，飞雪舞长空。\n赋象恒依物，萦回屡逐风。\n为知勤恤意，先此示年丰。' },
  { title: '送贺知章归四明', author: '明皇帝', poem: '遗荣期入道，辞老竟抽簪。\n岂不惜贤达，其如高尚心。\n寰中得秘要，方外散幽襟。\n独有青门饯，群僚怅别深。' },
  { title: '轩游宫十五夜', author: '明皇帝', poem: '行迈离秦国，巡方赴洛师。\n路逢三五夜，春色暗中期。\n关外长河转，宫中淑气迟。\n歌钟对明月，不减旧游时。' },
  { title: '观拔河俗戏', author: '明皇帝', poem: '壮徒恒贾勇，拔拒抵长河。\n欲练英雄志，须明胜负多。\n噪齐山岌嶪，气作水腾波。\n预期年岁稔，先此乐时和。' },
  { title: '同刘晃喜雨', author: '明皇帝', poem: '节变寒初尽，时和气已春。\n繁云先合寸，膏雨自依旬。\n飒飒飞平野，霏霏静暗尘。\n悬知花叶意，朝夕望中新。' },
  { title: '千秋节赐群臣镜', author: '明皇帝', poem: '铸得千秋镜，光生百炼金。\n分将赐群后，遇象见清心。\n台上冰华澈，窗中月影临。\n更衔长绶带，留意感人深。' },
  { title: '赐道士邓紫阳', author: '明皇帝', poem: '太乙三门诀，元君六甲符。\n下传金版术，上刻玉清书。\n有美探真士，囊中得秘书。\n自知三醮后，翊我灭残胡。' },
  { title: '幸蜀西至劒门', author: '明皇帝', poem: '劒阁横云峻，銮舆出狩回。\n翠屏千仞合，丹嶂五丁开。\n灌木萦旗转，仙云拂马来。\n乘时方在德，嗟尔勒铭才。' },
  { title: '答司马承祯上劒镜', author: '明皇帝', poem: '宝照含天地，神劒合阴阳。\n日月丽光景，星斗裁文章。\n写鉴表容质，佩服为身防。\n从兹一赏玩，永德保龄长。' },
  { title: '送赵法师还蜀因名山奠简', author: '明皇帝', poem: '道家奠灵简，自昔仰神仙。\n真子今将命，苍生福可传。\n江山寻故国，城郭信依然。\n二室遥相望，云回洞里天。' },
  { title: '送道士薛季昌还山', author: '明皇帝', poem: '洞府修真客，衡阳念旧居。\n将成金阙要，愿奉玉清书。\n云路三天近，松溪万籁虚。\n犹期传秘诀，来往候仙舆。' },
  { title: '送玄同真人李抱朴谒灊山仙祠', author: '明皇帝', poem: '城阙天中近，蓬瀛海上遥。\n归期千载鹤，春至一来朝。\n采药逢三秀，餐霞卧九霄。\n参同如有旨，金鼎待君烧。' },
  { title: '春日出苑游瞩', author: '明皇帝', poem: '三阳丽景早芳辰，四序佳园物候新。\n梅花百树障去路，垂柳千条暗回津。\n鸟飞直为惊风叶，鱼没都由怯岸人。\n惟愿圣主南山寿，何愁不赏万年春。' },
  { title: '春晚宴两相及礼官丽正殿学士探得风字', author: '明皇帝', poem: '乾道运无穷，恒将人代工。\n阴阳调历象，礼乐报玄穹。\n介胄清荒外，衣冠佐域中。\n言谈延国辅，词赋引文雄。\n野霁伊川绿，郊明巩树红。\n冕旒多暇景，诗酒会春风。' },
  { title: '首夏花萼楼观群臣宴宁王山亭回楼下又申之以赏乐赋诗', author: '明皇帝', poem: '今年通闰月，入夏展春辉。\n楼下风光晚，城隅宴赏归。\n九歌扬政要，六舞散朝衣。\n天喜时相合，人和事不违。\n礼中推意厚，乐处感心微。\n别赏阳台乐，前旬暮雨飞。' },
  { title: '同二相已下群官乐游园宴', author: '明皇帝', poem: '撰日岩廊暇，需云宴乐初。\n万方朝玉帛，千品会簪裾。\n地入南山近，城分北斗余。\n池塘垂柳密，原隰野花疎。\n帟幕看逾暗，歌钟听自虚。\n兴阑归骑转，还奏弼违书。' },
  { title: '集贤书院成送张说上集贤学士赐宴得珍字', author: '明皇帝', poem: '广学开书院，崇儒引席珍。\n集贤招衮职，论道命台臣。\n礼乐沿今古，文章革旧新。\n献酬尊俎列，宾主位班陈。\n节变云初夏，时移气尚春。\n所希光史册，千载仰兹晨。' },
  { title: '王屋山送道士司马承祯还天台', author: '明皇帝', poem: '紫府求贤士，清谿祖逸人。\n江湖与城阙，异迹且殊伦。\n间有幽栖者，居然厌俗尘。\n林泉先得性，芝桂欲调神。\n地道逾稽岭，天台接海滨。\n音徽从此间，万古一芳春。' },
  { title: '早度蒲津关', author: '明皇帝', poem: '钟鼓严更曙，山河野望通。\n鸣銮下蒲坂，飞斾入秦中。\n地险关逾壮，天平镇尚雄。\n春来津树合，月落戍楼空。\n马色分朝景，鸡声逐晓风。\n所希常道泰，非复候𦈡同。' },
  { title: '途经华岳', author: '明皇帝', poem: '饬驾去京邑，鸣鸾指洛川。\n循途经太华，回跸暂周旋。\n翠崿留斜影，悬岩冒夕烟。\n四方皆石壁，五位配金天。\n仿佛看高掌，依稀听子先。\n终当铭岁月，从此记灵仙。' },
  { title: '喜雪', author: '明皇帝', poem: '日观卜先征，时巡顺物情。\n风行未备礼，云密遽飘霙。\n委树寒花发，萦空落絮轻。\n朝如玉已会，庭似月犹明。\n既覩肤先合，还欣尺有盈。\n登封何以报？因此谢功成。' },
  { title: '幸凤泉汤', author: '明皇帝', poem: '西狩观周俗，南山历汉宫。\n荐鲜知路近，省敛觉年丰。\n阴谷含神爨，汤泉养圣功。\n益龄仙井合，愈疾醴源通。\n不重鸣岐凤，谁矜陈宝雄。\n愿将无限泽，沾沐众心同。' },
  { title: '南出雀鼠谷答张说', author: '明皇帝', poem: '雷出应乾象，风行顺国人。\n川途犹在晋，车马渐归秦。\n背陕关山险，横汾鼓吹频。\n草依阳谷变，花待北岩春。\n闻有鹓鸾客，清词雅调新。\n求音思欲报，心迹竟难陈。' },
  { title: '赐崔日知往潞州', author: '明皇帝', poem: '潞国开新府，壶关宠旧林。\n妙旌循吏德，持悦庶氓心。\n礼乐中朝贵，神明列郡钦。\n扬风非赠扇，易俗是张琴。\n藩镇讴谣满，行宫雨露深。\n会书丞相策，先赐颍川金。' },
  { title: '为赵法师别造精院过院赋诗', author: '明皇帝', poem: '宗师心物外，为道运虚舟。\n不恋岩泉赏，来从宫禁游。\n探玄知几岁，习静更宜秋。\n烟树辨朝色，风湍闻夜流。\n坐朝繁听览，寻胜在清幽。\n欲广无为化，因兹庶可求。' },
  { title: '端午', author: '明皇帝', poem: '端午临中夏，时清日复长。\n盐梅已佐鼎，曲糵且传觞。\n事古人留迹，年深缕积长。\n当轩知槿茂，向水觉芦香。\n亿兆同归寿，群公共保昌。\n忠贞如不替，贻厥后昆芳。' },
  { title: '春中兴庆宫酺宴', author: '明皇帝', poem: '九达长安道，三阳别馆春。\n还将听朝暇，回作豫游晨。\n不战要荒服，无刑礼乐新。\n合酺覃土宇，欢宴接群臣。\n玉斝飞千日，琼筵荐八珍。\n舞衣云曳影，歌扇月开轮。\n伐鼓鱼龙杂，撞钟角觝陈。\n曲终酣兴晚，须有醉归人。' },
  { title: '千秋节宴', author: '明皇帝', poem: '兰殿千秋节，称名万寿觞。\n风传率土庆，日表继天祥。\n玉宇开花蕚，宫县动会昌。\n衣冠白鹭下，帟幕翠云长。\n献遗成新俗，朝仪入旧章。\n月衔花绶镜，露缀彩丝囊。\n处处祠田祖，年年宴杖乡。\n深思一德事，小获万人康。' },
  { title: '左丞相说右丞相璟太子少傅乾曜同日上官命宴东堂赐诗', author: '明皇帝', poem: '赤帝收三杰，黄轩举二臣。\n由来丞相重，分掌国之钧。\n我有握中璧，双飞席上珍。\n子房推道要，仲子讶风神。\n复辍台衡老，将为调护人。\n鹓鸾同拜日，车骑拥行尘。\n乐聚南宫宴，觞连北斗醇。\n俾予成百揆，垂拱问彝伦。' },
  { title: '早登太行山中言志', author: '明皇帝', poem: '清跸度河阳，凝笳上太行。\n火龙明鸟道，铁骑绕羊肠。\n白雾埋阴壑，丹霞助晓光。\n涧泉含宿冻，山木带余霜。\n野老茅为屋，樵人薜作裳。\n宣风问耆艾，敦俗劝耕桑。\n凉德慙先哲，徽猷慕昔皇。' },
  { title: '平胡', author: '明皇帝', poem: '杂虏忽猖狂，无何敢乱常。\n羽书朝继入，烽火夜相望。\n将出凶门勇，兵因死地强。\n蒙轮皆突骑，按劒尽鹰扬。\n鼓角雄山野，龙蛇入战场。\n流膏润沙漠，溅血染锋铓。\n雾扫清玄塞，云开静朔方。\n武功今已立，文德愧前王。' },
  { title: '游兴庆宫作', author: '明皇帝', poem: '代邸青门右，离宫紫陌陲。\n庭如过沛日，水若渡江时。\n绮观连鸡岫，朱楼接雁池。\n从来敦棣蕚，今此茂荆枝。\n万叶传余庆，千年志不移。\n凭轩聊属目，轻辇共追随。\n务本方崇训，相辉保羽仪。\n时康俗易渐，德薄政难施。\n鼓吹迎飞盖，弦歌送羽巵。\n所希覃率土，孝弟一同规。' },
  { title: '送张说巡边', author: '明皇帝', poem: '端拱复垂裳，长怀御远方。\n股肱申教义，戈劒靖要荒。\n命将绥边服，雄图出庙堂。\n三台入武帐，八座起文昌。\n宝胄匡韩主，华宗辅汉王。\n茂先慙博物，平子谢文章。\n尽节恢时佐，输诚御寇场。\n三军临朔野，驷马即戎行。\n鼓吹威夷狄，旌轩溢洛阳。\n云台先着美，今日更贻芳。' },
  { title: '饯王晙巡边', author: '明皇帝', poem: '振武威荒服，扬文肃远墟。\n金坛申将礼，玉节授军符。\n免胄三方外，衔刀万里余。\n昔时吴会静，今日虏庭虚。\n分阃仍推毂，援桴且训车。\n风扬旌斾远，雨洗甲兵初。\n坐见台阶谧，行闻祅祲除。\n檄来虽插羽，箭去亦飞书。\n舟檝功须着，盐梅望匪疎。\n不应陈七德，欲使化先敷。' },
  { title: '巡省途次上党旧宫赋', author: '明皇帝', poem: '三千初击浪，九万欲抟空。\n天地犹惊否，阴阳始遇蒙。\n存贞期历试，佐贰伫昭融。\n多谢时康理，良慙实赖功。\n长怀问鼎气，夙负拔山雄。\n不学刘琨舞，先歌汉祖风。\n英髦既包括，豪杰自牢笼。\n人事一朝异，讴歌四海同。\n如何昔朱邸，今此作离宫？\n雁沼澄澜翠，猿岩落照红。\n小山秋桂馥，长坂旧兰丛。\n即是淹留处，乘欢乐未穷。' },
  { title: '潼关口号', author: '明皇帝', poem: '河曲回千里，关门限二京。\n所嗟非恃德，设险到天平。' },
  { title: '续薛令之题壁', author: '明皇帝', poem: '啄木觜距长，凤皇羽毛短。\n苦嫌松桂寒，任逐桑榆煖。' },
  { title: '送胡真师还西山', author: '明皇帝', poem: '仙客厌人间，孤云比性闲。\n话离情未已，烟水万重山。' },
  { title: '过大哥山池题石壁', author: '明皇帝', poem: '澄潭皎镜石崔巍，万壑千岩暗绿苔。\n林亭自有幽贞趣，况复秋深爽气来。' },
  { title: '题梅妃画真', author: '明皇帝', poem: '忆昔娇妃在紫宸，铅华不御得天真。\n霜绡虽似当时态，争奈娇波不顾人。' },
  { title: '鹡鸰颂', author: '明皇帝', poem: '伊我轩宫，奇树青葱。\n蔼周庐兮，冒霜停雪，以茂以悦。\n恣卷舒兮，连枝同荣，吐绿含英。\n曜春初兮，蓐收御节，寒露微结。\n气清虚兮，桂宫兰殿，唯所息宴。\n栖雍渠兮，行摇飞鸣，急难有情。\n情有余兮，顾惟德凉，夙夜兢惶。\n慙化疎兮，上之所教，下之所效。\n实在予兮，天伦之性，鲁卫分政。\n亲贤居兮，爰游爰处，爰笑爰语。\n巡庭除兮，观此翔禽，以悦我心，良史书兮。' },
  { title: '傀儡吟', author: '明皇帝', poem: '刻木牵丝作老翁，鸡皮鹤发与真同。\n须臾弄罢寂无事，还似人生一梦中。' },
  { title: '句', author: '明皇帝', poem: '昔见漳滨卧，言将人事违。\n今逢庆诞日，犹谓学仙归。\n棠棣花重发，鸰原鸟再飞。\n德比代云布，心如晋水清。' },
  { title: '延英殿玉灵芝诗三章章八句 一', author: '肃宗皇帝', poem: '玉殿肃肃，灵芝煌煌。\n重英发秀，连叶分房。\n宗庙之福，垂其耿光。' },
  { title: '延英殿玉灵芝诗三章章八句 二', author: '肃宗皇帝', poem: '元气产芝，明神合德。\n紫微间采，白蕣呈色。\n载启瑞图，庶符皇极。\n天心有眷，王道惟直。' },
  { title: '延英殿玉灵芝诗三章章八句 三', author: '肃宗皇帝', poem: '幸生芳本，当我扆旒。\n效此灵质，贲其王猷。\n神惟不爱，道亦无求。\n端拱思惟，永荷天休。' },
  { title: '赐棃李泌与诸王联句', author: '肃宗皇帝', poem: '先生年几许，颜色似童儿。\n夜抱九仙骨，朝披一品衣。\n不食千锺粟，唯餐两颗棃。\n天生此间气，助我化无为。' },
  { title: '中和节日宴百僚赐诗', author: '德宗皇帝', poem: '韶年启仲序，初吉谐良辰。\n肇兹中和节，式庆天地春。\n欢酣朝野同，生德区宇均。\n云开洒膏露，草疏芳河津。\n岁华今载阳，东作方肆勤。\n慙非熏风唱，曷用慰吾人。' },
  { title: '中和节赐百官燕集因示所怀', author: '德宗皇帝', poem: '至化恒在宥，保和兹息人。\n推诚抚诸夏，与物长为春。\n仲月风景暖，禁城花柳新。\n芳时协金奏，赐宴同群臣。\n丝竹岂云乐，忠贤惟所亲。\n庶洽朝野意，旷然天地均。' },
  { title: '重阳日赐宴曲江亭赋六韵诗用清字', author: '德宗皇帝', poem: '早衣对庭燎，躬化勤意诚。\n时此万机暇，适与佳节幷。\n曲池洁寒流，芳菊舒金英。\n乾坤爽气满，台殿秋光清。\n朝野庆年丰，高会多欢声。\n永怀无荒戒，良士同斯情。' },
  { title: '九月十八赐百僚追赏因书所怀', author: '德宗皇帝', poem: '雨霁霜气肃，天高云日明。\n繁林已坠叶，寒菊仍舒荣。\n懿此秋节时，更延追赏情。\n池台列广宴，丝竹传新声。\n至乐非外奖，浃欢同中诚。\n庶敦朝野意，永使风化清。' },
  { title: '送徐州张建封还镇', author: '德宗皇帝', poem: '牧守寄所重，才贤生为时。\n宣风自淮甸，授钺膺藩维。\n入觐展遐恋，临轩慰来思。\n忠诚在方寸，感激陈情词。\n报国尔所向，恤人予是资。\n欢宴不尽怀，车马当还期。\n谷雨将应候，行春犹未迟。\n勿以千里遥，而云无己知。' },
  { title: '麟德殿宴百僚', author: '德宗皇帝', poem: '忧勤承圣绪，开泰喜时康。\n恭己临群后，垂衣御八荒。\n务闲春向暮，朝罢日犹长。\n紫殿初筵列，彤庭广乐张。\n成功归辅弼，致理赖忠良。\n共此欢娱事，千秋乐未央。' },
  { title: '元日退朝观军仗归营', author: '德宗皇帝', poem: '献岁视元朔，万方咸在庭。\n端旒揖群后，回辇阅师贞。\n彩仗宿华殿，退朝归禁营。\n分行左右出，转斾风云生。\n历历趋复道，容容映层城。\n勇余矜捷技，令肃无喧声。\n眷此戎旅节，载嘉良士诚。\n顺时倾宴赏，亦以助文经。' },
  { title: '中和节赐群臣宴赋七韵', author: '德宗皇帝', poem: '东风变梅柳，万汇生春光。\n中和纪月令，方与天地长。\n耽乐岂予尚，懿兹时景良。\n庶遂亭育恩，同致寰海康。\n君臣永终始，交泰符阴阳。\n曲沼水新碧，华林桃稍芳。\n胜赏信多欢，戒之在无荒。' },
  { title: '三日书怀因示百僚', author: '德宗皇帝', poem: '佳节上元巳，芳时属暮春。\n流觞想兰亭，捧劒得金人。\n风轻水初绿，日晴花更新。\n天文信昭回，皇道颇敷陈。\n恭己每从俭，清心常保真。\n戒兹游衍乐，书以示群臣。' },
  { title: '重阳日中外同欢以诗言志因示群官', author: '德宗皇帝', poem: '[爽]节在重九，物华新雨余。\n清秋黄叶下，菊散金潭初。\n万实行就稔，百工欣所如。\n欢心畅遐迩，殊俗同车书。\n至化自敦睦，佳辰宜宴胥。\n锵锵间丝竹，济济罗簪裾。\n此乐匪足耽，此诚期永孚。' },
  { title: '重阳日即事', author: '德宗皇帝', poem: '令节晓澄霁，四郊烟霭空。\n天清白露洁，菊散黄金丛。\n寡德荷天贶，顺时休百工。\n岂怀歌钟乐，思为君臣同。\n至化在亭育，相成资始终。\n未知康衢咏，所仰惟年丰。' },
  { title: '丰年多庆九日示怀', author: '德宗皇帝', poem: '爽气肃时令，早衣闻朔鸿。\n重阳有佳节，具物欣年丰。\n皎洁暮潭色，芬敷新菊丛。\n芳尊满衢室，繁吹凝烟空。\n惠合信吾道，保和惟尔同。\n推诚至玄化，天下期为公。' },
  { title: '七月十五日题章敬寺', author: '德宗皇帝', poem: '招提迩皇邑，复道连重城。\n法筵会早秋，驾言访禅扃。\n尝闻大仙教，清净宗无生。\n七物匪吾宝，万行先求成。\n名相既双寂，繁华奚所荣。\n金风扇微凉，远烟凝翠晶。\n松院静苔色，竹房深磬声。\n境幽真虑恬，道胜外物轻。\n意适本非说，含毫空复情。' },
  { title: '中春麟德殿会百僚观新乐诗一章章十六句', author: '德宗皇帝', poem: '芳岁肇佳节，物华当仲春。\n乾坤既昭泰，烟景含氤氲。\n德浅荷玄贶，乐成思治人。\n前庭列钟鼓，广殿延群臣。\n八卦随舞意，五音转曲新。\n顾非咸池奏，庶协南风熏。\n式宴礼所重，浃欢情必均。\n同和谅在兹，万国希可亲。' },
  { title: '九日绝句', author: '德宗皇帝', poem: '禁苑秋来爽气多，昆明风动起沧波。\n中流箫鼓诚堪赏，讵假横汾发櫂歌。' },
  { title: '暮春喜雨诗', author: '文宗皇帝', poem: '风云喜际会，雷雨遂流滋。\n荐币虚陈礼，动天实精思。\n渐侵九夏节，复在三春时。\n霡霂垂朱阙，飘飖入绿墀。\n郊坰既沾足，黍稷有丰期。\n百辟同康乐，万方伫雍熙。' },
  { title: '题程修己竹障', author: '文宗皇帝', poem: '良工运精思，巧极似有神。\n临窗忽覩繁阴合，再盼真假殊未分。' },
  { title: '宫中题', author: '文宗皇帝', poem: '辇路生春草，上林花发时。\n凭高何限意，无复侍臣知。' },
  { title: '上巳日赐裴度', author: '文宗皇帝', poem: '注想待元老，识君恨不早。\n我家柱石衰，忧来学丘祷。' },
  { title: '上元日二首 一', author: '文宗皇帝', poem: '上元高会集群仙，心斋何事欲祈年。\n丹诚傥彻玉帝座，且共吾人庆大田。' },
  { title: '上元日二首 二', author: '文宗皇帝', poem: '蓂生三五叶初齐，上元羽客出桃蹊。\n不爱仙家登真诀，愿蒙四海福黔黎。' },
  { title: '夏日联句', author: '文宗皇帝', poem: '人皆苦炎热，我爱夏日长。\n熏风自南来，殿阁生微凉。' },
  { title: '百丈山', author: '宣宗皇帝', poem: '大雄真迹枕危峦，梵宇层楼耸万般。\n日月每从肩上过，山河长在掌中看。\n仙峰不间三春秀，灵境何时六月寒？\n更有上方人罕到，暮钟朝磬碧云端。' },
  { title: '吊白居易', author: '宣宗皇帝', poem: '缀玉联珠六十年，谁教冥路作诗仙。\n浮云不系名居易，造化无为字乐天。\n童子解吟《长恨曲》，胡儿能唱《琵琶篇》。\n文章已满行人耳，一度思卿一怆然。' },
  { title: '幸华严寺', author: '宣宗皇帝', poem: '云散晴山几万重，烟收春色更冲融。\n帐殿出空登碧汉，遐川俯望色蓝笼。\n林光入户低韶景，岭气通宵展霁风。\n今日追游何所似，莫慙汉武赏汾中。' },
  { title: '重阳锡宴群臣', author: '宣宗皇帝', poem: '款塞旋征骑，和戎委庙贤。\n倾心方倚注，叶力共安边。' },
  { title: '题泾县水西寺', author: '宣宗皇帝', poem: '大殿连云接爽溪，钟声还与鼓声齐。\n长安若问江南事，说道风光在水西。' },
  { title: '瀑布联句', author: '宣宗皇帝', poem: '千岩万壑不辞劳，远看方知出处高。\n溪涧岂能留得住，终归大海作波涛。' },
  { title: '句', author: '宣宗皇帝', poem: '海岳宴咸通，七载秉钧调四序。\n一方狱市获来苏。' },
  { title: '春游曲', author: '文德皇后', poem: '上苑桃花朝日明，兰闺艳妾动春情。\n井上新桃偷面色，檐边嫩柳学身轻。\n花中来去看舞蝶，树上长短听啼莺。\n林下何须远借问，出众风流旧有名。' },
  { title: '曳鼎歌', author: '则天皇后', poem: '羲农首出，轩昊膺期。\n唐虞继踵，汤禹乘时。\n天下光宅，海内雍熙。\n上玄降鉴，方建隆基。' },
  { title: '唐享昊天乐 第一', author: '则天皇后', poem: '太阴凝至化，真耀蕴轩仪。\n德迈娥台敞，仁高[姒]幄披。\n扪天遂启极，梦日乃升曦。' },
  { title: '唐享昊天乐 第二', author: '则天皇后', poem: '瞻紫极，望玄穹。\n翘至恳，罄深衷。\n听虽远，诚必通。\n垂厚泽，降云宫。' },
  { title: '唐享昊天乐 第三', author: '则天皇后', poem: '干仪混成冲邃，天道下济高明。\n闿阳晨披紫阙，太一晓降黄庭。\n圜坛敢申昭报，方璧冀展虔情。\n丹襟式敷衷恳，玄鉴庶察微诚。' },
  { title: '唐享昊天乐 第四', author: '则天皇后', poem: '巍巍叡业广，赫赫圣基隆。\n菲德承先顾，祯符萃眇躬。\n铭开武岩侧，图荐洛川中。\n微诚讵幽感，景命忽昭融。\n有怀慙紫极，无以谢玄穹。' },
  { title: '唐享昊天乐 第五', author: '则天皇后', poem: '朝坛雾卷，曙岭烟沈。\n爰设筐币，式表诚心。\n筵辉丽璧，乐畅和音。\n仰惟灵鉴，俯察翘襟。' },
  { title: '唐享昊天乐 第六', author: '则天皇后', poem: '昭昭上帝，穆穆下临。\n礼崇备物，乐奏锵金。\n兰羞委荐，桂醑盈斟。\n敢希明德，幸罄庄心。' },
  { title: '唐享昊天乐 第七', author: '则天皇后', poem: '尊浮九酝，礼备三周。\n陈诚菲奠，契福神猷。' },
  { title: '唐享昊天乐 第八', author: '则天皇后', poem: '奠璧郊坛昭大礼，锵金拊石表虔诚。\n始奏承云娱帝赏，复歌调露畅韶英。' },
  { title: '唐享昊天乐 第九', author: '则天皇后', poem: '荷恩承顾托，执契恭临抚。\n庙略静边荒，天兵曜神武。\n有截资先化，无为遵旧矩。\n祯符降昊穹，大业光寰宇。' },
  { title: '唐享昊天乐 第十', author: '则天皇后', poem: '肃肃祀典，邕邕礼秩。\n三献已周，九成斯毕。\n爰撤其俎，载迁其实。\n或升或降，惟诚惟质。' },
  { title: '唐享昊天乐 第十一', author: '则天皇后', poem: '礼终肆类，乐阕九成。\n仰惟明德，敢荐非馨。\n顾慙菲奠，久驰云𫐌。\n瞻荷灵泽，悚恋兼盈。' },
  { title: '唐享昊天乐 第十二', author: '则天皇后', poem: '式干路，辟天扉。\n回日驭，动云衣。\n登金阙，入紫微。\n望仙驾，仰恩徽。' },
  { title: '唐明堂乐章 外办将出', author: '则天皇后', poem: '总章陈昔典，衢室礼惟神。\n宏规则天地，神用叶陶钧。\n负扆三春旦，充庭万宇宾。\n顾己诚虚薄，空慙驭兆人。' },
  { title: '唐明堂乐章 皇帝行', author: '则天皇后', poem: '仰膺历数，俯顺讴歌。\n远安迩肃，俗阜时和。\n化光玉镜，讼息金科。\n方兴典礼，永戢干戈。' },
  { title: '唐明堂乐章 皇嗣出入升降', author: '则天皇后', poem: '至人光俗，大孝通神。\n谦以表性，恭惟立身。\n洪规载启，茂典方陈。\n誉隆三善，祥开万春。' },
  { title: '唐明堂乐章 迎送王公', author: '则天皇后', poem: '千官肃事，万国朝宗。\n载延百辟，爰集三宫。\n君臣德合，鱼水斯同。\n睿图方永，周历长隆。' },
  { title: '唐明堂乐章 登歌', author: '则天皇后', poem: '礼崇宗祀，志表严禋。\n笙镛合奏，文物惟新。\n敬遵茂典，敢择良辰。\n絜诚斯着，奠谒方申。' },
  { title: '唐明堂乐章 配飨', author: '则天皇后', poem: '笙镛间玉宇，文物昭清辉。\n晬影临芳奠，休光下太微。\n孝思期有感，明絜庶无违。' },
  { title: '唐明堂乐章 宫音', author: '则天皇后', poem: '履艮包群望，居中冠百灵。\n万方资广运，庶品荷财成。\n神功谅匪测，盛德实难名。\n藻奠申诚敬，恭祀表惟馨。' },
  { title: '唐明堂乐章 角音', author: '则天皇后', poem: '出震位，开平秩。\n扇条风，乘甲乙。\n龙德盛，鸟星出。\n荐珪篚，陈诚实。' },
  { title: '唐明堂乐章 徵音', author: '则天皇后', poem: '赫赫离精御炎陆，滔滔炽景开隆暑。\n冀延神鉴俯兰尊，式表虔襟陈桂俎。' },
  { title: '唐明堂乐章 商音', author: '则天皇后', poem: '律中夷则，序应收成。\n功宣建武，义表惟明。\n爰申礼奠，庶展翘诚。\n九秋是式，百谷斯盈。' },
  { title: '唐明堂乐章 羽音', author: '则天皇后', poem: '葭律肇启隆冬，苹藻攸陈飨祭。\n黄钟既陈玉烛，红粒方殷稔岁。' },
  { title: '唐大飨拜洛乐章 昭和', author: '则天皇后', poem: '九玄眷命，三圣基隆。\n奉成先旨，明台毕功。\n宗祀展敬，冀表深衷。\n永昌帝业，式播淳风。' },
  { title: '唐大飨拜洛乐章 致和', author: '则天皇后', poem: '神功不测兮运阴阳，包藏万宇兮孕八荒。\n天符既出兮帝业昌，愿临明祀兮降祯祥。' },
  { title: '唐大飨拜洛乐章 咸和', author: '则天皇后', poem: '坎泽祠容备举，坤坛祭典爰申。\n灵睠遥行秘躅，嘉贶荐委殊珍。\n肃礼恭禋载展，翘襟邈志逾殷。\n方期交际悬应。' },
  { title: '唐大飨拜洛乐章 九和', author: '则天皇后', poem: '祗荷坤德，钦若干灵。\n慙惕罔寘，兴居匪宁。\n恭崇礼则，肃奉仪形。\n惟凭展敬，敢荐非馨。' },
  { title: '唐大飨拜洛乐章 拜洛', author: '则天皇后', poem: '菲躬承睿顾，薄德忝坤仪。\n干干遵后命，翼翼奉先规。\n抚俗勤虽切，还淳化尚亏。\n未能弘至道，何以契明祇。' },
  { title: '唐大飨拜洛乐章 显和', author: '则天皇后', poem: '顾德有慙虚菲，明祇屡降祯符。\n汜水初呈秘象，温洛荐表昌图。\n玄泽流恩载洽，丹襟荷渥增愉。' },
  { title: '唐大飨拜洛乐章 敬和', author: '则天皇后', poem: '兰俎既升，苹羞可荐。\n金石载设，咸英已变。\n林泽斯总，山川是徧。\n敢用敷诚，实惟忘倦。' },
  { title: '唐大飨拜洛乐章 齐和', author: '则天皇后', poem: '沈潜演贶分三极，广大凝祯总万方。\n既荐羽旌文化启，还呈干戚武威扬。' },
  { title: '唐大飨拜洛乐章 德和', author: '则天皇后', poem: '夕惕同龙契，晨兢当凤扆。\n崇儒习旧规，偃伯循先旨。\n绝壤飞冠盖，遐区丽山水。\n幸承三圣余，忻属千年始。' },
  { title: '唐大飨拜洛乐章 禋和', author: '则天皇后', poem: '百礼崇容，千官肃事。\n灵降舞兆，神凝有粹。\n奠享咸周，威仪毕备。\n奏夏登列，歌雍撤肆。' },
  { title: '唐大飨拜洛乐章 通和', author: '则天皇后', poem: '皇皇灵睠，穆穆神心。\n暂动凝质，还归积阴。\n功玄枢纽，理寂高深。\n衔恩佩德，耸志翘襟。' },
  { title: '唐大飨拜洛乐章 归和', author: '则天皇后', poem: '言旋云洞兮蹑烟涂，永宁中宇兮安下都。\n包涵动植兮顺荣枯，长贻宝贶兮赞璇图。' },
  { title: '唐武氏享先庙乐章', author: '则天皇后', poem: '先德谦㧑冠昔，严规节素超今。\n奉国忠诚每竭，承家至孝纯深。\n追崇惧乖尊意，显号恐玷徽音。\n既迫王公屡请，方乃俯遂群心。\n有限无由展敬，奠醑每阙亲斟。\n大礼虔申典册，苹藻敬荐翘襟。' },
  { title: '早春夜宴', author: '则天皇后', poem: '九春开上节，千门敞夜扉。\n兰灯吐新燄，桂魄朗圆辉。\n送酒惟须满，流杯不用稀。\n务使霞浆兴，方乘泛洛归。' },
  { title: '游九龙潭', author: '则天皇后', poem: '山窗游玉女，涧户对琼峰。\n岩顶翔双凤，潭心倒九龙。\n酒中浮竹叶，杯上写芙蓉。\n故验家山赏，惟有风入松。' },
  { title: '赠胡天师', author: '则天皇后', poem: '高人叶高志，山服往山家。\n迢迢间风月，去去隔烟霞。\n碧岫窥玄洞，玉灶炼丹砂。\n今日星津上，延首望灵槎。' },
  { title: '从驾幸少林寺', author: '则天皇后', poem: '陪銮游禁苑，侍赏出兰闱。\n云偃攒峰盖，霞低插浪旗。\n日宫疏涧户，月殿启岩扉。\n金轮转金地，香阁曳香衣。\n铎吟轻吹发，幡摇薄雾霏。\n昔遇焚芝火，山红连野飞。\n花台无半影，莲塔有全辉。\n实赖能仁力，攸资善世威。\n慈缘兴福绪，于此罄归依。\n风枝不可静，泣血竟何追。' },
  { title: '石淙', author: '则天皇后', poem: '三山十洞光玄箓，玉峤金峦镇紫微。\n均露均霜标胜壤，交风交雨列皇畿。\n万仞高岩藏日色，千寻幽涧浴云衣。\n且驻欢筵赏仁智，雕鞍薄晚杂尘飞。' },
  { title: '腊日宣诏幸上苑', author: '则天皇后', poem: '明朝游上苑，火急报春知。\n花须连夜发，莫待晓风吹。' },
  { title: '如意娘', author: '则天皇后', poem: '看朱成碧思纷纷，顦顇支离为忆君。\n不信比来长下泪，开箱验取石榴裙。' },
  { title: '制袍字赐狄仁杰', author: '则天皇后', poem: '敷政术，守清勤。\n升显位，励相臣。' },
  { title: '拟小山篇', author: '徐贤妃', poem: '仰幽岩而流盼，抚桂枝以凝想。\n将千龄兮此遇，荃何为兮独往。' },
  { title: '长门怨', author: '徐贤妃', poem: '旧爱柏梁台，新宠昭阳殿。\n守分辞芳辇，含情泣团扇。\n一朝歌舞荣，夙昔诗书贱。\n颓恩诚已矣，覆水难重荐。' },
  { title: '秋风函谷应诏', author: '徐贤妃', poem: '秋风起函谷，劲气动河山。\n偃松千岭上，杂雨二陵间。\n低云愁广隰，落日惨重关。\n此时飘紫气，应验真人还。' },
  { title: '赋得北方有佳人', author: '徐贤妃', poem: '由来称独立，本自号倾城。\n柳叶眉间发，桃花脸上生。\n腕摇金钏响，步转玉环鸣。\n纤腰宜宝袜，红衫艳织成。\n悬知一顾重，别觉舞腰轻。' },
  { title: '进太宗', author: '徐贤妃', poem: '朝来临镜台，粧罢暂裴回。\n千金始一笑，一召讵能来。' },
  { title: '奉和圣制立春日侍宴内殿出翦彩花应制', author: '上官昭容', poem: '密叶因裁吐，新花逐翦舒。\n攀条虽不谬，摘橤讵知虚。\n春至由来发，秋还未肯疎。' },
  { title: '九月九日上幸慈恩寺登浮图群臣上菊花寿酒', author: '上官昭容', poem: '帝里重阳节，香园万乘来。\n却邪萸入佩，献寿菊传杯。\n墖类承天涌，门疑待佛开。\n睿词悬日月，长得仰昭回。' },
  { title: '彩书怨', author: '上官昭容', poem: '叶下洞庭初，思君万里余。\n露浓香被冷，月落锦屏虚。\n欲奏江南曲，贪封蓟北书。\n书中无别意，惟怅久离居。' },
  { title: '驾幸三会寺应制', author: '上官昭容', poem: '释子谈经处，轩臣刻字留。\n故台遗老识，残简圣皇求。\n驻跸怀千古，开襟望九州。\n四山缘塞合，二水夹城流。\n宸翰陪瞻仰，天杯接献酬。\n太平词藻盛，长愿纪鸿休。' },
  { title: '驾幸新丰温泉宫献诗三首 一', author: '上官昭容', poem: '三冬季月景[龙]年，万乘观风出灞川。\n遥看电跃龙为马，回瞩霜原玉作田。' },
  { title: '驾幸新丰温泉宫献诗三首 二', author: '上官昭容', poem: '鸾旗掣曳拂空回，羽骑骖驔蹑景来。\n隐隐骊山云外耸，迢迢御帐日边开。' },
  { title: '驾幸新丰温泉宫献诗三首 三', author: '上官昭容', poem: '翠幕珠帏敞月营，金罍玉斝泛兰英。\n岁岁年年常扈跸，长长久久乐升平。' },
  { title: '游长宁公主流杯池二十五首 一', author: '上官昭容', poem: '逐仙赏，展幽情。\n逾昆阆，迈蓬瀛。' },
  { title: '游长宁公主流杯池二十五首 二', author: '上官昭容', poem: '游鲁馆，陟秦台。\n汚山壁，媿琼瓌。' },
  { title: '游长宁公主流杯池二十五首 三', author: '上官昭容', poem: '檀栾竹影，飙𫗇松声。\n不烦歌吹，自足娱情。' },
  { title: '游长宁公主流杯池二十五首 四', author: '上官昭容', poem: '仰循茅宇，俯眄乔枝。\n烟霞问讯，风月相知。' },
  { title: '游长宁公主流杯池二十五首 五', author: '上官昭容', poem: '枝条郁郁，文质彬彬。\n山林作伴，松桂为邻。' },
  { title: '游长宁公主流杯池二十五首 六', author: '上官昭容', poem: '清波汹涌，碧树冥蒙。\n莫怪留步，因攀桂丛。' },
  { title: '游长宁公主流杯池二十五首 七', author: '上官昭容', poem: '莫论圆峤，休说方壶。\n何如鲁馆，即是仙都。' },
  { title: '游长宁公主流杯池二十五首 八', author: '上官昭容', poem: '玉环腾远创，金埒荷殊荣。\n弗玩珠玑饰，仍留仁智情。\n凿山便作室，凭树即为楹。\n公输与班尔，从此遂韬声。' },
  { title: '游长宁公主流杯池二十五首 九', author: '上官昭容', poem: '登山一长望，正遇九春初。\n结驷填街术，闾阎满邑居。\n鬬雪梅先吐，惊风柳未舒。\n直愁斜日落，不畏酒尊虚。' },
  { title: '游长宁公主流杯池二十五首 十', author: '上官昭容', poem: '霁晓气清和，披襟赏薜萝。\n玳瑁凝春色，琉璃漾水波。\n跂石聊长啸，攀松乍短歌。\n除非物外者，谁就此经过。' },
  { title: '游长宁公主流杯池二十五首 十一', author: '上官昭容', poem: '暂尔游山第，淹留惜未归。\n霞窗明月满，涧户白云飞。\n书引藤为架，人将薜作衣。\n此真攀玩所，临睨赏光辉。' },
  { title: '游长宁公主流杯池二十五首 十二', author: '上官昭容', poem: '放旷出烟云，萧条自不群。\n漱流清意府，隐几避嚻氛。\n石画妆苔色，风梭织水文。\n山室何为贵？唯余兰桂熏。' },
  { title: '游长宁公主流杯池二十五首 十三', author: '上官昭容', poem: '策杖临霞岫，危步下霜蹊。\n志逐深山静，途随曲涧迷。\n渐觉心神逸，俄看云雾低。\n莫怪人题树，祗为赏幽栖。' },
  { title: '游长宁公主流杯池二十五首 十四', author: '上官昭容', poem: '攀藤招逸客，偃桂协幽情。\n水中看树影，风里听松声。' },
  { title: '游长宁公主流杯池二十五首 十五', author: '上官昭容', poem: '携琴侍叔夜，负局访安期。\n不应题石壁，为记赏山时。' },
  { title: '游长宁公主流杯池二十五首 十六', author: '上官昭容', poem: '泉石多仙趣，岩壑写奇形。\n欲知堪悦耳，唯听水泠泠。' },
  { title: '游长宁公主流杯池二十五首 十七', author: '上官昭容', poem: '岩壑恣登临，莹目复怡心。\n风篁类长笛，流水当鸣琴。' },
  { title: '游长宁公主流杯池二十五首 十八', author: '上官昭容', poem: '嬾步天台路，惟登地肺山。\n幽岩仙桂满，今日恣情攀。' },
  { title: '游长宁公主流杯池二十五首 十九', author: '上官昭容', poem: '暂游仁智所，萧然松桂情。\n寄言栖遯客，勿复访蓬瀛。' },
  { title: '游长宁公主流杯池二十五首 二十', author: '上官昭容', poem: '瀑溜晴疑雨，丛篁昼似昏。\n山中真可玩，暂请报王孙。' },
  { title: '游长宁公主流杯池二十五首 二十一', author: '上官昭容', poem: '傍池聊试笔，倚石旋题诗。\n豫弹山水调，终拟从钟期。' },
  { title: '游长宁公主流杯池二十五首 二十二', author: '上官昭容', poem: '横铺豹皮褥，侧带鹿胎巾。\n借问何为者，山中有逸人。' },
  { title: '游长宁公主流杯池二十五首 二十三', author: '上官昭容', poem: '沁水田园先自多，齐城楼观更无过。\n倩语张骞莫辛苦，人今从此识天河。' },
  { title: '游长宁公主流杯池二十五首 二十四', author: '上官昭容', poem: '参差碧岫耸莲花，潺湲绿水莹金沙。\n何须远访三山路，人今已到九仙家。' },
  { title: '游长宁公主流杯池二十五首 二十五', author: '上官昭容', poem: '凭高瞰险足怡心，菌阁桃源不暇寻。\n余雪依林成玉树，残霙点岫即瑶岑。' },
  { title: '赠张云容舞', author: '杨贵妃', poem: '罗袖动香香不已，红蕖褭褭秋烟里。\n轻云岭上乍摇风，嫩柳池边初拂水。' },
  { title: '谢赐珍珠', author: '江妃', poem: '桂叶双眉久不描，残妆和泪汚红绡。\n长门尽日无梳洗，何必珍珠慰寂寥。' },
  { title: '黄台瓜辞', author: '章怀太子', poem: '种瓜黄台下，瓜熟子离离。\n一摘使瓜好，再摘使瓜稀。\n三摘犹自可，摘绝抱蔓归。' },
  { title: '奉和同太子监守违恋', author: '韩王元嘉', poem: '乾象开层构，离明启少阳。\n卜征从献吉，守器属元良。\n逖矣凌周诵，遥哉掩汉庄。\n好士倾南洛，多才盛北场。\n地分丹鹫岭，途间白云乡。\n储诚虔晓夕，宸爱积炎凉。\n珠璧连霄汉，万物仰重光。' },
  { title: '奉和圣制过温汤', author: '越王贞', poem: '凤辇腾宸驾，骊籞次干游。\n坎德疎温液，山隈派暖流。\n寒氛空外拥，蒸气沼中浮。\n林凋帷影散，云敛盖阴收。\n霜郊畅玄览，参差落景遒。' },
  { title: '石桥', author: '信安王祎', poem: '别有经行所，迥跨重峦侧。\n粤因求瘼余，倏想寻真域。\n放情恣披拂，杖策聊□□。\n□□□□□，□□□□色。\n乱幡雾中见，雁塔云间识。\n薄烟幂远郊，遥峰没归翼。\n仙桥危石架，幽洞乘□□。\n□□□□□，□□□易测。\n二教无先后，一相平而直。\n冀兹捐俗心，永怀依妙力。' },
  { title: '虚池驿题屏风', author: '宜芬公主', poem: '出嫁辞乡国，由来此别难。\n圣恩愁远道，行路泣相看。\n沙塞容颜尽，边隅粉黛残。\n妾心何所断，他日望长安。' },
  { title: '嘲陆畅', author: '女学士宋氏若华', poem: '十二层楼倚翠空，凤鸾相对立梧桐。\n双成走报监门卫，莫使吴歈入汉宫。' },
  { title: '奉和御制麟德殿宴百僚应制', author: '尚宫宋氏若昭', poem: '垂衣临八极，肃穆四门通。\n自是无为化，非关辅弼功。\n修文招隐伏，尚武殄妖凶。\n德炳韶光炽，恩沾雨露浓。\n衣冠陪御宴，礼乐盛朝宗。\n万寿称觞举，千年信一同。' },
  { title: '奉和御制麟德殿宴百官', author: '尚宫宋氏若宪', poem: '端拱承休命，时清荷圣皇。\n四聪闻受谏，五服远朝王。\n景媚莺初啭，春残日更长。\n命筵多济济，盛乐复锵锵。\n酆镐谁将敌，横汾未可方。\n愿齐山岳寿，祉福永无疆。' },
  { title: '奉和麟德殿宴百僚应[制]', author: '鲍氏君徽', poem: '睿泽先寰海，功成展武韶。\n戈鋋清外垒，文物盛中朝。\n圣祚山河固，宸章日月昭。\n玉筵鸾鹄集，仙管凤皇调。\n御柳新低绿，宫莺乍啭娇。\n愿将[亿]兆庆，千祀奉神尧。' },
  { title: '关山月', author: '鲍氏君徽', poem: '高高秋月明，北照辽阳城。\n塞迥光初满，风多晕更生。\n征人望乡思，战马闻鼙惊。\n朔风悲边草，胡沙暗虏营。\n霜凝匣中劒，风惫原上旌。\n早晚谒金阙，不闻刁斗声。' },
  { title: '惜花吟', author: '鲍氏君徽', poem: '枝上花，花下人，可怜颜色俱青春。\n昨日看花花灼灼，今朝看花花欲落。\n不如尽此花下欢，莫待春风总吹却。\n莺歌蝶舞韶光长，红炉煑茗松花香。\n妆成罢吟恣游后，独把芳枝归洞房。' },
  { title: '东亭茶宴', author: '鲍氏君徽', poem: '闲朝向晓出帘栊，茗宴东亭四望通。\n远眺城池山色里，俯聆弦管水声中。\n幽篁引沼新抽翠，芳槿低檐欲吐红。\n坐久此中无限兴，更怜团扇起清风。' },
  { title: '夜梦', author: '萧妃', poem: '昨日梦君归，贱妾下鸣机。\n极知意气薄，不着去时衣。\n故言如梦里，赖得雁书飞。' },
  { title: '咏灯', author: '南唐先主李昪', poem: '一点分明值万金，开时惟怕冷风侵。\n主人若也勤挑拨，敢向尊前不尽心。' },
  { title: '游后湖赏莲花', author: '嗣主璟', poem: '蓼花蘸水火不灭，水鸟惊鱼银梭投。\n满目荷花千万顷，红碧相杂敷清流。\n孙武已斩吴宫女，琉璃池上佳人头。' },
  { title: '保大五年元日大雪同太弟景遂汪王景逷齐王景逵进士李建勋中书徐铉勤政殿学士张义方登楼赋', author: '嗣主璟', poem: '珠帘高卷莫轻遮，往往相逢隔岁华。\n春气昨宵飘律管，东风今日放梅花。\n素姿好把芳姿掩，落势还同舞势斜。\n坐有宾朋尊有酒，可怜清味属侬家。' },
  { title: '句', author: '嗣主璟', poem: '灵槎思浩荡，老鹤倚崆峒。\n苍苔迷古道，红叶乱朝霞。\n栖凤枝梢犹輭弱，化龙形状已依稀。' },
  { title: '九月十日偶书', author: '后主煜', poem: '晚雨秋阴酒乍醒，感时心绪杳难平。\n黄花冷落不成艳，红叶飕飗竞鼓声。\n背世返能厌俗态，偶缘犹未忘多情。\n自从双鬓斑斑白，不学安仁却自惊。' },
  { title: '秋莺', author: '后主煜', poem: '残莺何事不知秋，横过幽林尚独游。\n老舌百般倾耳听，深黄一点入烟流。\n栖迟背世同悲鲁，浏亮如笙碎在缑。\n莫更留连好归去，露华凄冷蓼花愁。' },
  { title: '病起题山舍壁', author: '后主煜', poem: '山舍初成病乍轻，杖藜巾褐称闲情。\n炉开小火深回暖，沟引新流几曲声。\n暂约彭涓安朽质，终期宗远问无生。\n谁能役役尘中累，贪合鱼龙搆强名。' },
  { title: '送邓王二十弟从益牧宣城', author: '后主煜', poem: '且维轻舸更迟迟，别酒重倾惜解携。\n浩浪侵愁光荡漾，乱山凝恨色高低。\n君驰桧楫情何极，我凭阑干日向西。\n咫尺烟江几多地，不须怀抱重凄凄。' },
  { title: '渡中江望石城泣下', author: '后主煜', poem: '江南江北旧家乡，三十年来梦一场。\n吴苑宫闱今冷落，广陵台殿已荒凉。\n云笼远岫愁千片，雨打归舟泪万行。\n兄弟四人三百口，不堪闲坐细思量。' },
  { title: '挽辞 一', author: '后主煜', poem: '珠碎眼前珍，花凋世外春。\n未销心里恨，又失掌中身。\n玉笥犹残药，香匳已染尘。\n前哀将后感，无泪可沾巾。' },
  { title: '挽辞 二', author: '后主煜', poem: '艳质同芳树，浮危道略同。\n正悲春落实，又苦雨伤丛。\n秾丽今何在？飘零事已空。\n沈沈无问处，千载谢东风。' },
  { title: '悼诗', author: '后主煜', poem: '永念难消释，孤怀痛自嗟。\n雨深秋寂莫，愁引病增加。\n咽绝风前思，昏蒙眼上花。\n空王应念我，穷子正迷家。' },
  { title: '感怀 一', author: '后主煜', poem: '又见桐花发旧枝，一楼烟雨暮凄凄。\n凭阑惆怅人谁会，不觉澘然泪眼低。' },
  { title: '感怀 二', author: '后主煜', poem: '层城无复见娇姿，佳节缠哀不自持。\n空有当年旧烟月，芙蓉城上哭蛾眉。' },
  { title: '梅花', author: '后主煜', poem: '殷勤移植地，曲槛小阑边。\n共约重芳日，还忧不盛妍。\n阻风开步障，乘月溉寒泉。\n谁料花前后，蛾眉却不全。' },
  { title: '书灵筵手巾', author: '后主煜', poem: '浮生共顦顇，壮岁失婵娟。\n汗手遗香渍，痕眉染黛烟。' },
  { title: '书琵琶背', author: '后主煜', poem: '侁自肩如削，难胜数缕绦。\n天香留凤尾，余煖在檀槽。' },
  { title: '病中感怀', author: '后主煜', poem: '顦顇年来甚，萧条益自伤。\n风威侵病骨，雨气咽愁肠。\n夜鼎唯煎药，朝髭半染霜。\n前缘竟何似，谁与问空王。' },
  { title: '病中书事', author: '后主煜', poem: '病身坚固道情深，宴坐清香思自任。\n月照静居唯捣药，门扃幽院只来禽。\n庸医嬾听词何取，小婢将行力未禁。\n赖问空门知气味，不然烦恼万涂侵。' },
  { title: '赐宫人庆奴', author: '后主煜', poem: '风情渐老见春羞，到处消魂感旧游。\n多谢长条似相识，强垂烟态拂人头。' },
  { title: '题金楼子后', author: '后主煜', poem: '牙签万轴裹红绡，王粲书同付火烧。\n不于祖龙留面目，遗篇那得到今朝。' },
  { title: '句', author: '后主煜', poem: '迢迢牵牛星，杳在河之阳。\n粲粲黄姑女，耿耿遥相望。\n鸎狂应有恨，蝶舞已无多。\n揖让月在手，动摇风满怀。\n病态如衰弱，厌厌向五年。\n衰颜一病难牵复，晓殿君临颇自羞。\n冷笑秦皇经远略，静怜姬满苦时巡。\n鬓从今日添新白，菊是去年依旧黄。\n万古到头归一死，醉乡葬地有高原。\n人生不满百，刚作千年画。\n日暎仙云薄，秋高天碧深。\n乌照始潜辉，龙烛便争秉。\n凝珠满露枝，游飏日已西。\n肃穆寒初至，九重开扇鹄。\n四牖炳灯鱼，羽觞无算酌。\n倾盌更为寿，深卮递酬宾。' },
  { title: '蔷薇诗一首十八韵呈东海侍郎徐铉', author: '韩王从善', poem: '绿影覆幽池，芳菲四月时。\n管弦朝夕兴，组绣百千枝。\n盛引墙看徧，高烦架屡移。\n露轻濡彩笔，蜂误拂吟髭。\n日照玲珑幔，风摇翡翠帷。\n早红飘藓地，狂蔓挂蛛丝。\n嫩刺牵衣细，新条窣草垂。\n晚香难暂舍，娇态自相窥。\n深浅分前后，荣华互盛衰。\n尊前留客久，月下欲归迟。\n何处繁临砌？谁家密映篱。\n绛罗房灿烂，碧玉叶参差。\n分得殷勤种，开来远近知。\n晶荧歌袖袂，柔弱舞腰支。\n膏麝谁将比，庭萱自合嗤。\n匀妆低水鉴，泣泪滴烟𩅰。\n画拟凭梁广，名宜亚楚姬。\n寄君十八韵，思拙媿新奇。' },
  { title: '观棋', author: '吉王从谦', poem: '竹林二君子，尽日竟沈吟。\n相对终无语，争先各有心。\n恃强斯有失，守分固无侵。\n若算机筹处，沧沧海未深。' },
  { title: '赠别唐太师道袭', author: '蜀高祖王建', poem: '丱岁便将为肘腋，二纪何曾离一日。\n更深犹尚立案前，敷奏柔和不伤物。\n今朝荣贵慰我心，双旌引向重城出。\n褒斜旧地委勋贤，从此生灵永泰息。' },
  { title: '幸秦川上梓潼山', author: '后主衍', poem: '乔岩簇冷烟，幽径上寒天。\n下瞰峨眉岭，上窥华岳巅。\n驱驰非取乐，按幸为忧边。\n此去如登陟，歌楼路几千。' },
  { title: '题劒门', author: '后主衍', poem: '缓辔逾双劒，行行蹑石棱。\n作千寻壁垒，为万祀依凭。\n道德虽无取，江山粗可矜。\n回看城阙路，云叠树层层。' },
  { title: '过白卫岭和韩昭', author: '后主衍', poem: '先朝神武力开边，画断封疆四五千。\n前望陇山屯劒戟，后凭巫峡锁烽烟。\n轩皇尚自亲平寇，嬴政徒劳爱学仙。\n想到隗宫寻胜处，正应莺语暮春天。' },
  { title: '宫词', author: '后主衍', poem: '辉辉赫赫浮玉云，宣华池上月华新。\n月华如水浸宫殿，有酒不醉真痴人。' },
  { title: '醉妆词', author: '后主衍', poem: '者边走，那边走，只是寻花柳。\n那边走，者边走，莫厌金杯酒。' },
  { title: '巡衣锦军制还乡歌', author: '吴越王钱镠', poem: '三节还乡兮挂锦衣，碧天朗朗兮爱日晖。\n功成道上兮列旌旗，父老远来兮相追随。\n家山乡眷兮会时稀，今朝设宴兮觥散飞。\n斗牛无孛兮民无欺，吴越一王兮驷马归。' },
  { title: '句', author: '吴越王钱镠', poem: '须将一片地，付与有心人。\n黄河信有澄清日，后代应难继此才。\n传语龙王幷水府，钱塘借与筑钱城。' },
  { title: '宫中作', author: '后王钱俶', poem: '廊庑周遭翠幕遮，禁林深处绝喧哗。\n界开日影怜窗纸，穿破苔痕恶笋芽。\n西第晚宜供露茗，小池寒欲结冰花。\n谢公未是深沈量，犹把输赢局上夸。' },
  { title: '避暑摩诃池上作', author: '后蜀嗣主孟昶', poem: '冰肌玉骨清无汗，水殿风来暗香暖。\n帘开明月独窥人，敧枕钗横云鬓乱。\n起来琼户寂无声，时见疎星渡河汉。\n屈指西风几时来，只恐流年暗中换。' },
  { title: '批叶翘谏书纸尾', author: '闽王王继鹏', poem: '春色曾看紫陌头，乱红飞尽不禁愁。\n人情自厌芳华歇，一叶随风落御沟。' },
  { title: '丈人观', author: '蜀太后徐氏', poem: '早与元妃慕至化，同跻灵岳访真仙。\n当时信有壶中景，今日亲来洞里天。\n仪仗影空寥廓外，金丝声揭翠微巅。\n惟慙未致华胥理，徒卜升平万万年。' },
  { title: '玄都观', author: '蜀太后徐氏', poem: '千寻绿嶂夹流溪，登眺因知海岳低。\n瀑布迸舂青石碎，轮茵横翦翠峰齐。\n步黏苔藓龙桥滑，日闭烟罗鸟径迷。\n莫道穹天无路到，此山便是碧云梯。' },
  { title: '丈人观谒先帝御容', author: '蜀太后徐氏', poem: '圣帝归梧野，躬来谒圣颜。\n旋登三径路，似陟九嶷山。\n日照堆岚迥，云横积翠间。\n期修封禅礼，方俟再跻攀。' },
  { title: '题金华宫', author: '蜀太后徐氏', poem: '再到金华顶，玄都访道回。\n云披分景象，黛锁显楼台。\n雨涤前山净，风吹去路开。\n翠屏夹流水，何必羡蓬莱。' },
  { title: '丹景山至德寺', author: '蜀太后徐氏', poem: '周回云水游丹景，因与真妃眺上方。\n晴日晓升金晃曜，寒泉夜落玉丁当。\n松梢月转琴栖影，柏径风牵麝食香。\n虔煠六铢宜铸祝，惟祈圣祉保遐昌。' },
  { title: '题彭州阳平化', author: '蜀太后徐氏', poem: '寻真游胜境，巡礼到阳平。\n水远波澜碧，山高气象清。\n殿严孙氏貌，碑暗系师名。\n夜月登坛醮，松风森磬声。' },
  { title: '三学山夜看圣灯', author: '蜀太后徐氏', poem: '虔祷游灵境，元妃夙志同。\n玉香焚静夜，银烛炫辽空。\n泉漱云根月，钟敲桧杪风。\n印金标圣迹，飞石显神功。\n满望天涯极，平临日脚红。\n猿来斋石上，僧集讲筵中。\n顿作超三界，浑疑证六通。\n愿成修偃化，社稷保延洪。' },
  { title: '题天回驿', author: '蜀太后徐氏', poem: '周游灵境散幽情，千里江山暂得行。\n所恨风光看未足，却驱金翠入龟城。' },
  { title: '丈人观', author: '蜀太妃徐氏', poem: '获陪翠辇喜殊常，同涉仙坛岂厌长。\n不羡乘鸾入烟雾，此中便是五云乡。' },
  { title: '玄都观', author: '蜀太妃徐氏', poem: '登寻丹壑到玄都，接日红霞照座隅。\n即向周回岩下看，似看曾进画图无。' },
  { title: '游丈人观谒先帝御容', author: '蜀太妃徐氏', poem: '共谒御容仪，还同在禁闱。\n笙歌喧宝殿，彩仗耀金徽。\n清泪沾罗袂，红霞拂绣衣。\n九疑山水远，无路继湘妃。' },
  { title: '题金华宫', author: '蜀太妃徐氏', poem: '碧烟红雾漾人衣，宿雾苍苔石径危。\n风巧解吹松上曲，蝶娇频采脸边脂。\n同寻僻境思携手，暗指遥山学画眉。\n好把身心清净处，角冠霞帔事希夷。' },
  { title: '和题丹景山至德寺', author: '蜀太妃徐氏', poem: '丹景山头宿梵宫，玉轮金辂驻虚空。\n军持无水注寒碧，兰若有花开晚红。\n武士尽排青嶂下，内人皆在讲筵中。\n我家帝子传王业，积善终期四海同。' },
  { title: '题彭州阳平化', author: '蜀太妃徐氏', poem: '云浮翠辇届阳平，真似骖鸾到上清。\n风起半厓闻虎啸，雨来当面见龙行。\n晚寻水涧听松韵，夜上星坛看月明。\n长恐前身居此境，玉皇教向锦城生。' },
  { title: '三学山夜看圣灯', author: '蜀太妃徐氏', poem: '圣灯千万炬，旋向碧空生。\n细雨湿不暗，好风吹更明。\n磬敲金地响，僧唱梵天声。\n若说无心法，此光如有情。' },
  { title: '题天回驿', author: '蜀太妃徐氏', poem: '翠驿红亭近玉京，梦魂犹是在青城。\n比来出看江山景，却被江山看出行。' },
  { title: '郊庙歌辞 祀圜丘乐章 豫和', author: '褚亮', poem: '上灵睠命膺会昌，盛德殷荐叶辰良。\n景福降兮圣德远，玄化穆兮天历长。' },
  { title: '郊庙歌辞 祀圜丘乐章 太和', author: '褚亮', poem: '穆穆我后，道应千龄。\n登三处大，得一居贞。\n礼惟崇德，乐以和声。\n百神仰止，天下文明。' },
  { title: '郊庙歌辞 祀圜丘乐章 肃和', author: '褚亮', poem: '闿阳播气，甄曜垂明。\n有赫圜宰，深仁曲成。\n日丽苍璧，烟开紫营。\n聿遵干享，式降鸿祯。' },
  { title: '郊庙歌辞 祀圜丘乐章 雍和', author: '褚亮', poem: '钦惟大帝，[载]仰皇穹。\n始命田烛，爰启郊宫。\n云门骇听，雷鼓鸣空。\n神其介祀，景祚斯融。' },
  { title: '郊庙歌辞 祀圜丘乐章 寿和', author: '褚亮', poem: '八音斯奏，三献毕陈。\n宝祚惟永，晖光日新。' },
  { title: '郊庙歌辞 祀圜丘乐章 舒和', author: '褚亮', poem: '叠璧凝影皇坛路，编珠流彩帝郊前。\n已奏黄钟歌大吕，还符宝历祚昌年。' },
  { title: '郊庙歌辞 祀圜丘乐章 凯安', author: '褚亮', poem: '昔在炎运终，中华乱无象。\n酆郊赤乌见，邙山黑云上。\n大赉下周车，禁暴开殷网。\n幽明同叶赞，鼎祚齐天壤。' },
  { title: '郊庙歌辞 郊天旧乐章 豫和', author: '不详', poem: '苹蘩礼着，黍稷诚微。\n音盈凤管，彩驻龙旗。\n洪歆式就，介福攸归。\n送乐有阕，灵驭遄飞。' },
  { title: '郊庙歌辞 武后大享昊天乐章 一', author: '不详', poem: '大阴凝至化，真耀蕴轩仪。\n德迈娥台敞，仁高姒幄披。\n扪天遂启极，梦日乃升曦。' },
  { title: '郊庙歌辞 武后大享昊天乐章 二', author: '不详', poem: '瞻紫极，望玄穹。\n翘至恳，罄深衷。\n听虽远，诚必通。\n垂厚泽，降云宫。' },
  { title: '郊庙歌辞 武后大享昊天乐章 三', author: '不详', poem: '干仪混成冲邃，天道下济高明。\n闿阳晨披紫阙，太一晓降黄庭。\n圆坛敢[申]昭报，方璧冀展虔情。\n丹禁式敷衷恳，玄鉴庶察微诚。' },
  { title: '郊庙歌辞 武后大享昊天乐章 四', author: '不详', poem: '巍巍睿业广，赫赫圣基隆。\n菲德承先顾，祯符萃眇躬。\n铭开武岩侧，图荐洛川中。\n微诚讵幽感，景命忽昭融。\n有怀慙紫极，无以谢玄穹。' },
  { title: '郊庙歌辞 武后大享昊天乐章 五', author: '不详', poem: '朝坛雾卷，曙岭烟沈。\n爰设筐币，式表诚心。\n筵辉丽璧，乐畅和音。\n仰惟灵鉴，俯察翘襟。' },
  { title: '郊庙歌辞 武后大享昊天乐章 六', author: '不详', poem: '昭昭上帝，穆穆下临。\n礼崇备物，乐奏锵金。\n兰羞委荐，桂醑盈斟。\n敢希[明]德，聿罄庄心。' },
  { title: '郊庙歌辞 武后大享昊天乐章 七', author: '不详', poem: '樽浮九酝，礼备三周。\n陈诚菲奠，契福神猷。' },
  { title: '郊庙歌辞 武后大享昊天乐章 八', author: '不详', poem: '奠璧郊坛昭大礼，锵金拊石表虔诚。\n始奏承云娱帝赏，复歌调露畅韶英。' },
  { title: '郊庙歌辞 武后大享昊天乐章 九', author: '不详', poem: '荷恩承顾托，执契恭临抚。\n庙畧静边荒，天兵耀神武。\n有截资先化，无为遵旧矩。\n祯符降昊穹，大业光寰宇。' },
  { title: '郊庙歌辞 武后大享昊天乐章 十', author: '不详', poem: '肃肃祀典，邕邕礼秩。\n三献已周，九成斯毕。\n爰撤其俎，载迁其实。\n或升或降，唯诚唯质。' },
  { title: '郊庙歌辞 武后大享昊天乐章 十一', author: '不详', poem: '礼终肆类，乐阕九成。\n仰惟明德，敢荐非馨。\n顾慙菲奠，久驻云𫐌。\n瞻荷灵泽，悚恋兼盈。' },
  { title: '郊庙歌辞 武后大享昊天乐章 十二', author: '不详', poem: '式干路，辟天扉。\n回日驭，动云衣。\n登金阙，入紫微。\n望仙驾，仰恩徽。' },
  { title: '郊庙歌辞 中宗祀昊天乐章 豫和', author: '不详', poem: '天之历数归睿唐，顾惟菲德钦昊苍。\n撰吉日兮表殷荐，冀神鉴兮降闿阳。' },
  { title: '郊庙歌辞 中宗祀昊天乐章 太和', author: '不详', poem: '恭临宝位，肃奉瑶图。\n恒思解网，每轸泣辜。\n德慙巢燧，化劣唐虞。\n期我良弼，式赞嘉谟。' },
  { title: '郊庙歌辞 中宗祀昊天乐章 告谢', author: '不详', poem: '得一流玄泽，通三御紫宸。\n远叶千龄运，遐销九域尘。\n绝瑞骈阗集，殊祥络绎臻。\n登年庆栖亩，稔岁贺盈囷。' },
  { title: '郊庙歌辞 中宗祀昊天乐章 肃和', author: '不详', poem: '悠哉广覆，大矣曲成。\n九玄着象，七曜贞明。\n珪璧是奠，酝酎斯盈。\n作乐崇德，爰畅咸英。' },
  { title: '郊庙歌辞 中宗祀昊天乐章 雍和', author: '不详', poem: '郊坛展敬，严配因心。\n孤竹箫管，空桑瑟琴。\n肃穆大礼，铿锵八音。\n恭惟上帝，希降灵歆。' },
  { title: '郊庙歌辞 中宗祀昊天乐章 福和', author: '不详', poem: '九成爰奏，三献式陈。\n钦承景福，恭托明禋。' },
  { title: '郊庙歌辞 中宗祀昊天乐章 中宫助祭升坛', author: '不详', poem: '坤元光至德，柔训阐皇风。\n芣苡芳声远，螽斯美化隆。\n睿范超千载，嘉猷备六宫。\n肃恭陪盛典，钦若荐禋宗。' },
  { title: '郊庙歌辞 中宗祀昊天乐章 亚献', author: '不详', poem: '三灵降飨，三后配神。\n虔敷藻奠，敬展郊禋。' },
  { title: '郊庙歌辞 中宗祀昊天乐章 舒和', author: '不详', poem: '已陈粢盛敷严祀，更奏笙镛协雅声。\n璇图宝历欣宁谧，晏俗淳风乐太平。' },
  { title: '郊庙歌辞 中宗祀昊天乐章 凯安', author: '不详', poem: '堂堂圣祖兴，赫赫昌基泰。\n戎车盟津偃，玉帛涂山会。\n舜日启祥晖，尧云卷征斾。\n风猷被有截，声教覃无外。' },
  { title: '郊庙歌辞 明皇祀圜丘乐章 豫和', author: '不详', poem: '至矣丕搆，烝哉太平。\n授牺膺箓，复禹继明。\n草木仁化，凫鹥颂声。\n祀宗陈德，无媿斯诚。' },
  { title: '郊庙歌辞 明皇祀圜丘乐章 太和', author: '不详', poem: '郊坛斋帝，礼乐祀天。\n丹青寰宇，宫征山川。\n神祇毕降，行止重旋。\n融融穆穆，纳祉洪延。' },
  { title: '郊庙歌辞 明皇祀圜丘乐章 肃和', author: '不详', poem: '止奏潜聆，登仪宿啭。\n太玉躬奉，参钟首奠。\n簠簋聿升，牺牲遰荐。\n昭事颙若，存存以伣。' },
  { title: '郊庙歌辞 明皇祀圜丘乐章 雍和', author: '不详', poem: '烂云普洽，律风无外。\n千品其凝，九宾斯会。\n禋尊晋烛，纯牺涤汰。\n玄覆攸广，鸿休汪濊。' },
  { title: '郊庙歌辞 明皇祀圜丘乐章 寿和', author: '不详', poem: '六变爰阕，八阶载虔。\n祐我皇祚，于万斯年。' },
  { title: '郊庙歌辞 明皇祀圜丘乐章 舒和', author: '不详', poem: '祝史正辞，人神叶庆。\n福以德招，享以诚应。\n六变云备，百礼斯浃。\n祀事孔明，祚流万叶。' },
  { title: '郊庙歌辞 明皇祀圜丘乐章 凯安', author: '不详', poem: '馨香惟后德，明命光天保。\n肃和崇圣灵，陈信表皇道。\n玉𬭭初蹈厉，金匏既静好。' },
  { title: '郊庙歌辞 封泰山乐章 豫和 一', author: '张说', poem: '款泰坛，柴泰清。\n受天命，报天成。\n竦皇心，荐乐声。\n志上达，歌下迎。' },
  { title: '郊庙歌辞 封泰山乐章 豫和 二', author: '张说', poem: '亿上帝，临下庭。\n骑日月，陪列星。\n嘉祝信，大糦馨。\n澹神心，醉皇灵。' },
  { title: '郊庙歌辞 封泰山乐章 豫和 三', author: '张说', poem: '相百辟，贡八荒。\n九歌敍，万舞翔。\n肃振振，铿皇皇。\n帝欣欣，福穰穰。' },
  { title: '郊庙歌辞 封泰山乐章 豫和 四', author: '张说', poem: '高在上，道光明。\n物资始，德难名。\n承眷命，牧苍生。\n寰宇谧，太阶平。' },
  { title: '郊庙歌辞 封泰山乐章 豫和 五', author: '张说', poem: '天道无亲，至诚与邻。\n山川遍礼，宫征维新。\n玉帛非盛，聪明会真。\n正斯一德，通乎百神。' },
  { title: '郊庙歌辞 封泰山乐章 豫和 六', author: '张说', poem: '飨帝飨亲，维孝维圣。\n缉熙懿德，敷扬成命。\n华夷志同，笙镛礼盛。\n明灵降止，感此诚敬。' },
  { title: '郊庙歌辞 封泰山乐章 太和', author: '张说', poem: '孝敬中发，和容外彰。\n腾华照宇，如升太阳。\n贞璧就奠，玄灵垂光。\n礼乐具举，济济洋洋。' },
  { title: '郊庙歌辞 封泰山乐章 肃和', author: '张说', poem: '奠祖配天，承天享帝。\n百灵咸秩，四海来祭。\n植我苍璧，布我玄制。\n华日裴回，神烟容裔。' },
  { title: '郊庙歌辞 封泰山乐章 雍和', author: '张说', poem: '俎豆有馥，粢盛洁丰。\n亦有和羹，既戒既平。\n钟鼓管磬，肃唱和鸣。\n皇皇后祖，来我思成。' },
  { title: '郊庙歌辞 封泰山乐章 寿和', author: '张说', poem: '烝烝我后，享献惟夤。\n躬酌郁鬯，跪奠明神。\n孝莫孝乎，配上帝亲。\n敬莫敬乎，教天下臣。' },
  { title: '郊庙歌辞 封泰山乐章 舒和', author: '张说', poem: '六钟翕协六变成，八佾倘佯八风生。\n乐九[韶]兮人神感，美七德兮天地清。' },
  { title: '郊庙歌辞 封泰山乐章 凯安', author: '张说', poem: '烈祖顺三灵，文宗威四海。\n黄钺诛群盗，朱旗扫多罪。\n戢兵天下安，约法人心改。\n大哉干羽意，长见风云在。' },
  { title: '郊庙歌辞 封泰山乐章 豫和', author: '张说', poem: '乐已终，[烟]燎上。\n怀灵惠，结皇想。\n归风疾，回风爽。\n百[福]来，众神往。' },
  { title: '郊庙歌辞 祈谷乐章 肃和', author: '不详', poem: '履艮斯绳，居中体正。\n龙运垂祉，昭符启圣。\n式事严禋，聿怀嘉庆。\n惟帝永锡，时皇休命。' },
  { title: '郊庙歌辞 祈谷乐章 雍和', author: '不详', poem: '殷荐乘春，太坛临曙。\n八簋盈和，六瑚登御。\n嘉稷匪歆，德馨斯饫。\n祝嘏无易，灵心有豫。' },
  { title: '郊庙歌辞 祈谷乐章 舒和', author: '不详', poem: '玉帛牺牲申敬享，金丝𬭭羽盛音容。\n庶俾亿龄禔景福，长欣万宇洽时邕。' },
  { title: '郊庙歌辞 明堂乐章 肃和', author: '褚亮', poem: '象天御宇，乘时布政。\n严配申虔，宗禋展敬。\n罇罍盈列，树羽交映。\n玉币通诚，祚隆皇圣。' },
  { title: '郊庙歌辞 明堂乐章 雍和', author: '褚亮', poem: '八牖晨披，五精朝奠。\n雾凝璇篚，风清金县。\n神涤备全，明粢丰衍。\n载絜彝俎，陈诚以荐。' },
  { title: '郊庙歌辞 明堂乐章 舒和', author: '褚亮', poem: '御扆合宫承宝历，席图重馆奉明灵。\n偃武修文九围泰，沈烽静柝八荒宁。' },
  { title: '郊庙歌辞 武后明堂乐章 外办将出', author: '武则天', poem: '总章陈昔典，衢室礼惟神。\n宏规则天地，神用叶陶钧。\n负扆三春旦，充庭万宇宾。\n顾己诚虚薄，空慙亿兆人。' },
  { title: '郊庙歌辞 武后明堂乐章 皇帝行', author: '武则天', poem: '仰膺历数，俯顺讴歌。\n远安迩肃，俗阜时和。\n化光玉镜，讼息金科。\n方兴典礼，永戢干戈。' },
  { title: '郊庙歌辞 武后明堂乐章 皇嗣出入升降', author: '武则天', poem: '至人光俗，大孝通神。\n谦以表性，恭惟立身。\n洪规载启，茂典方陈。\n誉隆三善，祥开万春。' },
  { title: '郊庙歌辞 武后明堂乐章 迎送王公', author: '武则天', poem: '千官肃事，万国朝宗。\n载延百辟，爰集三宫。\n君臣德合，鱼水斯同。\n睿图方永，周历长隆。' },
  { title: '郊庙歌辞 武后明堂乐章 登歌', author: '武则天', poem: '礼崇宗祀，志表严禋。\n笙镛合奏，文物维新。\n敬遵茂典，敢择良辰。\n絜诚斯着，奠谒方申。' },
  { title: '郊庙歌辞 武后明堂乐章 配飨', author: '武则天', poem: '笙镛间玉宇，文物昭清晖。\n睟影临芳奠，休光下太微。\n孝思期有感，明絜庶无违。' },
  { title: '郊庙歌辞 武后明堂乐章 宫音', author: '武则天', poem: '履艮包群望，居中冠百灵。\n万方资广运，庶品荷财成。\n神功谅匪测，盛德实难名。\n藻奠申诚敬，恭祀表惟馨。' },
  { title: '郊庙歌辞 武后明堂乐章 角音', author: '武则天', poem: '出震位，开平秩。\n扇条风，乘甲乙。\n龙德盛，鸟星出。\n荐珪篚，陈诚实。' },
  { title: '郊庙歌辞 武后明堂乐章 徵音', author: '武则天', poem: '赫赫离精御炎陆，滔滔炽景开隆暑。\n冀延神鉴俯兰罇，式表虔襟陈桂俎。' },
  { title: '郊庙歌辞 武后明堂乐章 商音', author: '武则天', poem: '律中夷则，序应收成。\n功宣建武，义表惟明。\n爰申礼奠，庶展翘诚。\n九秋是式，百谷斯盈。' },
  { title: '郊庙歌辞 武后明堂乐章 羽音', author: '武则天', poem: '葭律肇启隆冬，苹藻攸陈飨祭。\n黄钟既陈玉烛，红粒方殷稔岁。' },
  { title: '郊庙歌辞 雩祀乐章 肃和', author: '褚亮', poem: '朱鸟开辰，苍龙启映。\n大帝昭飨，群生展敬。\n礼备怀柔，功宣舞咏。\n旬液应序，年祥协庆。' },
  { title: '郊庙歌辞 雩祀乐章 雍和', author: '褚亮', poem: '绀筵分彩，珤图吐绚。\n风管晨凝，云歌晓啭。\n肃事兰羞，虔申桂奠。\n百谷斯登，万箱攸荐。' },
  { title: '郊庙歌辞 雩祀乐章 舒和', author: '褚亮', poem: '凤曲登歌调令序，龙雩集舞泛祥风。\n彩旞云回昭睿德，朱干电发表神功。' },
  { title: '郊庙歌辞 雩祀乐章 豫和', author: '不详', poem: '鸟纬迁序，龙星见辰。\n纯阳在律，明德崇禋。\n五方降帝，万宇安人。\n恭以致享，肃以迎神。' },
  { title: '郊庙歌辞 五郊乐章 黄帝宫音', author: '魏征', poem: '黄中正位，含章居贞。\n既长六律，兼和五声。\n毕陈万舞，乃荐斯牲。\n神其下降，永祚休平。' },
  { title: '郊庙歌辞 五郊乐章 黄帝宫音 肃和', author: '魏征', poem: '眇眇方舆，苍苍圜盖。\n至哉枢纽，宅中图大。\n气调四序，风和万籁。\n祚我明德，时雍道泰。' },
  { title: '郊庙歌辞 五郊乐章 黄帝宫音 雍和', author: '魏征', poem: '金县夕肆，玉俎朝陈。\n飨荐黄道，芬流紫宸。\n迺诚迺敬，载享载禋。\n崇荐斯在，惟皇是宾。' },
  { title: '郊庙歌辞 五郊乐章 黄帝宫音 舒和', author: '魏征', poem: '御征乘宫出郊甸，安歌率舞递将迎。\n自有云门符帝赏，犹持雷鼓答天成。' },
  { title: '郊庙歌辞 五郊乐章 青帝角音', author: '魏征', poem: '鹤云旦起，鸟星昏集。\n律候新风，阳开初蛰。\n至德可飨，行潦斯挹。\n锡以无疆，蒸人乃粒。' },
  { title: '郊庙歌辞 五郊乐章 青帝角音 肃和', author: '魏征', poem: '玄鸟司春，苍龙登岁。\n节物变柳，光风转蕙。\n瑶席降神，朱弦飨帝。\n诚备祝嘏，礼殚珪币。' },
  { title: '郊庙歌辞 五郊乐章 青帝角音 雍和', author: '魏征', poem: '大乐稀音，至诚简礼。\n文物棣棣，声明济济。\n六变有成，三登无体。\n乃眷丰洁，恩覃恺悌。' },
  { title: '郊庙歌辞 五郊乐章 青帝角音 舒和', author: '魏征', poem: '笙歌籥舞属年韶，鹭鼓凫钟展时豫。\n调露初迎绮春节，承云遽践苍霄驭。' },
  { title: '郊庙歌辞 五郊乐章 赤帝徵音', author: '魏征', poem: '青阳告谢，朱明戒序。\n延长是祈，敬陈椒醑。\n博硕斯荐，笙镛备举。\n庶尽肃恭，非馨稷黍。' },
  { title: '郊庙歌辞 五郊乐章 赤帝徵音 肃和', author: '魏征', poem: '离位克明，火中宵见。\n峰云暮起，景风晨扇。\n木槿初荣，含桃可荐。\n芬馥百品，铿锵三变。' },
  { title: '郊庙歌辞 五郊乐章 赤帝徵音 雍和', author: '魏征', poem: '昭昭丹陆，奕奕炎方。\n礼陈牲币，乐备篪簧。\n琼羞溢俎，玉醑浮觞。\n恭惟正直，歆此馨香。' },
  { title: '郊庙歌辞 五郊乐章 赤帝徵音 舒和', author: '魏征', poem: '千里温风飘绛羽，十枝炎景賸朱干。\n陈觞荐俎歌二献，拊石𪭢金会七盘。' },
  { title: '郊庙歌辞 五郊乐章 白帝商音', author: '魏征', poem: '白藏应节，天高气清。\n岁功既阜，庶类收成。\n万方静谧，九土和平。\n馨香是荐，受祚聪明。' },
  { title: '郊庙歌辞 五郊乐章 白帝商音 肃和', author: '魏征', poem: '金行在节，素灵居正。\n气肃霜严，林雕草劲。\n豺祭隼击，潦收川镜。\n九谷已登，万箱流咏。' },
  { title: '郊庙歌辞 五郊乐章 白帝商音 雍和', author: '魏征', poem: '律应西成，气躔南吕。\n珪币咸列，笙竽备举。\n苾苾兰羞，芬芬桂醑。\n式资宴贶，用调霜序。' },
  { title: '郊庙歌辞 五郊乐章 白帝商音 舒和', author: '魏征', poem: '璇仪气爽惊缇籥，玉吕灰飞含素商。\n鸣鞞奏管芳羞荐，会舞安歌葆眊扬。' },
  { title: '郊庙歌辞 五郊乐章 黑帝羽音', author: '魏征', poem: '严冬季月，星回风厉。\n享祀报功，方祚来岁。' },
  { title: '郊庙歌辞 五郊乐章 黑帝羽音 肃和', author: '魏征', poem: '律回玉琯，星周金度。\n次极阳乌，纪穷阴兔。\n火林霰雪，阳泉凝冱。\n八蜡已登，三农息务。' },
  { title: '郊庙歌辞 五郊乐章 黑帝羽音 雍和', author: '魏征', poem: '阳月斯纪，应钟在候。\n载洁牲牷，爰登俎豆。\n既高既远，无声无臭。\n静言格思，惟神保祐。' },
  { title: '郊庙歌辞 五郊乐章 黑帝羽音 舒和', author: '魏征', poem: '执籥持羽初终曲，朱干玉𬭭始分行。\n七德九功咸已畅，明灵降福具穰穰。' },
  { title: '郊庙歌辞 五郊乐章 黄郊迎神', author: '不详', poem: '朱明季序，黄郊王辰。\n厚以载物，甘以养人。\n毓金为体，禀火成身。\n宫音式奏，奏以迎神。' },
  { title: '郊庙歌辞 五郊乐章 送神', author: '不详', poem: '春末冬暮，徂夏杪秋。\n土王四月，时季一周。\n黍稷已享，笾豆宜收。\n送神有乐，神其赐休。' },
  { title: '郊庙歌辞 五郊乐章 青郊迎神', author: '不详', poem: '缇幕移候，青郊启蛰。\n淑景迟迟，和风习习。\n璧玉宵备，旌旄曙立。\n张乐以迎，帝神其入。' },
  { title: '郊庙歌辞 五郊乐章 赤郊迎神', author: '不详', poem: '青阳节谢，朱明候改。\n靡草雕华，含桃流彩。\n虡列钟磬，筵陈脯醢。\n乐以迎神，神其如在。' },
  { title: '郊庙歌辞 五郊乐章 白郊迎神', author: '不详', poem: '序移玉律，节应金商。\n天严杀气，吹警秋方。\n槱燎既积，稷奠并芳。\n乐以迎奏，庶降神光。' },
  { title: '郊庙歌辞 五郊乐章 黑郊迎神', author: '不详', poem: '玄英戒序，黑郊临候。\n掌礼陈彝，司筵执豆。\n寒氛敛色，沍泉凝漏。\n乐以迎神，八音斯奏。' },
  { title: '郊庙歌辞 朝日乐章 肃和', author: '不详', poem: '惟圣格天，惟明飨日。\n帝郊肆类，王宫戒吉。\n珪奠春舒，钟歌晓溢。\n礼云克备，斯文有秩。' },
  { title: '郊庙歌辞 朝日乐章 雍和', author: '不详', poem: '晨仪式荐，明祀惟光。\n神物爰止，灵晖载扬。\n玄端肃事，紫幄兴祥。\n福履攸假，于昭允王。' },
  { title: '郊庙歌辞 朝日乐章 舒和', author: '不详', poem: '崇牙树羽延调露，旋宫扣律掩承云。\n诞敷懿德昭神武，载集丰功表睿文。' },
  { title: '郊庙歌辞 朝日乐章 迎神', author: '不详', poem: '太阳朝序，王宫有仪。\n蟠桃彩驾，细柳光驰。\n轩祥表合，汉历彰奇。\n礼和乐备，神其降斯。' },
  { title: '郊庙歌辞 朝日乐章 送神', author: '不详', poem: '五齐兼酌，百羞具陈。\n乐终广奏，礼毕崇禋。\n明鉴万宇，照临兆人。\n永流洪庆，式动曦轮。' },
  { title: '郊庙歌辞 夕月乐章 肃和', author: '不详', poem: '测妙为神，通微曰圣。\n坎祀贻则，郊禋展敬。\n璧荐登光，金歌动映。\n以载嘉德，以流曾庆。' },
  { title: '郊庙歌辞 夕月乐章 雍和', author: '不详', poem: '朏晨争举，天宗礼辟。\n夜典凉秋，阴明湛夕。\n有𨠨斯旨，有牲斯硕。\n穆穆其晖，穰穰是积。' },
  { title: '郊庙歌辞 夕月乐章 舒和', author: '不详', poem: '合吹八风金奏动，分容万舞玉鞘惊。\n词昭茂典光前列，夕曜乘功表盛明。' },
  { title: '郊庙歌辞 祀九宫贵神乐章 豫和 一', author: '不详', poem: '于昭上穹，临下有光。\n羽翼五佐，周流八荒。\n谁其飨之，时文对敭。\n虞经夏典，兹礼未遑。' },
  { title: '郊庙歌辞 祀九宫贵神乐章 豫和 二', author: '不详', poem: '黑帝旋驭，青躔导日。\n金箓上玄，玉堂初吉。\n钩陈夕次，銮和先跸。\n蔼蔼群灵，昭昭咸秩。' },
  { title: '郊庙歌辞 祀九宫贵神乐章 豫和 三', author: '不详', poem: '帝临中坛，受厘元神。\n皇灵萃止，羽旄肃陈。\n摄提运衡，招摇移轮。\n光光宇宙，电耀雷震。' },
  { title: '郊庙歌辞 祀九宫贵神乐章 豫和 四', author: '不详', poem: '夜如何其，明星煌煌。\n天清容卫，露结坛场。\n树羽幢幢，佩玉锵锵。\n凝精驻目，瞻望神光。' },
  { title: '郊庙歌辞 祀九宫贵神乐章 豫和 五', author: '不详', poem: '九位既肃，万灵毕会。\n天门启扄，日驭飞盖。\n焕兮棽离，傧兮暗霭。\n如山之福，惟圣时对。' },
  { title: '郊庙歌辞 祀九宫贵神乐章 豫和 六', author: '不详', poem: '崇崇泰坛，灵具临兮。\n铿锽大乐，振动心兮。\n神之降矣，卿云郁兮。\n神之至止，清风肃兮。' },
  { title: '郊庙歌辞 祀九宫贵神乐章 太和', author: '不详', poem: '帝在灵坛，大明登光。\n天回云粹，穆穆皇皇。\n金奏九夏，圭陈八芗。\n旷哉动植，如熙春阳。' },
  { title: '郊庙歌辞 祀九宫贵神乐章 肃和', author: '不详', poem: '歌工既奏，神位既秩。\n天符众星，运行太一。\n声和十管，气应中律。\n肃肃明廷，介兹元吉。' },
  { title: '郊庙歌辞 祀九宫贵神乐章 雍和', author: '不详', poem: '俎豆有践，黄流在尊。\n九宫之祀，三代莫存。\n乐变六宫，坛开八门。\n圣皇昭对，祐我黎元。' },
  { title: '郊庙歌辞 祀九宫贵神乐章 寿和', author: '不详', poem: '时文哲后，肃事严禋。\n馨我明德，享于贵神。\n大庖载盈，旨酒斯醇。\n精意所属，期于利人。' },
  { title: '郊庙歌辞 祀九宫贵神乐章 福和', author: '不详', poem: '祀既云毕，明灵告旋。\n礼洽和应，神歆福延。\n动植咸若，阴阳不愆。\n锡兹纯嘏，天子万年。' },
  { title: '郊庙歌辞 祀九宫贵神乐章 舒和', author: '不详', poem: '羽籥既阕干戚陈，八音克谐六变新。\n愉贵神兮般以乐，保皇祚兮万斯春。' },
  { title: '郊庙歌辞 祀九宫贵神乐章 凯安', author: '不详', poem: '盛德陈万舞，威棱畅九垓。\n风云交律候，日月丽昭回。\n行庆休祥发，乘和春气来。\n百神肃临享，荡荡天门开。' },
  { title: '郊庙歌辞 祀九宫贵神乐章 豫和', author: '不详', poem: '享申百礼，庆洽百灵。\n上排阊阖，洞入杳冥。\n奠玉高坛，燔柴广庭。\n神之降福，万国咸宁。' },
  { title: '郊庙歌辞 祀风师乐章 迎神', author: '包佶', poem: '太皞御气，句芒肇功。\n苍龙青旗，爰候祥风。\n律以和应，神以感通。\n鼎俎修蚃，时惟礼崇。' },
  { title: '郊庙歌辞 祀风师乐章 奠币登歌', author: '包佶', poem: '旨酒告絜，青苹应候。\n礼陈瑶币，乐献金奏。\n弹弦自昔，解冻惟旧。\n仰瞻肸蚃，群祥来凑。' },
  { title: '郊庙歌辞 祀风师乐章 迎俎酌献', author: '包佶', poem: '德盛昭临，迎拜巽方。\n爰候发生，式荐馨香。\n酌醴具举，工歌载扬。\n神歆六律，恩降百祥。' },
  { title: '郊庙歌辞 祀风师乐章 亚献终献', author: '包佶', poem: '膋芗备，玉帛陈。\n风动物，乐感神。\n三献终，百神臻。\n草木荣，天下春。' },
  { title: '郊庙歌辞 祀风师乐章 送神', author: '包佶', poem: '微穆敷华能应节，飘扬发彩宜行庆。\n送迎灵驾神心享，跪拜灵坛礼容盛。\n气和草木发萌芽，德畅禽鱼遂翔泳。\n永望翠盖逐流云，自兹率土调春令。' },
  { title: '郊庙歌辞 祀雨师乐章 迎神', author: '包佶', poem: '陟降左右，诚达幽圜。\n作解之功，乐惟有年。\n云𫐌戾止，洒雾飘烟。\n惟馨展礼，爰列豆笾。' },
  { title: '郊庙歌辞 祀雨师乐章 奠币登歌', author: '包佶', poem: '岁正朱明，礼布元制。\n惟乐能感，与神合契。\n阴雾离翍，灵驭摇裔。\n膏泽之庆，期于稔岁。' },
  { title: '郊庙歌辞 祀雨师乐章 迎俎酌献', author: '包佶', poem: '阳开幽蛰，躬奉郁鬯。\n礼备节应，震来灵降。\n动植求声，飞沈允望。\n时康气茂，惟神之贶。' },
  { title: '郊庙歌辞 祀雨师乐章 亚献终献', author: '包佶', poem: '奠既备，献将终。\n神行令，瑞飞空。\n迎干德，祈岁功。\n乘烟燎，俨从风。' },
  { title: '郊庙歌辞 祀雨师乐章 送神', author: '包佶', poem: '整驾升车望寥廓，垂阴荐祉荡昏氛。\n飨时灵贶僾如在，乐罢余声遥可闻。\n饮福陈诚礼容备，撤俎终献曙光分。\n跪拜临坛结空想，年年应节候油云。' },
  { title: '郊庙歌辞 祭方丘乐章 顺和', author: '褚亮', poem: '万方资以化，交泰属升平。\n易从业惟简，得一道斯宁。\n具仪光玉帛，送舞变咸英。\n黍稷良非贵，明德信惟馨。' },
  { title: '郊庙歌辞 祭方丘乐章 肃和', author: '褚亮', poem: '至矣坤德，皇哉地祇。\n开元统纽，合大承规。\n九宫肃列，六典相仪。\n永言配命，长保无亏。' },
  { title: '郊庙歌辞 祭方丘乐章 雍和', author: '褚亮', poem: '柔而能方，直而能敬。\n载厚以德，大亨以正。\n有涤斯牷，有馨斯盛。\n介兹景福，祚我休庆。' },
  { title: '郊庙歌辞 祭方丘乐章 舒和', author: '褚亮', poem: '玉币牲牷分荐享，羽旄干𬭭遰成容。\n一德惟宁两仪泰，三才保合四时邕。' },
  { title: '郊庙歌辞 武后大享拜洛乐章 昭和', author: '不详', poem: '九玄眷命，三圣基隆。\n奉承先旨，明台毕功。\n宗祀展敬，冀表深衷。\n永昌帝业，式播淳风。' },
  { title: '郊庙歌辞 武后大享拜洛乐章 致和', author: '不详', poem: '神功不测兮运阴阳，包藏万宇兮孕八荒。\n天符既出兮帝业昌，愿临明祀兮降祯祥。' },
  { title: '郊庙歌辞 武后大享拜洛乐章 咸和', author: '不详', poem: '坎泽祠容备举，坤坛祭典爰申。\n灵睠遥行秘躅，嘉贶荐委殊珍。\n肃礼恭禋载展，翘襟邈志逾殷。\n方期交际悬应。' },
  { title: '郊庙歌辞 武后大享拜洛乐章 九和', author: '不详', poem: '祗荷坤德，钦若干灵。\n慙惕罔寘，兴居匪宁。\n恭崇礼则，肃奉仪形。\n惟凭展敬，敢荐非馨。' },
  { title: '郊庙歌辞 武后大享拜洛乐章 显和', author: '不详', poem: '菲躬承睿顾，薄德忝坤仪。\n干干遵后命，翼翼奉先规。\n抚俗勤虽切，还淳化尚亏。\n未能弘至道，何以契明祇。' },
  { title: '郊庙歌辞 武后大享拜洛乐章 敬和', author: '不详', poem: '兰俎既升，苹羞可荐。\n金石载设，咸英已变。\n林泽斯总，山川是遍。\n敢用敷诚，实惟忘倦。' },
  { title: '郊庙歌辞 武后大享拜洛乐章 齐和', author: '不详', poem: '沈潜演贶分三极，广大凝祯总万方。\n既荐羽旌文化启，还呈干𬭭武威扬。' },
  { title: '郊庙歌辞 武后大享拜洛乐章 德和', author: '不详', poem: '夕惕司龙契，晨兢当凤扆。\n崇儒习旧规，偃伯循先旨。\n绝壤飞冠盖，遐区丽山水。\n幸承三圣余，忻属千年始。' },
  { title: '郊庙歌辞 武后大享拜洛乐章 禋和', author: '不详', poem: '百礼崇容，千官肃事。\n灵降无兆，神凝有粹。\n奠享咸周，威仪毕备。\n奏夏登列，歌雍彻肆。' },
  { title: '郊庙歌辞 武后大享拜洛乐章 通和', author: '不详', poem: '皇皇灵睠，穆穆神心。\n暂动凝质，还归积阴。\n功玄枢纽，理寂高深。\n衔恩佩德，耸志翘襟。' },
  { title: '郊庙歌辞 武后大享拜洛乐章 归和', author: '不详', poem: '言旋云洞兮蹑烟途，永宁中宇兮安下都。\n包涵动植兮顺荣枯，长贻宝贶兮赞璇图。' },
  { title: '郊庙歌辞 武后大享拜洛乐章 又归和', author: '不详', poem: '调云阕兮神座兴，骖云驾兮俨将升。\n腾绛霄兮垂景祐，翘丹恳兮荷休征。' },
  { title: '郊庙歌辞 祭方丘乐章 顺和', author: '不详', poem: '坤厚载物，德柔垂祉。\n九域咸雍，四溟为纪。\n敬因良节，虔修阴祀。\n广乐式张，灵其降止。' },
  { title: '郊庙歌辞 祭方丘乐章 金奏', author: '不详', poem: '坤元至德，品物资生。\n神凝博厚，道协高明。\n列镇五岳，环流四瀛。\n于何不载，万宝斯成。' },
  { title: '郊庙歌辞 祭汾阴乐章 顺和', author: '林钟宫', poem: '大乐和畅，殷荐明神。\n一降通感，八变必臻。\n有求斯应，无德不亲。\n降灵醉止，休征万人。' },
  { title: '郊庙歌辞 祭汾阴乐章 太簇角', author: '卢从愿', poem: '坤元载物，阳乐发生。\n播殖资始，品汇咸亨。\n列俎棋布，方坛砥平。\n神歆禋祀，后德惟明。' },
  { title: '郊庙歌辞 祭汾阴乐章 姑洗征', author: '刘晃', poem: '大君出震，有事郊禋。\n斋戒既肃，馨香毕陈。\n乐和礼备，候暖风春。\n恭惟降福，实赖明神。' },
  { title: '郊庙歌辞 祭汾阴乐章 南吕羽', author: '韩休', poem: '於穆濬哲，维清缉熙。\n肃事昭配，永言孝思。\n涤濯静嘉，馨香在兹。\n神之听之，用受福厘。' },
  { title: '郊庙歌辞 祭汾阴乐章 太和', author: '王晙', poem: '於穆圣皇，六叶重光。\n太原刻颂，后土疎场。\n宝鼎呈符，歊云孕祥。\n礼乐备矣，降福穰穰。' },
  { title: '郊庙歌辞 祭汾阴乐章 肃和', author: '崔玄童', poem: '聿修严配，展事禋宗。\n祥符宝鼎，礼备黄琮。\n[祝]词以信，明德惟聪。\n介兹景福，永永无穷。' },
  { title: '郊庙歌辞 祭汾阴乐章 雍和', author: '贾曾', poem: '蠲我饎餴，絜我膋芗。\n有豆孔硕，为羞既臧。\n至诚无昧，精意惟芳。\n神其醉止，欣欣乐康。' },
  { title: '郊庙歌辞 祭汾阴乐章 寿和', author: '苏颋', poem: '礼物斯具，乐章乃陈。\n谁其作主，皇考圣真。\n对越在天，圣明佐神。\n窅然汾上，厚泽如春。' },
  { title: '郊庙歌辞 祭汾阴乐章 舒和', author: '何鸾', poem: '乐奏云阕，礼章载虔。\n禋宗于地，昭假于天。\n惟馨荐矣，既醉歆焉。\n神之降福，永永万年。' },
  { title: '郊庙歌辞 祭汾阴乐章 凯安', author: '蒋挺', poem: '维岁之吉，维辰之良。\n圣君绂冕，肃事坛场。\n大礼已备，大乐斯[张]。\n神其醉止，降福无疆。' },
  { title: '郊庙歌辞 祭汾阴乐章 顺和', author: '源光裕', poem: '方丘既膳，嘉飨载谧。\n齐敬毕诚，陶匏贵质。\n秀毕丰荐，芳俎盈实。\n永永福流，其升如日。' },
  { title: '郊庙歌辞 禅社首乐章 顺和', author: '贺知章、源乾曜', poem: '至哉含柔德，万物资以生。\n常顺称厚载，流谦通变盈。\n圣心事能察，增广陈厥诚。\n黄祇僾如在，泰折俟咸亨。' },
  { title: '郊庙歌辞 禅社首乐章 太和', author: '贺知章、源乾曜', poem: '肃我成命，于昭黄祇。\n裘冕而祀，陟降在斯。\n五音克备，八音聿施。\n缉熙肆靖，厥心匪离。' },
  { title: '郊庙歌辞 禅社首乐章 肃和', author: '贺知章、源乾曜', poem: '黄祇是[祗]，我其夙夜。\n寅畏诚絜，匪遑宁舍。\n礼以琮玉，荐厥茅藉。\n念兹降康，胡宁克暇。' },
  { title: '郊庙歌辞 禅社首乐章 雍和', author: '贺知章、源乾曜', poem: '夙夜宥密，不敢宁宴。\n五齐既陈，八音在县。\n粢盛以洁，房俎斯荐。\n惟德惟馨，尚兹克徧。' },
  { title: '郊庙歌辞 禅社首乐章 寿和', author: '贺知章、源乾曜', poem: '惟以明发，有怀载殷。\n乐盈而反，礼顺其禋。\n立清以献，荐欲是亲。\n於穆不已，裒对斯臻。' },
  { title: '郊庙歌辞 禅社首乐章 福和', author: '贺知章、源乾曜', poem: '穆穆天子，告成岱宗。\n大裘如濡，执珽有颙。\n乐以平志，礼以和容。\n上帝临我，云胡肃邕。' },
  { title: '郊庙歌辞 禅社首乐章 灵具醉', author: '贺知章、源乾曜', poem: '灵具醉，杳熙熙。\n灵将往，眇禗禗。\n顾明德，吐正辞。\n烂遗光，流祯祺。' },
  { title: '郊庙歌辞 祭神州乐章 肃和', author: '褚亮', poem: '大矣坤仪，至哉神县。\n包含日域，牢笼月竁。\n露絜三清，风调六变。\n皇祇介祉，式歆恭荐。' },
  { title: '郊庙歌辞 祭神州乐章 雍和', author: '褚亮', poem: '泰折严享，阴郊展敬。\n礼以导神，乐以和性。\n黝牲在列，黄琮俯暎。\n九土既平，万邦贻庆。' },
  { title: '郊庙歌辞 祭神州乐章 舒和', author: '褚亮', poem: '坤道降祥和庶品，灵心载德厚群生。\n水土既调三极泰，文武毕备九区平。' },
  { title: '郊庙歌辞 祭神州乐章 迎神', author: '不详', poem: '黄舆厚载，赤寰归德。\n含育九区，保安万国。\n诚敬无怠，禋祀有则。\n乐以迎神，其仪不忒。' },
  { title: '郊庙歌辞 祭神州乐章 送神', author: '不详', poem: '神州阴祀，洪恩广济。\n草树沾和，飞沈沐惠。\n礼修鼎俎，奠歆瑶币。\n送乐有章，灵轩其逝。' },
  { title: '郊庙歌辞 祭[太]社乐章 肃和', author: '褚亮', poem: '后土凝德，神功协契。\n九域底平，两仪交际。\n戊期应序，阴墉展币。\n灵车少留，俯歆樽桂。' },
  { title: '郊庙歌辞 祭[太]社乐章 雍和', author: '褚亮', poem: '美报崇本，严恭展事。\n受露疎坛，承风启地。\n絜粢登俎，醇牺入馈。\n介福远流，群生毕遂。' },
  { title: '郊庙歌辞 祭[太]社乐章 舒和', author: '褚亮', poem: '神道发生敷九稼，阴极乘仁畅八埏。\n纬武经文隆景化，登祥荐祉启丰年。' },
  { title: '郊庙歌辞 祭大社乐章 迎神', author: '不详', poem: '烈山有子，后土有臣。\n播种百谷，济育兆人。\n春官缉礼，宗伯司禋。\n戊为吉日，迎享兹辰。' },
  { title: '郊庙歌辞 祭大社乐章 送神', author: '不详', poem: '吉祥式就，酬功载毕。\n亲地尊天，礼文经术。\n贶征令序，福流初日。\n神驭爰归，祠官其出。' },
  { title: '郊庙歌辞 蜡百神乐章 肃和', author: '不详', poem: '序迫岁阴，日躔星纪。\n爰稽茂典，聿崇清祀。\n绮币霞舒，瑞珪虹起。\n百禩垂裕，万灵荐祉。' },
  { title: '郊庙歌辞 蜡百神乐章 雍和', author: '不详', poem: '缇籥劲序，玄英晚候。\n姬蜡开仪，豳歌入奏。\n蕙馥雕俎，兰芬玉酎。\n大享明祇，永绥多祐。' },
  { title: '郊庙歌辞 蜡百神乐章 舒和', author: '不详', poem: '经纬两仪文化洽，削平方域武功成。\n瑶弦自乐乾坤泰，玉𬭭长欢区宇宁。' },
  { title: '郊庙歌辞 蜡百神乐章 迎神', author: '不详', poem: '八蜡开祭，万物合祀。\n上极天维，下穷坤纪。\n鼎俎流芬，罇彝荐美。\n有灵有祇，咸希来止。' },
  { title: '郊庙歌辞 蜡百神乐章 送神', author: '不详', poem: '十旬欢洽，一日祠终。\n澄彝拂俎，报德酬功。\n虑虔容肃，礼缛仪丰。\n神其降祉，整驭随风。' },
  { title: '郊庙歌辞 享先农乐章 咸和', author: '褚亮', poem: '粒食伊始，农之所先。\n古今攸赖，是曰人天。\n耕斯帝籍，播厥公田。\n式崇明祀，神其福焉。' },
  { title: '郊庙歌辞 享先农乐章 肃和', author: '褚亮', poem: '樽彝既列，瑚簋方荐。\n歌工载登，币礼斯奠。\n肃肃享祀，颙颙缨弁。\n神之听之，福流寰县。' },
  { title: '郊庙歌辞 享先农乐章 雍和', author: '褚亮', poem: '前夕视牲，质明奉俎。\n沐芳整弁，其仪式序。\n盛礼毕陈，嘉乐备举。\n歆我懿德，非馨稷黍。' },
  { title: '郊庙歌辞 享先农乐章 舒和', author: '褚亮', poem: '羽籥低昂文缀已，干戚蹈厉武行初。\n望岁祈农神所听，延祥介福岂云虚。' },
  { title: '郊庙歌辞 享先农乐章 咸和', author: '不详', poem: '三推礼就，万庾祈凝。\n夤宾志远，藨衮惟兴。\n降歆肃荐，垂祐祗膺。\n送神有乐，神其上升。' },
  { title: '郊庙歌辞 享先蚕乐章 永和', author: '不详', poem: '芳春开令序，韶苑畅和风。\n惟灵申广祐，利物表神功。\n绮会周天宇，黼黻藻寰中。\n庶几承庆节，歆奠下帷宫。' },
  { title: '郊庙歌辞 享先蚕乐章 肃和', author: '不详', poem: '明灵光至德，深功掩百神。\n祥源应节启，福绪逐年新。\n万宇承恩覆，七庙伫恭禋。\n于兹申至恳，方期远庆臻。' },
  { title: '郊庙歌辞 享先蚕乐章 展敬', author: '不详', poem: '霞庄列宝卫，云集动和声。\n金卮荐绮席，玉币委芳庭。\n因心罄丹款，先己励苍生。\n所冀延明福，于兹享至诚。' },
  { title: '郊庙歌辞 享先蚕乐章 絜诚', author: '不详', poem: '桂筵开玉俎，兰圃荐琼芳。\n八音调凤历，三献奉鸾觞。\n絜粢申大享，庭宇冀降祥。\n神其覃有庆，契福永无疆。' },
  { title: '郊庙歌辞 享先蚕乐章 昭庆', author: '不详', poem: '仙坛礼既毕，神驾俨将升。\n伫属深祥起，方期庶绩凝。\n虔诚资宇内，务本勖黎蒸。\n灵心昭备享，率土洽休征。' },
  { title: '郊庙歌辞 释奠文宣王乐章 诚和', author: '不详', poem: '圣道日用，神几不测。\n金石以陈，弦歌载陟。\n爰释其菜，匪馨于稷。\n来顾来享，是宗是极。' },
  { title: '郊庙歌辞 释奠文宣王乐章 承和', author: '不详', poem: '万国以贞光上嗣，三善茂德表重轮。\n视膳寝门尊要道，高辟崇贤引正人。' },
  { title: '郊庙歌辞 释奠文宣王乐章 肃和', author: '不详', poem: '粤惟上圣，有纵自天。\n傍周万物，俯应千年。\n旧章允着，嘉贽孔虔。\n王化兹首，儒风是宣。' },
  { title: '郊庙歌辞 释奠文宣王乐章 雍和', author: '不详', poem: '堂献瑶篚，庭敷璆县。\n礼备其容，乐和其变。\n肃肃亲享，雍雍执奠。\n明德惟馨，苹蘩可荐。' },
  { title: '郊庙歌辞 释奠文宣王乐章 舒和', author: '不详', poem: '隼集龟开昭圣烈，龙蹲凤跱肃神仪。\n尊儒敬业宏图阐，纬武经文盛德施。' },
  { title: '郊庙歌辞 享孔子庙乐章 迎神', author: '不详', poem: '通吴表圣，问老探真。\n三千弟子，五百贤人。\n亿龄规法，万载嗣禋。\n洁诚以祭，奏乐迎神。' },
  { title: '郊庙歌辞 享孔子庙乐章 送神', author: '不详', poem: '醴溢牺象，羞陈俎豆。\n鲁壁类闻，泗川入觏。\n里校覃福，胄筵承祐。\n雅乐清音，送神具奏。' },
  { title: '郊庙歌辞 释奠武成王乐章 迎神', author: '于邵', poem: '卜畋不从，兆发非熊。\n乃倾荒政，爰佐一戎。\n盛烈载垂，命祀惟崇。\n日练上戊，宿严閟宫。\n迎奏嘉至，感而遂通。' },
  { title: '郊庙歌辞 释奠武成王乐章 奠币登歌', author: '于邵', poem: '管磬升，膻芗集。\n上公进，嘉币执。\n信以通，僾如及。\n恢帝功，锡后邑。\n四维张，百度立。\n绵亿载，邈难挹。' },
  { title: '郊庙歌辞 释奠武成王乐章 迎俎酌献', author: '于邵', poem: '五齐洁，九牢硕。\n梡橛循，罍斝涤。\n进具物，扬鸿绩。\n和奏发，高灵寂。\n虔告终，繁祉锡。\n昭秩祀，永无易。' },
  { title: '郊庙歌辞 释奠武成王乐章 亚献终献', author: '于邵', poem: '贰觞以献，三变其终。\n顾此非馨，尚达斯衷。\n茅缩可致，神歆载融。\n始神翊周，拯溺除凶。\n时维降祐，永绝兴戎。' },
  { title: '郊庙歌辞 释奠武成王乐章 送神', author: '于邵', poem: '明祀方终，备乐斯阕。\n黝𫄸就瘗，豆笾告撤。\n肸蚃尚余，光景云灭。\n返归虚极，神心则悦。' },
  { title: '郊庙歌辞 享龙池乐章 第一章', author: '姚崇', poem: '恭闻帝里生灵沼，应报明君鼎业新。\n既协翠泉光宝命，还符白水出真人。\n此时舜海潜龙跃，此地尧河带马巡。\n独有前池一小雁，叨承旧惠入天津。' },
  { title: '郊庙歌辞 享龙池乐章 第二章', author: '蔡孚', poem: '帝宅王家大道边，神马龙龟涌圣泉。\n昔日昔时经此地，看来看去渐成川。\n歌台舞榭宜正月，柳岸梅洲胜往年。\n莫言波上春云少，祗为从龙直上天。' },
  { title: '郊庙歌辞 享龙池乐章 第三章', author: '沈佺期', poem: '龙池跃龙龙已飞，龙德[光]天天不违。\n池开天汉分黄道，龙向天门入紫微。\n邸第楼台多气色，君王凫雁有光辉。\n为报寰中百川水，来朝此地莫东归。' },
  { title: '郊庙歌辞 享龙池乐章 第四章', author: '卢怀慎', poem: '代邸东南龙跃泉，清漪碧浪远浮天。\n楼台影就波中出，日月光疑镜里悬。\n雁沼回流成舜海，龟书荐祉应尧年。\n大川既济慙为檝，报德空思奉细涓。' },
  { title: '郊庙歌辞 享龙池乐章 第五章', author: '姜皎', poem: '龙池初出此龙山，常经此地谒龙颜。\n日日芙蓉生夏水，年年杨柳变春湾。\n尧坛宝匣余烟雾，舜海渔舟尚往还。\n愿似飘飖五云影，从来从去九天间。' },
  { title: '郊庙歌辞 享龙池乐章 第六章', author: '崔日用', poem: '龙兴白水汉兴符，圣主时乘运斗枢。\n岸上丰茸五花树，波中的皪千金珠。\n操环昔闻迎夏启，发匣先来瑞有虞。\n风色云光随隐见，赤云神化象江湖。' },
  { title: '郊庙歌辞 享龙池乐章 第七章', author: '苏颋', poem: '西京凤邸跃龙泉，佳气休光镇在天。\n轩后雾图今已得，秦王水劒昔常传。\n恩鱼不似昆明钓，瑞鹤长如太液仙。\n愿侍巡游同旧里，更闻箫鼓济楼船。' },
  { title: '郊庙歌辞 享龙池乐章 第八章', author: '李乂', poem: '星分邑里四人居，水洊源流万顷余。\n魏国君王称象处，晋家藩邸化龙初。\n青蒲暂似游梁马，绿藻还疑宴镐鱼。\n自有神灵滋液地，年年云物史官书。' },
  { title: '郊庙歌辞 享龙池乐章 第九章', author: '姜皎', poem: '灵沼萦回邸第前，浴日涵天写曙天。\n始见龙台升凤阙，应如霄汉起神泉。\n石匮渚傍还启圣，桃李初生更有仙。\n欲化帝图从此受，正同河变一千年。' },
  { title: '郊庙歌辞 享龙池乐章 第十章', author: '裴璀', poem: '乾坤启圣吐龙泉，泉水年年胜一年。\n始看鱼跃方成海，即覩龙飞利在天。\n洲渚遥将银汉接，楼台直与紫微连。\n休气荣光常不散，悬知此地是神仙。' },
  { title: '郊庙歌辞 享太庙乐章 永和', author: '魏征、褚亮', poem: '於穆烈祖，弘此丕基。\n永言配命，子孙保之。\n百神既洽，万国在兹。\n是用孝享，神其格思。' },
  { title: '郊庙歌辞 享太庙乐章 肃和', author: '魏征、褚亮', poem: '大哉至德，允兹明圣。\n格于上下，聿遵诚敬。\n嘉乐斯登，鸣球以咏。\n神其降止，式隆景命。' },
  { title: '郊庙歌辞 享太庙乐章 雍和', author: '魏征、褚亮', poem: '崇兹享祀，诚敬兼至。\n乐以感灵，礼以昭事。\n粢盛咸絜，牲牷孔备。\n永言孝思，庶几不匮。' },
  { title: '郊庙歌辞 享太庙乐章 长发舞', author: '魏征、褚亮', poem: '睿哲维唐，长发其祥。\n帝命斯祐，王业克昌。\n配天载德，就日重光。\n本支百代，申锡无疆。' },
  { title: '郊庙歌辞 享太庙乐章 大基舞', author: '魏征、褚亮', poem: '猗与祖业，皇矣帝先。\n翦商德厚，封唐庆延。\n在姬犹稷，方晋喻宣。\n基我鼎运，于万斯年。' },
  { title: '郊庙歌辞 享太庙乐章 大成舞', author: '魏征、褚亮', poem: '周称王季，晋美帝文。\n明明盛德，穆穆齐芬。\n藏用四履，屈道三分。\n铿锵钟石，载纪鸿勋。' },
  { title: '郊庙歌辞 享太庙乐章 大明舞', author: '魏征、褚亮', poem: '五纪更运，三正递升。\n勋华既没，禹汤勃兴。\n神武命代，灵睠是膺。\n望云彰德，察纬告征。\n上纽天维，下安地轴。\n征师涿野，万国咸服。\n偃伯灵台，九官允穆。\n殊域委賮，怀生介福。\n大礼既饰，大乐已和。\n黑章扰囿，赤字浮河。\n功宣载籍，德被咏歌。\n克昌厥后，百禄是荷。' },
  { title: '郊庙歌辞 享太庙乐章 寿和', author: '魏征、褚亮', poem: '八音斯奏，三献毕陈。\n宝祚惟永，晖光日新。' },
  { title: '郊庙歌辞 享太庙乐章 舒和', author: '魏征、褚亮', poem: '圣敬通神光七庙，灵心荐祚和万方。\n严禋克配鸿基远，明德惟馨凤历昌。' },
  { title: '郊庙歌辞 享太庙乐章 崇德舞', author: '不详', poem: '五运改卜，千龄启圣。\n彤云晓聚，黄星夜映。\n叶阐珠囊，基开玉镜。\n下临万宇，上齐七政。\n雾开三象，尘清九服。\n海溓星晖，远安迩肃。\n天地交泰，华夷辑睦。\n翔泳归仁，中外禔福。\n绩逾黜夏，勋高翦商。\n武陈七德，刑设三章。\n祥禽巢阁，仁兽游梁。\n卜年惟永，景福无疆。' },
  { title: '郊庙歌辞 享太庙乐章 钧天[舞]', author: '不详', poem: '承天抚箓，纂圣登皇。\n遐清万宇，仰协三光。\n功成日用，道济时康。\n璇图载永，宝历斯昌。\n日月扬晖，烟云烂色。\n河岳修贡，神祇効职。\n舜风攸偃，尧曦先就。\n睿感通寰，孝思浃宙。\n奉扬先德，虔遵曩狩。\n展义天扄，飞英云岫。\n化逸王表，神凝帝先。\n乘云厌俗，驭日登玄。' },
  { title: '郊庙歌辞 享太庙乐章 太和舞', author: '不详', poem: '广乐既备，嘉荐既新。\n述先惟德，孝飨惟亲。\n七献具举，五齐毕陈。\n锡兹祚福，于万斯春。' },
  { title: '郊庙歌辞 享太庙乐章 景云舞', author: '不详', poem: '惟睿作圣，惟圣登皇。\n精感耀魄，时膺会昌。\n舜慙大孝，尧推让王。\n能事斯极，振古谁方。\n文明履运，车书同轨。\n巍巍赫赫，尽善尽美。\n衢室凝旒，大庭端扆。\n释负之寄，事光复子。\n脱屣高天，登遐上玄。\n龙湖超忽，象野芊绵。\n游衣复道，荐果初年。\n新庙奕奕，明德配天。' },
  { title: '郊庙歌辞 享太庙乐章 光大舞', author: '不详', poem: '大业龙祉，徽音骏尊。\n潜居皇德，赫嗣天昆。\n展仪宗祖，重诚孝孙。\n春秋无极，享奏存存。' },
  { title: '郊庙歌辞 享太庙乐章 迎神', author: '不详', poem: '七庙观德，百灵攸仰。\n俗荷财成，物资含养。\n道光执契，化笼提象。\n肃肃雍雍，神其来飨。' },
  { title: '郊庙歌辞 享太庙乐章 金奏', author: '不详', poem: '肃肃清庙，巍巍盛唐。\n配天立极，累圣重光。\n乐和管磬，礼备烝尝。\n永惟来格，降福无疆。' },
  { title: '郊庙歌辞 享太庙乐章 送神', author: '不详', poem: '五声备奏，三献终祠。\n车移凤辇，斾转虹旗。\n礼周笾豆，诚效虔祗。\n皇灵徙跸，簪绅拜辞。' },
  { title: '郊庙歌辞 武后享清庙乐章十首 第一', author: '不详', poem: '建清庙，赞玄功。\n择吉日，展禋宗。\n乐已变，礼方崇。\n望神驾，降仙宫。' },
  { title: '郊庙歌辞 武后享清庙乐章十首 第二', author: '不详', poem: '隆周创业，宝命惟新。\n敬宗茂典，爰表虔禋。\n声明已备，文物斯陈。\n肃容如在，恳志方申。' },
  { title: '郊庙歌辞 武后享清庙乐章十首 第三登歌', author: '不详', poem: '肃敷大礼，上谒尊灵。\n敬[陈]筐币，载表丹诚。' },
  { title: '郊庙歌辞 武后享清庙乐章十首 第四迎神', author: '不详', poem: '敬奠苹藻，式罄虔襟。\n洁诚斯展，伫降灵歆。' },
  { title: '郊庙歌辞 武后享清庙乐章十首 第五饮福', author: '不详', poem: '爰陈玉醴，式奠琼浆。\n灵心有穆，介福无疆。' },
  { title: '郊庙歌辞 武后享清庙乐章十首 第六送文舞', author: '不详', poem: '帝图草创，皇业初开。\n功高佐命，业赞云雷。' },
  { title: '郊庙歌辞 武后享清庙乐章十首 第七迎武舞', author: '不详', poem: '赫赫玄功被穹壤，皇皇至德洽生灵。\n开基拨乱妖氛廓，佐命宣威海内清。' },
  { title: '郊庙歌辞 武后享清庙乐章十首 第八武舞作', author: '不详', poem: '荷恩承顾托，执契恭临抚。\n庙畧静边荒，天兵耀神武。' },
  { title: '郊庙歌辞 武后享清庙乐章十首 第九彻俎', author: '不详', poem: '登歌已阕，献礼方周。\n钦承景福，肃奉鸿休。' },
  { title: '郊庙歌辞 武后享清庙乐章十首 第十送神', author: '不详', poem: '大礼言毕，仙卫将归。\n莫申丹恳，空瞻紫微。' },
  { title: '郊庙歌辞 享太庙乐章 严和', author: '不详', poem: '肃肃清庙，赫赫玄猷。\n功高万古，化奄十洲。\n中兴丕业，上荷天休。\n祗奉先构，礼备怀柔。' },
  { title: '郊庙歌辞 享太庙乐章 升和', author: '不详', poem: '顾惟菲薄，纂历应期。\n中外同轨，夷狄来思。\n乐用崇德，礼以陈词。\n夕惕若厉，钦奉弘基。' },
  { title: '郊庙歌辞 享太庙乐章 虔和', author: '不详', poem: '礼标荐鬯，肃事祠庭。\n敬申如在，敢托非馨。' },
  { title: '郊庙歌辞 享太庙乐章 歆和', author: '不详', poem: '崇禋已备，粢盛聿修。\n洁诚斯展，钟石方遒。' },
  { title: '郊庙歌辞 享太庙乐章 承光舞', author: '不详', poem: '金相载穆，玉裕重辉。\n养德清禁，承光紫微。\n干宫候色，震象增威。\n监国方永，宾天不归。\n孝友自衷，温文性与。\n龙楼正启，鹤驾斯举。\n丹扆流念，鸿名式序。\n中兴考室，永陈彝俎。' },
  { title: '郊庙歌辞 享太庙乐章 延和', author: '不详', poem: '巍巍累圣，穆穆重光。\n奄有区夏，祚启隆唐。\n百蛮饮泽，万国来王。\n本枝亿载，鼎祚逾长。' },
  { title: '郊庙歌辞 享太庙乐章 同和', author: '不详', poem: '惟圣配天敷盛礼，惟天为大阐洪名。\n恭禋展敬光先德，苹藻申虔表志诚。' },
  { title: '郊庙歌辞 享太庙乐章 宁和', author: '不详', poem: '炎驭失天纲，土德承天命。\n英猷被寰宇，懿躅隆邦政。\n七德已绥边，九夷咸底定。\n景化覃遐迩，深仁洽翔泳。' },
  { title: '郊庙歌辞 享太庙乐章 恭和', author: '不详', poem: '礼周三献，乐阕九成。\n肃承灵福，悚惕兼盈。' },
  { title: '郊庙歌辞 享太庙乐章 通和', author: '不详', poem: '祠容既毕，仙座爰兴。\n停停凤举，霭霭云升。\n长隆宝运，永锡休征。\n福覃贻厥，恩被黎蒸。' },
  { title: '郊庙歌辞 享太庙乐章 昭和', author: '不详', poem: '道洽二仪交泰，时休四宇和平。\n环珮肃于庭实，钟石扬乎颂声。' },
  { title: '郊庙歌辞 享太庙乐章 诚敬', author: '不详', poem: '顾惟菲质，忝位椒宫。\n虔奉苹藻，肃事神宗。\n敢申诚絜，庶罄深衷。\n睟容有裕，灵享无穷。' },
  { title: '郊庙歌辞 享太庙乐章 肃和', author: '不详', poem: '月礼已周，云和将变。\n爰献其醑，载迁其奠。\n明德逾隆，非馨是荐。\n泽沾动植，仁覃宇县。' },
  { title: '郊庙歌辞 享太庙乐章 昭感', author: '不详', poem: '铿锵韶濩，肃穆神容。\n洪规赫赫，祠典雍雍。\n已周三献，将乘六龙。\n虔诚有托，恳志无从。' },
  { title: '郊庙歌辞 享太庙乐章 永和三章 一', author: '张说', poem: '肃九室，谐八音。\n歌皇慕，动神心。\n礼宿设，乐妙寻。\n声明备，[祼]奠临。' },
  { title: '郊庙歌辞 享太庙乐章 永和三章 二', author: '张说', poem: '律迓气，音入玄。\n依玉几，御黼筵。\n聆忾息，僾周旋。\n九韶遍，百福传。' },
  { title: '郊庙歌辞 享太庙乐章 永和三章 三', author: '张说', poem: '信工祝，永颂声。\n来祖考，听和平。\n相百辟，贡九瀛。\n神休委，帝孝成。' },
  { title: '郊庙歌辞 享太庙乐章 太和', author: '张说', poem: '时文圣后，清庙肃邕。\n致诚勤荐，在貌思恭。\n玉节肆夏，金锵五钟。\n绳绳云步，穆穆天容。' },
  { title: '郊庙歌辞 享太庙乐章 肃和', author: '张说', poem: '天子享孝，工歌溥将。\n躬[祼]郁鬯，乃焚膋芗。\n臭以达阴，声以求阳。\n奉时烝尝，永代不忘。' },
  { title: '郊庙歌辞 享太庙乐章 雍和二章 一', author: '张说', poem: '在涤嘉豢，丽碑敬牲。\n角握之牡，色纯之骍。\n火传阳燧，水溉阴精。\n太公胖俎，[傅]说和羹。' },
  { title: '郊庙歌辞 享太庙乐章 雍和二章 二', author: '张说', poem: '俎豆有馥，粢盛絜丰。\n亦有和羹，既戒既平。\n鼓钟管磬，肃唱和鸣。\n皇皇后祖，来我思成。' },
  { title: '郊庙歌辞 享太庙乐章 文舞', author: '张说', poem: '圣謩九德，真言五千。\n庆集昌胄，符开帝先。\n高文杖钺，克配彼天。\n三宗握镜，六合涣然。\n帝其承祀，率礼罔愆。\n图书雾出，日月清悬。\n舞形德类，咏谂功传。\n黄龙蜿蟺，彩云蹁跹。\n五行气顺，八佾风宣。\n介此百禄，于皇万年。' },
  { title: '郊庙歌辞 享太庙乐章 光大舞', author: '张说', poem: '肃肃艺祖，滔滔濬源。\n有雄玉剑，作镇金门。\n玄王贻绪，后稷谋孙。\n肇禋九庙，四海来尊。' },
  { title: '郊庙歌辞 享太庙乐章 长发舞', author: '张说', poem: '具礼崇德，备乐承风。\n魏推幢主，周赠司空。\n不行而至，无成有终。\n神兴王业，天归帝功。' },
  { title: '郊庙歌辞 享太庙乐章 大政舞', author: '张说', poem: '于赫元命，权舆帝文。\n天齐八柱，地半三分。\n宗庙观德，笙镛乐勋。\n封唐之兆，成天下君。' },
  { title: '郊庙歌辞 享太庙乐章 大成舞', author: '张说', poem: '帝舞季历，龙圣生昌。\n后歌有𫊸，胎炎孕黄。\n天地合德，日月齐光。\n肃雝孝享，祚我万方。' },
  { title: '郊庙歌辞 享太庙乐章 大明舞', author: '张说', poem: '赤精乱德，四海困穷。\n黄旗举义，三灵会同。\n旱望春雨，云披大风。\n溥天来祭，高祖之功。' },
  { title: '郊庙歌辞 享太庙乐章 崇德舞', author: '张说', poem: '皇合一德，朝宗百神。\n削平天地，大拯生人。\n上帝配食，单于入臣。\n戎歌陈舞，晔晔震震。' },
  { title: '郊庙歌辞 享太庙乐章 钧天舞', author: '张说', poem: '高皇迈道，端拱无为。\n化怀獯鬻，兵赋句骊。\n礼尊封禅，乐盛来仪。\n合位娲后，同称伏羲。' },
  { title: '郊庙歌辞 享太庙乐章 大和舞', author: '张说', poem: '退居江水，郁起丹陵。\n礼物还旧，朝章中兴。\n龙图友及，骏命恭膺。\n鸣球香瓒，大糦是承。' },
  { title: '郊庙歌辞 享太庙乐章 景云舞', author: '张说', poem: '景云霏烂，告我帝符。\n噫帝冲德，与天为徒。\n笙镛遥远，俎豆虚无。\n春秋孝献，回复此都。' },
  { title: '郊庙歌辞 享太庙乐章 福和', author: '张说', poem: '备礼用乐，崇亲致尊。\n诚通慈降，敬彻爱存。\n献怀称寿，啐感承恩。\n皇帝孝德，子孙千亿。\n大包天域，长亘不极。' },
  { title: '郊庙歌辞 享太庙乐章 舒和', author: '张说', poem: '六钟翕协六变成，八佾徜徉八风生。\n乐九韶兮人神感，美七德兮天地清。' },
  { title: '郊庙歌辞 享太庙乐章 凯安四章 一', author: '张说', poem: '瑟彼瑶爵，亚惟上公。\n室如屏气，门不容躬。\n礼殷其本，乐执其中。\n圣皇永慕，天地幽通。' },
  { title: '郊庙歌辞 享太庙乐章 凯安四章 二', author: '张说', poem: '礼匝三献，乐遍九成。\n降循轩陛，仰欷皇情。\n福与仁合，德因孝明。\n百年[神畏]，四海风行。' },
  { title: '郊庙歌辞 享太庙乐章 凯安四章 三', author: '张说', poem: '总总干戚，填填鼓钟。\n奋扬争气，坐作为容。\n离若鸷鸟，合如战龙。\n万方观德，肃肃雝雝。' },
  { title: '郊庙歌辞 享太庙乐章 凯安四章 四', author: '张说', poem: '烈祖顺三灵，文宗威四海。\n黄钺诛群盗，朱旗扫多罪。\n戢兵天下安，约法人心改。\n大哉干羽意，长见风云在。' },
  { title: '郊庙歌辞 享太庙乐章 登歌', author: '张说', poem: '止笙磬，撤豆笾。\n廓无响，窅入玄。\n主在室，神在天。\n情余慕，礼罔愆。\n喜黍稷，屡丰年。' },
  { title: '郊庙歌辞 享太庙乐章 永和', author: '张说', poem: '眇嘉乐，授灵爽。\n感若来，思如往。\n休气散，回风上。\n返寂寞，还惚恍。\n怀灵驾，结空想。' },
  { title: '郊庙歌辞 享太庙乐章 广运舞', author: '郭子仪', poem: '于赫皇祖，昭明有融。\n惟文之德，惟武之功。\n河海静谧，车书混同。\n虔恭孝飨，穆穆玄风。' },
  { title: '郊庙歌辞 享太庙乐章 惟新舞', author: '刘晏', poem: '汉祚惟永，神功中兴。\n风驱氛祲，天覆黎蒸。\n三光再朗，庶绩其凝。\n重熙累洽，景命是膺。' },
  { title: '郊庙歌辞 享太庙乐章 保大舞', author: '郭子仪', poem: '於穆文考，圣神昭章。\n肃勺群慝，含光远方。\n万物茂遂，九夷宾王。\n愔愔云韶，德音不忘。' },
  { title: '郊庙歌辞 享太庙乐章 文明舞', author: '郑余庆', poem: '开邸除暴，时迈勋尊。\n三元告命，四极骏奔。\n金枝翠叶，辉烛瑶琨。\n象德亿载，贻庆汤孙。' },
  { title: '郊庙歌辞 享太庙乐章 大顺舞', author: '郑𬘡', poem: '於穆时文，受天明命。\n允恭玄默，化成理定。\n出震嗣德，应干传圣。\n猗欤缉熙，千亿流庆。' },
  { title: '郊庙歌辞 享太庙乐章 象德舞', author: '段文昌', poem: '肃肃清庙，登显至德。\n泽周八荒，兵定四极。\n生物咸遂，群盗灭息。\n明圣钦承，子孙千亿。' },
  { title: '郊庙歌辞 享太庙乐章 和宁舞', author: '牛僧孺', poem: '湜湜颀颀，融昭德辉。\n不纽不舒，贯成九围。\n武烈文经，敷施当宜。\n纂尧付启，亿万熙熙。' },
  { title: '郊庙歌辞 享太庙乐章 大定舞', author: '李回', poem: '受天明命，敷佑下土。\n化时以俭，卫文以武。\n氛消夷夏，俗臻往古。\n亿万斯年，形于律吕。' },
  { title: '郊庙歌辞 享太庙乐章 宣宗室舞', author: '夏侯孜', poem: '于铄令主，圣祚重昌。\n兴起教义，申明典章。\n俗尚素朴，人皆乐康。\n积德可报，流庆无疆。' },
  { title: '郊庙歌辞  懿宗室舞', author: '萧倣', poem: '圣祚无疆，庆传乐章。\n金枝繁茂，玉叶延长。\n海渎常[晏]，波涛不扬。\n汪汪美化，垂范今王。' },
  { title: '郊庙歌辞 享太庙乐章 咸宁舞', author: '不详', poem: '于铄丕嗣，惟帝之光。\n羽籥象德，金石荐祥。\n圣系无极，景命永昌。\n神降上哲，维天配长。' },
  { title: '郊庙歌辞 太清宫乐章 煌煌', author: '不详', poem: '煌煌道宫，肃肃太清。\n礼光尊祖，乐备充庭。\n罄竭诚至，希夷降灵。\n云凝翠盖，风燄红旌。\n众真以从，九奏初迎。\n永惟休祐，是锡和平。' },
  { title: '郊庙歌辞 太清宫乐章 冲和', author: '不详', poem: '虚无结思，钟磬和音。\n歌以颂德，香以达心。\n礼殊祼鬯，义感昭临。\n云车至止，庆垂愔愔。' },
  { title: '郊庙歌辞 太清宫乐章 香初上', author: '不详', poem: '肃肃我祖，緜緜道宗。\n至感潜达，灵心暗通。\n云𫐌御气，芝盖随风。\n四时禋祀，万国来同。' },
  { title: '郊庙歌辞 太清宫乐章 再上', author: '不详', poem: '仙宗绩道，我李承天。\n庆深虚极，符光象先。\n俗登仁寿，化阐蟺涓。\n五千贻范，亿万斯年。' },
  { title: '郊庙歌辞 太清宫乐章 终上', author: '不详', poem: '不宰元功，无为上圣。\n洪源长发，诞受天命。\n金奏迎真，璇宫展盛。\n备礼周乐，垂光储庆。' },
  { title: '郊庙歌辞 太清宫乐章 紫极舞', author: '不详', poem: '至道生元气，重圆法混成。\n无为观大象，冲用体常名。\n仙乐临丹阙，云车出玉京。\n灵符百代应，瑞节九贞迎。\n宝运开皇极，天临映太清。\n长垂一德庆，永庇万方宁。' },
  { title: '郊庙歌辞 太清宫乐章 序入破第一奏', author: '不详', poem: '真宗开妙理，冲教统清虚。\n化演无为日，言昭有象初。\n瑶台肃灵瑞，金阙映仙居。\n一奏三清乐，长回八景舆。' },
  { title: '郊庙歌辞 太清宫乐章 序入破第二奏', author: '不详', poem: '虚极仙宗本，希夷象帝先。\n百灵朝太上，万法祖重圆。\n善贷惟冲德，功成谓自然。\n云门达和气，思用合钧天。' },
  { title: '郊庙歌辞 太清宫乐章 序入破第三奏', author: '不详', poem: '元符传紫极，宝祚启高真。\n道德先垂裕，冲和已化淳。\n人风齐太古，天瑞叶惟新。\n仙乐清都上，长明交泰辰。' },
  { title: '郊庙歌辞 太清宫乐章 登歌', author: '不详', poem: '严禋展事，理洁烝尝。\n皇矣圣祖，德惟馨香。\n盛荐既撤，工歌载扬。\n大来之庆，降福穰穰。' },
  { title: '郊庙歌辞 太清宫乐章 真和', author: '不详', poem: '玉磬含香，金炉既馥。\n风驭泠泠，云坛肃肃。\n杳归大象，霈流嘉福。\n俾宁万邦，无思不服。' },
  { title: '郊庙歌辞 德明兴圣庙乐章 迎神', author: '李舒', poem: '元尊九德，佐尧光宅。\n烈祖太宗，方周作伯。\n响怀霜露，乐变金石。\n白云清风，髣髴来格。' },
  { title: '郊庙歌辞 德明兴圣庙乐章 登歌奠币', author: '李舒', poem: '四时有典，百事来祭。\n尊祖奉宗，严禋大帝。\n礼先苍璧，奠币黝制。\n于斯万年，熙成帝系。' },
  { title: '郊庙歌辞 德明兴圣庙乐章 迎俎', author: '李舒', poem: '盛牲实俎，涓选休成。\n鼎煁阳燧，玉盥阴精。\n有𫗣嘉豆，既和大羹。\n侑以清乐，细齐人情。' },
  { title: '郊庙歌辞 德明兴圣庙乐章 德明酌献', author: '李舒', poem: '清庙奕奕，和乐雍雍。\n器尊牺象，礼属宗公。\n白水方祼，黄流在中。\n谟明之德，万古清风。' },
  { title: '郊庙歌辞 德明兴圣庙乐章 兴圣酌献', author: '李舒', poem: '閟宫静谧，合乐周张。\n泰尊始献，百末重觞。\n震澹存诚，庶几迪尝。\n遥源之祚，天汉灵长。' },
  { title: '郊庙歌辞 德明兴圣庙乐章 亚献终献', author: '李舒', poem: '惟清惟肃，靡闻靡见。\n举备九成，俛终三献。\n庆彰曼寿，胙彻嘉荐。\n瘗玉埋牲，礼神斯徧。' },
  { title: '郊庙歌辞 德明兴圣庙乐章 送神', author: '李舒', poem: '元精回复，灵贶繁滋。\n风洒兰路，云摇桂旗。\n高丘缅邈，凉部逶迟。\n瞻望靡及，缠绵永思。' },
  { title: '郊庙歌辞 仪坤庙乐章 永和', author: '徐彦伯', poem: '猗若清庙，肃肃荧荧。\n国荐严祀，坤兴淑灵。\n有几在室，有乐在庭。\n临兹孝享，百禄惟宁。' },
  { title: '郊庙歌辞 仪坤庙乐章 金奏', author: '不详', poem: '阴灵曜祉，轩曜降精。\n祥符淑气，庆集柔明。\n瑶俎既列，雕桐发声。\n徽猷永远，比德皇英。' },
  { title: '郊庙歌辞 仪坤庙乐章 太和', author: '丘说', poem: '孝哉我后，冲乎迺圣。\n道映重华，德辉文命。\n慕深视箧，情殷抚镜。\n万国移风，兆人承庆。' },
  { title: '郊庙歌辞 仪坤庙乐章 肃和', author: '张齐贤', poem: '祼圭既濯，郁鬯既陈。\n画幕云举，黄流玉醇。\n仪充献酌，礼盛众禋。\n地察惟孝，愉焉飨亲。' },
  { title: '郊庙歌辞 仪坤庙乐章 雍和', author: '郑善玉', poem: '酌郁既灌，芗萧方𦶟。\n笾豆静器，簠簋芬𫗣。\n鱼腊荐美，牲牷表洁。\n是戢是将，载迎载列。' },
  { title: '郊庙歌辞 仪坤庙乐章 昭升', author: '薛稷', poem: '阳灵配德，阴魄昭升。\n尧坛凤下，汉室龙兴。\n伣天作对，前旒是凝。\n化行南国，道盛西陵。\n造舟集灌，无德而称。\n我粢既絜，我醴既澄。\n阴阴灵庙，光灵若凭。\n德馨惟享，孝思烝烝。' },
  { title: '郊庙歌辞 仪坤庙乐章 坤贞', author: '不详', poem: '乾道既亨，坤元以贞。\n肃雍攸在，辅佐斯成。\n外睦九族，内光一庭。\n克生睿哲，祚我休明。\n钦若徽范，悠哉淑灵。\n建兹清宫，于彼上京。\n缩茅以献，絜秬惟馨。\n实受其福，期乎亿龄。' },
  { title: '郊庙歌辞 仪坤庙乐章 寿和', author: '徐坚', poem: '於穆清庙，肃雍严祀。\n合福受厘，介以繁[祉]。' },
  { title: '郊庙歌辞 仪坤庙乐章 舒和', author: '胡雄', poem: '送文迎武递参差，一始一终光圣仪。\n四海生人歌有庆，千龄孝享肃无亏。' },
  { title: '郊庙歌辞 仪坤庙乐章 安和', author: '刘子玄', poem: '妙筭申帷幄，神谋及庙庭。\n两阶文物备，七德武功成。\n校猎长杨苑，屯军细柳营。\n将军献凯入，歌舞溢重城。' },
  { title: '郊庙歌辞 仪坤庙乐章 雍和', author: '员半千', poem: '孝享云毕，惟彻有章。\n云感玄羽，风凄素商。\n瞻望神座，祗恋匪遑。\n礼终乐阕，肃雍锵锵。' },
  { title: '郊庙歌辞 仪坤庙乐章 永和', author: '祝钦明', poem: '閟宫实实，清庙微微。\n降格无象，馨香有依。\n式昭纂庆，方融嗣徽。\n明禋是享，神保聿归。' },
  { title: '郊庙歌辞 仪坤庙乐章 迎神', author: '不详', poem: '月灵降德，坤元授光。\n娥英比秀，任姒均芳。\n瑶台荐祉，金屋延祥。\n迎神有乐，歆此嘉芗。' },
  { title: '郊庙歌辞 仪坤庙乐章 送神', author: '不详', poem: '玉帛仪大，金丝奏广。\n灵应有孚，冥征不爽。\n降彼休福，歆兹禋享。\n送乐有章，神麾其上。' },
  { title: '郊庙歌辞 昭德皇后庙乐章 永和', author: '不详', poem: '穆清庙，荐严禋。\n昭礼备，和乐新。\n望灵光，集元辰。\n祚无极，享万春。' },
  { title: '郊庙歌辞 昭德皇后庙乐章 肃和', author: '不详', poem: '诚心达，娱乐分。\n升箫膋，郁氛氲。\n茅既缩，鬯既薰。\n后来思，福如云。' },
  { title: '郊庙歌辞 昭德皇后庙乐章 雍和', author: '不详', poem: '我将我享，尽明而诚。\n载芬黍稷，载涤牺牲。\n懿矣元良，万邦以贞。\n心乎爱敬，若覩容声。' },
  { title: '郊庙歌辞 昭德皇后庙乐章 坤元', author: '不详', poem: '於穆先后，丽圣称崇。\n母临万宇，道[被]六宫。\n昌时协庆，理内成功。\n殷荐明德，传芳国风。' },
  { title: '郊庙歌辞 昭德皇后庙乐章 寿和', author: '不详', poem: '工祝致告，徽音不遐。\n酒醴咸旨，馨香具嘉。\n受厘献祉，永庆邦家。' },
  { title: '郊庙歌辞 昭德皇后庙乐章 舒和', author: '不详', poem: '金枝羽部彻清歌，瑶台肃穆笙磬罗。\n谐音遍响合明意，万类昭融灵应多。' },
  { title: '郊庙歌辞 昭德皇后庙乐章 凯安', author: '不详', poem: '辰位列四星，帝功参十乱。\n进贤勤内辅，扈跸清多难。\n承天厚载均，并耀宵光璨。\n留徽蔼前躅，万古披图焕。' },
  { title: '郊庙歌辞 让皇帝庙乐章 迎神', author: '李舒', poem: '皇矣天宗，德先王季。\n因心则友，克让以位。\n爰命有司，式遵前志。\n神其降灵，昭飨祀事。' },
  { title: '郊庙歌辞 让皇帝庙乐章 奠币', author: '李舒', poem: '惟帝时若，去而上仙。\n祀用商舞，乐备宫悬。\n白璧加荐，玄𫄸告虔。\n子孙拜后，承兹吉蠲。' },
  { title: '郊庙歌辞 让皇帝庙乐章 迎俎', author: '李舒', poem: '祀盛体荐，礼协粢盛。\n方周假庙，用鲁纯牲。\n捧彻祗敬，击拊和鸣。\n受厘归胙，既戒而平。' },
  { title: '郊庙歌辞 让皇帝庙乐章 酌献', author: '李舒', poem: '八音具举，三寿既盥。\n洁兹宗彝，瑟彼圭瓒。\n兰肴重错，椒醑飘散。\n降胙维城，永为藩翰。' },
  { title: '郊庙歌辞 让皇帝庙乐章 亚献终献', author: '李舒', poem: '秩礼有序，和音既同。\n九仪不忒，三揖将终。\n孝感藩后，相维辟公。\n四时之典，永永无穷。' },
  { title: '郊庙歌辞 让皇帝庙乐章 送神', author: '李舒', poem: '奠献已事，昏昕载分。\n风摇雨散，灵卫𬘡缊。\n龙驾帝服，上腾五云。\n泮宫复閟，寂寞无闻。' },
  { title: '郊庙歌辞 享隐太子庙乐章 诚和', author: '不详', poem: '道閟鹤关，运缠鸠里。\n门集大命，俾歆嘉祀。\n礼亚六瑚，诚殚二簋。\n有诚颙若，神斯戾止。' },
  { title: '郊庙歌辞 享隐太子庙乐章 肃和', author: '不详', poem: '岁肇春宗，干开震长。\n瑶山既寂，戾园斯享。\n玉肃其事，物昭其象。\n弦诵成风，笙歌合响。' },
  { title: '郊庙歌辞 享隐太子庙乐章 雍和', author: '不详', poem: '明典肃陈，神居邃启。\n春伯联事，秋官相礼。\n有来雍雍，登歌济济。\n缅维主鬯，庶歆芳醴。' },
  { title: '郊庙歌辞 享隐太子庙乐章 舒和', author: '不详', poem: '三县已判歌钟列，六佾将开羽𬭭分。\n尚想燕飞来蔽日，终疑鹤影降凌云。' },
  { title: '郊庙歌辞 享隐太子庙乐章 凯安', author: '不详', poem: '天步昔将开，商郊初欲践。\n抚戎金阵廓，贰极瑶图阐。\n鸡戟遂崇仪，龙楼期好善。\n弄兵隳震业，启圣隆嗣典。' },
  { title: '郊庙歌辞 隐太子庙乐章 迎神', author: '不详', poem: '苍震有位，黄离蔽明。\n江充祸结，戾据灾成。\n衔冤昔痛，赠典今荣。\n享灵有秩，奉乐以迎。' },
  { title: '郊庙歌辞 隐太子庙乐章 送神', author: '不详', poem: '皇情悼往，祀议增设。\n钟鼓铿锵，羽旄昭晰。\n掌礼云备，司筵告彻。\n乐以送神，灵其鉴阕。' },
  { title: '郊庙歌辞 享章怀太子庙乐章 迎神', author: '不详', poem: '副君昭象，道应黄离。\n铜楼备德，玉裕成规。\n仙气霭霭，灵从师师。\n前驱戾止，控鹤来仪。' },
  { title: '郊庙歌辞 享章怀太子庙乐章 登歌酌鬯', author: '不详', poem: '忠孝本着，羽翼先成。\n寝门昭德，驰道为程。\n币帛有典，容卫无声。\n司存既肃，庙享惟清。' },
  { title: '郊庙歌辞 享章怀太子庙乐章 迎俎酌献', author: '不详', poem: '通三锡胤，明两承英。\n太山比赫，伊水闻笙。\n宗祧是寄，礼乐其亨。\n嘉辰荐俎，以发声明。' },
  { title: '郊庙歌辞 享章怀太子庙乐章 送文舞迎武舞', author: '不详', poem: '羽籥崇文礼以毕，干𬭭奋武事将行。\n用舍繇来其有致，壮志宣威乐太平。' },
  { title: '郊庙歌辞 享章怀太子庙乐章 武舞作', author: '不详', poem: '绿林炽炎历，黄虞格有苗。\n沙尘惊塞外，帷幄命嫖姚。\n七德干戈止，三边云雾消。\n宝祚长无极，歌舞盛今朝。' },
  { title: '郊庙歌辞 享懿德太子庙乐章 迎神', author: '不详', poem: '甲观昭祥，画堂升位。\n礼绝群后，望尊储贰。\n启诵慙德，庄丕掩粹。\n伊浦凤翔，缑峰鹤至。' },
  { title: '郊庙歌辞 享懿德太子庙乐章 登歌酌鬯', author: '不详', poem: '誉阐元储，寄崇明两。\n玉裕虽晦，铜楼可想。\n弦诵辍音，笙歌罢响。\n币帛言设，礼容无爽。' },
  { title: '郊庙歌辞 享懿德太子庙乐章 迎俎酌献', author: '不详', poem: '雍雍盛典，肃肃灵祠。\n宾天有圣，对日无期。\n飘飖羽服，掣曳云旗。\n眷言主鬯，心乎怆兹。' },
  { title: '郊庙歌辞 享懿德太子庙乐章 送文舞迎武舞', author: '不详', poem: '八音协奏陈金石，六佾分行整礼容。\n沧溟赴海还称少，素月开轮即是重。' },
  { title: '郊庙歌辞 享懿德太子庙乐章 武舞作', author: '不详', poem: '隋季昔云终，唐年初启圣。\n纂戎将禁暴，崇儒更敷政。\n威略静三边，仁恩覃万姓。' },
  { title: '郊庙歌辞 享节愍太子庙乐章 迎神', author: '不详', poem: '储后望崇，元良寄切。\n寝门是仰，驰道不绝。\n仙袂云会，灵旗电晰。\n煌煌而来，礼物攸设。' },
  { title: '郊庙歌辞 享节愍太子庙乐章 登歌酌鬯', author: '不详', poem: '灼灼重明，仰承元首。\n既贤且哲，惟孝与友。\n惟孝虽遥，灵规不朽。\n礼因诚致，备絜玄酒。' },
  { title: '郊庙歌辞 享节愍太子庙乐章 迎俎酌献', author: '不详', poem: '嘉荐有典，至诚莫骞。\n画梁云亘，雕俎星连。\n乐器周列，礼容备宣。\n依稀如在，若未宾天。' },
  { title: '郊庙歌辞 享节愍太子庙乐章 送文舞出迎武舞入', author: '不详', poem: '邕邕阐化凭文德，赫赫宣威藉武功。\n既执羽旄先拂吹，还持玉𬭭更挥空。' },
  { title: '郊庙歌辞 享节愍太子庙乐章 武舞作', author: '不详', poem: '武德谅雍雍，由来扫寇戎。\n劒光挥作电，旗影列成虹。\n雾廓三边静，波澄四海同。\n睿图今已盛，相共舞皇风。' },
  { title: '郊庙歌辞 享文敬太子庙乐章 请神', author: '许孟容', poem: '觞牢具品，管磬有节。\n祝道夤恭，神仪昭晰。\n桐圭早贵，象辂追设。\n声达乐成，降歆丰洁。' },
  { title: '郊庙歌辞 享文敬太子庙乐章 登歌', author: '陈京', poem: '歌以德发，声以乐贵。\n乐善名存，追仙礼异。\n鸾旌拱修，凤鸣合吹。\n神听皇慈，仲月皆至。' },
  { title: '郊庙歌辞 享文敬太子庙乐章 迎俎酌献', author: '冯伉', poem: '撰日瞻景，诚陈乐张。\n礼容秩秩，羽舞煌煌。\n肃将涤濯，祗荐芬芳。\n永锡繁祉，思深飨尝。' },
  { title: '郊庙歌辞 享文敬太子庙乐章 送文舞迎武舞', author: '不详', poem: '干旄羽籥相亏蔽，一进一退殊行缀。\n昔献三雍盛礼容，今陈六佾崇仪制。' },
  { title: '郊庙歌辞 享文敬太子庙乐章 亚献终献', author: '崔邠', poem: '醴齐泛尊彝，轩县动干戚。\n入室僾如在，升阶虔所历。\n奋疾合威容，定利舒皦绎。\n方崇庙貌礼，永被君恩锡。' },
  { title: '郊庙歌辞 享文敬太子庙乐章 送神', author: '张荐', poem: '三献具举，九旗将旋。\n追劳表德，罢享宾天。\n风引仙管，堂虚画筵。\n芳馨常在，瞻望悠然。' },
  { title: '郊庙歌辞 享惠昭太子庙乐章 请神', author: '归登', poem: '嘉荐既陈，祀事孔明。\n闲歌在堂，万舞在庭。\n外则尽物，内则尽诚。\n凤笙如闻，歌其洁精。' },
  { title: '郊庙歌辞 享惠昭太子庙乐章 登歌', author: '杜羔', poem: '因心克孝，位震遗芬。\n宾天道茂，轸怀气分。\n发祗乃祀，咳叹如闻。\n二歌斯升，以咏德薰。' },
  { title: '郊庙歌辞 享惠昭太子庙乐章 迎俎酌献', author: '李逢吉', poem: '既洁酒醴，聿陈熟腥。\n肃将震念，昭格储灵。\n展矣礼典，薰然德馨。\n愔愔管磬，亦具是听。' },
  { title: '郊庙歌辞 享惠昭太子庙乐章 送文舞出迎武舞入', author: '孟简', poem: '喧喧金石容既缺，肃肃羽驾就行列。\n缑山遗响昔所闻，庙庭进旅今攸设。' },
  { title: '郊庙歌辞 享惠昭太子庙乐章 亚献终献', author: '裴度', poem: '重轮始发祥，齿胄方兴学。\n冥然升紫府，铿尔荐清乐。\n奠斝致馨香，在庭纷羽籥。\n礼成神既醉，髣髴缑山鹤。' },
  { title: '郊庙歌辞 享惠昭太子庙乐章 送神', author: '王涯', poem: '威仪毕陈，备乐将阕。\n苞茅酒缩，膋萧香彻。\n宫臣展事，肃雍在列。\n迎精送往，厥鉴昭晰。' },
  { title: '郊庙歌辞 武后崇先庙乐章', author: '不详', poem: '先德谦㧑冠昔，严规节素超今。\n奉国忠诚每竭，承家至孝纯深。\n追崇惧乖尊意，显号恐玷徽音。\n既迫王公屡请，方乃俯遂群心。\n有限无由展敬，奠醑每阙亲斟。\n大礼虔申典册，苹藻敬荐翘襟。' },
  { title: '郊庙歌辞 襃德庙乐章 昭德', author: '不详', poem: '道赫梧宫，悲盈蒿里。\n爰赐徽烈，载敷嘉祀。\n享洽四时，规陈二簋。\n灵应昭格，神其戾止。' },
  { title: '郊庙歌辞 襃德庙乐章 进德', author: '不详', poem: '涂山懿戚，妫汭崇姻。\n祠筵肇启，祭典方申。\n礼以备物，乐以感神。\n用隆敦敍，载穆彝伦。' },
  { title: '郊庙歌辞 襃德庙乐章 襃德', author: '不详', poem: '家着累仁，门昭积善。\n瑶篚既列，金县式展。' },
  { title: '郊庙歌辞 襃德庙乐章 武舞作', author: '不详', poem: '昭昭竹殿开，奕奕兰宫启。\n懿范隆丹掖，殊荣辟朱邸。\n六佾荐徽容，三簋陈芳醴。\n万石覃贻厥，分珪崇祖祢。' },
  { title: '郊庙歌辞 襃德庙乐章 彰德', author: '不详', poem: '名隆五岳，秩映三台。\n严祠已备，[睟]影方回。' },
  { title: '舞曲歌辞 功成庆善乐舞词', author: '不详', poem: '寿丘惟旧迹，酆邑乃前基。\n粤余承累圣，悬弧亦在兹。\n弱龄逢运改，提劒郁匡时。\n指麾八荒定，怀柔万国夷。\n梯山盛入欵，驾海亦来思。\n单于陪武帐，日逐卫文㮰。\n端扆朝四岳，无为任百司。\n霜节明秋景，轻冰结水湄。\n芸黄遍原隰，禾颕积京坻。\n共乐还谯宴，欢此大风诗。' },
  { title: '舞曲歌辞 中和乐舞词', author: '不详', poem: '芳岁肇佳节，物华当仲春。\n乾坤既昭泰，烟景含氤氲。\n德浅荷玄贶，乐成思治人。\n前庭列钟鼓，广殿延群臣。\n八卦随舞意，五音转曲新。\n顾非咸池奏，庶协南风薰。\n式宴礼所重，浃欢情必均。\n同和谅在兹，万国希可亲。' },
  { title: '舞曲歌辞 凯乐歌辞 破阵乐', author: '不详', poem: '受律辞元首，相将讨叛臣。\n咸歌破阵乐，共赏太平人。' },
  { title: '舞曲歌辞 凯乐歌辞 应圣期', author: '不详', poem: '圣德期昌运，雍熙万宇清。\n乾坤资化育，海岳共休明。\n辟土欣耕稼，销戈遂偃兵。\n殊方歌帝泽，执贽贺升平。' },
  { title: '舞曲歌辞 凯乐歌辞 贺圣欢', author: '不详', poem: '四海皇风被，千年德水清。\n戎衣更不着，今日告功成。' },
  { title: '舞曲歌辞 凯乐歌辞 君臣同庆乐', author: '不详', poem: '主圣开昌历，臣忠奉大猷。\n君看偃革后，便是太平秋。' },
  { title: '郊庙歌辞 梁郊祀乐章 庆和 一', author: '赵光逢、张衮', poem: '就阳位，升圆丘。\n佩双玉，御大裘。\n膺天命，拥神休。\n万灵感，百禄遒。' },
  { title: '郊庙歌辞 梁郊祀乐章 庆和 二', author: '赵光逢、张衮', poem: '秉黄钺，建朱旗。\n震八表，清二仪。\n帝业显，王道夷。\n受景命，启皇基。' },
  { title: '郊庙歌辞 梁郊祀乐章 庆和 三', author: '赵光逢、张衮', poem: '开九门，怀百神。\n通肸蚃，接氤氲。\n明粢荐，广乐陈。\n奠嘉璧，燎芳薪。' },
  { title: '郊庙歌辞 梁郊祀乐章 庆和 四', author: '赵光逢、张衮', poem: '膺宝图，执左契。\n德应天，圣飨帝。\n荐表衷，荷灵惠。\n寿万年，祚百世。' },
  { title: '郊庙歌辞 梁郊祀乐章 庆和 五', author: '赵光逢、张衮', poem: '惟德动天，有感必通。\n秉兹一德，禋于六宗。\n钦夤宝命，恭肃礼容。\n来顾来享，永穆皇风。' },
  { title: '郊庙歌辞 梁郊祀乐章 庆和 六', author: '赵光逢、张衮', poem: '天惟佑德，辟乃奉天。\n交感斯在，昭事罔愆。\n岁功已就，王道无偏。\n于焉报本，是用告虔。' },
  { title: '郊庙歌辞 梁郊祀乐章 庆顺', author: '赵光逢、张衮', poem: '圣皇戾止，天步舒迟。\n干干睿相，穆穆皇仪。\n进退必肃，陟降是祗。\n六变克协，万灵协随。' },
  { title: '郊庙歌辞 梁郊祀乐章 庆平', author: '赵光逢、张衮', poem: '天命降鉴，帝德惟馨。\n享祀不忒，礼容孔明。\n奠璧布币，荐神献精。\n神佑以答，敷锡永宁。' },
  { title: '郊庙歌辞 梁郊祀乐章 庆肃', author: '赵光逢、张衮', poem: '笾豆簠簋，黍稷非馨。\n懿兹彝器，厥德惟明。\n金石匏革，以和以平。\n繇此无体，期乎永宁。' },
  { title: '郊庙歌辞 梁郊祀乐章 庆熙', author: '赵光逢、张衮', poem: '哲后躬享，旨酒斯陈。\n王恭无斁，严祀维夤。\n皇祖以配，大孝以振。\n宜锡景福，永休下民。' },
  { title: '郊庙歌辞 梁郊祀乐章 庆隆', author: '赵光逢、张衮', poem: '恭祀上帝，于国之阳。\n爵醴是荷，鸿基永昌。' },
  { title: '郊庙歌辞 梁郊祀乐章 庆融', author: '赵光逢、张衮', poem: '道和气兮袭氤氲，宣皇规兮彰圣神。\n服遐裔兮敷质文，格苗扈兮息烟尘。' },
  { title: '郊庙歌辞 梁郊祀乐章 庆休', author: '赵光逢、张衮', poem: '大业来四夷，仁风和万国。\n白日体无私，皇天辅有德。\n七旬罪已服，六月师方克。\n伟哉帝道隆，终始常作则。' },
  { title: '郊庙歌辞 梁郊祀乐章 庆和', author: '赵光逢、张衮', poem: '烟燎升，礼容彻。\n诚感达，人神悦。\n灵贶彰，圣情结。\n玉座寂，金炉歇。' },
  { title: '郊庙歌辞 周郊祀乐章 昭顺乐', author: '不详', poem: '五兵勿用，万国咸安。\n告功圆盖，受命云坛。\n乐鸣凤律，礼备鸡竿。\n神光欲降，众目遐观。' },
  { title: '郊庙歌辞 周郊祀乐章 治顺乐', author: '不详', poem: '羽卫离丹阙，金轩赴泰坛。\n珠旗明月色，玉佩晓霜寒。\n黼黻龙衣备，琮璜宝器完。\n百神将受职，宗社保长安。' },
  { title: '郊庙歌辞 周郊祀乐章 感顺乐', author: '不详', poem: '明君陈大礼，展币祀圆丘。\n雅乐声其发，祥云色正浮。' },
  { title: '郊庙歌辞 周郊祀乐章 禋顺乐', author: '不详', poem: '黄彝将献，特牲预迎。\n既修昭事，潜达明诚。' },
  { title: '郊庙歌辞 周郊祀乐章 福顺乐', author: '不详', poem: '相承五运，取法三才。\n大礼爰展，率土咸来。\n卿云秘室，甘泉宝台。\n象樽初酌，受福不回。' },
  { title: '郊庙歌辞 周郊祀乐章 忠顺乐', author: '不详', poem: '木铎敷音文德昌，朱干成列武功彰。\n雷鼗鹭羽今休用，玉𬭭相参正发扬。' },
  { title: '郊庙歌辞 周郊祀乐章 武舞乐', author: '不详', poem: '圭瓒方陈礼，干旄乃象功。\n成文非羽籥，猛势若罴熊。' },
  { title: '郊庙歌辞 梁太庙乐舞辞 开平舞', author: '不详', poem: '黍稷馨，醴𨠨清。\n牲牷洁，金石铿。\n恭祀事，结皇情。\n神来格，歌颂声。' },
  { title: '郊庙歌辞 梁太庙乐舞辞 皇帝行', author: '不详', poem: '莫高者天，攀跻弗克。\n𬯀天有方，累仁积德。\n祖宗隆之，子孙履之。\n配天明祀，永永孝思。' },
  { title: '郊庙歌辞 梁太庙乐舞辞 帝盥', author: '不详', poem: '庄肃莅事，周旋礼容。\n裸鬯严洁，穆穆雍雍。' },
  { title: '郊庙歌辞 梁太庙乐舞辞 登歌', author: '不详', poem: '于赫我皇，建中立极。\n动以武功，静以文德。\n昭事上帝，欢心万国。\n大报严禋，四海述职。' },
  { title: '郊庙歌辞 梁太庙乐舞辞 大合舞', author: '不详', poem: '於穆皇祖，濬哲雍熙。\n美溢中夏，化被南陲。\n后稷累德，公刘创基。\n肇兴九庙，乐合来仪。' },
  { title: '郊庙歌辞 梁太庙乐舞辞 象功舞', author: '不详', poem: '天地合德，睿圣昭彰。\n累赠太傅，俄登魏王。\n雄名不朽，奕叶而光。\n建国之兆，君临万方。' },
  { title: '郊庙歌辞 梁太庙乐舞辞 来仪舞', author: '不详', poem: '于赫帝命，应天顺人。\n亭育品汇，宾礼百神。\n洪基永固，景命惟新。\n肃恭孝享，祚我生民。' },
  { title: '郊庙歌辞 梁太庙乐舞辞 昭德舞', author: '不详', poem: '肃肃文考，源濬派长。\n汉称诞季，周实生昌。\n奄有四海，超彼百王。\n笙镛迭奏，礼物荧煌。' },
  { title: '郊庙歌辞 梁太庙乐舞辞 饮福', author: '不详', poem: '戛玉𪭢金永颂声，檿丝孤竹和且清。\n灵歆醉止牺象盈，自天降福千万龄。' },
  { title: '郊庙歌辞 梁太庙乐舞辞 撤豆', author: '不详', poem: '笙镛洋洋，庭燎煌煌。\n明星有烂，祝史下堂。\n[笾]豆斯撤，礼容有章。\n克勤克俭，无怠无荒。' },
  { title: '郊庙歌辞 梁太庙乐舞辞 送神', author: '不详', poem: '其降无从，其往无踪。\n黍稷非馨，有感必通。\n赫奕令德，髣髴睟容。\n再拜慌忽，遐想昊穹。' },
  { title: '郊庙歌辞 后唐宗庙乐舞辞 昭德舞', author: '崔居俭、卢文纪', poem: '懿彼明德，赫赫煌煌。\n名高阃域，功着旗常。\n道符休泰，运叶祺祥。\n庆传万祀，以播耿光。' },
  { title: '郊庙歌辞 后唐宗庙乐舞辞 文明舞', author: '崔居俭、卢文纪', poem: '帝业光扬，皇图翕赫。\n圣德孔彰，神功不测。\n信及豚鱼，恩沾动植。\n懿范鸿名，传之万亿。' },
  { title: '郊庙歌辞 后唐宗庙乐舞辞 应天舞', author: '崔居俭、卢文纪', poem: '晋国肇兴，雄图再固。\n黼黻帝道，金玉王度。\n皇天无亲，惟德是辅。\n载诞英明，永光圣祚。' },
  { title: '郊庙歌辞 后唐宗庙乐舞辞 永平舞', author: '崔居俭、卢文纪', poem: '庆传瓒祚，位正瑶图。\n功宣四海，化被八区。\n静彰帝道，动合干符。\n千秋万祀，永荷昭苏。' },
  { title: '郊庙歌辞 后唐宗庙乐舞辞 武成舞', author: '崔居俭、卢文纪', poem: '艰难王业，返正皇唐。\n先天再造，却日重光。\n汉绍世祖，夏资少康。\n功成德茂，率祀无疆。' },
  { title: '郊庙歌辞 后唐宗庙乐舞辞 雍煕舞', author: '崔居俭、卢文纪', poem: '仁君御宇，寰海谧清。\n运符武德，道协文明。\n九成式敍，百度惟贞。\n金门积庆，玉叶传荣。' },
  { title: '郊庙歌辞 汉宗庙乐舞辞 武德舞', author: '张昭', poem: '明明我祖，天集休明。\n神母夜哭，彤云昼兴。\n笾豆有践，管籥斯登。\n孝孙致告，神其降灵。' },
  { title: '郊庙歌辞 汉宗庙乐舞辞 灵长舞', author: '张昭', poem: '天降祥，汉祚昌。\n火炎上，水灵长。\n建庙社，洁蒸尝。\n罗钟石，俨珩璜。\n陈玉豆，酌金觞。\n气昭感，德馨香。\n祗洛汭，瞻晋阳。\n降吾祖，福穰穰。' },
  { title: '郊庙歌辞 汉宗庙乐舞辞 积善舞', author: '张昭', poem: '黍稷斯馨，祖德惟明。\n蛇告赤帝，龟谋大横。\n云行雨施，天成地平。\n造我家邦，斡我璇衡。\n陶匏在御，醍盎惟精。\n或戛或击，载炮载烹。\n饮福受胙，舞降歌迎。\n滔滔不竭，洪惟水行。' },
  { title: '郊庙歌辞 汉宗庙乐舞辞 显仁舞', author: '张昭', poem: '运极金行谢，天资水德隆。\n礼神鄜畤馆，布政未央宫。\n诘旦备明祀，登歌荅茂功。\n云轩临降久，星俎荐陈丰。\n霭霭沈檀雾，铿锵环佩风。\n荧煌升藻藉，肸蚃转珠栊。\n尊祖咸韶备，贻孙书轨同。\n京坻长有积，宗社享无穷。' },
  { title: '郊庙歌辞 汉宗庙乐舞辞 章庆舞', author: '张昭', poem: '罘罳晓唱鸡人，三牲八簋斯陈。\n雾集瑶阶琐闼，香生绮席华茵。\n珠佩貂珰熠爚，羽旄干戚纷纶。\n酌鬯既终三献，凝旒何止千春。\n阿阁长栖彩凤，郊宫叠奏祥麟。\n赤伏英灵未泯，玄圭运祚重新。\n玉斝牺樽潋滟，龙旗凤辖逡巡。\n瞻望月游冠冕，犹疑苍野回轮。' },
  { title: '郊庙歌辞 汉宗庙乐舞辞 观德舞', author: '张昭', poem: '高庙明灵再启图，金根玉辂幸神都。\n巢阿丹凰衔书命，入昴飞星献宝符。\n正换熏弦娱赤子，忽登仙驾泣苍梧。\n荐樱鹤馆笳箫咽，酌鬯金楹劒佩趋。\n星俎云罍兼鲁礼，朱干象箾杂巴渝。\n氤氲龙麝交青琐，髣髴[锡]銮下蘂珠。\n荐豆奉觞亲玉几，配天合祖耀璇枢。\n受厘饮酒皇欢洽，仰俟余灵泰九区。' },
  { title: '郊庙歌辞 周宗庙乐舞辞 肃顺', author: '不详', poem: '我后至孝，祗谒祖先。\n仰瞻庙貌，夙设宫悬。\n朱弦疏越，羽舞回旋。\n神其来格，明祀惟虔。' },
  { title: '郊庙歌辞 周宗庙乐舞辞 治顺', author: '不详', poem: '清庙将入，衮服是依。\n载行载止，令行令仪。\n永终就养，空极孝思。\n瞻望如在，顾复长违。' },
  { title: '郊庙歌辞 周宗庙乐舞辞 肃雍舞', author: '不详', poem: '周道载兴，象日之明。\n万邦咸庆，百谷用成。\n於穆圣祖，祗荐鸿名。\n祀于庙社，陈其牺牲。\n进旅退旅，皇武之形。\n一倡三叹，朱弦之声。\n以妥以侑，既和且平。\n至诚潜达，介福攸宁。' },
  { title: '郊庙歌辞 周宗庙乐舞辞 章德舞', author: '不详', poem: '清庙新，展严禋。\n恭祖德，厚人伦。\n雅乐荐，礼器陈。\n俨皇尸，列虞宾。\n神如在，声不闻。\n享必信，貌惟夤。\n想龙服，奠牺樽。\n礼既备，庆来臻。' },
  { title: '郊庙歌辞 周宗庙乐舞辞 善庆舞', author: '不详', poem: '卜世长，帝祚昌。\n定中国，服四方。\n修明祀，从旧章。\n奏激楚，转清商。\n罗俎豆，列簪裳。\n歌累累，容皇皇。\n望来格，降休祥。\n祝敢告，寿无疆。' },
  { title: '郊庙歌辞 周宗庙乐舞辞 观成舞', author: '不详', poem: '穆穆王国，奕奕神功。\n毖祀载展，明德有融。\n彝樽斯满，簠簋斯丰。\n纷𫄨旄羽，锵洋磬钟。\n或升或降，克和克同。\n孔惠之礼，必肃之容。\n锡以纯嘏，祚其允恭。\n神保是飨，万世无穷。' },
  { title: '郊庙歌辞 周宗庙乐舞辞 明德舞', author: '不详', poem: '惟彼岐阳，德大流光。\n载造周室，泽及遐荒。\n于铄圣祖，上帝是皇。\n迺圣迺神，知微知彰。\n新庙奕奕，丰年穰穰。\n取彼血膋，以往蒸尝。\n黍稷惟馨，笾豆大房。\n工祝致告，受福无疆。' },
  { title: '郊庙歌辞 周宗庙乐舞辞 咸顺', author: '不详', poem: '万舞咸列，三阶克清。\n贯珠一倡，击石九成。\n盈觞虽酌，灵坐无形。\n永怀我祖，达其孝诚。' },
  { title: '郊庙歌辞 周宗庙乐舞辞 禋顺', author: '不详', poem: '旨酒既献，嘉殽乃迎。\n振其鼗鼓，洁以铏羹。\n肇禋肇祀，或炮或烹。\n皇尸俨若，保飨是明。' },
  { title: '郊庙歌辞 周宗庙乐舞辞 福顺', author: '不详', poem: '新庙奕奕，金奏洋洋。\n享于祖考，循彼典章。\n清酤特满，嘉玉腾光。\n神醉既告，帝祉无疆。' },
  { title: '郊庙歌辞 周宗庙乐舞辞 忠顺', author: '不详', poem: '称文既表温柔德，示武须成蹈厉容。\n缀兆疾舒皆应节，明明我祖乐无穷。' },
  { title: '郊庙歌辞  善胜舞', author: '不详', poem: '圣祖累功，福钟来裔。\n持羽执干，舞文不废。' },
  { title: '郊庙歌辞  禋顺', author: '不详', poem: '礼毕祀先，香散几筵。\n罢舞干戚，收撤豆笾。' },
  { title: '郊庙歌辞  肃顺', author: '不详', poem: '乐奏四顺，福受万年。\n神归碧天，庭余瑞烟。' },
  { title: '郊庙歌辞 晋朝飨乐章 初举酒文同乐', author: '不详', poem: '赫矣昌运，明哉圣王。\n文兴坠典，礼复旧章。\n鸳鸾济济，鸟兽跄跄。\n一人有庆，万福无疆。' },
  { title: '郊庙歌辞 晋朝飨乐章 举酒', author: '不详', poem: '大明御宇，至德动天。\n君臣庆会，礼乐昭宣。\n劒佩成列，金石在县。\n椒觞再献，宝历万年。' },
  { title: '郊庙歌辞 晋朝飨乐章 再举酒', author: '不详', poem: '朝野无事，寰瀛大康。\n圣人有作，盛礼重光。\n万国执玉，千官奉觞。\n南山永固，地久天长。' },
  { title: '郊庙歌辞 晋朝飨乐章 四举酒', author: '不详', poem: '八表欢无事，三秋贺有成。\n照临同日远，渥泽并云行。\n河变千年色，山呼万岁声。\n愿修封岱礼，方以称文明。' },
  { title: '郊庙歌辞 晋朝飨乐章 群臣酒行歌 一', author: '不详', poem: '劒佩俨如林，齐倾拱北心。\n渥恩颁美禄，咸濩听和音。\n一德君臣合，重瞳日月临。\n歌时兼乐圣，唯待赞泥金。' },
  { title: '郊庙歌辞 晋朝飨乐章 群臣酒行歌 二', author: '不详', poem: '万国咸归禹，千官共祝尧。\n拜恩瞻凤扆，倾耳听云韶。\n运启金行远，时和玉烛调。\n酒酣齐抃舞，同贺圣明朝。' },
  { title: '郊庙歌辞 晋朝飨乐章 群臣酒行歌 三', author: '不详', poem: '令节陈高会，群臣侍御筵。\n玉墀留爱景，金殿霭祥烟。\n振鹭涵天泽，灵禽下乐悬。\n圣明无一事，何处让尧年。' },
  { title: '郊庙歌辞 周朝飨乐章 忠顺', author: '不详', poem: '岁迎更始，节及朝元。\n冕旒仰止，冠劒相连。\n八音合奏，万物齐宣。\n常陈盛礼，愿永千年。' },
  { title: '郊庙歌辞 周朝飨乐章 治顺', author: '不详', poem: '庭陈大乐，作当太微。\n凝旒负扆，端拱垂衣。\n鸳鸾成列，簪组相辉。\n御炉香散，郁郁霏霏。' },
  { title: '郊庙歌辞 周朝飨乐章 福顺', author: '不详', poem: '圣皇端拱，多士输忠。\n蛮觞共献，臣心毕同。\n声齐嵩岳，祝比华封。\n千龄万祀，常保时雍。' },
  { title: '郊庙歌辞 周朝飨乐章 康顺', author: '不详', poem: '鸿钧广运，嘉节良辰。\n列辟在位，万国来宾。\n干旌屡舞，金石咸陈。\n礼容既备，帝履长春。' },
  { title: '郊庙歌辞 晋昭德成功舞歌 昭德舞歌二首 一', author: '不详', poem: '圣代修文德，明庭举旧章。\n两阶陈羽籥，万舞合宫商。\n劒佩森鸳鹭，箫韶下凤凰。\n我朝青史上，千古有辉光。' },
  { title: '郊庙歌辞 晋昭德成功舞歌 昭德舞歌二首 二', author: '不详', poem: '淮海干戈戢，朝廷礼乐施。\n白驹皆就絷，丹凤复来仪。\n德备三苗格，风行万国随。\n小臣同百兽，率舞贺昌期。' },
  { title: '郊庙歌辞 晋昭德成功舞歌 武功舞歌二首 一', author: '不详', poem: '拨乱资英主，开基自晋阳。\n一戎成大业，七德焕前王。\n炎汉提封远，姬周世祚长。\n朱干将玉戚，全象武功扬。' },
  { title: '郊庙歌辞 晋昭德成功舞歌 武功舞歌二首 二', author: '不详', poem: '睿算超前古，神功格上圆。\n百川留禹迹，万国戴尧天。\n既已櫜弓矢，诚宜播管弦。\n跄跄随鸟兽，共乐太平年。' },
  { title: '鼓吹曲辞 朱鹭', author: '张籍', poem: '翩翩兮朱鹭，来泛春塘栖绿树。\n羽毛如翦色如染，远飞欲下双翅敛。\n避人引子入深壍，动处水纹开滟滟。\n谁知豪家网尔躯，不如饮啄江海隅。' },
  { title: '鼓吹曲辞 艾如张', author: '李贺', poem: '锦襜褕，绣裆襦，强强饮啄哺尔雏。\n陇东卧穟满风雨，莫信龙媒陇西去。\n齐人织网如素空，张在野春平碧中。\n网丝漠漠无形影，误尔触之伤首红。\n艾叶绿花谁翦刻，中藏祸机不可测。' },
  { title: '鼓吹曲辞 上之回', author: '卢照邻', poem: '回中道路险，萧关烽候多。\n五营屯北地，万乘出西河。\n单于拜玉玺，天子按雕戈。\n振旅汾川曲，秋风横大歌。' },
  { title: '鼓吹曲辞 上之回', author: '李白', poem: '三十六离宫，楼台与天通。\n阁道步行月，美人愁烟空。\n恩疎宠不及，桃李伤春风。\n淫乐意何极，金舆向回中。\n万乘出黄道，千旗扬彩虹。\n前军细柳北，后骑甘泉东。\n岂问渭川老，宁邀襄野童。\n秋暮瑶池宴，归来乐未穷。' },
  { title: '鼓吹曲辞 上之回', author: '李贺', poem: '上之回，大旗喜。\n悬虹彗，挞凤尾。\n劒匣破，舞蛟龙。\n蚩尤死，鼓逢逢。\n天高庆雷齐坠地，地无惊烟海千里。' },
  { title: '鼓吹曲辞 战城南', author: '卢照邻', poem: '将军出紫塞，冒顿在乌贪。\n笳喧雁门北，阵翼龙城南。\n雕弓夜宛转，铁骑晓参潭。\n应须驻白日，为待战方酣。' },
  { title: '鼓吹曲辞 战城南', author: '李白', poem: '去年战桑干源，今年战葱河道。\n洗兵条支海上波，放马天山雪中草。\n万里长征战，三军尽衰老。\n匈奴以杀戮为耕作，古来唯见白骨黄沙田。\n秦家筑城备胡处，汉家还有烽火然。\n烽火然不息，征战无已时。\n野战格鬬死，败马号鸣向天悲。\n乌鸢啄人肠，衔飞上挂枯树枝。\n士卒涂草莽，将军空尔为。\n乃知兵者是凶器，圣人不得已而用之。' },
  { title: '鼓吹曲辞 战城南', author: '刘驾', poem: '城南征战多，城北无饥鵶。\n白骨马蹄下，谁言皆有家。\n城前水声苦，倏忽流万古。\n莫争城外地，城里有闲土。' },
  { title: '鼓吹曲辞 战城南二首 一', author: '僧贯休', poem: '万里桑干傍，茫茫古蕃壤。\n将军貌顦顇，抚劒悲年长。\n胡兵尚陵逼，久住亦非强。\n邯郸少年辈，个个有伎俩。\n拖枪半夜去，雪片大如掌。' },
  { title: '鼓吹曲辞 战城南二首 二', author: '僧贯休', poem: '碛中有阴兵，战马时惊蹶。\n轻猛李陵心，摧残苏武节。\n黄金锁子甲，风吹色如铁。\n十载不封侯，茫茫向谁说。' },
  { title: '鼓吹曲辞 巫山高', author: '郑世翼', poem: '巫山凌太清，岧峣类削成。\n霏霏暮雨合，霭霭朝云生。\n危峰入鸟道，深谷泻猿声。\n别有幽栖客，淹留攀桂情。' },
  { title: '鼓吹曲辞 巫山高二首 一', author: '沈佺期', poem: '巫山峰十二，环合隐昭回。\n俯眺琵琶峡，平看云雨台。\n古槎天外倚，瀑水日边来。\n何忽啼猨夜，荆王枕席开。' },
  { title: '鼓吹曲辞 巫山高二首 二', author: '沈佺期', poem: '神女向高唐，巫山下夕阳。\n裴回作行雨，婉娈逐荆王。\n电影江前落，雷声峡外长。\n霁云无处所，台馆晓苍苍。' },
  { title: '鼓吹曲辞 巫山高', author: '卢照邻', poem: '巫山望不极，望望下朝雰。\n莫辨啼猿树，徒看神女云。\n惊涛乱水脉，骤雨暗峰文。\n沾裳即此地，况复远思君。' },
  { title: '鼓吹曲辞 巫山高', author: '张循之', poem: '巫山高不极，沓沓状奇新。\n暗谷疑风雨，幽岩若鬼神。\n月明三峡曙，潮满二江春。\n为问阳台夕，应知入梦人。' },
  { title: '鼓吹曲辞 巫山高', author: '刘方平', poem: '楚国巫山秀，清猨日夜啼。\n万重春树合，十二碧峰齐。\n峡出朝云下，江来暮雨西。\n阳台归路直，不畏向家迷。' },
  { title: '鼓吹曲辞 巫山高', author: '皇甫冉', poem: '巫峡见巴东，迢迢半出空。\n云藏神女馆，雨到楚王宫。\n朝暮泉声落，寒暄树色同。\n清猨不可听，偏在九秋中。' },
  { title: '鼓吹曲辞 巫山高', author: '李端', poem: '巫山十二峰，皆在碧虚中。\n回合云藏日，霏微雨带风。\n猨声寒过水，树色暮连空。\n愁向高唐望，清秋见楚宫。' },
  { title: '鼓吹曲辞 巫山高', author: '于𣸣', poem: '何山无朝云，彼云亦悠扬。\n何山无暮雨，彼雨亦苍茫。\n宋玉恃才者，凭云构高唐。\n自重文赋名，荒淫归楚襄。\n峨峨十二峰，永作妖鬼乡。' },
  { title: '鼓吹曲辞 巫山高二首 一', author: '孟郊', poem: '巴山上峡重复重，阳台碧峭十二峰。\n荆王猎时逢暮雨，夜卧高丘梦神女。\n轻红流烟湿艳姿，行云飞去明星稀。\n目极魂断望不见，猨啼三声泪沾衣。' },
  { title: '鼓吹曲辞 巫山高二首 二', author: '孟郊', poem: '见尽数万里，不闻三声猨。\n但飞萧萧雨，中有亭亭魂。\n千载楚襄恨，遗文宋玉言。\n至今青冥里，云结深闺门。' },
  { title: '鼓吹曲辞 巫山高', author: '李贺', poem: '碧丛丛，高插天，大江翻澜神曳烟。\n楚魂寻梦风飔然，晓风飞雨生苔钱。\n瑶姬一去一千年，丁香笻竹啼老猨。\n古祠近月蟾桂寒，椒花坠红湿云间。' },
  { title: '鼓吹曲辞 巫山高', author: '僧齐己', poem: '巫山高，巫女妖。\n雨为暮兮云为朝，楚王顦顇魂欲销。\n秋猨嗥嗥日将夕，红霞紫烟凝老壁。\n千岩万壑花皆坼，但恐芳菲无正色。\n不知今古行人行，几人经此无秋情。\n云深庙远不可觅，十二峰头插天碧。' },
  { title: '鼓吹曲辞 将进酒', author: '李白', poem: '君不见黄河之水天上来，奔流到海不复回。\n君不见高堂明镜悲白发，朝如青丝暮成雪。\n人生得意须尽欢，莫使金尊空对月。\n天生我材必有用，千金散尽还复来。\n烹羊宰牛且为乐，会须一饮三百杯。\n岑夫子，丹丘生，将进酒，杯莫停。\n与君歌一曲，请君为我侧耳听。\n钟鼓馔玉不足贵，但愿长醉不复醒。\n古来圣贤皆寂寞，惟有饮者留其名。\n陈王昔时宴平乐，斗酒十千恣欢谑。\n主人何为言少钱，径须酤取对君酌。\n五花马，千金裘，呼儿将出换美酒，与尔同销万古愁。' },
  { title: '鼓吹曲辞 将进酒', author: '李贺', poem: '将进酒，将进酒。\n酒中有毒酖主父，言之主父伤主母。\n母为妾地父妾天，仰天俯地不忍言。\n佯为僵踣主父前，主父不知加妾鞭。\n旁人知妾为主说，主将泪洗鞭头血。\n推摧主母牵下堂，扶妾遣升堂上床。\n将进酒，酒中无毒令主寿。\n愿主回思归主母，遣妾如此事主父。\n妾为此事人偶知，自慙不密方自悲。\n主今颠倒安置妾，贪天僭地谁不为。' },
  { title: '鼓吹曲辞 君马黄', author: '李白', poem: '君马黄，我马白。\n马色虽不同，人心本无隔。\n共作游冶盘，双行洛阳陌。\n长劒既照曜，高冠何赩赫。\n各有千金裘，俱为五侯客。\n猛虎落陷穽，壮夫时屈厄。\n相知在急难，独好亦何益。' },
  { title: '鼓吹曲辞 芳树', author: '沈佺期', poem: '何地早芳菲？宛在长门殿。\n夭桃色若绶，秾李光如练。\n啼鸟弄花疎，游蠭饮香徧。\n叹息春风起，飘零君不见。' },
  { title: '鼓吹曲辞 芳树', author: '卢照邻', poem: '芳树本多奇，年华复在斯。\n结翠成新幄，开红满旧枝。\n风归花历乱，日度影参差。\n容色朝朝落，思君君不知。' },
  { title: '鼓吹曲辞 芳树', author: '徐彦伯', poem: '玉花珍簟上，金缕画屏开。\n晓月怜筝柱，春风忆镜台。\n筝柱春风吹晓月，芳树落花朝暝歇。\n藳砧刀头未有时，攀条拭泪坐相思。' },
  { title: '鼓吹曲辞 芳树', author: '韦应物', poem: '迢迢芳园树，列映清池曲。\n对此伤人心，还如故时绿。\n风条洒余霭，露叶承新旭。\n佳人不再攀，下有往来躅。' },
  { title: '鼓吹曲辞 芳树', author: '元稹', poem: '芳树已寥落，孤英尤可嘉。\n可怜团团叶，盖覆深深花。\n游蠭竞攒刺，鬬雀亦纷拏。\n天生细碎物，不爱好光华。\n非无歼殄法，念尔有生涯。\n春雷一声发，惊燕亦惊蛇。\n清池养神蔡，已复长虾蟆。\n雨露贵平施，吾其春草芽。' },
  { title: '鼓吹曲辞 芳树', author: '罗隐', poem: '细蘂慢逐风，暖香闲破鼻。\n青帝固有心，时时动人意。\n去年高枝犹压地，今年低枝已顦顇。\n吾所以见造化之权，变通之理。\n春夏作头，秋冬为尾。\n循环反复无穷已，今生长短同一轨。\n若使威可以制，力可以止，秦皇不肯敛手下沙丘，孟贲不合低头入蒿里。\n伊人彊猛犹如此，顾我劳生何足恃？\n但愿开素袍，倾绿蚁，陶陶兀兀大醉于青冥白昼间。\n任他上是天，下是地。' },
  { title: '鼓吹曲辞 有所思', author: '沈佺期', poem: '君子事行役，再空芳岁期。\n美人旷延伫，万里浮云思。\n园槿绽红艳，郊桑柔绿滋。\n坐看长夏晚，秋月生罗帏。' },
  { title: '鼓吹曲辞 有所思', author: '李白', poem: '我思仙人，乃在碧海之东隅。\n海寒多天风，白波连山倒蓬壶。\n长鲸喷涌不可涉，抚心茫茫泪如珠。\n西来青鸟东飞去，愿寄一书谢麻姑。' },
  { title: '鼓吹曲辞 有所思', author: '孟郊', poem: '桔槔烽火昼不灭，客路迢迢信难越。\n古镇刀攒万片霜，寒江浪起千堆雪。\n此时西去定如何，空使南心远凄切。' },
  { title: '鼓吹曲辞 有所思', author: '卢仝', poem: '当时我醉美人家，美人颜色娇如花。\n今日美人弃我去，青楼珠箔天之涯。\n天涯娟娟常娥月，三五二八盈又缺。\n翠眉蝉鬓生别离，一望不见心断绝。\n心断绝，几千里，梦中醉卧巫山云。\n觉来泪滴湘江水，湘江两岸花木深。\n美人不见愁人心，含愁更奏绿绮琴，调高弦绝无知音。\n美人兮美人！不知为暮雨兮为朝云。\n相思一夜梅花发，忽到窗前疑是君。' },
  { title: '鼓吹曲辞 有所思', author: '韦应物', poem: '借问江上柳，青青为谁春。\n空游昨日地，不见昨日人。\n缭绕万家井，往来车马尘。\n莫道无相识，要非心所亲。' },
  { title: '鼓吹曲辞 有所思', author: '刘氏云', poem: '朝亦有所思，暮亦有所思。\n登楼望君处，蔼蔼浮云飞。\n浮云遮却阳关道，向晚谁知妾怀抱。\n玉井苍苔春院深，桐花落地无人扫。' },
  { title: '鼓吹曲辞 雉子班', author: '李白', poem: '辟邪伎作鼓吹惊，雉子班之奏曲成。\n喔咿振迅欲飞鸣，扇锦翼，雄风生。\n双雌同饮啄，趫悍谁能争。\n乍向草中耿介死，不求黄金笼下生。\n天地至广大，何惜遂物情。\n善卷让天子，务光亦逃名。\n所贵旷士怀，朗然合太清。' },
  { title: '鼓吹曲辞 临高台', author: '褚亮', poem: '高台暂俯临，飞翼耸轻音。\n浮光随日度，漾影逐波深。\n迥瞰周平野，开怀畅远襟。\n独此三休上，还伤千岁心。' },
  { title: '鼓吹曲辞 临高台', author: '王勃', poem: '临高台，高台迢递绝浮埃。\n瑶轩绮构何崔嵬，鸾歌凤吹清且哀。\n俯瞰长安道，萋萋御沟草。\n斜对甘泉路，苍苍茂陵树。\n高台四望同，帝乡佳气郁葱葱。\n紫阁丹楼纷照曜，璧房锦殿相玲珑。\n东弥长乐观，西指未央宫。\n赤城映朝日，绿树摇春风。\n旗亭百队开新市，甲第千甍分戚里。\n朱轮翠盖不胜春，叠树层楹相对起。\n复有青楼大道中，绣户文窗雕绮栊。\n锦衣昼不襞，罗帏夕未空。\n歌屏朝揜翠，妆镜晚窥红。\n为吾安宝髻，蛾眉罢花丛。\n狭路尘间黯将暮，云间月色明如素。\n鸳鸯池上两两飞，凤皇楼下双双度。\n物色正如此，佳期那不顾。\n银鞍绣毂盛繁华，可怜今夜宿倡家。\n倡家少妇不须嚬，东园桃李片时春。\n君看旧日高台处，柏梁铜雀生黄尘。' },
  { title: '鼓吹曲辞 临高台', author: '僧贯休', poem: '凉风吹远念，使我升高台。\n宁知数片云，不是旧山来。\n故人天一涯，久客殊未回。\n雁来不得书，空寄声哀哀。' },
  { title: '鼓吹曲辞 黄雀行', author: '庄南杰', poem: '穿屋穿墙不知止，争树争巢入营死。\n林间公子挟弹弓，一丸致毙花丛里。\n小雏黄口未有知，青天不解高高飞。\n虞人设网当要路，白日啾嘲祸万机。' },
  { title: '鼓吹曲辞 钓竿篇', author: '沈佺期', poem: '朝日敛红烟，垂竿向绿川。\n人疑天上坐，鱼似镜中悬。\n避檝时惊透，猜钩每误牵。\n湍危不理辖，潭静欲留船。\n钓玉君徒尚，征金我未贤。\n为看芳饵下，贪得会无全。' },
  { title: '鼓吹曲辞 凯歌六首 一', author: '岑参', poem: '汉将承恩西破戎，捷书先奏未央宫。\n天子预开麟阁待，祗今谁数贰师功。' },
  { title: '鼓吹曲辞 凯歌六首 二', author: '岑参', poem: '官军西出过楼兰，营幕傍临月窟寒。\n蒲海晓霜凝劒尾，葱山夜雪扑旌竿。' },
  { title: '鼓吹曲辞 凯歌六首 三', author: '岑参', poem: '鸣笳擂鼓拥回军，破国平蕃昔未闻。\n大夫鹊印摇边月，天将龙旗掣海云。' },
  { title: '鼓吹曲辞 凯歌六首 四', author: '岑参', poem: '月落辕门鼓角鸣，千群面缚出蕃城。\n洗兵鱼海云迎阵，秣马龙堆月照营。' },
  { title: '鼓吹曲辞 凯歌六首 五', author: '岑参', poem: '蕃军遥见汉家营，满谷连山徧哭声。\n万箭千刀一夜杀，平明流血浸空城。' },
  { title: '鼓吹曲辞 凯歌六首 六', author: '岑参', poem: '暮雨旌旗湿未干，胡尘白草日光寒。\n昨日将军连晓战，蕃军只见马空鞍。' },
  { title: '鼓吹曲辞 鼓吹铙歌 晋阳武', author: '柳宗元', poem: '晋阳武，奋义威。\n炀之渝，德焉归。\n氓毕屠，绥者谁。\n皇烈烈，专天机。\n号以仁，扬其旗。\n日之升，九土晞。\n斥田圻，流洪辉。\n有其二，翼余隋。\n斮枭骜，连熊螭。\n枯以肉，勍者羸。\n后土荡，玄穹弥。\n合之育，莽然施。\n惟德辅，庆无期。' },
  { title: '鼓吹曲辞 鼓吹铙歌 兽之穷', author: '柳宗元', poem: '兽之穷，奔大麓。\n天厚黄德，狙犷服。\n甲之櫜弓，弭矢箙。\n皇旅靖，敌逾蹙。\n自亡其徒，匪予戮。\n屈𧹁猛，虔栗栗。\n縻以尺组，噉以秩。\n黎之阳，土茫茫。\n富兵戎，盈仓箱。\n乏者德，莫能享。\n驱豺兕，授我疆。' },
  { title: '鼓吹曲辞 鼓吹铙歌 战武牢', author: '柳宗元', poem: '战武牢，动河朔。\n逆之助，图掎角。\n怒鷇麛，抗乔岳。\n翘萌牙，傲霜雹。\n王谋内定，申掌握。\n铺施芟夷，二主缚。\n惮华戎，廓封略。\n命之瞢，卑以斮。\n归有德，唯先觉。' },
  { title: '鼓吹曲辞 鼓吹铙歌 泾水黄', author: '柳宗元', poem: '泾水黄，陇野茫。\n负太白，腾天狼。\n有鸟鸷立，羽翼张。\n钩喙决前，巨趯傍。\n怒飞饥啸，翾不可当。\n老雄死，子复良。\n巢岐饮渭，肆翱翔。\n顿地纮，提天纲。\n列缺掉帜，招摇耀铓。\n鬼神来助，梦嘉祥。\n脑涂原野，魂飞扬。\n星辰复，恢一方。' },
  { title: '鼓吹曲辞 鼓吹铙歌 奔鲸沛', author: '柳宗元', poem: '奔鲸沛，荡海垠。\n吐霓翳日，腥浮云。\n帝怒下顾，哀垫昏。\n[授]以神柄，推元臣。\n手援天矛，截修鳞。\n披攘蒙霿，开海门。\n地平水静，浮天垠。\n羲和显耀，乘清氛。\n赫炎溥畅，融大钧。' },
  { title: '鼓吹曲辞 鼓吹铙歌 苞枿', author: '柳宗元', poem: '苞枿𪒶矣，惟根之蟠。\n弥巴蔽荆，负南极以安。\n曰我旧梁氏，辑绥艰难。\n江汉之阻，都邑固以完。\n圣人作，神武用。\n有臣勇智，奋不以众。\n投迹死地，谋猷纵。\n化敌为家，虑则中。\n浩浩海裔，不威而同。\n系缧降王，定厥功。\n澶漫万里，宣唐风。\n蛮夷九译，咸来从。\n凯旋金奏，象形容。\n震赫万国，罔不龚。' },
  { title: '鼓吹曲辞 鼓吹铙歌 河右平', author: '柳宗元', poem: '河右澶漫，顽为之魁。\n王师如雷震，昆仑以颓。\n上聋下聪，骜不可回。\n助雠抗有德，惟人之灾。\n乃溃乃奋，执缚归厥命。\n万室蒙其仁，一夫则病。\n濡以鸿泽，皇之圣。\n威畏德怀，功以定。\n顺之于理，物咸遂厥性。' },
  { title: '鼓吹曲辞 鼓吹铙歌 铁山碎', author: '柳宗元', poem: '铁山碎，大漠舒。\n二虏劲，连穹庐。\n背北海，专坤隅。\n岁来侵边，或傅于都。\n天子命元帅，奋其雄图。\n破定襄，降魁渠。\n穷竟窟宅，斥余吾。\n百蛮破胆，边氓苏。\n威武辉耀，明鬼区。\n利泽弥万祀，功不可逾。\n官臣拜手，惟帝之谟。' },
  { title: '鼓吹曲辞 鼓吹铙歌 靖本邦', author: '柳宗元', poem: '本邦伊晋，惟时不靖。\n根柢之摇，枝叶攸病。\n守臣不任，勚于神圣。\n惟钺之兴，翦焉则定。\n洪惟我理，式和以敬。\n群顽既夷，庶绩咸正。\n皇谟载大，惟人之庆。' },
  { title: '鼓吹曲辞 鼓吹铙歌 吐谷浑', author: '柳宗元', poem: '吐谷浑盛彊，背西海以夸。\n岁侵扰我疆，退匿险且遐。\n帝谓神武师，往征靖皇家。\n烈烈斾其旗，熊虎杂龙蛇。\n王旅千万人，衔枚默无哗。\n束刃逾山徼，张翼纵漠沙。\n一举刈膻腥，尸骸积如麻。\n除恶务本根，况敢遗萌芽。\n洋洋西海水，威命穷天涯。\n系虏来王都，犒乐穷休嘉。\n登高望还师，竟野如春华。\n行者靡不归，亲戚讙要遮。\n凯旋献清庙，万国思无邪。' },
  { title: '鼓吹曲辞 鼓吹铙歌 高昌', author: '柳宗元', poem: '曲氏雄西北，别绝臣外区。\n既恃远且险，纵傲不我虞。\n烈烈王者师，熊螭以为徒。\n龙旗飜海浪，驲骑驰坤隅。\n贲育搏婴儿，一扫不复余。\n平沙际天极，但见黄云驱。\n臣靖执长缨，智勇伏囚拘。\n文皇南面坐，夷狄千群趋。\n咸称天子神，往古不得俱。\n献号天可汗，以覆我国都。\n兵戎不交害，各保性与躯。' },
  { title: '鼓吹曲辞 鼓吹铙歌 东蛮', author: '柳宗元', poem: '东蛮有谢氏，冠带理海中。\n自言我异世，虽圣莫能通。\n王卒如飞翰，鹏𬸣骇群龙。\n轰然自天坠，乃信神武功。\n系虏君臣人，累累来自东。\n无思不服从，唐业如山崇。\n百辟拜稽首，咸愿图形容。\n如周王会书，永永传无穷。\n睢盱万状乖，咿嗢九译重。\n广轮抚四海，浩浩知皇风。\n歌诗铙鼓间，以壮我元戎。' },
  { title: '横吹曲辞 陇头', author: '张籍', poem: '陇头已断人不行，胡骑夜入凉州城。\n汉家处处格鬬死，一朝尽没陇西地。\n驱我边人胡中去，散放牛羊食禾黍。\n去年中国养子孙，今着毡裘学胡语。\n谁能更使李轻车，收取凉州属汉家。' },
  { title: '横吹曲辞 陇头吟', author: '王维', poem: '长安少年游侠客，夜上戍楼看太白。\n陇头明月迥临关，陇上行人夜吹笛。\n关西老将不胜愁，驻马听之双泪流。\n身经大小百余战，麾下偏裨万户侯。\n苏武才为典属国，节旄空尽海西头。' },
  { title: '横吹曲辞 陇头吟', author: '翁绶', poem: '陇水潺湲陇树黄，征人陇上尽思乡。\n马嘶斜日朔风急，雁过寒云边思长。\n残月出林明劒戟，平沙隔水见牛羊。\n横行俱足封侯者，谁斩楼兰献未央。' },
  { title: '横吹曲辞 陇头水', author: '杨师道', poem: '陇头秋月明，陇水带关城。\n笳添离别曲，风送断肠声。\n映雪峰犹暗，乘冰马屡惊。\n雾中寒雁至，沙上转蓬轻。\n天山传羽檄，汉地急征兵。\n阵开都护道，劒聚伏波营。\n于兹觉无度，方共濯胡缨。' },
  { title: '横吹曲辞 陇头水', author: '卢照邻', poem: '陇坂高无极，征人一望乡。\n关河别去水，沙塞断归肠。\n马系千年树，旌悬九月霜。\n从来共呜咽，皆是为勤王。' },
  { title: '横吹曲辞 陇头水', author: '王建', poem: '陇水何年陇头别，不在山中亦呜咽。\n征人塞耳马不行，未到陇头闻水声。\n谓是西流入蒲海，还闻北海绕龙城。\n陇东陇西多屈曲，野麋饮水长簇簇。\n胡兵夜回水傍住，忆着来时磨劒处。\n向前无井复无泉，放马回看陇头树。' },
  { title: '横吹曲辞 陇头水', author: '于𣸣', poem: '借问陇头水，终年恨何事。\n深疑呜咽声，中有征人泪。\n昨日上山下，达曙不能寐。\n何处接长波？东流入清渭。' },
  { title: '横吹曲辞 陇头水 一', author: '僧皎然', poem: '陇头心欲绝，陇水不堪闻。\n碎影摇枪垒，寒声咽帐军。\n素从盐海积，绿带柳城分。\n日落天边望，逶迤入塞云。' },
  { title: '横吹曲辞 陇头水 二', author: '僧皎然', poem: '秦陇逼氐羌，征人去未央。\n如何幽咽水，幷欲断君肠。\n西注悲穷漠，东分忆故乡。\n旅魂声搅乱，无梦到辽阳。' },
  { title: '横吹曲辞 陇头水', author: '鲍溶', poem: '陇头水，千古不堪闻。\n生归苏属国，死别李将军。\n细响风凋草，清哀雁落云。' },
  { title: '横吹曲辞 陇头水', author: '罗隐', poem: '借问陇头水，年年恨何事。\n全疑呜咽声，中有征人泪。\n自古无长策，况我非深智。\n何计谢潺湲，一宵空不寐。' },
  { title: '横吹曲辞 出关', author: '魏征', poem: '中原还逐鹿，投笔事戎轩。\n纵横计不就，慷慨志犹存。\n策杖谒天子，驱马出关门。\n请缨羁南越，凭轼下东藩。\n郁纡陟高岫，出没望平原。\n古木吟寒鸟，空山啼夜猨。\n既伤千里目，还惊九折魂。\n岂不惮艰险，深怀国士恩。\n季布无二诺，侯嬴重一言。\n人生感意气，功名谁复论。' },
  { title: '横吹曲辞 入关', author: '贾驰', poem: '河上微风来，关头树初湿。\n今朝关城吏，又见孤客入。\n上国谁与期，西来徒自急。' },
  { title: '横吹曲辞 入关', author: '张祜', poem: '都城连百二，雄险北回环。\n地势遥尊岳，河流侧让关。\n秦皇曾虎视，汉祖亦龙颜。\n何事枭凶辈，干戈自不闲。' },
  { title: '横吹曲辞 出塞', author: '窦威', poem: '匈奴屡不平，汉将欲纵横。\n看云方结阵，却月始连营。\n潜军度马邑，扬斾掩龙城。\n会勒燕然石，方传车骑名。' },
  { title: '横吹曲辞 出塞', author: '陈子昂', poem: '忽闻天上将，关塞重横行。\n始返楼兰国，还向朔方城。\n黄金装战马，白羽集神兵。\n星月开天阵，山川列地营。\n晚风吹画角，春色耀飞旌。\n宁知班定远，独是一书生。' },
  { title: '横吹曲辞 出塞', author: '张易之', poem: '侠客重恩光，骢马饰金装。\n瞥闻传羽檄，驰突救边荒。\n转战磨筓地，横行戴斗乡。\n将军占太白，小妇怨流黄。\n騕褭青丝骑，娉婷红粉妆。\n一春莺度曲，八月雁成行。\n谁堪坐秋思，罗袖拂空床。' },
  { title: '横吹曲辞 出塞', author: '沈佺期', poem: '十年通大漠，万里出长平。\n寒日生戈劒，阴云摇斾旌。\n饥乌啼旧垒，疲马恋空城。\n辛苦[皋兰]北，胡霜损汉兵。' },
  { title: '横吹曲辞 出塞', author: '王维', poem: '居延城外猎天骄，白草连天野火烧。\n暮云空碛时驱马，秋日平原好射雕。\n护羌校尉朝乘障，破虏将军夜渡辽。\n玉靶角弓珠勒马，汉家将赐霍嫖姚。' },
  { title: '横吹曲辞 出塞 一', author: '王昌龄', poem: '秦时明月汉时关，万里长征人未还。\n但使龙城飞将在，不教胡马度阴山。' },
  { title: '横吹曲辞 出塞 二', author: '王昌龄', poem: '白花垣上望京师，黄河水流无尽时。\n穷秋旷野行人绝，马首东来知是谁。' },
  { title: '横吹曲辞 出塞', author: '马戴', poem: '金带连环束战袍，马头冲雪度临洮。\n卷旗夜劫单于帐，乱斫胡兵缺宝刀。' },
  { title: '横吹曲辞 前出塞九首 一', author: '杜甫', poem: '戚戚去故里，悠悠赴交河。\n公家有程期，亡命婴祸罗。\n君已富土境，开边一何多？\n弃绝父母恩，吞声行负戈。' },
  { title: '横吹曲辞 前出塞九首 二', author: '杜甫', poem: '出门日已远，不受徒旅欺。\n骨肉恩岂断，男儿死无时。\n走马脱辔头，手中挑青丝。\n捷下万仞冈，俯身试搴旗。' },
  { title: '横吹曲辞 前出塞九首 三', author: '杜甫', poem: '磨刀呜咽水，水赤刃伤手。\n欲轻肠断声，心绪乱已久。\n丈夫誓许国，愤惋复何有？\n功名图麒麟，战骨当速朽。' },
  { title: '横吹曲辞 前出塞九首 四', author: '杜甫', poem: '送徒既有长，远戍亦有身。\n生死向前去，不劳吏怒嗔。\n路逢相识人，附书与六亲。\n哀哉两决绝，不复同苦辛。' },
  { title: '横吹曲辞 前出塞九首 五', author: '杜甫', poem: '迢迢万余里，领我赴三军。\n军中异苦乐，主将宁尽闻。\n隔河见胡骑，倏忽数百群。\n我始为奴仆，几时树功勋。' },
  { title: '横吹曲辞 前出塞九首 六', author: '杜甫', poem: '挽弓当挽彊，用箭当用长。\n射人先射马，擒贼先擒王。\n杀人亦有限，列国自有疆。\n苟能制侵陵，岂在多杀伤。' },
  { title: '横吹曲辞 前出塞九首 七', author: '杜甫', poem: '驱马天雨雪，军行入高山。\n迳危抱寒石，指落曾冰间。\n已去汉月远，何时筑城还？\n浮云暮南征，可望不可攀。' },
  { title: '横吹曲辞 前出塞九首 八', author: '杜甫', poem: '单于寇我垒，百里风尘昏。\n雄劒四五动，彼军为我奔。\n虏其名王归，系颈授辕门。\n潜身备行列，一胜何足论。' },
  { title: '横吹曲辞 前出塞九首 九', author: '杜甫', poem: '从军十年余，能无分寸功。\n众人贵苟得，欲语羞雷同。\n中原有鬬争，况在狄与戎。\n丈夫四方志，安可辞固穷。' },
  { title: '横吹曲辞 后出塞五首 一', author: '杜甫', poem: '男儿生世间，及壮当封侯。\n战伐有功业，焉能守旧丘。\n召募赴蓟门，军动不可留。\n千金买马鞭，百金装刀头。\n闾里送我行，亲戚拥道周。\n斑白居上列，酒酣进庶羞。\n少年别有赠，含笑看吴钩。' },
  { title: '横吹曲辞 后出塞五首 二', author: '杜甫', poem: '朝进东门营，暮上河阳桥。\n落日照大旗，马鸣风萧萧。\n平沙列万幕，部伍各见招。\n中天悬明月，令严夜寂寥。\n悲笳数声动，壮士惨不骄。\n借问大将谁，恐是霍嫖姚。' },
  { title: '横吹曲辞 后出塞五首 三', author: '杜甫', poem: '古人重守边，今人重高勋。\n岂知英雄主，出师亘长云。\n六合已一家，四夷且孤军。\n遂使貔虎士，奋身勇所闻。\n拔劒击大荒，日牧胡马群。\n誓开玄冥北，持以奉吾君。' },
  { title: '横吹曲辞 后出塞五首 四', author: '杜甫', poem: '献凯日继踵，两蕃静无虞。\n渔阳豪侠地，击鼓吹笙竽。\n云帆转辽海，粳稻来东吴。\n越罗与楚练，照耀舆台躯。\n主将位益崇，气骄陵上都。\n边人不敢议，议者死路衢。' },
  { title: '横吹曲辞 后出塞五首 五', author: '杜甫', poem: '我本良家子，出师亦多门。\n将骄益愁思，身贵不足论。\n跃马二十年，恐辜明主恩。\n坐见幽州骑，长驱河洛昏。\n中夜间道归，故里但空村。\n恶名幸脱免，穷老无儿孙。' },
  { title: '横吹曲辞 出塞', author: '皇甫冉', poem: '吹角出塞门，前瞻即胡地。\n三军尽回首，皆洒望乡泪。\n转念关山长，行看风景异。\n由来征戍客，各负轻生义。' },
  { title: '横吹曲辞 出塞', author: '王之涣', poem: '黄砂直上白云间，一片孤城万仞山。\n羌笛何须怨杨柳，春风不度玉门关。' },
  { title: '横吹曲辞 出塞', author: '耿[𣲗]', poem: '汉家边事重，窦宪出临戎。\n绝漠秋山在，阳关旧路通。\n列营依茂草，吹角向高风。\n更就燕然石，看铭破虏功。' },
  { title: '横吹曲辞 出塞', author: '张籍', poem: '秋塞雪初下，将军远出师。\n分营长记火，放马不收旗。\n月冷边帐湿，沙昏夜探迟。\n征人皆白首，谁见灭胡时。' },
  { title: '横吹曲辞 出塞', author: '刘驾', poem: '胡风不开花，四气多作雪。\n北人尚冻死，况我本南越。\n古来犬羊地，巡狩无遗辙。\n九土耕不尽，武皇犹征伐。\n中天有高阁，图画何时歇？\n坐恐塞上山，低于砂中骨。' },
  { title: '横吹曲辞 出塞曲', author: '刘济', poem: '将军在重围，音信绝不通。\n羽书如流星，飞人甘泉宫。\n倚是幷州儿，少年心胆雄。\n一朝随召募，百战争王公。\n去年桑干北，今年桑干东。\n死是征人死，功是将军功。\n汗马牧秋月，疲兵卧霜风。\n仍闻左贤王，更欲图云中。' },
  { title: '横吹曲辞 出塞曲 一', author: '于鹄', poem: '微雪将军出，吹笳天未明。\n观兵登古戍，斩将对双旌。\n分阵瞻山势，潜军制马鸣。\n如今新史上，已有灭胡名。' },
  { title: '横吹曲辞 出塞曲 二', author: '于鹄', poem: '单于骄爱猎，放火到军城。\n待月调新弩，防秋置远营。\n空山朱戟影，寒碛铁衣声。\n逢着降胡说，阴山有伏兵。' },
  { title: '横吹曲辞 出塞曲 一', author: '僧贯休', poem: '埽尽狂胡迹，回戈望故关。\n相逢唯死鬬，岂易得生还。\n纵宴参胡乐，收兵过雪山。\n不封十万户，此事亦应闲。' },
  { title: '横吹曲辞 出塞曲 二', author: '僧贯休', poem: '玉帐将军意，慇懃把酒论。\n功高宁在我，阵没与招魂。\n塞色干戈束，军容喜气屯。\n男儿今始是，敢出玉关门。' },
  { title: '横吹曲辞 出塞曲 三', author: '僧贯休', poem: '回首陇山头，连天草木秋。\n圣君应入梦，半路遣封侯。\n水不担阴雪，柴令倒戍楼。\n归来麟阁上，春色满皇州。' },
  { title: '横吹曲辞 入塞', author: '刘希夷', poem: '将军陷虏围，边务息戎机。\n霜雪交河尽，旌旗入塞飞。\n晓光随马度，春色伴人归。\n课绩朝明主，临轩拜武威。' },
  { title: '横吹曲辞 入塞曲', author: '耿[𣲗]', poem: '将军带十围，重锦制戎衣。\n猨臂销弓力，虬须长劒威。\n首登平乐宴，新破大宛归。\n楼上姝姬笑，门前问客稀。\n暮烽玄菟急，秋草紫骝肥。\n未奉君主诏，高槐昼掩扉。' },
  { title: '横吹曲辞 入塞曲 一', author: '僧贯休', poem: '单于烽火动，都护去天涯。\n别赐黄金甲，亲临白玉墀。\n塞垣须静谧，师旅审安危。\n定远条支宠，如今胜古时。' },
  { title: '横吹曲辞 入塞曲 二', author: '僧贯休', poem: '方见将军贵，分明对冕旒。\n圣恩如远被，狂虏不难收。\n臣节唯期死，功勋敢望侯。\n终辞修里第，从此出皇州。' },
  { title: '横吹曲辞 入塞曲 三', author: '僧贯休', poem: '百里精兵动，参差便渡辽。\n如何好白日，亦照此天骄。\n远树深疑贼，惊蓬迥似雕。\n凯歌何日唱？碛路共天遥。' },
  { title: '横吹曲辞 入塞曲 一', author: '沈彬', poem: '欲为皇王服远戎，万人金甲鼓鼙中。\n阵云暗塞三边黑，兵血愁天一片红。\n半夜飜营旗搅月，深秋防戍劒磨风。\n谤书未及明君𦶟，卧骨将军已殁功。' },
  { title: '横吹曲辞 入塞曲 二', author: '沈彬', poem: '苦战沙间卧箭痕，戍楼闲上望星文。\n生希国泽分偏将，死夺河源荅圣君。\n鸢覰败兵眠白草，马惊边鬼哭阴云。\n功多地远无人纪，汉阁笙歌日又曛。' },
  { title: '横吹曲辞 折杨柳', author: '卢照邻', poem: '倡楼启曙扉，园柳正依依。\n鸟鸣知岁隔，条变识春归。\n露叶疑啼脸，风花乱舞衣。\n攀折聊将寄，军中书信稀。' },
  { title: '横吹曲辞 折杨柳', author: '沈佺期', poem: '玉窗朝日映，罗帐春风吹。\n拭泪攀杨柳，长条宛地垂。\n白花飞历乱，黄鸟思参差。\n妾自肝肠断，旁人那得知。' },
  { title: '横吹曲辞 折杨柳', author: '乔知之', poem: '可怜濯濯春杨柳，攀折将来就纤手。\n妾容与此同盛衰，何必君恩独能久。' },
  { title: '横吹曲辞 折杨柳', author: '刘宪', poem: '沙塞三河道，金闺二月春。\n碧烟杨柳色，红粉绮罗人。\n露叶怜啼脸，风花思舞巾。\n攀持君不见，为听曲中新。' },
  { title: '横吹曲辞 折杨柳', author: '崔湜', poem: '二月风光半，三边戍不还。\n年华妾自惜，杨柳为君攀。\n落絮缘衫袖，垂条拂髻鬟。\n那堪音信断，流涕望阳关。' },
  { title: '横吹曲辞 折杨柳', author: '韦承庆', poem: '万里边城地，三春杨柳节。\n叶似镜中眉，花如关外雪。\n征人远乡思，倡妇高楼别。\n不忍掷年华，含情寄攀折。' },
  { title: '横吹曲辞 折杨柳', author: '欧阳瑾', poem: '垂柳拂妆台，葳蕤叶半开。\n年华枝上见，边思曲中来。\n嫩色宜新雨，轻花伴落梅。\n朝朝倦攀折，征戍几时回。' },
  { title: '横吹曲辞 折杨柳', author: '张祜', poem: '红粉青楼曙，垂杨仲月春。\n怀君重攀折，非妾妒腰身。\n舞带萦丝断，娇娥向叶嚬。\n横吹凡几曲，独自最愁人。' },
  { title: '横吹曲辞 折杨柳', author: '张九龄', poem: '纤纤折杨柳，持此寄情人。\n一枝何足贵，怜是故园春。\n迟景那能久，流芳不及新。\n更愁征戍客，鬓老边城尘。' },
  { title: '横吹曲辞 折杨柳', author: '余延寿', poem: '大道连国门，东西种杨柳。\n葳蕤君不见，褭娜垂来久。\n缘枝栖暝禽，雄去雌独吟。\n余花怨春尽，微月起秋阴。\n坐望窗中蝶，起攀枝上叶。\n好风吹长条，妸娜何如妾。\n妾见柳园新，高楼四五春。\n莫吹胡塞曲，愁杀陇头人。' },
  { title: '横吹曲辞 折杨柳', author: '李白', poem: '垂杨拂绿水，摇艳东风年。\n花明玉关雪，叶暖金窗烟。\n美人结长恨，相对心凄然。\n攀条折春色，远寄龙庭前。' },
  { title: '横吹曲辞 折杨柳 一', author: '孟郊', poem: '杨柳多短枝，短枝多别离。\n赠远累攀折，柔条安得垂。\n青春有定节，离别无定时。\n但恐人别促，不怨来迟迟。\n莫言短枝条，中有长相思。\n朱颜与绿杨，幷在别离期。' },
  { title: '横吹曲辞 折杨柳 二', author: '孟郊', poem: '楼上春风过，风前杨柳歌。\n枝疎缘别苦，曲怨为年多。\n花惊燕地雪，叶映楚池波。\n谁堪别离此，征戍在交河。' },
  { title: '横吹曲辞 折杨柳', author: '李端', poem: '东城攀柳叶，柳叶低着草。\n少壮莫轻年，轻年有人老。\n柳发徧川岗，登高堪断肠。\n雨烟轻漠漠，何树近君乡？\n赠君折杨柳，颜色岂能久。\n上客莫沾巾，佳人正回首。\n新柳送君行，古柳伤君情。\n突兀临荒渡，婆娑出旧营。\n隋家两岸尽，陶宅五株平。\n日暮偏愁望，春山有鸟声。' },
  { title: '横吹曲辞 折杨柳', author: '翁绶', poem: '紫陌金堤映绮罗，游人处处动离歌。\n阴移古戍迷荒草，花带残阳落远波。\n台上少年吹白雪，楼中思妇敛青蛾。\n殷勤攀折赠行客，此去关山雨雪多。' },
  { title: '横吹曲辞 望行人', author: '王建', poem: '自从江树秋，日日上江楼。\n梦见离珠浦，书来在桂州。\n不同鱼比目，终恨水分流。\n久不开明镜，多应是白头。' },
  { title: '横吹曲辞 望行人', author: '张籍', poem: '秋风窗下起，旅雁向南飞。\n日日出门望，家家行客归。\n无因见边使，空待寄寒衣。\n独闭青楼暮，烟深鸟雀稀。' },
  { title: '横吹曲辞 关山月', author: '卢照邻', poem: '塞垣通碣石，虏障抵祈连。\n相思在万里，明月正孤悬。\n影移金岫北，光断玉门前。\n寄书谢中妇，时看鸿雁天。' },
  { title: '横吹曲辞 关山月', author: '沈佺期', poem: '汉月生辽海，曈昽出半晖。\n合昏玄兔郡，中夜白登围。\n晕落关山迥，光合霜霰微。\n将军听晓角，战马欲南归。' },
  { title: '横吹曲辞 关山月', author: '李白', poem: '明月出天山，苍茫云海间。\n长风几万里，吹度玉门关。\n汉下白登道，胡窥青海湾。\n由来征战地，不见有人还。\n戍客望边色，思归多苦颜。\n高楼当此夜，叹息未应闲。' },
  { title: '横吹曲辞 关山月', author: '长孙佐辅', poem: '凄凄还切切，戍客多离别。\n何处最伤心？关山见秋月。\n关月竟如何？由来远近过。\n始经玄兔塞，终绕白狼河。\n忽忆秦楼妇，流光应共有。\n已得竝蛾眉，还知揽纤手。\n去岁照同行，比翼复连形。\n今宵照独立，顾影自茕茕。\n余晖渐西落，夜夜看如昨。\n借问映旌旗，何如鉴帷幕。\n拂晓朔风悲，蓬惊雁不飞。\n几时征戍罢，还向月中归。' },
  { title: '横吹曲辞 关山月', author: '耿[𣲗]', poem: '月明边徼静，戍客望乡时。\n塞古柳衰尽，关寒榆发迟。\n苍苍万里道，戚戚十年悲。\n今夜青楼上，还应照所思。' },
  { title: '横吹曲辞 关山月二首 一', author: '戴叔伦', poem: '月出照关山，秋风人未还。\n清光无远近，乡泪半书间。' },
  { title: '横吹曲辞 关山月二首 二', author: '戴叔伦', poem: '一雁过连营，繁霜覆古城。\n胡笳在何处？半夜起边声。' },
  { title: '横吹曲辞 关山月', author: '崔融', poem: '月生西海上，气逐边风壮。\n万里度关山，苍茫非一状。\n汉兵开郡国，胡马窥亭障。\n夜夜闻悲笳，征人起南望。' },
  { title: '横吹曲辞 关山月', author: '李端', poem: '露湿月苍苍，关头榆叶黄。\n回轮照海远，分彩上楼长。\n水冻频移幕，兵疲数望乡。\n祗应城影外，万里共如霜。' },
  { title: '横吹曲辞 关山月', author: '王建', poem: '关山月，营开道白前军发。\n冻轮当碛光悠悠，照见三堆两堆骨。\n边风割面天欲明，金莎岭西看看没。' },
  { title: '横吹曲辞 关山月', author: '张籍', poem: '秋月朗朗关山上，山中行人马蹄响。\n关山秋来雨雪多，行人见月唱边歌。\n海边漠漠天气白，胡儿夜度黄龙碛。\n军中探骑暮出城，伏兵暗处低旌戟。\n溪水连地霜草平，野𫘞寻水碛中鸣。\n陇头风急雁不下，沙场苦战多流星。\n可怜万国关山道，年年战骨多秋草。' },
  { title: '横吹曲辞 关山月', author: '翁绶', poem: '裴回汉月满边州，照尽天涯到陇头。\n影转银河寰海静，光分玉塞古今愁。\n笳吹远戍孤烽灭，雁下平沙万里秋。\n况是故园摇落夜，那堪少妇独登楼。' },
  { title: '横吹曲辞 关山月', author: '鲍氏君[徽]微', poem: '高高秋月明，北照辽阳城。\n塞迥光初满，风多晕更生。\n征人望乡思，战马闻鞞惊。\n朔风悲边草，胡沙昏虏营。\n霜疑匣中劒，风惫原上旌。\n早晚谒金阙，不闻刁斗声。' },
  { title: '横吹曲辞 洛阳道', author: '于武陵', poem: '浮世若浮云，千回故复新。\n旋添青草冢，更有白头人。\n岁暮客将老，雪晴山欲春。\n行行车与马，不尽洛阳尘。' },
  { title: '横吹曲辞 洛阳道', author: '郑渥', poem: '客亭门外路东西，多少喧腾事不齐。\n杨柳惹鞭公子醉，纻麻掩泪鲁人迷。\n通宵尘土飞山月，是处经营夹御堤。\n顷刻知音几存殁，半回依约认轮蹄。' },
  { title: '横吹曲辞 洛阳陌', author: '李白', poem: '白玉谁家郎，回车渡天津。\n看花东上陌，惊动洛阳人。' },
  { title: '横吹曲辞 长安道', author: '崔颢', poem: '长安甲第高入云，谁家居住霍将军。\n日晚朝回拥宾从，路傍拜揖何纷纷。\n莫言炙手手可热，须臾火尽灰亦灭。\n莫言贫贱即可欺，人生富贵自有时。\n一朝天子赐颜色，世上悠悠应始知。' },
  { title: '横吹曲辞 长安道', author: '孟郊', poem: '胡风激秦树，贱子风中泣。\n家家朱门开，得见不可入。\n长安十二衢，投树鸟亦急。\n高阁何人家？笙簧正喧吸。' },
  { title: '横吹曲辞 长安道', author: '聂夷中', poem: '此地无驻马，夜中犹走轮。\n所以路旁草，少于衣上尘。' },
  { title: '横吹曲辞 长安道', author: '韦应物', poem: '汉家宫殿含云烟，两宫十里相连延。\n晨霞出没弄丹阙，春雨依微自甘泉。\n春雨依微春尚早，长安贵游爱芳草。\n宝马横来下建章，香车却转避驰道。\n贵游谁最贵，卫霍世难比。\n何能蒙主恩？幸遇边尘起。\n归来甲第拱皇居，朱门峨峨临九衢。\n中有流苏合欢之宝帐，一百二十凤皇罗列含明珠。\n下有锦铺翠被之粲烂，博山吐香五云散。\n丽人绮阁情飘飖，头上鸳钗双翠翘。\n低鬟曳袖回春雪，聚黛一声愁碧霄。\n山珍海错弃藩篱，烹犊炰羔如折葵。\n既请列侯封部曲，还将金印授庐儿。\n欢荣若此何所苦，但苦白日西南驰。' },
  { title: '横吹曲辞 长安道', author: '白居易', poem: '花枝缺处青楼开，艳歌一曲酒一杯。\n美人劝我急行乐，自古朱颜不再来。\n君不见外州客，长安道，一回来，一回老。' },
  { title: '横吹曲辞 长安道', author: '薛能', poem: '汲汲复营营，东西连两京。\n关𦈡古若在，山岳累应成。\n各自有身事，不相知姓名。\n交驰喧众类，分散入重城。\n此路去无尽，万方人始生。\n空余片言苦，来往觅刘桢。' },
  { title: '横吹曲辞 长安道', author: '僧贯休', poem: '憧憧合合，八表一辙。\n黄尘雾合，车马火热。\n名汤风雨，利辗霜雪。\n千车万駄，半宿关月。\n上有尧禹，下有夔契。\n紫气银轮兮常覆金阙，仙掌捧日兮浊河澄澈。\n愚将草木兮有言，与华封人兮不别。' },
  { title: '横吹曲辞 长安道', author: '沈佺期', poem: '秦地平如掌，层城出云汉。\n楼阁九衢春，车马千门旦。\n绿柳开复合，红尘聚还散。\n日晚鬬鸡回，经过狭斜看。' },
  { title: '横吹曲辞 梅花落', author: '卢照邻', poem: '梅岭花初发，天山雪未开。\n雪处疑花满，花边似雪回。\n因风入舞袖，杂粉向妆台。\n匈奴几万里，春至不知来。' },
  { title: '横吹曲辞 梅花落', author: '沈佺期', poem: '铁骑几时回，金闺怨早梅。\n雪中花已落，风暖叶应开。\n夕逐新春管，香迎小岁杯。\n感时何足贵，书里报轮台。' },
  { title: '横吹曲辞 梅花落', author: '刘方平', poem: '新岁芳梅树，繁苞四面同。\n春风吹渐落，一夜几枝空。\n小妇今如此，长城恨不穷。\n莫将辽海雪，来比后庭中。' },
  { title: '横吹曲辞 紫骝马', author: '卢照邻', poem: '骝马照金鞍，转战入皐兰。\n塞门风稍急，长城水正寒。\n雪暗鸣珂重，山长喷玉难。\n不辞横绝漠，流血几时干。' },
  { title: '横吹曲辞 紫骝马', author: '李白', poem: '紫骝行且嘶，双飜碧玉蹄。\n临流不肎渡，似惜锦障泥。\n白雪关山远，黄云海树迷。\n挥鞭万里去，安得念春闺。' },
  { title: '横吹曲辞 紫骝马', author: '李益', poem: '争场看鬬鸡，白鼻紫䯄嘶。\n漳水春归晚，丛台日向低。\n歇鞍珠作汗，试劒玉如泥。\n为谢红梁燕，年年妾独栖。' },
  { title: '横吹曲辞 紫骝马', author: '秦韬玉', poem: '渥洼奇骨本难求，况是豪家重紫骝。\n臕大宜悬银压銙，力浑欺却玉衔头。\n生狞弄影风随起，躞蹀冲尘汗满沟。\n若遇丈夫皆调御，任从骑取觅封侯。' },
  { title: '横吹曲辞 骢马', author: '李群玉', poem: '浮云何权奇，绝足势未知。\n长嘶青海风，躞蹀振云丝。\n由来渥洼种，本是苍龙儿。\n穆满不再活，无人昆阆骑。\n君识跃峤怯，宁劳耀金羁。\n青刍与白水，空笑驽骀肥。\n伯乐傥一见，应惊耳长垂。\n当思八荒外，逐日向瑶池。' },
  { title: '横吹曲辞 骢马曲', author: '纪唐天', poem: '连钱出塞蹋沙蓬，岂比当时御史骢。\n逐北自谙深碛路，连嘶谁念静边功。\n登山每与青云合，弄影应知碧草同。\n今日虏平将换妾，不如罗袖舞春风。' },
  { title: '横吹曲辞 雨雪曲', author: '李端', poem: '天山一丈雪，杂雨夜霏霏。\n湿马胡歌乱，经烽汉火微。\n丁零苏武别，疎勒范羌归。\n若着关头过，长榆叶定稀。' },
  { title: '横吹曲辞 雨雪曲', author: '翁绶', poem: '边声四合殷河流，雨雪飞来徧陇头。\n铁岭探人迷鸟道，阴山飞将湿貂裘。\n斜飘旌斾过戎帐，半杂风沙入戍楼。' },
  { title: '横吹曲辞 刘生', author: '卢照邻', poem: '刘生气不平，抱劒欲专征。\n报恩为豪侠，死难在横行。\n翠羽装劒鞘，黄金饰马缨。\n但令一顾重，不吝百身轻。' },
  { title: '横吹曲辞 雍台歌', author: '温庭筠', poem: '太子池南楼百尺，八窗新树疎帘隔。\n黄金铺首画钩陈，羽葆亭童拂交戟。\n盘纡阑楯临高台，帐殿临流鸾扇开。\n早雁声鸣细波起，映花卤簿龙飞回。' },
  { title: '横吹曲辞 捉搦歌', author: '张祜', poem: '门上关，墙上棘，窗中女子声唧唧，洛阳大道徒自直。\n女子心在婆舍侧，呜呜笼鸟触四隅。\n养男男娶妇，养女女嫁夫。\n阿婆六十翁七十，不知女子长日泣，从他嫁去无悒悒。' },
  { title: '横吹曲辞 幽州胡马客歌', author: '李白', poem: '幽州胡马客，绿眼虎皮冠。\n笑拂两只箭，万人不可干。\n弯弓若转月，白雁落云端。\n双双掉鞭行，游猎向楼兰。\n出门不顾后，报国死何难。\n天骄五单于，狼戾好凶残。\n牛马散北海，割鲜若虎餐。\n虽居燕支山，不道朔雪寒。\n妇女马上笑，颜如赪玉盘。\n飜入射鸟兽，花月醉雕鞍。\n旄头四光芒，争战若蜂攒。\n白刃洒赤血，流沙为之丹。\n名将古谁是，疲兵良可叹。\n何时天狼灭？父子得闲安。' },
  { title: '横吹曲辞 白鼻䯄', author: '李白', poem: '银鞍白鼻䯄，绿地障泥锦。\n细雨春风花落时，挥鞭且就胡姬饮。' },
  { title: '横吹曲辞 白鼻䯄', author: '张祜', poem: '为底胡姬酒，长来白鼻䯄。\n摘莲抛水上，郎意在浮花。' },
  { title: '相和歌辞 箜篌引', author: '李贺', poem: '公乎公乎，提壶将焉如？\n屈平沈湘不足慕，徐衍入海诚为愚。\n公乎公乎，床有菅席盘有鱼。\n北里有贤兄，东邻有小姑。\n陇亩油油黍与葫，瓦甒浊醪蚁浮浮。\n黍可食，醪可饮，公乎公乎其奈居。\n被发奔流竟何如？贤兄小姑哭呜呜。' },
  { title: '相和歌辞 公无渡河', author: '李白', poem: '黄河西来决崐崘，咆吼万里触龙门。\n波滔天，尧咨嗟。\n大禹理百川，儿啼不窥家。\n杀湍湮洪水，九州始蚕麻。\n其害乃去，茫然风沙。\n被发之叟狂而痴，清晨径流欲奚为。\n旁人不惜妻止之，公无渡河苦渡之。\n虎可搏，河难凭。\n公果溺死流海湄，有长鲸白齿若雪山。\n公乎公乎，挂骨于其间，箜篌所悲竟不还。' },
  { title: '相和歌辞 公无渡河', author: '王建', poem: '渡头恶天两岸远，波涛塞川如叠坂。\n幸无白刃驱向前，何用将身自弃捐。\n蛟龙啮尸鱼食血，黄泥直下无青天。\n男儿纵轻妇人语，惜君性命还须取。\n妇人无力挽断衣，舟沈身死悔难追，公无渡河公自为。' },
  { title: '相和歌辞 公无渡河', author: '温庭筠', poem: '黄河怒浪连天来，大响谹谹如殷雷。\n龙伯驱风不敢上，百川喷雪高崔嵬。\n二十五弦何太哀？请公勿渡立裴回。\n下有狂蛟锯为尾，裂帆截櫂磨霜齿。\n神锥凿石塞神潭，白马𫎺𧽼赤尘起。\n公乎跃马扬玉鞭，灭没高蹄日千里。' },
  { title: '相和歌辞 公无渡河', author: '王叡', poem: '浊波洋洋兮凝晓雾，公无渡河兮公苦渡。\n风号水激兮呼不闻，提壶看入兮中流去。\n浪摆衣裳兮随步没，沈尸深入兮蛟螭窟。\n蛟螭尽醉兮君血干，推出黄沙兮泛君骨。\n当时君死妾何适？遂就波澜合魂魄。\n愿持精卫衔石心，穷取河源塞泉脉。' },
  { title: '相和歌辞 江南曲', author: '宋之问', poem: '妾住越城南，离居不自堪。\n采花惊曙鸟，摘叶𫗪春蚕。\n嬾结茱萸带，愁安玳瑁簪。\n侍臣消瘦尽，日暮碧江潭。' },
  { title: '相和歌辞 江南曲', author: '刘眘虚', poem: '美人何荡漾，湖上风月长。\n玉手欲有赠，裴回双鸣珰。\n歌声随渌水，怨色起朝阳。\n日暮还家望，云波横洞房。' },
  { title: '相和歌辞 江南曲', author: '丁仙芝', poem: '长干斜路北，近浦是儿家。\n有意来相访，明朝出浣纱。\n发向横塘口，船开值急流。\n知郎旧时意，且请拢船头。\n昨暝逗南陵，风声波浪阻。\n入浦不逢人，归家谁信汝。\n未晓已成妆，乘潮去茫茫。\n因从京口渡，使报邵陵王。\n始下芙蓉楼，言发琅邪岸。\n急为打船开，恶许傍人见。' },
  { title: '相和歌辞 江南曲八首 一', author: '刘希夷', poem: '暮宿南洲草，晨行北岸林。\n日悬沧海阔，水隔洞庭深。\n烟景无留意，风波有异浔。\n岁游难极目，春戏易为心。\n朝夕无荣遇，芳菲已满襟。' },
  { title: '相和歌辞 江南曲八首 二', author: '刘希夷', poem: '艳唱潮初落，江花露未晞。\n春洲惊翡翠，朱服弄芳菲。\n画舫烟中浅，青阳日际微。\n锦帆冲浪湿，罗袖拂行衣。\n含情罢所采，相叹惜流晖。' },
  { title: '相和歌辞 江南曲八首 三', author: '刘希夷', poem: '君为陇西客，妾遇江南春。\n朝游含灵果，夕采弄风苹。\n果气时不歇，苹花日自新。\n以此江南物，持赠陇西人。\n空盈万里怀，欲赠竟无因。' },
  { title: '相和歌辞 江南曲八首 四', author: '刘希夷', poem: '皓如楚江月，霭若吴岫云。\n波中自皎镜，山上亦氛氲。\n明月留照妾，轻云持赠君。\n山川各离散，光气乃殊分。\n天涯一为别，江北自相闻。' },
  { title: '相和歌辞 江南曲八首 五', author: '刘希夷', poem: '舣舟乘潮去，风帆振草凉。\n潮平见楚甸，天际望维扬。\n洄溯经千里，烟波接两乡。\n云明江屿出，日照海流长。\n此中逢岁晏，浦树落花芳。' },
  { title: '相和歌辞 江南曲八首 六', author: '刘希夷', poem: '暮春三月晴，维扬吴楚城。\n城临大江汜，回映洞浦清。\n晴云曲金阁，珠楼碧烟里。\n月明芳树群鸟飞，风过长林杂花起。\n可怜离别谁家子，于此一至情何已。' },
  { title: '相和歌辞 江南曲八首 七', author: '刘希夷', poem: '北堂红草盛丰茸，南湖碧水照芙蓉。\n朝游暮起金花尽，渐觉罗裳珠露浓。\n自惜妍华三五岁，已叹关山千万重。\n人情一去无还日，欲赠怀芳怨不逢。' },
  { title: '相和歌辞 江南曲八首 八', author: '刘希夷', poem: '忆昔江南年盛时，平生怨在长洲曲。\n冠盖星繁湘水上，冲风摽落洞庭渌。\n落花舞袖红纷纷，朝霞高阁洗晴云。\n谁言此处婵娟子，珠玉为心以奉君。' },
  { title: '相和歌辞 江南曲', author: '于鹄', poem: '偶向江边采白苹，还随女伴赛江神。\n众中不敢分明语，暗掷金钱卜远人。' },
  { title: '相和歌辞 江南曲', author: '李益', poem: '嫁得瞿塘贾，朝朝误妾期。\n早知潮有信，嫁与弄潮儿。' },
  { title: '相和歌辞 江南曲', author: '李贺', poem: '汀洲白苹草，柳恽乘马归。\n江头樝树香，岸上蝴蝶飞。\n酒杯若叶露，玉轸蜀桐虚。\n朱楼通水陌，沙暖一双鱼。' },
  { title: '相和歌辞 江南曲', author: '李商隐', poem: '郎船安两桨，侬舸动双桡。\n埽黛开宫额，裁裙约楚腰。\n乖期方积思，临醉欲拚娇。\n莫以采菱唱，欲羡秦台箫。' },
  { title: '相和歌辞 江南曲', author: '韩翃', poem: '长乐花枝雨点消，江城日暮好相邀。\n春楼不闭葳蕤锁，绿水回通宛转桥。' },
  { title: '相和歌辞 江南曲', author: '温庭筠', poem: '妾家白苹浦，日上芙蓉檝。\n轧轧摇桨声，移舟入茭叶。\n溪长茭叶深，作底难相寻。\n避郎郎不见，㶉𫛶自浮沈。\n拾萍萍无根，采莲莲有子。\n不作浮萍生，宁作藕花死。\n岸傍骑马郎，乌帽紫游缰。\n含愁复含笑，回首问横塘。\n妾住金陵步，门前朱雀航。\n流苏持作帐，芙蓉持作梁。\n出入金犊幰，兄弟侍中郎。\n前年学歌舞，定得郎相许。\n连娟眉绕山，依约腰如杵。\n凤管悲若咽，鸾弦娇欲语。\n扇薄露红𫓪，罗轻压金缕。\n明月西南楼，珠帘玳瑁钩。\n横波巧能笑，弯蛾不识愁。\n花开子留树，草长根依土。\n早闻金沟远，底事归郎许。\n不学杨白花，朝朝泪如雨。' },
  { title: '相和歌辞 江南曲', author: '张籍', poem: '江南人家多橘树，吴姬舟上织白纻。\n土地卑湿饶虫蛇，连木为牌入江住。\n江村亥日长为市，落帆渡桥来浦里。\n青莎覆城竹为屋，无井家家饮潮水。\n长江午日酤春酒，高高酒旗悬江口。\n倡楼两岸悬水栅，夜唱竹枝留北客。\n江南风土欢乐多，悠悠处处尽经过。' },
  { title: '相和歌辞 江南曲', author: '罗隐', poem: '江烟湿雨鲛绡輭，漠漠远山眉黛浅。\n水国多愁又有情，夜槽压酒银船满。\n绷丝采怨凝晓空，吴王台榭春梦中。\n鸳鸯㶉𫛶唤不起，平铺渌水眠东风。\n西陵路边月悄悄，油壁轻车嫁苏小。' },
  { title: '相和歌辞 江南曲', author: '陆龟蒙', poem: '为爱江南雪，涉江聊采苹。\n水深烟浩浩，空对双车轮。\n车轮明月团，车盖浮云盘。\n云月徒自好，水中行路难。\n遥遥洛阳道，夹岸生春草。\n寄语櫂船郎，莫夸风浪好。' },
  { title: '相和歌辞 江南曲 一', author: '陆龟蒙', poem: '鱼戏莲叶间，参差隐叶扇。\n䴔䴖鸀鳿窥，潋滟无因见。' },
  { title: '相和歌辞 江南曲 二', author: '陆龟蒙', poem: '鱼戏莲叶东，初霞射红尾。\n傍临谢山侧，恰值清风起。' },
  { title: '相和歌辞 江南曲 三', author: '陆龟蒙', poem: '鱼戏莲叶西，盘盘舞波急。\n潜依曲岸凉，正对斜光入。' },
  { title: '相和歌辞 江南曲 四', author: '陆龟蒙', poem: '鱼戏莲叶南，欹危午烟叠。\n光摇越鸟巢，影乱吴娃檝。' },
  { title: '相和歌辞 江南曲 五', author: '陆龟蒙', poem: '鱼戏莲叶北，澄阳动微涟。\n回看帝子渚，稍背鄂君船。' },
  { title: '相和歌辞 度关山', author: '李端', poem: '雁塞日初晴，胡关雪复平。\n危竿缘广漠，古窦傍长城。\n拔劒金星出，弯弧玉羽鸣。\n谁知系虏者，贾谊是书生。' },
  { title: '相和歌辞 关山曲 一', author: '马戴', poem: '金锁耀兜鍪，黄云拂紫骝。\n叛羌旗下戮，陷壁夜中收。\n霜霰戎衣故，关河碛气秋。\n箭创殊未合，更遣击兰州。' },
  { title: '相和歌辞 关山曲 二', author: '马戴', poem: '火发龙山北，中宵易左贤。\n勒兵临汉水，惊雁散胡天。\n木落防河急，军孤受敌偏。\n犹闻汉皇怒，按劒待开边。' },
  { title: '相和歌辞 登高丘而望远', author: '李白', poem: '登高丘而望远海，六鼇骨已霜，三山流安在。\n扶桑半摧折，白日沈光彩。\n银台金阙如梦中，秦皇汉武空相待。\n精卫费木石，鼋鼍无所凭。\n君不见骊山茂陵尽灰灭，牧羊之子来攀登。\n盗贼劫宝玉，精灵竟何能。' },
  { title: '相和歌辞 蒿里', author: '僧贯休', poem: '兔不迟，乌更急，但恐穆王八骏，着鞭不及。\n所以蒿里，坟出蕺蕺，气凌云天，龙腾凤集，尽为风消土吃，狐掇蚁拾。\n黄金不啼玉不泣，白杨骚屑。\n乱风愁月，折碑石人。\n莽秽榛没，牛羊窸窣。\n时见牧童儿，弄枯骨。' },
  { title: '相和歌辞 挽歌', author: '赵微明', poem: '寒日蒿上明，凄凄郭东路。\n素车谁家子，丹旐引将去。\n原下荆棘丛，丛边有新墓。\n人间痛伤别，此是长别处。\n旷野何萧条，青松白杨树。' },
  { title: '相和歌辞 挽歌二首 一', author: '于鹄', poem: '阴风吹黄蒿，挽歌渡秋水。\n车马却归城，孤坟月明里。' },
  { title: '相和歌辞 挽歌二首 二', author: '于鹄', poem: '双辙出郭门，緜緜东西道。\n送死多于生，几人得终老。\n见人切肺肝，不如归山好。\n不闻哀哭声，默默安怀抱。\n时尽从物化，又免生忧扰。\n世间寿者稀，尽为悲伤恼。' },
  { title: '相和歌辞 挽歌', author: '孟云卿', poem: '草草门巷喧，涂车俨成位。\n冥寞何所须，尽我生人意。\n北邙路非远，此别终天地。\n临穴频抚棺，至哀反无泪。\n尔形未衰老，尔息犹童穉。\n骨肉不可离，皇天若容易。\n房帷即虚张，庭宇为哀次。\n薤露歌若斯，人生尽如寄。' },
  { title: '相和歌辞 挽歌', author: '白居易', poem: '丹旐何飞扬，素骖亦悲鸣。\n晨光照闾巷，輀车俨欲行。\n萧条九月天，哀挽出重城。\n借问送者谁，妻子与弟兄。\n苍苍上古原，峨峨开新茔。\n含酸一恸哭，异口同哀声。\n旧垄转芜绝，新坟日罗列。\n春风草绿北邙山，此地年年生死别。' },
  { title: '相和歌辞 对酒', author: '崔国辅', poem: '行行日将夕，荒村古冢无人迹。\n朦胧荆棘一鸟飞，屡唱提壶酤酒吃。\n古人不达酒不足，遗恨精灵传此曲。\n寄言当代诸少年，平生且尽杯中渌。' },
  { title: '相和歌辞 对酒二首 一', author: '李白', poem: '松子栖金华，安期入蓬海。\n此人古之仙，羽化竟何在？\n浮生速流电，倏忽变光彩。\n天地无凋换，容颜有迁改。\n对酒不肯饮，含情欲谁待。' },
  { title: '相和歌辞 对酒二首 二', author: '李白', poem: '劝君莫拒杯，春风笑人来。\n桃李如旧识，倾花向我开。\n流莺啼碧树，明月窥金罍。\n昨来朱颜子，今日白发催。\n棘生石虎殿，鹿走姑苏台。\n自古帝王宅，城阙闭黄埃。\n君若不饮酒，昔人安在哉。' },
  { title: '相和歌辞 陌上桑', author: '李白', poem: '美女渭桥东，春还事蚕作。\n五马如飞龙，青丝结金络。\n不知谁家子，调笑来相谑。\n妾本秦罗敷，玉颜艳名都。\n绿条映素手，采桑向城隅。\n使君且不顾，况复论秋胡。\n寒螀爱碧草，鸣凤栖青梧。\n托心自有处，但怪傍人愚。\n徒令白日暮，高驾空踟蹰。' },
  { title: '相和歌辞 陌上桑', author: '常建', poem: '翳翳陌上桑，南枝交北堂。\n美人金梯出，素手自提筐。\n非但畏蚕饥，盈盈娇路傍。' },
  { title: '相和歌辞 陌上桑', author: '陆龟蒙', poem: '皓齿还如贝色含，长眉亦似烟华贴。\n邻娃尽着绣裆襦，独自提筐采蚕叶。' },
  { title: '相和歌辞 采桑', author: '郎大家宋氏', poem: '春来南雁归，日去西蚕远。\n妾思纷何极，客游殊未返。' },
  { title: '相和歌辞 采桑', author: '刘希夷', poem: '杨柳送行人，青青西入秦。\n秦家采桑女，楼上不胜春。\n盈盈灞水曲，步步春芳绿。\n红脸耀明珠，绛唇含白玉。\n回首渭桥东，遥怜树色同。\n青丝娇落日，缃绮弄春风。\n携笼长叹息，逶迤恋春色。\n看花若有情，倚树疑无力。\n薄暮思悠悠，使君南陌头。\n相逢不相识，归去梦青楼。' },
  { title: '相和歌辞 采桑', author: '李彦𬀩', poem: '采桑畏日高，不待春眠足。\n攀条有余愁，那矜貌如玉。\n千金岂不赠，五马空踟躅。\n何以变真性，幽篁雪中绿。' },
  { title: '相和歌辞 采桑', author: '王建', poem: '鸟鸣桑叶间，叶绿条复柔。\n攀看去手近，放下长长钩。\n黄花盖野田，白马少年游。\n所念岂回顾，良人在高楼。' },
  { title: '相和歌辞 日出行', author: '李白', poem: '日出东方隈，似从地底来。\n历天又入海，六龙所舍安在哉？\n其始与终古不息，人非元气安能与之久裴回。\n草不谢荣于春风，木不怨落于秋天。\n谁挥鞭策驱四运，万物兴歇皆自然。\n羲和羲和，汝奚汩没于荒淫之波。\n鲁阳何德？驻景挥戈。\n逆道违天，矫诬实多。\n吾将囊括大块，浩然与溟涬同科。' },
  { title: '相和歌辞 日出行', author: '李贺', poem: '白日下崐崘，发光如舒丝。\n徒照葵藿心，不照游子悲。\n折折黄河曲，日从中央转。\n旸谷耳曾闻，若木眼不见。\n奈何铄石，胡为销人。\n羿弯弓属矢那不中，足令久不得奔，讵教晨光夕昏。' },
  { title: '相和歌辞 王昭君', author: '崔国辅', poem: '汉使南还尽，胡中妾独存。\n紫台緜望绝，秋草不堪论。' },
  { title: '相和歌辞 王昭君', author: '卢照邻', poem: '合殿恩中绝，交河使渐稀。\n肝肠辞玉辇，形影向金微。\n汉宫草应绿，胡庭沙正飞。\n愿逐三秋雁，年年一度归。' },
  { title: '相和歌辞 王昭君', author: '骆宾王', poem: '敛容辞豹尾，缄怨度龙鳞。\n金钿明汉月，玉箸染胡尘。\n妆镜菱花暗，愁眉柳叶嚬。\n惟有清笳曲，时闻芳树春。' },
  { title: '相和歌辞 王昭君', author: '沈佺期', poem: '非君惜鸾殿，非妾妬蛾眉。\n薄命由骄虏，无情是画师。\n嫁来胡地恶，不竝汉宫时。\n心苦无聊赖，何堪上马辞。' },
  { title: '相和歌辞 王昭君', author: '梁献', poem: '图画失天真，容华坐误人。\n君恩不可再，妾命在和亲。\n泪点关山月，衣销边塞尘。\n一闻阳鸟至，思绝汉宫春。' },
  { title: '相和歌辞 王昭君', author: '上官仪', poem: '玉关春色晚，金河路几千。\n琴悲桂条上，笛怨柳花前。\n雾掩临妆月，风惊入鬓蝉。\n缄书待还使，泪尽白云天。' },
  { title: '相和歌辞 王昭君', author: '董思恭', poem: '琵琶马上弹，行路曲中难。\n汉月正南远，燕山直北寒。\n髻鬟风拂散，眉黛雪沾残。\n斟酌红颜尽，何劳镜里看。' },
  { title: '相和歌辞 王昭君', author: '顾朝阳', poem: '莫将铅粉匣，不用镜花光。\n一去边城路，何情更画妆。\n影销胡地月，衣尽汉宫香。\n妾死非关命，祗缘怨断肠。' },
  { title: '相和歌辞 王昭君三首 一', author: '东方虬', poem: '汉道初全盛，朝廷足武臣。\n何须薄命妾，辛苦事和亲。' },
  { title: '相和歌辞 王昭君三首 二', author: '东方虬', poem: '揜涕辞丹凤，衔悲向白龙。\n单于浪惊喜，无复旧时容。' },
  { title: '相和歌辞 王昭君三首 三', author: '东方虬', poem: '胡地无花草，春来不似春。\n自然衣带缓，非是为腰身。' },
  { title: '相和歌辞 王昭君三首 一', author: '郭元振', poem: '自嫁单于国，长衔汉掖悲。\n容颜日顦顇，有甚画图时。' },
  { title: '相和歌辞 王昭君三首 二', author: '郭元振', poem: '厌践冰霜域，嗟为边塞人。\n思从汉南猎，一见汉家尘。' },
  { title: '相和歌辞 王昭君三首 三', author: '郭元振', poem: '闻有南河信，传闻杀画师。\n始知君惠重，更遣画蛾眉。' },
  { title: '相和歌辞 王昭君', author: '刘长卿', poem: '自矜妖艳色，不顾丹青人。\n那知粉缋能相负，却使容华飜误身。\n上马辞君嫁骄虏，玉颜对人啼不语。\n北风雁急浮清秋，万里独见黄河流。\n纤腰不复汉宫宠，双蛾长向胡天愁。\n琵琶弦中苦调多，萧萧羌笛声相和。\n可怜一曲传乐府，能使千秋伤绮罗。' },
  { title: '相和歌辞 王昭君二首 一', author: '李白', poem: '汉家秦地月，流影照明妃。\n一上玉关道，天涯去不归。\n汉月还从东海出，明妃西嫁无来日。\n燕支长寒雪作花，蛾眉顦顇没胡沙。\n生乏黄金枉图画，死留青冢使人嗟。' },
  { title: '相和歌辞 王昭君二首 二', author: '李白', poem: '昭君拂玉鞍，上马啼红颊。\n今日汉宫人，明朝胡地妾。' },
  { title: '相和歌辞 王昭君', author: '储光羲', poem: '日暮惊沙乱雪飞，傍人相劝易罗衣。\n强来前帐看歌舞，共待单于夜猎归。' },
  { title: '相和歌辞 王昭君', author: '僧皎然', poem: '自倚婵娟望主恩，谁知美恶忽相飜。\n黄金不买汉宫貌，青冢空埋胡地魂。' },
  { title: '相和歌辞 王昭君二首 一', author: '白居易', poem: '满面胡沙满鬓风，眉销残黛脸销红。\n愁苦辛勤顦顇尽，如今却似画图中。' },
  { title: '相和歌辞 王昭君', author: '令狐楚', poem: '锦车天外去，毳幕云中开。\n魏阙苍龙远，萧关赤雁哀。' },
  { title: '相和歌辞 王昭君', author: '张仲素', poem: '仙娥今下嫁，骄子自同和。\n劒戟归田尽，牛羊绕塞多。' },
  { title: '相和歌辞 王昭君', author: '李商隐', poem: '毛延寿画欲通神，忍为黄金不为人。\n马上琵琶行万里，汉宫长有隔生春。' },
  { title: '相和歌辞 明妃曲', author: '王偃', poem: '北望单于日半斜，明君马上泣胡沙。\n一双泪滴黄河水，应得东流入汉家。' },
  { title: '相和歌辞 昭君词', author: '张文琮', poem: '戒途飞万里，回首望三秦。\n忽见天山雪，还疑上苑春。\n玉痕垂泪粉，罗袂拂胡尘。\n为得胡中曲，还悲远嫁人。' },
  { title: '相和歌辞 昭君词', author: '陈昭', poem: '跨鞍今永诀，垂泪别亲宾。\n汉地行将远，胡关逐望新。\n交河拥塞路，陇首暗沙尘。\n唯有孤明月，犹能远送人。' },
  { title: '相和歌辞 昭君词', author: '戴叔伦', poem: '汉宫若远近，路在寒沙上。\n到死不得归，何人共南望。' },
  { title: '相和歌辞 昭君词', author: '李端', poem: '李陵初送子卿回，汉月明明照帐来。\n忆着长安旧游处，千门万户玉楼台。' },
  { title: '相和歌辞 楚妃叹', author: '张籍', poem: '湘云初起江沈沈，君王遥在云梦林。\n江南雨多旌旗暗，台下朝朝春水深。\n章华殿前朝万国，君心独自终无极。\n楚兵满地能逐禽，谁用一身继筋力。\n西江若飜云梦中，麋鹿死尽应还宫。' },
  { title: '相和歌辞 楚妃怨', author: '张籍', poem: '梧桐叶下黄金井，横架辘轳牵素绠。\n美人初起天未明，手拂银缾秋水冷。' },
  { title: '相和歌辞 王子乔', author: '宋之问', poem: '王子乔，爱神仙，七月七日上宾天。\n白虎摇瑟凤吹笙，乘骑云气吸日精。\n吸日精，长不归，遗庙今在而人非。\n空望山头草，草露湿君衣。' },
  { title: '相和歌辞 蜀国弦', author: '李贺', poem: '枫香晚华静，锦水南山影。\n惊石坠猨哀，竹云愁半岭。\n凉月生秋浦，玉沙鳞鳞光。\n谁家红泪客，不忍过瞿塘。' },
  { title: '相和歌辞 长歌行', author: '李白', poem: '桃李得日开，荣华照当年。\n东风动百物，草木尽欲言。\n枯枝无丑叶，涸水吐清泉。\n大力运天地，羲和无停鞭。\n功名不早着，竹帛将何宣？\n桃李务青春，谁能贯白日。\n富贵与神仙，蹉跎成两失。\n金石犹销铄，风霜无久质。\n畏落日月后，强欢歌与酒。\n秋霜不惜人，倏忽侵蒲柳。' },
  { title: '相和歌辞 长歌行', author: '王昌龄', poem: '旷野饶悲风，飕飕黄蒿草。\n系马停白杨，谁知我怀抱。\n所是同袍者，相逢尽衰老。\n况登汉家陵，南望长安道。\n下有枯树根，上有鼷鼠窠。\n高皇子孙尽，千古无人过。\n宝玉频发掘，精灵其奈何？\n人生须达命，有酒且长歌。' },
  { title: '相和歌辞 短歌行', author: '聂夷中', poem: '八月木荫薄，十叶三堕枝。\n人生过五十，亦已同此时。\n朝出东郭门，嘉树郁参差。\n暮出西郭门，原草已离披。\n南邻好台榭，北邻善歌吹。\n荣华忽消歇，四顾令人悲。\n生死与荣辱，四者乃常期。\n古人耻其名，没世无人知。\n无言鬓似霜，勿谓发如丝。' },
  { title: '相和歌辞 短歌行', author: '李白', poem: '白日何短短，百年苦易满。\n苍穹浩茫茫，万劫太极长。\n麻姑垂两鬓，一半已成霜。\n天公见玉女，大笑亿千场。\n吾欲搅六龙，回车挂扶桑。\n北斗酌美酒，劝龙各一觞。\n富贵非所愿，为人驻颓光。' },
  { title: '相和歌辞 短歌行六首 一', author: '顾况', poem: '城边路，今人犂田昔人墓。\n岸上沙，昔时江水今人家。\n今人昔人共长叹，四气相催节回换。\n明月皎皎入华池，白云离离度清汉。' },
  { title: '相和歌辞 短歌行六首 二', author: '顾况', poem: '我欲升天天隔霄，我思渡水水无桥。\n我欲上山山路险，我欲汲井井泉遥。\n越人翠被今何夕，独立沙边江草碧。' },
  { title: '相和歌辞 短歌行六首 三', author: '顾况', poem: '新系青丝百尺绳，心在君家辘轳上。\n我心皎洁君不知，辘轳一转一惆怅。' },
  { title: '相和歌辞 短歌行六首 四', author: '顾况', poem: '何处春风吹晓幕？江南绿水通朱阁。\n美人二八面如花，泣向东风畏花落。' },
  { title: '相和歌辞 短歌行六首 五', author: '顾况', poem: '临春风，听春鸟。\n别时多，见时少。\n愁人夜永不得眠，瑶井玉绳相向晓。' },
  { title: '相和歌辞 短歌行六首 六', author: '顾况', poem: '轩辕皇帝初得仙，鼎湖一去三千年。\n周流三十六洞天，洞中日月星辰连。\n骑龙驾景游八极，轩辕弓劒无人识，东海青童寄消息。' },
  { title: '相和歌辞 短歌行', author: '王建', poem: '人初生，日初出。\n上山迟，下山疾。\n百年三万六千朝，夜里分将彊半日。\n有歌有舞间早为，昨日健于今日时。\n人家见生男女好，不知男女催人老。\n短歌行，无乐声。' },
  { title: '相和歌辞 短歌行', author: '张籍', poem: '青天荡荡高且虚，上有白日无根株。\n流光暂出还入地，催我少年不须臾。\n与君相逢不寂寞，衰老不复如今乐。\n玉卮盛酒置君前，再拜愿君千万年。' },
  { title: '相和歌辞 短歌行二首 一', author: '白居易', poem: '曈曈太阳如火色，上行千里下一刻。\n出为白昼入为夜，圜转如珠住不得。\n住不得，可奈何？为君举酒歌短歌。\n歌声苦，词亦苦，四座少年君听取。\n今夕未竟明夕催，秋风才往春风回。\n人无根蔕时不驻，朱颜白日相隳颓。\n劝君且强笑一面，劝君复强饮一杯。\n人生不得长欢乐，年少须臾老到来。' },
  { title: '相和歌辞 短歌行二首 二', author: '白居易', poem: '世人求富贵，多为身嗜欲。\n盛衰不自由，得失常相逐。\n问君少年日，苦学将干禄。\n负笈尘中游，抱书雪前宿。\n布衾不周体，藜茄才充腹。\n三十登宦途，五十被朝服。\n奴温已挟纩，马肥初食粟。\n未敢议欢游，尚为名检束。\n耳目聋暗后，堂上调丝竹。\n牙齿缺落时，盘中堆酒肉。\n彼来此已去，外余中不足。\n少壮与荣华，相避如寒燠。\n青云去地远，白日终天速。\n从古无奈何，短歌听一曲。' },
  { title: '相和歌辞 短歌行', author: '陆龟蒙', poem: '爪牙在身上，陷穽犹可制。\n爪牙在胷中，劒戟无所畏。\n人言畏猛虎，谁是撩头毙。\n祗见古来心，奸雄暗相噬。' },
  { title: '相和歌辞 短歌行', author: '僧皎然', poem: '古人若不死，吾亦何所悲。\n萧萧烟雨九原上，白杨青松葬者谁。\n贵贱同一尘，死生同一指。\n人生在世共如此，何异浮云与流水。\n短歌行，短歌无穷日已倾。\n邺宫梁苑徒有名，春草秋风伤我情。\n何为不学金仙侣？一悟空王无死生。' },
  { title: '相和歌辞 铜雀台', author: '王无竞', poem: '北登铜雀上，西望青松郭。\n𰬸帐空苍苍，陵田纷漠漠。\n平生事已变，歌吹宛犹昨。\n长袖拂玉麈，遗情结罗幕。\n妾怨在朝露，君恩岂中薄。\n高台奏曲终，曲终泪横落。' },
  { title: '相和歌辞 铜雀台', author: '郑愔', poem: '日斜漳浦望，风起邺台寒。\n玉座平生晚，金尊妓吹阑。\n舞余依帐泣，歌罢向陵看。\n萧索松风暮，愁烟入井阑。' },
  { title: '相和歌辞 铜雀台', author: '刘长卿', poem: '娇爱更何日？高台空数层。\n含啼映双袖，不忍看西陵。\n漳河东流无复来，百花辇路为苍苔。\n青楼月夜长寂寞，碧云日暮空裴回。\n君不见邺中万事非昔时，古人何在今人悲。\n春风不逐君王去，草色年年旧宫路。\n宫中歌舞已浮云，空指行人往来处。' },
  { title: '相和歌辞 铜雀台', author: '贾至', poem: '日暮铜雀静，西陵鸟雀归。\n抚弦心断绝，听管泪霏霏。\n灵几临朝奠，空床卷夜衣。\n苍苍川上月，应照妾魂飞。' },
  { title: '相和歌辞 铜雀台', author: '罗隐', poem: '强歌强舞竟难胜，花落花开泪满缯。\n祗合当年伴君死，免教顦顇望西陵。' },
  { title: '相和歌辞 铜雀台', author: '薛能', poem: '魏帝当时铜雀台，黄花深映棘丛开。\n人生富贵须回首，此地岂无歌舞来。' },
  { title: '相和歌辞 铜雀台', author: '张氏琰', poem: '君王冥寞不可见，铜雀歌舞空裴回。\n西陵啧啧悲宿鸟，空殿沈沈闭青苔。\n青苔无人迹，红粉空相哀。' },
  { title: '相和歌辞 铜雀台', author: '梁氏琼', poem: '歌扇向陵开，齐行奠玉杯。\n舞时飞燕列，梦里片云来。\n月色空余恨，松声暮更哀。\n谁怜未死妾，掩袂下铜台。' },
  { title: '相和歌辞 铜雀妓 一', author: '王勃', poem: '妾本深宫妓，曾城闭九重。\n君王欢爱尽，歌舞为谁容。\n锦衾不复襞，罗衣谁再缝。\n高台西北望，流涕向青松。' },
  { title: '相和歌辞 铜雀妓 二', author: '王勃', poem: '金凤邻铜雀，漳河望邺城。\n君王无处所，台榭若平生。\n舞筵纷可就，歌梁俨未倾。\n西陵松槚冷，谁见绮罗情。' },
  { title: '相和歌辞 铜雀妓', author: '沈佺期', poem: '昔年分鼎地，今日望陵台。\n一旦雄图尽，千秋遗令开。\n绮罗君不见，歌舞妾空来。\n恩共漳河水，东流无重回。' },
  { title: '相和歌辞 铜雀妓', author: '乔知之', poem: '金阁惜分香，𫓪华不重妆。\n空余歌舞地，犹是为君王。\n哀弦调已绝，艳曲不须长。\n共看西陵暮，秋烟生白杨。' },
  { title: '相和歌辞 铜雀妓', author: '王适', poem: '日暮铜雀迥，幽声玉座清。\n萧森松柏望，委郁绮罗情。\n君恩不再重，妾舞为谁轻。' },
  { title: '相和歌辞 铜雀妓', author: '欧阳詹', poem: '萧条登古台，回首黄金屋。\n落叶不归林，高陵永为谷。\n妆容徒自丽，舞态阅谁目。\n惆怅𰬸帷前，歌声苦于哭。' },
  { title: '相和歌辞 铜雀妓', author: '袁晖', poem: '君爱本相饶，从来事舞腰。\n那堪攀玉座，肠断望陵朝。\n怨着情无主，哀凝曲不调。\n况临松日暮，悲吹坐萧萧。' },
  { title: '相和歌辞 铜雀妓', author: '刘商', poem: '魏主矜蛾眉，美人美于玉。\n高台无昼夜，歌舞竟未足。\n盛色如转圜，夕阳落深谷。\n仍令身殁后，尚足平生欲。\n红粉横泪痕，调弦空向屋。\n举头君不在，唯见西陵木。\n玉辇岂再来，娇鬟为谁绿。\n那堪秋风里，更舞阳春曲。\n曲终情不胜，阑干向西哭。\n台边生野草，来去罥罗縠。\n况复陵寝间，双双见麋鹿。' },
  { title: '相和歌辞 铜雀妓', author: '李贺', poem: '佳人一壶酒，秋容满千里。\n石马卧新烟，忧来何所似？\n歌声且潜弄，陵树风自起。\n长裾压高台，泪眼看花机。' },
  { title: '相和歌辞 铜雀妓', author: '吴烛', poem: '秋色西陵满绿芜，繁弦急管彊欢娱。\n长舒罗袖不成舞，却向风前承泪珠。' },
  { title: '相和歌辞 铜雀妓', author: '朱光弼', poem: '魏王铜雀妓，日暮管弦清。\n一见西陵树，悲心舞不成。' },
  { title: '相和歌辞 铜雀妓', author: '朱放', poem: '恨唱歌声咽，愁飜舞袖迟。\n西陵日欲暮，是妾断肠时。' },
  { title: '相和歌辞 铜雀妓', author: '僧皎然', poem: '彊开尊酒向陵看，忆得君王旧日欢。\n不觉余歌悲自断，非关艳曲转声难。' },
  { title: '相和歌辞 雀台怨', author: '马戴', poem: '魏宫歌舞地，蝶戏鸟还鸣。\n玉座人难到，铜台雨滴平。\n西陵树不见，漳浦草空生。\n万恨尽埋此，徒悬千载名。' },
  { title: '相和歌辞 雀台怨', author: '程氏长文', poem: '君王去后行人绝，萧竽不响歌喉咽。\n雄劒无威光彩沈，宝琴零落金星灭。\n玉阶寂寂坠秋露，月照当时歌舞处。\n当时歌舞人不回，化为今日西陵灰。' },
  { title: '相和歌辞 置酒行', author: '李益', poem: '置酒命所欢，凭觞遂为戚。\n日往不再来，兹辰坐成昔。\n百龄非长久，五十将半百。\n胡为劳我形，已须还复白。\n西山鸾鹤顾，矫矫烟雾翮。\n明霞发金丹，阴洞潜水碧。\n安得凌风羽，崦嵫驻灵魄。\n兀然坐衰老，慙叹东陵柏。' },
  { title: '相和歌辞 置酒行', author: '陆龟蒙', poem: '落尘花片排香痕，阑珊醉露栖愁魂。\n洞庭波色惜不得，东风领入黄金尊。\n千筠掷毫春谱大，碧舞红啼相唱和。\n安知寂寞西海头，青𥳇未垂孤凤饿。' },
  { title: '相和歌辞 长歌续短歌', author: '李贺', poem: '长歌破衣襟，短歌断白发。\n秦王不可见，旦夕成内热。\n渴饮壶中酒，饥拔陇头粟。\n凄凄四月兰，千里一时绿。\n夜峰何离离，月明落石底。\n裴回沿石寻，照出高峰外。\n不得与之游，歌成鬓先改。' },
  { title: '相和歌辞 猛虎行', author: '储光羲', poem: '寒亦不忧雪，饥亦不食人。\n人血岂不甘，所恶伤明神。\n太室为我宅，孟门为我邻。\n百兽为我膳，五龙为我宾。\n蒙马一何威，浮江亦以仁。\n彩章耀朝日，牙爪雄武臣。\n高云逐气浮，厚地随声振。\n君能贾余勇，日夕长相亲。' },
  { title: '相和歌辞 猛虎行', author: '李白', poem: '朝作猛虎行，暮作猛虎吟。\n肠断非关陇头水，泪下不为雍门琴。\n旌旗缤纷两河道，战鼓惊山欲倾倒。\n秦人半作燕地囚，胡马飜衔洛阳草。\n一输一失关下兵，朝降夕叛幽蓟城。\n巨鼇未斩海水动，鱼龙奔走安得宁。\n颇似楚汉时，飜覆无定止。\n朝过博浪沙，暮入淮阴市。\n张良未遇韩信贫，刘项存亡在两臣。\n暂到下邳受兵略，来投漂母作主人。\n贤哲栖栖古如此，今时亦弃青云士。\n有策不敢犯龙鳞，窜身南国避胡尘。\n宝书长劒挂高阁，金鞍骏马散故人。\n昨日方为宣城客，掣铃交通二千石。\n有时六博快壮心，绕床三帀呼一掷。\n楚人每道张旭奇，心藏风云世莫知。\n三吴邦伯多顾盼，四海雄侠皆相推。\n萧曹曾作沛中吏，攀龙附凤当有时。\n溧阳酒楼三月春，杨花漠漠愁杀人。\n胡人绿眼吹玉笛，吴歌白纻飞梁尘。\n丈夫相见且为乐，槌牛挝鼓会众宾。\n我从此去钓东海，得鱼笑寄情相亲。' },
  { title: '相和歌辞 猛虎行', author: '韩愈', poem: '猛虎虽云恶，亦各有匹侪。\n群行深谷间，百兽望风低。\n身食黄熊父，子食赤豹麛。\n择肉于熊罴，肎视兔与貍。\n正昼当谷眠，眼有百步威。\n自矜无当对，气性纵以乖。\n朝怒杀其子，暮还飧其妃。\n匹侪四散走，猛虎还孤栖。\n狐鸣门四旁，乌鹊从噪之。\n出逐猴入居，虎不知所归。\n谁云猛虎恶，中路正悲啼。\n豹来衔其尾，熊来攫其颐。\n猛虎死不辞，但慙前所为。\n虎坐无助死，况如汝细微。\n故当结以信，亲当结以私。\n亲故且不保，人谁信汝为。' },
  { title: '相和歌辞 猛虎行', author: '张籍', poem: '南山北山树冥冥，猛虎白日绕林行。\n向晚一身当道食，山中麋鹿尽无声。\n年年养子在深谷，雌雄上山不相逐。\n谷中近窟有山村，长向村家取黄犊。\n五陵年少不敢射，空来林下看行迹。' },
  { title: '相和歌辞 猛虎行', author: '李贺', poem: '长戈莫舂，彊弩莫烹。\n乳孙哺子，教得生狞。\n举头为城，掉尾为旌。\n东海黄公，愁见夜行。\n道逢驺虞，牛哀不平。\n生何用尺刀，壁上雷鸣。\n泰山之下，妇人哭声。\n官家有程，吏不敢听。' },
  { title: '相和歌辞 猛虎行', author: '僧齐己', poem: '磨尔牙，错尔爪，狐莫威，兔莫狡，饮来吞噬取肠饱。\n横行不怕日月明，皇天产尔为生狞。' },
  { title: '相和歌辞 君子行', author: '僧齐己', poem: '圣人不生，麟龙何瑞？\n梧桐不高，凤皇何止？\n吾闻古之有君子，行藏以时，进退求己。\n荣必为天下荣，耻必为天下耻。' },
  { title: '相和歌辞 燕歌行', author: '高适', poem: '汉家烟尘在东北，汉将辞家破残贼。\n男儿本自重横行，天子非常赐颜色。\n𪭢金伐鼓下榆关，旌旗逶迤碣石间。\n校尉羽书飞瀚海，单于猎火照狼山。\n山川萧条极边土，胡骑凭凌杂风雨。\n战士军前半死生，美人帐下犹歌舞。\n大漠穷秋塞草衰，孤城落日鬬兵稀。\n身当恩遇常轻敌，力尽关山未解围。\n铁衣远戍辛勤久，玉箸应啼别离后。\n少妇城南欲断肠，征人蓟北空回首。\n边风飘飘那可度，绝域苍茫更何有。\n杀气三日作阵云，寒声一夜传刁斗。\n相看白刃血纷纷，死节从来岂顾勋。\n君不见沙场征战苦，至今犹忆李将军。' },
  { title: '相和歌辞 燕歌行', author: '贾至', poem: '国之重镇惟幽都，东威九夷制北胡。\n五军精卒三十万，百战百胜擒单于。\n前临滹沲后沮水，崇山沃野亘千里。\n昔时燕王重贤士，黄金筑台从隗始。\n倏忽兴王定蓟丘，汉家又以封王侯。\n萧条魏晋为横流，鲜卑窃据朝五州。\n我唐区夏余十纪，军容武备赫万祀。\n彤弓黄钺授元帅，垦耕大漠为内地。\n季秋胶折边草腓，治兵羽猎因出师。\n千营万队连旌旗，望之如火忽雷驰。\n匈奴慑窜穷发北，大荒万里无尘飞。\n隋家昔为天下宰，穷兵黩武征辽海。\n南风不竞多死声，鼓卧旗折黄云横。\n六军将士皆死尽，战马空鞍归故营。\n时迁道革天下平，白环入贡沧海清。\n自有农夫已高枕，无劳校尉重横行。' },
  { title: '相和歌辞 燕歌行', author: '陶翰', poem: '请君留楚调，听我吟燕歌。\n家在辽水头，边风意气多。\n出身为汉将，正值戎未和。\n雪中凌天山，冰上渡交河。\n大小百余战，封侯竟蹉跎。\n归来霸陵下，故旧无相过。\n雄劒委尘匣，空门唯雀罗。\n玉𥮾还赵女，宝瑟付齐娥。' },
  { title: '相和歌辞 从军行二首 一', author: '虞世南', poem: '涂山烽候惊，弭节度龙城。\n冀马楼兰将，燕犀上谷兵。\n劒寒花不落，弓晓月逾明。\n凛凛严霜节，冰壮黄河绝。\n蔽日卷征蓬，浮天散飞雪。\n全兵值月满，精骑乘胶折。\n结发早驱驰，辛苦事旌麾。\n马冻重关冷，轮摧九折危。\n独有西山将，年年属数奇。' },
  { title: '相和歌辞 从军行二首 二', author: '虞世南', poem: '爟火发金微，连营出武威。\n孤城寒云起，绝阵虏尘飞。\n侠客吸龙劒，恶少缦胡衣。\n朝摩骨都垒，夜解谷蠡围。\n萧关远无极，蒲海广难依。\n沙磴离旌断，晴川候马归。\n交河梁已毕，燕山斾欲飞。\n方知万里相，侯服有光辉。' },
  { title: '相和歌辞 从军行', author: '骆宾王', poem: '平生一顾念，意气溢三军。\n野日分戈影，天星合劒文。\n弓弦抱汉月，马足践胡尘。\n不求生入塞，唯当死报君。' },
  { title: '相和歌辞 从军行', author: '刘希夷', poem: '秋来风瑟瑟，群马胡行疾。\n严城昼不开，伏兵暗相失。\n天子庙堂拜，将军玉门出。\n纷纷伊洛间，戎马数千匹。\n军门压黄河，兵气冲白日。\n平生怀伏劒，忼慨既投笔。\n南登汉月孤，北走燕云密。\n近取韩彭计，早知孙吴术。\n丈夫清万里，谁能埽一室。' },
  { title: '相和歌辞 从军行', author: '乔知之', poem: '南庭结白露，北风埽黄叶。\n此时鸿燕来，惊鸣催思妾。\n曲房理针线，平碪捣文练。\n鸳绮裁易成，龙乡信难见。\n窈窕九重闺，寂寞十年啼。\n纱窗白云宿，罗幌月光栖。\n云月晓微微，愁思流黄机。\n玉霜冻珠履，金吹薄罗衣。\n汉家已得地，君去将何事？\n宛转结蚕书，寂寞无雁使。\n生平荷恩信，本为容华进。\n况复落红颜，蝉声催绿鬓。' },
  { title: '相和歌辞 从军行', author: '李颀', poem: '白日登山望烽火，昏黄饮马傍交河。\n行人刁斗风砂暗，公主琵琶幽怨多。\n野营万里无城郭，雨雪纷纷连大漠。\n胡雁哀鸣夜夜飞，胡儿眼泪双双落。\n闻道玉门犹被遮，应将性命逐轻车。\n年年战骨埋荒外，空见蒲萄入汉家。' },
  { title: '相和歌辞 从军行三首 一', author: '李约', poem: '看图闲教阵，画地静论边。\n乌垒天西戍，鹰姿塞上川。\n路长须算日，书远每题年。\n无复生还望，飜思未别前。' },
  { title: '相和歌辞 从军行三首 二', author: '李约', poem: '栅高三面鬬，箭尽举烽频。\n营柳和烟暮，关榆带雪春。\n边城多老将，碛路少归人。\n点尽三河卒，年年添塞尘。' },
  { title: '相和歌辞 从军行三首 三', author: '李约', poem: '候火起雕城，尘砂拥战声。\n游军藏汉帜，降骑说蕃情。\n霜降滮池浅，秋深太白明。\n嫖姚方虎视，不觉请添兵。' },
  { title: '相和歌辞 从军行', author: '戎昱', poem: '昔从李都尉，双鞬照马蹄。\n擒生黑山北，杀敌黄云西。\n太白沈虏地，边草复萋萋。\n归来邯郸市，百尺青楼梯。\n感激然诺重，平生胆力齐。\n芳筵暮歌发，艳粉轻鬟低。\n半醉秋风起，铁骑门前嘶。\n远戍报烽火，孤城严鼓鼙。\n挥鞭望尘去，少妇莫含啼。' },
  { title: '相和歌辞 从军行', author: '厉玄', poem: '边草早不春，劒花增泞尘。\n广场收骥尾，清瀚怯龙鳞。\n帆色已归越，松声厌避秦。\n几时逢范蠡，处处是通津。' },
  { title: '相和歌辞 从军行二首 一', author: '李白', poem: '从军玉门道，逐虏金微山。\n笛奏梅花曲，刀开明月环。\n鼓声鸣海上，兵气拥云间。\n愿斩单于首，长驱静铁关。' },
  { title: '相和歌辞 从军行二首 二', author: '李白', poem: '百战沙场碎铁衣，城南已合数重围。\n突营射杀呼延将，独领残兵千骑归。' },
  { title: '相和歌辞 从军行', author: '王维', poem: '吹角动行人，喧喧行人起。\n笳鸣马嘶乱，争渡金河水。\n日暮沙漠垂，战声烟尘里。\n尽系名王颈，归来报天子。' },
  { title: '相和歌辞 从军行', author: '王昌龄', poem: '向夕临大荒，朔风轸归虑。\n平沙万里余，飞鸟宿何处？\n虏骑猎长原，翩翩傍河去。\n边声摇白草，海气生黄雾。\n百战苦风尘，十年履霜露。\n虽投定远笔，未坐将军树。\n早知行路难，悔不理章句。' },
  { title: '相和歌辞 从军行 二', author: '王昌龄', poem: '烽火城西百尺楼，黄昏独上海风秋。\n更吹横笛关山月，谁解金闺万里愁。' },
  { title: '相和歌辞 从军行 三', author: '王昌龄', poem: '琵琶起舞换新声，总是关山旧别情。\n撩乱边愁弹不尽，高高秋月下长城。' },
  { title: '相和歌辞 从军行 四', author: '王昌龄', poem: '青海长云暗雪山，孤城遥望雁门关。\n黄沙百战穿金甲，不破楼兰终不还。' },
  { title: '相和歌辞 从军行', author: '卢纶', poem: '二十在边城，军中得勇名。\n卷旗收败马，断碛拥残兵。\n覆阵乌鸢起，烧山草木明。\n塞闲思远猎，师老厌分营。\n雪岭无人迹，冰河足雁声。\n李陵甘此没，惆怅汉公卿。' },
  { title: '相和歌辞 从军行六首 一', author: '刘长卿', poem: '回看虏骑合，城下汉兵稀。\n白刃两相向，黄云愁不飞。\n手中无尺铁，徒欲突重围。' },
  { title: '相和歌辞 从军行六首 二', author: '刘长卿', poem: '落日更萧条，北方动枯草。\n将军追虏骑，夜失阴山道。\n战败仍树勋，韩彭但空老。' },
  { title: '相和歌辞 从军行六首 三', author: '刘长卿', poem: '草枯秋塞上，望见渔阳郭。\n胡马嘶一声，汉兵泪双落。\n谁为吮痈者，此事令人薄。' },
  { title: '相和歌辞 从军行六首 四', author: '刘长卿', poem: '目极雁门道，青青边草春。\n一身事征战，匹马同辛勤。\n末路成白首，功归天下人。' },
  { title: '相和歌辞 从军行六首 五', author: '刘长卿', poem: '倚劒白日暮，望乡登戍楼。\n北风吹羌笛，此夜关山愁。\n回首不无意，滹河空自流。' },
  { title: '相和歌辞 从军行六首 六', author: '刘长卿', poem: '黄沙一万里，白首无人怜。\n报国劒已折，归乡身幸全。\n单于古台下，边色寒苍然。' },
  { title: '相和歌辞 从军行', author: '杜𬱟', poem: '秋草马蹄轻，角弓持弦急。\n去为龙城候，正值胡兵袭。\n军气横大荒，战酣日将入。\n长风金鼓动，白雾铁衣湿。\n四起愁边声，南辕时伫立。\n断蓬孤自转，寒雁飞相及。\n万里云沙涨，路平冰霰涩。\n夜闻汉使归，独向刀环泣。' },
  { title: '相和歌辞 从军行 一', author: '僧皎然', poem: '候骑出纷纷，元戎霍冠军。\n汉鞞秋聒地，羌火昼烧云。\n万里戍城合，三边羽檄分。\n乌孙驱未尽，肯顾辽阳勋。' },
  { title: '相和歌辞 从军行 二', author: '僧皎然', poem: '汉斾拂丹霄，汉军新破辽。\n红尘驱卤簿，白羽拥嫖姚。\n战苦军犹乐，功高将不骄。\n至今丁令塞，朔吹空萧萧。' },
  { title: '相和歌辞 从军行 三', author: '僧皎然', poem: '百万逐呼韩，频年不解鞍。\n兵屯绝漠暗，马饮浊河干。\n破虏功未录，劳师力已殚。\n须防肘腋下，飞祸出无端。' },
  { title: '相和歌辞 从军行 四', author: '僧皎然', poem: '飞将下天来，奇谋阃外裁。\n水心龙劒动，地肺雁山开。\n望气燕师锐，当锋虏阵摧。\n从今射雕骑，不敢过云堆。' },
  { title: '相和歌辞 从军行 五', author: '僧皎然', poem: '黄纸君王诏，青泥校尉书。\n誓师张虎落，选将擐犀渠。\n雾暗津浦失，天寒塞柳疎。\n横行十万骑，欲埽虏尘余。' },
  { title: '相和歌辞 从军行', author: '王建', poem: '汉军逐单于，日没处河曲。\n浮云道傍起，行子车下宿。\n枪城围鼓角，氊帐依山谷。\n马上悬壶浆，刀头分顿肉。\n来时高堂上，父母亲结束。\n回首不见家，风吹破衣服。\n金创生肢节，相与拔箭镞。\n闻道西凉州，家家妇人哭。' },
  { title: '相和歌辞 从军行', author: '张祜', poem: '少年金紫就光辉，直指边城虎翼飞。\n一卷旌收千骑虏，万全身出百重围。\n黄云断塞寻鹰去，白草连天射雁归。\n白首汉廷刀笔吏，丈夫功业本相依。' },
  { title: '相和歌辞 从军行五首 一', author: '令狐楚', poem: '荒鸡隔水啼，汗马逐风嘶。\n终日随征斾，何时罢鼓鼙。' },
  { title: '相和歌辞 从军行五首 二', author: '令狐楚', poem: '孤心眠夜雪，满眼是秋沙。\n万里犹防塞，三年不见家。' },
  { title: '相和歌辞 从军行五首 三', author: '令狐楚', poem: '却望冰河阔，前登雪岭高。\n征人几多在，又拟战临洮。' },
  { title: '相和歌辞 从军行五首 四', author: '令狐楚', poem: '胡风千里惊，汉月五更明。\n纵有还家梦，犹闻出塞声。' },
  { title: '相和歌辞 从军行五首 五', author: '令狐楚', poem: '暮雪连青海，阴云覆白山。\n可怜班定远，出入玉门关。' },
  { title: '相和歌辞 从军行三首 一', author: '王涯', poem: '旌甲从军久，风云识阵难。\n今朝韩信计，日下斩成安。' },
  { title: '相和歌辞 从军行三首 二', author: '王涯', poem: '燕颔多奇相，狼头敢犯边。\n寄言班定远，正是立功年。' },
  { title: '相和歌辞 从军行三首 三', author: '王涯', poem: '旄头夜落捷书飞，来奏金门着赐衣。\n白马将军频破敌，黄龙戍卒几时归。' },
  { title: '相和歌辞 从军有苦乐行', author: '李益', poem: '劳者且勿歌，我欲送君觞。\n从军有苦乐，此曲乐未央。\n仆本居陇上，陇水断人肠。\n东过秦宫路，宫路入咸阳。\n时逢汉帝出，谏猎至长杨。\n讵驰游侠窟，非结少年场。\n一旦承嘉惠，轻命重恩光。\n秉笔参帷帟，从军至朔方。\n边地多阴风，草木自凄凉。\n断绝海云去，出没胡沙长。\n参差引雁翼，隐辚腾军装。\n劒文夜如水，马汗冻成霜。\n侠气五都少，矜功六郡良。\n山河起目前，睚眦死路傍。\n北逐驱獯虏，西临复旧疆。\n昔还赋余资，今出乃赢粮。\n一矢弢夏服，我弓不再张。\n寄言丈夫雄，苦乐身自当。' },
  { title: '相和歌辞 苦战远征人', author: '鲍溶', poem: '征人歌古曲，携手上河梁。\n李陵死别处，杳杳玄冥乡。\n忆昔从此路，连年征鬼方。\n久行迷汉历，三洗氊衣裳。\n百战身且在，微功信难忘。\n远承云台议，非势孰敢当。\n落日吊李广，白身过河阳。\n闲弓失月影，劳劒无龙光。\n去日始束发，今来发成霜。\n虚名乃闲事，生见父母乡。\n掩抑大风歌，裴回少年场。\n诚哉古人言，鸟尽良弓藏。' },
  { title: '相和歌辞 苦哉行五首 一', author: '戎昱', poem: '彼鼠侵我厨，纵貍授梁肉。\n鼠虽为君却，貍食自须足。\n冀雪大国耻，飜是大国辱。\n膻腥逼绮罗，甎瓦杂珠玉。\n登楼非骋望，目笑是心哭。\n何意天乐中，至今奏胡曲。' },
  { title: '相和歌辞 苦哉行五首 二', author: '戎昱', poem: '官军收洛阳，家住洛阳里。\n夫壻与兄弟，目前见伤死。\n吞声不许哭，还谴衣罗绮。\n上马随匈奴，数秋黄尘里。\n生为名家女，死作塞垣鬼。\n乡国无还期，天津哭流水。' },
  { title: '相和歌辞 苦哉行五首 三', author: '戎昱', poem: '登楼望天衢，目极泪盈睫。\n彊笑无笑容，须妆旧花靥。\n昔年买奴仆，奴仆来碎叶。\n岂意未死间，自为匈奴妾。\n一生忽至此，万事痛苦业。\n得出塞垣飞，不如彼蜂蝶。' },
  { title: '相和歌辞 苦哉行五首 四', author: '戎昱', poem: '妾家青河边，七叶承貂蝉。\n身为最小女，偏得浑家怜。\n亲戚不相识，幽闺十五年。\n有时最远出，祗到中门前。\n前年狂胡来，惧死飜生全。\n今秋官军至，岂意遭戈鋋。\n匈奴为先锋，长鼻黄发拳。\n弯弓猎生人，百步牛羊膻。\n脱身落虎口，不及归黄泉。\n苦哉难重陈，暗哭苍苍天。' },
  { title: '相和歌辞 苦哉行五首 五', author: '戎昱', poem: '可汗奉亲诏，今月归燕山。\n忽如乱刀劒，[搅]妾心肠间。\n出户望北荒，迢迢玉门关。\n生人为死别，有去无时还。\n汉月割妾心，胡风凋妾颜。\n去去断绝魂，叫天天不闻。' },
  { title: '相和歌辞 鞠歌行', author: '李白', poem: '玉不自言如桃李，鱼目笑之卞和耻。\n楚国青蝇何太多？连城白璧遭谗毁。\n荆山长号泣血人，忠臣死为刖足鬼。\n听曲知宁戚，[夷]吾因小妻。\n秦穆五羊皮，买死百里奚。\n洗拂青云上，当时贱如泥。\n朝歌鼓刀叟，虎变蟠溪中。\n一举钓六合，逐荒营丘东。\n平生渭水曲，谁识此老翁。\n奈何今之人，双目送征鸿。' },
  { title: '相和歌辞 前苦寒行二首 一', author: '杜甫', poem: '汉时长安雪一丈，牛马毛寒缩如猬。\n楚江巫峡冰入怀，虎豹哀号又堪记。\n秦城老翁荆扬客，惯习炎蒸岁𫄨绤。\n玄冥祝融气或交，手持白羽未敢释。' },
  { title: '相和歌辞 前苦寒行二首 二', author: '杜甫', poem: '去年白帝雪在山，今年白帝雪在地。\n冻埋蛟龙南浦缩，寒刮肌肤北风利。\n楚人四时皆麻衣，楚天万里无晶辉。\n三足之乌足恐断，羲和送将安所归。' },
  { title: '相和歌辞 后苦寒行二首 一', author: '杜甫', poem: '南纪巫庐瘴不绝，太古以来无尺雪。\n蛮夷长老怨苦寒，崐崘天关冻应折。' },
  { title: '相和歌辞 后苦寒行二首 二', author: '杜甫', poem: '晚来江门失大木，猛风中夜吹白屋。\n天兵断斩青海戎，杀气南行动坤轴，不尔苦寒何太酷？\n巴东之峡生凌凘，彼苍回轩人得知。' },
  { title: '相和歌辞 苦寒行', author: '刘驾', poem: '严寒动八荒，莿莿无休时。\n阳乌不自暖，雪压扶桑枝。\n岁暮寒益壮，青春安得归。\n朔雁到南海，越禽何处飞？\n谁言贫士叹，不为身无衣。' },
  { title: '相和歌辞  苦寒行', author: '僧贯休', poem: '北风北风，职何严毒。\n摧壮士心，缩金乌足。\n冻云嚣嚣碍雪，一片下不得。\n声绕枯桑，根在沙塞。\n黄河彻底，顽直到海。\n一气搏束，万物无态。\n唯有吾庭前杉松树枝，枝枝健在。' },
  { title: '相和歌辞  苦寒行', author: '僧齐己', poem: '冰峰撑空寒矗矗，雪凝水冻埋海陆。\n杀物之性，伤人之欲。\n既不能断绝蒺藜荆棘之根株，又不能展凤皇麒麟之拳跼。\n如此则何如为和煦，为膏雨。\n自然天下之荣枯，融融于万户。' },
  { title: '相和歌辞  北上行', author: '李白', poem: '北上何所苦，北上缘太行。\n磴道盘且峻，巉岩凌穹苍。\n马足蹶侧石，车轮摧高冈。\n沙尘接幽州，烽火连朔方。\n杀气毒劒戟，严风裂衣裳。\n奔鲸夹黄河，凿齿屯洛阳。\n前行无归日，返顾思旧乡。\n惨戚冰雪里，悲号绝中肠。\n尺布不掩体，皮肤剧枯桑。\n汲水涧谷阻，采薪陇坂长。\n猛虎又掉尾，磨牙皓秋霜。\n草木不可湌，饥饮零露浆。\n叹此北上苦，停骖为之伤。\n何日王道平？开颜覩天光。' },
  { title: '相和歌辞  豫章行', author: '李白', poem: '胡风吹代马，北拥鲁阳关。\n吴兵照海雪，西讨何时还？\n半渡上辽津，黄云惨无颜。\n老母与子别，呼天野草间。\n白马绕旌旗，悲鸣相追攀。\n白杨秋月苦，早落豫章山。\n本为休明人，斩虏素不闲。\n岂惜战鬬死，为君埽凶顽。\n精感石没羽，岂忘惮险艰。\n楼船若鲸飞，波荡落星湾。\n此曲不可奏，三军鬓成斑。' },
  { title: '相和歌辞  董逃行', author: '元稹', poem: '董逃董逃董卓逃，揩铿戈甲声劳嘈。\n剜剜深脐脂燄燄，人皆数叹曰。\n尔独不忆年年取我身上膏，膏销骨尽烟火死。\n长安城中贼毛起，城门四走公卿士。\n走劝刘虞作天子，刘虞不敢作天子。\n曹瞒纂乱从此始，董逃董逃人莫喜。\n胜负飜环相枕倚，缝缀难成裁破易。\n何况曲针不能伸巧指，欲学裁缝须准拟。' },
  { title: '相和歌辞  董逃行', author: '张籍', poem: '洛阳城头火曈曈，乱兵烧我天子宫。\n宫城南面有深山，尽将老幼藏其间。\n重岩为屋橡为食，丁男夜行候消息。\n闻道官军犹掠人，旧里如今归未得。\n董逃行，汉家几时重太平。' },
  { title: '相和歌辞  相逢行', author: '崔颢', poem: '妾年初二八，家住洛桥头。\n玉户临驰道，朱门近御沟。\n使君何假问，夫壻大长秋。\n女弟新承宠，诸兄近拜侯。\n春生百子殿，花发五城楼。\n出入千门里，年年乐未休。' },
  { title: '相和歌辞 相逢行二首 一', author: '李白', poem: '朝骑五花马，谒帝出银台。\n秀色谁家子，云车珠箔开。\n金鞭遥指点，玉勒近迟回。\n夹毂相借问，疑从天上来。\n怜肠愁欲断，斜日复相催。\n下车何轻盈，飘然似落梅。\n邀入青绮门，当歌共衔杯。\n衔杯映歌扇，似月云中见。\n相见不相亲，不如不相见。\n相见情已深，未语可知心。\n胡为守空闺，孤眠愁锦衾。\n锦衾与罗帏，缠緜会有时。\n春风正澹荡，暮雨来何迟？\n愿因三青鸟，更报长相思。\n光景不待人，须臾发成丝。\n当年失行乐，老去徒伤悲。\n持此道密意，无令旷佳期。' },
  { title: '相和歌辞 相逢行二首 二', author: '李白', poem: '相逢红尘内，高揖黄金鞭。\n万户垂杨里，君家阿那边。' },
  { title: '相和歌辞 相逢行', author: '韦应物', poem: '二十登汉朝，英声迈今古。\n适从东方来，又欲谒明主。\n犹酣新丰酒，尚带霸陵雨。\n邂逅两相逢，别来间寒暑。\n宁知白日晚，暂向花间语。\n忽闻长乐钟，走马东西去。' },
  { title: '相和歌辞 三妇艳诗', author: '董思恭', poem: '大妇裁纨素，中妇弄明珰。\n小妇多姿态，登楼红粉妆。\n丈人且安坐，初日渐流光。' },
  { title: '相和歌辞 中妇织流黄', author: '虞世南', poem: '寒闺织素锦，含怨敛双蛾。\n综新交缕涩，经脆断丝多。\n衣香逐举袖，钏动应鸣梭。\n还恐裁缝罢，无信达交河。' },
  { title: '相和歌辞 难忘曲', author: '李贺', poem: '夹道开洞门，弱杨低画戟。\n帘影竹叶起，箫声吹日色。\n蠭语绕妆镜，拂蛾学春碧。\n乱系丁香梢，满阑花向夕。' },
  { title: '相和歌辞 塘上行', author: '李贺', poem: '藕花凉露湿，花缺藕根涩。\n飞下雌鸳鸯，塘水声溢溢。' },
  { title: '相和歌辞 苦辛行', author: '戎昱', poem: '且莫奏短歌，听余苦辛词。\n如今刀笔士，不及屠酤儿。\n少年无事学诗赋，岂意文章复相误。\n东西南北少知音，终年竟岁悲行路。\n仰面诉天天不闻，低头告地地不言。\n天地生我尚如此，陌上他人何足论。\n谁谓西江深，涉之固无忧。\n谁谓南山高，可以登之游。\n险巇惟有世间路，一向令人堪白头。\n贵人立意不可测，等闲桃李成荆棘。\n风尘之士深可亲，心如鸡犬能依人。\n悲来却忆汉天子，不弃相如家旧贫。\n饮酒酒能散羇愁，谁家有酒判一醉，万事从他江水流。' },
  { title: '相和歌辞 秋胡行', author: '高适', poem: '妾本邯郸未嫁时，容华倚翠人未知。\n一朝结发从君子，将妾迢迢东路陲。\n时逢大道无难阻，君方游宦从陈汝。\n蕙楼独卧频度春，彩落辞君几徂暑。\n三月垂杨蚕未眠，携笼结侣南陌边。\n道逢行子不相识，赠妾黄金买少年。\n妾家夫壻轻离久，寸心誓与长相守。\n愿言行路莫多情，送妾贞心在人口。\n日暮蚕饥相命归，携笼端饰来庭闱。\n劳心苦力终无恨，所冀君恩那可依。\n闻说行人已归止，乃是向来赠金子。\n相看颜色不复言，相顾怀慙有何已。\n从来自隐无疑背，直为君情也相会。\n如何咫尺仍有情，况复迢迢千里外。\n此时顾恩不顾身，念君此日赴河津。\n莫道向来不得意，故欲留规诫后人。' },
  { title: '相和歌辞 善哉行', author: '僧贯休', poem: '有美一人兮婉如清扬，识曲别音兮令姿煌煌。\n绣袂捧琴兮登君子堂，如彼萱草兮使我忧忘。\n欲赠之以紫玉尺，白银珰，久不见之兮湘水茫茫。' },
  { title: '相和歌辞 善哉行', author: '僧齐己', poem: '大鹏刷翮谢溟渤，青云万层高突出。\n下视秋涛空渺弥，旧处鱼龙皆细物。\n人生在世何容易，眼浊心昏信生死。\n愿除嗜欲待身轻，携手同寻列仙事。' },
  { title: '相和歌辞 来日大难', author: '李白', poem: '来日一身，携粮负薪。\n道长食尽，苦口焦唇。\n今日醉饱，乐过千春。\n仙人相存，诱我远学。\n海陵三山，陆憩五岳。\n乘龙上三天，飞目瞻两角。\n授以神药，金丹满握。\n蟪蛄蒙恩，深媿短促。\n思填东海，彊衔一木。\n道重天地，轩师广成。\n蝉翼九五，以求长生。\n下士大笑，如苍蝇声。' },
  { title: '相和歌辞 当来日大难', author: '元稹', poem: '当来日大难行，前有坂，后有坑，大梁侧，小梁倾，两轴相绞，两轮相撑，大牛竖，小牛横，乌啄牛背，足跌力狞。\n当来日大难行，太行虽险，险可使平。\n轮轴自挠，牵制不停。\n泥潦渐久，荆棘旋生。\n行必不得，不如不行。' },
  { title: '相和歌辞 陇西行', author: '王维', poem: '十里一走马，五里一扬鞭。\n都护军书至，匈奴围酒泉。\n关山正飞雪，烽戍断无烟。' },
  { title: '相和歌辞 陇西行', author: '耿[𣲗]', poem: '雪下阳关路，人稀陇戍头。\n封狐犹未翦，边将岂无羞。\n白草三冬色，黄云万里愁。\n因思李都尉，毕竟不封侯。' },
  { title: '相和歌辞 陇西行', author: '长孙佐辅', poem: '阴云凝朔气，陇上正飞雪。\n四月草不生，北风劲如切。\n朝来羽书急，夜救长城窟。\n道隘行不前，相呼抱鞍歇。\n人寒指欲堕，马冻蹄亦裂。\n射雁旋充饥，斧冰还止渴。\n宁辞解围鬬，但恐乘疲没。\n早晚边候空，归来养羸卒。' },
  { title: '相和歌辞 东门行', author: '柳宗元', poem: '汉家三十六将军，东方雷动横阵云。\n鸡鸣函谷客如雾，貌同心异不可数。\n赤丸夜语飞电光，徼巡司隶眠如羊。\n当街一叱百吏走，冯敬胷中函匕首。\n凶徒侧耳潜惬心，悍臣破胆皆杜口。\n魏王卧内藏兵符，子西掩袂真无辜。\n羌胡毂下一朝起，敌国舟中非所拟。\n安陵谁辨削砺功，韩国讵明深井里。\n绝咽断骨那下补，万金宠赠不如土。' },
  { title: '相和歌辞 饮马长城窟行', author: '太宗皇帝', poem: '塞外悲风切，交河冰已结。\n瀚海百重波，阴山千里雪。\n迥戍危烽火，层峦引高节。\n悠悠卷斾旌，饮马出长城。\n寒沙连骑迹，朔吹断边声。\n胡尘清玉塞，羌笛韵金钲。\n绝寞干戈戢，车徒振原隰。\n都尉反龙堆，将军旋马邑。\n扬麾氛雾静，纪石功名立。\n荒裔一戎衣，云台凯歌入。' },
  { title: '相和歌辞 饮马长城窟行', author: '虞世南', poem: '驰马渡河干，流深马渡难。\n前逢锦车使，都护在楼兰。\n轻骑犹衔勒，疑兵尚解鞍。\n温池下绝涧，栈道接危峦。\n拓地勋未赏，亡城律讵宽。\n有月关犹暗，经春陇尚寒。\n云昏无复影，冰合不闻湍。\n怀君不可遇，聊持报一餐。' },
  { title: '相和歌辞 饮马长城窟行', author: '袁朗', poem: '朔风动秋草，清跸长安道。\n长城连不穷，所以隔华戎。\n规模惟圣作，荷负晓成功。\n鸟庭已向内，龙荒更凿空。\n玉关尘卷静，金微路已通。\n汤征随北怨，舜咏起南风。\n画野功初立，绥边事云集。\n朝服践狼居，凯歌旋马邑。\n山响传凤吹，霜华藻琼钑。\n属国拥节归，单于款关入。\n日落寒云起，惊沙被原隰。\n零落叶已寒，河流清且急。\n四时徭役尽，千载干戈戢。\n太平今若斯，汗马竟无施。\n惟当事笔研，归去草封禅。' },
  { title: '相和歌辞 饮马长城窟行', author: '王翰', poem: '长安少年无远图，一生惟羡执金吾。\n骐𬴊前殿拜天子，走马为君西击胡。\n胡沙猎猎吹人面，汉虏相逢不相见。\n遥闻鼙鼓动地来，传道单于夜犹战。\n此时顾恩宁顾身，为君一行摧万人。\n壮士挥戈回白日，单于溅血染朱轮。\n回来饮马长城窟，长安道傍多白骨。\n问之耆老何代人，云是秦王筑城卒。\n黄昏塞北无人烟，鬼哭啾啾声沸天。\n无罪见诛功不赏，孤魂流落此城边。\n当昔秦王按劒起，诸侯膝行不敢视。\n富国彊兵二十年，筑怨兴徭九千里。\n秦王筑城何太愚，天实亡秦非北胡。\n一朝祸起萧墙内，渭水咸阳不复都。' },
  { title: '相和歌辞 饮马长城窟行', author: '王建', poem: '长城窟，长城窟边多马骨。\n古来此地无井泉，赖得秦家筑城卒。\n征人饮马愁不回，长城变作望乡堆。\n蹄迹未干人去近，续后马来泥污尽。\n枕弓睡着待水生，不见阴山在前阵。\n马蹄足脱装马头，健儿战死谁封侯。' },
  { title: '相和歌辞 饮马长城窟行', author: '僧子兰', poem: '游客长城下，饮马长城窟。\n马嘶闻水腥，为浸征人骨。\n岂不是流泉，终不成潺湲。\n洗尽骨上土，不洗骨中冤。\n骨若比流水，四海有还魂。\n空流呜咽声，声中疑是言。' },
  { title: '相和歌辞 上留田', author: '李白', poem: '行至上留田，孤坟何峥嵘。\n积此万古恨，春草不复生。\n悲风四边来，肠断白杨声。\n借问谁家地，埋没蒿里茔。\n古老向余言，言是上留田。\n蓬科马鬣今已平，昔之弟死兄不葬。\n他人于此举铭旌，一鸟死，百鸟鸣，一兽死，百兽惊。\n桓山之禽别离苦，欲去回翔不能征。\n田氏仓卒骨肉分，青天白日摧紫荆。\n交柯之木本同形，东枝顦顇西枝荣。\n无心之物尚如此，参商胡乃寻天兵。\n孤竹延陵，让国扬名。\n高风缅邈，颓波激清。\n尺布之谣，塞耳不能听。' },
  { title: '相和歌辞 上留田', author: '僧贯休', poem: '父不父，兄不兄，上留田，蝥贼生。\n徒陟冈，泪峥嵘，我欲使诸凡鸟雀，尽变为鹡鸰。\n我欲使诸凡草木，尽变为田荆。\n邻人歌，邻人歌，古风清，清风生。' },
  { title: '相和歌辞 安乐宫', author: '李贺', poem: '深井桐乌起，尚复牵清水。\n未盥邵陵王，瓶中弄长翠。\n新城安乐宫，宫如凤皇翅。\n歌回蜡版鸣，大绾提壶使。\n绿繁悲水曲，茱萸别秋子。' },
  { title: '相和歌辞 放歌行', author: '王昌龄', poem: '南渡洛阳津，西望十二楼。\n明堂坐天子，月朔朝诸侯。\n清乐动千门，皇风被九州。\n庆云从东来，泱漭抱日流。\n升平贵论道，文墨将何求。\n有诏征草泽，微臣献谋猷。\n冠冕如星罗，拜揖曹与周。\n望尘非吾事，入赋且迟留。\n幸蒙国士识，因脱负薪裘。\n今者放歌行，以慰梁父愁。\n但营数斗禄，奉养毋丰羞。\n若得金膏遂，飞云亦可俦。' },
  { title: '相和歌辞 野田黄雀行', author: '李白', poem: '游莫逐炎洲翠，栖莫近吴宫燕。\n吴宫火起焚尔窠，炎洲逐翠遭网罗。' },
  { title: '相和歌辞 野田黄雀行', author: '储光羲', poem: '啧啧野田雀，不知躯体微。\n闲穿深蒿里，争食复争飞。\n穷老一颓舍，枣多桑树稀。\n无枣犹可食，无桑何以衣。\n萧条空仓暮，相引时来归。\n邪路岂不捷，渚田岂不肥。\n水长路且坏，恻恻与心违。' },
  { title: '相和歌辞 野田黄雀行', author: '僧贯休', poem: '高树风多，吹尔巢落。\n深蒿叶暖，宜尔依薄。\n莫近鸮类，珠网亦恶。\n饮野田之清水，食野田之黄粟。\n深花中睡，𡋯土里浴。\n如此即全胜啄太仓之谷，而更穿人屋。' },
  { title: '相和歌辞 野田黄雀行', author: '僧齐己', poem: '双双野田雀，上下同饮啄。\n暖去栖蓬蒿，寒归傍篱落。\n殷勤避罗网，乍可遇雕鹗。\n雕鹗虽不仁，分明在寥廓。' },
  { title: '相和歌辞 雁门太守行', author: '李贺', poem: '黑云压城城欲摧，甲光向月金鳞开。\n角声满天秋色里，塞上燕支凝夜紫。\n半卷红旗临易水，霜重鼓寒声不起。\n报君黄金台上意，提携玉龙为君死。' },
  { title: '相和歌辞 雁门太守行', author: '张祜', poem: '城头月没霜如水，趚趚蹋沙人似鬼。\n灯前拭泪试香裘，长引一声残漏子。\n驼囊泻酒酒一杯，前头啑血心不回。\n寄语年少妻莫哀，鱼金虎竹天上来，雁门山边骨成灰。' },
  { title: '相和歌辞 雁门太守行', author: '庄南杰', poem: '旌旗闪闪摇天末，长笛横吹虏尘阔。\n跨下嘶风白练狞，腰间切玉青蛇活。\n击革𪭢金燧牛尾，犬羊兵败如山死。\n九泉寂寞葬秋虫，湿云荒草啼秋思。' },
  { title: '相和歌辞 飞来双白鹤', author: '虞世南', poem: '飞来双白鹤，奋翼远凌烟。\n双栖集紫盖，一举背青田。\n飏影过伊洛，流声入管弦。\n鸣群倒景外，刷羽阆风前。\n映海疑浮雪，拂涧泻飞泉。\n燕雀宁知去，蜉蝣不识还。\n何言别俦侣，从此间山川。\n顾步已相失，裴回反自怜。\n危心犹警露，哀响讵闻天。\n无因振六翮，轻举复随仙。' },
  { title: '相和歌辞 门有车马客行', author: '虞世南', poem: '财雄重交结，戚里擅豪华。\n曲台临上路，高门抵狭斜。\n赭汗千金马，绣毂五香车。\n白鹤随飞盖，朱鹭入鸣笳。\n夏莲开劒水，春桃发露花。\n轻裙染回雪，浮蚁泛流霞。\n高谈辨飞兔，摛藻握灵蛇。\n逢恩借羽翼，失路委泥沙。\n暧暧风烟晚，路长归骑远。\n日斜青琐第，尘飞金谷苑。\n危弦促柱奏巴渝，遗簪堕珥解罗襦。\n如何守直道，飜使谷名愚。' },
  { title: '相和歌辞 门有车马客行', author: '李白', poem: '门有车马客，金鞍曜朱轮。\n谓从丹霄落，乃是故乡亲。\n呼儿埽中堂，坐客论悲辛。\n对酒两不饮，停觞泪盈巾。\n叹我万里游，飘飖三十春。\n空谈霸王略，紫绶不挂身。\n雄劒藏玉匣，阴符生素尘。\n廓落无所合，流离湘水滨。\n借问宗党间，多为泉下人。\n生苦百战役，死托万鬼邻。\n北风扬胡沙，埋翳周与秦。\n大运且如此，苍穹宁匪仁。\n恻怆竟何道？存亡任大钧。' },
  { title: '相和歌辞 蜀道难', author: '张文琮', poem: '梁山镇地险，积石阻云端。\n深谷下寥廓，层岩上郁盘。\n飞梁架绝岭，栈道接危峦。\n揽辔独长息，方知斯路难。' },
  { title: '相和歌辞 蜀道难', author: '李白', poem: '噫吁嚱！危乎高哉！蜀道之难难于上青天！蚕丛及鱼凫，开国何茫然。\n尔来四万八千岁，乃与秦塞通人烟。\n西当太白有鸟道，可以横绝峨眉巅。\n地崩山摧壮士死，然后天梯石栈方钩连。\n上有六龙回日之高标，下有冲波逆折之回川。\n黄鹤之飞尚不得，猨猱欲度愁攀缘。\n青泥何盘盘，百步九折萦岩峦。\n扪参历井仰胁息，以手抚膺坐长叹。\n问君西游何时还？畏途巉岩不可攀。\n但见悲鸟号枯木，雄飞呼雌绕林间。\n又闻子规啼夜月，愁空山，蜀道之难难于上青天！使人听此雕朱颜。\n连峰去天不盈尺，枯松倒挂倚绝壁。\n飞湍瀑流相喧豗，砅崖转石万壑雷。\n其崄也若此，嗟尔远道之人胡为乎来哉？\n劒阁峥嵘而崔嵬，一夫当关，万夫莫开。\n所守或匪亲，化为狼与豺。\n朝避猛虎，夕避长蛇。\n磨牙吮血，杀人如麻。\n锦城虽云乐，不如早还家。\n蜀道之难难于上青天，侧身西望长咨嗟。' },
  { title: '相和歌辞 櫂歌行', author: '骆宾王', poem: '写月图黄罢，凌波拾翠通。\n镜花摇芰日，衣麝入荷风。\n叶密舟难荡，莲疎浦易空。\n凤媒羞自托，鸳翼恨难穷。\n秋帐灯花翠，倡楼粉色红。\n相思无别曲，幷在櫂歌中。' },
  { title: '相和歌辞 櫂歌行', author: '徐坚', poem: '櫂女饰银钩，新妆下翠楼。\n霜丝青桂檝，兰栧紫霞舟。\n水落金陵曙，风起洞庭秋。\n扣船过曲浦，飞帆越回流。\n影入桃花浪，香飘杜若洲。\n洲长殊未返，萧散云霞晚。\n日下大江平，烟生归岸远。\n岸远闻潮波，争途游戏多。\n因声赵津女，来听采菱歌。' },
  { title: '相和歌辞 胡无人行', author: '徐彦伯', poem: '十月繁霜下，征人远凿空。\n云摇锦更节，海照角端弓。\n暗碛埋砂树，冲飙卷塞蓬。\n方随膜拜入，歌舞玉门中。' },
  { title: '相和歌辞 胡无人行', author: '聂夷中', poem: '男儿徇大义，立节不沽名。\n腰间悬陆离，大歌胡无行。\n不读战国书，不览黄石经。\n醉卧咸阳楼，梦入受降城。\n更愿生羽翼，飞身入青冥。\n请携天子劒，斫下旄头星。\n自然胡无人，虽有无战争。\n悠哉典属国，驱羊老一生。' },
  { title: '相和歌辞 胡无人行', author: '李白', poem: '严风吹霜海草雕，筋干精坚胡马骄。\n汉家战士三十万，将军兼领霍嫖姚。\n流星白羽腰间插，劒花秋莲光出匣。\n天兵照雪下玉关，虏箭如沙射金甲。\n云龙风虎尽交回，太白入月敌可摧。\n敌可摧，旄头灭，履胡之肠涉胡血。\n悬胡青天上，埋胡紫[塞]旁。\n胡无人，汉道昌，陛下之寿三千霜。\n但歌大风云飞扬，安得猛士兮守四方。\n胡无人，汉道昌。' },
  { title: '相和歌辞 胡无人行', author: '僧贯休', poem: '霍嫖姚，赵充国，天子将之平朔漠。\n肉胡之肉，烬胡帐幄。\n千里万里，惟留胡之空壳。\n边风萧萧，榆叶初落。\n杀气昼赤，枯骨夜哭。\n将军既立殊勋，遂有胡无人曲。\n我闻之，天子富有四海，德被无垠。' },
  { title: '相和歌辞 白头吟', author: '刘希夷', poem: '洛阳城东桃李花，飞来飞去落谁家。\n洛阳女儿惜颜色，行逢落花长叹息。\n今年花落颜色改，明年花开复谁在。\n已见松柏摧为薪，更闻桑田变成海。\n古人无复洛城东，今人还对落花风。\n年年岁岁花相似，岁岁年年人不同。\n寄言全盛红颜子，须怜半死白头翁。\n此翁白头真可怜，伊昔红颜美少年。\n公子王孙芳树下，清歌妙舞落花前。\n光禄池台文锦绣，将军楼阁画神仙。\n一朝卧病无人识，三春行乐在谁边。\n宛转蛾眉能几时，须臾白发乱如丝。\n但看旧来歌舞地，惟有黄昏鸟雀悲。' },
  { title: '相和歌辞 白头吟二首 一', author: '李白', poem: '锦水东北流，波荡双鸳鸯。\n雄巢汉宫树，雌弄秦草芳。\n宁同万死碎绮翼，不忍云间两分张。\n此时阿娇正娇妬，独坐长门愁日暮。\n但愿君恩顾妾深，岂惜黄金将买赋。\n相如作赋得黄金，丈夫好新多异心。\n一朝将聘茂陵女，文君因赠白头吟。\n东流不作西归水，落花辞条归故林。\n兔丝固无情，随风任颠倒。\n谁使女萝枝，而来彊萦抱。\n两草犹一心，人心不如草。\n莫卷龙须席，从他生网丝。\n且留琥珀枕，或有梦来时。\n覆水再收岂满杯，弃妾已去难重回。\n古时得意不相负，祗今惟见青陵台。' },
  { title: '相和歌辞 白头吟二首 二', author: '李白', poem: '锦水东流碧，波荡双鸳鸯。\n雄巢汉宫树，雌弄秦草芳。\n相如去蜀谒武帝，赤车驷马生辉光。\n一朝再览大人作，万乘忽欲凌云翔。\n闻道阿娇失恩宠，千金买赋要君王。\n相如不忆贫贱日，官高金多聘私室。\n茂陵姝子皆见求，文君欢爱徒此毕。\n泪如双泉水，行堕紫罗襟。\n五起鸡三唱，清晨白头吟。\n长吁不整绿云鬓，仰诉青天哀怨深。\n城崩杞梁妻，谁道土无心。\n东流不作西归水，落花辞枝羞故林。\n头上玉燕钗，是妾嫁时物。\n赠君表相思，罗袖幸时拂。\n莫卷龙须席，从他生网丝。\n且留琥珀枕，还有梦来时。\n鹔鹴裘在锦屏上，自君一挂无由披。\n妾有秦楼镜，照心胜照井。\n愿持照新人，双对可怜影。\n覆水却收不满杯，相如还谢文君回。\n古来得意不相负，祗今惟有青陵台。' },
  { title: '相和歌辞 白头吟', author: '张籍', poem: '请君膝上琴，弹我白头吟。\n忆昔君前娇笑语，两情宛转如萦素。\n宫中为我起高楼，更开华池种芳树。\n春天百草秋始衰，弃我不待白头时。\n罗襦玉珥色未暗，今朝已道不相宜。\n扬州青铜作明镜，暗中持照不见影。\n人心回互自无穷，眼前好恶那能定。\n君恩已去若再返，菖蒲花生月长满。' },
  { title: '相和歌辞 反白头吟', author: '白居易', poem: '炎炎者烈火，营营者小蝇。\n火不热真玉，蝇不点清冰。\n此苟无所受，彼莫能相仍。\n乃知物性中，各有能不能。\n古称怨报死，则人有所惩。\n惩淫或应可，在道未为弘。\n譬如蜩鷃徒，啾啾啅龙鹏。\n宜当委之去，寥廓高飞腾。\n岂能泥尘下，区区酬怨憎。\n胡为作自苦，吞悲仍抚膺。' },
  { title: '相和歌辞 决绝[词]三首 一', author: '元稹', poem: '乍可为天上牵牛织女星，不愿为庭前红槿枝。\n七月七日一相见，故心终不移。\n那能朝开暮飞去，一任东西南北吹。\n分不两相守，恨不两相思。\n对面且如此，背面当何知。\n春风撩乱伯劳语，此时抛去时。\n握手苦相问，竟不言后期。\n君情既决绝，妾意已参差。\n借如死生别，安得长苦悲。' },
  { title: '相和歌辞 决绝[词]三首 二', author: '元稹', poem: '噫春冰之将泮，何余怀之独结。\n有美一人，于焉旷绝。\n一日不见，比一日于三年，况三年之旷别。\n水得风兮小而已波，笋在苞兮高不见节。\n矧桃李之当春，竞众人之攀折。\n我自顾悠悠而若云，又安能保君皓皓之如雪。\n感破镜之分明，覩泪痕之余血。\n幸他人之既不我先，又安能使他人之终不我夺。\n已焉哉！织女别黄姑，一年一度暂相见，彼此隔河何事无。' },
  { title: '相和歌辞 决绝[词]三首 三', author: '元稹', poem: '夜夜相抱眠，幽怀尚沈结。\n那堪一年事，长遣一宵说。\n但感久相思，何暇暂相悦。\n虹桥薄夜成，龙驾侵晨列。\n生憎野鹊往迟回，死恨天鸡识时节。\n曙色渐曈昽，华星次明灭。\n一去又一年，一年何时彻。\n有此迢遰期，不如生死别。' },
  { title: '相和歌辞 梁甫吟', author: '李白', poem: '长啸梁甫吟，何时见阳春？\n君不见朝歌屠叟辞棘津，八十西来钓渭滨。\n宁羞白发照渌水，逢时吐气思经纶。\n广张三千六百钧，风雅暗与文王亲。\n大贤虎变愚不测，当年颇似寻常人。\n君不见高阳酒徒起草中，长揖山东隆准公。\n入门不拜骋雄辨，两女辍洗来趋风。\n东下齐城七十二，指麾楚汉如旋蓬。\n狂生落拓尚如此，何况壮士当群雄。\n我欲攀龙见明主，雷公砰訇震天鼓。\n帝旁投壶多玉女，三时大笑开电光。\n倏烁晦冥起风雨，阊阖九门不可通。\n以额叩关阍者怒，白日不照吾精诚。\n杞国无事忧天倾，䝟貐磨牙竞人肉。\n驺虞不折生草茎，手接飞猱搏雕虎。\n侧足焦原未言苦，智者可卷愚者豪。\n世人见我轻鸿毛，力排南山三壮士，齐相杀之费二桃。\n吴楚弄兵无剧孟，亚夫咍尔为徒劳。\n梁父吟，梁父吟，声正悲。\n张公两龙劒，神物合有时。\n风云感会起屠钓，大人𡸣屼当安之。' },
  { title: '相和歌辞 东武吟', author: '李白', poem: '好古笑流俗，素闻贤达风。\n方希佐明主，长揖辞成功。\n白日在高天，回光烛微躬。\n恭承凤皇诏，歘起云萝中。\n清切紫霄迥，优游丹禁通。\n君王赐颜色，声价凌烟虹。\n乘舆拥翠盖，扈从金城东。\n宝马丽绝景，锦衣入新丰。\n倚岩望松雪，对酒鸣丝桐。\n因学扬子云，献赋甘泉宫。\n天书美片善，清芬播无穷。\n归来入咸阳，谈笑皆王公。\n一朝去金马，飘落成飞蓬。\n宾友日疎散，玉尊亦已空。\n才力犹可倚，不慙世上雄。\n闲作东武吟，曲尽情未终。\n书此谢知己，吾寻黄绮翁。' },
  { title: '相和歌辞 怨诗二首 一', author: '薛奇童', poem: '日晚梧桐落，微寒入禁垣。\n月悬三雀观，霜度万秋门。\n艳舞矜新宠，愁容泣旧恩。\n不堪深殿里，帘外欲黄昏。' },
  { title: '相和歌辞 怨诗二首 二', author: '薛奇童', poem: '禁苑春风起，流莺绕合欢。\n玉窗通日气，珠箔卷轻寒。\n杨叶垂金砌，梨花入井阑。\n君王好长袖，新作舞衣宽。' },
  { title: '相和歌辞 怨诗', author: '张汯', poem: '去年离别雁初归，今夜裁缝萤已飞。\n征客近来音信断，不知何处寄寒衣。' },
  { title: '相和歌辞 怨诗', author: '刘元济', poem: '玉关芳信断，兰闺锦字新。\n愁来好自抑，念切已含嚬。\n虚牖风惊梦，空床月厌人。\n归期傥可促，勿度柳园春。' },
  { title: '相和歌辞 怨诗三首 一', author: '李暇', poem: '罗敷初总髻，蕙芳正娇小。\n月落始归船，春眠恒着晓。' },
  { title: '相和歌辞 怨诗三首 二', author: '李暇', poem: '何处期郎游？小苑花台间。\n相忆不可见，且复乘月还。' },
  { title: '相和歌辞 怨诗三首 三', author: '李暇', poem: '别来花照路，别后露垂叶。\n歌舞须及时，如何坐悲妾。' },
  { title: '相和歌辞 怨诗二首 一', author: '崔国辅', poem: '楼前桃李疎，池上芙蓉落。\n织锦犹未成，虫声入罗幕。' },
  { title: '相和歌辞 怨诗二首 二', author: '崔国辅', poem: '妾有罗衣裳，秦王在时作。\n为舞春风多，秋来不堪着。' },
  { title: '相和歌辞 怨诗', author: '孟郊', poem: '试妾与君泪，两处滴池水。\n看取芙蓉花，今年为谁死。' },
  { title: '相和歌辞 怨诗', author: '刘义', poem: '君莫嫌丑妇，丑妇死守贞。\n山头一怪石，长作望夫名。\n鸟有竝翼飞，兽有比肩行。\n丈夫不立义，岂如鸟兽情。' },
  { title: '相和歌辞 怨诗', author: '鲍溶', poem: '女萝寄松柏，绿蔓花緜緜。\n三五定君婚，结发早移天。\n肃肃羊雁礼，泠泠琴瑟篇。\n恭承采蘩祀，敢效同居贤。\n皎日不留景，良时如逝川。\n秋心还遗爱，春貌无归妍。\n翠袖洗朱粉，碧阶对绮钱。\n新人易如玉，废瑟难为弦。\n寄羡蕣华木，荣名香阁前。\n岂无摇落苦，贵与根蒂连。\n希君旧光景，照妾薄暮年。' },
  { title: '相和歌辞 怨诗', author: '白居易', poem: '夺宠心那惯，寻思倚殿门。\n不知移旧爱，何处作新恩。' },
  { title: '相和歌辞 怨诗二首 一', author: '姚氏月华', poem: '春水悠悠春水绿，对此思君泪相续。\n羞将离恨向东风，理尽秦筝不成曲。' },
  { title: '相和歌辞 怨诗二首 二', author: '姚氏月华', poem: '与君形影分胡越，玉枕终年对离别。\n登台北望烟雨深，回身泣向寥天月。' },
  { title: '相和歌辞 怨歌行', author: '虞世南', poem: '紫殿秋风冷，雕甍白日沈。\n裁纨凄断曲，织素别离心。\n掖庭羞改画，长门不惜金。\n宠移恩稍薄，情疎恨转深。\n香销翠羽帐，弦断凤皇琴。\n镜前红粉歇，阶上绿苔侵。\n谁言掩歌扇，飜作白头吟。' },
  { title: '相和歌辞 怨歌行', author: '李白', poem: '十五入汉宫，花颜笑春红。\n君王选玉色，侍寝金屏中。\n荐枕娇夕月，卷衣恋春风。\n宁知赵飞燕，夺宠恨无穷。\n沈忧能伤人，绿鬓成霜蓬。\n一朝不得意，世事徒为空。\n鹔鹴换美酒，舞衣罢雕笼。\n寒苦不忍言，为君奏丝桐。\n肠断弦亦绝，悲心夜忡忡。' },
  { title: '相和歌辞 怨歌行', author: '吴少微', poem: '城南有怨妇，含怨倚兰丛。\n自谓二八时，歌舞入汉宫。\n皇恩弄幸玉堂中，绿陌黄花催夜酒。\n锦衣罗袂逐春风，建章西宫焕若神。\n燕赵美女二千人，君王厌德不忘新。\n况群艳冶纷来陈，是时别君不再见。\n三十三春长信殿，长信重门昼掩关。\n清房晓帐幽且闲，绮窗虫网氛尘色。\n文轩莺对桃李颜，天王贵宫不贮老。\n浩然泪陨今来还，自怜转晚暮。\n试逐佳游芳草路，小腰丽女夺人奇。\n金鞍少年曾不顾，归来谁为夫。\n请谢西家妇，莫辞先醉解罗襦。' },
  { title: '相和歌辞 明月照高楼', author: '雍陶', poem: '朗月何高高，楼中帘影寒。\n一妇独含叹，四坐谁成欢。\n时节屡已移，游旅杳不还。\n沧溟倘未涸，妾泪终不干。\n君若无定云，妾若不动山。\n云行出山易，山逐云去难。\n愿为边塞尘，因风委君颜。\n君颜良洗多，荡妾浊水间。' },
  { title: '相和歌辞 长门怨', author: '徐贤妃', poem: '旧爱柏梁台，新宠昭阳殿。\n守分辞方辇，含情泣团扇。\n一朝歌舞荣，夙昔诗书贱。\n颓恩诚已矣，覆水难重荐。' },
  { title: '相和歌辞 长门怨', author: '沈佺期', poem: '月皎风泠泠，长门次掖庭。\n玉阶闻坠叶，罗幌见飞萤。\n清露凝珠缀，流尘下翠屏。\n妾心君未察，秋叹剧繁星。' },
  { title: '相和歌辞 长门怨', author: '吴少微', poem: '月出映曾城，孤圜上太清。\n君王春爱歇，枕席凉风生。\n怨咽不能寝，踟蹰步前楹。\n空阶白露色，百草寒虫鸣。\n念昔金房里，犹嫌玉座轻。\n如何娇所误，长夜泣恩情。' },
  { title: '相和歌辞 长门怨', author: '张修之', poem: '长门落景尽，洞房秋月明。\n玉阶草路积，金屋网尘生。\n妾妬今应改，君恩昔未平。' },
  { title: '相和歌辞 长门怨', author: '裴交泰', poem: '自闭长门经几秋，罗衣湿尽泪还流。\n一种蛾眉明月夜，南宫歌管北宫愁。' },
  { title: '相和歌辞 长门怨', author: '刘皂', poem: '宫殿沈沈月欲分，昭阳更漏不堪闻。\n珊瑚枕上千行泪，不是思君是恨君。' },
  { title: '相和歌辞 长门怨', author: '袁晖', poem: '早知君爱歇，本自无萦妬。\n谁使恩情深，今来反相误。\n愁眠罗帐晓，泣坐金闺暮。\n独有梦中魂，犹言意如故。' },
  { title: '相和歌辞 长门怨', author: '刘言史', poem: '独坐炉边结夜愁，暂时恩去亦难留。\n手持金箸垂红泪，乱拨寒灰不举头。' },
  { title: '相和歌辞 长门怨二首 一', author: '李白', poem: '天回北斗挂西楼，金屋无人萤火流。\n月光欲到长门殿，别作深宫一段愁。' },
  { title: '相和歌辞 长门怨二首 二', author: '李白', poem: '桂殿长愁不记春，黄金四屋起秋尘。\n夜悬明镜青天上，独照长门宫里人。' },
  { title: '相和歌辞 长门怨', author: '李华', poem: '弱体鸳鸯荐，啼妆翡翠衾。\n鸦鸣秋殿晓，人静禁门深。\n每忆椒房宠，那堪永巷阴。\n日惊罗带缓，非复旧来心。' },
  { title: '相和歌辞 长门怨', author: '岑参', poem: '君王嫌妾妬，闭妾在长门。\n舞袖垂新宠，愁眉结旧恩。\n绿钱生履迹，红粉湿啼痕。\n羞被桃花笑，看春独不言。' },
  { title: '相和歌辞 长门怨', author: '齐澣', poem: '茕茕孤思逼，寂寂长门夕。\n妾妬亦非深，君恩那不惜。\n携琴就玉阶，调悲声未谐。\n将心托明月，流影入君怀。' },
  { title: '相和歌辞 长门怨', author: '刘长卿', poem: '何事长门闭，珠帘只自垂。\n月移深殿早，春向后宫迟。\n蕙草生闲地，梨花发旧枝。\n芳菲自恩幸，看却被风吹。' },
  { title: '相和歌辞 长门怨', author: '僧皎然', poem: '春风日日闭长门，摇荡春心自梦魂。\n若遣花开只笑妾，不如桃李正无言。' },
  { title: '相和歌辞 长门怨', author: '卢纶', poem: '空宫古廊殿，寒月照斜晖。\n卧听未央曲，满箱歌舞衣。' },
  { title: '相和歌辞 长门怨', author: '戴叔伦', poem: '自忆专房宠，曾居第一流。\n移恩向何处？暂妬不容收。\n夜久丝管绝，月明宫殿秋。\n空将旧时意，长望凤皇楼。' },
  { title: '相和歌辞 长门怨', author: '刘驾', poem: '御泉长绕凤皇楼，只是恩波别处流。\n闲揲舞衣归未得，夜来砧杵六宫秋。' },
  { title: '相和歌辞 长门怨 一', author: '高蟾', poem: '天上何劳万古春，君前谁是百年人。\n魂销尚媿金炉烬，思起犹慙玉辇尘。\n烟翠薄情攀不得，星芒浮艳采无因。\n可怜明镜来相向，何似恩光朝夕新。' },
  { title: '相和歌辞 长门怨 二', author: '高蟾', poem: '天上凤皇休寄梦，人间鹦鹉旧堪悲。\n平生心绪无人识，一只金梭万丈丝。' },
  { title: '相和歌辞 长门怨', author: '张祜', poem: '日映宫墙柳色寒，笙歌遥指碧云端。\n珠铅滴尽无心语，彊把花枝冷笑看。' },
  { title: '相和歌辞 长门怨二首 一', author: '郑谷', poem: '闲把罗衣泣凤皇，先朝曾教舞霓裳。\n春来却羡庭花落，得逐晴风出禁墙。' },
  { title: '相和歌辞 长门怨二首 二', author: '郑谷', poem: '流水君恩共不回，杏花争忍埽成堆。\n残春未必多烟雨，泪滴闲阶长绿苔。' },
  { title: '相和歌辞 长门怨二首 一', author: '刘氏媛', poem: '雨滴梧桐秋夜长，愁心和雨到昭阳。\n泪痕不学君恩断，拭却千行更万行。' },
  { title: '相和歌辞 长门怨二首 二', author: '刘氏媛', poem: '学画蛾眉独出群，当时人道便承恩。\n经年不见君王面，花落黄昏空掩门。' },
  { title: '相和歌辞 阿娇怨', author: '刘禹锡', poem: '望见葳蕤举翠华，试开金屋埽庭花。\n须臾宫女传来信，云幸平阳公主家。' },
  { title: '相和歌辞 班倢伃', author: '徐彦伯', poem: '君恩忽断绝，妾思终未央。\n巾栉不可见，枕席空余香。\n窗暗网罗白，阶秋苔藓黄。\n应门寂已闭，流涕向昭阳。' },
  { title: '相和歌辞 班倢伃', author: '严识玄', poem: '贱妾如桃李，君王若岁时。\n秋风一已劲，摇落不胜悲。\n寂寂苍苔满，沈沈绿草滋。\n荣华非此日，指辇竞何辞。' },
  { title: '相和歌辞 班倢伃三首 一', author: '王维', poem: '玉窗萤影度，金殿人声绝。\n秋夜守罗帏，孤灯耿不灭。' },
  { title: '相和歌辞 班倢伃三首 二', author: '王维', poem: '宫殿生秋草，君王恩幸疎。\n那堪闻凤吹，门外度金舆。' },
  { title: '相和歌辞 班倢伃三首 三', author: '王维', poem: '怪来妆阁闭，朝下不相迎。\n总向春园里，花间语笑声。' },
  { title: '相和歌辞 倢伃怨', author: '崔湜', poem: '不分君恩断，新妆视镜中。\n容华尚春日，娇爱已秋风。\n枕席临窗晓，帏屏向月空。\n年年后庭树，荣落在深宫。' },
  { title: '相和歌辞 倢伃怨', author: '崔国辅', poem: '长信宫中草，年年愁处生。\n故侵珠履迹，不使玉阶行。' },
  { title: '相和歌辞 倢伃怨', author: '张烜', poem: '贱妾裁纨扇，初摇明月姿。\n君王看舞席，坐起秋风时。\n玉树清御路，金陈翳垂丝。\n昭阳无分理，愁寂任前期。' },
  { title: '相和歌辞 倢伃怨', author: '刘方平', poem: '夕殿别君王，宫深月似霜。\n人愁在长信，萤出向昭阳。\n露裛红兰死，秋雕碧树伤。\n惟当合欢扇，从此箧中藏。' },
  { title: '相和歌辞 倢伃怨', author: '王沈', poem: '长信梨花暗欲栖，应门上籥草萋萋。\n春风吹花乱扑户，班倢车声不至啼。' },
  { title: '相和歌辞 倢伃怨', author: '皇甫冉', poem: '由来咏团扇，今与值秋风。\n事逐时皆往，恩无日再中。\n早鸿闻上苑，寒露下深宫。\n颜色年年谢，相如赋岂工。' },
  { title: '相和歌辞 倢伃怨', author: '陆龟蒙', poem: '妾貌非倾国，君王忽然宠。\n南山掌上来，不及新恩重。\n后宫多窈窕，日日学新声。\n一落君王耳，南山又须轻。' },
  { title: '相和歌辞 倢伃怨', author: '翁绶', poem: '谗谤潜来起百忧，朝承恩宠暮仇讐。\n火烧白玉非因玷，霜翦红兰不待秋。\n花落昭阳谁共辇，月明长信独登楼。\n繁华事逐东流水，团扇悲歌万古愁。' },
  { title: '相和歌辞 倢伃怨', author: '刘氏云', poem: '君恩不可见，妾岂如秋扇。\n秋扇尚有时，妾身永微贱。\n莫言朝花不复落，娇容几夺昭阳殿。' },
  { title: '相和歌辞 长信怨', author: '王𬤇', poem: '飞燕倚身轻，争人巧笑名。\n生君弃妾意，增妾怨君情。\n日落昭阳殿，秋来长信城。\n寥寥金殿里，歌吹夜无声。' },
  { title: '相和歌辞 长信怨 一', author: '王昌龄', poem: '金井梧桐秋叶黄，珠帘不卷夜来霜。\n金炉玉枕无颜色，卧听南宫清漏长。' },
  { title: '相和歌辞 长信怨 二', author: '王昌龄', poem: '奉帚平明金殿开，暂将团扇共裴回。\n玉颜不及寒鵶色，犹带昭阳日影来。' },
  { title: '相和歌辞 长信怨', author: '李白', poem: '月皎昭阳殿，霜清长信宫。\n天行乘玉辇，飞燕与君同。\n更有留情处，承恩乐未穷。\n谁怜团扇妾，独坐怨秋风。' },
  { title: '相和歌辞 蛾眉怨', author: '王翰', poem: '君不见宜春苑中九华殿，飞阁连连直如发。\n白日全含朱鸟窗，流云半入苍龙阙。\n宫中彩女夜无事，学凤吹箫弄清越。\n珠帘北卷待凉风，绣户南开向明月。\n忽闻天子忆蛾眉，宝凤衔花揲两螭。\n传声走马开金屋，夹路鸣环上玉墀。\n长乐彤庭宴华寝，三千美人曳光锦。\n灯前含笑更罗衣，帐里承恩荐瑶枕。\n不意君心半路回，求仙别作望仙台。\n仓琅禁闼遥相忆，紫翠岩房昼不开。\n欲向人间种桃实，先从海底觅蓬莱。\n蓬莱可求不可上，孤舟缥缈知何往？\n黄金作盘铜作茎，晴天白露掌中擎。\n王母嫣然感君意，云车雨斾欲相迎。\n飞帘观前空怨慕，少君何事须相误。\n一朝埋没茂陵田，贱妾蛾眉不重顾。\n宫车晚出向南山，仙卫逶迤去不还。\n朝晡泣对麒麟树，树下苍苔日渐斑。\n人生百年夜将半，对酒长歌莫长叹。\n賸知白日不可思，一死一生何足算。' },
  { title: '相和歌辞 玉阶怨', author: '李白', poem: '玉阶生白露，夜久侵罗袜。\n却下水精帘，玲珑望秋月。' },
  { title: '相和歌辞 宫怨', author: '长孙佐辅', poem: '窗前好树名玫瑰，去年花落今年开。\n无情春色尚识返，君心忽断何时来？\n忆昔妆成候仙仗，宫琐玲珑日新上。\n拊心却笑西子嚬，掩鼻谁忧郑姬谤。\n草染文章衣下履，花黏甲乙床前帐。\n三千玉貌休自夸，十二金钗独相向。\n盛衰倾夺欲何如，娇爱飜悲逐佞谀。\n重远岂能慙沼鹄，弃前方见泣船鱼。\n看笼不记熏龙脑，咏扇空曾秃鼠须。\n始意类萝新托柏，终伤如荠却甘荼。\n深院独开还独闭，鹦鹉惊飞苔覆地。\n满箱旧赐前日衣，渍枕新垂夜来泪。\n痕多开镜照还悲，绿髻青蛾尚未衰。\n莫道新缣长绝比，犹逢故劒会相追。' },
  { title: '相和歌辞 宫怨', author: '李益', poem: '露湿晴花宫殿香，月明歌吹在昭阳。\n似将海水添宫漏，共滴长门一夜长。' },
  { title: '相和歌辞 宫怨', author: '于𣸣', poem: '妾家望江口，少年家财厚。\n临江起珠楼，不卖文君酒。\n当年乐贞独，巢燕时为友。\n父兄未许人，畏妾事姑舅。\n西墙邻宋玉，窥见妾眉宇。\n一旦及天聪，恩光生户牖。\n谓言入汉宫，富贵可长久。\n君王纵有情，不奈陈皇后。\n谁怜颊似桃，孰知腰胜柳。\n今日在长门，从来不如丑。' },
  { title: '相和歌辞 宫怨 一', author: '柯崇', poem: '尘满金炉不炷香，黄昏独自立重廊。\n笙歌何处承恩宠？一一随风入上阳。' },
  { title: '相和歌辞 宫怨 二', author: '柯崇', poem: '长门槐柳半萧疎，玉辇沈思恨有余。\n红泪旋销倾国态，黄金谁为达相如。' },
  { title: '相和歌辞 杂怨三首 一', author: '聂夷中', poem: '生在绮罗下，岂识渔阳道。\n良人自戍来，夜夜梦中到。\n渔阳万里远，近于中门限。\n中门逾有时，渔阳常在眼。' },
  { title: '相和歌辞 杂怨三首 二', author: '聂夷中', poem: '良人昨日去，明日又不还。\n别时各有泪，零落青楼前。' },
  { title: '相和歌辞 杂怨三首 三', author: '聂夷中', poem: '君泪濡罗巾，妾泪滴路尘。\n罗巾今在手，日得随妾身。\n路尘如因飞，得上君车轮。' },
  { title: '相和歌辞 杂怨三首 一', author: '孟郊', poem: '夭桃花清晨，游女红粉新。\n夭桃花薄暮，游女红粉故。\n树有百年花，人无一定颜。\n花送人老尽，人悲花自闲。' },
  { title: '相和歌辞 杂怨三首 二', author: '孟郊', poem: '贫女镜不明，寒花日少容。\n暗蛩有虚织，短线无长缝。\n浪水不可照，狂夫不可从。\n浪水多散影，狂夫多异踪。\n持此一生薄，空成百恨浓。' },
  { title: '相和歌辞 杂怨三首 三', author: '孟郊', poem: '忆人莫至悲，至悲空自衰。\n寄人莫翦衣，翦衣未必归。\n朝为双蒂花，暮为四散飞。\n花落却绕树，游子不顾期。' },
  { title: '相和歌辞 子夜春歌', author: '王翰', poem: '春气满林香，春游不可忘。\n落花吹欲尽，垂柳折还长。\n桑女淮南曲，金鞍塞北装。\n行行小垂手，日暮渭川阳。' },
  { title: '相和歌辞 子夜冬歌', author: '崔国辅', poem: '寂寥抱冬心，裁罗又褧褧。\n夜久频挑灯，霜寒剪刀冷。' },
  { title: '相和歌辞 子夜冬歌', author: '薛耀', poem: '朔风扣群木，岩霜凋百草。\n借问月中人，安得长不老。' },
  { title: '相和歌辞 子夜四时歌六首 春歌二首 一', author: '郭元振', poem: '青楼含日光，绿池起风色。\n赠子同心花，殷勤此何极。' },
  { title: '相和歌辞 子夜四时歌六首 春歌二首 二', author: '郭元振', poem: '陌头杨柳枝，已被春风吹。\n妾心正断绝，君怀那得知。' },
  { title: '相和歌辞 子夜四时歌六首 秋歌二首 一', author: '郭元振', poem: '邀欢空伫立，望美频回顾。\n何时复采菱？江中密相遇。' },
  { title: '相和歌辞 子夜四时歌六首 冬歌二首 一', author: '郭元振', poem: '北极严气升，南至温风谢。\n调丝竞短歌，拂枕怜长夜。' },
  { title: '相和歌辞 子夜四时歌六首 冬歌二首 二', author: '郭元振', poem: '帷横双翡翠，被卷两鸳鸯。\n婉态不自得，宛转君王床。' },
  { title: '相和歌辞 子夜四时歌四首 春歌', author: '李白', poem: '秦地罗敷女，采桑绿水边。\n素手青条上，红妆白日鲜。\n蚕饥妾欲去，五马莫留连。' },
  { title: '相和歌辞 子夜四时歌四首 夏歌', author: '李白', poem: '镜湖三百里，菡萏发荷花。\n五月西施采，人看隘若邪。\n回舟不待月，归去越王家。' },
  { title: '相和歌辞 子夜四时歌四首 秋歌', author: '李白', poem: '长安一片月，万户捣衣声。\n秋风吹不尽，总是玉关情。\n何日平胡虏？良人罢远征。' },
  { title: '相和歌辞 子夜四时歌四首 冬歌', author: '李白', poem: '明朝驿使发，一夜絮征袍。\n素手抽针冷，那堪把剪刀。\n裁缝寄远道，几日到临洮。' },
  { title: '相和歌辞 子夜四时歌四首 春歌', author: '陆龟蒙', poem: '山连翠羽屏，草接烟华席。\n望尽南飞燕，佳人断信息。' },
  { title: '相和歌辞 子夜四时歌四首 夏歌', author: '陆龟蒙', poem: '兰眼擡露斜，莺唇映花老。\n金龙倾漏尽，玉井敲冰早。' },
  { title: '相和歌辞 子夜四时歌四首 秋歌', author: '陆龟蒙', poem: '凉汉清泬寥，衰林怨风雨。\n愁听络纬唱，似与羇魂语。' },
  { title: '相和歌辞 子夜四时歌四首 冬歌', author: '陆龟蒙', poem: '南光走冷圭，北籁号空木。\n年年任霜霰，不减筼筜绿。' },
  { title: '相和歌辞 大子夜歌二首 一', author: '陆龟蒙', poem: '歌谣数百种，子夜最可怜。\n慷慨吐清音，明转出天然。' },
  { title: '相和歌辞 大子夜歌二首 二', author: '陆龟蒙', poem: '丝竹发歌响，假器扬清音。\n不知歌谣妙，声势出口心。' },
  { title: '相和歌辞 子夜警歌二首 一', author: '陆龟蒙', poem: '镂椀传绿酒，雕炉熏紫烟。\n谁知苦寒调，共作白雪弦。' },
  { title: '相和歌辞 子夜警歌二首 二', author: '陆龟蒙', poem: '恃爱如欲进，含羞出不前。\n朱口发艳歌，玉指弄娇弦。' },
  { title: '相和歌辞 丁督护歌', author: '李白', poem: '云阳上征去，两岸饶商贾。\n吴牛喘月时，拖船一何苦。\n水浊不可饮，壶浆半成土。\n一唱都护歌，心摧泪如雨。\n万人凿盘石，无由达江浒。\n君看石芒砀，掩泪悲千古。' },
  { title: '相和歌辞 团扇郎', author: '张祜', poem: '白团扇，今来此去捐。\n愿得入郎手，团圆郎眼前。' },
  { title: '相和歌辞 团扇郎', author: '刘禹锡', poem: '团扇复团扇，奉君清暑殿。\n秋风入庭树，从此不相见。\n上有乘鸾女，苍苍虫网遍。\n明年入怀袖，别是机中练。' },
  { title: '相和歌辞 碧玉歌', author: '李暇', poem: '碧玉上宫妓，出入千花林。\n珠被玳瑁床，感郎情意深。' },
  { title: '相和歌辞 懊恼曲', author: '温庭筠', poem: '藕丝作线难胜针，蘂粉染黄那得深。\n玉白兰芳不相顾，倡楼一笑轻千金。\n莫言自古皆如此，健劒刜钟铅绕指。\n三秋庭绿尽迎霜，惟有荷花守红死。\n西江小吏朱斑轮，柳缕吐芽香玉春。\n两股金钗已相许，不令独作空城尘。\n悠悠楚水流如马，恨紫愁红满平野。\n野土千年怨不平，至今烧作鸳鸯瓦。' },
  { title: '相和歌辞 读曲歌五首 一', author: '张祜', poem: '窗中独自起，帘外独自行。\n愁见蜘蛛织，寻思直到明。' },
  { title: '相和歌辞 读曲歌五首 二', author: '张祜', poem: '碓上米不舂，窗中丝罢络。\n看渠驾去车，定是无四角。' },
  { title: '相和歌辞 读曲歌五首 三', author: '张祜', poem: '不见心相许，徒云脚漫勤。\n摘荷空摘叶，是底采莲人。' },
  { title: '相和歌辞 读曲歌五首 四', author: '张祜', poem: '窗外山魈立，知渠脚不多。\n三更机底下，摸着是谁梭。' },
  { title: '相和歌辞 读曲歌五首 五', author: '张祜', poem: '郎去摘黄瓜，郎来收赤枣。\n郎耕种麻地，今作西舍道。' },
  { title: '相和歌辞 春江花月夜二首 一', author: '张子容', poem: '林花发岸口，气色动江新。\n此夜江中月，流光花上春。\n分明石潭里，宜照浣纱人。' },
  { title: '相和歌辞 春江花月夜二首 二', author: '张子容', poem: '交甫怜瑶佩，仙妃难重期。\n沈沈绿江晚，惆怅碧云姿。\n初逢花上月，言是弄珠时。' },
  { title: '相和歌辞 春江花月夜', author: '张若虚', poem: '春江潮水连海平，海上明月共潮生。\n滟滟随波千万里，何处春江无月明？\n江流宛转遶芳甸，月照花林皆似霰。\n空里流霜不觉飞，汀上白沙看不见。\n江天一色无纤尘，皎皎空中孤月轮。\n江畔何人初见月？江月何年初照人？\n人生代代无穷已，江月年年望相似。\n不知江月待何人，但见长江送流水。\n白云一片去悠悠，青枫浦上不胜愁。\n谁家今夜扁舟子，何处相思明月楼？\n可怜楼上月裴回，应照离人妆镜台。\n玉户帘中卷不去，捣衣砧上拂还来。\n此时相望不相闻，愿逐月华流照君。\n鸿雁长飞光不度，鱼龙潜跃水成文。\n昨夜闲潭梦落花，可怜春半不还家。\n江水流春去欲尽，江潭落月复西斜。\n斜月沈沈藏海雾，碣石潇湘无限路。\n不知乘月几人归，落月摇情满江树。' },
  { title: '相和歌辞 春江花月夜', author: '温庭筠', poem: '玉树歌阑海云黑，花庭忽作青芜国。\n秦淮有水水无情，还向金陵漾春色。\n杨家二世安九重，不御华芝嫌六龙。\n百幅锦帆风力满，连天展尽金芙蓉。\n珠翠丁星复明灭，龙头劈浪哀笳发。\n千里涵空照水魂，万枝破鼻团香雪。\n漏转霞高沧海西，颇黎枕上闻天鸡。\n蛮弦代雁曲如语，一醉昏昏天下迷。\n四方倾动烟尘起，犹在浓香梦魂里。\n后主荒宫有晓莺，飞来只隔西江水。' },
  { title: '相和歌辞 玉树后庭花', author: '张祜', poem: '轻车何草草，独唱后庭花。\n玉座谁为主，徒悲张丽华。' },
  { title: '相和歌辞 堂堂', author: '温庭筠', poem: '钱塘岸上春如织，淼淼寒潮带晴色。\n淮南游客马连嘶，碧草迷人归不得。\n风飘客意如吹烟，纤指殷勤伤雁弦。\n一曲堂堂红烛筵，金鲸泻酒如飞泉。' },
  { title: '相和歌辞 三阁词四首 一', author: '刘禹锡', poem: '贵人三阁上，日晏未梳头。\n不应有恨事，娇甚却成愁。' },
  { title: '相和歌辞 三阁词四首 二', author: '刘禹锡', poem: '珠箔曲琼钩，子细见扬州。\n北兵那得度，浪语判悠悠。' },
  { title: '相和歌辞 三阁词四首 三', author: '刘禹锡', poem: '沈香帖阁柱，金缕画门楣。\n回首降幡下，已见黍离离。' },
  { title: '相和歌辞 三阁词四首 四', author: '刘禹锡', poem: '三人出眢井，一身登槛车。\n朱门漫临水，不可见鲈鱼。' },
  { title: '相和歌辞 神弦曲', author: '李贺', poem: '西山日没东山昏，旋风吹马马踏云。\n画弦素管声浅繁，花裙綷䌨步秋尘。\n桂叶刷风桂坠子，青狸哭血寒狐死。\n古壁彩虬金帖尾，雨工骑入秋潭水。\n百年老鸮成木魅，笑声碧火巢中起。' },
  { title: '相和歌辞 神弦别曲', author: '李贺', poem: '巫山小女隔云别，松花春风山上发。\n绿盖独穿香迳归，白马花竿前孑孑。\n蜀江风澹水如罗，堕兰谁泛相经过。\n南山桂树为君死，云衫残污红脂花。' },
  { title: '相和歌辞 祠渔山神女歌 迎神', author: '王维', poem: '坎坎击鼓，渔山之下。\n吹洞箫，望极浦。\n女巫进，纷屡舞。\n陈瑶席，湛清酤。\n风凄凄，又夜雨。\n不知神之来兮不来，使我心兮苦复苦。' },
  { title: '相和歌辞 祠渔山神女歌 送神', author: '王维', poem: '纷进舞兮堂前，目眷眷兮琼筵。\n来不言兮意不传，作暮雨兮愁空山。\n悲急管兮思繁弦，神之驾兮俨欲旋。\n倏云收兮雨歇，山青青兮水潺湲。' },
  { title: '相和歌辞 祠神歌 迎神', author: '王叡', poem: '蓪草头花椰叶裙，蒲葵树下舞蛮云。\n引领望江遥滴酒，白苹风起水生文。' },
  { title: '相和歌辞 祠神歌 送神', author: '王叡', poem: '枨枨山响荅琵琶，酒湿青莎肉饲鵶。\n树叶无声神去后，纸钱灰出木绵花。' },
  { title: '相和歌辞 乌夜啼', author: '杨巨源', poem: '可怜杨叶复杨花，雪净烟深碧玉家。\n乌栖不定枝条弱，城头夜半声哑哑。\n浮萍摇荡门前水，任罥芙蓉莫堕沙。' },
  { title: '相和歌辞 乌夜啼', author: '李白', poem: '黄云城边乌欲栖，归飞哑哑枝上啼。\n机中织锦秦川女，碧纱如烟隔窗语。\n停梭怅然忆远人，独宿孤房泪如雨。' },
  { title: '相和歌辞 乌夜啼二首 一', author: '顾况', poem: '玉房掣锁声翻叶，银箭添泉遶霜堞。\n毕逋发刺月衔城，八九雏飞其母惊。\n此是天上老鵶鸣，人间老鵶无此声。\n摇杂佩，耿华烛，良夜羽人弹此曲，东方曈曈赤日旭。' },
  { title: '相和歌辞 乌夜啼二首 二', author: '顾况', poem: '月出江林西，江林寂寂城鵶啼。\n昔人何处为此曲？今人何处听不足。\n城寒月晓驰思深，江上青草为谁绿。' },
  { title: '相和歌辞 乌夜啼', author: '李群玉', poem: '曾波隔梦渚，一望青枫林。\n有乌在其间，达晓自悲吟。\n是时月黑天，四野烟雨深。\n如闻生离哭，其声痛人心。\n悄悄夜正长，空山响哀音。\n远客不可听，坐愁华发侵。\n既非蜀帝魂，恐是恒山禽。\n四子各分散，母声犹至今。' },
  { title: '相和歌辞 乌夜啼', author: '聂夷中', poem: '众鸟各归枝，乌乌尔不栖。\n还应知妾恨，故向绿窗啼。' },
  { title: '相和歌辞 乌夜啼', author: '白居易', poem: '城上归时晚，庭前宿处危。\n月明无叶树，霜滑有风枝。\n啼涩饥喉咽，飞低冻翅垂。\n画堂鹦鹉鸟，冷暖不相知。' },
  { title: '相和歌辞 乌夜啼', author: '王建', poem: '庭树乌，尔何不向别处栖？\n夜夜夜半当户啼。\n家人把烛出洞户，惊栖失群飞落树。\n一飞直欲飞上天，回回不离旧栖处。\n未明重绕主人屋，欲下空中黑相触。\n风飘雨湿亦不移，君家树头多好枝。' },
  { title: '相和歌辞 乌夜啼', author: '张祜', poem: '忽忽南飞返，危弦共怨凄。\n暗霜移树宿，残夜遶枝啼。\n咽绝声重敍，愔淫思乍迷。\n不妨还报喜，误使玉颜低。' },
  { title: '相和歌辞 乌栖曲', author: '李白', poem: '姑苏台上乌栖时，吴王宫里醉西施。\n吴歌楚舞欢未毕，青山犹衔半边日。' },
  { title: '相和歌辞 乌栖曲', author: '李端', poem: '白马逐牛车，黄昏入狭斜。\n狭斜柳树乌争宿，争枝未得飞上屋。\n东房少妇壻从军，每听乌啼知夜分。' },
  { title: '相和歌辞 乌栖曲', author: '王建', poem: '章华宫人夜上楼，君王望月西山头。\n夜深宫殿门不锁，白露满山山叶堕。' },
  { title: '相和歌辞 乌栖曲', author: '张籍', poem: '西山作宫潮满池，宫乌晓鸣茱萸枝。\n吴姬自唱采莲曲，君王昨夜舟中宿。' },
  { title: '相和歌辞 栖乌曲二首 一', author: '刘方平', poem: '蛾眉曼脸倾城国，鸣环动佩新相识。\n银汉斜临白玉堂，芙蓉行障掩灯光。' },
  { title: '相和歌辞 栖乌曲二首 二', author: '刘方平', poem: '画舸双艚锦为缆，芙蓉花发莲叶暗。\n门前月色映横塘，感郎中夜渡潇湘。' },
  { title: '相和歌辞 莫愁乐', author: '张祜', poem: '侬居石城下，郎到石城游。\n自郎石城出，长在石城头。' },
  { title: '相和歌辞 莫愁曲', author: '李贺', poem: '草生陇坂下，鵶噪城堞头。\n何人此城里，城角栽石榴。\n青丝系五马，黄金络双牛。\n白鱼驾莲船，夜作十里游。\n归来无人识，暗上沈香楼。\n罗床倚瑶瑟，残月倾帘钩。\n今日槿花落，明朝梧树秋。\n若负平生意，何名作莫愁。' },
  { title: '相和歌辞 估客乐', author: '李白', poem: '海客乘天风，将船远行役。\n譬如云中鸟，一去无踪迹。' },
  { title: '相和歌辞 贾客乐', author: '张籍', poem: '金陵向西贾客多，船中生长乐风波。\n欲发移船近江口，船头祭神各浇酒。\n停杯共说远行期，入蜀经蛮远别离。\n金多众中为上客，夜夜算缗眠独迟。\n秋江初月猩猩语，孤帆夜发满湘渚。\n水工持檝防暗滩，直过山边及前侣。\n年年逐利西复东，姓名不在县籍中。\n农夫税多长辛苦，弃业长为贩卖翁。' },
  { title: '相和歌辞 贾客词', author: '刘禹锡', poem: '贾客无定游，所游惟利幷。\n眩俗杂良苦，乘时知重轻。\n心计析秋毫，摇钩侔悬衡。\n锥刀既无弃，转化日已盈。\n邀福祷波神，施财游化城。\n妻约雕金钏，女垂贯珠缨。\n高赀比封君，奇货通幸卿。\n趋时鸷鸟思，藏镪盘龙形。\n大艑浮通川，高楼次旗亭。\n行止皆有乐，关梁似无征。\n农夫何为者？辛苦事寒耕。' },
  { title: '相和歌辞 贾客词', author: '刘驾', poem: '贾客灯下起，犹言发已迟。\n高山有疾路，暗行终不疑。\n寇盗伏其路，猛兽来相追。\n金玉四散去，空囊委路岐。\n扬州有大宅，白骨无地归。\n少妇当此日，对镜弄花枝。' },
  { title: '相和歌辞 襄阳乐', author: '张祜', poem: '大堤花月夜，长江春水流。\n东风正上信，春夜特来游。' },
  { title: '相和歌辞 襄阳曲二首 一', author: '崔国辅', poem: '蕙草娇红蕚，时光舞碧鸡。\n城中美年少，相见白铜鞮。' },
  { title: '相和歌辞 襄阳曲二首 二', author: '崔国辅', poem: '少年襄阳地，来往襄阳城。\n城中轻薄子，知妾解秦筝。' },
  { title: '相和歌辞 襄阳曲', author: '施肩吾', poem: '大堤女儿郎莫寻，三三五五结同心。\n清晨对镜冶容色，意欲取郎千万金。' },
  { title: '相和歌辞 襄阳曲', author: '李端', poem: '襄阳堤路长，草碧杨柳黄。\n谁家女儿临夜妆，红罗帐里有灯光。\n雀钗翠羽动明珰，欲出不出脂粉香。\n同居女伴正衣裳，中庭寒月白如霜。\n贾生十八称才子，空得门前一断肠。' },
  { title: '相和歌辞 大堤曲', author: '张柬之', poem: '南国多佳人，莫若大堤女。\n玉床翠羽帐，宝袜莲花炬。\n魂处自目成，色授开心许。\n迢迢不可见，日暮空愁予。' },
  { title: '相和歌辞 大堤曲', author: '杨巨源', poem: '二八婵娟大堤女，开𬬻相对依江渚。\n待客登楼向水看，邀郎卷幔临花语。\n细雨蒙蒙湿芰荷，巴东商侣挂帆多。\n自传芳酒涴红袖，谁调妍妆回翠蛾。\n珍簟华灯夕阳后，当𬬻理瑟矜纤手。\n月落星微五鼓声，春风摇荡窗前柳。\n岁岁逢迎沙岸间，北人多识绿云鬟。\n无端嫁与五陵少，离别烟波伤玉颜。' },
  { title: '相和歌辞 大堤曲', author: '李白', poem: '汉水临襄阳，花开大堤暖。\n佳期大堤下，泪向南云满。\n春风复无情，吹我梦魂散。\n不见眼中人，天长音信断。' },
  { title: '相和歌辞 大堤曲', author: '李贺', poem: '妾家住横塘，红纱满桂香。\n青云教绾头上髻，明月与作耳边珰。\n莲风起，江畔春。\n大堤上，留北人。\n郎食鲤鱼尾，妾食猩猩唇。\n莫指襄阳道，绿浦归帆少。\n今日菖蒲花，明朝枫树老。' },
  { title: '相和歌辞 大堤行', author: '孟浩然', poem: '大堤行乐处，车马相驰突。\n岁岁春草生，踏青二三月。\n王孙挟珠弹，游女矜罗韈。\n携手今莫同，江花为谁发。' },
  { title: '相和歌辞 三洲歌', author: '温庭筠', poem: '团圆莫作波中月，洁白莫为枝上雪。\n月随波动碎潾潾，雪似梅花不堪折。\n李娘十六青丝发，画带双花为君结。\n门前有路轻离别，惟恐归来旧香灭。' },
  { title: '相和歌辞 拔蒲歌', author: '张祜', poem: '拔蒲来，领郎镜湖边。\n郎心在何处？莫趂新莲去。\n拔得无心蒲，问郎看好无。' },
  { title: '相和歌辞 杨叛儿', author: '李白', poem: '君歌杨叛儿，妾劝新丰酒。\n何许最关人，乌啼白门柳。\n乌啼隐杨花，君醉留妾家。\n博山炉中沈香火，双咽一气凌紫霞。' },
  { title: '相和歌辞 常林欢', author: '温庭筠', poem: '宜城酒熟花覆桥，沙晴绿鸭鸣咬咬。\n秾桑绕舍麦如尾，幽轧鸣机双燕巢。\n马声特特荆门道，蛮水扬光色如草。\n锦荐金炉梦正长，东家呃喔鸡鸣早。' },
  { title: '相和歌辞 江南弄', author: '王勃', poem: '江南弄，巫山连楚梦，行雨行云几相送。\n瑶轩金谷上春时，玉童仙女无见期。\n紫露香烟眇难托，清风明月遥相思。\n遥相思，草徒绿，为听双飞凤凰曲。' },
  { title: '相和歌辞 江南弄', author: '李贺', poem: '江中绿雾起凉波，天上叠𪩘红嵯峨。\n水风浦云生老竹，渚瞑蒲帆如一幅。\n鲈鱼千头酒百斛，酒中倒卧南山绿。\n吴歈越吟未终曲，江上团团帖寒玉。' },
  { title: '相和歌辞 采莲曲', author: '崔国辅', poem: '玉溆花红发，金塘水碧流。\n相逢畏相失，并着采莲舟。' },
  { title: '相和歌辞 采莲曲', author: '徐彦伯', poem: '妾家越水边，摇艇入江烟。\n既觅同心侣，复采同心莲。\n折藕丝能脆，开花叶正圆。\n春歌弄明月，归棹落花前。' },
  { title: '相和歌辞 采莲曲', author: '李白', poem: '若耶溪边采莲女，笑隔荷花共人语。\n日照新妆水底明，风飘香袖空中举。\n岸上谁家游冶郎，三三五五映垂杨。\n紫骝嘶入落花去，见此踟蹰空断肠。' },
  { title: '相和歌辞 采莲曲', author: '贺知章', poem: '稽山罢雾郁嵯峨，镜水无风也自波。\n莫言春度芳菲尽，别有中流采芰荷。' },
  { title: '相和歌辞 采莲曲三首 一', author: '王昌龄', poem: '吴姬越艳楚王妃，争弄莲舟水湿衣。\n来时浦口花迎入，采罢江头月送归。' },
  { title: '相和歌辞 采莲曲三首 二', author: '王昌龄', poem: '荷叶罗裙一色裁，芙蓉向脸两边开。\n乱入池中看不见，闻歌始觉有人来。' },
  { title: '相和歌辞 采莲曲三首 三', author: '王昌龄', poem: '越女作桂舟，还将桂为檝。\n湖上水渺漫，清江初可涉。\n摘取芙蓉花，莫摘芙蓉叶。' },
  { title: '相和歌辞 采莲曲二首 一', author: '戎昱', poem: '虽听采莲曲，讵识采莲心。\n漾檝爱花远，回船愁浪深。\n烟生极浦色，日落半江阴。\n同侣怜波静，看妆堕玉簪。' },
  { title: '相和歌辞 采莲曲二首 二', author: '戎昱', poem: '涔阳女儿花满头，毵毵同泛木兰舟。\n春风日暮南湖里，争唱菱歌不肯休。' },
  { title: '相和歌辞 采莲曲', author: '储光羲', poem: '浅渚荷花繁，深塘菱叶疎。\n独往方自得，耻邀淇上姝。\n广江无术阡，大泽绝方隅。\n浪中海童语，流下鲛人居。\n春雁时隐舟，新荷复满湖。\n采采乘日暮，不思贤与愚。' },
  { title: '相和歌辞 采莲曲二首 一', author: '鲍溶', poem: '弄舟朅来南塘水，荷叶映身摘莲子。\n暑衣清净鸳鸯喜，作浪舞花惊不起。\n殷勤护惜纤纤指，水菱初熟多新刺。' },
  { title: '相和歌辞 采莲曲二首 二', author: '鲍溶', poem: '采莲朅来水无风，莲潭如镜松如龙。\n夏衫短袖交斜红，艳歌笑鬬新芙蓉，戏鱼住听莲花东。' },
  { title: '相和歌辞 采莲曲', author: '张籍', poem: '秋江岸边莲子多，采莲女儿凭船歌。\n青房圆实齐戢戢，争前竞折荡漾波。\n试牵绿茎下寻藕，断处丝多刺伤手。\n白练束腰袖半卷，不插玉钗妆梳浅。\n船中未满度前洲，借问谁家家住远。\n归时共待暮潮上，自弄芙蓉还荡桨。' },
  { title: '相和歌辞 采莲曲', author: '白居易', poem: '菱叶萦波荷飐风，荷花深处小船通。\n逢郎欲语低头笑，碧玉搔头落水中。' },
  { title: '相和歌辞 采莲曲', author: '僧齐己', poem: '越江女，越江莲。\n齐菡萏，双婵娟。\n嬉游向何处？\n采摘且同船。\n浩唱发容与，清波生漪涟。\n时逢岛屿泊，几共鸳鸯眠。\n襟袖既盈溢，馨香亦相传。\n薄暮归去来，苎罗生碧烟。' },
  { title: '相和歌辞 采莲归', author: '王勃', poem: '采莲归，绿水芙蓉衣，秋风起浪凫雁飞。\n桂棹兰桡下长浦，罗裙玉腕摇轻橹。\n叶屿花潭极望平，江讴越吹相思苦。\n相思苦，佳期不可驻。\n塞外征夫犹未还，江南采莲今已暮。\n今已暮，摘莲花，今渠那必尽倡家。\n官道城南把桑叶，何如江上采莲花？\n莲花复莲花，花叶何重叠。\n叶翠本羞眉，花红彊如颊。\n佳人不兹期，怅望别离时。\n牵花怜共蒂，折藕爱连丝。\n故情何处所？新物徒华滋。\n不惜南津交佩解，还羞北海雁书迟。\n采莲歌有节，采莲夜未歇。\n正逢浩荡江上风，又值徘徊江上月。\n莲浦夜相逢，吴姬越女何丰茸。\n共问寒江千里外，征客关山更几重。' },
  { title: '相和歌辞 采莲女', author: '阎朝隐', poem: '采莲女，采莲舟，春日春江碧水流。\n莲衣承玉钏，莲刺罥银钩。\n薄暮敛容歌一曲，氛氲香气满汀洲。' },
  { title: '相和歌辞 湖边采莲妇', author: '李白', poem: '小姑织白纻，未解将人语。\n大嫂采芙蓉，溪湖千万重。\n长兄行不在，莫使外人逢。\n愿学秋胡妇，真心比古松。' },
  { title: '相和歌辞 张静婉采莲曲', author: '温庭筠', poem: '兰膏坠发红玉春，燕钗拖颈抛盘云。\n城西杨柳向娇晚，门前沟水波潾潾。\n麒麟公子朝天客，珮马珰珰铛度春陌。\n掌中无力舞衣轻，翦断鲛绡破春碧。\n抱月飘烟一尺腰，麝脐龙髓怜娇饶。\n秋罗拂衣碎光动，露重花多香不销。\n㶉𫛶胶胶塘水满，绿萍如粟莲茎短。\n一夜西风送雨来，粉痕零落愁红浅。\n船头折藕丝暗牵，藕根莲子相留连。\n郎心似月月易缺，十五十六清光圆。' },
  { title: '相和歌辞 凤笙曲', author: '沈佺期', poem: '忆昔王子晋，凤笙游云空。\n挥手弄白日，安能恋青宫。\n岂无婵娟子，结念罗帐中。\n怜寿不贵色，身世两无穷。' },
  { title: '相和歌辞 凤吹笙曲', author: '李白', poem: '仙人十五爱吹笙，学得昆丘彩凤鸣。\n始闻炼气餐金液，复道朝天赴玉京。\n玉京迢迢几千里，凤笙去去无边已。\n欲叹离声发绛唇，更嗟别调流纤指。\n此时惜别讵堪闻，此地相看未忍分。\n重吟真曲和清吹，却奏仙歌响绿云。\n绿云紫气向函关，访道应寻缑氏山。\n莫学吹笙王子晋，一遇浮丘断不还。' },
  { title: '相和歌辞 采菱曲', author: '储光羲', poem: '浊水菱叶肥，清水菱叶鲜。\n义不游浊水，志士多苦言。\n潮没具区薮，潦深云梦田。\n朝随北风去，暮逐南风还。\n浦口多渔家，相与邀我船。\n饭稻以终日，羹莼将永年。\n方冬水物穷，又欲休山樊。\n尽室相随从，所贵无忧患。' },
  { title: '相和歌辞 采菱行', author: '刘禹锡', poem: '白马湖平秋日光，紫菱如锦彩鸾翔。\n荡舟游女满中央，采菱不顾马上郎。\n争多逐胜纷相向，时转兰桡破轻浪。\n长鬟弱袂动参差，钗影钏文浮荡漾。\n笑语哇咬顾晚晖，蓼花绿岸扣舷归。\n归来共到市桥步，野蔓系船萍满衣。\n家家竹楼临广陌，下有连樯多估客。\n携觞荐芰夜经过，醉踏大堤相应歌。\n屈平祠下沅江水，月照寒波白烟起。\n一曲南音此地闻，长安北望三千里。' },
  { title: '相和歌辞 阳春歌', author: '李白', poem: '长安白日照春空，绿杨结烟桑褭风。\n披香殿前花始红，流芳发色绣户中。\n绣户中，相经过。\n飞燕皇后轻身舞，紫宫夫人绝世歌。' },
  { title: '相和歌辞 阳春曲', author: '温庭筠', poem: '云母空窗晓烟薄，香昏龙气凝辉阁。\n霏霏雾雨杏花天，帘外春威着罗幕。\n曲栏伏槛金麒麟，沙苑芳郊连翠茵。\n廐马何能啮芳草，路人不敢随流尘。' },
  { title: '相和歌辞 阳春曲', author: '庄南杰', poem: '紫锦红囊香满风，金鸾玉轼摇丁冬。\n沙鸥白羽翦晴碧，野桃红艳烧春空。\n芳草绵延锁平地，垅蝶双双舞幽翠。\n凤叫龙吟白日长，落花声底仙娥醉。' },
  { title: '相和歌辞 阳春曲', author: '僧贯休', poem: '为口莫学阮嗣宗，不言是非非至公。\n为手须似朱云辈，折槛英风至今在。\n男儿结发事君亲，须𢽾前贤多慷慨。\n历数雍熙房与杜，魏公姚公宋开府。' },
  { title: '相和歌辞 朝云引', author: '郎大家宋氏', poem: '巴西巫峡指巴东，朝云触石上朝空。\n巫山巫峡高何已，行雨行云一时起。\n一时起，三春暮。\n若言来，且就阳台路。' },
  { title: '相和歌辞 上云乐', author: '李白', poem: '金天之西，白日所没。\n康老胡雏，生彼月窟。\n巉岩仪容，[戌]削风骨。\n碧玉炅炅双目瞳，黄金拳拳两鬓红。\n华盖垂下睫，嵩岳临上唇。\n不覩谲诡貌，岂知造化神。\n大道是文康之严父，元气乃文康之老亲。\n抚顶弄盘古，推车转天轮。\n云见日月初生时，铸冶火精与水银。\n阳乌未出谷，顾兔半藏身。\n女娲戏黄土，团作愚下人。\n散在六合间，蒙蒙如沙尘。\n生死了不尽，谁明此胡是仙真。\n西海栽若木，东溟植扶桑。\n别来几多时，枝叶万里长。\n中国有七圣，半路颓鸿荒。\n陛下应运起，龙飞入咸阳。\n赤眉立盆子，白水兴汉光。\n叱咤四海动，洪涛为簸扬。\n举足蹋紫微，天关自开张。\n老胡感至德，东来进仙倡。\n五色师子，九苞凤凰。\n是老胡鸡犬，鸣舞飞帝乡。\n淋漓飒沓，进退成行。\n能胡歌，献汉酒。\n跪双膝，并两肘。\n散花指天举素手，拜龙颜，献圣寿。\n北斗戾，南山摧。\n天子九九八十一[万]岁，长倾万岁杯。' },
  { title: '相和歌辞 上云乐', author: '李贺', poem: '飞香走红满天春，花龙盘盘上紫云。\n三千宫女列金屋，五十弦瑟海上闻。\n大江碎碎银沙路，嬴女机中断烟素。\n断烟素，缝舞衣，八月一日君前舞。' },
  { title: '相和歌辞 凤台曲', author: '王无竞', poem: '凤台何逶迤，嬴女管参差。\n一旦彩云至，身去无还期。\n遗曲此台上，世人多学吹。\n一吹一落泪，至今怜玉姿。' },
  { title: '相和歌辞 凤台曲', author: '李白', poem: '尝闻秦帝女，传得凤凰声。\n是日逢仙子，当时别有情。\n人吹彩箫去，天借绿云迎。\n曲在身不返，空余弄玉名。' },
  { title: '相和歌辞 凤凰曲', author: '李白', poem: '嬴女吹玉箫，吟弄天上春。\n青鸾不独去，更有携手人。\n影灭彩云断，遗声落西秦。' },
  { title: '相和歌辞 君道曲', author: '李白', poem: '大君若天覆，广运无不至。\n轩后爪牙常先太山稽，如心之使臂。\n小白鸿翼于夷吾，刘葛鱼水本无二。\n土扶可成墙，积德为厚地。' },
  { title: '舞曲歌辞 吴俞儿舞歌 劒俞', author: '陆龟蒙', poem: '枝月喉，櫂霜脊，北斗离离在寒碧。\n龙魂清，虎尾白，秋照海心同一色。\n纛影咤沙干影侧，神豪发直。\n四睨之人股佶栗，欲定不定定不得。\n舂牍残，儿且止。\n狄胡有胆大如山，怖亦死。' },
  { title: '舞曲歌辞 吴俞儿舞歌 矛俞', author: '陆龟蒙', poem: '手盘风，头背分，电光战扇，欲刺敲心留半线。\n缠肩绕脰，𧞔合眩旋。\n卓植赴列，夺避中节。\n前冲函礼穴，上指孛彗灭，与君一用来有截。' },
  { title: '舞曲歌辞 吴俞儿舞歌 弩俞', author: '陆龟蒙', poem: '牛来开弦，人为置镞。\n捩机关，迸山谷。\n鹿骇涩，隼击迟。\n析毫中睫，洞腋分龟。\n达坚垒，残雄师。\n可以冠猛乐壮曲，抑扬蹈厉，有裂犀兕之气者非公与。' },
  { title: '舞曲歌辞 东海有勇妇', author: '李白', poem: '梁山感杞妻，恸哭为之倾。\n金石忽暂开，都由激深情。\n东海有勇妇，何慙苏子卿。\n学劒越处子，超腾若流星。\n捐躯报夫讐，万死不顾生。\n白刃耀素雪，苍天感精诚。\n十步两躩跃，三呼一交兵。\n斩首掉国门，蹴踏五藏行。\n割此伉俪愤，粲然大义明。\n北海李使君，飞章奏天庭。\n舍罪警风俗，流芳播沧瀛。\n志在列女籍，竹帛已光荣。\n淳于免诏狱，汉主为缇萦。\n津妾一櫂歌，脱父于严刑。\n十子若不肖，不如一女英。\n豫让斩空衣，有心竟无成。\n要离杀庆忌，壮夫素所轻。\n妻子亦何辜，焚之买虚名。\n岂如东海妇，事立独扬名。' },
  { title: '舞曲歌辞 章和二年中', author: '李贺', poem: '云萧素，风拂拂，麦芒如篲黍和粟。\n关中父老百领襦，关东吏人乏诟租。\n健犊春耕土膏黑，菖蒲丛丛沿水脉。\n殷勤为我下田鉏，百钱携赏丝桐客。\n游春漫光坞花白，野林散香神降席。\n拜神得寿献天子，七星贯断姮娥死。' },
  { title: '舞曲歌辞 公莫舞歌', author: '李贺', poem: '方花古础排九楹，刺豹淋血盛银甖。\n华筵鼓吹无桐竹，长刀直立割鸣筝。\n横楣麤锦生红纬，日炙锦嫣王未醉。\n腰下三看宝玦光，项庄掉箾拦前起。\n材官小臣公莫舞，座上真人赤龙子。\n芒砀云瑞抱天回，咸阳王气清如水。\n铁枢铁楗重束关，大旗五丈撞双环。\n汉王今日须秦印，绝膑刳肠臣不论。' },
  { title: '舞曲歌辞 拂舞辞', author: '李贺', poem: '吴娥声绝天，空云闲裴回。\n门外满车马，亦须生绿苔。\n尊有乌程酒，劝君千万寿。\n全胜汉武锦楼上，晓望晴寒饮花露。\n东方日不破，天光无老时。\n丹成作蛇乘白雾，千年重化玉井龟。\n从蛇作龟二千载，吴堤绿草年年在。\n背有八卦称神仙，邪鳞顽甲滑腥涎。' },
  { title: '舞曲歌辞 白鸠辞', author: '李白', poem: '铿鸣钟，考朗鼓。\n歌白鸠，引拂舞。\n白鸠之白谁与邻，霜衣雪襟诚可珍。\n含哺七子能平均，食不咽，性安驯。\n首农政，鸣阳春。\n天子刻玉杖，镂形赐耆人。\n白鹭亦白非纯真，外洁其色心匪仁。\n阙五德，无司晨。\n胡为啄我葭下之紫鳞，鹰鹯雕鹗，贪而好杀。\n凤皇虽大圣，不愿以为臣。' },
  { title: '舞曲歌辞 独漉篇', author: '李白', poem: '独漉水中泥，水浊不见月。\n不见月尚可，水深行人没。\n越鸟从南来，胡鹰亦北度。\n我欲弯弓向天射，惜其中道失归路。\n落叶别树，飘零随风。\n客无所托，悲与此同。\n罗帷舒卷，似有人开。\n明月直入，无心可猜。\n雄劒挂壁，时时龙鸣。\n不断犀象，绣涩苔生。\n国耻未雪，何由成名。\n神鹰梦泽，不顾鸱鸢。\n为君一击，抟鹏九天。' },
  { title: '舞曲歌辞 独漉歌', author: '王建', poem: '独独漉漉，鼠食猫肉。\n乌日中，鹤露宿，黄河水直人心曲。' },
  { title: '舞曲歌辞 白纻辞二首 一', author: '崔国辅', poem: '洛阳梨花落如霰，河阳桃叶生复齐。\n坐恐玉楼春欲尽，红绵粉絮裛妆啼。' },
  { title: '舞曲歌辞 白纻辞二首 二', author: '崔国辅', poem: '董贤女弟在椒风，窈窕繁华贵后宫。\n璧带金釭皆翡翠，一朝零落变成空。' },
  { title: '舞曲歌辞 白纻辞二首 一', author: '杨衡', poem: '玉缨翠珮杂轻罗，香汗微渍朱颜酡，为君起唱白纻歌。\n清声褭云思繁多，凝笳哀琴时相和。\n金壶半倾芳夜促，梁尘霏霏暗红烛。\n令君安坐听终曲，坠叶飘花难再复。' },
  { title: '舞曲歌辞 白纻辞二首 二', author: '杨衡', poem: '蹑珠履，步琼筵。\n轻身起舞红烛前，芳姿艳态妖且妍。\n回眸转袖暗催弦，凉风萧萧流水急。\n月华泛艳红莲湿，牵裙揽带翻成泣。' },
  { title: '舞曲歌辞 白纻辞三首 一', author: '李白', poem: '扬清歌，发皓齿，北方佳人东邻子。\n且吟白纻停渌水，长袖拂面为君起。\n寒云夜卷霜海空，胡风吹天飘塞鸿。\n玉颜满堂乐未终，馆娃日落歌吹蒙。' },
  { title: '舞曲歌辞 白纻辞三首 二', author: '李白', poem: '月寒江清夜沈沈，美人一笑千黄金。\n垂罗舞縠扬哀音，郢中白雪且莫吟，子夜吴歌动君心。\n动君心，冀君赏。\n愿作天池双鸯鸯，一朝飞去青云上。' },
  { title: '舞曲歌辞 白纻辞三首 三', author: '李白', poem: '吴刀翦彩缝舞衣，明妆丽服夺春辉。\n扬眉转袖若雪飞，倾城独立世所稀。\n激楚结风醉忘归，高堂月落烛已微，玉钗挂缨君莫违。' },
  { title: '舞曲歌辞 白纻歌二首 一', author: '王建', poem: '天河漫漫北斗粲，宫中乌啼知夜半。\n新缝白纻舞衣成，来迟邀得吴王迎。\n低鬟转面掩双袖，玉钗浮动秋风生。\n酒多夜长夜未晓，月明灯光两相照，后庭歌声更窈窕。' },
  { title: '舞曲歌辞 白纻歌二首 二', author: '王建', poem: '馆娃宫中春日暮，荔枝木瓜花满树。\n城头乌栖休击鼓，青娥弹瑟白纻舞。\n夜天燑燑不见星，宫中火照西江明。\n美人醉起无次第，堕钗遗佩满中庭。\n此时但愿可君意，回昼为宵亦不寐，年年奉君君莫弃。' },
  { title: '舞曲歌辞 白纻歌', author: '张籍', poem: '皎皎白纻白且鲜，将作春衫称少年。\n裁缝长短不能定，自持刀尺向姑前。\n复恐兰膏污纤指，常遣傍人收堕珥。\n衣裳着时寒食下，还把玉鞭鞭白马。' },
  { title: '舞曲歌辞 白纻歌', author: '柳宗元', poem: '翠帷双卷出倾城，龙劒破匣霜月明。\n朱唇掩抑悄无声，金簧玉磬宫中生。' },
  { title: '舞曲歌辞 冬白纻歌', author: '元稹', poem: '吴宫夜长宫漏款，帘幕四垂灯焰暖。\n西施自舞王自管，雪纻翻翻鹤翎散。\n促节牵繁舞腰嬾，舞腰嬾，王罢饮。\n盖覆西施凤花锦，身作匡床臂为枕。\n朝佩𪭢𪭢王晏寝，酒醒阍报门无事。\n子胥死后言为讳，近王之臣谕王意。\n共笑越王穷惴惴，夜夜抱冰寒不睡。' },
  { title: '舞曲歌辞 霓裳辞十首 一', author: '王建', poem: '弟子部中留一色，听风听水作霓裳。\n散声未足重来授，直到床前见上皇。' },
  { title: '舞曲歌辞 霓裳辞十首 二', author: '王建', poem: '中管五弦初半曲，遥教合上隔帘听。\n一声声向天头落，效得仙人夜唱经。' },
  { title: '舞曲歌辞 霓裳辞十首 三', author: '王建', poem: '自直梨园得出稀，更番上曲不教归。\n一时跪拜霓裳彻，立地阶前赐紫衣。' },
  { title: '舞曲歌辞 霓裳辞十首 四', author: '王建', poem: '旋翻新谱声初足，除却梨园未教人。\n宣与书家分手写，中官走马赐功臣。' },
  { title: '舞曲歌辞 霓裳辞十首 五', author: '王建', poem: '伴教霓裳有贵妃，从初直到曲成时。\n日长耳里闻声熟，拍数分毫错总知。' },
  { title: '舞曲歌辞 霓裳辞十首 六', author: '王建', poem: '弦索𪭢𪭢隔彩云，五更初发一山闻。\n武皇自送西王母，新换霓裳月色裙。' },
  { title: '舞曲歌辞 霓裳辞十首 七', author: '王建', poem: '敕赐宫人澡浴回，遥看美女院门开。\n一山星月霓裳动，好字先从殿里来。' },
  { title: '舞曲歌辞 霓裳辞十首 八', author: '王建', poem: '传呼法部按霓裳，新得承恩别作行。\n应是贵妃楼上看，内人舁下彩罗箱。' },
  { title: '舞曲歌辞 霓裳辞十首 九', author: '王建', poem: '朝元阁上山风起，夜听霓裳玉露寒。\n宫女月中更替立，黄金梯滑竝行难。' },
  { title: '舞曲歌辞 霓裳辞十首 十', author: '王建', poem: '知向华清年月满，山头山底种长生。\n去时留下霓裳曲，总是离宫别馆声。' },
  { title: '舞曲歌辞 柘枝词', author: '失撰人名', poem: '将军奉命即须行，塞外领彊兵。\n闻道烽烟动，腰间宝劒匣中鸣。' },
  { title: '舞曲歌辞 柘枝词 一', author: '薛能', poem: '同营三十万，震鼓伐西羌。\n战血黏秋草，征尘搅夕阳。\n归来人不识，帝里独戎装。' },
  { title: '舞曲歌辞 柘枝词 二', author: '薛能', poem: '悬军征拓羯，内地隔萧关。\n日色昆仑上，风声朔漠间。\n何当千万骑，飒飒贰师还。' },
  { title: '舞曲歌辞 柘枝词 三', author: '薛能', poem: '意气成功日，春风起絮天。\n楼台新邸第，歌舞小婵娟。\n急破催摇曳，罗衫半脱肩。' },
  { title: '舞曲歌辞 屈柘词', author: '温庭筠', poem: '杨柳萦桥绿，玫瑰拂地红。\n绣衫金騕褭，花髻玉珑璁。\n宿雨香潜润，春流水暗通。\n画楼初梦断，晴日照湘风。' },
  { title: '琴曲歌辞 白雪歌', author: '僧贯休', poem: '列鼎佩金章，泪眼看风枝。\n却思食藜藿，身作屠沽儿。\n负米无远近，所希升斗归。\n为人无贵贱，莫学鸡狗肥。\n斯言如不忘，别更无光辉。\n斯言如或忘，即安用人为。' },
  { title: '琴曲歌辞 湘妃', author: '刘长卿', poem: '帝子不可见，秋风来暮思。\n婵娟湘江月，千载空蛾眉。' },
  { title: '琴曲歌辞 湘妃', author: '李贺', poem: '筠竹千年老不死，长伴秦娥盖湘水。\n蛮娘吟弄满寒空，九山静绿泪花红。\n离鸾别凤烟梧中，巫云蜀雨遥相通。\n幽愁秋气上青枫，凉夜波间吟古龙。' },
  { title: '琴曲歌辞 湘妃怨', author: '孟郊', poem: '南巡竟不返，帝子怨逾积。\n万里丧蛾眉，潇湘水空碧。\n冥冥荒山下，古庙收贞魄。\n乔木深青春，清光满瑶席。\n搴芳徒有荐，灵意殊脉脉。\n玉佩不可亲，裴回烟波夕。' },
  { title: '琴曲歌辞 湘妃怨', author: '陈羽', poem: '二妃怨处云沈沈，二妃哭处湘水深。\n商人酒滴庙前草，萧飒风生斑竹林。' },
  { title: '琴曲歌辞 湘妃列女操', author: '鲍溶', poem: '有虞夫人哭虞后，淑女何事又伤离。\n竹上泪迹生不尽，寄哀云和五十丝。\n云和经奏钧天曲，乍听宝琴遥嗣续。\n三湘测测流急绿，秋夜露寒蜀帝飞。\n枫林月斜楚臣宿，更疑川宫日黄昏。\n暗携女手殷勤言，环佩玲珑有无间。\n终疑既远双悄悄，苍梧旧云岂难召。\n老猨心寒不可啸，目眄眄兮意蹉跎。' },
  { title: '琴曲歌辞 湘夫人', author: '邹绍先', poem: '枫叶下秋渚，二妃愁渡湘。\n疑山空杳蔼，何处望君王？\n日落水云里，油油心自伤。' },
  { title: '琴曲歌辞 湘夫人', author: '李颀', poem: '九嶷日已暮，三湘云复愁。\n窅蔼罗袂色，潺湲江水流。\n佳期来北渚，捐玦在芳洲。' },
  { title: '琴曲歌辞 湘夫人', author: '郎士元', poem: '娥眉对湘水，遥哭苍梧间。\n万乘既已殁，孤舟谁忍还。\n至今楚山上，犹有泪痕斑。\n南有涔阳路，渺渺多新愁。\n昔神降回时，风波江上秋。\n彩云忽无处，碧水空安流。' },
  { title: '琴曲歌辞 霹雳引', author: '沈佺期', poem: '岁七月，火伏而金生。\n客有鼓瑟于门者，奏霹雳之商声。\n始戛羽以𬴃砉，终扣宫而砰駖。\n电耀耀兮龙跃，雷阗阗兮雨冥。\n气呜唅以会雅，态歘翕以横生。\n有如驱千旗，制五兵，截荒虺，斮长鲸。\n孰与广陵比，意别鹤俦精而已。\n俾我雄子魄动，毅夫发立，怀恩不浅，武义双辑，视胡若芥，翦羯如拾。\n岂徒慨慷中筵，备群娱之翕习哉。' },
  { title: '琴曲歌辞 拘幽操', author: '韩愈', poem: '目揜揜兮其凝其盲，耳肃肃兮听不闻声。\n朝不日出兮夜不见月与星，有知无知兮为死为生。\n呜呼！臣罪当诛兮天王圣明。' },
  { title: '琴曲歌辞 越裳操', author: '韩愈', poem: '雨之施，物以孳，我何意于彼为。\n自周之先，其艰其勤。\n以有疆宇，私我后人。\n我祖在上，四方在下。\n厥临孔威，敢戏以侮。\n孰荒于门，孰治于田。\n四海既均，越裳是臣。' },
  { title: '琴曲歌辞', author: '韩愈', poem: '我家于豳，自我先公。\n伊我承绪，敢有不同。\n今狄之人，将土我疆。\n民为我战，谁使死伤。\n彼岐有岨，我往独处。\n人莫余追，无思我悲。' },
  { title: '琴曲歌辞 履霜操', author: '韩愈', poem: '父兮儿寒，母兮儿饥。\n儿罪当笞，逐儿何为？\n儿在中野，以宿以处。\n四无人声，谁与儿语。\n儿寒何衣，儿饥何食。\n儿行于野，履霜以足。\n母生众儿，有母怜之。\n独无母怜，儿宁不悲。' },
  { title: '琴曲歌辞 雉朝飞操', author: '李白', poem: '麦陇青青三月时，白雉朝飞挟两雌。\n锦衣绮翼何离褷，犊牧采薪感之悲。\n春天和，白日暖，啄食饮泉勇气满。\n争雄鬬死绣颈断，雉子班奏急管弦，心倾美酒尽玉椀。\n枯杨枯杨尔生荑，我独七十而孤栖。\n弹弦写恨意不尽，瞑目归黄泥。' },
  { title: '琴曲歌辞 雉朝飞操', author: '韩愈', poem: '雉之飞，于朝日。\n群雌孤雄，意气横出。\n当东而西，当啄而飞。\n随飞随啄，群雌粥粥。\n嗟我虽人，曾不如彼雉鸡。\n生身七十年，无一妾与妃。' },
  { title: '琴曲歌辞 雉朝飞操', author: '张祜', poem: '朝阳陇东泛暖景，双啄双飞双顾影。\n朱冠锦襦聊日整，漠漠雾中如衣褧。\n伤心卢女弦，七十老翁长独眠。\n雄飞在草雌在田，衷肠结愤气呵天。\n圣人在上心不偏，翁得女妻甚可怜。' },
  { title: '琴曲歌辞 思归引', author: '张祜', poem: '重重作闺清旦𫔎，两耳深声长不彻。\n深宫坐愁百年身，一片玉中生愤血。\n焦桐罢弹丝自绝，漠漠暗魂愁夜月。\n故乡不归谁共穴，石上作蒲蒲九节。' },
  { title: '琴曲歌辞 猗兰操', author: '韩愈', poem: '兰之猗猗，扬扬其香。\n不采而佩，于兰何伤。\n今天之旋，其曷为然。\n我行四方，以日以年。\n雪霜贸贸，荠麦之茂。\n子如不伤，我不尔觏。\n荠麦之茂，荠麦之有。\n君子之伤，君子之守。' },
  { title: '琴曲歌辞 幽兰', author: '崔涂', poem: '幽植众能知，贞芳只暗持。\n自无君子佩，未是国香衰。\n白露沾长早，青春每到迟。' },
  { title: '琴曲歌辞 将归操', author: '韩愈', poem: '秋之水兮其色幽幽，我将济兮不得其由。\n涉其浅兮石啮我足，乘其深兮龙入我舟，我济而悔兮将安归尤？\n归乎归乎，无与石鬬兮无应龙求。' },
  { title: '琴曲歌辞 龟山操', author: '韩愈', poem: '龟之气兮不能云雨，龟之枿兮不中梁柱，龟之大兮祗以奄鲁。\n知将隳兮哀莫余伍，周公有鬼兮嗟余归辅。' },
  { title: '琴曲歌辞 残形操', author: '韩愈', poem: '有兽维狸兮我梦得之，其身孔明兮而头不知。\n吉凶何为兮觉坐而思，巫咸上天兮识者其谁。' },
  { title: '琴曲歌辞 双燕离', author: '李白', poem: '双燕复双燕，双飞令人羡。\n玉楼珠阁不独栖，金窗绣户长相见。\n柏梁失火去，因入吴王宫。\n吴宫又焚荡，雏尽巢亦空。\n憔悴一身在，孀雌忆故雄。\n双飞难再得，伤我寸心中。' },
  { title: '琴曲歌辞 列女操', author: '孟郊', poem: '梧桐相待老，鸳鸯会双死。\n贞妇贵徇夫，舍生亦如此。\n波澜誓不起，妾心井中水。' },
  { title: '琴曲歌辞 别鹄操', author: '韩愈', poem: '雄鹄衔枝来，雌鹄啄泥归。\n巢成不生子，大义当乖离。\n江汉水之大，鹄身鸟之微。\n更无相逢日，安可相随飞。' },
  { title: '琴曲歌辞 别鹤', author: '杨巨源', poem: '海鹤一为别，高程方杳然。\n影摇江海路，思结潇湘天。\n皎然仰白日，真姿栖紫烟。\n含情九霄际，顾侣五云前。\n遐心属清都，凄响激朱弦。\n超摇间云雨，迢遰各山川。\n东南信多水，会合当有年。' },
  { title: '琴曲歌辞 别鹤', author: '王建', poem: '主人一去池水绝，池鹤散飞不相别。\n青天漫漫碧海重，知向何山风雪中？\n万里虽然音影在，向心终是死生同。\n池边巢破松树死，树头年年乌生子。' },
  { title: '琴曲歌辞 别鹤', author: '张籍', poem: '双鹤出云谿，分飞各自迷。\n空巢在松杪，折羽落江泥。\n寻水终不饮，逢林亦未栖。\n别离应易老，万里两凄凄。' },
  { title: '琴曲歌辞 别鹤', author: '杜牧', poem: '分飞共所从，六翮势摧风。\n声断碧云外，影孤明月中。\n青田归路远，月桂旧巢空。\n矫翼知何处，天涯不可穷。' },
  { title: '琴曲歌辞 走马引', author: '李贺', poem: '我有辞乡劒，玉锋堪截云。\n襄阳走马客，意气自生春。\n朝嫌劒光静，暮嫌劒花冷。\n能持劒向人，不解持照身。' },
  { title: '琴曲歌辞 昭君怨', author: '白居易', poem: '明妃风貌最娉婷，合在椒房应四星。\n只得当年备宫掖，何曾专夜奉帏屏。\n见疎从道迷图画，知屈那教配虏廷。\n自是君恩薄如纸，不须一向恨丹青。' },
  { title: '琴曲歌辞 昭君怨 一', author: '张祜', poem: '万里边城远，千山行路难。\n举头唯见日，何处是长安。' },
  { title: '琴曲歌辞 昭君怨 二', author: '张祜', poem: '汉庭无大议，戎虏几先和。\n莫羡倾城色，昭君恨最多。' },
  { title: '琴曲歌辞 昭君怨', author: '梁氏琼', poem: '自古无和亲，贻灾到妾身。\n胡风嘶去马，汉月吊行轮。\n衣薄狼山雪，妆成虏塞春。\n回看父母国，生死毕胡尘。' },
  { title: '琴曲歌辞 明妃怨', author: '杨凌', poem: '汉国明妃去不还，马𫘞弦管向阴山。\n匣中纵有菱花镜，羞对单于照旧颜。' },
  { title: '琴曲歌辞 蔡氏五弄 游春曲二首 一', author: '王涯', poem: '万树江边杏，新开一夜风。\n满园深浅色，照在绿波中。' },
  { title: '琴曲歌辞 蔡氏五弄 游春曲二首 二', author: '王涯', poem: '上苑何穷树，花开次第新。\n香车与丝骑，风静亦生尘。' },
  { title: '琴曲歌辞  游春辞二首 一', author: '王涯', poem: '曲江丝柳变烟条，寒骨冰随暖气销。\n才见春光生绮陌，已闻清乐动云韶。' },
  { title: '琴曲歌辞  游春辞二首 二', author: '王涯', poem: '经过柳陌与桃蹊，寻逐风光着处迷。\n鸟度时时冲絮起，花繁衮衮压枝低。' },
  { title: '琴曲歌辞  游春辞三首 一', author: '令狐楚', poem: '晚游临碧殿，日上望春亭。\n芳树罗仙仗，晴山展翠屏。' },
  { title: '琴曲歌辞  游春辞三首 二', author: '令狐楚', poem: '一夜好风吹，新花一万枝。\n风前调玉管，花下簇金羁。' },
  { title: '琴曲歌辞  游春辞三首 三', author: '令狐楚', poem: '阊阖春风起，蓬莱雪水消。\n相将折杨柳，争取最长条。' },
  { title: '琴曲歌辞  渌水曲', author: '李白', poem: '渌水明秋月，南湖采白苹。\n荷花娇欲语，愁杀荡舟人。' },
  { title: '琴曲歌辞  渌水辞', author: '李贺', poem: '今宵好风月，阿侯在何处？\n为有倾城色，翻成足愁苦。\n东湖采莲叶，南湖拔蒲根。\n未持寄小姑，且持感愁魂。' },
  { title: '琴曲歌辞  幽居弄', author: '顾况', poem: '苔衣生，花露滴，月入西林荡东壁。\n扣商占角两三声，洞户谿窗一冥寂。\n独去沧洲无四邻，身婴世网此何身？\n关情命曲寄惆怅，久别江南山里人。' },
  { title: '琴曲歌辞  秋思二首 一', author: '李白', poem: '春阳如昨日，碧树鸣黄鹂。\n芜然蕙草暮，飒尔凉风吹。\n天秋木叶下，月冷莎鸡悲。\n坐愁群芳歇，白露凋华滋。' },
  { title: '琴曲歌辞  秋思二首 二', author: '李白', poem: '阏氏黄叶落，妾望白登台。\n月出碧云断，蝉声秋色来。\n胡兵沙塞合，汉使玉关回。\n征客无归日，空悲蕙草摧。' },
  { title: '琴曲歌辞  秋思二首 一', author: '鲍溶', poem: '胡风吹雁翼，远别无人乡。\n君近鴈来处，几回断君肠。\n昔奉千日书，抚心怨星霜。\n无书又千日，世路重茫茫。\n燕国有佳丽，蛾眉富春光。\n自然君归晚，花落君空堂。\n君其若不然，岁晚双鸳鸯。\n顾兔蚀残月，幽光不如星。\n女儿晚事夫，颜色同秋萤。\n秋日边马思，武夫不遑宁。\n燕歌易水怨，劒舞蛟龙腥。\n风折连枝树，水翻无蒂萍。\n立身多户门，何必燕山铭。\n生世不如鸟，双双比翼翎。' },
  { title: '琴曲歌辞  秋思二首 二', author: '鲍溶', poem: '季秋天地闲，万物生意足。\n我忧长于生，安得及草木。\n试从古人愿，致酒歌秉烛。\n燕赵皆世人，讵能长似玉。\n俯怜老期近，仰视日车速。\n萧飒御风君，魂梦愿相逐。\n百年夜销半，端为垂缨束。' },
  { title: '琴曲歌辞  秋思', author: '司空曙', poem: '静与嬾相偶，年将衰共催。\n前途欢不集，往事恨空来。\n昼景委红叶，月华铺绿苔。\n沈思更何有？结坐玉琴哀。' },
  { title: '琴曲歌辞  秋思', author: '司空图', poem: '身病时亦危，逢秋多恸哭。\n风波一摇荡，天地几翻覆。\n孤萤出荒池，落叶穿破屋。' },
  { title: '琴曲歌辞  秋思二首 一', author: '王涯', poem: '网轩凉吹动轻衣，夜听更长玉漏稀。\n月渡天河光转湿，鹊惊秋树叶频飞。' },
  { title: '琴曲歌辞  秋思二首 二', author: '王涯', poem: '宫连太液见苍波，暑气微清秋意多。\n一夜轻风苹末起，露珠翻尽满池荷。' },
  { title: '琴曲歌辞 胡笳十八拍 第一拍', author: '刘商', poem: '汉室将衰兮四夷不宾，动干戈兮征战频。\n哀哀父母生育我，见离乱兮当此辰。\n纱窗对镜未经事，将谓珠帘能蔽身。\n一朝虏骑入中国，苍黄处处逢胡人。\n忽将薄命委锋镝，可惜红颜随虏尘。' },
  { title: '琴曲歌辞 胡笳十八拍 第二拍', author: '刘商', poem: '马上将余向绝域，厌生求死死不得。\n戎羯腥膻岂是人，豺狼喜怒难姑息。\n行尽天山足霜霰，风土萧条近胡国。\n万里重阴鸟不飞，寒沙莽莽无南北。' },
  { title: '琴曲歌辞 胡笳十八拍 第三拍', author: '刘商', poem: '如羇囚兮在缧绁，忧虑万端无处说。\n使余力兮翦余发，食余肉兮饮余血。\n诚知杀身愿如此，以余为妻不如死。\n早被蛾眉累此身，空悲弱质柔如水。' },
  { title: '琴曲歌辞 胡笳十八拍 第四拍', author: '刘商', poem: '山川路长谁记得，何处天涯是乡国？\n自从惊怖少精神，不觉风霜损颜色。\n夜中归梦来又去，朦胧岂解传消息。\n漫漫胡天叫不闻，明明汉月应相识。' },
  { title: '琴曲歌辞 胡笳十八拍 第五拍', author: '刘商', poem: '水头宿兮草头坐，风吹汉地衣裳破。\n羊脂沐发长不梳，羔子皮裘领仍左。\n狐襟貉袖腥复膻，昼披行兮夜披卧。\n毡帐时移无定居，日月长兮不可过。' },
  { title: '琴曲歌辞 胡笳十八拍 第六拍', author: '刘商', poem: '怪得春光不来久，胡中风土无花柳。\n天翻地覆谁得知，如今正南看北斗。\n姓名音信两不通，终日经年常闭口。\n是非取与在指㧑，言语传情不如手。' },
  { title: '琴曲歌辞 胡笳十八拍 第七拍', author: '刘商', poem: '男儿妇人带弓箭，塞马蕃羊卧霜霰。\n寸步东西岂自由，偷生乞死非情愿。\n龟兹筚篥愁中听，碎叶琵琶夜深怨。\n竟夕无云月上天，故乡应得重相见。' },
  { title: '琴曲歌辞 胡笳十八拍 第八拍', author: '刘商', poem: '忆昔私家恣娇小，远取珍禽学驯扰。\n如今沦弃念故乡，悔不当初放林表。\n朔风萧萧寒日暮，星河寥落胡天晓。\n旦夕思归不得归，愁心想似笼中鸟。' },
  { title: '琴曲歌辞 胡笳十八拍 第九拍', author: '刘商', poem: '当日苏武单于问，道是宾鸿解传信。\n学他刺血写得书，书上千重万重恨。\n髯胡少年能走马，弯弓射飞无远近。\n遂令边雁转怕人，绝域何由达方寸。' },
  { title: '琴曲歌辞 胡笳十八拍 第十拍', author: '刘商', poem: '恨凌辱兮恶腥膻，憎胡地兮怨胡天。\n生得胡儿欲弃捐，及生母子情宛然。\n貌殊语异憎还爱，心中不觉常相牵。\n朝朝暮暮在眼前，腹生手养宁不怜。' },
  { title: '琴曲歌辞 胡笳十八拍 第十一拍', author: '刘商', poem: '日来月往相推迁，迢迢星岁欲周天。\n无冬无夏卧霜霰，水冻草枯为一年。\n汉家甲子有正朔，绝域三光空自悬。\n几回鸿雁来又去，肠断蟾蜍亏复圆。' },
  { title: '琴曲歌辞 胡笳十八拍 第十二拍', author: '刘商', poem: '破瓶落井空永沈，故乡望断无归心。\n宁知远使问姓名，汉语泠泠传好音。\n梦魂几度到乡国，觉后翻成哀怨深。\n如今果是梦中事，喜过悲来情不任。' },
  { title: '琴曲歌辞 胡笳十八拍 第十三拍', author: '刘商', poem: '童稚牵衣双在侧，将来不可留又忆。\n还乡惜别两难分，宁弃胡儿归旧国。\n山川万里复边戍，背面无由得消息。\n泪痕满面对残阳，终日依依向南北。' },
  { title: '琴曲歌辞 胡笳十八拍 第十四拍', author: '刘商', poem: '莫以胡儿可羞耻，恩情亦各言其子。\n手中十指有长短，截之痛惜皆相似。\n还乡岂不见亲族，念此飘零隔生死。\n南风万里吹我心，心亦随风渡辽水。' },
  { title: '琴曲歌辞 胡笳十八拍 第十五拍', author: '刘商', poem: '叹息襟怀无定分，当时怨来归又恨。\n不知愁怨意若何？似有锋铓扰方寸。\n悲欢竝行情未快，心意相尤自相问。\n不缘生得天属亲，岂向仇讐结恩信。' },
  { title: '琴曲歌辞 胡笳十八拍 第十六拍', author: '刘商', poem: '去时只觉天苍苍，归日始知胡地长。\n重阴白日落何处？秋鴈所向应南方。\n平沙四顾自迷惑，远近悠悠随鴈行。\n征途未尽马蹄尽，不见行人边草黄。' },
  { title: '琴曲歌辞 胡笳十八拍 第十七拍', author: '刘商', poem: '行尽胡天千万里，惟见黄沙白云起。\n马饥跑雪衔草根，人渴敲冰饮流水。\n燕山髣髴辨烽戍，鼙鼓如闻汉家垒。\n努力前程是帝乡，生前免向胡中死。' },
  { title: '琴曲歌辞 胡笳十八拍 第十八拍', author: '刘商', poem: '归来故乡见亲族，田园半芜春草绿。\n明烛重然煨烬灰，寒泉更洗沈泥玉。\n载持巾栉礼仪好，一弄丝桐生死足。\n出入关山十二年，哀情尽在胡笳曲。' },
  { title: '琴曲歌辞 飞龙引二首 一', author: '李白', poem: '黄帝铸鼎于荆山，炼丹砂。\n丹砂成黄金，骑龙飞上太清家。\n云愁海思令人嗟，宫中彩女颜如花。\n飘然挥手凌紫霞，从风纵体登銮车。\n登銮车，侍轩辕。\n遨游青天中，其乐不可言。' },
  { title: '琴曲歌辞 飞龙引二首 二', author: '李白', poem: '鼎湖流水清且闲，轩辕去时有弓劒。\n古人传道留其间，后宫婵娟多花颜。\n乘鸾飞烟亦不还，骑龙攀天造天关。\n造天关，闻天语，长云河车载玉女。\n载玉女，过紫皇，紫皇乃赐白兔所捣之药，后天而老凋三光。\n下视瑶池见王母，蛾眉萧飒如秋霜。' },
  { title: '琴曲歌辞 乌夜啼引', author: '张籍', poem: '秦乌啼哑哑，夜啼长安吏人家。\n吏人得罪囚在狱，倾家卖产将自赎。\n少妇起听夜啼乌，知是官家有赦书。\n下床心喜不重寐，未明上堂贺舅姑。\n少妇语啼乌，汝啼慎勿虚。\n借汝庭树作高巢，年年不令伤尔雏。' },
  { title: '琴曲歌辞 宛转歌 一', author: '郎大家宋氏', poem: '风已清，月朗琴复鸣。\n掩抑非千态，殷勤是一声。\n歌宛转，宛转和且长。\n愿为双鸿鹄，比翼共翱翔。' },
  { title: '琴曲歌辞 宛转歌 二', author: '郎大家宋氏', poem: '日已暮，长檐鸟应度。\n此时望君君不来，此时思君君不顾。\n歌宛转，宛转那能异栖宿。\n愿为形与影，出入恒相逐。' },
  { title: '琴曲歌辞 宛转歌二首 一', author: '刘方平', poem: '星参差，月二八，灯五枝。\n黄鹤瑶琴将别去，芙蓉羽帐惜空垂。\n歌宛转，宛转恨无穷。\n愿为波与浪，俱起碧流中。' },
  { title: '琴曲歌辞 宛转歌二首 二', author: '刘方平', poem: '晓将近，黄姑织女银河尽。\n九华锦衾无复情，千金宝镜谁能引。\n歌宛转，宛转伤别离。\n愿作杨与柳，同向玉窗垂。' },
  { title: '琴曲歌辞 宛转行', author: '张籍', poem: '华屋重翠幄，绮席雕象床。\n远漏微更疎，薄衾中夜凉。\n炉氲暗裴回，寒灯背斜光。\n妍姿结宵态，寝臂幽梦长。\n宛转复宛转，忆忆更未央。' },
  { title: '琴曲歌辞 王敬伯歌', author: '李端', poem: '妾本舟中客，闻君江上琴。\n君初感妾叹，妾亦感君心。\n遂出合欢被，同为交颈禽。\n传杯惟畏浅，接膝犹嫌远。\n侍婢奏箜篌，女郎歌宛转。\n宛转怨如何，中庭霜渐多。\n霜多叶可惜，昨日非今夕。\n徒结万里欢，终成一宵客。\n王敬伯，渌水青山从此隔。' },
  { title: '琴曲歌辞 三峡流泉歌', author: '李季兰', poem: '妾家本住巫山云，巫山流水常自闻。\n玉琴弹出转寥敻，直似当时梦中听。\n三峡流泉几千里，一时流入深闺里。\n巨石奔崖指下生，飞波走浪弦中起。\n初疑喷涌含雷风，又似呜咽流不通。\n回湍曲濑势将尽，时复滴沥平沙中。\n忆昔阮公为此曲，能使仲容听不足。\n一弹既罢复一弹，愿似流泉镇相续。' },
  { title: '琴曲歌辞 风入松歌', author: '僧皎然', poem: '西岭松声落日秋，千枝万叶风飕飗。\n美人援琴弄成曲，写得松间声断续。\n声断续，清我魂，流波坏陵安足论。\n美人夜坐月明里，含少商兮照清征。\n风何凄兮飘飉，搅寒松兮又夜起。\n夜未央，曲何长，金徽更促声泱泱。\n何人此时不得意，意苦弦悲闻客堂。' },
  { title: '琴曲歌辞 秋风引', author: '刘禹锡', poem: '何处秋风至？萧萧送鴈群。\n朝来入庭树，孤客最先闻。' },
  { title: '琴曲歌辞 明月引', author: '卢照邻', poem: '洞庭波起兮鸿鴈翔，风瑟瑟兮野苍苍。\n浮云卷霭，明月流光。\n荆南兮赵北，碣石兮潇湘。\n澄清规于万里，照离思于千行。\n横桂枝于西第，绕菱花于北堂。\n高楼思妇，飞盖君王。\n文姬绝域，侍子他乡。\n见胡鞍之似练，知汉劒之如霜。\n试登高而极目，莫不变而回肠。' },
  { title: '琴曲歌辞 明月歌', author: '阎朝隐', poem: '梅花雪白柳叶黄，云雾四起月苍苍，箭水泠冷刻漏长。\n挥玉指，拂罗裳，为君一奏楚明光。' },
  { title: '琴曲歌辞 绿竹引', author: '宋之问', poem: '青溪绿潭潭水侧，修竹婵娟同一色。\n徒生仙实凤不游，老死空山人讵识。\n妙年秉愿逃俗纷，归卧嵩丘弄白云。' },
  { title: '琴曲歌辞 山人劝酒', author: '李白', poem: '苍苍云松，落落绮皓。\n春风尔来为阿谁，胡蝶忽然满芳草。\n秀眉霜雪颜桃花，骨青髓绿长美好。\n称是秦时避世人，劝酒相欢不知老。\n各守兔鹿志，耻随龙虎争。\n歘起佐太子，汉王乃复惊。\n顾谓戚夫人，彼翁羽翼成。\n归来南山下，泛若云无情。\n举觞酹巢由，洗耳何独清？\n浩歌望嵩岳，意气还相倾。' },
  { title: '琴曲歌辞 幽涧泉', author: '李白', poem: '拂彼白石，弹吾素琴。\n幽涧愀兮流泉深，善手明徽高张清。\n心寂历似千古，松飕飗兮万寻。\n中见愁猨吊影而危处兮，呌秋木而长吟。\n客有哀时失志而听者，泪淋浪以沾襟。\n乃缉商缀羽，潺湲成音。\n吾但写声发情于妙指，殊不知此曲之古今。\n幽涧泉，鸣深林。' },
  { title: '琴曲歌辞 龙宫操', author: '顾况', poem: '龙宫月明光参差，精卫衔石东飞时。\n鲛人织绡采藕丝，翻江倒海倾吴蜀。\n汉女江妃杳相续，龙王宫中水不足。' },
  { title: '琴曲歌辞 飞鸢操', author: '刘禹锡', poem: '鸢飞杳杳青云里，鸢鸣萧萧风四起。\n旗尾飘扬势渐高，箭头砉划声相似。\n长空悠悠霁日悬，六翮不动凝飞烟。\n游鶤翔鴈出其下，庆云清景相回旋。\n忽闻饥乌一噪聚，瞥下云中争腐鼠。\n腾音砺吻相喧呼，仰天大吓疑鸳雏。\n畏人避犬投高处，俛啄无声犹屡顾。\n青鸟自爱玉山禾，仙禽徒贵华亭露。\n朴𣙙危巢向暮时，毰毸饱腹蹲枯枝。\n游童挟弹一麾肘，臆碎羽分人不悲。\n天生众禽各有类，威凤文章在仁义。\n鹰隼仪形蝼蚁心，虽能戾天何足贵。' },
  { title: '琴曲歌辞 升仙操', author: '李群玉', poem: '嬴女去秦宫，琼箫生碧空。\n凤台闭烟雾，鸾吹飘天风。\n复闻周太子，亦遇浮丘公。\n丛簧发仙弄，轻举紫霞中。\n浊世不久住，清都路何穷。\n一去霄汉上，世人那得逢。' },
  { title: '琴曲歌辞 司马相如琴歌', author: '张祜', poem: '凤兮凤兮非无凰，山重水阔不可量。\n梧桐结阴在朝阳，濯羽弱水鸣高翔。' },
  { title: '琴曲歌辞 霍将军', author: '崔颢', poem: '长安甲第高入云，谁家居住霍将军。\n日晚朝回拥宾从，路傍揖拜何纷纷。\n莫言炙手手可热，须臾火尽灰亦灭。\n莫言贫贱即可欺，人生富贵自有时。\n一朝天子赐颜色，世上悠悠应自知。' },
  { title: '琴曲歌辞 琴歌', author: '顾况', poem: '琴调秋些，胡风遶雪。\n峡泉生咽，佳人愁些。' },
  { title: '杂曲歌辞 秦女休行', author: '李白', poem: '西门秦氏女，秀色如琼花。\n手挥白杨刀，清昼杀讐家。\n罗袖洒赤血，英声凌紫霞。\n直上西山去，关吏相邀遮。\n壻为燕国王，身被诏狱加。\n犯刑若履虎，不畏落爪牙。\n素颈未及断，摧眉伏泥沙。\n金鸡忽放赦，大辟得宽赊。\n何慙聂政姊，万古共惊嗟。' },
  { title: '杂曲歌辞 出门行二首 一', author: '孟郊', poem: '长河悠悠去无极，百龄同此可叹息。\n秋风白露沾人衣，壮心凋落夺颜色。\n少年出门将诉谁，川无梁兮路无岐。\n一闻陌上苦寒奏，使我伫立惊且悲。\n君今得意厌粱肉，岂复念我贫贱时。' },
  { title: '杂曲歌辞 出门行二首 二', author: '孟郊', poem: '海风萧萧天雨霜，穷愁独坐夜何长？\n驱车旧忆太行险，始知游子悲故乡。\n美人相思隔天阙，长望云端不可越。\n手持琅玕欲有赠，爱而不见心断绝。\n南山峨峨白石烂，碧海之波浩漫漫。\n参辰出没不相待，我欲横天无羽翰。' },
  { title: '杂曲歌辞 出自蓟北门行', author: '李白', poem: '虏阵横北荒，胡星曜精芒。\n羽书速惊电，烽火昼连光。\n虎竹救边急，戎车森已行。\n明主不安席，按劒心飞扬。\n推毂出猛将，连旗登战场。\n兵威冲绝漠，杀气凌穹苍。\n列卒赤山下，开营紫塞傍。\n途冬沙风紧，旌旗飒凋伤。\n[画]角悲海月，征衣卷天霜。\n挥刃斩楼兰，弯弓射贤王。\n单于一平荡，种落自奔亡。\n收功报天子，行歌归咸阳。' },
  { title: '杂曲歌辞 蓟门行五首 一', author: '高适', poem: '边城十一月，雨雪乱霏霏。\n元戎号令严，人马亦轻肥。\n羌胡无尽日，征战几人归。' },
  { title: '杂曲歌辞 蓟门行五首 二', author: '高适', poem: '幽州多骑射，结发重横行。\n一朝事将军，出入有声名。\n纷纷猎秋草，相向角弓鸣。' },
  { title: '杂曲歌辞 蓟门行五首 三', author: '高适', poem: '蓟门逢古老，独立思氛氲。\n一身既零丁，头鬓白纷纷。\n勋庸今已矣，不识霍将军。' },
  { title: '杂曲歌辞 蓟门行五首 四', author: '高适', poem: '茫茫长城外，日没更烟尘。\n胡骑虽凭陵，汉兵不顾身。\n古树满空塞，黄云愁杀人。' },
  { title: '杂曲歌辞 蓟门行五首 五', author: '高适', poem: '汉家能用武，开拓穷异域。\n戍卒厌糠核，降胡饱衣食。\n开亭试一望，吾欲涕沾臆。' },
  { title: '杂曲歌辞 蓟门行', author: '李希仲', poem: '旄头有精芒，胡骑猎秋草。\n羽檄南渡河，边庭用兵早。\n汉家爱征战，宿将今已老。\n辛苦羽林儿，从戎榆关道。\n一身救边速，烽火连蓟门。\n前军鸟飞断，格鬬尘沙昏。\n寒日鼓声急，单于夜火奔。\n当须徇忠义，身死报国恩。' },
  { title: '杂曲歌辞 君子有所思行', author: '李白', poem: '紫阁连终南，青冥天倪色。\n凭崖望咸阳，宫阙罗北极。\n万井惊画出，九衢如弦直。\n渭水清银河，横天流不息。\n朝野盛文物，衣冠何翕赩。\n廐马散连山，军容威绝域。\n伊皐运元化，卫霍输筋力。\n歌钟乐未休，荣去老还逼。\n圆光过满缺，太阳移中昃。\n不散东海金，何争西辉匿。\n无作牛山悲，恻怆泪沾臆。' },
  { title: '杂曲歌辞 君子有所思行 一', author: '僧贯休', poem: '我爱正考甫，思贤作商颂。\n我爱扬子云，理乱皆如凤。\n振衣中夜起，露花香旖旎。\n扑碎骊龙明月珠，敲出凤凰五色髓。\n陋卷萧萧风淅淅，缅想斯人胜珪璧。\n寂寥千载不相逢，无限区区尽虚掷。\n君不见沈约道，佳人不在兹，春光为谁惜。' },
  { title: '杂曲歌辞 君子有所思行 二', author: '僧贯休', poem: '安得龙猛笔，点石为黄金。\n散问酷吏家，使无贪残心。\n甘棠密叶成翠幄，颍凤不来天地塞。\n所以倾城人，如今不可得。' },
  { title: '杂曲歌辞 伤歌行', author: '张籍', poem: '黄门诏下促收捕，京兆君系御史府。\n出门无复部曲随，亲戚相逢不容语。\n辞成谪尉南海州，受命不得须臾留。\n身着青衫骑恶马，东门之东无送者。\n邮夫防吏急喧驱，往往惊堕马蹏下。\n长安里中荒大宅，朱门已除十二戟。\n高堂舞榭锁管弦，美人遥望西南天。' },
  { title: '杂曲歌辞 伤歌行', author: '孟郊', poem: '众毒蔓贞松，一枝难久荣。\n岂知黄庭客，仙骨生不成。\n春色舍芳蕙，秋风遶枯茎。\n弹琴不成曲，始觉知音倾。\n馆月改旧照，吊宾写余情。\n还舟空江上，波浪送铭旌。' },
  { title: '杂曲歌辞 伤歌行', author: '庄南杰', poem: '兔走鸟飞不相见，人事依稀速如电。\n王母夭桃一度开，玉楼红粉千回变。\n车驰马走咸阳道，石家旧宅空荒草。\n秋雨无情不惜花，芙蓉一一惊香倒。\n劝君莫谩栽荆棘，秦皇虚费驱山力。\n英风一去更无言，白骨沈埋暮山碧。' },
  { title: '杂曲歌辞 悲歌', author: '李白', poem: '悲来乎，悲来乎！主人有酒且莫斟，听我一曲悲来吟。\n悲来不吟还不笑，天下无人知我心。\n君有数斗酒，我有三尺琴。\n琴鸣酒乐两相得，一杯不啻千钧金。\n悲来乎，悲来乎！天虽长，地虽久，金玉满堂应不守。\n富贵百年能几何？死生一度人皆有。\n孤猨坐啼坟上月，且须一尽杯中酒。\n悲来乎，悲来乎！凤鸟不至河无图，微子去之箕子奴。\n汉帝不忆李将军，楚王放却屈大夫。\n悲来乎，悲来乎！秦家李斯早追悔，虚名拨向身之外。\n范子何曾爱五湖，功成名遂身自退。\n劒是一夫用，书能知姓名。\n惠施不肯干万乘，卜式未必穷一经。\n还须黑头取方伯，莫谩白首为儒生。' },
  { title: '杂曲歌辞 悲哉行', author: '孟云卿', poem: '孤儿去慈亲，远客丧主人。\n莫吟苦辛曲，谁忍闻可闻。\n可闻不可说，去去无期别。\n行人念前程，不待参辰没。\n朝亦常苦饥，暮亦常苦饥。\n飘飘万余里，贫贱多是非。\n少年莫远游，远游多不归。' },
  { title: '杂曲歌辞 悲哉行', author: '白居易', poem: '悲哉为儒者，力学不能疲。\n读书眼欲暗，秉笔手生胝。\n十上方一第，成名常苦迟。\n纵有宦达者，两鬓已成丝。\n可怜少壮日，适在穷贱时。\n丈夫老且病，焉用富贵为。\n沈沈朱门宅，中有乳臭儿。\n状貌如妇人，光明膏粱肌。\n手不把书卷，身不擐戎衣。\n二十袭封爵，门承勋戚资。\n春来日日出，服御何轻肥。\n朝从博徒饮，暮有倡楼期。\n评封还酒债，堆金选蛾眉。\n声色狗马外，其余一无知。\n山苗与涧松，地势随高卑。\n古来无奈何，非君独伤悲。' },
  { title: '杂曲歌辞 悲哉行', author: '鲍溶', poem: '促促晨复昏，死生同一源。\n贵年不惧老，贱老伤久存。\n朗朗哭前歌，绛旌引幽魂。\n来为千金子，去卧百草根。\n黄土塞生路，悲风送回辕。\n金鞍旧良马，四顾不出门。\n生结千岁念，荣及百代孙。\n黄金买性命，白刃讐一言。\n宁知北山上，松柏侵田园。' },
  { title: '杂曲歌辞 妾薄命', author: '崔国辅', poem: '虽入秦帝宫，不上秦帝床。\n夜夜玉窗里，与他卷罗裳。' },
  { title: '杂曲歌辞 妾薄命', author: '武平一', poem: '有女妖且丽，裴回湘水湄。\n水湄兰杜芳，采之将寄谁。\n瓠犀发皓齿，双蛾嚬翠眉。\n红脸如开莲，素肤若凝脂。\n绰约多逸态，轻盈不自持。\n常矜绝代色，复恃倾城姿。\n子夫前入侍，飞燕复当时。\n正悦掌中舞，宁哀团扇诗。\n洛川昔云遇，高唐今尚违。\n幽合禽雀噪，闲阶草露滋。\n流景一何速，年华不可追。\n解佩安何赠，怨咽空自悲。' },
  { title: '杂曲歌辞 妾薄命', author: '李百药', poem: '团扇秋风起，长门夜月明。\n羞闻拊背人，恨说舞腰轻。\n太常应已醉，刘君恒带酲。\n横陈每虚设，吉梦竟何成。' },
  { title: '杂曲歌辞 妾薄命', author: '杜审言', poem: '草绿长门闭，苔青永巷幽。\n宠移新爱夺，泣下故情留。\n啼鸟惊残梦，飞花搅独愁。\n自怜春色罢，团扇复迎秋。' },
  { title: '杂曲歌辞 妾薄命', author: '刘元淑', poem: '自从离别守空闺，遥闻征战起云梯。\n夜夜愁君辽海外，年年弃妾渭桥西。\n阳春白日照空暖，紫燕衔花向庭满。\n彩鸾琴里怨声多，飞鹊镜前妆梳断。\n谁家夫壻不从征，应是渔阳别有情。\n莫道红颜燕地少，家家还似洛阳城。\n且逐新人殊未归，还令秋至夜霜飞。\n北斗星前横度鴈，南楼月下捣寒衣。\n夜深闻鴈肠欲绝，独坐缝衣灯又灭。\n暗啼罗帐空自怜，梦度阳关向谁说。\n每怜容貌宛如神，如何薄命不胜人。\n愿君朝夕燕山至，好作明年杨柳春。' },
  { title: '杂曲歌辞 妾薄命', author: '李白', poem: '汉帝重阿娇，贮之黄金屋。\n咳唾落九天，随风生珠玉。\n宠极爱还歇，妒深情却疎。\n长门一步地，不肯暂回车。\n雨落不上天，水覆难再收。\n君情与妾意，各自东西流。\n昔日芙蓉花，今成断根草。\n以色事他人，能得几时好。' },
  { title: '杂曲歌辞 妾薄命', author: '孟郊', poem: '不惜十指弦，为君千万弹。\n常恐新声至，坐使故声残。\n弃置今日悲，即是昨日欢。\n将新变故易，持故为新难。\n青山有蘼芜，泪叶长不干。\n空令后代人，采掇幽思攒。' },
  { title: '杂曲歌辞 妾薄命', author: '张籍', poem: '薄命妇，良家子，无事从军去万里。\n汉家天子平四夷，护羌都尉裹尸归。\n念君此行为死别，对君裁缝泉下衣。\n与君一日为夫妇，千年万岁亦相守。\n君爱龙城征战功，妾愿青楼欢乐同。\n人生各各有所欲，讵得将心入君腹。' },
  { title: '杂曲歌辞 妾薄命三首 一', author: '李端', poem: '忆妾初嫁君，花鬟如绿云。\n回灯入绮帐，对面脱罗裙。\n折步教人学，偷香与客熏。\n容颜南国重，名字北方闻。\n一从失恩意，转觉身憔悴。\n对镜不梳头，倚窗空落泪。\n新人莫恃新，秋至会无春。\n从来闭在长门者，必是宫中第一人。' },
  { title: '杂曲歌辞 妾薄命三首 二', author: '李端', poem: '玉垒城边争走马，铜蹏市里共乘舟。\n鸣环动佩思无尽，掩袖低巾泪不流。\n畴昔将歌邀客醉，如今欲舞对君羞。\n忍怀贱妾平生曲，独上襄阳旧酒楼。' },
  { title: '杂曲歌辞 妾薄命三首 三', author: '李端', poem: '自从君弃妾，憔悴不羞人。\n惟余坏粉泪，未免映衫匀。' },
  { title: '杂曲歌辞 妾薄命', author: '卢纶', poem: '妾年初二八，两度嫁狂夫。\n薄命今犹在，坚贞扫地无。' },
  { title: '杂曲歌辞 妾薄命', author: '卢弼', poem: '君恩已断尽成空，追想娇欢恨莫穷。\n长为蕣华光晓日，谁知团扇送秋风。\n黄金买赋心徒切，清路飞尘信莫通。\n闲凭玉栏思旧事，几回春暮泣残红。' },
  { title: '杂曲歌辞 妾薄命', author: '胡曾', poem: '阿娇初失汉皇恩，旧赐罗衣亦罢熏。\n欹枕夜悲金屋雨，卷帘朝泣玉楼云。\n宫前叶落鸳鸯瓦，架上尘生翡翠裙。\n龙骑不巡时渐久，长门长掩绿苔文。' },
  { title: '杂曲歌辞 妾薄命', author: '王贞白', poem: '薄命头欲白，频年嫁不成。\n秦娥未十五，昨夜事公卿。\n岂有机杼力，空传歌舞名。\n妾专修妇德，媒氏却相轻。' },
  { title: '杂曲歌辞 羽林行', author: '王建', poem: '长安恶少出名字，楼下劫商楼上醉。\n天明下直明光宫，散入五陵松柏中。\n百回杀人身合死，赦书尚有收城功。\n九衢一日消息定，乡吏籍中重改姓。\n出来依旧属羽林，立在殿前射飞禽。' },
  { title: '杂曲歌辞 羽林行', author: '孟郊', poem: '朔雪寒断指，朔风劲裂冰。\n胡中射雕者，此日犹不能。\n翩翩羽林儿，锦臂飞苍鹰。\n挥鞭决白马，走出黄河凌。' },
  { title: '杂曲歌辞 羽林行', author: '鲍溶', poem: '朝出羽林宫，入参云台议。\n独请万里行，不奏和亲事。\n君王重年少，深纳开边利。\n宝马雕玉鞍，一朝从万骑。\n煌煌都门外，祖帐光七贵。\n歌钟乐行军，云物惨别地。\n箫笳整部曲，幢盖动郊次。\n临风亲戚怀，满袖儿女泪。\n行行复何赠，长劒报恩字。' },
  { title: '杂曲歌辞 白马篇', author: '李白', poem: '龙马花雪毛，金鞍五陵豪。\n秋霜切玉劒，落日明珠袍。\n鬬鸡事万乘，轩盖一何高。\n弓摧宜山虎，手接泰山猱。\n酒后竞风彩，三杯弄宝刀。\n杀人如翦草，剧孟同游遨。\n发愤去函谷，从军向临洮。\n叱咤万战场，匈奴尽波涛。\n归来使酒气，未肯拜萧曹。\n羞入原宪室，荒径隐蓬蒿。' },
  { title: '杂曲歌辞 升天行', author: '僧齐己', poem: '身不沈，骨不重，驱青鸾，驾白凤。\n幢盖飘飘入冷空，天风瑟瑟星河动。\n瑶阙参差阿母家，楼台戏闭凝彤霞。\n五三仙子乘龙车，堂前碾烂蟠桃花。\n回头却顾蓬山顶，一点浓岚在深井。' },
  { title: '杂曲歌辞 神仙曲', author: '李贺', poem: '碧峰海面藏灵书，上帝拣作神仙居。\n晴时笑语闻空虚，鬬乘巨浪骑鲸鱼。\n春罗翦字邀王母，共宴红楼最深处。\n鹤羽冲风过海迟，不如却使青龙去。\n犹疑王母不相许，垂露娃鬟更传语。' },
  { title: '杂曲歌辞 北风行', author: '李白', poem: '烛龙栖寒门，光曜犹旦开。\n日月照之何不及此，惟有北风怒号天上来。\n燕山雪花大如席，片片吹落轩辕台。\n幽州思妇十二月，停歌罢笑双蛾摧。\n倚门望行人，念君长城苦寒良可哀。\n别时提劒救边去，遗此虎文金髀钗。\n中有一双白羽箭，蜘蛛结网生尘埃。\n箭空在，人今战死不复回。\n不忍见此物，焚之已成灰。\n黄河捧土尚可塞，北风雨雪恨难裁。' },
  { title: '杂曲歌辞 苦热行', author: '王维', poem: '赤日满天地，火云成山岳。\n草木尽焦卷，川泽皆竭涸。\n轻纨觉衣重，密树苦阴薄。\n莞簟不可近，𫄨绤再三濯。\n思出宇宙外，旷然在寥廓。\n长风万里来，江海荡烦浊。\n却顾身为患，始知心未觉。\n忽入甘露门，宛然清凉乐。' },
  { title: '杂曲歌辞 苦热行', author: '王毂', poem: '祝融南来鞭火龙，火旗焰焰烧天红。\n日轮当午凝不去，万国如在洪炉中。\n五岳翠干云彩灭，阳侯海底愁波竭。\n何当一夕金风发？为我扫却天下热。' },
  { title: '杂曲歌辞 苦热行', author: '僧皎然', poem: '六月金数伏，兹辰日在庚。\n炎曦曝肌肤，毒雾昏檐楹。\n安得奋翅翮，超遥出云征。\n不知天地心，如何匠生成。\n火德烧百卉，瑶草不及荣。\n省客当此时，忽贻怀中琼。\n捧玩烦袂涤，啸歌美风生。\n迟君佐元气，调使四序平。\n中令霜不祅，火余气常贞。\n江南诗骚客，休吟苦热行。' },
  { title: '杂曲歌辞 苦热行', author: '僧齐己', poem: '离宫划开赤帝怒，喝起六龙奔日驭。\n下土熬熬若煎煮，苍生惶惶无处处。\n火云峥嵘焚泬寥，东皐老农肠欲焦。\n何当一雨苏我苗？为君击坏歌帝尧。' },
  { title: '杂曲歌辞 太行苦热行', author: '刘长卿', poem: '迢迢太行路，自古称险恶。\n千骑俨欲前，群峰望如削。\n火云从中起，仰视飞鸟落。\n汗马卧高原，危旌倚长薄。\n清风何不至？赤日方煎烁。\n石露山木焦，鳞穷水泉涸。\n九重今旰食，万里传明略。\n诸将候轩车，元凶愁鼎镬。\n何劳短兵接，自有长缨缚。\n通越事岂难，渡泸功未博。\n朝辞羊肠坂，夕望贝丘郭。\n漳水斜遶营，常山遥入幕。\n永怀姑苏下，因寄建安作。\n白雪和诚难，沧波意空托。\n陈琳书记好，王粲从军乐。\n早晚归汉庭，随君上麟阁。' },
  { title: '杂曲歌辞 太行苦热行', author: '独孤及', poem: '驷马上太行，修途亘辽碣。\n王程无留驾，日昃未遑歇。\n请问此何时，恢台朱明月。\n长蛇稽天讨，上将方北伐。\n明主命使臣，皇华得时杰。\n已忘羊肠险，岂惮温风入。\n摇策汗滂沲，登崖思纡结。\n炎云如烟火，溪谷将恐竭。\n昼景赩可畏，凉飙何由发？\n山长飞鸟堕，目极行车绝。\n赵魏方俶扰，安危俟明哲。\n归路岂不怀，饮冰有苦节。\n会同传檄至，疑议立谈决。\n况有阮元瑜，翩翩秉书札。\n起予歌赤坂，永好逾白雪。\n维念剖竹人，无因执羁绁。' },
  { title: '杂曲歌辞 春日行', author: '李白', poem: '深宫高楼入紫清，金作蛟龙盘绣楹。\n佳人当窗弄白日，弦将手语弹鸣筝。\n春风吹落君王耳，此曲乃是升天行。\n因出天池泛蓬瀛，楼船蹙沓波浪惊。\n三千双蛾献歌笑，挝钟考鼓宫殿倾。\n万姓聚舞歌太平，我无为，人自宁。\n三十六帝欲相迎，仙人飘翩下云𫐌。\n帝不去，留镐京。\n安能为轩辕，独往入窅冥。\n小臣拜献南山寿，陛下万古垂鸿名。' },
  { title: '杂曲歌辞 春日行', author: '张籍', poem: '春日融融池上暖，竹牙出土兰心短。\n草堂晨起酒半醒，家僮报我园花满。\n头上皮冠未曾整，直入花间不寻径。\n树树殷勤尽遶行，举枝未徧春日暝。\n不用积金着青天，不用服药求神仙。\n但愿园里花长好，一生饮酒花前老。' },
  { title: '杂曲歌辞 朗月行', author: '李白', poem: '小时不识月，呼作白玉盘。\n又疑瑶台镜，飞在青云端。\n仙人垂两足，桂树作团团。\n白兔捣药成，问言与谁餐。\n蟾蜍蚀圜影，天明夜已残。\n羿昔落九乌，天人清且安。\n阴精此沦惑，去去不足观。\n忧来其如何？恻怆摧心肝。' },
  { title: '杂曲歌辞 前有一尊酒行二首 一', author: '李白', poem: '春风东来忽相过，金尊绿酒生微波。\n落花纷纷稍觉多，美人欲醉朱颜酡。\n青轩桃李能几何？流光欺人忽蹉跎。\n君起舞，日西夕，当年意气不肯倾，白发如丝叹何益。' },
  { title: '杂曲歌辞 前有一尊酒行二首 二', author: '李白', poem: '琴奏龙门之绿桐，玉壶美酒清若空。\n催弦拂柱与君饮，看朱成碧颜始红。\n胡姬貌如花，当𬬻笑春风。\n笑春风，舞罗衣，君今不醉欲安归。' },
  { title: '杂曲歌辞 缓歌行', author: '李颀', poem: '小来托身攀贵游，倾财破产无所忧。\n暮拟经过石渠署，朝将出入铜龙楼。\n结交杜陵轻薄子，谓言可生复可死。\n一沈一浮会有时，弃我翻然如脱屣。\n男儿立身须自彊，十五闭户颍水阳。\n业就功成见明主，击钟鼎食坐华堂。\n二八蛾眉梳堕马，美酒清歌曲房下。\n文昌宫中赐锦衣，长安陌上退朝归。\n五侯宾从莫敢视，三省官僚揖者稀。\n早知今日读书是，悔作从来任侠非。' },
  { title: '杂曲歌辞 结客少年场行', author: '虞世南', poem: '韩魏多奇节，倜傥遗名利。\n共矜然诺心，各负纵横志。\n结友一言重，相思千里至。\n绿沈明月弦，金络浮云辔。\n吹箫入吴市，击筑游燕肆。\n寻源博望侯，结客远相求。\n少年重一顾，长驱背陇头。\n燄燄霜戈动，耿耿劒虹浮。\n天山冬夏雪，交河南北流。\n云起龙沙暗，木落鴈行秋。\n轻生徇知己，非是为身谋。' },
  { title: '杂曲歌辞 结客少年场行', author: '虞羽客', poem: '幽幷侠少年，金络控连钱。\n窃符方救赵，击筑正怀燕。\n轻生辞凤阙，挥袂上祁连。\n陆离横宝劒，出没惊徂旃。\n蒙轮恒顾敌，超乘忽争先。\n摧枯逾百战，拓地远三千。\n骨都魂已散，楼兰首复传。\n龙城含晓雾，瀚海隔遥天。\n歌吹金微返，振旅玉门旋。\n烽火今已息，非复照甘泉。' },
  { title: '杂曲歌辞 结客少年场行', author: '卢照邻', poem: '长安重游侠，洛阳富才雄。\n玉劒浮云骑，金鞍明月弓。\n鬬鸡过渭北，走马向关东。\n孙宾遥见待，郭解暗相通。\n不受千金爵，谁论万里功。\n将军下天上，虏骑入云中。\n烽火夜似月，兵气晓成虹。\n横行徇知己，负羽远从戎。\n龙旌昏朔雾，鸟阵卷寒风。\n追奔瀚海咽，战罢阴山空。\n归来谢天子，何如马上翁。' },
  { title: '杂曲歌辞 结客少年场行', author: '李白', poem: '紫燕黄金瞳，啾啾摇绿鬉。\n平明相驰逐，结客洛门东。\n少年学劒术，凌轹白猨公。\n珠袍曳锦带，七首插吴鸿。\n由来万夫勇，挟此生雄风。\n托交从剧孟，买醉入新丰。\n笑尽一杯酒，杀人都市中。\n羞道易水寒，从令日贯虹。\n燕丹事不立，虚没秦帝宫。\n舞阳死灰人，安可与成功。' },
  { title: '杂曲歌辞 结客少年场行', author: '沈彬', poem: '重义轻生一劒知，白虹贯日报讐归。\n片心惆怅清平世，酒市无人问布衣。' },
  { title: '杂曲歌辞 少年子', author: '李百药', poem: '少年飞翠盖，上路动金镳。\n始酌文君酒，新吹弄玉箫。\n少年不欢乐，何以尽芳朝。\n千金笑里面，一搦抱中腰。\n挂冠岂惮宿，迎拜不胜娇。\n寄语少年子，无辞归路遥。' },
  { title: '杂曲歌辞 少年子', author: '李白', poem: '青云少年子，挟弹章台左。\n鞍马四边开，突如流星过。\n金丸落飞鸟，夜入琼楼卧。\n夷齐是何人？独守西山饿。' },
  { title: '杂曲歌辞 少年乐', author: '李贺', poem: '芳草落花如锦地，二十长游醉乡里。\n红缨不重白马骄，垂柳金丝香拂水。\n吴娥未笑花不开，绿鬓耸堕兰云起。\n陆郎倚醉牵罗袂，夺得宝钗金翡翠。' },
  { title: '杂曲歌辞 少年乐', author: '张祜', poem: '二十便封侯，名居第一流。\n绿鬟深小院，清管下高楼。\n醉把金船掷，闲敲玉镫游。\n带盘红鼹鼠，袍砑紫犀牛。\n锦袋归调箭，罗鞋起拨毬。\n眼前长贵盛，那信世间愁。' },
  { title: '杂曲歌辞 少年行三首 一', author: '李白', poem: '击筑饮美酒，劒歌易水湄。\n经过燕太子，结托幷州儿。\n少年负壮气，奋烈自有时。\n因声鲁句践，争情勿相欺。' },
  { title: '杂曲歌辞 少年行三首 二', author: '李白', poem: '五陵年少金市东，银鞍白马度春风。\n落花踏尽游何处？笑入胡姬酒肆中。' },
  { title: '杂曲歌辞 少年行三首 三', author: '李白', poem: '君不见淮南少年游侠客，白日毬猎夜拥掷。\n呼卢百万终不惜，报讐千里如咫尺。\n少年游侠好经过，浑身装束皆绮罗。\n兰蕙相随喧妓女，风光去处满笙歌。\n骄矜自言不可有，侠士堂中养来久。\n好鞍好马乞与人，十千五千旋沽酒。\n赤心用尽为知己，黄金不惜栽桃李。\n桃李栽来几度春，一回花落一回新。\n府县尽为门下客，王侯皆是平交人。\n男儿百年且乐命，何须徇书受贫病。\n男儿百年且荣身，何须徇节甘风尘。\n衣冠半是征战士，穷儒浪作林泉民。\n遮莫枝根长百丈，不如当代多还往。\n遮莫姻亲连帝城，不如当身自簪缨。\n看取富贵眼前者，何用悠悠身后名。' },
  { title: '杂曲歌辞 少年行四首 一', author: '王维', poem: '新丰美酒斗十千，咸阳游侠多少年。\n相逢意气为君饮，系马高楼垂柳边。' },
  { title: '杂曲歌辞 少年行四首 二', author: '王维', poem: '汉家君臣欢宴终，高议云台论战功。\n天子临轩赐侯印，将军佩出明光宫。' },
  { title: '杂曲歌辞 少年行四首 三', author: '王维', poem: '出身仕汉羽林郎，初随骠骑战渔阳。\n孰知不向边庭苦，纵死犹闻侠骨香。' },
  { title: '杂曲歌辞 少年行四首 四', author: '王维', poem: '一身能臂两雕弧，虏骑千群只似无。\n偏坐金鞍调白羽，纷纷射杀五单于。' },
  { title: '杂曲歌辞 少年行二首 一', author: '王昌龄', poem: '西陵侠年少，送客过长亭。\n青槐夹两路，白马如流星。\n闻道羽书急，单于寇井陉。\n气高轻赴难，谁顾燕山铭。' },
  { title: '杂曲歌辞 少年行二首 二', author: '王昌龄', poem: '走马还相寻，西楼下夕阴。\n结交期一劒，留意赠千金。\n高阁歌声远，重关柳色深。\n夜闲须尽醉，莫负百年心。' },
  { title: '杂曲歌辞 少年行', author: '张籍', poem: '少年从出猎长杨，禁中新拜羽林郎。\n独到辇前射双虎，君王手赐黄金铛。\n日日鬬鸡都市里，赢得宝刀重刻字。\n百里报讐夜出城，平明还在倡楼醉。\n遥闻虏到平陵下，不待诏书行上马。\n斩得名王献桂宫，封侯起第一日中。\n不为六郡良家子，百战始取边城功。' },
  { title: '杂曲歌辞 少年行三首 一', author: '李嶷', poem: '十八羽林郎，戎衣事汉王。\n臂鹰金殿侧，挟弹玉舆旁。\n驰道春风起，陪游出建章。' },
  { title: '杂曲歌辞 少年行三首 二', author: '李嶷', poem: '侍猎长杨下，承恩更射飞。\n尘生马影灭，箭落鴈行稀。\n薄暮归随仗，联翩入琐闱。' },
  { title: '杂曲歌辞 少年行三首 三', author: '李嶷', poem: '玉劒膝边横，金杯马上倾。\n朝游茂陵道，暮宿凤凰城。\n豪吏多猜忌，无劳问姓名。' },
  { title: '杂曲歌辞 少年行', author: '刘长卿', poem: '射飞夸侍猎，行乐爱联镳。\n荐枕青娥艳，鸣鞭白马骄。\n曲房珠翠合，深巷管弦调。\n日晚春风里，衣香满路飘。' },
  { title: '杂曲歌辞 少年行四首 一', author: '令狐楚', poem: '少小边州惯放狂，骣骑蕃马射黄羊。\n如今年事无筋力，犹倚营门数鴈行。' },
  { title: '杂曲歌辞 少年行四首 二', author: '令狐楚', poem: '家本清河住五城，须凭弓箭得功名。\n等闲飞鞚秋原上，独向寒云试射声。' },
  { title: '杂曲歌辞 少年行四首 三', author: '令狐楚', poem: '弓背霞明劒照霜，秋风走马出咸阳。\n未收天子河湟地，不拟回头望故乡。' },
  { title: '杂曲歌辞 少年行四首 四', author: '令狐楚', poem: '霜满中庭月过楼，金尊玉柱对清秋。\n当年称意须为乐，不到天明未肯休。' },
  { title: '杂曲歌辞 少年行二首 一', author: '杜牧', poem: '官为骏马监，职帅羽林儿。\n两绶藏不见，落花何处期？\n猎敲白玉镫，怒袖紫金锤。\n田窦长留醉，苏辛曲护岐。\n豪持出塞节，笑别远山眉。\n捷报云台贺，公卿拜寿巵。' },
  { title: '杂曲歌辞 少年行二首 二', author: '杜牧', poem: '连环羁玉声光碎，绿锦蔽泥虬卷高。\n春风细雨走马去，珠落璀璀白𦋺袍。' },
  { title: '杂曲歌辞 少年行三首 一', author: '杜甫', poem: '莫笑田家老瓦盆，自从盛酒长儿孙。\n倾银注瓦惊人眼，共醉终同卧竹根。' },
  { title: '杂曲歌辞 少年行三首 二', author: '杜甫', poem: '巢燕养雏浑去尽，红花结子已无多。\n黄衫年少来宜数，不见堂前东逝波。' },
  { title: '杂曲歌辞 少年行三首 三', author: '杜甫', poem: '马上谁家白面郎，临阶下马坐人床。\n不通姓字麄豪甚，指点银瓶索酒尝。' },
  { title: '杂曲歌辞 少年行', author: '张祜', poem: '少年足风情，垂鞭卖眼行。\n带金师子小，裘锦骐𬴊狞。\n选匠装金镫，推钱买[钿]筝。\n李陵虽效死，时论得虚名。' },
  { title: '杂曲歌辞 少年行', author: '韩翃', poem: '千点斓斒喷玉骢，青丝结尾绣缠騣。\n鸣鞭晚出章台路，叶叶春依杨柳风。' },
  { title: '杂曲歌辞 少年行', author: '施肩吾', poem: '醉骑白马走空衢，恶少皆称电不如。\n五凤街头闲勒辔，半垂衫袖揖金吾。' },
  { title: '杂曲歌辞 少年行三首 一', author: '僧贯休', poem: '锦衣鲜华手擎鹘，闲行气貌多轻忽。\n稼穑艰难总不知，五帝三王是何物。' },
  { title: '杂曲歌辞 少年行三首 二', author: '僧贯休', poem: '自拳五色毬，迸入他人宅。\n却捉苍头奴，玉鞭打一百。' },
  { title: '杂曲歌辞 少年行三首 三', author: '僧贯休', poem: '面白如削玉，猖狂曲江曲。\n马上黄金鞍，适来新赌得。' },
  { title: '杂曲歌辞 少年行', author: '韦庄', poem: '五陵豪客多，买酒黄金贱。\n醉下酒家楼，美人双翠幰。\n挥劒邯郸市，走马梁王苑。\n乐事殊未央，年华已云晚。' },
  { title: '杂曲歌辞 汉宫少年行', author: '李益', poem: '君不见上宫警夜营八屯，冬冬街鼓朝朱轩。\n玉阶霜仗拥未合，少年排入铜龙门。\n暗闻弦管九天上，宫漏沈沈清吹繁。\n才明走马绝驰道，呼鹰挟弹通缭垣。\n玉笼金琐养黄口，探雏取卵伴王孙。\n分曹六博快一掷，迎欢先意笑语喧。\n巧为柔媚学优孟，儒衣嬉戏冠沐猨。\n晚来香街经柳市，行过倡市宿桃根。\n相逢杯酒一言失，回朱点白闻至尊。\n金张许史伺颜色，王侯将相莫敢论。\n岂知人事无定势，朝欢暮戚如掌翻。\n椒房宠移子爱夺，一夕秋风生戾园。\n徒用黄金将买赋，宁知白玉暗成痕。\n持杯收水水已覆，徙薪避火火更燔。\n欲求四老张丞相，南山如天不可上。' },
  { title: '杂曲歌辞 长乐少年行', author: '崔国辅', poem: '遗却珊瑚鞭，白马骄不行。\n章台折杨柳，春草路旁情。' },
  { title: '杂曲歌辞 长安少年行十首 一', author: '李廓', poem: '金紫少年郎，绕街鞍马光。\n身从左中尉，官属右春坊。\n刬戴扬州帽，重熏异国香。\n垂鞭踏青草，来去杏园芳。' },
  { title: '杂曲歌辞 长安少年行十首 二', author: '李廓', poem: '追逐轻薄伴，闲游不着绯。\n长拢出猎马，数换打毬衣。\n晓日寻花去，春风带酒归。\n青楼无昼夜，歌舞歇时稀。' },
  { title: '杂曲歌辞 长安少年行十首 三', author: '李廓', poem: '日高春睡足，帖马赏年华。\n倒插银鱼袋，行随金犊车。\n还携新市酒，远醉曲江花。\n几度归侵黑，金吾送到家。' },
  { title: '杂曲歌辞 长安少年行十首 四', author: '李廓', poem: '好胜耽长行，天明烛满楼。\n留人看独脚，赌马换偏头。\n乐奏曾无歇，杯巡不暂休。\n时时遥冷笑，怪客有春愁。' },
  { title: '杂曲歌辞 长安少年行十首 五', author: '李廓', poem: '遨游携艳妓，装束似男儿。\n杯酒逢花住，笙歌簇马吹。\n鸎声催曲急，春色讶归迟。\n不以闻衔鼓，华筵待月移。' },
  { title: '杂曲歌辞 长安少年行十首 六', author: '李廓', poem: '赏春惟逐胜，大宅可曾归。\n不乐还逃席，多狂惯衩衣。\n歌人踏月起，语燕卷帘飞。\n好妇惟相妒，倡楼不醉稀。' },
  { title: '杂曲歌辞 长安少年行十首 七', author: '李廓', poem: '戟门连日闭，苦饮惜残春。\n开琐通新客，教姬屈醉人。\n请歌牵白马，自舞踏红茵。\n时辈皆相许，平生不负身。' },
  { title: '杂曲歌辞 长安少年行十首 八', author: '李廓', poem: '新年高殿上，始见有光辉。\n玉鴈排方带，金鹅立仗衣。\n酒深和椀赐，马疾打珂飞。\n朝下人争看，香街意气归。' },
  { title: '杂曲歌辞 长安少年行十首 九', author: '李廓', poem: '游市慵骑马，随姬入坐车。\n楼边听歌吹，帘外市钗花。\n乐眼从人闹，归心畏日斜。\n苍头来去报，饮伴到倡家。' },
  { title: '杂曲歌辞 长安少年行十首 十', author: '李廓', poem: '小妇教鹦鹉，头边唤醉醒。\n犬娇眠玉簟，鹰掣撼金铃。\n碧地攒花障，红泥待客亭。\n虽然长按曲，不饮不曾听。' },
  { title: '杂曲歌辞 长安少年行', author: '僧皎然', poem: '翠楼春酒虾蟆陵，长安少年皆共矜。\n纷纷半醉绿槐道，蹀躞花骢骄不胜。' },
  { title: '杂曲歌辞 渭城少年行', author: '崔颢', poem: '洛阳二月梨花飞，秦地行人春忆归。\n扬鞭走马城南陌，朝逢驿使秦川客。\n驿使前日发章台，传道长安春早来。\n棠梨宫中燕初至，葡萄馆里花正开。\n念此使人归更早，三月便达长安道。\n长安道上春可怜，摇风荡日曲河边。\n万户楼台临渭水，五陵花柳满秦川。\n秦川寒食盛繁华，游子春来喜见花。\n鬬鸡下杜尘初合，走马章台日半斜。\n章台帝城称贵里，青楼日晚歌钟起。\n贵里豪家白马骄，五陵年少不相饶。\n双双挟弹来金市，两两鸣鞭上渭桥。\n渭城桥头酒新熟，金鞍白马谁家宿。\n可怜锦瑟筝琵琶，玉台清酒就君家。\n小妇春来不解羞，娇歌一曲杨柳花。' },
  { title: '杂曲歌辞 邯郸少年行', author: '高适', poem: '邯郸城南游侠子，自矜生长邯郸里。\n千场纵博家仍富，几度报讐身不死。\n宅中歌笑日纷纷，门外车马如云屯。\n未知肝胆向谁是，令人却忆平原君。\n君不见今人交态薄，黄金用尽还疎索。\n以兹感激辞旧游，更于时事无所求。\n且与少年饮美酒，往来射猎西山头。' },
  { title: '杂曲歌辞 长安少年行', author: '郑锡', poem: '霞鞍金口骝，豹袖紫貂裘。\n家住丛台下，门前漳水流。\n唤人呈楚舞，借客试吴钩。\n见说秦兵至，甘心赴国讐。' },
  { title: '杂曲歌辞 轻薄篇', author: '李益', poem: '豪不必驰千骑，雄不在垂双鞬。\n天生俊气自相逐，出与雕鹗同飞翻。\n朝行九衢不得意，下鞭走马城西原。\n忽闻燕雁一声去，回鞭挟弹平陵园。\n归来青楼曲未半，美人玉色当金尊。\n淮阴少年不相下，酒酣半笑倚市门。\n安知我有不平色，白日欲顾红尘昏。\n死生容易如反掌，得意失意由一言。\n少年但饮莫相问，此中报讐亦报恩。' },
  { title: '杂曲歌辞 轻薄篇二首 一', author: '僧贯休', poem: '绣林锦野，春态相压。\n谁家少年，马蹏蹋蹋。\n鬬鸡走狗夜不归，一掷赌却如花妾。\n惟云不颠不狂，其名不彰。\n悲夫！。' },
  { title: '杂曲歌辞 轻薄篇二首 二', author: '僧贯休', poem: '木落萧萧，蛩鸣唧唧。\n不觉朱蔫脸红，霜劫鬓漆。\n世途多事，泣向秋日。\n方吟少壮不努力，老大徒伤悲。' },
  { title: '杂曲歌辞 轻薄行', author: '僧齐己', poem: '玉鞭金镫骅骝蹏，横眉吐气如虹霓。\n五陵春暖芳草齐，笙歌到处花成泥。\n日沈月上且鬬鸡，醉来莫问天高低。\n伯阳道德何涕唾，仲尼礼乐徒卑栖。' },
  { title: '杂曲歌辞 灞上轻薄行', author: '孟郊', poem: '长安无缓步，况值天景暮。\n相逢灞浐间，亲戚不相顾。\n自叹方拙身，忽随轻薄伦。\n常恐失所避，化为车辙尘。\n此中生白发，疾走亦未歇。' },
  { title: '杂曲歌辞 游侠篇', author: '崔颢', poem: '少年负胆气，好勇复知机。\n仗劒出门去，孤城逢合围。\n杀人辽水上，走马渔阳归。\n错落金琐甲，蒙茸貂鼠衣。\n还家行且猎，弓矢速如飞。\n地迥鹰犬疾，草深狐兔肥。\n腰间悬两绶，转眄生光辉。' },
  { title: '杂曲歌辞 游侠行', author: '孟郊', poem: '壮士性刚决，火中见石裂。\n杀人不回头，轻生如暂别。\n岂知眼有泪，肯白头上发。\n平生无恩酬，劒闲一百月。' },
  { title: '杂曲歌辞 侠客行', author: '李白', poem: '赵客缦胡缨，吴钩霜雪明。\n银鞍照白马，飒沓如流星。\n十步杀一人，千里不留行。\n事了拂衣去，深藏身与名。\n闲过信陵饮，脱劒膝前横。\n将炙啖朱亥，持觞劝侯嬴。\n三杯吐然诺，五岳倒为轻。\n眼花耳热后，意气素霓生。\n救赵挥金槌，邯郸先震惊。\n千秋二壮士，烜赫大梁城。\n纵死侠骨香，不慙世上英。\n谁能书阁下，白首太玄经。' },
  { title: '杂曲歌辞 侠客行', author: '元稹', poem: '侠客不怕死，怕在事不成。\n事成不肯藏姓名，我非窃贼谁夜行。\n白日堂堂杀袁盎，九衢草草人面青。\n此客此心师海鲸，海鲸露背横沧溟。\n海滨分作两处生，海鲸分海减海力。\n侠客有谋人不测，三尺铁蛇延二国。' },
  { title: '杂曲歌辞 侠客行', author: '温庭筠', poem: '欲出鸿都门，阴云蔽城阙。\n宝劒黯如水，微红湿余血。\n白马夜频嘶，三更霸陵雪。' },
  { title: '杂曲歌辞 行行游且猎篇', author: '李白', poem: '边城儿，生年不读一字书，但知游猎夸轻趫。\n胡马秋肥宜白草，骑来蹑影何矜骄。\n金鞭拂云挥鸣鞘，半酣呼鹰出远郊。\n弓弯满月不虚发，双鸧迸落连飞𩩉。\n海边观者皆辟易，猛气英风振沙碛。' },
  { title: '杂曲歌辞 游子吟', author: '孟郊', poem: '慈母手中线，游子身上衣。\n临行密密缝，意恐迟迟归。\n谁言寸草心，报得三春晖。' },
  { title: '杂曲歌辞 游子吟', author: '李益', poem: '女羞夫壻荡，客耻主人贱。\n遭遇同众流，低回愧相见。\n君非青铜镜，何事空照面？\n莫以衣上尘，不谓心如练。\n人生当荣盛，待士勿言倦。\n君看白日驰，何异弦上箭。' },
  { title: '杂曲歌辞 壮士吟', author: '贾岛', poem: '壮士不曾悲，悲即无回期。\n如何易水上，未歌先泪垂。' },
  { title: '杂曲歌辞 壮士行', author: '刘禹锡', poem: '阴风振寒郊，猛虎正咆哮。\n徐行出烧地，连吼入黄茆。\n壮士走马去，镫前弯玉弰。\n叱之使人立，一发如铍交。\n悍睛忽星坠，飞血溅林梢。\n彪炳为我席，膻腥充我庖。\n里中欣害除，贺酒纷号呶。\n明日长桥上，倾城看斩蛟。' },
  { title: '杂曲歌辞 壮士行', author: '鲍溶', poem: '西方太白高，壮士羞病死。\n心知报恩处，对酒歌易水。\n砂鸿嗥天末，横劒别妻子。\n苏武执节归，班超束书起。\n山河不足重，重在遇知己。' },
  { title: '杂曲歌辞 壮士行', author: '施肩吾', poem: '一斗之胆撑脏腑，如磥之筋碍臂骨。\n有时误入千人丛，自觉一身横突兀。\n当今四海无烟尘，胸襟被压不得伸。\n冻枭残虿我不取，污我匣黑青蛇鳞。' },
  { title: '杂曲歌辞 浩歌', author: '李贺', poem: '南风吹山作平地，帝遣天吴移海水。\n王母桃花千遍红，彭祖巫咸几回死。\n青毛骢马参差钱，娇春杨柳含细烟。\n筝人劝我金屈巵，神血未凝身问谁。\n不须浪饮丁督护，世上英雄本无主。\n买丝绣作平原君，有酒惟浇赵州土。\n漏催水咽玉蟾蜍，卫娘发薄不胜梳。\n看见秋眉换深绿，二十男儿那刺促。' },
  { title: '杂曲歌辞 浩歌行', author: '白居易', poem: '天长地久无终毕，昨夜今朝又明日。\n鬓发苍浪牙齿疎，不觉身年四十七。\n前去五十有几年，把镜照面心茫然。\n既无长绳系白日，又无大药驻朱颜。\n朱颜日渐不如故，青史功名在何处？\n欲留年少待富贵，富贵不来年少去。\n去复去兮如长河，东流赴海无回波。\n贤愚贵贱同归尽，北邙冢墓高嵯峨。\n古来如此非独我，未死有酒且酣歌。\n颜回短命伯夷饿，我今所得亦已多。' },
  { title: '杂曲歌辞 归去来引', author: '张炽', poem: '归去来，归期不可违。\n相见故明月，浮云共我归。' },
  { title: '杂曲歌辞 丽人曲', author: '崔国辅', poem: '红颜称绝代，欲并真无侣。\n独有镜中人，由来自相许。' },
  { title: '杂曲歌辞 丽人行', author: '杜甫', poem: '三月三日天气新，长安水边多丽人。\n态浓意远淑且真，肌理细腻骨肉匀。\n绣罗衣裳照暮春，蹙金孔雀银麒麟。\n头上何所有？翠微㔩叶垂鬓唇。\n背后何所见？珠压腰衱稳称身。\n就中云幕椒房亲，赐名大国虢与秦。\n紫𫘞之峰出翠釜，水晶之盘行素鳞。\n犀筯厌饫久未下，鸾刀缕切空纷纶。\n黄门飞鞚不动尘，御厨丝络送八珍。\n箫鼓哀吟感鬼神，宾从杂遝实要津。\n后来鞍马何逡巡，当轩下马入锦茵。\n杨花雪落覆白苹，青鸟飞去衔红巾。\n炙手可热势绝伦，慎莫近前丞相嗔。' },
  { title: '杂曲歌辞 东飞伯劳歌', author: '张柬之', poem: '青田白鹤丹山凤，婺女姮娥两相送。\n谁家绝世绮帐前，艳粉芳脂映宝钿。\n窈窕玉堂褰翠幕，参差绣户悬珠箔。\n绝世三五爱红妆，冶袖长裾兰麝香。\n春去花枝俄易改，可叹年光不相待。' },
  { title: '杂曲歌辞 东飞伯劳歌', author: '李峤', poem: '传书青鸟迎箫凤，巫岭荆台数通梦。\n谁家窈窕住园楼，五马千金照陌头。\n罗裙玉佩当轩出，点翠施红竞春日。\n佳人二八盛舞歌，羞将百万呈双娥。\n庭前芳树朝夕改，空驻妍华欲谁待。' },
  { title: '杂曲歌辞 东飞伯劳歌', author: '李暇', poem: '秦王龙劒燕后琴，珊瑚宝匣镂双心。\n谁家女儿抱香枕，开衾灭烛愿侍寝。\n琼窗半上金缕帱，轻罗隐面不障羞。\n青绮帏中坐相忆，红罗镜里见愁色。\n檐花照月莺对栖，空将可怜暗中啼。' },
  { title: '杂曲歌辞 鸣雁行', author: '李白', poem: '胡雁鸣，辞燕山，昨发委羽朝度关。\n一一衔芦枝，南飞散落天地间。\n连行接翼往复还，客居烟波寄湘吴。\n凌霜触雪毛体枯，畏逢矰缴惊相呼。' },
  { title: '杂曲歌辞 鸣雁行', author: '韩愈', poem: '嗷嗷鸣雁鸣且飞，穷秋南去春北归。\n去寒就暖识所处，天长地阔栖息稀。\n风霜酸苦稻粱微，羽毛摧落身不肥。\n徘徊反顾群侣违，哀鸣欲下洲渚非。\n江南水阔朝云多，草长沙輭无网罗。' },
  { title: '杂曲歌辞 鸣雁行', author: '鲍溶', poem: '七月朔方雁心苦，联影翻空落南土。\n八月江南阴复晴，浮云绕天难夜行。\n羽翼劳痛心虚惊，一声相呼百处鸣。\n楚童夜宿烟波侧，沙上布罗连草色。\n月暗风悲欲下天，不知何处容栖息？\n楚童胡为伤我神，尔不曾作远行人。\n江南羽族本不少，宁得网罗此客鸟。' },
  { title: '杂曲歌辞 鸣雁行', author: '陆龟蒙', poem: '朔风动地来，吹起沙上声。\n闺中有边思，玉筯此时横。\n莫怕儿女恨，主人烹不鸣。' },
  { title: '杂曲歌辞 空城雀', author: '李白', poem: '嗷嗷空城雀，身计何戚促。\n本与鹪鹩群，不随凤凰族。\n提携四黄口，饮乳未尝足。\n食君糠粃余，常恐乌鸢逐。\n耻涉太行险，羞营覆车粟。\n天命有定端，守分绝所欲。' },
  { title: '杂曲歌辞 空城雀', author: '王建', poem: '空城雀，何不飞来人家住？\n空城无人种禾黍。\n土间生子草间长，满地蓬蒿幸无主。\n近村虽有高树枝，雨中无食长苦饥。\n八月小儿夹弓箭，家家畏我田头飞。\n但能不出空城里，秋时百草皆有子。\n黄口黄口莫啾啾，长尔得成无横死。' },
  { title: '杂曲歌辞 空城雀', author: '聂夷中', poem: '一雀入官仓，所食能损几。\n所虑往损频，官仓乃害尔。\n鱼网不在天，鸟网不在水。' },
  { title: '杂曲歌辞 空城雀', author: '刘驾', poem: '饥啄空城土，莫近太仓粟。\n一粒未充肠，却入公子腹。\n且吊城上骨，几曾害尔族。\n不闻庄辛语，今日寒芜绿。' },
  { title: '杂曲歌辞 车遥遥', author: '孟郊', poem: '路喜到江尽，江上又通舟。\n舟车两无阻，何处不得游？\n丈夫四方志，女子安可留？\n郎自别日言，无令生远愁。\n旅鴈忽叫月，断猨寒啼秋。\n此夕梦君梦，君在百城楼。\n寄泪无因波，寄恨无因辀。\n愿为驭者手，与郎回马头。' },
  { title: '杂曲歌辞 车遥遥', author: '张籍', poem: '征人遥遥出古城，双轮齐动驷马鸣。\n山川无处无归路，念君长作万里行。\n野田人稀秋草绿，日暮放马车中宿。\n惊麏游兔在我傍，独唱乡歌对僮仆。\n君家大宅凤城隅，年年道上随行车。\n愿为玉銮系华轼，终日有声在君侧。\n门前旧辙久已平，无由复得君消息。' },
  { title: '杂曲歌辞 车遥遥', author: '张祜', poem: '东方昽昽车轧轧，地色不分新去辙。\n闺门半掩床半空，斑斑枕花残泪红。\n君心若车千万转，妾身如辙遗渐远。\n碧川迢迢山宛宛，马蹏在耳轮在眼。\n桑间女儿情不浅，莫道野蚕能作茧。' },
  { title: '杂曲歌辞 车遥遥', author: '胡曾', poem: '自从车马出门朝，便入空房守寂寥。\n玉枕夜残鱼信绝，金钿秋尽雁书遥。\n脸边楚雨临风落，头上春云向日销。\n芳草又衰还不至，碧天霜冷转无憀。' },
  { title: '杂曲歌辞 自君之出矣', author: '辛弘智', poem: '自君之出矣，梁尘静不飞。\n思君如满月，夜夜减容晖。' },
  { title: '杂曲歌辞 自君之出矣', author: '李康成', poem: '自君之出矣，弦吹绝无声。\n思君如百草，撩乱逐春生。' },
  { title: '杂曲歌辞 自君之出矣', author: '卢仝', poem: '自君之出矣，壁上蜘蛛织。\n近取见妾心，夜夜无休息。\n妾有双玉环，寄君表相忆。\n环是妾之心，玉是君之德。\n驰情增悴容，蓄思损精力。\n玉簟寒凄凄，延想心恻恻。\n风含霜月明，水泛碧天色。\n此水有尽时，此情无终极。' },
  { title: '杂曲歌辞 自君之出矣', author: '雍裕之', poem: '自君之出矣，宝镜为谁明。\n思君如陇水，长闻呜咽声。' },
  { title: '杂曲歌辞 自君之出矣', author: '张祜', poem: '自君之出矣，万物看成古。\n千寻葶苈枝，争奈长长苦。' },
  { title: '杂曲歌辞 长相思', author: '郎大家宋氏', poem: '长相思，久离别。\n关山阻，风烟绝。\n台上镜文销，袖中书字灭。\n不见君形影，何曾有懽悦。' },
  { title: '杂曲歌辞 长相思', author: '苏颋', poem: '君不见天津桥下东流水，东望龙门北朝市。\n杨柳青青宛地垂，桃红李白花参差。\n花参差，柳堪结，此时忆君心断绝。' },
  { title: '杂曲歌辞 长相思三首 一', author: '李白', poem: '长相思，在长安，络纬秋啼金井栏。\n微霜凄凄簟色寒，孤灯不明思欲绝。\n卷帷望月空长叹，美人如花隔云端。\n上有青冥之长天，下有绿水之波澜。\n天长路远魂飞苦，梦魂不到关山难。\n长相思，摧心肝。' },
  { title: '杂曲歌辞 长相思三首 二', author: '李白', poem: '日色已尽花含烟，月明欲素愁不眠。\n赵瑟初停凤凰柱，蜀琴欲奏鸳鸯弦。\n此曲有意无人传，愿随春风寄燕然，忆君迢迢隔青天。\n昔日横波目，今成流泪泉。\n不信妾肠断，归来看取明镜前。' },
  { title: '杂曲歌辞 长相思三首 三', author: '李白', poem: '美人在时花满堂，美人去后花余床。\n床中绣被卷不寝，至今三载犹闻香。\n香亦竟不灭，人亦竟不来。\n相思黄叶落，白露点青苔。' },
  { title: '杂曲歌辞 长相思', author: '张继', poem: '辽阳望河县，白首无由见。\n海上珊瑚枝，年年寄春燕。' },
  { title: '杂曲歌辞 长相思二首 一', author: '令狐楚', poem: '君行登陇上，妾梦在闺中。\n玉筯千行落，银床一半空。' },
  { title: '杂曲歌辞 长相思二首 二', author: '令狐楚', poem: '绮席春眠觉，纱窗晓望迷。\n朦胧残梦里，犹自在辽西。' },
  { title: '杂曲歌辞 长相思', author: '白居易', poem: '九月西风兴，月冷霜华凝。\n思君秋夜长，一夜魂九升。\n二月东风来，草坼花心开。\n思君春日迟，一日肠九回。\n妾住洛桥北，君住洛桥南。\n十五即相识，今年二十三。\n有如女萝草，生在松之侧。\n蔓短枝苦高，萦回上不得。\n人言人有愿，愿至天必成。\n愿作远方兽，步步比肩行。\n愿作深山木，枝枝连理生。' },
  { title: '杂曲歌辞 千里思', author: '李白', poem: '李陵没胡沙，苏武还汉家。\n迢迢五原关，朔雪乱边花。\n一去隔绝域，思归但长嗟。\n鸿雁向西北，飞书报天涯。' },
  { title: '杂曲歌辞 千里思', author: '李端', poem: '凉州风月美，遥望居延路。\n泛泛下天云，青青缘塞树。\n燕山苏武上，海岛田横住。\n更是草生时，行人出门去。' },
  { title: '杂曲歌辞 行路难', author: '卢照邻', poem: '君不见长安城北渭桥边，枯木横槎卧古田。\n昔日含红复含紫，常时留雾亦留烟。\n春景春风花似雪，香车玉轝恒阗咽。\n若个游人不竞攀，若个倡家不来折。\n倡家宝袜蛟龙帔，公子银鞍千万骑。\n黄莺一向花娇春，两两三三将子戏。\n千尺长条百尺枝，丹桂青榆相蔽亏。\n珊瑚叶上鸳鸯鸟，凤凰巢里雏鹓儿。\n巢倾枝折凤归去，条枯叶落狂风吹。\n一朝零落无人问，万古摧残君讵知。\n人生贵贱无终始，倏忽须臾难久恃。\n谁家能驻西山日，谁家能堰东流水。\n汉家陵树满秦川，行来行去尽哀怜。\n自昔公卿二千石，咸拟荣华一万年。\n不见朱唇将白貌，惟闻素棘与黄泉。\n金貂有时须换酒，玉麈但摇莫计钱。\n寄言坐客神仙署，一生一死交情处。\n苍龙阙下君不来，白鹤山前我应去。\n云间海上邈难期，赤心会合在何时？\n但愿尧年一百万，长作巢由也不辞。' },
  { title: '杂曲歌辞 行路难', author: '张纮', poem: '君不见温家玉镜台，提携抱握九重来。\n君不见相如绿绮琴，一抚一拍凤凰音。\n人生意气须及早，莫负当年行乐心。\n荆王奏曲楚妃叹，曲尽欢终夜将半。\n朱楼银阁正平生，碧草青苔坐芜漫。\n当春对酒不须疑，视目相看能几时。\n春风吹尽燕初至，此时自谓称君意。\n秋露萎草鸿始归，此时衰暮与君违。\n人生翻覆何常足，谁保容颜无是非。' },
  { title: '杂曲歌辞 行路难五首 一', author: '贺兰进明', poem: '君不见嵒下井，百尺不及泉。\n君不见山上蒿，数寸凌云烟。\n人生相命亦如此，何苦太息自忧煎。\n但愿亲友长含笑，相逢莫吝杖头钱。\n寒夜邀欢须秉烛，岂得空思花柳年。' },
  { title: '杂曲歌辞 行路难五首 二', author: '贺兰进明', poem: '君不见门前柳，荣曜暂时萧索久。\n君不见陌上花，狂风吹去落谁家。\n谁家思妇见之叹，蓬首不梳心历乱。\n盛年夫壻长别离，岁暮相逢色凋换。' },
  { title: '杂曲歌辞 行路难五首 三', author: '贺兰进明', poem: '君不见荒树枝，春花落尽蜂不窥。\n君不见梁上泥，秋风始高燕不栖。\n荡子从军事征战，蛾眉婵娟空守闺。\n独宿自然堪下泪，况复时闻乌夜啼。' },
  { title: '杂曲歌辞 行路难五首 四', author: '贺兰进明', poem: '君不见云间月，暂盈还复缺。\n君不见林下风，声远意难穷。\n亲故平生欲聚散，欢娱未尽尊酒空。\n自叹青青陵上柏，岁寒能与几人同。' },
  { title: '杂曲歌辞 行路难五首 五', author: '贺兰进明', poem: '君不见东流水，一去无穷已。\n君不见西郊云，日夕空氛氲。\n群雁裴回不能去，一雁悲鸣复失群。\n人生结交在终始，莫为升沈中路分。' },
  { title: '杂曲歌辞 行路难', author: '崔颢', poem: '君不见建章宫中金明枝，万万长条拂地垂。\n二月三月花如霰，九重幽深君不见。\n艳彩朝含四宝宫，香风吹入朝云殿。\n汉家宫女春未阑，爱此芳香朝暮看。\n看去看来心不忘，攀折将安镜台上。\n双双素手剪不成，两两红妆笑相向。\n建章昨夜起春风，一花飞落长信宫。\n长信丽人见花泣，忆此珍树何嗟及。\n我昔初在昭阳时，朝折暮折登玉墀。\n祗言岁岁长相对，不寤今朝遥相思。' },
  { title: '杂曲歌辞 行路难三首 一', author: '李白', poem: '金尊清酒斗十千，玉盘珍羞直万钱。\n停杯投筯不能食，拔劒四顾心茫然。\n欲渡黄河冰塞川，将登太行雪暗天。\n闲来垂钓坐溪上，忽复乘舟梦日边。\n行路难，行路难，多岐路，今安在？\n长风破浪会有时，直挂云帆济沧海。' },
  { title: '杂曲歌辞 行路难三首 二', author: '李白', poem: '大道如青天，我独不得出。\n羞逐长安社中儿，赤鸡白狗赌梨栗。\n弹劒作歌奏苦声，曳裾王门不称情。\n淮阴市井笑韩信，汉朝公卿忌贾生。\n君不见昔时燕家重郭隗，拥篲折腰无嫌猜。\n剧辛乐毅感恩分，输肝剖胆效英才。\n昭王白骨萦蔓草，谁人更扫黄金台。\n行路难，归去来。' },
  { title: '杂曲歌辞 行路难三首 三', author: '李白', poem: '有耳莫洗颍川水，有口莫食首阳蕨。\n含光混世贵无名，何用孤高比云月。\n吾观自古贤达人，功成不退皆殒身。\n子胥既弃吴江上，屈原终投湘水滨。\n陆机才多岂自保，李斯税驾苦不早。\n华亭鹤唳讵可闻，上蔡苍鹰何足道？\n君不见吴中张翰称达士，秋风忽忆江东行。\n且乐生前一杯酒，何须身后千载名。' },
  { title: '杂曲歌辞 行路难三首 一', author: '顾况', poem: '君不见古来烧水银，变作北邙山上尘。\n藕丝挂身在虚空，欲落不落愁杀人。\n睢水英雄多血刃，建章宫阙成灰烬。\n淮王身死桂枝折，徐氏一去音书绝。\n行路难，行路难，生死皆由天。\n秦皇汉武遭下脱，汝独何人学神仙。' },
  { title: '杂曲歌辞 行路难三首 二', author: '顾况', poem: '君不见担雪塞井徒用力，炊砂作饭岂堪吃。\n一生肝胆向人尽，相识不如不相识。\n冬青树上挂凌宵，岁[晏]花凋树不凋。\n凡物各自有根本，种禾终不生豆苗。\n行路难，行路难，何处是平道？\n中心无事当富贵，今日觉君颜色好。' },
  { title: '杂曲歌辞 行路难三首 三', author: '顾况', poem: '君不见少年头上如云发，少壮如云老如雪。\n岂知灌顶有醍醐，能使清凉头不热。\n吕梁之水挂飞流，鼋鼍蛟蜃不敢游。\n少年恃险若平地，独倚长劒凌清秋。\n行路难，行路难，昔少年，今已老。\n前朝竹帛事皆空，日暮牛羊古城草。' },
  { title: '杂曲歌辞 行路难', author: '李颀', poem: '汉家名臣杨德祖，四代五公享茅土。\n父兄子弟绾银黄，跃马鸣珂朝建章。\n火浣单衣绣方领，茱萸锦带玉盘囊。\n宾客填街复满坐，片言出口生辉光。\n世人逐势争奔走，沥胆隳肝惟恐后。\n当时一顾生青云，自谓生死长随君。\n一朝谢病还乡里，穷巷苍茫绝知己。\n秋风落叶闭重门，昨日论交竟谁是。\n薄俗嗟嗟难重陈，深山麋鹿下为邻。\n鲁连所以蹈沧海，古往今来称达人。' },
  { title: '杂曲歌辞 行路难二首 一', author: '高适', poem: '君不见富家翁，昔时贫贱谁比数。\n一朝金多结豪贵，万事胜人健如虎。\n子孙成长满眼前，妻能管弦妾能舞。\n自矜一朝忽如此，却笑傍人独悲苦。\n东邻少年安所如，席门穷巷出无车。' },
  { title: '杂曲歌辞 行路难二首 二', author: '高适', poem: '长安少年不少钱，能骑骏马鸣金鞭。\n五侯相逢大道边，美人弦管争留连。\n黄金如斗不敢惜，片言如山莫弃捐。\n安知顦顇读书者，暮宿虚台私自怜。' },
  { title: '杂曲歌辞 行路难', author: '张籍', poem: '湘东行人长叹息，十年离家归未得。\n弊裘羸马苦难行，童仆饥寒少筋力。\n君不见床头黄金尽，壮士无颜色。\n龙蟠泥中未有云，不能生彼升天翼。' },
  { title: '杂曲歌辞 行路难', author: '聂夷中', poem: '莫言行路难，夷狄如中国。\n谓言骨肉亲，中门如异域。\n出处全在人，路亦无通塞。\n门前两条辙，何处去不得。' },
  { title: '杂曲歌辞 行路难', author: '韦应物', poem: '荆山之白玉兮。\n良工雕琢双环连，月蚀中央镜心穿。\n故人赠妾初相结，恩在环中寻不绝。\n人情厚薄苦须臾，昔似连环今似玦。\n连环可碎不可离，如何物在人自移。\n上客勿遽欢，听妾歌路难。\n傍人见环环可怜，不知中有长恨端。' },
  { title: '杂曲歌辞 行路难三首 一', author: '柳宗元', poem: '君不见夸父逐日窥虞渊，跳踉北海超昆仑。\n披霄决汉出沆漭，瞥裂左右遗星辰。\n须臾力尽道渴死，狐鼠蜂蚁争噬吞。\n北方竫人长九寸，开口抵掌更笑喧。\n啾啾饮食滴与粒，生死亦足终天年。\n睢盱大志少成遂，坐使儿女相悲怜。' },
  { title: '杂曲歌辞 行路难三首 二', author: '柳宗元', poem: '虞衡斤斧罗千山，工命采斫杙与椽。\n深林土翦十取一，百牛连鞅摧双辕。\n万围千寻妨道路，东西蹶倒山火焚。\n遗余毫末不见保，𨅬砾磵壑何当存。\n群材未成质已夭，突兀𡷸豁空岩峦。\n柏梁天灾武库火，匠石狼顾相愁冤。\n君不见南山栋梁益稀少，爱材养育谁复论。' },
  { title: '杂曲歌辞 行路难三首 三', author: '柳宗元', poem: '飞雪断道冰成梁，侯家炽炭雕玉房。\n蟠龙吐耀虎喙张，熊蹲豹掷争低昂。\n攒峦丛崿射朱光，丹霞翠雾飘奇香。\n美人四向回明珰，雪山冰谷晞太阳。\n星躔奔走不得止，奄忽双燕栖虹梁。\n风台露榭生光饰，死灰弃置参与商。\n盛时一去贵反贱，桃笙葵扇安可常。' },
  { title: '杂曲歌辞 行路难', author: '鲍溶', poem: '玉堂向夕如无人，丝竹俨然宫商死。\n细人何言入君耳？尘生金尊酒如水。\n君今不念岁蹉跎，雁天明明凉露多。\n华灯青凝久照夜，彩童窈窕虚垂罗。\n入宫见妬君不察，莫入此地出风波。' },
  { title: '杂曲歌辞 行路难五首 一', author: '僧贯休', poem: '不会当时作天地，刚有多般愚与智。\n到头还用真宰心，何如上下皆清气。\n大道冥冥不知处，那堪顿得羲和辔。\n义不义兮仁不仁，拟学长生更容易。\n负心为炉复为火，缘木求鱼应且止。\n君不见烧金炼石古帝王，鬼火荧荧白杨里。' },
  { title: '杂曲歌辞 行路难五首 二', author: '僧贯休', poem: '君不见道傍废井生古木，本是骄奢贵人屋。\n几度美人照影来，素绠银缾濯纤玉。\n云飞雨散今如此，绣闼雕甍作荒谷。\n沸渭笙歌君莫夸，不应长是西家哭。\n休说遗编行者几，至竟终须合天理。\n败他成此亦何功，苏张终作多言鬼。\n行路难，行路难，不在羊肠里。' },
  { title: '杂曲歌辞 行路难五首 三', author: '僧贯休', poem: '九有茫茫共尧日，浪死虚生亦非一。\n清净玄音竟不闻，花眼酒肠暗如漆。\n或偶因片言只字登第光二亲，又不能献可替不航要津。\n口谈羲轩与周孔，履行不及屠沽人。\n行路难，行路难，日暮途远空悲叹。' },
  { title: '杂曲歌辞 行路难五首 四', author: '僧贯休', poem: '君不见道傍树有寄生枝，青青郁郁同荣衰。\n无情之物尚如此，为人不及还堪悲。\n父归坟兮未朝夕，已分黄金争田宅。\n高堂老母头似霜，心作数支泪常滴。\n我闻忽如负芒刺，不独为君空叹息。\n古人尺布犹可缝，浔阳义犬令人忆。\n寄言世上为人子，孝义团圆莫如此。' },
  { title: '杂曲歌辞 行路难五首 五', author: '僧贯休', poem: '君不见山高海深人不测，古往今来转青碧。\n浅近轻浮莫与交，池卑只解生荆棘。\n谁道黄金如粪土，张耳陈余断消息。\n行路难，行路难，君自看。' },
  { title: '杂曲歌辞 行路难二首 一', author: '僧齐己', poem: '行路难，君好看。\n惊波不在黤黮间，小人心里藏奔湍。\n七盘九折寒崷崪，翻车倒盖犹堪出。\n未似是非唇舌危，暗中潜毁平人骨。\n君不见楚灵均，千古沈冤湘水滨。\n又不见李太白，一朝却作江南客。' },
  { title: '杂曲歌辞 行路难二首 二', author: '僧齐己', poem: '下浸与高盘，不为行路难。\n是非真险恶，翻覆作峰峦。\n漆媿同时黑，朱慙巧处丹。\n令人畏相识，欲画白云看。' },
  { title: '杂曲歌辞 行路难', author: '翁绶', poem: '行路艰难不复歌，故人荣达我蹉跎。\n双轮晚上铜梁雪，一叶春浮瘴海波。\n自古要津皆若此，方今失路欲如何？\n君看西汉翟丞相，凤沼朝辞暮雀罗。' },
  { title: '杂曲歌辞 行路难', author: '薛能', poem: '何处力堪殚？人心险万端。\n藏山难测度，暗水自波澜。\n对面如千里，回肠似七盘。\n已经吴坂困，欲向鴈门难。\n南北诚须泣，高深不可干。\n无因善行止，车辙得平安。' },
  { title: '杂曲歌辞 从军中行路难二首 二', author: '骆宾王', poem: '君不见玉关尘色暗边亭，铜鞮杂虏寇长城。\n天子按劒征余勇，将军受脤事横行。\n七德龙韬开玉帐，千里鼍鼓叠金钲。\n阴山苦雾埋高垒，交河孤月照连营。\n连营去去无穷极，拥斾遥遥过绝国。\n阵云朝结晦天山，寒沙夕涨迷疎勒。\n龙鳞水上开鱼贯，马首山前振雕翼。\n长驱万里詟祁连，分麾三命武功宣。\n百发乌号遥碎柳，七尺龙文迥照莲。\n春来秋去移灰琯，兰闺柳市芳尘断。\n鴈门迢遰尺书稀，鸳被相思双带缓。\n行路难，誓令氛祲静皐兰。\n但使封侯龙额贵，讵随中妇凤楼寒。' },
  { title: '杂曲歌辞 变行路难', author: '王昌龄', poem: '向晚横吹悲，风动马嘶合。\n前驱引旗节，千重阵云帀。\n单于下阴山，砂砾空飒飒。\n封侯取一战，岂复念闺合。' },
  { title: '杂曲歌辞 古别离', author: '沈佺期', poem: '白水东悠悠，中有西行舟。\n舟行有返棹，水去无还流。\n奈何生别者，戚戚怀远游。\n远游谁当惜，所悲会难收。\n自君间芳躧，青阳四五遒。\n皓月掩兰室，光风虚蕙楼。\n相思无明晦，长叹累冬秋。\n离居分迟暮，驾高何淹留。' },
  { title: '杂曲歌辞 古别离', author: '孟云卿', poem: '朝日上高台，离人怨秋草。\n但见万里天，不见万里道。\n君行本遥远，苦乐良难保。\n宿昔梦同衾，忧心梦颠倒。\n含酸欲谁诉，转转伤怀抱。\n结发年已迟，征行去何早。\n寒暄有时谢，顦顇难再好。\n人皆算年寿，死者何曾老。\n少壮无见期，水深风浩浩。' },
  { title: '杂曲歌辞 古别离', author: '李益', poem: '双劒欲别风凄然，雌沈水底雄上天。\n江回汉转两不见，云交雨合知何年。\n古来万事皆由命，何用临岐苦涕涟。' },
  { title: '杂曲歌辞 古别离二首 一', author: '于𣸣', poem: '入室少情意，出门多路岐。\n黄鹤有归日，荡子无还时。\n人谁无分命，妾身何太奇。\n君为东南风，妾作西北枝。\n青楼邻里妇，终年画长眉。\n自倚对良匹，笑妾空罗帏。' },
  { title: '杂曲歌辞 古别离二首 二', author: '于𣸣', poem: '郎本东家儿，妾本西家女。\n对门中道间，终谓无离阻。\n岂知中道间，遣作空闺主。\n自是爱封侯，非关备胡虏。' },
  { title: '杂曲歌辞 古别离二首 一', author: '李端', poem: '水国叶黄时，洞庭霜落夜。\n行舟闻商估，宿在枫林下。\n此地送君还，茫茫似梦间。\n后期知几日，前路转多山。\n巫峡通湘浦，迢迢隔云雨。\n天晴见海樯，月落闻津鼓。\n人老自多愁，水深难急流。\n清宵歌一曲，白首对汀洲。' },
  { title: '杂曲歌辞 古别离二首 二', author: '李端', poem: '与君桂阳别，令君岳阳待。\n后事忽差池，前期日空在。\n木落鴈嗷嗷，洞庭波浪高。\n远山云似盖，极浦树如毫。\n朝发能几里，暮来风又起。\n如何两处愁，皆在孤舟里。\n昨夜天月明，长川寒且清。\n菊花开欲尽，荠菜拍来生。\n下江帆势速，五两遥相逐。\n欲问去时人，知投何处宿。\n空令猨啸时，泣对湘潭竹。' },
  { title: '杂曲歌辞 古别离', author: '王缙', poem: '下阶欲离别，相对映兰丛。\n含辞未及吐，泪落兰丛中。\n高堂静秋日，罗衣飘暮风。\n谁能待明月，回首见床空。' },
  { title: '杂曲歌辞 古别离', author: '僧皎然', poem: '太湖三山口，吴王在时道。\n寂寞千载心，无人见春草。\n谁堪缄怨者，持此伤怀抱。\n孤舟畏狂风，一点宿烟岛。\n望所思兮若何，月荡漾兮空波。\n云离离兮北断，鴈眇眇兮南多。\n身去兮天畔，心折兮湖岸。\n春山胡为兮塞路，使我归梦兮撩乱。' },
  { title: '杂曲歌辞 古别离二首 一', author: '施肩吾', poem: '古人谩歌西飞燕，十年不见狂夫面。\n三更风作切梦刀，万转愁成系肠线。\n所嗟不及牛女星，一年一度得相见。' },
  { title: '杂曲歌辞 古别离二首 二', author: '施肩吾', poem: '老母别爱子，少妻送征郎。\n血流既四面，乃亦断二肠。\n不愁寒无衣，不怕饥无粮。\n惟恐征战不还乡，母化为鬼妻为孀。' },
  { title: '杂曲歌辞 古别离', author: '吴融', poem: '紫燕黄鹄虽别离，一举千里何难追。\n犹闻啼风与叫月，流连断续令人悲。\n赋情更有深缱绻，碧甃千寻尚为浅。\n蟾蜍正向清夜流，蛱蝶须教堕丝罥。\n莫道断丝不可续，丹穴凤皇胶不远。\n草草通流水不回，海上两潮长不返。' },
  { title: '杂曲歌辞 古离别', author: '王适', poem: '昔岁惊杨柳，高楼悲独守。\n今年芳树枝，孤栖怨别离。\n珠帘昼不卷，罗幔晓长垂。\n苦调琴先觉，愁容镜独知。\n频来鴈度无消息，罢去鸳文何用织。\n夜还罗帐空有情，春着帬腰自无力。\n青轩桃李落纷纷，紫庭兰蕙日氛氲。\n已能顦顇今如此，更复含情一待君。' },
  { title: '杂曲歌辞 古离别', author: '常理', poem: '君御狐白裘，妾居缃绮帱。\n粟钿金夹膝，花错玉搔头。\n离别生庭草，征行断戍楼。\n蟏蛸网清曙，菡萏落红秋。\n小胆空房怯，长眉满镜愁。\n为传儿女意，不用远封侯。' },
  { title: '杂曲歌辞 古离别', author: '姚系', poem: '凉风已袅袅，露重木兰枝。\n独上高楼望，行人远不知。\n轻寒入洞户，明月满秋池。\n燕去鸿方至，年年是别离。' },
  { title: '杂曲歌辞 古离别', author: '张彪', poem: '离别无远近，事欢情亦悲。\n不闻车轮声，后会将何时。\n去日忘寄书，来日乖前期。\n纵知明当还，一夕千万思。' },
  { title: '杂曲歌辞 古离别', author: '赵微明', poem: '违别未几日，一日如三秋。\n犹疑望可见，日日上高楼。\n惟见分手处，白苹满芳洲。\n寸心宁死别，不忍生离愁。' },
  { title: '杂曲歌辞 古离别二首 一', author: '孟郊', poem: '松山云缭绕，萍路水分离。\n云去有归日，水分无合时。\n春芳役双眼，春色柔四支。\n杨柳织别愁，千条万条丝。' },
  { title: '杂曲歌辞 古离别二首 二', author: '孟郊', poem: '山川古今路，纵横无断绝。\n来往天地间，人皆有离别。\n行衣未束带，中肠已先结。\n不用看镜中，自知生白发。\n欲陈去留意，声向言前咽。\n愁结填心胸，茫茫若为说。\n荒郊烟莽苍，旷野风凄切。\n处处得相随，人那不如月。' },
  { title: '杂曲歌辞 古离别', author: '顾况', poem: '西江上，风动麻姑嫁时浪。\n西山为水水为尘，不是人间离别人。' },
  { title: '杂曲歌辞 古离别', author: '僧贯休', poem: '离恨如旨酒，古今饮皆醉。\n只恐长江水，尽是儿女泪。\n伊余非此辈，送人空把臂。\n他日再相逢，清风动天地。' },
  { title: '杂曲歌辞 古离别', author: '韦庄', poem: '晴烟漠漠柳毵毵，不那离情酒半酣。\n更把马鞭云外指，断肠春色在江南。' },
  { title: '杂曲歌辞 生别离', author: '孟云卿', poem: '结发生别离，相思复相保。\n何知日已久，五变庭中草。\n眇眇天海途，悠悠吴江岛。\n但恐不出门，出门无远道。\n远道行既难，家贫衣服单。\n严风吹积雪，晨起鼻何酸。\n人生各有恋，岂不怀所安。\n分明天上日，生死誓同欢。' },
  { title: '杂曲歌辞 生别离', author: '白居易', poem: '食蘗不易食梅难，蘗能苦兮梅能酸。\n未如生别之为难，苦在心兮酸在肝。\n晨鸡载鸣残月没，征马重嘶行人出。\n回看骨肉哭一声，梅酸蘗苦甘如蜜。\n黄河水白黄云秋，行人河边相对愁。\n天寒野旷何处宿？棠梨叶战风飕飕。\n生离别，生离别，忧从中来无断绝。\n忧积心劳血气衰，未年三十生白发。' },
  { title: '杂曲歌辞 远别离', author: '李白', poem: '远别离，古有皇英之二女，乃在洞庭之南，潇湘之浦。\n海水直下万里深，谁人不言此离苦。\n日惨惨兮云冥冥，猩猩啼烟兮鬼啸雨。\n我纵言之将何补，皇穹窃恐不照余之忠诚。\n雷冯冯兮欲吼怒，尧舜当之亦禅禹。\n君失臣兮龙为鱼，权归臣兮鼠变虎。\n或云尧幽囚，舜野死，九疑联緜皆相似，重瞳孤坟竟何是。\n帝子泣兮绿云间，随风波兮去无还。\n恸哭兮远望，见苍梧之深山。\n苍梧山崩湘水绝，竹上之泪乃可灭。' },
  { title: '杂曲歌辞 远别离', author: '张籍', poem: '莲叶团团杏花拆，长江鲤鱼鳍鬣赤。\n念君少年弃亲戚，千里万里独为客。\n谁言远别心不易，天星坠地能为石。\n几时断得城南陌，勿使居人有行役。' },
  { title: '杂曲歌辞 远别离二首 一', author: '令狐楚', poem: '杨柳黄金穗，梧桐碧玉枝。\n春来消息断，早晚是归时。' },
  { title: '杂曲歌辞 远别离二首 二', author: '令狐楚', poem: '玳织鸳鸯履，金装翡翠簪。\n畏人相问着，不拟到城南。' },
  { title: '杂曲歌辞 久别离', author: '李白', poem: '别来几春未还家，玉窗五见樱桃花。\n况有锦字书，开缄使人嗟。\n至此肠断彼心绝，云鬟绿鬓罢揽结。\n愁如回飙乱白雪，去年寄书报阳台。\n今年寄书重相催，胡为东风为我吹行云。\n使西来，待来竟不来，落花寂寂委青苔。' },
  { title: '杂曲歌辞 新别离', author: '戴叔伦', poem: '手把杏花枝，未曾经别离。\n黄昏掩闺后，寂寞自心知。' },
  { title: '杂曲歌辞 今别离', author: '崔国辅', poem: '送别未能旋，相望连水口。\n船行欲映洲，几度急摇手。' },
  { title: '杂曲歌辞 暗别离', author: '刘氏瑶', poem: '槐花结子桐叶焦，单飞越鸟嗁青霄。\n翠轩辗云轻遥遥，燕脂泪迸红线条。\n瑶草歇芳心耿耿，玉佩无声画屏冷。\n朱弦暗断不见人，风动花枝月中影。\n青鸾脉脉西飞去，海阔天高不知处。' },
  { title: '杂曲歌辞 潜别离', author: '白居易', poem: '不得哭，潜别离，不得语，暗相思，两心之外无人知。\n深笼夜[锁]独栖鸟，利劒[春]断连理枝。\n河水虽浊有清日，乌头虽黑有白时。\n惟有潜离与暗别，彼此甘心无后期。' },
  { title: '杂曲歌辞 别离曲', author: '张籍', poem: '行人结束出门去，马蹏几时踏门路。\n忆昔君初纳彩时，不言身属辽阳戍。\n早知今日当别离，成君家计良为谁。\n男儿生身自有役，那得悮我少年时。\n不如逐君征战死，谁能独老空闺里。' },
  { title: '杂曲歌辞 别离曲', author: '陆龟蒙', poem: '丈夫非无泪，不洒离别间。\n仗劒对尊酒，耻为游子颜。\n蝮蛇一螫手，壮士疾解腕。\n所思在功名，离别何足叹。' },
  { title: '杂曲歌辞 西洲曲', author: '温庭筠', poem: '悠悠复悠悠，昨日下西洲。\n西洲风色好，遥见武昌楼。\n武昌何郁郁，侬家定无匹。\n小妇被流黄，登楼抚瑶瑟。\n朱弦繁复轻，素手直凄清。\n一弹三四解，掩抑似含情。\n南楼登且望，西江广复平。\n艇子摇两桨，催过石头城。\n门前乌臼树，惨澹天将曙。\n鹍𫛥飞复还，郎随早帆去。\n回头语同伴，定复负情侬。\n去帆不安幅，作抵使西风。\n他日相寻索，莫作西洲客。\n西洲人不归，春草年年碧。' },
  { title: '杂曲歌辞 荆州乐', author: '李白', poem: '白帝城边足风波，瞿塘五月谁敢过。\n荆州麦熟茧成蛾，缫丝忆君头绪多，拨谷飞鸣奈妾何。' },
  { title: '杂曲歌辞 荆州乐二首 一', author: '刘禹锡', poem: '渚宫杨柳暗，麦城朝雉飞。\n可怜踏青伴，乘暖着轻衣。' },
  { title: '杂曲歌辞 荆州乐二首 二', author: '刘禹锡', poem: '今日好南风，商旅相催发。\n沙头樯竿上，始见春江阔。' },
  { title: '杂曲歌辞 荆州泊', author: '李端', poem: '南楼西下时，月里闻来棹。\n桂水舳舻回，荆州津济闹。\n移帷望星汉，引带思容貌。\n今夜一江人，惟应妾身觉。' },
  { title: '杂曲歌辞 纪南歌', author: '刘禹锡', poem: '风烟纪南城，尘土荆门路。\n天寒猎兽者，走上樊姬墓。' },
  { title: '杂曲歌辞 宜城歌', author: '刘禹锡', poem: '野水遶空城，行尘起孤驿。\n花台侧生树，石碣阳镌头。\n靡靡度行人，温风吹宿麦。' },
  { title: '杂曲歌辞 长干曲四首 一', author: '崔颢', poem: '君家定何处？妾住在横塘。\n停舟暂借问，或恐是同乡。' },
  { title: '杂曲歌辞 长干曲四首 二', author: '崔颢', poem: '家临九江水，去来九江侧。\n同是长干人，生小不相识。' },
  { title: '杂曲歌辞 长干曲四首 三', author: '崔颢', poem: '下渚多风浪，莲舟渐觉稀。\n那能不相待，独自逆潮归。' },
  { title: '杂曲歌辞 长干曲四首 四', author: '崔颢', poem: '三江潮水急，五湖风浪涌。\n由来花性轻，莫畏莲舟重。' },
  { title: '杂曲歌辞 长干行二首 一', author: '李白', poem: '妾发初覆额，折花门前剧。\n郎骑竹马来，遶床弄青梅。\n同居长干里，两小无嫌猜。\n十四为君妇，羞颜尚不开。\n低头向暗壁，千唤不一回。\n十五始展眉，愿同尘与灰。\n常存抱柱信，岂上望夫台。\n十六君远行，瞿塘滟预堆。\n五月不可触，猨鸣天上哀。\n门前迟行迹，一一生绿苔。\n苔深不能扫，落叶秋风早。\n八月蝴蝶来，双飞西园草。\n感此伤妾心，坐愁红颜老。\n早晚下三巴，预将书报家。\n相迎不道远，直至长风沙。' },
  { title: '杂曲歌辞 长干行二首 二', author: '李白', poem: '忆妾深闺里，烟尘不曾识。\n嫁与长干人，沙头候风色。\n五月南风兴，思君在巴陵。\n八月西风起，想君发扬子。\n去来悲如何，见少别离多。\n湘潭几日到，妾梦越风波。\n昨夜狂风度，吹折江头树。\n淼淼暗无边，行人在何处？\n北客真王公，朱衣满江中。\n日暮来投宿，数朝不肎东。\n好乘浮云骢，佳期兰渚东。\n鸳鸯绿浦上，翡翠锦屏中。\n自怜十五余，颜色桃李红。\n那作商人妇，愁水复愁风。' },
  { title: '杂曲歌辞 长干行', author: '张潮', poem: '壻贫如珠玉，壻富如埃尘。\n贫时不忘旧，富贵多宠新。\n妾本富家女，与君为偶匹。\n惠好一何深，中门不曾出。\n妾有绣衣裳，葳蕤金缕光。\n念君贫且贱，易此从远方。\n远方三千里，发去悔不已。\n日暮情更来，空望去时水。\n孟夏麦始秀，江上多南风。\n商贾归欲尽，君今尚巴东。\n巴东有巫山，窈窕神女颜。\n常恐游此山，果然不知还。' },
  { title: '杂曲歌辞 小长干曲', author: '崔国辅', poem: '月暗送湖风，相寻路不通。\n菱歌唱不辍，知在此塘中。' },
  { title: '杂曲歌辞 杞梁妻', author: '僧贯休', poem: '秦之无道兮四海枯，筑长城兮遮北胡。\n筑人筑土一万里，杞梁贞妇嗁呜呜。\n上无父兮中无夫，下无子兮孤复孤。\n一号城崩塞色苦，再号杞梁骨出土。\n疲魂饥魄相逐归，陌上少年莫相非。' },
  { title: '杂曲歌辞 卢女曲', author: '崔颢', poem: '二月春来半，宫中日渐长。\n柳垂金屋暖，花覆玉楼香。\n拂匣先临镜，调笙更炙簧。\n还将卢女曲，夜夜奉君王。' },
  { title: '杂曲歌辞 卢姬篇', author: '崔颢', poem: '卢姬小小魏王家，绿鬓红唇桃李花。\n魏王绮楼十二重，水精帘箔绣芙蓉。\n白玉阑干金作柱，楼上朝朝学歌舞。\n前堂后堂罗袖人，南窗北窗花发春。\n翠幌珠帘鬬弦管，一奏一弹云欲断。\n君王日晚下朝归，鸣环佩玉生光辉。\n人生今日得骄贵，谁道卢姬身细微。' },
  { title: '杂曲歌辞 邯郸才人嫁为厮养卒妇', author: '李白', poem: '妾本丛台女，扬蛾入丹阙。\n自倚颜如花，宁知有凋歇。\n一辞玉阶下，去若朝云没。\n每忆邯郸城，深宫梦秋月。\n君王不可见，惆怅至明发。' },
  { title: '杂曲歌辞 杨白花', author: '柳宗元', poem: '杨白花，风吹度江水。\n坐令宫树无颜色，摇荡春光千万里。\n茫茫晓日下长秋，哀歌未断城鵶起。' },
  { title: '杂曲歌辞 茱萸女', author: '万楚', poem: '山阴柳家女，九日采茱萸。\n复得东邻伴，双为陌上姝。\n插花向高髻，结子置长裾。\n作性恒迟缓，非关诧丈夫。\n平明折林树，日入反城隅。\n侠客邀罗袖，行人挑短书。\n蛾眉自有主，年少莫踟蹰。' },
  { title: '杂曲歌辞 于阗采花', author: '李白', poem: '于阗采花人，自言花相似。\n明妃一朝西入胡，胡中美女多羞死。\n乃知汉地多名姝，胡中无花可方比。\n丹青能令丑者妍，无盐翻在深宫里。\n自古妬蛾眉，胡沙埋皓齿。' },
  { title: '杂曲歌辞 秦女卷衣', author: '李白', poem: '天子居未央，妾侍卷衣裳。\n顾无紫宫宠，敢拂黄金床。\n水至亦不去，熊来尚可当。\n微身奉日月，飘若萤火光。\n愿君采葑菲，无以下体妨。' },
  { title: '杂曲歌辞 爱妾换马 一', author: '张祜', poem: '一面妖桃千里蹏，娇姿骏背价应齐。\n乍牵玉勒辞金栈，催整花钿出绣闺。\n去日岂无沾袂泣，归时还有顿衔嘶。\n婵娟躞蹀春风里，挥手摇鞭杨柳堤。' },
  { title: '杂曲歌辞 爱妾换马 二', author: '张祜', poem: '绮阁香销华厩空，忍将行雨换追风。\n休怜柳叶双眉翠，却爱桃花两耳红。\n侍宴永辞春色里，趁朝休立漏声中。\n恩劳未尽情先尽，暗泣嘶风两意同。' },
  { title: '杂曲歌辞 枯鱼过河泣', author: '李白', poem: '白龙改常服，偶被豫且制。\n谁使尔为鱼，徒劳诉天帝。\n作书报鲸鲵，勿恃风涛势。\n涛落归泥沙，翻遭蝼蚁噬。\n万乘慎出入，柏人以为诫。' },
  { title: '杂曲歌辞 饮酒乐', author: '聂夷中', poem: '日月似有事，一夜行一周。\n草木犹须老，人生得无愁。\n一饮解百结，再饮破百忧。\n白发欺贫贱，不入醉人头。\n我愿东海水，尽向杯中流。\n安得阮步兵，同入醉乡游。' },
  { title: '杂曲歌辞 王孙游', author: '崔国辅', poem: '自与王孙别，频看黄鸟飞。\n应由春草误，着处不成归。' },
  { title: '杂曲歌辞 发白马', author: '李白', poem: '将军发白马，旌节渡黄河。\n箫鼓聒川岳，沧溟涌洪波。\n武安有振瓦，易水无寒歌。\n铁骑若雪山，饮流涸滹沱。\n扬兵猎月窟，转战畧朝那。\n倚剑登燕然，边峰列嵯峨。\n萧条万里外，耕作五原多。\n一扫清大漠，包虎戢金戈。' },
  { title: '杂曲歌辞 结韈子', author: '李白', poem: '燕南壮士吴门豪，筑中置铅鱼隐刀。\n感君恩重许君命，泰山一掷轻鸿毛。' },
  { title: '杂曲歌辞 沐浴子', author: '李白', poem: '沐芳莫弹冠，浴兰莫振衣。\n处世忌太洁，志人贵藏辉。\n沧浪有钓叟，吾与尔同归。' },
  { title: '杂曲歌辞 三台二首 一', author: '韦应物', poem: '一年一年老去，明日后日花开。\n未报长安平定，万国岂得衔杯。' },
  { title: '杂曲歌辞 三台二首 二', author: '韦应物', poem: '冰泮寒塘始绿，雨余百草皆生。\n朝来门合无事，晚下高斋有情。' },
  { title: '杂曲歌辞 上皇三台', author: '韦应物', poem: '不寐倦长更，披衣出户行。\n月寒秋竹冷，风切夜窗声。' },
  { title: '杂曲歌辞 突厥三台', author: '韦应物', poem: '鴈门山上鴈初飞，马邑阑中马正肥。\n日旰山西逢驿使，殷勤南北送征衣。' },
  { title: '杂曲歌辞 宫中三台二首 一', author: '王建', poem: '鱼藻池边射鸭，芙蓉园里看花。\n日色柘袍相似，不着红鸾扇遮。' },
  { title: '杂曲歌辞 宫中三台二首 二', author: '王建', poem: '池北池南草绿，殿前殿后花红。\n天子千年万岁，未央明月清风。' },
  { title: '杂曲歌辞 江南三台四首 一', author: '王建', poem: '扬州桥边小妇，长干市里商人。\n三年不得消息，各自拜鬼求神。' },
  { title: '杂曲歌辞 江南三台四首 二', author: '王建', poem: '青草湖边草色，飞猨岭上猨声。\n万里三湘客到，有风有雨人行。' },
  { title: '杂曲歌辞 江南三台四首 三', author: '王建', poem: '树头花落花开，道上人去人来。\n朝愁暮愁即老，百年几度三台。' },
  { title: '杂曲歌辞 江南三台四首 四', author: '王建', poem: '闻身彊健且为，头白齿落难追。\n准拟百年千岁，能得几许多时。' },
  { title: '杂曲歌辞 筑城曲', author: '张籍', poem: '筑城去，千人万人齐抱杵。\n重重土坚试行锥，军吏执鞭催作迟。\n来时一年深碛里，着尽短衣渴无水。\n力尽不得抛杵声，杵声未定人皆死。\n家家养男当门户，今日作君城下土。' },
  { title: '杂曲歌辞 筑城曲五解', author: '元稹', poem: '年年塞下丁，长作出塞兵。\n自从冒顿彊，官筑遮虏城。\n筑城须努力，城高遮得贼。\n但恐贼路多，有城遮不得。\n丁口传父口，莫问城坚不。\n平城被虏围，汉𣃁城墙走。\n因兹虏请和，虏往骑来多。\n半疑兼半信，筑城犹嵯峨。\n筑城安敢烦，愿听丁一言。\n请筑鸿胪寺，兼愁虏出关。' },
  { title: '杂曲歌辞 筑城曲', author: '陆龟蒙', poem: '城上一掊土，手中千万杵。\n筑城畏不坚，坚城在何处？\n莫叹筑城劳，将军要却敌。\n城高功亦高，尔命何处惜。' },
  { title: '杂曲歌辞 湖阴曲', author: '温庭筠', poem: '祖龙黄须珊瑚鞭，铁骢金面青连钱。\n虎髯拔劒欲成梦，日压贼营如血鲜。\n海旗风急惊眠起，甲重光摇照湖水。\n苍黄追骑尘外归，森索妖星阵前死。\n五陵愁碧春萋萋，灞川玉马空中嘶。\n羽书如电入青琐，雪腕如搥催画鞞。\n白虬天子金煌铓，高临帝座回龙章。\n吴波不动楚山晚，花压阑干春昼长。' },
  { title: '杂曲歌辞 无愁果有愁曲', author: '李商隐', poem: '东有青龙西白虎，中含福皇包世度。\n玉壶渭水笑清潭，凿天不到牵牛处。\n骐𬴊踏云天马狞，牛山撼碎珊瑚声。\n秋娥点滴不成泪，十二玉楼无故钉。\n推烟唾月抛千里，十番红桐一行死。\n白杨别屋鬼迷人，空留暗记如蚕纸。\n日暮向风牵短丝，血凝血散今谁是。' },
  { title: '杂曲歌辞 起夜来', author: '施肩吾', poem: '香销连理带，尘覆合欢杯。\n嬾卧相思枕，愁吟起夜来。' },
  { title: '杂曲歌辞 起夜半', author: '聂夷中', poem: '念远心如烧，不觉中夜起。\n桃花带露泛，立在月明里。' },
  { title: '杂曲歌辞 独不见', author: '沈佺期', poem: '卢家小妇郁金堂，海燕双栖玳瑁梁。\n九月寒砧催下叶，十年征戍忆辽阳。\n白狼河北音书断，丹凤城南秋夜长。\n谁知含愁独不见，使妾明月照流黄。' },
  { title: '杂曲歌辞 独不见', author: '王训', poem: '日晚宜春暮，风輭上林朝。\n对酒近初节，开楼荡夜娇。\n石桥通小涧，竹路上青霄。\n持底谁见许，长愁成细腰。' },
  { title: '杂曲歌辞 独不见', author: '杨巨源', poem: '东风艳阳色，柳绿花如霰。\n竞理同心鬟，争持合欢扇。\n香传贾娘手，粉离何郎面。\n最恨卷帘时，含情独不见。' },
  { title: '杂曲歌辞 独不见', author: '李白', poem: '白马谁家子，黄龙边塞儿。\n天山三丈雪，岂是远行时。\n春蕙忽秋草，莎鸡鸣曲池。\n风催寒椶响，月入霜闺悲。\n忆与君别年，种桃齐蛾眉。\n桃今百余尺，花落成枯枝。\n终然独不见，流泪空自知。' },
  { title: '杂曲歌辞 独不见', author: '戴叔伦', poem: '前宫路非远，旧苑春将遍。\n玉户看早梅，雕梁数归燕。\n身轻逐舞袖，香暖传歌扇。\n自知秋风词，长侍昭阳殿。\n谁信后庭人，年年独不见。' },
  { title: '杂曲歌辞 独不见', author: '胡曾', poem: '玉关一自有氛埃，年少从军竟未回。\n门外尘凝张乐榭，水边香灭按歌台。\n窗残夜月人何处？帘卷春风燕复来。\n万里寂寥音信绝，寸心争忍不成灰。' },
  { title: '杂曲歌辞 携手曲', author: '田娥', poem: '携手共惜芳菲节，莺啼锦花满城阙。\n行乐逶迤念容色，色衰祗恐君恩歇。\n凤笙龙管白日阴，盈亏自感青天月。' },
  { title: '杂曲歌辞 大垂手', author: '聂夷中', poem: '金刀翦轻云，盘用黄金缕。\n装束赵飞燕，教来掌上舞。\n舞罢飞燕死，片片随风去。' },
  { title: '杂曲歌辞 夜夜曲', author: '不详', poem: '愁人夜独伤，灭烛卧兰房。\n祗恐多情月，旋来照妾床。' },
  { title: '杂曲歌辞 夜夜曲', author: '王偃', poem: '北斗星移银汉低，班姬愁思凤城西。\n青槐陌上人行绝，明月楼前乌夜啼。' },
  { title: '杂曲歌辞 夜夜曲', author: '僧贯休', poem: '蟪蛄切切风骚骚，芙蓉喷香蟾蜍高。\n孤灯耿耿征妇劳，更深扑落金错刀。' },
  { title: '杂曲歌辞 秋夜长', author: '王勃', poem: '秋夜长，殊未央。\n月明白露澄清光，层城绮阁遥相望。\n遥相望，川无梁。\n北风受节鴈南翔，崇兰委质时菊芳。\n鸣环曳履出长廊，为君秋夜捣衣裳。\n纤罗对凤皇，丹绮双鸳鸯。\n调砧乱杵思自伤，思自伤，征夫万里戍他乡。\n鹤关音信断，龙门道路长。\n所在天一方，寒衣徒自香。' },
  { title: '杂曲歌辞 秋夜长', author: '张籍', poem: '秋天如水夜未央，天汉东西月色光。\n愁人不寐畏枕席，暗虫唧唧遶我傍。\n荒城为村无更声，起看北斗天未明。\n白露满田风褭褭，千声万声鹖鸟鸣。' },
  { title: '杂曲歌辞 秋夜曲二首 一', author: '王建', poem: '天清漏长霜泊泊，兰绿收荣桂膏涸。\n高楼云鬟弄婵娟，古瑟暗断秋风弦。\n玉关遥隔万里道，金刀不翦双泪泉。\n香囊火死香气少，向帷合眼何时晓？\n城乌作营嗁野月，秦川少妇生离别。' },
  { title: '杂曲歌辞 秋夜曲二首 二', author: '王建', poem: '秋灯向壁掩洞房，良人此夜直明光。\n天河悠悠漏水长，南楼北斗两相当。' },
  { title: '杂曲歌辞 秋夜曲', author: '张仲素', poem: '丁丁漏水夜何长，漫漫轻云露月光。\n秋壁暗虫通夕响，寒衣未寄莫飞霜。' },
  { title: '杂曲歌辞 秋夜曲', author: '王涯', poem: '桂魄初生秋露微，轻罗已薄未更衣。\n银筝夜久殷勤弄，心怯空房不忍归。' },
  { title: '杂曲歌辞 夜坐吟', author: '李白', poem: '冬夜夜寒觉夜长，沈吟久坐坐北堂。\n冰合井泉月入闺，青缸凝明照悲嗁。\n青缸灭，嗁转多，掩妾泪，听君歌。\n歌有声，妾有情，情声合，两无违。\n一语不入意，从君万曲梁尘飞。' },
  { title: '杂曲歌辞 夜寒吟', author: '鲍溶', poem: '九衢金吾夜行行，上宫玉漏遥分明。\n霜飙乘阴扫地起，旅鸿迷雪绕枕声。\n远人归梦既不成，留家惜夜欢心发。\n罗幕画堂深皎洁，兰烟对酒客几人。\n兽火扬光二三月，细腰楚姬丝竹间。\n白纻长袖歌闲闲，岂识苦寒损朱颜。' },
  { title: '杂曲歌辞 定情乐', author: '施肩吾', poem: '敢嗟君不怜，自是命不谐。\n着破三条裾，却还双股钗。' },
  { title: '杂曲歌辞 春江曲', author: '郭元振', poem: '江水春沈沈，上有双竹林。\n竹叶坏水色，郎亦坏人心。' },
  { title: '杂曲歌辞 春江曲', author: '张籍', poem: '春江无云潮水平，蒲心出水凫雏鸣。\n长干夫壻爱远行，自染春衣缝已成。\n妾身生长金陵侧，去年随夫住江北。\n春来未到父母家，舟小风多渡不得。\n欲辞舅姑先问人，私向江头祭水神。' },
  { title: '杂曲歌辞 春江曲', author: '王涯', poem: '摇漾越江春，相将看白苹。\n归时不觉夜，出浦月随人。' },
  { title: '杂曲歌辞 春江曲二首 一', author: '张仲素', poem: '家寄征江岸，征人几岁游。\n不知潮水信，每日到沙头。' },
  { title: '杂曲歌辞 春江曲二首 二', author: '张仲素', poem: '乘晓南湖去，参差叠浪横。\n前洲在何处？雾里鴈嘤嘤。' },
  { title: '杂曲歌辞 江上曲', author: '李嘉祐', poem: '江上澹澹芙蓉花，江口蛾眉独浣纱。\n可怜应是阳台女，坐对鸬鹚娇不语。\n掩面羞看北地人，回首忽作空山雨。\n苍梧秋色不堪论，千载依依帝子魂。\n君看峰上斑斑竹，尽是湘妃泣泪痕。' },
  { title: '杂曲歌辞 桃花曲', author: '顾况', poem: '魏帝宫人舞凤楼，隋家天子泛龙舟。\n君王夜醉春眠[晏]，不觉桃花逐水流。' },
  { title: '杂曲歌辞 树中草', author: '李白', poem: '鸟衔野田草，误入枯桑里。\n客土植危根，逢春犹不死。\n草木虽无情，因依尚可生。\n如何同枝叶，各自有枯荣。' },
  { title: '杂曲歌辞 树中草', author: '张祜', poem: '青青树中草，托根非不危。\n草生树却死，荣枯君可知。' },
  { title: '杂曲歌辞 春游吟', author: '李章', poem: '初春遍芳甸，千里霭盈瞩。\n美人摘新英，步步玩春绿。\n所思杳何处，宛在吴江曲。\n可怜不得共芳菲，日暮归来泪满衣。' },
  { title: '杂曲歌辞 春游乐', author: '施肩吾', poem: '一年三百六十日，赏心那似春中物。\n草迷曲坞花满园，东家少年西家出。' },
  { title: '杂曲歌辞 春游乐二首 一', author: '李端', poem: '游童苏合带，倡女蒲葵扇。\n初日映城时，相思忽相见。\n褰裳踏露草，理鬓回花面。\n薄暮不同归，留情此芳甸。' },
  { title: '杂曲歌辞 春游乐二首 二', author: '李端', poem: '柘弹连钱马，银钩妥堕鬟。\n采桑春陌上，踏草夕阳间。\n意合辞先露，心诚貌却闲。\n明朝若相忆，云雨出巫山。' },
  { title: '杂曲歌辞 春游曲三首 一', author: '张仲素', poem: '烟柳飞轻絮，风榆落小钱。\n蒙蒙百花里，罗绮竞秋千。' },
  { title: '杂曲歌辞 春游曲三首 二', author: '张仲素', poem: '骋望登香阁，争高下砌台。\n林间踏青去，席上意钱来。' },
  { title: '杂曲歌辞 春游曲三首 三', author: '张仲素', poem: '行乐三春节，林花百和香。\n当年重意气，先占鬬鸡场。' },
  { title: '杂曲歌辞 乐府二首 一', author: '刘言史', poem: '花颔红騣一向偏，绿槐香陌欲朝天。\n仍嫌众里娇行疾，傍镫深藏白玉鞭。' },
  { title: '杂曲歌辞 乐府二首 二', author: '刘言史', poem: '喷珠团香小桂条，玉鞭兼赐霍嫖姚。\n弄影便从天禁出，碧蹏声碎五门桥。' },
  { title: '杂曲歌辞 乐府', author: '顾况', poem: '暖谷春光至，宸游近甸荣。\n云随天仗转，风入御帘轻。\n翠盖浮佳气，朱楼倚太清。\n朝臣冠劒退，宫女管弦迎。\n细草承雕辇，繁花入幔城。\n文房开圣藻，武卫宿天营。\n玉醴随觞至，铜壶逐漏行。\n五星含土德，万姓彻中声。\n亲祀先崇典，躬推示劝耕。\n国风新正乐，农器近消兵。\n道德关河固，刑章日月明。\n野人同鸟兽，率舞感升平。' },
  { title: '杂曲歌辞 乐府', author: '权德舆', poem: '光风澹荡百花吐，楼上朝朝学歌舞。\n身年二八壻侍中，幼妹承恩兄尚主。\n绿窗珠箔绣鸳鸯，侍婢先焚百和香。\n莺嗁日出不知曙，寂寂罗帏春梦长。' },
  { title: '杂曲歌辞 乐府三首 一', author: '孟郊', poem: '莲子不可得，荷花生水中。\n犹胜道傍柳，无事荡春风。' },
  { title: '杂曲歌辞 乐府三首 二', author: '孟郊', poem: '渌萍与荷叶，同时一水中。\n风吹荷叶在，渌萍西复东。' },
  { title: '杂曲歌辞 乐府三首 三', author: '孟郊', poem: '莲花未开时，苦心终日卷。\n春水徒荡漾，荷花未开展。' },
  { title: '杂曲歌辞 乐府', author: '陆长源', poem: '芙蓉初出水，菡萏露中花。\n风吹着枯木，无奈值空槎。' },
  { title: '杂曲歌辞 杂曲', author: '王勃', poem: '智琼神女，来访文君。\n蛾眉始约，罗袖初薰。\n歌齐曲韵，舞乱行分。\n若向阳台荐枕，何啻得胜朝云。' },
  { title: '杂曲歌辞 古曲五首 一', author: '施肩吾', poem: '可怜江北女，惯唱江南曲。\n摇荡木兰舟，双凫不成浴。' },
  { title: '杂曲歌辞 古曲五首 二', author: '施肩吾', poem: '郎为匕上香，妾为笼上灰。\n归时虽暖热，去罢生尘埃。' },
  { title: '杂曲歌辞 古曲五首 三', author: '施肩吾', poem: '夜裁鸳鸯绮，朝织蒲桃绫。\n欲试一寸心，待缝三尺冰。' },
  { title: '杂曲歌辞 古曲五首 四', author: '施肩吾', poem: '怜时鱼得水，怨罢商与参。\n不如山支子，却解结同心。' },
  { title: '杂曲歌辞 古曲五首 五', author: '施肩吾', poem: '红颜感暮花，白日同流水。\n思君如孤灯，一夜一心死。' },
  { title: '杂曲歌辞 高句丽', author: '李白', poem: '金花折风帽，白马小迟回。\n翩翩舞广袖，似鸟海东来。' },
  { title: '杂曲歌辞 摩多楼子', author: '李贺', poem: '玉塞去金人，二万四千里。\n风吹沙作云，一时渡辽水。\n天白水如练，甲丝双串断。\n行行莫苦辛，城月犹残半。\n晓气朔烟上，趢趗胡马蹏。\n行人听水别，隔陇长东西。' },
  { title: '杂曲歌辞 辽东行', author: '王建', poem: '辽东万里辽水曲，古戍无城复无屋。\n黄云盖地雪作山，不惜黄金买衣服。\n战回各自收弓箭，正西回面家乡远。\n年年郡县送征人，将与辽东作丘坂。\n宁为草木乡中生，有身不向辽东行。' },
  { title: '杂曲歌辞 渡辽水', author: '王建', poem: '渡辽水，此去咸阳五千里。\n来时父母知隔生，重着衣裳如送死。\n亦有白骨归咸阳，营家各与题本乡。\n身在应无回渡日，驻马相看辽水傍。' },
  { title: '杂曲歌辞 昔昔盐 垂柳覆金堤', author: '赵嘏', poem: '新年垂柳色，袅袅对空闺。\n不畏芳菲好，自缘离别嗁。\n因风飘玉户，向日映金堤。\n驿使何时度？还将赠陇西。' },
  { title: '杂曲歌辞 昔昔盐 蘼芜叶复齐', author: '赵嘏', poem: '提筐红叶下，度日采蘼芜。\n掬翠香盈袖，看花忆故夫。\n叶齐谁复见，风暖恨偏孤。\n一被春光累，容颜与昔殊。' },
  { title: '杂曲歌辞 昔昔盐 水溢芙蓉沼', author: '赵嘏', poem: '渌沼春光后，青青草色浓。\n绮罗惊翡翠，暗粉妒芙蓉。\n云遍窗前见，荷翻镜里逢。\n将心托流水，终日渺无从。' },
  { title: '杂曲歌辞 昔昔盐 花飞桃李蹊', author: '赵嘏', poem: '远期难可托，桃李自依依。\n花径无容迹，戎裘未下机。\n随风开又落，度日扫还飞。\n欲折枝枝赠，那知归不归。' },
  { title: '杂曲歌辞 昔昔盐 采桑秦氏女', author: '赵嘏', poem: '南陌采桑出，谁知妾姓秦。\n独怜倾国貌，不负早莺春。\n珠履荡花湿，龙钩折桂新。\n使君那驻马，自有侍中人。' },
  { title: '杂曲歌辞 昔昔盐 织锦窦家妻', author: '赵嘏', poem: '当年谁不羡，分作窦家妻。\n锦字行行苦，罗帷日日嗁。\n岂知登陇远，祗恨下机迷。\n直候阳关使，殷勤寄海西。' },
  { title: '杂曲歌辞 昔昔盐 关山别荡子', author: '赵嘏', poem: '那堪闻荡子，迢遰涉关山。\n肠为马嘶断，衣从泪滴斑。\n愁看塞上路，讵惜镜中颜。\n傥见征西鴈，应传一字还。' },
  { title: '杂曲歌辞 昔昔盐 风月守空闺', author: '赵嘏', poem: '良人犹远戍，耿耿夜闺空。\n绣户流宵月，罗帷坐晓风。\n魂飞沙帐北，肠断玉关中。\n尚自无消息，锦衾那得同。' },
  { title: '杂曲歌辞 昔昔盐 恒敛千金笑', author: '赵嘏', poem: '玉颜恒自敛，羞出镜台前。\n早惑阳城客，今悲华锦筵。\n从军人更远，投喜鹊空传。\n夫壻交河北，迢迢路几千。' },
  { title: '杂曲歌辞 昔昔盐 长垂双玉嗁', author: '赵嘏', poem: '双双红泪堕，度日暗中嗁。\n鴈出居延北，人犹辽海西。\n向灯垂玉枕，对月洒金闺。\n不惜罗衣湿，惟愁归意迷。' },
  { title: '杂曲歌辞 昔昔盐 蟠龙随镜隐', author: '赵嘏', poem: '鸾镜无由照，蛾眉岂忍看。\n不知愁发换，空见隐龙蟠。\n那惬红颜改，偏伤白日残。\n今朝窥玉匣，双泪落阑干。' },
  { title: '杂曲歌辞 昔昔盐 彩凤逐帷低', author: '赵嘏', poem: '巧绣双飞凤，朝朝伴下帷。\n春花那见照，暮色已频欺。\n欲卷思君处，将嗁裛泪时。\n何年征戍客？传语报佳期。' },
  { title: '杂曲歌辞 昔昔盐 惊魂同夜鹊', author: '赵嘏', poem: '万里无人见，众情难与论。\n思君常入梦，同鹊屡惊魂。\n孤寝红罗帐，双嗁玉筯痕。\n妾心甘自保，岂复暂忘恩。' },
  { title: '杂曲歌辞 昔昔盐 倦寝听晨鸡', author: '赵嘏', poem: '去去边城骑，愁眠掩夜闺。\n披衣窥落月，拭泪待鸣鸡。\n不愤连年别，那堪长夜嗁。\n功成应自恨，早晚发辽西。' },
  { title: '杂曲歌辞 昔昔盐 暗牖悬蛛网', author: '赵嘏', poem: '暗中蛛网织，历乱绮窗前。\n万里终无信，一条徒自悬。\n分从珠露滴，愁见隙风牵。\n妾意何聊赖，看看剧断弦。' },
  { title: '杂曲歌辞 昔昔盐 空梁落燕泥', author: '赵嘏', poem: '春至今朝燕，花时伴独嗁。\n飞斜珠箔隔，语近画梁低。\n帷卷闲窥户，床空暗落泥。\n谁能长对此，双去复双栖。' },
  { title: '杂曲歌辞 昔昔盐 前年过代北', author: '赵嘏', poem: '代北几千里，前年又复经。\n燕山云自合，胡塞草应青。\n铁马喧鼙鼓，蛾眉怨锦屏。\n不知羌笛曲，掩泪若为听。' },
  { title: '杂曲歌辞 昔昔盐 今岁往辽西', author: '赵嘏', poem: '万里飞书至，闻君已渡辽。\n祗谙新别苦，忘却旧时娇。\n烽戍年将老，红颜日向雕。\n胡沙兼汉苑，相望几迢迢。' },
  { title: '杂曲歌辞 昔昔盐 一去无还意', author: '赵嘏', poem: '良人征绝域，一去不言还。\n百战攻胡虏，三冬阻玉关。\n萧萧边马思，猎猎戍旗闲。\n独把千重恨，连年未解颜。' },
  { title: '杂曲歌辞 昔昔盐 那能惜马蹏', author: '赵嘏', poem: '云中路杳杳，江畔草萋萋。\n妾久垂珠泪，君何惜马蹏。\n边风悲晓角，营月怨春鼙。\n未道休征战，愁眉又复低。' },
  { title: '杂曲歌辞 水调 歌第一', author: '不详', poem: '平沙落日大荒西，陇上明星高复低。\n孤山几处看烽火，壮士连营候鼓鼙。' },
  { title: '杂曲歌辞 水调 歌第二', author: '不详', poem: '猛将关西意气多，能骑骏马弄雕戈。\n金鞍宝铰精神出，笛倚新翻水调歌。' },
  { title: '杂曲歌辞 水调 歌第三', author: '不详', poem: '王孙别上绿珠轮，不羡名公乐此身。\n户外碧潭春洗马，楼前红烛夜迎人。' },
  { title: '杂曲歌辞 水调 歌第四', author: '不详', poem: '陇头一叚气长秋，举目萧条总是愁。\n秖为征人多下泪，年年添作断肠流。' },
  { title: '杂曲歌辞 水调 歌第五', author: '不详', poem: '双带仍分影，同心巧结香。\n不应须换彩，意欲媚浓妆。' },
  { title: '杂曲歌辞 水调 入破第一', author: '不详', poem: '细草河边一鴈飞，黄龙关里挂戎衣。\n为受明王恩宠甚，从事经年不复归。' },
  { title: '杂曲歌辞 水调 入破第二', author: '不详', poem: '锦城丝管日纷纷，半入江风半入云。\n此曲只应天上去，人间能得几回闻。' },
  { title: '杂曲歌辞 水调 入破第三', author: '不详', poem: '昨夜遥欢出建章，今朝缀赏度昭阳。\n传声莫闭黄金屋，为报先开白玉堂。' },
  { title: '杂曲歌辞 水调 入破第四', author: '不详', poem: '日晚笳声咽戍楼，陇云漫漫水东流。\n行人万里向西去，满目关山空恨愁。' },
  { title: '杂曲歌辞 水调 入破第五', author: '不详', poem: '千年一遇圣明朝，愿对君王舞细腰。\n乍可当熊任生死，谁能伴凤上云霄。' },
  { title: '杂曲歌辞 水调 入破第六彻', author: '不详', poem: '闺烛无人影，罗屏有梦魂。\n近来音耗绝，终日望君门。' },
  { title: '杂曲歌辞 水调', author: '吴融', poem: '凿河千里走黄沙，浮殿西来动日华。\n可道新声是亡国，且贪惆怅后庭花。' },
  { title: '杂曲歌辞 堂堂 一', author: '李义府', poem: '镂月成歌扇，裁云作舞衣。\n自怜回雪影，好取洛川归。' },
  { title: '杂曲歌辞 堂堂 二', author: '李义府', poem: '嬾正鸳鸯被，羞褰玳瑁床。\n春风别有意，密处也寻香。' },
  { title: '杂曲歌辞 堂堂', author: '李贺', poem: '堂堂复堂堂，红脱梅灰香。\n十年粉蠹生画梁，饥虫不食推碎黄。\n蕙花已老桃叶长，禁院悬帘隔御光。\n华清源中礜石汤，裴回百凤随君王。' },
  { title: '杂曲歌辞 凉州 歌第一', author: '不详', poem: '汉家宫里柳如丝，上苑桃花连碧池。\n圣寿已传千岁酒，天文更赏百僚诗。' },
  { title: '杂曲歌辞 凉州 歌第二', author: '不详', poem: '朔风吹叶鴈门秋，万里烟尘昏戍楼。\n征马长思青海北，胡笳夜听陇山头。' },
  { title: '杂曲歌辞 凉州 歌第三', author: '不详', poem: '开箧泪沾襦，见君前日书。\n夜台空寂寞，犹见紫云车。' },
  { title: '杂曲歌辞 凉州 排遍第一', author: '不详', poem: '三秋陌上早霜飞，羽猎平田浅草齐。\n锦背苍鹰初出按，五花骢马喂来肥。' },
  { title: '杂曲歌辞 凉州 排遍第二', author: '不详', poem: '鸳鸯殿里笙歌起，翡翠楼前出舞人。\n唤上紫微三五夕，圣明方寿一千春。' },
  { title: '杂曲歌辞 凉州词', author: '耿[𣲗]', poem: '国使翩翩随斾旌，陇西岐路足荒城。\n毡裘牧马胡雏小，日暮蕃歌三两声。' },
  { title: '杂曲歌辞 凉州词 一', author: '张籍', poem: '边城暮雨鴈飞低，芦笋初生渐欲齐。\n无数铃声遥过碛，应驮白练到安西。' },
  { title: '杂曲歌辞 凉州词 二', author: '张籍', poem: '古镇城门白碛开，胡兵往往傍沙堆。\n巡边使客行应早，每待平安火到来。' },
  { title: '杂曲歌辞 凉州词 三', author: '张籍', poem: '凤林关里水东流，白草黄榆六十秋。\n边将皆承主恩泽，无人解道取凉州。' },
  { title: '杂曲歌辞 凉州词', author: '薛逢', poem: '昨夜蕃兵报国讐，沙州都护破凉州。\n黄河九曲今归汉，塞外纵横战血流。' },
  { title: '杂曲歌辞 太和 第一', author: '不详', poem: '国门卿相旧山庄，圣主移来宴绿芳。\n帘外辗为车马路，花间踏出舞人场。' },
  { title: '杂曲歌辞 太和 第二', author: '不详', poem: '国鸟尚含天乐转，寒风犹带御衣香。\n为报碧潭明月夜，会须留赏待君王。' },
  { title: '杂曲歌辞 太和 第三', author: '不详', poem: '庭前鹊遶相思树，井上莺歌争刺桐。\n含情少妇悲春草，多是良人学转蓬。' },
  { title: '杂曲歌辞 太和 第四', author: '不详', poem: '塞北江南共一家，何须泪落怨黄沙。\n春酒半酣千日醉，庭前还有落梅花。' },
  { title: '杂曲歌辞 太和 第五彻', author: '不详', poem: '我皇膺运太平年，四海朝宗会百川。\n自古几多明圣主，不如今帝胜尧天。' },
  { title: '杂曲歌辞 伊州 歌第一', author: '盖嘉运', poem: '秋风明月独离居，荡子从戎十载余。\n征人去日殷勤属，归鴈来时数寄书。' },
  { title: '杂曲歌辞 伊州 歌第二', author: '盖嘉运', poem: '彤闱晓辟万鞍回，玉辂春游薄晚开。\n渭北清光摇草树，州南嘉景入楼台。' },
  { title: '杂曲歌辞 伊州 歌第三', author: '盖嘉运', poem: '闻道黄花戍，频年不解兵。\n可怜闺里月，偏照汉家营。' },
  { title: '杂曲歌辞 伊州 歌第四', author: '盖嘉运', poem: '千里东归客，无心忆旧游。\n挂帆游白水，高枕到青州。' },
  { title: '杂曲歌辞 伊州 歌第五', author: '盖嘉运', poem: '桂殿江乌对，雕屏海燕重。\n秖应多酿酒，醉罢乐高钟。' },
  { title: '杂曲歌辞 伊州 入破第一', author: '盖嘉运', poem: '千门今夜晓初晴，万里天河彻帝京。\n璨璨繁星驾秋色，棱棱霜气韵钟声。' },
  { title: '杂曲歌辞 伊州 入破第二', author: '盖嘉运', poem: '长安二月柳依依，西出流沙路渐微。\n阏氏山上春光少，相府庭边驿使稀。' },
  { title: '杂曲歌辞 伊州 入破第三', author: '盖嘉运', poem: '三秋大漠冷溪山，八月严霜变草颜。\n卷斾风行宵渡碛，衔枚电扫晓应还。' },
  { title: '杂曲歌辞 伊州 入破第四', author: '盖嘉运', poem: '行乐三阳早，芳菲二月春。\n闺中红粉态，陌上看花人。' },
  { title: '杂曲歌辞 伊州 入破第五', author: '盖嘉运', poem: '君住孤山下，烟深夜径长。\n辕门渡绿水，游苑遶垂杨。' },
  { title: '杂曲歌辞 陆州 歌第一', author: '不详', poem: '分野中峰变，阴晴众壑殊。\n欲投人处宿，隔浦问樵夫。' },
  { title: '杂曲歌辞 陆州 歌第二', author: '不详', poem: '共得烟霞径，东归山水游。\n萧萧望林夜，寂寂坐中秋。' },
  { title: '杂曲歌辞 陆州 歌第三', author: '不详', poem: '香气传空满，妆花映薄红。\n歌声天仗外，舞态御楼中。' },
  { title: '杂曲歌辞 陆州 排遍第一', author: '不详', poem: '树发花如锦，莺嗁柳若丝。\n更逢欢宴地，愁见别离时。' },
  { title: '杂曲歌辞 陆州 排遍第二', author: '不详', poem: '明月照秋叶，西风响夜砧。\n彊言徒自乱，往事不堪寻。' },
  { title: '杂曲歌辞 陆州 排遍第三', author: '不详', poem: '坐对银釭晓，停留玉筯痕。\n君门常不见，无处谢前恩。' },
  { title: '杂曲歌辞 陆州 排遍第四', author: '不详', poem: '曙月当窗满，征人出塞遥。\n画楼终日闭，清管为谁调。' },
  { title: '杂曲歌辞 簇拍陆州', author: '不详', poem: '西去轮台万里余，故乡音耗日应疎。\n陇山鹦鹉能言语，为报闺人数寄书。' },
  { title: '杂曲歌辞 石州', author: '不详', poem: '自从君去远巡边，终日罗帏独自眠。\n看花情转切，揽镜泪如泉。\n一自离君后，嗁多双脸穿。\n何时狂虏灭，免得更留连。' },
  { title: '杂曲歌辞 盖罗缝 一', author: '不详', poem: '秦时明月汉时关，万里征人尚未还。\n但愿龙庭神将在，不教胡马渡阴山。' },
  { title: '杂曲歌辞 盖罗缝 二', author: '不详', poem: '音书杜绝白狼西，桃李无颜黄鸟嗁。\n寒鸟春深归去尽，出门肠断草萋萋。' },
  { title: '杂曲歌辞 双带子', author: '不详', poem: '私言切语谁人会，海燕双飞绕画梁。\n君学秋胡不相识，妾亦无心去采桑。' },
  { title: '杂曲歌辞 昆仑子', author: '不详', poem: '[扬]子谭经去，淮王载酒过。\n醉来嗁鸟唤，坐久落花多。' },
  { title: '杂曲歌辞 祓禊曲 一', author: '不详', poem: '昨见春条绿，那知秋叶黄。\n蝉声犹未断，寒鴈已成行。' },
  { title: '杂曲歌辞 祓禊曲 二', author: '不详', poem: '金谷园中柳，春来已舞腰。\n那堪好风景，独上洛阳桥。' },
  { title: '杂曲歌辞 祓禊曲 三', author: '不详', poem: '何处堪愁思，花间长乐宫。\n君王不重客，泣泪向春风。' },
  { title: '杂曲歌辞 上巳乐', author: '张祜', poem: '猩猩血彩系头标，天上齐声举画桡。\n却是内人争意切，六宫罗袖一时招。' },
  { title: '杂曲歌辞 穆护砂', author: '不详', poem: '玉管朝朝弄，清歌日日新。\n折花当驿路，寄与陇头人。' },
  { title: '杂曲歌辞 思归乐 一', author: '不详', poem: '晚日催弦管，春风入绮罗。\n杏花如有意，偏落舞衫多。' },
  { title: '杂曲歌辞 思归乐 二', author: '不详', poem: '万里春应尽，三江鴈亦稀。\n连天汉水广，孤客未言归。' },
  { title: '杂曲歌辞 金殿乐', author: '不详', poem: '入夜秋砧动，千门起四邻。\n不缘楼上月，应为陇头人。' },
  { title: '杂曲歌辞 胡渭州 一', author: '不详', poem: '亭亭孤月照行舟，寂寂长江万里流。\n乡国不知何处是？云山漫漫使人愁。' },
  { title: '杂曲歌辞 胡渭州 二', author: '不详', poem: '杨柳千寻色，桃花一苑芳。\n风吹入帘里，惟有惹衣香。' },
  { title: '杂曲歌辞 戎浑', author: '不详', poem: '风劲角弓鸣，将军猎渭城。\n草枯鹰眼疾，雪尽马蹏轻。' },
  { title: '杂曲歌辞 墙头花 一', author: '不详', poem: '蟋蟀鸣洞房，梧桐落金井。\n为君裁舞衣，天寒翦刀冷。' },
  { title: '杂曲歌辞 墙头花 二', author: '不详', poem: '妾有罗衣裳，秦王在时作。\n为舞春风多，秋来不堪着。' },
  { title: '杂曲歌辞 采桑', author: '不详', poem: '自古多征战，由来尚甲兵。\n长驱千里去，一举两蕃平。\n按劒从沙漠歌谣满帝京寄言天下将须立武功名。' },
  { title: '杂曲歌辞 [杨]下采桑', author: '不详', poem: '飞丝惹绿尘，软叶对孤轮。\n今朝入园去，物色彊看人。' },
  { title: '杂曲歌辞 破阵乐 一', author: '不详', poem: '秋来四面足风沙，塞外征人暂别家。\n千里不辞行路远，时光早晚到天涯。' },
  { title: '杂曲歌辞 破阵乐 二', author: '不详', poem: '汉兵出顿金微，照日明光铁衣。\n百里火幡熖熖，千行云骑𬴂𬴂。\n蹙踏辽河自竭，鼓噪燕山可飞。\n正属四方朝贺，端知万舞皇威。' },
  { title: '杂曲歌辞 破阵乐 三', author: '不详', poem: '少年胆气凌云，共许骁雄出群。\n匹马城南挑战，单刀蓟北从军。\n一鼓鲜卑送欵，五饵单于解纷。\n誓欲成名报国，羞将开口论勋。' },
  { title: '杂曲歌辞 战胜乐', author: '不详', poem: '百战得功名，天兵意气生。\n三边永不战，此是我皇英。' },
  { title: '杂曲歌辞 劒南臣', author: '不详', poem: '不分君恩断，观妆视镜中。\n容华尚春日，娇爱已秋风。\n枕席临窗晓，屏帷对月空。\n年年后庭树，芳悴在深宫。' },
  { title: '杂曲歌辞 征步郎', author: '不详', poem: '塞外虏尘飞，频年度碛西。\n死生随玉劒，辛苦向金微。' },
  { title: '杂曲歌辞 [叹]疆场', author: '不详', poem: '闻道行人至，妆梳对镜台。\n泪痕犹尚在，笑靥自然开。' },
  { title: '杂曲歌辞 塞姑', author: '不详', poem: '昨日卢梅塞口，整见诸人镇守。\n都护三年不归，折尽江边杨柳。' },
  { title: '杂曲歌辞 水鼓子', author: '不详', poem: '雕弓白羽猎初回，薄夜牛羊复下来。\n梦水河边秋草合，黑山峰外阵云开。' },
  { title: '杂曲歌辞 婆罗门', author: '杨敬述进', poem: '回乐峰前沙似雪，受降城外月如霜。\n不知何处吹芦管？一夜征人尽望乡。' },
  { title: '杂曲歌辞 浣沙女 一', author: '不详', poem: '南陌春风早，东邻去日斜。\n千花开瑞锦，香扑美人车。' },
  { title: '杂曲歌辞 浣沙女 二', author: '不详', poem: '长乐青门外，宜春小苑东。\n楼开万户上，人向百花中。' },
  { title: '杂曲歌辞 镇西', author: '不详', poem: '天边物色更无春，祗有羊群与马群。\n谁家营里吹羌笛，哀怨教人不忍闻。' },
  { title: '杂曲歌辞 镇西 二', author: '不详', poem: '岁去年来拜圣朝，更无山阙对溪桥。\n九门杨柳浑无半，犹自千条与万条。' },
  { title: '杂曲歌辞 回纥', author: '不详', poem: '曾闻瀚海使难通，幽闺少妇罢裁缝。\n缅想边庭征战苦，谁能对镜治愁容。\n久戍人将老，须臾变作白头翁。' },
  { title: '杂曲歌辞 长命女', author: '不详', poem: '云送关西雨，风传渭北秋。\n孤灯然客梦，寒杵捣乡愁。' },
  { title: '杂曲歌辞 醉公子', author: '不详', poem: '昨日春园饮，今朝倒接䍠。\n谁人扶上马，不省下楼时。' },
  { title: '杂曲歌辞 一片子', author: '不详', poem: '柳色青山映，梨花雪鸟藏。\n绿窗桃李下，闲坐叹春芳。' },
  { title: '杂曲歌辞 甘州', author: '不详', poem: '欲使传消息，空书意不任。\n寄君明月镜，偏照故人心。' },
  { title: '杂曲歌辞 濮阳女', author: '不详', poem: '鴈来书不至，月照独眠房。\n贱妾多愁思，不堪秋夜长。' },
  { title: '杂曲歌辞 相府莲', author: '不详', poem: '夜闻邻妇泣，切切有余哀。\n即问缘何事，征人战未回。' },
  { title: '杂曲歌辞 蔟拍相府莲', author: '不详', poem: '莫以今时宠，宁无旧日恩。\n看花满眼泪，不共楚王言。\n闺烛无人影，罗屏有梦魂。\n近来音耗绝，终日望应门。' },
  { title: '杂曲歌辞 离别难', author: '不详', poem: '此别难重陈，花深复变人。\n来时梅覆雪，去日柳含春。\n物候催行客，归途淑气新。\n剡川今已远，魂梦暗相亲。' },
  { title: '杂曲歌辞 离别难', author: '白居易', poem: '绿杨陌上送行人，马去车回一望尘。\n不觉别时红泪尽，归来无泪可沾巾。' },
  { title: '杂曲歌辞 山鹧鸪 一', author: '不详', poem: '玉关征戍久，空闺人独愁。\n寒露湿青苔，别来蓬鬓秋。' },
  { title: '杂曲歌辞 山鹧鸪 二', author: '不详', poem: '人坐青楼晚，莺语百花时。\n愁人多自老，肠断君不知。' },
  { title: '杂曲歌辞 鹧鸪词', author: '李益', poem: '湘江斑竹枝，锦翼鹧鸪飞。\n处处湘云合，郎从何处归。' },
  { title: '杂曲歌辞 鹧鸪词 一', author: '李涉', poem: '湘江烟水深，沙岸隔枫林。\n何处鹧鸪飞？日斜斑竹阴。\n二女虚垂泪，三闾枉自沈。\n惟有鹧鸪鸟，独伤行客心。' },
  { title: '杂曲歌辞 鹧鸪词 二', author: '李涉', poem: '越冈连越井，越鸟更南飞。\n何处鹧鸪嗁，夕烟东岭归。\n岭头行人少，天涯北客稀。\n鹧鸪嗁别处，相对泪沾衣。' },
  { title: '杂曲歌辞 乐世', author: '白居易', poem: '管急丝繁拍渐稠，绿腰宛转曲终头。\n诚知乐世声声乐，老病人听未免愁。' },
  { title: '杂曲歌辞 急[乐世]', author: '白居易', poem: '正抽碧线绣红罗，忽听黄莺敛翠蛾。\n秋思冬愁春恨望，大都不得意时多。' },
  { title: '杂曲歌辞 何满子', author: '白居易', poem: '世传满子是人名，临就刑时曲始成。\n一曲四词歌八叠，从头便是断肠声。' },
  { title: '杂曲歌辞 何满子', author: '薛逢', poem: '系马宫槐老，持杯店菊黄。\n故交今不见，流恨满川光。' },
  { title: '杂曲歌辞 清平调 一', author: '李白', poem: '云想衣裳花想容，春风拂槛露华浓。\n若非群玉山头见，会向瑶台月下逢。' },
  { title: '杂曲歌辞 清平调 二', author: '李白', poem: '一枝红艳露凝香，云雨巫山枉断肠。\n借问汉宫谁得似，可怜飞燕倚新妆。' },
  { title: '杂曲歌辞 清平调 三', author: '李白', poem: '名花倾国两相欢，长得君王带笑看。\n解释春风无限恨，沈香亭北倚阑干。' },
  { title: '杂曲歌辞 回波乐', author: '李景伯', poem: '回波尔时酒巵，微臣职在箴规。\n侍宴既过三爵，諠哗窃恐非仪。' },
  { title: '杂曲歌辞 圣明乐 一', author: '张仲素', poem: '玉帛殊方至，歌钟比屋闻。\n华夷今一贯，同贺圣明君。' },
  { title: '杂曲歌辞 圣明乐 二', author: '张仲素', poem: '九陌祥烟合，千春瑞月明。\n宫花将苑柳，先发凤皇城。' },
  { title: '杂曲歌辞 圣明乐', author: '令狐楚', poem: '海浪恬丹徼，边尘静异山。\n从今万里外，不复锁萧关。' },
  { title: '杂曲歌辞 大酺乐', author: '不详', poem: '泪滴珠难尽，容残玉易销。\n傥随明月去，莫道梦魂遥。' },
  { title: '杂曲歌辞 大酺乐 一', author: '杜审言', poem: '圣后乘干日，皇明御历辰。\n紫宫初启坐，苍璧正临春。\n雷雨垂膏泽，金钱赐下人。\n诏酺欢赏徧，交泰覩惟新。' },
  { title: '杂曲歌辞 大酺乐 二', author: '杜审言', poem: '毘陵震泽九州通，士女欢娱万国同。\n伐鼓撞钟惊海上，新妆袨服照江东。\n梅花落处疑残雪，柳叶开时任好风。\n大德不官逢道泰，天长地久属年丰。' },
  { title: '杂曲歌辞 大酺乐 一', author: '张祜', poem: '车驾东来值太平，大酺三日洛阳城。\n小儿一伎竿头绝，天下传呼万岁声。' },
  { title: '杂曲歌辞 大酺乐 二', author: '张祜', poem: '紫陌酺归日欲斜，红尘开路薛王家。\n双鬟前说楼前鼓，两伎争轮好结花。' },
  { title: '杂曲歌辞 千秋乐', author: '张祜', poem: '八月平时花萼楼，万方同乐奏千秋。\n倾城人看长竿出，一伎初成赵解愁。' },
  { title: '杂曲歌辞 火凤辞 一', author: '李百药', poem: '歌声扇里出，妆影扇中轻。\n未能令掩笑，何处欲鄣声。\n知音自不惑，得念是分明。\n莫见双嚬敛，疑人含笑情。' },
  { title: '杂曲歌辞 火凤辞 二', author: '李百药', poem: '佳人靓晚妆，清唱动兰房。\n影入含风扇，声飞照日梁。\n娇嚬眉际敛，逸韵口中香。\n自有横陈分，应怜秋夜长。' },
  { title: '杂曲歌辞 热戏乐', author: '张祜', poem: '热戏争心剧火烧，铜槌暗执不相饶。\n上皇失喜宁王笑，百尺幢竿果动摇。' },
  { title: '杂曲歌辞 春莺啭', author: '张祜', poem: '兴庆池南柳未开，太真先把一枝梅。\n内人已唱春莺啭，花下傞傞软舞来。' },
  { title: '杂曲歌辞 达摩支', author: '温庭筠', poem: '捣麝成尘香不灭，拗莲作寸丝难绝。\n红泪文姬洛水春，白头苏武天山雪。\n君不见无愁高纬花漫漫，漳浦宴余清露寒。\n一旦臣僚共囚虏，欲吹羌管先汍澜。\n旧臣头鬓霜华早，可惜雄心醉中老。\n万古春归梦不归，邺城风雨连天草。' },
  { title: '杂曲歌辞 如意娘', author: '则天皇后', poem: '看朱成碧思纷纷，憔悴支离为忆君。\n不信比来长下泪，开箱验取石榴裙。' },
  { title: '杂曲歌辞 雨霖铃', author: '张祜', poem: '雨霖铃夜却归秦，犹是张徽一曲新。\n长说上皇垂泪教，月明南内更无人。' },
  { title: '杂曲歌辞 桂花曲', author: '不详', poem: '可怜天上桂花孤，试问姮娥更要无。\n月宫幸有闲田地，何不中央种两株。' },
  { title: '杂曲歌辞 渭城曲', author: '王维', poem: '谓城朝雨浥轻尘，客舍青青柳色春。\n劝君更尽一杯酒，西出阳关无故人。' },
  { title: '杂曲歌辞 竹枝', author: '顾况', poem: '帝子苍梧不复归，洞庭叶下荆云飞。\n巴人夜唱竹枝后，肠断晓猨声渐稀。' },
  { title: '杂曲歌辞 竹枝 一', author: '刘禹锡', poem: '白帝城头春草生，白盐山下蜀江清。\n南人上来歌一曲，北人莫上动乡情。' },
  { title: '杂曲歌辞 竹枝 二', author: '刘禹锡', poem: '山桃红花满上头，蜀江春水拍江流。\n花红易衰似郎意，水流无限似侬愁。' },
  { title: '杂曲歌辞 竹枝 三', author: '刘禹锡', poem: '江上朱楼新雨晴，瀼西春水縠文生。\n桥东桥西好杨柳，人来人去唱歌行。' },
  { title: '杂曲歌辞 竹枝 四', author: '刘禹锡', poem: '日出三竿春雾消，江头蜀客驻兰桡。\n凭寄狂夫书一纸，住在成都万里桥。' },
  { title: '杂曲歌辞 竹枝 五', author: '刘禹锡', poem: '两岸山花似雪开，家家春酒满银杯。\n昭君坊中多女伴，永安宫外踏青来。' },
  { title: '杂曲歌辞 竹枝 六', author: '刘禹锡', poem: '瞿塘嘈嘈十二滩，此中道路古来难。\n长恨人心不如水，等闲平地起波澜。' },
  { title: '杂曲歌辞 竹枝 七', author: '刘禹锡', poem: '巫峡苍苍烟雨时，清猨啼在最高枝。\n个里愁人肠自断，由来不是此声悲。' },
  { title: '杂曲歌辞 竹枝 八', author: '刘禹锡', poem: '城西门前滟滪堆，年年波浪不能摧。\n懊恼人心不如石，少时东去复西来。' },
  { title: '杂曲歌辞 竹枝 九', author: '刘禹锡', poem: '山上层层桃李花，云间烟火是人家。\n银钏金钗来负水，长刀短笠去烧畬。' },
  { title: '杂曲歌辞 竹枝 一', author: '白居易', poem: '瞿塘峡口冷烟低，白帝城头月向西。\n唱到竹枝声咽处，寒猨晴鸟一时啼。' },
  { title: '杂曲歌辞 竹枝 二', author: '白居易', poem: '竹枝苦怨怨何人，夜静山空歇又闻。\n蛮儿巴女齐声唱，愁杀江楼病使君。' },
  { title: '杂曲歌辞 竹枝 三', author: '白居易', poem: '巴东船舫上巴西，波面风生雨脚齐。\n水蓼冷花红蔟蔟，江蓠湿叶碧萋萋。' },
  { title: '杂曲歌辞 竹枝 四', author: '白居易', poem: '江畔谁人唱竹枝，前声断咽后声迟。\n怪来调苦缘词苦，多是通州司马诗。' },
  { title: '杂曲歌辞 竹枝 一', author: '李涉', poem: '荆门滩急水潺潺，两岸猨啼烟满山。\n渡头年少应官去，月落西陵望不还。' },
  { title: '杂曲歌辞 竹枝 二', author: '李涉', poem: '巫峡云开神女祠，绿潭红树影参差。\n下牢戍口初相问，无义滩头剩别离。' },
  { title: '杂曲歌辞 竹枝 三', author: '李涉', poem: '石壁千重树万重，白云斜掩碧芙蓉。\n昭君溪上年年月，独自婵娟色最浓。' },
  { title: '杂曲歌辞 竹枝 四', author: '李涉', poem: '十二峰头月欲低，空蒙江上子规啼。\n孤舟一夜东归客，泣向春风忆建溪。' },
  { title: '杂曲歌辞 竹枝 一', author: '孙光宪', poem: '门前春水白苹花，岸上无人小艇斜。\n商女经过江欲暮，散抛残食饲神雅。' },
  { title: '杂曲歌辞 竹枝 二', author: '孙光宪', poem: '乱绳千结绊人深，越罗万丈表长寻。\n杨柳在身垂意绪，藕花落尽见莲心。' },
  { title: '杂曲歌辞 杨柳枝 一', author: '白居易', poem: '一树春风万万枝，嫩于金色软于丝。\n永丰西角荒园里，尽日无人属阿谁。' },
  { title: '杂曲歌辞 杨柳枝 二', author: '白居易', poem: '一树衰残委泥土，双枝荣耀植天庭。\n定知玄象今春后，柳宿光中添两星。' },
  { title: '杂曲歌辞 杨柳枝 三', author: '白居易', poem: '依依袅袅复青青，句引清风无限情。\n白雪花繁空扑地，绿丝条弱不胜莺。' },
  { title: '杂曲歌辞 杨柳枝 四', author: '白居易', poem: '红板江桥青酒旗，馆娃宫暖日斜时。\n可怜雨歇东风定，万树千条各自垂。' },
  { title: '杂曲歌辞 杨柳枝 五', author: '白居易', poem: '苏州杨柳任君夸，更有钱塘胜馆娃。\n若解多情寻小小，绿杨深处是苏家。' },
  { title: '杂曲歌辞 杨柳枝 六', author: '白居易', poem: '苏家小女旧知名，杨柳风前别有情。\n剥条盘作银环样，卷叶吹为玉笛声。' },
  { title: '杂曲歌辞 杨柳枝 七', author: '白居易', poem: '叶含浓露如啼眼，枝袅轻风似舞腰。\n小树不禁攀折苦，乞君留取两三条。' },
  { title: '杂曲歌辞 杨柳枝 八', author: '白居易', poem: '人言柳叶似愁眉，更有愁肠似柳丝。\n柳丝挽断肠牵断，彼此应无续得期。' },
  { title: '杂曲歌辞 杨柳枝', author: '卢贞', poem: '一树依依在永丰，两枝飞去杳无踪。\n玉皇曾采人间曲，应逐歌声入九重。' },
  { title: '杂曲歌辞 杨柳枝 一', author: '刘禹锡', poem: '塞北梅花羌笛吹，淮南桂树小山词。\n请君莫奏前朝曲，听唱新翻杨柳枝。' },
  { title: '杂曲歌辞 杨柳枝 二', author: '刘禹锡', poem: '南陌东城春早时，相逢何处不依依。\n桃红李白皆夸好，须得垂杨相发辉。' },
  { title: '杂曲歌辞 杨柳枝 三', author: '刘禹锡', poem: '凤阙轻遮翡翠帷，龙墀遥望曲尘丝。\n御沟春水柳晖映，狂杀长安年少儿。' },
  { title: '杂曲歌辞 杨柳枝 四', author: '刘禹锡', poem: '金谷园中莺乱飞，铜驼陌上好风吹。\n城东桃李须臾尽，争似垂杨无限时。' },
  { title: '杂曲歌辞 杨柳枝 五', author: '刘禹锡', poem: '花萼楼前初种时，美人楼上鬬腰支。\n如今抛掷上街里，露叶如啼欲恨谁。' },
  { title: '杂曲歌辞 杨柳枝 六', author: '刘禹锡', poem: '炀帝行宫汴水滨，数株残柳不胜春。\n昨来风起花如雪，飞入宫墙不见人。' },
  { title: '杂曲歌辞 杨柳枝 七', author: '刘禹锡', poem: '御陌青门拂地垂，千条金缕万条丝。\n如今绾作同心结，将赠行人知不知。' },
  { title: '杂曲歌辞 杨柳枝 八', author: '刘禹锡', poem: '城外春风满酒旗，行人挥袂日西时。\n长安陌上无穷树，唯有垂杨管别离。' },
  { title: '杂曲歌辞 杨柳枝 九', author: '刘禹锡', poem: '轻盈袅娜占春华，舞榭妆楼处处遮。\n春尽絮飞留不得，随风好去落谁家。' },
  { title: '杂曲歌辞 杨柳枝 一', author: '李商隐', poem: '暂凭樽酒送无憀，莫损愁眉与细腰。\n人世死前唯有别，春风争拟惜长条。' },
  { title: '杂曲歌辞 杨柳枝 二', author: '李商隐', poem: '含烟惹雾每依依，万绪千条拂落晖。\n为报行人休尽折，半留相送半迎归。' },
  { title: '杂曲歌辞 杨柳枝', author: '韩琮', poem: '梁苑隋堤事已空，万条犹舞旧春风。\n那堪更想千年后，谁见杨花入汉宫。' },
  { title: '杂曲歌辞 杨柳枝', author: '施肩吾', poem: '伤见路傍杨柳春，一枝折尽一重新。\n今年还折去年处，不送去年离别人。' },
  { title: '杂曲歌辞 杨柳枝 一', author: '温庭筠', poem: '宜春苑外最长条，闲袅春风伴舞腰。\n正是玉人肠断处，一渠春水赤栏桥。' },
  { title: '杂曲歌辞 杨柳枝 二', author: '温庭筠', poem: '南内墙东御路傍，预知春色柳丝黄。\n杏花未肯无情思，何事情人最断肠。' },
  { title: '杂曲歌辞 杨柳枝 三', author: '温庭筠', poem: '苏小门前柳万条，毵毵金线拂平桥。\n黄莺不语东风起，深闭朱门伴细腰。' },
  { title: '杂曲歌辞 杨柳枝 四', author: '温庭筠', poem: '金缕毵毵碧瓦沟，六宫眉黛惹春愁。\n晚来更带龙池雨，半拂栏干半入楼。' },
  { title: '杂曲歌辞 杨柳枝 五', author: '温庭筠', poem: '馆娃宫外邺城西，远映征帆近拂堤。\n系得王孙归意切，不关春草绿萋萋。' },
  { title: '杂曲歌辞 杨柳枝 六', author: '温庭筠', poem: '两两黄鹂色似金，袅枝啼露动芳音。\n春来幸自长如线，可惜牵缠荡子心。' },
  { title: '杂曲歌辞 杨柳枝 七', author: '温庭筠', poem: '御柳如丝映九重，凤凰窗柱绣芙蓉。\n景阳楼伴千条露，一面新妆待晓钟。' },
  { title: '杂曲歌辞 杨柳枝 八', author: '温庭筠', poem: '织锦机边莺语频，停梭垂泪忆征人。\n塞门三月犹萧索，纵有垂杨未觉春。' },
  { title: '杂曲歌辞 杨柳枝 一', author: '皇甫松', poem: '春入行宫映翠微，玄宗侍女舞烟丝。\n如今柳向空城绿，玉笛何人更把吹。' },
  { title: '杂曲歌辞 杨柳枝 二', author: '皇甫松', poem: '烂熳春归水国时，吴王宫殿柳垂丝。\n黄莺长呌空闺畔，西子无因更得知。' },
  { title: '杂曲歌辞 杨柳枝 一', author: '僧齐己', poem: '凤楼高映绿阴阴，凝碧多含雨露深。\n莫谓一枝柔软力，几曾牵破别离心。' },
  { title: '杂曲歌辞 杨柳枝 二', author: '僧齐己', poem: '馆娃宫畔响廊前，依托吴王养翠烟。\n劒去国亡台榭毁，却随红树噪秋蝉。' },
  { title: '杂曲歌辞 杨柳枝 三', author: '僧齐己', poem: '秾低似中陶潜酒，软极如伤宋玉风。\n多谢将军遶营种，翠中闲卓战旗红。' },
  { title: '杂曲歌辞 杨柳枝 四', author: '僧齐己', poem: '高僧爱惜遮江寺，游子伤残露野桥。\n争似着行垂上苑，碧桃红杏对摇摇。' },
  { title: '杂曲歌辞 杨柳枝 一', author: '张祜', poem: '莫折宫前杨柳枝，玄宗曾向笛中吹。\n伤心日暮烟霞起，无限春愁生翠眉。' },
  { title: '杂曲歌辞 杨柳枝 二', author: '张祜', poem: '凝碧池边敛翠眉，景阳台下绾青丝。\n那胜妃子朝元阁，玉手和烟弄一枝。' },
  { title: '杂曲歌辞 杨柳枝 一', author: '孙鲂', poem: '灵和风暖太昌春，舞线摇丝向昔人。\n何似晓来江雨后，一行如画隔遥津。' },
  { title: '杂曲歌辞 杨柳枝 二', author: '孙鲂', poem: '彭泽初栽五树时，只应闲看一枝枝。\n不知天意风流处，要与佳人学画眉。' },
  { title: '杂曲歌辞 杨柳枝 三', author: '孙鲂', poem: '暖傍离亭静拂桥，入流穿槛绿摇摇。\n不知落日谁相送，魂断千条与万条。' },
  { title: '杂曲歌辞 杨柳枝 四', author: '孙鲂', poem: '春来绿树遍天涯，未见垂杨未可夸。\n晴日万株烟一阵，闲坊兼是莫愁家。' },
  { title: '杂曲歌辞 杨柳枝 五', author: '孙鲂', poem: '十首当年有旧词，唱青歌翠几无遗。\n未曾得向行人道，不为离情莫折伊。' },
  { title: '杂曲歌辞 杨柳枝 一', author: '薛能', poem: '华清高树出离宫，南陌柔条带暖风。\n谁见轻阴是良夜，瀑泉声畔月明中。' },
  { title: '杂曲歌辞 杨柳枝 二', author: '薛能', poem: '洛桥晴影覆江船，羌笛秋声湿塞烟。\n闲想习池公宴罢，水蒲风絮夕阳天。' },
  { title: '杂曲歌辞 杨柳枝 三', author: '薛能', poem: '嫩绿轻悬似缀旒，路人遥见隔宫楼。\n谁能更近丹墀种，解播皇风入九州。' },
  { title: '杂曲歌辞 杨柳枝 四', author: '薛能', poem: '暖风晴日断浮埃，废路新条发钓台。\n处处轻轻可惆怅，后人攀处古人栽。' },
  { title: '杂曲歌辞 杨柳枝 五', author: '薛能', poem: '潭上江边袅袅垂，日高风静絮相随。\n青楼一树无人见，正是女郎眠觉时。' },
  { title: '杂曲歌辞 杨柳枝 六', author: '薛能', poem: '汴水高悬百万条，风清两岸一时摇。\n隋家力尽虚栽得，无限春风属圣朝。' },
  { title: '杂曲歌辞 杨柳枝 七', author: '薛能', poem: '和花烟树九重城，夹路春阴十万营。\n唯向边头不堪望，一株顦顇少人行。' },
  { title: '杂曲歌辞 杨柳枝 八', author: '薛能', poem: '窗外齐垂旭日初，楼边轻好暖风徐。\n游人莫道栽无益，桃李清阴却不如。' },
  { title: '杂曲歌辞 杨柳枝 九', author: '薛能', poem: '众木犹寒独早青，御沟桥畔曲江亭。\n陶家旧日应如此，一院春条绿遶厅。' },
  { title: '杂曲歌辞 杨柳枝 十', author: '薛能', poem: '帐偃缨垂细复繁，令人心想石家园。\n风条月影皆堪重，何事侯门爱树萱。' },
  { title: '杂曲歌辞 杨柳枝 一', author: '牛峤', poem: '解冻风来末上青，解垂罗袖拜卿卿。\n无端袅娜临官路，舞送行人过一生。' },
  { title: '杂曲歌辞 杨柳枝 二', author: '牛峤', poem: '吴王宫里色偏深，一簇纤条万缕金。\n不愤钱塘苏小小，引郎枝下结同心。' },
  { title: '杂曲歌辞 杨柳枝 三', author: '牛峤', poem: '桥北桥南千万条，恨伊张绪不相饶。\n金羁白马临风望，认得羊家静婉腰。' },
  { title: '杂曲歌辞 杨柳枝 四', author: '牛峤', poem: '狂雪随风扑马飞，惹烟无力被风欹。\n莫交移入灵和殿，宫女三千又妒伊。' },
  { title: '杂曲歌辞 杨柳枝 五', author: '牛峤', poem: '袅翠笼烟拂暖波，舞裙新染曲尘罗。\n章华台畔隋堤上，倚得春风尔许多。' },
  { title: '杂曲歌辞 杨柳枝 一', author: '和凝', poem: '软碧摇烟似送人，映花时把翠眉嚬。\n青青自是风流主，漫飐金丝待洛神。' },
  { title: '杂曲歌辞 杨柳枝 二', author: '和凝', poem: '瑟瑟罗裙金缕腰，黛眉偎破未重描。\n醉来咬损新花子，拽住仙郎尽放娇。' },
  { title: '杂曲歌辞 杨柳枝 三', author: '和凝', poem: '鹊桥初就咽银河，今夜仙郎自性和。\n不是昔年攀桂树，岂能月里索姮娥。' },
  { title: '杂曲歌辞 杨柳枝 一', author: '孙光宪', poem: '闾门风暖落花干，飞遍江南雪不寒。\n独有晚来临水驿，闲人多凭赤阑干。' },
  { title: '杂曲歌辞 杨柳枝 二', author: '孙光宪', poem: '有池有榭即蒙蒙，浸润翻成长养功。\n恰似有人长点检，着行排立向春风。' },
  { title: '杂曲歌辞 杨柳枝 三', author: '孙光宪', poem: '根柢虽然傍浊河，无妨终日近笙歌。\n骖骖金带谁堪比，还笑黄莺不较多。' },
  { title: '杂曲歌辞 杨柳枝 四', author: '孙光宪', poem: '万株枯槁怨亡隋，似吊吴台各自垂。\n好是淮阴明月里，酒楼横笛不胜吹。' },
  { title: '杂曲歌辞 浪淘沙 一', author: '刘禹锡', poem: '九曲黄河万里沙，浪淘风簸自天涯。\n如今直上银河去，同到牵牛织女家。' },
  { title: '杂曲歌辞 浪淘沙 二', author: '刘禹锡', poem: '洛水桥边春日斜，碧流轻浅见琼沙。\n无端陌上狂风急，惊起鸳鸯出浪花。' },
  { title: '杂曲歌辞 浪淘沙 三', author: '刘禹锡', poem: '汴水东流虎眼文，清淮晓色鸭头春。\n君看渡口淘沙处，渡却人间多少人。' },
  { title: '杂曲歌辞 浪淘沙 四', author: '刘禹锡', poem: '鹦鹉洲头浪飐沙，青楼春望日将斜。\n衔泥燕子争归舍，独自狂夫不忆家。' },
  { title: '杂曲歌辞 浪淘沙 五', author: '刘禹锡', poem: '濯锦江边两岸花，春风吹浪正淘沙。\n女郎剪下鸳鸯锦，将向中流疋晚霞。' },
  { title: '杂曲歌辞 浪淘沙 六', author: '刘禹锡', poem: '日照澄洲江雾开，淘金女伴满江隈。\n美人首饰侯王印，尽是沙中浪底来。' },
  { title: '杂曲歌辞 浪淘沙 七', author: '刘禹锡', poem: '八月涛声吼地来，头高数丈触山回。\n须臾却入海门去，卷起沙堆似雪堆。' },
  { title: '杂曲歌辞 浪淘沙 八', author: '刘禹锡', poem: '莫道谗言如浪深，莫言迁客似沙沈。\n千淘万漉虽辛苦，吹尽狂沙始到金。' },
  { title: '杂曲歌辞 浪淘沙 九', author: '刘禹锡', poem: '流水淘沙不暂停，前波未灭后波生。\n令人忽忆潇湘渚，回唱迎神三两声。' },
  { title: '杂曲歌辞 浪淘沙 一', author: '白居易', poem: '一泊沙来一泊去，一重浪灭一重生。\n相搅相淘无歇日，会交山海一时平。' },
  { title: '杂曲歌辞 浪淘沙 二', author: '白居易', poem: '白浪茫茫与海连，平沙浩浩四无边。\n暮去朝来淘不住，遂令东海变桑田。' },
  { title: '杂曲歌辞 浪淘沙 三', author: '白居易', poem: '青草湖中万里程，黄梅雨里一人行。\n愁见滩头夜泊处，风翻暗浪打船声。' },
  { title: '杂曲歌辞 浪淘沙 四', author: '白居易', poem: '借问江湖与海水，何似君情与妾心。\n相恨不如潮有信，相思始觉海非深。' },
  { title: '杂曲歌辞 浪淘沙 五', author: '白居易', poem: '海底飞尘终有日，山头化石岂无时。\n谁道小郎抛小妇，船头一去没回期。' },
  { title: '杂曲歌辞 浪淘沙 六', author: '白居易', poem: '随波逐浪到天涯，迁客生还有几家。\n却到帝乡重富贵，请君莫忘浪淘沙。' },
  { title: '杂曲歌辞 浪淘沙 一', author: '皇甫松', poem: '滩头细草接疎林，浪恶罾船半欲沈。\n宿鹭眠洲非旧浦，去年沙觜是江心。' },
  { title: '杂曲歌辞 浪淘沙 二', author: '皇甫松', poem: '蛮歌豆蔻北人愁，松雨蒲风夜艇秋。\n浪起䴔䴖眠不得，寒沙细细入江流。' },
  { title: '杂曲歌辞 纥那曲 一', author: '刘禹锡', poem: '杨柳郁青青，竹枝无限情。\n同郎一回顾，听唱纥那声。' },
  { title: '杂曲歌辞 纥那曲 二', author: '刘禹锡', poem: '踏曲兴无穷，调同词不同。\n愿郎千万寿，长作主人翁。' },
  { title: '杂曲歌辞 潇湘神二曲 一', author: '刘禹锡', poem: '湘水流，湘水流，九疑云物至今愁。\n君问二妃何处所？零陵香草露中秋。' },
  { title: '杂曲歌辞 潇湘神二曲 二', author: '刘禹锡', poem: '斑竹枝，斑竹枝，泪痕点点寄相思。\n楚客欲听瑶瑟怨，潇湘深夜月明时。' },
  { title: '杂曲歌辞 抛毬乐 一', author: '刘禹锡', poem: '五彩绣团团，登君玳瑁筵。\n最宜红烛下，偏称落花前。\n上客如先起，应须赠一船。' },
  { title: '杂曲歌辞 抛毬乐 二', author: '刘禹锡', poem: '春早见花枝，朝朝恨发迟。\n及看花落后，却忆未开时。\n幸有抛毬乐，一杯君莫辞。' },
  { title: '杂曲歌辞 太平乐 一', author: '白居易', poem: '岁丰仍节俭，时泰更销兵。\n圣念长如此，何忧不太平。' },
  { title: '杂曲歌辞 太平乐 二', author: '白居易', poem: '湛露浮尧酒，薰风起舜歌。\n愿同尧舜意，所乐在人和。' },
  { title: '杂曲歌辞 太平乐', author: '王涯', poem: '风俗今和厚，君王在穆清。\n行看采花曲，尽是太阶平。' },
  { title: '杂曲歌辞 太平乐', author: '张仲素', poem: '圣德超千古，皇威静四方。\n苍生今息战，无事觉时长。' },
  { title: '杂曲歌辞 升平乐 一', author: '薛能', poem: '正气遶宫楼，皇居信上游。\n远冈延圣祚，平地载神州。\n会合皆重译，潺湲近八流。\n中兴岂假问，据此自千秋。' },
  { title: '杂曲歌辞 升平乐 二', author: '薛能', poem: '寥泬敞延英，朝班立位横。\n宣传无草动，拜舞有衣声。\n鸳瓦云消湿，虫丝日照明。\n辛勤自不到，遥见似前生。' },
  { title: '杂曲歌辞 升平乐 三', author: '薛能', poem: '处处足欢声，时康岁已深。\n不同三尺劒，应似五弦琴。\n寿笑山犹尽，明嫌日有阴。\n何当怜一物，亦遣断愁吟。' },
  { title: '杂曲歌辞 升平乐 四', author: '薛能', poem: '曙质绝埃氛，彤庭列禁军。\n圣颜初对日，龙尾竞缘云。\n珮响交成韵，帘阴暖带纹。\n逍遥岂有事，于此咏南薰。' },
  { title: '杂曲歌辞 升平乐 五', author: '薛能', poem: '一物周天至，洪纤尽晏然。\n车书无异俗，甲子竝丰年。\n奇技皆归朴，征夫亦服田。\n君王故不有，台鼎合韦弦。' },
  { title: '杂曲歌辞 升平乐 六', author: '薛能', poem: '日日听歌谣，区中尽祝尧。\n虫蝗初不害，夷狄近全销。\n史笔唯书瑞，天台绝见祆。\n因令匹夫志，转欲事清朝。' },
  { title: '杂曲歌辞 升平乐 七', author: '薛能', poem: '品物尽昭苏，神功复帝谟。\n他时应有寿，当代且无虞。\n赐历通遐俗，移关入半胡。\n鹪鹩一何幸，于此寄微躯。' },
  { title: '杂曲歌辞 升平乐 八', author: '薛能', poem: '无战复无私，尧时即此时。\n焚香临极早，待月卷帘迟。\n端拱乾坤内，何言黈纩垂。\n君看圣明验，只此是神龟。' },
  { title: '杂曲歌辞 升平乐 九', author: '薛能', poem: '旭日上清穹，明堂坐圣聪。\n衣裳承瑞气，冠冕盖重曈。\n花木经宵露，旌旗立仗风。\n何期于此地，见说似仙宫。' },
  { title: '杂曲歌辞 升平乐 十', author: '薛能', poem: '五帝三皇主，萧曹魏邴臣。\n文章惟反朴，戈甲尽生尘。\n谏纸应无用，朝纲自有伦。\n升平不可纪，所见是闲人。' },
  { title: '杂曲歌辞 金缕衣', author: '不详', poem: '劝君莫惜金缕衣，劝君惜取少年时。\n花开堪折直须折，莫待无花空折枝。' },
  { title: '杂曲歌辞 凤归云 一', author: '滕潜', poem: '金井栏边见羽仪，梧桐树上宿寒枝。\n五陵公子怜文彩，画与佳人刺绣衣。' },
  { title: '杂曲歌辞 凤归云 二', author: '滕潜', poem: '饮啄蓬山最上头，和烟飞下禁城秋。\n曾将弄玉归云去，金翿斜开十二楼。' },
  { title: '杂曲歌辞 拜新月', author: '李端', poem: '开帘见新月，便即下阶拜。\n细语人不闻，北风吹裙带。' },
  { title: '杂曲歌辞 拜新月', author: '吉中孚妻张氏', poem: '拜新月，拜月出堂前。\n暗魄深笼桂，虚弓未引弦。\n拜新月，拜月妆楼上。\n鸾镜未安台，蛾眉已相向。\n拜新月，拜月不胜情，庭前风露清。\n月临人自老，望月更长生。\n东家阿母亦拜月，一拜一悲声断绝。\n昔年拜月逞容仪，如今拜月双泪垂。\n回看众女拜新月，却忆红闺年少时。' },
  { title: '杂曲歌辞 忆江南 三', author: '白居易', poem: '江南忆，其次忆吴宫。\n吴酒一杯春竹叶，吴娃双舞醉芙蓉，早晚复相逢。' },
  { title: '杂曲歌辞 忆江南 一', author: '刘禹锡', poem: '春过也，共惜艳阳年。\n犹有桃花流水上，无辞竹叶醉樽前，惟待见青天。' },
  { title: '杂曲歌辞 忆江南 二', author: '刘禹锡', poem: '春去也，多谢洛城人。\n弱柳从风疑举袂，丛兰裛露似沾巾，独笑亦含嚬。' },
  { title: '杂曲歌辞 宫中调笑 一', author: '王建', poem: '团扇，团扇，美人病来遮面。\n玉颜憔悴三年，谁复商量管弦。\n弦管，弦管，春草昭阳路断。' },
  { title: '杂曲歌辞 宫中调笑 二', author: '王建', poem: '胡蝶，胡蝶，飞上金花枝叶。\n君前对舞春风，百叶桃花树红。\n红树，红树，燕语莺啼日暮。' },
  { title: '杂曲歌辞 宫中调笑 三', author: '王建', poem: '罗袖，罗袖，暗舞春风依旧。\n遥看歌舞玉楼，好日新妆坐愁。\n愁坐，愁坐，一世虚生虚过。' },
  { title: '杂曲歌辞 宫中调笑 四', author: '王建', poem: '杨柳，杨柳，日暮白沙渡口。\n船头江水茫茫，商人少妇断肠。\n肠断，肠断，鹧鸪夜飞失伴。' },
  { title: '杂曲歌辞 宫中调笑 一', author: '韦应物', poem: '胡马，胡马，远放燕支山下。\n咆沙咆雪独嘶，东望西望路迷。\n迷路，迷路，边草无穷日暮。' },
  { title: '杂曲歌辞 宫中调笑 二', author: '韦应物', poem: '河汉，河汉，晓挂秋城漫漫。\n愁人起望相思，江南塞北别离。\n离别，离别，河汉虽同路绝。' },
  { title: '杂曲歌辞 转应词', author: '戴叔伦', poem: '边草，边草，边草尽来兵老。\n山南山北雪晴，千里万里月明。\n明月，明月，胡笳一声愁绝。' },
  { title: '杂曲歌辞 宫中行乐词 一', author: '李白', poem: '小小生金屋，盈盈在紫微。\n山花插宝髻，石竹绣罗衣。\n每出深宫里，常随步辇归。\n只愁歌舞散，化作彩云飞。' },
  { title: '杂曲歌辞 宫中行乐词 二', author: '李白', poem: '柳色黄金嫩，梨花白雪香。\n玉楼巢翡翠，金殿锁鸳鸯。\n选妓随雕辇，征歌出洞房。\n宫中谁第一，飞燕在昭阳。' },
  { title: '杂曲歌辞 宫中行乐词 三', author: '李白', poem: '卢橘为秦树，蒲萄出汉宫。\n烟花宜落日，丝管醉春风。\n笛奏龙鸣水，箫吟凤下空。\n君王多乐事，何必向回中。' },
  { title: '杂曲歌辞 宫中行乐词 四', author: '李白', poem: '玉树春归日，金宫乐事多。\n后庭朝未入，轻辇夜相过。\n笑出花间语，娇来烛下歌。\n莫教明月去，留着醉姮娥。' },
  { title: '杂曲歌辞 宫中行乐词 五', author: '李白', poem: '绣户香风暖，纱窗曙色新。\n宫花争笑日，池草暗生春。\n绿树闻歌鸟，青楼见舞人。\n昭阳桃李月，罗绮自相亲。' },
  { title: '杂曲歌辞 宫中行乐词 六', author: '李白', poem: '今日明光里，还须结伴游。\n春风开紫殿，天乐下珠楼。\n艳舞全知巧，娇歌半欲羞。\n更怜花月夜，宫女笑藏钩。' },
  { title: '杂曲歌辞 宫中行乐词 七', author: '李白', poem: '寒雪梅中尽，春风柳上归。\n宫莺娇欲醉，檐燕语还飞。\n迟日明歌席，新花艳舞衣。\n晚来移彩仗，行乐泥光辉。' },
  { title: '杂曲歌辞 宫中行乐词 八', author: '李白', poem: '水绿南薰殿，花红北阙楼。\n莺歌闻太液，凤吹遶瀛洲。\n素女鸣珠佩，天人弄彩毬。\n今朝风日好，宜入未央游。' },
  { title: '杂曲歌辞 宫中乐 一', author: '令狐楚', poem: '楚塞金陵静，巴山玉垒空。\n万方无一事，端拱大明宫。' },
  { title: '杂曲歌辞 宫中乐 二', author: '令狐楚', poem: '霜霁长杨苑，冰开太液池。\n宫中行乐日，天下盛明时。' },
  { title: '杂曲歌辞 宫中乐 三', author: '令狐楚', poem: '柳色烟相似，梨花雪不如。\n春风真有意，一一丽皇居。' },
  { title: '杂曲歌辞 宫中乐 四', author: '令狐楚', poem: '月上宫花静，烟含苑树深。\n银台门已闭，仙漏夜沈沈。' },
  { title: '杂曲歌辞 宫中乐 五', author: '令狐楚', poem: '九重青锁闼，百尺碧云楼。\n明月秋风起，珠帘上玉钩。' },
  { title: '杂曲歌辞 宫中乐 一', author: '张仲素', poem: '网户交如绮，纱窗薄似烟。\n乐吹天上曲，人是月中仙。' },
  { title: '杂曲歌辞 宫中乐 二', author: '张仲素', poem: '翠匣开寒镜，珠钗挂步摇。\n妆成秖畏晓，更漏促春宵。' },
  { title: '杂曲歌辞 宫中乐 三', author: '张仲素', poem: '江果瑶池实，金盘露井冰。\n甘泉将避暑，台殿晓光凝。' },
  { title: '杂曲歌辞 宫中乐 四', author: '张仲素', poem: '月彩浮鸾殿，砧声隔凤楼。\n笙歌临水槛，红烛乍迎秋。' },
  { title: '杂曲歌辞 宫中乐 五', author: '张仲素', poem: '奇树留寒翠，神池结夕波。\n黄山一夜雪，渭水雁声多。' },
  { title: '杂曲歌辞 踏歌词 一', author: '崔液', poem: '彩女迎金屋，仙姬出画堂。\n鸳鸯裁锦袖，翡翠帖花黄。\n歌响舞分行，艳色动流光。' },
  { title: '杂曲歌辞 踏歌词 二', author: '崔液', poem: '庭际花微落，楼前汉已横。\n金壶催夜尽，罗袖拂寒轻。\n乐笑畅欢情，未半着天明。' },
  { title: '杂曲歌辞 踏歌词 一', author: '谢偃', poem: '春景娇春台，新露泣新梅。\n春叶参差吐，新花重叠开。\n花影飞莺去，歌声度鸟来。\n倩看飘飖雪，何如舞袖回。' },
  { title: '杂曲歌辞 踏歌词 二', author: '谢偃', poem: '逶迤度香阁，顾步出兰闺。\n欲遶鸳鸯殿，先过桃李蹊。\n风带舒还卷，簪花举复低。\n欲问今宵乐，但听歌声齐。' },
  { title: '杂曲歌辞 踏歌词 三', author: '谢偃', poem: '夜久星沉没，更深月影斜。\n裙轻才动佩，鬟薄不胜花。\n细风吹宝袜，轻露湿红纱。\n相看乐未已，兰灯照九华。' },
  { title: '杂曲歌辞 踏歌词 一', author: '张说', poem: '花蕚楼前雨露新，长安城里太平人。\n龙衔火树千灯艳，鸡踏莲花万岁春。' },
  { title: '杂曲歌辞 踏歌词 二', author: '张说', poem: '帝宫三五戏春台，行雨流风莫妒来。\n西域灯轮千影合，东华金阙万重开。' },
  { title: '杂曲歌辞 踏歌行 一', author: '刘禹锡', poem: '春江月出大堤平，堤上女郎连袂行。\n唱尽新词看不见，红霞影树鹧鸪鸣。' },
  { title: '杂曲歌辞 踏歌行 二', author: '刘禹锡', poem: '桃蹊柳陌好经过，灯下妆成月下歌。\n为是襄王故宫地，至今犹自细腰多。' },
  { title: '杂曲歌辞 踏歌行 三', author: '刘禹锡', poem: '新词宛转递相传，振袖倾鬟风露前。\n月落乌啼云雨散，游童陌上拾花钿。' },
  { title: '杂曲歌辞 踏歌行 四', author: '刘禹锡', poem: '日暮江头闻竹枝，南人行乐北人悲。\n自从雪里唱新曲，直至三春花尽时。' },
  { title: '杂曲歌辞 天长地久词 一', author: '卢纶', poem: '玉砌红花树，香风不敢吹。\n春光解天意，偏发殿南枝。' },
  { title: '杂曲歌辞 天长地久词 二', author: '卢纶', poem: '虹桥千步廊，半在水中央。\n天子方清暑，宫人重暮妆。' },
  { title: '杂曲歌辞 天长地久词 三', author: '卢纶', poem: '辞辇复当熊，倾心奉上宫。\n君王若看貌，甘在众妃中。' },
  { title: '杂曲歌辞 天长地久词 四', author: '卢纶', poem: '云日呈祥礼物殊，北庭生献五单于。\n塞天万里无飞鸟，可在边城用郅都。' },
  { title: '杂曲歌辞 天长地久词 五', author: '卢纶', poem: '台殿云凉风日微，君王初赐六宫衣。\n楼船罢泛归犹早，行道才人鬬射飞。' },
  { title: '杂曲歌辞 欸乃曲 一', author: '元结', poem: '偏存名迹在人间，顺俗与时未安闲。\n来谒大官兼问政，扁舟却入九疑山。' },
  { title: '杂曲歌辞 欸乃曲 二', author: '元结', poem: '湘江二月春水平，满月和风宜夜行。\n唱桡欲过平阳戍，守吏相呼问姓名。' },
  { title: '杂曲歌辞 欸乃曲 三', author: '元结', poem: '千里枫林烟雨深，无朝无暮有猨吟。\n停桡静听曲中意，好是云山韶濩音。' },
  { title: '杂曲歌辞 欸乃曲 四', author: '元结', poem: '零陵郡北湘水东，浯溪形胜满湘中。\n溪口石颠堪自逸，谁能相伴作渔翁。' },
  { title: '杂曲歌辞 欸乃曲 五', author: '元结', poem: '下泷船似入深渊，上泷船似欲升天。\n泷南始到九疑郡，应绝高人乘兴船。' },
  { title: '杂曲歌辞 十二月乐辞 正月', author: '李贺', poem: '上楼迎春新春归，暗黄着柳宫漏迟。\n薄薄淡霭弄野姿，寒绿幽泥生短丝。\n锦床晓卧玉肌冷，露脸未开对朝暝。\n官街柳带不堪折，早晚菖蒲胜绾结。' },
  { title: '杂曲歌辞 十二月乐辞 二月', author: '李贺', poem: '二月饮酒采桑津，宜男草生兰笑人。\n蒲如交劒风如薰，劳劳胡燕怨酣春。\n薇帐逗烟生绿尘，金翅峨髻愁暮云。\n沓飒起舞真珠裙，津头送别唱流水。\n酒客背寒南山死。' },
  { title: '杂曲歌辞 十二月乐辞 三月', author: '李贺', poem: '东方风来满眼春，花城柳暗愁几人，复宫深殿竹风起。\n新翠舞襟静如水，光风转蕙百余里。\n暖雾驱云扑天地，军装宫妓扫蛾浅。\n摇摇锦旗夹城暖，曲水飘香去不归。\n梨花落尽成秋苑。' },
  { title: '杂曲歌辞 十二月乐辞 四月', author: '李贺', poem: '晓凉暮凉树如盖，千山浓绿生云外。\n依微香雨青氛氲，腻叶蟠花照曲门。\n金塘闲水摇碧漪，老景沈重无惊飞，堕红残蕚暗参差。' },
  { title: '杂曲歌辞 十二月乐辞 五月', author: '李贺', poem: '雕玉押帘上，轻縠笼虚门。\n井汲铅华水，扇织鸳鸯文。\n回雪舞凉殿，甘露洗空绿。\n罗袖从徊翔，香汗沾宝粟。' },
  { title: '杂曲歌辞 十二月乐辞 六月', author: '李贺', poem: '裁生罗，伐湘竹。\n帔拂疎霜簟秋玉，炎炎红镜东方开。\n晕如车轮上徘徊，啾啾赤帝骑龙来。' },
  { title: '杂曲歌辞 十二月乐辞 七月', author: '李贺', poem: '星依云渚冷，露滴盘中圆。\n好花生木末，衰蕙愁空园。\n夜天如玉砌，池叶极青钱。\n仅厌舞衫薄，稍知花簟寒。\n晓风何拂拂，北斗光阑干。' },
  { title: '杂曲歌辞 十二月乐辞 八月', author: '李贺', poem: '孀妾怨长夜，独客梦归家。\n傍檐虫缉丝，向壁灯垂花。\n檐外月光吐，帘中树影斜。\n悠悠飞露姿，点缀池中荷。' },
  { title: '杂曲歌辞 十二月乐辞 九月', author: '李贺', poem: '离宫散萤天似水，竹黄池冷芙蓉死。\n月缀金铺光脉脉，凉苑虚庭空澹白。\n霜花飞飞风草草，翠锦斓斑满层道。\n鸡人罢唱晓珑璁，鸦啼金井下疎桐。' },
  { title: '杂曲歌辞 十二月乐辞 十月', author: '李贺', poem: '玉壶银箭稍难倾，釭花夜笑凝幽明。\n碎霜斜舞上罗幕，烛笼两行照飞阁。\n珠帷怨卧不成眠，金凤刺衣着体寒，长眉对月鬬弯环。' },
  { title: '杂曲歌辞 十二月乐辞 十一月', author: '李贺', poem: '宫城团回凛严光，白光碎碎堕琼芳。\n挝钟高饮千日酒，却天凝寒作君寿。' },
  { title: '杂曲歌辞 十二月乐辞 十二月', author: '李贺', poem: '日脚淡光红洒洒，薄霜不销桂枝下。\n依稀和气解冬严，已就长日辞长夜。' },
  { title: '杂曲歌辞 十二月乐辞 闰月', author: '李贺', poem: '帝重光，年重时，七十二候回环推。\n天官玉琯灰剩飞，今岁何长来岁迟。\n王母移桃献天子，羲氏和氏迂龙辔。' },
  { title: '杂曲歌辞 桃花行 一', author: '李峤', poem: '岁去无言忽顦顇，时来含笑吐氛氲。\n不能拥路迷仙客，故欲开蹊侍圣君。' },
  { title: '杂曲歌辞 桃花行 二', author: '李峤', poem: '绮蕚成蹊遍籞芳，红英扑地满筵香。\n莫将秋宴传王母，来比春华寿圣皇。' },
  { title: '杂曲歌辞 桃花行 三', author: '李峤', poem: '源水丛花无数开，丹跗红蕚间青梅。\n从今结子三千岁，预喜仙游复摘来。' },
  { title: '杂曲歌辞 桃花行 四', author: '李峤', poem: '桃花灼灼有光辉，无数成蹊点更飞。\n为见芳林含笑待，遂同温树不言归。' },
  { title: '杂曲歌辞 桃花行 五', author: '李峤', poem: '红蕚竞妍春苑曙，粉茸新向御筵开。\n长年愿奉西王宴，近侍慙无东朔才。' },
  { title: '杂曲歌辞 苏摩遮 一', author: '张说', poem: '摩遮本出海西胡，琉璃宝服紫髯胡。\n闻道皇恩遍宇宙，来时歌舞助欢娱。' },
  { title: '杂曲歌辞 苏摩遮 二', author: '张说', poem: '绣装帕额宝花冠，夷歌骑舞借人看。\n自能激水成阴气，不虑今年寒不寒。' },
  { title: '杂曲歌辞 苏摩遮 三', author: '张说', poem: '腊月凝阴积帝台，豪歌击鼓送寒来。\n油囊取得天河水，将添上寿万年杯。' },
  { title: '杂曲歌辞 苏摩遮 四', author: '张说', poem: '寒气宜人最可怜，故将寒水散庭前。\n惟愿圣君无限寿，长取新年续旧年。' },
  { title: '杂曲歌辞 苏摩遮 五', author: '张说', poem: '昭成皇后帝家亲，荣乐诸人不比伦。\n往日霜前花委地，今年雪后树逢春。' },
  { title: '杂曲歌辞 舞马词 一', author: '张说', poem: '万玉朝宗凤扆，千金率领龙媒。\n眄鼓凝骄躞蹀，听歌弄影徘徊。' },
  { title: '杂曲歌辞 舞马词 二', author: '张说', poem: '天禄遥征卫叔，日龙上借羲和。\n将共两骖争舞，来随八骏齐歌。' },
  { title: '杂曲歌辞 舞马词 三', author: '张说', poem: '彩旄八佾成行，时龙五色因方。\n屈膝衔杯赴节，倾心献寿无疆。' },
  { title: '杂曲歌辞 舞马词 四', author: '张说', poem: '帝皂龙驹沛艾，星兰骥子权奇。\n腾倚骧洋应节，繁骄接迹不移。' },
  { title: '杂曲歌辞 舞马词 五', author: '张说', poem: '二圣先天合德，群灵率土可封。\n击石骖驔紫燕，𪭢金顾步苍龙。' },
  { title: '杂曲歌辞 舞马词 六', author: '张说', poem: '圣君出震应箓，神马浮河献图。\n足踏天庭鼓舞，心将帝乐蜘踌。' },
  { title: '杂曲歌辞 舞马千秋万岁乐府词 一', author: '张说', poem: '金天诞圣千秋节，玉醴还分万寿觞。\n试听紫骝歌乐府，何如𫘧骥舞华冈。\n连骞势出鱼龙变，蹀躞骄生鸟兽行。\n岁岁相传指树日，翩翩来伴庆云翔。' },
  { title: '杂曲歌辞 舞马千秋万岁乐府词 二', author: '张说', poem: '圣王至德与天齐，天马来仪自海西。\n腕足齐行拜两膝，繁骄不进蹈千蹄。\n䯱髵奋鬣时蹲踏，鼓怒骧身忽上跻。\n更有衔杯终宴曲，垂头掉尾醉如泥。' },
  { title: '杂曲歌辞 舞马千秋万岁乐府词 三', author: '张说', poem: '远听明君爱逸才，玉鞭金翅引龙媒。\n不因兹白人间有，定是飞黄天上来。\n影弄日华相照耀，喷含云色且徘徊。\n莫言阙下桃花舞，别有河中兰叶开。' },
  { title: '杂曲歌辞 小曲新词 一', author: '白居易', poem: '霁色鲜宫殿，秋声脆管弦。\n圣明千岁乐，岁岁似今年。' },
  { title: '杂曲歌辞 小曲新词 二', author: '白居易', poem: '红裙明月夜，碧殿早秋时。\n好向昭阳宿，天凉玉漏迟。' },
  { title: '杂曲歌辞 闺怨词 一', author: '白居易', poem: '朝憎莺百啭，夜妒燕双栖。\n不惯经春别，谁知到晓啼。' },
  { title: '杂曲歌辞 闺怨词 二', author: '白居易', poem: '珠箔笼寒月，纱窗背晓灯。\n夜来巾上泪，一半是春冰。' },
  { title: '杂曲歌辞 闺怨词 三', author: '白居易', poem: '关山征戍远，闺阁别离难。\n苦战应顦顇，寒衣不要宽。' },
  { title: '杂曲歌辞 皇帝感词 一', author: '卢纶', poem: '提劒云雷动，垂衣日月明。\n禁花呈瑞色，国老见星精。\n发棹鱼先跃，窥巢鸟不惊。\n山呼一万岁，直入九重城。' },
  { title: '杂曲歌辞 皇帝感词 二', author: '卢纶', poem: '天衣五凤彩，御马六龙文。\n雨露清驰道，风雷翊上军。\n高旍花外转，行漏乐前闻。\n时见金鞭举，空中指瑞云。' },
  { title: '杂曲歌辞 皇帝感词 三', author: '卢纶', poem: '妙算干戈止，神谋宇宙清。\n两阶文物盛，七德武功成。\n校猎长杨苑，屯军细柳营。\n归来献明主，歌舞隘春城。' },
  { title: '杂曲歌辞 皇帝感词 四', author: '卢纶', poem: '天乐下天中，云𫐌俨在空。\n铅黄艳河汉，语笑合笙镛。\n已见长随凤，仍闻不避熊。\n君王亲试舞，阊阖静无风。' },
  { title: '杂歌谣辞 渔父歌 一', author: '张志和', poem: '西塞山边白鹭飞，桃花流水鳜鱼肥。\n青箬笠，绿蓑衣，春江细雨不须归。' },
  { title: '杂歌谣辞 渔父歌 二', author: '张志和', poem: '钓台渔父褐为裘，两两三三舴艋舟。\n能纵棹，惯乘流，长江白浪不曾忧。' },
  { title: '杂歌谣辞 渔父歌 三', author: '张志和', poem: '霅溪湾里钓渔翁，舴艋为家西复东。\n江上雪，浦边风，笑着荷衣不叹穷。' },
  { title: '杂歌谣辞 渔父歌 四', author: '张志和', poem: '松江蟹舍主人欢，菰饭莼羹亦共餐。\n枫叶落，荻花干，醉宿渔舟不觉寒。' },
  { title: '杂歌谣辞 渔父歌 五', author: '张志和', poem: '青草湖中月正圆，巴陵渔父棹歌连。\n钓车子，掘头船，乐在风波不用仙。' },
  { title: '杂歌谣辞 渔父歌', author: '和凝', poem: '白芷汀寒立鹭[鸶]，苹风轻翦浪花时。\n烟幂幂，日迟迟，香引芙蓉惹钓丝。' },
  { title: '杂歌谣辞 渔父歌', author: '欧阳炯', poem: '风浩寒溪照胆明，小君山上玉蟾生。\n荷露坠，翠烟轻，拨[拉]游鱼几处惊。' },
  { title: '杂歌谣辞 渔父歌 一', author: '李珣', poem: '水接衡门十里余，信船归去卧看书。\n轻爵禄，慕玄虚，莫道渔人只为鱼。' },
  { title: '杂歌谣辞 渔父歌 二', author: '李珣', poem: '避世垂纶不记年，官高争得似君闲。\n倾白酒，对青山，笑指柴门待月还。' },
  { title: '杂歌谣辞 渔父歌 三', author: '李珣', poem: '棹警鸥飞水溅袍，影侵潭面柳垂绦。\n终日醉，绝尘劳，曾见钱塘八月涛。' },
  { title: '杂歌谣辞 鸡鸣曲', author: '王建', poem: '鸡初鸣，明星照东屋。\n鸡再鸣，红霞生海腹。\n百官待漏双阙前，圣人亦挂山龙服。\n宝钗命妇灯下起，环珮玲珑晓光里。\n直内初烧玉[案]香，司更尚滴铜壶水。\n金吾卫里直郎妻，到明不睡听晨鸡。\n天头日月相送迎，夜栖旦鸣人不迷。' },
  { title: '杂歌谣辞 鸡鸣曲', author: '李廓', poem: '星稀月没上五更，胶胶角角鸡初鸣。\n征人牵马出门立，辞妾欲向安西行。\n再鸣引颈檐头下，月中角声催上马。\n才分地色第三鸣，旌旗红尘已出城。\n妇人上城乱招手，夫壻不闻遥哭声。\n长恨鸡鸣别时苦，不遣鸡栖近窗户。' },
  { title: '杂歌谣辞 吴楚歌', author: '张籍', poem: '庭前春鸟啄林声，红夹罗襦缝未成。\n今朝社日停针线，起向朱樱树下行。' },
  { title: '杂歌谣辞 李夫人歌 一', author: '李商隐', poem: '一带不结心，两股方安髻。\n慙愧白茅人，月没教星替。' },
  { title: '杂歌谣辞 李夫人歌 二', author: '李商隐', poem: '剩结茱萸枝，多擘秋莲的。\n独自有波光，彩囊盛不得。' },
  { title: '杂歌谣辞 李夫人歌 三', author: '李商隐', poem: '蛮丝系条脱，妍眼和香屑。\n寿宫不惜铸南人，柔肠早被秋波割。\n清澄有余幽素香，鳏鱼渴凤真珠房。\n不知瘦骨类冰井，更许夜帘通晓霜。\n土花漠碧云[茫茫]，黄河欲尽天苍黄。' },
  { title: '杂歌谣辞 李夫人歌', author: '李贺', poem: '紫皇宫殿重重开，夫人飞入琼瑶台。\n绿香绣帐何时歇，青云无光宫水咽。\n翩联桂花坠秋月，孤鸾惊啼商丝发。\n红璧阑珊悬佩珰，歌台小妓遥相望。\n玉蟾滴水鸡人唱，露华兰叶参差光。' },
  { title: '杂歌谣辞 李夫人歌', author: '鲍溶', poem: '璇闺羽帐华烛陈，方士夜降夫人神。\n葳蕤半露芙蓉色，窈窕将期环珮身。\n丽如三五月，可望难亲近。\n嚬黛含犀竟不言，春思秋怨谁能问。\n欲求巧笑如生时，歌尘在空瑟衔丝。\n神来未及梦相见，帝比初亡心更悲。\n爱之欲其生又死，东流万代无回水。\n宫漏丁丁夜向晨，烟销雾散愁方士。' },
  { title: '杂歌谣辞 李夫人歌', author: '张祜', poem: '延年不语望三星，莫说夫人上涕零。\n争奈世间惆怅在，甘泉宫夜看图形。' },
  { title: '杂歌谣辞 中山孺子妾歌', author: '李白', poem: '中山孺子妾，特以色见珍。\n虽不如延年妹，亦是当时绝世人。\n桃李出深井，花艳惊上春。\n一贵复一贱，关天岂由身。\n芙蓉老秋霜，团扇羞网尘。\n戚姬髡翦入舂市，万古共悲辛。' },
  { title: '杂歌谣辞 临江王节士歌', author: '李白', poem: '洞庭白波木叶稀，燕鸿始入吴云飞。\n吴云寒，燕鸿苦。\n风号沙宿潇湘浦，节士感秋泪如雨。\n白日当天心，照之可以事明主。\n壮士愤，雄风生。\n安得倚天劒，跨海斩长鲸。' },
  { title: '杂歌谣辞 司马将军歌', author: '李白', poem: '狂风吹古月，窃弄章华台。\n北落明星动光彩，南征猛将如云雷。\n手中电曳倚天劒，直斩长鲸海水开。\n我见楼船壮心目，颇似龙骧下三蜀。\n扬兵习战张虎旗，江中白浪如银屋。\n身居玉帐临河魁，紫髯若戟冠崔嵬。\n细柳开营揖天子，始知灞上为婴孩。\n羌笛横吹阿亸回，向月楼中吹落梅。\n将军自起舞长劒，壮士呼声动九垓。\n功成献凯见明主，丹青画像麒麟台。' },
  { title: '杂歌谣辞 郑樱桃歌', author: '李颀', poem: '石季龙，僭天禄。\n擅雄豪，美人姓郑名樱桃。\n樱桃美颜香且泽，娥娥侍寝专宫掖。\n后庭卷衣三万人，翠眉清镜不得亲。\n官军女骑一千匹，繁花照耀漳河春。\n织成花映红纶巾，红旗掣曳卤簿新。\n鸣鼙走马接飞鸟，铜[驮]琴瑟随去尘。\n凤阳重门如意馆，百尺金梯倚银汉。\n自言富贵不可量，女为公主男为王。\n赤花双簟珊瑚床，盘龙斗帐琥珀光。\n淫昏伪位神所恶，灭石者陵终不误。\n邺城苍苍白露微，世事飜覆黄云飞。' },
  { title: '杂歌谣辞 襄阳歌', author: '李白', poem: '落日欲没岘山西，倒着接䍠花下迷。\n襄阳小儿齐拍手，拦街争唱白铜鞮。\n傍人借问笑何事，笑杀山公醉似泥。\n鸬鹚杓，鹦鹉杯，百年三万六千日，一日须倾三百杯。\n遥看汉水鸭头绿，恰似蒲萄初酦醅。\n此江若变作春酒，垒曲便筑糟丘台。\n千金骏马换少妾，醉坐雕鞍歌落梅。\n车傍侧挂一壶酒，凤笙龙管行相催。\n咸阳市上叹黄犬，何如月下倾金罍。\n君不见晋朝羊公一片石，龟龙剥落生莓苔。\n泪亦不能为之堕，心亦不能为之哀。\n谁能忧彼身后事，金凫银鸭葬死灰。\n清风朗月不用一钱买，玉山自倒非人推。\n舒州杓，力士铛，李白与尔同死生。\n襄王云雨今安在，江水东流猨夜声。' },
  { title: '杂歌谣辞 襄阳曲 一', author: '李白', poem: '襄阳行乐处，歌舞白铜鞮。\n江城回渌水，花月使人迷。' },
  { title: '杂歌谣辞 襄阳曲 二', author: '李白', poem: '山公醉酒时，酩酊襄阳下。\n头上白接䍠，倒着还骑马。' },
  { title: '杂歌谣辞 襄阳曲 三', author: '李白', poem: '岘山临汉江，水渌沙如雪。\n上有堕泪碑，青苔久磨灭。' },
  { title: '杂歌谣辞 襄阳曲 四', author: '李白', poem: '且醉习家池，莫看堕泪碑。\n山公欲上马，笑杀襄阳儿。' },
  { title: '杂歌谣辞 苏小小歌', author: '李贺', poem: '幽兰露，如啼眼。\n无物结同心，烟花不堪翦。\n草如茵，松如盖。\n风为裳，水为佩。\n油壁车，久相待。\n冷翠烛，劳光彩。\n西陵下，风吹雨。' },
  { title: '杂歌谣辞 苏小小歌', author: '温庭筠', poem: '买莲莫破券，买酒莫解金。\n酒里春容抱离恨，水中莲子怀芳心。\n吴公女儿腰似束，家在钱塘小江曲。\n一自檀郎逐便风，门前春水年年绿。' },
  { title: '杂歌谣辞 苏小小歌 一', author: '张祜', poem: '车轮不可遮，马足不可绊。\n长怨十字街，使郎心四散。' },
  { title: '杂歌谣辞 苏小小歌 二', author: '张祜', poem: '新人千里去，故人千里来。\n翦刀横眼底，方觉泪难裁。' },
  { title: '杂歌谣辞 苏小小歌 三', author: '张祜', poem: '登山不愁峻，涉海不愁深。\n中擘庭前枣，教郎见赤心。' },
  { title: '杂歌谣辞 挟瑟歌', author: '陆龟蒙', poem: '挟瑟为君抚，君嫌声太古。\n寥寥倚浪丝，㗫㗫沈湘语。\n赖有秋风知，清泠吹玉柱。' },
  { title: '杂歌谣辞 勅勒歌', author: '不详', poem: '敕勒金𬯎壁，阴山无岁华。\n帐外风飘雪，营前月照沙。\n羌儿吹玉管，胡姬踏锦花。\n却笑江南客，梅落不归家。' },
  { title: '杂歌谣辞 得体歌', author: '不详', poem: '得体纥那也，纥囊得体那。\n潭里船车闹，扬州铜器多。\n三郎当殿坐，听唱得体歌。' },
  { title: '杂歌谣辞 得宝歌', author: '不详', poem: '得宝弘农野，弘农得宝那。\n潭里船车闹，扬州铜器多。\n三郎当殿坐，听唱得宝歌。' },
  { title: '杂歌谣辞 黄台瓜辞', author: '章怀太子', poem: '种瓜黄台下，瓜熟子离离。\n一摘使瓜好，再摘令瓜稀。\n三摘尚自可，摘绝抱蔓归。' },
  { title: '杂歌谣辞 古歌', author: '沈佺期', poem: '落叶流风向玉台，夜寒秋思洞房开。\n水精帘外金波下，云母窗前银汉回。\n玉阶阴阴苔藓色，君王履綦难再得。\n璇闺窈窕秋夜长，绣户徘徊秋月光。\n燕姬彩帐芙蓉色，秦子金炉兰麝香。\n北斗七星横夜半，清歌一曲断君肠。' },
  { title: '杂歌谣辞 古歌 一', author: '薛维翰', poem: '美人怨何深，含情倚金阁。\n不嚬复不语，红泪双双落。' },
  { title: '杂歌谣辞 古歌 二', author: '薛维翰', poem: '美人闭红烛，独坐裁新锦。\n频放翦刀声，夜寒知未寝。' },
  { title: '杂歌谣辞 黄昙子歌', author: '温庭筠', poem: '参差绿蒲短，摇艳云塘满。\n红潋荡融融，莺翁㶉𫛶暖。\n萋芊小城路，马上修蛾懒。\n罗衫褭向风，点粉金鹂卵。' },
  { title: '杂歌谣辞 邯郸郭公辞', author: '温庭筠', poem: '金笳悲故曲，玉座积深尘。\n言是邯郸伎，不易邺城人。\n青苔竟埋骨，红粉自伤神。\n唯有漳河柳，还向旧营春。' },
  { title: '杂歌谣辞 箜篌谣', author: '李白', poem: '攀天莫登龙，走山莫骑虎。\n贵贱结交心不移，唯有严陵及光武。\n周公称大圣，管蔡宁相容。\n汉谣一斗粟，不与淮南舂。\n兄弟尚路人，吾心安所从。\n它人方寸间，山海几千重。\n轻言托朋友，对面九疑峰。\n多花必早落，桃李不如松。\n管鲍久已死，何人继其踪。' },
  { title: '杂歌谣辞 邺城童子谣', author: '李贺', poem: '邺城中，暮尘起。\n将黑丸，斫文吏。\n棘为鞭，虎为马。\n团团走，邺城下。\n切玉劒，射日弓。\n献何人，奉相公。\n扶毂来，关右儿。\n香扫涂，相公归。' },
  { title: '杂歌谣辞 大麦行', author: '杜甫', poem: '大麦干枯小麦黄，妇人行泣夫走藏。\n东至集壁西梁洋，问谁腰镰胡与羌。\n岂无蜀兵三千人，部领辛苦江山长。\n安得如鸟有羽翅，托身白云还故乡。' },
  { title: '杂歌谣辞 白鼍鸣', author: '张籍', poem: '天欲雨，有东风，南谿白鼍鸣窟中。\n六月人家井无水，夜闻白鼍人尽起。' },
  { title: '杂歌谣辞 步虚词', author: '陈羽', poem: '汉武清斋读鼎书，内官扶上画云车。\n坛上月明宫殿闭，仰看星斗礼空虚。' },
  { title: '杂歌谣辞 步虚词', author: '顾况', poem: '逈步游三洞，清心礼七真。\n飞符超羽翼，禁火醮星辰。\n残药沾鸡犬，灵香出凤麟。\n壶中无窄处，愿得一容身。' },
  { title: '杂歌谣辞 步虚词 一', author: '刘禹锡', poem: '阿母种桃云海际，花落子成二千岁。\n海风吹折最繁枝，跪捧琼盘献天帝。' },
  { title: '杂歌谣辞 步虚词 二', author: '刘禹锡', poem: '华表千年鹤一归，凝丹为顶雪为衣。\n星星仙语人听尽，却向五云翻翅飞。' },
  { title: '杂歌谣辞 步虚词 一', author: '韦渠牟', poem: '玉简真人降，金书道箓通。\n烟霞方蔽日，云雨已生风。\n四极威仪异，三天使命同。\n那将人世恋，不去上清宫。' },
  { title: '杂歌谣辞 步虚词 二', author: '韦渠牟', poem: '羽驾正翩翩，云鸿最自然。\n霞冠将月晓，珠佩与星连。\n镂玉留新诀，雕金得旧编。\n不知飞鸟学，更有几人仙。' },
  { title: '杂歌谣辞 步虚词 三', author: '韦渠牟', poem: '上帝求仙使，真符取玉郎。\n三才闲布象，二景郁生光。\n骑吏排龙虎，笙歌走凤凰。\n天高人不见，暗入白云乡。' },
  { title: '杂歌谣辞 步虚词 四', author: '韦渠牟', poem: '鸾鹤共徘徊，仙官使者催。\n香花三洞启，风雨百神来。\n凤篆文初定，龙泥印已开。\n何须生羽翼，始得上瑶台。' },
  { title: '杂歌谣辞 步虚词 五', author: '韦渠牟', poem: '羽节忽排烟，苏君已得仙。\n命风驱日月，缩地走山川。\n几处留丹灶，何时种玉田。\n一朝骑白虎，直上紫微天。' },
  { title: '杂歌谣辞 步虚词 六', author: '韦渠牟', poem: '静发降灵香，思神意智长。\n虎存时促步，龙想更成章。\n扣齿风雷响，挑灯日月光。\n仙云在何处？髣髴满空堂。' },
  { title: '杂歌谣辞 步虚词 七', author: '韦渠牟', poem: '几度游三洞，何方召百神。\n风云皆守一，龙虎亦全真。\n执节仙童小，烧香玉女春。\n应须绝岩内，委曲问皇人。' },
  { title: '杂歌谣辞 步虚词 八', author: '韦渠牟', poem: '上法杳无营，玄修似有情。\n道宫琼作想，真帝玉为名。\n召岳驱旌节，驰雷发吏兵。\n云车降何处，斋室有仙卿。' },
  { title: '杂歌谣辞 步虚词 九', author: '韦渠牟', poem: '羽卫一何鲜，香云起莫烟。\n方朝太素帝，更向玉清天。\n凤曲凝犹吹，龙骖俨欲前。\n真文几时降，知在永和年。' },
  { title: '杂歌谣辞 步虚词 十', author: '韦渠牟', poem: '大道何年学，真符此日催。\n还持金作印，未要玉为台。\n羽节分明授，霞衣整顿裁。\n应缘五云使，教上列仙来。' },
  { title: '杂歌谣辞 步虚词 十一', author: '韦渠牟', poem: '独自授金书，萧条咏紫虚。\n龙行还当马，云起自成车。\n九转风烟合，千年井灶余。\n参差从太一，寿等混元初。' },
  { title: '杂歌谣辞 步虚词 十二', author: '韦渠牟', poem: '道学已通神，香花会女真。\n霞床珠斗帐，金荐玉舆轮。\n一室心偏静，三天夜正春。\n灵官竟谁降，仙相有夫人。' },
  { title: '杂歌谣辞 步虚词 十三', author: '韦渠牟', poem: '上界有黄房，仙家道路长。\n神来知位次，乐变协宫商。\n竞把瑠璃椀，谁倾白玉浆。\n霞衣最芬馥，苏合是灵香。' },
  { title: '杂歌谣辞 步虚词 十四', author: '韦渠牟', poem: '珠佩紫霞缨，夫人会八灵。\n太霄犹有观，绝宅岂无形。\n暮雨徘徊降，仙歌宛转听。\n谁逢玉妃辇，应检九真经。' },
  { title: '杂歌谣辞 步虚词 十五', author: '韦渠牟', poem: '西海辞金母，东方拜木公。\n云行疑带雨，星步欲凌风。\n羽袖挥丹凤，霞巾曳彩虹。\n飘飖九霄外，下视望仙宫。' },
  { title: '杂歌谣辞 步虚词 十六', author: '韦渠牟', poem: '玉树杂金花，天河织女家。\n月邀丹凤舄，风送紫鸾车。\n雾縠笼绡带，云屏列锦霞。\n瑶台千万里，不觉往来赊。' },
  { title: '杂歌谣辞 步虚词 十七', author: '韦渠牟', poem: '舞凤凌天出，歌麟入夜听。\n云容衣眇眇，风韵曲泠泠。\n扣齿端金简，焚香检玉经。\n仙宫知不远，只近太微星。' },
  { title: '杂歌谣辞 步虚词 十八', author: '韦渠牟', poem: '紫府与玄洲，谁来物外游。\n无烦骑白鹿，不用驾青牛。\n金化颜应驻，云飞鬓不秋。\n仍闻碧海上，更用玉为楼。' },
  { title: '杂歌谣辞 步虚词 十九', author: '韦渠牟', poem: '辔鹤复骖鸾，全家去不难。\n鸡声随羽化，犬影入云看。\n酿玉当成酒，烧金且转丹。\n何妨五色绶，次第给仙官。' },
  { title: '杂歌谣辞 步虚词', author: '僧皎然', poem: '予因览真诀，遂感西域君。\n玉笙下青冥，人间未曾闻。\n日华炼魂魄，皎皎无垢氛。\n谓我有仙骨，且令饵氤氲。\n俯仰媿灵颜，愿随鸾鹤群。\n俄然动风驭，缥眇归青云。' },
  { title: '杂歌谣辞 步虚词', author: '高骈', poem: '青溪道士人不识，上天下天鹤一只。\n洞门深[锁]碧窗寒，滴露妍朱写周易。' },
  { title: '杂歌谣辞 步虚引', author: '陈陶', poem: '小隐山人十洲客，莓苔为衣双耳白。\n青编为我忽降书，暮雨虹蜺一千尺。\n赤城门闭六丁直，晓日已烧东海色。\n朝天半夜闻玉鸡，星斗离离碍龙翼。' },
  { title: '咏汉高祖', author: '王珪', poem: '汉祖起丰沛，乘运以跃鳞。\n手奋三尺劒，西灭无道秦。\n十月五星聚，七年四海宾。\n高抗威宇宙，贵有天下人。\n忆昔与项王，契阔时未伸。\n鸿门既薄蚀，荥阳亦蒙尘。\n虮虱生介胄，将卒多苦辛。\n爪牙驱信越，腹心谋张陈。\n赫赫西楚国，化为丘与榛。' },
  { title: '咏淮阴侯', author: '王珪', poem: '秦王日凶慝，豪杰争共亡。\n信亦胡为者，剑歌从项梁。\n项羽不能用，脱身归汉王。\n道契君臣合，时来名位彰。\n北讨燕承命，东驱楚绝粮。\n斩龙堰濉水，擒豹熸夏阳。\n功成享天禄，建旗还南昌。\n千金答漂母，百钱酬下乡。\n吉凶成纠缠，倚伏难预详。\n弓藏狡兔尽，慷慨念心伤。' },
  { title: '早春桂林殿应诏', author: '陈叔达', poem: '金铺照春色，玉律动年华。\n朱楼云似盖，丹桂雪如花。\n水岸衔阶转，风条出柳斜。\n轻舆临太液，湛露酌流霞。' },
  { title: '后渚置酒', author: '陈叔达', poem: '大渚初惊夜，中流沸鼓鼙。\n寒沙满曲浦，夕雾上邪谿。\n岸广凫飞急，云深鴈度低。\n严关犹未遂，此夕待晨鸡。' },
  { title: '听邻人琵琶', author: '陈叔达', poem: '本是龙门桐，因妍入汉宫。\n香缘罗袖里，声逐朱弦中。\n虽有相思韵，翻将入塞同。\n关山临却月，花蘂散回风。\n为将金谷引，添令曲未终。' },
  { title: '州城西园入斋祠社', author: '陈叔达', poem: '升坛预洁祀，诘早肃分司。\n达气风霜积，登光日色迟。\n农教先八政，阳和秩四时。\n祈年服垂冕，告币动褰帷。\n瘗地尊余奠，人天庶有资。\n椒兰卒清酌，簠簋彻香萁。\n折俎分归胙，充庭降受厘。\n方凭知礼节，况奉化雍熙。' },
  { title: '春首', author: '陈叔达', poem: '雪花联玉树，冰彩散瑶池。\n翔禽遥出没，积翠远参差。' },
  { title: '初年', author: '陈叔达', poem: '和风起天路，严气消冰井。\n索索枝未柔，厌厌漏犹永。' },
  { title: '咏菊', author: '陈叔达', poem: '霜间开紫蔕，露下发金英。\n但令逢采摘，宁辞独晚荣。' },
  { title: '自君之出矣', author: '王融', poem: '自君之出矣，金炉香不然。\n思君当明烛，终宵空自煎。' },
  { title: '自君之出矣  一', author: '陈叔达', poem: '自君之出矣，红颜转憔悴。\n思君如明烛，煎心且衔泪。' },
  { title: '自君之出矣  二', author: '陈叔达', poem: '自君之出矣，明镜罢红妆。\n思君如夜烛，煎泪几千行。' },
  { title: '赋饮马长城窟', author: '袁朗', poem: '朔风动秋草，清跸长安道。\n长城连不穷，所以隔华戎。\n规模惟圣作，负荷晓成功。\n鸟庭已向内，龙荒更凿空。\n玉关尘卷静，金微路已通。\n汤征随北怨，舜咏起南风。\n画地功初立，绥边事云集。\n朝服践狼居，凯歌旋马邑。\n山响传凤吹，霜华藻琼钑。\n属国拥节归，单于款关入。\n日落寒风起，惊蓬被原隰。\n零落叶已寒，河流清且急。\n四时徭役尽，千载干戈戢。\n太平今若斯，汗马竟无施。\n唯当事笔砚，归去草封禅。' },
  { title: '和洗掾登城南坂望京邑', author: '袁朗', poem: '二华连陌塞，九陇统金方。\n奥区称富贵，重险擅雄强。\n龙飞灞水上，凤集岐山阳。\n神皐多瑞迹，列代有兴王。\n我后膺灵命，爰求宅兹土。\n宸居法太微，建国资天府。\n玄风叶黎庶，德泽浸区宇。\n醒醉各相扶，讴歌从圣主。\n南登少陵岸，还望帝城中。\n帝城何郁郁，佳气乃葱葱。\n金凤凌绮观，璇题敞兰宫。\n复道东西合，交衢南北通。\n万国朝前殿，群公议宣室。\n鸣珮含早风，华蝉曜朝日。\n栢梁宴初罢，千钟欢未毕。\n端拱肃岩廊，思贤听琴瑟。\n逶迤万雉列，隐轸千闾布。\n飞甍夹御沟，曲台临上路。\n处处歌钟鸣，喧阗车马度。\n日落长楸间，含情两相顾。\n是月冬之季，阴寒昼不开。\n惊风四面集，飞雪千里回。\n狐白登廊庙，牛衣出草莱。\n讵知韩长孺，无复重然灰。' },
  { title: '秋日应诏', author: '袁朗', poem: '玉树凉风举，金塘细草萎。\n叶落商飙观，鸿归明月池。\n迎寒桂酒熟，含露菊花垂。\n一奉章台宴，千秋长愿斯。' },
  { title: '秋夜独坐', author: '袁朗', poem: '危弦断客心，虚弹落惊禽。\n新秋百虑净，独夜九愁深。\n枯蓬唯逐吹，坠叶不归林。\n如何悲此曲，坐作白头吟。' },
  { title: '出塞曲', author: '窦威', poem: '匈奴屡不平，汉将欲纵横。\n看云方结阵，却月始连营。\n潜军度马邑，扬斾掩龙城。\n会勒燕然石，方传车骑名。' },
  { title: '新曲二首 一', author: '长孙无忌', poem: '阿侬家住朝歌下，早传名。\n结伴来游淇水上，旧长情。\n玉珮金钿随步远，云罗雾縠逐风轻。\n转目机心悬自许，何须更待听琴声。' },
  { title: '新曲二首 二', author: '长孙无忌', poem: '回雪凌波游洛浦，遇陈王。\n婉约娉婷工语笑，侍兰房。\n芙蓉绮帐还开揜，翡翠珠被烂齐光。\n长愿今宵奉颜色，不爱吹箫逐凤皇。' },
  { title: '灞桥待李将军', author: '长孙无忌', poem: '飒飒风叶下，遥遥烟景曛。\n霸陵无醉尉，谁滞李将军。' },
  { title: '奉和正日临朝', author: '颜师古', poem: '七府璇衡始，三元宝历新。\n负扆延百辟，垂旒御九宾。\n肃肃皆鹓鹭，济济盛簪绅。\n天涯致重译，日域献奇珍。' },
  { title: '召拜御史大夫赠袁天纲', author: '杜淹', poem: '伊吕深可慕，松乔定是虚。\n系风终不得，脱屣欲安如。\n且珍纨素美，当与薜萝疎。\n既逢杨得意，非复久闲居。' },
  { title: '咏寒食鬬鸡应秦王教', author: '杜淹', poem: '寒食东郊道，扬鞲竞出笼。\n花冠初照日，芥羽正生风。\n顾敌知心勇，先鸣觉气雄。\n长翘频扫阵，利爪屡通中。\n飞毛遍绿野，洒血渍芳丛。\n虽然百战胜，会自不论功。' },
  { title: '寄赠齐公', author: '杜淹', poem: '冠盖游梁日，诗书问志年。\n佩兰长坂上，攀桂小山前。\n结交澹若水，履道直如弦。\n此欢终未极，于兹独播迁。\n赭衣登蜀道，白首别秦川。\n泪随沟水逝，心逐晓旌悬。\n去去逾千里，悠悠隔九天。\n郊野间长薄，城阙隐凝烟。\n关门共月对，山路与云连。\n此时寸心里，难用尺书传。' },
  { title: '五郊乐章 黄帝宫音', author: '魏征', poem: '黄中正位，含章居贞。\n既长六律，兼和五声。\n毕陈万舞，乃荐斯牲。\n神其下降，永祚休平。' },
  { title: '五郊乐章 黄帝宫音 肃和', author: '魏征', poem: '眇眇方舆，苍苍圜盖。\n至哉枢纽，宅中图大。\n气调四序，风和万籁。\n祚我明德，时雍道泰。' },
  { title: '五郊乐章 黄帝宫音 雍和', author: '魏征', poem: '金悬夕肆，玉俎朝陈。\n飨荐黄道，芬流紫辰。\n廼诚廼敬，载享载禋。\n崇荐斯在，惟皇是宾。' },
  { title: '五郊乐章 黄帝宫音 舒和', author: '魏征', poem: '御征乘宫出郊甸，安歌率舞逓将迎。\n自有云门符帝赏，犹持雷鼓荅天成。' },
  { title: '五郊乐章 青帝角音', author: '魏征', poem: '鹤云旦起，鸟星昏集。\n律候新风，阳开初蛰。\n至德可飨，行潦斯挹。\n锡以无疆，烝人乃粒。' },
  { title: '五郊乐章 青帝角音 肃和', author: '魏征', poem: '玄鸟司春，苍龙登岁。\n节物变柳，光风转蕙。\n瑶席降神，朱弦飨帝。\n诚备祝嘏，礼殚珪币。' },
  { title: '五郊乐章 青帝角音 雍和', author: '魏征', poem: '大乐稀音，至诚简礼。\n文物棣棣，声名济济。\n六变有成，三登无体。\n廼眷丰絜，恩覃恺悌。' },
  { title: '五郊乐章 青帝角音 舒和', author: '魏征', poem: '笙歌籥舞属年韶，鹭鼓凫钟展时豫。\n调露初迎绮春节，承云遽践苍霄驭。' },
  { title: '五郊乐章 赤帝徵音', author: '魏征', poem: '青阳告谢，朱明戒序。\n咸长是祈，敬陈椒醑。\n博硕斯荐，笙镛备举。\n庶尽肃恭，非馨稷黍。' },
  { title: '五郊乐章 赤帝徵音 肃和', author: '魏征', poem: '离位克明，火中宵见。\n峰云暮起，景风晨扇。\n木槿初荣，含桃可荐。\n芬馥百品，铿锵三变。' },
  { title: '五郊乐章 赤帝徵音 雍和', author: '魏征', poem: '昭昭丹陆，帟帟炎方。\n礼陈牲币，乐备箎簧。\n琼羞溢俎，玉𨠨浮觞。\n恭惟正直，歆此馨香。' },
  { title: '五郊乐章 赤帝徵音 舒和', author: '魏征', poem: '千里温风飘降羽，十枝炎景媵朱干。\n陈觞荐俎歌三献，拊石𪭢金会七盘。' },
  { title: '五郊乐章 白帝商音', author: '魏征', poem: '白藏应节，天高气清。\n岁功既阜，庶类收成。\n万方静谧，九土和平。\n馨香是荐，受祚聪明。' },
  { title: '五郊乐章 白帝商音 肃和', author: '魏征', poem: '金行在节，素灵居正。\n气肃霜严，林凋草劲。\n豺祭隼击，潦收川镜。\n九谷已登，万箱流咏。' },
  { title: '五郊乐章 白帝商音 雍和', author: '魏征', poem: '律应西成，气躔南吕。\n珪币咸列，笙竽备举。\n苾苾兰羞，芬芬桂醑。\n式资宴贶，用调霜序。' },
  { title: '五郊乐章 白帝商音 舒和', author: '魏征', poem: '璇仪气爽惊缇籥，玉吕灰飞含素商。\n鸣鞞奏管芳羞荐，会舞安歌葆眊扬。' },
  { title: '五郊乐章 黑帝羽音', author: '魏征', poem: '严冬季月，星回风厉。\n享祀报功，方祚来岁。' },
  { title: '五郊乐章 黑帝羽音 肃和', author: '魏征', poem: '律周玉琯，星回金度。\n次极阳乌，纪穷阴兔。\n火林霰雪，阳泉凝冱。\n八蜡已登，三农息务。' },
  { title: '五郊乐章 黑帝羽音 雍和', author: '魏征', poem: '阳月斯纪，应钟在候。\n载絜牲牷，爰登俎豆。\n既高既远，无声无臭。\n静言格思，惟神保祐。' },
  { title: '五郊乐章 黑帝羽音 舒和', author: '魏征', poem: '执籥持羽初终曲，朱干玉𬭭始分行。\n七德九功咸已畅，明灵降福具穰穰。' },
  { title: '享太庙乐章 永和', author: '魏征', poem: '於穆烈祖，弘此丕基。\n永言配命，子孙保之。\n百神既洽，万国在兹。\n是用孝享，神其格思。' },
  { title: '享太庙乐章 肃和', author: '魏征', poem: '大哉至德，允兹明圣。\n格于上下，聿遵诚敬。\n嘉乐斯登，鸣球以咏。\n神其降止，式隆景命。' },
  { title: '享太庙乐章 雍和', author: '魏征', poem: '崇兹享祀，诚敬兼至。\n乐以感灵，礼以昭事。\n粢盛咸絜，牲牷孔备。\n永言孝思，庶几不匮。' },
  { title: '享太庙乐章 长发舞', author: '魏征', poem: '濬哲惟唐，长发其祥。\n帝命斯祐，王业克昌。\n配天载德，就日重光。\n本枝百代，申锡无疆。' },
  { title: '享太庙乐章 大基舞', author: '魏征', poem: '猗与祖业，皇矣帝先。\n剪商德厚，封唐庆延。\n在姬犹稷，方晋逾宣。\n基我鼎运，于斯万年。' },
  { title: '享太庙乐章 大成舞', author: '魏征', poem: '周穆王季，晋美帝文。\n明明盛德，穆穆齐芬。\n藏用四履，屈道参分。\n铿锵钟石，载纪鸿勋。' },
  { title: '享太庙乐章 大明舞', author: '魏征', poem: '五纪更运，三正逓升。\n勋华既没，禹汤勃兴。\n神武命代，灵睠是膺。\n望云彰德，察纬告征。\n上纽天维，下安地轴。\n征师涿野，万国咸服。\n偃伯灵台，九官允穆。\n殊域委赆，怀生介福。\n大礼既饰，大乐已和。\n黑章扰囿，赤字浮河。\n功宣载籍，德被咏歌。\n克昌厥后，百禄是荷。' },
  { title: '享太庙乐章 寿和', author: '魏征', poem: '八音斯奏，三献毕陈。\n宝祚惟永，晖光日新。' },
  { title: '享太庙乐章 舒和', author: '魏征', poem: '圣敬通神光七庙，灵心荐祚和万方。\n严禋克配鸿基远，明德惟馨凤历昌。' },
  { title: '赋西汉', author: '魏征', poem: '受降临轵道，争长趣鸿门。\n驱传渭桥上，观兵细柳屯。\n夜宴经柏谷，朝游出杜原。\n终藉叔孙礼，方知皇帝尊。' },
  { title: '暮秋言怀', author: '魏征', poem: '首夏别京辅，杪秋滞三河。\n沈沈蓬莱阁，日夕乡思多。\n霜剪凉阶蕙，风捎幽渚荷。\n岁芳坐沦歇，感此式微歌。' },
  { title: '述怀', author: '魏征', poem: '中原初逐鹿，投笔事戎轩。\n纵横计不就，慷慨志犹存。\n杖策谒天子，驱马出关门。\n请缨系南粤，凭轼下东藩。\n郁纡陟高岫，出没望平原。\n古木鸣寒鸟，空山啼夜猿。\n既伤千里目，还惊九折魂。\n岂不惮艰险，深怀国士恩。\n季布无二诺，侯嬴重一言。\n人生感意气，功名谁复论。' },
  { title: '奉和正日临朝应诏', author: '魏征', poem: '百灵侍轩后，万国会涂山。\n岂如今睿哲，迈古独光前。\n声教溢四海，朝宗引百川。\n锵洋鸣玉珮，灼烁耀金蝉。\n淑景辉雕辇，高旌扬翠烟。\n庭实超王会，广乐盛钧天。\n既欣东日户，复咏南风篇。\n愿奉光华庆，从斯亿万年。' },
  { title: '祈谷乐章 肃和', author: '褚亮', poem: '履艮斯绳，居中体正。\n龙运垂祉，昭符启圣。\n式事严禋，聿怀嘉庆。\n惟帝永锡，时皇休命。' },
  { title: '祈谷乐章 雍和', author: '褚亮', poem: '殷荐乘春，太坛临曙。\n八簋盈和，六瑚登御。\n嘉稷匪歆，德馨斯饫。\n祝嘏无易，灵心有豫。' },
  { title: '祈谷乐章 舒和', author: '褚亮', poem: '玉帛牺牲申敬享，金丝𬭭羽盛音容。\n庶俾亿龄禔景福，长欣万宇洽时邕。' },
  { title: '明堂乐章 肃和', author: '褚亮', poem: '象天御宇，乘时布政。\n严配申虔，宗禋展敬。\n罇罍盈列，树羽交暎。\n玉币通诚，祚隆皇圣。' },
  { title: '明堂乐章 雍和', author: '褚亮', poem: '八牖晨披，五精朝奠。\n雾凝璇篚，风清金县。\n神涤备全，明粢丰衍。\n载[絜]彝俎，陈诚以荐。' },
  { title: '明堂乐章 舒和', author: '褚亮', poem: '御扆合宫承宝历，席图重馆奉明灵。\n偃武修文九围泰，沈烽静柝八荒宁。' },
  { title: '雩祀乐章 肃和', author: '褚亮', poem: '朱鸟开辰，苍龙启暎。\n大帝昭飨，群生展敬。\n礼备怀柔，功宣舞咏。\n旬液应序，年祥叶庆。' },
  { title: '雩祀乐章 雍和', author: '褚亮', poem: '绀筵分彩，珤图吐绚。\n凤管晨凝，云歌晓啭。\n肃事苹藻，虔申桂奠。\n百谷斯登，万箱攸荐。' },
  { title: '雩祀乐章 舒和', author: '褚亮', poem: '凤曲登歌调令序，龙雩集舞泛祥风。\n彩旞云回昭睿德，朱干电发表神功。' },
  { title: '享先农乐章 诚和', author: '褚亮', poem: '粒食伊始，农之所先。\n古今攸赖，是曰人天。\n耕斯帝籍，播厥公田。\n式崇明祀，神其福焉。' },
  { title: '享先农乐章 肃和', author: '褚亮', poem: '罇彝既列，瑚簋方荐。\n歌工载登，币礼斯奠。\n肃肃享祀，颙颙缨弁。\n神之听之，福流寰县。' },
  { title: '享先农乐章 雍和', author: '褚亮', poem: '前夕视牲，质明奉俎。\n沐芳整弁，其仪式序。\n盛礼毕陈，嘉乐备举。\n歆我懿德，非馨稷黍。' },
  { title: '享先农乐章 舒和', author: '褚亮', poem: '羽籥低昂文缀已，干戚蹈厉武行初。\n望岁祈农神所听，延祥介福岂云虚。' },
  { title: '祭神州乐章 肃和', author: '褚亮', poem: '大矣坤仪，至哉神县。\n包含日域，牢笼月竁。\n露絜三清，风调六变。\n皇祗届止，式歆恭荐。' },
  { title: '祭神州乐章 雍和', author: '褚亮', poem: '泰圻严享，阴郊展敬。\n礼以导神，乐以和性。\n黝牲在列，黄琮俯暎。\n九土既平，万邦贻庆。' },
  { title: '祭神州乐章 舒和', author: '褚亮', poem: '坤道降祥和庶品，灵心载德厚群生。\n水土既调三极泰，文武毕备九区平。' },
  { title: '祭方丘乐章 顺和', author: '褚亮', poem: '万物资以化，交泰属升平。\n易从业惟简，得一道斯宁。\n具仪光玉帛，送舞变咸英。\n黍稷良非贵，明德信惟馨。' },
  { title: '祭方丘乐章 肃和', author: '褚亮', poem: '至矣坤德，皇哉地祗。\n开元统纽，合大承规。\n九宫肃列，六典相仪。\n永言配命，长保无亏。' },
  { title: '祭方丘乐章 雍和', author: '褚亮', poem: '柔而能方，直而能敬。\n厚载以德，大亨以正。\n有涤斯牷，有馨斯盛。\n介兹景福，祚我休庆。' },
  { title: '祭方丘乐章 舒和', author: '褚亮', poem: '玉币牲牷分荐享，羽旄干𬭭遰成容。\n一德惟宁两仪泰，三材保合四时邕。' },
  { title: '临高台', author: '褚亮', poem: '高台暂俯临，飞翼耸轻音。\n浮光随日度，漾影逐波深。\n回瞰周平野，开怀畅远襟。\n独此三休上，还伤千岁心。' },
  { title: '赋得蜀都', author: '褚亮', poem: '列宿光参井，分芒跨梁岷。\n沈犀对江浦，驷马入城𬮱。\n英图多霸迹，历选有名臣。\n连骑簪缨满，含章词赋新。\n得上仙槎路，无待访严遵。' },
  { title: '奉和咏日午', author: '褚亮', poem: '曦车日亭午，浮箭未移晖。\n日光无落照，树影正中围。\n草萎看稍靡，叶燥望疑稀。\n昼寝慙经笥，暂解入朝衣。' },
  { title: '奉和望月应魏王教', author: '褚亮', poem: '层轩登皎月，流照满中天。\n色共梁珠远，光随赵璧圆。\n落影临秋扇，虚轮入夜弦。\n所欣东馆里，预奉西园篇。' },
  { title: '咏花烛', author: '褚亮', poem: '兰迳香风满，梅梁暖日斜。\n言是东方骑，来寻南陌车。\n靥星临夜烛，眉月隐轻纱。\n莫言春稍晚，自有镇开花。' },
  { title: '在陇头哭潘学士', author: '褚亮', poem: '陇底嗟长别，流襟一恸君。\n何言幽咽所，更作死生分。\n转蓬飞不息，悲松断更闻。\n谁能驻征马，回首望孤坟。' },
  { title: '奉和禁苑饯别应令', author: '褚亮', poem: '大藩初锡瑞，出牧迩皇京。\n暂以绿车重，言承朱传荣。\n舒桃临远骑，垂柳映京营。\n惠化宣千里，威风动百城。\n禁籞芳嘉节，神襟饯送情。\n金笳催别景，玉琯切离声。\n野花开更落，山鸟哢还惊。\n微臣夙多幸，薄宦奉储明。\n钓台慙作赋，伊水滥闻笙。\n怀德良知久，酬恩识命轻。' },
  { title: '和御史韦大夫喜霁之作', author: '褚亮', poem: '晴天度旅雁，斜影照残虹。\n野净余烟尽，山明远色同。\n沙平寒水落，叶脆晚枝空。\n白简光朝幰，彤驺出禁中。\n息驾游兰[坂]，雕文折桂丛。\n无因轻羽扇，徒自仰仁风。' },
  { title: '晚别乐记室彦', author: '褚亮', poem: '穷途属岁晚，临水忽分悲。\n抱影同为客，伤情共此时。\n雾色侵虚牖，霜氛冷薄帷。\n举袂惨将别，停杯怅不怡。\n风严征雁远，雪暗去篷迟。' },
  { title: '伤始平李少府正己', author: '褚亮', poem: '劳息本相循，悲欢理自均。\n谁能免玄夜，惜尔正青春。\n迈德惟家宝，生才谅国珍。\n高文缀翡翠，茂学掩麒麟。\n述作纷无已，言谈妙入神。\n断肠虽累月，分手未盈旬。\n辅嗣俄长往，颜生即短辰。\n声华满昭代，形影委穷尘。\n禅草回中使，生刍引吊宾。\n同游秘府日，方驾直城𬮱。\n并拜黄图右，分曹清渭滨。\n风期嵇吕好，存殁范张亲。\n虚座怜王述，遗篇恸景纯。\n精灵与毫翰，千祀寿何人。' },
  { title: '秋鴈', author: '褚亮', poem: '日暮霜风急，羽翮转难任。\n为有传书意，翩翩入上林。' },
  { title: '冬日宴群公于宅各赋一字得杯', author: '于志宁', poem: '陋巷朱轩拥，衡门缇骑来。\n俱裁七步咏，同倾三雅杯。\n色动迎春柳，花发犯寒梅。\n宾筵未半醉，骊歌不用催。' },
  { title: '冬日宴于庶子宅各赋一字得趣', author: '令狐德棻', poem: '高门聊命赏，群英于此遇。\n放旷山水情，留连文酒趣。\n夕烟起林兰，霜枝殒庭树。\n落景虽已倾，归轩幸能驻。' },
  { title: '冬日宴于庶子宅各赋一字得色', author: '封行高', poem: '夫君敬爱重，欢言情不极。\n雅引发清音，丽藻穷雕饰。\n水结曲池冰，日暖平亭色。\n引满既杯倾，终之以弁侧。' },
  { title: '冬日宴于庶子宅各赋一字得节', author: '杜正伦', poem: '李门余妄进，徐榻君恒设。\n清论畅玄言，雅琴飞白雪。\n寒云暧落景，朔风凄暮节。\n方欣投辖情，且驻当归别。' },
  { title: '玄武门侍宴', author: '杜正伦', poem: '大君端扆暇，睿赏狎林泉。\n开轩临禁籞，藉野列芳筵。\n参差歌管飏，容裔羽旗悬。\n玉池流若醴，云阁聚非烟。\n湛露晞尧日，熏风入舜弦。\n大德侔玄造，微物荷陶甄。\n谬陪瑶水宴，仍厕栢梁篇。\n阚名徒上月，邹辩讵谈天。\n既喜光华旦，还伤迟暮年。\n犹冀升中日，簪裾奉肃然。' },
  { title: '奉和正日临朝', author: '岑文本', poem: '时雍表昌运，日正叶灵符。\n德兼三代礼，功包四海图。\n逾沙纷在列，执玉俨相趋。\n清跸喧辇道，张乐骇天衢。\n拂蜺九旗暎，仪凤八音殊。\n佳气浮仙掌，熏风绕帝梧。\n天文光七政，皇恩被九区。\n方陪瘗玉礼，珥笔岱山隅。' },
  { title: '奉述飞白书势', author: '岑文本', poem: '六文开玉篆，八体曜银书。\n飞毫列锦绣，拂素起龙鱼。\n凤举崩云绝，鸾惊游雾疎。\n别有临池草，恩沾垂露余。' },
  { title: '冬日宴于庶子宅各赋一字得平', author: '岑文本', poem: '金兰笃惠好，尊酒畅生平。\n既欣投辖赏，暂缓望乡情。\n爱景含霜晦，落照带风轻。\n于兹欢宴洽，宠辱讵相惊。' },
  { title: '安德山池宴集', author: '岑文本', poem: '甲第多清赏，芳辰命羽巵。\n书帷通竹径，琴台枕槿篱。\n池疑夜壑徙，山似郁洲移。\n雕楹网萝薜，激濑合埙篪。\n鸟戏翻新叶，鱼跃动清漪。\n自得淹留趣，宁劳攀桂枝。' },
  { title: '安德山池宴集', author: '刘洎', poem: '平阳擅歌舞，金谷盛招携。\n何如兼往烈，会赏叶幽栖。\n已均朝野致，还欣物我齐。\n春晚花方落，兰深径渐迷。\n蒲新节尚短，荷小盖犹低。\n无劳拂长袖，直待夜乌啼。' },
  { title: '安德山池宴集', author: '褚遂良', poem: '伏枥丹霞外，遮园焕景舒。\n行云泛层阜，蔽月下清渠。\n亭中奏赵瑟，席上舞燕裾。\n花落春莺晚，风光夏叶初。\n良朋比兰蕙，雕藻迈琼琚。\n独有狂歌客，来承欢宴余。' },
  { title: '安德山池宴集', author: '杨续', poem: '狭斜通凤阙，上路抵青楼。\n簪绂启宾馆，轩盖临御沟。\n西城多妙舞，主第出名讴。\n列峰疑宿雾，疏壑拟藏舟。\n花蝶辞风影，苹藻含春流。\n酒阑高宴毕，自反山之幽。' },
  { title: '游清都观寻沈道士得仙字', author: '刘孝孙', poem: '纷吾因暇豫，行乐极留连。\n寻真谒紫府，披雾觌青天。\n缅怀金阙外，遐想玉京前。\n飞轩俯松柏，抗殿接云烟。\n滔滔清夏景，嘒嘒早秋蝉。\n横琴对危石，酌醴临寒泉。\n聊祛尘俗累，宁希龟鹤年。\n无劳生羽翼，自可狎神仙。' },
  { title: '早发成皐望河', author: '刘孝孙', poem: '清晨发岩邑，车马走轘辕。\n回瞰黄河上，惝怳屡飞魂。\n鸿流遵积石，惊浪下龙门。\n仙槎不辨处，沈璧想犹存。\n远近洲渚出，飒沓凫鴈喧。\n怀古空延伫，叹逝将何言。' },
  { title: '游灵山寺', author: '刘孝孙', poem: '吾王游胜地，骖驾历祗园。\n临风画角愤，耀日采旗翻。\n永怀筌了义，寂念启玄门。\n深谿穷地脉，高嶂接云根。\n信美谐心赏，幽邃且攀援。\n曳裾欣扈从，方悟屏尘諠。' },
  { title: '冬日宴于庶子宅各赋一字得鲜', author: '刘孝孙', poem: '解襟游胜地，披云促宴筵。\n清文振笔妙，高论写言泉。\n冻柳含风落，寒梅照日鲜。\n骊歌虽欲奏，归驾且留连。' },
  { title: '送刘散员同赋陈思王诗游人久不归', author: '刘孝孙', poem: '乡关渺天末，引领怅怀归。\n羁旅久淫滞，物色屡芳菲。\n稍觉私意尽，行看蓬鬓衰。\n如何千里外，伫立沾裳衣。' },
  { title: '咏笛', author: '刘孝孙', poem: '凉秋夜笛鸣，流风韵九成。\n调高时慷慨，曲变或凄清。\n征客怀离绪，邻人思旧情。\n幸以知音顾，千载有奇声。' },
  { title: '赋得春莺送友人', author: '刘孝孙', poem: '流莺拂绣羽，二月上林期。\n待雪消金禁，衔花向玉墀。\n翅掩飞燕舞，啼恼婕妤悲。\n料取金闺意，因君问所思。' },
  { title: '巫山高', author: '陆敬', poem: '巫岫郁岧嶤，高高入紫霄。\n白云抱危石，玄猨挂迥条。\n悬崖激巨浪，脆叶陨惊飙。\n别有阳台处，风雨共飘飖。' },
  { title: '游隋故都', author: '陆敬', poem: '洛城聊顾步，长想遂留连。\n水鬬宫初毁，风变鼎将迁。\n皐陶德不建，汾隅祀忽焉。\n宗祊旷无象，声朔缅谁传。\n枌榆何冷落，禾黍郁芊緜。\n悲歌尽商颂，太息悯周篇。\n来苏伫圣德，濡足乃乘干。\n正始淳风被，人劳用息肩。\n舞象文思泽，偃伯武功宣。\n则百昌厥后，于万永斯年。\n兹辰素商节，灰管变星躔。\n平原悴秋草，乔木敛寒烟。\n翻黄坠疎叶，凝翠积高天。\n参差海曲鴈，寂寞柳门蝉。\n兴悼今如此，悲愁复在旃。\n彷徨不忍去，杖策屡回邅。' },
  { title: '游清都观寻沈道士得都字', author: '陆敬', poem: '聊排灵琐闼，徐步入清都。\n青谿冥寂士，思玄徇道枢。\n十芒生药笥，七燄发丹炉。\n缥袠桐君录，朱书王母符。\n宫槐散绿穗，日槿落青柎。\n矫翰雷门鹤，飞来叶县凫。\n凌风自可御，安事迫中区。\n方追羽化侣，从此得玄珠。' },
  { title: '七夕赋咏成篇', author: '陆敬', poem: '夙驾鸣鸾启阊阖，霓裳遥裔俨天津。\n五明霜纨开羽扇，百和香车动画轮。\n婉娈夜分能几许，靓妆冶服为谁新。\n片时欢娱自有极，已复长望隔年人。' },
  { title: '七夕赋咏成篇', author: '沈叔安', poem: '皎皎宵月丽秋光，耿耿天津横复长。\n停梭且复留残纬，拂镜及早更新妆。\n彩凤齐驾初成辇，雕鹊填河已作梁。\n虽喜得同今夜枕，还愁重空明日床。' },
  { title: '七夕赋咏成篇', author: '何仲宣', poem: '日日思归勤理鬓，朝朝伫望嬾调梭。\n凌风宝扇遥临月，映水仙车远渡河。\n历历珠星疑拖珮，冉冉云衣似曳罗。\n通宵道意终无尽，向晓离愁已复多。' },
  { title: '游清都观寻沈道士得芳字', author: '赵中虚', poem: '青谿阻千仞，姑射藐汾阳。\n未若游兹境，探玄众妙场。\n鹤来疑羽客，云泛似霓裳。\n寓目虽灵宇，游神乃帝乡。\n道存真理得，心灰俗累忘。\n烟霞凝抗殿，松桂肃长廊。\n早蝉清暮响，崇兰散晚芳。\n即此翔寥廓，非复控榆枋。' },
  { title: '送刘散员赋得陈思王诗明月照高楼', author: '杨濬', poem: '高楼一何绮，素月复流明。\n重轩望不极，余晖揽讵盈。\n镜华当牖照，钩影隔帘生。\n逆愁异尊酒，对此难为情。' },
  { title: '陇头水', author: '杨师道', poem: '陇头秋月明，陇水带关城。\n笳添离别曲，风送断肠声。\n映雪峰犹暗，乘冰马屡惊。\n雾中寒雁至，沙上转蓬轻。\n天山传羽檄，汉地急征兵。\n阵开都护道，劒聚伏波营。\n于兹觉无渡，方共濯胡缨。' },
  { title: '中书寓直咏雨简褚起居上官学士', author: '杨师道', poem: '云暗苍龙阙，沈沈殊未开。\n窗临凤凰沼，飒飒雨声来。\n电影入飞阁，风威凌吹台。\n长檐响奔溜，清簟肃浮埃。\n早荷叶稍没，新篁枝半摧。\n兹晨怅多绪，怀友自难裁。\n况复重城内，日暮独裴回。\n玉阶良史笔，金马掞天才。\n高甍通散骑，复道驾蓬莱。\n思君赠桃李，于此冀琼瓌。' },
  { title: '阙题', author: '杨师道', poem: '汉家伊洛九重城，御路浮桥万里平。\n桂户雕梁连绮翼，虹梁绣柱映丹楹。\n朝光欲动千门曙，丽日初照百花明。\n燕赵蛾眉旧倾国，楚宫腰细本传名。\n二月桑津期结伴，三春淇水逐关情。\n兰丛有意飞双蝶，柳叶无趣隐啼莺。\n扇里细妆将夜并，风前独舞共花荣。\n两鬟百万谁论价，一笑千金判是轻。\n不为披图来侍寝，非因主第奉身迎。\n羊车讵畏青门闭，兔月今宵照后庭。' },
  { title: '初秋夜坐应诏', author: '杨师道', poem: '玉琯凉初应，金壶夜渐阑。\n沧池流稍洁，仙掌露方漙。\n雁声风处断，树影月中寒。\n爽气长空净，高吟觉思宽。' },
  { title: '赋终南山用风字韵应诏', author: '杨师道', poem: '眷言怀隐逸，辍驾践幽丛。\n白云飞夏雨，碧岭横春虹。\n草绿长杨路，花疎五柞宫。\n登临日将晚，兰桂起香风。' },
  { title: '咏饮马应诏', author: '杨师道', poem: '清晨控龙马，弄影出花林。\n躞蹀依春涧，联翩度碧浔。\n苔流染丝络，水洁写雕簪。\n一御瑶池驾，讵忆长城阴。' },
  { title: '初宵看婚', author: '杨师道', poem: '洛城花烛动，戚里画新蛾。\n隐扇羞应惯，含情愁已多。\n轻啼湿红粉，微睇转横波。\n更笑巫山曲，空传暮雨过。' },
  { title: '侍宴赋得起坐弹鸣琴二首 一', author: '杨师道', poem: '北林鹊夜飞，南轩月初进。\n调弦发清征，荡心祛褊吝。\n变作离鸿声，还入思归引。\n长叹未终极，秋风飘素鬓。' },
  { title: '侍宴赋得起坐弹鸣琴二首 二', author: '杨师道', poem: '丝传园客意，曲奏楚妃情。\n罕有知音者，空劳流水声。' },
  { title: '咏琴', author: '杨师道', poem: '久擅龙门质，孤竦峄阳名。\n齐娥初发弄，赵女正调声。\n嘉客勿遽反，繁弦曲未成。' },
  { title: '咏笙', author: '杨师道', poem: '短长插凤翼，洪细摹鸾音。\n能令楚妃叹，复使荆王吟。\n切切孤竹管，来应云和琴。' },
  { title: '应诏咏巢乌', author: '杨师道', poem: '桂树春晖满，巢乌刷羽仪。\n朝飞丽城上，夜宿碧林陲。\n背风藏密叶，向日逐疎枝。\n仰德还能哺，依仁遂可窥。\n惊鸣雕辇侧，王吉自相知。' },
  { title: '奉和夏日晚景应诏', author: '杨师道', poem: '辇路夹垂杨，离宫通建章。\n日落横峰影，云归起夕凉。\n雕轩动流吹，羽盖息回塘。\n薙草生还绿，残花落尚香。\n青岩类姑射，碧涧似汾阳。\n幸属无为日，欢娱尚未央。' },
  { title: '奉和圣制春日望海', author: '杨师道', poem: '春山临渤海，征旅辍晨装。\n回瞰卢龙塞，斜瞻肃慎乡。\n洪波回地轴，孤屿映云光。\n落日惊涛上，浮天骇浪长。\n仙台隐螭驾，水府泛鼋梁。\n碣石朝烟灭，之罘归雁翔。\n北巡非汉后，东幸异秦皇。\n搴旗羽林客，跋距少年场。\n龙击驱辽水，鹏飞出带方。\n将举青丘缴，安访白霓裳。' },
  { title: '春朝闲步', author: '杨师道', poem: '休沐乘闲豫，清晨步北林。\n池塘藉芳草，兰芷袭幽衿。\n雾中分晓日，花里弄春禽。\n野迳香恒满，山阶笋屡侵。\n何须命轻盖，桃李自成阴。' },
  { title: '还山宅', author: '杨师道', poem: '暮春还旧岭，徙倚玩年华。\n芳草无行迳，空山正落花。\n垂藤扫幽石，卧柳碍浮槎。\n鸟散茅檐静，云披涧户斜。\n依然此泉路，犹是昔烟霞。' },
  { title: '咏马', author: '杨师道', poem: '宝马权奇出未央，雕鞍照曜紫金装。\n春草初生驰上苑，秋风欲动戏长杨。\n鸣珂屡度章台侧，细蹀经向濯龙傍。\n徒令汉将连年去，宛城今已献名王。' },
  { title: '奉和咏弓', author: '杨师道', poem: '霜重麟胶劲，风高月影圆。\n乌飞随帝辇，雁落逐鸣弦。' },
  { title: '咏砚', author: '杨师道', poem: '圆池类璧水，轻翰染烟华。\n将军欲定远，见弃不应赊。' },
  { title: '奉和正日临朝应诏', author: '杨师道', poem: '皇猷被寰宇，端扆属元辰。\n九重丽天邑，千门临上春。' },
  { title: '咏舞', author: '杨师道', poem: '二八如回雪，三春类早花。\n分行向烛转，一种逐风斜。' },
  { title: '奉和执契静三边应诏', author: '许敬宗', poem: '玄塞隔阴戎，朱光分昧谷。\n地游穷北际，云崖尽西陆。\n星次绝轩台，风衢乖禹服。\n寰区无所外，天覆今咸育。\n窜苗犹有孽，戮负自贻辜。\n疎网妖鲵漏，盘薮怪禽逋。\n髯飞尚假息，乳视暂稽诛。\n干灵振玉弩，神略运璇枢。\n日羽廓游气，天阵清华野。\n升晅光西夜，驰恩溢东泻。\n挥袂静昆炎，开关纳流赭。\n锦轺凌右地，华缨羇大夏。\n清台映罗叶，玄沚控瑶池。\n驼鹿输珍贶，树羽飨来仪。\n辍肴观化宇，栖籞萃条支。\n熏风交阆阙，就日泛蒙漪。\n充庭延饮至，绚简敷春藻。\n迎姜已创图，命力方论道。\n昔托游河乘，再备商山皓。\n欣逢德化流，思效登封草。' },
  { title: '奉和行经破薛举战地应制', author: '许敬宗', poem: '混元分大象，长策挫修鲸。\n于斯建宸极，由此创鸿名。\n一戎干宇泰，千祀德流清。\n垂衣凝庶绩，端拱铸群生。\n复整瑶池驾，还临官渡营。\n周游寻曩迹，旷望动天情。\n帷宫面丹浦，帐殿瞩宛城。\n虏场栖九穗，前歌被六英。\n战地甘泉涌，阵处景云生。\n普天沾凯泽，相携欣颂平。' },
  { title: '奉和入潼关', author: '许敬宗', poem: '曦驭循黄道，星陈引翠旗。\n济潼纡万乘，临河耀六师。\n前旌弥陆海，后骑发通伊。\n势逾回地轴，威盛转天机。\n是节岁穷纪，关树荡凉飔。\n仙露含灵掌，瑞鼎照川湄。\n冲襟赏临睨，高咏入京畿。' },
  { title: '奉和春日望海', author: '许敬宗', poem: '韩夷愆奉賮，凭险乱天常。\n乃神弘庙畧，横海剪吞航。\n电野清玄菟，腾笳振白狼。\n连云飞巨舰，编石架浮梁。\n周游临大壑，降望极遐荒。\n桃门通山抃，蓬渚降霓裳。\n惊涛含蜃阙，骇浪掩晨光。\n青丘绚春组，丹谷耀华桑。\n长驱七萃卒，成功百战场。\n俄且旋戎路，饮至肃岩廊。' },
  { title: '奉和元日应制', author: '许敬宗', poem: '天正开初节，日观上重轮。\n百灵滋景祚，万玉庆惟新。\n待旦敷玄造，韬旒御紫宸。\n武帐临光宅，文卫象钩陈。\n广庭扬九奏，大帛丽三辰。\n发生同化育，播物体陶钧。\n霜空澄晓气，霞景莹芳春。\n德辉覃率[土]，相贺奉还淳。' },
  { title: '奉和初春登楼即目应诏', author: '许敬宗', poem: '旭日临重壁，天眷极中京。\n春晖发芳甸，佳气满层城。\n去鸟随看没，来云逐望生。\n歌里非烟飏，琴上凯风清。\n文波浮镂槛，摛景焕雕楹。\n璇玑体宽政，隆栋象端衡。\n创规虽有作，凝拱遂无营。\n沐恩空改鬓，将何谢夏成。' },
  { title: '奉和秋日即目应制', author: '许敬宗', poem: '玉露交珠网，金风度绮钱。\n昆明秋景淡，岐岫落霞然。\n辞燕归寒海，来鸿出远天。\n叶动罗帷飏，花映绣裳鲜。\n规空升暗魄，笼野散轻烟。\n鹊度林光起，凫没水文圆。\n无机络秋纬，如管奏寒蝉。\n乃睠情何极，宸襟豫有旃。' },
  { title: '奉和秋暮言志应制', author: '许敬宗', poem: '秋深桂初发，寒窗菊余菲。\n波拥群凫至，秋飘朔雁归。\n月荚生还落，云枝似复非。\n凝宸阅栖亩，观文伫少微。\n圣敬韬前哲，先天谅不违。' },
  { title: '奉和喜雪应制', author: '许敬宗', poem: '嵰州表奇贶，閟竹应遐巡。\n何如御京洛，流霰下天津。\n忽若琼林曙，俄同李径春。\n姑峰映仙质，郢路杂歌尘。\n伏槛观花瑞，称觞庆冬积。\n飘河共泻银，委树还重璧。\n连山分掩翠，绵霄远韬碧。\n千里徧浮空，五轫咸沦迹。\n机前辉裂素，池上伴凌波。\n腾华承玉宇，凝照混金娥。\n是日松筠性，欣奉柏梁歌。' },
  { title: '奉和登陕州城楼应制', author: '许敬宗', poem: '挹河澂绿宇，御沟映朱宫。\n辰旗翻丽景，星盖曳雕虹。\n学嚬齐柳嫩，妍笑发春藂。\n锦鳞文碧浪，绣羽绚青空。\n眷念三阶静，遥想二南风。' },
  { title: '游清都观寻沈道士得清字', author: '许敬宗', poem: '幽人蹈箕颍，方士访蓬瀛。\n岂若逢真气，齐契体无名。\n既诠众妙理，聊畅远游情。\n纵心驰贝阙，怡神想玉京。\n或命余杭酒，时听洛滨笙。\n风衢通阆苑，星使下层城。\n蕙帐晨飙动，芝房夕露清。\n方叶栖迟趣，于此听钟声。' },
  { title: '奉和七夕宴悬圃应制二首 一', author: '许敬宗', poem: '牛闺临浅汉，鸾驷涉秋河。\n两怀萦别绪，一宿庆停梭。\n星模铅里靥，月写黛中蛾。\n奈许今宵度，长婴离恨多。' },
  { title: '奉和七夕宴悬圃应制二首 二', author: '许敬宗', poem: '婺闺期今夕，娥轮泛浅潢。\n迎秋伴暮雨，待暝合神光。\n荐寝低云鬓，呈态解霓裳。\n喜中愁漏促，别后怨天长。' },
  { title: '奉和仪鸾殿早秋应制', author: '许敬宗', poem: '睿想追嘉豫，临轩御早秋。\n斜晖丽粉壁，清吹肃朱楼。\n高殿凝阴满，雕窗艳曲流。\n小臣参广宴，大造谅难酬。' },
  { title: '奉和咏雨应诏', author: '许敬宗', poem: '舞商初赴节，湘燕远迎秋。\n飘丝交殿网，乱滴起池沤。\n激溜分龙阙，斜飞洒凤楼。\n崇朝方浃宇，宸盼俯凝旒。' },
  { title: '奉和过慈恩寺应制', author: '许敬宗', poem: '凤阙隣金地，龙旗拂宝台。\n云楣将叶并，风牖送花来。\n月宫清晚桂，虹梁绚早梅。\n梵境留宸瞩，掞发丽天才。' },
  { title: '冬日宴于庶子宅各赋一字得归', author: '许敬宗', poem: '倦游嗟落拓，短翮慕追飞。\n周醪忽同醉，牙弦乃共挥。\n油云澹寒色，落景霭霜霏。\n累日方投分，兹夕谅无归。' },
  { title: '送刘散员同赋得陈思王诗山树郁苍苍', author: '许敬宗', poem: '乔木托危岫，积翠绕连冈。\n叶疎犹漏影，花少未流芳。\n风来闻肃肃，雾罢见苍苍。\n此中饯行迈，不异上河梁。' },
  { title: '侍宴莎册宫应制得情字', author: '许敬宗', poem: '三星希曙景，万骑翊天行。\n葆羽翻风队，腾吹掩山楹。\n暖日晨光浅，飞烟旦彩轻。\n塞寒桃变色，冰断箭流声。\n渐奏长安道，神皐动睿情。' },
  { title: '奉和过旧宅应制', author: '许敬宗', poem: '飞云临紫极，出震表青光。\n自尔家寰海，今兹返帝乡。\n情深感代国，乐甚䜩谯方。\n白水浮佳气，黄星聚太常。\n岐凤鸣层阁，酆雀贺雕梁。\n桂山犹总翠，蘅薄尚流芳。\n攀鳞有遗皓，沐德抃称觞。' },
  { title: '奉和宴中山应制', author: '许敬宗', poem: '飞云旋碧海，解网宥青丘。\n养贤停八骏，观风驻五牛。\n张乐临尧野，扬麾历舜州。\n中山献仙酤，赵媛发清讴。\n塞门朱鴈入，郊薮紫麟游。\n一举氛霓静，千龄德化流。' },
  { title: '奉和圣制登三台言志应制', author: '许敬宗', poem: '中天表云榭，载极耸昆楼。\n圣作规玄造，轩阿复聿修。\n高门符令节，形胜总神州。\n企翼抟禽萃，飞甍燕雀游。\n缀星罗百拱，缘汉转三休。\n旦云生玉舃，初月上银钩。\n妙管含秦凤，仙姿丽斗牛。\n形言防处逸，粹藻发嘉猷。\n荷生无以谢，尽瘁竟何酬。' },
  { title: '安德山池宴集', author: '许敬宗', poem: '戚里欢娱地，园林瞩望新。\n山庭带芳杜，歌吹叶阳春。\n台榭疑巫峡，荷蕖似洛滨。\n风花萦少女，虹梁聚美人。\n宴游穷至乐，谈笑毕良辰。\n独叹高阳晚，归路不知津。' },
  { title: '奉和圣制送来济应制', author: '许敬宗', poem: '万乘腾镳警岐路，百壶供帐饯离宫。\n御沟分水声难绝，广宴当歌曲易终。\n兴言共伤千里道，俯迹聊示五情同。\n良哉既深留帝念，沃化方有赞天聪。' },
  { title: '七夕赋咏成篇', author: '许敬宗', poem: '一年抱怨嗟长别，七夕含态始言归。\n飘飘罗袜光天步，灼灼新妆鉴月辉。\n情催巧笑开星靥，不惜呈露解云衣。\n所叹却随更漏尽，掩泣还弄昨宵机。' },
  { title: '拟江令于长安归扬州九日赋', author: '许敬宗', poem: '本逐征鸿去，还随落叶来。\n菊花应未满，请待诗人开。' },
  { title: '和边城秋气早', author: '李义府', poem: '金微凝素节，玉律应清葭。\n边马秋声急，征鸿晓阵斜。\n关树凋凉叶，塞草落寒花。\n雾暗长川景，云昏大漠沙。\n谿深路难越，川平望超忽。\n极望断烟飘，遥落惊蓬没。\n霜结龙城吹，水照龟林月。\n日色夏犹冷，霜华春未歇。\n睿作高紫宸，分明映玄阙。' },
  { title: '招谕有怀赠同行人', author: '李义府', poem: '远游冒艰阻，深入劳存谕。\n春去辞国门，秋还在边戍。\n轩车行未返，节序催难驻。\n陌上悲转蓬，园中想芳树。\n蜀山自纷纠，岷水恒奔注。\n临泛多苦怀，登攀寡欢趣。\n永夕飞淫雨，崇朝蒸毒雾。\n不求绥岭桃，宁美邛乡蒟。\n白狼行欲静，骢马何常驱。\n愿接轺斾尘，联翩东北骛。' },
  { title: '宣正殿芝草', author: '李义府', poem: '明王敦孝感，宝殿秀灵芝。\n色带朝阳净，光涵雨露滋。\n且标宣德重，更引国恩施。\n圣祚今无限，微臣乐未移。' },
  { title: '咏鹦鹉', author: '李义府', poem: '牵弋辞重海，触网去层峦。\n戢翼雕笼际，延思彩霞端。\n慕侣朝声切，离群夜影寒。\n能言殊可贵，相助忆长安。' },
  { title: '在巂州遥敍封禅', author: '李义府', poem: '天齐标巨镇，日观启崇朝。\n岧嶤临渤澥，隐嶙控河沂。\n眺迥分吴乘，凌高属汉祠。\n建岳诚为长，升功谅在兹。\n帝猷符广运，玄范畅文思。\n飞声总地络，腾化抚干维。\n瑞策开珍凤，祯图荐宝龟。\n创封超昔夏，修禅掩前姬。\n东后方肆觐，西都导六师。\n肃驾移星苑，扬罕驭风司。\n沸鼓喧平陆，凝跸静通逵。\n汶阳驰月羽，蒙阴警电麾。\n岩花飘曙辇，峰叶荡春旗。\n石闾环藻卫，金坛映黼帷。\n仙阶溢秘秬，灵检燿祥芝。\n张乐分韶濩，观礼纵华夷。\n佳气浮丹谷，荣光泛绿坻。\n三始贻遐贶，万岁受重厘。\n菲质陶恩奖，趋迹奉轩墀。\n触网沦幽裔，乘徼限明时。\n周南昔已叹，邛西今复悲。' },
  { title: '堂堂词二首 一', author: '李义府', poem: '镂月成歌扇，裁云作舞衣。\n自怜回雪影，好取洛川归。' },
  { title: '堂堂词二首 二', author: '李义府', poem: '嬾整鸳鸯被，羞褰玳瑁床。\n春风别有意，密处也寻香。' },
  { title: '咏乌', author: '李义府', poem: '日里飏朝彩，琴中伴夜啼。\n上林如许树，不借一枝栖。' },
  { title: '从军行二首 一', author: '虞世南', poem: '涂山烽候惊，弭节度龙城。\n冀马楼兰将，燕犀上谷兵。\n劒寒花不落，弓晓月逾明。\n凛凛严霜节，冰壮黄河绝。\n蔽日卷征蓬，浮天散飞雪。\n全兵值月满，精骑乘胶折。\n结发早驱驰，辛苦事旌麾。\n马冻重关冷，轮摧九折危。\n独有西山将，年年属数奇。' },
  { title: '从军行二首 二', author: '虞世南', poem: '烽火发金微，连营出武威。\n孤城塞云起，绝阵虏尘飞。\n侠客吸龙劒，恶少缦胡衣。\n朝摩骨都垒，夜解谷蠡围。\n萧关远无极，蒲海广难依。\n沙磴离旌断，晴川候马归。\n交河梁已毕，燕山斾欲挥。\n方知万里相，侯服见光辉。' },
  { title: '拟饮马长城窟', author: '虞世南', poem: '驰马渡河干，流深马渡难。\n前逢锦车使，都护在楼兰。\n轻骑犹衔勒，疑兵尚解鞍。\n温池下绝涧，栈道接危峦。\n拓地勋未赏，亡城律岂宽。\n有月关犹暗，经春陇尚寒。\n云昏无复影，冰合不闻湍。\n怀君不可遇，聊持报一飧。' },
  { title: '出塞', author: '虞世南', poem: '上将三略远，元戎九命尊。\n缅怀古人节，思酬明主恩。\n山西多勇气，塞北有游魂。\n扬桴上陇坂，勒骑下平原。\n誓将绝沙漠，悠然去玉门。\n轻赍不遑舍，惊策骛戎轩。\n凛凛边风急，萧萧征马烦。\n雪暗天山道，冰塞交河源。\n雾锋黯无色，霜旗冻不翻。\n耿介倚长劒，日落风尘昏。' },
  { title: '结客少年场行', author: '虞世南', poem: '韩魏多奇节，倜傥遗声利。\n共矜然诺心，各负纵横志。\n结交一言重，相期千里至。\n绿沈明月弦，金络浮云辔。\n吹箫入吴市，击筑游燕肆。\n寻源博望侯，结客远相求。\n少年怀一顾，长驱背陇头。\n燄燄戈霜动，耿耿劒虹浮。\n天山冬夏雪，交河南北流。\n云起龙沙暗，木落鴈门秋。\n轻生殉知己，非是为身谋。' },
  { title: '怨歌行', author: '虞世南', poem: '紫殿秋风冷，雕甍落日沈。\n裁纨凄断曲，织素别离心。\n掖庭羞改画，长门不惜金。\n宠移恩稍薄，情疎恨转深。\n香销翠羽帐，弦断凤皇琴。\n镜前红粉歇，阶上绿苔侵。\n谁言掩歌扇，翻作白头吟。' },
  { title: '中妇织流黄', author: '虞世南', poem: '寒闺织素锦，含怨敛双蛾。\n综新交缕澁，经脆断丝多。\n衣香逐举袖，钏动应鸣梭。\n还恐裁缝罢，无信达交河。' },
  { title: '门有车马客', author: '虞世南', poem: '陈遵重交结，田蚡擅豪华。\n曲台临上路，高轩抵狭斜。\n赭汗千金马，绣轴五香车。\n白鹤随飞盖，朱鹭入鸣笳。\n夏莲开劒水，春桃发绶花。\n高谈辩飞兔，摛藻握灵蛇。\n逢恩出毛羽，失路委泥沙。\n暧暧风烟晚，路长归骑远。\n日斜青琐第，尘飞金谷苑。\n危弦促柱奏巴渝，遗簪堕珥解罗襦。\n如何守直道，翻使谷名愚。' },
  { title: '飞来双白鹤', author: '虞世南', poem: '飞来双白鹤，奋翼远凌烟。\n俱栖集紫盖，一举背青田。\n飏影过伊洛，流声入管弦。\n鸣群倒景外，刷羽阆风前。\n暎海疑浮雪，拂涧泻飞泉。\n燕雀宁知去，蜉蝣不识还。\n何言别俦侣，从此间山川。\n顾步已相失，裴回各自怜。\n危心犹警露，哀响讵闻天。\n无因振六翮，轻举复随仙。' },
  { title: '奉和幽山雨后应令', author: '虞世南', poem: '肃城邻上苑，黄山迩桂宫。\n雨歇连峰翠，烟开竟野通。\n排虚翔戏鸟，跨水落长虹。\n日下林全暗，云收岭半空。\n山泉鸣石涧，地籁响岩风。' },
  { title: '赋得吴都', author: '虞世南', poem: '画野通淮泗，星躔应斗牛。\n玉牒宏图表，黄旗美气浮。\n三分开霸业，万里宅神州。\n高台临茂苑，飞阁跨澄流。\n江涛如素盖，海气似朱楼。\n吴趋自有乐，还似镜中游。' },
  { title: '赋得慎罚', author: '虞世南', poem: '帝图光往册，上德表鸿名。\n道冠二仪始，风高三代英。\n乐和知化洽，讼息表刑清。\n罚轻犹在念，忽喜尚留情。\n明慎全无枉，哀矜在好生。\n五疵过亦察，二辟理弥精。\n幪巾示廉耻，嘉石务详平。\n每削繁苛性，常深恻隐诚。\n政宽思济猛，疑罪必从轻。\n于张惩不滥，陈郭宪无倾。\n刑措谅斯在，欢然仰颂声。' },
  { title: '奉和咏日午', author: '虞世南', poem: '高天净秋色，长汉转曦车。\n玉树阴初正，桐圭影未斜。\n翠盖飞圆彩，明镜发轻花。\n再中良表瑞，共仰璧晖赊。' },
  { title: '发营逢雨应诏', author: '虞世南', poem: '豫游欣胜地，皇泽乃先天。\n油云阴御道，膏雨润公田。\n陇麦沾逾翠，山花湿更然。\n稼穑良所重，方复悦丰年。' },
  { title: '赋得临池竹应制', author: '虞世南', poem: '葱翠梢云质，垂彩暎清池。\n波泛含风影，流摇防露枝。\n龙鳞漾嶰谷，凤翅拂涟漪。\n欲识凌冬性，唯有岁寒知。' },
  { title: '侍宴应诏赋韵得前字', author: '虞世南', poem: '芬芳禁林晚，容与桂丹前。\n横空一鸟度，照水百花然。\n绿野明斜日，青山澹晚烟。\n滥陪终宴赏，握管类窥天。' },
  { title: '侍宴归鴈堂', author: '虞世南', poem: '歌堂面渌水，舞馆接金塘。\n竹开霜后翠，梅动雪前香。\n凫归初命侣，鴈起欲分行。\n刷羽同栖集，怀恩愧稻粱。' },
  { title: '凌晨早朝', author: '虞世南', poem: '万瓦宵光曙，重檐夕雾收。\n玉花停夜烛，金壶送晓筹。\n日晖青琐殿，霞生结绮楼。\n重门应启路，通籍引王侯。' },
  { title: '奉和咏风应魏王教', author: '虞世南', poem: '逐舞飘轻袖，传歌共绕梁。\n动枝生乱影，吹花送远香。' },
  { title: '初晴应教', author: '虞世南', poem: '初日明燕馆，新溜满梁池。\n归云半入岭，残滴尚悬枝。' },
  { title: '春夜', author: '虞世南', poem: '春苑月裴回，竹堂侵夜开。\n惊鸟排林度，风花隔水来。' },
  { title: '咏舞', author: '虞世南', poem: '繁弦奏渌水，长袖转回鸾。\n一双俱应节，还似镜中看。' },
  { title: '咏萤', author: '虞世南', poem: '的历流光小，飘飖弱翅轻。\n恐畏无人识，独自暗中明。' },
  { title: '蝉', author: '虞世南', poem: '垂緌饮清露，流响出疎桐。\n居高声自远，非是藉秋风。' },
  { title: '秋鴈', author: '虞世南', poem: '日暮霜风急，羽翮转难任。\n为有传书意，联翩入上林。' },
  { title: '奉和月夜观星应令', author: '虞世南', poem: '早秋炎景暮，初弦月彩新。\n清风涤暑气，零露净嚣尘。\n薄雾销轻縠，鲜云卷夕鳞。\n休光灼前曜，瑞彩接重轮。\n缘情摛圣藻，并作命徐陈。\n宿草诚渝滥，吹嘘偶搢绅。\n天文岂易述，徒知仰北辰。' },
  { title: '和銮舆顿戏下', author: '虞世南', poem: '重轮依紫极，前耀奉丹霄。\n天经恋宸扆，帝命扈仙镳。\n乘[星]开鹤禁，带月下虹桥。\n银书含晓色，金辂转晨飙。\n雾澈轩营近，尘暗苑城遥。\n莲花分秀蕚，竹箭下惊潮。\n抚己慙龙干，承恩集凤条。\n瑶山盛风乐，抽简荐徒谣。' },
  { title: '奉和至寿春应令', author: '虞世南', poem: '瑶山盛风乐，南巡务逸游。\n如何事巡抚，民瘼谅斯求。\n文鹤扬轻盖，苍龙饰桂舟。\n泛沫萦沙屿，寒澌拥急流。\n路指八仙馆，途经百尺楼。\n眷言昔游践，廻驾且淹留。\n后车喧凤吹，前旌暎彩旒。\n龙骖驻六马，飞阁上三休。\n调谐金石奏，欢洽羽觞浮。\n天文徒可仰，何以厕琳球。' },
  { title: '奉和幸江都应诏', author: '虞世南', poem: '南国行周化，稽山秘夏图。\n百王岂殊轨，千载协前谟。\n肆觐遵时豫，顺动悦来苏。\n安流进玉轴，戒道翼金吾。\n龙旗焕辰象，凤吹溢川涂。\n封唐昔敷锡，分陕被荆吴。\n沐道咸知让，慕义久成都。\n冬律初飞管，阳鸟正衔芦。\n严飙肃林薄，暧景澹江湖。\n鸿私浃幽远，厚泽润凋枯。\n虞琴起歌咏，汉筑动巴歈。\n多幸沾行苇，无庸类散樗。' },
  { title: '奉和献岁䜩宫臣', author: '虞世南', poem: '履端初起节，长苑命高筵。\n肆夏喧金奏，重润响朱弦。\n春光催柳色，日彩泛槐烟。\n微臣同滥吹，谬得仰钧天。' },
  { title: '奉和出颍至淮应令', author: '虞世南', poem: '良晨喜利涉，解缆入淮浔。\n寒流泛鹢首，霜吹响哀吟。\n潜鳞波里跃，水鸟浪前沈。\n邗沟非复远，怅望悦宸襟。' },
  { title: '应诏嘲司花女', author: '虞世南', poem: '学画鸦黄半未成，垂肩軃亸袖太憨生。\n缘憨却得君王惜，长把花枝傍辇行。' },
  { title: '古意六首 一', author: '王绩', poem: '幽人在何所？紫岩有仙躅。\n月下横宝琴，此外将安欲。\n材抽峄山干，徽点昆丘玉。\n漆抱蛟龙唇，丝缠凤凰足。\n前弹广陵罢，后以明光续。\n百金买一声，千金传一曲。\n世无钟子期，谁知心所属。' },
  { title: '古意六首 二', author: '王绩', poem: '竹生大夏谿，苍苍富奇质。\n绿叶吟风劲，翠茎犯霄密。\n霜霰封其柯，鹓鸾食其实。\n宁知轩辕后，更有伶伦出。\n刀斧俄见寻，根株坐相失。\n裁为十二管，吹作雄雌律。\n有用虽自伤，无心复招疾。\n不如山上草，离离保终吉。' },
  { title: '古意六首 三', author: '王绩', poem: '宝龟尺二寸，由来宅深水。\n浮游五湖内，宛转三江里。\n何不深复深，轻然至溱洧。\n溱洧源流狭，春秋不濡轨。\n渔人递往还，网罟相萦藟。\n一朝失运会，刳肠血流死。\n丰骨输庙堂，鲜腴籍笾簋。\n弃置谁怨尤，自我招此否。\n余灵寄明卜，复来钦所履。' },
  { title: '古意六首 四', author: '王绩', poem: '松生北岩下，由来人径绝。\n布叶捎云烟，插根拥岩穴。\n自言生得地，独负凌云洁。\n何时畏斤斧，几度经霜雪。\n风惊西北枝，雹陨东南节。\n不知岁月久，稍觉枝干折。\n藤萝上下碎，枝干纵横裂。\n行当糜烂尽，坐共灰尘灭。\n宁关匠石顾，岂为王孙折。\n盛衰自有时，圣贤未尝屑。\n寄言悠悠者，无为嗟大耋。' },
  { title: '古意六首 五', author: '王绩', poem: '桂树何苍苍，秋来花更芳。\n自言岁寒性，不知露与霜。\n幽人重其德，徙植临前堂。\n连拳八九树，偃蹇二三行。\n枝枝自相纠，叶叶还相当。\n去来双鸿鹄，栖息两鸳鸯。\n荣荫诚不厚，斤斧亦勿伤。\n赤心许君时，此意那可忘。' },
  { title: '古意六首 六', author: '王绩', poem: '彩凤欲将归，提罗出郊访。\n罗张大泽已，凤入重云飏。\n朝栖昆阆木，夕饮蓬壶涨。\n问凤那远飞，贤君坐相望。\n凤言荷深德，微禽安足尚。\n但使雏卵全，无令[矰]缴放。\n皇臣力牧举，帝乐箫韶畅。\n自有来巢时，明年阿阁上。' },
  { title: '石竹咏', author: '王绩', poem: '萋萋结绿枝，晔晔垂朱英。\n常恐零露降，不得全其生。\n叹息聊自思，此生岂我情。\n昔我未生时，谁者令我萌。\n弃置勿重陈，委化何足惊。' },
  { title: '田家三首 一', author: '王绩', poem: '阮籍生涯懒，嵇康意气疎。\n相逢一醉饱，独坐数行书。\n小池聊养鹤，闲田且牧猪。\n草生元亮径，花暗子云居。\n倚床看妇织，登垅课儿锄。\n回头寻仙事，并是一空虚。' },
  { title: '田家三首 二', author: '王绩', poem: '家住箕山下，门枕颍川滨。\n不知今有汉，唯言昔避秦。\n琴伴前庭月，酒劝后园春。\n自得中林士，何忝上皇人。' },
  { title: '田家三首 三', author: '王绩', poem: '平生唯酒乐，作性不能无。\n朝朝访乡里，夜夜遣人酤。\n家贫留客久，不暇道精麤。\n抽帘持益炬，拔箦更燃炉。\n恒闻饮不足，何见有残壶。' },
  { title: '赠李征君大寿', author: '王绩', poem: '孔淳辞散骑，陆昶谢中郎。\n幅巾朝帝罢，杖策去官忙。\n附车还赵郡，乘船向武昌。\n九征书未已，十辟誉弥彰。\n副君迎绮季，天子送严光。\n灞陵幽径近，磻谿隐路长。\n编蓬还作室，绩草更为裳。\n会稽置樵处，兰陵卖药行。\n看书惟道德，开教止农桑。\n别有幽怀侣，由来高让王。\n前年辞厚币，今岁返寒乡。\n有书横石架，无毡坐土床。\n兰英犹足酿，竹实本无粮。\n涧松寒转直，山菊秋自香。\n管宁存祭礼，王霸重朝章。\n去去相随去，披裘骄盛唐。' },
  { title: '山中敍志', author: '王绩', poem: '物外知何事，山中无所有。\n风鸣静夜琴，月照芳春酒。\n直置百年内，谁论千载后。\n张奉娉贤妻，老莱籍嘉偶。\n孟光傥未嫁，梁鸿正须妇。' },
  { title: '赠梁公', author: '王绩', poem: '我欲图世乐，斯乐难可常。\n位大招讥嫌，禄极生祸殃。\n圣莫若周公，忠岂逾霍光。\n成王已兴诮，宣帝如负芒。\n范蠡何智哉，单舟戒轻装。\n疏广岂不怀，策杖还故乡。\n朱门虽足悦，赤族亦可伤。\n履霜成坚冰，知足胜不祥。\n我今穷家子，自言此见长。\n功成皆能退，在昔谁灭亡。' },
  { title: '薛记室收过庄见寻率题古意以赠', author: '王绩', poem: '伊昔逢丧乱，历数闰当余。\n豺狼塞衢路，桑梓成丘墟。\n余及尔皆亡，东西各异居。\n尔为背风鸟，我为涸辙鱼。\n逮承云雷后，欣逢天地初。\n东川聊下钓，南亩试挥锄。\n资税幸不及，伏腊常有储。\n散诞时须酒，萧条嬾向书。\n朽木不可雕，短翮将焉摅。\n故人有深契，过我蓬高庐。\n曳裾出门迎，握手登前除。\n相看非旧颜，忽若形骸疎。\n追道宿昔事，切切心相于。\n忆我少年时，携手游东渠。\n梅李夹两岸，花枝何扶疏。\n同志亦不多，西庄有姚徐。\n尝爱陶渊明，酌醴焚枯鱼。\n尝学公孙弘，策杖牧群猪。\n追念甫如昨，奄忽成空虚。\n人生讵能几，岁岁常不舒。\n赖有北山僧，教我以真如。\n使我视听遣，自觉尘累祛。\n何事须筌蹄，今已得兔鱼。\n旧游傥多暇，同此释纷拏。' },
  { title: '晚年敍志示翟处士', author: '王绩', poem: '弱龄慕奇调，无事不兼修。\n望气登重阁，占星上小楼。\n明经思待诏，学剑觅封侯。\n弃𦈡频北上，怀刺几西游。\n中年逢丧乱，非复昔追求。\n失路青门隐，藏名白社游。\n风云私所爱，屠博暗为俦。\n解纷曾霸越，释难颇存周。\n晚岁聊长想，生涯太若浮。\n归来南亩上，更坐北溪头。\n古岸多磐石，春泉足细流。\n东隅诚已谢，西景惧难收。\n无谓退耕近，伏念已经秋。\n庚桑逢处跪，陶潜见人羞。\n三晨宁举火，五月镇披裘。\n自有居常乐，谁知身世忧。' },
  { title: '春日', author: '王绩', poem: '前旦出园游，林华都未有。\n今朝下堂来，池冰开已久。\n雪被南轩梅，风催北庭柳。\n遥呼灶前妾，却报机中妇。\n年光恰恰来，满瓮营春酒。' },
  { title: '采药', author: '王绩', poem: '野情贪药饵，郊居倦蓬荜。\n青龙护道符，白犬游仙术。\n腰镰戊己月，负锸庚辛日。\n时时断嶂遮，往往孤峰出。\n行披葛仙经，坐检神农帙。\n龟蛇采二苓，赤白寻双术。\n地冻根难尽，藂枯苗易失。\n从容肉作名，薯蓣高成质。\n家丰松叶酒，器贮参花蜜。\n且复归去来，刀圭辅衰疾。' },
  { title: '在京思故园见乡人问', author: '王绩', poem: '旅泊多年岁，老去不知回。\n忽逢门前客，道发故乡来。\n敛眉俱握手，破涕共衔杯。\n殷勤访朋旧，屈曲问童孩。\n衰宗多弟姪，若个赏池台。\n旧园今在否，新树也应栽。\n柳行疎密布，茅斋宽窄裁。\n经移何处竹？别种几株梅。\n渠当无绝水，石计总生苔。\n院果谁先熟，林花那后开。\n羇心祗欲问，为报不须猜。\n行当驱下泽，去剪故园莱。' },
  { title: '北山', author: '王绩', poem: '旧知山里绝氛埃，登高日暮心悠哉。\n子平一去何时返？仲叔长游遂不来。\n幽兰独夜清琴曲，桂树凌云浊酒杯。\n槁项同枯木，丹心等死灰。' },
  { title: '野望', author: '王绩', poem: '东皐薄暮望，徙倚欲何依。\n树树皆秋色，山山唯落晖。\n牧人驱犊返，猎马带禽归。\n相顾无相识，长歌怀采薇。' },
  { title: '赠程处士', author: '王绩', poem: '百年长扰扰，万事悉悠悠。\n日光随意落，河水任情流。\n礼乐囚姬旦，诗书缚孔丘。\n不如高枕枕，时取醉消愁。' },
  { title: '九月九日赠崔使君善为', author: '王绩', poem: '野人迷节候，端坐隔尘埃。\n忽见黄花吐，方知素节回。\n映岩千段发，临浦万株开。\n香气徒盈把，无人送酒来。' },
  { title: '独坐', author: '王绩', poem: '问君樽酒外，独坐更何须。\n有客谈名理，无人索地租。\n三男婚令族，五女嫁贤夫。\n百年随分了，未羡陟方壶。' },
  { title: '游仙四首 一', author: '王绩', poem: '暂出东陂路，过访北岩前。\n蔡经新学道，王烈旧成仙。\n驾鹤来无日，乘龙去几年。\n三山银作地，八洞玉为天。\n金精飞欲尽，石髓溜应坚。\n自悲生世促，无暇待桑田。' },
  { title: '游仙四首 二', author: '王绩', poem: '上月芝兰径，中岩紫翠房。\n金壶新练乳，玉釜始煎香。\n六局黄公术，三门赤帝方。\n吹沙聊作鸟，动石试为羊。\n缑氏还程促，瀛洲会日长。\n谁知北岩下，延首咏霓裳。' },
  { title: '游仙四首 三', author: '王绩', poem: '结衣寻野路，负杖入山门。\n道士言无宅，仙人更有村。\n斜溪横桂渚，小径入桃源。\n玉床尘稍冷，金炉火尚温。\n心疑游北极，望似陟西昆。\n逆愁归旧里，萧条访子孙。' },
  { title: '游仙四首 四', author: '王绩', poem: '真经知那是，仙骨定何为。\n许迈心长切，嵇康命似奇。\n桑疎金阙迥，苔重石梁危。\n照水然犀角，游山费虎皮。\n鸭桃闻已种，龙竹未经骑。\n为向天仙道，栖遑君讵知。' },
  { title: '策杖寻隐士', author: '王绩', poem: '策杖寻隐士，行行路渐赊。\n石梁横涧断，土室映山斜。\n孝然纵有舍，威辇遂无家。\n置酒烧枯叶，披书坐落花。\n新垂滋水钓，旧结茂陵罝。\n岁岁长如此，方知轻世华。' },
  { title: '赠学仙者', author: '王绩', poem: '采药层城远，寻师海路赊。\n玉壶横日月，金阙断烟霞。\n仙人何处在？道士未还家。\n谁知彭泽意，更覔步兵那。\n春酿煎松叶，秋杯浸菊花。\n相逢宁可醉，定不学丹砂。' },
  { title: '黄颊山', author: '王绩', poem: '别有青溪道，斜亘碧岩隈。\n崩榛横古蔓，荒石拥寒苔。\n野心长寂寞，山径本幽回。\n步步攀藤上，朝朝负药来。\n几看松叶秀，频值菊花开。\n无人堪作伴，岁晚独悠哉。' },
  { title: '建德破后入长安咏秋蓬示辛学士', author: '王绩', poem: '遇坎聊知止，逢风或未归。\n孤根何处断？轻叶强能飞。' },
  { title: '过酒家五首 一', author: '王绩', poem: '洛阳无大宅，长安乏主人。\n黄金销未尽，祗为酒家贫。' },
  { title: '过酒家五首 二', author: '王绩', poem: '此日长昏饮，非关养性灵。\n眼看人尽醉，何忍独为醒。' },
  { title: '过酒家五首 三', author: '王绩', poem: '竹叶连糟翠，蒲萄带曲红。\n相逢不令尽，别后为谁空。' },
  { title: '过酒家五首 四', author: '王绩', poem: '对酒但知饮，逢人莫强牵。\n倚𬬻便得睡，横瓮足堪眠。' },
  { title: '过酒家五首 五', author: '王绩', poem: '有客须教饮，无钱可别沽。\n来时长道贳，慙媿酒家胡。' },
  { title: '夜还东溪', author: '王绩', poem: '石苔应可践，丛枝幸易攀。\n青溪归路直，乘月夜歌还。' },
  { title: '山中别李处士', author: '王绩', poem: '为向东溪道，人来路渐赊。\n山中春酒熟，何处得停家。' },
  { title: '初春', author: '王绩', poem: '春来日渐长，醉客喜年光。\n稍觉池亭好，偏宜酒瓮香。' },
  { title: '醉后', author: '王绩', poem: '阮籍醒时少，陶潜醉日多。\n百年何足度，乘兴且长歌。' },
  { title: '题酒店壁', author: '王绩', poem: '昨夜缾始尽，今朝瓮即开。\n梦中占梦罢，还向酒家来。' },
  { title: '戏题卜铺壁', author: '王绩', poem: '旦逐刘伶去，宵随毕卓眠。\n不应长卖卜，须得杖头钱。' },
  { title: '尝春酒', author: '王绩', poem: '野觞浮郑酌，山酒漉陶巾。\n但令千日醉，何惜两三春。' },
  { title: '独酌', author: '王绩', poem: '浮生知几日，无状逐空名。\n不知多酿酒，时向竹林倾。' },
  { title: '秋夜喜遇王处士', author: '王绩', poem: '北场芸藿罢，东皐刈黍归。\n相逢秋月满，更值夜萤飞。' },
  { title: '山夜调琴', author: '王绩', poem: '促轸乘明月，抽弦对白云。\n从来山水韵，不使俗人闻。' },
  { title: '看酿酒', author: '王绩', poem: '六月调神曲，正朝汲美泉。\n从来作春酒，未省不经年。' },
  { title: '食后', author: '王绩', poem: '田家无所有，晚食遂为常。\n菜剪三秋绿，飧炊百日黄。\n胡麻山𪎊样，楚豆野麋方。\n始暴松皮脯，新添杜若浆。\n葛花消酒毒，萸蔕发羹香。\n鼓腹聊乘兴，宁知逢世昌。' },
  { title: '过汉故城', author: '王绩', poem: '大汉昔未定，强秦犹擅场。\n中原逐鹿罢，高祖郁龙骧。\n经始谋帝坐，兹焉壮未央。\n规模穷栋宇，表里浚城隍。\n群后崇长乐，中朝增建章。\n钩陈被兰锜，乐府奏芝房。\n翡翠明珠帐，鸳鸯白玉堂。\n清晨宝鼎食，闲夜郁金香。\n天马来东道，佳人倾北方。\n何其赫隆盛，自谓保灵长。\n历数有时尽，哀平嗟不昌。\n冰坚成巨猾，火德遂颓纲。\n奥位匪虚校，贪天竟速亡。\n魂神吁社稷，豺虎鬬岩廊。\n金狄移灞岸，铜盘向洛阳。\n君王无处所，年代几荒凉。\n宫阙谁家域，蓁芜罥我裳。\n井田唯有草，海水变为桑。\n在昔高门内，于今岐路傍。\n余基不可识，古墓列成行。\n狐兔惊魍魉，鸱鸮吓獝狂。\n空城寒日晚，平野暮云黄。\n烈烈焚青棘，萧萧吹白杨。\n千秋幷万岁，空使咏歌伤。' },
  { title: '益州城西张超亭观妓', author: '王绩', poem: '落日明歌席，行云逐舞人。\n江南飞暮雨，梁上下轻尘。\n冶服看疑画，粧台望似春。\n高车勿遽返，长袖欲相亲。' },
  { title: '咏妓', author: '王绩', poem: '妖姬饰靓妆，窈窕出兰房。\n日照当轩影，风吹满路香。\n早时歌扇薄，今日舞衫长。\n不应令曲误，持此试周郎。' },
  { title: '辛司法宅观妓', author: '王绩', poem: '南国佳人至，北堂罗荐开。\n长裙随凤管，促柱送鸾杯。\n云光身后荡，雪态掌中回。\n到愁金谷晚，不怪玉山颓。' },
  { title: '咏巫山', author: '王绩', poem: '电影江前落，雷声峡外长。\n霁云无处所，台馆晓苍苍。' },
  { title: '咏怀', author: '王绩', poem: '故乡行云是，虚室坐间同。\n日落西山暮，方知天下空。' },
  { title: '句', author: '王绩', poem: '琴曲唯留古，书多半是经。\n横裁桑节杖，直剪竹皮巾。\n鹤警琴亭夜，莺啼酒瓮春。\n颜回唯乐道，原宪岂伤贫。\n寄身千载下，聊游万物初。\n欲令无作有，翻觉实成虚。\n双关防易断，只眼畏难全。\n鱼鳞张九拒，鹤翅拥三边。' },
  { title: '咏舞', author: '萧德言', poem: '低身锵玉珮，举袖拂罗衣。\n对檐疑燕起，映雪似花飞。' },
  { title: '过严君平古井', author: '郑世翼', poem: '严平本高尚，远蹈古人风。\n卖卜成都市，流名大汉中。\n旧井改人世，寒泉久不通。\n多年既罢汲，无禽乃遂空。\n如何属秋气，唯见落双桐。' },
  { title: '登北邙还望京洛', author: '郑世翼', poem: '步登北邙坂，踟蹰聊写望。\n宛洛盛皇居，规模穷大壮。\n三河分设险，两崤资巨防。\n飞观紫烟中，层台碧云上。\n青槐夹驰道，迢迢修且旷。\n左右多第宅，参差居将相。\n清晨谒帝返，车马相追访。\n胥徒各异流，文物纷殊状。\n嚣尘暗天起，箫管从风飏。\n伊余孤且直，生平独沦丧。\n山幽有桂丛，何为坐惆怅。' },
  { title: '巫山高', author: '郑世翼', poem: '巫山凌太清，岧嶤类削成。\n霏霏暮雨合，霭霭朝云生。\n危峰入鸟道，深谷写猨声。\n别有幽栖客，淹留攀桂情。' },
  { title: '看新婚', author: '郑世翼', poem: '初筓梦桃李，新妆应摽梅。\n疑逐朝云去，翻随暮雨来。\n杂珮含风响，丛花隔扇开。\n姮娥对此夕，何用久裴回。' },
  { title: '见佳人负钱出路', author: '郑世翼', poem: '独负千金价，应从买笑来。\n秖持难发口，经为几人开。' },
  { title: '送金竟陵入蜀', author: '崔信明', poem: '金门去蜀道，玉垒望长安。\n岂言千里远，方寻九折难。\n西上君飞葢，东归我挂冠。\n猨声出峡断，月彩落江寒。\n从今与君别，花月几新残。' },
  { title: '侍宴咏石榴', author: '孔绍安', poem: '可惜庭中树，移根逐汉臣。\n只为来时晚，花开不及春。' },
  { title: '咏夭桃', author: '孔绍安', poem: '结叶还临影，飞香欲徧空。\n不意余花落，翻沈露井中。' },
  { title: '赠蔡君', author: '孔绍安', poem: '畴昔同幽谷，伊尔迁乔木。\n赫奕盛青紫，讨论穷简牍。' },
  { title: '结客少年场行', author: '孔绍安', poem: '结客佩吴钩，横行度陇头。\n鴈在弓前落，云从阵后浮。\n吴师惊燧象，燕将警奔牛。\n转蓬飞不息，冰河结未流。\n若使三边定，当封万户侯。' },
  { title: '伤顾学士', author: '孔绍安', poem: '迢遰双崤道，超忽三川湄。\n此中俱失路，思君不可思。\n游人行变橘，逝者遽焚芝。\n忆昔江湖上，同咏子衿诗。\n何言陵谷徙，翻惊邻笛悲。\n陈根非席卉，穗帐异书帷。\n与善成空说，歼良信在兹。\n今日严夫子，哀命不哀时。' },
  { title: '别徐永元秀才', author: '孔绍安', poem: '金汤既失险，玉石乃同焚。\n坠叶还相覆，落羽更为群。\n岂谓三秋节，重伤千里分。\n远离弦易转，幽咽水难闻。\n欲识相思处，山川间白云。' },
  { title: '落叶', author: '孔绍安', poem: '早秋惊落叶，飘零似客心。\n翻飞未肯下，犹言惜故林。' },
  { title: '踏歌词三首 一', author: '谢偃', poem: '春景娇春台，新露泣新梅。\n春叶参差吐，新花重叠开。\n花影飞莺去，歌声度鸟来。\n倩看飘飖雪，何如舞袖回。' },
  { title: '踏歌词三首 二', author: '谢偃', poem: '逶迤度香合，顾步出兰闺。\n欲绕鸳鸯殿，先过桃李蹊。\n风带舒还卷，簪花举复低。\n欲问今宵乐，但听歌声齐。' },
  { title: '踏歌词三首 三', author: '谢偃', poem: '夜久星沉没，更深月影斜。\n裙轻才动珮，鬟薄不胜花。\n细风吹宝袂，轻露湿红纱。\n相看乐未已，兰灯照九华。' },
  { title: '乐府新歌应教', author: '谢偃', poem: '青楼绮阁已含春，凝妆艳粉复如神。\n细细轻裙全漏影，离离薄扇讵障尘。\n樽中酒色恒宜满，曲里歌声不厌新。\n紫燕欲飞先遶栋，黄莺始哢即娇人。\n撩乱垂丝昏柳陌，参差浓叶暗桑津。\n上客莫畏斜光晚，自有西园明月轮。' },
  { title: '奉和出颖至淮应令', author: '蔡允恭', poem: '久倦川涂曲，忽此望淮圻。\n波长泛淼淼，眺迥情依依。\n稍觉金乌转，渐见锦帆稀。\n欲知仁化洽，讴歌满路归。' },
  { title: '和卫尉寺柳', author: '杜之松', poem: '汉将本屯营，辽河有戍城。\n大夫曾取姓，先生亦得名。\n高枝拂远鴈，疎影度遥星。\n不辞攀折苦，为入管弦声。' },
  { title: '荅王无功冬夜载酒乡馆', author: '崔善为', poem: '颁条忝贵郡，悬榻久相望。\n处士同杨郑，邦君谢李疆。\n讵知方拥篲，逢子敬惟桑。\n明朝蓬户侧，会自谒任棠。' },
  { title: '荅王无功九日', author: '崔善为', poem: '秋来菊花气，深山客重寻。\n露叶疑涵玉，风花似散金。\n摘来还泛酒，独坐即徐斟。\n王弘贪自醉，无复觅杨林。' },
  { title: '荅王无功问故园', author: '朱仲晦', poem: '我从铜州来，见子上京客。\n问我故乡事，慰子羁旅色。\n子问我所知，我对子应识。\n朋游总强健，童稚各长成。\n华宗盛文史，连墙富池亭。\n独子园最古，旧林间新坰。\n柳行随堤势，茅斋看地形。\n竹从去年移，梅是今年荣。\n渠水经夏响，石苔终岁青。\n院果早晚熟，林花先后明。\n语罢相叹息，浩然起深情。\n归哉且五斗，饷子东皐耕。' },
  { title: '从军行', author: '王宏', poem: '儿生三日掌上珠，燕颔猨肱秾李肤。\n十五学劒北击胡，羌歌燕筑送城隅。\n城隅路接伊川驿，河阳渡头邯郸陌。\n可怜少年把手时，黄鸟双飞梨花白。\n秦王筑城三千里，西自临洮东辽水。\n山边叠叠黑云飞，海畔莓莓青草死。\n从来战鬬不求勋，杀身为君君不闻。\n凤皇楼上吹急管，落日裴回肠先断。' },
  { title: '文德皇后挽歌', author: '朱子奢', poem: '神京背紫陌，缟驷结行辀。\n北去横桥道，西分清渭流。\n寒光向垄没，霜气入松楸。\n今日泉台路，非是濯龙游。' },
  { title: '大酺乐', author: '张文收', poem: '泪滴珠难尽，容残玉易销。\n倘随明月去，莫道梦魂遥。' },
  { title: '与琳法师', author: '毛明素', poem: '冶长倦缧绁，韩安叹死灰。\n始验山中木，方知贵不材。' },
  { title: '上之回', author: '陈子良', poem: '承平重游乐，诏跸上之回。\n属车响流水，清笳转落梅。\n岭云盖道转，岩花映绶开。\n下辇便高宴，何如在瑶台。' },
  { title: '新成安乐宫', author: '陈子良', poem: '春色照兰宫，秦女坐牕中。\n柳叶来眉上，桃花落脸红。\n拂尘开扇匣，卷帐却薰笼。\n衫薄偏憎日，裙轻更畏风。' },
  { title: '夏晚寻于政世置酒赋韵', author: '陈子良', poem: '聊从嘉遯所，酌醴共抽簪。\n以兹山水地，留连风月心。\n长榆落照尽，高柳暮蝉吟。\n一返桃源路，别后难追寻。' },
  { title: '入蜀秋夜宿江渚', author: '陈子良', poem: '我行逢日暮，弭櫂独维舟。\n水雾一边起，风林两岸秋。\n山阴黑断碛，月影素寒流。\n故乡千里外，何以慰羁愁。' },
  { title: '赋得妓', author: '陈子良', poem: '金谷多欢宴，佳丽正芳菲。\n流霞席上满，回雪掌中飞。\n明月临歌扇，行云接舞衣。\n何必桃将李，别有待春晖。' },
  { title: '詶萧侍中春园听妓', author: '陈子良', poem: '微雨散芳菲，中园照落晖。\n红树摇歌扇，绿珠飘舞衣。\n繁弦调对酒，杂引动思归。\n愁人当此夕，羞见落花飞。' },
  { title: '游侠篇', author: '陈子良', poem: '洛阳丽春色，游侠骋轻肥。\n水逐车轮转，尘随马足飞。\n云影遥临盖，花气近薰衣。\n东郊鬬鸡罢，南皮射雉归。\n日暮河桥上，扬鞭惜晚晖。' },
  { title: '春晚看群公朝还人为八韵', author: '陈子良', poem: '游子惜春暮，策杖出蒿莱。\n正直康庄晚，群公谒帝回。\n履度南宫至，车从北阙来。\n珂影傍明月，笳声动落梅。\n迎风采旄转，照日绶花开。\n红尘掩鹤盖，翠柳拂龙媒。\n绮云临舞阁，丹霞薄吹台。\n轻肥宁所羡，未若反山隈。' },
  { title: '赞德上越国公杨素', author: '陈子良', poem: '君侯称上宰，命世挺才英。\n本超骐骥足，复蕴风云情。\n摅藻掞锦绮，育德润瑶琼。\n已踵四知举，非无三杰名。\n济世同舟檝，匡政本阿衡。\n雍容入青锁，肃穆侍丹楹。\n桂宫擅鸣珮，槐路独飞缨。\n高门罗虎戟，绮阁丽雕甍。\n金罇酌湛湛，歌扇掩盈盈。\n匈奴轶燕蓟，烽火照幽幷。\n天子名薄伐，受脤事专征。\n七德播雄略，十万骋行兵。\n鴈行蔽虏甸，鱼贯出长城。\n交河方饮马，瀚海盛扬旌。\n拔劒倚天外，蒙犀辉日精。\n弯弧穿伏石，挥戈斩大鲸。\n鼓鼙朝作气，刁斗夜偏鸣。\n六郡多壮士，三边岂足平。\n岭云朝合阵，山月夜临营。\n胡尘暗马色，芳树动笳声。\n关云未尽散，塞雾常自生。\n川长蔓草绿，峰逈杂花明。\n小人愧王氏，雕文慙马卿。\n滥此叨书记，何以谢过荣。\n高山徒仰止，终是恨才轻。' },
  { title: '于塞北春日思归', author: '陈子良', poem: '我家吴会青山远，他乡关塞白云深。\n为许羁愁长下泪，那堪春色更伤心。\n惊鸟屡飞恒失侣，落花一去不归林。\n如何此日嗟迟暮，悲来还作白头吟。' },
  { title: '送别', author: '陈子良', poem: '落叶聚还散，征禽去不归。\n以我穷途泣，沾君出塞衣。' },
  { title: '七夕看新妇隔巷停车', author: '陈子良', poem: '隔巷遥停幰，非复为来迟。\n只言更尚浅，未是渡河时。' },
  { title: '咏春雪', author: '陈子良', poem: '光映妆楼月，花承歌扇风。\n欲妬梅将柳，故落早春中。' },
  { title: '骢马', author: '庾抱', poem: '枥上浮云骢，本出吴门中。\n发迹来东道，长鸣起北风。\n回鞍拂桂白，赪汗类尘红。\n灭没徒留影，无因图汉宫。' },
  { title: '别蔡参军', author: '庾抱', poem: '人世多飘忽，沟水易西东。\n今日欢娱尽，何年风月同？\n悲生万里外，恨起一杯中。\n性灵如未失，南北有征鸿。' },
  { title: '赋得胥台露', author: '庾抱', poem: '胥台既落构，荆棘稍侵扉。\n栋拆连云影，梁摧照日晖。\n翔鶤逐不及，巢燕[反]无归。\n唯有团阶露，承晓共沾衣。' },
  { title: '卧疴喜霁开扉望月简宫内知友', author: '庾抱', poem: '秋雨移弦望，疲疴倦苦辛。\n忽对荆山璧，委照越吟人。\n高高侵地镜，皎皎彻天津。\n色丽班姬箧，光润洛川神。\n轮辉池上动，桂影隙中新。\n怀贤虽不见，忽似暂参辰。' },
  { title: '和乐记室忆江水', author: '庾抱', poem: '遥想观涛处，犹意采莲歌。\n无因关塞叶，共下洞庭波。' },
  { title: '凌朝浮江旅思', author: '马周', poem: '太清上初日，春水送孤舟。\n山远疑无树，潮平似不流。\n岸花开且落，江鸟没还浮。\n羁望伤千里，长歌遣四愁。' },
  { title: '出玉关', author: '来济', poem: '歛辔遵龙汉，衔凄渡玉关。\n今日流沙外，垂涕念生还。' },
  { title: '七夕', author: '张文恭', poem: '凤律惊秋气，龙梭静夜机。\n星桥百枝动，云路七香飞。\n映月回雕扇，凌霞曳绮衣。\n含情向华幄，流态入重闱。\n欢余夕漏尽，怨结晓骖归。\n谁念分河汉，还忆两心违。' },
  { title: '佳人照镜', author: '张文恭', poem: '倦采蘼芜叶，贪怜照胆明。\n两边俱拭泪，一处有啼声。' },
  { title: '奉和同太子监守违恋', author: '薛元超', poem: '储禁铜扉启，宸行玉轪遥。\n空怀寿街吏，尚隔寝门朝。\n北首瞻龙戟，尘外想鸾镳。\n飞文映仙榜，沥思叶神飙。\n帝念纡苍璧，干文焕紫霄。\n归塘横笔海，平圃振词条。\n欲应重轮曲，锵洋韵九韶。' },
  { title: '荅辨才探得招字', author: '萧翼', poem: '邂逅欵良宵，殷勤荷胜招。\n弥天俄若旧，初地岂成遥。\n酒蚁倾还泛，心猨躁似调。\n谁怜失群鴈，长苦业风飘。' },
  { title: '道失', author: '欧阳询', poem: '已惑孔贵嫔，又被辞人侮。\n花牋一何荣，七字谁曾许。\n不下结绮阁，空迷江令语。\n雕戈动地来，悮杀陈后主。' },
  { title: '巫山高', author: '阎立本', poem: '君不见巫山高高半天起，绝壁千寻尽相似。\n君不见巫山磕匝翠屏开，湘江碧水遶山来。\n绿树春娇明月峡，红花朝覆白云台。\n台上朝云无定所，此中窕窈神仙女。\n仙女盈盈仙骨飞，清容出没有光辉。\n欲暮高唐行雨送，今宵定入荆王梦。\n荆王梦里爱秾华，枕席初开红帐遮。\n可怜欲晓啼猨处，说道巫山是妾家。' },
  { title: '同潘屯田冬日早朝', author: '张文琮', poem: '假寐怀古人，夙兴瞻晓月。\n通晨禁门启，冠盖趋朝谒。\n霜霭清九衢，霞光照双阙。\n纷纶文物纪，焕烂声明发。\n腰劒动陆离，鸣玉和清越。' },
  { title: '蜀道难', author: '张文琮', poem: '梁山镇地险，积石阻云端。\n深谷下寥廓，层岩上郁盘。\n飞梁驾绝岭，栈道接危峦。\n揽辔独长息，方知斯路难。' },
  { title: '昭君怨', author: '张文琮', poem: '戒途飞万里，回首望三秦。\n忽见天山雪，还疑上苑春。\n玉痕垂粉泪，罗袂拂胡尘。\n为得胡中曲，还悲远嫁人。' },
  { title: '咏水', author: '张文琮', poem: '标名资上善，流派表灵长。\n地图罗四渎，天文载五潢。\n方流涵玉润，圆折动珠光。\n独有蒙园吏，栖偃玩濠梁。' },
  { title: '赋桥', author: '张文琮', poem: '造舟浮渭日，鞭石表秦初。\n星文遥写汉，虹势尚凌虚。\n已授文成履，空题武骑书。\n别有临濠上，栖偃独观鱼。' },
  { title: '和杨舍人咏中书省花树', author: '张文琮', poem: '花萼映芳丛，参差间早红。\n因风时落砌，杂雨乍浮空。\n影照凤池水，香飘鸡树风。\n岂不爱攀折，希君怀袖中。' },
  { title: '奉和过旧宅应制', author: '上官仪', poem: '石关清晚夏，璇舆御早秋。\n神麾飏珠雨，仙吹响飞流。\n沛水祥云泛，宛郊瑞气浮。\n大风迎汉筑，藂烟入舜球。\n翠梧临凤邸，滋兰带鹤舟。\n偃伯歌玄化，扈跸颂王游。\n遗簪谬昭奖，珥笔荷恩休。' },
  { title: '早春桂林殿应诏', author: '上官仪', poem: '步辇出披香，清歌临太液。\n晓树流莺满，春堤芳草积。\n风光翻露文，雪华上空碧。\n花蝶来未已，山光暧将夕。' },
  { title: '安德山池宴集', author: '上官仪', poem: '上路抵平津，后堂罗荐陈。\n缔交开狎赏，丽席展芳辰。\n密树风烟积，回塘荷芰新。\n雨霁虹桥晚，花落凤台春。\n翠钗低舞席，文杏散歌尘。\n方惜流觞满，夕鸟已城𬮱。' },
  { title: '酬薛舍人万年宫晚景寓直怀友', author: '上官仪', poem: '奕奕九成台，窈窕绝尘埃。\n苍苍万年树，玲珑下冥雾。\n池色摇晚空，岩花歛余煦。\n清切丹禁静，浩荡文河注。\n留连穷胜托，夙期暌善谑。\n东望安仁省，西临子云阁。\n长啸披烟霞，高步寻兰若。\n金狄掩通门，雕鞍归骑喧。\n燕姝对明月，荆艳促芳尊。\n别有青山路，策杖访王孙。' },
  { title: '奉和颍川公秋夜', author: '上官仪', poem: '泬寥空色远，芸黄凄序变。\n涸浦落遵鸿，长飙送巢燕。\n千秋流夕景，万籁含宵唤。\n峻雉聆金柝，层台切银箭。' },
  { title: '谢都督挽歌', author: '上官仪', poem: '漠漠佳城幽，苍苍松槚暮。\n鲁幕飘欲卷，宛驷悲还顾。\n楚挽绕卢山，胡笳临武库。\n怅然郊原静，烟生归鸟度。' },
  { title: '八咏应制二首 一', author: '上官仪', poem: '启重帷，重帷照文杏。\n翡翠藻轻花，流苏媚浮影。\n瑶笙燕始归，金堂露初晞。\n风随少女至，虹共美人归。\n罗荐已擘鸳鸯被，绮衣复有蒲萄带。\n残红艳粉映帘中，戏蝶流莺聚窗外。\n洛滨春雪回，巫峡暮云来。\n雪花飘玉辇，云光上璧台。\n共待新妆出，清歌送落梅。' },
  { title: '八咏应制二首 二', author: '上官仪', poem: '入丛台，丛台裛春露。\n滴沥间深红，参差散轻素。\n妆蝶惊复聚，黄鹂飞且顾。\n攀折殊未已，复值惊飞起。\n送影舞衫前，飘香歌扇里。\n望望惜春晖，行行犹未归。\n暂得佳游趣，更愁花鸟稀。\n且学鸟声调凤管，方移花影入鸳机。' },
  { title: '和太尉戏赠高阳公', author: '上官仪', poem: '薰炉御史出神仙，云鞍羽盖下芝田。\n红尘正起浮桥路，青楼遥敞御沟前。\n倾城比态芳菲节，绝世相娇是六年。\n惯是洛滨要解珮，本是河间好数钱。\n翠钗照耀衔云发，玉步逶迤动罗袜。\n石榴绞带轻花转，桃枝绿扇微风发。\n无情拂袂欲留宾，讵恨深潭不可越。\n天津一别九秋长，岂若随闻三日香。\n南国自然胜掌上，东家复是忆王昌。' },
  { title: '王昭君', author: '上官仪', poem: '玉关春色晚，金河路几千。\n琴悲桂条上，笛怨柳花前。\n雾掩临妆月，风惊入鬓蝉。\n缄书待还使，泪尽白云天。' },
  { title: '咏雪应诏', author: '上官仪', poem: '禁园凝朔气，瑞雪掩晨曦。\n花明栖凤阁，珠散影娥池。\n飘素迎歌上，翻光向舞移。\n幸因千里映，还绕万年枝。' },
  { title: '奉和山夜临秋', author: '上官仪', poem: '殿帐清炎气，辇道含秋阴。\n凄风移汉筑，流水入虞琴。\n云飞送断雁，月上净疎林。\n滴沥露枝响，空蒙烟壑深。' },
  { title: '江王太妃挽歌', author: '上官仪', poem: '黄鹤悲歌绝，椒花清颂余。\n埃凝写邻镜，网结和扉鱼。\n银消风烛尽，珠灭夜轮虚。\n别有南陵路，幽丛临叶疎。' },
  { title: '故北平公挽歌', author: '上官仪', poem: '木落园林旷，庭虚风露寒。\n北里清音绝，南陔芳草残。\n远气犹标劒，浮云尚写冠。\n寂寂琴台晚，秋阴入井干。' },
  { title: '高密长公主挽歌', author: '上官仪', poem: '湘渚韬灵迹，娥台静瑞音。\n凤逐清箫远，鸾随幽镜沈。\n霜处华芙落，风前银烛侵。\n寂寞平阳宅，月冷洞房深。' },
  { title: '咏画障', author: '上官仪', poem: '芳晨丽日桃花浦，珠帘翠帐凤凰楼。\n蔡女菱歌移锦缆，燕姬春望上琼钩。\n新妆漏影浮轻扇，冶袖飘香入浅流。\n未减行雨荆台下，自比凌波洛浦游。' },
  { title: '奉和秋日即目应制', author: '上官仪', poem: '上苑通平乐，神池迩建章。\n楼台相掩映，城阙互相望。\n缇油泛行幔，箫吹转浮梁。\n晚云含朔气，斜照荡秋光。\n落叶飘蝉影，平流写雁行。\n槿散凌风缛，荷销裛露香。\n仙歌临枍诣，玄豫历长杨。\n归路乘明月，千门开未央。' },
  { title: '入朝洛堤步行', author: '上官仪', poem: '脉脉广川流，驱马历长洲。\n鹊飞山月曙，蝉噪野风秋。' },
  { title: '春日', author: '上官仪', poem: '花轻蝶乱仙人杏，叶密莺啼帝女桑。\n飞云阁上春应至，明月楼中夜未央。' },
  { title: '从驾闾山咏马', author: '上官仪', poem: '桂香尘处减，练影月前空。\n定惑由关吏，徒嗟塞上翁。' },
  { title: '中和乐九章 歌登封第一', author: '卢照邻', poem: '炎图丧宝，黄历开璇。\n祖武类帝，宗文配天。\n玉銮垂日，翠华陵烟。\n东云干吕，南风入弦。\n山称万岁，河庆千年。\n金绳永结，璧丽长悬。' },
  { title: '中和乐九章 歌明堂第二', author: '卢照邻', poem: '穆穆圣皇，雍雍明堂。\n左平右墄，上圆下方。\n调均风雨，制度阴阳。\n四牕八达，五室九房。\n南通夏火，西瞰秋霜。\n天子临御，万玉锵锵。' },
  { title: '中和乐九章 歌东军第三', author: '卢照邻', poem: '遐哉庙畧，赫矣台臣。\n横戈碣石，倚劒浮津。\n风丘拂箨，日域清尘。\n岛夷复祀，龙伯来宾。\n休兵宇县，献馘天𬮱。\n斾海凯入，耀辉震震。' },
  { title: '中和乐九章 歌南郊第四', author: '卢照邻', poem: '虔郊上帝，肃事圆丘。\n龙驾四牡，鸾旗九斿。\n钟歌晚引，紫炀高浮。\n日丽苍璧，云飞鸣球。\n皇之庆矣，万寿千秋。' },
  { title: '中和乐九章 歌中宫第五', author: '卢照邻', poem: '祥游沙麓，庆洽瑶衣。\n黄云昼聚，白气宵飞。\n居中履正，禀和体微。\n仪刑赤县，演教椒闱。\n陶钧万国，丹青四妃。\n河洲在咏，风化攸归。' },
  { title: '中和乐九章 歌储宫第六', author: '卢照邻', poem: '波澄少海，景丽前星。\n高禖诞圣，甲观升灵。\n承规翠所，问寝瑶庭。\n宗儒侧席，问道横经。\n山宾皎皎，国胄青青。\n黄裳元吉，邦家以宁。' },
  { title: '中和乐九章 歌诸王第七', author: '卢照邻', poem: '星陈帝子，岳列天孙。\n义光带砺，象着乾坤。\n我有明德，利建攸存。\n苴以茅社，锡以牺尊。\n藩屏王室，翼亮尧门。\n八才两献，夫何足论。' },
  { title: '中和乐九章 歌公卿第八', author: '卢照邻', poem: '蹇蹇三事，师师百僚。\n群龙在职，振鹭盈朝。\n丰金辉首，珮玉鸣腰。\n青蒲翼翼，丹地翘翘。\n歌云佐汉，捧日匡尧。\n天工人代，邈邈昭昭。' },
  { title: '中和乐九章 总歌第九', author: '卢照邻', poem: '明明天子兮圣德扬，穆穆皇后兮阴化康。\n登若木兮坐明堂，池蒙汜兮家扶桑。\n武化偃兮文化昌，礼乐昭兮股肱良。\n君臣已定兮君永无疆，颜子更生兮徒皇皇。\n若有人兮天一方，忠为衣兮信为裳。\n飡白玉兮饮琼芳，心思荃兮路阻长。' },
  { title: '关山月', author: '卢照邻', poem: '塞垣通碣石，虏障抵[祁]连。\n相思在万里，明月正孤悬。\n影移金岫北，光断玉门前。\n寄言闺中妇，时看鸿雁天。' },
  { title: '上之回', author: '卢照邻', poem: '回中道路险，萧关烽候多。\n五营屯北地，万乘出西河。\n单于拜玉玺，天子按雕戈。\n振旅汾川曲，秋风横大歌。' },
  { title: '紫骝马', author: '卢照邻', poem: '骝马照金鞍，转战入皐兰。\n塞门风稍急，长城水正寒。\n雪暗鸣珂重，山长喷玉难。\n不辞横绝漠，流血几时干。' },
  { title: '战城南', author: '卢照邻', poem: '将军出紫塞，冒顿在乌贪。\n笳喧雁门北，阵翼龙城南。\n雕弓夜宛转，铁骑晓参驔。\n应须驻白日，为待战方酣。' },
  { title: '梅花落', author: '卢照邻', poem: '梅岭花初发，天山雪未开。\n雪处疑花落，花边似雪回。\n因风入舞袖，杂粉向妆台。\n匈奴几万里，春至不知来。' },
  { title: '结客少年场行', author: '卢照邻', poem: '长安重游侠，洛阳富财雄。\n玉劒浮云骑，金鞭明月弓。\n鬬鸡过渭北，走马向关东。\n孙宾遥见待，郭解暗相通。\n不受千金爵，谁论万里功。\n将军下天上，虏骑入云中。\n烽火夜似月，兵气晓成虹。\n横行徇知己，负羽远从戎。\n龙旌昏朔雾，鸟阵卷胡风。\n追奔瀚海咽，战罢阴山空。\n归来谢天子，何如马上翁。' },
  { title: '咏史四首 一', author: '卢照邻', poem: '季生昔未达，身辱功不成。\n髠钳为台隶，灌园变姓名。\n幸逢滕将军，兼遇曹丘生。\n汉祖广招纳，一朝拜公卿。\n百金孰云重，一诺良匪轻。\n廷议斩樊哙，群公寂无声。\n处身孤且直，遭时坦而平。\n丈夫当如此，唯唯何足荣。' },
  { title: '咏史四首 二', author: '卢照邻', poem: '大汉昔云季，小人道遂振。\n玉帛委奄尹，斧锧婴缙绅。\n邈哉郭先生，卷舒得其真。\n雍容谢朝廷，谈笑奖人伦。\n在晦不绝俗，处乱不为亲。\n诸侯不得友，天子不得臣。\n冲情甄负甑，重价折角巾。\n悠悠天下士，相送洛桥津。\n谁知仙舟上寂寂无四邻。' },
  { title: '咏史四首 三', author: '卢照邻', poem: '公业负奇志，交结尽才雄。\n良田四百顷，所食常不充。\n一为侍御史，慷慨说何公。\n何公何为败，吾谋适不同。\n仲颕恣残忍，废兴良在躬。\n死人如乱麻，天子如转蓬。\n干戈及黄屋，荆棘生紫宫。\n郑生运其谋，将以清国戎。\n时来命不遂，脱身归山东。\n凛凛千载下，穆然怀春风。' },
  { title: '咏史四首 四', author: '卢照邻', poem: '昔有平陵男，姓朱名阿游。\n直发上冲冠，壮气横三秋。\n愿得斩马劒，先断佞臣头。\n天子玉槛折，将军丹血流。\n捐生不肯拜，视死其若休。\n归来教乡里，童蒙远相求。\n弟子数百人，散在十二州。\n三公不敢吏，五鹿何能酬。\n名与日月悬，义与天壤俦。\n何必疲执戟，区区在封侯。\n伟哉旷达士，知命固不忧。' },
  { title: '赠李荣道士', author: '卢照邻', poem: '锦节衔天使，琼仙驾羽君。\n投金翠山曲，奠璧清江𣸣。\n圆洞开丹鼎，方坛聚绛云。\n宝贶幽难识，空歌迥易分。\n风摇十洲影，日乱九江文。\n敷诚归上帝，应诏在明君。\n独有南冠客，耿耿泣离群。\n遥看八会所，真气晓氤氲。' },
  { title: '早度分水岭', author: '卢照邻', poem: '丁年游蜀道，班鬓向长安。\n徒费周王粟，空弹汉吏冠。\n马蹄穿欲尽，貂裘敝转寒。\n层冰横九折，积石凌七盘。\n重溪既下漱，峻峰亦上干。\n陇头闻戍鼓，岭外咽飞湍。\n瑟瑟松风急，苍苍山月团。\n传语后来者，斯路诚独难。' },
  { title: '三月曲水宴得尊字', author: '卢照邻', poem: '风烟彭泽里，山水仲长园。\n由来弃铜墨，本自重琴尊。\n高情邈不嗣，雅道今复存。\n有美光时彦，养德坐山樊。\n门开芳杜迳，室距桃花源。\n公子黄金勒，仙人紫气轩。\n长怀去城市，高咏狎兰荪。\n连沙飞白鹭，孤屿啸玄猿。\n日影岩前落，云花江上翻。\n兴兰车马散，林塘夕鸟喧。' },
  { title: '奉使益州至长安发钟阳驿', author: '卢照邻', poem: '跻险方未夷，乘春聊骋望。\n落花赴丹谷，奔流下青嶂。\n葳蕤晓树滋，滉瀁春江涨。\n平川看钓侣，狭径闻樵唱。\n蝶戏绿苔前，莺歌白云上。\n耳目多异赏，风烟有奇状。\n峻阻将长城，高标吞巨舫。\n联翩事羁靮，辛苦劳疲恙。\n夕济几潺湲，晨登每惆怅。\n谁念复刍狗，山河独偏丧。' },
  { title: '和王奭秋夜有所思', author: '卢照邻', poem: '寂寂南轩夜，悠然怀所知。\n长河落雁苑，明月下鲸池。\n凤台有清曲，此曲何人吹？\n丹唇间玉齿，妙响入云涯。\n穷巷秋风叶，空庭寒露枝。\n劳歌欲有和，星鬓已将垂。' },
  { title: '望宅中树有所思', author: '卢照邻', poem: '我家有庭树，秋叶正离离。\n上舞双栖鸟，中秀合欢枝。\n劳思复劳望，相见不相知。\n何当共攀折？歌笑此堂垂。' },
  { title: '宿晋安亭', author: '卢照邻', poem: '闻有弦歌地，穿凿本多奇。\n游人试一览，临玩果忘疲。\n窗横暮卷叶，檐卧古生枝。\n旧石开红鲜，新河覆绿池。\n孤猿稍断绝，宿鸟复参差。\n泛滟月华晓，裴回星鬓垂。\n今日删书客，凄惶君讵知。' },
  { title: '于时春也慨然有江湖之思寄赠柳九陇', author: '卢照邻', poem: '提琴一万里，负书三十年。\n晨攀偃蹇树，暮宿清泠泉。\n翔禽鸣我侧，旅兽过我前。\n无人且无事，独酌还独眠。\n遥闻彭泽宰，高弄武城弦。\n形骸寄文墨，意气托神仙。\n我有壶中要，题为物外篇。\n将以贻好道，道远莫致旃。\n相思劳日夜，相望阻风烟。\n坐惜春华晚，徒令客思悬。\n水去东南地，气凝西北天。\n关山悲蜀道，花鸟忆秦川。\n天子何时问，公卿本亦怜。\n自哀还自乐，归薮复归田。\n海屋银为栋，云车电作鞭。\n倘遇鸾将鹤，谁论貂与蝉。\n莱洲频度浅，桃实几成圆。\n寄言飞凫舃，岁[晏]同联翩。' },
  { title: '至望喜瞩目言怀贻剑外知己', author: '卢照邻', poem: '圣图夷九折，神化掩三分。\n缄愁赴蜀道，题拙奉虞薰。\n隐辚度深谷，遥褭上高云。\n碧流递萦注，青山互纠纷。\n涧松咽风绪，岩花濯露文。\n思北常依驭，图南每丧群。' },
  { title: '赤谷安禅师塔', author: '卢照邻', poem: '独坐岩之曲，悠然无俗纷。\n酌酒呈丹桂，思诗赠白云。\n烟霞朝晚聚，猿鸟岁时闻。\n水华竞秋色，山翠含夕曛。\n高谈十二部，细核五千文。\n如如数冥味，生生理氛氲。\n古人有糟粕，轮扁情未分。\n且当事芝术，从吾所好云。' },
  { title: '赠益府裴录事', author: '卢照邻', poem: '忽忽岁云暮，相望限风烟。\n长歌欲对酒，危坐遂停弦。\n停弦变霜露，对酒怀朋故。\n朝看桂蟾晚，夜闻鸿雁度。\n鸿度何时还？桂晚不同攀。\n浮云映丹壑，明月满青山。\n青山云路深，丹壑月华临。\n耿耿离忧积，空令星鬓侵。' },
  { title: '赠益府群官', author: '卢照邻', poem: '一鸟自北燕，飞来向西蜀。\n单栖剑门上，独舞岷山足。\n昂藏多古貌，哀怨有新曲。\n群凤从之游，问之何所欲？\n荅言寒乡子，飘飖万余里。\n不息恶木枝，不饮盗泉水。\n常思稻粱遇，愿栖梧桐树。\n智者不我邀，愚夫余不顾。\n所以成独立，耿耿岁云暮。\n日夕苦风霜，思归赴洛阳。\n羽翮毛衣短，关山道路长。\n明月流客思，白云迷故乡。\n谁能借风便，一举凌苍苍。' },
  { title: '送梓州高参军还京', author: '卢照邻', poem: '京洛风尘远，褒斜烟露深。\n北游君似智，南飞我异禽。\n别路琴声断，秋山猿鸟吟。\n一乖青岩酌，空伫白云心。' },
  { title: '大剑送别刘右史', author: '卢照邻', poem: '金碧禺山远，关梁蜀道难。\n相逢属晚岁，相送动征鞍。\n地咽緜川冷，云凝剑阁寒。\n倘遇忠孝所，为道忆长安。' },
  { title: '同临津纪明府孤雁', author: '卢照邻', poem: '三秋违北地，万里向南翔。\n河洲花稍白，关塞叶初黄。\n避缴风霜劲，怀书道路长。\n水流疑箭动，月照似弓伤。\n横天无有阵，度海不成行。\n会刷能鸣羽，还赴上林乡。' },
  { title: '失群雁', author: '卢照邻', poem: '三秋北地雪皑皑，万里南翔渡海来。\n欲随石燕沈湘水，试逐铜乌绕帝台。\n帝台银阙距金塘，中间鹓鹭已成行。\n先过上苑传书信，暂下中州戏稻粱。\n虞人负缴来相及，齐客虚弓忽见伤。\n毛翎频顿飞无力，羽翮摧颓君不识。\n唯有庄周解爱鸣，复道郊哥重奇色。\n惆怅惊思悲未已，裴回自怜中罔极。\n传闻有鸟集朝阳，讵胜仙凫迩帝乡。\n云间海上应鸣舞，远得鹍弦犹独抚。\n金龟全写中牟印，玉鹄当变莱芜釜。\n愿君弄影凤皇池，时忆笼中摧折羽。' },
  { title: '行路难', author: '卢照邻', poem: '君不见长安城北渭桥边，枯木横槎卧古田。\n昔日含红复含紫，常时留雾亦留烟。\n春景春风花似雪，香车玉轝恒阗咽。\n若个游人不竞攀，若个娼家不来折。\n娼家宝袜蛟龙帔，公子银鞍千万骑。\n黄莺一一向花娇，青鸟双双将子戏。\n千尺长条百尺枝，月桂星榆相蔽亏。\n珊瑚叶上鸳鸯鸟，凤皇巢里雏鹓儿。\n巢倾枝折凤归去，条枯叶落任风吹。\n一朝零落无人问，万古摧残君讵知。\n人生贵贱无终始，倏忽须臾难久恃。\n谁家能驻西山日，谁家能堰东流水。\n汉家陵树满秦川，行来行去尽哀怜。\n自昔公卿二千石，咸拟荣华一万年。\n不见朱唇将白貌，唯闻素棘与黄泉。\n金貂有时换美酒，玉麈但摇莫计钱。\n寄言坐客神仙署，一生一死交情处。\n苍龙阙下君不来，白鹤山前我应去。\n云间海上邈难期，赤心会合在何时。\n但愿尧年一百万，长作巢由也不辞。' },
  { title: '明月引', author: '卢照邻', poem: '洞庭波起兮鸿雁翔，风瑟瑟兮野苍苍。\n浮云卷霭，明月流光。\n荆南兮赵北，碣石兮潇湘。\n澄清规于万里，照离思于千行。\n横桂枝于西第，绕菱花于北堂。\n高楼思妇，飞盖君王。\n文姬绝域，侍子他乡。\n见胡鞍之似练，知汉剑之如霜。\n试登高而骋目，莫不变而回肠。' },
  { title: '狱中学骚体', author: '卢照邻', poem: '夫何秋夜之无情兮，皎皛悠悠而太长。\n圜户杳其幽邃兮，愁人披此严霜。\n见河汉之西落，闻鸿雁之南翔。\n山有桂兮桂有芳，心思君兮君不将。\n忧与忧兮相积，欢与欢兮两忘。\n风袅袅兮木纷纷，凋绿叶兮吹白云。\n寸步千里兮不相闻，思公子兮日将曛。\n林已暮兮鸟群飞，重门掩兮人径稀。\n万族皆有所托兮，蹇独淹留而不归。' },
  { title: '怀仙引', author: '卢照邻', poem: '若有人兮山之曲，驾青虬兮乘白鹿。\n往从之游愿心足，披涧户，访岩轩。\n石濑潺湲横石径，松萝幂䍥掩松门。\n下空蒙而无鸟，上巉岩而有猨。\n怀飞阁，度飞梁。\n休余马于幽谷，挂余冠于夕阳。\n曲复曲兮烟庄邃，行复行兮天路长。\n修途杳其未半，飞雨忽以茫茫。\n山坱轧，磴连褰。\n攀石壁而无据，溯泥溪而不前。\n向无情之白日，窃有恨于皇天。\n回行遵故道，通川遍流潦。\n回首望群峰，白云正溶溶。\n珠为阙兮玉为楼，青云盖兮紫霜裘。\n天长地久时相忆，千龄万代一来游。' },
  { title: '七日登乐游故墓', author: '卢照邻', poem: '四序周缇籥，三正纪璇耀。\n绿野变初黄，旸山开晓眺。\n中天擢露掌，匝地分星徼。\n汉寝睠遗灵，秦江想余吊。\n蚁泛青田酌，莺歌紫芝调。\n柳色摇岁华，冰文荡春照。\n远迹谢群动，高情符众妙。\n兰游澹未归，倾光下岩窈。' },
  { title: '释疾文三歌 一', author: '卢照邻', poem: '岁将暮兮欢不再，时已晚兮忧来多。\n东郊绝此麒麟笔，西山秘此凤凰柯。' },
  { title: '释疾文三歌 二', author: '卢照邻', poem: '岁去忧来兮东流水，地久天长兮人共死。\n明镜羞窥兮向十年，骏马停驱兮几千里。\n麟兮凤兮，自古吞恨无已。' },
  { title: '释疾文三歌 三', author: '卢照邻', poem: '茨山有薇兮颍水有漪，夷为柏兮秋有实。\n叔为柳兮春向飞，倏尔而笑，泛沧浪兮不归。' },
  { title: '酬杨比部员外暮宿琴堂朝跻书阁率尔见赠之作', author: '卢照邻', poem: '闲拂檐尘看，鸣琴候月弹。\n桃源迷汉姓，松径有秦官。\n空谷归人少，青山背日寒。\n羡君栖隐处，遥望在云端。' },
  { title: '刘生', author: '卢照邻', poem: '刘生气不平，抱剑欲专征。\n报恩为豪侠，死难在横行。\n翠羽装刀鞘，黄金饰马铃。\n但令一顾重，不恡百身轻。' },
  { title: '陇头水', author: '卢照邻', poem: '陇阪高无极，征人一望乡。\n关河别去水，沙塞断归肠。\n马系千年树，旌悬九月霜。\n从来共呜咽，皆是为勤王。' },
  { title: '巫山高', author: '卢照邻', poem: '巫山望不极，望望下朝氛。\n莫辨啼猿树，徒看神女云。\n惊涛乱水脉，骤雨暗峰文。\n沾裳即此地，况复远思君。' },
  { title: '芳树', author: '卢照邻', poem: '芳树本多奇，年华复在斯。\n结翠成新幄，开红满故枝。\n风归花历乱，日度影参差。\n容色朝朝落，思君君不知。' },
  { title: '雨雪曲', author: '卢照邻', poem: '虏骑三秋入，关云万里平。\n雪似胡沙暗，冰如汉月明。\n高阙银为阙，长城玉作城。\n节旄零落尽，天子不知名。' },
  { title: '昭君怨', author: '卢照邻', poem: '合殿恩中绝，交河使渐稀。\n肝肠辞玉辇，形影向金微。\n汉地草应绿，胡庭沙正飞。\n愿逐三秋雁，年年一度归。' },
  { title: '折杨柳', author: '卢照邻', poem: '倡楼启曙扉，杨柳正依依。\n莺啼知岁隔，条变识春归。\n露叶凝愁黛，风花乱舞衣。\n攀折聊将寄，军中音信稀。' },
  { title: '十五夜观灯', author: '卢照邻', poem: '锦里开芳宴，兰缸艳早年。\n缛彩遥分地，繁光远缀天。\n接汉疑星落，依楼似月悬。\n别有千金笑，来映九枝前。' },
  { title: '入秦川界', author: '卢照邻', poem: '陇阪长无极，苍山望不穷。\n石径萦疑断，回流映似空。\n花开绿野雾，莺啭紫岩风。\n春芳勿遽尽，留赏故人同。' },
  { title: '文翁讲堂', author: '卢照邻', poem: '锦里淹中馆，岷山稷下亭。\n空梁无燕雀，古壁有丹青。\n槐落犹疑市，苔深不辨铭。\n良哉二千石，江汉表遗灵。' },
  { title: '相如琴台', author: '卢照邻', poem: '闻有雍容地，千年无四邻。\n园院风烟古，池台松槚春。\n云疑作赋客，月似听琴人。\n寂寂啼莺处，空伤游子神。' },
  { title: '石镜寺', author: '卢照邻', poem: '古墓芙蓉塔，神铭松柏烟。\n鸾沈仙镜底，花没梵轮前。\n铢衣千古佛，宝月两重圆。\n隐隐香台夜，钟声彻九天。' },
  { title: '辛法司宅观妓', author: '卢照邻', poem: '南国佳人至，北棠罗荐开。\n长帬随凤管，促柱送鸾杯。\n云光身后落，雪态掌中回。\n到愁金谷晚，不怪玉山颓。' },
  { title: '春晚山庄率题二首 一', author: '卢照邻', poem: '顾步三春晚，田园四望通。\n游丝横惹树，戏蝶乱依藂。\n竹懒偏宜水，花狂不待风。\n唯余诗酒意，当了一生中。' },
  { title: '春晚山庄率题二首 二', author: '卢照邻', poem: '田家无四邻，独坐一园春。\n莺啼非选树，鱼戏不惊纶。\n山水弹琴尽，风花酌酒频。\n年华已可乐，高兴复留人。' },
  { title: '江中望月', author: '卢照邻', poem: '江水向涔阳，澄澄写月光。\n镜圆珠留彻，弦满箭波长。\n沈钩摇兔影，浮桂动丹芳。\n延照相思夕，千里共沾裳。' },
  { title: '元日述怀', author: '卢照邻', poem: '筮仕无中秩，归耕有外臣。\n人歌小岁酒，花舞大唐春。\n草色迷三径，风光动四邻。\n愿得长如此，年年物候新。' },
  { title: '益州城西张超亭观妓', author: '卢照邻', poem: '落日明歌席，行云逐舞人。\n江前飞暮雨，梁上下轻尘。\n冶服看疑画，粧楼望似春。\n高车勿遽返，长袖欲相亲。' },
  { title: '还京赠别', author: '卢照邻', poem: '风月清江夜，山水白云朝。\n万里同为客，三秋契不凋。\n戏凫分断岸，归骑别高标。\n一去仙桥道，还望锦城遥。' },
  { title: '至陈仓晓晴望京邑', author: '卢照邻', poem: '拂曙驱飞传，初晴带晓凉。\n雾歛长安树，云归仙帝乡。\n涧流漂素沫，岩景霭朱光。\n今朝好风色，延瞰极天庄。' },
  { title: '晚渡滹沱敬赠魏大', author: '卢照邻', poem: '津谷朝行远，冰川夕望曛。\n霞明深浅浪，风卷去来云。\n澄波泛月影，激浪聚沙文。\n谁忍仙舟上，携手独思君。' },
  { title: '和吴侍御被使燕然', author: '卢照邻', poem: '春归龙塞北，骑指雁门垂。\n胡笳折杨柳，汉使采燕支。\n戍城聊一望，花雪几参差。\n关山有新曲，应向笛中吹。' },
  { title: '七夕泛舟二首 一', author: '卢照邻', poem: '汀葭肃徂暑，江树起初凉。\n水疑通织室，舟似泛仙潢。\n连桡渡急响，鸣櫂下浮光。\n日晚菱歌唱，风烟满夕阳。' },
  { title: '七夕泛舟二首 二', author: '卢照邻', poem: '凤杼秋期至，凫舟野望开。\n微吟翠塘侧，延想白云隈。\n石似支机罢，槎疑犯宿来。\n天潢殊漫漫，日暮独悠哉。' },
  { title: '西使兼送孟学士南游', author: '卢照邻', poem: '地道巴陵北，天山弱水东。\n相看万余里，共倚一征蓬。\n零雨悲王粲，清尊别孔融。\n裴回闻夜鹤，怅望待秋鸿。\n骨肉胡秦外，风尘关塞中。\n唯余剑锋在，耿耿气成虹。' },
  { title: '送郑司仓入蜀', author: '卢照邻', poem: '离人丹水北，游客锦城东。\n别意还无已，离忧自不穷。\n陇云朝结阵，江月夜临空。\n关塞疲征马，霜氛落早鸿。\n潘年三十外，蜀道五千中。\n送君秋水曲，酌酒对清风。' },
  { title: '绵州官池赠别同赋湾字', author: '卢照邻', poem: '𬨎轩遵上国，仙佩下灵关。\n尊酒方无地，联绻喜暂攀。\n离言欲赠策，高辨正连环。\n野迳浮云断，荒池春草斑。\n残花落古树，度鸟入澄湾。\n欲敍他乡别，幽谷有绵蛮。' },
  { title: '还赴蜀中贻示京邑游好', author: '卢照邻', poem: '籞宿花初满，章台柳向飞。\n如何正此日，还望昔多违。\n怅别风期阻，将乖云会稀。\n歛衽辞丹阙，悬旗陟翠微。\n野禽喧戍鼓，春草变征衣。\n回顾长安道，关山起夕霏。' },
  { title: '初夏日幽庄', author: '卢照邻', poem: '闻有高踪客，耿介坐幽庄。\n林壑人事少，风烟鸟路长。\n瀑水含秋气，垂藤引夏凉。\n苗深全覆陇，荷上半侵塘。\n钓渚青凫没，村田白鹭翔。\n知君振奇藻，还嗣海隅芳。' },
  { title: '山庄休沐', author: '卢照邻', poem: '兰署乘闲日，蓬扉狎遁栖。\n龙柯疎玉井，凤叶下金堤。\n川光摇水箭，山气上云梯。\n亭幽闻唳鹤，窗晓听鸣鸡。\n玉轸临风奏，琼浆映月携。\n田家自有乐，谁肯谢青溪。' },
  { title: '山林休日田家', author: '卢照邻', poem: '归休乘暇日，馌稼返秋场。\n径草疏王篲，岩枝落帝桑。\n耕田虞讼寝，凿井汉机忘。\n戎葵朝委露，齐枣夜含霜。\n南涧泉初冽，东篱菊正芳。\n还思北窗下，高卧偃羲皇。' },
  { title: '宴梓州南亭得池字', author: '卢照邻', poem: '二条开胜迹，大隐叶冲规。\n亭阁分危岫，楼台遶曲池。\n长薄秋烟起，飞梁古蔓垂。\n水鸟翻荷叶，山虫咬桂枝。\n游人惜将晚，公子爱忘疲。\n愿得回三舍，琴尊长若斯。' },
  { title: '山行寄刘李二参军', author: '卢照邻', poem: '万里烟尘客，三春桃李时。\n事去纷无限，愁来不自持。\n狂歌欲叹凤，失路反占龟。\n草碍人行缓，花繁鸟度迟。\n彼美参卿事，留连求友诗。\n安知倦游子，两鬓渐如丝。' },
  { title: '首春贻京邑文士', author: '卢照邻', poem: '寂寂罢将迎，门无车马声。\n横琴荅山水，披卷阅公卿。\n忽闻岁云晏，倚杖出檐楹。\n寒辞杨柳陌，春满凤皇城。\n梅花扶院吐，兰叶遶阶生。\n览镜改容色，藏书留姓名。\n时来不假问，生死任交情。' },
  { title: '赠许左丞从驾万年宫', author: '卢照邻', poem: '闻道上之回，诏跸下蓬莱。\n中枢移北斗，左辖去南台。\n黄山闻凤笛，清跸侍龙媒。\n曳日朱旗卷，参云金障开。\n朝参五城柳，夕宴柏梁杯。\n汉畤光如月，秦祠听似雷。\n寂寂芸香阁，离思独悠哉。' },
  { title: '晚渡渭桥寄示京邑游好', author: '卢照邻', poem: '我行背城阙，驱马独悠悠。\n寥落百年事，裴回万里忧。\n途遥日向夕，时晚鬓将秋。\n滔滔俯东逝，耿耿泣西浮。\n长虹掩钓浦，落雁下星洲。\n草变黄山曲，花飞清渭流。\n迸水惊愁鹭，腾沙起狎鸥。\n一赴清泥道，空思玄灞游。' },
  { title: '羁卧山中', author: '卢照邻', poem: '卧壑迷时代，行歌任死生。\n红颜意气尽，白璧故交轻。\n涧户无人迹，山窗听鸟声。\n春色缘岩上，寒光入溜平。\n雪尽松帷暗，云开石路明。\n夜伴饥鼯宿，朝随驯雉行。\n度溪犹忆处，寻洞不知名。\n紫书常日阅，丹药几年成。\n扣钟鸣天鼓，烧香厌地精。\n倘遇浮丘鹤，飘飖凌太清。' },
  { title: '酬张少府柬之', author: '卢照邻', poem: '昔余与夫子，相遇汉川阴。\n珠浦龙犹卧，檀溪马正沈。\n价重瑶山曲，词惊丹凤林。\n十年暌赏慰，万里隔招寻。\n毫翰风期阻，荆衡云路深。\n鹏飞俱望昔，蠖屈共悲今。\n谁谓青衣道，还叹白头吟。\n地接神仙磵，江连云雨岑。\n飞泉如散玉，落日似悬金。\n重以瑶华赠，空怀舞咏心。' },
  { title: '过东山谷口', author: '卢照邻', poem: '不知名利险，辛苦滞皇州。\n始觉飞尘倦，归来事绿畴。\n桃源迷处所，桂树可淹留。\n迹异人间俗，禽同海上鸥。\n古苔依井被，新乳傍崖流。\n野老堪成鹤，山神或化鸠。\n泉鸣碧涧底，花落紫岩幽。\n日暮飡龟壳，天寒御鹿裘。\n不辨秦将汉，宁知春与秋。\n多谢青溪客，去去赤松游。' },
  { title: '送幽州陈参军赴任寄呈乡曲父老', author: '卢照邻', poem: '蓟北三千里，关西二十年。\n冯唐犹在汉，乐毅不归燕。\n人同黄鹤远，乡共白云连。\n郭隗池台处，昭王尊酒前。\n故人当已老，旧壑几成田。\n红颜如昨日，衰鬓似秋天。\n西蜀桥应毁，东周石尚全。\n灞池水犹绿，榆关月早圆。\n塞云初上雁，庭树欲销蝉。\n送君之旧国，挥泪独澘然。' },
  { title: '哭金部韦郎中', author: '卢照邻', poem: '金曹初受拜，玉地始含香。\n翻同五日尹，遽见一星亡。\n贺客犹扶路，哀人遂上堂。\n歌筵长寂寂，哭位自苍苍。\n岁时宾径断，朝暮雀罗张。\n书留魏主阙，魂掩汉家床。\n徒令永平帝，千载罢撞郎。' },
  { title: '哭明堂裴主簿', author: '卢照邻', poem: '缔欢三十载，通家数百年。\n潘杨称代穆，秦晋忝姻连。\n风云洛阳道，花月茂陵田。\n相悲共相乐，交骑复交筵。\n始谓调金鼎，如何掩玉泉。\n黄公酒𬬻处，青眼竹林前。\n故琴无复雪，新树但生烟。\n遽痛兰襟断，徒令宝剑悬。\n客散同秋叶，人亡似夜川。\n送君一长恸，松台路几千。' },
  { title: '同崔录事哭郑员外', author: '卢照邻', poem: '文学秋天远，郎官星位尊。\n伊人表时彦，飞誉满司存。\n楚席光文雅，瑶山侍讨论。\n凤词凌汉阁，龟辩罩周园。\n已陪东岳驾，将逝北溟鲲。\n如何万化尽，空叹九飞魂。\n白马西京驿，青松北海门。\n夜台无晓箭，朝奠有虚尊。\n一代儒风没，千年陇雾昏。\n梁山送夫子，湘水吊王孙。\n仆本多悲泪，沾裳不待猿。\n闻君绝弦曲，吞恨更无言。' },
  { title: '登玉清', author: '卢照邻', poem: '绝顶横临日，孤峰半倚天。\n裴回拜真老，万里见风烟。' },
  { title: '曲池荷', author: '卢照邻', poem: '浮香绕曲岸，圆影覆华池。\n常恐秋风早，飘零君不知。' },
  { title: '浴浪鸟', author: '卢照邻', poem: '独舞依磐石，群飞动轻浪。\n奋迅碧沙前，长怀白云上。' },
  { title: '临阶竹', author: '卢照邻', poem: '封霜连锦砌，防露拂瑶阶。\n聊将仪凤质，暂与俗人谐。' },
  { title: '含风蝉', author: '卢照邻', poem: '高情临爽月，急响送秋风。\n独有危冠意，还将衰鬓同。' },
  { title: '葮川独泛', author: '卢照邻', poem: '倚櫂春江上，横舟石岸前。\n山瞑行人断，迢迢独泛仙。' },
  { title: '送二兄入蜀', author: '卢照邻', poem: '关山客子路，花柳帝王城。\n此中一分手，相顾怜无声。' },
  { title: '宿玄武二首 一', author: '卢照邻', poem: '方池开晓色，圆月下秋阴。\n已乘千里兴，还抚一弦琴。' },
  { title: '宿玄武二首 二', author: '卢照邻', poem: '庭摇北风柳，院绕南溟禽。\n累宿恩方重，穷秋叹不深。' },
  { title: '九陇津集', author: '卢照邻', poem: '落落树阴紫，澄澄水华碧。\n复有翻飞禽，裴回疑曳舃。' },
  { title: '游昌化山精舍', author: '卢照邻', poem: '宝地乘峰出，香台接汉高。\n稍觉真途近，方知人事劳。' },
  { title: '登封大酺歌四首 一', author: '卢照邻', poem: '明君封禅日重光，天子垂衣历数长。\n九州四海常无事，万岁千秋乐未央。' },
  { title: '登封大酺歌四首 二', author: '卢照邻', poem: '日观仙云随凤辇，天门瑞雪照龙衣。\n繁弦绮席方终夜，妙舞清歌欢未归。' },
  { title: '登封大酺歌四首 三', author: '卢照邻', poem: '翠凤逶迤登介丘，仙鹤裴回天上游。\n借问干封何所乐，人皆寿命得千秋。' },
  { title: '登封大酺歌四首 四', author: '卢照邻', poem: '千年圣主应昌期，万国淳风王化基。\n请比上古无为代，何如今日太平时。' },
  { title: '九月九日登玄武山', author: '卢照邻', poem: '九月九日眺山川，归心归望积风烟。\n他乡共酌金花酒，万里同悲鸿雁天。' },
  { title: '少年行', author: '李百药', poem: '少年飞翠盖，上路勒金镳。\n始酌文君酒，新吹弄玉箫。\n少年不欢乐，何以尽芳朝。\n千金笑里面，一搦掌中腰。\n挂缨岂惮宿，落珥不胜娇。\n寄语少年子，无辞归路遥。' },
  { title: '渡汉江', author: '李百药', poem: '东流既弥弥，南纪信滔滔。\n水激沈碑岸，波骇弄珠皐。\n含星映浅石，浮盖下奔涛。\n溜阔霞光近，川长晓气高。\n樯乌转轻翼，戏鸟落风毛。\n客心既多绪，长歌且代劳。' },
  { title: '秋晚登古城', author: '李百药', poem: '日落征途远，怅然临古城。\n颓墉寒雀集，荒堞晚乌惊。\n萧森灌木上，迢遰孤烟生。\n霞景焕余照，露气澄晚清。\n秋风转摇落，此志安可平。' },
  { title: '途中述怀', author: '李百药', poem: '伯喈迁塞北，亭伯之辽东。\n伊余何为客，独守云台中。\n途遥已日暮，时泰道斯穷。\n拔心悲岸草，半死落岩桐。\n目送衡阳雁，情伤江上枫。\n福兮良所伏，今也信难通。\n丈夫自有志，宁伤官不公。' },
  { title: '郢城怀古', author: '李百药', poem: '客心悲暮序，登墉瞰平陆。\n林泽窅芊緜，山川郁重复。\n王公资设险，名都拒江隩。\n方城次北门，溟海穷南服。\n长策挫吴豕，雄图竞周鹿。\n万乘重沮漳，九鼎轻伊谷。\n大搜云梦掩，壮观章华筑。\n人世更盛衰，吉凶良倚伏。\n遽见邻交断，仍覩贤臣逐。\n南风忽不竞，西师日侵蹙。\n运圯属驰驱，时屯恣敲朴。\n莫救夷陵火，无复秦庭哭。\n鄢郢遂丘墟，风尘俄惨黩。\n狐兔时游践，霜露日沾沐。\n钓渚故池平，神台层宇覆。\n阵云埋夏首，穷阴惨荒谷。\n怅矣舟壑迁，悲哉年祀倏。\n虽异三春望，终伤千里目。' },
  { title: '晚渡江津', author: '李百药', poem: '寂寂江山晚，苍苍原野暮。\n秋气怀易悲，长波淼难溯。\n索索风叶下，离离早鸿度。\n丘壑列夕阴，葭菼凝寒雾。\n日落亭皐远，独此怀归慕。' },
  { title: '王师渡汉水经襄阳', author: '李百药', poem: '导漾疏源远，归海会流长。\n延波接荆梦，通望迩沮漳。\n高岸沈碑影，曲溆丽珠光。\n云昏翠岛没，水广素涛扬。\n阅川已多叹，遐睇几增伤。\n临谿犹驻马，望岘欲沾裳。\n乔木下寒叶，亭林落晓霜。\n山公不可遇，谁与访高阳。' },
  { title: '谒汉高庙', author: '李百药', poem: '纂尧灵命启，灭楚余闰终。\n飞名膺帝箓，沈迹韫神功。\n瑞气朝浮砀，祥符夜告丰。\n抑扬驾人杰，叱咤掩时雄。\n缔构三灵改，经纶五纬同。\n干戈革宇内，声教尽寰中。\n运谢年逾远，魂归道未穷。\n树碑留故邑，抗殿表祠宫。\n沐兰祈泗上，谒帝动深衷。\n英威肃如在，文物杳成空。\n竹皮聚寒径，枌社落霜丛。\n萧索阴云晚，长川起大风。' },
  { title: '登叶县故城谒沈诸梁庙', author: '李百药', poem: '总辔临秋原，登城望寒日。\n烟霞共掩映，林野俱萧瑟。\n楚塞郁不穷，吴山高渐出。\n客行殊未已，沐澡期终吉。\n椒桂奠芳樽，风云下虚室。\n馆宇肃而静，神心康且逸。\n伊我非真龙，勿惊疲朽质。' },
  { title: '安德山池宴集', author: '李百药', poem: '朝宰论思暇，高宴临方塘。\n云飞凤台管，风动令君香。\n细草开金埒，流霞泛羽觞。\n虹桥分水态，镜石引菱光。\n上才同振藻，小技谬连章。\n怀音自兰室，徐步返山庄。' },
  { title: '和许侍郎游昆明池', author: '李百药', poem: '神池望不极，沧波接远天。\n仪星似河汉，落景类虞泉。\n年深平馆宇，道泰偃戈船。\n差池下凫雁，掩映生云烟。\n浪花开已合，风文直且连。\n税马金堤外，横舟石岸前。\n羽觞倾绿蚁，飞日落红鲜。\n积水浮深智，明珠曜雅篇。\n大鲸方远击，沈灰独未然。\n知君啸俦侣，短翮徒联翩。' },
  { title: '赋得魏都', author: '李百药', poem: '炎运精华歇，清都宝命开。\n帝里三方盛，王庭万国来。\n玄武疏遥磴，金凤上层台。\n乍进仙童药，时倾避暑杯。\n南馆招奇士，西园引上才。\n还惜刘公干，疲病清漳隈。' },
  { title: '赋礼记', author: '李百药', poem: '玉帛资王会，郊丘叶圣情。\n重广开环堵，至道轶金籝。\n盘薄依厚地，遥裔腾太清。\n方悦升中礼，足以慰余生。' },
  { title: '奉和正日临朝应诏', author: '李百药', poem: '化历昭唐典，承天顺夏正。\n百灵警朝禁，三辰扬斾旌。\n充庭富礼乐，高䜩齿簪缨。\n献寿符万岁，移风韵九成。' },
  { title: '妾薄命', author: '李百药', poem: '团扇秋风起，长门夜月明。\n羞闻拊背入，恨说舞腰轻。\n太常先已醉，刘君恒带酲。\n横陈每虚设，吉梦竟何成。' },
  { title: '火凤词二首 一', author: '李百药', poem: '歌声扇后出，妆影镜中轻。\n未能令掩笑，何处欲障声。\n知音自不惑，得念是分明。\n莫见双嚬歛，疑人含笑情。' },
  { title: '火凤词二首 二', author: '李百药', poem: '佳人靓晚妆，清唱动兰房。\n影出含风扇，声飞照日梁。\n娇嚬眉际歛，逸韵口中香。\n自有横陈会，应怜秋夜长。' },
  { title: '奉和初春出游应令', author: '李百药', poem: '鸣笳出望苑，飞盖下芝田。\n水光浮落照，霞彩淡轻烟。\n柳色迎三月，梅花隔二年。\n日斜归骑动，余兴满山川。' },
  { title: '寄杨公', author: '李百药', poem: '公子盛西京，光华早著名。\n分庭接游士，虚馆待时英。\n高阁浮香出，长廊宝钏鸣。\n面花无隔笑，歌扇不障声。' },
  { title: '戏赠潘徐城门迎两新妇', author: '李百药', poem: '秦晋称旧匹，潘徐有世亲。\n三星宿已会，四德婉而嫔。\n霞光鬓里薄，月影扇中新。\n年华与妆面，共作一芳春。' },
  { title: '送别', author: '李百药', poem: '眷言一杯酒，凄怆起离忧。\n夜花飘露气，暗水急还流。\n雁行遥上月，虫声迥映秋。\n明日河梁上，谁与论仙舟。' },
  { title: '雨后', author: '李百药', poem: '晚来风景丽，晴初物色华。\n薄云向空尽，轻虹逐望斜。\n后窗临岸竹，前阶枕浦沙。\n寂寥无与晤，尊酒论风花。' },
  { title: '文德皇后挽歌', author: '李百药', poem: '裴回两仪殿，怅望九成台。\n玉辇终辞宴，瑶筐遂不开。\n野旷阴风积，川长思鸟来。\n寒山寂已暮，虞殡有余哀。' },
  { title: '咏蝉', author: '李百药', poem: '清心自饮露，哀响乍吟风。\n未上华冠侧，先惊翳叶中。' },
  { title: '咏萤火示情人', author: '李百药', poem: '窗里怜灯暗，阶前畏月明。\n不辞逢露湿，祗为重宵行。' },
  { title: '春眺', author: '李百药', poem: '疲疴荷拙患，沦踬合幽襟。\n栖息在何处？丘中鸣素琴。' },
  { title: '奉和太子纳妃太平公主出降', author: '刘祎之', poem: '梦梓光青陛，秾桃蔼紫宫。\n德优宸念远，礼备国姻崇。\n万户声明发，三条骑吹通。\n香轮送重景，彩斾引仙虹。' },
  { title: '奉和别越王', author: '刘祎之', poem: '周屏辞金殿，梁骖整玉珂。\n管声依折柳，琴韵动流波。\n鹤盖分阴促，龙轩别念多。\n延襟小山路，还起大风歌。' },
  { title: '酬郑沁州', author: '刘祎之', poem: '麒阁一代良，熊轩千里躅。\n缉图昭国典，按部留宸瞩。\n匪厌承明庐，伫兼司隶局。\n芸书暂辍载，竹使方临俗。\n节变风绪高，秋深露华溽。\n寒山敛轻霭，霁野澄初旭。\n已切长年悲，谁堪岐路促。\n遥林征马迅，别馆嘶骖跼。\n雅赠响𪭢金，索居暌倚玉。\n凄断离鸿引，劳歌思足曲。' },
  { title: '孝敬皇帝挽歌', author: '刘祎之', poem: '戒奢虚蜃辂，锡号纪鸿名。\n地叶苍梧野，途经紫聚城。\n重照掩寒色，晨飙断曙声。\n一随仙骥远，霜雪愁阴生。' },
  { title: '九成宫秋初应诏', author: '刘祎之', poem: '帝圃疏金阙，仙台驻玉銮。\n野分鸣𬸚岫，路接宝鸡坛。\n林树千霜积，山宫四序寒。\n蝉急知秋早，莺疎觉夏阑。\n怡神紫气外，凝睇白云端。\n舜海词波发，空惊游圣难。' },
  { title: '奉和别鲁王', author: '李敬玄', poem: '绿车旋楚服，丹跸伫秦川。\n珠皐转归骑，金岸引行旃。\n一朝限原隰，千里间风烟。\n莺喧上林谷，凫响御沟泉。\n断云移鲁盖，离歌动舜弦。\n别念凝神扆，崇恩洽玳筵。\n顾惟慙叩寂，徒自仰钧天。' },
  { title: '奉和别越王', author: '李敬玄', poem: '飞盖回兰坂，宸襟伫柏梁。\n别馆分泾渭，归路指衡漳。\n关山通曙色，林籞徧春光。\n帝念纡千里，词波照五潢。' },
  { title: '奉和别越王', author: '张大安', poem: '盛藩资右戚，连蕚重皇情。\n离襟怆睢苑，分途指邺城。\n丽日开芳甸，佳气积神京。\n何时骖驾入，还见谒承明。' },
  { title: '奉和太子纳妃太平公主出降', author: '元万顷', poem: '象辂初乘鴈，璇宫早结褵。\n离元应春夕，帝子降秋期。\n鸣瑜合清响，冠玉丽秾姿。\n和声跻凤掖，交影步鸾墀。' },
  { title: '奉和春日池台', author: '元万顷', poem: '日影飞花殿，风文积草池。\n凤楼通夜敞，虬辇望春移。' },
  { title: '奉和春日二首 一', author: '元万顷', poem: '花轻蘂乱仙人杏，叶密莺喧帝女桑。\n飞云阁上春应至，明月楼中夜未央。' },
  { title: '奉和春日二首 二', author: '元万顷', poem: '凤辇迎风乘紫阁，鸾车避日转彤闱。\n中堂促管淹春望，后殿清歌开夜扉。' },
  { title: '奉和太子纳妃太平公主出降', author: '郭正一', poem: '桂宫初服冕，兰掖早升筓。\n礼盛亲迎晋，声芬出降齐。\n金龟开瑞钮，宝翟上仙袿。\n转扇承宵月，扬旌照夕蜺。' },
  { title: '奉和太子纳妃太平公主出降三首 一', author: '胡元范', poem: '帝子威仪绝，储妃礼度优。\n叠鼓陪仙观，凝笳翼画辀。\n郁郁神香满，奕奕彩云浮。\n排空列锦罽，腾欢溢皇州。' },
  { title: '奉和太子纳妃太平公主出降三首 二', author: '胡元范', poem: '金闺未息火，玉树钟天爱。\n月路饰还装，星津动归佩。\n紫极流宸渥，清规伫慈诲。\n恩波洽九流，光辉轶千载。' },
  { title: '奉和太子纳妃太平公主出降三首 三', author: '胡元范', poem: '列席诏亲贤，式宴坐神仙。\n圣文飞圣笔，天乐奏钧天。\n曲池涵瑞景，文宇孕祥烟。\n小臣同百兽，率舞悦尧年。' },
  { title: '奉和太子纳妃太平公主出降', author: '任希古', poem: '帝子升青陛，王姬降紫宸。\n星光移杂珮，月彩荐重轮。\n龙旌翻地杪，凤管飏天滨。\n槐阴浮浅濑，葆吹翼轻尘。' },
  { title: '和东观群贤七夕临泛昆明池', author: '任希古', poem: '秋风始摇落，秋水正澄鲜。\n飞眺牵牛渚，激赏镂鲸川。\n岸珠沦晓魄，池灰敛曙烟。\n泛查分写汉，仪星别搆天。\n云光波处动，日影浪中悬。\n惊鸿絓蒲弋，游鲤入庄筌。\n萍叶疑江上，菱花似镜前。\n长林代轻幄，细草即芳筵。\n文峰开翠潋，笔海控清涟。\n不挹兰樽圣，空仰桂舟仙。' },
  { title: '和左仆射燕公春日端居述怀', author: '任希古', poem: '丰野光三杰，妫庭赞五臣。\n绨缃歌美誉，丝竹咏芳尘。\n圣历开环象，昌年降甫申。\n高门非舍筑，华构岂垂纶。\n凤邸抟霄翰，龙池跃海鳞。\n玉鼎升黄阁，金章谒紫宸。\n礼闱通政本，文昌总国均。\n调风振薄俗，清教叙彝伦。\n星回应缇管，日御警寅宾。\n叶上曾槐变，花发小堂春。\n思挂五都冕，言访北山巾。\n赫赫容台上，千祀耀平津。' },
  { title: '和长孙秘监伏日苦热', author: '任希古', poem: '玉署三时晓，金羁五日归。\n北林开逸径，东阁敞闲扉。\n池镜分天色，云峰减日辉。\n游鳞映荷聚，惊翰遶林飞。\n披襟[扬]子宅，舒啸仰重闱。' },
  { title: '和李公七夕', author: '任希古', poem: '落日照高牖，凉风起庭树。\n悠悠天宇平，昭昭月华度。\n开轩卷绡幕，延首晞云路。\n层汉有灵妃，仙居无与晤。\n履化悲流易，临川怨迟暮。\n昔从九春徂，方此三秋遇。\n瑶驾越星河，羽盖凝珠露。\n便妍耀井色，窈窕凌波步。\n始阅故人新，俄见新人故。\n掩泪收机石，衔啼襞纨素。\n惆怅何伤已，裴回劳永慕。\n无由西北归，空自东南顾。' },
  { title: '和长孙秘监七夕', author: '任希古', poem: '二秋叶神媛，七夕望仙妃。\n影照河阳妓，色丽平津闱。\n鹊桥波里出，龙车霄外飞。\n露泫低珠佩，云移荐锦衣。\n更深黄月落，夜久靥星稀。\n空接灵台下，方恧辨支机。' },
  { title: '奉和太子纳妃太平公主出降三首 一', author: '裴守真', poem: '瑜珮升青殿，秾华降紫微。\n还如桃李发，更似凤皇飞。\n金屋真离象，瑶台起婺徽。\n彩缨纷碧坐，[缋]羽泛褕衣。' },
  { title: '奉和太子纳妃太平公主出降三首 二', author: '裴守真', poem: '云路移彤辇，天津转明镜。\n仙珠照乘归，宝月重轮映。\n望园嘉宴洽，主第欢娱盛。\n丝竹扬帝熏，簪裾奉宸庆。' },
  { title: '奉和太子纳妃太平公主出降三首 三', author: '裴守真', poem: '藂云霭晓光，湛露晞朝阳。\n天文天景丽，睿藻睿词芳。\n玉庭散秋色，银宫生夕凉。\n太平超邃古，万寿乐无疆。' },
  { title: '奉和圣制过温汤', author: '杨思玄', poem: '丰城观汉迹，温谷幸秦余。\n地接幽王垒，涂分郑国渠。\n风威肃文卫，日彩镜雕舆。\n远岫凝氛重，寒丛对影疎。\n回瞻汉章阙，佳气满宸居。' },
  { title: '奉和别鲁王', author: '杨思玄', poem: '元王诗传博，文后宠灵优。\n鹤盖动宸眷，龙章送远游。\n函关疏别道，灞岸引行舟。\n北林分苑树，东流溢御沟。\n鸟声含羽碎，骑影曳花浮。\n圣泽九垓普，天文七曜周。\n方图献雅乐，簪带奉鸣球。' },
  { title: '奉和圣制过温汤', author: '王德真', poem: '握图开万宇，属圣启千年。\n骊阜疏缇骑，惊鸿映彩旃。\n玉霜鸣凤野，金阵藻龙川。\n祥烟聚危岫，德水溢飞泉。\n停舆兴睿览，还举大风篇。' },
  { title: '奉和圣制过温汤', author: '郑义真', poem: '洛川方驻跸，丰野暂停銮。\n汤泉恒独涌，温谷岂知寒。\n漏鼓依岩畔，相风出树端。\n岭烟遥聚草，山月迥临鞍。\n日用诚多幸，天文遂仰观。' },
  { title: '奉和展礼岱宗涂经濮济', author: '萧楚材', poem: '拂汉星旗转，分霄日羽明。\n将追会阜迹，更勒岱宗铭。\n林戈咽济岸，兽鼓震河庭。\n叶箭凌寒矫，鸟弓望晓惊。\n已降汾水作，仍深迎渭情。' },
  { title: '奉和展礼岱宗涂经濮济', author: '薛克构', poem: '龙图冠胥陆，凤驾指云亭。\n非烟泛济浦，绿字启河汀。\n画裳晨应月，文戟曙分星。\n四田巡揖礼，三驱道契经。\n行欣奉万岁，窃抃偶千龄。' },
  { title: '日暮望泾水', author: '徐珩', poem: '导源径陇阪，属汭贯嬴都。\n下濑波常急，回圻溜亦纡。\n毒流秦卒毙，泥粪汉田腴。\n独有迷津客，怀归轸暮途。' },
  { title: '赠韩思彦', author: '贺遂亮', poem: '意气百年内，平生一寸心。\n欲交天下士，未面已虚襟。\n君子重名义，直道冠衣簪。\n风云行可托，怀抱自然深。\n落霞静霜景，坠叶下风林。\n若上南登岸，希访北山岑。' },
  { title: '酬贺遂亮', author: '韩思彦', poem: '古人一言重，尝谓百年轻。\n今投欢会面，顾盼尽平生。\n簪裾非所托，琴酒冀相倂。\n累日同游处，通宵欵素诚。\n霜飘知柳脆，雪冒觉松贞。\n愿言何所道，幸得岁寒名。' },
  { title: '自御史左授山阳丞', author: '魏求己', poem: '朝升照日槛，夕次下乌台。\n风竿一眇邈，月树几裴回。\n翼向高标敛，声随下调哀。\n怀燕首自白，非是为年催。' },
  { title: '赠右台监察邓茂迁左台殿中', author: '刘怀一', poem: '惟昔参多士，无双仰异才。\n鹰鹯同效逐，鹓鹭忝游陪。\n入仕光三命，迁荣历二台。\n隔墙钦素躅，对问限清埃。\n紫署春光早，兰闱曙色催。\n谁言夕鸟至，空想邓林隈。' },
  { title: '湘川新曲二首 一', author: '杜易简', poem: '昭潭深无底，橘洲浅而浮。\n本欲凌波去，翻为目成留。\n愿君稍弭檝，无令贱妾羞。' },
  { title: '湘川新曲二首 二', author: '杜易简', poem: '二八相招携，采菱渡前谿。\n弱腕随桡起，纤腰向舸低。\n自解看花笑，憎闻染竹啼。' },
  { title: '落成会咏一首', author: '陈元光', poem: '泉潮天万里，一镇屹天中。\n筮宅龙钟地，承恩燕翼宫。\n环堂巍岳秀，带砺大江雄。\n轮奂云霄望，晶华日月通。\n凌烟乔木茂，献宝介圭崇。\n昆俊歌常棣，民和教即戎。\n盘庚迁美士，陶侃效兼庸。\n设醴延张老，开轩礼吕蒙。\n无孤南国仰，庶补圣皇功。' },
  { title: '示珦', author: '陈元光', poem: '恩衔枫陛渥，策向桂渊弘。\n载笔沿儒习，持弓缵祖风。\n祛灾勦猛虎，溥德翊飞龙。\n日阅书开士，星言驾劝农。\n勤劳思命重，戏谑逐时空。\n百粤雾纷满，诸戎泽普通。\n愿言加壮努，勿坐鬓霜蓬。' },
  { title: '太母魏氏半径题石', author: '陈元光', poem: '乔岳标仙迹，玄扃妥寿姬。\n乌号非岭海，鹤仰向京师。\n系牒公侯裔，悬弧将相儿。\n清贞蜚简籍，规范肃门楣。\n万里提兵路，三年报母慈。\n劒埋龙守壤，石卧虎司碑。\n忧阕情犹结，祥回禫届期。\n竹符忠介凛，桐杖孝思凄。\n许史峋嶙篆，曹侯感旧诗。\n鸿蒙山暝启，骏彩德昭垂。\n华表瑶池冥，清漳玉树枝。\n昭题盟岳渎，展墓庆重熙。' },
  { title: '和陈元光平潮寇诗', author: '许天正', poem: '抱磴从天上，驱车返岭东。\n气昂无丑虏，策妙诎群雄。\n飞絮随风散，余氛响日镕。\n长戈收百甲，聚骑破千重。\n落劒惟戎首，游绳系胁从。\n四野无坚壁，群生未化融。\n龙湖膏泽下，早晚徧枯穷。' },
  { title: '咏牛应制', author: '许圉师', poem: '逸足还同骥，奇毛自偶麟。\n欲知花迹远，云影入天津。' },
  { title: '荅户部员外贺遂涉戏赠', author: '赵谦光', poem: '锦帐随情设，金𬬻任意熏。\n惟愁员外署，不应列星文。' },
  { title: '送苏尚书赴益州', author: '郑惟忠', poem: '离忧将岁尽，归望逐春来。\n庭花如有意，留艳待人开。' },
  { title: '咏燕', author: '张𬸦', poem: '变石身犹重，衔泥力尚微。\n从来赴甲第，两起一双飞。' },
  { title: '岭外守岁', author: '李福业', poem: '冬去更筹尽，春随斗柄回。\n寒暄一夜隔，客鬓两年催。' },
  { title: '奉和进船洛水应制', author: '薛眘惑', poem: '禁园纡睿览，仙櫂叶宸游。\n洛北风花树，江南彩画舟。\n荣生兰蕙草，春入凤皇楼。\n兴尽离宫暮，烟光起夕流。' },
  { title: '奉和九月九日应制', author: '贺敱', poem: '商飙凝素籥，玄览贲黄图。\n晓霜惊断雁，晨吹结栖乌。\n寒花低岸菊，凉叶下庭梧。\n泽宫申旧典，相圃叶前模。\n玉砌分雕戟，金沟转镂衢。\n带星飞夏箭，映月上轩弧。\n庆展簪裾洽，恩融雨露濡。\n天文发丹篆，宝思掩玄珠。\n承欢徒抃舞，负弛窃忘躯。' },
  { title: '奉和圣制夏日游石淙山', author: '狄仁杰', poem: '宸晖降望金舆转，仙路峥嵘碧涧幽。\n羽杖遥临鸾鹤驾，帷宫直坐凤麟洲。\n飞泉洒液恒疑雨，密树含凉镇似秋。\n老臣预陪悬圃宴，余年方共赤松游。' },
  { title: '修书院学士奉勅宴梁王宅', author: '魏元忠', poem: '大君敦宴赏，万乘下梁园。\n酒助闲平乐，人沾雨露恩。\n荣光开帐殿，佳气满旌门。\n愿陪南岳寿，长奉北宸樽。' },
  { title: '银潢宫侍宴应制', author: '魏元忠', poem: '别殿秋云上，离宫夏景移。\n寒风生玉树，凉气下瑶池。\n堑花仍吐叶，岩木尚抽枝。\n愿奉南山寿，千秋长若斯。' },
  { title: '折杨柳', author: '韦承庆', poem: '万里边城地，三春杨柳节。\n叶似镜中眉，花如关外雪。\n征人远乡思，倡妇高楼别。\n不忍掷年华，含情寄攀折。' },
  { title: '寒食应制', author: '韦承庆', poem: '凤城春色晚，龙禁早晖通。\n旧火收槐燧，余寒入桂宫。\n莺啼正隐叶，鸡鬬始开笼。\n蔼蔼瑶山满，仙歌始乐风。' },
  { title: '凌朝浮江旅思', author: '韦承庆', poem: '天晴上初日，春水送孤舟。\n山远疑无树，潮平似不流。\n岸花开且落，江鸟没还浮。\n羁望伤千里，长歌遣四愁。' },
  { title: '直中书省', author: '韦承庆', poem: '清切凤皇池，扶疎鸡树枝。\n唯应集鸾鹭，何为宿羁雌。\n大造乾坤辟，深恩雨露垂。\n昆蚑皆含养，驽骀亦驱驰。\n木偶翻为用，芝泥忽滥窥。\n九思空自勉，五字本无施。\n徒喜逢千载，何阶荅二仪。\n萤光向日尽，蚊力负山疲。\n禁宇庭除阔，闲宵钟箭移。\n暗花临户发，残月下帘欹。\n白发随年改，丹心为主披。\n命将时共泰，言与行俱危。\n寄谢巢由客，尧年正在斯。' },
  { title: '南行别弟', author: '韦承庆', poem: '澹澹长江水，悠悠远客情。\n落花相与恨，到地一无声。' },
  { title: '南中咏雁', author: '韦承庆', poem: '万里人南去，三春雁北飞。\n不知何岁月？得与尔同归。' },
  { title: '江楼', author: '韦承庆', poem: '独酌芳春酒，登楼已半曛。\n谁惊一行雁，冲断过江云。' },
  { title: '凝碧池侍宴看竞渡应制', author: '李怀远', poem: '上苑清銮路，高居重豫游。\n前对芙蓉沼，傍临杜若洲。\n地如玄扈望，波似洞庭秋。\n列筵飞翠斝，分曹戏鹢舟。\n湍高櫂影没，岸近榜歌遒。\n舞曲依鸾殿，箫声下凤楼。\n忽闻天上乐，疑逐海查流。' },
  { title: '奉和九月九日登慈恩寺浮图应制', author: '崔日用', poem: '紫宸欢每洽，绀殿法初隆。\n菊泛延龄酒，兰吹解愠风。\n咸英调正乐，香梵徧秋空。\n临幸浮天瑞，重阳日再中。' },
  { title: '奉和圣制送张说巡边', author: '崔日用', poem: '轩相推风后，周官重夏卿。\n庙谋能允迪，韬略又纵横。\n吉日四黄马，宣王六月兵。\n拟清鸡鹿塞，先指朔方城。\n列将怀威抚，匈奴畏盛名。\n去当推毂送，来伫出郊迎。\n绝漠蓬将断，华筵槿正荣。\n壮心看舞劒，别绪应悬旌。\n睿锡承优旨，干文复宠行。\n暂劳期永逸，赫矣振天声。' },
  { title: '奉和立春游苑迎春应制', author: '崔日用', poem: '乘时迎气正璇衡，灞浐烟氛向晚清。\n剪绮裁红妙春色，宫梅殿柳识天情。\n瑶筐彩燕先呈端，金缕晨鸡未学鸣。\n圣泽阳和宜宴乐，年年捧日向东城。' },
  { title: '奉和圣制春日幸望春宫应制', author: '崔日用', poem: '东郊风物正熏馨，素浐凫鹥戏绿汀。\n凤阁斜通平乐观，龙旗直逼望春亭。\n光风摇动兰英紫，淑气依迟柳色青。\n渭浦明晨修禊事，群公倾贺水心铭。' },
  { title: '奉和人日重宴大明宫恩赐彩缕人胜应制', author: '崔日用', poem: '新年宴乐坐东朝，钟鼓铿锽大乐调。\n金屋瑶筐开宝胜，花笺彩笔颂春椒。\n曲池苔色冰前液，上苑梅香雪里娇。\n宸极此时飞圣藻，微臣窃抃预闻韶。' },
  { title: '奉和圣制龙池篇', author: '崔日用', poem: '龙兴白水汉兴符，圣主时乘运斗枢。\n岸上䒠茸五花树，波中的皪千金珠。\n操环昔闻迎夏启，发匣先来瑞有虞。\n风色云光随隐见，赤云神化象江湖。' },
  { title: '夜宴安乐公主宅', author: '崔日用', poem: '银烛金屏坐碧堂，只言河汉动神光。\n主家盛时欢不极，才子能歌夜未央。' },
  { title: '饯唐永昌', author: '崔日用', poem: '洛阳桴鼓今不鸣，朝野咸推重太平。\n冬至冰霜俱怨别，春来花鸟若为情。' },
  { title: '奉和送金城公主适西蕃', author: '崔日用', poem: '圣后经纶远，谋臣计划多。\n受降追汉策，筑馆计戎和。\n俗化乌孙垒，春生积石河。\n六龙今出饯，双鹤愿为歌。' },
  { title: '奉和人日清晖阁宴群臣遇雪应制', author: '宗楚客', poem: '窈窕神仙阁，参差云汉间。\n九重中叶启，七日早春还。\n太液天为水，蓬莱雪作山。\n今朝上林树，无处不堪攀。' },
  { title: '安乐公主移入新宅侍宴应制', author: '宗楚客', poem: '星桥他日创，仙牓此时开。\n马向铺钱埒，箫闻弄玉台。\n人同卫叔美，客似长卿才。\n借问游天汉，谁能取石回。' },
  { title: '正月晦日侍宴浐水应制赋得长字', author: '宗楚客', poem: '御辇出明光，乘流泛羽觞。\n珠胎随月减，玉漏与年长。\n寒尽梅犹白，风迟柳未黄。\n日斜旌骑转，休气满林塘。' },
  { title: '奉和幸上阳宫侍宴应制', author: '宗楚客', poem: '紫庭金凤阙，丹禁玉鸡川。\n似立蓬瀛上，疑游昆阆前。\n鸟将歌合转，花共锦争鲜。\n湛露飞尧酒，熏风入舜弦。\n水光摇落日，树色带晴烟。\n向夕回雕辇，佳气满岩泉。' },
  { title: '奉和幸安乐公主山庄应制', author: '宗楚客', poem: '玉楼银牓枕严城，翠盖红旗列禁营。\n日映层岩图画色，风摇杂树管弦声。\n水边重阁含飞动，云里孤峰类削成。\n幸覩八龙游阆苑，无劳万里访蓬瀛。' },
  { title: '奉和圣制喜雪应制', author: '宗楚客', poem: '飘飘瑞雪下山川，散漫轻飞集九埏。\n似絮还飞垂柳陌，如花更绕落梅前。\n影随明月团纨扇，声将流水杂鸣弦。\n共荷神功万庾积，终朝圣寿百千年。' },
  { title: '句', author: '宗楚客', poem: '竹町罗千卫，兰莛降两宫。\n七萃銮舆动，千年瑞检开。\n彩旗临凤阙，翠幕遶龟津。' },
  { title: '奉和九日幸临渭亭登高应制得晖字', author: '苏瓌', poem: '重阳早露晞，睿赏瞰秋矶。\n菊气先熏酒，萸香更袭衣。\n清切丝桐会，纵横文雅飞。\n恩深荅效浅，留醉奉宸晖。' },
  { title: '兴庆池侍宴应制', author: '苏瓌', poem: '金阙平明宿雾收，瑶池式宴俯清流。\n瑞凤飞来随帝辇，祥鱼出戏跃王舟。\n帷齐绿树当筵密，盖转缃荷接岸浮。\n如临窃比微臣惧，若济叨陪圣主游。' },
  { title: '奉和圣制烛龙斋祭', author: '张九龄', poem: '上帝临下，鉴亦有光。\n孰云阴隲，惟圣克彰。\n六月徂暑，四郊愆阳。\n我后其勤，告于坛场。\n精意允溢，群灵鼓舞。\n蔚兮朝云，沛然时雨。\n雨我原田，亦既有年。\n烛龙煌煌，明宗报祀。\n于以助之，天人帝子。\n闻诗有训，国风兹始。' },
  { title: '奉和圣制喜雨', author: '张九龄', poem: '艰我稼穑，载育载亭。\n随物应之，曷圣与灵。\n谓我何凭，惟德之馨。\n谁云天远，以诚必至。\n太清无云，羲和顿辔。\n于斯烝人，瞻彼非觊。\n阴冥倏忽，沛泽咸洎。\n何以致之，我后之感。\n无皐无隰，黍稷黯黯。\n无卉无木，敷芬黮黤。\n黄龙勿来，鸣鸟不思。\n人和年丰，皇心则怡。\n岂与周宣，云汉徒诗。' },
  { title: '南郊文武出入舒和之乐', author: '张九龄', poem: '祝史辞正，人神庆叶。\n福以德昭，享以诚接。\n六变云备，百礼斯浃。\n祀事孔明，祚流万叶。' },
  { title: '奉和圣制幸晋阳宫', author: '张九龄', poem: '隋季失天策，万方罹凶残。\n皇祖称义旗，三灵皆获安。\n圣期将申锡，王业成艰难。\n盗移未改命，历在终履端。\n彼汾惟帝乡，雄都信郁盘。\n一月朔巡狩，群后陪清銮。\n霸迹在沛庭，旧仪覩汉官。\n唐风思何深？舜典敷更宽。\n户蒙枌榆复，邑争牛酒欢。\n缅惟翦商后，岂独微禹叹。\n三后既在天，万年斯不刊。\n尊祖实我皇，天文皆仰观。' },
  { title: '奉和圣制次成皐先圣擒建德之所', author: '张九龄', poem: '天命诚有集，王业初惟艰。\n翦商自文祖，夷项在兹山。\n地识斩蛇处，河临饮马间。\n威加昔运往，泽流今圣还。\n尊祖颂先烈，赓歌安用攀。\n绍成即我后，封岱出天关。' },
  { title: '奉和圣制赐诸州刺史以题座右', author: '张九龄', poem: '圣人合天德，洪覆在元元。\n每劳苍生念，不以黄屋尊。\n兴化俟群辟，择贤守列藩。\n得人此为盛，咨岳今复存。\n降鉴引君道，殷勤启政门。\n容光无不照，有象必为言。\n成宪知所奉，致理归其根。\n肃肃禀玄猷，煌煌戒朱轩。\n岂徒任遇重，兼尔宴锡繁。\n载闻励臣节，持答明主恩。' },
  { title: '奉和圣制送十道采访使及朝集使', author: '张九龄', poem: '三年一上计，万国趋河洛。\n课最力已陈，赏延恩复博。\n垂衣深共理，改瑟其咸若。\n首路回竹符，分镳扬木铎。\n戒程有攸往，诏饯无淹泊。\n昭晰动天文，殷勤在人瘼。\n持久望兹念，克终期所托。\n行矣当自强，春耕庶秋获。' },
  { title: '奉和圣制谒玄元皇帝庙斋', author: '张九龄', poem: '兴运昔有感，建祠北山巅。\n云雷初缔构，日月今悠然。\n紫气尚蓊郁，玄元如在焉。\n迨兹事追远，轮奂复增鲜。\n洞府香林处，斋坛清汉边。\n吾君乃尊祖，夙驾此留连。\n乐动人神会，钟成律度圆。\n笙歌下鸾鹤，芝术萃灵仙。\n曾是福黎庶，岂唯味虚玄。\n赓歌徒有作，微薄谢昭宣。' },
  { title: '巫山高', author: '张九龄', poem: '巫山与天近，烟景长青荧。\n此中楚王梦，梦得神女灵。\n神女去已久，云雨空冥冥。\n唯有巴猿啸，哀音不可听。' },
  { title: '和黄门卢监望秦始皇陵', author: '张九龄', poem: '秦帝始求仙，骊山何遽卜。\n中年既无效，兹地所宜复。\n徒役如雷奔，珍怪亦云蓄。\n黔首无寄命，赭衣相追逐。\n人怨神亦怒，身死宗遂覆。\n土崩失天下，龙鬬入函谷。\n国为项籍屠，君同华元戮。\n始掘既由楚，终焚乃因牧。\n上宰议扬贤，中阿感桓速。\n一闻过秦论，载怀空杼轴。' },
  { title: '酬周判官巡至始兴会改秘书少监见贻之作兼呈耿广州', author: '张九龄', poem: '惟昔迁乐土，迨今已重世。\n阴庆荷先德，素风慙后裔。\n唯益梓桑恭，岂禀山川丽。\n于时初自勉，揆己无兼济。\n瘠土资劳力，良书启蒙蔽。\n一探石室文，再擢金门第。\n既起南宫草，复掌西掖制。\n过举及小人，便蕃在中岁。\n亚司河海秩，转牧江湖澨。\n勿谓符竹轻，但觉涓尘细。\n一麾尚云忝，十驾宜求税。\n心息已如灰，迹牵且为赘。\n忽捧天书委，将革海隅弊。\n朝闻循诚节，夕饮蒙瘴疠。\n义疾耻无勇，盗憎攻亦锐。\n葵藿是倾心，豺狼何反噬。\n履险甘所受，劳贤恧相曳。\n揽辔但荒服，循陔便私第。\n嘉庆始获申，恩华复相继。\n无庸我先举，同事君犹滞。\n当推奉使绩，且结拜亲契。\n更延怀安旨，曾是虑危际。\n善谋虽若兹，至理焉可替。\n所杖有神道，况承明主惠。' },
  { title: '和吏部李侍郎见示秋夜望月忆诸侍郎之什其卒章有前后行之戏因命仆继作', author: '张九龄', poem: '清秋发高兴，凉月复闲宵。\n光逐露华满，情因水镜摇。\n同时亦所见，异路无相招。\n美景向空尽，欢言随事销。\n忽听金华作，诚如玉律调。\n南宫尚为后，东观何其辽。\n名数虽云隔，风期幸未遥。\n今来重余论，怀此更终朝。' },
  { title: '登南岳事毕谒司马道士', author: '张九龄', poem: '将命祈灵岳，回策诣真士。\n绝迹寻一径，异香闻数里。\n分庭八桂树，肃容两童子。\n入室希把袖，登床愿启齿。\n诱我弃智诀，迨兹长生理。\n吸精反自然，炼药求不死。\n斯言眇霄汉，顾余婴纷滓。\n相去九牛毛，慙叹知何已。' },
  { title: '九月九日登龙山', author: '张九龄', poem: '郡庭常窘束，凉野求昭旷。\n楚客凛秋时，桓公旧台上。\n清明风日好，历落江山望。\n极远何萧条，中留坐惆怅。\n东弥夏首阔，西拒荆门壮。\n夷险虽异时，古今岂殊状。\n先贤杳不接，故老犹可访。\n投吊伤昔人，挥斤感前匠。\n自为本疎散，未始忘幽尚。\n际会非有欲，往来是无妄。\n为邦复多幸，去国殊迁放。\n且泛篱下菊，还聆郢中唱。\n灌园亦何为，于陵乃逃相。' },
  { title: '登郡城南楼', author: '张九龄', poem: '闭阁幸无事，登楼聊永日。\n云霞千里开，洲渚万形出。\n澹澹澄江漫，飞飞度鸟疾。\n邑人半舻舰，津树多枫橘。\n感别时已屡，凭眺情非一。\n远怀不我同，孤兴与谁悉。\n平生本单绪，邂逅承优秩。\n谬忝为邦寄，多慙理人术。\n驽铅虽自勉，仓廪素非实。\n陈力倘无効，谢病从芝术。' },
  { title: '岁初巡属县登高安南楼言怀', author: '张九龄', poem: '山城本孤峻，凭高结层轩。\n江气偏宜早，林英粲已繁。\n余滋含宿霁，众妍在朝暾。\n拂衣释簿领，伏槛遗纷喧。\n深俯东溪澳，远延南山樊。\n归云纳前岭，去鸟投遥村。\n目尽有余意，心恻不可谖。\n朅来彭蠡泽，载经敷浅原。\n春及但生思，时哉无与言。\n不才叨过举，唯力酬明恩。\n美化犹寂蔑，迅节徒飞奔。\n虽无成立効，庶以去思论。\n行复徇孤迹，亦云吾道存。' },
  { title: '秋晚登楼望南江入始兴郡路', author: '张九龄', poem: '潦收沙衍出，霜降天宇晶。\n伏槛一长眺，津途多远情。\n思来江山外，望尽烟云生。\n滔滔不自辨，役役且何成。\n我来飒衰鬓，孰云飘华缨。\n枥马苦踡跼，笼禽念遐征。\n岁阴向晼晚，日夕空屏营。\n物生贵得性，身累由近名。\n内顾觉今是，追叹何时平。' },
  { title: '登古阳云台', author: '张九龄', poem: '庭树日衰飒，风霜未云已。\n驾言遣忧思，乘兴求相似。\n楚国兹故都，兰台有余址。\n传闻襄王世，仍立巫山祀。\n方此全盛时，岂无婵娟子。\n色荒神女至，魂荡宫观启。\n蔓草今如积，朝云为谁起。' },
  { title: '与生公寻幽居处', author: '张九龄', poem: '同方久厌俗，相与事遐讨。\n及此云山去，窅然岩径好。\n疑入武陵源，如逢汉阴老。\n清谐欣有得，幽闲歘盈抱。\n我本玉阶侍，偶访金仙道。\n兹焉求卜筑，所过皆神造。\n岁晚林始敷，日晏崖方杲。\n不种缘岭竹，岂植临潭草。\n即途可淹留，随日成黼藻。\n期为静者说，曾是终焉保。\n今为简书畏，秖令归思浩。' },
  { title: '与生公游石窟山', author: '张九龄', poem: '探秘孰云远，忘怀复尔同。\n日寻高深意，宛是神仙中。\n跻险搆灵室，诡制非人功。\n潜洞黝无底，殊庭忽似梦。\n岂如武安凿，自若茅山通。\n造物良有寄，嬉游迺惬衷。\n犹希咽玉液，从此升云空。\n咄咄共携手，泠然且驭风。' },
  { title: '郡舍南有园畦杂树聊以永日', author: '张九龄', poem: '为郡久无补，越乡空复深。\n苟能秉素节，安用叨华簪。\n却步园畦里，追吾野逸心。\n形骸拘俗吏，光景赖闲林。\n内讼诚知止，外言犹匪忱。\n成蹊谢李径，衞足感葵阴。\n荣达岂不伟，孤生非所任。\n江城何寂历，秋树亦萧森。\n下有北流水，上有南飞禽。\n我愿从归翼，无然坐自沈。' },
  { title: '临泛东湖', author: '张九龄', poem: '郡庭日休暇，湖曲邀胜践。\n乐职在中和，灵心挹上善。\n乘流坐清旷，举目眺悠缅。\n林与西山重，云因北风卷。\n晶明画不逮，阴影镜无辨。\n晚秀复芬敷，秋光更遥衍。\n万族纷可佳，一游岂能展。\n羇孤忝邦牧，顾己非时选。\n梁公世不容，长孺心亦褊。\n永念出笼絷，常思退疲蹇。\n岁徂风露严，日恐兰苕剪。\n佳辰不可得，良会何其鲜。\n罢兴还江城，闭关聊自遣。' },
  { title: '始兴南山下有林泉尝卜居焉荆州卧病有怀此地', author: '张九龄', poem: '出处各有在，何者为陆沈。\n幸无迫贱事，聊可祛迷襟。\n世路少夷坦，孟门未岖嵚。\n多慙入火术，常惕履冰心。\n一跌不自保，万全焉可寻。\n行行念归路，眇眇惜光阴。\n浮生如过隙，先达已吾箴。\n敢忘丘山施，亦云年病侵。\n力衰在所养，时谢良不任。\n但忆旧栖息，愿言遂窥临。\n云间日孤秀，山下面清深。\n萝茑自为幄，风泉何必琴。\n归此老吾老，还当日千金。' },
  { title: '晨坐斋中偶而成咏', author: '张九龄', poem: '寒露洁秋空，遥山纷在瞩。\n孤顶乍修耸，微云复相续。\n人兹赏地偏，鸟亦爱林旭。\n结念凭幽远，抚躬曷羁束。\n仰霄谢逸翰，临路嗟疲足。\n徂岁方暌携，归心亟踯躅。\n休闲倘有素，岂负南山曲。' },
  { title: '咏史', author: '张九龄', poem: '大德始无颇，中智是所是。\n居然已不一，况乃务相诡。\n小道致泥难，巧言因萋毁。\n穰侯或见迟，苏生得阴揣。\n轻既长沙傅，重亦边郡徙。\n势倾不幸然，迹在胡宁尔。\n沧溟所为大，江汉日来委。\n沣水虽复清，鱼鼈岂游此。\n贤哉有小白，雠中有管氏。\n若人不世生，悠悠多如彼。' },
  { title: '龙门旬宴得月字韵', author: '张九龄', poem: '恩华逐芳岁，形胜兼韶月。\n中席傍鱼潭，前山倚龙阙。\n花迎妙妓至，鸟避仙舟发。\n宴赏良在兹，再来情不歇。' },
  { title: '骊山下逍遥公旧居游集', author: '张九龄', poem: '君子体清尚，归处有兼资。\n虽然经济日，无忘幽栖时。\n卜居旧何所，休澣尝来兹。\n岑寂罕人至，幽深获我思。\n松涧聆遗风，兰林览余滋。\n往事诚已矣，道存犹可追。\n遗子后黄金，作歌先紫芝。\n明德有自来，奕世皆秉彝。\n岂与磻溪老，崛起周太师。\n我心希硕人，逮此问元龟。\n怊怅既怀远，沈吟亦省私。\n已云宠禄过，况在华发衰。\n轩盖有迷复，丘壑无磷缁。\n感物重所怀，何但止足斯。' },
  { title: '杂诗五首 一', author: '张九龄', poem: '孤桐亦胡为，百尺傍无枝。\n疎阴不自覆，修干欲何施。\n高冈地复迥，弱植风屡吹。\n凡鸟已相噪，凤皇安得知。' },
  { title: '杂诗五首 二', author: '张九龄', poem: '萝茑必有托，风霜不能落。\n酷在兰将蕙，甘从葵与藿。\n运命虽为宰，寒暑自回薄。\n悠悠天地间，委顺无不乐。' },
  { title: '杂诗五首 三', author: '张九龄', poem: '良辰不可遇，心赏更蹉跎。\n终日块然坐，有时劳者歌。\n庭前揽芳蕙，江上托微波。\n路远无能达，忧情空复多。' },
  { title: '杂诗五首 四', author: '张九龄', poem: '湘水吊灵妃，斑竹为情绪。\n汉水访游女，解佩欲谁与。\n同心不可见，异路空延伫。\n浦上青枫林，津傍白沙渚。\n行吟至落日，坐望秖愁予。\n神物亦岂孤，佳期竟何许。' },
  { title: '杂诗五首 五', author: '张九龄', poem: '木直几自寇，石坚亦他攻。\n何言为用薄，而与火膏同。\n物类有固然，谁能取径通。\n纤纤良田草，靡靡唯从风。\n日夜沐甘泽，春秋等芳丛。\n生性苟不夭，香臭谁为中。\n道家贵至柔，儒生何固穷。\n终始行一意，无乃过愚公。' },
  { title: '感遇十二首 一', author: '张九龄', poem: '兰叶春葳蕤，桂华秋皎洁。\n欣欣此生意，自尔为佳节。\n谁知林栖者，闻风坐相悦。\n草木有本心，何求美人折。' },
  { title: '感遇十二首 二', author: '张九龄', poem: '幽林归独卧，滞虑洗孤清。\n持此谢高鸟，因之传远情。\n日夕怀空意，人谁感至精。\n飞沈理自隔，何所慰吾诚。' },
  { title: '感遇十二首 三', author: '张九龄', poem: '鱼游乐深池，鸟栖欲高枝。\n嗟尔蜉蝣羽，薨薨亦何为。\n有生岂不化，所感奚若斯。\n神理日微灭，吾心安得知。\n浩叹杨朱子，徒然泣路岐。' },
  { title: '感遇十二首 四', author: '张九龄', poem: '孤鸿海上来，池潢不敢顾。\n侧见双翠鸟，巢在三珠树。\n矫矫珍木巅，得无金丸惧。\n美服患人指，高明逼神恶。\n今我游冥冥，弋者何所慕。' },
  { title: '感遇十二首 五', author: '张九龄', poem: '吴越数千里，梦寐今夕见。\n形骸非我亲，衾枕即乡县。\n化蝶犹不识，川鱼安可羡。\n海上有仙山，归期觉神变。' },
  { title: '感遇十二首 六', author: '张九龄', poem: '西日下山隐，北风乘夕流。\n燕雀感昏旦，檐楹呼匹俦。\n鸿鹄虽自远，哀音非所求。\n贵人弃疵贱，下士尝殷忧。\n众情累外物，恕己忘内修。\n感叹长如此，使我心悠悠。' },
  { title: '感遇十二首 七', author: '张九龄', poem: '江南有丹橘，经冬犹绿林。\n岂伊地气暖，自有岁寒心。\n可以荐嘉客，奈何阻重深。\n运命唯所遇，循环不可寻。\n徒言树桃李，此木岂无阴。' },
  { title: '感遇十二首 八', author: '张九龄', poem: '永日徒离忧，临风怀蹇修。\n美人何处所？孤客空悠悠。\n青鸟跂不至，朱鳖谁云浮。\n夜分起踯躅，时逝曷淹留。' },
  { title: '感遇十二首 九', author: '张九龄', poem: '抱影吟中夜，谁闻此叹息。\n美人适异方，庭树含幽色。\n白云愁不见，沧海飞无翼。\n凤皇一朝来，竹花斯可食。' },
  { title: '感遇十二首 十', author: '张九龄', poem: '汉上有游女，求思安可得。\n袖中一札书，欲寄双飞翼。\n冥冥愁不见，耿耿徒缄忆。\n紫兰秀空蹊，皓露夺幽色。\n馨香岁欲晚，感叹情何极。\n白云在南山，日暮长太息。' },
  { title: '感遇十二首 十一', author: '张九龄', poem: '我有异乡忆，宛在云溶溶。\n凭此目不觏，要之心所钟。\n但欲附高鸟，安敢攀飞龙。\n至精无感遇，悲惋填心胸。\n归来扣寂寞，人愿天岂从。' },
  { title: '感遇十二首 十二', author: '张九龄', poem: '闭门迹群化，凭林结所思。\n啸叹此寒木，畴昔乃芳蕤。\n朝阳凤安在，日暮蝉独悲。\n浩思极中夜，深嗟欲待谁。\n所怀诚已矣，既往不可追。\n鼎食非吾事，云仙尝我期。\n胡越方杳杳，车马何迟迟。\n天壤一何异，幽嘿卧帘帷。' },
  { title: '江上遇疾风', author: '张九龄', poem: '疾风江上起，鼓怒扬烟埃。\n白昼晦如夕，洪涛声若雷。\n投林鸟铩羽，入浦鱼曝鳃。\n瓦飞屋且发，帆快樯已摧。\n不知天地气，何为此喧豗。' },
  { title: '南阳道中作', author: '张九龄', poem: '登郢属岁阴，及宛懵所适。\n复闻东汉主，遗此南都迹。\n佳气蔼厥初，霸图纷在昔。\n兹邦称贵近，与世尝薰赫。\n遭遇感风云，变衰空草泽。\n不识邓公树，犹传阴后石。\n驱马历𬮱阇，荆榛翳阡陌。\n事去物无象，感来心不怿。\n怀古对穷秋，兴言伤远客。\n眇默遵岐路，辛勤弊行役。\n云雁号相呼，林麕走自索。\n顾忆徇书剑，未尝安枕席。\n岂暇墨突黔，空持辽豕白。\n迷复期非远，归欤赏农隙。' },
  { title: '湘中作', author: '张九龄', poem: '湘流绕南岳，绝目转青青。\n怀禄未能已，瞻途屡所经。\n烟屿宜春望，林猿莫夜听。\n永路日多绪，孤舟天复冥。\n浮没从此去，嗟嗟劳我形。' },
  { title: '彭蠡湖上', author: '张九龄', poem: '沿涉经大湖，湖流多行泆。\n决晨趋北渚，逗浦已西日。\n所适虽淹旷，中流且闲逸。\n瑰诡良复多，感见乃非一。\n庐山直阳浒，孤石当阴术。\n一水云际飞，数峰湖心出。\n象类何交乣，形言岂深悉。\n且知皆自然，高下无相恤。' },
  { title: '入庐山仰望瀑布水', author: '张九龄', poem: '绝顶有悬泉，喧喧出烟杪。\n不知几时岁，但见无昏晓。\n闪闪青崖落，鲜鲜白日皎。\n洒流湿行云，溅沫惊飞鸟。\n雷吼何喷薄，箭驰入窈窕。\n昔闻山下蒙，今乃林峦表。\n物情有诡激，坤元曷纷矫。\n默然置此去，变化谁能了。' },
  { title: '出为豫章郡途次庐山东岩下', author: '张九龄', poem: '兹山镇何所，乃在澄湖阴。\n下有蛟螭伏，上与虹蜺寻。\n灵仙未始旷，窟宅何其深。\n双阙出云峙，三宫入烟沈。\n攀崖犹昔境，种杏非旧林。\n想像终古迹，惆怅独往心。\n纷吾婴世网，数载忝朝簪。\n孤根自靡托，量力况不任。\n多谢周身防，常恐横议侵。\n岂匪鹓鸿列，惕如泉壑临。\n迨兹刺江郡，来此涤尘襟。\n有趣逢樵客，忘怀狎野禽。\n栖闲义未果，用拙欢在今。\n愿言答休命，归事丘中琴。' },
  { title: '巡属县道中作', author: '张九龄', poem: '春令夙所奉，驾言遵此行。\n途中却郡掾，林下招村氓。\n至邑无纷剧，来人但欢迎。\n岂伊念邦政，尔实在时清。\n短才滥符竹，弱岁起柴荆。\n再入江村道，永怀山薮情。\n矧逢阳节献，默听时禽鸣。\n迹与素心别，感从幽思盈。\n流芳日不待，夙志蹇无成。\n知命且何欲，所图唯退耕。\n华簪极身泰，衰鬓慙木荣。\n苟得不可遂，吾其谢世婴。' },
  { title: '夏日奉使南海在道中作', author: '张九龄', poem: '缅然万里露，赫曦三伏时。\n飞走逃深林，流烁恐生疵。\n行李岂无苦，而我方自怡。\n肃事诚在公，拜庆遂及私。\n展力慙浅效，衔恩感深慈。\n且欲汤火蹈，况无鬼神欺。\n朝发高山阿，夕济长江湄。\n秋瘴宁我毒，夏水胡不夷。\n信知道存者，但问心所之。\n吕梁有出入，乃觉非虚词。' },
  { title: '巡按自漓水南行', author: '张九龄', poem: '理棹虽云远，饮冰宁有惜。\n况乃佳山川，怡然傲潭石。\n奇峰岌前转，茂树隈中积。\n猿鸟声自呼，风泉气相激。\n目因诡容逆，心与清晖涤。\n纷吾谬执简，行郡将移檄。\n即事聊独欢，素怀岂兼适。\n悠悠咏靡盬，庶以穷日夕。' },
  { title: '使还都湘东作', author: '张九龄', poem: '仓庚昨归候，阳鸟今去时。\n感物遽如此，劳生安可思。\n养真无上格，图进岂前期。\n清节往来苦，壮容离别衰。\n盛明非不遇，弱操自云私。\n孤楫清川泊，征衣寒露滋。\n风朝津树落，日夕岭猿悲。\n牵役而无悔，坐愁秪自怡。\n当须报恩已，终尔谢尘缁。' },
  { title: '冬中至玉泉山寺属穷阴冰闭崖谷无色及仲春行县复往焉故有此作', author: '张九龄', poem: '灵境信幽绝，芳时重暄妍。\n再来及兹胜，一遇非无缘。\n万木柔可结，千花敷欲然。\n松间鸣好鸟，竹下流清泉。\n石壁开精舍，金光照法筵。\n真空本自寂，假有聊相宣。\n复此灰心者，仍追巢顶禅。\n简书虽有畏，身世亦相捐。' },
  { title: '郢城西北有大古冢数十观其封域多是楚时诸王而年代久远不复可识唯直西有樊妃冢因后人为植松柏故行路尽知之', author: '张九龄', poem: '苹藻生南涧，蕙兰秀中林。\n嘉名有所在，芳气无幽深。\n楚子初逞志，樊妃尝献箴。\n能令更择士，非直罢从禽。\n旧国皆湮灭，先王亦莫寻。\n唯传贤媛陇，犹结后人心。\n牢落山川意，萧疎松柏阴。\n破墙时直上，荒径或斜侵。\n惠问终不绝，风流独至今。\n千春思窈窕，黄鸟复哀音。' },
  { title: '荆州作二首 一', author: '张九龄', poem: '先达志其大，求意不约文。\n士伸在知己，已况仕于君。\n微诚夙所尚，细故不足云。\n时来忽易失，事往良难分。\n顾念凡近姿，焉欲殊常勋。\n亦以行则是，岂必素有闻。\n千虑且犹失，万绪何其纷。\n进士苟非党，免相安得群。\n众口金可铄，孤心丝共棼。\n意忠仗朋信，语勇同败军。\n古剑徒有气，幽兰秪自薰。\n高秩向所忝，于义如浮云。' },
  { title: '荆州作二首 二', author: '张九龄', poem: '千载一遭遇，往贤所至难。\n问余奚为者，无阶忽上抟。\n明圣不世出，翼亮非苟安。\n崇高自有配，孤陋何足干。\n遇恩一时来，窃位三岁寒。\n谁谓诚不尽，知穷力亦殚。\n虽至负乘寇，初无挟术钻。\n浩荡出江湖，翻覆如波澜。\n心伤不材树，自念独飞翰。\n徇义在匹夫，报恩犹一餐。\n况乃山海泽，效无毫发端。\n内讼已慙沮，积毁今摧残。\n胡为复惕息，伤鸟畏虚弹。' },
  { title: '在郡秋怀二首 一', author: '张九龄', poem: '秋风入前林，萧瑟鸣高枝。\n寂寞游子思，寤叹何人知。\n宦成名不立，志存岁已驰。\n五十而无闻，古人深所疵。\n平生去外饰，直道如不羁。\n未得操割效，忽复寒暑移。\n物情自古然，身退毁亦随。\n悠悠沧江渚，望望白云涯。\n露下霜且降，泽中草离披。\n兰艾若不分，安用馨香为。' },
  { title: '在郡秋怀二首 二', author: '张九龄', poem: '庭芜生白露，岁候感遐心。\n策蹇慙远途，巢枝思故林。\n小人恐致寇，终日如临深。\n鱼鸟好自逸，池笼安所钦。\n挂冠东都门，采蕨南山岑。\n议道诚愧昔，览分还惬今。\n怃然忧成老，空尔白头吟。' },
  { title: '忝官二十年尽在内职及为郡尝积恋因赋诗焉', author: '张九龄', poem: '江流去朝宗，昼夜兹不舍。\n仲尼在川上，子牟存阙下。\n圣达有由然，孰是无心者。\n一郡苟能化，百城岂云寡。\n爱礼谁为羊，恋主吾犹马。\n感初时不载，思奋翼无假。\n闲宇常自闭，沈心何用写。\n揽衣步前庭，登陴临旷野。\n白水生迢递，清风寄潇洒。\n愿言采芳泽，终朝不盈把。' },
  { title: '二弟宰邑南海见群鴈南飞因成咏以寄', author: '张九龄', poem: '鸿雁自北来，嗷嗷度烟景。\n常怀稻粱惠，岂惮江山永。\n小大每相从，羽毛当自整。\n双凫侣晨泛，独鹤参宵警。\n为我更南飞，因书至梅岭。' },
  { title: '将发还乡示诸弟', author: '张九龄', poem: '岁阳亦颓止，林意日萧摵。\n云胡当此时，缅迈复为客。\n至爱孰能舍，名义来相迫。\n负德良不赀，输诚靡所惜。\n一木逢厦构，纤尘愿山益。\n无力主君恩，宁利客卿璧。\n去去荣归养，怃然叹行役。' },
  { title: '叙怀二首 一', author: '张九龄', poem: '弱岁读群史，抗迹追古人。\n被褐有怀玉，佩印从负薪。\n志合岂兄弟，道行无贱贫。\n孤根亦何赖，感激此为邻。' },
  { title: '叙怀二首 二', author: '张九龄', poem: '晚节从卑秩，岐路良非一。\n既闻持两端，复见挟三术。\n木瓜诚有报，玉楮论无实。\n已矣直躬者，平生壮图失。\n去去勿重陈，归来茹芝术。' },
  { title: '题画山水障', author: '张九龄', poem: '心累犹不尽，果为物外牵。\n偶因耳目好，复假丹青妍。\n尝抱野间意，而迫区中缘。\n尘事固已矣，秉意终不迁。\n良工适我愿，妙墨挥岩泉。\n变化合群有，高深侔自然。\n置陈北堂上，倣像南山前。\n静无户庭出，行已兹地偏。\n萱草忧可树，合欢忿益蠲。\n所因本微物，况乃凭幽筌。\n言象会自泯，意色聊自宣。\n对玩有佳趣，使我心渺绵。' },
  { title: '奉和圣制瑞雪篇', author: '张九龄', poem: '万年春，三朝日，上御明台旅庭实。\n初瑞雪兮霏微，俄同云兮蒙密。\n此时骚切阴风生，先过金殿有余清。\n信宿婵娟飞雪度，能使玉人俱掩嫮。\n皓皓楼前月初白，纷纷陌上尘皆素。\n昨讶骄阳积数旬，始知和气待迎新。\n匪惟在人利，曾是扶天意。\n天意岂云遥，雪下不崇朝。\n皇情玩无斁，雪委方盈尺。\n草树纷早荣，京坻宛先积。\n君恩诚谓何，岁稔复人和。\n预数斯箱庆，应如此雪多。\n朝冕旒兮载悦，想籉笠兮农节。\n倚瑶琴兮或歌，续薰风兮瑞雪。\n福浸昌，应尤盛，瑞雪年年常感圣。\n愿以柏梁作，长为柳花咏。' },
  { title: '奉和圣制温泉歌', author: '张九龄', poem: '有时神物待圣人，去后汤还冷，来时树亦春。\n今兹十月自东归，羽斾逶迤上翠微。\n温谷葱葱佳气色，离宫奕奕叶光辉。\n临渭川，近天邑。\n浴日温泉复在兹，群仙洞府那相及。\n吾君利物心，玄泽浸苍黔。\n渐渍神汤无疾苦，薰歌一曲感人深。' },
  { title: '南郊太尉酌献武舞作凯安之乐', author: '张九龄', poem: '馨香惟后德，明命光天保。\n肃祀崇圣灵，陈信表黄道。\n玉戚初蹈厉，金匏既静好。\n介福何穰穰，精诚格穹昊。' },
  { title: '奉和圣制经孔子旧宅', author: '张九龄', poem: '孔门太山下，不见登封时。\n徒有先王法，今为明主思。\n恩加万乘幸，礼致一牢祠。\n旧宅千年外，光华空在兹。' },
  { title: '奉和圣制次琼岳韵', author: '张九龄', poem: '山祗亦望幸，云雨见灵心。\n岳馆逢朝霁，关门解宿阴。\n咸京天上近，清渭日边临。\n我武因冬狩，何言是即禽。' },
  { title: '奉和圣制送李尚书入蜀', author: '张九龄', poem: '眷言感忠义，何有间山川。\n徇节今如此，离情空复然。\n皇心在勤恤，德泽委昭宣。\n周月成功后，明年或劳还。' },
  { title: '奉和圣制初出洛城', author: '张九龄', poem: '东土淹龙驾，西人望翠华。\n山川祗询物，宫观岂为家。\n十月回星斗，千官捧日车。\n洛阳无怨思，巡幸更非赊。' },
  { title: '奉和圣制途次陕州作', author: '张九龄', poem: '驰道当河陕，陈诗问国风。\n川原三晋别，襟带两京同。\n后殿函关尽，前旌阙塞通。\n行看洛阳陌，光景丽天中。' },
  { title: '勅赐宁王池宴', author: '张九龄', poem: '贤王有池馆，明主赐春游。\n淑气林间发，恩光水上浮。\n徒慙和鼎地，终谢巨川舟。\n皇泽空如此，轻生莫可酬。' },
  { title: '天津桥东旬宴得歌字韵', author: '张九龄', poem: '清洛象天河，东流形胜多。\n朝来逢宴喜，春尽却妍和。\n泉鲔欢时跃，林莺醉里歌。' },
  { title: '上阳水窗旬宴得移字韵', author: '张九龄', poem: '河汉非应到，汀洲忽在斯。\n仍逢帝乐下，如逐海槎窥。\n春赏时将换，皇恩岁不移。\n今朝游宴所，莫比天泉池。' },
  { title: '折杨柳', author: '张九龄', poem: '纤纤折杨柳，持此寄情人。\n一枝何足贵，怜是故园春。\n迟景那能久，芳菲不及新。\n更愁征戍客，容鬓老边尘。' },
  { title: '剪彩', author: '张九龄', poem: '姹女矜容色，为花不让春。\n既争芳意早，谁待物华真。\n叶作参差发，枝从点缀新。\n自然无限态，长在艳阳晨。' },
  { title: '和崔黄门寓直夜听蝉之作', author: '张九龄', poem: '蝉嘶玉树枝，向夕惠风吹。\n幸入连宵听，应缘饮露知。\n思深秋欲近，声静夜相宜。\n不是黄金饰，清香徒尔为。' },
  { title: '和姚令公从幸温汤喜雪', author: '张九龄', poem: '万乘飞黄马，千金狐白裘。\n正逢银霰积，如向玉京游。\n瑞色铺驰道，花文拂彩旒。\n还闻吉甫颂，不共郢歌俦。' },
  { title: '立春日晨起对积雪', author: '张九龄', poem: '忽对林亭雪，瑶华处处开。\n今年迎气始，昨夜伴春回。\n玉润窗前竹，花繁院里梅。\n东郊斋祭所，应见五神来。' },
  { title: '三月三日申王园亭宴集', author: '张九龄', poem: '稽亭追往事，睢苑胜前闻。\n飞阁凌芳树，华池落彩云。\n藉草人留酌，衔花鸟赴群。\n向来同赏处，惟恨碧林曛。' },
  { title: '三月三日登龙山', author: '张九龄', poem: '伊川与灞津，今日祓除人。\n岂似龙山上，还同湘水滨。\n衰颜忧更老，淑景望非春。\n禊饮岂吾事，聊将偶俗尘。' },
  { title: '和王司马折梅寄京邑昆弟', author: '张九龄', poem: '离别念同嬉，芬荣欲共持。\n独攀南国树，遥寄北风时。\n林惜迎春早，花愁去日迟。\n还闻折梅处，更有棣华诗。' },
  { title: '晚霁登王六东阁', author: '张九龄', poem: '试上江楼望，初逢山雨晴。\n连空青嶂合，向晚白云生。\n彼美要殊观，萧条见远情。\n情来不可极，日暮水流清。' },
  { title: '苏侍郎紫薇庭各赋一物得芍药', author: '张九龄', poem: '仙禁生红药，微芳不自持。\n幸因清切地，还遇艳阳时。\n名见桐君箓，香闻郑国诗。\n孤根若可用，非直爱华滋。' },
  { title: '和黄门卢侍御咏竹', author: '张九龄', poem: '清切紫庭垂，葳蕤防露枝。\n色无玄月变，声有惠风吹。\n高节人相重，虚心世所知。\n凤皇佳可食，一去一来仪。' },
  { title: '和韦尚书答梓州兄南亭宴集', author: '张九龄', poem: '棠棣闻余兴，乌衣有旧游。\n门前杜城陌，池上曲江流。\n暇日尝繁会，清风咏阻修。\n始知西峙岳，同气此相求。' },
  { title: '答陈拾遗赠竹簪', author: '张九龄', poem: '与君尝此志，因物复知心。\n遗我龙钟节，非无玳瑁簪。\n幽素宜相重，雕华岂所任。\n为君安首饰，怀此代兼金。' },
  { title: '赠澧阳韦明府', author: '张九龄', poem: '君有百炼刃，堪断七重犀。\n谁开太阿匣，持割武城鸡。\n竟与尚书佩，遥应天子提。\n何时遇操宰，当使玉如泥。' },
  { title: '在洪州答綦毋学士', author: '张九龄', poem: '旬雨不愆期，由来自若时。\n尔无言郡政，吾岂欲天欺。\n常念涓尘益，惟欢草树滋。\n课成非所拟，人望在东菑。' },
  { title: '酬王六霁后书怀见示', author: '张九龄', poem: '云雨俱行罢，江天已洞开。\n炎氛霁后灭，边绪望中来。\n作骥君垂耳，为鱼我曝鳃。\n更怜湘水赋，还是洛阳才。' },
  { title: '酬王六寒朝见诒', author: '张九龄', poem: '贾生流寓日，扬子寂寥时。\n在物多相背，唯君独见思。\n渔为江上曲，雪作郢中词。\n忽枉兼金讯，长怀伐木诗。' },
  { title: '林亭咏', author: '张九龄', poem: '穿筑非求丽，幽闲欲寄情。\n偶怀因壤石，真意在蓬瀛。\n苔益山文古，池添竹气清。\n从兹果萧散，无事亦无营。' },
  { title: '晨出郡舍林下', author: '张九龄', poem: '晨兴步北林，萧散一开襟。\n复见林上月，娟娟犹未沈。\n片云自孤远，丛筿亦清深。\n无事由来贵，方知物外心。' },
  { title: '园中时蔬尽皆锄理唯秋兰数本委而不顾彼虽一物有足悲者遂赋二章 一', author: '张九龄', poem: '场藿已成岁，园葵亦向阳。\n兰时独不偶，露节渐无芳。\n旨异菁为蓄，甘非蔗有浆。\n人多利一饱，谁复惜馨香。' },
  { title: '园中时蔬尽皆锄理唯秋兰数本委而不顾彼虽一物有足悲者遂赋二章 二', author: '张九龄', poem: '幸得不锄去，孤苗守旧根。\n无心羡旨蓄，岂欲近名园。\n遇赏宁充佩，为生莫碍门。\n幽林芳意在，非是为人论。' },
  { title: '林亭寓言', author: '张九龄', poem: '林居逢岁晏，遇物使情多。\n蘅茝不时与，芬荣奈汝何。\n更怜篱下菊，无如松上萝。\n因依自有命，非是隔阳和。' },
  { title: '送使广州', author: '张九龄', poem: '家在湘源住，君今海峤行。\n经过正中道，相送倍为情。\n心逐书邮去，形随世网婴。\n因声谢远别，缘义不缘名。' },
  { title: '送姚评事入蜀各赋一物得卜肆', author: '张九龄', poem: '蜀严化已久，沈冥空所思。\n尝闻卖卜处，犹忆下帘时。\n驱传应经此，怀贤倘问之。\n归来说往事，历历偶心期。' },
  { title: '送窦校书见饯得云中辨江树', author: '张九龄', poem: '江水天连色，无涯净野氛。\n微明岸傍树，凌乱渚前云。\n举棹形徐转，登舻意渐分。\n渺茫从此去，空复惜离群。' },
  { title: '饯王司马入计同用洲字', author: '张九龄', poem: '元僚行上计，举饯出林丘。\n忽望题舆远，空思解榻游。\n别筵铺柳岸，征棹倚芦洲。\n独叹湘江水，朝宗向北流。' },
  { title: '东湖临泛饯王司马', author: '张九龄', poem: '南土秋虽半，东湖草未黄。\n聊乘风日好，来泛芰荷香。\n兰棹无劳速，菱歌不厌长。\n忽怀京洛去，难与共清光。' },
  { title: '饯济阴梁明府各探一物得荷叶', author: '张九龄', poem: '荷叶生幽渚，芳华信在兹。\n朝朝空此地，采采欲因谁。\n但恐星霜改，还将蒲稗衰。\n怀君美人别，聊以赠心期。' },
  { title: '饯陈学士还江南同用征字', author: '张九龄', poem: '荷𦰏旋江澳，衔杯饯霸陵。\n别前林鸟息，归处海烟凝。\n风土乡情接，云山客念凭。\n圣朝岩穴选，应待鹤书征。' },
  { title: '通化门外送别', author: '张九龄', poem: '屡别容华改，长愁意绪微。\n义将私爱隔，情与故人归。\n薄宦无时赏，劳生有事机。\n离魂今夕梦，先绕旧林飞。' },
  { title: '送杨道士往天台', author: '张九龄', poem: '鬼谷还成道，天台去学仙。\n行应松子化，留与世人传。\n此地烟波远，何时羽驾旋？\n当须一把袂，城郭共依然。' },
  { title: '送杨府李功曹', author: '张九龄', poem: '平生属良友，结绶望光辉。\n何知人事拙，相与宦情非。\n别路穿林尽，征帆际海归。\n居然已多意，况复两乡违。' },
  { title: '送宛句赵少府', author: '张九龄', poem: '解巾行作吏，尊酒谢离居。\n修竹含清景，华池澹碧虚。\n地将幽兴惬，人与旧游疎。\n林下纷相送，多逢长者车。' },
  { title: '送韦城李少府', author: '张九龄', poem: '送客南昌尉，离亭西候春。\n野花看欲尽，林鸟听犹新。\n别酒青门路，归轩白马津。\n相知无远近，万里尚为邻。' },
  { title: '送苏主簿赴偃师', author: '张九龄', poem: '我与文雄别，胡然邑吏归。\n贤人安下位，鸷鸟欲卑飞。\n激节轻华冕，移官徇彩衣。\n羡君行乐处，从此拜庭闱。' },
  { title: '送广州周判官', author: '张九龄', poem: '海郡雄蛮落，津亭壮越台。\n城隅百雉映，水曲万家开。\n里树桄榔出，时禽翡翠来。\n观风犹未尽，早晚使车回。' },
  { title: '郡江南上别孙侍御', author: '张九龄', poem: '云嶂天涯尽，川途海县穷。\n何言此地僻，忽与故人同。\n身负邦君弩，情纡御史骢。\n王程不我驻，离思逐秋风。' },
  { title: '道逢北使题赠京邑亲知', author: '张九龄', poem: '征骖稍靡靡，去国方迟迟。\n路遶南登岸，情摇北上旗。\n故人怜别日，旅雁逐归时。' },
  { title: '江上使风呈裴宣州耀卿', author: '张九龄', poem: '江路与天连，风帆何淼然。\n遥林浪出没，孤舫鸟联翩。\n常爱千钧重，深思万事捐。\n报恩非徇禄，还逐贾人船。' },
  { title: '溪行寄王震', author: '张九龄', poem: '山气朝来爽，溪流日向清。\n远心何处惬，闲棹此中行。\n丛桂林间待，群鸥水上迎。\n徒然适我愿，幽独为谁情。' },
  { title: '自豫章南还江上作', author: '张九龄', poem: '归去南江水，磷磷见底清。\n转逢空阔处，聊洗滞留情。\n浦树遥如待，江鸥近若迎。\n津途别有趣，况乃濯吾缨。' },
  { title: '将至岳阳有怀赵二', author: '张九龄', poem: '湘岸多深林，青冥昼结阴。\n独无谢客赏，况复贾生心。\n草色虽云发，天光或未临。\n江潭非所遇，为尔白头吟。' },
  { title: '使还湘水', author: '张九龄', poem: '归舟宛何处，正值楚江平。\n夕逗烟村宿，朝缘浦树行。\n于役已弥岁，言旋今惬情。\n乡郊尚千里，流目夏云生。' },
  { title: '初发道中寄远', author: '张九龄', poem: '日夜乡山远，秋风复此时。\n旧闻胡马思，今听楚猿悲。\n念别朝昏苦，怀归岁月迟。\n壮图空不息，常恐发如丝。' },
  { title: '自湘水南行', author: '张九龄', poem: '落日摧行舫，逶迤洲渚间。\n虽云有物役，乘此更休闲。\n暝色生前浦，清晖发近山。\n中流澹容与，唯爱鸟飞还。' },
  { title: '初入湘中有喜', author: '张九龄', poem: '征鞍穷郢路，归棹入湘流。\n望鸟唯贪疾，闻猿亦罢愁。\n两边枫作岸，数处橘为洲。\n却记从来意，翻疑梦里游。' },
  { title: '耒阳溪夜行', author: '张九龄', poem: '乘夕棹归舟，缘源路转幽。\n月明看岭树，风静听溪流。\n岚气船间入，霜华衣上浮。\n猿声虽此夜，不是别家愁。' },
  { title: '江上', author: '张九龄', poem: '长林何缭绕，远水复悠悠。\n尽日余无见，为心那不愁。\n忆将亲爱别，行为主恩酬。\n感激空如此，芳时屡已遒。' },
  { title: '自彭蠡湖初入江', author: '张九龄', poem: '江岫殊空阔，云烟处处浮。\n上来群噪鸟，中去独行舟。\n牢落谁相顾，逶迤日自愁。\n更将心问影，于役复何求。' },
  { title: '赴使泷峡', author: '张九龄', poem: '溪路日幽深，寒空入两嵚。\n霜清百丈水，风落万重林。\n夕鸟联归翼，秋猿断去心。\n别离多远思，况乃岁方阴。' },
  { title: '湖口望庐山瀑布泉', author: '张九龄', poem: '万丈洪泉落，迢迢半紫氛。\n奔飞流杂树，洒落出重云。\n日照虹蜺似，天清风雨闻。\n灵山多秀色，空水共氤氲。' },
  { title: '浈阳峡', author: '张九龄', poem: '行舟傍越岑，窈窕越溪深。\n水暗先秋冷，山晴当昼阴。\n重林间五色，对壁耸千寻。\n惜此生遐远，谁知造化心。' },
  { title: '使至广州', author: '张九龄', poem: '昔年尝不调，兹地亦邅回。\n本谓双凫少，何知驷马来。\n人非汉使橐，郡是越王台。\n去去虽殊事，山川长在哉。' },
  { title: '春江晚景', author: '张九龄', poem: '江林多秀发，云日复相鲜。\n征路那逢此，春心益渺然。\n兴来秪自得，佳气莫能传。\n薄暮津亭下，余花满客船。' },
  { title: '与王六履震广州津亭晓望', author: '张九龄', poem: '明发临前渚，寒来净远空。\n水纹天上碧，日气海边红。\n景物纷为异，人情赖此同。\n乘槎自有适，非欲破长风。' },
  { title: '初发曲江溪中', author: '张九龄', poem: '溪流清且深，松石复阴临。\n正尔可嘉处，胡为无赏心。\n我由不忍别，物亦有缘侵。\n自匪常行迈，谁能知此音。' },
  { title: '旅宿淮阳亭口号', author: '张九龄', poem: '日暮荒亭上，悠悠旅思多。\n故乡临桂水，今夜渺星河。\n暗草霜华发，空亭雁影过。\n兴来谁与晤，劳者自为歌。' },
  { title: '望月怀远', author: '张九龄', poem: '海上生明月，天涯共此时。\n情人怨遥夜，竟夕起相思。\n灭烛怜光满，披衣觉露滋。\n不堪盈手赠，还寝梦佳期。' },
  { title: '秋夕望月', author: '张九龄', poem: '清逈江城月，流光万里同。\n所思如梦里，相望在庭中。\n皎洁青苔露，萧条黄叶风。\n含情不得语，频使桂华空。' },
  { title: '咏燕', author: '张九龄', poem: '海燕何微眇，乘春亦𫏐来。\n岂知泥滓贱，秪见玉堂开。\n绣户时双入，华轩日几回。\n无心与物竞，鹰隼莫相猜。' },
  { title: '故刑部李尚书荆谷山集会', author: '张九龄', poem: '尝闻继老耼，身退道弥耽。\n结宇倚青壁，疎泉喷碧潭。\n苔石随人古，烟花寄酒酣。\n山光纷向夕，归兴杜城南。' },
  { title: '戏题春意', author: '张九龄', poem: '一作江南守，江林三四春。\n相鸣不及鸟，相乐喜关人。\n日守朱丝直，年催华发新。\n淮阳秪有卧，持此度芳辰。' },
  { title: '庭梅咏', author: '张九龄', poem: '芳意何能早，孤荣亦自危。\n更怜花蔕弱，不受岁寒移。\n朝雪那相妬，阴风已屡吹。\n馨香虽尚尔，飘荡复谁知。' },
  { title: '听筝', author: '张九龄', poem: '端居正无绪，那复发秦筝。\n纤指传新意，繁弦起怨情。\n悠扬思欲绝，掩抑态还生。\n岂是声能感，人心自不平。' },
  { title: '初秋忆金均两弟', author: '张九龄', poem: '江渚秋风至，他乡离别心。\n孤云愁自远，一叶感何深。\n忧喜尝同域，飞鸣忽异林。\n青山西北望，堪作白头吟。' },
  { title: '秋怀', author: '张九龄', poem: '感惜芳时换，谁知客思悬。\n忆随鸿向煖，愁学马思边。\n留滞机还息，纷拏网自牵。' },
  { title: '故刑部李尚书挽词三首 一', author: '张九龄', poem: '仙宗出赵北，相业起山东。\n明德尝为礼，嘉谋屡作忠。\n论经白虎殿，献赋甘泉宫。\n与善今何在？苍生望已空。' },
  { title: '故刑部李尚书挽词三首 二', author: '张九龄', poem: '宿昔三台践，荣华驷马归。\n印从青琐拜，翰入紫宸挥。\n题剑恩方重，藏舟事已非。\n龙门不可望，感激涕沾衣。' },
  { title: '故刑部李尚书挽词三首 三', author: '张九龄', poem: '永叹常山宝，沈埋京兆阡。\n同盟会五月，华表记千年。\n渺漫野中草，微茫空里烟。\n共悲人事绝，唯对杜陵田。' },
  { title: '故徐州刺史赠吏部侍郎苏公挽歌词三首 一', author: '张九龄', poem: '韦玄方继相，荀爽复齐名。\n在贵兼天爵，能贤出世卿。\n学闻金马诏，神见玉人清。\n藏壑今如此，为山遂不成。' },
  { title: '故徐州刺史赠吏部侍郎苏公挽歌词三首 二', author: '张九龄', poem: '相如只谢病，子敬忽云亡。\n岂悟瑶台雪，分雕玉树行。\n清规留草议，故事在封章。\n本谓山公启，而今殁始扬。' },
  { title: '故徐州刺史赠吏部侍郎苏公挽歌词三首 三', author: '张九龄', poem: '返葬长安陌，秋风箫鼓悲。\n奈何相送者，不是平生时。\n寒影催年急，哀歌助晚迟。\n宁知建旟罢，丹旐向京师。' },
  { title: '故荥阳君苏氏挽歌词三首 一', author: '张九龄', poem: '门绪公侯列，嫔风诗礼行。\n松萝方有寄，桃李忽无成。\n剑去双龙别，雏哀九凤鸣。\n何言峄山树，还似半心生。' },
  { title: '故荥阳君苏氏挽歌词三首 二', author: '张九龄', poem: '永叹芳魂断，行看草露滋。\n二宗荣盛日，千古别离时。\n竟罢生刍赠，空留画扇悲。' },
  { title: '故荥阳君苏氏挽歌词三首 三', author: '张九龄', poem: '缟服纷相送，玄扃翳不开。\n更悲泉火灭，徒见柳车回。\n旧室容衣奠，新茔拱树栽。\n唯应月照簟，潘岳此时哀。' },
  { title: '眉州康司马挽歌词', author: '张九龄', poem: '家受专门学，人称入室贤。\n刘桢徒有气，管辂独无年。\n谪去长沙国，魂归京兆阡。\n从兹匣中劒，埋没罢冲天。' },
  { title: '奉和圣制早发三乡山行', author: '张九龄', poem: '羽衞森森西向秦，山川历历在清晨。\n晴云稍卷寒岩树，宿雨能销御路尘。\n圣德由来合天道，灵符即此应时巡。\n遗贤一一皆羁致，犹欲高深访隐沦。' },
  { title: '奉和圣制龙池篇', author: '张九龄', poem: '天启神龙生碧泉，泉水灵源浸迤延。\n飞龙已向珠潭出，积水仍将银汉连。\n岸傍花柳看胜画，浦上楼台问是仙。\n我后元符从此得，方为万岁寿图川。' },
  { title: '奉和圣制南郊礼毕酺宴', author: '张九龄', poem: '配天昭圣业，率土庆辉光。\n春发三条路，酺开百戏场。\n流恩均庶品，纵观聚康庄。\n妙舞来平乐，新声出建章。\n分曹日抱戴，赴节凤归昌。\n幸奏承云乐，同晞湛露阳。\n气和皆有感，泽厚自无疆。\n饱德君臣醉，连歌奉柏梁。' },
  { title: '奉和圣制早渡蒲津关', author: '张九龄', poem: '魏武中流处，轩皇问道回。\n长堤春树发，高掌曙云开。\n龙负王舟渡，人占仙气来。\n河津会日月，天仗役风雷。\n东顾重关尽，西驰万国陪。\n还闻股肱郡，元首咏康哉。' },
  { title: '奉和圣制同二相南出雀鼠谷', author: '张九龄', poem: '设险诸侯地，承平圣主巡。\n东君朝二月，南斾拥三辰。\n寒出重关尽，年随行漏新。\n瑞云丛捧日，芳树曲迎春。\n舞咏先驰道，恩华及从臣。\n汾川花鸟意，并奉属车尘。' },
  { title: '奉和圣制经河上公庙', author: '张九龄', poem: '昔者河边叟，谁知隐与仙。\n姓名终不识，章句此空传。\n迹为坐忘晦，言犹强着诠。\n精灵竟何所，祠宇独依然。\n道在纡宸睠，风行动睿篇。\n从兹化天下，清净复何先。' },
  { title: '奉和圣制送尚书燕国公赴朔方', author: '张九龄', poem: '宗臣事有征，庙筭在休兵。\n天与三台座，人当万里城。\n朔南方偃革，河右暂扬旌。\n宠锡从仙禁，光华出汉京。\n山川勤远畧，原隰轸皇情。\n为奏薰琴唱，仍题宝劒名。\n闻风六郡伏，计日五戎平。\n山甫归应疾，留侯功复成。\n歌钟旋可望，袵席岂难行。\n四牡何时入？吾君忆履声。' },
  { title: '奉和圣制途经华山', author: '张九龄', poem: '万乘华山下，千岩云汉中。\n灵居虽窅密，睿览忽玄同。\n日月临高掌，神仙仰大风。\n攒峰势岌岌，翊辇气雄雄。\n揆物知幽赞，铭勋表圣衷。\n会应陪玉检，来此告成功。' },
  { title: '奉和圣制早登太行山率尔言志', author: '张九龄', poem: '孟月摄提贞，乘时我后征。\n晨严九折度，暮戒六军行。\n日御驰中道，风师卷太清。\n戈鋋林表出，组练雪间明。\n动植希皇豫，高深奉睿情。\n陪游七圣列，望幸百神迎。\n气色烟犹喜，恩光草尚荣。\n之罘称万岁，今此复同声。' },
  { title: '奉和圣制登封礼毕洛城酺宴', author: '张九龄', poem: '大君毕能事，端扆乐成功。\n运与千龄合，欢将万国同。\n汉酺歌圣酒，韶乐舞薰风。\n河洛荣光遍，云烟喜气通。\n春华顿觉早，天泽倍知崇。\n草木皆沾被，犹言不在躬。' },
  { title: '恩赐乐游园宴应制', author: '张九龄', poem: '宝筵延厚命，供帐序群公。\n形胜宜春接，威仪建礼同。\n晞阳人似露，解愠物从风。\n朝庆千龄始，年华二月中。\n辉光遍草木，和气发丝桐。\n岁岁无为化，宁知乐九功。' },
  { title: '奉和圣制过王濬墓', author: '张九龄', poem: '汉王思巨鹿，晋将在弘农。\n入蜀举长筭，平吴成大功。\n与浑虽不协，归皓实为雄。\n孤绩沦千载，流名感圣衷。\n万乘度荒陇，一顾凛生风。\n古节犹不弃，今人争效忠。' },
  { title: '奉和吏部崔尚书雨后大明朝堂望南山', author: '张九龄', poem: '迢递终南顶，朝朝阊阖前。\n朅来青绮外，高在翠微先。\n双凤褰为阙，群龙俨若仙。\n还知到玄圃，更是谒甘泉。\n夜雨尘初灭，秋空月正悬。\n诡容纷入望，霁色宛成妍。\n东极华阴践，西弥嶓冢连。\n奔峰出岭外，瀑水落云边。\n汉帝宫将苑，商君陌与阡。\n林华铺近甸，烟霭遶晴川。\n既庶仁斯及，分忧政已宣。\n山公启事罢，吉甫颂声传。\n济济金门步，洋洋玉树篇。\n徒歌虽有属，清越岂同年。' },
  { title: '和崔尚书喜雨', author: '张九龄', poem: '积阳虽有晦，经月未为灾。\n上念人天重，先祈云汉回。\n仁心及草木，号令起风雷。\n照烂阴霞止，交纷瑞雨来。\n三辰破黍稷，四达屏氛埃。\n池溜因添满，林芳为洒开。\n听中声滴沥，望处影徘徊。\n惠泽成丰岁，昌言发上才。\n无论验石鼓，不是御云台。\n直颂皇恩浃，崇朝遍九垓。' },
  { title: '和许给事中直夜简诸公', author: '张九龄', poem: '未央钟漏晚，仙宇蔼沈沈。\n武衞千庐合，严扃万户深。\n左掖知天近，南窗见月临。\n树摇金掌露，庭徙玉楼阴。\n他日闻更直，中宵属所钦。\n声华大国宝，夙夜近臣心。\n逸兴乘高阁，雄飞在禁林。\n宁思窃抃者，情发为知音。' },
  { title: '和苏侍郎小园夕霁寄诸弟', author: '张九龄', poem: '清风阊阖至，轩盖承明归。\n云月爱秋景，林堂开夜扉。\n何言兼济日，尚与宴私违。\n兴逐蒹葭变，文因棠棣飞。\n人伦用忠孝，帝德已光辉。\n赠弟今为贵，方知陆氏微。' },
  { title: '酬宋使君见赠之作', author: '张九龄', poem: '时来不自意，宿昔谬枢衡。\n翊圣负明主，妨贤媿友生。\n罢归犹右职，待罪尚南荆。\n政有留棠旧，风因继组成。\n高轩问疾苦，烝庶荷仁明。\n衰废时所薄，秪言僚故情。' },
  { title: '酬宋使君见诒', author: '张九龄', poem: '陟邻初禀训，献策幸逢时。\n朝列且云忝，君恩复若兹。\n庭闱际海曲，轺传荷天慈。\n顾己欢乌鸟，闻君泣素丝。\n才明应主召，福善岂神欺。\n但愿白心在，终然湼不淄。' },
  { title: '酬通事舍人寓直见示篇中兼起居陆舍人景献', author: '张九龄', poem: '轩掖殊清秘，才华固在斯。\n兴因膏泽洒，情与惠风吹。\n所美应人誉，何私亦我仪。\n同声感乔木，比翼谢长离。\n价以陆生减，贤慙鲍叔知。\n薄游尝独媿，芳讯乃兼施。\n此夜金闺籍，伊人琼树枝。\n飞鸣复何远，相顾幸媞媞。' },
  { title: '与袁补阙寻蔡拾遗会此公出行后蔡有五韵诗见赠以此篇答焉', author: '张九龄', poem: '辙迹陈家巷，诗书孟子邻。\n偶来乘兴者，不值草玄人。\n契是忘年合，情非累日申。\n闻君还薄暮，见眷及兹辰。' },
  { title: '酬赵二侍御使西军赠两省旧僚之作', author: '张九龄', poem: '石室先鸣者，金门待制同。\n操刀尝愿割，持斧竟称雄。\n应敌兵初起，缘边虏欲空。\n使车经陇月，征斾绕河风。\n忽枉兼金讯，非徒秣马功。\n气清蒲海曲，声满柏台中。\n顾己尘华省，欣君震远戎。\n明时独匪报，尝欲退微躬。' },
  { title: '武司功初有幽庭春暄见贻夏首获见以诗报焉', author: '张九龄', poem: '芳月尽离居，幽怀重起予。\n虽言春事晚，尚想物华初。\n迟日皦方照，高斋澹复虚。\n笋成林向密，花落树应疎。\n赠鲤情无间，求莺思有余。\n暄妍不相待，含叹欲焉如。' },
  { title: '酬王履震游园林见贻', author: '张九龄', poem: '宅生惟海县，素业守郊园。\n中览霸王说，上徼明主恩。\n一行罢兰径，数载历金门。\n既负潘生拙，俄从周任言。\n逶迤恋轩陛，萧散反丘樊。\n旧迳稀人迹，前池耗水痕。\n并看芳树老，唯觉敝庐存。\n自我栖幽谷，逢君翳覆盆。\n孟轲应有命，贾谊得无冤。\n江上行伤远，林间偶避喧。\n地偏人事绝，时霁鸟声繁。\n独善心俱闭，穷居道共尊。\n乐因南涧藻，忧岂北堂萱。\n幽意加投漆，新诗重赠轩。\n平生徇知己，穷达与君论。' },
  { title: '饯王尚书出边', author: '张九龄', poem: '汉相推人杰，殷宗伐鬼方。\n还闻出将重，坐见即戎良。\n上策应为豫，中权且用光。\n令申兵气倍，威憺虏魂亡。\n树比公孙大，城如道济长。\n夏云登陇首，秋露泫辽阳。\n武德舒宸睠，文思饯乐章。\n感恩身既许，激节胆犹尝。\n祖帐倾朝列，军麾驻道傍。\n诗人何所咏，尚父欲鹰扬。' },
  { title: '送赵都护赴安西', author: '张九龄', poem: '将相有更践，简心良独难。\n远图尝画地，超拜乃登坛。\n戎即昆山序，车同渤海单。\n义无中国费，情必远人安。\n他日文兼武，而今栗且宽。\n自然来月窟，何用刺楼兰。\n南至三冬晚，西驰万里寒。\n封侯自有处，征马去啴啴。' },
  { title: '奉使自蓝田玉山南行', author: '张九龄', poem: '征骖入云壑，始忆步金门。\n通籍微躯幸，归途明主恩。\n匪唯徇行役，兼得慰晨昏。\n是节暑云炽，纷吾心所尊。\n海县且悠缅，山邮日骏奔。\n徒知恶嚣事，未暇息阴论。\n峣武经陈迹，衡湘指故园。\n水闻南涧险，烟望北林繁。\n远霭千岩合，幽声百籁喧。\n阴泉夏犹冻，阳景昼方暾。\n懿此高深极，徒令梦想存。\n盛明期有报，长往复奚言。' },
  { title: '贺给事尝诣蔡起居郊馆有诗因命同作', author: '张九龄', poem: '记言闻直史，筑室面层阿。\n岂不承明入，终云幽意多。\n沈冥高士致，休澣故人过。\n前岭游氛灭，中林芳气和。\n兹辰阻佳趣，望美独如何。' },
  { title: '南山下旧居闲放', author: '张九龄', poem: '秪役已云久，乘闲返服初。\n块然屏尘事，幽独坐林闾。\n清旷前山远，纷喧此地疎。\n乔木凌青霭，修篁媚绿渠。\n耳和绣翼鸟，目畅锦鳞鱼。\n寂寞心还间，飘飖体自虚。\n兴来命旨酒，临罢阅仙书。\n但乐多幽意，宁知有毁誉。\n尚想争名者，谁云要路居。\n都忘下流叹，倾夺竟何如。' },
  { title: '高斋闲望言怀', author: '张九龄', poem: '高斋复晴景，延眺属清秋。\n风物动归思，烟林生远愁。\n纷吾自穷海，薄宦此中州。\n取路无高足，随波适下流。\n岁华空冉冉，心曲且悠悠。\n坐惜芳时歇，胡然久滞留。' },
  { title: '别乡人南还', author: '张九龄', poem: '橘柚南中暖，桑榆北地阴。\n何言荣落异，因见别离心。\n吾亦江乡子，思归梦寐深。\n闻君去水宿，结思渺云林。\n牵缀从浮事，迟回谢所钦。\n东南行舫远，秋浦念猿吟。' },
  { title: '初发江陵有怀', author: '张九龄', poem: '极望涔阳浦，江天渺不分。\n扁舟从此去，鸥鸟自为群。\n他日怀真赏，中年负俗纷。\n适来果微尚，倏尔会斯文。\n复想金闺籍，何如梦渚云。\n我行多胜寄，浩思独氛氲。' },
  { title: '同綦毋学士月夜闻雁', author: '张九龄', poem: '栖宿岂无意，飞飞更远寻。\n长途未及半，中夜有遗音。\n月思关山笛，风号流水琴。\n空声两相应，幽感一何深。\n避缴归南浦，离群呌北林。\n联翩俱不定，怜尔越乡心。' },
  { title: '登总持寺阁', author: '张九龄', poem: '香阁起崔嵬，高高沙版开。\n攀跻千仞上，纷诡万形来。\n草间商君陌，云重汉后台。\n山从函谷断，川向斗城回。\n林里春容变，天边客思催。\n登临信为美，怀远独悠哉。' },
  { title: '晚憩王少府东阁', author: '张九龄', poem: '披轩肆流览，云壑见深重。\n空水秋弥净，林烟晚更浓。\n坐隅分洞府，檐际列群峰。\n窈窕生幽意，参差多异容。\n还慙大隐迹，空想列仙踪。\n赖此升攀处，萧条得所从。' },
  { title: '登城楼望西山作', author: '张九龄', poem: '城楼枕南浦，日夕顾西山。\n宛宛鸾鹤处，高高烟雾间。\n仙井今犹在，洪厓久不还。\n金编莫我授，羽驾亦难攀。\n檐际千峰出，云中一鸟闲。\n纵观穷水国，游思徧人寰。\n勿复尘埃事，归来且闭关。' },
  { title: '祠紫盖山经玉泉山寺', author: '张九龄', poem: '指涂跻楚望，策马傍荆岑。\n稍稍松篁入，泠泠磵谷深。\n观奇逐幽暎，历险忘岖嵚。\n上界投佛影，中天扬梵音。\n焚香忏在昔，礼足誓来今。\n灵异若有对，神仙真可寻。\n高僧闻逝者，远俗是初心。\n藓驳经行处，猿啼燕坐林。\n归真已寂灭，留迹岂[湮沈]。\n法地自兹广，何云千万金。' },
  { title: '洪州西山祈雨是日辄应因赋诗言事', author: '张九龄', poem: '兹山蕴灵异，走望良有归。\n丘祷虽已久，甿心难重违。\n迟明申藻荐，先夕旅岩扉。\n独宿云峰下，萧条人吏稀。\n我来不外适，幽抱自中微。\n静入风泉奏，凉生松栝围。\n穷年滞远想，寸晷阅清晖。\n虚美怅无属，素情缄所依。\n诡随嫌弱操，羇束谢贞肥。\n义济亦吾道，诚存为物祈。\n灵心倏已应，甘液幸而飞。\n闭阁且无责，随车安敢希。\n多慙德不感，知复是耶非。' },
  { title: '经江宁览旧迹至玄武湖', author: '张九龄', poem: '南国更数世，北湖方十洲。\n天清华林苑，日晏景阳楼。\n果下回仙骑，津傍驻彩斿。\n凫鹥喧凤管，荷芰鬬龙舟。\n七子陪诗赋，千人和棹讴。\n应言在镐乐，不让横汾秋。\n风俗因纾慢，江山成易由。\n驹王信不武，孙叔是无谋。\n佳气日将歇，霸功谁与修。\n桑田东海变，麋鹿姑苏游。\n否运争三国，康时劣九州。\n山虽幕府在，馆岂豫章留。\n水淀还相阅，菱歌亦故遒。\n雄图不足问，唯想事风流。' },
  { title: '登襄阳岘山', author: '张九龄', poem: '昔年亟攀践，征马复来过。\n信若山川旧，谁如岁月何。\n蜀相吟安在，羊公碣已磨。\n令图犹寂寞，嘉会亦蹉跎。\n宛宛樊城岸，悠悠汉水波。\n逶迤春日远，感寄客情多。\n地本原林秀，朝来烟景和。\n同心不同赏，留叹此岩阿。' },
  { title: '登荆州城楼', author: '张九龄', poem: '天宇何其旷，江城坐自拘。\n层楼百余尺，迢递在西隅。\n暇日时登眺，荒郊临故都。\n累累见陈迹，寂寂想雄图。\n古往山川在，今来郡邑殊。\n北疆虽入郑，东距岂防吴。\n几代传荆国，当时敌陕郛。\n上流空有处，中土复何虞。\n枕席夷三峡，关梁豁五湖。\n承平无异境，守隘莫论夫。\n自罢金门籍，来参竹使符。\n端居向林薮，微尚在桑榆。\n直似王陵戆，非如宁武愚。\n今兹对南浦，乘雁与双凫。' },
  { title: '登乐游原春望书怀', author: '张九龄', poem: '城隅有乐游，表里见皇州。\n策马既长远，云山亦悠悠。\n万壑清光满，千门喜气浮。\n花间直城路，草际曲江流。\n凭眺兹为美，离居方独愁。\n已惊玄发换，空度绿荑柔。\n奋翼笼中鸟，归心海上鸥。\n既伤日月逝，且欲桑榆收。\n豹变焉能及，莺鸣非可求。\n愿言从所好，初服返林丘。' },
  { title: '候使登石头驿楼作', author: '张九龄', poem: '山槛凭南望，川途眇北流。\n远林天翠合，前浦日华浮。\n万井缘津渚，千艘咽渡头。\n渔商多末事，耕稼少良畴。\n自守陈蕃榻，尝登王粲楼。\n徒然骋目处，岂是获心游。\n向迹虽愚谷，求名异盗丘。\n息阴芳木所，空复越乡忧。' },
  { title: '登临沮楼', author: '张九龄', poem: '高深不可厌，巡属复来过。\n本与众山绝，况兹韶景和。\n危楼入水倒，飞槛向空摩。\n杂树缘青壁，樛枝挂绿萝。\n潭清能彻底，鱼乐好跳波。\n有象言虽具，无端思转多。\n同怀不在此，孤赏欲如何。' },
  { title: '陪王司马登薛公逍遥台', author: '张九龄', poem: '尝闻薛公泪，非直雍门琴。\n窜逐留遗迹，悲凉见此心。\n府中因暇豫，江上幸招寻。\n人事已成古，风流独至今。\n闲情多感叹，清景暂登临。\n无复甘棠在，空余蔓草深。\n晴光送远目，胜气入幽襟。\n水去朝沧海，春来换碧林。\n赋怀湘浦吊，碑想汉川沈。\n曾是陪游日，徒为梁父吟。' },
  { title: '尝与大理丞袁公太府丞田公偶诣一所林沼尤胜因并坐其次相得甚欢遂赋诗焉以咏其事', author: '张九龄', poem: '方驾与吾友，同怀不异寻。\n偶逢池竹处，便会江湖心。\n夏近林方密，春余水更深。\n清华两辉暎，闲步亦窥临。\n苹藻复佳色，凫鹥亦好音。\n韶芳媚洲渚，蕙气袭衣襟。\n萧散皆为乐，裴回从所钦。\n谓予成夙志，岁晚共抽簪。' },
  { title: '与弟游家园', author: '张九龄', poem: '定省荣君赐，来归是昼游。\n林乌飞旧里，园果让新秋。\n枝长南庭树，池临北涧流。\n星霜屡尔别，兰麝为谁幽。\n善积家方庆，恩深国未酬。\n栖栖将义动，安得久情留。' },
  { title: '郡内闲斋', author: '张九龄', poem: '郡阁昼常掩，庭芜日复滋。\n檐风落鸟毳，窗叶挂虫丝。\n拙病宦情少，羇闲秋气悲。\n理人无异绩，为郡但经时。\n唯有江湖意，沈冥空在兹。' },
  { title: '城南隅山池春中田袁二公盛称其美夏首获赏果会夙言故有此咏', author: '张九龄', poem: '忆昨闻佳境，驾言寻昔蹊。\n非惟初物变，亦与旧游暌。\n幽渚为君说，清晨即我携。\n途深独睥睨，历险共攀跻。\n林笋苞青箨，津杨委绿荑。\n荷香初出浦，草色复缘堤。\n乐处将鸥狎，谭端用马齐。\n且言临海郡，兼话武陵溪。\n异壤风烟绝，空山岩迳迷。\n如何际朝野，从此待金闺。' },
  { title: '西江夜行', author: '张九龄', poem: '遥夜人何在，澄潭月里行。\n悠悠天宇旷，切切故乡情。\n外物寂无扰，中流澹自清。\n念归林叶换，愁坐露华生。\n犹有汀洲鹤，宵分乍一鸣。' },
  { title: '南还湘水言怀', author: '张九龄', poem: '拙宦今何有？劳歌念不成。\n十年乖夙志，一别悔前行。\n归去田园老，倘来轩冕轻。\n江间稻正熟，林里桂初荣。\n鱼意思在藻，鹿心怀食苹。\n时哉苟不达，取乐遂吾情。' },
  { title: '商洛山行怀古', author: '张九龄', poem: '园绮值秦末，嘉遁此山阿。\n陈迹向千古，荒途始一过。\n硕人久沦谢，乔木自森罗。\n故事昔尝览，遗风今岂讹。\n泌泉空活活，樵叟独皤皤。\n是处清晖满，从中幽兴多。\n长怀赤松意，复忆紫芝歌。\n避世辞轩冕，逢时解薜萝。\n盛明今在运，吾道竟如何。' },
  { title: '南还以诗代书赠京师旧僚', author: '张九龄', poem: '薄宦晨昏阙，尊尊义取斯。\n穷愁年貌改，寂历尔胡为。\n不谄词多忤，无容礼益卑。\n微生尚何有？远迹固其宜。\n思扰梁山曲，情遥越鸟枝。\n故园从海上，良友邈天涯。\n云雨叹一别，川原劳载驰。\n上慙伯乐顾，中负叔牙知。\n去国诚寥落，经途弊险巇。\n岁逢霜雪苦，林属蕙兰萎。\n欲赠幽芳歇，行悲旧赏移。\n一从关作限，两见月成规。\n苒苒穷年籥，行行尽路岐。\n征鞍税北渚，归帆指南垂。\n树晚犹葱蒨，江寒尚渺弥。\n土风从楚别，山水入湘奇。\n石濑相奔触，烟林更蔽亏。\n层崖夹洞浦，轻舸泛澄漪。\n松筿行皆傍，禽鱼动輙随。\n惜哉边地隔，不与故人窥。\n畴昔陪鹓鹭，朝阳振羽仪。\n来音虽寂寞，接景每逶迤。\n朝罢冥尘事，宾来话酒巵。\n邀欢逐芳草，结兴选华池。\n及此风成叹，何时雾可披。\n自怜无用者，谁念有情离。\n望美音容阔，怀贤梦想疲。\n因声达霄汉，持拙守东陂。' },
  { title: '初发道中赠王司马兼寄诸公', author: '张九龄', poem: '昔岁尝陈力，中年退屏居。\n承颜方弄鸟，放性或观鱼。\n曾是安疵拙，诚非议卷舒。\n林园事益简，烟月赏恒余。\n不意栖愚谷，无阶奉诏书。\n湛恩均大造，弱植媿空虚。\n肃命趋仙阙，侨装抚传车。\n念行开祖帐，怜别降题舆。\n谁谓风期许，叨延礼数殊。\n义沾投分末，情及解携初。\n追饯扶江介，光辉烛里闾。\n子云应寂寞，公叔为吹嘘。\n景物春来异，音容日向疎。\n川原行稍稳，钟鼓听犹徐。\n林隔王公轝，云迷班氏庐。\n恋亲唯委咽，思德更踌躇。\n徇义当由此，怀安乃阙如。\n愿酬明主惠，行矣岂徒欤。' },
  { title: '自始兴溪夜上赴岭', author: '张九龄', poem: '尝蓄名山意，兹为世网牵。\n征途屡及此，初服已非然。\n日落青岩际，溪行绿筿边。\n去舟乘月后，归鸟息人前。\n数曲迷幽嶂，连圻触暗泉。\n深林风绪结，遥夜客情悬。\n非梗胡为泛，无膏亦自煎。' },
  { title: '当涂界寄裴宣州', author: '张九龄', poem: '故人宣城守，亦在江南偏。\n如何分虎竹，相与间山川。\n章绶胡为者，形骸非自然。\n含情津渡阔，倚望脰空延。\n远近闻佳政，平生仰大贤。\n推心徒有属，会面良无缘。\n日夕遵前渚，江村投暮烟。\n念行秪意默，怀远岂言宣。\n委曲风波事，难为尺素传。' },
  { title: '郡中每晨兴輙见群鹤东飞至暮又行列而返哢唳云路甚和乐焉予媿独处江城常目送此意有所羡遂赋以诗', author: '张九龄', poem: '云间有数鹤，抚翼意无违。\n晓日东田去，烟霄北渚归。\n欢呼良自适，罗列好相依。\n远集长江静，高翔众鸟稀。\n岂烦仙子驭，何畏野人机。\n却念乘轩者，拘留不得飞。' },
  { title: '和裴侍中承恩拜扫旋辔途中有怀寄州县官僚乡国亲故', author: '张九龄', poem: '嵩岳神惟降，汾川鼎气雄。\n生才作霖雨，继代有清通。\n天下称贤相，朝端挹至公。\n自家来佐国，移孝入为忠。\n霜露多前感，丘园想旧风。\n扈巡过晋北，问俗到河东。\n便道恩华降，还乡礼教崇。\n野尊延故老，朝服见儿童。' },
  { title: '和姚令公哭李尚书乂', author: '张九龄', poem: '贵贱虽殊等，平生窃下风。\n云泥势已绝，山海纳还通。\n忽叹登龙者，翻将吊鹤同。\n琴诗犹可托，剑履独成空。\n畴昔尝论礼，兴言每匪躬。\n人思崔琰议，朝掩祭遵公。\n作善神何酷，依仁命不融。\n天文虚北斗，人事罢南宫。\n上幸既伤旧，下流弥感衷。\n无恩报国士，徒欲问玄穹。' },
  { title: '奉和圣制经函谷关作', author: '张九龄', poem: '函谷虽云险，黄河已复清。\n圣心无所隔，空此置关城。' },
  { title: '奉和圣制度潼关口号', author: '张九龄', poem: '嶙嶙故城垒，荒凉空戍楼。\n在德不在险，方知王道休。' },
  { title: '答太常靳博士见赠一绝', author: '张九龄', poem: '上苑春先入，中园花尽开。\n唯余幽径草，尚待日光催。' },
  { title: '登荆州城望江二首 一', author: '张九龄', poem: '滔滔大江水，天地相终始。\n经阅几世人，复叹谁家子。' },
  { title: '登荆州城望江二首 二', author: '张九龄', poem: '东望何悠悠，西来昼夜流。\n岁月既如此，为心那不愁。' },
  { title: '赋得自君之出矣', author: '张九龄', poem: '自君之出矣，不复理残机。\n思君如满月，夜夜减清辉。' },
  { title: '荅陆澧', author: '张九龄', poem: '松叶堪为酒，春来酿几多。\n不辞山路远，踏雪也相过。' },
  { title: '奉和上元酺宴应诏', author: '杨炯', poem: '甲乙遇灾年，周隋送上弦。\n妖星六丈出，沴气七重悬。\n赤县空无主，苍生欲问天。\n龟龙开宝命，云火昭灵庆。\n万物覩真人，千秋逢圣政。\n祖宗玄泽远，文武休光盛。\n大号域中平，皇威天下惊。\n参辰昭文物，宇宙浃声名。\n汉后三章令，周王五伐兵。\n匈奴穷地角，本自远正朔。\n骄子起天街，由来亏礼乐。\n一衣扫风雨，再战夷屯剥。\n清明日月旦，萧索烟云涣。\n寒暑既平分，阴阳复贞观。\n惟神谐妙物，乃圣符幽赞。\n下武发祯祥，平阶属会昌。\n金泥封日观，璧水匝明堂。\n业盛勋华德，兴包天地皇。\n孝思义罔极，易礼光前式。\n天焕三辰辉，灵书五云色。\n敬时穷发歛，卜代盈千亿。\n五纬聚华轩，重光入望园。\n公卿论至道，天子拜昌言。\n雷解初开出，星空即便元。\n瑶台凉景荐，银阙秋阴遍。\n百戏骋鱼龙，千门壮宫殿。\n深仁洽蛮徼，恺乐周寰县。\n宣室召群臣，明庭礼百神。\n仰德还符日，沾恩更似春。\n襄城非牧竖，楚国有巴人。' },
  { title: '广溪峡', author: '杨炯', poem: '广溪三峡首，旷望兼川陆。\n山路遶羊肠，江城镇鱼腹。\n乔林百丈偃，飞水千寻瀑。\n惊浪回高天，盘涡转深谷。\n汉氏昔云季，中原争逐鹿。\n天下有英雄，襄阳有龙伏。\n常山集军旅，永安兴版筑。\n池台忽已倾，邦家遽沦覆。\n庸才若刘禅，忠佐为心腹。\n设险犹可存，当无贾生哭。' },
  { title: '巫峡', author: '杨炯', poem: '三峡七百里，唯言巫峡长。\n重岩窅不极，叠嶂凌苍苍。\n绝壁横天险，莓苔烂锦章。\n入夜分明见，无风波浪狂。\n忠信吾所蹈，泛舟亦何伤。\n可以涉砥柱，可以浮吕梁。\n美人今何在？灵芝徒有芳。\n山空夜猿啸，征客泪沾裳。' },
  { title: '西陵峡', author: '杨炯', poem: '绝壁耸万仞，长波射千里。\n盘薄荆之门，滔滔南国纪。\n楚都昔全盛，高丘烜望祀。\n秦兵一旦侵，夷陵火潜起。\n四维不复设，关塞良难恃。\n洞庭且忽焉，孟门终已矣。\n自古天地辟，流为峡中水。\n行旅相赠言，风涛无极已。\n及余践斯地，瓌奇信为美。\n江山若有灵，千载伸知己。' },
  { title: '从军行', author: '杨炯', poem: '烽火照西京，心中自不平。\n牙璋辞凤阙，铁骑绕龙城。\n雪暗凋旗画，风多杂鼓声。\n宁为百夫长，胜作一书生。' },
  { title: '刘生', author: '杨炯', poem: '卿家本六郡，年长入三秦。\n白璧酬知己，黄金谢主人。\n剑锋生赤电，马足起红尘。\n日暮歌钟发，喧喧动四邻。' },
  { title: '骢马', author: '杨炯', poem: '骢马铁连钱，长安侠少年。\n帝畿平若水，官路直如弦。\n夜玉妆车轴，秋金铸马鞭。\n风霜但自保，穷达任皇天。' },
  { title: '出塞', author: '杨炯', poem: '塞外欲纷纭，雌雄犹未分。\n明堂占气色，华盖辨星文。\n二月河魁将，三千太乙军。\n丈夫皆有志，会见立功勋。' },
  { title: '有所思', author: '杨炯', poem: '贱妾留南楚，征夫向北燕。\n三秋方一日，少别比千年。\n不掩嚬红楼，无论数绿钱。\n相思明月夜，迢递白云天。' },
  { title: '梅花落', author: '杨炯', poem: '窗外一株梅，寒花五出开。\n影随朝日远，香逐便风来。\n泣对铜钩障，愁看玉镜台。\n行人断消息，春恨几裴回。' },
  { title: '折杨柳', author: '杨炯', poem: '边地遥无极，征人去不还。\n秋容凋翠羽，别泪损红颜。\n望断流星驿，心驰明月关。\n藁砧何处在？杨柳自堪攀。' },
  { title: '紫骝马', author: '杨炯', poem: '侠客重周游，金鞭控紫骝。\n蛇弓白羽箭，鹤辔赤茸秋。\n发迹来南海，长鸣向北州。\n匈奴今未灭，画地取封侯。' },
  { title: '战城南', author: '杨炯', poem: '塞北途辽远，城南战苦辛。\n旛旗如鸟翼，甲胄似鱼鳞。\n冻水寒伤马，悲风愁杀人。\n寸心明白日，千里暗黄尘。' },
  { title: '送临津房少府', author: '杨炯', poem: '岐路三秋别，江津万里长。\n烟霞驻征盖，弦奏促飞觞。\n阶树含斜日，池风泛早凉。\n赠言未终竟，流涕忽沾裳。' },
  { title: '送丰城王少府', author: '杨炯', poem: '愁结乱如麻，长天照落霞。\n离亭隐乔树，沟水浸平沙。\n左尉才何屈，东关望渐赊。\n行看转牛斗，持此报张华。' },
  { title: '送郑州周司空', author: '杨炯', poem: '汉国临清渭，京城枕浊河。\n居人下珠泪，宾御促骊歌。\n望极关山远，秋深烟雾多。\n唯余三五夕，明月暂经过。' },
  { title: '送梓州周司功', author: '杨炯', poem: '御沟一相送，征马屡盘桓。\n言笑方无日，离忧独未宽。\n举杯聊劝酒，破涕暂为欢。\n别后风清夜，思君蜀路难。' },
  { title: '送杨处士反初卜居曲江', author: '杨炯', poem: '雁门归去远，垂老脱袈裟。\n萧寺休为客，曹溪便寄家。\n绿琪千岁树，黄槿四时花。\n别怨应无限，门前桂水斜。' },
  { title: '途中', author: '杨炯', poem: '悠悠辞鼎邑，去去指金墉。\n途路盈千里，山川亘百重。\n风行常有地，云出本多峰。\n郁郁园中柳，亭亭山上松。\n客心殊不乐，乡泪独无从。' },
  { title: '送刘校书从军', author: '杨炯', poem: '天将下三宫，星门召五戎。\n坐谋资庙略，飞檄伫文雄。\n赤土流星剑，乌号明月弓。\n秋阴生蜀道，杀气绕湟中。\n风雨何年别，琴尊此日同。\n离亭不可望，沟水自西东。' },
  { title: '游废观', author: '杨炯', poem: '青幛倚丹田，荒凉数百年。\n犹知小山桂，尚识大罗天。\n药败金炉火，苔昏玉女泉。\n岁时无壁画，朝夕有阶烟。\n花柳三春节，江山四望悬。\n悠然出尘网，从此狎神仙。' },
  { title: '和石侍御山庄', author: '杨炯', poem: '烟霞非俗宇，岩壑只幽居。\n水浸何曾畎，荒郊不复锄。\n影浓山树密，香浅泽花疎。\n阔堑防斜径，平堤夹小渠。\n莲房若个实，竹节几重虚。\n萧然隔城市，酌醴焚枯鱼。' },
  { title: '送李庶子致仕还洛', author: '杨炯', poem: '此地倾城日，由来供帐华。\n亭逢李广骑，门接邵平瓜。\n原野烟氛匝，关河游望赊。\n白云断岩岫，绿草覆江沙。\n诏赐扶阳宅，人荣御史车。\n灞池一相送，流涕向烟霞。' },
  { title: '早行', author: '杨炯', poem: '敞朗东方彻，阑干北斗斜。\n地气俄成雾，天云渐作霞。\n河流才辨马，岩路不容车。\n阡陌经三岁，闾阎对五家。\n露文沾细草，风影转高花。\n日月从来惜，关山犹自赊。' },
  { title: '和崔司空伤姬人', author: '杨炯', poem: '昔时南浦别，鹤怨宝琴弦。\n今日东方至，鸾销珠镜前。\n水流衔砌咽，月影向窗悬。\n妆匣凄余粉，熏炉灭旧烟。\n晚庭摧玉树，寒帐委金莲。\n佳人不再得，云日几千年。' },
  { title: '和骞右丞省中暮望', author: '杨炯', poem: '故事闲台阁，仙门蔼已深。\n旧章窥复道，云幌肃重阴。\n玄律葭灰变，青阳斗柄临。\n年光摇树色，春气绕兰心。\n风响高窗度，流痕曲岸侵。\n天门总枢辖，人镜辨衣簪。\n日暮南宫静，瑶华振雅音。' },
  { title: '和酬虢州李司法', author: '杨炯', poem: '唇齿标形胜，关河壮邑居。\n寒山抵方伯，秋水面鸿胪。\n君子从游宦，忘情任卷舒。\n风霜下刀笔，轩盖拥门闾。\n平野芸黄遍，长洲鸿雁初。\n菊花宜泛酒，浦叶好裁书。\n昔我芝兰契，悠然云雨疎。\n非君重千里，谁有惠双鱼。' },
  { title: '和郑雠校内省眺瞩思乡怀友', author: '杨炯', poem: '铜门初下辟，石馆始沈研。\n游雾千金字，飞云五色牋。\n楼台横紫极，城阙俯青田。\n暄入瑶房里，春回玉宇前。\n霞文埋落照，风物澹归烟。\n翰墨三余隙，关山四望悬。\n颓峰暌酌羽，流水旷鸣弦。\n虽欣承白雪，终恨隔青天。' },
  { title: '和旻上人伤果禅师', author: '杨炯', poem: '净业初中日，浮生大小年。\n无人本无我，非后亦非前。\n箫鼓旁喧地，龙蛇直映天。\n法门摧栋宇，觉海破舟船。\n书镇秦王饷，经文宋国传。\n声华周百亿，风烈被三千。\n芜没青园寺，荒凉紫陌田。\n德音殊未远，拱木已生烟。' },
  { title: '和刘侍郎入隆唐观', author: '杨炯', poem: '福地阴阳合，仙都日月开。\n山川临四险，城树隐三台。\n伏槛排云出，飞轩遶涧回。\n参差凌倒影，潇洒轶浮埃。\n百果珠为实，群峰锦作苔。\n悬萝暗疑雾，瀑布响成雷。\n方士烧丹液，真人泛玉杯。\n还如问桃水，更似得蓬莱。\n汉帝求仙日，相如作赋才。\n自然金石奏，何必上天台。' },
  { title: '和辅先入昊天观星瞻', author: '杨炯', poem: '遁甲爰皇里，星占太乙宫。\n天门开奕奕，佳气郁葱葱。\n碧落三干外，黄图四海中。\n邑居环若水，城阙抵新丰。\n玉槛昆仑侧，金枢地轴东。\n上真朝北斗，元始咏南风。\n汉君祠五帝，淮王礼八公。\n道书编竹简，灵液灌梧桐。\n草茂琼阶绿，花繁宝树红。\n石楼纷似画，地镜淼如空。\n桑海年应积，桃源路不穷。\n黄轩若有问，三月住崆峒。' },
  { title: '和刘长史荅十九兄', author: '杨炯', poem: '帝尧平百姓，高祖宅三秦。\n子弟分河岳，衣冠动缙绅。\n盛名恒不陨，历代几相因。\n街巷涂山曲，门闾洛水滨。\n五龙金作友，一子玉为人。\n宝剑丰城气，明珠魏国珍。\n风标自落落，文质且彬彬。\n共许刁元亮，同推周伯仁。\n石城俯天阙，钟阜对江津。\n骥足方遐骋，狼心独未驯。\n鼓鼙鸣九域，风火集重𬮱。\n城势余三板，兵威乏四邻。\n居然混玉石，直置保松筠。\n耿介酬天子，危言数贼臣。\n钟仪琴未奏，苏武节犹新。\n受禄宁辞死，扬名不顾身。\n精诚动天地，忠义感明神。\n怪鸟俄垂翼，修蛇竟暴鳞。\n来朝拜休命，述职下梁岷。\n善政驰金马，嘉声绕玉轮。\n三荆忽有赠，四海更相亲。\n宫征谐鸣石，光辉掩烛银。\n山川遥满目，零露坐沾巾。\n友爱光天下，恩波浃后尘。\n懦夫仰高节，下里继阳春。' },
  { title: '夜送赵纵', author: '杨炯', poem: '赵氏连城璧，由来天下传。\n送君还旧府，明月满前川。' },
  { title: '息夫人', author: '宋之问', poem: '可怜楚破息，肠断息夫人。\n仍为泉下骨，不作楚王嫔。\n楚王宠莫盛，息君情更亲。\n情亲怨生别，一朝俱杀身。' },
  { title: '初到陆浑山庄', author: '宋之问', poem: '授衣感穷节，策马凌伊关。\n归齐逸人趣，日觉秋琴闲。\n寒露衰北阜，夕阳破东山。\n浩歌步榛樾，栖鸟随我还。' },
  { title: '夜饮东亭', author: '宋之问', poem: '春泉鸣大壑，皓月吐层岑。\n岑壑景色佳，慰我远游心。\n暗芳足幽气，惊栖多众音。\n高兴南山曲，长谣横素琴。' },
  { title: '芳树', author: '宋之问', poem: '何地早芳菲，宛在长门殿。\n夭桃色若绶，秾李光如练。\n啼鸟弄花疎，游蜂饮香遍。\n叹息春风起，飘零君不见。' },
  { title: '送赵六贞固', author: '宋之问', poem: '目断南浦云，心醉东郊柳。\n怨别此何时，春芳来已久。\n与君共时物，尽此盈樽酒。\n始愿今不从，春风恋携手。' },
  { title: '题张老松树', author: '宋之问', poem: '岁晚东岩下，周顾何凄恻。\n日落西山阴，众草起寒色。\n中有乔松树，使我长叹息。\n百尺无寸枝，一生自孤直。' },
  { title: '别之望后独宿蓝田山庄', author: '宋之问', poem: '鹡鸰有旧曲，调苦不成歌。\n自叹兄弟少，常嗟离别多。\n尔寻北京路，予卧南山阿。\n泉晚更幽咽，云秋尚嵯峨。\n药栏听蝉噪，书幌见禽过。\n愁至愿甘寝，其如乡梦何。' },
  { title: '浣纱篇赠陆上人', author: '宋之问', poem: '越女颜如花，越王闻浣纱。\n国微不自宠，献作吴宫娃。\n山薮半潜匿，苎萝更蒙遮。\n一行霸句践，再笑倾夫差。\n艳色夺人目，敩嚬亦相夸。\n一朝还旧都，靓粧寻若耶。\n鸟惊入松网，鱼畏沈荷花。\n始觉冶容妄，方悟群心邪。\n钦子秉幽意，世人共称嗟。\n愿言托君怀，倘类蓬生麻。\n家住雷门曲，高阁凌飞霞。\n淋漓翠羽帐，旖旎采云军。\n春风艳楚舞，秋月缠胡笳。\n自昔专娇爱，袭玩唯矜奢。\n达本知空寂，弃彼犹泥沙。\n永割偏执性，自长薰修芽。\n携妾不障道，来止妾西家。' },
  { title: '雨从箕山来', author: '宋之问', poem: '雨从箕山来，倏与飘风度。\n晴明西峰日，绿缛南溪树。\n此时客精庐，幸蒙真僧顾。\n深入清净理，妙断往来趣。\n意得两契如，言尽共忘喻。\n观花寂不动，闻鸟悬可悟。\n向夕闻天香，淹留不能去。' },
  { title: '初至崖口', author: '宋之问', poem: '崖口众山断，嵚崟耸天壁。\n气冲落日红，影入春潭碧。\n锦缋织苔藓，丹青画松石。\n水禽泛容与，岩花飞的皪。\n微路从此深，我来限于役。\n惆怅情未已，群峰暗将夕。' },
  { title: '自湘源至潭州衡山县', author: '宋之问', poem: '浮湘沿迅湍，逗浦凝远盼。\n渐见江势阔，行嗟水流漫。\n赤岸杂云霞，绿竹缘溪涧。\n向背群山转，应接良景晏。\n沓障连夜猿，平沙覆阳雁。\n纷吾望阙客，归桡速已惯。\n中道方溯洄，迟念自兹撰。\n赖欣衡阳美，持以蠲忧患。' },
  { title: '入崖口五渡寄李适', author: '宋之问', poem: '抱琴登绝壑，伐木溯清川。\n路极意谓尽，势回趣转绵。\n人远草木秀，山深云景鲜。\n余负海峤情，自昔微尚然。\n弥旷十余载，今来宛仍前。\n未窥仙源极，独进野人船。\n时攀乳窦憩，屡薄天窗眠。\n夜弦响松月，朝楫弄苔泉。\n因冥象外理，永谢区中缘。\n碧潭可遗老，丹砂堪学仙。\n莫使驰光暮，空令归鹤怜。' },
  { title: '洞庭湖', author: '宋之问', poem: '地尽天水合，朝及洞庭湖。\n初日当中涌，莫辨东西隅。\n晶耀目何在，滢荧心欲无。\n灵光晏海若，游气耿天吴。\n张乐轩皇至，征苗夏禹徂。\n楚臣悲落叶，尧女泣苍梧。\n野积九江润，山通五岳图。\n风恬鱼自跃，云夕雁相呼。\n独此临泛漾，浩将人代殊。\n永言洗氛浊，卒岁为清娱。\n要使功成退，徒劳越大夫。' },
  { title: '景龙四年春祠海', author: '宋之问', poem: '肃事祠春溟，宵斋洗蒙虑。\n鸡鸣见日出，鹭下惊涛鹜。\n地阔八荒近，天回百川澍。\n筵端接空曲，目外唯雰雾。\n暖气物象来，周游晦明互。\n致牲匪玄享，禋涤期灵煦。\n的的波际禽，沄沄岛间树。\n安期今何在，方丈蔑寻路。\n仙事与世隔，冥搜徒已屡。\n四明背群山，遗老莫辨处。\n抚中良自慨，弱龄忝恩遇。\n三入文史林，两拜神仙署。\n虽叹出关远，始知临海趣。\n赏来空自多，理胜孰能喻。\n留楫竟何待，徙倚忽云暮。' },
  { title: '温泉庄卧病寄杨七炯', author: '宋之问', poem: '移疾卧兹岭，寥寥倦幽独。\n赖有嵩丘山，高枕长在目。\n兹山栖灵异，朝夜翳云族。\n是日蒙雨晴，返景入岩谷。\n幂幂涧畔草，青青山下木。\n此意方无穷，环顾怅林麓。\n伊洛何悠漫，川原信重复。\n夏余鸟兽蕃，秋末禾黍熟。\n秉愿守樊圃，归闲欣艺牧。\n惜无载酒人，徒把凉泉掬。' },
  { title: '荅田征君', author: '宋之问', poem: '家临清溪水，溪水绕盘石。\n绿萝四面垂，褭褭百余尺。\n风泉度丝管，苔藓铺茵席。\n传闻颍阳人，霞外漱灵液。\n忽枉岩中翰，吟望朝复夕。\n何当遂远游，物色候逋客。' },
  { title: '自衡阳至韶州谒能禅师', author: '宋之问', poem: '谪居窜炎壑，孤帆淼不系。\n别家万里余，流目三春际。\n猿啼山馆晓，虹饮江皐霁。\n湘岸竹泉幽，衡峰石囷闭。\n岭嶂穷攀越，风涛极沿济。\n吾师在韶阳，欣此得躬诣。\n洗虑宾空寂，焚香结精誓。\n愿以有漏躯，聿薰无生慧。\n物用益冲旷，心源日闲细。\n伊我获此途，游道回晚计。\n宗师信舍法，摈落文史艺。\n坐禅罗浮中，寻异穷海裔。\n何辞御魑魅，自可乘炎疠。\n回首望旧乡，云林浩亏蔽。\n不作离别苦，归期多年岁。' },
  { title: '见南山夕阳召监师不至', author: '宋之问', poem: '夕阳黯晴碧，山翠互明灭。\n此中意无限，要与开士说。\n徒郁仲举思，讵回道林辙。\n孤兴欲待谁，待此湖上月。' },
  { title: '游法华寺', author: '宋之问', poem: '薄游京都日，遥羡稽山名。\n分刺江海郡，朅来征素情。\n松露洗心眷，象筵敷念诚。\n薄云界青嶂，皎日𬸣朱甍。\n苔涧深不测，竹房闲且清。\n感真六象见，垂兆二𪅝鸣。\n古今信灵迹，中州莫与京。\n林𪩘永栖业，岂伊佐一生。\n浮悟虽已久，事试去来成。\n观念幸相续，庶几最后明。' },
  { title: '宿云门寺', author: '宋之问', poem: '云门若邪里，泛鹢路才通。\n夤缘绿筿岸，遂得青莲宫。\n天香众壑满，夜梵前山空。\n漾漾潭际月，飔飗杉上风。\n兹焉多嘉遯，数子今莫同。\n凤归慨处士，鹿化闻仙公。\n樵路郑州北，举井阿岩东。\n永夜岂云寐，曙华忽葱茏。\n谷鸟啭尚涩，源桃惊未红。\n再来期春暮，当造林端穷。\n庶几踪谢客，开山投剡中。' },
  { title: '春湖古意', author: '宋之问', poem: '院梅发向尺，园鸟复成曲。\n落日游南湖，果掷颜如玉。\n含情不得语，转盼知所属。\n惆怅未可归，宁关须采菉。' },
  { title: '游陆浑南山自歇马岭到枫香林以诗代书荅李舍人适', author: '宋之问', poem: '晨登歇马岭，遥望伏牛山。\n孤出群峰首，熊熊元气间。\n太和亦崔嵬，石扇横闪倏。\n细岑互攒倚，浮𪩘竞奔蹙。\n白云遥入怀，青霭近可掬。\n徒寻灵异迹，周顾惬心目。\n晨拂鸟路行，暮投人烟宿。\n稉稻远弥秀，栗芋秋新熟。\n石髓非一岩，药苗乃万族。\n间关踏云雨，缭绕缘水木。\n西见商山芝，南到楚乡竹。\n楚竹幽且深，半杂枫香林。\n浩歌清潭曲，寄尔桃源心。' },
  { title: '早发大庾岭', author: '宋之问', poem: '晨跻大庾险，驿鞍驰复息。\n雾露昼未开，浩途不可测。\n嵥起华夷界，信为造化力。\n歇鞍问徒旅，乡关在西北。\n出门怨别家，登岭恨辞国。\n自惟勗忠孝，斯罪懵所得。\n皇明颇照洗，延议日纷惑。\n兄弟远沦居，妻子成异域。\n羽翮伤已毁，童幼怜未识。\n踌蹰恋北顾，亭午晞霁色。\n春煖阴梅花，瘴回阳鸟翼。\n含沙缘涧聚，吻草依林植。\n适蛮悲疾首，怀巩泪沾臆。\n感谢鹓鹭朝，勤修魑魅职。\n生还倘非远，誓拟酬恩德。' },
  { title: '自洪府舟行直书其事', author: '宋之问', poem: '仲春辞国门，畏途横万里。\n越淮乘楚嶂，造江泛吴汜。\n严程无休隙，日夜涉风水。\n昔闻垂堂言，将诫千金子。\n问余何奇剥，迁窜极炎鄙。\n揆己道德余，幼闻虚白旨。\n贵身贱外物，抗迹远尘轨。\n朝游伊水湄，夕卧箕山趾。\n妙年拙自晦，皎洁弄文史。\n谬辱紫泥书，挥翰青云里。\n事往每增伤，宠来常誓止。\n铭骨怀报称，逆鳞让金紫。\n安位衅潜搆，退耕祸犹起。\n栖岩实吾策，触藩诚内耻。\n济济同时人，台庭鸣劒履。\n愚以卑自衞，兀坐去沈滓。\n迨兹理已极，窃位申知己。\n群议负宿心，获戾光华始。\n黄金忽销铄，素业坐沦毁。\n浩叹诬平生，何独恋枌梓。\n浦树浮郁郁，皐兰覆靡靡。\n百越去魂断，九疑望心死。\n未尽匡阜游，远欣罗浮美。\n周旋本师训，佩服无生理。\n异国多灵仙，幽探忘年纪。\n敝庐嵩山下，空谷茂兰芷。\n悠悠南溟远，采掇长已矣。' },
  { title: '下桂江县黎壁', author: '宋之问', poem: '放溜觌前溆，连山分上干。\n江回云壁转，天小雾峰攒。\n吼沫跳急浪，合流环峻滩。\n欹离出漩划，缭绕避涡盘。\n舟子怯桂水，最言斯路难。\n吾生抱忠信，吟啸自安闲。\n旦别已千岁，夜愁劳万端。\n企予见夜月，委曲破林峦。\n潭旷竹烟尽，洲香橘露团。\n岂傲夙所好，对之与俱欢。\n思君罢琴酌，泣此夜漫漫。' },
  { title: '奉使嵩山途经缑岭', author: '宋之问', poem: '侵星发洛城，城中歌吹声。\n毕景至缑岭，岭上烟霞生。\n草树饶野意，山川多古情。\n大隐德所薄，归来可退耕。' },
  { title: '伤王七秘书监寄呈扬州陆长史通简府僚广陵以广好事', author: '宋之问', poem: '王氏贵先宗，衡门栖道风。\n传心晤有物，秉化游无穷。\n学奥九流异，机玄三语同。\n书乃墨场绝，文称词伯雄。\n白屋藩魏主，苍生期谢公。\n一祗贤良诏，遂谒承明宫。\n补衮望奚塞，尊儒位未充。\n罢官七门里，归老一丘中。\n尝忝长者辙，微言私谓通。\n我行会稽郡，路出广陵东。\n物在人已矣，都疑淮海空。' },
  { title: '使至嵩山寻杜四不遇慨然复伤田洗马韩观主因以题壁赠杜侯杜四', author: '宋之问', poem: '洛桥瞻太室，期子在云烟。\n归来不相见，孤赏弄寒泉。\n与君阔松石，于兹二十年。\n田公谢昭世，韩子秘幽埏。\n忆昔同携手，山栖接二贤。\n笙歌入玄地，诗酒坐寥天。\n旧友悉零落，罢琴私自怜。\n逝者非药误，餐霞意可全。\n为余理还策，相与事灵仙。' },
  { title: '玩郡斋海榴', author: '宋之问', poem: '泽国韶气早，开帘延霁天。\n野禽宵未啭，山蜚昼仍眠。\n目兹海榴发，列暎岩楹前。\n熠爚御风静，葳蕤含景鲜。\n清晨绿堪佩，亭午丹欲然。\n昔忝金闺籍，尝见玉池莲。\n未若宗族地，更逢荣耀全。\n南金虽自贵，贺赏讵能迁。\n抚躬万里绝，岂染一朝妍。\n徒缘滞遐郡，常是惜流年。\n越俗鄙章甫，扪心空自怜。' },
  { title: '长安路', author: '宋之问', poem: '秦地平如掌，层城出云汉。\n楼阁九衢春，车马千门旦。\n绿柳开复合，红尘聚还散。\n日晚鬬鸡场，经过狭斜看。' },
  { title: '折杨柳', author: '宋之问', poem: '玉树朝日映，罗帐春风吹。\n拭泪攀杨柳，长条宛地垂。\n白花飞历乱，黄鸟思参差。\n妾自肝肠断，傍人那得知。' },
  { title: '有所思', author: '宋之问', poem: '君子事行役，再空芳岁期。\n美人旷遥伫，万里浮云思。\n园桃绽红艳，郊叶柔绿滋。\n坐看长夏晚，秋月生罗帷。' },
  { title: '军中人日登高赠房明府', author: '宋之问', poem: '幽郊昨夜阴风断，顿觉朝来阳吹暖。\n泾水桥南柳欲黄，杜陵城北花应满。\n长安昨夜寄春衣，短翮登兹一望归。\n闻道凯旋乘骑入，看君走马见芳菲。' },
  { title: '寒食还陆浑别业', author: '宋之问', poem: '洛阳城里花如雪，陆浑山中今始发。\n旦别河桥杨柳风，夕卧伊川桃李月。\n伊川桃李正芳新，寒食山中酒复春。\n野老不知尧舜力，酣歌一曲太平人。' },
  { title: '寒食江州满塘驿', author: '宋之问', poem: '去年上巳洛桥边，今年寒食庐山曲。\n遥怜巩树花应满，复见吴洲草新绿。\n吴洲春草兰杜芳，感物思归怀故乡。\n驿骑明朝宿何处？猿声今夜断君肠。' },
  { title: '至端州驿见杜五审言沈三佺期阎五朝隐王二无竞题壁慨然成咏', author: '宋之问', poem: '逐臣北地承严谴，谓到南中每相见。\n岂意南中岐路多，千山万水分乡县。\n云摇雨散各翻飞，海阔天长音信稀。\n处处山川同瘴疠，自怜能得几人归。' },
  { title: '绿竹引', author: '宋之问', poem: '青溪绿潭潭水侧，修竹婵娟同一色。\n徒生僊实凤不游，老死空山人讵识。\n妙年秉愿逃俗纷，归卧嵩丘弄白云。\n含情傲睨慰心目，何可一日无此君。' },
  { title: '明河篇', author: '宋之问', poem: '八月凉风天气晶，万里无云河汉明。\n昏见南楼清且浅，晓落西山纵复横。\n洛阳城阙天中起，长河夜夜千门里。\n复道连甍共蔽亏，画堂琼户特相宜。\n云母帐前初泛滥，水精帘外转逶迤。\n倬彼昭回如练白，复出东城接南陌。\n南陌征人去不归，谁家今夜捣寒衣。\n鸳鸯机上疎萤度，乌鹊桥边一雁飞。\n雁飞萤度愁难歇，坐见明河渐微没。\n已能舒卷任浮云，不惜光辉让流月。\n明河可望不可亲，愿得乘槎一问津。\n更将织女支机石，还访成都卖卜人。' },
  { title: '龙门应制', author: '宋之问', poem: '宿雨霁氛埃，流云度城阙。\n河堤柳新翠，苑树花先发。\n洛阳花柳此时浓，山水楼台暎几重。\n群公拂雾朝翔凤，天子乘春幸凿龙。\n凿龙近出王城外，羽从琳琅拥轩盖。\n云罕才临御水桥，天衣已入香山会。\n山壁崭岩断复连，清流澄澈俯伊川。\n雁塔遥遥绿波上，星龛奕奕翠微边。\n层峦旧长千寻木，远壑初飞百丈泉。\n彩仗蜺旌遶香阁，下辇登高望河洛。\n东城宫阙拟昭回，南陌沟塍殊绮错。\n林下天香七宝台，山中春酒万年杯。\n微风一起祥花落，仙乐初鸣瑞鸟来。\n鸟来花落纷无已，称觞献寿烟霞里。\n歌舞淹留景欲斜，石关犹驻五云车。\n鸟旗翼翼留芳草，龙骑骎骎暎晚花。\n千乘万骑銮舆出，水静山空严警跸。\n郊外喧喧引看人，倾都南望属车尘。\n嚣声引飏闻黄道，佳气周回入紫宸。\n先王定鼎山河固，宝命乘周万物新。\n吾皇不事瑶池乐，时雨来观农扈春。' },
  { title: '初宿淮口', author: '宋之问', poem: '孤舟汴河水，去国情无已。\n晚泊投楚乡，明月清淮里。\n汴河东泻路穷兹，洛阳西顾日增悲。\n夜闻楚歌思欲断，况值淮南木落时。' },
  { title: '王子乔', author: '宋之问', poem: '王子乔，爱神仙，七月七日上宾天。\n白虎摇瑟凤吹笙，乘骑云气吸日精。\n吸日精，长不归，遗庙今在而人非。\n空望山头草，草露湿人衣。' },
  { title: '放白鹇篇', author: '宋之问', poem: '故人赠我绿绮琴，兼致白鹇鸟。\n琴是峄山桐，鸟出吴溪中。\n我心松石清霞里，弄此幽弦不能已。\n我心河海白云垂，怜此珍禽空自知。\n著书晚下麒麟阁，幼稚骄痴候门乐。\n乃言物性不可违，白鹇愁慕刷毛衣。\n玉徽闭匣留为念，六翮开笼任尔飞。' },
  { title: '桂州三月三日', author: '宋之问', poem: '代业京华里，远投魑魅乡。\n登高望不极，云海四茫茫。\n伊昔承休盼，曾为人所羡。\n两朝赐颜色，二纪陪欢宴。\n昆明御宿侍龙媒，伊阙天泉复几回。\n西夏黄河水心劒，东周清洛羽觞杯。\n苑中落花扫还合，河畔垂杨拨不开。\n千春万寿多行乐，柏梁和歌攀睿作。\n赐金分帛奉恩辉，风举云摇入紫微。\n晨趋北阙鸣珂至，夜出南宫把烛归。\n载笔儒林多岁月，襆被文昌佐吴越。\n越中山海高且深，兴来无处不登临。\n永和九年刺海郡，暮春三月醉山阴。\n愚谓嬉游长似昔，不言流寓歘成今。\n始安繁华旧风俗，帐饮倾城沸江曲。\n主人丝管清且悲，客子肝肠断还续。\n荔浦蘅皐万里余，洛阳音信绝能疎。\n故园今日应愁思，曲水何能更祓除。\n逐伴谁怜合浦叶，思归岂食桂江鱼。\n不求汉使金囊赠，愿得佳人锦字书。' },
  { title: '下山歌', author: '宋之问', poem: '下嵩山兮多所思，携佳人兮步迟迟。\n松间明月长如此，君再游兮复何时。' },
  { title: '冬宵引赠司马承祯', author: '宋之问', poem: '河有冰兮山有雪，北户墐兮行人绝。\n独坐山中兮对松月，怀美人兮屡盈缺。\n明月的的寒潭中，青松幽幽吟劲风。\n此情不向俗人说，爱而不见恨无穷。' },
  { title: '高山引', author: '宋之问', poem: '攀云窈窕兮上跻悬峰，长路浩浩兮此去何从。\n水一曲兮肠一曲，山一重兮悲一重。\n松槚邈已远，友于何日逢？\n况满室兮童稚，攒众虑于心胷。\n天高难诉兮远负明德，却望咸京兮挥涕龙钟。' },
  { title: '嵩山天门歌', author: '宋之问', poem: '登天门兮坐盘石之磷𥒘，前漎漎兮未半，下漠漠兮无垠。\n纷窈窕兮岩倚披以鹏翅，洞胶葛兮峰棱层以龙鳞。\n松移岫转，左变而右易。\n风生云起，出鬼而入神。\n吾亦不知其灵怪如此，愿游杳冥兮见羽人。\n重曰：天门兮穹崇，回合兮攒藂。\n松万接兮柱日，石千寻兮倚空。\n晚阴兮足风，夕阳兮赩红。\n试一望兮夺魄，况众妙之无穷。' },
  { title: '奉和立春日侍宴内出剪彩花应制', author: '宋之问', poem: '金阁粧新杏，琼筵弄绮梅。\n人间都未识，天上忽先开。\n蜨绕香丝住，蜂怜艳粉回。\n今年春色早，应为剪刀催。' },
  { title: '春日芙蓉园侍宴应制', author: '宋之问', poem: '芙蓉秦地沼，卢橘汉家园。\n谷转斜盘径，川回曲抱原。\n风来花自舞，春入鸟能言。\n侍宴瑶池夕，归途笳吹繁。' },
  { title: '夏日仙蕚亭应制', author: '宋之问', poem: '高岭逼星河，乘舆此日过。\n野含时雨润，山杂夏云多。\n睿藻光岩穴，宸襟洽薜萝。\n悠然小天下，归路满笙歌。' },
  { title: '奉和九月九日登慈恩寺浮屠应制', author: '宋之问', poem: '凤刹侵云半，虹旌倚日边。\n散花多宝塔，张乐布金田。\n时菊芳仙酝，秋兰动睿篇。\n香街稍欲晚，清跸扈归天。' },
  { title: '奉和九日幸临渭亭登高应制得欢字', author: '宋之问', poem: '令节三秋晚，重阳九日欢。\n仙杯还泛菊，宝馔且调兰。\n御气云霄近，乘高宇宙宽。\n今朝万寿引，宜向曲中弹。' },
  { title: '奉和圣制闰九月九日登庄严总持二寺阁', author: '宋之问', poem: '闰月再重阳，仙舆历宝坊。\n帝歌云稍白，御酒菊犹黄。\n风铎喧行漏，天花拂舞行。\n豫游多景福，梵宇日生光。' },
  { title: '麟趾殿侍宴应制', author: '宋之问', poem: '北阙层城峻，西宫复道悬。\n乘舆历万户，置酒望三川。\n花柳含丹日，山河入绮筵。\n欲知陪赏处，空外有飞烟。' },
  { title: '上阳宫侍宴应制得林字', author: '宋之问', poem: '广乐张前殿，重裘感圣心。\n砌蓂霜月尽，庭树雪云深。\n旧渥骖宸御，慈恩忝翰林。\n微臣一何幸，再得听瑶琴。' },
  { title: '幸少林寺应制', author: '宋之问', poem: '绀宇横天室，回銮指帝休。\n曙阴迎日尽，春气抱岩流。\n空乐繁行漏，香烟薄彩斿。\n玉膏从此泛，仙驭接浮丘。' },
  { title: '幸岳寺应制', author: '宋之问', poem: '𫏐幸珠筵地，俱怜石濑清。\n泛流张翠幕，拂迥挂红旌。\n雅曲龙调管，芳樽蚁泛觥。\n陪欢玉座晚，复得听金声。' },
  { title: '扈从登封途中作', author: '宋之问', poem: '帐殿郁崔嵬，仙游实壮哉。\n晓云连幕卷，夜火杂星回。\n谷暗千旗出，山鸣万乘来。\n扈从良可赋，终乏掞天才。' },
  { title: '扈从登封告成颂', author: '宋之问', poem: '复道开行殿，钩陈列禁兵。\n和风吹鼓角，佳气动旗旌。\n后骑回天苑，前山入御营。\n万方俱下拜，相与乐升平。' },
  { title: '松山岭应制', author: '宋之问', poem: '翼翼高旌转，锵锵凤辇飞。\n尘销清跸路，云湿从臣衣。\n白羽摇丹壑，天营逼翠微。\n芳声耀今古，四海警宸威。' },
  { title: '缑山庙', author: '宋之问', poem: '王子宾仙去，飘飖笙鹤飞。\n徒闻沧海变，不见白云归。\n天路何其远，人间此会稀。\n空歌日云暮，霜月渐微微。' },
  { title: '奉和梁王宴龙泓应教得微字', author: '宋之问', poem: '水府沦幽壑，星轺下紫微。\n鸟惊司仆驭，花落侍臣衣。\n芳树摇春晚，晴云绕座飞。\n淮王正留客，不醉莫言归。' },
  { title: '寿阳王花烛图', author: '宋之问', poem: '仙媛乘龙日，天孙捧雁来。\n可怜桃李树，更绕凤皇台。\n烛照香车入，花临宝扇开。\n莫令银箭晓，为尽合欢杯。' },
  { title: '江南曲', author: '宋之问', poem: '妾住越城南，离居不自堪。\n采花惊曙鸟，摘叶𫗪春蚕。\n懒结茱萸带，愁安玳瑁簪。\n待君消瘦尽，日暮碧江潭。' },
  { title: '牛女', author: '宋之问', poem: '粉席秋期缓，针楼别怨多。\n奔龙争渡月，飞鹊乱填河。\n失喜先临镜，含羞未解罗。\n谁能留夜色，来夕倍还梭。' },
  { title: '冬夜寓直麟阁', author: '宋之问', poem: '直事披三省，重关闭七门。\n广庭怜雪净，深屋喜炉温。\n月幌花虚馥，风窗竹暗喧。\n东山白云意，兹夕寄琴尊。' },
  { title: '登禅定寺阁', author: '宋之问', poem: '梵宇出三天，登临望八川。\n开襟坐霄汉，挥手拂云烟。\n函谷青山外，昆池落日边。\n东京杨柳陌，少别已经年。' },
  { title: '陆浑山庄', author: '宋之问', poem: '归来物外情，负杖阅岩耕。\n源水看花入，幽林采药行。\n野人相问姓，山鸟自呼名。\n去去独吾乐，无然愧此生。' },
  { title: '蓝田山庄', author: '宋之问', poem: '宦游非吏隐，心事好幽偏。\n考室先依地，为农且用天。\n辋川朝伐木，蓝水暮浇田。\n独与秦山老，相欢春酒前。' },
  { title: '春日山家', author: '宋之问', poem: '今日游何处？春泉洗药归。\n悠然紫芝曲，昼掩白云扉。\n鱼乐偏寻藻，人闲屡采薇。\n丘中无俗事，身世两相违。' },
  { title: '春日宴宋主簿山亭得寒字', author: '宋之问', poem: '公子正邀欢，林亭春未兰。\n攀岩践苔易，迷路出花难。\n窗覆垂杨煖，阶侵瀑水寒。\n帝城归路直，留兴接鹓鸾。' },
  { title: '江亭晚望', author: '宋之问', poem: '浩渺浸云根，烟岚出远村。\n鸟归沙有迹，帆过浪无痕。\n望水知柔性，看山欲断魂。\n纵情犹未已，回马欲黄昏。' },
  { title: '秋晚游普耀寺', author: '宋之问', poem: '薄暮曲江头，仁祠暂可留。\n山形无隐霁，野色徧呈秋。\n荷覆香泉密，藤缘宝树幽。\n平生厌尘事，过此忽悠悠。' },
  { title: '答李司户夔', author: '宋之问', poem: '远方来下客，𬨎轩摄使臣。\n弄琴宜在夜，倾酒贵逢春。\n驷马留孤馆，双鱼赠故人。\n明朝散云雨，遥仰德为邻。' },
  { title: '寄天台司马道士', author: '宋之问', poem: '卧来生白发，览镜忽成丝。\n远愧餐霞子，童颜且自持。\n旧游惜疎旷，微尚日磷缁。\n不寄西山药，何由东海期。' },
  { title: '使往天平军马约与陈子昂新乡为期及还而不相遇', author: '宋之问', poem: '入衞期之子，吁嗟不少留。\n情人去何处？淇水日悠悠。\n恒碣青云断，衡漳白露秋。\n知君心许国，不是爱封侯。' },
  { title: '过函谷关', author: '宋之问', poem: '二百四十载，海内何纷纷。\n六国兵同合，七雄势未分。\n从成拒秦帝，策决问苏君。\n鸡鸣将狗盗，论德不论勋。' },
  { title: '送朔方何侍郎', author: '宋之问', poem: '闻道云中使，乘骢往复还。\n河兵守阳月，塞虏失阴山。\n拜职尝随骠，铭功不让班。\n旋闻受降日，歌舞入萧关。' },
  { title: '送田道士使蜀投龙', author: '宋之问', poem: '风驭忽泠然，云台路几千。\n蜀门峰势断，巴字水形连。\n人隔壶中地，龙游洞里天。\n赠言回驭日，图画彼山川。' },
  { title: '送许州宋司马赴任', author: '宋之问', poem: '颍郡水东流，荀陈兄弟游。\n偏伤兹日远，独向聚星州。\n河润在明德，人康非外求。\n当闻力为政，遥慰我心愁。' },
  { title: '送赵司马赴蜀州', author: '宋之问', poem: '饯子西南望，烟緜劒道微。\n桥寒金雁落，林曙碧鸡飞。\n职拜舆方远，仙成履会归。\n定知和氏璧，遥掩玉轮辉。' },
  { title: '送永昌萧赞府', author: '宋之问', poem: '柳变曲江头，送君函谷游。\n弄琴宽别意，酌醴醉春愁。\n恋本亦何极，赠言微所求。\n莫令金谷水，不入故园流。' },
  { title: '送李侍御', author: '宋之问', poem: '行李恋庭闱，乘轺振彩衣。\n南登指吴服，北走出秦畿。\n去国夏云断，还乡秋雁飞。\n旋闻郡计入，更有使臣归。' },
  { title: '饯湖州薛司马', author: '宋之问', poem: '别驾促严程，离筵多故情。\n交深季作友，义重伯为兄。\n镇静移吴俗，风流在汉京。\n会看陈仲举，从此拜公卿。' },
  { title: '送杜审言', author: '宋之问', poem: '卧病人事绝，嗟君万里行。\n河桥不相送，江树远含情。\n别路追孙楚，维舟吊屈平。\n可惜龙泉劒，流落在丰城。' },
  { title: '送武进郑明府', author: '宋之问', poem: '弦歌试宰日，城阙赏心违。\n北谢苍龙去，南随黄鹄飞。\n夏云海中出，吴山江上微。\n甿谣岂云远，从此庆缁衣。' },
  { title: '送姚侍御出使江东', author: '宋之问', poem: '帝忧河朔郡，南发海陵仓。\n坐叹青春别，逶迤碧水长。\n饮冰朝受命，衣锦昼还乡。\n为问东山桂，无人何自芳。' },
  { title: '留别之望舍弟', author: '宋之问', poem: '同气有三人，分飞在此晨。\n西驰巴岭徼，东去洛阳滨。\n强饮离前酒，终伤别后神。\n谁怜散花蕚，独赴日南春。' },
  { title: '汉江宴别', author: '宋之问', poem: '汉广不分天，舟移杳若仙。\n秋虹暎晚日，江鹤弄晴烟。\n积水浮冠盖，遥风逐管弦。\n嬉游不可极，留恨此山川。' },
  { title: '初发荆府赠长史', author: '宋之问', poem: '□□□□□，□□□□□。\n仍随五马谪，载与两禽奔。\n明主无由见，群公莫与言。\n幸君逢圣日，何惜理虞翻。' },
  { title: '晚泊湘江', author: '宋之问', poem: '五岭恓惶客，三湘顦顇颜。\n况复秋雨霁，表里见衡山。\n路逐鹏南转，心依雁北还。\n唯余望乡泪，更染竹成斑。' },
  { title: '过蛮洞', author: '宋之问', poem: '越岭千重合，蛮谿十里斜。\n竹迷樵子径，萍匝钓人家。\n林暗交枫叶，园香覆橘花。\n谁怜在荒外，孤赏足云霞。' },
  { title: '经梧州', author: '宋之问', poem: '南国无霜霰，连年见物华。\n青林暗换叶，红橤续开花。\n春去闻山鸟，秋来见海槎。\n流芳虽可悦，会自泣长沙。' },
  { title: '渡吴江别王长史', author: '宋之问', poem: '倚櫂望兹川，销魂独黯然。\n乡连江北树，云断日南天。\n劒别龙初没，书成雁不传。\n离舟意无限，催渡复催年。' },
  { title: '泛镜湖南溪', author: '宋之问', poem: '乘兴入幽栖，舟行日向低。\n岩花候冬发，谷鸟作春啼。\n沓嶂开天小，丛篁夹路迷。\n犹闻可怜处，更在若邪溪。' },
  { title: '途中寒食题黄梅临江驿寄崔融', author: '宋之问', poem: '马上逢寒食，愁中属暮春。\n可怜江浦望，不见洛阳人。\n北极怀明主，南溟作逐臣。\n故园肠断处，日夜柳条新。' },
  { title: '游韶州广界寺', author: '宋之问', poem: '影殿临丹壑，香台隐翠霞。\n巢飞衔象鸟，砌蹋雨空花。\n宝铎摇初霁，金池暎晚沙。\n莫愁归路远，门外有三车。' },
  { title: '宿清远峡山寺', author: '宋之问', poem: '香岫悬金刹，飞泉届石门。\n空山唯习静，中夜寂无喧。\n说法初闻鸟，看心欲定猿。\n寥寥隔尘市，何异武陵源。' },
  { title: '题大庾岭北驿', author: '宋之问', poem: '阳月南飞雁，传闻至此回。\n我行殊未已，何日复归来？\n江静潮初落，林昏瘴不开。\n明朝望乡处，应见陇头梅。' },
  { title: '度大庾岭', author: '宋之问', poem: '度岭方辞国，停轺一望家。\n魂随南翥鸟，泪尽北枝花。\n山雨初含霁，江云欲变霞。\n但令归有日，不敢恨长沙。' },
  { title: '端州别袁侍郎', author: '宋之问', poem: '合浦途未极，端溪行𫏐临。\n泪来空泣脸，愁至不知心。\n客醉山月静，猿啼江树深。\n明朝共分手，之子爱千金。' },
  { title: '过史正议宅', author: '宋之问', poem: '旧交此零落，雨泣访遗尘。\n劒几传好事，池台伤故人。\n国香兰已歇，里树橘犹新。\n不见吴中隐，空余江海滨。' },
  { title: '梁宣王挽词三首 一', author: '宋之问', poem: '贵藩尧母族，外戚汉家亲。\n业重兴王际，功高复辟辰。\n爱贤唯报国，乐善不防身。\n今日衣冠送，空伤置醴人。' },
  { title: '梁宣王挽词三首 二', author: '宋之问', poem: '金精何日闭，玉匣此时开。\n东望连吾子，南瞻近帝台。\n地形龟食报，坟土燕衔来。\n可叹虞歌夕，纷纷骑吹回。' },
  { title: '梁宣王挽词三首 三', author: '宋之问', poem: '像设千年在，平生万事违。\n彩旌翻葆吹，圭翣奠灵衣。\n垅日寒无影，郊云冻不飞。' },
  { title: '鲁忠王挽词三首 一', author: '宋之问', poem: '同盟会五月，归葬出三条。\n日惨咸阳树，天寒渭水桥。\n稍看朱鹭转，尚识紫骝骄。\n寂寂泉台恨，从兹罢玉箫。' },
  { title: '鲁忠王挽词三首 二', author: '宋之问', poem: '邦家锡宠光，存没贵忠良。\n遂裂山河地，追尊父子王。\n人悲槐里月，马踏槿原霜。\n别向天京北，悠悠此路长。' },
  { title: '鲁忠王挽词三首 三', author: '宋之问', poem: '树羽迎朝日，撞钟望早霞。\n故人悲宿草，中使惨晨笳。\n气有冲天劒，星无犯斗槎。\n唯余孔公宅，长接鲁王家。' },
  { title: '范阳王挽词二首 一', author: '宋之问', poem: '贤相称邦杰，清流举代推。\n公才掩诸夏，文体变当时。\n宾吊飜成鹤，人亡惜喻龟。\n洛阳今纸贵，犹写太冲词。' },
  { title: '范阳王挽词二首 二', author: '宋之问', poem: '赠秩徽章洽，求书秘草成。\n客随朝露尽，人逐夜舟惊。\n蒿里衣冠送，松门印绶迎。\n谁知杨伯起，今日重哀荣。' },
  { title: '故赵王属赠黄门侍郎上官公挽词二首 一', author: '宋之问', poem: '韦门旌旧德，班氏业前书。\n谪去因丞相，归来为倢伃。\n周原乌相冢，越岭雁随车。\n冥漠辞昭代，空怜赋子虚。' },
  { title: '故赵王属赠黄门侍郎上官公挽词二首 二', author: '宋之问', poem: '绿车随帝子，青琐翊宸机。\n昔枉朝歌骑，今虚夕拜闱。\n柳河凄挽曲，薤露湿灵衣。\n一厝穷泉闭，双鸾遂不飞。' },
  { title: '药', author: '宋之问', poem: '有卉秘神仙，君臣有礼焉。\n忻当苦口喻，不畏入肠偏。\n扁鹊功成日，神农定品年。\n丹成如可待，鸡犬自闻天。' },
  { title: '奉和九日登慈恩寺浮图应制', author: '宋之问', poem: '瑞塔千寻起，仙舆九日来。\n萸房陈宝席，菊蘂散花台。\n御气鹏霄近，升高凤野开。\n天歌将梵乐，空里共裴回。' },
  { title: '送沙门泓景道俊玄奘还荆州应制', author: '宋之问', poem: '三乘归净域，万骑饯通庄。\n就日离亭近，弥天别路长。\n荆南旋杖钵，渭北限津梁。\n何日纡真果，还来入帝乡。' },
  { title: '咏笛', author: '宋之问', poem: '羌笛写龙声，长吟入夜清。\n关山孤月下，来向陇头鸣。\n逐吹梅花落，含春柳色惊。\n行观向子赋，坐忆旧邻情。' },
  { title: '咏钟', author: '宋之问', poem: '既接南邻磬，还随北里笙。\n平陵通曙响，长乐警宵声。\n秋至含霜动，春归应律鸣。\n岂惟恒待扣，金簴有余清。' },
  { title: '花落', author: '宋之问', poem: '铁骑几时回，金闺怨早梅。\n雪寒花已落，风暖叶还开。\n夕逐新春管，香迎小岁桮。\n盛时何足贵，书里报轮台。' },
  { title: '旅宿淮阳亭口号', author: '宋之问', poem: '日暮风亭上，悠悠旅思多。\n故乡临桂水，今夜渺星河。\n暗草霜华发，空亭鴈影过。\n兴来谁与语，劳者自为歌。' },
  { title: '内题赋得巫山雨', author: '宋之问', poem: '神女向高唐，巫山下夕阳。\n裴回作行雨，婉恋逐荆王。\n电影江前落，雷声峡外长。\n霁云无处所，台馆晓苍苍。' },
  { title: '王昭君', author: '宋之问', poem: '非君惜鸾殿，非妾妬娥眉。\n薄命由骄虏，无情是画师。\n嫁来胡地日，不竝汉宫时。\n辛苦无聊赖，何堪上马辞。' },
  { title: '铜雀台', author: '宋之问', poem: '昔年分鼎地，今日望陵台。\n一旦雄图尽，千秋遗令开。\n绮罗君不见，歌舞妾空来。\n恩共漳河水，东流无重回。' },
  { title: '巫山高', author: '宋之问', poem: '巫山峰十二，环合象昭回。\n俯听琵琶峡，平看云雨台。\n古槎天外落，瀑水日边来。\n何忍猨啼夜，荆王枕席开。' },
  { title: '望月有怀', author: '宋之问', poem: '天使下西楼，含光万里秋。\n台前似挂镜，帘外如悬钩。\n张尹将眉学，班姬取扇俦。\n佳期应借问，为报大刀头。' },
  { title: '驾出长安', author: '宋之问', poem: '圣德超千古，皇风扇九围。\n天回万象出，驾动六龙飞。\n淑气来黄道，祥云覆紫微。\n太平多扈从，文物有光辉。' },
  { title: '饯中书侍郎来济', author: '宋之问', poem: '暧暧去尘昏灞岸，飞飞轻盖指河梁。\n云峰衣结千重叶，雪岫花开几树粧。\n深悲黄鹤孤舟远，独对青山别路长。\n却将分手沾襟泪，还用持添离席觞。' },
  { title: '奉和春初幸太平公主南庄应制', author: '宋之问', poem: '青门路接凤凰台，素浐宸游龙骑来。\n涧草自迎香辇合，岩花应待御筵开。\n文移北斗成天象，酒递南山作寿杯。\n此日侍臣将石去，共欢明主赐金回。' },
  { title: '三阳宫侍宴应制得幽字', author: '宋之问', poem: '离宫秘苑胜瀛洲，别有仙人洞壑幽。\n岩边树色含风冷，石上泉声带雨秋。\n鸟向歌筵来度曲，云依帐殿结为楼。\n微臣昔忝方明御，今日还陪八骏游。' },
  { title: '奉和晦日幸昆明池应制', author: '宋之问', poem: '春豫灵池会，沧波帐殿开。\n舟凌石鲸度，槎拂斗牛回。\n节晦蓂全落，春迟柳暗催。\n象溟看浴景，烧劫辨沈灰。\n镐饮周文乐，汾歌汉武才。\n不愁明月尽，自有夜珠来。' },
  { title: '奉和幸大荐福寺', author: '宋之问', poem: '香刹中天起，宸游满路辉。\n乘龙太子去，驾象法王归。\n殿饰金人影，窗摇玉女扉。\n稍迷新草木，徧识旧庭闱。\n水入禅心定，云从宝思飞。\n欲知皇劫远，初拂六铢衣。' },
  { title: '奉和幸三会寺应制', author: '宋之问', poem: '六飞回玉辇，双树谒金仙。\n瑞鸟呈书字，神龙吐浴泉。\n净心遥证果，睿想独超禅。\n塔涌香花地，山围日月天。\n梵音迎漏彻，空乐倚云悬。\n今日登仁寿，长看法镜圆。' },
  { title: '奉和荐福寺应制', author: '宋之问', poem: '梵筵光圣邸，游豫览宏规。\n不改灵光殿，因开功德池。\n莲生新步叶，桂长昔攀枝。\n涌塔庭中见，飞楼海上移。\n闻韶三月幸，观象七星危。\n欲识龙归处，朝朝云气随。' },
  { title: '奉和幸神皐亭应制', author: '宋之问', poem: '清跸喧黄道，乘舆降紫宸。\n霜戈凝晓日，云管发阳春。\n台古全疑汉，林余半识秦。\n宴酣诗布泽，节改令行仁。\n昔恃山河险，今依道德淳。\n多慙献嘉颂，空累属车尘。' },
  { title: '奉和幸长安故城未央宫应制', author: '宋之问', poem: '汉王未息战，萧相乃营宫。\n壮丽一朝尽，威灵千载空。\n皇明怅前迹，置酒宴群公。\n寒轻彩仗外，春发幔城中。\n乐思回斜日，歌词继大风。\n今朝天子贵，不假叔孙通。' },
  { title: '奉和幸韦嗣立山庄侍宴应制', author: '宋之问', poem: '枢掖调梅暇，林园艺槿初。\n入朝荣劒履，退食偶琴书。\n地隐东岩室，天回北斗车。\n旌门临䆗窱，辇道属扶疎。\n云罕明丹壑，霜笳彻紫虚。\n水疑投石处，溪似钓璜余。\n帝泽颁巵酒，人欢颂里闾。\n一承黄竹咏，长奉白茅居。' },
  { title: '扈从登封告成颂应制', author: '宋之问', poem: '御路回中岳，天营接下都。\n百灵无后至，万国竞前驱。\n文衞严清跸，幽仙读宝符。\n贝花明汉果，芝草入尧厨。\n济济衣冠会，喧喧夷夏俱。\n宗禋仰神理，刊木望川途。\n抚己贫非病，时来本不愚。\n愿陪丹凤辇，率舞白云衢。' },
  { title: '宴安乐公主宅得空字', author: '宋之问', poem: '英藩筑外馆，爱主出王宫。\n宾至星槎落，仙来月宇空。\n玳梁飜贺燕，金埒倚晴虹。\n箫奏秦台里，书开鲁壁中。\n短歌能驻日，艳舞欲娇风。\n闻有淹留处，山阿满桂丛。' },
  { title: '春日郑协律山亭陪宴饯郑卿同用楼字', author: '宋之问', poem: '潘园枕郊郭，爱客坐相求。\n尊酒东城外，骖𬴂南陌头。\n池平分洛水，林缺见嵩丘。\n暗竹侵山径，垂杨拂妓楼。\n彩云歌处断，迟日舞前留。\n此地何年别，兰芳空自幽。' },
  { title: '和姚给事寓直之作', author: '宋之问', poem: '清论满朝阳，高才拜夕郎。\n还从避马路，来接珥貂行。\n宠就黄扉日，威回白简霜。\n柏台迁鸟茂，兰署得人芳。\n禁静钟初彻，更疎漏渐长。\n晓河低武库，流火度文昌。\n寓直恩徽重，乘秋藻翰扬。\n暗投空欲报，下调不成章。' },
  { title: '和库部李员外秋夜寓直之作', author: '宋之问', poem: '相庭贻庆远，才子拜郎初。\n起草徯仙阁，焚香卧直庐。\n更深河欲断，节劲柳偏疎。\n气耿凌云笔，心摇待漏车。\n叨荣厕俦侣，省己恧空虚。\n徒裴阳春和，难参丽曲余。' },
  { title: '酬李丹徒见赠之作', author: '宋之问', poem: '镇吴称奥里，试剧仰通才。\n近挹人披雾，遥闻境震雷。\n一朝逢解榻，累日共衔杯。\n连辔登山尽，浮舟望海回。\n以予慙拙宦，期子遇良媒。\n赠曲南凫断，征途北雁催。\n更怜江上月，还入镜中开。' },
  { title: '使过襄阳登凤林寺阁', author: '宋之问', poem: '香阁临清汉，丹梯隐翠微。\n林篁天际密，人世谷中违。\n苔石衔仙洞，莲舟泊钓矶。\n山云浮栋起，江雨入庭飞。\n信美虽南国，严程限北归。\n幽寻不可再，留步惜芳菲。' },
  { title: '宋公宅送宁谏议', author: '宋之问', poem: '宋公爰创宅，庾氏更诛茅。\n间出人三秀，平临楚四郊。\n汉臣来绛节，荆牧动金铙。\n尊溢宜城酒，笙裁曲沃匏。\n露荷秋变节，风柳夕鸣梢。\n一散阳台雨，方随越鸟巢。' },
  { title: '送合宫苏明府颋', author: '宋之问', poem: '铉府诞英规，公才天下知。\n谓乘羔雁族，继入凤皇池。\n赤县求人隐，青门起路岐。\n翟回车少别，凫化舃遥驰。\n神哭周南境，童歌渭北垂。\n贤哉荀奉倩，衮职伫来仪。' },
  { title: '送杨六望赴金水', author: '宋之问', poem: '借问梁山道，嵚岑几万重。\n遥州刀作字，绝壁劒为峰。\n惜别路穷此，留欢意不从。\n忧来生白发，时晚爱青松。\n勿以西南远，夷歌寝盛容。\n台阶有高位，宁复久临邛。' },
  { title: '下桂江龙目滩', author: '宋之问', poem: '停午出滩险，轻舟容易前。\n峰攒入云树，崖喷落江泉。\n巨石潜山怪，深篁隐洞仙。\n鸟游溪寂寂，猿啸岭娟娟。\n挥袂日凡几，我行途已千。\n暝投苍梧郡，愁枕白云眠。' },
  { title: '入泷州江', author: '宋之问', poem: '孤舟泛盈盈，江流日纵横。\n夜杂蛟螭寝，晨披瘴疠行。\n潭蒸水沫起，山热火云生。\n猿躩时能啸，鸢飞莫敢鸣。\n海穷南徼尽，乡远北魂惊。\n泣向文身国，悲看凿齿氓。\n地偏多育蛊，风恶好相鲸。\n余本岩栖客，悠哉慕玉京。\n厚恩尝愿答，薄宦不祈成。\n违隐乖求志，披荒为近名。\n镜愁玄发改，心负紫芝荣。\n运启中兴历，时逢外域清。\n祗应保忠信，延促付神明。' },
  { title: '始安秋日', author: '宋之问', poem: '桂林风景异，秋似洛阳春。\n晚霁江天好，分明愁杀人。\n卷云山𧥄𧥄，碎石水磷磷。\n世业事黄老，妙年孤隐沦。\n归欤卧沧海，何物贵吾身。' },
  { title: '桂州黄潭舜祠', author: '宋之问', poem: '虞世巡百越，相传葬九疑。\n精灵游此地，祠树日光辉。\n禋祭忽群望，丹青图二妃。\n神来兽率舞，仙去凤还飞。\n日暝山气落，江空潭霭微。\n帝乡三万里，乘彼白云归。' },
  { title: '登粤王台', author: '宋之问', poem: '江上粤王台，登高望几回。\n南溟天外合，北户日边开。\n地湿烟尝起，山晴雨半来。\n冬花采卢橘，夏果摘杨梅。\n迹类虞翻枉，人非贾谊才。\n归心不可见，白发重相催。' },
  { title: '早发始兴江口至虚氏村作', author: '宋之问', poem: '候晓逾闽峤，乘春望越台。\n宿云鹏际落，残月蚌中开。\n薜荔摇青气，桄榔翳碧苔。\n桂香多露裛，石响细泉回。\n抱叶玄猿啸，衔花翡翠来。\n南中虽可悦，北思日悠哉。\n鬒发俄成素，丹心已作灰。\n何当首归路，行剪故园莱。' },
  { title: '发藤州', author: '宋之问', poem: '朝夕苦遄征，孤魂长自惊。\n泛舟依雁渚，投馆听猿鸣。\n石发缘溪蔓，林衣埽地轻。\n云峰刻不似，苔藓画难成。\n露裛千花气，泉和万籁声。\n攀幽红处歇，跻险绿中行。\n恋切芝兰砌，悲缠松柏茔。\n丹心江北死，白发岭南生。\n魑魅天边国，穷愁海上城。\n劳歌意无限，今日为谁明。' },
  { title: '游称心寺', author: '宋之问', poem: '释事怀三隐，清襟谒四禅。\n江鸣潮未落，林晓日初悬。\n宝叶交香雨，金沙吐细泉。\n望谐舟客趣，思发海人烟。\n顾枥仍留马，乘杯久弃船。\n未忧龟负岳，且识鸟耘田。\n理契都无象，心冥不寄筌。\n安期庶可揖，天地得齐年。' },
  { title: '夜渡吴松江怀古', author: '宋之问', poem: '宿帆震泽口，晓渡松江𣸣。\n櫂发鱼龙气，舟冲鸿雁群。\n寒潮顿觉满，暗浦稍将分。\n气出海生日，光清湖起云。\n水乡尽天衞，叹息为吴君。\n谋士伏劒死，至今悲所闻。' },
  { title: '谒禹庙', author: '宋之问', poem: '夏王乘四载，兹地发金符。\n峻命终不易，报功畴敢渝。\n先驱总昌会，后至伏灵诛。\n玉帛空天下，衣冠照海隅。\n旋闻厌黄屋，更道出苍梧。\n林表祠转茂，山阿井讵枯。\n舟迁龙负壑，田变鸟芸芜。\n旧物森如在，天威肃未殊。\n玄夷届瑶席，玉女侍清都。\n奕奕扃闱邃，轩轩杖衞趋。\n气青连曙海，云白洗春湖。\n猿啸有时答，禽言常自呼。\n灵歆异蒸糈，至乐匪笙竽。\n茅殿今文袭，梅梁古制无。\n运遥日崇丽，业盛答昭苏。\n伊昔力云尽，而今功尚敷。\n揆材非美箭，精享愧生刍。\n郡职昧为理，邦空宁自诬。\n下车霰已积，摄事露行濡。\n人隐冀多祐，曷唯沾薄躯。' },
  { title: '游禹穴回出若邪', author: '宋之问', poem: '禹穴今朝到，邪溪此路通。\n著书闻太史，炼药有仙翁。\n鹤往笼犹挂，龙飞劒已空。\n石帆摇海上，天镜落湖中。\n水低寒云白，山边坠叶红。\n归舟何虑晚，日暮使樵风。' },
  { title: '灵隐寺”', author: '宋之问', poem: '鹫岭郁岧峣，龙宫锁寂寥。\n楼观沧海日，门对浙江潮。\n桂子月中落，天香云外飘。\n扪萝登墖远，刳木取泉遥。\n霜薄花更发，冰轻叶未凋。\n夙龄尚遐异，搜对涤烦嚣。\n待入天台路，看余度石桥。' },
  { title: '游云门寺', author: '宋之问', poem: '维舟探静域，作礼事尊经。\n投迹一萧散，为心自杳冥。\n龛依大禹穴，楼倚少微星。\n沓嶂围兰若，回溪抱竹庭。\n觉花涂砌白，甘露洗山青。\n雁塔𬸣金地，虹桥转翠屏。\n人天宵现景，神鬼昼潜形。\n理胜常虚寂，缘空自感灵。\n入禅从鸽遶，说法有龙听。\n劫累终期灭，尘躬且未宁。\n摇摇不安寐，待月咏岩扃。' },
  { title: '早发韶州', author: '宋之问', poem: '炎徼行应尽，回瞻乡路遥。\n珠厓天外郡，铜柱海南标。\n日夜清明少，春冬雾雨饶。\n身经大火热，颜入瘴江消。\n触影含沙怒，逢人女草摇。\n露浓看菌湿，风飓觉船飘。\n直御魑将魅，宁论鸱与鸮。\n虞翻思报国，许靖愿归朝。\n绿树秦京道，青云洛水桥。\n故园长在目，魂去不须招。' },
  { title: '早入清远峡', author: '宋之问', poem: '传闻峡山好，旭日櫂前沂。\n雨色摇丹嶂，泉声聒翠微。\n两岩天作带，万壑树披衣。\n秋菊迎霜序，春藤碍日辉。\n翳潭花似织，缘岭竹成围。\n寂历环沙浦，葱茏转石圻。\n露余江未热，风落瘴初稀。\n猿饮排虚上，禽惊掠水飞。\n榜童夷唱合，樵女越吟归。\n良候斯为美，边愁自有违。\n谁言望乡国，流涕失芳菲。' },
  { title: '发端州初入西江', author: '宋之问', poem: '问我将何去？清晨溯越溪。\n翠微县宿雨，丹壑饮晴霓。\n树影捎云密，藤阴覆水低。\n潮回出浦驶，洲转望乡迷。\n人意长怀北，江行日向西。\n破颜看鹊喜，拭泪听猿嗁/。\n骨肉初分爱，亲朋忽解携。\n路遥魂欲断，身辱理能齐。\n畴日三山意，于兹万绪暌。\n金陵有仙馆，即事寻丹梯。' },
  { title: '渡汉江', author: '宋之问', poem: '岭外音书断，经冬复历春。\n近乡情更怯，不敢问来人。' },
  { title: '嵩山夜还', author: '宋之问', poem: '家住嵩山下，好采旧山薇。\n自省游泉石，何曾不夜归。' },
  { title: '湖中别鉴上人', author: '宋之问', poem: '愿与道林近，在意逍遥篇。\n自有灵佳寺，何用沃洲禅。' },
  { title: '题鉴上人房二首 一', author: '宋之问', poem: '落花双树积，芳草一庭春。\n玩之堪兴异，何必见幽人。' },
  { title: '题鉴上人房二首 二', author: '宋之问', poem: '晚入应真理，经行尚未回。\n房中无俗物，林下有青苔。' },
  { title: '答田征君', author: '宋之问', poem: '出游杳何处？迟回伊洛间。\n归寝忽成梦，宛在嵩丘山。' },
  { title: '伤曹娘二首 一', author: '宋之问', poem: '凤飞楼伎绝，鸾死镜台空。\n独怜脂粉气，犹着舞衣中。' },
  { title: '伤曹娘二首 二', author: '宋之问', poem: '河伯怜娇态，冯夷要姝妓。\n寄言游戏人，莫弄黄河水。' },
  { title: '河阳', author: '宋之问', poem: '昔日河阳县，氛氲香气多。\n曹娘娇态尽，春树不堪过。' },
  { title: '燕巢军幕', author: '宋之问', poem: '北关怜翠幕，不是厌朱楼。\n故来呈燕颔，报道欲封侯。' },
  { title: '苑中遇雪应制', author: '宋之问', poem: '紫禁仙舆诘旦来，青旗遥倚望春台。\n不知庭霰今朝落，疑是林花昨夜开。' },
  { title: '送司马道士游天台', author: '宋之问', poem: '羽客笙歌此地违，离筵数处白云飞。\n蓬莱阙下长相忆，桐柏山头去不归。' },
  { title: '登逍遥楼', author: '宋之问', poem: '逍遥楼上望乡关，绿水泓澄云雾间。\n北去衡阳二千里，无因雁足系书还。' },
  { title: '奉和春日玩雪应制', author: '宋之问', poem: '北阙彤云掩曙霞，东风吹雪舞山家。\n琼章定少千人和，银树长芳六出花。' },
  { title: '郡宅中斋', author: '宋之问', poem: '郡宅枕层岭，春湖绕芳甸。\n云甍出万家，卧览皆已徧。\n渔商汗成雨，廨邑明若练。\n越俗镜中行，夏祠云表见。\n兹都信盘郁，英远常栖眄。\n王子事黄老，独乐恣游衍。\n谢公念苍生，同忧感推荐。\n灵越多秀士，运阔无由面。\n神理翳青山，风流满黄卷。\n揆予谬承奖，自惜从缨弁。\n瑶水执仙羁，金闺负时选。\n晨趋博望苑，夜直明光殿。\n一朝罢台阁，万里违乡县。\n风土足慰心，况悦年芳变。\n淮廪伫滋实，沂歌非所羡。\n讼寝归四明，龄颓亲九转。\n微尚本江海，少留岂交战。\n唯余后凋色，窃比东南箭。' },
  { title: '称心寺', author: '宋之问', poem: '步陟招提宫，北极山海观。\n千岩递萦绕，万壑殊悠漫。\n乔木转夕阳，文轩划清涣。\n泄云多表里，惊潮每昏旦。\n问予金门客，何事沧洲畔。\n谬以三署资，来刺百城半。\n人隐尚未弭，岁华岂兼玩。\n东山桂枝芳，明发坐盈叹。' },
  { title: '新年作', author: '宋之问', poem: '乡心新岁切，天畔独澘然。\n老至居人下，春归在客先。\n岭猨同旦暮，江柳共风烟。\n已似长沙傅，从今又几年。' },
  { title: '剪彩', author: '宋之问', poem: '驻想持金错，居然作管灰。\n绮罗纤手制，桃李向春开。\n拾藻蜂初泊，衔花鸟未回。\n不言将巧笑，飜逐美人来。' },
  { title: '七夕', author: '宋之问', poem: '传道仙星媛，年年会水隅。\n停梭借蟋蟀，留巧付蜘蛛。\n去昼从云请，归轮𥩟日输。\n莫言相见阔，天上日应殊。' },
  { title: '桂州陪王都督晦日宴逍遥楼', author: '宋之问', poem: '晦节高楼望，山川一半春。\n意随蓂叶尽，愁共柳条新。\n投刺登龙日，开怀纳鸟晨。\n兀然心似醉，不觉有吾身。' },
  { title: '和赵员外桂阳桥遇佳人', author: '宋之问', poem: '江雨朝飞浥细尘，阳桥花柳不胜春。\n金鞍白马来从赵，玉面红妆本姓秦。\n妬女犹怜镜中发，侍儿堪感路傍人。\n荡舟为乐非吾事，自叹空闺梦寐频。' },
  { title: '函谷关', author: '宋之问', poem: '至人□□识仙风，瑞霭丹光远郁葱。\n灵迹才辞周柱下，祥氛已入函关中。\n不从紫气台端候，何得青华观里逢。\n欲访乘牛求宝箓，愿随鹤驾徧瑶空。' },
  { title: '咏省壁画鹤', author: '宋之问', poem: '粉壁图仙鹤，昂藏真气多。\n𬸣飞竟不去，当是恋恩波。' },
  { title: '广州朱长史座观妓', author: '宋之问', poem: '歌舞须连夜，神仙莫放归。\n参差随暮雨，前路湿人衣。' },
  { title: '谒二妃庙', author: '宋之问', poem: '还以金屋贵，留兹宝席尊。\n江凫啸风雨，山鬼泣朝昏。' },
  { title: '赠严侍御', author: '宋之问', poem: '受脤清边服，乘骢历塞尘。\n当闻汉雪耻，羞共虏和亲。' },
  { title: '在荆州重赴岭南', author: '宋之问', poem: '梦泽三秋日，苍梧一片云。\n还将鹓鹭羽，重入鹧鸪群。' },
  { title: '则天皇后挽歌', author: '宋之问', poem: '象物行周礼，衣冠集汉都。\n谁怜事虞舜，下里泣苍梧。' },
  { title: '邓国太夫人挽歌', author: '宋之问', poem: '鸾死铅妆歇，人亡锦字空。\n悲端若能减，渭水亦应穷。' },
  { title: '杨将军挽歌', author: '宋之问', poem: '亭寒照苦月，陇暗积愁云。\n今日山门树，何处有将军。' },
  { title: '塞垣行', author: '崔湜', poem: '疾风卷溟海，万里扬砂砾。\n仰望不见天，昏昏竟朝夕。\n是时军两进，东拒复西敌。\n蔽山张旗鼓，间道潜锋镝。\n精骑突晓围，奇兵袭暗壁。\n十月边塞寒，四山沍阴积。\n雨雪鴈南飞，风尘景西迫。\n昔我事讨论，未尝怠经籍。\n一朝弃笔砚，十年操矛戟。\n岂要黄河誓，须勒燕然石。\n可嗟牧羊臣，海上久为客。' },
  { title: '送梁卿王郎中使东蕃吊册', author: '崔湜', poem: '梁侯上卿秀，王子中台杰。\n赠册绥九夷，旌旃下双阙。\n西堂礼乐送，南陌轩车别。\n征路入海云，行舟溯江月。\n兹邦久钦化，历载归朝谒。\n皇心谅所嘉，寄尔宣风烈。' },
  { title: '饯唐州高使君赴任', author: '崔湜', poem: '芳春桃李时，京都物华好。\n为岳岂不贵，所悲涉远道。\n远道不可思，宿昔梦见之。\n赠君双佩刀，日夕视来期。' },
  { title: '冀北春望', author: '崔湜', poem: '回首览燕赵，春生两河间。\n旷然万里余，际海不见山。\n雨歇青林润，烟空绿野闲。\n问乡何处所，目送白云还。' },
  { title: '景龙二年余自门下平章事削阶授江州员外司马寻拜襄州刺史春日赴襄阳途中言志', author: '崔湜', poem: '余本燕赵人，秉心愚且直。\n群籍备所见，孤贞每自饬。\n徇禄期代耕，受任亦量力。\n幸逢休明时，朝野两荐推。\n一朝趋金门，十载奉瑶墀。\n入掌迁固笔，出参枚马词。\n吏部既三践，中书亦五期。\n进无负鼎说，退慙补衮诗。\n常恐婴悔吝，不得少酬私。\n嗷嗷路傍子，纳谤纷无已。\n上动明主疑，下贻大臣耻。\n毫发顾无累，冰壶邈自持。\n天道何期平，幽冤终见明。\n始佐庐陵郡，寻牧襄阳城。\n彤帏荷新宠，朱黻蒙旧荣。\n力薄慙任重，恩深知命轻。\n饬徒留前路，行子悲且慕。\n犹闻长乐钟，尚辨青门树。\n慈亲不忍诀，昆弟默相顾。\n去去勿重陈，川长日云暮。' },
  { title: '大漠行', author: '崔湜', poem: '单于犯蓟堧，骠骑略萧边。\n南山木叶飞下地，北海蓬根乱上天。\n科斗连营太原道，鱼丽合阵武威川。\n三军遥倚杖，万里相驰逐。\n旌斾悠悠静瀚源，鼙鼓喧喧动卢谷。\n穷徼上幽陵，吁嗟倦寝兴。\n马蹄冻溜石，胡毳暖生冰。\n云沙泱漭天光闭，河塞阴沈海色凝。\n崆峒异国谁能托，萧索边心常不乐。\n近见行人畏白龙，遥闻公主愁黄鹤。\n阳春半，岐路间。\n瑶台苑，玉门关。\n百花芳树红将歇，二月兰皐绿未还。\n阵云不散鱼龙水，雨雪犹飞鸿鴈山。\n山嶂连緜不可极，路远辛勤梦颜色。\n北堂萱草不寄来，东园桃李长相忆。\n汉将纷纭攻战盈，胡寇萧条幽朔清。\n韩君拜节偏知远，郑吉驱旌坐见迎。\n火绝烟沈右西极，谷静山空左北平。\n但使将军能百战，不须天子筑长城。' },
  { title: '奉和登骊山高顶寓目应制', author: '崔湜', poem: '名山何壮哉，玄览一徘徊。\n御路穿林转，旌门倚石开。\n烟霞肘后发，河塞掌中来。\n不学蓬壶远，经年犹未回。' },
  { title: '侍宴长宁公主东庄应制', author: '崔湜', poem: '沁园东郭外，鸾驾一游盘。\n水榭宜时陟，山楼向晚看。\n席临天女贵，杯接近臣欢。\n圣藻悬宸象，微臣窃仰观。' },
  { title: '奉和送金城公主适西蕃应制', author: '崔湜', poem: '怀戎前策备，降女旧因修。\n箫鼓辞家怨，旌旃出塞愁。\n尚孩中念切，方远御慈留。\n顾乏谋臣用，仍劳圣主忧。' },
  { title: '幸白鹿观应制', author: '崔湜', poem: '御旗探紫箓，仙杖辟丹丘。\n捧药芝童下，焚香桂女留。\n鸾歌无岁月，鹤语记春秋。\n臣朔真何幸，常陪汉武游。' },
  { title: '幸梨园亭观打毬应制', author: '崔湜', poem: '年光陌上发，香辇禁中游。\n草绿鸳鸯殿，花明翡翠楼。\n宝杯承露酌，仙管杂风流。\n今日陪欢豫，皇恩不可酬。' },
  { title: '慈恩寺九日应制', author: '崔湜', poem: '帝里重阳节，香园万乘来。\n却邪萸结佩，献寿菊传杯。\n塔类承天涌，门疑待佛开。\n睿词悬日月，长得仰昭回。' },
  { title: '折杨柳', author: '崔湜', poem: '二月风光半，三边戍不还。\n年华妾自惜，杨柳为君攀。\n落絮萦衫袖，垂条拂髻鬟。\n那堪音信断，流涕望阳关。' },
  { title: '边愁', author: '崔湜', poem: '九月蓬根断，三边草叶腓。\n风尘马变色，霜雪劒生衣。\n客思愁阴晚，边书驿骑归。\n殷勤凤楼上，还袂及春晖。' },
  { title: '婕妤怨', author: '崔湜', poem: '不分君恩断，新妆视镜中。\n容华尚春日，娇爱已秋风。\n枕席临窗晓，帷屏向月空。\n年年后庭树，荣落在深宫。' },
  { title: '酬杜麟台春思', author: '崔湜', poem: '春还上林苑，花满洛阳城。\n鸳衾夜凝思，龙镜晓含情。\n忆梦残灯落，离魂暗马惊。\n可怜朝与暮，楼上独盈盈。' },
  { title: '寄天台司马先生', author: '崔湜', poem: '闻有三元客，祈仙九转成。\n人间白云返，天上赤龙迎。\n尚惜金芝晚，仍攀琪树荣。\n何年缑岭上，一谢洛阳城。' },
  { title: '唐都尉山池', author: '崔湜', poem: '曲渚飏轻舟，前谿钓晚流。\n鴈翻蒲叶起，鱼拨荇花游。\n金子悬湘柚，珠房折海榴。\n幽寻惜未已，清月半西楼。' },
  { title: '江楼夕望', author: '崔湜', poem: '试陟江楼望，悠悠去国情。\n楚山霞外断，汉水月中平。\n公子留遗邑，夫人有旧城。' },
  { title: '襄城即事', author: '崔湜', poem: '子牟怀魏阙，元凯滞襄城。\n冠盖仍为里，沙台尚识名。\n山光晴后绿，江色晚来清。' },
  { title: '秦州薛都督挽词', author: '崔湜', poem: '十里绛山幽，千年汾水流。\n碑传门客见，劒是故人留。\n陇树烟含夕，山门月照秋。\n古来钟鼎盛，共尽一嵩丘。' },
  { title: '奉和春日幸望春宫', author: '崔湜', poem: '澹荡春光满晓空，逍遥御辇入离宫。\n山河眺望云天外，台榭参差烟雾中。\n庭际花飞锦绣合，枝间鸟啭管弦同。\n即此欢娱齐镐宴，唯应率舞乐薰风。' },
  { title: '奉和幸韦嗣立山庄侍宴应制', author: '崔湜', poem: '丞相登前府，尚书启旧林。\n式闾明主睿，荣族圣嫔心。\n川狭旌门抵，岩高蔽帐临。\n闲窗凭柳暗，小径入松深。\n云卷千峰色，泉和万籁吟。\n兰迎天女佩，竹碍侍臣簪。\n宸翰三光烛，朝荣四海钦。\n还嗟绝机叟，白首汉川阴。' },
  { title: '同李员外春闺', author: '崔湜', poem: '落日啼连夜，孤灯坐彻明。\n卷帘双燕入，披幌百花惊。\n陇上寒应晚，闺中织未成。\n管弦愁不意，梳洗懒无情。\n去岁闻西伐，今年送北征。\n容颜离别尽，流恨满长城。' },
  { title: '襄阳早秋寄岑侍郎', author: '崔湜', poem: '江城秋气早，旭旦坐南闱。\n落叶惊衰鬓，清霜换旅衣。\n时来矜早达，事往觉前非。\n体道徒推理，防身终昧微。\n故人金华省，肃穆秉天机。\n谁念江汉广，蹉跎心事违。' },
  { title: '赠苏少府赴任江南余时还京', author: '崔湜', poem: '丈夫不叹别，达士自安卑。\n揽泣固无趣，衔杯空尔为。\n流云春窈窕，去水暮逶迤。\n行舟忽东泛，归骑亦西驰。\n秦地多芳草，江潭有桂枝。\n谁言阻遐阔，所贵在相知。' },
  { title: '登总持寺阁', author: '崔湜', poem: '宿雨清龙界，晨晖满凤城。\n升攀重阁迥，凭览四郊明。\n井邑周秦地，山河今古情。\n纡余一水合，寥落五陵平。\n处处风烟起，欣欣草木荣。\n故人不可见，冠盖满东京。' },
  { title: '早春边城怀归', author: '崔湜', poem: '大漠羽书飞，长城未解围。\n山川凌玉嶂，旌节下金微。\n路向南庭远，书因北鴈稀。\n乡关摇别思，风雪散戎衣。\n岁尽仍为客，春还尚未归。\n明年征骑返，歌舞及芳菲。' },
  { title: '至桃林塞作', author: '崔湜', poem: '去国未千里，离家已再旬。\n丹心恒恋阙，白首更辞亲。\n怀璧常贻训，捐金讵得邻。\n抱冤非忤物，罹谤岂由人。\n不滥辞终辨，无瑕理竟伸。\n黻还中省旧，符与外台新。\n塞上同迁客，江潭异逐臣。\n泪垂非属岘，肠断固由秦。\n岁月行遒尽，山川难重陈。\n始知亭伯去，还是拙谋身。' },
  { title: '襄阳作', author: '崔湜', poem: '庙堂初解印，郡邸忽腰章。\n按节巡河右，鸣驺入汉阳。\n城临南岘出，树绕北津长。\n好学风犹扇，夸才俗未忘。\n江山跨七泽，烟雨接三湘。\n蛟浦菱荷净，渔舟橘柚香。\n醉中求习氏，梦里忆襄王。\n宅坏仍思凤，碑存更忆羊。\n下车慙政美，闭阁幸时康。\n多谢南征术，于今尚不亡。' },
  { title: '喜入长安', author: '崔湜', poem: '云日能催晓，风光不惜年。\n赖逢征客尽，归在落花前。' },
  { title: '奉和幸韦嗣立山庄应制', author: '崔湜', poem: '竹径桃源本出尘，松轩茅栋别惊新。\n御跸何须林下驻，山公不是俗中人。' },
  { title: '踏歌词二首 一', author: '崔液', poem: '彩女迎金屋，仙姬出画堂。\n鸳鸯裁锦袖，翡翠贴花黄。\n歌响舞分行，艳色动流光。' },
  { title: '踏歌词二首 二', author: '崔液', poem: '庭际花微落，楼前汉已横。\n金台催夜尽，罗袖拂寒轻。\n乐笑畅欢情，未半着天明。' },
  { title: '代春闺', author: '崔液', poem: '江南日暖鸿始来，柳条初碧叶半开。\n玉关遥遥戍未回，金闺日夕生绿苔。\n寂寂春花烟色暮，檐燕双双落花度。\n青楼明镜昼无光，红帐罗衣徒自香。\n妾恨十年长独守，君情万里在渔阳。' },
  { title: '上元夜六首 一', author: '崔液', poem: '玉漏银壶且莫催，铁关金锁彻明开。\n谁家见月能闲坐，何处闻灯不看来。' },
  { title: '上元夜六首 二', author: '崔液', poem: '神灯佛火百轮张，刻像图形七宝装。\n影里如闻金口说，空中似散玉毫光。' },
  { title: '上元夜六首 三', author: '崔液', poem: '今年春色胜常年，此夜风光最可怜。\n𫛛鹊楼前新月满，凤皇台上宝灯燃。' },
  { title: '上元夜六首 四', author: '崔液', poem: '金勒银鞍控紫骝，玉轮珠幰驾青牛。\n骖驔始散东城曲，倏忽还来南陌头。' },
  { title: '上元夜六首 五', author: '崔液', poem: '公子王孙意气骄，不论相识也相邀。\n最怜长袖风前弱，更赏新弦暗里调。' },
  { title: '上元夜六首 六', author: '崔液', poem: '星移汉转日将微，露洒烟飘灯渐稀。\n犹惜路傍歌舞处，踌蹰相顾不能归。' },
  { title: '冀北春望', author: '崔液', poem: '回首览燕赵，春生两河间。\n旷然余万里，际海不见山。\n雨歇青林润，烟空绿野闲。\n问乡无处所，目送白云关。' },
  { title: '拟古神女宛转歌二首 一', author: '崔液', poem: '风已清，月朗琴复明。\n掩抑悲千态，殷勤是一声。\n歌宛转，宛转和更长。\n愿为双鸿鹄，比翼共翱翔。' },
  { title: '拟古神女宛转歌二首 二', author: '崔液', poem: '日已暮，长檐鸟应度。\n此时望君君不来，此时思君君不顾。\n歌宛转，宛转那能异栖宿。\n愿为形与影，出入恒相逐。' },
  { title: '望韩公堆', author: '崔涤', poem: '韩公堆上望秦川，渺渺关山西接连。\n孤客一身千里外，未知归日是何年。' },
  { title: '倬彼我系 一', author: '王勃', poem: '倬彼我系，出自有周。\n分疆锡社，派别支流。\n居衞仕宋，臣嬴相刘。\n廼武廼文，或公或侯。' },
  { title: '倬彼我系 二', author: '王勃', poem: '晋历崩坼，衣冠扰弊。\n粤自太原，播徂江澨。\n礼丧贤隐，时屯道闭。\n王室如毁，生人多殪。' },
  { title: '倬彼我系 三', author: '王勃', poem: '伊我有器，思逢其主。\n自东施西，择木开宇。\n田彼河曲，家乎汾浦。\n天未厌乱，吾将谁辅。' },
  { title: '倬彼我系 四', author: '王勃', poem: '伊我祖德，思济九埏。\n不常厥所，于兹五迁。\n欲及时也，夫岂愿焉。\n其位虽屈，其言则传。' },
  { title: '倬彼我系 五', author: '王勃', poem: '爰述帝制，大搜王道。\n曰天曰人，是祖是考。\n礼乐咸若，诗书具草。\n贻厥孙谋，永为家宝。' },
  { title: '倬彼我系 六', author: '王勃', poem: '伊余小子，信慙明哲。\n彼网有条，彼车有辙。\n思屏人事，克终前烈。\n于嗟代网，卒余来絏。' },
  { title: '倬彼我系 七', author: '王勃', poem: '来絏伊何，谓余曰仕。\n我瞻先达，三十方起。\n夫岂不怀，高山仰止。\n愿言毓德，啜菽饮水。' },
  { title: '倬彼我系 八', author: '王勃', poem: '有鸟反哺，其声嗷嗷。\n言念旧德，忧心忉忉。\n今我不养，岁月其滔。\n僶俛从役，岂敢告劳。' },
  { title: '倬彼我系 九', author: '王勃', poem: '从役伊何，薄求卑位。\n告劳伊何，来参卿事。\n名存实爽，负信愆义。\n静言遐思，中心是愧。' },
  { title: '上巳浮江宴韵得阯字', author: '王勃', poem: '披观玉京路，驻赏金台阯。\n逸兴怀九仙，良辰倾四美。\n松吟白云际，桂馥青溪里。\n别有江海心，日暮情何已。' },
  { title: '春日宴乐游园赋韵得接字', author: '王勃', poem: '帝里寒光尽，神臯春望浃。\n梅郊落晚英，柳甸惊初叶。\n流水抽奇弄，崩云洒芳牒。\n清尊湛不空，暂喜平生接。' },
  { title: '山亭夜宴', author: '王勃', poem: '桂宇幽襟积，山亭凉夜永。\n森沈野径寒，肃穆岩扉静。\n竹晦南汀色，荷翻北潭影。\n清兴殊未阑，林端照初景。' },
  { title: '咏风', author: '王勃', poem: '肃肃凉景生，加我林壑清。\n驱烟寻磵户，卷雾出山楹。\n去来固无迹，动息如有情。\n日落山水静，为君起松声。' },
  { title: '怀仙', author: '王勃', poem: '鹤岑有奇径，麟洲富仙家。\n紫泉漱珠液，玄岩列丹葩。\n常希披尘网，眇然登云车。\n鸾情极霄汉，凤想疲烟霞。\n道存蓬瀛近，意惬朝市赊。\n无为坐惆怅，虚此江上华。' },
  { title: '忽梦游仙', author: '王勃', poem: '仆本江上客，牵迹在方内。\n寤寐霄汉间，居然有灵对。\n翕尔登霞首，依然蹑云背。\n电策驱龙光，烟途俨鸾态。\n乘月披金帔，连星解琼珮。\n浮识俄易归，真游邈难再。\n寥廓沈遐想，周遑奉遗诲。\n流俗非我乡，何当释尘昧。' },
  { title: '杂曲', author: '王勃', poem: '智琼神女，来访文君。\n蛾眉始约，罗袖初薰。\n歌齐曲韵，舞乱行纷。\n若向阳台荐枕，何啻得胜朝云。' },
  { title: '秋夜长', author: '王勃', poem: '秋夜长，殊未央。\n月明白露澄清光，层城绮阁遥相望。\n遥相望，川无梁。\n北风受节南雁翔，崇兰委质时菊芳。\n鸣环曳履出长廊，为君秋夜捣衣裳。\n纤罗对凤皇，丹绮双鸳鸯。\n调砧乱杵思自伤，思自伤，征夫万里戍他乡。\n鹤关音信断，龙门道路长。\n君在天一方，寒衣徒自香。' },
  { title: '采莲曲', author: '王勃', poem: '采莲归，绿水芙蓉衣。\n秋风起浪凫雁飞，桂櫂兰桡下长浦。\n罗裙玉腕轻摇橹，叶屿花潭极望平。\n江讴越吹相思苦，相思苦，佳期不可驻。\n塞外征夫犹未还，江南采莲今已暮。\n今已暮，采莲花，渠今那必尽娼家。\n官道城南把桑叶，何如江上采莲花。\n莲花复莲花，花叶何稠叠。\n叶翠本羞眉，花红强如颊。\n佳人不在兹，怅望别离时。\n牵花怜共蒂，折藕爱连丝。\n故情无处所，新物从华滋。\n不惜西津交佩解，还羞北海雁书迟。\n采莲歌有节，采莲夜未歇。\n正逢浩荡江上风，又值裴回江上月。\n裴回莲浦夜相逢，吴姬越女何丰茸。\n共问寒江千里外，征客关山路几重。' },
  { title: '临高台', author: '王勃', poem: '临高台，高台迢遰绝浮埃。\n瑶轩绮构何崔嵬，鸾歌凤吹清且哀。\n俯瞰长安道，萋萋御沟草。\n斜对甘泉路，苍苍茂陵树。\n高台四望同，帝乡佳气郁葱葱。\n紫阁丹楼纷照耀，璧房锦殿相玲珑。\n东弥长乐观，西指未央宫。\n赤城映朝日，绿树摇春风。\n旗亭百隧开新市，甲第千甍分戚里。\n朱轮翠盖不胜春，叠榭层楹相对起。\n复有青楼大道中，绣户文窗雕绮栊。\n锦衾夜不襞，罗帷昼未空。\n歌屏朝揜翠，妆镜晚窥红。\n为君安宝髻，蛾眉罢花丛。\n尘间狭路黯将暮，云间月色明如素。\n鸳鸯池上两两飞，凤凰楼下双双度。\n物色正如此，佳期那不顾。\n银鞍绣毂盛繁华，可怜今夜宿娼家。\n娼家少妇不须颦，东园桃李片时春。\n君看旧日高台处，柏梁铜雀生黄尘。' },
  { title: '滕王阁', author: '王勃', poem: '滕王高阁临江渚，珮玉鸣鸾罢歌舞。\n画栋朝飞南浦云，珠帘暮卷西山雨。\n闲云潭影日悠悠，物换星移几度秋。\n阁中帝子今何在？槛外长江空自流。' },
  { title: '江南弄', author: '王勃', poem: '江南弄，巫山连楚梦，行雨行云几相送。\n瑶轩金谷上春时，玉童仙女无见期。\n紫露香烟渺难托，清风明月遥相思。\n遥相思，草徒绿，为听双飞凤凰曲。' },
  { title: '圣泉宴', author: '王勃', poem: '披襟乘石磴，列籍俯春泉。\n兰气熏山酌，松声韵野弦。\n影飘垂叶外，香度落花前。\n兴洽林塘晚，重岩起夕烟。' },
  { title: '寻道观', author: '王勃', poem: '芝廛光分野，蓬阙盛规模。\n碧坛清桂阈，丹洞肃松枢。\n玉笈三山记，金箱五岳图。\n苍虬不可得，空望白云衢。' },
  { title: '散关晨度', author: '王勃', poem: '关山凌旦开，石路无尘埃。\n白马高谭去，青牛真气来。\n重门临巨壑，连栋起崇隈。\n即今扬策度，非是弃𦈡回。' },
  { title: '别薛华', author: '王勃', poem: '送送多穷路，遑遑独问津。\n悲凉千里道，凄断百年身。\n心事同漂泊，生涯共苦辛。\n无论去与住，俱是梦中人。' },
  { title: '重别薛华', author: '王勃', poem: '明月沈珠浦，秋风濯锦川。\n楼台临绝岸，洲渚亘长天。\n旅泊成千里，栖遑共百年。\n穷途唯有泪，还望独潸然。' },
  { title: '游梵宇三觉寺', author: '王勃', poem: '杏阁披青磴，雕台控紫岑。\n叶齐山路狭，花积野坛深。\n萝幌栖禅影，松门听梵音。\n遽忻陪妙躅，延赏涤烦襟。' },
  { title: '麻平晚行', author: '王勃', poem: '百年怀土望，千里倦游情。\n高低寻戍道，远近听泉声。\n磵叶才分色，山花不辨名。\n羁心何处尽？风急暮猨清。' },
  { title: '送卢主簿', author: '王勃', poem: '穷途非所恨，虚室自相依。\n城阙居年满，琴尊俗事稀。\n开襟方未已，分袂忽多违。\n东岩富松竹，岁暮幸同归。' },
  { title: '饯韦兵曹', author: '王勃', poem: '征骖临野次，别袂惨江垂。\n川霁浮烟歛，山明落照移。\n鹰风凋晚叶，蝉露泣秋枝。\n亭臯分远望，延想间云涯。' },
  { title: '白下驿饯唐少府', author: '王勃', poem: '下驿穷交日，昌亭旅食年。\n相知何用早，怀抱即依然。\n浦楼低晚照，乡路隔风烟。\n去去如何道，长安在日边。' },
  { title: '杜少府之任蜀州', author: '王勃', poem: '城阙辅三秦，风烟望五津。\n与君离别意，同是宦游人。\n海内存知己，天涯若比隣。\n无为在岐路，儿女共沾巾。' },
  { title: '仲春郊外', author: '王勃', poem: '东园垂柳径，西堰落花津。\n物色连三月，风光绝四隣。\n鸟飞村觉曙，鱼戏水知春。' },
  { title: '郊兴', author: '王勃', poem: '空园歌独酌，春日赋闲居。\n泽兰侵小径，河柳覆长渠。\n雨去花光湿，风归叶影疎。\n山人不惜醉，唯畏绿尊虚。' },
  { title: '郊园即事', author: '王勃', poem: '烟霞春旦赏，松竹故年心。\n断山疑画障，县溜泻鸣琴。\n草徧南亭合，花开北院深。\n闲居饶酒赋，随兴欲抽簪。' },
  { title: '观佛迹寺', author: '王勃', poem: '莲座神容俨，松崖圣趾余。\n年长金迹浅，地久石文疎。\n颓华临曲磴，倾影赴前除。\n共嗟陵谷远，俄视化城虚。' },
  { title: '山居晚眺赠王道士', author: '王勃', poem: '金坛疎俗宇，玉洞侣仙群。\n花枝栖晚露，峰叶度晴云。\n斜照移山影，回沙拥籀文。\n琴尊方待兴，竹树已迎曛。' },
  { title: '八仙迳', author: '王勃', poem: '柰园欣八正，松岩访九仙。\n援萝窥雾术，攀林俯云烟。\n代北鸾骖至，辽西鹤骑旋。\n终希脱尘网，连翼下芝田。' },
  { title: '春日还郊', author: '王勃', poem: '闲情兼嘿语，携杖赴岩泉。\n草绿萦新带，榆青缀古钱。\n鱼床侵岸水，鸟路入山烟。\n还题平子赋，花树满春田。' },
  { title: '对酒春园作', author: '王勃', poem: '投簪下山阁，携酒对河梁。\n狭水牵长镜，高花送断香。\n繁莺歌似曲，疎蝶舞成行。\n自然催一醉，非但阅年光。' },
  { title: '观内怀仙', author: '王勃', poem: '玉架残书隐，金坛旧迹迷。\n牵花寻紫涧，步叶下清谿。\n琼浆犹类乳，石髓尚如泥。\n自能成羽翼，何必仰云梯。' },
  { title: '秋日别王长史', author: '王勃', poem: '别路余千里，深恩重百年。\n正悲西候日，更动北梁篇。\n野色笼寒雾，山光歛暮烟。\n终知难再奉，怀德自潸然。' },
  { title: '上巳浮江宴韵得遥字', author: '王勃', poem: '上巳年光促，中川兴绪遥。\n绿齐山叶满，红泄片花销。\n泉声喧后涧，虹影照前桥。\n遽悲春望远，江路积波潮。' },
  { title: '长柳', author: '王勃', poem: '晨征犯烟磴，夕憩在云关。\n晚风清近壑，新月照澄湾。\n郊童樵唱返，津叟钓歌还。\n客行无与晤，赖此释愁颜。' },
  { title: '铜雀妓二首 一', author: '王勃', poem: '金凤隣铜雀，漳河望邺城。\n君王无处所，台榭若平生。\n舞席纷何就，歌梁俨未倾。\n西陵松槚冷，谁见绮罗情。' },
  { title: '铜雀妓二首 二', author: '王勃', poem: '妾本深宫妓，层城闭九重。\n君王欢爱尽，歌舞为谁容。\n锦衾不复襞，罗衣谁再缝。\n高台西北望，流涕向青松。' },
  { title: '羁游饯别', author: '王勃', poem: '客心悬陇路，游子倦江干。\n槿丰朝砌静，筿密夜窗寒。\n琴声销别恨，风景驻离欢。\n宁觉山川远，悠悠旅思难。' },
  { title: '易阳早发', author: '王勃', poem: '饬装侵晓月，奔策候残星。\n危阁寻丹障，回梁属翠屏。\n云间迷树影，雾里失峰形。\n复此凉飙至，空山飞夜萤。' },
  { title: '焦岸早行和陆四', author: '王勃', poem: '侵星违旅馆，乘月戒征俦。\n复嶂迷晴色，虚岩辨暗流。\n猿吟山漏晓，萤散野风秋。\n故人渺何际，乡关云雾浮。' },
  { title: '深湾夜宿', author: '王勃', poem: '津涂临巨壑，村宇架危岑。\n堰绝滩声隐，风交树影深。\n江童暮理楫，山女夜调砧。\n此时故乡远，宁知游子心。' },
  { title: '伤裴录事丧子', author: '王勃', poem: '兰阶霜候早，松露穸台深。\n魄散珠胎没，芳销玉树沈。\n露文晞宿草，烟照惨平林。\n芝焚空欢息，流恨满籝金。' },
  { title: '泥谿', author: '王勃', poem: '弭櫂凌奔壑，低鞭蹑峻岐。\n江涛出岸险，峰磴入云危。\n溜急船文乱，岩斜骑影移。\n水烟笼翠渚，山照落丹崖。\n风生苹浦叶，露泣竹潭枝。\n泛水虽云美，劳歌谁复知。' },
  { title: '三月曲水宴得烟字', author: '王勃', poem: '彭泽官初去，河阳赋始传。\n田园归旧国，诗酒间长筵。\n列室窥丹洞，分楼瞰紫烟。\n萦回亘津渡，出没控郊鄽。\n凤琴调上客，龙辔俨群仙。\n松石偏宜古，藤萝不记年。\n重檐交密树，复磴拥危泉。\n抗石晞南岭，乘沙眇北川。\n傅岩来筑处，磻谿入钓前。\n日斜真趣远，幽思梦凉蝉。' },
  { title: '秋日仙游观赠道士', author: '王勃', poem: '石图分帝宇，银牒洞灵宫。\n回丹萦岫室，复翠上岩栊。\n雾浓金灶静，云暗玉坛空。\n野花常捧露，山叶自吟风。\n林泉明月在，诗酒故人同。\n待余逢石髓，从尔命飞鸿。' },
  { title: '晚留凤州', author: '王勃', poem: '宝鸡辞旧役，仙凤历遗墟。\n去此近城阙，青山明月初。' },
  { title: '羁春', author: '王勃', poem: '客心千里倦，春事一朝归。\n还伤北园里，重见落花飞。' },
  { title: '林塘怀友', author: '王勃', poem: '芳屏画春草，仙杼织朝霞。\n何如山水路，对面即飞花。' },
  { title: '山扉夜坐', author: '王勃', poem: '抱琴开野室，携酒对情人。\n林塘花月下，别似一家春。' },
  { title: '春庄', author: '王勃', poem: '山中兰叶径，城外李桃园。\n岂知人事静，不觉鸟声喧。' },
  { title: '春游', author: '王勃', poem: '客念纷无极，春泪倍成行。\n今朝花树下，不觉恋年光。' },
  { title: '春园', author: '王勃', poem: '山泉两处晚，花柳一园春。\n还持千日醉，共作百年人。' },
  { title: '林泉独饮', author: '王勃', poem: '丘壑经涂赏，花柳遇时春。\n相逢今不醉，物色自轻人。' },
  { title: '登城春望', author: '王勃', poem: '物外山川近，晴初景霭新。\n芳郊花柳遍，何处不宜春。' },
  { title: '他乡叙兴', author: '王勃', poem: '缀叶归烟晚，乘花落照春。\n边城琴酒处，俱是越乡人。' },
  { title: '夜兴', author: '王勃', poem: '野烟含夕渚，山月照秋林。\n还将中散兴，来偶步兵琴。' },
  { title: '临江二首 一', author: '王勃', poem: '泛泛东流水，飞飞北上尘。\n归骖将别櫂，俱是倦游人。' },
  { title: '临江二首 二', author: '王勃', poem: '去骖嘶别路，归櫂隐寒洲。\n江臯木叶下，应想故城秋。' },
  { title: '江亭夜月送别二首 一', author: '王勃', poem: '江送巴南水，山横塞北云。\n津亭秋月夜，谁见泣离群。' },
  { title: '江亭夜月送别二首 二', author: '王勃', poem: '乱烟笼碧砌，飞月向南端。\n寂寂离亭掩，江山此夜寒。' },
  { title: '别人四首 一', author: '王勃', poem: '久客逢余闰，他乡别故人。\n自然堪下泪，谁忍望征尘。' },
  { title: '别人四首 二', author: '王勃', poem: '江上风烟积，山幽云雾多。\n送君南浦外，还望将如何。' },
  { title: '别人四首 三', author: '王勃', poem: '桂轺虽不驻，兰筵幸未开。\n林塘风月赏，还待故人来。' },
  { title: '别人四首 四', author: '王勃', poem: '霜华净天末，雾色笼江际。\n客子常畏人，何为久留滞。' },
  { title: '赠李十四四首 一', author: '王勃', poem: '野客思茅宇，山人爱竹林。\n琴尊唯待处，风月自相寻。' },
  { title: '赠李十四四首 二', author: '王勃', poem: '小径偏宜草，空庭不厌花。\n平生诗与酒，自得会仙家。' },
  { title: '赠李十四四首 三', author: '王勃', poem: '乱竹开三径，飞花满四邻。\n从来扬子宅，别有尚玄人。' },
  { title: '赠李十四四首 四', author: '王勃', poem: '风筵调桂轸，月径引藤杯。\n直当花院里，书斋望晓开。' },
  { title: '早春野望', author: '王勃', poem: '江旷春潮白，山长晓岫青。\n他乡临睨极，花柳映边亭。' },
  { title: '山中', author: '王勃', poem: '长江悲已滞，万里念将归。\n况属高风晚，山山黄叶飞。' },
  { title: '冬郊行望', author: '王勃', poem: '桂密岩花白，梨疎林叶红。\n江臯寒望尽，归念断征篷。' },
  { title: '寒夜思友三首 一', author: '王勃', poem: '久别侵怀抱，他乡变容色。\n月下调鸣琴，相思此何极。' },
  { title: '寒夜思友三首 二', author: '王勃', poem: '云间征思断，月下归愁切。\n鸿雁西南飞，如何故人别。' },
  { title: '寒夜思友三首 三', author: '王勃', poem: '朝朝翠山下，夜夜苍江曲。\n复此遥相思，清尊湛芳绿。' },
  { title: '始平晚息', author: '王勃', poem: '观阙长安近，江山蜀路赊。\n客行朝复夕，无处是乡家。' },
  { title: '扶风昼届离京浸远', author: '王勃', poem: '帝里金茎去，扶风石柱来。\n山川殊未已，行路方悠哉。' },
  { title: '普安建阴题壁', author: '王勃', poem: '江汉深无极，梁岷不可攀。\n山川云雾里，游子几时还。' },
  { title: '九日', author: '王勃', poem: '九日重阳节，开门有菊花。\n不知来送酒，若个是陶家。' },
  { title: '秋江送别二首 一', author: '王勃', poem: '早是他乡值早秋，江亭明月带江流。\n已觉逝川伤别念，复看津树隐离舟。' },
  { title: '秋江送别二首 二', author: '王勃', poem: '归舟归骑俨成行，江南江北互相望。\n谁谓波澜才一水，已觉山川是两乡。' },
  { title: '蜀中九日', author: '王勃', poem: '九月九日望乡台，他席他乡送客杯。\n人情已厌南中苦，鸿雁那从北地来。' },
  { title: '寒夜怀友杂体二首 一', author: '王勃', poem: '北山烟雾始茫茫，南津霜月正苍苍。\n秋深客思纷无已，复值征鸿中夜起。' },
  { title: '寒夜怀友杂体二首 二', author: '王勃', poem: '复阁重楼向浦开，秋风明月度江来。\n故人故情怀故宴，相望相思不相见。' },
  { title: '落花落', author: '王勃', poem: '落花落，落花纷漠漠。\n绿叶青跗映丹萼，与君裴回上金阁。\n影拂粧阶玳瑁筵，香飘舞馆茱萸幙。\n落花飞，撩乱入中帷。\n落花春正满，春人归不归。\n落花度，氛氲遶高树。\n落花春已繁，春人春不顾。\n绮阁青台静且闲，罗袂红巾复往还。\n盛年不再得，高枝难重攀。\n试复旦游落花里，暮宿落花间。\n与君落花院，台上起双鬟。' },
  { title: '九日怀封元寂', author: '王勃', poem: '九日郊原望，平野遍霜威。\n兰气添新酌，花香染别衣。\n九秋良会少，千里故人稀。\n今日龙山外，当忆雁书归。' },
  { title: '出境游山二首 一', author: '王勃', poem: '源水终无路，山阿若有人。\n驱羊先动石，走兔欲投巾。\n洞晚秋泉冷，岩朝古树新。\n峰斜连鸟翅，磴叠上鱼鳞。\n化鹤千龄早，元龟六代春。\n浮云今可驾，沧海自成尘。' },
  { title: '出境游山二首 二', author: '王勃', poem: '振翮凌霜吹，正月伫天浔。\n回镳凌翠壑，飞轸控青岑。\n岩深灵灶没，涧毁石渠沈。\n宫阙云间近，江山物外临。\n玉坛栖暮夜，珠洞结秋阴。\n萧萧离俗影，扰扰望乡心。\n谁意山游好屡伤人事侵。' },
  { title: '河阳桥代窦郎中佳人答杨中舍', author: '王勃', poem: '披风听鸟长河路，临津织女遥相妬。\n判知秋夕带啼还，那及春朝携手度。' },
  { title: '晦日宴高氏林亭同用华字', author: '王勔', poem: '上序披林馆，中京视物华。\n竹窗低露叶，梅迳起风花。\n景落春台雾，池侵旧渚沙。\n绮筵歌吹晚，暮雨泛香车。' },
  { title: '奉教追赴九成宫途中口号', author: '李峤', poem: '委质承仙翰，衹命遄遥策。\n事偶从梁游，人非背淮客。\n长驱历川阜，迥眺穷原泽。\n郁郁桑柘繁，油油禾黍积。\n雨余林气静，日下山光夕。\n未攀丛桂岩，犹倦飘蓬陌。\n行当奉麾盖，慰此劳行役。' },
  { title: '秋山望月酬李骑曹', author: '李峤', poem: '愁客坐山隈，怀抱自悠哉。\n况复高秋夕，明月正裴回。\n亭亭出迥岫，皎皎映层台。\n色带银河满，光含玉露开。\n淡云笼影度，虚晕抱轮回。\n谷邃凉阴静，山空夜响哀。\n寒催数雁过，风送一萤来。\n独轸离居恨，遥想故人杯。' },
  { title: '和同府李祭酒休沐田居', author: '李峤', poem: '列位簪缨序，隐居林野躅。\n徇物爽全直，栖真昧均俗。\n若人兼吏隐，率性夷荣辱。\n地藉朱邸基，家在青山足。\n暂弭西园盖，言事东臯粟。\n筑室俯涧滨，开扉面岩曲。\n庭幽引夕雾，檐迥通晨旭。\n迎秋谷黍黄，含露园葵绿。\n胜情狎兰杜，雅韵锵金玉。\n伊我怀丘园，愿心从所欲。' },
  { title: '扈从还洛呈侍从群官', author: '李峤', poem: '四海帝王家，两都周汉室。\n观风昔来幸，御气今旋跸。\n雷奋六合开，天行万乘出。\n玄冥奉时驾，白拒参戎律。\n后队咽笳箫，前驱严罕罼。\n辉光射东井，禁令横西秩。\n帐殿别阳秋，旌门临甲乙。\n将交洛城雨，稍远长安日。\n邙巩云外来，咸秦雾中失。\n孟冬霜霰下，是月农功毕。\n天道向归余，皇情美阴隲。\n行存名岳礼，逓问高年疾。\n祝鸟既开罗，调人更张瑟。\n登原采讴诵，俯谷求才术。\n邑罕悬磬贫，山无挂瓢逸。\n施恩浃寰宇，展义该文质。\n德泽盛轩游，哀矜深禹恤。\n申歌地庐骇，献寿衢尊溢。\n瑞色抱氤氲，寒光变萧𫗋。\n宗枝旦奭辅，侍从王刘匹。\n竝辑蛟龙书，同簪凤皇笔。\n陶甄荷吹万，颂叹归明一。\n欢与道路长，顾随谈笑密。\n叨承廊庙选，谬齿夔龙弼。\n喜构大厦成，慙非栋隆吉。' },
  { title: '奉使筑朔方六州城率尔而作', author: '李峤', poem: '奉诏受边服，总徒筑朔方。\n驱彼犬羊族，正此戎夏疆。\n子来多悦豫，王事宁怠遑。\n三旬无愆期，百雉郁相望。\n雄视沙漠垂，有截北海阳。\n二庭已顿颡，五岭尽来王。\n驱车登崇墉，顾眄凌大荒。\n千里何萧条，草木自悲凉。\n凭轼讯古今，慨焉感兴亡。\n汉障缘河远，秦城入海长。\n顾无庙堂策，贻此中夏殃。\n道隐前业衰，运开今化昌。\n制为百王式，举合千载防。\n马牛被路隅，锋镝销战场。\n岂不怀贤劳，所图在永康。\n王事何为者，称代陈颂章。' },
  { title: '早发苦竹馆', author: '李峤', poem: '合沓岩嶂深，朦胧烟雾晓。\n荒阡下樵客，野猿惊山鸟。\n开门听潺湲，入径寻窈窕。\n栖鼯抱寒木，流萤飞暗筿。\n早霞稍霏霏，残月犹皎皎。\n行看远星稀，渐觉游氛少。\n我行抚轺传，兼得傍林沼。\n贪玩水石奇，不知川路渺。\n徒怜野心旷，讵恻浮年小。\n方解宠辱情，永托累尘表。' },
  { title: '安辑岭表事平罢归', author: '李峤', poem: '云端想京县，帝乡如可见。\n天涯望越台，海路几悠哉。\n六月飞鹏去，三年瑞雉来。\n境遥铜柱出，山险石门开。\n自我违瀍洛，瞻途屡挥霍。\n朝朝寒路多，夜夜征衣薄。\n白简承朝宪，朱方抚夷落。\n既弘天覆广，且谕皇恩博。\n皇恩溢外区，憬俗咏来苏。\n声朔臣天子，坛场拜老夫。\n降宫韬将略，黄石寝兵符。\n返斾收龙虎，空营集鸟乌。\n日落澄氛霭，凭高视襟带。\n东瓯抗于越，南斗临吴会。\n春色绕边陲，飞花出荒外。\n卉服纷如积，长川思游客。\n风生丹桂晚，云起苍梧夕。\n去舳舣清江，归轩趋紫陌。\n衣裳会百蛮，琛賮委重关。\n不学金刀使，空持宝劒还。' },
  { title: '鹧鸪', author: '李峤', poem: '可怜鹧鸪飞，飞向树南枝。\n南枝日照暖，北枝霜露滋。\n露滋不堪栖，使我常夜啼。\n愿逢云中鹤，衔我向寥廓。\n愿作城上乌，一年生九雏。\n何不旧巢住，枝弱不得去。\n何意道苦辛，客子常畏人。' },
  { title: '清明日龙门游泛', author: '李峤', poem: '晴晓国门通，都门蔼将发。\n纷纷洛阳道，南望伊川阙。\n衍漾乘和风，清明送芬月。\n林窥二山动，水见千龛越。\n罗袂罥杨丝，香桡犯苔发。\n群心行乐未，唯恐流芳歇。' },
  { title: '云', author: '李峤', poem: '大梁白云起，氛氲殊未歇。\n锦文触石来，盖影凌天发。\n烟煴万年树，掩映三秋月。\n会入大风歌，从龙赴圆阙。' },
  { title: '拟古东飞伯劳西飞燕', author: '李峤', poem: '传书青鸟迎箫凤，巫岭荆台数通梦。\n谁家窈窕住园楼，五马千金照陌头。\n罗裙玉珮当轩出，点翠施红竞春日。\n佳人二八盛舞歌，羞将百万呈双蛾。\n庭前芳树朝夕改，空驻妍华欲谁待。' },
  { title: '宝劒篇', author: '李峤', poem: '吴山开，越溪涸，三金合冶成宝锷。\n淬绿水，鉴红云，五采焰起光氛氲。\n背上铭为万年字，胸前点作七星文。\n龟甲参差白虹色，辘轳宛转黄金饰。\n骇犀中断宁方利，骏马群𬴂未拟直。\n风霜凛凛匣上清，精气遥遥斗间明。\n避灾朝穿晋帝屋，逃乱夜入楚王城。\n一朝运偶逢大仙，虎吼龙鸣腾上天。\n东皇提升紫微座，西皇佩下赤城田。\n承平久息干戈事，侥幸得充文武备。\n除灾辟患宜君王，益寿延龄后天地。' },
  { title: '汾阴行', author: '李峤', poem: '君不见昔日西京全盛时，汾阴后土亲祭祠。\n斋宫宿寝设储供，撞钟鸣鼓树羽旗。\n汉家五叶才且雄，宾延万灵朝九戎。\n栢梁赋诗高宴罢，诏书法驾幸河东。\n河东太守亲扫除，奉迎至尊导銮舆。\n五营夹道列容衞，三河纵观空里闾。\n回旌驻跸降灵场，焚香奠醑邀百祥。\n金鼎发色正焜煌，灵祇炜烨摅景光。\n埋玉陈牲礼神毕，举麾上马乘舆出。\n彼汾之曲嘉可游，木兰为楫桂为舟。\n櫂歌微吟彩鹢浮，箫鼓哀鸣白云秋。\n欢娱宴洽赐群后，家家复除户牛酒。\n声明动天乐无有，千秋万岁南山寿。\n自从天子向秦关，玉辇金车不复还。\n珠帘羽扇长寂寞，鼎湖龙髯安可攀。\n千龄人事一朝空，四海为家此路穷。\n豪雄意气今何在，坛场宫馆尽蒿篷。\n路逢故老长叹息，世事回环不可测。\n昔时青楼对歌舞，今日黄埃聚荆棘。\n山川满目泪沾衣，富贵荣华能几时。\n不见秪今汾水上，唯有年年秋雁飞。' },
  { title: '中宗降诞日长宁公主满月侍宴应制', author: '李峤', poem: '神龙见像日，仙凤养雏年。\n大火乘天正，明珠对月圆。\n作新金箧里，歌奏玉筐前。\n今日宜孙庆，还参祝寿篇。' },
  { title: '奉和送金城公主适西蕃应制', author: '李峤', poem: '汉帝抚戎臣，丝言命锦轮。\n还将弄机女，远嫁织皮人。\n曲怨关山月，妆消道路尘。\n所嗟秾李树，空对小榆春。' },
  { title: '侍宴长宁公主东庄应制', author: '李峤', poem: '别业临青甸，鸣銮降紫霄。\n长筵鹓鹭集，仙管凤皇调。\n树接南山近，烟含北渚遥。\n承恩咸已醉，恋赏未还镳。' },
  { title: '立春日侍宴内殿出剪彩花应制', author: '李峤', poem: '早闻年欲至，剪彩学芳辰。\n缀绿奇能似，裁红巧逼真。\n花从箧里发，叶向手中春。\n不与时光竞，何名天上人。' },
  { title: '奉和人日清晖阁宴群臣遇雪应制', author: '李峤', poem: '三阳偏胜节，七日最灵辰。\n行庆传芳蚁，升高缀彩人。\n阶前蓂候月，楼上雪惊春。\n今日衔天造，还疑上汉津。' },
  { title: '奉和春日游苑喜雨应制', author: '李峤', poem: '仙跸九成台，香筵万寿杯。\n一旬初降雨，二月早闻雷。\n叶向朝𬯀密，花含宿润开。\n幸承天泽豫，无使日光催。' },
  { title: '春日侍宴幸芙蓉园应制', author: '李峤', poem: '年光竹里遍，春色杏间遥。\n烟气笼青阁，流文荡画桥。\n飞花随蝶舞，艳曲伴鸎娇。\n今日陪欢豫，还疑陟紫霄。' },
  { title: '甘露殿侍宴应制', author: '李峤', poem: '月宇临丹地，云窗网碧纱。\n御筵陈桂醑，天酒酌榴花。\n水向浮桥直，城连禁苑斜。\n承恩恣欢赏，归路满烟霞。' },
  { title: '奉和七夕两仪殿会宴应制', author: '李峤', poem: '灵匹三秋会，仙期七夕过。\n查来人泛海，桥渡鹊填河。\n帝缕升银阁，天机罢玉梭。\n谁言七襄咏，重入五弦歌。' },
  { title: '奉和九月九日登慈恩寺浮图应制', author: '李峤', poem: '瑞塔千寻起，仙舆九日来。\n萸房陈宝席，菊橤散花台。\n御气鹏霄近，升高凤野开。\n天歌将梵乐，空里共裴回。' },
  { title: '闰九月九日幸总持寺登浮图应制', author: '李峤', poem: '闰节开重九，真游下大千。\n花寒仍荐菊，座晚更披莲。\n刹凤回雕辇，帆虹间彩旃。\n还将西梵曲，助入南薰弦。' },
  { title: '奉和骊山高顶寓目应制', author: '李峤', poem: '步辇陟山巅，山高入紫烟。\n忠臣还捧日，圣后欲扪天。\n迥识平陵树，低看华岳莲。\n帝乡应不远，空见白云悬。' },
  { title: '游禁苑陪幸临渭亭遇雪应制', author: '李峤', poem: '同云接野烟，飞雪暗长天。\n拂树添梅色，过楼助粉妍。\n光含班女扇，韵入楚王弦。\n六出迎仙藻，千箱荅瑞年。' },
  { title: '幸白鹿观应制', author: '李峤', poem: '驻跸三天路，回旃万仞谿。\n真庭群帝飨，洞府百灵栖。\n玉酒仙垆酿，金方暗壁题。\n伫看青鸟入，还陟紫云梯。' },
  { title: '送沙门弘景道俊玄奘还荆州应制', author: '李峤', poem: '三乘归净域，万骑饯通庄。\n就日离亭近，弥天别路长。\n荆南旋杖钵，渭北限津梁。\n何日纡真果，还来入帝乡。' },
  { title: '酬杜五弟晴朝独坐见赠', author: '李峤', poem: '平明坐虚馆，旷望几悠哉。\n宿雾分空尽，朝光度隙来。\n影低藤架密，香动药阑开。\n未展山阳会，空留池上杯。' },
  { title: '同赋山居七夕', author: '李峤', poem: '明月青山夜，高天白露秋。\n花庭开粉席，云岫敞针楼。\n石类支机影，池似泛槎流。\n暂惊河女鹊，终狎野人鸥。' },
  { title: '送崔主簿赴沧州', author: '李峤', poem: '紫陌追随日，青门相见时。\n宦游从此去，离别几年期。\n芳桂尊中酒，幽兰下调词。\n他乡有明月，千里照相思。' },
  { title: '寒食清明日早赴王门率成', author: '李峤', poem: '游客趋梁邸，朝光入楚台。\n槐烟乘晓散，榆火应春开。\n日带晴虹上，花随早蝶来。\n雄风乘令节，余吹拂轻灰。' },
  { title: '和周记室从驾晓发合璧宫', author: '李峤', poem: '濯龙春苑曙，翠凤晓旗舒。\n野色开烟后，山光澹月余。\n风长笳响咽，川迥骑行疎。\n珠履陪仙驾，金声振属车。' },
  { title: '和杜侍御太清台宿直旦有怀', author: '李峤', poem: '貂冠朝彩振，乌署晓光分。\n欲啸迁乔侣，先飞掷地文。\n庭虚麦雨润，林静蕙风薰。\n嵇驾终难仰，梁凫且自群。' },
  { title: '和杜学士江南初霁羁怀', author: '李峤', poem: '大江开宿雨，征櫂下春流。\n雾卷晴山出，风恬晚浪收。\n岸花明水树，川鸟乱沙洲。\n羁眺伤千里，劳歌动四愁。' },
  { title: '晚景怅然简二三子', author: '李峤', poem: '楚客秋悲动，梁台夕望赊。\n梧桐稍下叶，山桂欲开花。\n气引迎寒露，光收向晚霞。\n长歌白水曲，空对绿池华。' },
  { title: '送李邕', author: '李峤', poem: '落日荒郊外，风景正凄凄。\n离人席上起，征马路傍嘶。\n别酒倾壶赠，行书掩泪题。\n殷勤御沟水，从此各东西。' },
  { title: '又送别', author: '李峤', poem: '岐路方为客，芳尊暂解颜。\n人随转蓬去，春伴落梅还。\n白云度汾水，黄河遶晋关。\n离心不可问，宿昔鬓成斑。' },
  { title: '饯骆四二首 一', author: '李峤', poem: '平生何以乐，斗酒夜相逢。\n曲中惊别绪，醉里失愁容。\n星月悬秋汉，风霜入曙钟。\n明日临沟水，青山几万重。' },
  { title: '饯骆四二首 二', author: '李峤', poem: '甲第驱车入，良宵秉烛游。\n人追竹林会，酒献菊花秋。\n霜吹飘无已，星河漫不流。\n重嗟欢赏地，翻召别离忧。' },
  { title: '春日游苑喜雨应诏', author: '李峤', poem: '园楼春正归，入苑弄芳菲。\n密雨迎僊步，低云拂御衣。\n危花沾易落，度鸟湿难飞。\n膏泽登千庾，欢情徧九围。' },
  { title: '九日应制得欢字', author: '李峤', poem: '令节三秋晚，重阳九日欢。\n仙杯还泛菊，宝馔且调兰。\n御气云霄近，乘高宇宙宽。\n今朝万寿引，宜向曲中弹。' },
  { title: '二月奉教作', author: '李峤', poem: '柳陌鸎初啭，梅梁燕始归。\n和风泛紫若，柔露濯青薇。\n日艳临花影，霞翻入浪晖。\n乘春重游豫，淹赏玩芳菲。' },
  { title: '三月奉教作', author: '李峤', poem: '银井桐花发，金堂草色齐。\n韶光爱日宇，淑气满风蹊。\n蝶影将花乱，虹文向水低。\n芳春随意晚，佳赏日无暌。' },
  { title: '四月奉教作', author: '李峤', poem: '暄籥三春谢，炎钟九夏初。\n润浮梅雨夕，凉散麦风余。\n叶暗庭帏满，花残院锦疎。\n胜情多赏托，尊酒狎林箊。' },
  { title: '五月奉教作', author: '李峤', poem: '绿树炎氛满，朱楼夏景长。\n池含冻雨气，山映火云光。\n果院新樱熟，花庭曙槿芳。\n欲逃三伏暑，还泛十旬觞。' },
  { title: '六月奉教作', author: '李峤', poem: '养日暂裴回，畏景尚悠哉。\n避暑移琴席，追凉□□□。\n竹风依扇动，桂酒溢壶开。\n劳饵□飞雪，自可□□□。' },
  { title: '八月奉教作', author: '李峤', poem: '黄叶秋风起，苍葭晓露团。\n鹤鸣初警候，雁上欲凌寒。\n月镜如开匣，云缨似缀冠。\n清尊对旻序，高宴有余欢。' },
  { title: '九月奉教作', author: '李峤', poem: '曲池朝下雁，幽砌夕吟蛩。\n叶径兰芳尽，花潭菊气浓。\n寒催四序律，霜度九秋钟。\n还当明月夜，飞盖远相从。' },
  { title: '十月奉教作', author: '李峤', poem: '白藏初送节，玄律始迎冬。\n林枯黄叶尽，水耗绿池空。\n霜待临庭月，寒随入牖风。\n别有欢娱地，歌舞应丝桐。' },
  { title: '十一月奉教作', author: '李峤', poem: '凝阴结暮序，严气肃长飙。\n霜犯狐裘夕，寒侵兽火朝。\n冰深遥架浦，雪冻近封条。\n平原已从猎，日暮整还镳。' },
  { title: '十二月奉教作', author: '李峤', poem: '玉烛年行尽，铜史漏犹长。\n池冷凝宵冻，庭寒积曙霜。\n兰心未动色，梅馆欲含芳。\n裴回临岁晚，顾步伫春光。' },
  { title: '和曲典设扈从东郊忆弟使往安西冬至日恨不得同申拜庆', author: '李峤', poem: '玉关方叱驭，桂苑正陪舆。\n桓岭嗟分翼，姜川限馈鱼。\n雪花含□晚，云叶带荆舒。\n重此西流咏，弥伤南至初。' },
  { title: '马武骑挽歌二首 一', author: '李峤', poem: '五日皆休沐，三泉独不归。\n池台金阙是，尊酒玳筵非。\n巷静游禽入，门闲过客稀。\n唯余昔年凤，尚绕故楼飞。' },
  { title: '马武骑挽歌二首 二', author: '李峤', poem: '昔下天津馆，尝过帝子家。\n夜倾金屋酒，春舞玉台花。\n试马依红埒，吹箫弄紫霞。\n谁言东郭路，翻枉北门车。' },
  { title: '武三思挽歌', author: '李峤', poem: '玉匣金为缕，银钩石作铭。\n短歌伤薤曲，长暮泣松扃。\n事往昏朝雾，人亡折夜星。\n忠贤良可惜，图画入丹青。' },
  { title: '天官崔侍郎夫人吴氏挽歌', author: '李峤', poem: '宠服当年盛，芳魂此地穷。\n劒飞龙匣在，人去鹊巢空。\n簟怆孤生竹，琴哀半死桐。\n唯当青史上，千载仰嫔风。' },
  { title: '日', author: '李峤', poem: '旦出扶桑路，遥升若木枝。\n云间五色满，霞际九光披。\n东陆苍龙驾，南郊赤羽驰。\n倾心比葵藿，朝夕奉光曦。' },
  { title: '月', author: '李峤', poem: '桂满三五夕，蓂开二八时。\n清辉飞鹊鉴，新影学蛾眉。\n皎洁临疎牖，玲珑鉴薄帷。\n愿言从爱客，清夜幸同嬉。' },
  { title: '星', author: '李峤', poem: '蜀郡灵槎转，丰城宝劒新。\n将军临北塞，天子入西秦。\n未作三台辅，宁为五老臣。\n今宵颍川曲，谁识聚贤人。' },
  { title: '风', author: '李峤', poem: '落日生苹末，摇扬徧远林。\n带花疑凤舞，向竹似龙吟。\n月动临秋扇，松清入夜琴。\n若至兰台下，还拂楚王襟。' },
  { title: '烟', author: '李峤', poem: '瑞气凌青阁，空蒙上翠微。\n迥浮双阙路，遥拂九仙衣。\n桑柘迎寒色，松篁暗晚晖。\n还当紫霄上，时接彩鸾飞。' },
  { title: '露', author: '李峤', poem: '滴沥明花苑，葳蕤泫竹丛。\n玉垂丹棘上，珠湛绿荷中。\n夜警千年鹤，朝零七月风。\n愿凝仙掌内，长奉未央宫。' },
  { title: '雾', author: '李峤', poem: '曹公迷楚泽，汉帝出平城。\n涿鹿妖氛静，丹山霁色明。\n类烟飞稍重，方雨散还轻。\n倘入非熊兆，宁思玄豹情。' },
  { title: '雨', author: '李峤', poem: '西北云肤起，东南雨足来。\n灵童出海见，神女向台回。\n斜影风前合，圆文水上开。\n十旬无破块，九土信康哉。' },
  { title: '雪', author: '李峤', poem: '瑞雪惊千里，同云暗九霄。\n地疑明月夜，山似白云朝。\n逐舞花光动，临歌扇影飘。\n大周天阙路，今日海神朝。' },
  { title: '山', author: '李峤', poem: '地镇标神秀，峩峩上翠氛。\n泉飞一道带，峰出半天云。\n古壁丹青色，新花绮绣纹。\n已开封禅所，希谒圣明君。' },
  { title: '石', author: '李峤', poem: '宗子维城固，将军饮羽威。\n岩花鉴里发，云叶锦中飞。\n入宋星初陨，过湘燕早归。\n倘因持补极，宁复想支机。' },
  { title: '原', author: '李峤', poem: '王粲销忧日，江淹起恨年。\n带川遥绮错，分隰迥阡眠。\n□□横周甸，莓苔阙晋田。\n方知急难响，长在脊令篇。' },
  { title: '野', author: '李峤', poem: '凤出秦郊迥，鹑飞楚塞空。\n苍梧云影去，涿鹿雾光通。\n草暗少原绿，花明入蜀红。\n谁言版筑士，犹处傅岩中。' },
  { title: '田', author: '李峤', poem: '贡禹怀书日，张衡作赋辰。\n杏花开凤轸，菖叶布龙鳞。\n瑞麦两岐秀，嘉禾同颖新。\n宁知帝王力，击壤自安贫。' },
  { title: '道', author: '李峤', poem: '铜驼分巩洛，劒阁低临邛。\n紫徼三千里，青楼十二重。\n玉关尘似雪，金穴马如龙。\n今日中衢上，尧尊更可逢。' },
  { title: '海', author: '李峤', poem: '习坎疏丹壑，朝宗合紫微。\n三山巨鳌涌，万里大鹏飞。\n楼写春云色，珠含明月辉。\n会因添雾露，方逐众川归。' },
  { title: '江', author: '李峤', poem: '日夕三江望，灵潮万里回。\n霞津锦浪动，月浦练花开。\n湍似黄牛去，涛从白马来。\n英灵已杰出，谁识卿云才。' },
  { title: '河', author: '李峤', poem: '源出昆仑中，长波接汉空。\n桃花来马颊，竹箭入龙宫。\n德水千年变，荣光五色通。\n若披兰叶检，□□□□□。' },
  { title: '洛', author: '李峤', poem: '九洛韶光媚，三川物候新。\n花明丹凤浦，日映玉鸡津。\n元礼期仙客，陈王覩丽人。\n神龟方锡瑞，绿字重来臻。' },
  { title: '城', author: '李峤', poem: '四塞称天府，三河建洛都。\n飞云霭层阙，白日丽南隅。\n独下仙人凤，群惊御史乌。\n何辞一万里，边徼捍匈奴。' },
  { title: '门', author: '李峤', poem: '奕奕彤闱下，煌煌紫禁隈。\n阿房万户列，阊阖九重开。\n疏广遗荣去，于公待驷来。\n讵知金马侧，方朔有奇才。' },
  { title: '市', author: '李峤', poem: '阛阓开三市，旗亭起百寻。\n渐离初击筑，司马正弹琴。\n细柳龙鳞映，长槐兔月阴。\n徒知观衞玉，讵肯挂秦[金]。' },
  { title: '井', author: '李峤', poem: '玉甃谈仙客，铜台赏魏君。\n蜀都宵映火，杞国旦生云。\n向日莲花净，含风李树薰。\n已开千里国，还聚五星文。' },
  { title: '宅', author: '李峤', poem: '寂寞蓬蒿径，喧喧湫隘庐。\n屡逢长者辙，时引故人车。\n孟母迁邻罢，将军辞第初。\n谁怜草玄处，独对一床书。' },
  { title: '池', author: '李峤', poem: '彩櫂浮太液，清触醉习家。\n诗情对明月，云曲拂流霞。\n烟散龙形净，波含凤影斜。\n安仁动秋兴，鱼鸟思空赊。' },
  { title: '楼', author: '李峤', poem: '百尺重城际，千寻大道隈。\n汉宫井干起，吴国落星开。\n笛怨绿珠去，箫随弄玉来。\n销忧聊暇日，谁识仲宣才。' },
  { title: '桥', author: '李峤', poem: '乌鹊填应满，黄公去不归。\n势疑虹始见，形似雁初飞。\n妙应七星制，高分半月辉。\n秦王空构石，仙岛远难依。' },
  { title: '经', author: '李峤', poem: '汉室鸿儒盛，邹堂大义明。\n五千道德阐，三百礼仪成。\n青紫方拾芥，黄金徒满籝。\n谁知怀逸辩，重席冠群英。' },
  { title: '史', author: '李峤', poem: '马记天官设，班图地里新。\n善谈方亹亹，青简见彬彬。\n方朔初闻汉，荆轲昔向秦。\n正辞堪载笔，终翼作良臣。' },
  { title: '诗', author: '李峤', poem: '都尉仙凫远，梁王驷马来。\n扇中纨素制，机上锦纹回。\n天子三章传，陈王七步才。\n缁衣久擅美，祖德信悠哉。' },
  { title: '赋', author: '李峤', poem: '布义孙卿子，登高楚屈平。\n铜台初下笔，乐观正飞缨。\n乍有凌云势，时闻掷地声。\n造端长体物，无复大夫名。' },
  { title: '书', author: '李峤', poem: '削简龙文见，临池鸟迹舒。\n河图八卦出，洛范九畴初。\n垂露春光满，崩云骨气余。\n请君看入木，一寸乃非虚。' },
  { title: '檄', author: '李峤', poem: '羽檄本宣明，由来□木声。\n联翩至汉国，迢递入燕营。\n毛义持书去，张仪韫璧行。\n曹风虽觉愈，陈草始知名。' },
  { title: '纸', author: '李峤', poem: '妙迹蔡侯施，芳名左伯驰。\n云飞锦绮落，花发缥红披。\n舒卷随幽显，廉方合轨仪。\n莫惊反掌字，当取葛洪规。' },
  { title: '笔', author: '李峤', poem: '握管门庭侧，含毫山水隈。\n霜辉简上发，锦字梦中开。\n鹦鹉摛文至，麒麟绝句来。\n何当遇良史，左右振奇才。' },
  { title: '砚', author: '李峤', poem: '左思裁赋日，王充作论年。\n光随锦文发，形带石岩圆。\n积润循毫里，开池小学前。\n君苗徒见𦶟，谁咏士衡篇。' },
  { title: '墨', author: '李峤', poem: '长安分石炭，上党结松心。\n遶画蝇初落，含滋绶更深。\n悲丝光易染，叠素彩还沈。\n别有张芝学，书池幸见临。' },
  { title: '劒', author: '李峤', poem: '我有昆吾劒，求趋夫子庭。\n白虹时切玉，紫气夜干星。\n锷上芙蓉动，匣中霜雪明。\n倚天持报国，画地取雄名。' },
  { title: '刀', author: '李峤', poem: '列辟鸣鸾至，惟良佩犊旋。\n带环疑写月，引鉴似含泉。\n入梦华梁上，含锋彩笔前。\n莫惊开百炼，特拟定三边。' },
  { title: '箭', author: '李峤', poem: '汉甸初收羽，燕城忽解围。\n影随流水急，光带落星飞。\n夏列三成范，尧沈九日辉。\n断蛟云梦泽，希为识忘归。' },
  { title: '弹', author: '李峤', poem: '侠客持苏合，佳游满帝乡。\n避丸深可诮，求炙遂难忘。\n金迸疑星落，珠沈似月光。\n谁知少孺子，将此见吴王。' },
  { title: '弩', author: '李峤', poem: '挺质本轩皇，申威振远方。\n机张惊雉雊，玉彩耀星芒。\n高鸟行应尽，清猿坐见伤。\n苏秦六百步，持此说韩王。' },
  { title: '旗', author: '李峤', poem: '桂影承宵月，虹辉接曙云。\n纵横齐八阵，舒卷引三军。\n日薄蛟龙影，风翻鸟隼文。\n谁知怀勇志，蟠地几缤纷。' },
  { title: '旌', author: '李峤', poem: '告善康庄侧，求贤市肆中。\n拥麾分彩雉，持节曳丹虹。\n影丽天山雪，光摇朔塞风。\n方知美周政，抗斾赋车攻。' },
  { title: '戈', author: '李峤', poem: '富父舂喉日，殷辛漂杵年。\n晓霜含白刃，落影驻雕鋋。\n夕摈金门侧，朝提玉塞前。\n愿随龙影度，横□阵云边。' },
  { title: '鼓', author: '李峤', poem: '舜日谐鼗响，尧年韵土声。\n向楼疑吹击，震谷似雷惊。\n仙鹤排门起，灵鼍带水鸣。\n乐云行已奏，礼曰冀相成。' },
  { title: '弓', author: '李峤', poem: '桃文称辟恶，桑质表初生。\n宛转雕鞬际，依稀半月明。\n遥弯落雁影，虚引怯猿声。\n徒切乌号思，攀龙遂不成。' },
  { title: '琴', author: '李峤', poem: '名士竹林隈，鸣琴宝匣开。\n风前中散至，月下步兵来。\n淮海多为室，梁岷旧作台。\n子期如可听，山水响余哀。' },
  { title: '瑟', author: '李峤', poem: '伏羲初制法，素女昔传名。\n流水嘉鱼跃，丛台舞凤惊。\n嘉宾饮未极，君子娱俱幷。\n倘入丘之户，应知由也情。' },
  { title: '琵琶', author: '李峤', poem: '朱丝闻岱谷，铄质本多端。\n半月分弦出，丛花拂面安。\n将军曾制曲，司马屡陪观。\n本是胡中乐，希君马上弹。' },
  { title: '筝', author: '李峤', poem: '蒙恬芳轨设，游楚妙弹开。\n新曲帐中发，清音指下来。\n钿装模六律，柱列配三才。\n莫听西秦奏，筝筝有剩哀。' },
  { title: '钟', author: '李峤', poem: '既接南邻磬，还随北里笙。\n平陵通曙响，长乐警宵声。\n秋至含霜动，春归应律鸣。\n欲知常待扣，金簴有余清。' },
  { title: '箫', author: '李峤', poem: '虞舜调清管，王襃赋雅音。\n参差横凤翼，搜索动人心。\n□□□□□，□□□□□。\n□□□□□，□□□□□。' },
  { title: '笛', author: '李峤', poem: '羗笛写龙声，长吟入夜清。\n关山孤月下，来向陇头鸣。\n逐吹梅花落，含春柳色惊。\n行观向子赋，坐忆旧邻情。' },
  { title: '笙', author: '李峤', poem: '悬匏曲沃上，孤筿汶阳隈。\n形写歌鸾翼，声随舞凤哀。\n欢娱分北里，纯孝即南陔。\n今日虞音奏，跄跄鸟兽来。' },
  { title: '歌', author: '李峤', poem: '汉帝临汾水，周仙去洛滨。\n郢中吟白雪，梁上绕飞尘。\n响发行云驻，声随子夜新。\n愿君听扣角，当自识贤臣。' },
  { title: '舞', author: '李峤', poem: '妙伎游金谷，佳人满石城。\n霞衣席上转，花岫雪前明。\n仪凤谐清曲，回鸾应雅声。\n非君一顾重，谁赏素腰轻。' },
  { title: '珠', author: '李峤', poem: '灿烂金舆侧，玲珑玉殿隈。\n昆池明月满，合浦夜光回。\n彩逐灵蛇转，行随舞凤来。\n甘泉宫起罢，花媚望风台。' },
  { title: '玉', author: '李峤', poem: '映石先过魏，连城欲向秦。\n洛阳陪胜友，燕赵类佳人。\n方水晴虹媚，常山瑞马新。\n徒为卞和识，不遇楚王珍。' },
  { title: '金', author: '李峤', poem: '南楚标前贡，西秦识旧城。\n祭天封汉岭，掷地警孙声。\n向日披沙净，含风振铎鸣。\n方同杨伯起，独有四知名。' },
  { title: '银', author: '李峤', poem: '思妇屏辉掩，游人烛影长。\n玉壶初下箭，桐井共安床。\n色带长河色，光浮满月光。\n灵山有珍瓮，仙阙荐君王。' },
  { title: '钱', author: '李峤', poem: '汉日五铢建，姬年九府流。\n天龙带泉宝，地马列金沟。\n赵壹囊初乏，何曾箸欲收。\n金门应入论，玉井冀来求。' },
  { title: '锦', author: '李峤', poem: '汉使巾车远，河阳步障陈。\n云浮仙石日，霞满蜀江春。\n机迥回文巧，绅兼束髪新。\n若逢楚王贵，不作夜行人。' },
  { title: '罗', author: '李峤', poem: '妙舞随裙动，行歌入扇清。\n莲花依帐发，秋月鉴帷明。\n云薄衣初卷，蝉飞翼转轻。\n若珍三代服，同擅绮纨名。' },
  { title: '绫', author: '李峤', poem: '金缕通秦国，为裘指魏君。\n落花遥写雾，飞鹤近图云。\n马眼冰凌影，竹根雪霰文。\n何当画秦女，烟际坐氤氲。' },
  { title: '素', author: '李峤', poem: '□□□□女，纤腰洛浦妃。\n□□远方望，雁足上林飞。\n妙夺鲛绡色，光腾月扇辉。\n非君下路去，谁赏故人机。' },
  { title: '布', author: '李峤', poem: '御绩创羲黄，缁冠表素王。\n瀑飞临碧海，火浣擅炎方。\n孙被登三相，刘衣阐四方。\n伫因舂斗粟，来晓棣华芳。' },
  { title: '舟', author: '李峤', poem: '征櫂三江暮，连樯万里回。\n相乌风际转，画鹢浪前开。\n羽客乘霞至，仙人弄月来。\n何当同傅说，特展巨川材。' },
  { title: '车', author: '李峤', poem: '天子驭金根，蒲轮辟四门。\n五神趋雪至，双毂似雷奔。\n丹凤栖金辖，非熊载宝轩。\n无阶忝虚左，珠乘奉王言。' },
  { title: '床', author: '李峤', poem: '传闻有象床，畴昔献君王。\n玳瑁千金起，珊瑚七宝妆。\n桂筵含柏馥，兰席拂沈香。\n愿奉罗帷夜，长乘秋月光。' },
  { title: '席', author: '李峤', poem: '避席承宣父，重筵揖戴公。\n桂香浮半月，兰气袭回风。\n舞拂丹霞上，歌清白雪中。\n伫将文绮色，舒卷帝王宫。' },
  { title: '帷', author: '李峤', poem: '久闭先生户，高褰太守车。\n罗将翡翠合，锦逐凤皇舒。\n明月弹琴夜，清风入幌初。\n方知决胜策，黄石受兵书。' },
  { title: '帘', author: '李峤', poem: '清风时入燕，紫殿几含秋。\n暧暧笼铃阁，纤纤上玉钩。\n窗中翡翠动，户外水精浮。\n巧作盘龙势，长迎飞燕游。' },
  { title: '屏', author: '李峤', poem: '洞彻琉璃蔽，威纡屈膝回。\n锦中云母列，霞上织成开。\n山上含春动，神仙倒景来。\n修身兼竭节，谁识作铭才。' },
  { title: '被', author: '李峤', poem: '桂友寻东阁，兰交聚北堂。\n象筵分锦绣，罗荐合鸳鸯。\n光逸偷眠稳，王章泣恨长。\n孔怀欣共寝，棣萼几含芳。' },
  { title: '鉴', author: '李峤', poem: '明鉴掩尘埃，含情照魏台。\n日中乌鹊至，花里凤皇来。\n玉彩疑冰彻，金辉似月开。\n方知乐彦辅，自有鉴人才。' },
  { title: '扇', author: '李峤', poem: '翟羽旧传名，蒲葵价不轻。\n花芳不满面，罗薄讵障声。\n御热含风细，临秋带月明。\n同心如可赠，持表合欢情。' },
  { title: '烛', author: '李峤', poem: '兔月清光隐，龙盘画烛新。\n三星花入夜，四序玉调晨。\n浮炷依罗幌，吹香匝绮茵。\n若逢燕国相，持用举贤人。' },
  { title: '酒', author: '李峤', poem: '孔坐洽良俦，陈筵几献酬。\n临风竹叶满，湛月桂香浮。\n每接高阳宴，长陪河朔游。\n会从玄石饮，云雨出圆丘。' },
  { title: '兰', author: '李峤', poem: '虚室重招寻，忘言契断金。\n英浮汉家酒，雪俪楚王琴。\n广殿轻香发，高台远吹吟。\n河汾应擢秀，谁肯访山阴。' },
  { title: '菊', author: '李峤', poem: '玉律三秋暮，金精九日开。\n荣舒洛媛浦，香泛野人杯。\n靃靡寒潭侧，丰茸晓岸隈。\n黄花今日晚，无复白衣来。' },
  { title: '竹', author: '李峤', poem: '高簳楚江𣸣，婵娟含曙氛。\n白花摇凤影，青节动龙文。\n叶埽东南日，枝捎西北云。\n谁知湘水上，流泪独思君。' },
  { title: '藤', author: '李峤', poem: '吐叶依松磴，舒苗长石台。\n神农尝药罢，质子寄书来。\n色映蒲萄架，花分竹叶杯。\n金堤不见识，玉润几重开。' },
  { title: '萱', author: '李峤', poem: '屣步寻芳草，忘忧自结丛。\n黄英开养性，绿叶正依笼。\n色湛仙人露，香传少女风。\n还依北堂下，曹植动文雄。' },
  { title: '茅', author: '李峤', poem: '楚甸供王日，衡阳入贡年。\n麏包青野外，鸱啸绮楹前。\n尧帝成茨罢，殷汤祭雨旋。\n方期大君锡，不惧小巫捐。' },
  { title: '荷', author: '李峤', poem: '新溜满澄陂，圆荷影若规。\n风来香气远，日落盖阴移。\n鱼戏排缃叶，龟浮见绿池。\n魏朝难接采，楚服但同披。' },
  { title: '萍', author: '李峤', poem: '二月虹初见，三春蚁正浮。\n青苹含吹转，紫蒂带波流。\n屡逐明神荐，常随旅客游。\n既能甜似蜜，还遶楚王舟。' },
  { title: '菱', author: '李峤', poem: '巨野韶光暮，东平春溜通。\n影摇江浦月，香引櫂歌风。\n日色翻池上，潭花发镜中。\n五湖多赏乐，千里望难穷。' },
  { title: '瓜', author: '李峤', poem: '欲识东陵味，青门五色瓜。\n龙蹄远珠履，女臂动金花。\n六子方呈瑞，三仙实可嘉。\n终朝奉𫄨绤，谒帝伫非赊。' },
  { title: '松', author: '李峤', poem: '郁郁高岩表，森森幽涧陲。\n鹤栖君子树，风拂大夫枝。\n百尺条阴合，千年盖影披。\n岁寒终不改，劲节幸君知。' },
  { title: '桂', author: '李峤', poem: '未[殖]银宫里，宁移玉殿幽。\n枝生无限月，花满自然秋。\n侠客条为马，仙人叶作舟。\n愿君期道术，攀折可淹留。' },
  { title: '槐', author: '李峤', poem: '暮律移寒火，春宫长旧栽。\n叶生驰道侧，花落凤庭隈。\n烈士怀忠触，鸿儒访业来。\n何当赤墀下，疎干拟三台。' },
  { title: '柳', author: '李峤', poem: '杨柳郁氤氲，金堤总翠氛。\n庭前花类雪，楼际叶如云。\n列宿分龙影，芳池写凤文。\n短箫何以奏，攀折为思君。' },
  { title: '桐', author: '李峤', poem: '孤秀峄阳岑，亭亭出众林。\n春光杂凤影，秋月弄圭阴。\n高映龙门迥，双依玉井深。\n不因将入爨，谁谓作鸣琴。' },
  { title: '桃', author: '李峤', poem: '独有成蹊处，秾华发井傍。\n山风凝笑脸，朝露泫啼妆。\n隐士颜应改，仙人路渐长。\n还欣上林苑，千岁奉君王。' },
  { title: '李', author: '李峤', poem: '潘岳闲居日，王戎戏陌辰。\n蝶游芳径馥，鸎啭弱枝新。\n叶暗青房晚，花明玉井春。\n方知有灵干，特用表真人。' },
  { title: '梨', author: '李峤', poem: '擅美玄光侧，传芳瀚海中。\n凤文疎象郡，花影丽新丰。\n色对瑶池紫，甘依大谷红。\n若令逢汉主，还冀识张公。' },
  { title: '梅', author: '李峤', poem: '大庾歛寒光，南枝独早芳。\n雪含朝暝色，风引去来香。\n妆面回青镜，歌尘起画梁。\n若能遥止渴，何暇泛琼浆。' },
  { title: '橘', author: '李峤', poem: '万里盘根植，千秋布叶繁。\n既荣潘子赋，方重陆生言。\n玉蘤含霜动，金衣逐吹翻。\n愿辞湘水曲，长茂上林园。' },
  { title: '凤', author: '李峤', poem: '有鸟居丹穴，其名曰凤皇。\n九苞应灵瑞，五色成文章。\n屡向秦楼侧，频过洛水阳。\n鸣岐今日见，阿阁伫来翔。' },
  { title: '鹤', author: '李峤', poem: '黄鹤远联翩，从鸾下紫烟。\n翱翔一万里，来去几千年。\n已憩青田侧，时游丹禁前。\n莫言空警露，犹冀一闻天。' },
  { title: '乌', author: '李峤', poem: '日路朝飞急，霜台夕影寒。\n联翩依月树，迢递绕风竿。\n白首何年改，青琴此夜弹。\n灵台如可托，千里向长安。' },
  { title: '鹊', author: '李峤', poem: '不分荆山抵，甘从石印飞。\n危巢畏风急，绕树觉星稀。\n喜逐行人至，愁随织女归。\n倘游明镜里，朝夕动光辉。' },
  { title: '雁', author: '李峤', poem: '春晖满朔方，归雁发衡阳。\n望月惊弦影，排云结阵行。\n往还倦南北，朝夕苦风霜。\n寄语能鸣侣，相随入帝乡。' },
  { title: '凫', author: '李峤', poem: '飒沓睢阳涘，浮游汉水隈。\n钱飞出井见，鹤引入琴哀。\n李陵赋诗罢，王乔曳舄来。\n何当归太液，翱集动成雷。' },
  { title: '鸎', author: '李峤', poem: '芳树杂花红，群鸎乱晓空。\n声分折杨吹，娇韵落梅风。\n写啭清弦里，迁乔暗木中。\n友生若可冀，幽谷响还通。' },
  { title: '雉', author: '李峤', poem: '白雉振朝声，飞来表太平。\n楚郊疑凤出，陈宝若鸡鸣。\n童子怀仁至，中郎作赋成。\n冀君看饮啄，耿介独含情。' },
  { title: '燕', author: '李峤', poem: '天女伺辰至，玄衣澹碧空。\n差池沐时雨，颉颃舞春风。\n相贺雕阑侧，双飞翠幕中。\n勿惊留爪去，犹冀识吴宫。' },
  { title: '雀', author: '李峤', poem: '大厦初成日，嘉宾集杏梁。\n衔书表周瑞，入幕应王祥。\n暮宿江城里，朝游涟水傍。\n愿齐鸿鹄至，希逐凤皇翔。' },
  { title: '龙', author: '李峤', poem: '衔烛耀幽都，含章拟凤雏。\n西秦饮渭水，东洛荐河图。\n带火移星陆，升云出鼎湖。\n希逢圣人步，庭阙正晨趋。' },
  { title: '麟', author: '李峤', poem: '汉祀应祥开，鲁郊西狩回。\n奇音中钟吕，成角喻英才。\n画像临仙阁，藏书入帝台。\n若惊能吐哺，为待凤皇来。' },
  { title: '象', author: '李峤', poem: '郁林开郡毕，维扬作贡初。\n万推方演梦，惠子正焚书。\n执燧奔吴战，量舟入魏墟。\n六牙行致远，千叶奉高居。' },
  { title: '马', author: '李峤', poem: '天马本来东，嘶惊御史骢。\n苍龙遥逐日，紫燕迥追风。\n明月来鞍上，浮云落盖中。\n得随穆天子，何假唐成公。' },
  { title: '牛', author: '李峤', poem: '齐歌初入相，燕阵早横功。\n欲向桃林下，先过梓树中。\n在吴频喘月，奔梦屡惊风。\n不用五丁士，如何九折通。' },
  { title: '豹', author: '李峤', poem: '车法肇宗周，鼷文阐大猷。\n还将君子变，来蕴太公筹。\n委质超羊鞟，飞名列虎侯。\n若令逢雨露，长隐南山幽。' },
  { title: '熊', author: '李峤', poem: '导洛宜阳右，乘春别馆前。\n昭仪忠汉日，太傅翊周年。\n列射三侯满，兴师七步旋。\n莫言舒紫褥，犹异饮清泉。' },
  { title: '鹿', author: '李峤', poem: '涿鹿闻中冀，秦原辟帝畿。\n柰花开旧苑，萍叶蔼前诗。\n道士乘仙日，先生折角时。\n方怀丈夫志，抗首别心期。' },
  { title: '羊', author: '李峤', poem: '绝饮惩浇俗，行驱梦逸材。\n仙人拥石去，童子驭车来。\n夜玉含星动，晨毡映雪开。\n莫言鸿渐力，长牧上林隈。' },
  { title: '兔', author: '李峤', poem: '上蔡应初击，平冈远不稀。\n目随槐叶长，形逐桂条飞。\n汉月澄秋色，梁园映雪辉。\n唯当感纯孝，郛郭引兵威。' },
  { title: '人日侍宴大明宫恩赐彩缕人胜应制', author: '李峤', poem: '凤城景色已含韶，人日风光倍觉饶。\n桂吐半轮迎此夜，蓂开七叶应今朝。\n鱼猜水冻行犹澁，鸎喜春熙弄欲娇。\n媿奉登高摇彩翰，欣逢御气上丹霄。' },
  { title: '奉和初春幸太平公主南庄应制', author: '李峤', poem: '主家山第接云开，天子春游动地来。\n羽骑参差花外转，霓旌摇曳日边回。\n还将石溜调琴曲，更取峰霞入酒杯。\n鸾辂已辞乌鹊渚，箫声犹绕凤皇台。' },
  { title: '太平公主山亭侍宴应制', author: '李峤', poem: '黄金瑞牓绛河隈，白玉仙舆紫禁来。\n碧树青岑云外耸，朱楼画阁水中开。\n龙舟下瞰鲛人室，羽节高临凤女台。\n遽惜欢娱歌吹晚，挥戈更却曜灵回。' },
  { title: '奉和拜洛应制', author: '李峤', poem: '七萃銮舆动，千年瑞检开。\n文如龟负出，图似凤衔来。\n殷荐三神享，明禋万国陪。\n周旗黄鸟集，汉幄紫云回。\n日暮钩陈转，清歌上帝台。' },
  { title: '奉和幸大荐福寺应制', author: '李峤', poem: '雁沼开香域，鹦林降彩旃。\n还窥图凤宇，更坐跃龙川。\n桂轝朝群辟，兰宫列四禅。\n半空银阁断，分砌宝绳连。\n甘雨苏燋泽，慈云动沛篇。\n独慙贤作砺，空喜福成田。' },
  { title: '奉和幸长安故城未央宫应制', author: '李峤', poem: '旧宫贤相筑，新苑圣君来。\n运改城隍变，年深栋宇摧。\n后池无复水，前殿久成灰。\n莫辨祈风观，空传承露杯。\n宸心千载合，睿律九韶开。\n今日联章处，犹疑上柏台。' },
  { title: '奉和幸望春宫送朔方总管张仁亶', author: '李峤', poem: '玉塞征骄子，金符命老臣。\n三军张武斾，万乘饯行轮。\n猛气凌玄朔，崇恩降紫宸。\n投醪还结士，辞第本忘身。\n露下鹰初击，风高雁欲宾。\n方销塞北祲，还靖漠南尘。' },
  { title: '奉和幸三会寺应制', author: '李峤', poem: '故台苍颉里，新邑紫泉居。\n岁在开金寺，时来降玉舆。\n龙形虽近刹，鸟迹尚留书。\n竹是蒸青外，池仍点墨余。\n天文光圣草，宝思合真如。\n谬奉千龄日，欣陪十地初。' },
  { title: '奉和天枢成宴夷夏群僚应制', author: '李峤', poem: '辙迹光西崦，勋庸纪北燕。\n何如万方会，颂德九门前。\n灼灼临黄道，迢迢入紫烟。\n仙盘正下露，高柱欲承天。\n山类丛云起，珠疑大火悬。\n声流尘作刼，业固海成田。\n帝泽倾尧酒，宸歌掩舜弦。\n欣逢下生日，还覩上皇年。' },
  { title: '皇帝上礼抚事述怀', author: '李峤', poem: '配极辉光远，承天顾托隆。\n负图济多难，脱履归成功。\n圣道昭永锡，邕言让在躬。\n还推万方重，咸仰四门聪。\n恭己忘自逸，因人体至公。\n垂旒沧海晏，解网法星空。\n云散天五色，春还日再中。\n称觞合缨弁，率舞应丝桐。\n凯乐深居镐，传歌盛饮丰。\n小臣滥簪笔，无以颂唐风。' },
  { title: '奉和幸韦嗣立山庄侍宴应制', author: '李峤', poem: '南洛师臣契，东岩王佐居。\n幽情遗绂冕，宸眷属樵渔。\n制下峒山跸，恩回灞水舆。\n松门驻旌盖，薜幄引簪裾。\n石磴平黄陆，烟楼半紫虚。\n云霞仙路近，琴酒俗尘疎。\n乔木千龄外，悬泉百丈余。\n崖深经炼药，穴古旧藏书。\n树宿抟风鸟，池潜纵壑鱼。\n宁知天子贵，尚忆武侯庐。' },
  { title: '倡妇行', author: '李峤', poem: '十年倡家妇，三秋边地人。\n红妆楼上歇，白发陇头新。\n夜夜风霜苦，年年征戍频。\n山西长落日，塞北久无春。\n团扇辞恩宠，回文赠苦辛。\n胡兵屡攻战，汉使绝和亲。\n消息如瓶井，沈浮似路尘。\n空余千里月，照妾两眉嚬。' },
  { title: '饯薛大夫护边', author: '李峤', poem: '荒隅时未通，副相下临戎。\n授律星芒动，分兵月晕空。\n犀皮拥青橐，象齿饰雕弓。\n决胜三河勇，长驱六郡雄。\n登山窥代北，屈指计辽东。\n伫见燕然上，抽毫颂武功。' },
  { title: '和杜学士旅次淮口阻风', author: '李峤', poem: '夕吹生寒浦，清淮上暝潮。\n迎风欲举櫂，触浪反停桡。\n淼漫烟波阔，参差林岸遥。\n日沈丹气敛，天敞白云销。\n水雁衔芦叶，沙鸥隐荻苗。\n客行殊未已，川路几迢迢。' },
  { title: '送光禄刘主簿之洛', author: '李峤', poem: '函谷双崤右，伊川二陕东。\n仙舟窅将隔，芳斝暂云同。\n朋席余欢尽，文房旧侣空。\n他乡千里月，岐路九秋风。\n背枥嘶班马，分洲呌断鸿。\n别后青山外，相望白云中。' },
  { title: '送骆奉礼从军', author: '李峤', poem: '玉塞边烽举，金坛庙略申。\n羽书资锐笔，戎幕引英宾。\n剑动三军气，衣飘万里尘。\n琴尊留别赏，风景惜离晨。\n笛梅含晚吹，营柳带余春。\n希君勒石返，歌舞入城𬮱。' },
  { title: '王屋山第之侧杂构小亭暇日与群公同游', author: '李峤', poem: '桂亭依绝𪩘，兰榭俯回溪。\n绮栋鱼鳞出，雕甍凤羽栖。\n引泉聊涨沼，凿磴且通蹊。\n席上山花落，帘前野树低。\n弋林开曙景，钓渚发晴霓。\n狎水惊梁雁，临风听楚鸡。\n复看题柳叶，弥喜荫桐圭。' },
  { title: '奉和杜员外扈从教阅', author: '李峤', poem: '杪冬严杀气，穷纪送颓光。\n薄狩三农隙，大阅五戎塲。\n菜田初起烧，兰野正开防。\n夹岸虹旗转，分朋兽罟张。\n燕弧带晓月，吴劒动秋霜。\n原启前禽路，山萦后骑行。\n云区坠日羽，星苑毙天狼。\n礼振军容肃，威宣武节扬。\n神心体殷祝，灵兆叶姬祥。\n幸陪仙驾末，欣采翰林芳。' },
  { title: '军师凯旋自邕州顺流舟中', author: '李峤', poem: '鸣鞞入嶂口，泛舸历川湄。\n尚想江陵阵，犹疑下濑师。\n岸回帆影疾，风逆鼓声迟。\n萍叶沾兰桨，林花拂桂旗。\n弓鸣苍隼落，劒动白猿悲。\n芳树吟羗管，幽篁入楚词。\n全军多胜策，无战在明时。\n寄谢山东妙，长缨徒自欺。' },
  { title: '夏晚九成宫呈同僚', author: '李峤', poem: '碣馆分襄野，平台架射峰。\n英藩信炜烨，胜地本从容。\n林引梧庭凤，泉归竹沼龙。\n小轩恒共处，长坂属相从。\n野席兰琴奏，山台桂酒𬪩。\n一枰移昼景，六着尽宵钟。\n枚藻清词律，邹谈耀辩锋。\n结欢良有裕，联采愧无庸。\n暂悦丘中赏，还希物外踪。\n风烟远近至，鱼鸟去来逢。\n月涧横千丈，云崖列万重。\n树红山果熟，崖绿水苔浓。\n愿以西园柳，长间北岩松。' },
  { title: '田假限疾不获还庄载想田园兼思亲友率成短韵用写长怀赠杜幽素', author: '李峤', poem: '游宦劳牵网，风尘久化衣。\n迹驰东苑路，望阻北岩扉。\n及此承休告，聊将狎遯肥。\n十旬俄委疾，三径且殊归。\n茂陵窅难即，灵台暂可依。\n疲疴旅城寺，延想属郊畿。\n夕梦园林是，晨瞻邑里非。\n绿畴良已秽，清濠旷不追。\n野花何处落？山月几秋辉。\n彼美符商政，优游绝汉机。\n高情物累遣，逸气烟霞飞。\n乐道方无闷，怀贤独有违。\n尊虚旧园酒，琴静故人徽。\n夏沼莲初发，秋田麦稍稀。\n何当携手去，岁暮采芳菲。' },
  { title: '刘侍读见和山邸十篇重申此赠', author: '李峤', poem: '神岳瑶池圃，仙宫玉树林。\n乘时警天御，清暑涤宸襟。\n梁驾陪玄赏，淄庭掩翠岑。\n对岩龙岫出，分壑雁池深。\n檐迥松萝映，窗高石镜临。\n落泉奔涧响，惊吹助猿吟。\n野气迷凉燠，山花杂古今。\n英藩盛宾侣，胜景想招寻。\n践径披兰叶，攀崖引桂阴。\n穆生时泛醴，邹子或调琴。\n雉翳分塲合，鱼钩向浦沈。\n朝游极斜景，夕宴待横参。\n顾己慙铅锷，叨名齿玳簪。\n暂依朱邸馆，还畅白云心。\n丘壑信多美，烟霞得所钦。\n寓言摅宿志，窃吹简知音。\n奖价逾珍石，酬文重振金。\n方从仁智所，携手濯清浔。' },
  { title: '晚秋喜雨', author: '李峤', poem: '积阳躔首夏，隆旱届徂秋。\n炎威振皇服，歊景暴神州。\n气涤朝川朗，光澄夕照浮。\n草木委林甸，禾黍悴原畴。\n国惧流金眚，人深悬磬忧。\n紫宸兢履薄，丹扆念推沟。\n望肃坛场祀，冤申囹圄囚。\n御车迁玉殿，荐菲撤琼羞。\n济窘邦储发，蠲穷井赋优。\n服闲云骥屏，冗术土龙修。\n睿感通三极，天诚贯六幽。\n夏祈良未拟，商祷讵为俦。\n穴蚁祯符应，山蛇毒影收。\n腾云八际满，飞雨四溟周。\n聚霭笼仙阙，连霏绕画楼。\n旱陂仍积水，涸沼更通流。\n晚穗萎还结，寒苗瘁复抽。\n九农欢岁阜，万宇庆时休。\n野洽如坻咏，途喧击壤讴。\n幸闻东李道，欣奉北场游。' },
  { title: '中秋月二首 一', author: '李峤', poem: '盈缺青冥外，东风万古吹。\n何人种丹桂，不长出轮枝。' },
  { title: '中秋月二首 二', author: '李峤', poem: '圆魄上寒空，皆言四海同。\n安知千里外，不有雨兼风。' },
  { title: '侍宴桃花园咏花应制', author: '李峤', poem: '岁去无言忽顦顇，时来含笑吐氛氲。\n不能拥路迷仙客，故欲开蹊待圣君。' },
  { title: '奉和圣制幸韦嗣立山庄应制', author: '李峤', poem: '万骑千官拥帝车，八龙三马访仙家。\n凤皇原上开青壁，鹦鹉杯中弄紫霞。' },
  { title: '游苑遇雪应制', author: '李峤', poem: '散漫祥云逐圣回，飘飖瑞雪绕天来。\n不能落后争飞絮，故欲迎前赛早梅。' },
  { title: '送司马先生', author: '李峤', poem: '蓬阁桃源两处分，人间海上不相闻。\n一朝琴里悲黄鹤，何日山头望白云。' },
  { title: '上清晖合遇雪', author: '李峤', poem: '千钟圣酒御筵披，六出祥英乱绕枝。\n即此神仙对琼圃，何须辙迹向瑶池。' },
  { title: '石淙', author: '李峤', poem: '羽盖龙旗下绝冥，兰除薜幄坐云扃。\n鸟和百籁疑调管，花发千岩似画屏。\n金灶浮烟朝漠漠，石床寒水夜泠泠。\n自然碧洞窥仙境，何必丹丘是福庭。' },
  { title: '南海乱石山作', author: '杜审言', poem: '涨海积稽天，群山高嶪地。\n相传称乱石，图典失其事。\n悬危悉可惊，大小都不类。\n乍将云岛极，还与星河次。\n上耸忽如飞，下临仍欲坠。\n朝暾赩丹紫，夜魄炯青翠。\n穹崇雾雨蓄，幽隐灵仙閟。\n万寻挂鹤巢，千丈垂猿臂。\n昔去景风涉，今来姑洗至。\n观此得咏歌，长时想精异。' },
  { title: '送和西蕃使', author: '杜审言', poem: '使出凤皇池，京师阳春晚。\n圣朝尚边策，诏谕兵戈偃。\n拜手明光殿，摇心上林苑。\n种落逾青羌，关山度赤坂。\n疆场及无事，雅歌而餐饭。\n宁独锡和戎，更当封定远。' },
  { title: '蓬莱三殿侍宴奉敕咏终南山应制', author: '杜审言', poem: '北斗挂城边，南山倚殿前。\n云标金阙迥，树杪玉堂悬。\n半岭通佳气，中峰绕瑞烟。\n小臣持献寿，长此戴尧天。' },
  { title: '望春亭侍游应诏', author: '杜审言', poem: '帝出明光殿，天临太液池。\n尧樽随步辇，舜乐绕行麾。\n万寿祯祥献，三春景物滋。\n小臣同酌海，歌颂荅无为。' },
  { title: '宿羽亭侍宴应制', author: '杜审言', poem: '步辇千门出，离宫二月开。\n风光新柳报，宴赏落花催。\n碧水摇空阁，青山绕吹台。\n圣情留晚兴，歌管送余杯。' },
  { title: '岁夜安乐公主满月侍宴应制', author: '杜审言', poem: '戚里生昌胤，天杯宴重臣。\n画楼初满月，香殿早迎春。\n睿作尧君宝，孙谋梁国珍。\n明朝元会日，万寿乐章陈。' },
  { title: '奉和七夕侍宴两仪殿应制', author: '杜审言', poem: '一年衔别怨，七夕始言归。\n敛泪开星靥，微步动云衣。\n天回兔欲落，河旷鹊停飞。\n那堪尽此夜，复往弄残机。' },
  { title: '大酺', author: '杜审言', poem: '圣后乘干日，皇明御历辰。\n紫宫初启坐，苍璧正临春。\n雷雨垂膏泽，金钱赠下人。\n诏酺欢赏徧，交泰覩惟新。' },
  { title: '赋得妾薄命', author: '杜审言', poem: '草绿长门掩，苔青永巷幽。\n宠移新爱夺，泪落故情留。\n啼鸟惊残梦，飞花搅独愁。\n自怜春色罢，团扇复迎秋。' },
  { title: '和韦承庆过义阳公主山池五首 一', author: '杜审言', poem: '野兴城中发，朝英物外求。\n情悬朱绂望，契动赤泉游。\n海燕巢书阁，山鸡舞画楼。\n雨余清晚夏，共坐北岩幽。' },
  { title: '和韦承庆过义阳公主山池五首 二', author: '杜审言', poem: '迳转危峰逼，桥回缺岸妨。\n玉泉移酒味，石髓换粳香。\n绾雾青丝弱，牵风紫蔓长。\n犹言宴乐少，别向后池塘。' },
  { title: '和韦承庆过义阳公主山池五首 三', author: '杜审言', poem: '携琴遶碧沙，摇笔弄青霞。\n杜若幽庭草，芙蓉曲沼花。\n宴游成野客，形胜得仙家。\n往往留仙步，登攀日易斜。' },
  { title: '和韦承庆过义阳公主山池五首 四', author: '杜审言', poem: '攒石当轩倚，悬泉度牖飞。\n鹿麛冲妓席，鹤子曳童衣。\n园果尝难遍，池莲摘未稀。\n卷帘唯待月，应在醉中归。' },
  { title: '和韦承庆过义阳公主山池五首 五', author: '杜审言', poem: '赏玩期他日，高深爱此时。\n池分八水背，峰作九山疑。\n地静鱼偏逸，人闲鸟欲欺。\n青溪留别兴，更与白云期。' },
  { title: '和晋陵陆丞早春游望', author: '杜审言', poem: '独有宦游人，偏惊物候新。\n云霞出海曙，梅柳渡江春。\n淑气催黄鸟，晴光转绿苹。\n忽闻歌古调，归思欲沾巾。' },
  { title: '秋夜宴临津郑明府宅', author: '杜审言', poem: '行止皆无地，招寻独有君。\n酒中堪累月，身外即浮云。\n露白宵钟彻，风清晓漏闻。\n坐携余兴往，还似未离群。' },
  { title: '和康五庭芝望月有怀', author: '杜审言', poem: '明月高秋迥，愁人独夜看。\n暂将弓并曲，飜与扇俱团。\n雾濯清辉苦，风飘素影寒。\n罗衣一此鉴，顿使别离难。' },
  { title: '登襄阳城', author: '杜审言', poem: '旅客三秋至，层城四望开。\n楚山横地出，汉水接天回。\n冠盖非新里，章华即旧台。\n习池风景异，归路满尘埃。' },
  { title: '旅寓安南', author: '杜审言', poem: '交趾殊风候，寒迟暖复催。\n仲冬山果熟，正月野花开。\n积雨生昏雾，轻霜下震雷。\n故乡逾万里，客思倍从来。' },
  { title: '春日怀归', author: '杜审言', poem: '心是伤归望，春归异往年。\n河山鉴魏阙，桑梓忆秦川。\n花杂芳园鸟，风和绿野烟。\n更怀欢赏地，车马洛桥边。' },
  { title: '代张侍御伤美人', author: '杜审言', poem: '二八泉扉掩，帷屏宠爱空。\n泪痕消夜烛，愁绪乱春风。\n巧笑人疑在，新妆曲未终。\n应怜脂粉气，留着舞衣中。' },
  { title: '送高郎中北使', author: '杜审言', poem: '北狄愿和亲，东京发使臣。\n马衔边地雪，衣染异方尘。\n岁月催行旅，恩荣变苦辛。\n歌钟期重锡，拜手落花春。' },
  { title: '都尉山亭', author: '杜审言', poem: '紫藤萦葛藟，绿刺罥蔷薇。\n下钓看鱼跃，探巢畏鸟飞。\n叶疎荷已晚，枝亚果新肥。\n胜迹都无限，只应伴月归。' },
  { title: '夏日过郑七山斋', author: '杜审言', poem: '共有樽中好，言寻谷口来。\n薜萝山迳入，荷芰水亭开。\n日气含残雨，云阴送晚雷。\n洛阳钟鼓至，车马系迟回。' },
  { title: '送崔融', author: '杜审言', poem: '君王行出将，书记远从征。\n祖帐连河阙，军麾动洛城。\n旌旃朝朔气，笳吹夜边声。\n坐觉烟尘扫，秋风古北平。' },
  { title: '经行岚州', author: '杜审言', poem: '北地春光晚，边城气候寒。\n往来花不发，新旧雪仍残。\n水作琴中听，山疑画里看。\n自惊牵远役，艰险促征鞍。' },
  { title: '重九日宴江阴', author: '杜审言', poem: '蟋蟀期归晚，茱萸节候新。\n降霜青女月，送酒白衣人。\n高兴要长寿，卑栖隔近臣。\n龙沙即此地，旧俗坐为邻。' },
  { title: '除夜有怀', author: '杜审言', poem: '故节当歌守，新年把烛迎。\n冬氛恋虬箭，春色候鸡鸣。\n兴尽闻壶覆，宵阑见斗横。\n还将万亿寿，更谒九重城。' },
  { title: '晦日宴游', author: '杜审言', poem: '日晦随蓂荚，春情着杏花。\n解绅宜就水，张幕会连沙。\n歌管风轻度，池台日半斜。\n更看金谷骑，争向石崇家。' },
  { title: '七夕', author: '杜审言', poem: '白露含明月，青霞断绛河。\n天街七襄转，阁道二神过。\n袨服锵环珮，香筵拂绮罗。\n年年今夜尽，机杼别情多。' },
  { title: '守岁侍宴应制', author: '杜审言', poem: '季冬除夜接新年，帝子王孙捧御筵。\n宫阙星河低拂树，殿廷灯烛上薰天。\n弹弦奏节梅风入，对局探钩柏酒传。\n欲向正元歌万寿，暂留欢赏寄春前。' },
  { title: '春日京中有怀', author: '杜审言', poem: '今年游寓独游秦，愁思看春不当春。\n上林苑里花徒发，细柳营前叶漫新。\n公子南桥应尽兴，将军西第几留宾。\n寄语洛城风日道，明年春色倍还人。' },
  { title: '扈从出长安应制', author: '杜审言', poem: '分野都畿列，时乘六御均。\n京师旧西幸，洛道此东巡。\n文物驱三统，声名走百神。\n龙旗萦漏夕，凤辇拂钩陈。\n抚迹地灵古，游情皇鉴新。\n山追散马日，水忆钓鱼人。\n禹食传中使，尧樽遍下臣。\n省方称国阜，问道识风淳。\n岁晚天行吉，年丰景从亲。\n欢娱包历代，宇宙忽疑春。' },
  { title: '春日江津游望', author: '杜审言', poem: '旅客摇边思，春江弄晚晴。\n烟销垂柳弱，雾卷落花轻。\n飞棹乘空下，回流向日平。\n鸟啼移几处，蝶舞乱相迎。\n忽叹人皆浊，堤防水至清。\n谷王常不让，深可戒中盈。' },
  { title: '泛舟送郑卿入京', author: '杜审言', poem: '帝坐蓬莱殿，恩追社稷臣。\n长安遥向日，宗伯正乘春。\n相宅开基地，倾都送别人。\n行舟萦渌水，列戟满红尘。\n酒助欢娱洽，风催景气新。\n此时光乃命，谁为惜无津。' },
  { title: '度石门山', author: '杜审言', poem: '石门千仞断，迸水落遥空。\n道束悬崖半，桥欹绝涧中。\n仰攀人屡息，直下骑才通。\n泥拥奔虵径，云埋伏兽丛。\n星躔牛斗北，地脉象牙东。\n开塞随行变，高深触望同。\n江声连骤雨，日气抱残虹。\n未改朱明律，先含白露风。\n坚贞深不惮，险澁谅难穷。\n有异登临赏，徒为造化功。' },
  { title: '赠崔融二十韵', author: '杜审言', poem: '十年俱薄宦，万里各他方。\n云天断书札，风土异炎凉。\n太息幽兰紫，劳歌奇树黄。\n日疑怀叔度，夜似忆真长。\n北使从江表，东归在洛阳。\n相逢慰畴昔，相对叙存亡。\n草深穷巷毁，竹尽故园荒。\n雅节君弥固，衰颜余自伤。\n人事盈虚改，交游宠辱妨。\n雀罗争去翟，鹤氅竞寻王。\n思极欢娱至，朋情讵可忘。\n琴樽横宴席，岩谷卧词场。\n连骑追佳赏，城中及路傍。\n三川宿雨霁，四月晚花芳。\n复此开悬榻，宁唯入后堂。\n兴酣鸲鹆舞，言洽凤皇翔。\n高选俄迁职，严程已饬装。\n抚躬衔道义，携手恋辉光。\n玉振先推美，金铭旧所防。\n勿嗟离别易，行役共时康。' },
  { title: '赠苏味道', author: '杜审言', poem: '北地寒应苦，南庭戍未归。\n边声乱羗笛，朔气卷戎衣。\n雨雪关山暗，风霜草木稀。\n胡兵战欲尽，虏骑猎犹肥。\n雁塞何时入，龙城几度围。\n据鞍雄劒动，插笔羽书飞。\n舆驾还京邑，朋游满帝畿。\n方期来献凯，歌舞共春辉。' },
  { title: '赠苏绾书记', author: '杜审言', poem: '知君书记本翩翩，为许从戎赴朔边。\n红粉楼中应计日，燕支山下莫经年。' },
  { title: '渡湘江', author: '杜审言', poem: '迟日园林悲昔游，今春花鸟作边愁。\n独怜京国人南窜，不似湘江水北流。' },
  { title: '戏赠赵使君美人', author: '杜审言', poem: '红粉青娥暎楚云，桃花马上石榴帬。\n罗敷独向东方去，谩学他家作使君。' },
  { title: '三妇艳', author: '董思恭', poem: '大妇裁纨素，中妇弄明珰。\n小妇多姿态，登楼红粉妆。\n丈人且安坐，初日渐流光。' },
  { title: '感怀', author: '董思恭', poem: '野郊怆新别，河桥非旧饯。\n惨日映峰沈，愁云随盖转。\n哀笳时断续，悲旌乍舒卷。\n望望情何极，浪浪泪空泫。\n无复昔时人，芳春共谁遣。' },
  { title: '守岁二首 一', author: '董思恭', poem: '暮景斜芳殿，年华丽绮宫。\n寒辞去冬雪，暖带入春风。\n阶馥舒梅素，盘花卷烛红。\n共欢新故岁，迎送一宵中。' },
  { title: '守岁二首 二', author: '董思恭', poem: '岁阴穷暮纪，献节启新芳。\n冬尽今宵促，年开明日长。\n冰销出镜水，梅散入风香。\n对此欢终宴，倾壶待曙光。' },
  { title: '昭君怨二首 一', author: '董思恭', poem: '新年犹尚小，那堪远聘秦。\n裾衫沾马汗，眉黛染胡尘。\n举眼无相识，路逢皆异人。\n唯有梅将李，犹带故乡春。' },
  { title: '昭君怨二首 二', author: '董思恭', poem: '琵琶马上弹，行路曲中难。\n汉月正南远，燕山直北寒。\n髻鬟风拂乱，眉黛雪沾残。\n斟酌红颜改，徒劳握镜看。' },
  { title: '咏日', author: '董思恭', poem: '沧海十枝晖，悬圃重轮庆。\n蕣华发晨楹，菱彩飜朝镜。\n忽遇惊风飘，自有浮云映。\n更也人皆仰，无待挥戈正。' },
  { title: '咏月', author: '董思恭', poem: '北堂未安寝，西园聊骋望。\n玉户照罗帏，珠轩明绮障。\n别客长安道，思妇高楼上。\n所愿君莫违，清风时可访。' },
  { title: '咏星', author: '董思恭', poem: '历历东井舍，昭昭右掖垣。\n云际龙文出，池中鸟色飜。\n流辉下月路，坠影入河源。\n方知颍川集，别有太丘门。' },
  { title: '咏风', author: '董思恭', poem: '萧萧度阊阖，习习下庭闱。\n花蝶自飘舞，兰蕙生光辉。\n相乌正举翼，退鹢已惊飞。\n方从列子御，更逐浮云归。' },
  { title: '咏云', author: '董思恭', poem: '帝乡白云起，飞盖上天衢。\n带月绮罗映，从风枝叶敷。\n参差过层阁，倏忽下苍梧。\n因风望既远，安得久踟蹰。' },
  { title: '咏雪', author: '董思恭', poem: '天山飞雪度，言是落花朝。\n惜哉不我与，萧索从风飘。\n鲜洁凌纨素，纷糅下枝条。\n良时竟何在，坐见容华销。' },
  { title: '咏露', author: '董思恭', poem: '夜色凝仙掌，晨甘下帝庭。\n不觉九秋至，远向三危零。\n芦渚花初白，葵园叶尚青。\n晞阳一洒惠，方愿益沧溟。' },
  { title: '咏雾', author: '董思恭', poem: '苍山寂已暮，翠观黯将沈。\n终南晨豹隐，巫峡夜猿吟。\n天寒气不歇，景晦色方深。\n待访公超市，将予赴华阴。' },
  { title: '咏虹', author: '董思恭', poem: '春暮萍生早，日落雨飞余。\n横彩分长汉，倒色媚清渠。\n梁前朝影出，桥上晚光舒。\n愿逐旌旗转，飘飘侍直庐。' },
  { title: '咏桃', author: '董思恭', poem: '禁苑春光丽，花蹊几树装。\n缀条深浅色，点露参差光。\n向日分千笑，迎风共一香。\n如何仙岭侧，独秀隐遥芳。' },
  { title: '咏李', author: '董思恭', poem: '盘根植瀛渚，交干横倚天。\n舒华光四海，卷叶荫山川。' },
  { title: '咏弓', author: '董思恭', poem: '上弦明月半，激箭流星远。\n落雁带书惊，啼猿映枝转。' },
  { title: '咏琵琶', author: '董思恭', poem: '半月无双影，金花有四时。\n摧藏千里态，掩抑几重悲。\n促节萦红袖，清音满翠帷。\n驶弹风响急，缓曲钏声迟。\n空余关陇恨，因此代相思。' },
  { title: '咏琴', author: '刘允济', poem: '昔在龙门侧，谁想凤鸣时。\n雕琢今为器，宫商不自持。\n巴人缓疎节，楚客弄繁丝。\n欲作高张引，飜成下调悲。' },
  { title: '怨情', author: '刘允济', poem: '玉关芳信断，兰闺锦字新。\n愁来好自抑，念切已含嚬。\n虚牖风惊梦，空床月厌人。\n归期倘可促，勿度柳园春。' },
  { title: '见道边死人', author: '刘允济', poem: '凄凉徒见日，冥寞讵知年。\n魂兮不可问，应为直如弦。' },
  { title: '九日登玄武山旅眺', author: '邵大震', poem: '九月九日望遥空，秋水秋天生夕风。\n寒雁一向南去远，游人几度菊花丛。' },
  { title: '奉和圣制夏日游石淙山', author: '姚崇', poem: '二室三涂光地险，均霜揆日处天中。\n石泉石镜恒留月，山鸟山花竞逐风。\n周王久谢瑶池赏，汉主悬慙玉树宫。\n别有祥烟伴佳气，能随轻辇共葱葱。' },
  { title: '故洛阳城侍宴应制', author: '姚崇', poem: '游豫停仙跸，登临对晚晴。\n川凫连倒影，岩鸟应虚声。\n野奏风成曲，山居云作缨。\n今朝丘壑上，高兴小蓬瀛。' },
  { title: '春日洛阳城侍宴', author: '姚崇', poem: '南山开宝历，北渚对芳蹊。\n的历风梅度，参差露草低。\n尧樽临上席，舜乐下前溪。\n任重由来醉，乘酣志转迷。' },
  { title: '秋夜望月', author: '姚崇', poem: '明月有余鉴，羁人殊未安。\n桂含秋树晚，波入夜池寒。\n灼灼云枝净，光光草露团。\n所思迷所在，长望独长叹。' },
  { title: '夜渡江', author: '姚崇', poem: '夜渚带浮烟，苍茫晦远天。\n舟轻不觉动，缆急始知牵。\n听草遥寻岸，闻香暗识莲。\n唯看孤帆影，常似客心悬。' },
  { title: '奉和圣制龙池篇', author: '姚崇', poem: '恭闻帝里生灵沼，应报明君鼎业新。\n既协翠泉光宝命，还符白水出真人。\n此时舜海潜龙跃，此地尧河带马巡。\n独有前池一小雁，叨承旧惠入天津。' },
  { title: '奉和御制璟与张说源乾曜同日上官命宴都堂赐诗应制', author: '宋璟', poem: '丞相邦之重，非贤谅不居。\n老臣慵且惫，何德以当诸。\n厚秩先为忝，崇班复此除。\n太常陈礼乐，中掖降簪裾。\n圣酒山河润，仙文象纬舒。\n冒恩怀宠锡，陈力省空虚。\n郭隗慙无骏，冯谖媿有鱼。\n不知周勃者，荣幸定何如。' },
  { title: '奉和圣制同二相已下群官乐游园宴', author: '宋璟', poem: '侍饮终酺会，承恩续胜游。\n戴天惟庆幸，选地即殊尤。\n北向祗双阙，南临赏一丘。\n曲江新溜暖，上苑杂花稠。\n亹亹韶弦屡，戋戋贲帛周。\n醉归填畛陌，荣耀接轩裘。' },
  { title: '奉和圣制送张说巡边', author: '宋璟', poem: '帝道薄存兵，王师尚有征。\n是关司马法，爰命总戎行。\n画阃崇威信，分麾盛宠荣。\n聚观方结辙，出祖遂倾城。\n圣酒江河润，天词象纬明。\n德风边草偃，胜气朔云平。\n宰国推良器，为军挹壮声。\n至和常得体，不战即亡精。\n以智泉宁竭，其徐海自清。\n迟还庙堂坐，赠别故人情。' },
  { title: '奉和圣制荅张说扈从南出雀鼠谷', author: '宋璟', poem: '秦地雄西夏，幷州近北胡。\n禹行山启路，舜在邑为都。\n忽视寒暄隔，深思险易殊。\n四时宗伯叙，六义宰臣铺。\n征作宫常应，星环日每纡。\n盛哉逢道合，良以致亨衢。' },
  { title: '蒲津迎驾', author: '宋璟', poem: '回銮下蒲坂，飞斾指秦京。\n雒上黄云送，关中紫气迎。\n霞朝看马色，月晓听鸡鸣。\n防拒连山险，长桥压水平。\n省方知化洽，察俗觉时清。\n天下长无事，空余襟带名。' },
  { title: '送苏尚书赴益州', author: '宋璟', poem: '我望风烟接，君行霰雪飞。\n园亭若有送，杨柳最依依。' },
  { title: '初春行宫侍宴应制', author: '苏味道', poem: '温液吐涓涓，跳波急应弦。\n簪裾承睿赏，花柳发韶年。\n圣酒千钟洽，宸章七曜悬。\n微臣从此醉，还似梦钧天。' },
  { title: '单于川对雨二首 一', author: '苏味道', poem: '崇朝遘行雨，薄晚屯密云。\n缘阶起素沫，竟水聚圆文。\n河柳低未举，山花落已芬。\n清尊久不荐，淹留遂待君。' },
  { title: '单于川对雨二首 二', author: '苏味道', poem: '飞雨欲迎旬，浮云已送春。\n还从濯枝后，来应洗兵辰。\n气合龙祠外，声过鲸海滨。\n伐邢知有属，已见静边尘。' },
  { title: '正月十五夜', author: '苏味道', poem: '火树银花合，星桥铁锁开。\n暗尘随马去，明月逐人来。\n游伎皆秾李，行歌尽落梅。\n金吾不禁夜，玉漏莫相催。' },
  { title: '咏雾', author: '苏味道', poem: '氤氲起洞壑，遥裔匝平畴。\n乍似含龙劒，还疑映蜃楼。\n拂林随雨密，度径带烟浮。\n方谢公超步，终从彦辅游。' },
  { title: '咏虹', author: '苏味道', poem: '纡余带星渚，窈窕架天浔。\n空因壮士见，还共美人沈。\n逸照含良玉，神花藻瑞金。\n独留长劒彩，终负昔贤心。' },
  { title: '咏霜', author: '苏味道', poem: '金祇暮律尽，玉女暝氛归。\n孕冷随钟彻，飘华逐劒飞。\n带日浮寒影，乘风进晚威。\n自有贞筠质，宁将庶草腓。' },
  { title: '咏井', author: '苏味道', poem: '玲珑映玉槛，澄澈泻银床。\n流声集孔雀，带影出𫅗羊。\n桐落秋蛙散，桃舒春锦芳。\n帝力终何有，机心庶此忘。' },
  { title: '咏石', author: '苏味道', poem: '济北甄神贶，河西濯锦文。\n声应天池雨，影触岱宗云。\n燕归犹可候，羊起自成群。\n何当握灵髓，高枕绝嚣氛。' },
  { title: '奉和受图温洛应制', author: '苏味道', poem: '绿绮膺河检，清坛俯洛滨。\n天旋俄制跸，孝享属严禋。\n陟配光三祖，怀柔洎百神。\n雾开中道日，雪歛属车尘。\n预奉咸英奏，长歌亿万春。' },
  { title: '使岭南闻崔马二御史竝拜台郎', author: '苏味道', poem: '振鹭齐飞日，迁莺远听闻。\n明光共待漏，清鉴各披云。\n喜得廊庙举，嗟为台阁分。\n故林怀柏悦，新幄阻兰薰。\n冠去神羊影，车迎瑞雉群。\n远从南斗外，遥仰列星文。' },
  { title: '赠封御史入台', author: '苏味道', poem: '故事推三独，兹辰对两闱。\n夕鸦共鸣舞，屈草接芳菲。\n盛府持清橐，殊章动绣衣。\n风连台阁起，霜就简书飞。\n凛凛当朝色，行行满路威。\n惟当击隼去，复覩落雕归。' },
  { title: '始背洛城秋郊瞩目奉怀台中诸侍御', author: '苏味道', poem: '薄游忝霜署，直指戒冰心。\n荔浦方南纪，蘅臯暂北临。\n山晴关塞断，川暮广城阴。\n场圃通圭甸，沟塍碍石林。\n野童来捃拾，田叟去讴吟。\n蟋蟀秋风起，蒹葭晚露深。\n帝城犹郁郁，征传几骎骎。\n回忆披书地，劳歌谢所钦。' },
  { title: '九江口南济北接蕲春南与浔阳岸', author: '苏味道', poem: '江路一悠哉，滔滔九派来。\n远潭昏似雾，前浦沸成雷。\n鳞介多潜育，渔商几溯洄。\n风摇蜀柹下，日照楚萍开。\n近漱湓城曲，斜吹蠡泽隈。\n锡龟犹入贡，浮兽罢为灾。\n津吏挥桡疾，邮童整传催。\n归心讵可问，为视落潮回。' },
  { title: '和武三思于天中寺寻复礼上人之作', author: '苏味道', poem: '藩戚三雍暇，禅居二室隈。\n忽闻从桂苑，移步践花台。\n敏学推多艺，高谈属辩才。\n是非宁滞着，空有掠嫌猜。\n五行幽机畅，三蕃妙键开。\n味同甘露洒，香似逆风来。\n砌古留方石，池清辨烧灰。\n人寻鹤洲返，月逐虎谿回。\n企躅瞻飞盖，攀游想渡杯。\n愿陪为善乐，从此去尘埃。' },
  { title: '嵩山石淙侍宴应制', author: '苏味道', poem: '雕舆藻衞拥千官，仙洞灵谿访九丹。\n隐暧源花迷近路，参差岭竹扫危坛。\n重崖对耸霞文駮，瀑水交飞雨气寒。\n天洛宸襟有余兴，裴回周矖驻归銮。' },
  { title: '古劒篇', author: '郭震', poem: '君不见昆吾铁冶飞炎烟，红光紫气俱赫然。\n良工锻炼凡几年，铸得宝劒名龙泉。\n龙泉颜色如霜雪，良工咨嗟叹奇绝。\n琉璃玉匣吐莲花，错镂金环映明月。\n正逢天下无风尘，幸得周防君子身。\n精光黯黯青蛇色，文章片片绿龟鳞。\n非直结交游侠子，亦曾亲近英雄人。\n何言中路遭弃捐，零落漂沦古狱边。\n虽复尘埋无所用，犹能夜夜气冲天。' },
  { title: '塞上', author: '郭震', poem: '塞外虏尘飞，频年出武威。\n死生随玉劒，辛苦向金微。\n久戍人将老，长征马不肥。\n仍闻酒泉郡，已合数重围。' },
  { title: '寄刘校书', author: '郭震', poem: '俗吏三年何足论，每将荣辱在朝昏。\n才微易向风尘老，身贱难酬知己恩。\n御苑残莺啼落日，黄山细雨湿归轩。\n回首汉家丞相府，昨来谁得扫重门。' },
  { title: '同徐员外除太子舍人寓直之作', author: '郭震', poem: '太子擅元良，宫臣命伟长。\n除荣辞会府，直宿总书坊。\n露湿幽岩桂，风吹便坐桑。\n阁连云一色，池带月重光。\n叶死兰无气，荷枯水不香。\n遥闻秋兴作，言是晋中郎。' },
  { title: '春江曲', author: '郭震', poem: '江水春沈沈，上有双竹林。\n竹叶坏水色，郎亦坏人心。' },
  { title: '王昭君三首 一', author: '郭震', poem: '自嫁单于国，长衔汉掖悲。\n容颜日憔悴，有甚画图时。' },
  { title: '王昭君三首 二', author: '郭震', poem: '厌践冰霜域，嗟为边塞人。\n思从漠南猎，一见汉家尘。' },
  { title: '王昭君三首 三', author: '郭震', poem: '闻有南河信，传言杀画师。\n始知君念重，更肯惜蛾眉。' },
  { title: '子夜四时歌六首 春歌 一', author: '郭震', poem: '陌头杨柳枝，已被春风吹。\n妾心正断绝，君怀那得知。' },
  { title: '子夜四时歌六首 春歌 二', author: '郭震', poem: '青楼含日光，绿池起风色。\n赠子同心花，殷勤此何极。' },
  { title: '子夜四时歌六首 秋歌 一', author: '郭震', poem: '邀欢空伫立，望美频回顾。\n何时复采菱，江中密相遇。' },
  { title: '子夜四时歌六首 秋歌 二', author: '郭震', poem: '辟恶茱萸囊，延年菊花酒。\n与子结绸缪，丹心此何有。' },
  { title: '子夜四时歌六首 冬歌 一', author: '郭震', poem: '北极严气升，南至温风谢。\n调丝竞短歌，拂枕怜长夜。' },
  { title: '子夜四时歌六首 冬歌 二', author: '郭震', poem: '帷横双翡翠，被卷两鸳鸯。\n婉态不自得，宛转君王床。' },
  { title: '二月乐游诗', author: '郭震', poem: '二月芳游始，开轩望晓池。\n绿兰日吐叶，红蘂向盈枝。\n柳色行将改，君心幸莫移。\n阳春遽多意，唯愿两人知。' },
  { title: '十月乐游诗', author: '郭震', poem: '十月严阴盛，霜气下玉台。\n罗衣羞自解，绮帐待君开。\n银箭更筹缓，金炉香气来。\n愁仍夜未几，已使炭成灰。' },
  { title: '萤', author: '郭震', poem: '秋风凛凛月依依，飞过高梧影里时。\n暗处若教同众类，世间争得有人知。' },
  { title: '蛩', author: '郭震', poem: '愁杀离家未达人，一声声到枕前闻。\n苦吟莫向朱门里，满耳笙歌不听君。' },
  { title: '云', author: '郭震', poem: '聚散虚空去复还，野人闲处倚筇看。\n不知身是无根物，蔽月遮星作万端。' },
  { title: '野井', author: '郭震', poem: '纵无汲引味清澄，冷浸寒空月一轮。\n凿处若教当要路，为君常济往来人。' },
  { title: '米囊花', author: '郭震', poem: '开花空道胜于草，结实何曾济得民。\n却笑野田禾与黍，不闻弦管过青春。' },
  { title: '惜花', author: '郭震', poem: '艳拂衣襟蘂拂杯，遶枝闲共蝶徘徊。\n春风满目还惆怅，半欲离披半未开。' },
  { title: '莲花', author: '郭震', poem: '脸腻香薰似有情，世间何物比轻盈。\n湘妃雨后来池看，碧玉盘中弄水晶。' },
  { title: '弘农清岩曲有磐石可坐宋十一每拂拭待余寄诗赠之', author: '田游岩', poem: '信彼称灵石，居然狎遁栖。\n裴回承翠𪩘，斌驳带深谿。\n夕阴起层岫，清景半虹霓。\n风来应啸阮，波动可琴嵇。\n仆也颍阳客，望彼空思齐。\n傥见山人至，簪嵩且杖藜。' },
  { title: '和宋之问下山歌', author: '王无竞', poem: '日云暮兮下嵩山，路连绵兮树石间。\n出谷口兮见明月，心裴回兮不能还。' },
  { title: '北使长城', author: '王无竞', poem: '秦世筑长城，长城无极已。\n暴兵四十万，兴工九千里。\n死人如乱麻，白骨相撑委。\n殚弊未云悟，穷毒岂知止。\n胡尘未北灭，楚兵遽东起。\n六国复嚣嚣，两龙鬬觺觺。\n卯金竟握谶，反璧俄沦祀。\n仁义寝邦国，狙暴行终始。\n一旦咸阳宫，翻为汉朝市。' },
  { title: '凤台曲', author: '王无竞', poem: '凤台何逶迤，嬴女管参差。\n一旦彩云至，身去无还期。\n遗曲此台上，世人多学吹。\n一吹一落泪，至今怜玉姿。' },
  { title: '铜雀台', author: '王无竞', poem: '北登铜雀上，西望青松郭。\n𰬸帐空苍苍，陵田纷漠漠。\n平生事已变，歌吹宛犹昨。\n长袖拂玉尘，遗情结罗幕。\n妾怨在朝露，君恩岂中薄。\n高台奏曲终，曲终泪横落。' },
  { title: '巫山', author: '王无竞', poem: '神女向高唐，巫山下夕阳。\n裴回行作雨，婉娈逐荆王。\n电影江前落，雷声峡外长。\n朝云无处所，台馆晓苍苍。' },
  { title: '和宋之问下山歌', author: '贾曾', poem: '良游晼晚兮月呈光，锦路逶迤兮山路长。\n王孙不留兮岁将晏，嵩岩仙草兮为谁芳。' },
  { title: '孝和皇帝挽歌', author: '贾曾', poem: '新命千龄启，鸿图累圣余。\n天行应潜跃，帝出受图书。\n礼若传尧旧，功疑复夏初。\n梦游长不返，何国是华胥。' },
  { title: '奉和春日出苑瞩目应令', author: '贾曾', poem: '铜龙晓辟问安回，金辂春游博望开。\n渭北晴光摇草树，终南佳气入楼台。\n招贤已得商山老，托乘还征邺下才。\n臣在东周独留滞，忻逢睿藻日边来。' },
  { title: '有所思', author: '贾曾', poem: '洛阳城东桃李花，飞来飞去落谁家。\n幽闺女儿爱颜色，坐见落花长叹息。\n今岁花开君不待，明年花开复谁在。\n故人不共洛阳东，今来空对落花风。\n年年岁岁花相似，岁岁年年人不同。' },
  { title: '祭汾阴乐章', author: '贾曾', poem: '蠲我渐饎，洁我膋芗。\n有豆孔硕，为羞既臧。\n至城无昧，精意惟芳。\n神其醉止，欣欣乐康。' },
  { title: '使至汴州喜逢宋之问', author: '李夔', poem: '阮籍蓬池上，孤韵竹林才。\n巨源从吏道，正拥使车来。\n相逢且交臂，相命且衔杯。\n醉后长歌毕，余声绕吹台。' },
  { title: '祭汾阴乐章', author: '崔玄童', poem: '聿修严配，展事禋宗。\n祥符宝鼎，礼备黄琮。\n祝词以信，明德惟聪。\n介兹景福，永永无穷。' },
  { title: '祭汾阴乐章', author: '何鸾', poem: '乐奏云阕，礼章载虔。\n禋宗于地，昭假于天。\n惟馨荐矣，既醉歆焉。\n神之降福，永永万年。' },
  { title: '祭汾阴乐章', author: '蒋挺', poem: '维岁之吉，维辰之良。\n圣君绂冕，肃事坛场。\n大礼已备，大乐斯张。\n神其醉止，降福无疆。' },
  { title: '关山月', author: '崔融', poem: '月生西海上，气逐边风壮。\n万里度关山，苍茫非一状。\n汉兵开郡国，胡马窥亭障。\n夜夜闻悲笳，征人起南望。' },
  { title: '拟古', author: '崔融', poem: '饮马临浊河，浊河深不测。\n河水日东注，河源乃西极。\n思君正如此，谁为生羽翼。\n日夕大川阴，云霞千里色。\n所思在河处，宛在机中织。\n离梦当有魂，愁容定无力。\n夙龄负奇志，中夜三叹息。\n拔劒斩长榆，弯弓射小棘。\n班张固非拟，衞霍行可即。\n寄谢闺中人，努力加飧食。' },
  { title: '西征军行遇风', author: '崔融', poem: '北风卷尘沙，左右不相识。\n飒飒吹万里，昏昏同一色。\n马烦莫敢进，人急未遑食。\n曹木春更悲，天景昼相匿。\n夙龄慕忠义，雅尚存孤直。\n览史怀浸骄，读诗叹孔棘。\n及兹戎旅地，忝从书记职。\n兵气腾北荒，军声振西极。\n坐觉威灵远，行看氛祲息。\n愚臣何以报，倚马申微力。' },
  { title: '塞垣行', author: '崔融', poem: '疾风卷溟海，万里扬沙砾。\n仰望不见天，昏昏竟朝夕。\n是时军两进，东拒复西敌。\n蔽山张旗鼓，间道潜锋镝。\n精骑突晓围，奇兵袭暗壁。\n十月边塞寒，四山沍阴积。\n雨雪鴈南飞，风尘景西迫。\n昔我事讨论，未尝怠经籍。\n一朝弃笔砚，十年操矛戟。\n岂要黄河誓，须勒燕山石。\n可嗟牧羊臣，海外久为客。' },
  { title: '登东阳沈隐侯八咏楼', author: '崔融', poem: '旦登西北楼，楼峻石墉厚。\n宛生长定□，俯压三江口。\n排阶衔鸟衡，交疏过牛斗。\n左右会稽镇，出入具区薮。\n越岩森其前，浙江漫其后。\n此地实东阳，由来山水乡。\n隐侯有遗咏，落简尚余芳。\n具物昔未改，斯人今已亡。\n粤余忝藩左，束髪事文场。\n怅不见夫子，神期遥相望。' },
  { title: '从军行', author: '崔融', poem: '穹庐杂种乱金方，武将神兵下玉堂。\n天子旌旗过细柳，匈奴运数尽枯杨。\n关头落月横西岭，塞下凝云断北荒。\n漠漠边尘飞众鸟，昏昏朔气聚群羊。\n依稀蜀杖迷新竹，髣髴胡床识故桑。\n临海旧来闻骠骑，寻河本自有中郎。\n坐看战壁为平土，近待军营作破羌。' },
  { title: '和宋之问寒食题黄梅临江驿', author: '崔融', poem: '春分自淮北，寒食渡江南。\n忽见浔阳水，疑是宋家潭。\n明主阍难呌，孤臣逐未堪。\n遥思故园陌，桃李正酣酣。' },
  { title: '留别杜审言幷呈洛中旧游', author: '崔融', poem: '斑鬓今为别，红颜昨共游。\n年年春不待，处处酒相留。\n驻马西桥上，回车南陌头。\n故人从此隔，风月坐悠悠。' },
  { title: '咏宝劒', author: '崔融', poem: '宝劒出昆吾，龟龙夹采珠。\n五精初献术，千户竞沦都。\n匣气冲牛斗，山形转辘轳。\n欲知天下贵，持此问风胡。' },
  { title: '吴中好风景', author: '崔融', poem: '洛渚问吴潮，吴门想洛桥。\n夕烟杨柳岸，春水木兰桡。\n城邑高楼近，星辰北斗遥。\n无因生羽翼，轻举托还飙。' },
  { title: '则天皇后挽歌二首 一', author: '崔融', poem: '宵陈虚禁夜，夕临空山阴。\n日月昏尺景，天地惨何心。\n紫殿金铺涩，黄陵玉座深。\n镜匳长不启，圣主泪沾巾。' },
  { title: '则天皇后挽歌二首 二', author: '崔融', poem: '前殿临朝罢，长陵合葬归。\n山川不可望，文物尽成非。\n阴月霾中道，轩星落太微。\n空余天子孝，松上景云飞。' },
  { title: '户部尚书崔公挽歌', author: '崔融', poem: '八座图书委，三台章奏盈。\n举杯常有劝，曳履忽无声。\n市若荆州罢，池如薛县平。\n空余济南劒，天子署高名。' },
  { title: '韦长史挽词', author: '崔融', poem: '日落桑榆下，寒生松柏中。\n冥冥多苦雾，切切有悲风。\n京兆新阡辟，扶阳甲第空。\n郭门从此去，荆棘渐蒙笼。' },
  { title: '和梁王众传张光禄是王子晋后身', author: '崔融', poem: '闻有冲天客，披云下帝畿。\n三年上宾去，千载忽来归。\n昔偶浮丘伯，今同丁令威。\n中郎才貌是，柱史姓名非。\n祗召趋龙阙，承恩拜虎闱。\n丹成金鼎献，酒至玉杯挥。\n天仗分旄节，朝容间羽衣。\n旧坛何处所，新庙坐光辉。\n汉主存仙要，淮南爱道机。\n朝朝缑氏鹤，长向洛城飞。' },
  { title: '哭蒋詹事俨', author: '崔融', poem: '江上有长离，从容盛羽仪。\n一鸣百兽舞，一举群鸟随。\n应我圣明代，巢君阿阁垂。\n钩陈侍帷扆，环衞奉旌麾。\n雅量沧海纳，完才庙廊施。\n养亲光孝道，事主竭忠规。\n贞节既已固，殊荣良不訾。\n朝游云汉省，夕宴芙蓉池。\n汲黯言当直，陈平智本奇。\n功成喜身退，时往惜年驰。\n镇国山基毁，中天柱石颓。\n将军空有颂，刺史独留碑。\n芜漫藏书壁，荒凉悬劒枝。\n昔余参下位，数载忝牵羁。\n置榻恩逾重，迎门礼自卑。\n竹林常接兴，黍谷每逢吹。\n逸翰金相发，清谈玉柄挥。\n不轻文举少，深叹子云疲。\n遗爱犹如在，残编尚可窥。\n即今流水曲，何处俗人知。' },
  { title: '嵩山石淙侍宴应制', author: '崔融', poem: '洞口仙岩类削成，泉香石冷昼含清。\n龙旗画月中天下，凤管披云此地迎。\n树作帷屏阳景翳，芝如宫阙夏凉生。\n今朝出豫临悬圃，明日陪游向赤城。' },
  { title: '塞上寄内', author: '崔融', poem: '旅魂惊塞北，归望断河西。\n春风若可寄，暂为遶兰闺。' },
  { title: '侍从途中口号应制', author: '阎朝隐', poem: '疵贱出山东，忠贞任土风。\n因敷河朔藻，得奉洛阳宫。\n一顾侍御史，再顾给事中。\n常愿粉肌骨，特荅造化功。' },
  { title: '奉和圣制夏日游石淙山', author: '阎朝隐', poem: '金台隐隐陵黄道，玉辇亭亭下绛雰。\n千种冈峦千种树，一重岩壑一重云。\n花落风吹红的历，藤垂日晃绿葐蒀。\n五百里内贤人聚，愿陪阊阖侍天文。' },
  { title: '鹦鹉猫儿篇', author: '阎朝隐', poem: '霹雳引，丰隆鸣，猛兽噫气蛇吼声。\n鹦鹉鸟，同资造化兮殊粹精。\n鹔鹴毛，翡翠翼。\n鹓雏延颈，鹍鸡弄色。\n鹦鹉鸟，同禀阴阳兮异埏埴。\n彼何为兮，隐隐振振。\n此何为兮，绿衣翠襟。\n彼何为兮，窘窘蠢蠢。\n此何为兮，好貌好音。\n彷彷兮徉徉，似妖姬躧步兮动罗裳。\n趋趋兮跄跄，若处子回眸兮登玉堂。\n爰有兽也，安其忍，觜其脇，距其胸，与之放旷浪浪兮，从从容容。\n钩爪锯牙也，宵行昼伏无以当，遇之兮忘味。\n抟击腾掷也，朝飞暮噪无以拒，逢之兮屏气。\n由是言之，贪残薄则智慧作，贪残临之兮不复攫。\n由是言之，智慧周则贪残囚，智慧犯之兮不复忧。\n菲形陋质虽贱微，皇王顾遇长光辉。\n离宫别馆临朝市，妙舞繁弦杂宫征。\n嘉喜堂前景福内，合欢殿上明光里。\n云母屏风文彩合，流苏斗帐香烟起。\n承恩宴盼接宴喜，高视七头金骆驼。\n平怀五尺铜狮子，国有君兮国有臣。\n君为主兮臣为宾，朝有贤兮朝有德。\n贤为君兮德为饰，千年万岁兮心转忆。' },
  { title: '三日曲水侍宴应制', author: '阎朝隐', poem: '三月重三日，千春续万春。\n圣泽如东海，天文似北辰。\n荷叶珠盘净，莲花宝盖新。\n陛下制万国，臣作水心人。' },
  { title: '奉和九日幸临渭亭登高应制得筵字', author: '阎朝隐', poem: '九九侍神仙，高高坐半天。\n文章二曜动，气色五星连。\n簪绂趋皇极，笙歌接御筵。\n愿因茱菊酒，相守百千年。' },
  { title: '奉和送金城公主适西蕃应制', author: '阎朝隐', poem: '甥舅重亲地，君臣厚义乡。\n还将贵公主，嫁与耨檀王。\n卤簿山河暗，琵琶道路长。\n回瞻父母国，日出在东方。' },
  { title: '奉和立春游苑迎春应制', author: '阎朝隐', poem: '管籥周移寰极里，乘舆望幸斗城𬮱。\n草根未结青丝缕，萝茑犹垂绿帔巾。\n鹊入巢中言改岁，燕衔书上道宜新。\n愿得长绳系取日，光临天子万年春。' },
  { title: '奉和圣制春日幸望春宫应制', author: '阎朝隐', poem: '句芒人面乘两龙，道是春神衞九重。\n彩胜年年逢七日，酴醿岁岁满千钟。\n宫梅间雪祥光遍，城柳含烟淑气浓。\n醉倒君前情未尽，愿因歌舞自为容。' },
  { title: '夜宴安乐公主新宅', author: '阎朝隐', poem: '凤皇鸣舞乐昌年，蜡炬开花夜管弦。\n半醉徐击珊瑚树，已闻钟漏晓声传。' },
  { title: '饯唐永昌', author: '阎朝隐', poem: '洛阳难理若棼丝，椎破连环定不疑。\n鹦鹉休言秦地乐，回头一顾一相思。' },
  { title: '明月歌', author: '阎朝隐', poem: '梅花雪白柳叶黄，云雾四起月苍苍，箭水泠泠刻漏长。\n挥玉指，拂罗裳，为君一奏楚明光。' },
  { title: '采莲女', author: '阎朝隐', poem: '采莲女，采莲舟，春日春江碧水流。\n莲衣承玉钏，莲刺罥银钩。\n薄暮敛容歌一曲，氛氲香气满汀洲。' },
  { title: '奉和登骊山应制', author: '阎朝隐', poem: '龙行踏绛气，天半语相闻。\n混沌疑初判，洪荒若始分。' },
  { title: '奉和九日幸临渭亭登高应制得月字', author: '韦元旦', poem: '云物开千里，天行乘九月。\n丝言丹凤池，斾转苍龙阙。\n灞水欢娱地，秦京游侠窟。\n欣承解愠词，圣酒黄花发。' },
  { title: '奉和送金城公主适西蕃应制', author: '韦元旦', poem: '柔远安夷俗，和亲重汉年。\n军容旌节送，国命锦车传。\n琴曲悲千里，箫声恋九天。\n唯应西海月，来就掌珠圆。' },
  { title: '饯唐州高使君赴任', author: '韦元旦', poem: '桐栢膺新命，芝兰惜旧游。\n鸣臯夜鹤在，迁木早莺求。\n传拥淮源路，尊空灞水流。\n落花纷送远，春色引离忧。' },
  { title: '早朝', author: '韦元旦', poem: '震维芳月季，宸极众星尊。\n珮玉朝三陛，鸣珂度九门。\n挈壶分早漏，伏槛耀初暾。\n北倚苍龙阙，西临紫凤垣。\n词庭草欲奏，温室树无言。\n鳞翰空为忝，长怀圣主恩。' },
  { title: '奉和立春游苑迎春应制', author: '韦元旦', poem: '灞涘长安恒近日，殷正腊月早迎新。\n池鱼戏叶仍含冻，宫女裁花已作春。\n向苑云疑承翠幄，入林风若起青苹。\n年年斗柄东无限，愿挹琼觞寿北辰。' },
  { title: '奉和圣制春日幸望春宫应制', author: '韦元旦', poem: '九重楼阁半山霞，四望韶阳春未赊。\n侍跸妍歌临灞涘，留觞艳舞出京华。\n危竿竞捧中街日，戏马争衔上苑花。\n景色欢娱长若此，承恩不醉不还家。' },
  { title: '奉和人日宴大明宫恩赐彩缕人胜应制', author: '韦元旦', poem: '鸾凤旌旗拂晓陈，鱼龙角觝大明辰。\n青韶既肇人为日，绮胜初成日作人。\n圣藻凌云裁栢赋，仙歌促宴摘梅春。\n垂旒一庆宜年酒，朝野俱欢荐寿新。' },
  { title: '奉和幸安乐公主山庄应制', author: '韦元旦', poem: '银河南渚帝城隅，帝辇平明出九衢。\n刻凤蟠螭凌桂邸，穿池叠石写蓬壶。\n琼箫暂下钧天乐，绮缀长悬明月珠。\n仙牓承恩争既醉，方知朝野更欢娱。' },
  { title: '兴庆池侍宴应制', author: '韦元旦', poem: '沧池漭沆帝城边，殊胜昆明凿汉年。\n夹岸旌旗疏辇道，中流箫鼓振楼船。\n云峰四起迎宸幄，水树千重入御筵。\n宴乐已深鱼藻咏，承恩更欲奏甘泉。' },
  { title: '夜宴安乐公主宅', author: '韦元旦', poem: '主第新成银作牓，宾筵广宴玉为楼。\n壶觞既卜仙人夜，歌舞宜停织女秋。' },
  { title: '奉和初春幸太平公主南庄应制', author: '邵升', poem: '沁园佳丽夺蓬瀛，翠壁红泉绕上京。\n二圣忽从鸾殿幸，双仙正下凤楼迎。\n花含步辇空间出，树杂帷宫画里行。\n无路乘槎窥汉渚，徒知访卜就君平。' },
  { title: '奉和送金城公主适西蕃应制', author: '唐远悊', poem: '皇恩睠下人，割爱远和亲。\n少女风游兑，姮娥月去秦。\n龙笛迎金榜，骊歌送锦轮。\n那堪桃李色，移向虏庭春。' },
  { title: '汾阴后土祠作', author: '李适', poem: '昔予读旧史，遍覩汉世君。\n武皇实稽古，建兹百代勋。\n号令垂懋典，旧经备阙文。\n西巡历九嶷，舳舻被江滨。\n勒兵十八万，旌旗何纷纷。\n朅来茂陵下，英声不复闻。\n我行岁方晏，极望山河分。\n神光终冥漠，鼎气独氛氲。\n揽涕步脽上，登高见彼汾。\n雄图今安在，飞飞有白云。' },
  { title: '荅宋十一崖口五渡见赠', author: '李适', poem: '闻君访远山，跻险造幽绝。\n眇然青云境，观奇弥年月。\n登岭亦溯溪，孤舟事沿越。\n崿嶂传彩翠，崖磴互欹缺。\n石林上攒藂，金涧下明灭。\n扪壁窥丹井，梯苔瞰乳穴。\n忽枉岩中赠，对玩未尝辍。\n殷勤独往事，委曲炼药说。\n邀余名山期，从尔泛海澨。\n岁晏秉宿心，斯言非徒设。' },
  { title: '饯许州宋司马赴任', author: '李适', poem: '昔吾游箕山，朅来涉颍水。\n复有许由庙，迢迢白云里。\n闻君佐繁昌，临风怅怀此。\n傥到平舆泉，寄谢干将里。' },
  { title: '奉和圣制九日侍宴应制得高字', author: '李适', poem: '禁苑秋光入，宸游霁色高。\n萸房颁彩笥，菊蘂荐香醪。\n后骑萦堤柳，前旌拂御桃。\n王枚俱得从，浅浅愧飞毫。' },
  { title: '游禁苑幸临渭亭遇雪应制', author: '李适', poem: '长乐喜春归，披香瑞雪霏。\n花从银合度，絮绕玉窗飞。\n写曜衔天藻，呈祥拂御衣。\n上林纷可望，无处不光辉。' },
  { title: '奉和九日登慈恩寺浮图应制', author: '李适', poem: '凤辇乘朝霁，鹦林对晚秋。\n天文贝叶写，圣泽菊花浮。\n塔似神功造，龛疑佛影留。\n幸陪清汉跸，欣奉净居游。' },
  { title: '侍宴长宁公主东庄应制', author: '李适', poem: '凤楼纡睿幸，龙舸畅宸襟。\n歌舞平阳第，园亭沁水林。\n山花添圣酒，涧竹绕熏琴。\n愿奉瑶池驾，千春侍德音。' },
  { title: '奉和送金城公主适西蕃应制', author: '李适', poem: '绛河从远聘，青海赴和亲。\n月作临边晓，花为度陇春。\n主歌悲顾鹤，帝策重安人。\n独有琼箫去，悠悠思锦轮。' },
  { title: '安乐公主移入新宅', author: '李适', poem: '星桥他日创，仙榜此时开。\n马向铺钱埒，箫闻奏玉台。\n人疑衞叔美，客似长卿才。\n借问游天使，谁能取石回。' },
  { title: '奉和幸望春宫送朔方军大总管张仁亶', author: '李适', poem: '地限骄南牧，天临饯北征。\n解衣延宠命，横劒总威名。\n豹略恭宸旨，雄文动睿情。\n坐观膜拜入，朝夕受降城。' },
  { title: '人日宴大明宫恩赐彩缕人胜应制', author: '李适', poem: '朱城待凤韶年至，碧殿疏龙淑气来。\n宝帐金屏人已帖，图花学鸟胜初裁。\n林香近接宜春苑，山翠遥添献寿杯。\n向夕凭高风景丽，天文垂耀象昭回。' },
  { title: '奉和春日幸望春宫应制', author: '李适', poem: '玉辇金舆天上来，花园四望锦屏开。\n轻丝半拂朱门柳，细缬全披画阁梅。\n舞蝶飞行飘御席，[歌莺]度曲绕仙杯。\n圣词今日光辉满，汉主秋风莫道才。' },
  { title: '奉和立春游苑迎春', author: '李适', poem: '金舆翠辇迎嘉节，御苑仙宫待献春。\n淑气初衔梅色浅，条风半拂柳墙新。\n天杯庆寿齐南岳，圣藻光辉动北辰。\n稍觉披香歌吹近，龙骖日暮下城𬮱。' },
  { title: '帝幸兴庆池戏竞渡应制', author: '李适', poem: '拂露金舆丹斾转，凌晨黼帐碧池开。\n南山倒影从云落，北涧摇光写溜回。\n急桨争标排荇度，轻帆截浦触荷来。\n横汾宴镐欢无极，歌舞年年圣寿杯。' },
  { title: '侍宴安乐公主庄应制', author: '李适', poem: '平阳金牓凤皇楼，沁水银河鹦鹉洲。\n彩仗遥临丹壑里，仙舆暂幸绿亭幽。\n前池锦石莲花艳，后岭香𬬻桂蘂秋。\n贵主称觞万年寿，还轻汉武济汾游。' },
  { title: '侍宴安乐公主新宅应制', author: '李适', poem: '银河半倚凤皇台，玉酒相传鹦鹉杯。\n若见君平须借问，仙槎一去几时来。' },
  { title: '饯唐永昌赴任东都', author: '李适', poem: '闻道飞凫向洛阳，翩翩矫翮度文昌。\n因声寄意三花树，少室岩前几过香。' },
  { title: '奉和圣制立春日侍宴内殿出剪彩花应制', author: '刘宪', poem: '上林宫馆好，春光独早知。\n剪花疑始发，刻燕似新窥。\n色浓轻雪点，香浅嫩风吹。\n此日叨陪侍，恩荣得数枝。' },
  { title: '奉和人日清晖阁宴群臣遇雪应制', author: '刘宪', poem: '舆辇乘人日，登临上凤京。\n风寻歌曲飏，雪向舞行萦。\n千官随兴合，万福与时幷。\n承恩长若此，微贱幸升平。' },
  { title: '奉和七夕宴两仪殿应制', author: '刘宪', poem: '秋吹过双阙，星仙动二灵。\n更深移月镜，河浅度云𫐌。\n殿上呼方朔，人间失武丁。\n天文兹夜里，光映紫微庭。' },
  { title: '奉和九月九日圣制登慈恩寺浮图应制', author: '刘宪', poem: '飞塔云霄半，清晨羽斾游。\n登临凭季月，寥廓见中州。\n御酒新寒退，天文瑞景留。\n辟邪将献寿，兹日奉千秋。' },
  { title: '闰九月九日幸总持寺登浮图应制', author: '刘宪', poem: '重阳登闰序，上界叶时巡。\n驻辇天花落，开筵妓乐陈。\n城端刹柱见，云表露盘新。\n临睨光辉满，飞文动睿神。' },
  { title: '侍宴长宁公主东庄', author: '刘宪', poem: '公主林亭地，清晨降玉舆。\n画桥飞渡水，仙阁涌临虚。\n晴新看蛱蝶，夏早摘芙蕖。\n文酒娱游盛，忻叨侍从余。' },
  { title: '奉和送金城公主入西蕃应制', author: '刘宪', poem: '外馆逾河右，行营指路岐。\n和亲悲远嫁，忍爱泣将离。\n旌斾羗风引，轩车汉月随。\n那堪马上曲，时向管中吹。' },
  { title: '奉和圣制登骊山高顶寓目应制', author: '刘宪', poem: '骊阜镇皇都，銮游眺八区。\n原隰旌门里，风云扆座隅。\n直城如斗柄，官树似星榆。\n从臣词赋末，滥得上天衢。' },
  { title: '奉和幸白鹿观应制', author: '刘宪', poem: '玄游乘落晖，仙宇蔼霏微。\n石梁萦涧转，珠斾扫坛飞。\n芝童荐膏液，松鹤舞骖𬴂。\n还似瑶池上，歌成周驭归。' },
  { title: '折杨柳', author: '刘宪', poem: '沙塞三河道，金闺二月春。\n碧烟杨柳色，红粉绮罗人。\n露叶怜啼脸，风花思舞巾。\n攀持君不见，为听曲中新。' },
  { title: '奉和立春日内出彩花树应制', author: '刘宪', poem: '禁苑韶年此日归，东郊道上转青旗。\n柳色梅芳何处所，风前雪里觅芳菲。\n开冰池内鱼新跃，剪彩花间燕始飞。\n欲识王游布阳气，为观天藻竞春晖。' },
  { title: '奉和春日幸望春宫应制', author: '刘宪', poem: '暮春春色最便妍，苑里花开列御筵。\n商山积翠临城起，浐水浮光共幕连。\n莺藏嫩叶歌相唤，蝶碍芳丛舞不前。\n欢娱节物今如此，愿奉宸游亿万年。' },
  { title: '奉和幸安乐公主山庄应制', author: '刘宪', poem: '主家别墅帝城隈，无劳海上觅蓬莱。\n沓石悬流平地起，危楼曲阁半天开。\n庭莎作荐舞行出，浦树相将歌棹回。\n此日风光与形胜，衹言作伴圣词来。' },
  { title: '兴庆池侍宴应制', author: '刘宪', poem: '苍龙阙下天泉池，轩驾来游箫管吹。\n缘堤夏筿萦不散，冐水新荷卷复披。\n帐殿疑从画里出，楼船直在镜中移。\n自然东海神仙处，何用西昆辙迹疲。' },
  { title: '奉和幸大荐福寺应制', author: '刘宪', poem: '地灵传景福，天驾俨钩陈。\n佳哉藩邸旧，赫矣梵宫新。\n香塔鱼山下，禅堂雁水滨。\n珠幡映白日，镜殿写青春。\n甚欢延故吏，大觉拯生人。\n幸承歌颂末，长奉属车尘。' },
  { title: '奉和幸三会寺应制', author: '刘宪', poem: '岧嶤仓史台，敞朗绀园开。\n戒旦壶人集，翻霜羽骑来。\n下辇登三袭，褰旒望九垓。\n林披馆陶牓，水浸昆明灰。\n网户飞花缀，幡竿度鸟回。\n豫游仙唱动，潇洒出尘埃。' },
  { title: '奉和幸长安故城未央宫应制', author: '刘宪', poem: '汉宫千祀外，轩驾一来游。\n夷荡长如此，威灵不复留。\n凭高睿赏发，怀古圣情周。\n寒向南山歛，春过北渭浮。\n土功昔云盛，人英今所求。\n幸听熏风曲，方知霸道羞。' },
  { title: '奉和幸礼部尚书窦希玠宅应制', author: '刘宪', poem: '北斗枢机任，西京肺腑亲。\n畴昔王门下，今兹御幸辰。\n恩光山水被，圣作管弦新。\n遶坐熏红药，当轩暗绿筠。\n摘荷才早夏，听鸟尚余春。\n行漏今徒晚，风烟起观津。' },
  { title: '奉和圣制幸望春宫送朔方大总管张仁亶', author: '刘宪', poem: '命将择耆年，图功胜必全。\n光辉万乘饯，威武二庭宣。\n中衢横鼓角，旷野蔽旌旃。\n推食天厨至，投醪御酒传。\n凉风过雁苑，杀气下鸡田。\n分阃恩何极，临岐动睿篇。' },
  { title: '奉和幸韦嗣立山庄侍宴应制', author: '刘宪', poem: '东山有谢安，枉道降鸣銮。\n缇骑分初日，霓旌度晓寒。\n云跸岩间下，虹桥涧底盘。\n幽栖俄以届，圣瞩宛余欢。\n崖悬飞溜直，岸转绿潭宽。\n桂华尧酒泛，松响舜琴弹。\n明主恩斯极，贤臣节更殚。\n不才叨侍从，咏德以濡翰。' },
  { title: '人日玩雪应制', author: '刘宪', poem: '胜日登临云叶起，芳风摇荡雪花飞。\n呈晖幸得承金镜，飏彩还将奉玉衣。' },
  { title: '上巳日祓禊渭滨应制', author: '刘宪', poem: '桃花欲落柳条长，沙头水上足风光。\n此时御跸来游处，愿奉年年祓禊觞。' },
  { title: '苑中遇雪应制', author: '刘宪', poem: '龙骖晓入望春宫，正逢春雪舞东风。\n花光倂洒天文上，寒气行消御酒中。' },
  { title: '夜宴安乐公主新宅', author: '刘宪', poem: '层轩洞户旦新披，度曲飞觞夜不疲。\n绮缀玲珑河色晓，珠帘隐映月华窥。' },
  { title: '奉和圣制幸韦嗣立山庄', author: '刘宪', poem: '非吏非隐晋尚书，一丘一壑降乘舆。\n天藻缘情两曜合，山巵献寿万年余。' },
  { title: '饯唐永昌', author: '刘宪', poem: '始见郎官拜洛阳，旋闻近侍发雕章。\n绪言已勖期年政，绮字当生满路光。' },
  { title: '晦日置酒林亭', author: '高正臣', poem: '正月符嘉节，三春玩物华。\n忘怀寄尊酒，陶性狎山家。\n柳翠含烟叶，梅芳带雪花。\n光阴不相借，迟迟落景斜。' },
  { title: '晦日重宴', author: '高正臣', poem: '芳辰重游衍，乘景共追随。\n班荆陪旧识，倾盖得新知。\n水叶分莲沼，风花落柳枝。\n自符河朔趣，宁羡高阳池。' },
  { title: '晦日宴高氏林亭', author: '崔知贤', poem: '上月河阳地，芳辰景物华。\n緜蛮变时鸟，照曜起春霞。\n柳摇风处色，梅散日前花。\n淹留洛城晚，歌吹石崇家。' },
  { title: '上元夜效小庾体', author: '崔知贤', poem: '今夜启城𬮱，结伴戏芳春。\n鼓声撩乱动，风光触处新。\n月下多游骑，灯前饶看人。\n欢乐无穷已，歌舞达明晨。' },
  { title: '三月三日宴王明府山亭', author: '崔知贤', poem: '京洛皇居，芳禊春余。\n影媚元巳，和风上除。\n云开翠帟，水鹜鲜居。\n林渚萦暎，烟霞卷舒。\n花飘粉蝶，藻跃文鱼。\n沿波式宴，其乐只且。' },
  { title: '三月三日宴王明府山亭', author: '席元明', poem: '日惟上巳，时亨有巢。\n中尊引桂，芳筵籍茅。\n书僮橐笔，膳夫行炰。\n烟霏万雉，花明四郊。\n沼苹白带，山花紫苞。\n同人聚饮，千载神交。' },
  { title: '晦日宴高氏林亭', author: '韩仲宣', poem: '欲知行有乐，芳尊对物华。\n地接安仁县，园是季伦家。\n柳处云疑叶，梅间雪似花。\n日落归途远，留兴伴烟霞。' },
  { title: '晦日重宴', author: '韩仲宣', poem: '凤苑先吹晚，龙楼夕照披。\n陈遵已投辖，山公正坐池。\n落日催金奏，飞霞送玉巵。\n此时陪绮席，不醉欲何为。' },
  { title: '上元夜效小庾体', author: '韩仲宣', poem: '他乡月夜人，相伴看灯轮。\n光随九华出，影共百枝新。\n歌钟盛北里，车马沸南邻。\n今宵何处好？惟有洛城春。' },
  { title: '三月三日宴王明府山亭', author: '韩仲宣', poem: '河滨上巳，洛汭春华。\n碧池涵日，翠斝澄霞。\n沟垂细柳，岸拥平沙。\n歌莺响树，舞蝶惊花。\n云浮宝马，水韵香车。\n熟记行乐，淹留景斜。' },
  { title: '晦日宴高氏林亭', author: '周彦昭', poem: '胜地临鸡浦，高会偶龙沙。\n御柳惊春色，仙筇掩月华。\n门邀千里驭，杯泛九光霞。\n日落山亭晚，雷送七香车。' },
  { title: '晦日宴高氏林亭', author: '高球', poem: '温洛年光早，皇州景望华。\n连镳寻上路，乘兴入山家。\n轻苔网危石，春水架平沙。\n赏极林塘暮，处处起烟霞。' },
  { title: '三月三日宴王[明]府山亭', author: '高球', poem: '洛城春禊，元巳芳年。\n季伦园里，逸少亭前。\n曲中举白，谈际生玄。\n陆离轩盖，凄清管弦。\n萍疎波荡，柳弱风牵。\n未淹欢趣，林溪夕烟。' },
  { title: '晦日宴高氏林亭', author: '弓嗣初', poem: '上序春晖丽，中园物候华。\n高才盛文雅，逸兴满烟霞。\n参差金谷树，皎镜碧塘沙。\n萧散林亭晚，倒载欲还家。' },
  { title: '晦日重宴', author: '弓嗣初', poem: '年华蔼芳隰，春溜满新池。\n促赏依三友，延欢寄一巵。\n鸟声随管变，花影逐风移。\n行乐方无极，淹留惜晚曦。' },
  { title: '三月三日宴王明府山亭', author: '高瑾', poem: '暮春元巳，春服初裁。\n童冠八九，于洛之隈。\n河堤草变，巩树花开。\n逸人谈发，仙御舟来。\n间关黄鸟，瀺灂丹腮。\n乐饮命席，优哉悠哉。' },
  { title: '晦日宴高氏林亭', author: '高瑾', poem: '试入山亭望，言是石崇家。\n二月风光起，三春桃李华。\n莺吟上乔木，雁往息平沙。\n相看会取醉，宁知还路赊。' },
  { title: '晦日重宴', author: '高瑾', poem: '忽闻莺响谷，于此命相知。\n正开彭泽酒，来向高阳池。\n柳叶风前弱，梅花影处危。\n赏洽林亭晚，落照下参差。' },
  { title: '上元夜效小庾体', author: '高瑾', poem: '初年三五夜，相知一两人。\n连镳出巷口，飞毂下池漘。\n灯光恰似月，人面倂如春。\n遨游终未已，相欢待日轮。' },
  { title: '晦日宴高氏林亭', author: '王茂时', poem: '践胜寻良会，乘春玩物华。\n还随张放友，来向石崇家。\n止水分岩镜，闲庭枕浦沙。\n未极林泉赏，参差落照斜。' },
  { title: '晦日宴高氏林亭', author: '徐皓', poem: '绮筵乘暇景，琼醑对年华。\n门多金埒骑，路引璧人车。\n苹早犹藏叶，梅残正落花。\n蔼蔼林亭晚，余兴促流霞。' },
  { title: '晦日宴高氏林亭', author: '长孙正隐', poem: '晦晚属烟霞，遨游重岁华。\n歌钟虽戚里，林薮是山家。\n细雨犹开日，深池不涨沙。\n淹留迷处所，岩岫几重花。' },
  { title: '上元夜效小庾体同用春字', author: '长孙正隐', poem: '薄晚啸游人，车马乱驱尘。\n月光三五夜，灯燄一重春。\n烟云迷北阙，箫管识南邻。\n洛城终不闭，更出小平津。' },
  { title: '晦日宴高氏林亭', author: '高绍', poem: '啸侣入山家，临春玩物华。\n葛弦调绿水，桂醑酌丹霞。\n岸柳开新叶，庭梅落早花。\n兴洽林亭晚，方还倒载车。' },
  { title: '晦日宴高氏林亭', author: '郎余令', poem: '三春休晦节，九谷泛年华。\n半晴余细雨，全晚澹残霞。\n尊开疎竹叶，管应落梅花。\n兴阑相顾起，流水送香车。' },
  { title: '晦日宴高氏林亭', author: '陈嘉言', poem: '公子申敬爱，携朋玩物华。\n人是平阳客，地即石崇家。\n水文生旧浦，风色满新花。\n日暮连归骑，长川照晚霞。' },
  { title: '晦日重宴', author: '陈嘉言', poem: '高门引冠盖，下客抱支离。\n绮席珍羞满，文场翰藻摛。\n蓂华雕上月，柳色蔼春池。\n日斜归戚里，连骑勒金羁。' },
  { title: '上元夜效小庾体', author: '陈嘉言', poem: '今夜可怜春，河桥多丽人。\n宝马金为络，香车玉作轮。\n连手窥潘掾，分头看洛神。\n重城自不掩，出向小平津。' },
  { title: '晦日宴高氏林亭', author: '周彦晖', poem: '砌蓂收晦魄，津柳竞年华。\n既狎忘筌友，方淹投辖车。\n绮筵回舞雪，琼醑泛流霞。\n云低上天晚，丝雨带风斜。' },
  { title: '晦日重宴', author: '周彦晖', poem: '春华归柳树，俯景落蓂枝。\n置驿铜街右，开筵玉浦陲。\n林烟含障密，竹雨带珠危。\n兴阑巾倒戴，山公下习池。' },
  { title: '晦日宴高氏林亭', author: '高峤', poem: '飞观写春望，开宴坐汀沙。\n积溜含苔色，晴空荡日华。\n歌入平阳第，舞对石崇家。\n莫虑能骑马，投辖自停车。' },
  { title: '晦日重宴', author: '高峤', poem: '驾言寻凤侣，乘欢俯雁池。\n班荆逢旧识，斟桂喜深知。\n紫兰方出径，黄莺未啭枝。\n别有陶春日，青天云雾披。' },
  { title: '晦日宴高氏林亭', author: '刘友贤', poem: '春来日渐赊，琴酒逐年华。\n欲向文通迳，先游武子家。\n池碧新流满，岩红落照斜。\n兴阑情未尽，步步惜风花。' },
  { title: '晦日宴高氏林亭', author: '周思钧', poem: '早春惊柳穟，初晦掩蓂华。\n骑出平阳里，筵开衞尉家。\n竹影含云密，池纹带雨斜。\n重惜林亭晚，上路满烟霞。' },
  { title: '晦日重宴', author: '周思钧', poem: '绮筵乘晦景，高宴下阳池。\n濯雨梅香散，含风柳色移。\n轻尘依扇落，流水入弦危。\n勿顾林亭晚，方欢云雾披。' },
  { title: '祭汾阴乐章', author: '苏颋', poem: '礼物斯具，乐章乃陈。\n谁其作主，皇考圣真。\n对越在天，圣明佐神。\n窅然汾上，厚泽如春。' },
  { title: '奉和圣制行次成皐途经先圣擒建德之所感而成诗应制', author: '苏颋', poem: '汉东不执象，河朔方鬬龙。\n夏灭渐宁乱，唐兴终奋庸。\n皇威正赫赫，兵气何匈匈。\n用武三川震，归淳六代𬪩。\n成臯覩王业，天下致人雍。\n即此巡于岱，曾孙受命封。' },
  { title: '奉和圣制登蒲州逍遥楼应制', author: '苏颋', poem: '在昔尧舜禹，遗尘成典谟。\n圣皇东巡狩，况乃经此都。\n楼观纷迤逦，河山几萦纡。\n缅怀祖宗业，相继文武图。\n尚德既无险，观风谅有孚。\n岂如汾水上，箫鼓事游娱。' },
  { title: '奉和圣制过晋阳宫应制', author: '苏颋', poem: '隋运与天绝，生灵厌氛昏。\n圣期在宁乱，士马兴太原。\n立极万邦推，登庸四海尊。\n庆膺神武帝，业付皇曾孙。\n缅慕封唐道，追惟归沛魂。\n诏书感先义，典礼巡旧藩。\n高殿彩云合，春旗祥风翻。\n率西见汾水，奔北空塞垣。\n款曲童儿佐，依迟故老言。\n里颁慈惠赏，家受复除恩。\n下辇崇三教，建碑当九门。\n孝思敦至美，亿载奉开元。' },
  { title: '奉和姚令公温汤旧馆永怀故人卢公之作', author: '苏颋', poem: '树德岂孤迈，降神良竝出。\n伟兹廊庙桢，调彼盐梅实。\n正悦虞垂举，翻悲郑侨卒。\n同心不可忘，交臂何为失。\n清路荷前幸，明时称右弼。\n曾联野外游，尚记帷中密。\n新恸情莫遣，旧游词更述。\n空令还辱和，长叹知音日。' },
  { title: '和杜主簿春日有所思', author: '苏颋', poem: '朝上高楼上，俯见洛阳陌。\n摇荡吹花风，落英纷已积。\n美人不共此，芳好空所惜。\n揽镜尘网滋，当窗苔藓碧。\n缅怀在云汉，良愿暌枕席。\n翻似无见时，如何久为客。' },
  { title: '饯郢州李使君', author: '苏颋', poem: '楚有章华台，遥遥云梦泽。\n复闻拥符传，及是收图籍。\n佳政在离人，能声寄侯伯。\n离怀朔风起，试望秋阴积。\n中路凄以寒，群山霭将夕。\n伤心聊把袂，怊怅麒麟客。' },
  { title: '饯唐州高使君赴任', author: '苏颋', poem: '永日奏文时，东风摇荡夕。\n浩然思乐事，翻复饯征客。\n淮水春流清，楚山暮云白。\n勿言行路远，所贵专城伯。' },
  { title: '晓济胶川南入密界', author: '苏颋', poem: '饮马胶川上，傍胶南趣密。\n林遥飞鸟迟，云去晴山出。\n落晖隐桑柘，秋原被花实。\n惨然游子寒，风露将萧瑟。' },
  { title: '夜发三泉即事', author: '苏颋', poem: '暗发三泉山，穷秋听骚屑。\n北林夜鸣雨，南望晓成雪。\n祗咏北风凉，讵知南土热。\n沙溪忽沸渭，石道乍明灭。\n宛若银碛横，复如瑶台结。\n指程赋所恋，遇虞不遑歇。\n重纩濡莫解，悬旌冻犹揭。\n下奔泥栈榰，上觏云梯设。\n[搏]颊羸马顿，回眸惴人跌。\n憧憧往复还，心注思逾切。\n冉冉年将病，力困衰怠竭。\n天彭信方隅，地势诚斗绝。\n忝曳尚书履，叨兼使臣节。\n京坻有岁饶，亭障无边孽。\n归奏丹墀左，骞能俟来哲。' },
  { title: '小园纳凉即事', author: '苏颋', poem: '烦暑避蒸郁，居闲习高明。\n长风自远来，层阁有余清。\n散洒纳凉气，萧条遗世情。\n奈何夸大隐，终日系尘缨。' },
  { title: '昆明池晏坐答王兵部珣三韵见示', author: '苏颋', poem: '画舸疾如飞，遥遥泛夕晖。\n石黥吹浪隐，玉女步尘归。\n独有衔恩处，明珠在钓矶。' },
  { title: '奉和圣制春台望应制', author: '苏颋', poem: '壮丽天之府，神明王者宅。\n大君乘飞龙，登彼复怀昔。\n圆阙朱光燄，横山翠微积。\n河汧流作表，县聚开成陌。\n即旧在皇家，维新具物华。\n云连所上居恒属，日更时中望不斜。\n三月沧池摇积水，万年青树缀新花。\n暴嬴国此尝图霸，霸业后仁先以诈。\n东破诸侯西入秦，咸阳北阪南渭津。\n诗书焚𦶟散学士，高阁奢逾娇美人。\n事往覆辀经远喻，春还按跸凭高赋。\n戎观爱力深惟省，越厌陈方何足务。\n清吹遥遥发帝台，宸文耿耿照天回。\n伯夷位事愚臣忝，喜奏声成凤鸟来。' },
  { title: '长相思', author: '苏颋', poem: '君不见天津桥下东流水，南望龙门北朝市。\n杨柳青青宛地垂，桃红李白花参差。\n花参差，柳堪结，此时忆君心断绝。' },
  { title: '蜀城哭台州乐安少府', author: '苏颋', poem: '远游跻劒阁，长想属天台。\n万里隔三载，此邦余重来。\n音容旷不覩，梦寐殊悠哉。\n边郡饶藉藉，晚庭正回回。\n喜传上都封，因促傍吏开。\n向悟海盐客，已而梁木摧。\n变衣寝门外，挥涕少城隈。\n却记分明得，犹持委曲猜。\n师儒昔训奖，仲季时童孩。\n服义题书箧，邀欢泛酒杯。\n𫏐令风雨散，仍迫岁时回。\n其道惟正直，其人信美偲。\n白头还作尉，黄绶固非才。\n可叹悬蛇疾，先贻问𫛳灾。\n故乡闭穷壤，宿草生寒荄。\n零落九原去，蹉跎四序催。\n曩期冬赠橘，今哭夏成梅。\n执礼谁为赗，居常不徇财。\n北登嵔𡻱坂，东望姑苏台。\n天路本悬绝，江波复溯洄。\n念孤心易断，追往恨艰裁。\n不遂卿将伯，孰云陈与雷。\n吾衰亦如此，夫子复何哀。' },
  { title: '立春日侍宴内出剪彩花应制', author: '苏颋', poem: '晓入宜春苑，秾芳吐禁中。\n剪刀因裂素，妆粉为开红。\n彩异惊流雪，香饶点便风。\n裁成识天意，万物与花同。' },
  { title: '春日芙蓉园侍宴应制', author: '苏颋', poem: '御道红旗出，芳园翠辇游。\n绕花开水殿，架竹起山楼。\n荷芰轻薰幄，鱼龙出负舟。\n宁知穆天子，空赋白云秋。' },
  { title: '奉和圣制人日清晖阁宴群臣遇雪应制', author: '苏颋', poem: '楼观空烟里，初年瑞雪过。\n苑花齐玉树，池水作银河。\n七日祥图启，千春御赏多。\n轻飞传彩胜，天上奉薰歌。' },
  { title: '奉和七夕宴两仪殿应制', author: '苏颋', poem: '灵媛乘秋发，仙装警夜催。\n月光窥欲渡，河色辨应来。\n机石天文写，针楼御赏开。\n窃观栖鸟至，疑向鹊桥回。' },
  { title: '奉和九日幸临渭亭登高应制得时字', author: '苏颋', poem: '嘉会宜长日，高筵顺动时。\n晓光云外洗，晴色雨余滋。\n降鹤因韶德，吹花入御词。\n愿陪阳数节，亿万九秋期。' },
  { title: '游禁苑幸临渭亭遇雪应制', author: '苏颋', poem: '平明敞帝居，霰雪下凌虚。\n写月含珠缀，从风薄绮疏。\n年惊花絮早，春夜管弦初。\n已属云天外，欣承霈泽余。' },
  { title: '奉和送金城公主适西蕃应制', author: '苏颋', poem: '帝女出天津，和戎转罽轮。\n川经断肠望，地与析支邻。\n奏曲风嘶马，衔悲月伴人。\n旋知偃兵革，长是汉家亲。' },
  { title: '奉和圣制登骊山高顶寓目应制', author: '苏颋', poem: '仙跸御层氛，高高积翠分。\n岩声中谷应，天语半空闻。\n丰树连黄叶，函关入紫云。\n圣图恢宇县，歌赋小横汾。' },
  { title: '幸白鹿观应制', author: '苏颋', poem: '碧虚清吹下，蔼蔼入仙宫。\n松磴攀云绝，花源接涧空。\n受符邀羽使，传诀注香童。\n讵似闲居日，徒闻有顺风。' },
  { title: '题寿安王主簿池馆', author: '苏颋', poem: '洛邑通驰道，韩郊在属城。\n馆将花雨映，潭与竹声清。\n贤俊鸾栖棘，宾游马佩衡。\n愿言随狎鸟，从此濯吾缨。' },
  { title: '扈从温泉奉和姚令公喜雪', author: '苏颋', poem: '清道丰人望，乘时汉主游。\n恩晖随霰下，庆泽与云浮。\n泉暖惊银碛，花寒爱玉楼。\n鼎臣今有问，河伯且应留。' },
  { title: '秋社日崇让园宴得新字', author: '苏颋', poem: '鸣爵三农稔，勾龙百代神。\n运昌叨辅弼，时泰喜黎民。\n树缺池光近，云开日影新。\n生全应有地，长愿乐交亲。' },
  { title: '奉和魏仆射秋日还乡有怀之作', author: '苏颋', poem: '南宫夙拜罢，东道昼游初。\n饮饯倾冠盖，传呼问里闾。\n树悲悬劒所，溪想钓璜余。\n明发辉光至，增荣驷马车。' },
  { title: '武[担]山寺', author: '苏颋', poem: '武[担]独苍然，坟山下玉泉。\n鳖灵时共尽，龙女事同迁。\n松柏衔哀处，幡花种福田。\n讵知留镜石，长与法轮圆。' },
  { title: '饯潞州陆长史再守汾州', author: '苏颋', poem: '河尹政成期，为汾昔所推。\n不荣三入地，还美再临时。\n拥传云初合，闻莺日正迟。\n道傍多出饯，别有吏民思。' },
  { title: '饯荆州崔司马', author: '苏颋', poem: '茂礼雕龙昔，香名展骥初。\n水连南海涨，星拱北辰居。\n稍发仙人履，将题别驾舆。\n明年征拜入，荆玉不藏诸。' },
  { title: '送吏部李侍郎东归得归字', author: '苏颋', poem: '陌上有光辉，披云向洛畿。\n赏来荣扈从，别至惜分飞。\n泉溜含风急，山烟带日微。\n茂曹今去矣，人物喜东归。' },
  { title: '送光禄姚卿还都', author: '苏颋', poem: '汉室有英台，荀家宠俊才。\n九卿朝已入，三子暮同来。\n不授纶为草，还司鼎用梅。\n两京王者宅，驷马日应回。' },
  { title: '春晚送瑕丘田少府还任因寄洛中镜上人', author: '苏颋', poem: '闻道还沂上，因声寄洛滨。\n别时花欲尽，归处酒应春。\n聚散同行客，悲欢属故人。\n少年追乐地，遥赠一沾巾。' },
  { title: '送贾起居奉使入洛取图书因便拜觐', author: '苏颋', poem: '旧国才因地，当朝史命官。\n遗文征阙简，还思采芳兰。\n传发关门候，觞称邑里欢。\n早持京副入，旋伫洛书刊。' },
  { title: '送常侍舒公归觐', author: '苏颋', poem: '朝闻讲艺余，晨省拜恩初。\n训胄尊庠序，荣亲耀里闾。\n朱丹华毂送，斑白绮筵舒。\n江上春流满，还应荐跃鱼。' },
  { title: '兴州出行', author: '苏颋', poem: '危途晓未分，驱马傍江𣸣。\n滴滴泣花露，微微出岫云。\n松梢半吐月，萝翳渐移曛。\n旅客肠应断，吟猿更使闻。' },
  { title: '边秋薄暮', author: '苏颋', poem: '海外秋鹰击，霜前旅雁归。\n边风思鞞鼓，落日惨旌麾。\n浦暗渔舟入，川长猎骑稀。\n客悲逢薄暮，况乃事戎机。' },
  { title: '晓发方骞驿', author: '苏颋', poem: '传置远山蹊，龙钟蹴涧泥。\n片阴常作雨，微照已生霓。\n鬓髪愁氛换，心情险路迷。\n方知向蜀者，偏识子规啼。' },
  { title: '经三泉路作', author: '苏颋', poem: '三月松作花，春行日渐赊。\n竹障山鸟路，藤蔓野人家。\n透石飞梁下，寻云绝磴斜。\n此中谁与乐，挥涕语年华。' },
  { title: '故高安大长公主挽词', author: '苏颋', poem: '彤管承师训，青圭备礼容。\n孟孙家代宠，元女国朝封。\n柔轨题贞顺，闲规赋肃雍。\n宁知落照尽，霜吹入悲松。' },
  { title: '赠司徒豆卢府君挽词', author: '苏颋', poem: '宠赠追胡广，亲临比贺循。\n几闻投劒客，多会服缌人。\n草闭坟将古，松阴地不春。\n二陵犹可望，存殁有忠臣。' },
  { title: '故右散骑常侍舒国公褚公挽词', author: '苏颋', poem: '阳翟疏丰构，临平演庆源。\n学筵尊授几，儒服宠乘轩。\n审谕留中密，开陈与上言。\n徂晖一不借，空有赐东园。' },
  { title: '奉和初春幸太平公主南庄应制', author: '苏颋', poem: '主第山门起灞川，宸游风景入初年。\n凤皇楼下交天仗，乌鹊桥头敞御筵。\n往往花间逢彩石，时时竹里见红泉。\n今朝扈跸平阳馆，不羡乘槎云汉边。' },
  { title: '奉和春日幸望春宫应制', author: '苏颋', poem: '东望望春春可怜，更逢晴日柳含烟。\n宫中下见南山尽，城上平临北斗悬。\n细草徧承回辇处，轻花微落奉觞前。\n宸游对此欢无极，鸟哢声声入管弦。' },
  { title: '人日重宴大明宫恩赐彩缕人胜应制', author: '苏颋', poem: '疏龙磴道切昭回，建凤旗门绕帝台。\n七叶仙蓂依月吐，千株御柳拂烟开。\n初年竞贴宜春胜，长命先浮献寿杯。\n是日皇灵知窃幸，群心就捧大明来。' },
  { title: '侍宴安乐公主山庄应制', author: '苏颋', poem: '骎骎羽骑历城池，帝女楼台向晚披。\n雾洒旌旗云外出，风回岩岫雨中移。\n当轩半落天河水，绕径全低月树枝。\n箫鼓宸游陪宴日，和鸣双凤喜来仪。' },
  { title: '兴庆池侍宴应制', author: '苏颋', poem: '降鹤池前回步辇，栖鸾树杪出行宫。\n山光积翠遥疑逼，水态含青近若空。\n直视天河垂象外，俯窥京室画图中。\n皇欢未使恩波极，日暮楼船更起风。' },
  { title: '广达楼下夜侍酺宴应制', author: '苏颋', poem: '东岳封廻宴洛京，西墉通晚会公卿。\n楼台绝胜宜春苑，灯火还同不夜城。\n正覩人间朝市乐，忽闻天上管弦声。\n酺来万舞群臣醉，喜戴千年圣主明。' },
  { title: '龙池乐章', author: '苏颋', poem: '西京凤邸跃龙泉，佳气休光镇在天。\n轩后雾图今已得，秦王水劒昔常传。\n恩鱼不入昆明钓，瑞鹤长如太液仙。\n愿侍巡游同旧里，更闻箫鼓济楼船。' },
  { title: '扈从鄠杜间奉呈刑部尚书舅崔黄门马常侍', author: '苏颋', poem: '翠辇红旗出帝京，长杨鄠杜昔知名。\n云山一一看皆美，竹树萧萧画不成。\n羽骑将过持袂拂，香车欲度卷帘行。\n汉家曾草巡游赋，何似今来应圣明。' },
  { title: '景龙观送裴士曹', author: '苏颋', poem: '昔日尝闻公主第，今时变作列仙家。\n池傍坐客穿丛筿，树下游人扫落花。\n雨雪长疑向函谷，山泉直似到流沙。\n君还洛邑分明记，此处同来阅岁华。' },
  { title: '春晚紫微省直寄内', author: '苏颋', poem: '直省清华接建章，向来无事日犹长。\n花间燕子栖𫛛鹊，竹下鹓雏绕凤皇。\n内史通宵承紫诰，中人落晚爱红妆。\n别离不惯无穷忆，莫误卿卿学太常。' },
  { title: '赠彭州权别驾', author: '苏颋', poem: '双流脉脉锦城开，追饯年年往复廻。\n秪道歌谣迎半刺，徒闻礼数揖中台。\n黄莺急啭春风尽，斑马长嘶落景催。\n莫怆分飞岐路别，还当奏最掖垣来。' },
  { title: '寒食宴于中舍别驾兄弟宅', author: '苏颋', poem: '子推山上歌龙罢，定国门前结驷来。\n始覩元昆锵玉至，旋闻季子佩刀廻。\n晴花处处因风起，御柳条条向日开。\n自有长筵欢不极，还将彩服咏南陔。' },
  { title: '九月九日望蜀台', author: '苏颋', poem: '蜀王望蜀旧台前，九日分明见一川。\n北料乡关方自此，南辞城郭复依然。\n青松系马攒岩畔，黄菊留人籍道边。\n自昔登临湮灭尽，独闻忠孝两能传。' },
  { title: '奉和晦日幸昆明池应制', author: '苏颋', poem: '炎历事边陲，昆明始凿池。\n豫游光后圣，征战罢前规。\n霁色清珍宇，年芳入锦陂。\n御杯兰荐叶，仙仗柳交枝。\n二石分河泻，双珠代月移。\n微臣比翔泳，恩广自无涯。' },
  { title: '奉和圣制幸礼部尚书窦希玠宅应制', author: '苏颋', poem: '尚书列侯第，外戚近臣家。\n飞栋临青绮，回舆转翠华。\n日交当户树，泉漾满池花。\n圆顶图嵩石，方流拥魏沙。\n豫游今听履，侍从昔鸣笳。\n自有天文降，无劳访海槎。' },
  { title: '奉和幸韦嗣立山庄应制', author: '苏颋', poem: '𪭢金寒野霁，步玉晓山幽。\n帝幄期松子，臣庐访葛侯。\n百工征往梦，七圣扈来游。\n斗柄乘时转，台阶捧日留。\n树重岩籁合，泉迸水光浮。\n石径喧朝履，璜溪拥钓舟。\n恩如犯星夜，欢拟济河秋。\n不学尧年隐，空令傲许由。' },
  { title: '奉和圣制送张说上集贤学士赐宴得兹字', author: '苏颋', poem: '肃肃金殿里，招贤固在兹。\n锵锵石渠内，序拜亦同时。\n宴锡欢谈道，文成贵说诗。\n用儒今作相，敦学旧为师。\n下际天光近，中来帝渥滋。\n国朝良史载，能事日论思。' },
  { title: '奉和圣制途经华岳应制', author: '苏颋', poem: '朝望莲华岳，神心就日来。\n晴观五千仞，仙掌拓山开。\n受命金符叶，过祥玉瑞陪。\n雾披乘鹿见，云起驭龙廻。\n偃树枝封雪，残碑石冐苔。\n圣皇惟道契，文字勒岩隈。' },
  { title: '奉和圣制经河上公庙应制', author: '苏颋', poem: '河流无日夜，河上有神仙。\n辇路曾经此，坛场即宛然。\n下疑成洞穴，高若在空烟。\n善物遗方外，和光绕道边。\n事因周史得，言与汉王传。\n喜属膺期圣，邦家业又玄。' },
  { title: '奉和圣制答张说出雀鼠谷', author: '苏颋', poem: '雨施巡方罢，云从训俗廻。\n密途汾水衞，清跸晋郊陪。\n寒着山边尽，春当日下来。\n御祠玄鸟应，仙仗绿杨开。\n作颂音传雅，观文色动台。\n更知西向乐，宸藻协盐梅。' },
  { title: '奉和恩赐乐游园宴应制', author: '苏颋', poem: '乐游光地选，酺饮庆天从。\n座密千官盛，场开百戏容。\n绿塍际山尽，缇幕倚云重。\n下上花齐发，周廻柳遍浓。\n夺晴纷劒履，喧听杂歌钟。\n日晚衔恩散，尧人倂可封。' },
  { title: '恩制尚书省僚宴昆明池同用尧字', author: '苏颋', poem: '露渥洒云霄，天官次斗杓。\n昆明四十里，空水极晴朝。\n雁似衔红叶，鲸疑喷海潮。\n翠山来彻底，白日去廻标。\n泳广渔杈溢，浮深妓舫摇。\n饱恩皆醉止，合舞共歌尧。' },
  { title: '奉和圣制幸望春宫送[朔方]大总管张仁亶', author: '苏颋', poem: '北风吹早雁，日夕渡河飞。\n气冷胶应折，霜明草正腓。\n老臣帷幄筭，元宰庙堂机。\n饯饮廻仙跸，临戎解御衣。\n军装乘晓发，师律候春归。\n方伫勋庸盛，天词降紫微。' },
  { title: '奉和圣制登太行山中言志应制', author: '苏颋', poem: '北山东入海，驰道上连天。\n顺动三光柱，登临万象悬。\n俛观河内邑，平指洛阳川。\n按跸夷关险，张旗亘井泉。\n晓岩中警柝，春事下搜田。\n德重周王问，歌轻汉后传。\n宸游铺令典，睿思起芳年。\n愿以封书奏，廻銮禅肃然。' },
  { title: '奉和圣制漕桥东送新除岳牧', author: '苏颋', poem: '宝贤不遗俊，台阁尽鹓鸾。\n未若调人切，其如简帝难。\n上才膺出典，中旨念分官。\n特以专城贵，深惟列郡安。\n政行思务本，风靡属胜残。\n有令田知急，无分狱在宽。\n至言题睿札，殊渥洒仙翰。\n诏饯三台降，朝荣万国欢。\n举杯临水发，张乐拥桥观。\n式伫东封会，锵锵检玉坛。' },
  { title: '奉和圣制途次旧居应制', author: '苏颋', poem: '潞国临淄邸，天王别驾舆。\n出潜离隐际，小往大来初。\n东陆行春典，南阳即旧居。\n约川星罕驻，扶道日旗舒。\n云覆连行在，风廻助扫除。\n木行城邑望，臯落土田疏。\n昔试邦兴后，今过俗徯予。\n示威宁校猎，崇让不陈鱼。\n府吏趋宸扆，乡耆捧帝车。\n帐倾三饮处，闲整六飞余。\n盛业铭汾鼎，昌期应洛书。\n愿陪歌赋末，留比蜀相如。' },
  { title: '奉和圣制至长春宫登楼望稼穑之作', author: '苏颋', poem: '帝迹奚其远，皇符之所崇。\n敬时尧务作，尽力禹称功。\n赫赫惟元后，经营自左冯。\n变芜秔稻实，流恶水泉通。\n国阜犹前豹，人疲讵昔熊。\n黄图巡沃野，清吹入离宫。\n是阅京坻富，仍观都邑雄。\n凭轩一何绮，积溜写晴空。\n礼节家安外，和平俗在中。\n见龙垂渭北，辞雁指河东。\n睿思方居镐，宸游若饮丰。\n宁夸子云从，秪为猎扶风。' },
  { title: '利州北佛龛前重于去岁题处作', author: '苏颋', poem: '重岩载看美，分塔起层标。\n蜀守经涂处，巴人作礼朝。\n地疑三界出，空是六尘销。\n卧石铺苍藓，行塍覆绿条。\n岁年书有记，非为学题桥。' },
  { title: '闲园即事寄韦侍郎', author: '苏颋', poem: '结庐东城下，直望江南山。\n青霭远相接，白云来复还。\n拂筵红藓上，开幔绿条间。\n物应春偏好，情忘趣转闲。\n宪臣饶美度，联事惜徂颜。\n有酒空盈酌，高车不可攀。' },
  { title: '扈从温泉同紫微黄门群公泛渭川得齐字', author: '苏颋', poem: '虹旗映绿荑，春仗汉丰西。\n侍跸浮清渭，扬舲降紫泥。\n近临钧石地，遥指钓璜溪。\n岸转帆飞疾，川平棹举齐。\n傅舟来是用，轩驭往应迷。\n兴阕菱歌动，沙洲乱夕鹥。' },
  { title: '饯赵尚书摄御史大夫赴朔方军', author: '苏颋', poem: '劲虏欲南窥，扬兵护朔陲。\n赵尧宁易印，邓禹即分麾。\n野饯廻三杰，军谋用六奇。\n云边愁出塞，日下怆临岐。\n拔劒行人舞，挥戈战马驰。\n明年麟阁上，充国画于斯。' },
  { title: '晓发兴州入陈平路', author: '苏颋', poem: '旌节指巴岷，年年行且巡。\n暮来青嶂宿，朝去绿江春。\n鱼贯梁缘马，猿奔树息人。\n邑祠犹是汉，溪道即名陈。\n旧史饶迁谪，恒情厌苦辛。\n宁知报恩者，天子一忠臣。' },
  { title: '同饯阳将军兼源州都督御史中丞', author: '苏颋', poem: '右地接龟沙，中朝任虎牙。\n然明方改俗，去病不为家。\n将礼登坛盛，军容出塞华。\n朔风摇汉鼓，边马思胡笳。\n旗合无邀正，冠危有触邪。\n当看劳还日，及此御沟花。' },
  { title: '扈从凤泉和崔黄门喜恩旨解严罢围之作', author: '苏颋', poem: '辇路岐山曲，储胥渭水湄。\n教成提将鼓，礼备植虞旗。\n不取从畋乐，先流去杀慈。\n舜韶同舞日，汤祝尽飞时。\n物应阳和施，人知雨露私。\n何如穆天子，七萃几劳师。' },
  { title: '秋夜寓直中书呈黄门舅', author: '苏颋', poem: '帘栊上夜钩，清列听更筹。\n忽共鸡枝老，还如骑省秋。\n循庭喜三入，对渚忆双游。\n紫绂名初拜，黄缣迹尚留。\n月舒当北幌，云赋直东楼。\n恩渥迷天施，童蒙慰我求。\n迟君台鼎节，闻义一承流。' },
  { title: '先是新昌小园期京兆尹一访兼郎官数子自顷沈疴年复一年兹愿不果率然成章', author: '苏颋', poem: '独好中林隐，先期上月春。\n闲花傍户落，喧鸟逼檐驯。\n寂寞东坡叟，传呼北里人。\n在山琴易调，开瓮酒归醇。\n伫望应三接，弥留忽几旬。\n不疑丹火变，空负绿条新。\n鬬蚁闻常日，歌龙值此辰。\n其如众君子，嘉会阻清尘。' },
  { title: '奉和马常侍寺中之作', author: '苏颋', poem: '怨暑时云谢，愆阳泽暂偏。\n鼎陈从祀日，钥动问刑年。\n绛服龙雩寝，玄冠马使旋。\n作霖期傅说，为旱听周宣。\n河岳阴符启，星辰暗檄传。\n浮凉吹景气，飞动洒空烟。\n飒飒将秋近，沈沈与暝连。\n分湍泾水石，合颖雍州田。\n德施超三五，文雄赋十千。\n及斯何以乐，明主敬人天。' },
  { title: '慈恩寺二月半寓言', author: '苏颋', poem: '二月韶春半，三空霁景初。\n献来应有受，灭尽竟无余。\n化迹传官寺，归诚谒梵居。\n殿堂花覆席，观阁柳垂疏。\n共命枝间鸟，长生水上鱼。\n问津窥彼岸，迷路得真车。\n行密幽关静，谈精俗态祛。\n稻麻欣所遇，蓬箨怆焉如。\n不驻秦京陌，还题蜀郡舆。\n爱离方自此，廻望独踌躇。' },
  { title: '饯泽州卢使君赴任', author: '苏颋', poem: '闻道降纶书，为邦建彩旟。\n政凭循吏往，才以贵卿除。\n词赋良无敌，声华蔼有余。\n荣承四岳后，请绝五天初。\n关路通秦壁，城池接晋墟。\n撰期行子赋，分典列侯居。\n别望喧追饯，离言系惨舒。\n平芜寒蛬乱，乔木夜蝉疎。\n寥泬秋先起，推移月向诸。\n旧交何以赠，客至待烹鱼。' },
  { title: '陈仓别陇州司户李维深', author: '苏颋', poem: '京国自携手，同途欣解颐。\n情言正的的，春物宛迟迟。\n忽背雕戎役，旋瞻获宝祠。\n蜀城余出守，吴岳尔归思。\n欢惬更伤此，眷殷殊念兹。\n扬麾北林径，跂石南涧湄。\n中作壶觞饯，回添道路悲。\n数花临磴日，百草覆田时。\n有美同人意，无为行子辞。\n酣歌拔劒起，毋是答恩私。' },
  { title: '奉和崔尚书赠大理陆卿鸿胪刘卿见示之作', author: '苏颋', poem: '戏藻嘉鱼乐，栖梧见凤飞。\n类从皆有召，声应乃无违。\n美价逢时出，奇才选众稀。\n避堂贻后政，扫第发前几。\n出曳仙人履，还熏侍女衣。\n省中何赫奕，庭际满芳菲。\n吏部端清鉴，丞郎肃紫机。\n会心歌咏是，廻迹宴言非。\n北寺邻玄阙，南城写翠微。\n参差交隐见，髣髴接光辉。\n宾序尝柔德，刑孚已霁威。\n巨源林下契，不速自同归。' },
  { title: '敬和崔尚书大明朝堂雨后望终南山见示之作', author: '苏颋', poem: '奕奕轻车至，清晨朝未央。\n未央在霄极，中路视咸阳。\n委曲汉京近，周廻秦塞长。\n日华动泾渭，天翠合岐梁。\n五丈旌旗色，百层枌橑光。\n东连归马地，南指鬬鸡场。\n晴壑照金戺，秋云含璧珰。\n由余窥霸国，萧相奉兴王。\n功役隐不见，颂声存复扬。\n权宜珍构绝，圣作宝图昌。\n在德期巢燧，居安法禹汤。\n冢卿才顺美，多士赋成章。\n价重三台俊，名超百郡良。\n焉知掖垣下，陈力自迷方。' },
  { title: '夜闻故梓州韦使君明当引绋感而成章', author: '苏颋', poem: '恻矣南邻问，冥然东岱幽。\n里闬宁相杵，朝叹忽迁舟。\n君心惟伯仲，吾人复款游。\n对连时亦早，交喜岁才周。\n序发扶阳赠，文因司寇酬。\n讵期危露尽，相续逝川流。\n卧疾无三吊，居闲有百忧。\n振风吟鼓夕，明月照帷秋。\n藓驳题诗馆，杨疎奏伎楼。\n共将歌笑叹，转为弟兄留。\n感物存如梦，观生去若浮。\n余非忘情者，雪涕报林丘。' },
  { title: '御箭连中双兔', author: '苏颋', poem: '宸游经上苑，羽猎向闲田。\n狡兔初迷窟，纤骊讵着鞭。\n三驱仍百步，一发遂双连。\n影射含霜草，魂消向月弦。\n欢声动寒木，喜气满晴天。\n那似陈王意，空随乐府篇。' },
  { title: '奉和圣制过潼津关', author: '苏颋', poem: '在德何夷险，观风复往还。\n自能同善闭，中路可无关。' },
  { title: '山鹧鸪词二首 一', author: '苏颋', poem: '玉关征戍久，空闺人独愁。\n寒露湿青苔，别来蓬鬓秋。' },
  { title: '山鹧鸪词二首 二', author: '苏颋', poem: '人坐青楼晚，莺语百花时。\n愁多人易老，断肠君不知。' },
  { title: '汾上惊秋', author: '苏颋', poem: '北风吹白云，万里渡河汾。\n心绪逢摇落，秋声不可闻。' },
  { title: '山驿闲卧即事', author: '苏颋', poem: '息燕归檐静，飞花落院闲。\n不愁愁自着，谁道忆乡关。' },
  { title: '将赴益州题小园壁', author: '苏颋', poem: '岁穷惟益老，春至却辞家。\n可惜东园树，无人也作花。' },
  { title: '咏礼部尚书厅后鹊', author: '苏颋', poem: '怀印喜将归，窥巢恋且依。\n自知栖不定，还欲向南飞。' },
  { title: '咏死兔', author: '苏颋', poem: '兔子死兰弹，持来挂竹竿。\n试将明镜照，何异月中看。' },
  { title: '夜宴安乐公主新宅', author: '苏颋', poem: '车如流水马如龙，仙使高台十二重。\n天上初移衡汉匹，可怜歌舞夜相从。' },
  { title: '侍宴桃花园咏桃花应制', author: '苏颋', poem: '桃花灼灼有光辉，无数成蹊点更飞。\n为见芳林含笑待，遂同温树不言归。' },
  { title: '奉和圣制幸韦嗣立庄应制', author: '苏颋', poem: '树色参差隐翠微，泉流百尺向空飞。\n传闻此处投竿住，遂使兹辰扈跸归。' },
  { title: '重送舒公', author: '苏颋', poem: '散骑金貂服彩衣，松花水上逐春归。\n悬知邑里遥相望，事主荣亲代所稀。' },
  { title: '句', author: '苏颋', poem: '飞埃结红雾，游盖飘青云。\n指如十挺墨，耳似两张匙。\n丑虽有足，甲不全身。\n见君无口，知伊少人。' },
  { title: '龙池篇', author: '姜晞', poem: '灵沼萦廻邸第前，浴日涵春写曙天。\n始见龙台升凤阙，应如霄汉起神泉。\n石匮渚傍还启圣，桃李初生更有仙。\n欲化帝图从此受，正同河变一千年。' },
  { title: '龙池篇', author: '姜皎', poem: '龙池初出此龙山，常经此地谒龙颜。\n日日芙蓉生夏水，年年杨柳变春湾。\n尧坛宝匣余烟雾，舜海渔舟尚往还。\n愿似飘飖五云影，从来从去九天关。' },
  { title: '奉和圣制龙池篇', author: '蔡孚', poem: '帝宅王家大道边，神马潜龙涌圣泉。\n昔日昔时经此地，看来看去渐成川。\n歌台舞榭宜正月，柳岸梅洲胜往年。\n莫疑波上春云少，祗为从龙直上天。' },
  { title: '打毬篇', author: '蔡孚', poem: '德阳宫北苑东头，云作高台月作楼。\n金锤玉蓥千金地，宝杖雕文七宝毬。\n窦融一家三尚主，梁翼频封万户侯。\n容色由来荷恩顾，意气平生事侠游。\n共道用兵如断蔗，俱能走马入长楸。\n红鬣锦鬃风𫘧骥，黄络青丝电紫骝。\n奔星乱下花场里，初月飞来画杖头。\n自有长鸣须决胜，能驰迅走满先筹。\n薄暮汉宫愉乐罢，还归尧室晓垂旒。' },
  { title: '阮公体', author: '徐晶', poem: '秦王按劒怒，发卒戍龙沙。\n雄图尚未毕，海内已纷拏。\n黄尘暗天起，白日敛精华。\n唯见长城外，僵尸如乱麻。' },
  { title: '同蔡孚五亭咏', author: '徐晶', poem: '章奏中京罢，云泉别业归。\n拂琴铺野席，牵柳挂朝衣。\n翡翠巢书幌，鸳鸯立钓矶。\n幽栖可怜处，春事满林扉。' },
  { title: '蔡起居山亭', author: '徐晶', poem: '文史归休日，栖闲卧草亭。\n蔷薇一架紫，石竹数重青。\n垂露和仙药，烧香诵道经。\n莫将山水弄，持与世人听。' },
  { title: '送友人尉蜀中', author: '徐晶', poem: '故友汉中尉，请为西蜀吟。\n人家多种橘，风土爱弹琴。\n水向昆明阔，山连大夏深。\n理闲无别事，时寄一登临。' },
  { title: '赠温驸马汝阳王', author: '徐晶', poem: '畴昔承余论，文章幸滥推。\n夜陪银汉赏，朝奉桂山词。\n梁邸调歌日，秦楼按舞时。\n登高频作赋，体物屡为诗。\n连骑长楸下，浮觞曲水湄。\n北堂留上客，南陌送佳期。\n忆昨陪临泛，于今阻宴私。\n再看冬雪满，三见夏花滋。\n都尉朝青阁，淮王侍紫墀。\n宁知倦游者，华髪老京师。' },
  { title: '边词', author: '张敬忠', poem: '五原春色旧来迟，二月垂杨未挂丝。\n即今河畔冰开日，正是长安花落时。' },
  { title: '戏咏', author: '张敬忠', poem: '有意嫌兵部，专心望考功。\n谁知脚蹭蹬，几落省墙东。' },
  { title: '题巴州光福寺楠木', author: '史俊', poem: '近郭城南山寺深，亭亭奇树出禅林。\n结根幽壑不知岁，耸干摩天凡几寻。\n翠色晚将岚气合，月光时有夜猨吟。\n经行绿叶望成盖，宴坐黄花长满襟。\n此木尝闻生豫章，今朝独秀在巴乡。\n凌霜不肯让松柏，作宇由来称栋梁。\n会待良工时一眄，应归法水作慈航。' },
  { title: '仪坤庙乐章 永和', author: '徐彦伯', poem: '猗若清庙，肃肃荧荧。\n国荐严祀，坤兴淑灵。\n有几在室，有乐在庭。\n临兹孝享，百禄惟宁。' },
  { title: '仪坤庙乐章 金奏', author: '徐彦伯', poem: '阴灵效祉，轩曜降精。\n祥符淑气，庆集柔明。\n瑶俎既列，雕桐发声。\n徽猷永远，比德皇英。' },
  { title: '拟古三首 一', author: '徐彦伯', poem: '遥裔烟屿鸿，双影旦夕同。\n交翰倚沙月，和鸣弄江风。\n𦶜若茂芳序，君子从远戎。\n云生阴海没，花落春潭空。\n红泪掩促柱，锦衾罗薰笼。\n自伤琼草绿，讵惜铅粉红。\n裂帛附双燕，为予向辽东。' },
  { title: '拟古三首 二', author: '徐彦伯', poem: '读书三十载，驰骛周六经。\n儒衣干时主，忠策献阙廷。\n一朝奉休盼，从容厕群英。\n束身趋建礼，秉笔坐承明。\n廨署相填噎，僚吏纷纵横。\n五日休澣时，屠苏绕玉屏。\n橘花覆北沼，桂树交西荣。\n树栖两鸳鸯，含春向我鸣。\n皎洁绮罗艳，便娟丝管清。\n扰扰天地间，出处各有情。\n何必岩石下，枯槁闲此生。' },
  { title: '拟古三首 三', author: '徐彦伯', poem: '颓光无淹晷，逝水有迅流。\n绿苔纷易歇，红颜不再求。\n歌笑当及春，无令壮志秋。\n弱年仕关辅，簃门豁御沟。\n敷愉东城际，婉娈南陌头。\n荷花娇绿水，杨叶暖青楼。\n中有绮罗人，可怜名莫愁。\n画屏绕金膝，珠帘悬玉钩。\n纤指调宝琴，泠泠哀且柔。\n赠君鸳鸯带，因以鹔鹴裘。\n窗晓吟日坐，闺夕秉烛游。\n无作北门客，咄咄怀百忧。' },
  { title: '赠刘舍人古意', author: '徐彦伯', poem: '女床閟灵鸟，文章世所希。\n巢君碧梧树，舞君青琐闱。\n或言凤池乐，抚翼更西飞。\n凤池环禁林，仙阁霭沈沈。\n璇题激流日，珠缀緜清阴。\n郁穆丝言重，荧煌台座深。\n风张丹戺翮，月弄紫庭音。\n众彩结不散，孤英跂莫寻。\n浩歌在西省，经传恣潜心。' },
  { title: '和李适荅宋十一入崖口五渡见赠', author: '徐彦伯', poem: '闻有独往客，拂衣捐世心。\n结欣薄枉渚，撰念萦旧林。\n经亘去崖合，冥緜归壑深。\n琪树环碧彩，金潭生翠阴。\n沿洄弄沙榜，诡仄眺明岑。\n夕闻桂里猿，晓玩松上禽。\n杂佩蕴孤袖，琼敷缀双襟。\n我怀沧州想，懿尔白云吟。\n秉愿理方协，存期迹易寻。\n兹言庶不负，为报岩中琴。' },
  { title: '雪', author: '徐彦伯', poem: '雪暗穷海云，洒空纷似露。\n朔风吹故里，宛转玉阶树。\n孤妾调玉瑟，早寒生锦衿。\n况君张罗幕，愁坐北庭阴。' },
  { title: '比干墓', author: '徐彦伯', poem: '大位天下宝，维贤国之镇。\n殷道微而在，受辛纂颓胤。\n山鸣鬼又哭，地裂川亦震。\n媟黩皆佞谀，虔刘尽英隽。\n孤卿帝叔父，特进贞而顺。\n玉床逾皜洁，铜柱方歊焮。\n奉国历三朝，观窍明一瞬。\n季代猖狂主，蓄怒提白刃。\n之子弥忠谠，愤然更勇进。\n抚膺誓陨越，知死故不恡。\n已矣竟剖心，哲妇亦同殉。\n骊龙暴双骨，太岳摧孤仞。\n周发次商郊，冤骸悲莫殣。\n锋劒剿遗孽，报复一何迅。\n驻罕歌淑灵，命徒对旅榇。\n自尔衔幽酷，于嗟流景骏。\n丘坟被宿莽，坛戺缘飞燐。\n贞观戒北征，维皇念忠信。\n荒坟护草木，刻桷吹煨烬。\n代远恩更崇，身颓名益振。\n帝词书乐石，国馔罗芳衅。\n伟哉烈士图，奇英千古徇。' },
  { title: '题东山子李适碑阴二首 一', author: '徐彦伯', poem: '陇嶂萦紫气，金光赫氛氲。\n美人含遥霭，桃李芳自薰。\n图高黄鹤羽，宝夺骊龙群。\n忽惊薤露曲，掩噎东山云。' },
  { title: '题东山子李适碑阴二首 二', author: '徐彦伯', poem: '回也寔夭折，贾生亦脆促。\n今复哀若人，危光迅风烛。\n夜台沦清镜，穷尘埋结绿。\n何以赠下泉，生刍唯一束。' },
  { title: '淮亭吟', author: '徐彦伯', poem: '贞寂虑兮淮山幽，怜芳若兮{临/手}中洲。\n崩湍委咽日夜流，孤客危坐心自愁。\n矧鹤唳兮风晓，复猿鸣兮霜秋。\n熠耀飞兮蟋蟀吟，倚清瑟兮横凉琴。\n撷瑶芳兮吊楚水，弄琪树兮歌越岑。\n山埼𥐟兮隈曲，水涓涟兮洞汩。\n金光延起兮骤兴没，青苔竟兮绿苹歇。\n绿苹歇兮凋朱颜，美人寂历兮何时闲。\n君不见可怜桐柏上，丰茸桂树花满山。' },
  { title: '芳树', author: '徐彦伯', poem: '玉花珍簟上，金缕画屏开。\n晓月怜筝柱，春风忆镜台。\n筝柱春风吹晓月，芳树落花朝暝歇。\n藁砧刀头未有期，攀条拭泪坐相思。' },
  { title: '游禁苑幸临渭亭遇雪应制', author: '徐彦伯', poem: '玉律藏冰候，彤阶飞雪时。\n日寒消不尽，风定舞还迟。\n琼树留宸瞩，璇花入睿词。\n悬知穆天子，黄竹谩言诗。' },
  { title: '奉和送金城公主适西蕃应制', author: '徐彦伯', poem: '凤扆怜箫曲，鸾闺念掌珍。\n羗庭遥筑馆，庙策重和亲。\n星转银河夕，花移玉树春。\n圣心凄送远，留跸望征尘。' },
  { title: '幸白鹿观应制', author: '徐彦伯', poem: '凤舆乘八景，龟箓向三仙。\n日月移平地，云霞缀小天。\n金童擎紫药，玉女献青莲。\n花洞留宸赏，还旗绕夕烟。' },
  { title: '胡无人行', author: '徐彦伯', poem: '十月繁霜下，征人远凿空。\n云摇锦车节，海照角端弓。\n暗碛埋沙树，冲飙卷塞蓬。\n方随膜拜入，歌舞玉门中。' },
  { title: '倢伃', author: '徐彦伯', poem: '君恩忽断绝，妾思终未央。\n巾栉不可见，枕席空余香。\n窗暗网罗白，阶秋苔藓黄。\n应门寂已闭，流涕向昭阳。' },
  { title: '采莲曲', author: '徐彦伯', poem: '妾家越水边，摇艇入江烟。\n既觅同心侣，复采同心莲。\n折藕丝能脆，开花叶正圆。\n春歌弄明月，归櫂落花前。' },
  { title: '孤烛叹', author: '徐彦伯', poem: '切切夜闺冷，微微孤烛然。\n玉盘红泪滴，金烬彩光圆。\n煖手缝轻素，嚬蛾续断弦。\n相思咽不语，回向锦屏眠。' },
  { title: '闺怨', author: '徐彦伯', poem: '征客戍金微，愁闺独掩扉。\n尘埃生半榻，花絮落残机。\n褪暖蚕初卧，巢昏燕欲归。\n春风日向尽，衔涕作征衣。' },
  { title: '饯唐州高使君赴任', author: '徐彦伯', poem: '香萼媚红滋，垂条萦绿丝。\n情人拂瑶袂，共惜此芳时。\n骕骦已踯躅，鸟隼方葳蕤。\n跂予望太守，流润及京师。' },
  { title: '奉和幸新丰温泉宫应制', author: '徐彦伯', poem: '姬典歌时迈，虞篇记省方。\n何如黑帝月，玄览白云乡。\n翠仗萦船岸，明斾应萯阳。\n风摇花眊彩，雪艳宝戈芒。\n御陌开函次，离宫夹树行。\n桂枝笼騕褭，松叶覆堂皇。\n仙石含珠液，温池孕璧房。\n涌疑神瀵溢，澄若帝台浆。\n独沸流常热，潜蒸气转香。\n青坛环玉甃，红础铄金光。\n藻曜凝芳洁，葳蕤献淑祥。\n五龙归宝算，九鳸叶时康。\n同预华封老，中衢祝圣皇。' },
  { title: '同韦舍人元旦早朝', author: '徐彦伯', poem: '夕转清壶漏，晨惊长乐钟。\n逶迤纶禁客，假寐守铜龙。\n予亦趋三殿，肩随谒九重。\n繁珂接曙响，华劒比春容。\n相问韶光歇，弥怜芳意浓。\n愿言乘日旰，携手即云峰。' },
  { title: '侍宴韦嗣立山庄应制', author: '徐彦伯', poem: '鼎臣休澣隙，方外结遥心。\n别业青霞境，孤潭碧树林。\n每驰东墅策，遥弄北溪琴。\n帝眷纾时豫，台园赏岁阴。\n移銮明月沼，张组白云岑。\n御酒瑶觞落，仙坛竹径深。\n三光悬圣藻，五等冠朝簪。\n自昔皇恩感，咸言独自今。' },
  { title: '送特进李峤入都祔庙', author: '徐彦伯', poem: '特进三公下，台臣百揆先。\n孝图开寝石，祠主卜牲筵。\n恩级青纶赐，徂装紫橐悬。\n绸缪金鼎席，宴饯玉潢川。\n北斗分征路，东山起赠篇。\n乐池歌绿藻，梁苑藉红荃。\n骑转商岩日，旌摇关塞烟。\n庙堂须鲠议，锦节伫来旋。' },
  { title: '春闺', author: '徐彦伯', poem: '戍客戍清波，幽闺幽思多。\n暗梁闻语燕，夜烛见飞蛾。\n宝鸭藏脂粉，金屏缀绮罗。\n裁衣卷纹素，织锦度鸣梭。\n有使通西极，缄书寄北河。\n年光只恐尽，征战莫蹉跎。' },
  { title: '奉和兴庆池戏竞渡应制', author: '徐彦伯', poem: '夹道传呼翊翠虬，天回日转御芳洲。\n青潭晓霭笼仙跸，红屿晴花隔彩旒。\n香溢金杯环广坐，声传妓舸匝中流。\n群臣相庆嘉鱼乐，共哂横汾歌吹秋。' },
  { title: '苑中遇雪应制', author: '徐彦伯', poem: '千钟圣酒御筵披，六出祥英乱绕枝。\n即此神仙对琼圃，何烦辙迹向瑶池。' },
  { title: '上巳日祓禊渭滨应制', author: '徐彦伯', poem: '晴风丽日满芳洲，柳色春筵祓锦流。\n皆言侍跸横汾宴，暂似乘槎天汉游。' },
  { title: '夜宴安乐公主新宅应制', author: '徐彦伯', poem: '凤楼开阖引明光，花酎连添醉益香。\n欲知帝女薰天贵，金柯玉柱夜成行。' },
  { title: '饯唐永昌', author: '徐彦伯', poem: '金溪碧水玉潭沙，凫舄翩翩弄日华。\n鬬鸡香陌行春倦，为摘东园桃李花。' },
  { title: '侍宴桃花园', author: '徐彦伯', poem: '源水丛花无数开，丹跗红萼间青梅。\n从今结子三千岁，预喜仙游复摘来。' },
  { title: '石淙', author: '徐彦伯', poem: '碧淀红涔崿嶂间，淙嵌洑岨洊成湾。\n琪树琁娟花未落，银芝窋䆛露初还。\n八风行殿开仙牓，七景飞舆下石关。\n张茑席云平圃䜩，焜煌金记蕴名山。' },
  { title: '晚憩田家', author: '骆宾王', poem: '转蓬劳远役，披薜下田家。\n山形类九折，水势急三巴。\n悬梁接断岸，涩路拥崩查。\n雾岩沦晓魄，风溆涨寒沙。\n心迹一朝舛，关山万里赊。\n龙章徒表越，闽俗本殊华。\n旅行悲泛梗，离赠折疎麻。\n唯有寒潭菊，独似故园花。' },
  { title: '出石门', author: '骆宾王', poem: '层岩远接天，绝岭上栖烟。\n松低轻盖偃，藤细弱丝悬。\n石明如挂镜，苔分似列钱。' },
  { title: '至分陕', author: '骆宾王', poem: '陕西开胜壤，召南分沃畴。\n列树巢维鹊，平渚下雎鸠。\n憩棠疑勿剪，曳葛似攀樛。\n至今王化美，非独在隆周。' },
  { title: '寓居洛滨对雪忆谢二', author: '骆宾王', poem: '旅思眇难裁，冲飙恨易哀。\n旷望洛川晚，飘飖瑞雪来。\n积彩明书幌，流韵绕琴台。\n色夺迎仙羽，花避犯霜梅。\n谢庭赏方逸，袁扉掩未开。\n高人傥有访，兴尽讵须回。' },
  { title: '北眺舂陵', author: '骆宾王', poem: '揽辔疲宵迈，驱马倦晨兴。\n既出封泥谷，还过避雨陵。\n山行明照上，谿宿密云蒸。\n登高徒欲赋，词殚独抚膺。' },
  { title: '夏日游目聊作', author: '骆宾王', poem: '暂屏嚣尘累，言寻物外情。\n致逸心逾默，神幽体自轻。\n浦夏荷香满，田秋麦气清。\n讵假沧浪上，将濯楚臣缨。' },
  { title: '同崔驸马晓初登楼思京', author: '骆宾王', poem: '丽谯通四望，繁忧起万端。\n绮疏低晚魄，镂槛肃初寒。\n白云乡思远，黄图归路难。\n唯余西向笑，暂似当长安。' },
  { title: '月夜有怀简诸同病', author: '骆宾王', poem: '闲庭落景尽，疎帘夜月通。\n山灵响似应，水净望如空。\n栖枝犹绕鹊，遵渚未来鸿。\n可叹高楼妇，悲思杳难终。' },
  { title: '叙寄员半千', author: '骆宾王', poem: '薄宦三河道，自负十余年。\n不应惊若厉，秪为直如弦。\n坐历山川险，吁嗟陵谷迁。\n长吟空抱膝，短翮讵冲天。\n魂归沧海上，望断白云前。\n钓名劳拾紫，隐迹自谈玄。\n不学多能圣，徒思鸿宝仙。\n斯志良难已，此道岂徒然。\n嗟为刀笔吏，耻从绳墨牵。\n岐路情虽狎，人伦地本偏。\n长揖谢时事，独往访林泉。\n寄言二三子，生死不来旋。' },
  { title: '咏怀古意上裴侍郎', author: '骆宾王', poem: '三十二余罢，鬓是潘安仁。\n四十九仍入，年非朱买臣。\n纵横愁系越，坎𡒄倦游秦。\n出笼穷短翮，委辙涸枯鳞。\n穷经不沾用，弹铗欲谁申。\n天子未驱策，岁月几沈沦。\n轻生长慷慨，效死独殷勤。\n徒歌易水客，空老渭川人。\n一得视边塞，万里何苦辛。\n剑匣胡霜影，弓开汉月轮。\n金刀动秋色，铁骑想风尘。\n为国坚诚款，捐躯忘贱贫。\n勒功思比宪，决略暗欺陈。\n若不犯霜雪，虚掷玉京春。' },
  { title: '春夜韦明府宅宴得春字', author: '骆宾王', poem: '酌桂陶芳夜，披薜啸幽人。\n雅琴驯鲁雉，清歌落范尘。\n宿云低迥盖，残月上虚轮。\n幸此承恩洽，聊当故乡春。' },
  { title: '过张平子墓', author: '骆宾王', poem: '西鄂该通理，南阳擅德音。\n玉巵浮藻丽，铜浑积思深。\n忽怀今日昔，非复昔时今。\n日落丰碑暗，风来古木吟。\n惟叹穷泉下，终郁羡鱼心。' },
  { title: '从军中行路难二首 二', author: '骆宾王', poem: '君不见玉关尘色暗边庭，铜鞮杂虏寇长城。\n天子按剑征余勇，将军受脤事横行。\n七德龙韬开玉帐，千里鼍鼓垒金钲。\n阴山苦雾埋高垒，交河孤月照连营。\n连营去去无穷极，拥斾遥遥过绝国。\n阵云朝结晦天山，寒沙夕涨迷疎勒。\n龙鳞水上开鱼贯，马首山前振雕翼。\n长驱万里詟祈连，分麾三命武功宣。\n百发乌号遥碎柳，七尺龙文迥照莲。\n春来秋去移灰琯，兰闺柳市芳尘断。\n雁门迢递尺书稀，鸳被相思双带缓。\n行路难，行路难，誓令氛祲静臯兰。\n但使封侯龙頟贵，讵随中妇凤楼寒。' },
  { title: '从军行', author: '骆宾王', poem: '平生一顾重，意气溢三军。\n埜日分戈影，天星合剑文。\n弓弦抱汉月，马足践胡尘。\n不求生入塞，唯当死报君。' },
  { title: '王昭君', author: '骆宾王', poem: '歛容辞豹尾，缄恨度龙鳞。\n金钿明汉月，玉筯染胡尘。\n古镜菱花暗，愁眉柳叶颦。\n唯有清笳曲，时闻芳树春。' },
  { title: '于紫云观赠道士', author: '骆宾王', poem: '碧落澄秋景，玄门启曙关。\n人疑列御至，客似令威还。\n羽盖徒欣仰，云车未可攀。\n衹应倾玉醴，时许寄颓颜。' },
  { title: '渡瓜步江', author: '骆宾王', poem: '捧檄辞幽径，鸣榔下贵洲。\n惊涛疑跃马，积气似连牛。\n月迥寒沙净，风急夜江秋。\n不学浮云影，他乡空滞留。' },
  { title: '途中有怀', author: '骆宾王', poem: '睠然怀楚奏，怅矣背秦关。\n涸鳞惊照辙，坠羽怯虚弯。\n素服三川化，乌裘十上还。\n莫言无皓齿，时俗薄朱颜。' },
  { title: '至分水戍', author: '骆宾王', poem: '行役忽离忧，复此怆分流。\n溅石回湍咽，萦丛曲涧幽。\n阴岩常结晦，宿莽竞含秋。\n况乃霜晨早，寒风入戍楼。' },
  { title: '望乡夕泛', author: '骆宾王', poem: '归怀剩不安，促榜犯风澜。\n落宿含楼近，浮月带江寒。\n喜逐行前至，忧从望里宽。\n今夜南枝鹊，应无绕树难。' },
  { title: '久客临海有怀', author: '骆宾王', poem: '天涯非日观，地屺望星楼。\n练光摇乱马，剑气上连牛。\n草湿姑苏夕，叶下洞庭秋。\n欲知凄断意，江上涉安流。' },
  { title: '游兖部逢孔君自衞来欣然相遇若旧', author: '骆宾王', poem: '游人自衞返，背客隔淮来。\n倾盖金兰合，忘筌玉叶开。\n繁花明日柳，疎蕊落风梅。\n将期重交态，时慰不然灰。' },
  { title: '西京守岁', author: '骆宾王', poem: '闲居寡言宴，独坐惨风尘。\n忽见严冬尽，方知列宿春。\n夜将寒色去，年共晓光新。\n耿耿他乡夕，无由展旧亲。' },
  { title: '同辛簿简仰酬思玄上人林泉四首 一', author: '骆宾王', poem: '闻君招隐地，髣髴武陵春。\n缉芰知还楚，披榛似避秦。\n崩查年祀积，幽草岁时新。\n一谢沧浪水，安知有逸人。' },
  { title: '同辛簿简仰酬思玄上人林泉四首 二', author: '骆宾王', poem: '芳晨临上月，幽赏狎中园。\n有蝶堪成梦，无羊可触藩。\n忘怀南涧藻，蠲思北堂萱。\n坐叹华滋歇，思君谁为言。' },
  { title: '同辛簿简仰酬思玄上人林泉四首 三', author: '骆宾王', poem: '林泉恣探历，风景暂裴徊。\n客有迁莺处，人无结驷来。\n聚花如薄雪，沸水若轻雷。\n今日徒招隐，终知异凿坏。' },
  { title: '同辛簿简仰酬思玄上人林泉四首 四', author: '骆宾王', poem: '俗远风尘隔，春还初服迟。\n林疑中散地，人似上皇时。\n芳杜湘君曲，幽兰楚客词。\n山中有春草，长似寄相思。' },
  { title: '秋日饯陆道士陈文林', author: '骆宾王', poem: '青牛游华岳，赤马走吴宫。\n玉柱离鸿怨，金罍浮蚁空。\n日霁崤陵雨，尘起洛阳风。\n唯当玄度月，千里与君同。' },
  { title: '送郑少府入辽共赋侠客远从戎', author: '骆宾王', poem: '边烽警榆塞，侠客度桑干。\n柳叶开银镝，桃花照玉鞍。\n满月临弓影，连星入剑端。\n不学燕丹客，空歌易水寒。' },
  { title: '送费六还蜀', author: '骆宾王', poem: '星楼望蜀道，月峡指吴门。\n万行流别泪，九折切惊魂。\n雪影含花落，云阴带叶昏。\n还愁三径晚，独对一清尊。' },
  { title: '秋日送侯四得弹字', author: '骆宾王', poem: '我留安豹隐，君去学鹏抟。\n岐路分襟易，风云促膝难。\n夕涨流波急，秋山落日寒。\n惟有思归引，凄断为君弹。' },
  { title: '秋日送尹大赴京', author: '骆宾王', poem: '挂瓢余隐舜，负鼎尔干汤。\n竹叶离罇满，桃花别路长。\n低河耿秋色，落月抱寒光。\n素书如可嗣，幽谷𥩟宾行。' },
  { title: '秋夜送閰五还润州', author: '骆宾王', poem: '通庄抵旧里，沟水泣新知。\n断云飘易滞，连露积难披。\n素风啼迥堞，惊月绕疎枝。\n无力励短翰，轻举送长离。' },
  { title: '送王明府参选赋得鹤', author: '骆宾王', poem: '振衣游紫府，飞盖背青田。\n虚心恒警露，孤影尚凌烟。\n离歌凄妙曲，别操绕繁弦。\n在阴如可和，轻响会闻天。' },
  { title: '秋日送别', author: '骆宾王', poem: '寂寥心事晚，摇落岁时秋。\n共此伤年髪，相看惜去留。\n当歌应破涕，哀命返穷愁。\n别后能相忆，东陵有故侯。' },
  { title: '别李峤得胜字', author: '骆宾王', poem: '芳尊徒自满，别恨转难胜。\n客似游江岸，人疑上灞陵。\n寒更承夜永，凉景向秋澄。\n离心何以赠，自有玉壶冰。' },
  { title: '在衮州饯宋五之问', author: '骆宾王', poem: '淮沂泗水地，梁甫汶阳东。\n别路青骊远，离尊绿蚁空。\n柳寒凋密翠，棠晚落疎红。\n别后相思曲，凄断入琴风。' },
  { title: '游灵公观', author: '骆宾王', poem: '灵峰标胜境，神府枕通川。\n玉殿斜连汉，金堂迥架烟。\n断风疎晚竹，流水切危弦。\n别有青门外，空怀玄圃仙。' },
  { title: '夏日游山家同夏少府', author: '骆宾王', poem: '返照下层岑，物外狎招寻。\n兰径薰幽珮，槐庭落暗金。\n谷静风声彻，山空月色深。\n一遣樊笼累，唯余松桂心。' },
  { title: '初秋登王司马楼宴得同字', author: '骆宾王', poem: '展骥端居暇，登龙喜宴同。\n缔赏三清满，承欢六义通。\n野晦寒阴积，潭虚夕照空。\n顾慙非梦鸟，滥此厕雕虫。' },
  { title: '初秋于窦六郎宅宴', author: '骆宾王', poem: '千里风云契，一朝心赏同。\n意尽深交合，神灵俗累空。\n草带销寒翠，花枝发夜红。\n唯将澹若水，长揖古人风。' },
  { title: '冬日宴', author: '骆宾王', poem: '二三物外友，一百杖头钱。\n赏洽袁公地，情披乐令天。\n促席鸾觞满，当炉兽炭然。\n何须攀桂树，逢此自留连。' },
  { title: '镂鸡子', author: '骆宾王', poem: '幸遇清明节，欣逢旧练人。\n刻花争脸态，写月竞眉新。\n晕罢空余月，诗成倂道春。\n谁知怀玉者，含响未吟晨。' },
  { title: '咏美人在天津桥', author: '骆宾王', poem: '美女出东邻，容与上天津。\n整衣香满路，移步袜生尘。\n水下看妆影，眉头画月新。\n寄言曹子建，个是洛川神。' },
  { title: '送宋五之问得凉字', author: '骆宾王', poem: '愿言游泗水，支离去二漳。\n道术君所笃，筌蹄余自忘。\n雪威侵竹冷，秋爽带池凉。\n欲騐离襟切，岐路在他乡。' },
  { title: '宪台出絷寒夜有怀', author: '骆宾王', poem: '独坐怀明发，长谣苦未安。\n自应迷北叟，谁肯问南冠。\n生死交情异，殷忧岁序阑。\n空余朝夕鸟，相伴夜啼寒。' },
  { title: '送郭少府探得忧字', author: '骆宾王', poem: '开筵枕德水，辍棹舣仙舟。\n贝阙桃花浪，龙门竹箭流。\n当歌凄别曲，对酒泣离忧。\n还望青门外，空见白云浮。' },
  { title: '冬日过故人任处士书斋', author: '骆宾王', poem: '神交尚投漆，虚室罢游兰。\n网积窗文乱，苔深履迹残。\n雪明书帐冷，水静墨池寒。\n独此琴台夜，流水为谁弹。' },
  { title: '送刘少府游越州', author: '骆宾王', poem: '一丘余枕石，三越尔怀铅。\n离亭分鹤盖，别岸指龙川。\n露下蝉声断，寒来雁影连。\n如何沟水上，凄断听离弦。' },
  { title: '赋得白云抱幽石', author: '骆宾王', poem: '重岩抱危石，幽涧曳轻云。\n绕镇仙衣动，飘蓬羽盖分。\n锦色连花静，苔光带叶熏。\n讵知吴会影，长抱谷城文。' },
  { title: '赋得春云处处生', author: '骆宾王', poem: '千里年光静，四望春云生。\n椠日祥光举，疎云瑞叶轻。\n盖阴笼迥树，阵影抱危城。\n非将吴会远，飘荡帝乡情。' },
  { title: '在岳咏蝉', author: '骆宾王', poem: '西陆蝉声唱，南冠客思侵。\n那堪玄鬓影，来对白头吟。\n露重飞难进，风多响易沈。\n无人信高洁，谁为表予心。' },
  { title: '咏水', author: '骆宾王', poem: '列名通地纪，疎派合天津。\n波随月色净，态逐桃花春。\n照霞如隐石，映柳似沈鳞。\n终当挹上善，属意澹交人。' },
  { title: '同张二咏雁', author: '骆宾王', poem: '唼藻沧江远，衔卢紫塞长。\n雾深迷晓景，风急断秋行。\n阵照通宵月，书封几夜霜。\n无复能鸣分，空知愧稻粱。' },
  { title: '咏雪', author: '骆宾王', poem: '龙云玉叶上，鹤雪瑞花新。\n影乱铜乌吹，光销玉马津。\n含辉明素篆，隐迹表祥轮。\n幽兰不可俪，徒自绕阳春。' },
  { title: '咏云酒', author: '骆宾王', poem: '朔空曾纪历，带地旧疏泉。\n色泛临砀瑞，香流赴蜀仙。\n款交欣散玉，洽友悦沈钱。\n无复中山赏，空吟吴会篇。' },
  { title: '尘灰', author: '骆宾王', poem: '洛川流雅韵，秦道擅苛威。\n听歌梁上动，应律管中飞。\n光飘神女袜，影落羽人衣。\n愿言心未翳，终冀效轻微。' },
  { title: '秋晨同淄川毛司马秋九咏 秋风', author: '骆宾王', poem: '紫陌炎氛歇，青苹晚吹浮。\n乱竹摇疎影，萦池织细流。\n飘香曳舞袖，带粉泛妆楼。\n不分君恩绝，纨扇曲中秋。' },
  { title: '秋晨同淄川毛司马秋九咏 秋云', author: '骆宾王', poem: '南陆铜浑改，西郊玉叶轻。\n泛斗瑶光动，临阳瑞色明。\n盖阴连凤阙，阵影翼龙城。\n讵知时不遇，空伤流滞情。' },
  { title: '秋晨同淄川毛司马秋九咏 秋蝉', author: '骆宾王', poem: '九秋行已暮，一枝聊暂安。\n隐榆非谏楚，噪柳异悲潘。\n分形妆薄鬓，镂影饰危冠。\n自怜疎影断，寒林夕吹寒。' },
  { title: '秋晨同淄川毛司马秋九咏 秋露', author: '骆宾王', poem: '玉关寒气早，金塘秋色归。\n泛掌光逾净，添荷滴尚微。\n变霜凝晓液，承月委圆辉。\n别有吴台上，应湿楚臣衣。' },
  { title: '秋晨同淄川毛司马秋九咏 秋月', author: '骆宾王', poem: '云披玉绳净，月满镜轮圆。\n裛露珠晖冷，凌霜桂影寒。\n漏彩含疎薄，浮光漾急澜。\n西园徒自赏，南飞终未安。' },
  { title: '秋晨同淄川毛司马秋九咏 秋水', author: '骆宾王', poem: '贝阙寒流彻，玉轮秋浪清。\n图云锦色净，写月练花明。\n泛曲鹍弦动，随轩凤辖惊。\n唯当御沟上，凄断送归情。' },
  { title: '秋晨同淄川毛司马秋九咏 秋萤', author: '骆宾王', poem: '玉虬分静夜，金萤照晚凉。\n含辉疑泛月，带火怯凌霜。\n散彩萦虚牖，飘花绕洞房。\n下帷如不倦，当解惜余光。' },
  { title: '秋晨同淄川毛司马秋九咏 秋菊', author: '骆宾王', poem: '擢秀三秋晚，开芳十步中。\n分黄俱笑日，含翠共摇风。\n碎影涵流动，浮香隔岸通。\n金翘徒可泛，玉斝竟谁同。' },
  { title: '秋晨同淄川毛司马秋九咏 秋雁', author: '骆宾王', poem: '联翩辞海曲，遥曳指江干。\n阵去金河冷，书归玉塞寒。\n带月凌空易，迷烟逗浦难。\n何当同顾影，刷羽泛清澜。' },
  { title: '乐大夫挽词五首 一', author: '骆宾王', poem: '可叹浮生促，吁嗟此路难。\n丘陵一起恨，言笑几时懽。\n萧索郊埏晚，荒凉井径寒。\n谁当门下客，独见有任安。' },
  { title: '乐大夫挽词五首 二', author: '骆宾王', poem: '蒿里谁家地，松门何代丘。\n百年三万日，一别几千秋。\n返照寒无影，穷泉冻不流。' },
  { title: '乐大夫挽词五首 三', author: '骆宾王', poem: '昔去梅笳发，今来薤露晞。\n彤驺朝帝阙，丹旐背王畿。\n城郭犹疑是，原陵稍觉非。\n九原如可作，千载与谁归。' },
  { title: '乐大夫挽词五首 四', author: '骆宾王', poem: '一旦先朝菌，千秋掩夜台。\n青乌新兆去，白马故人来。\n草露当春泣，松风向暮哀。\n宁知荒垅外，吊鹤自裴徊。' },
  { title: '乐大夫挽词五首 五', author: '骆宾王', poem: '忽见泉台路，犹疑水镜悬。\n何如开白日，非复覩青天。\n华表迎千岁，幽扃送百年。\n独嗟流水引，长掩伯牙弦。' },
  { title: '丹阳刺史挽词三首 一', author: '骆宾王', poem: '百龄嗟倏忽，一旦向山阿。\n丹桂销已尽，青松哀更多。\n薰风虚听曲，薤露反成歌。\n自有藏舟处，谁怜隙驷过。' },
  { title: '丹阳刺史挽词三首 二', author: '骆宾王', poem: '恻怆恒山羽，留连棣萼篇。\n佳城非旧日，京兆即新阡。\n城郭三千岁，丘陵几万年。\n唯余松柏垅，朝夕起寒烟。' },
  { title: '丹阳刺史挽词三首 三', author: '骆宾王', poem: '短歌三献曲，长夜九泉台。\n此室玄扃掩，何年白日开。\n荒郊疎古木，寒隧积陈荄。\n独此伤心地，松声薄暮来。' },
  { title: '称心寺', author: '骆宾王', poem: '征帆恣远寻，逶迤过称心。\n凝滞蘅𦶜岸，沿洄樝柚林。\n穿溆不厌曲，舣潭惟爱深。\n为乐凡几许，听取舟中琴。' },
  { title: '陪润州薛司空丹徒桂明府游招隐寺', author: '骆宾王', poem: '共寻招隐寺，初识戴颙家。\n还依旧泉壑，应改昔云霞。\n绿竹寒天笋，红蕉腊月花。\n金绳倘留客，为系日光斜。' },
  { title: '棹歌行', author: '骆宾王', poem: '写月涂黄罢，凌波拾翠通。\n镜花摇芰日，衣麝入荷风。\n叶密舟难荡，莲疎浦易空。\n凤媒羞自托，鸳翼恨难穷。\n秋帐灯华翠，倡楼粉色红。\n相思无别曲，倂在棹歌中。' },
  { title: '海曲书情', author: '骆宾王', poem: '薄游倦千里，劳生负百年。\n未能槎上汉，讵肯剑游燕。\n白云照春海，青山横曙天。\n江涛让双璧，渭水掷三钱。\n坐惜风光晚，长歌独块然。' },
  { title: '蓬莱镇', author: '骆宾王', poem: '旅客春心断，边城夜望高。\n野楼疑海气，白鹭似江涛。\n结绶疲三入，承冠泣二毛。\n将飞怜弱羽，欲济乏轻舠。\n赖有阳春曲，穷愁且代劳。' },
  { title: '和李明府', author: '骆宾王', poem: '传闻叶县履，飞向洛阳城。\n驰道临层掖，津门对小平。\n霞残疑制锦，云度似飘缨。\n藻掞潘江澈，尘虚范甑清。\n讵怜冲斗气，犹向匣中鸣。' },
  { title: '春晚从李长史游开道林故山', author: '骆宾王', poem: '幽寻极幽壑，春望陟春台。\n云光栖断树，灵影入仙杯。\n古藤依格上，野径约山隈。\n落蘂飜风去，流莺满树来。\n兴阑荀御动，归路起浮埃。' },
  { title: '冬日野望', author: '骆宾王', poem: '故人无与晤，安步陟山椒。\n野静连云卷，川明断雾销。\n灵岩闻晓籁，洞浦涨秋潮。\n三江归望断，千里故乡遥。\n劳歌徒自奏，客魂谁为招。' },
  { title: '晚渡黄河', author: '骆宾王', poem: '千里寻归路，一苇乱平源。\n通波连马颊，迸水急龙门。\n照日荣光净，惊风瑞浪翻。\n棹唱临风断，樵讴入听喧。\n岸迥秋霞落，潭深夕雾繁。\n谁堪逝川上，日暮不归魂。' },
  { title: '宿山庄', author: '骆宾王', poem: '金陵一超忽，玉烛几还周。\n露积吴台草，风入郢门楸。\n林虚宿断雾，磴险挂悬流。\n拾青非汉策，化缁类秦裘。\n牵迹犹多蹇，劳生未寡尤。\n独此他乡梦，空山明月秋。' },
  { title: '晚度天山有怀京邑', author: '骆宾王', poem: '忽上天山路，依然想物华。\n云疑上苑叶，雪似御沟花。\n行叹戎麾远，坐怜衣带赊。\n交河浮绝塞，弱水浸流沙。\n旅思徒漂梗，归期未及瓜。\n宁知心断绝，夜夜泣胡笳。' },
  { title: '夕次蒲类津', author: '骆宾王', poem: '二庭归望断，万里客心愁。\n山路犹南属，河源自北流。\n晚风连朔气，新月照边秋。\n灶火通军壁，烽烟上戍楼。\n龙庭但苦战，燕颔会封侯。\n莫作兰山下，空令汉国羞。' },
  { title: '远使海曲春夜多怀', author: '骆宾王', poem: '长啸三春晚，端居百虑盈。\n未安胡蝶梦，遽切鲁禽情。\n别岛连寰海，离魂断戍城。\n流星疑伴使，低月似依营。\n怀禄宁期达，牵时匪狥名。\n艰虞行已远，时迹自相惊。' },
  { title: '早发诸暨', author: '骆宾王', poem: '征夫怀远路，夙驾上危峦。\n薄烟横绝𪩘，轻冻澁回湍。\n野雾连空暗，山风入曙寒。\n帝城临灞涘，禹穴枕江干。\n橘性行应化，蓬心去不安。\n独掩穷途泪，长歌行路难。' },
  { title: '望月有所思', author: '骆宾王', poem: '九秋凉风肃，千里月华开。\n圆光随露湛，碎影逐波来。\n似霜明玉砌，如镜写珠胎。\n晚色依关近，边声杂吹哀。\n离居分照耀，怨绪共裴徊。\n自绕南飞羽，空忝北堂才。' },
  { title: '送吴七游蜀', author: '骆宾王', poem: '日观分齐壤，星桥接蜀门。\n桃花嘶别路，竹叶泻离樽。\n夏老兰犹茂，秋深柳尚繁。\n雾销山望迥，风高野听喧。\n劳歌徒欲奏，赠别竟无言。\n唯有当秋月，空照野人园。' },
  { title: '西行别东台详正学士', author: '骆宾王', poem: '意气坐相亲，关河别故人。\n客似秦川上，歌疑易水滨。\n塞荒行辨玉，台远尚名轮。\n泄井怀边将，寻源重汉臣。\n上苑梅花早，御沟杨柳新。\n只应持此曲，别作边城春。' },
  { title: '和王记室从赵王春日游陀山寺', author: '骆宾王', poem: '鸟旟陪访道，鹫岭狎栖真。\n四禅明静业，三空广胜因。\n祥河疎叠涧，慧日皎重轮。\n叶暗龙宫密，花明鹿苑春。\n雕谈筌奥旨，妙辩漱玄津。\n雅曲终难和，徒自奏巴人。' },
  { title: '夏日夜忆张二', author: '骆宾王', poem: '伏枕忧思深，拥膝独长吟。\n烹鲤无尺素，筌鱼劳寸心。\n疎麻空有折，芳桂湛无斟。\n广庭含夕气，闲宇澹虚阴。\n织虫垂夜砌，惊鸟栖暝林。\n驩娱百年促，羁病一生侵。\n讵堪孤月夜，流水入鸣琴。' },
  { title: '寒夜独坐游子多怀简知己', author: '骆宾王', poem: '故乡眇千里，离忧积万端。\n鹑服长悲碎，蜗庐未卜安。\n富钩徒有想，贫铗为谁弹。\n柳秋风叶脆，荷晓露文团。\n晚金丛岸菊，余佩下幽兰。\n伐木伤心易，维桑归去难。\n独有孤明月，时照客庭寒。' },
  { title: '在军中赠先还知己', author: '骆宾王', poem: '蓬转俱行役，瓜时独未还。\n魂迷金阙路，望断玉门关。\n献凯多慙霍，论封几谢班。\n风尘催白首，岁月损红颜。\n落雁低秋塞，惊凫起暝湾。\n胡霜如剑锷，汉月似刀环。\n别后边庭树，相思几度攀。' },
  { title: '秋日山行简梁大官', author: '骆宾王', poem: '乘马陟层阜，回首睇山川。\n攒峰衔宿雾，叠𪩘架寒烟。\n百重含翠色，一道落飞泉。\n香吹分岩桂，鲜云抱石莲。\n地偏心易远，致默体逾玄。\n得性虚游刃，忘言已弃筌。\n弹冠劳巧拙，结绶倦牵缠。\n不如从四皓，丘中鸣一弦。' },
  { title: '晚泊江镇', author: '骆宾王', poem: '四运移阴律，三翼泛阳侯。\n荷香销晚夏，菊气入新秋。\n夜乌喧粉堞，宿雁下芦洲。\n海雾笼边徼，江风绕戍楼。\n转蓬惊别渚，徙橘怆离忧。\n魂飞灞陵岸，泪尽洞庭流。\n振影希鸿陆，逃名谢蚁丘。\n还嗟帝乡远，空望白云浮。' },
  { title: '浮槎', author: '骆宾王', poem: '昔负千寻质，高临九仞峰。\n真心凌晚桂，劲节掩寒松。\n忽值风飙折，坐为波浪冲。\n摧残空有恨，拥肿遂无庸。\n渤海三千里，泥沙几万重。\n似舟飘不定，如梗泛何从。\n仙客终难托，良工岂易逢。\n徒怀万乘器，谁为一先容。' },
  { title: '晚泊河曲', author: '骆宾王', poem: '三秋倦行役，千里泛归潮。\n通波竹箭水，轻舸木兰桡。\n金隄连曲岸，贝阙影浮桥。\n水净千年近，星飞五老遥。\n叠花开宿浪，浮叶下凉飙。\n浦荷疎晚菂，津柳渍寒条。\n恓惶劳梗泛，凄断倦蓬飘。\n仙槎不可托，河上独长谣。' },
  { title: '早发淮口望盱眙', author: '骆宾王', poem: '养蒙分四渎，习坎奠三荆。\n徙帝留余地，封王表旧城。\n岸昏涵蜃气，潮满应鸡声。\n洲迥连沙静，川虚积溜明。\n一朝从捧檄，千里倦悬旌。\n背流桐柏远，逗浦木兰轻。\n小山迷隐路，大块切劳生。\n唯有贞心在，独映寒潭清。' },
  { title: '边城落日', author: '骆宾王', poem: '紫塞流沙北，黄图灞水东。\n一朝辞俎豆，万里逐沙蓬。\n候月恒持满，寻源屡凿空。\n野昏边气合，烽迥戍烟通。\n膂力风尘倦，疆场岁月穷。\n河流控积石，山路远崆峒。\n壮志凌苍兕，精诚贯白虹。\n君恩如可报，龙剑有雌雄。' },
  { title: '宿温城望军营', author: '骆宾王', poem: '虏地寒胶折，边城夜柝闻。\n兵符关帝阙，天策动将军。\n塞静胡笳彻，沙明楚练分。\n风旗翻翼影，霜剑转龙文。\n白羽摇如月，青山断若云。\n烟疎疑卷幔，尘灭似销氛。\n投笔怀班业，临戎想顾勋。\n还应雪汉耻，持此报明君。' },
  { title: '过故宋', author: '骆宾王', poem: '旧国千年尽，荒城四望通。\n云浮非隐帝，日举类游童。\n绮琴朝化洽，祥石夜论空。\n马去遥奔郑，蛇分近带丰。\n池文敛束水，竹影漏寒丛。\n园兔承行月，川禽避断风。\n故宋诚难定，从梁事未工。\n唯当过周客，独愧吴台空。' },
  { title: '边夜有怀', author: '骆宾王', poem: '汉地行逾远，燕山去不穷。\n城荒犹筑怨，碣毁尚铭功。\n古戍烟尘满，边庭人事空。\n夜关明陇月，秋塞急胡风。\n倚伏良难定，荣枯岂易通。\n旅魂劳泛梗，离恨断征蓬。\n苏武封犹薄，崔骃宦不工。\n惟余北叟意，欲寄南飞鸿。' },
  { title: '伤祝阿王明府', author: '骆宾王', poem: '洛川真气上，重泉惠政融。\n含章光后烈，继武嗣前雄。\n与善良难验，生涯忽易穷。\n翔凫犹化履，狎雉尚驯童。\n钱满荒阶绿，尘浮虚帐红。\n夏余将宿草，秋近未惊蓬。\n烟晦泉门闭，日尽夜台空。\n谁堪孤陇外，独听白杨风。' },
  { title: '四月八日题七级', author: '骆宾王', poem: '化城分鸟堞，香阁俯龙川。\n复栋侵黄道，重檐架紫烟。\n铭书非晋代，壁画是梁年。\n霸略今何在，王宫尚岿然。\n二帝曾游圣，三卿是偶贤。\n因兹游胜侣，超彼托良缘。\n我出有为界，君登非想天。\n悠悠青旷里，荡荡白云前。\n今日经行处，曲音号盖烟。' },
  { title: '和孙长史秋日卧病', author: '骆宾王', poem: '霍第疏天府，潘园近帝台。\n调弦三妇至，置驿五侯来。\n尚想欢娱洽，吁嗟岁月催。\n金坛分上将，玉帐引瓌材。\n决胜鲸波静，腾谋鸟谷开。\n白云淮水外，紫陌灞陵隈。\n节变惊衰柳，笳繁思落梅。\n调神和玉烛，掞藻握珠胎。\n怅矣欣怀土，居然欲死灰。\n还因承雅曲，暂喜跃沈鳃。' },
  { title: '饯郑安阳入蜀', author: '骆宾王', poem: '彭山折坂外，井络少城隈。\n地是三巴俗，人非百里材。\n畏途君怅望，岐路我裴徊。\n心赏风烟隔，容华岁月催。\n遥遥分凤野，去去转龙媒。\n遗锦非前邑，鸣琴即旧台。\n剑门千仞起，石路五丁开。\n海客乘槎渡，仙童驭竹回。\n魂将离鹤远，思逐断猿哀。\n唯有双凫舄，飞去复飞来。' },
  { title: '咏怀', author: '骆宾王', poem: '少年识事浅，不知交道难。\n一言芬若桂，四海臭如兰。\n宝剑思存楚，金锤许报韩。\n虚心徒有托，循迹谅无端。\n太息关山险，吁嗟岁月阑。\n忘机殊会俗，守拙异怀安。\n阮籍空长啸，刘琨独未懽。\n十步庭芳敛，三秋陇月团。\n槐疎非尽意，松晚夜凌寒。\n悲调弦中急，穷愁醉里宽。\n莫将流水引，空向俗人弹。' },
  { title: '春日离长安客中言怀', author: '骆宾王', poem: '年华开早律，霁色荡芳晨。\n城阙千门晓，山河四望春。\n御沟通太液，戚里对平津。\n宝瑟调中妇，金罍引上宾。\n剧谈推曼倩，惊坐揖陈遵。\n意气一言合，风期万里亲。\n自惟安直道，守拙忌因人。\n谈器非先木，图荣异后薪。\n揶揄慙路鬼，憔悴切波臣。\n玄草终疲汉，乌裘几滞秦。\n生涯无岁月，岐路有风尘。\n还嗟太行道，处处白头新。' },
  { title: '夕次旧吴', author: '骆宾王', poem: '维舟背楚服，振策下吴畿。\n盛德弘三让，雄图枕九围。\n黄池通霸迹，赤壁畅戎威。\n文物俄迁谢，英灵有盛衰。\n行叹鸱夷没，遽惜湛卢飞。\n地古烟尘暗，年深馆宇稀。\n山川四望是，人事一朝非。\n悬剑空留信，亡珠尚识机。\n郑风遥可托，关月眇难依。\n西北云逾滞，东南气转微。\n徒怀伯通隐，多谢买臣归。\n唯有荒台露，薄暮湿征衣。' },
  { title: '早秋出塞寄东台详正学士', author: '骆宾王', poem: '促驾逾三水，长驱望五原。\n天阶分斗极，地理接楼烦。\n溪月明关陇，戎云聚塞垣。\n山川殊物候，风壤异凉喧。\n戍古秋尘合，沙寒宿雾繁。\n昔余迷学步，投迹忝词源。\n兰渚浮延阁，蓬山款禁园。\n彯缨陪绂冕，载笔偶玙璠。\n汲冢宁详蠹，秦牢讵辨冤。\n一朝从篚服，千里骛轻轩。\n乡梦随魂断，边声入听喧。\n南图终铩翮，北上遽催辕。\n吊影慙连茹，浮生倦触藩。\n数奇何以托，桃李自无言。' },
  { title: '幽絷书情通简知己', author: '骆宾王', poem: '昔岁逢杨意，观光贵楚材。\n穴疑丹凤起，场似白驹来。\n一命沦骄饵，三缄慎祸胎。\n不言劳倚伏，忽此遘邅回。\n骢马刑章峻，苍鹰狱吏猜。\n绝缣非易辨，疑璧果难裁。\n揆画慙周道，端忧滞夏台。\n生涯一灭裂，岐路几裴徊。\n青陆春芳动，黄沙旅思催。\n圆扉长寂寂，疎网尚恢恢。\n入穽先摇尾，迷津正曝腮。\n覆盆徒望日，蛰户未经雷。\n霜歇兰犹败，风多木屡摧。\n地幽蚕室闭，门静雀罗开。\n自悯秦冤痛，谁怜楚奏哀。\n汉阳穷鸟客，梁甫卧龙才。\n有气还冲斗，无时会凿坏。\n莫言韩长孺，长作不然灰。' },
  { title: '在军登城楼', author: '骆宾王', poem: '城上风威冷，江中水气寒。\n戎衣何日定，歌舞入长安。' },
  { title: '于易水送人', author: '骆宾王', poem: '此地别燕丹，壮士髪冲冠。\n昔时人已没，今日水犹寒。' },
  { title: '咏镜', author: '骆宾王', poem: '写月无芳桂，照日有花菱。\n不持光谢水，翻将影学冰。' },
  { title: '挑灯杖', author: '骆宾王', poem: '禀质非贪热，焦心岂惮熬。\n终知不自润，何处用脂膏。' },
  { title: '咏尘', author: '骆宾王', poem: '凌波起罗袜，含风染素衣。\n别有知音调，闻歌应自飞。' },
  { title: '玩初月', author: '骆宾王', poem: '忌满光先缺，乘昏影暂流。\n既能明似镜，何用曲如钩。' },
  { title: '送别', author: '骆宾王', poem: '寒更承夜永，凉夕向秋澄。\n离心何以赠，自有玉壶冰。' },
  { title: '忆蜀地佳人', author: '骆宾王', poem: '东西吴蜀关山远，鱼来雁去两难闻。\n莫怪常有千行泪，只为阳台一片云。' },
  { title: '咏鹅', author: '骆宾王', poem: '鹅，鹅，鹅，曲项向天歌。\n白毛浮绿水，红掌拨清波。' },
  { title: '奉和圣制夏日游石淙山', author: '武三思', poem: '此地岩壑数千重，吾君驾鹤□乘龙。\n掩暎叶光含翡翠，参差石影带芙蓉。\n白日将移冲叠𪩘，玄云欲度碍高峰。\n对酒鸣琴追野趣，时闻清吹入长松。' },
  { title: '仙鹤篇', author: '武三思', poem: '白鹤乘空何处来？青田紫盖本相依。\n缑山七月虽长去，辽水千年会忆归。\n缑山杳杳翔寥廓，辽水累累叹城郭。\n经随羽客步丹丘，曾逐仙人游碧落。\n迢迢碧落断氛埃，霞堂云阁几重开。\n欲寻东海黄金灶，仍向西山白玉台。\n九臯独唳方清切，五里惊群俄断绝。\n月下分行似度云，风前飏影疑回雪。\n风前月下路漫漫，水宿云翔去几般。\n宛转能倾吴国市，裴回巧拂汉皇坛。\n琴中作曲从来易，鼓里传声有甚难。\n夜夜恒飞银汉曲，朝朝常饮玉池澜。\n别有闻箫出紫烟，还如化履上青天。\n霜毛忽控三神下，玉羽俄看二客旋。\n燕雀终迷横海志，蜉蝣岂识在阴年。\n莫言一举轻千里，为与三山送九仙。' },
  { title: '宴龙泓', author: '武三思', poem: '登临开胜托，眺瞩尽良游。\n岩崿萦纡上，澄潭屈曲流。\n泛兰清兴洽，折桂野文遒。\n别后相思处，崎岖碧涧幽。' },
  { title: '凝碧池侍宴应制得出水槎', author: '武三思', poem: '彼木生何代，为槎复几年。\n欲乘银汉曲，先泛玉池边。\n拥溜根横岸，沈波影倒悬。\n无劳问蜀客，此处即高天。' },
  { title: '奉和宴小山池赋得谿字应制', author: '武三思', poem: '年光开碧沼，云色歛青谿。\n冻解鱼方戏，风暄鸟欲啼。\n岩泉飞野鹤，石镜舞山鸡。\n柳发龙鳞出，松新麈尾齐。\n九韶从此验，三月定应迷。' },
  { title: '奉和过梁王宅即目应制', author: '武三思', poem: '岩居多水石，野宅满风烟。\n本谓开三径，俄欣降九天。\n穿林移步辇，拂岸转行旃。\n凤竹初垂箨，龟河未吐莲。\n愿持山作寿，恒用劫为年。' },
  { title: '奉和春日游龙门应制', author: '武三思', poem: '凤架临香地，龙舆上翠微。\n星宫含雨气，月殿抱春辉。\n碧涧长虹下，雕梁早燕归。\n云疑浮宝盖，石似拂天衣。\n露草侵阶长，风花遶席飞。\n日斜宸赏洽，清吹入重闱。' },
  { title: '秋日于天中寺寻复礼上人', author: '武三思', poem: '妙域三时殿，香岩七宝宫。\n金绳先界道，玉柄即谈空。\n喻筏知何极，传灯竟不穷。\n弥天高义远，初地胜因通。\n理诣归一处，心行不二中。\n有无双惑遣，真俗两缘同。\n摘叶疑焚翠，投花若散红。\n网珠遥映日，檐铎近吟风。\n定沼寒光素，禅枝暝色葱。\n愿随方便力，长冀释尘笼。' },
  { title: '奉和圣制夏日游石淙山', author: '张易之', poem: '六龙骧首晓骎骎，七圣陪轩集颍阴。\n千丈松萝交翠幕，一丘山水当鸣琴。\n青鸟白云王母使，垂藤断葛野人心。\n山中日暮幽岩下，泠然香吹落花深。' },
  { title: '侍从过公主南宅侍宴探得风字应制', author: '张易之', poem: '逐赏平阳第，鸣笳上苑东。\n鸟吟千户竹，蝶舞百花丛。\n时攀小山桂，共挹大王风。\n坐客无劳起，秦箫曲未终。' },
  { title: '出塞', author: '张易之', poem: '侠客重恩光，骏马饰金装。\n瞥闻传羽檄，驰突救边荒。\n转战磨笄地，横行戴斗乡。\n将军占太白，小妇怨流黄。\n騕褭青丝骑，娉婷红粉妆。\n一春莺度曲，八月雁成行。\n谁堪坐秋思，罗袖拂空床。' },
  { title: '泛舟侍宴应制', author: '张易之', poem: '平明出御沟，解缆坐回舟。\n绿水澄明月，红罗结绮楼。\n弦歌争浦入，冠盖逐川流。\n白鱼臣作伴，相对舞王舟。' },
  { title: '奉和圣制夏日游石淙山', author: '张昌宗', poem: '云车遥裔三珠树，帐殿交阴八桂丛。\n磵险泉声疑度雨，川平桥势若晴虹。\n叔夜弹琴歌白雪，孙登长啸韵清风。\n即此陪欢游阆苑，无劳辛苦向崆峒。' },
  { title: '少年行', author: '张昌宗', poem: '少年不识事，落魄游韩魏。\n珠轩流水车，玉勒浮云骑。\n纵横意不一，然诺心无二。\n白璧赠穰苴，黄金奉毛遂。\n妙舞飘龙管，清歌吟凤吹。\n三春小苑游，千日中山醉。\n直言身可沈，谁论名与利。\n依倚孟尝君，自知能市义。' },
  { title: '太平公主山亭侍宴', author: '张昌宗', poem: '淮南有小山，嬴女隐其间。\n折桂芙蓉浦，吹箫明月湾。\n扇掩将雏曲，钗承堕马鬟。\n欢情本无限，莫掩洛城关。' },
  { title: '奉和圣制夏日游石淙山', author: '薛曜', poem: '玉洞幽寻更是天，朱霞绿景镇韶年。\n飞花藉藉迷行路，啭鸟遥遥作管弦。\n雾隐长林成翠幄，风吹细雨即虹泉。\n此中碧酒恒参圣，浪道昆山别有仙。' },
  { title: '子夜冬歌', author: '薛曜', poem: '朔风扣群木，严霜凋百草。\n借问月中人，安得长不老。' },
  { title: '舞马篇', author: '薛曜', poem: '星精龙种竞腾骧，双眼黄金紫艳光。\n一朝逢遇升平代，伏皂衔图事帝王。\n我皇盛德苞六宇，俗泰时和虞石拊。\n昔闻九代有余名，今日百兽先来舞。\n钩陈周衞俨旌旄，钟镈陶匏声殷地。\n承云嘈囋骇日灵，调露铿鈜动天驷。\n奔尘飞箭若麟螭，蹑景追风忽见知。\n咀衔拉铁并权奇，被服雕章何陆离。\n紫玉鸣珂临宝镫，青丝彩络带金羁。\n随歌鼓而电惊，逐丸劒而飙驰。\n态聚𨄳还急，骄凝骤不移。\n光敌白日下，气拥绿烟垂。\n婉转盘跚殊未已，悬空步骤红尘起。\n惊凫翔鹭不堪俦，矫凤回鸾那足拟。\n蘅垂桂褭香氛氲，长鸣汗血尽浮云。\n不辞辛苦来东道，祗为箫韶朝夕闻。\n阊阖间，玉台侧，承恩煦兮生光色。\n鸾锵锵，车翼翼，备国容兮为戎饰。\n充云翘兮天子庭，荷日用兮情无极。\n吉良乘兮一千岁，神是得兮天地期。\n大易占云南山寿，𫎺𧽼共乐圣明时。' },
  { title: '正夜侍宴应诏', author: '薛曜', poem: '重关钟漏通，夕敞凤皇宫。\n双阙祥烟里，千门明月中。\n酒杯浮湛露，歌曲唱风流。\n侍臣咸醉止，恒慙恩遇崇。' },
  { title: '送道士入天台', author: '薛曜', poem: '洛阳陌上多离别，蓬莱山下足波潮。\n碧海桑田何处在？笙歌一听一遥遥。' },
  { title: '奉和圣制夏日游石淙山', author: '杨敬述', poem: '山中别有神仙地，屈曲幽深碧涧垂。\n岩前暂驻黄金辇，席上还飞白玉巵。\n远近风泉俱合杂，高低云石共参差。\n林壑偏能留睿赏，长天莫遽下丹曦。' },
  { title: '奉和圣制夏日游石淙山', author: '于季子', poem: '九旗云布临嵩室，万骑星陈集颍川。\n瑞液含滋登禹膳，飞流荐响入虞弦。\n山扉野径朝花积，帐殿帷宫夏叶连。\n微臣献寿迎千寿，愿奉尧年倚万年。' },
  { title: '咏云', author: '于季子', poem: '瑞云千里映，祥辉四望新。\n随风乱鸟翅，泛水结鱼鳞。\n布叶疑临夏，开花讵待春。\n愿得承嘉景，无令掩桂轮。' },
  { title: '咏萤', author: '于季子', poem: '卉草诚幽贱，枯朽绝因依。\n忽逢借羽翼，不觉生光辉。\n直念恩华重，长嗟报効微。\n方思助日月，为许愿曾飞。' },
  { title: '早春洛阳荅杜审言', author: '于季子', poem: '梓泽年光往复来，杜霸游人去不回。\n若非载笔登麟阁，定是吹箫伴凤台。\n路傍桃李花犹嫩，波上芙蕖叶未开。\n分明寄语长安道，莫教留滞洛阳才。' },
  { title: '咏项羽', author: '于季子', poem: '北伐虽全赵，东归不王秦。\n空歌拔山力，羞作渡江人。' },
  { title: '咏汉高祖', author: '于季子', poem: '百战方夷项，三章且代秦。\n功归萧相国，气尽戚夫人。' },
  { title: '南行别弟', author: '于季子', poem: '万里人南去，三春雁北飞。\n不知何岁月？得与尔同归。' },
  { title: '长信宫中树', author: '乔知之', poem: '婀娜当轩树，䒠茸倚兰殿。\n叶艳九春华，香摇五明扇。\n余花鸟弄尽，新叶虫书徧。\n零落心自知，芳菲君不见。' },
  { title: '下山逢故夫', author: '乔知之', poem: '妾身本薄命，轻弃城南隅。\n庭前厌芍药，山上采蘼芜。\n春风罥纨袖，零露湿罗襦。\n羞将憔悴日，提笼逢故夫。' },
  { title: '巫山高', author: '乔知之', poem: '巫山十二峰，参差互隐见。\n浔阳几千里，周览忽已徧。\n想像神女姿，摘芳共珍荐。\n楚云何逶迤，红树日葱蒨。\n楚云没湘源，红树断荆门。\n郢路不可见，况复夜闻猨。' },
  { title: '弃妾篇', author: '乔知之', poem: '妾本丛台右，君在鴈门陲。\n悠悠淇水曲，彩燕入桑枝。\n不因媒结好，本以容相知。\n容谢君应去，情移会有离。\n还君结缕带，归妾识成诗。\n此物虽轻贱，不用使人嗤。' },
  { title: '苦寒行', author: '乔知之', poem: '胡天夜清迥，孤云独飘飏。\n遥裔出鴈关，逶迤含晶光。\n阴陵久裴回，幽都无多阳。\n初寒冻巨海，杀气流大荒。\n朔马饮寒冰，行子履胡霜。\n路有从役倦，卧死黄沙场。\n羁旅因相依，恸之泪沾裳。\n由来从军行，赏存不赏亡。\n亡者诚已矣，徒令存者伤。' },
  { title: '从军行', author: '乔知之', poem: '南庭结白露，北风扫黄叶。\n此时鸿鴈来，惊鸣催思妾。\n曲房理针线，平砧捣文练。\n鸳绮裁易成，龙乡信难见。\n窈窕九重闺，寂寞十年啼。\n纱窗白云宿，罗幌月光栖。\n云月隐微微，夜上流黄机。\n玉霜冻珠履，金吹薄罗衣。\n汉家已得地，君去将何事。\n宛转结蚕书，寂寥无鴈使。\n生平荷恩信，本为荣华进。\n况复落红颜，蝉声催绿鬓。' },
  { title: '拟古赠陈子昂', author: '乔知之', poem: '惸惸孤形影，悄悄独游心。\n以此从王事，常与子同衾。\n别离三河间，征战二庭深。\n胡天夜雨霜，胡鴈晨南翔。\n节物感离居，同衾违故乡。\n南归日将远，北方尚蓬飘。\n孟秋七月时，相送出外郊。\n海风吹凉木，边声响梢梢。\n勤役千万里，将临五十年。\n心事为谁道，抽琴歌坐筵。\n一弹再三叹，宾御泪潺湲。\n送君竟此曲，从兹长绝弦。' },
  { title: '绿珠篇', author: '乔知之', poem: '石家金谷重新声，明珠十斛买娉婷。\n此日可怜君自许，此时可喜得人情。\n君家闺阁不曾难，常将歌舞借人看。\n意气雄豪非分理，骄矜势力横相干。\n辞君去君终不忍，徒劳掩袂伤铅粉。\n百年离别在高楼，一旦红颜为君尽。' },
  { title: '和李侍郎古意', author: '乔知之', poem: '妾家巫山隔汉川，君度南庭向胡苑。\n高楼迢遰想金天，河汉昭回更怆然。\n夜如何其夜未央，闲花照月愁洞房。\n自矜夫婿胜王昌，三十曾作侍中郎。\n一从流落戍渔阳，怀哉万恨结中肠。\n南山幂幂兔丝花，北陵青青女萝树。\n由来花叶同一根，今日枝条分两处。\n三星差池光照灼，北斗西指秋云薄。\n茎枯花谢枝憔悴，香销色尽花零落。\n美人长叹艳容萎，含情收取摧折枝。\n调丝独弹声未移，感君行坐星岁迟。\n闺中宛转今若斯，谁能为报征人知。' },
  { title: '倡女行', author: '乔知之', poem: '石榴酒，葡萄浆，兰桂芳，茱萸香。\n愿君驻金鞍，暂此共年芳。\n愿君解罗襦，一醉同匡床。\n文君正新寡，结念在歌倡。\n昨宵绮帐迎韩寿，今朝罗袖引潘郎。\n莫吹羌笛惊邻里，不用琵琶喧洞房。\n且歌新夜曲，莫弄楚明光。\n此曲怨且艳，哀音断人肠。' },
  { title: '羸骏篇', author: '乔知之', poem: '喷玉长鸣西北来，自言当代是龙媒。\n万里铁关行入贡，九重金阙为君开。\n蹀躞朝驰过上苑，𫎺𧽼暝走发章台。\n玉勒金鞍荷装饰，路傍观者无穷极。\n小山桂树比权奇，上林桃花况颜色。\n忽闻天将出龙沙，汉主持将驾鼓车。\n去去山川劳日夜，遥遥关塞断烟霞。\n山川关塞十年征，汗血流离赴月营。\n肌肤销远道，膂力尽长城。\n长城日夕苦风霜，中有连年百战场。\n摇珂啮勒金羁尽，争锋足顿铁菱伤。\n垂耳罢轻赍，弃置在寒谿。\n大宛蒲海北，滇壑隽崖西。\n沙平留缓步，路远暗频嘶。\n从来力尽君须弃，何必寻途我已迷。\n岁岁年年奔远道，朝朝暮暮催疲老。\n扣冰晨饮黄河源，拂雪夜食天山草。\n楚水澶谿征战事，吴塞乌江辛苦地。\n持来报主不辞劳，宿昔立功非重利。\n丹心素节本无求，长鸣向君君不留。\n祗应澶漫归田里，万里低昂任生死。\n君王倘若不见遗，白骨黄金犹可市。' },
  { title: '铜雀妓', author: '乔知之', poem: '金阁惜分香，铅华不重妆。\n空余歌舞地，犹是为君王。\n哀弦调已绝，艳曲不须长。\n共看西陵暮，秋烟起白杨。' },
  { title: '侍宴应制得分字', author: '乔知之', poem: '紫禁肃晴氛，朱楼落晓云。\n豫游龙驾转，天乐凤箫闻。\n竹外仙亭出，花间辇路分。\n微臣一何幸，词赋奉明君。' },
  { title: '梨园亭子侍宴', author: '乔知之', poem: '年光陌上发，香辇禁中游。\n草绿鸳鸯殿，花红翡翠楼。\n天杯承露酌，仙管杂风流。\n今日陪欢豫，皇恩不可酬。' },
  { title: '和苏员外寓直', author: '乔知之', poem: '自昔重为郎，伊人练国章。\n三旬登建礼，五夜直明光。\n墨草尚书奏，衣飘侍御香。\n开轩竹气静，拂簟蕙风凉。\n晓漏离阊阖，鸣钟出未央。\n从来宿台上，天子贵文强。' },
  { title: '哭故人', author: '乔知之', poem: '生死久离居，凄凉历旧庐。\n叹兹三径断，不践十年余。\n古木巢禽合，荒庭爱客疎。\n匣留弹罢劒，床积读残书。\n玉没终无像，兰言强问虚。\n平生不得意，泉路复何如。' },
  { title: '折杨柳', author: '乔知之', poem: '可怜濯濯春杨柳，攀折将来就纤手。\n妾容与此同盛衰，何必君恩能独久。' },
  { title: '人日登高', author: '乔侃', poem: '仆本多悲者，年来不悟春。\n登高一游目，始觉柳条新。\n杜陵犹识汉，桃源不辨秦。\n𫏐若升云雾，还似出嚣尘。\n赖得烟霞气，淹留攀桂人。' },
  { title: '出塞', author: '乔备', poem: '沙场三万里，猛将五千兵。\n旌断冰谿戍，笳吹铁关城。\n阴云暮下雪，寒日昼无晶。\n直为怀恩苦，谁知边塞情。' },
  { title: '长门怨', author: '乔备', poem: '秋入长门殿，木落洞房虚。\n妾思宵徒静，君恩日更疎。\n坠露清金阁，流萤点玉除。\n还将闺里恨，遥问马相如。' },
  { title: '将军行', author: '刘希夷', poem: '将军辟辕门，耿介当风立。\n诸将欲言事，逡巡不敢入。\n劒气射云天，鼓声振原隰。\n黄尘塞路起，走马追兵急。\n弯弓从此去，飞箭如雨集。\n截围一百里，斩首五千级。\n代马流血死，胡人抱鞍泣。\n古来养甲兵，有事常讨袭。\n乘我庙堂运，坐使干戈戢。\n献凯归京师，军容何翕习。' },
  { title: '从军行', author: '刘希夷', poem: '秋天风飒飒，群胡马行疾。\n严城昼不开，伏兵暗相失。\n天子庙堂拜，将军凶门出。\n纷纷伊洛道，戎马几万匹。\n军门压黄河，兵气冲白日。\n平生怀仗劒，慷慨即投笔。\n南登汉月孤，北走代云密。\n近取韩彭计，早知孙吴术。\n丈夫清万里，谁能扫一室。' },
  { title: '春女行', author: '刘希夷', poem: '春女颜如玉，怨歌阳春曲。\n巫山春树红，沅湘春草绿。\n自怜妖艳姿，妆成独见时。\n愁心伴杨柳，春尽乱如丝。\n目极千余里，悠悠春江水。\n频想玉关人，愁卧金闺里。\n尚言春花落，不知秋风起。\n娇爱犹未终，悲凉从此始。\n忆昔楚王宫，玉楼粧粉红。\n纤腰弄明月，长袖舞春风。\n容华委西山，光阴不可还。\n桑林变东海，富贵今何在？\n寄言桃李容，胡为闺合重。\n但看楚王墓，唯有数株松。' },
  { title: '孤松篇', author: '刘希夷', poem: '蚕月桑叶青，鸎时柳花白。\n澹艳烟雨姿，敷芬阳春陌。\n如何秋风起，零落从此始。\n独有南涧松，不叹东流水。\n玄阴天地冥，皓雪朝夜零。\n岂不罹寒暑，为君留青青。\n青青好颜色，落落任孤直。\n群树遥相望，众草不敢逼。\n灵龟卜真隐，仙鸟宜栖息。\n耻受秦帝封，愿言唐侯食。\n寒山夜月明，山冷气清清。\n凄兮归凤集，吹之作琴声。\n松子卧仙岑，寂听疑野心。\n清泠有真曲，樵采无知音。\n美人何时来？幽径委绿苔。\n吁嗟深涧底，弃捐广厦材。' },
  { title: '嵩岳闻笙', author: '刘希夷', poem: '月出嵩山东，月明山益空。\n山人爱清景，散髪卧秋风。\n风止夜何清，独夜草虫鸣。\n仙人不可见，乘月近吹笙。\n绛唇吸灵气，玉指调真声。\n真声是何曲，三山鸾鹤情。\n昔去落尘俗，愿言闻此曲。\n今来卧嵩岑，何幸承幽音。\n神仙乐吾事，笙歌铭夙心。' },
  { title: '秋日题汝阳潭壁', author: '刘希夷', poem: '独坐秋阴生，悲来从所适。\n行见汝阳潭，飞萝蒙水石。\n悬瓢木叶上，风吹何历历。\n幽人不耐烦，振衣步闲寂。\n回流清见底，金沙覆银砾。\n错落非一文，空胧几千尺。\n鱼鳞可怜紫，鸭毛自然碧。\n吟咏秋水篇，渺然忘损益。\n秋水随形影，清浊混心迹。\n岁暮归去来，东山余宿昔。' },
  { title: '采桑', author: '刘希夷', poem: '杨柳送行人，青青西入秦。\n谁家采桑女，楼上不胜春。\n盈盈灞水曲，步步春芳绿。\n红脸耀明珠，绛唇含白玉。\n回首渭桥东，遥怜春色同。\n青丝娇落日，缃绮弄春风。\n携笼长叹息，逶迟恋春色。\n看花若有情，倚树疑无力。\n薄暮思悠悠，使君南陌头。\n相逢不相识，归去梦青楼。' },
  { title: '谒汉世祖庙', author: '刘希夷', poem: '舂陵气初发，渐台首未传。\n列营百万众，持国十八年。\n运开朱旗后，道合赤符先。\n宛城劒鸣匣，昆阳镝应弦。\n犷兽血涂地，巨人声沸天。\n长驱过北赵，短兵出南燕。\n太守迎门外，王郎死道边。\n升坛九城陌，端拱千秋年。\n朝廷方雀跃，劒珮几联翩。\n至德刑四海，神仪翳九泉。\n宗子行旧邑，恭闻清庙篇。\n君容穆而圣，臣像俨犹贤。\n攒木承危柱，疎萝挂朽椽。\n祠庭巢鸟啄，祭器网虫缘。\n怀古江山在，惟新历数迁。\n空余今夜月，长似旧时悬。' },
  { title: '巫山怀古', author: '刘希夷', poem: '巫山幽阴地，神女艳阳年。\n襄王伺容色，落日望悠然。\n归来高唐夜，金釭燄青烟。\n颓想卧瑶席，梦魂何翩翩。\n摇落殊未已，荣华倏徂迁。\n愁思潇湘浦，悲凉云梦田。\n猿啼秋风夜，鴈飞明月天。\n巴歌不可听，听此益潺湲。' },
  { title: '归山', author: '刘希夷', poem: '归去嵩山道，烟花覆青草。\n草绿山无尘，山青杨柳春。\n日暮松声合，空歌思杀人。' },
  { title: '代闺人春日', author: '刘希夷', poem: '珠帘的晓光，玉颜艳春彩。\n林间鸟鸣唤，户外花相待。\n花鸟惜芳菲，鸟鸣花乱飞。\n人今伴花鸟，日暮不能归。\n池月怜歌扇，山云爱舞衣。\n佳期杨柳陌，携手莫相违。' },
  { title: '蜀城怀古', author: '刘希夷', poem: '蜀土遶水竹，吴天积风霜。\n穷览通表里，气色何苍苍。\n旧国有年代，青楼思艳妆。\n古人无岁月，白骨冥丘荒。\n寂历弹琴地，幽流读书堂。\n玄龟埋卜室，彩凤灭词场。\n阵图一一在，栢树双双行。\n鬼神清汉庙，鸟雀参秦仓。\n叹世已多感，怀心益自伤。\n赖蒙灵丘境，时当明月光。' },
  { title: '洛川怀古', author: '刘希夷', poem: '萋萋春草绿，悲歌牧征马。\n行见白头翁，坐泣青竹下。\n感叹前问之，赠予辛苦词。\n岁月移今古，山河更盛衰。\n晋家都洛滨，朝廷多近臣。\n词赋归潘岳，繁华称季伦。\n梓泽春草菲，河阳乱华飞。\n绿珠不可夺，白首同所归。\n高楼倏冥灭，茂林久摧折。\n昔时歌舞台，今成狐兔穴。\n人事互消亡，世路多悲伤。\n北邙是吾宅，东岳为吾乡。\n君看北邙道，髑髅萦蔓草。\n芳□□□□，□□□□□。\n碑茔或半存，荆棘敛幽魂。\n挥涕弃之去，不忍闻此言。' },
  { title: '春日行歌', author: '刘希夷', poem: '山树落梅花，飞落野人家。\n野人何所有，满瓮阳春酒。\n携酒上春台，行歌伴落梅。\n醉罢卧明月，乘梦游天台。' },
  { title: '江南曲八首 一', author: '刘希夷', poem: '暮宿南洲草，晨行北岸林。\n日悬沧海阔，水隔洞庭深。\n烟景无留意，风波有异浔。\n岁游难极目，春戏易为心。\n朝夕无荣遇，芳菲已满襟。' },
  { title: '江南曲八首 二', author: '刘希夷', poem: '艳唱潮初落，江花露未晞。\n春洲惊翡翠，朱服弄芳菲。\n画舫烟中浅，青阳日际微。\n锦帆冲浪湿，罗袖拂行衣。\n含情罢所采，相叹惜流晖。' },
  { title: '江南曲八首 三', author: '刘希夷', poem: '君为陇西客，妾遇江南春。\n朝游含灵果，夕采弄风苹。\n果气时不歇，苹花日自新。\n以此江南物，持赠陇西人。\n空盈万里怀，欲赠竟无因。' },
  { title: '江南曲八首 四', author: '刘希夷', poem: '皓如楚江月，霭若吴岫云。\n波中自皎镜，山上亦氤氲。\n明月留照妾，轻云持赠君。\n山川各离散，光气乃殊分。\n天涯一为别，江北不相闻。' },
  { title: '江南曲八首 五', author: '刘希夷', poem: '舣舟乘潮去，风帆振早凉。\n潮平见楚甸，天际望维扬。\n洄溯经千里，烟波接两乡。\n云明江屿出，日照海流长。\n此中逢岁[晏]，浦树落花芳。' },
  { title: '江南曲八首 六', author: '刘希夷', poem: '暮春三月晴，维扬吴楚城。\n城临大江汜，回映洞浦清。\n晴云曲金阁，珠楼碧烟里。\n月明芳树群鸟飞，风过长林杂花起。\n可怜离别谁家子，于此一至情何已。' },
  { title: '江南曲八首 七', author: '刘希夷', poem: '北堂红草盛䒠茸，南湖碧水照芙蓉。\n朝游暮起金花尽，渐觉罗裳珠露浓。\n自惜妍华三五岁，已叹关山千万重。\n人情一去无还日，欲赠怀芳怨不逢。' },
  { title: '江南曲八首 八', author: '刘希夷', poem: '忆昔江南年盛时，平生怨在长洲曲。\n冠盖星繁江水上，冲风摽落洞庭渌。\n落花两袖红纷纷，朝霞高阁洗晴云。\n谁言此处婵娟子，珠玉为心以奉君。' },
  { title: '捣衣篇', author: '刘希夷', poem: '秋天瑟瑟夜漫漫，夜白风清玉露漙。\n燕山游子衣裳薄，秦地佳人闺阁寒。\n欲向楼中萦楚练，还来机上裂齐纨。\n揽红袖兮愁徙倚，盼青砧兮怅盘桓。\n盘桓徙倚夜已久，萤火双飞入帘牖。\n西北风来吹细腰，东南月上浮纤手。\n此时秋月可怜明，此时秋风别有情。\n君看月下参差影，为听莎间断续声。\n绛河转兮青云晓，飞鸟鸣兮行人少。\n攒眉缉缕思纷纷，对影穿针魂悄悄。\n闻道还家未有期，谁怜登陇不胜悲。\n梦见形容亦旧日，为许裁缝改昔时。\n缄书远寄交河曲，须及明年春草绿。\n莫言衣上有斑斑，只为思君泪相续。' },
  { title: '公子行', author: '刘希夷', poem: '天津桥下阳春水，天津桥上繁华子。\n马声回合青云外，人影动摇绿波里。\n绿波荡漾玉为砂，青云离披锦作霞。\n可怜杨柳伤心树，可怜桃李断肠花。\n此日遨游邀美女，此时歌舞入娼家。\n娼家美女郁金香，飞来飞去公子傍。\n的的珠帘白日映，娥娥玉颜红粉妆。\n花际裴回双蛱蝶，池边顾步两鸳鸯。\n倾国倾城汉武帝，为云为雨楚襄王。\n古来容光人所羡，况复今日遥相见。\n愿作轻罗着细腰，愿为明镜分娇面。\n与君相向转相亲，与君双栖共一身。\n愿作贞松千岁古，谁论芳槿一朝新。\n百年同谢西山日，千秋万古北邙尘。' },
  { title: '代悲白头吟', author: '刘希夷', poem: '洛阳城东桃李花，飞来飞去落谁家。\n洛阳女儿好颜色，坐见落花长叹息。\n今年花落颜色改，明年花开复谁在。\n已见松柏摧为薪，更闻桑田变成海。\n古人无复洛城东，今人还对落花风。\n年年岁岁花相似，岁岁年年人不同。\n寄言全盛红颜子，应怜半死白头翁。\n此翁白头真可怜，伊昔红颜美少年。\n公子王孙芳树下，清歌妙舞落花前。\n光禄池台开锦绣，将军楼阁画神仙。\n一朝卧病无相识，三春行乐在谁边。\n宛转蛾眉能几时，须臾鹤髪乱如丝。\n但看古来歌舞地，惟有黄昏鸟雀悲。' },
  { title: '代秦女赠行人', author: '刘希夷', poem: '鸾镜晓含春，蛾眉向影嚬。\n开□衣裳破，那堪粉黛新。\n春还洛阳道，为忆春阶草。\n杨叶未能攀，梅花待君扫。\n今朝喜鹊傍人飞，应是狂夫走马归。\n遥想行歌共游乐，迎前含笑着春衣。' },
  { title: '洛中晴月送殷四入关', author: '刘希夷', poem: '清洛浮桥南渡头，天晶万里散华洲。\n晴看石濑光无数，晓入寒潭浸不流。\n微云一点曙烟起，南陌憧憧遍行子。\n欲将此意与君论，复道秦关尚千里。' },
  { title: '入塞', author: '刘希夷', poem: '将军陷虏围，边务息戎机。\n霜雪交河尽，旌旗入塞飞。\n晓光随马度，春色伴人归。\n课绩朝明主，临轩拜武威。' },
  { title: '览镜', author: '刘希夷', poem: '青楼挂明镜，临照不胜悲。\n白发今如此，人生能几时。\n秋风下山路，明月上春期。\n叹息君恩尽，容颜不可思。' },
  { title: '晚春', author: '刘希夷', poem: '佳人眠洞房，回首见垂杨。\n寒尽鸳鸯被，春生玳瑁床。\n庭阴幕青霭，帘影散红芳。\n寄语同心伴，迎春且薄妆。' },
  { title: '送友人之新丰', author: '刘希夷', poem: '日暮秋风起，关山断别情。\n泪随黄叶下，愁向绿樽生。\n野路归骖转，河洲宿鸟惊。\n宾游宽旅宴，王事促严程。' },
  { title: '饯李秀才赴举', author: '刘希夷', poem: '鸿鹄振羽翮，翻飞入帝乡。\n朝鸣集银树，暝宿下金塘。\n日月天门近，风烟夜路长。\n自怜穷浦鴈，岁岁不随阳。' },
  { title: '夜集张𬤇所居', author: '刘希夷', poem: '江南成久客，门馆日萧条。\n惟有图书在，多伤鬓髪凋。\n诸生陪讲诵，稚子给渔樵。\n隐室寒灯净，空阶落叶飘。\n沧洲自有趣，谁道隐须招。' },
  { title: '故园置酒', author: '刘希夷', poem: '酒熟人须饮，春还鬓已秋。\n愿逢千日醉，得缓百年忧。\n旧里多青草，新知尽白头。\n风前灯易灭，川上月难留。\n卒卒周姬旦，栖栖鲁孔丘。\n平生能几日，不及且遨游。' },
  { title: '晚憩南阳旅馆', author: '刘希夷', poem: '旅馆何年废，征夫此日过。\n途穷人自哭，春至鸟还歌。\n行路新知少，荒田古径多。\n池篁覆丹谷，坟树遶清波。\n日照蓬阴转，风微野气和。\n伤心不可去，回首怨如何。' },
  { title: '庆云章', author: '陈子昂', poem: '昆仑元气，实生庆云。\n大人作矣，五色氤氲。\n昔在帝妫，南风既薰。\n丛芳烂熳，郁郁纷纷。\n旷矣千祀，庆云来止。\n玉叶金柯，祚我天子。\n非我天子，庆云谁昌。\n非我圣母，庆云谁光。\n庆云光矣，周道昌矣。\n九万八千，天授皇年。' },
  { title: '感遇诗三十八首 一', author: '陈子昂', poem: '微月生西海，幽阳始代升。\n圆光正东满，阴魂已朝凝。\n太极生天地，三元更废兴。\n至精谅斯在，三五谁能征。' },
  { title: '感遇诗三十八首 二', author: '陈子昂', poem: '兰若生春夏，芊蔚何青青。\n幽独空林色，朱蕤冒紫茎。\n迟迟白日晚，袅袅秋风生。\n岁华尽摇落，芳意竟何成。' },
  { title: '感遇诗三十八首 三', author: '陈子昂', poem: '苍苍丁零塞，今古缅荒途。\n亭堠何摧兀，暴骨无全躯。\n黄沙幕南起，白日隐西隅。\n汉甲三十万，曾以事匈奴。\n但见沙场死，谁怜塞上孤。' },
  { title: '感遇诗三十八首 四', author: '陈子昂', poem: '乐羊为魏将，食子殉军功。\n骨肉且相薄，他人安得忠。\n吾闻中山相，乃属放麑翁。\n孤兽犹不忍，况以奉君终。' },
  { title: '感遇诗三十八首 五', author: '陈子昂', poem: '市人矜巧智，于道若童蒙。\n倾夺相夸侈，不知身所终。\n曷见玄真子，观世玉壶中。\n窅然遗天地，乘化入无穷。' },
  { title: '感遇诗三十八首 六', author: '陈子昂', poem: '吾观龙变化，乃知至阳精。\n石林何冥密，幽洞无留行。\n古之得仙道，信与元化幷。\n玄感非象识，谁能测沈冥。\n世人拘目见，酣酒笑丹经。\n昆仑有瑶树，安得采其英。' },
  { title: '感遇诗三十八首 七', author: '陈子昂', poem: '白日每不归，青阳时暮矣。\n茫茫吾何思，林卧观无始。\n众芳委时晦，𫛸鴂鸣悲耳。\n鸿荒古已颓，谁识巢居子。' },
  { title: '感遇诗三十八首 八', author: '陈子昂', poem: '吾观昆仑化，日月沦洞冥。\n精魄相交会，天壤以罗生。\n仲尼推太极，老聃贵窈冥。\n西方金仙子，崇义乃无明。\n空色皆寂灭，缘业定何成。\n名教信纷藉，死生俱未停。' },
  { title: '感遇诗三十八首 九', author: '陈子昂', poem: '圣人秘元命，惧世乱其真。\n如何嵩公辈，诙谲误时人。\n先天诚为美，阶乱祸谁因。\n长城备胡寇，嬴祸发其亲。\n赤精既迷汉，子年何救秦。\n去去桃李花，多言死如麻。' },
  { title: '感遇诗三十八首 十', author: '陈子昂', poem: '深居观元化，悱然争朵颐。\n谗说相啖食，利害纷㘈㘈。\n便便夸毘子，荣耀更相持。\n务光让天下，商贾竞刀锥。\n已矣行采芝，万世同一时。' },
  { title: '感遇诗三十八首 十一', author: '陈子昂', poem: '吾爱鬼谷子，青谿无垢氛。\n囊括经世道，遗身在白云。\n七雄方龙鬬，天下久无君。\n浮荣不足贵，遵养晦时文。\n舒可弥宇宙，卷之不盈分。\n岂徒山木寿，空与麋鹿群。' },
  { title: '感遇诗三十八首 十二', author: '陈子昂', poem: '呦呦南山鹿，罹罟以媒和。\n招摇青桂树，幽蠹亦成科。\n世情甘近习，荣耀纷如何。\n怨憎未相复，亲爱生祸罗。\n瑶台倾巧笑，玉杯殒双蛾。\n谁见枯城蘖，青青成斧柯。' },
  { title: '感遇诗三十八首 十三', author: '陈子昂', poem: '林居病时久，水木澹孤清。\n闲卧观物化，悠悠念无生。\n青春始萌达，朱火已满盈。\n徂落方自此，感叹何时平。' },
  { title: '感遇诗三十八首 十四', author: '陈子昂', poem: '临岐泣世道，天命良悠悠。\n昔日殷王子，玉马遂朝周。\n宝鼎沦伊谷，瑶台成古丘。\n西山伤遗老，东陵有故侯。' },
  { title: '感遇诗三十八首 十五', author: '陈子昂', poem: '贵人难得意，赏爱在须臾。\n莫以心如玉，探他明月珠。\n昔称夭桃子，今为舂市徒。\n鸱鸮悲东国，麋鹿泣姑苏。\n谁见鸱夷子，扁舟去五湖。' },
  { title: '感遇诗三十八首 十六', author: '陈子昂', poem: '圣人去已久，公道缅良难。\n蚩蚩夸毘子，尧禹以为谩。\n骄荣贵工巧，势利迭相干。\n燕王尊乐毅，分国愿同欢。\n鲁连让齐爵，遗组去邯郸。\n伊人信往矣，感激为谁叹。' },
  { title: '感遇诗三十八首 十七', author: '陈子昂', poem: '幽居观天运，悠悠念群生。\n终古代兴没，豪圣莫能争。\n三季沦周赧，七雄灭秦嬴。\n复闻赤精子，提劒入咸京。\n炎光既无象，晋虏复纵横。\n尧禹道已昧，昏虐势方行。\n岂无当世雄，天道与胡兵。\n咄咄安可言，时醉而未醒。\n仲尼溺东鲁，伯阳遁西溟。\n大运自古来，旅人胡叹哉。' },
  { title: '感遇诗三十八首 十八', author: '陈子昂', poem: '逶迤势已久，骨鲠道斯穷。\n岂无感激者，时俗颓此风。\n灌园何其鄙，皎皎于陵中。\n世道不相容，嗟嗟张长公。' },
  { title: '感遇诗三十八首 十九', author: '陈子昂', poem: '圣人不利己，忧济在元元。\n黄屋非尧意，瑶台安可论。\n吾闻西方化，清净道弥敦。\n奈何穷金玉，雕刻以为尊。\n云构山林尽，瑶图珠翠烦。\n鬼工尚未可，人力安能存。\n夸愚适增累，矜智道逾昏。' },
  { title: '感遇诗三十八首 二十', author: '陈子昂', poem: '玄天幽且默，群议曷嗤嗤。\n圣人教犹在，世运久陵夷。\n一绳将何系？忧醉不能持。\n去去行采芝，勿为尘所欺。' },
  { title: '感遇诗三十八首 二十一', author: '陈子昂', poem: '蜻蛉游天地，与世本无患。\n飞飞未能止，黄雀来相干。\n穰侯富秦宠，金石比交欢。\n出入咸阳里，诸侯莫敢言。\n宁知山东客，激怒秦王肝。\n布衣取丞相，千载为辛酸。' },
  { title: '感遇诗三十八首 二十二', author: '陈子昂', poem: '微霜知岁晏，斧柯始青青。\n况乃金天夕，浩露沾群英。\n登山望宇宙，白日已西暝。\n云海方荡潏，孤鳞安得宁。' },
  { title: '感遇诗三十八首 二十三', author: '陈子昂', poem: '翡翠巢南海，雄雌珠树林。\n何知美人意，骄爱比黄金。\n杀身炎州里，委羽玉堂阴。\n旖旎光首饰，葳蕤烂锦衾。\n岂不在遐远，虞罗忽见寻。\n多材信为累，叹息此珍禽。' },
  { title: '感遇诗三十八首 二十四', author: '陈子昂', poem: '挈瓶者谁子，姣服当青春。\n三五明月满，盈盈不自珍。\n高堂委金玉，微缕悬千钧。\n如何负公鼎，被敚笑时人。' },
  { title: '感遇诗三十八首 二十五', author: '陈子昂', poem: '玄蝉号白露，兹岁已蹉跎。\n群物从大化，孤英将奈何？\n瑶台有青鸟，远食玉山禾。\n昆仑见玄凤，岂复虞云罗。' },
  { title: '感遇诗三十八首 二十六', author: '陈子昂', poem: '荒哉穆天子，好与白云期。\n宫女多怨旷，层城闭蛾眉。\n日耽瑶池乐，岂伤桃李时。\n青苔空萎绝，白发生罗帷。' },
  { title: '感遇诗三十八首 二十七', author: '陈子昂', poem: '朝发宜都渚，浩然思故乡。\n故乡不可见，路隔巫山阳。\n巫山彩云没，高丘正微茫。\n伫立望已久，涕落沾衣裳。\n岂兹越乡感，忆昔楚襄王。\n朝云无处所，荆国亦沦亡。' },
  { title: '感遇诗三十八首 二十八', author: '陈子昂', poem: '昔日章华宴，荆王乐荒淫。\n霓旌翠羽盖，射兕云梦林。\n朅来高唐观，怅望云阳岑。\n雄图今何在？黄雀空哀吟。' },
  { title: '感遇诗三十八首 二十九', author: '陈子昂', poem: '丁亥岁云暮，西山事甲兵。\n赢粮匝邛道，荷戟争羗城。\n严冬阴风劲，穷岫泄云生。\n昏噎无昼夜，羽檄复相惊。\n拳跼竞万仞，崩危走九冥。\n籍籍峰壑里，哀哀冰雪行。\n圣人御宇宙，闻道泰阶平。\n肉食谋何失，藜藿缅纵横。' },
  { title: '感遇诗三十八首 三十', author: '陈子昂', poem: '可怜瑶台树，灼灼佳人姿。\n碧华映朱实，攀折青春时。\n岂不盛光宠，荣君白玉墀。\n但恨红芳歇，凋伤感所思。' },
  { title: '感遇诗三十八首 三十一', author: '陈子昂', poem: '朅来豪游子，势利祸之门。\n如何兰膏叹，感激自生冤。\n众趋明所避，时弃道犹存。\n云渊既已失，罗网与谁论。\n箕山有高节，湘水有清源。\n唯应白鸥鸟，可为洗心言。' },
  { title: '感遇诗三十八首 三十二', author: '陈子昂', poem: '索居犹几日，炎夏忽然衰。\n阳彩皆阴翳，亲友尽暌违。\n登山望不见，涕泣久涟洏。\n宿梦感颜色，若与白云期。\n马上骄豪子，驱逐正蚩蚩。' },
  { title: '感遇诗三十八首 三十三', author: '陈子昂', poem: '金鼎合神丹，世人将见欺。\n飞飞骑羊子，胡乃在峨眉。\n变化固幽类，芳菲能几时。\n疲疴苦沦世，忧痗日侵淄。\n眷然顾幽褐，白云空涕洟。' },
  { title: '感遇诗三十八首 三十四', author: '陈子昂', poem: '朔风吹海树，萧条边已秋。\n亭上谁家子，哀哀明月楼。\n自言幽燕客，结发事远游。\n赤丸杀公吏，白刃报私雠。\n避雠至海上，被役此边州。\n故乡三千里，辽水复悠悠。\n每愤胡兵入，常为汉国羞。\n何知七十战，白首未封侯。' },
  { title: '感遇诗三十八首 三十五', author: '陈子昂', poem: '本为贵公子，平生实爱才。\n感时思报国，拔劒起蒿莱。\n西驰丁零塞，北上单于台。\n登山见千里，怀古心悠哉。\n谁言未忘祸，磨灭成尘埃。' },
  { title: '感遇诗三十八首 三十六', author: '陈子昂', poem: '浩然坐何慕，吾蜀有峨眉。\n念与楚狂子，悠悠白云期。\n时哉悲不会，涕泣久涟洏。\n梦登绥山穴，南采巫山芝。\n探元观群化，遗世从云螭。\n婉变时永矣，感悟不见之。' },
  { title: '感遇诗三十八首 三十七', author: '陈子昂', poem: '朝入云中郡，北望单于台。\n胡秦何密迩，沙朔气雄哉。\n藉藉天骄子，猖狂已复来。\n塞垣无名将，亭堠空崔嵬。\n咄嗟吾何叹，边人涂草莱。' },
  { title: '感遇诗三十八首 三十八', author: '陈子昂', poem: '仲尼探元化，幽鸿顺阳和。\n大运自盈缩，春秋递来过。\n盲飙忽号怒，万物相纷劘。\n溟海皆震荡，孤凤其如何。' },
  { title: '观荆玉篇', author: '陈子昂', poem: '鸱夷双白玉，此玉有缁磷。\n悬之千金价，举世莫知真。\n丹青非异色，轻重有殊伦。\n勿信玉工言，徒悲荆国人。' },
  { title: '鸳鸯篇', author: '陈子昂', poem: '飞飞鸳鸯鸟，举翼相蔽亏。\n俱来绿潭里，共向白云涯。\n音容相眷恋，羽翮两逶迤。\n苹萍戏春渚，霜霰遶寒池。\n浦沙连岸净，汀树拂潭垂。\n年年此游玩，岁岁来追随。\n凤凰起丹穴，独向梧桐枝。\n鸿雁来紫塞，空忆稻粱肥。\n乌啼倦依托，鹤鸣伤别离。\n岂若此双禽，飞翻不异林。\n刷尾青江浦，交颈紫山岑。\n文章负奇色，和鸣多好音。\n闻有鸳鸯绮，复有鸳鸯衾。\n持为美人赠，勖此故交心。' },
  { title: '与东方左史虬修竹篇', author: '陈子昂', poem: '龙种生南岳，孤翠郁亭亭。\n峰岭上崇崒，烟雨下微冥。\n夜闻鼯鼠呌，昼聒泉鹤声。\n春风正淡荡，白露已清泠。\n哀响激金奏，密色滋玉英。\n岁寒霜雪苦，含彩独青青。\n岂不厌凝洌，羞比春木荣。\n春木有荣歇，此节无凋零。\n始愿与金石，终古保坚贞。\n不意伶伦子，吹之学凤鸣。\n遂偶云和瑟，张乐奏天庭。\n妙曲方千变，箫韶亦九成。\n信蒙雕斲美，常愿事仙灵。\n驱驰翠虬驾，伊郁紫鸾笙。\n结交嬴台女，吟弄升天行。\n携手登白日，远游戏赤城。\n低昂玄鹤舞，断续彩云生。\n永随众仙逝，三山游玉京。' },
  { title: '蓟丘览古赠卢居士藏用七首 轩辕台', author: '陈子昂', poem: '北登蓟丘望，求古轩辕台。\n应龙已不见，牧马空黄埃。\n尚想广成子，遗迹白云隈。' },
  { title: '蓟丘览古赠卢居士藏用七首 燕昭王', author: '陈子昂', poem: '南登碣石坂，遥望黄金台。\n丘陵尽乔木，昭王安在哉。\n霸图怅已矣，驱马复归来。' },
  { title: '蓟丘览古赠卢居士藏用七首 乐生', author: '陈子昂', poem: '王道已沦昧，战国竞贪兵。\n乐生何感激，仗义下齐城。\n雄图竟中夭，遗叹寄阿衡。' },
  { title: '蓟丘览古赠卢居士藏用七首 燕太子', author: '陈子昂', poem: '秦王日无道，太子怨亦深。\n一闻田光义，匕首赠千金。\n其事虽不立，千载为伤心。' },
  { title: '蓟丘览古赠卢居士藏用七首 田光先生', author: '陈子昂', poem: '自古皆有死，狥义良独稀。\n奈何燕太子，尚使田生疑。\n伏劒诚已矣，感我涕沾衣。' },
  { title: '蓟丘览古赠卢居士藏用七首 邹衍', author: '陈子昂', poem: '大运沦三代，天人罕有窥。\n邹子何寥廓，漫说九瀛垂。\n兴亡已千载，今也则无推。' },
  { title: '蓟丘览古赠卢居士藏用七首 郭隗', author: '陈子昂', poem: '逢时独为贵，历代非无才。\n隗君亦何幸，遂起黄金台。' },
  { title: '西还至散关答乔补阙知之', author: '陈子昂', poem: '葳蕤苍梧凤，嘹唳白露蝉。\n羽翰本非匹，结交何独全。\n昔君事胡马，余得奉戎旃。\n携手向沙塞，关河缅幽燕。\n芳岁几阳止，白日屡徂迁。\n功业云台薄，平生玉佩捐。\n叹此南归日，犹闻北戍边。\n代水不可涉，巴江亦潺湲。\n揽衣度函谷，衔涕望秦川。\n蜀门自兹始，云山方浩然。' },
  { title: '度峡口山赠乔补阙知之王二无竞', author: '陈子昂', poem: '峡口大漠南，横绝界中国。\n丛石何纷𫄙，赤山复翕赩。\n远望多众容，逼之无异色。\n崔崒乍孤断，逶迤屡回直。\n信关胡马冲，亦距汉边塞。\n岂依河山险，将顺休明德。\n物壮诚有衰，势雄良易极。\n逦迤忽而尽，泱漭平不息。\n之子黄金躯，如何此荒域。\n云台盛多士，待君丹墀侧。' },
  { title: '题居延古城赠乔十二知之', author: '陈子昂', poem: '闻君东山意，宿昔紫芝荣。\n沧洲今何在？华髪旅边城。\n还汉功既薄，逐胡策未行。\n徒嗟白日暮，坐对黄云生。\n桂枝芳欲晚，薏苡谤谁明。\n无为空自老，含叹负生平。' },
  { title: '赠赵六贞固二首 一', author: '陈子昂', poem: '回中[烽]火入，塞上追兵起。\n此时边朔寒，登陇思君子。\n东顾望汉京，南山云雾里。' },
  { title: '赠赵六贞固二首 二', author: '陈子昂', poem: '赤螭媚其彩，婉娈苍梧泉。\n昔者瑯琊子，躬耕亦慨然。\n美人岂遐旷，之子乃前贤。\n良辰在何许，白日屡颓迁。\n道心固微密，神用无留连。\n舒可弥宇宙，揽之不盈拳。\n蓬莱久芜没，金石徒精坚。\n良宝委短褐，闲琴独婵娟。' },
  { title: '答韩使同在边', author: '陈子昂', poem: '汉家失中策，胡马屡南驱。\n闻诏安边使，曾是故人谟。\n废书怅怀古，负劒许良图。\n出关岁方晏，乘障日多虞。\n虏入白登道，烽交紫塞途。\n连兵屯北地，清野备东胡。\n边城方晏闭，斥堠始昭苏。\n复闻韩长孺，辛苦事匈奴。\n雨雪颜容改，纵横才位孤。\n空怀老臣策，未获赵军租。\n但蒙魏侯重，不受谤书诬。\n当取金人祭，还歌凯入都。' },
  { title: '征东至淇门答宋十一参军之问', author: '陈子昂', poem: '南星中大火，将子涉清淇。\n西林改微月，征斾空自持。\n碧潭去已远，瑶华折遗谁。\n若问辽阳戍，悠悠天际旗。' },
  { title: '答洛阳主人', author: '陈子昂', poem: '平生白云志，早爱赤松游。\n事亲恨未立，从宦此中州。\n主人亦何问，旅客非悠悠。\n方谒明天子，清宴奉良筹。\n再取连城璧，三陟平津侯。\n不然拂衣去，归从海上鸥。\n宁随当代子，倾侧且沈浮。' },
  { title: '酬晖上人秋夜山亭有赠', author: '陈子昂', poem: '皎皎白林秋，微微翠山静。\n禅居感物变，独坐开轩屏。\n风泉夜声杂，月露宵光冷。\n多谢忘机人，尘忧未能整。' },
  { title: '酬李参军崇嗣旅馆见赠', author: '陈子昂', poem: '昨夜银河畔，星文犯遥汉。\n今朝紫气新，物色果逢真。\n言从天上落，乃是地仙人。\n白璧疑冤楚，乌裘似入秦。\n摧藏多古意，历览备艰辛。\n乐广云虽覩，夷吾风未春。\n凤歌空有问，龙性讵能驯。\n宝劒终应出，骊珠会见珍。\n未及冯公老，何惊孺子贫。\n青云傥可致，北海忆孙宾。' },
  { title: '酬晖上人夏日林泉', author: '陈子昂', poem: '闻道白云居，窈窕青莲宇。\n岩泉万丈流，树石千年古。\n林卧对轩窗，山阴满庭户。\n方释尘事劳，从君袭兰杜。' },
  { title: '同宋参军之问梦赵六赠卢陈二子之作', author: '陈子昂', poem: '晓霁望嵩丘，白云半岩足。\n氛氲涵翠微，宛如嬴台曲。\n故人昔所尚，幽琴歌断续。\n变化竟无常，人琴遂两亡。\n白云失处所，梦想暧容光。\n畴昔疑缘业，儒道两相妨。\n前期许幽报，迨此尚茫茫。\n晤言既已失，感叹情何一。\n始忆携手期，云台与峨眉。\n达兼济天下，穷独善其时。\n诸君推管乐，之子慕巢夷。\n奈何苍生望，卒为黄绶欺。\n铭鼎功未立，山林事亦微。\n抚孤一流恸，怀旧日暌违。\n卢子尚高节，终南卧松雪。\n宋侯逢圣君，骖驭游青云。\n而我独蹭蹬，语默道犹屯。\n征戍在辽阳，蹉跎草再黄。\n丹丘恨不及，白露已苍苍。\n远闻山阳赋，感涕下沾裳。' },
  { title: '送别出塞', author: '陈子昂', poem: '平生闻高义，书劒百夫雄。\n言登青云去，非此白头翁。\n胡兵屯塞下，汉骑属云中。\n君为白马将，腰佩骍角弓。\n单于不敢射，天子伫深功。\n蜀山余方隐，良会何时同。' },
  { title: '登蓟丘楼送贾兵曹入都', author: '陈子昂', poem: '东山宿昔意，北征非我心。\n孤负平生愿，感涕下沾襟。\n暮登蓟楼上，永望燕山岑。\n辽海方漫漫，胡沙飞且深。\n峨眉杳如梦，仙子曷由寻。\n击劒起叹息，白日忽西沈。\n闻君洛阳使，因子寄南音。' },
  { title: '夏日晖上人房别李参军崇嗣', author: '陈子昂', poem: '四十九变化，一十三死生。\n翕忽玄黄里，驱驰风雨情。\n是非纷妄作，宠辱坐相惊。\n至人独幽鉴，窈窕随昏明。\n咫尺山河道，轩窗日月庭。\n别离焉足问，悲乐固能幷。\n我辈何为尔，栖皇犹未平。\n金台可攀陟，宝界绝将迎。\n户牖观天地，阶基上杳冥。\n自超三界乐，安知万里征。\n中国要荒内，人寰宇宙荣。\n弦望如朝夕，宁嗟蜀道行。' },
  { title: '秋园卧病呈晖上人', author: '陈子昂', poem: '幽寂旷日遥，林园转清密。\n疲疴澹无豫，独坐泛瑶瑟。\n怀挟万古情，忧虞百年疾。\n绵绵多滞念，忽忽每如失。\n缅想赤松游，高寻白云逸。\n荣吝始都丧，幽人遂贞吉。\n图书纷满床，山水蔼盈室。\n宿昔心所尚，平生自兹毕。\n愿言谁见知，梵筵有同术。\n八月高秋晚，凉风正萧瑟。' },
  { title: '登泽州城北楼䜩', author: '陈子昂', poem: '平生倦游者，观化久无穷。\n复来登此国，临望与君同。\n坐见秦兵垒，遥闻赵将雄。\n武安君何在，长平事已空。\n且歌玄云曲，御酒舞薰风。\n勿使青衿子，嗟尔白头翁。' },
  { title: '山水粉图', author: '陈子昂', poem: '山图之白云兮，若巫山之高丘。\n纷群翠之鸿溶，又似蓬瀛海水之周流。\n信夫人之好道，爱云山以幽求。' },
  { title: '彩树歌', author: '陈子昂', poem: '嘉锦筵之珍树兮，错众彩之氛氲。\n状瑶台之微月，点巫山之朝云。\n青春兮不可逢，况蕙色之增芬。\n结芳意而谁赏，怨绝世之无闻。\n红荣碧艳坐看歇，素华流年不待君。\n故吾思昆仑之琪树，厌桃李之缤纷。' },
  { title: '春台引', author: '陈子昂', poem: '感阳春兮生碧草之油油，怀宇宙以伤远，登高台而写忧。\n迟美人兮不见，恐青岁之遂遒。\n从毕公以酣饮，寄林塘而一留。\n采芳荪于北渚，忆桂树于南州。\n何云木之美丽，而池馆之崇幽。\n星台秀士，月旦诸子。\n嘉青鸟之辰，迎火龙之始。\n挟宝书与瑶瑟，芳蕙华而兰靡。\n乃掩白苹，藉绿芷。\n酒既醉，乐未已。\n击青钟，歌渌水。\n怨青春之萎绝，赠瑶台之旖旎。\n愿一见而道意，结众芳之绸缪。\n曷余情之荡漾，瞩青云以增愁。\n怅三山之飞鹤，忆海上之白鸥。\n重曰：群仙去兮青春颓，岁华歇兮黄鸟哀。\n富贵荣乐几时兮，朱宫碧堂生青苔，白云兮归来。' },
  { title: '登幽州台歌', author: '陈子昂', poem: '前不见古人，后不见来者。\n念天地之悠悠，独怆然而涕下。' },
  { title: '喜马参军相遇醉歌', author: '陈子昂', poem: '独幽默以三月兮，深林潜居。\n时岁忽兮，孤愤遐吟。\n谁知我心，孺子孺子，其可与理分。' },
  { title: '度荆门望楚', author: '陈子昂', poem: '遥遥去巫峡，望望下章台。\n巴国山川尽，荆门烟雾开。\n城分苍野外，树断白云隈。\n今日狂歌客，谁知入楚来。' },
  { title: '晚次乐乡县', author: '陈子昂', poem: '故乡杳无际，日暮且孤征。\n川原迷旧国，道路入边城。\n野戍荒烟断，深山古木平。\n如何此时恨，噭噭夜猿鸣。' },
  { title: '同王员外雨后登开元寺南楼因酬晖上人独坐山亭有赠', author: '陈子昂', poem: '钟梵经行罢，香林坐入禅。\n岩庭交杂树，石濑泻鸣泉。\n水月心方寂，云霞思独玄。\n宁知人世里，疲病得攀缘。' },
  { title: '东征答朝臣相送', author: '陈子昂', poem: '平生白云意，疲薾愧为雄。\n君王谬殊宠，旌节此从戎。\n挼绳当系虏，单马岂邀功。\n孤劒将何托，长谣塞上风。' },
  { title: '咏主人壁上画鹤寄乔主簿崔著作', author: '陈子昂', poem: '古壁仙人画，丹青尚有文。\n独舞纷如雪，孤飞暧似云。\n自矜彩色重，宁忆故池群。\n江海联翩翼，长鸣谁复闻。' },
  { title: '居延海树闻莺同作', author: '陈子昂', poem: '边地无芳树，莺声忽听新。\n间关如有意，愁绝若怀人。\n明妃失汉宠，蔡女没胡尘。\n坐闻应落泪，况忆故园春。' },
  { title: '题李三书斋', author: '陈子昂', poem: '灼灼青春仲，悠悠白日升。\n声容何足恃，荣吝坐相矜。\n愿与金庭会，将待玉书征。\n还丹应有术，烟驾共君乘。' },
  { title: '送魏大从军', author: '陈子昂', poem: '匈奴犹未灭，魏绛复从戎。\n怅别三河道，言追六郡雄。\n雁山横代北，狐塞接云中。\n勿使燕然上，惟留汉将功。' },
  { title: '送殷大入蜀', author: '陈子昂', poem: '禺山金碧路，此地饶英灵。\n送君一为别，凄断故乡情。\n片云生极浦，斜日隐离亭。\n坐看征骑没，惟见远山青。' },
  { title: '落第西还别刘祭酒高明府', author: '陈子昂', poem: '别馆分周国，归骖入汉京。\n地连函谷塞，川接广阳城。\n望迥楼台出，途遥烟雾生。\n莫言长落羽，贫贱一交情。' },
  { title: '落第西还别魏四懔', author: '陈子昂', poem: '转蓬方不定，落羽自惊弦。\n山水一为别，欢娱复几年。\n离亭暗风雨，征路入云烟。\n还因北山迳，归守东陂田。' },
  { title: '送客', author: '陈子昂', poem: '故人洞庭去，杨柳春风生。\n相送河洲晚，苍茫别思盈。\n白苹已堪把，绿芷复含荣。\n江南多桂树，归客赠生平。' },
  { title: '春夜别友人二首 一', author: '陈子昂', poem: '银烛吐青烟，金樽对绮筵。\n离堂思琴瑟，别路遶山川。\n明月隐高树，长河没晓天。\n悠悠洛阳道，此会在何年。' },
  { title: '春夜别友人二首 二', author: '陈子昂', poem: '紫塞白云断，青春明月初。\n对此芳樽夜，离忧怅有余。\n清冷花露满，滴沥檐宇虚。\n怀君欲何赠，愿上大臣书。' },
  { title: '遂州南江别乡曲故人', author: '陈子昂', poem: '楚江复为客，征棹方悠悠。\n故人悯追送，置酒此南洲。\n平生亦何恨，夙昔在林丘。\n违此乡山别，长谣去国愁。' },
  { title: '送东莱王学士无竞', author: '陈子昂', poem: '宝劒千金买，平生未许人。\n怀君万里别，持赠结交亲。\n孤松宜晚岁，众木爱芳春。\n已矣将何道，无令白首新。' },
  { title: '送梁李二明府', author: '陈子昂', poem: '负书犹在汉，怀策未闻秦。\n复此穷秋日，芳樽别故人。\n黄金装屡尽，白首契逾新。\n空羡双凫舄，俱飞向玉轮。' },
  { title: '送魏兵曹使嶲州得登字', author: '陈子昂', poem: '阳山淫雾雨，之子慎攀登。\n羗笮多珍宝，人言有爱憎。\n欲酬明主惠，当尽使臣能。\n勿以王阳道，迢递畏崚嶒。' },
  { title: '送著作佐郎崔融等从梁王东征', author: '陈子昂', poem: '金天方肃杀，白露始专征。\n王师非乐战，之子慎佳兵。\n海气侵南部，边风扫北平。\n莫卖卢龙塞，归邀麟阁名。' },
  { title: '春晦饯陶七于江南同用风字', author: '陈子昂', poem: '黄鹤烟云去，青江琴酒同。\n离帆方楚越，沟水复西东。\n芙蓉生夏浦，杨柳送春风。\n明日相思处，应对菊花丛。' },
  { title: '喜遇冀侍御珪崔司议泰之二使', author: '陈子昂', poem: '谢病南山下，幽卧不知春。\n使星入东井，云是故交亲。\n惠风吹宝瑟，微月忆清真。\n凭轩一留醉，江海寄情人。' },
  { title: '登蓟城西北楼送崔著作融入都', author: '陈子昂', poem: '蓟楼望燕国，负劒喜兹登。\n清规子方奏，单戟我无能。\n仲冬边风急，云汉复霜棱。\n慷慨竟何道，西南恨失朋。' },
  { title: '月夜有怀', author: '陈子昂', poem: '美人挟赵瑟，微月在西轩。\n寂寞夜何久，殷勤玉指繁。\n清光委衾枕，遥思属湘沅。\n空帘隔星汉，犹梦感精魂。' },
  { title: '夏日游晖上人房', author: '陈子昂', poem: '山水开精舍，琴歌列梵筵。\n人疑白楼赏，地似竹林禅。\n对户池光乱，交轩岩翠连。\n色空今已寂，乘月弄澄泉。' },
  { title: '春日登金华观', author: '陈子昂', poem: '白玉仙台古，丹丘别望遥。\n山川乱云日，楼榭入烟霄。\n鹤舞千年树，虹飞百尺桥。\n还疑赤松子，天路坐相邀。' },
  { title: '群公集毕氏林亭', author: '陈子昂', poem: '金门有遗世，鼎实恣和邦。\n默语谁能识，琴樽寄北窗。\n子牟恋魏阙，渔父爱沧江。\n良时信同此，岁晚迹难双。' },
  { title: '宴胡楚真禁所', author: '陈子昂', poem: '人生固有命，天道信无言。\n青绳一相点，白璧遂成冤。\n请室闲逾邃，幽庭春未暄。\n寄谢韩安国，何惊狱吏尊。' },
  { title: '魏氏园林人赋一物得秋亭萱草', author: '陈子昂', poem: '昔时幽径里，荣耀杂春丛。\n今来玉墀上，销歇畏秋风。\n细叶犹含绿，鲜花未吐红。\n忘忧谁见赏，空此北堂中。' },
  { title: '晦日宴高氏林亭', author: '陈子昂', poem: '寻春游上路，追宴入山家。\n主第簪缨满，皇州景望华。\n玉池初吐溜，珠树始开花。\n欢娱方未极，林阁散余霞。' },
  { title: '晦日重宴高氏林亭', author: '陈子昂', poem: '公子好追随，爱客不知疲。\n象筵开玉馔，翠羽饰金巵。\n此时高宴所，讵减习家池。' },
  { title: '上元夜效小庾体', author: '陈子昂', poem: '三五月华新，遨游逐上春。\n相邀洛城曲，追宴小平津。\n楼上看珠妓，车中见玉人。\n芳宵殊未极，随意守灯轮。' },
  { title: '洛城观酺应制', author: '陈子昂', poem: '圣人信恭己，天命允昭回。\n苍极神功被，青云秘箓开。\n垂衣受金册，张乐宴瑶台。\n云凤休征满，鱼龙杂戏来。\n崇恩逾五日，惠泽畅三才。\n玉帛群臣醉，徽章缛礼该。\n方覩升中禅，言观拜洛回。\n微臣固多幸，敢上万年杯。' },
  { title: '奉和皇帝上礼抚事述怀应制', author: '陈子昂', poem: '大君忘自我，应运居紫宸。\n揖让期明辟，讴歌且顺人。\n轩宫帝图盛，皇极礼容申。\n南面朝万国，东堂会百神。\n云陛旗常满，天庭玉帛陈。\n钟石和睿思，雷雨被深仁。\n承平信娱乐，王业本艰辛。\n愿罢瑶池宴，来观农扈春。\n卑宫昭夏德，尊老睦尧亲。\n微臣敢拜手，歌舞颂维新。' },
  { title: '酬田逸人游岩见寻不遇题隐居里壁', author: '陈子昂', poem: '游人献书去，薄暮返灵台。\n传道寻仙友，青囊卖卜来。\n闻莺忽相访，题凤久裴回。\n石髓空盈握，金经秘不开。\n还疑缝掖子，复似洛阳才。' },
  { title: '白帝城怀古', author: '陈子昂', poem: '日落沧江晚，停桡问土风。\n城临巴子国，台没汉王宫。\n荒服任周甸，深山尚禹功。\n岩悬青壁断，地险碧流通。\n古木生云际，孤帆出雾中。\n川途去无限，客思坐何穷。' },
  { title: '岘山怀古', author: '陈子昂', poem: '秣马临荒甸，登高览旧都。\n犹悲堕泪碣，尚想卧龙图。\n城邑遥分楚，山川半入吴。\n丘陵徒自出，贤圣几凋枯。\n野树苍烟断，津楼晚气孤。\n谁知万里客，怀古正踌蹰。' },
  { title: '宿空舲峡青树邨浦', author: '陈子昂', poem: '的的明月水，啾啾寒夜猿。\n客思浩方乱，洲浦寂无喧。\n忆作千金子，宁知九逝魂。\n虚闻事朱阙，结绶骛华轩。\n委别高堂爱，窥觎明主恩。\n今成转蓬去，叹息复何言。' },
  { title: '宿襄河驿浦', author: '陈子昂', poem: '沿流辞北渚，结缆宿南洲。\n合岸昏初夕，廻塘暗不流。\n卧闻塞鸿断，坐听峡猿愁。\n沙浦明如月，汀葭晦若秋。\n不及能鸣雁，徒思海上鸥。\n天河殊未晓，沧海信悠悠。' },
  { title: '赠严仓曹乞推命录', author: '陈子昂', poem: '少学纵横术，游楚复游燕。\n栖遑长委命，富贵未知天。\n闻道沈冥客，青囊有秘篇。\n九宫探万象，三算极重玄。\n愿奉唐生诀，将知跃马年。\n非同墨翟问，空滞杀龙川。' },
  { title: '和陆明府赠将军重出塞', author: '陈子昂', poem: '忽闻天上将，关塞重横行。\n始返楼兰国，还向朔方城。\n黄金装战马，白羽集神兵。\n星月开天阵，山川列地营。\n晚风吹画角，春色耀飞旌。\n宁知班定远，犹是一书生。' },
  { title: '江上暂别萧四刘三旋欣接遇', author: '陈子昂', poem: '昨夜沧江别，言乖天汉游。\n宁期此相遇，尚接武陵洲。\n结绶还逢育，衔杯且对刘。\n波潭一弥弥，临望几悠悠。\n山水丹青杂，烟云紫翠浮。\n终愧神仙友，来接野人舟。' },
  { title: '秋日遇荆州府崔兵曹使宴', author: '陈子昂', poem: '𬨎轩凤皇使，林薮鹖鸡冠。\n江湖一相许，云雾坐交欢。\n兴尽崔亭伯，言忘释道安。\n林光稍欲暮，岁物已将阑。\n古树苍烟断，虚亭白露寒。\n瑶琴山水曲，今日为君弹。' },
  { title: '卧病家园', author: '陈子昂', poem: '世上无名子，人间岁月赊。\n纵横策已弃，寂寞道为家。\n卧病谁能问，闲居空物华。\n犹忆灵台友，栖真隐太霞。\n还丹奔日御，却老饵云芽。\n宁知白社客，不厌青门瓜。' },
  { title: '于长史山池三日曲水宴', author: '陈子昂', poem: '摘兰藉芳月，祓宴坐廻汀。\n泛滟清流满，葳蕤白芷生。\n金弦挥赵瑟，玉指弄秦筝。\n岩榭风光媚，郊园春树平。\n烟花飞御道，罗绮照昆明。\n日落红尘合，车马乱纵横。' },
  { title: '合州津口别舍弟至东阳峡步趂不及眷然有忆作以示之', author: '陈子昂', poem: '江潭共为客，洲浦独迷津。\n思积芳庭树，心断白眉人。\n同衾成楚越，别岛类胡秦。\n林岸随天转，云峰逐望新。\n遥遥终不见，默默坐含嚬。\n念别疑三月，经游未一旬。\n孤舟多逸兴，谁共尔为邻。' },
  { title: '万州晓发放舟乘涨还寄蜀中亲朋', author: '陈子昂', poem: '空蒙岩雨霁，烂熳晓云归。\n啸旅乘明发，奔桡骛断矶。\n苍茫林岫转，络绎涨涛飞。\n远岸孤烟出，遥峰曙日微。\n前瞻未能眴，坐望已相依。\n曲直多今古，经过失是非。\n还期方浩浩，征思日𬴂𬴂。\n寄谢千金子，江海事多违。' },
  { title: '入峭峡安居谿伐木谿源幽邃林岭相映有奇致焉', author: '陈子昂', poem: '肃徒歌伐木，骛檝漾轻舟。\n靡迤随廻水，潺湲溯浅流。\n烟沙分两岸，露岛夹双洲。\n古树连云密，交峰入浪浮。\n岩潭相映媚，谿谷屡环周。\n路迥光逾逼，山深兴转幽。\n麕鼯寒思晚，猿鸟暮声秋。\n誓息兰台策，将从桂树游。\n因书谢亲爱，千岁觅蓬丘。' },
  { title: '入东阳峡与李明府舟前后不相及', author: '陈子昂', poem: '东岩初解缆，南浦遂离群。\n出没同洲岛，沿洄异渚𣸣。\n风烟犹可望，歌笑浩难闻。\n路转青山合，峰廻白日曛。\n奔涛上漫漫，积水下沄沄。\n倏忽犹疑及，差池复两分。\n离离间远树，蔼蔼没遥氛。\n地上巴陵道，星连牛斗文。\n孤狖啼寒月，哀鸿呌断云。\n仙舟不可见，摇思坐氛氲。' },
  { title: '同旻上人伤寿安傅少府', author: '陈子昂', poem: '生涯良浩浩，天命固谆谆。\n闻道神仙尉，怀德遂为邻。\n畴昔逢尧日，衣冠仕汉辰。\n交游纷若凤，词翰宛如麟。\n太息劳黄绶，长思谒紫宸。\n金兰徒有契，玉树已埋尘。\n把臂虽无托，平生固亦亲。\n援琴一流涕，旧馆几沾巾。\n杳杳泉中夜，悠悠世上春。\n幽明长隔此，歌哭为何人。' },
  { title: '南山家园林木交映盛夏五月幽然清凉独坐思远率成十韵', author: '陈子昂', poem: '寂寥守寒巷，幽独卧空林。\n松竹生虚白，阶庭横古今。\n郁蒸炎夏晚，栋宇閟清阴。\n轩窗交紫霭，檐户对苍岑。\n凤蕴仙人箓，鸾歌素女琴。\n忘机委人代，闭牖察天心。\n蛱蝶怜红药，蜻蜓爱碧浔。\n坐观万象化，方见百年侵。\n扰扰将何息，青青长苦吟。\n愿随白云驾，龙鹤相招寻。' },
  { title: '还至张掖古城闻东军告捷赠韦五虚己', author: '陈子昂', poem: '孟秋首归路，仲月旅边亭。\n闻道兰山战，相邀在井陉。\n屡鬬关月满，三捷虏云平。\n汉军追北地，胡骑走南庭。\n君为幕中士，畴昔好言兵。\n白虎锋应出，青龙阵几成。\n披图见丞相，按节入咸京。\n宁知玉门道，翻作陇西行。\n北海朱旄落，东归白露生。\n纵横未得意，寂寞寡相迎。\n负劒空叹息，苍茫登古城。' },
  { title: '题祀山烽树赠乔十二侍御', author: '陈子昂', poem: '汉庭荣巧宦，云阁薄边功。\n可怜骢马使，白首为谁雄。' },
  { title: '初入峡苦风寄故乡亲友', author: '陈子昂', poem: '故乡今日友，欢会坐应同。\n宁知巴峡路，辛苦石尤风。' },
  { title: '题田洗马游岩桔槔', author: '陈子昂', poem: '望苑长为客，商山遂不归。\n谁怜北陵井，未息汉阴机。' },
  { title: '古意题徐令壁', author: '陈子昂', poem: '白云苍梧来，氛氲万里色。\n闻君太平世，栖泊灵台侧。' },
  { title: '赠别冀侍御崔司议', author: '陈子昂', poem: '有道君匡国，无闷余在林。\n白云峨眉上，岁晚来相寻。' },
  { title: '三月三日宴王明府山亭', author: '陈子昂', poem: '暮春嘉月，上巳芳辰。\n群公禊饮，于洛之滨。\n奕奕车骑，粲粲都人。\n连帷竞野，袨服缛津。\n青郊树密，翠渚萍新。\n今我不乐，含意□申。' },
  { title: '唐封泰山乐章 豫和六首 一', author: '张说', poem: '挹泰坛，紫泰清。\n受天命，报天成。\n竦皇心，荐乐声。\n志上达，歌下迎。' },
  { title: '唐封泰山乐章 豫和六首 二', author: '张说', poem: '亿上帝，临下庭。\n骑日月，陪列星。\n嘉视信，大糦声。\n澹神心，醉皇灵。' },
  { title: '唐封泰山乐章 豫和六首 三', author: '张说', poem: '相百辟，贡八荒。\n九歌叙，万舞翔。\n肃振振，铿皇皇。\n帝欣欣，福穰穰。' },
  { title: '唐封泰山乐章 豫和六首 四', author: '张说', poem: '高在上，道光明。\n物资始，德难名。\n承眷命，牧苍生。\n寰宇谧，泰阶平。' },
  { title: '唐封泰山乐章 豫和六首 五', author: '张说', poem: '天道无亲，至诚与邻。\n山川遍礼，宫征惟新。\n玉帛非盛，聪明会真。\n正斯一德，通乎百神。' },
  { title: '唐封泰山乐章 豫和六首 六', author: '张说', poem: '享帝享亲，维孝维圣。\n缉熙懿德，敷扬成命。\n华夷志同，笙镛礼盛。\n明灵降止，感此诚敬。' },
  { title: '唐封泰山乐章 太和', author: '张说', poem: '孝敬中发，和容外彰。\n腾华照宇，如升太阳。\n贞璧就奠，玄灵垂光。\n礼乐具举，济济洋洋。' },
  { title: '唐封泰山乐章 肃和', author: '张说', poem: '奠祖配天，承天享帝。\n百灵咸秩，四海来祭。\n植我苍璧，布我玄制。\n华日裴回，神烟容裔。' },
  { title: '唐封泰山乐章 雍和', author: '张说', poem: '俎豆有馥，粢盛絜丰。\n亦有和羹，既戒既平。\n鼓钟管磬，肃唱和鸣。\n皇皇我祖，来我思成。' },
  { title: '唐封泰山乐章 寿和', author: '张说', poem: '烝烝我后，享献惟寅。\n躬酌郁鬯，跪奠明神。\n孝莫孝乎，配上帝亲。\n敬莫敬乎，教天下臣。' },
  { title: '唐封泰山乐章 舒和', author: '张说', poem: '六钟翕协六变成，八佾徜徉八风生。\n乐九[韶]兮[人神]感，美七德兮天地清。' },
  { title: '唐封泰山乐章 凯和', author: '张说', poem: '烈祖顺三灵，文宗威四海。\n黄钺诛群盗，朱旗扫多罪。\n戢兵天下安，约法人心改。\n大哉干羽意，常见风云在。' },
  { title: '唐封泰山乐章 豫和', author: '张说', poem: '礼乐终，[烟]燎上。\n怀灵惠，结皇想。\n归风疾，回风爽。\n百[福]来，众神往。' },
  { title: '唐享太庙乐章 永和三首 一', author: '张说', poem: '肃九室，谐八音。\n歌皇慕，动神心。\n礼宿设，乐妙寻。\n声明备，祼奠临。' },
  { title: '唐享太庙乐章 永和三首 二', author: '张说', poem: '律迓气，音入玄。\n依玉几，御黼筵。\n聆忾息，僾周旋。\n九韶徧，百福传。' },
  { title: '唐享太庙乐章 永和三首 三', author: '张说', poem: '信工祝，永颂声。\n来祖考，听和平。\n相百辟，贡九瀛。\n神休委，帝孝成。' },
  { title: '唐享太庙乐章 太和', author: '张说', poem: '时文圣后，清庙肃邕。\n致诚勤荐，在貌思恭。\n玉节肆夏，金锵五钟。\n绳绳云步，穆穆天容。' },
  { title: '唐享太庙乐章 肃和', author: '张说', poem: '天子享孝，工歌溥将。\n射祼郁鬯，乃焚膋芗。\n臭以达旨，声以求阳。\n奉时烝尝，永代不忘。' },
  { title: '唐享太庙乐章 雍和二首 一', author: '张说', poem: '在涤嘉豢，丽碑敬牲。\n角握之牝，色纯之骍。\n火传阳燧，水溉阴精。\n太公胖俎，傅说和羹。' },
  { title: '唐享太庙乐章 雍和二首 二', author: '张说', poem: '俎豆有馥，齐盛絜丰。\n亦有和羹，既戒既平。\n鼓钟管磬，肃唱和鸣。\n皇皇后祖，来我思成。' },
  { title: '唐享太庙乐章 文舞', author: '张说', poem: '圣谟九德，真言五千。\n庆集昌胄，符开帝先。\n高文杖钺，克配彼天。\n三宗握镜，六合涣燃。\n帝其承祀，率礼罔愆。\n图书雾出，日月清悬。\n舞形德类，咏谂功传。\n黄龙蜿蟺，彩云蹁跹。\n五行气顺，八佾风宣。\n介此百禄，于皇万年。' },
  { title: '唐享太庙乐章 光大舞', author: '张说', poem: '肃肃艺祖，滔滔濬源。\n有雄玉劒，作镇金门。\n玄王贻绪，后稷谋孙。\n肇禋九庙，四海来尊。' },
  { title: '唐享太庙乐章 长发舞', author: '张说', poem: '具礼崇德，备乐承风。\n魏推幢主，周赠司空。\n不行而至，无成有终。\n神兴王业，天归帝功。' },
  { title: '唐享太庙乐章 大政舞', author: '张说', poem: '于赫元命，权舆帝文。\n天齐八柱，地半三分。\n宗庙观德，笙镛乐勋。\n封唐之兆，成天下君。' },
  { title: '唐享太庙乐章 大成舞', author: '张说', poem: '帝舞季历，龙圣生昌。\n后歌有𫊸，胎炎孕黄。\n天地合德，日月齐光。\n肃雍孝享，祚我万方。' },
  { title: '唐享太庙乐章 大明舞', author: '张说', poem: '赤精乱德，四海困穷。\n黄旗举义，三灵会同。\n早望春雨，云披大风。\n溥天来祭，高祖之功。' },
  { title: '唐享太庙乐章 崇德舞', author: '张说', poem: '皇合一德，朝宗百神。\n削平天地，大拯生人。\n上帝配食，单于入臣。\n戎歌陈武，晔晔震震。' },
  { title: '唐享太庙乐章 钧天舞', author: '张说', poem: '高皇迈道，端拱无为。\n化怀獯鬻，兵[戢]句骊。\n礼尊封禅，乐盘来仪。\n合位娲后，同称伏羲。' },
  { title: '唐享太庙乐章 大和舞', author: '张说', poem: '退居江水，郁起丹陵。\n礼物还旧，朝章中兴。\n龙图友及，骏命恭膺。\n鸣球香瓒，大糦是承。' },
  { title: '唐享太庙乐章 景云舞', author: '张说', poem: '景云霏烂，告我帝符。\n噫帝冲德，与天为徒。\n笙镛遥远，俎豆虚无。\n春秋孝献，回复此都。' },
  { title: '唐享太庙乐章 福和', author: '张说', poem: '备礼用乐，崇亲致尊。\n诚通慈降，敬彻爱存。\n献怀称寿，啐感承恩。\n皇帝孝德，子孙千亿。\n大包天域，长亘不极。' },
  { title: '唐享太庙乐章 舒和', author: '张说', poem: '六钟翕协六变成，八佾徜徉八风生。\n乐九韶兮人神感，美七德兮天地清。' },
  { title: '唐享太庙乐章 凯安三首 一', author: '张说', poem: '瑟彼瑶爵，亚维上公。\n室如屏气，门不容躬。\n礼殷其本，乐执其中。\n圣皇永慕，天地幽通。' },
  { title: '唐享太庙乐章 凯安三首 二', author: '张说', poem: '礼匝三献，乐徧九成。\n降循轩陛，仰欷皇情。\n福与仁合，德因孝明。\n百年神畏，四海风行。' },
  { title: '唐享太庙乐章 凯安三首 三', author: '张说', poem: '总总干戚，填填鼓钟。\n奋扬增气，坐作为容。\n离若鸷鸟，合如战龙。\n万方观德，肃肃邕邕。' },
  { title: '唐享太庙乐章 登歌', author: '张说', poem: '止笙磬，撤豆笾。\n廓无响，窅入玄。\n主在室，神在天。\n情余慕，礼罔愆。\n喜黍稷，屡丰年。' },
  { title: '唐享太庙乐章 永和', author: '张说', poem: '眇嘉乐，授灵爽。\n感若来，思如往。\n休气散，回风上。\n返寂寞，还惚恍。\n怀灵驾，结空想。' },
  { title: '奉和圣制赐诸州刺史应制以题坐右', author: '张说', poem: '文明遍禹迹，鳏寡达尧心。\n正在亲人守，能令王泽深。\n朝廷多秀士，镕炼比精金。\n犀节同分命，熊轩各外临。\n圣主赋新诗，穆若听薰琴。\n先言教为本，次言则是钦。\n三时农不夺，午夜犬无侵。\n愿使天宇内，品物遂浮沈。\n寄情群飞鹤，千里一扬音。\n共蹑华胥梦，龚黄安足寻。' },
  { title: '奉和圣制送宇文融安辑户口应制', author: '张说', poem: '至德临天下，劳情遍九围。\n念兹人去本，蓬转将何依。\n外避征戍数，内伤亲党稀。\n嗟不逢明盛，胡能照隐微。\n柏台简行李，兰殿锡朝衣。\n别曲动秋风，恩令生春辉。\n使出四海安，诏下万心归。\n怍非夔龙佐，徒歌鸿雁飞。' },
  { title: '奉和圣制过晋阳宫应制', author: '张说', poem: '太原俗尚武，高皇初奋庸。\n星轩三晋躔，土乐二尧封。\n北风遂举鹏，西河亦上龙。\n至德起王业，继明赖人雍。\n六合启昌期，再兴广圣踪。\n传呼大驾来，文物如云从。\n连营火百里，纵观人千重。\n翠华渡汾水，白日临崒峰。\n枌榆恩赏洽，桑梓旧情恭。\n往运感不追，清时惜难逢。\n诗发尊祖心，颂刊盛德容。\n愿君及春事，廻舆绥万邦。' },
  { title: '奉和圣制行次成臯应制', author: '张说', poem: '夏氏阶隋乱，自言河朔雄。\n王师进谷水，兵气临山东。\n前扫成臯阵，却下洛阳宫。\n义合帝图起，威加天宇同。\n轩台百年外，虞典一巡中。\n战龙思王业，倚马赋神功。' },
  { title: '奉和圣制温汤对雪应制', author: '张说', poem: '瑞雪带寒风，寒风入阴琯。\n阴琯方凝闭，寒风复凄断。\n宫似瑶林匝，庭如月华满。\n正赓挟纩词，非近温汤暖。' },
  { title: '奉和圣制义成校猎喜雪应制', author: '张说', poem: '文教资武功，郊畋阅邦政。\n不知仁育久，徒看禽兽盛。\n夜霰氛埃灭，朝日山川净。\n绰仗飞走繁，抨弦筋角劲。\n帝射参神道，龙驰合人性。\n五豝连一发，百中皆先命。\n勇爵均万夫，雄图罗七圣。\n星为吉符老，雪作丰年庆。\n喜听行猎诗，威神入军令。' },
  { title: '清明日诏宴宁王山池赋得飞字', author: '张说', poem: '今日清明宴，佳境惜芳菲。\n摇扬花杂下，娇啭鸎乱飞。\n绿渚传歌榜，红桥度舞旗。\n和风偏应律，细雨不沾衣。\n承恩如改火，春去春来归。' },
  { title: '四月十三日诏宴宁王亭子赋得好字', author: '张说', poem: '何许承恩宴，山亭风日好。\n绿嫩鸣鹤洲，阴秾鬬鸡道。\n果思夏来茂，花嫌春去早。\n行乐无限时，皇情及芳草。' },
  { title: '药园宴武辂沙将军赋得洛字', author: '张说', poem: '东第乘余兴，南园宴清洛。\n文学引邹枚，歌钟陈衞霍。\n风高大夫树，露下将军药。\n待闻出塞还，丹青上麟阁。' },
  { title: '修书院学士奉敕宴梁王宅赋得树字', author: '张说', poem: '虎殿成鸿业，猿岩题凤赋。\n既荷大君恩，还蒙小山遇。\n秋吹迎弦管，凉云生竹树。\n共惜朱邸欢，无辞洛城暮。' },
  { title: '夕宴房主簿舍', author: '张说', poem: '岁晏关雍空，风急河谓冰。\n薄游羁物役，微尚惬远凭。\n旅馆月宿永，闭扃云思兴。\n伊人美修夜，朋酒惠来称。\n交谈既清雅，琴吹亦凄凝。\n不逢君蹇涸，幽意长郁蒸。' },
  { title: '行从方秀川与刘评事文同宿', author: '张说', poem: '方秀美盘游，频年降天罕。\n水共伊川接，山将阙门断。\n捧日照恩华，攀云引疲散。\n野宿霜入帐，孤衾寒不暖。\n静闻宫漏疎，卧视庭月满。\n开炉命温酎，中夜发清管。\n风送关山长，气遒星岁短。\n寓言情思惬，适兴真意坦。\n寰中病羁挂，方外嫌纵诞。\n愿君乐盛时，无嗟带𬙋缓。' },
  { title: '送郭大夫元振再使吐蕃', author: '张说', poem: '犬戎废东献，汉使驰西极。\n长策问酋渠，猜阻自夷殛。\n容髪徂边岁，旌裘敝海色。\n五年一见家，妻子不相识。\n武库兵犹动，金方事未息。\n远图待才智，苦节输筋力。\n脱刀赠分手，书带加餐食。\n知君万里侯，立功在异域。' },
  { title: '送李侍郎逈秀薛长史季昶同赋得水字', author: '张说', poem: '汉郡接胡庭，幽幷对烽垒。\n旌旗按部曲，文武惟卿士。\n薛公善筹划，李相威边鄙。\n中冀分两河，长城各万里。\n藉马黄花塞，搜兵白狼水。\n胜敌在安人，为君汗青史。' },
  { title: '别平一师', author: '张说', poem: '王子不事俗，高驾眇难追。\n茅土非屑盼，倾城无乐资。\n宴坐深林中，三世同一时。\n皎皎独往心，不为尘网欺。\n朅来已复去，今去何来思。\n廻首谢同行，勤会安请期。' },
  { title: '送王光庭', author: '张说', poem: '同居洛阳陌，经日懒相求。\n及尔江湖去，言别怅悠悠。\n楚云眇羁翼，海月倦行舟。\n爱而不可见，徒嗟芳岁流。' },
  { title: '新都南亭送郭元振卢崇道', author: '张说', poem: '竹径女萝蹊，莲洲文石隄。\n静深人俗断，寻玩往还迷。\n碧潭秀初月，素林惊夕栖。\n褰幌纳蟾影，理琴听猿啼。\n佳辰改宿昔，胜寄坐暌携。\n长怀赏心爱，如玉复如珪。' },
  { title: '赠崔公', author: '张说', poem: '我闻西汉日，四老南山幽。\n长歌紫芝秀，高卧白云浮。\n朝野光尘绝，榛芜年貌秋。\n一朝驱驷马，连辔入龙楼。\n昔遯高皇去，今从太子游。\n行藏惟圣节，福祸在人谋。\n卒能匡惠帝，岂不赖留侯。\n事随年代远，名与图籍留。\n平生钦淳德，慷慨景前修。\n蜯蛤伺阴兔，蛟龙望斗牛。\n无嗟异飞伏，同气幸相求。' },
  { title: '赠赵公', author: '张说', poem: '湘东股肱守，心与帝乡期。\n舟楫中途蹇，风波复来思。\n嘉我常联翼，金貂侍玉墀。\n迹参前马圣，名缀鬻熊师。\n寒暑一何速，山川远间之。\n宁知洞庭上，独得平生时。\n精意微绝简，从权讨妙棋。\n林壑为予请，纷霭发华滋。\n流赏忽已散，惊帆杳难追。\n送君在南浦，侘傺投此词。' },
  { title: '赠赵侍御', author: '张说', poem: '禄放迹异端，偏荒事同蹇。\n苟忘风波累，俱会云壑践。\n险式压西湖，侨庐对南岘。\n夜楼江月入，朝幌山云卷。\n山势远涛连，江途斜汉转。\n坐啸予多暇，行吟子独善。\n并辔躧郊郭，方舟玩游演。\n虚声万籁分，水色千里辨。\n不知岸阴谢，再见春露泫。\n绿壤发欣颜，华年助虫篆。\n上世时难接，古人情可选。\n泊渚烦为媒，多才怨成褊。\n长沙𫛳作赋，任道可知浅。\n请从三已心，荣辱两都遣。' },
  { title: '答李伯鱼桐竹', author: '张说', poem: '结庐桐竹下，室迩人相深。\n接垣分竹径，隔户共桐阴。\n落花朝满岸，明月夜披林。\n竹有龙鸣管，桐留凤舞琴。\n奇声与高节，非吾谁赏心。' },
  { title: '寄姚司马', author: '张说', poem: '共君春种瓜，本期清夏暑。\n瓜成人已去，失望将谁语。\n裛露摘香园，感味怀心许。\n偶逢西风便，因之寄鄂渚。' },
  { title: '代书答姜七崔九', author: '张说', poem: '婀娜金闺树，离披野田草。\n虽殊两地荣，幸共三春好。\n花殊鸟飞处，叶镂虫行道。\n真心独感人，惆怅令人老。' },
  { title: '代书寄吉十一', author: '张说', poem: '一雁雪上飞，值我衡阳道。\n口衔离别字，远寄当归草。\n目想春来迟，心惊寒去早。\n忆乡乘羽翮，慕侣盈怀抱。\n零落答故人，将随江树老。' },
  { title: '代书寄薛四', author: '张说', poem: '孤雁东飞来，寄我纹与素。\n纹足经三象，素当综群务。\n远见故人心，一言重千金。\n答之彩毛翰，继以瑶华音。\n岁寒众木改，松柏心常在。' },
  { title: '过蜀道山', author: '张说', poem: '我行春三月，山中百花开。\n披林入峭蒨，攀磴陟崔嵬。\n白云半峰起，清江出峡来。\n谁知高深意，缅邈心幽哉。' },
  { title: '蜀路二首 一', author: '张说', poem: '云埃夜澄廓，山日晓晴鲜。\n叶落苍江岸，鸿飞白露天。\n磷磷含水石，幂幂覆林烟。\n客心久无绪，秋风殊未然。' },
  { title: '蜀路二首 二', author: '张说', poem: '徭蜀时未改，别家乡念盈。\n忆昨出门日，春风发鲜荣。\n及兹旋辕地，秋风满路生。\n昏晓思魏阙，梦寐还秦京。\n秦京开朱第，魏阙垂紫缨。\n幽独玄虚阁，不闻人马声。\n艺业为君重，名位为君轻。\n玉琴知调苦，宝镜对胆清。\n鹰饥常啄腥，凤饥亦待琼。\n于君自有属，物外岂能轻。' },
  { title: '再使蜀道', author: '张说', poem: '眇眇葭萌道，苍苍褒斜谷。\n烟壑争晦深，云山共重复。\n古来风尘子，同眩望乡目。\n芸阁有儒生，轺车倦驰逐。\n青春客岷岭，白露摇江服。\n岁月镇羁孤，山川俄反复。\n鱼游恋深水，鸟迁恋乔木。\n如何别亲爱，坐去文章国。\n蟋蟀鸣户庭，蟏蛸网琴筑。' },
  { title: '江路忆郡', author: '张说', poem: '雾敛江早明，星翻汉将没。\n卧闻峡猿响，起视榜人发。\n倚棹攀岸筿，凭船弄波月。\n水宿厌洲渚，晨光屡挥忽。\n林泽来不穷，烟波去无歇。\n结思笙竽里，摇情游侠窟。\n年貌不暂留，欢愉及玄髪。\n云涓恋山海，禽马怀燕越。\n自非行役人，安知慕城阙。' },
  { title: '过汉南城叹古坟', author: '张说', poem: '旧国多陵墓，荒凉无岁年。\n汹涌蔽平冈，汩若波涛连。\n上世千金子，潜卧九重泉。\n松柏剪无余，碑记灭罔传。\n葬于不毛地，咸谓楚先贤。\n事尽情可识，使人心怅然。' },
  { title: '至尉氏', author: '张说', poem: '夕次阮公台，啸歌临爽垲。\n高名安足赖，故物今皆改。\n吾兄昔兹邑，遗爱称贤宰。\n桑中雉未飞，屋上乌犹在。\n途逢旧甿吏，城有同僚采。\n望尘远见迎，拂馆来欣待。\n慈惠留千室，友于存四海。\n始知鲁衞间，优劣相悬倍。' },
  { title: '襄州景空寺题融上人兰若', author: '张说', poem: '高名出汉阴，禅阁跨香岑。\n众山既围绕，长川复回临。\n云峰晓灵变，风木夜虚吟。\n碧湫龙池满，苍松虎径深。\n旧知青岩意，偏入杳冥心。\n何由侣飞锡，从此脱朝簪。' },
  { title: '巡边在河北作', author: '张说', poem: '抚劒空余勇，弯弧遂无力。\n老去事如何，据鞍长叹息。\n故交索将尽，后进稀相识。\n独怜半死心，尚有寒松直。' },
  { title: '入海二首 一', author: '张说', poem: '乘桴入南海，海旷不可临。\n茫茫失方面，混混如凝阴。\n云山相出没，天地互浮沈。\n万里无涯际，云何测广深。\n潮波自盈缩，安得会虚心。' },
  { title: '入海二首 二', author: '张说', poem: '海上三神山，逍遥集众仙。\n灵心岂不同，变化无常全。\n龙伯如人类，一钓两鳌连。\n金台此沦没，玉真时播迁。\n问子劳何事，江上泣经年。\n隰中生红草，所美非美然。' },
  { title: '相州山池作', author: '张说', poem: '尝怀谢公咏，山水陶嘉月。\n及此年事衰，徒看众花发。\n观鱼乐何在，听鸟情都歇。\n星汉流不停，蓬莱去难越。\n邺中秋麦秀，淇上春云没。\n日见尘物空，如何静心阙。' },
  { title: '岳州作', author: '张说', poem: '夜梦云阙间，从容簪履列。\n朝游洞庭上，缅望京华绝。\n潦收江未清，火退山更热。\n重欷视欲醉，懵满气如噎。\n器留鱼鼈腥，衣点蚊虻血。\n髪白思益壮，心玄用弥拙。\n冠劒日苔藓，琴书坐废撤。\n唯有报恩字，刻意长不灭。' },
  { title: '岳州行郡竹篱', author: '张说', poem: '山郡不沟郭，荒居无翳壅。\n爱人忠主利，善守闭为勇。\n苟非小勤瘁，安得期逸宠。\n版筑恐土疎，襄城嫌役重。\n藩栅聊可固，筠篁近易奉。\n差池截浦沙，缭绕缘隈垅。\n矗似长云亘，森如高戟耸。\n预绝豺狼忧，知免牛羊恐。\n闾里宽矫步，榛丛恣踏踵。\n始果游处心，终日成闲拱。' },
  { title: '游洞庭湖湘', author: '张说', poem: '缅邈洞庭岫，葱蒙水雾色。\n宛在太湖中，可望不可即。\n剖竹守穷渚，开门对奇域。\n城池自絷笼，缨绶为徽𬙊。\n靡日不思往，经时始愿克。\n飞棹越溟波，维舟恣攀陟。\n䆗窱入云步，崎岖倚松息。\n岩坛有鹤过，壁字无人识。\n滴石香乳溜，垂崖灵草植。\n玩幽轻雾阻，讨异忘曛逼。\n寒沙际水平，霜树笼烟直。\n空宫闻莫覩，地道窥难测。\n此处学金丹，何人生羽翼。\n谁传九光要，几拜三仙职。\n紫气徒想像，清潭长眇默。\n霓裳若有来，觏我云峰侧。' },
  { title: '㴩湖山寺', author: '张说', poem: '楚老游山寺，提携观画壁。\n扬袂指辟支，睩眄相鬬阋。\n险哉透撞儿，千金赌一掷。\n成败身自受，傍人那叹息。' },
  { title: '出湖寄赵冬曦', author: '张说', poem: '西泛平湖尽，参差入乱山。\n东瞻岳阳郡，汗漫太虚间。\n窘步同行乐，遒文互屡看。\n山戍上云桂，江亭临水关。\n川途倏忽间，风景依如昨。\n湘浦未赐环，荆门犹主诺。' },
  { title: '岳阳早霁南楼', author: '张说', poem: '山水佳新霁，南楼玩初旭。\n夜来枝半红，雨后洲全绿。\n四运相终始，万形纷代续。\n适临青草湖，再变黄鸎曲。\n地穴穿东武，江流下西蜀。\n歌闻枉渚邅，舞见长沙促。\n心阻意徒驰，神和生自足。\n白髪悲上春，知常谢先欲。' },
  { title: '岳阳石门墨山二山相连有禅堂观天下绝境', author: '张说', poem: '囷轮江上山，近在华容县。\n常涉巴丘首，天晴遥可见。\n佳游屡前诺，芳月愆幽眷。\n及此符守移，欢言临道便。\n既携赏心客，复有送行掾。\n竹径入阴窅，松萝上空蒨。\n草共林一色，云与峰万变。\n探窥石门断，缘越沙涧转。\n两山势争雄，峰𪩘相顾眄。\n药妙灵仙宝，境华岩壑选。\n清都西渊绝，金地东敞宴。\n池果接园畦，风烟迩台殿。\n高寻去石顶，旷览天宇遍。\n千山纷满目，百川豁对面。\n骑来云气迎，人去鸟声恋。\n长揖桃源士，举世同企羡。' },
  { title: '和尹懋秋夜游㴩湖', author: '张说', poem: '坐啸人事闲，佳游野情发。\n山门送落照，湖口升微月。\n林寻猿狖居，水戏鼋鼍穴。\n朔风吹飞雁，芳草亦云歇。' },
  { title: '五君咏五首 魏齐公元忠', author: '张说', poem: '齐公生人表，逈天闻鹤唳。\n清论早揣摩，玄心晚超诣。\n入相廊庙静，出军沙漠霁。\n见深吕禄忧，举后陈平计。\n甘心除君恶，足以报先帝。' },
  { title: '五君咏五首 苏许公瓌', author: '张说', poem: '许公信国桢，克美具瞻情。\n百事资朝问，三章广世程。\n处高心不有，临节自为名。\n朱户传新戟，青松拱旧茔。\n凄凉丞相府，余庆在玄成。' },
  { title: '五君咏五首 李赵公峤', author: '张说', poem: '李公实神敏，才华乃天授。\n睦亲何用心，处贵不忘旧。\n故事遵台阁，新诗冠宇宙。\n在人忠所奉，恶我诚将宥。\n南浦去莫归，嗟嗟蔑孙秀。' },
  { title: '五君咏五首 郭代公元振', author: '张说', poem: '代公举鹏翼，悬飞摩海雾。\n志康天地屯，适与云雷遇。\n兴丧一言决，安危万心注。\n大勋书王府，舛命沦江路。\n势倾北夏门，哀靡东平树。' },
  { title: '五君咏五首 赵耿公彦昭', author: '张说', poem: '耿公山岳秀，才杰心亦妙。\n鸷鸟峻标立，哀玉扣清调。\n协赞休明启，恩华日月照。\n何意瑶台云，风吹落江徼。\n湘流下浔阳，洒泪一投吊。' },
  { title: '游龙山静胜寺', author: '张说', poem: '每上襄阳楼，遥望龙山树。\n郁茀吐冈岭，微蒙在烟雾。\n下车岁已成，饰马闲余步。\n苦霜裛野草，爱日扬江煦。\n云对石上塔，风吹松下路。\n禅室宴三空，神祠同六趣。\n儿童共戏谑，猿鸟相惊顾。\n南识桓公台，北望先贤墓。\n世上人何在，时闻心不住。\n但传无尽灯，可使有情悟。' },
  { title: '一柱观', author: '张说', poem: '旧说江陵观，初疑神化来。\n空山结云阁，绮靡随风回。\n奈何任一柱，斯焉容众材。\n奇功非长世，今余草露台。' },
  { title: '登九里台是樊姬墓', author: '张说', poem: '楚国所以霸，樊姬有力焉。\n不怀沈尹禄，谁谙叔敖贤。\n万化茫无在，孤坟独岿然。\n北分阳台陌，南识郢城阡。\n漠漠渚宫树，苍苍云梦田。\n登高形胜出，访古令名传。\n自我来符守，因君树蕙荃。\n诗书将变俗，𫄨纩忽弥年。\n志阐三折后，愁值二毛前。\n伫立帝京路，遥心寄此篇。' },
  { title: '过怀王墓', author: '张说', poem: '咿嚘不可信，以此败怀王。\n客死峣关路，返葬岐江阳。\n啼狖抱山月，饥狐猎野霜。\n一闻怀沙事，千载尽悲凉。' },
  { title: '闻雨', author: '张说', poem: '多雨绝尘事，寥寥入太玄。\n城阴疎复合，檐滴断还连。\n念我劳造化，从来五十年。\n误将心徇物，近得还自然。\n闲居草木侍，虚室鬼神怜。\n有时进美酒，有时泛清弦。\n声真不世识，心醉岂言诠。' },
  { title: '夜坐', author: '张说', poem: '怀哉四壁时，未有五都价。\n百金谁见许，斗酒难为贳。\n落花生芳春，孤月皎清夜。\n复逢利交客，题户遥相谢。' },
  { title: '山夜闻钟', author: '张说', poem: '夜卧闻夜钟，夜静山更响。\n霜风吹寒月，䆗窱虚中上。\n前声既舂容，后声复晃荡。\n听之如可见，寻之定无像。\n信知本际空，徒挂生灭想。' },
  { title: '冬日见牧牛人担青草归', author: '张说', poem: '塞上绵应折，江南草可结。\n欲持梅岭花，远竞榆关雪。\n日月无他照，山川何顿别。\n苟齐两地心，天问将安说。' },
  { title: '咏镜', author: '张说', poem: '宝镜如明月，出自秦宫样。\n隐起双蟠龙，衔珠俨相向。\n常恐君不察，匣中委清量。\n积翳掩菱花，虚心蔽尘状。\n倘蒙罗袖拂，光生玉台上。' },
  { title: '咏瓢', author: '张说', poem: '美酒酌悬瓢，真淳好相映。\n蜗房卷堕首，鹤颈抽长柄。\n雅色素而黄，虚心轻且劲。\n岂无雕刻者，贵此成天性。' },
  { title: '杂诗四首 一', author: '张说', poem: '抱薰心常焦，举斾心常摇。\n天长地自久，欢乐能几朝。\n君看西陵树，歌舞为谁娇。' },
  { title: '杂诗四首 二', author: '张说', poem: '山闲苦积雨，木落悲时遽。\n赏心凡几人，良辰在何处？\n触石满堂侈，洒我终夕虑。\n客鸟怀主人，衔花未能去。\n剖珠贵分明，琢玉思坚贞。\n要君意如此，终始莫相轻。' },
  { title: '杂诗四首 三', author: '张说', poem: '问子青霞意，何事留朱轩。\n自言心远俗，未始迹辞喧。\n过蒙良时幸，侧息吏途烦。\n簪缨非宿好，文史弃前言。\n夕卧北窗下，梦归南山园。\n白云慙幽谷，清风愧泉源。\n十年兹赏废，佳期今复存。\n挂冠谢朝侣，星驾别君门。' },
  { title: '杂诗四首 四', author: '张说', poem: '默念群疑起，玄通百虑清。\n初心灭阳艳，复见湛虚明。\n悟灭心非尽，求虚见后生。\n应将无住法，修到不成名。' },
  { title: '和张监游终南', author: '张说', poem: '宿怀终南意，及此语云峰。\n夜闻竹涧静，晓望林岭重。\n春烟生古石，时鸟戏幽松。\n岂无山中赏，但畏心莫从。' },
  { title: '古泉驿', author: '张说', poem: '昔闻陈仲子，守义辞三公。\n身赁妻织屦，乐亦在其中。\n岂无穷贱苦，羞与倾巧同。\n长白临河上，于陵入济东。\n我行吊遗迹，感叹古泉空。' },
  { title: '河上公', author: '张说', poem: '尊师厌尘去，精魄知何明。\n形气不复生，弟子空伤情。\n济北神如在，淮南药未成。\n共期终莫遂，寥落两无成。' },
  { title: '奉和圣制初入秦川路寒食应制', author: '张说', poem: '上阳柳色唤春归，临渭桃花拂水飞。\n总为朝廷巡幸去，顿教京洛少光辉。\n昨从分陕山南口，驰道依依渐花柳。\n入关正投寒食前，还京遂落清明后。\n路上天心重豫游，御前恩赐特风流。\n便幕那能镂鸡子，行宫善巧帖毛毬。\n渭桥南渡花如扑，麦陇青青断人目。\n汉家行树直新丰，秦地骊山抱温谷。\n香池春溜水初平，预欢浴日照京城。\n今岁随宜过寒食，明年陪宴作清明。' },
  { title: '时乐鸟篇', author: '张说', poem: '旧传南海出灵禽，时乐名闻不可寻。\n形貌乍同鹦鹉类，精神别禀凤皇心。\n千年待圣方轻举，万里呈才无伴侣。\n红茸糅绣好毛衣，清泠讴鵶好言语。\n内人试取御衣牵，啄手暝声不许前。\n心愿阳乌恒保日，志嫌阴鹤欲凌天。\n天情玩讶良无已，察图果见祥经里。\n本持符瑞验明王，还用文章比君子。\n自怜弱羽讵堪珍，喜共华篇来示人。\n人见嘤嘤报恩鸟，多慙碌碌具官臣。' },
  { title: '安乐郡主花烛行', author: '张说', poem: '青宫朱邸翊皇闱，玉叶琼蕤发紫微。\n姬姜本来舅甥国，卜筮俱道凤皇飞。\n星昴殷冬献吉日，夭桃秾李遥相匹。\n鸾车凤传王子来，龙楼月殿天孙出。\n平台火树连上阳，紫炬红轮十二行。\n丹炉飞铁驰炎焰，炎霞烁电吐明光。\n绿𫐌绀幰纷如雾，节鼓清笳前启路。\n城隅靡靡稍东还，桥上鳞鳞转南渡。\n五方观者聚中京，四合尘烟涨洛城。\n商女香车珠结网，天人宝马玉繁缨。\n百壶渌酒千斤肉，大道连延障锦轴。\n先祝圣人寿万年，复祷宜家承百禄。\n珊瑚刻盘青玉尊，因之假道入梁园。\n梁园山竹凝云汉，仰望高楼在天半。\n翠幕兰堂苏合薰，珠帘挂户水波纹。\n别起芙蓉织成帐，金镂鸳鸯两相向。\n罽茵饰地承雕履，花烛分阶移锦帐。\n织女西垂隐烛台，双童连缕合欢杯。\n蔼蔼绮庭嫔从列，娥娥红粉扇中开。\n黄金两印双花绶，富贵婚姻古无有。\n清歌棠棣美王姬，流化邦人正夫妇。' },
  { title: '离会曲', author: '张说', poem: '何处送客洛桥头，洛水泛泛中行舟。\n可怜河树叶萎蕤，关关河鸟声相思。\n街鼓喧喧日将夕，去棹归轩两相迫。' },
  { title: '邺都引', author: '张说', poem: '君不见魏武草创争天禄，群雄睚眦相驰逐。\n昼携壮士破坚阵，夜接词人赋华屋。\n都邑缭绕西山阳，桑榆汗漫漳河曲。\n城郭为虚人代改，但有西园明月在。\n邺傍高冢多贵臣，娥眉𥊑睩共灰尘。\n试上铜台歌舞处，唯有秋风愁杀人。' },
  { title: '城南亭作', author: '张说', poem: '珂马朝归连万石，矟门洞启亲迎客。\n北堂珍重琥珀酒，庭前列肆茱萸席。\n长袖迟回意绪多，清商缓转[目]腾波。\n旧传比翼侯家舞，新出将雏主第歌。\n汉家绛灌余兵气，晋代浮虚安足贵。\n正逢天下金镜清，偏加日饮醇醪意。\n谁复遨游不复归，闲庭莫畏不芳菲。\n会待城南春色至，竟将花柳拂罗衣。' },
  { title: '同赵侍御干湖作', author: '张说', poem: '江南湖水咽山川，春江溢入共湖连。\n气色纷沦横罩海，波涛鼓怒上漫天。\n鳞宗壳族嬉为府，弋叟罛师利焉聚。\n欹帆侧柁弄风口，赴险临深绕湾浦。\n一湾一浦怅邅回，千曲千溠怳迷哉。\n乍见灵妃含笑往，复闻游女怨歌来。\n暑来寒往运洄洑，潭生水落移陵谷。\n云间坠翮散泥沙，波上浮查栖树木。\n昨暮飞霜下北津，今朝行雁度南滨。\n处处沟洚清源竭，年年旧苇白头新。\n天地盈虚尚难保，人间倚伏何须道。\n秋月皛皛泛澄澜，冬景青青步纤草。\n念君宿昔观物变，安得踌蹰不衰老。' },
  { title: '赠崔二安平公乐世词', author: '张说', poem: '十五红粧侍绮楼，朝承握槊夜藏钩。\n君臣一意金门宠，兄弟双飞玉殿游。\n宁知宿昔恩华乐，变作潇湘离别愁。\n地湿莓苔生舞袖，江声怨叹入箜篌。\n自怜京兆双眉妩，会待南来五马留。' },
  { title: '送尹补阙元凯琴歌', author: '张说', poem: '凤哉凤哉！啄琅玕。\n饮瑶池，栖昆仑之山哉。\n中国有圣人，感和气。\n飞来飞来，自歌自舞。\n先王册府，麒鳞之台。\n羇雌众雏故山曲，其鸣喈喈。\n其鸣喈喈，欲往衔之歘去来。\n去别鸾凤心徘徊，明年阿阁梧桐花叶开。\n群飞凤归来，群飞凤归来。' },
  { title: '送考功武员外学士使嵩山署舍利塔', author: '张说', poem: '怀玉泉，恋仁者，寂灭真心不可见。\n空留影塔嵩岩下，宝王四海转千轮。\n金昙百粒送分身，山中二月娑罗会。\n虚呗遥遥愁思人，我念过去微尘劫。\n与子禅门同正法，虽在神仙兰省间。\n常持清净莲花叶，来亦好，去亦好。\n了观车行马不移，当见菩提离烦恼。' },
  { title: '遥同蔡起居偃松篇', author: '张说', poem: '清都众木总荣芬，传道孤松最出群。\n名接天庭长景色，气连宫阙借氛氲。\n悬池的的停华露，偃盖重重拂瑞云。\n不借流膏助仙鼎，愿将桢干捧明君。\n莫比冥灵楚南树，朽老江边代不闻。' },
  { title: '奉和圣制登骊山瞩眺应制', author: '张说', poem: '寒山上半空，临眺尽寰中。\n是日巡游处，晴光远近同。\n川明分渭水，树暗辨新丰。\n岩壑清音暮，天歌起大风。' },
  { title: '奉和圣制幸白鹿观应制', author: '张说', poem: '洞府寒山曲，天游日旰回。\n披云看石镜，拂雪上金台。\n竹径龙骖下，松庭鹤辔来。\n双童还献药，五色耀仙材。' },
  { title: '奉和圣制送金城公主适西蕃应制', author: '张说', poem: '青海和亲日，潢星出降时。\n戎王子壻宠，汉国舅家慈。\n春野开离䜩，云天起别词。\n空弹马上曲，讵减凤楼思。' },
  { title: '奉和同皇太子过慈恩寺应制二首 一', author: '张说', poem: '翼翼宸恩永，煌煌福地开。\n离光升宝殿，震气绕香台。\n上界幡花合，中天伎乐来。\n愿君无量寿，仙乐屡徘徊。' },
  { title: '奉和同皇太子过慈恩寺应制二首 二', author: '张说', poem: '朗朗神居峻，轩轩瑞象威。\n圣君成愿果，太子拂天衣。\n至乐三灵会，深仁四皓归。\n还闻涡水曲，更绕白云飞。' },
  { title: '侍宴武三思山第应制赋得风字', author: '张说', poem: '梁王池馆好，晓日凤楼通。\n竹町罗千衞，兰筵降两宫。\n清歌芳树下，妙舞落花中。\n臣觉筵中听，还如大国风。' },
  { title: '奉和圣制过宁王宅应制', author: '张说', poem: '进酒忘忧观，箫韶喜降临。\n帝尧敦族礼，王季友兄心。\n竹院龙鸣笛，梧宫凤遶林。\n大风将小雅，一字尽千金。' },
  { title: '奉和圣制同玉真公主过大哥山池题石壁应制', author: '张说', poem: '绿竹初成苑，丹砂欲化金。\n乘龙与骖凤，歌吹满山林。\n爽气凝情逈，寒光映浦深。\n忘忧题此观，为乐赏同心。' },
  { title: '奉和圣制赐王公千秋镜应制', author: '张说', poem: '宝镜颁神节，凝规写圣情。\n千秋题作字，长寿带为名。\n月向天边下，花从日里生。\n不承悬象意，谁辨照心明。' },
  { title: '奉和圣制经邹鲁祭孔子应制', author: '张说', poem: '孔圣家邹鲁，儒风蔼典坟。\n龙骖廻旧宅，凤德咏余芬。\n入室神如在，升堂乐似闻。\n悬知一王法，今日待明君。' },
  { title: '侍宴蘘荷亭应制', author: '张说', poem: '回銮青岳观，帐殿紫烟峰。\n仙路迎三鸟，云衢驻两龙。\n园林看化塔，坛𫮃识余封。\n山外闻箫管，还如天上逢。' },
  { title: '侍宴浐水赋得浓字', author: '张说', poem: '千行发御柳，一叶下仙筇。\n青浦宸游至，朱城佳气浓。\n云霞交暮色，草树喜春容。\n蔼蔼天旗转，清笳入九重。' },
  { title: '奉和圣制同刘晃喜雨应制', author: '张说', poem: '青气含春雨，知从岱岳来。\n行云避师出，洒雨待车廻。\n厌浥尘清道，空蒙柳映台。\n最宜三五夜，晴月九重开。' },
  { title: '奉和圣制观拔河俗戏应制', author: '张说', poem: '今岁好拖钩，横衔敞御楼。\n长绳系日住，贯索挽河流。\n鬬力频催鼓，争都更上筹。\n春来百种戏，天意在宜秋。' },
  { title: '奉和圣制途次陕州应制', author: '张说', poem: '周召尝分陕，诗书空复传。\n何如万乘睠，追赏二南篇。\n郡带洪河侧，宫临大道边。\n洛城将日近，佳气满山川。' },
  { title: '奉和圣制野次喜雪应制', author: '张说', poem: '寒更玉漏催，晓色御前开。\n泱漭云阴积，氤氲风雪廻。\n山知银作瓮，宫见璧成台。\n欲验丰年象，飘摇仙藻来。' },
  { title: '奉和圣制温泉言志应制', author: '张说', poem: '温谷媚新丰，骊山横半空。\n汤池薰水殿，翠木暖烟宫。\n起疾逾仙药，无私合圣功。\n始知尧舜德，心与万人同。' },
  { title: '皇帝降诞日集贤殿赐宴', author: '张说', poem: '仲秋金帝起，五日土行昭。\n瑞表壬寅露，光传甲子宵。\n阴风吹大泽，梦日照昌朝。\n不独华封老，千年喜祝尧。' },
  { title: '晦日诏宴永穆公主亭子赋得流字', author: '张说', poem: '堂邑山林美，朝恩晦日游。\n园亭含淑气，竹树遶春流。\n舞席千花妓，歌船五彩楼。\n群欢与王泽，岁岁满皇州。' },
  { title: '恩制赐食于丽正殿书院宴赋得林字', author: '张说', poem: '东壁图书府，西园翰墨林。\n诵诗闻国政，讲易见天心。\n位窃和羹重，恩叨醉酒深。\n缓歌春兴曲，情竭为知音。' },
  { title: '羽林恩召观御书王太尉碑', author: '张说', poem: '陇首名公石，来承圣札归。\n鱼龙生意态，钩劒动铓辉。\n字得神明保，词慙少女徽。\n谁家羽林将，又逐凤书飞。' },
  { title: '东都酺宴四首 一', author: '张说', poem: '重华升宝历，轩帝眇闲居。\n政成天子孝，俗返上皇初。\n忘味因观乐，欢心寄合酺。\n自怜疲马意，恋恋主恩余。' },
  { title: '东都酺宴四首 二', author: '张说', poem: '朱城尘曀灭，翠幕景情开。\n震震灵鼍起，翔翔舞凤来。\n雕盘装草树，绮乘结楼台。\n共喜光华日，酣歌捧玉杯。' },
  { title: '东都酺宴四首 三', author: '张说', poem: '晓月调金阙，朝暾对玉盘。\n争驰群鸟散，鬬伎百花团。\n遇圣人知幸，承恩物自欢。\n洛桥将举烛，醉舞拂归鞍。' },
  { title: '东都酺宴四首 四', author: '张说', poem: '恺宴惟今席，余欢殊未穷。\n入云歌袅袅，向日伎丛丛。\n驶管催酣兴，留关待曲终。\n长安若为乐，应与万方同。' },
  { title: '道家四首奉敕撰 一', author: '张说', poem: '金坛启曙闱，真气肃微微。\n落月衔仙窦，初霞拂羽衣。\n香随龙节下，云逐凤箫飞。\n暂住蓬莱戏，千年始一归。' },
  { title: '道家四首奉敕撰 二', author: '张说', poem: '窈窕流精观，深沈紫翠庭。\n金匳调上药，宝案读仙经。\n作赋看神雨，乘槎辨客星。\n秪应谢人俗，轻举托云𫐌。' },
  { title: '道家四首奉敕撰 三', author: '张说', poem: '金炉承道诀，玉牒启玄机。\n云逐笙歌度，星流宫殿飞。\n乘风嬉浩荡，窥月弄光辉。\n唯有三山鹤，应同千载归。' },
  { title: '道家四首奉敕撰 四', author: '张说', poem: '道记开中箓，真官表上清。\n焚香三鸟至，炼药九仙成。\n天上灵书下，空中妙伎迎。\n迎来出烟雾，渺渺戏蓬瀛。' },
  { title: '凤楼寻胜地', author: '张说', poem: '西掖持醇酒，东山就白云。\n开轩绿池映，命席紫兰芬。\n舞度花为伴，莺来管作群。\n太平多乐事，春物共氛氲。' },
  { title: '幽州夜饮', author: '张说', poem: '凉风吹夜雨，萧瑟动寒林。\n正有高堂宴，能忘迟暮心。\n军中宜劒舞，塞上重笳音。\n不作边城将，谁知恩遇深。' },
  { title: '崔礼部园亭得深字', author: '张说', poem: '窈窕留清馆，虚徐步晚阴。\n水连伊阙近，树接夏阳深。\n柳蔓怜垂拂，藤梢爱上寻。\n讶君轩盖侣，非复俗人心。' },
  { title: '送郑大夫惟忠从公主入蕃', author: '张说', poem: '凤吹遥将断，龙旗送欲还。\n倾都邀节使，传酌缓离颜。\n春碛沙连海，秋城月对关。\n和戎因赏魏，定远莫辞班。' },
  { title: '送崔二长史日知赴潞州', author: '张说', poem: '东山怀卧理，南省怅悲翁。\n共见前途促，何知后会同。\n莫轻一筵宴，明日半成空。\n况尔新离阙，思归迷梦中。' },
  { title: '同贺八送兖公赴荆州', author: '张说', poem: '畴昔同声友，骞飞出凤池。\n风云一荡薄，日月屡参差。\n此别黄叶下，前期安可知。\n谁怜楚南树，不为岁寒移。' },
  { title: '饯唐州高使君', author: '张说', poem: '常时好闲独，朋旧少相过。\n及尔宣风去，方嗟别日多。\n淮流春晼晚，江海路蹉跎。\n百岁屡分散，欢言复几何。' },
  { title: '送王晙自羽林赴永昌令', author: '张说', poem: '将星移北洛，神雨避东京。\n为负刚肠誉，还追强项名。\n白云向伊阙，黄叶散昆明。\n多谢弦歌宰，稀闻桴鼓声。' },
  { title: '同王仆射山亭饯岑广武羲得言字', author: '张说', poem: '闻道长岑令，奋翼宰旅门。\n长安东陌上，送客满朱轩。\n琴爵留佳境，山池借好园。\n兹游恨不见，别后缀离言。' },
  { title: '送任御史江南发粮以赈河北百姓', author: '张说', poem: '河朔人无岁，荆南义廪开。\n将兴泛舟役，必仗济川才。\n夜月临江浦，春云历楚台。\n调饥坐相望，绣服几时回。' },
  { title: '送王尚一严嶷二侍御赴司马都督军', author: '张说', poem: '汉掖通沙塞，边兵护草腓。\n将行司马令，助以铁冠威。\n白露鹰初下，黄尘骑欲飞。\n明年春酒熟，留酌二星归。' },
  { title: '送李问政河北简兵', author: '张说', poem: '斗酒贻朋爱，踌蹰出御沟。\n依然四牡别，更想八龙游。\n密亲仕燕冀，连年迩寇讐。\n因君阅河朔，垂泪语幽州。' },
  { title: '送薛植入京', author: '张说', poem: '青组言从史，鸿都忽见求。\n款言人向老，饮别岁方秋。\n髣髴长安陌，平生是旧游。\n何时复相遇，宛在水中流。' },
  { title: '相州前池别许郑二判官景先神力', author: '张说', poem: '数步圆塘水，双鸿戢羽仪。\n一飞乔木上，一返故林垂。\n澹泊含秋景，虚明抱夜规。\n无因留绝翰，云海意差池。' },
  { title: '岳州宴别潭州王熊二首 一', author: '张说', poem: '丝管清且哀，一曲倾一杯。\n气将然诺重，心向友朋开。\n古木无生意，寒云若死灰。\n赠君芳杜草，为植建章台。' },
  { title: '岳州宴别潭州王熊二首 二', author: '张说', poem: '缙云连省阁，沟水遽西东。\n然诺心犹在，荣华岁不同。\n孤城临楚塞，远树入秦宫。\n谁念三千里，江潭一老翁。' },
  { title: '广州萧都督入朝过岳州宴饯得冬字', author: '张说', poem: '孤城抱大江，节使往朝宗。\n果是台中旧，依然水上逢。\n京华遥比日，疲老飒如冬。\n窃羡能言鸟，衔恩向九重。' },
  { title: '岳州别姚司马绍之制许归侍', author: '张说', poem: '和玉悲无已，长沙宦不成。\n天从扇枕愿，人遂倚门情。\n方外怀司马，江东忆步兵。\n问君栖泊处，空岭夜猿惊。' },
  { title: '送岳州李十从军桂州', author: '张说', poem: '送客之江上，其人美且才。\n风波万里阔，故旧十年来。\n劒拔蛟随断，弓张鸟自摧。\n阳桥书落落，驿马定先回。' },
  { title: '岳州别赵国公王十一琚入朝', author: '张说', poem: '昔滥貂蝉长，同承雨露霏。\n今参鱼鳖守，望美洞庭归。\n浦树悬秋影，江云烧落辉。\n离魂似征帆，恒往帝乡飞。' },
  { title: '岳州别子均', author: '张说', poem: '离筵非燕喜，别酒正销魂。\n念汝犹童孺，嗟予隔远藩。\n津亭拔心草，江路断肠猿。\n他日将何见，愁来独倚门。' },
  { title: '端州别高六戬', author: '张说', poem: '异壤同羁窜，途中喜共过。\n愁多时举酒，劳罢或长歌。\n南海风潮壮，西江瘴疠多。\n于焉复分手，此别伤如何。' },
  { title: '南中别蒋五岑向青州', author: '张说', poem: '老亲依北海，贱子弃南荒。\n有泪皆成血，无声不断肠。\n此中逢故友，彼地送还乡。\n愿作枫林叶，随君度洛阳。' },
  { title: '南中别陈七李十', author: '张说', poem: '二年共游处，一旦各西东。\n请君聊驻马，看我转征蓬。\n画鹢愁南海，离驹思北风。\n何时似春雁，双入上林中。' },
  { title: '南中别王陵成崇', author: '张说', poem: '握手与君别，歧路赠一言。\n曹卿礼公子，楚媪馈王孙。\n倏尔生六翮，翻飞戾九门。\n常怀客鸟意，会答主人恩。' },
  { title: '岭南送使', author: '张说', poem: '秋雁逢春返，流人何日归？\n将余去国泪，洒子入乡衣。\n饥狖啼相聚，愁猿喘更飞。\n南中不可问，书此示京畿。' },
  { title: '幽州别阴长河行先', author: '张说', poem: '惠好交情重，辛勤世事多。\n荆南久为别，蓟北远来过。\n寄目云中鸟，留欢酒上歌。\n影移春复间，迟暮两如何。' },
  { title: '和朱使欣道峡似巫山之作', author: '张说', poem: '江如晓天净，石似暮霞张。\n征帆一流览，宛若巫山阳。\n楚客思归路，秦人谪异乡。\n猿鸣孤月夜，再使泪沾裳。' },
  { title: '和朱使欣二首 一', author: '张说', poem: '南土多为寇，西江尽畏途。\n山行阻篁竹，水宿碍萑蒲。\n使越才应有，征蛮力岂无。\n空传人赠劒，不见虎衔珠。' },
  { title: '和朱使欣二首 二', author: '张说', poem: '江势连山远，天涯此夜愁。\n霜空极天静，寒月带江流。\n思起南征棹，文高北望楼。\n自怜如坠叶，泛泛侣仙舟。' },
  { title: '过庾信宅', author: '张说', poem: '兰成追宋玉，旧宅偶词人。\n笔涌江山气，文骄云雨神。\n包胥非救楚，随会反留秦。\n独有东阳守，来嗟古树春。' },
  { title: '卢巴驿闻张御史张判官欲到不得待留赠之', author: '张说', poem: '旅窜南方远，传闻北使来。\n旧庭知玉树，合浦识珠胎。\n白发因愁改，丹心托梦廻。\n皇恩若再造，为忆不然灰。' },
  { title: '南中赠高六戬', author: '张说', poem: '北极辞明代，南溟宅放臣。\n丹诚由义尽，白发带愁新。\n鸟坠炎洲气，花飞洛水春。\n平生歌舞席，谁忆不归人。' },
  { title: '岳州山城', author: '张说', poem: '山城丰日暇，闭户见天心。\n东旷迎朝色，西楼引夕阴。\n书观千载近，学静二毛深。\n忽有南风至，吹君堂上琴。' },
  { title: '与赵冬曦尹懋子均登南楼', author: '张说', poem: '危楼泻洞湖，积水照城隅。\n命驾邀渔火，通家引凤雏。\n山晴红蘂匝，洲晓绿苗铺。\n举目思乡县，春光定不殊。' },
  { title: '游㴩湖上寺', author: '张说', poem: '湖上奇峰积，山中芳树春。\n何知绝世境，来遇赏心人。\n清旧岩前乐，呦嘤鸟兽驯。\n静言观听里，万法自成轮。' },
  { title: '晦日', author: '张说', poem: '晦日嫌春浅，江浦看湔衣。\n道傍花欲合，枝上鸟犹稀。\n共忆浮桥晚，无人不醉归。\n寄书题此日，雁过洛阳飞。' },
  { title: '湘州九日城北亭子', author: '张说', poem: '西楚茱萸节，南淮戏马台。\n宁知沅水上，复有菊花杯。\n亭帐凭高出，亲朋自远来。\n短歌将急景，同使兴情催。' },
  { title: '翻着葛巾呈赵尹', author: '张说', poem: '昔日接㒿倒，今我葛巾翻。\n宿酒何时醒，形骸不复存。\n忽闻有嘉客，躧步出闲门。\n桃花春径满，误识武陵源。' },
  { title: '戏题草树', author: '张说', poem: '忽惊石榴树，远出渡江来。\n戏问芭蕉叶，何愁心不开。\n微霜拂宫桂，凄吹扫庭槐。\n荣盛更如此，慙君独见哀。' },
  { title: '岳州赠广平公宋大夫', author: '张说', poem: '亚相本时英，归来复国桢。\n朝推长孺直，野慕隐之清。\n传节还闽嶂，皇华入汉京。\n宁思江上老，岁[晏]独无成。' },
  { title: '和魏仆射还乡', author: '张说', poem: '富贵还乡国，光华满旧林。\n秋风树不静，君子叹何深。\n故老空悬劒，邻交日散金。\n众芳摇落尽，独有岁寒心。' },
  { title: '和张监观赦', author: '张说', poem: '日御临双阙，天街俨百神。\n雷兹作解气，岁复建寅春。\n喜候开星驿，欢声发市人。\n金环能作赋，来入管弦声。' },
  { title: '寄天台司马道士', author: '张说', poem: '世上求真客，天台去不还。\n传闻有仙要，梦寐在兹山。\n朱阙青霞断，瑶堂紫月闲。\n何时枉飞鹤，笙吹接人间。' },
  { title: '下江南向夔州', author: '张说', poem: '天明江雾歇，洲浦棹歌来。\n绿水逶迤去，青山相向开。\n城临蜀帝祀，云接楚王台。\n旧知巫山上，游子共徘徊。' },
  { title: '还至端州驿前与高六别处', author: '张说', poem: '旧馆分江日，凄然望落晖。\n相逢传旅食，临别换征衣。\n昔记山川是，今伤人代非。\n往来皆此路，生死不同归。' },
  { title: '四月一日过江赴荆州', author: '张说', poem: '春色沅湘尽，三年客始回。\n夏云随北帆，同日过江来。\n水漫荆门出，山平郢路开。\n比肩羊叔子，千载岂无才。' },
  { title: '湘州北亭', author: '张说', poem: '人务南亭少，风烟北院多。\n山花迷径路，池水拂藤萝。\n萍散鱼时跃，林幽鸟任歌。\n悠然白云意，乘兴抱琴过。' },
  { title: '荆州亭入朝', author: '张说', poem: '巫山云雨峡，湘水洞庭波。\n九辨人犹摈，三秋鴈始过。\n旃裘吴地尽，髫荐楚言多。\n不果朝宗愿，其如江汉何。' },
  { title: '岳州守岁', author: '张说', poem: '除夜清樽满，寒庭燎火多。\n舞衣连臂拂，醉坐合声歌。\n至乐都忘我，冥心自委和。\n今年只如此，来岁知如何。' },
  { title: '咏尘', author: '张说', poem: '仙浦生罗袜，神京染素衣。\n裨山期益峻，照日幸增辉。\n夕伴龙媒合，朝游凤辇归。\n独怜范甑下，思绕画梁飞。' },
  { title: '阙题', author: '张说', poem: '婚礼知无贺，承家叹有辉。\n亲迎骥子跃，吉兆凤雏飞。\n温席开华扇，梁门换褧衣。\n遥思桃李日，应赋采苹归。' },
  { title: '深渡驿', author: '张说', poem: '旅泊青山夜，荒庭白露秋。\n洞房悬月影，高枕听江流。\n猿响寒岩树，萤飞古驿楼。\n他乡对摇落，倂觉起离忧。' },
  { title: '惠文太子挽歌二首 一', author: '张说', poem: '碣馆英灵在，瑶山美谥尊。\n剪桐悲曩戏，攻玉怆新恩。\n宫仗传驰道，朝衣送国门。\n千秋谷门外，明月照西园。' },
  { title: '惠文太子挽歌二首 二', author: '张说', poem: '梁国深文雅，淮王爱道仙。\n帝欢同宴日，神夺上宾年。\n旒旐飞行树，帷宫宿野烟。\n指言君爱弟，挥泪满山川。' },
  { title: '节义太子杨妃挽歌二首 一', author: '张说', poem: '西华三公族，东闱五可才。\n玉环初受庆，金玦反逢灾。\n桂殿花空落，桐园月自开。\n朝云将暮雨，长绕望思台。' },
  { title: '节义太子杨妃挽歌二首 二', author: '张说', poem: '昔日三朝路，逶迤四望车。\n绣腰长命绮，隐髻连枝花。\n今春戾园树，索然无岁华。\n共伤千载后，惟号一王家。' },
  { title: '韦谯公挽歌二首 一', author: '张说', poem: '五瑞分王国，双珠映后家。\n文飞书上凤，武结笥中蛇。\n出豫荣前马，回鸾丧后车。\n衮衣将锡命，泉路有光华。' },
  { title: '韦谯公挽歌二首 二', author: '张说', poem: '国骋双骐骥，庭仪两凤皇。\n将星连相位，玉树伴金乡。\n歌舞侯家艳，轩裘戚里光。\n安知杜陵下，碑版已相望。' },
  { title: '右丞相苏公挽歌二首 一', author: '张说', poem: '王宰丹青化，春卿礼乐才。\n缁衣传旧职，华衮赠新哀。\n路泣群官送，山嘶驷马廻。\n佳辰无白日，宾阁有青苔。' },
  { title: '右丞相苏公挽歌二首 二', author: '张说', poem: '门歌出野田，冠带寝穷泉。\n万事皆身外，平生尚目前。\n西垣紫泥綍，东岳白云篇。\n自惜同声处，从今遂绝弦。' },
  { title: '崔尚书挽词', author: '张说', poem: '相宅隆坤宝，承家占海封。\n庭中男执雁，门外女乘龙。\n鸣玉游三省，𪭢金侍九重。\n一朝宾客散，留劒在青松。' },
  { title: '右侍郎集贤院学士徐公挽词二首 一', author: '张说', poem: '才美临淄北，名高淮海东。\n羽仪三省遍，渔猎五车通。\n玉殿孤新榜，珠英落旧丛。' },
  { title: '右侍郎集贤院学士徐公挽词二首 二', author: '张说', poem: '叹息书林友，才华天下选。\n并赋三阳宫，集诗集贤殿。\n具物衣如在，咄嗟长不见。\n既哀薤露词，岂忘平生眷。' },
  { title: '崔司业挽歌二首 一', author: '张说', poem: '海岱英灵气，胶庠礼乐资。\n风流满天下，人物擅京师。\n疾起扬雄赋，魂游谢客诗。\n从今好文主，遗恨不同时。' },
  { title: '崔司业挽歌二首 二', author: '张说', poem: '象设存华馆，威仪下墓田。\n凤池伤旧草，麟史泣遗编。\n帷盖墟烟没，干旌陇日悬。\n古来埋玉树，流恨满山川。' },
  { title: '李工部挽歌三首 一', author: '张说', poem: '锦帐为郎日，金门待诏时。\n杨宫先上赋，柏殿几连诗。\n瞬息琴歌断，凄凉箫挽悲。\n那堪霸陵岸，回首望京师。' },
  { title: '李工部挽歌三首 二', author: '张说', poem: '宅兆西陵上，平生雅志从。\n城临丹阙近，山望白云重。\n会葬知元伯，看碑识蔡邕。\n无由接神理，挥涕向青松。' },
  { title: '李工部挽歌三首 三', author: '张说', poem: '常时好宾客，永日对弦歌。\n是日归泉下，伤心无奈何。\n墓庭人已散，祭处鸟来过。\n碑石生苔藓，荣名岂复多。' },
  { title: '赠工部尚书冯公挽歌三首 一', author: '张说', poem: '忠鲠难为事，平生尽畏途。\n如弦心自直，秀木势恒孤。\n诏葬南陵道，神游北斗枢。\n贵门传万石，余庆在双珠。' },
  { title: '赠工部尚书冯公挽歌三首 二', author: '张说', poem: '爵位题龙旐，威仪出凤城。\n路傍人泣送，门外马嘶迎。\n万事非吾有，千悲是世情。\n昔焉称夏日，今也谥冬卿。' },
  { title: '赠工部尚书冯公挽歌三首 三', author: '张说', poem: '窅然长夜台，举世可哀哉。\n泉户一朝闭，松风四面来。\n石碑填駮藓，珠服聚尘埃。\n谁言辽东鹤，千年往复廻。' },
  { title: '徐高御挽歌', author: '张说', poem: '蒲密遥千载，鸣琴始一追。\n公卿传世范，仁义续灵基。\n不待南游禄，何先北帝期。\n玉棺从此闭，金鼎代相欺。' },
  { title: '奉和圣制春日幸望春宫应制', author: '张说', poem: '别馆芳菲上苑东，飞花澹荡御筵红。\n城临渭水天河静，阙对南山雨露通。\n绕殿流莺凡几树，当蹊乱蝶许多丛。\n春园既醉心和乐，共识皇恩造化同。' },
  { title: '侍宴隆庆池应制', author: '张说', poem: '灵池月满直城隈，黻帐天临御路开。\n东沼初阳疑吐出，南山晓翠若浮来。\n鱼龙百戏纷容与，凫鹢双舟较溯洄。\n愿似金隄青草馥，长承瑶水白云杯。' },
  { title: '奉和圣制春日出苑应制', author: '张说', poem: '禁林艳裔发青阳，春望逍遥出画堂。\n雨洗亭臯千亩绿，风吹梅李一园香。\n鹤飞不去随青管，鱼跃翻来入彩航。\n睿赏欢承天保定，遒文更覩日重光。' },
  { title: '扈从温泉宫献诗', author: '张说', poem: '温泉启蛰气氛氲，渭浦归鸿日数群。\n骑仗联联环北极，鸣笳步步引南熏。\n松间彩殿笼佳气，山上朱旗绕瑞云。\n不知远梦华胥国，何如亲奉帝尧君。' },
  { title: '三月三日诏宴定昆池宫庄赋得筵字', author: '张说', poem: '凤皇楼下对天泉，鹦鹉洲中匝管弦。\n旧识平阳佳丽地，今逢上巳盛明年。\n舟将水动千寻日，幕共林横两岸烟。\n不降玉人观禊饮，谁令醉舞拂宾筵。' },
  { title: '先天应令', author: '张说', poem: '三阳丽景早芳辰，四序嘉园物候新。\n梅花百般障行路，垂柳千条暗回津。\n鸟惊直为飞风叶，鱼跃都由怯岸人。\n唯愿圣主南山寿，何愁不赏万年春。' },
  { title: '舞马千秋万岁乐府词三首 一', author: '张说', poem: '金天诞圣千秋节，玉醴还分万寿觞。\n试听紫骝歌乐府，何如𫘧骥舞华冈。\n连𬸣势出鱼龙变，躞蹀骄生鸟兽行。\n岁岁相传指树日，翩翩来伴庆云翔。' },
  { title: '舞马千秋万岁乐府词三首 二', author: '张说', poem: '圣皇至德与天齐，天马来仪自海西。\n腕足徐行拜两膝，繁骄不进踏千蹄。\n髬髵奋鬣时蹲踏，鼓怒骧身忽上跻。\n更有衔杯终宴曲，垂头掉尾醉如泥。' },
  { title: '舞马千秋万岁乐府词三首 三', author: '张说', poem: '远听明君爱逸才，玉鞭金翅引龙媒。\n不因兹白人间有，定是飞黄天上来。\n影弄日华相照耀，喷含云色且裴徊。\n莫言阙下桃花舞，别有河中兰叶开。' },
  { title: '同赵侍御巴陵早春作', author: '张说', poem: '江上春来早可观，巧将春物妬余寒。\n水苔共绕留乌石，花鸟争开鬬鸭栏。\n佩胜芳辰日渐暖，然灯美夜月初圆。\n意随北雁云飞去，直待南州蕙草残。' },
  { title: '幽州新岁作', author: '张说', poem: '去岁荆南梅似雪，今年蓟北雪如梅。\n共知人事何常定，且喜年华去复来。\n边镇戍歌连夜动，京城燎火彻明开。\n遥遥西向长安日，愿上南山寿一杯。' },
  { title: '扈从幸韦嗣立山庄应制', author: '张说', poem: '寒灰飞玉琯，汤井驻金舆。\n既得方明相，还寻大隗居。\n悬泉珠贯下，列帐锦屏舒。\n骑远林逾密，笳繁谷自虚。\n门旗堑复磴，殿幕裹通渠。\n舞凤迎公主，雕龙赋婕妤。\n地幽天赏洽，酒乐御筵初。\n菲才叨侍从，连藻媿应徐。' },
  { title: '奉和圣制喜雪应制', author: '张说', poem: '圣德与天同，封峦欲报功。\n诏书期日下，灵感应时通。\n触石云呈瑞，含花雪告丰。\n积如沙照月，散似面从风。\n舞集仙台上，歌流帝乐中。\n遥知百神喜，洒路待行宫。' },
  { title: '奉和圣制寒食作应制', author: '张说', poem: '寒食春过半，花秾鸟复娇。\n从来禁火日，会接清明朝。\n鬬敌鸡殊胜，争毬马绝调。\n晴空数云点，香树百风摇。\n改木迎新燧，封田表旧烧。\n皇情爱嘉节，传曲与箫韶。' },
  { title: '奉和圣制赐崔日知往潞州应制', author: '张说', poem: '圣情留曩镇，佳气翊兴王。\n增戟雄都府，高车转太常。\n川横八练阔，山带五龙长。\n连帅初恩命，天人旧纪纲。\n饯涂飞御藻，阖境自生光。\n明主征循吏，何年下凤皇。' },
  { title: '春晚侍宴丽正殿探得开字', author: '张说', poem: '圣政惟稽古，宾门引上才。\n坊因购书立，殿为集贤开。\n髦彦星辰下，仙章日月回。\n字如龙负出，韵是凤衔来。\n庭柳余春驻，宫莺早夏催。\n喜承芸阁宴，幸奉柏梁杯。' },
  { title: '奉和圣制花蕚楼下宴应制', author: '张说', poem: '万心翘乐宴，三舍缓昌时。\n山接夏云险，台留春日迟。\n节移芳未歇，兴隔赏仍追。\n醉后传嘉惠，楼前舞圣慈。\n皇恩与时合，天意若人期。\n故发前旬雨，新垂湛露诗。' },
  { title: '奉和圣制度蒲关应制', author: '张说', poem: '蒲坂横临晋，华芝晓望秦。\n关城雄地险，桥路扼天津。\n楼映行宫日，隄含宫树春。\n黄云随宝鼎，紫气逐真人。\n东咏唐虞迹，西观周汉尘。\n山河非国宝，明主爱忠臣。' },
  { title: '奉和圣制途经华岳应制', author: '张说', poem: '西岳镇皇京，中峰入太清。\n玉銮重岭应，缇[骑]薄云迎。\n霁日悬高掌，寒空类削成。\n轩游会神处，汉幸望仙情。\n旧庙青林古，新碑绿字生。\n群臣愿封岱，还驾勒鸿名。' },
  { title: '奉和圣制过王濬墓应制', author: '张说', poem: '牛斗三分国，龙骧一统年。\n智高宁受制，风急肯廻船。\n有策擒吴嚭，无言让范宣。\n援孤因势屈，功重为谗偏。\n旧迹灰尘散，枯坟故老传。\n百代逢明主，何辞死道边。' },
  { title: '奉和圣制经河上公庙应制', author: '张说', poem: '河上无名老，知非汉代人。\n先探道德要，留待圣明辰。\n玄妙为天下，清虚用谷神。\n化将和气一，风与太初邻。\n灵庙观遗像，仙歌入至真。\n皇心齐万物，何处不同尘。' },
  { title: '奉和圣制幸凤汤泉应制', author: '张说', poem: '周狩闻岐礼，秦都辨雍名。\n献禽天子孝，存老圣皇情。\n温润宜冬幸，游畋乐岁成。\n汤云出水殿，暖气入山营。\n坎意无私洁，干心称物平。\n帝歌流乐府，溪谷也增荣。' },
  { title: '恩赐乐游园宴', author: '张说', poem: '汉苑佳游地，轩庭近侍臣。\n共持荣幸日，来赏艳阳春。\n馔玉颁王篚，𪭢金下帝钧。\n池台草色徧，宫观柳条新。\n花绶光连榻，朱颜畅饮醇。\n圣朝多乐事，天意每随人。' },
  { title: '三月二十日诏宴乐游园赋得风字', author: '张说', poem: '乐游形胜地，表里望郊宫。\n北阙连天顶，南山对掌中。\n皇恩贷芳月，旬宴美成功。\n鱼戏芙蓉水，莺啼杨柳风。\n春光看欲暮，天泽恋无穷。\n长袖招斜日，留光待曲终。' },
  { title: '赴集贤院学士上赐宴应制得辉字', author: '张说', poem: '侍帝金华讲，千龄道固稀。\n位将贤士设，书共学徒归。\n首命深燕隗，通经浅汉韦。\n列筵荣赐食，送客愧儒衣。\n贺燕窥檐下，迁莺入殿飞。\n欲知朝野庆，文教日光辉。' },
  { title: '端午三殿侍宴应制探得鱼字', author: '张说', poem: '小暑夏弦应，徽音商管初。\n愿赍长命缕，来续大恩余。\n三殿褰珠箔，群官上玉除。\n助阳尝麦彘，顺节进龟鱼。\n甘露垂天酒，芝花捧御书。\n合丹同蝘蜓，灰骨共蟾蜍。\n今日伤蛇意，衔珠遂阙如。' },
  { title: '奉和圣制春中兴庆宫酺宴应制', author: '张说', poem: '千龄逢启圣，万域共来威。\n庆接郊禋后，酺承农事稀。\n御楼横广路，天乐下重闱。\n鸾凤调歌曲，虹霓动舞衣。\n合声云上聚，连步月中归。\n物覩恩无外，神和道入微。\n镐京陪乐饮，柏殿奉文飞。\n徒竭秋云影，何资春日晖。' },
  { title: '奉和圣制千秋节宴应制', author: '张说', poem: '五德生王者，千龄启圣人。\n赤光来照夜，黄云上覆晨。\n海县衔恩久，朝章献舞新。\n高居帝座出，夹道众官陈。\n槊杖洗清景，磬管凝秋旻。\n珠囊含瑞露，金镜抱仙轮。\n何岁无乡饮，何田不报神。\n薰歌与名节，传代幸群臣。' },
  { title: '奉和圣制太行山中言志应制', author: '张说', poem: '六龙鸣玉銮，九折步云端。\n河络南浮近，山经北上难。\n羽仪映松雪，戈甲带春寒。\n百谷晨笳动，千岩晓仗攒。\n皇心感韶节，敷藻念人安。\n既立省方馆，复建礼神坛。\n扈跸参天老，承荣忝夏官。\n长勤百年意，思见一胜残。' },
  { title: '奉和御制与宋璟源乾曜同日上官命宴东堂赐诗应制', author: '张说', poem: '大块镕群品，经生偶圣时。\n猥承三事命，虚忝百僚师。\n右揆谋华硕，前星傅重资。\n连骞求旧礼，滥典乐贤诗。\n赐釜同荣拜，𪭢金宴宰司。\n菊花吹御酒，兰叶捧天词。\n宝历休明盛，颓年晷漏衰。\n少留青史笔，未敢赤松期。' },
  { title: '奉和圣制暇日与兄弟同游兴庆宫作应制', author: '张说', poem: '汉武横汾日，周王宴镐年。\n何如造区夏，复此睦亲贤。\n巢凤新成阁，飞龙旧跃泉。\n棣华歌尚在，桐叶戏仍传。\n禁籞氛埃隔，平台景物连。\n圣慈良有裕，王道固无偏。\n问俗兆人阜，观风五教宣。\n献图开益地，张乐奏钧天。\n侍酒衢樽满，询刍谏鼓悬。\n永言形友爱，万国共周旋。' },
  { title: '奉和圣制送王晙巡边应制', author: '张说', poem: '六月歌周雅，三边遣夏卿。\n欲施攻战法，先作简稽行。\n礼乐知谋帅，春秋识用兵。\n一劳堪定国，万里即长城。\n策有和戎利，威传破虏名。\n军前雨洒道，楼上月临营。\n别藻瑶华降，同衣锦襮荣。\n关山由义近，戎马为恩轻。\n丝竹路傍散，风云马上生。\n朝廷谓吉甫，邦国望君平。' },
  { title: '将赴朔方军应制', author: '张说', poem: '礼乐逢明主，韬钤用老臣。\n恭凭神武策，远御鬼方人。\n供帐荣恩饯，山川喜诏巡。\n天文日月丽，朝赋管弦新。\n幼志传三略，衰材谢六钧。\n胆由忠作伴，心固道为邻。\n汉保河南地，胡清塞北尘。\n连年大军后，不日小康辰。\n劒舞轻离别，歌酣忘苦辛。\n从来思博望，许国不谋身。' },
  { title: '奉和圣制爰因巡省途次旧居应制', author: '张说', poem: '葱郁兴王郡，殷忧启圣图。\n周成会西土，汉武幸南都。\n岁卜銮舆迈，农祠鴈政敷。\n武威棱外域，文教靡中区。\n警跸干戈捧，朝宗万玉趋。\n旧藩人事革，新化国容殊。\n壁有真龙画，庭余鸣凤梧。\n丛觞祝尧寿，合鼎献汤厨。\n阳乐寒初变，春恩蛰更苏。\n三耆颁命服，五稔复田输。\n君赋大风起，人歌湛露濡。\n从臣观玉叶，方愿纪灵符。' },
  { title: '宿直温泉宫羽林献诗', author: '张说', poem: '冬狩美秦正，新丰乐汉行。\n星陈玄武阁，月对羽林营。\n寒木罗霜仗，空山响夜更。\n恩深灵液暖，节劲古松贞。\n文武皆王事，输心不为名。' },
  { title: '玄武门侍射', author: '张说', poem: '射观通玄阙，兵栏辟御筵。\n雕弧月半上，画的晕重圆。\n羿后神幽赞，灵王法暗传。\n贯心精四返，饮羽妙三联。\n雪鹤来衔箭，星麟下集弦。\n一逢军宴洽，万庆武功宣。' },
  { title: '扈从南出雀鼠谷', author: '张说', poem: '豫动三灵赞，时巡四海威。\n陕关凌曙出，平路半春归。\n霍镇迎云罕，汾河送羽旗。\n山南柳半密，谷北草全稀。\n迟日宜华盖，和风入袷衣。\n上林千里近，应见百花飞。' },
  { title: '洛桥北亭诏饯诸刺史', author: '张说', poem: '离亭拂御沟，别曲舞船楼。\n诏饯朝廷牧，符分海县忧。\n股肱还入郡，父母更临州。\n扇逐仁风传，车随霖雨流。\n恩光水上溢，荣色柳间浮。\n预待群方最，三公不远求。' },
  { title: '东都酺宴', author: '张说', poem: '尧舜传天下，同心致太平。\n吾君内举圣，远合至公情。\n锡命承丕业，崇亲享大名。\n二天资广运，两曜益齐明。\n道畅昆虫乐，恩深朽蠹荣。\n皇舆久西幸，留镇在东京。\n合宴千官入，分曹百戏呈。\n乐来嫌景遽，酒着讶寒轻。\n喜气连云阁，欢呼动洛城。\n人间知几代，今日见河清。' },
  { title: '奉酬韦祭酒嗣立偶游龙门北溪忽怀骊山别业呈诸留守之作', author: '张说', poem: '石涧泉虚落，松崖路曲回。\n闻君北溪下，想像南山隈。\n近念鼎湖别，遥思云嶂陪。\n不同奇觏往，空覩斯文来。\n岁后寒初变，春前芳未开。\n黄蕤袅岸柳，紫蕚折村梅。\n尽室兹游玩，盈门几乐哉。\n嗟留洛阳陌，梦诣建章台。\n野失巢由性，朝非元凯才。\n布怀钦远迹，幽意日尘埃。' },
  { title: '奉酬韦祭酒自汤还都经龙门北溪庄见贻之作', author: '张说', poem: '闻君汤井至，潇洒憇郊林。\n拂曙携清赏，披云觏绿岑。\n欢言游览意，款曲望归心。\n是日期佳客，同山忽异寻。\n桃花迂路转，杨柳间门深。\n泛舟伊水涨，系马香树阴。\n繁弦弄水族，娇吹狎沙禽。\n春满汀色媚，景斜岚气侵。\n怀仁殊未远，重德匪专临。\n来藻敷幽思，连词报所钦。' },
  { title: '酬崔光禄冬日述怀赠答', author: '张说', poem: '徐陈尝并作，枚马亦同时。\n各负当朝誉，俱承明主私。\n夫君迈前侣，观国骋奇姿。\n山似鸣威凤，泉如出宝龟。\n才雄子云笔，学广仲舒帷。\n紫绶拂三寺，朱门临九逵。\n昔我含香日，联尔缙云司。\n朝携兰省步，夕退竹林期。\n中路一分手，数载来何迟。\n求友还相得，群英复在兹。\n留台少人务，方驾递寻追。\n涉玩怀同赏，沾芳忆共持。\n迎宾南涧饮，载妓东城嬉。\n春郊绿亩秀，秋涧白云滋。\n名画披人物，良书讨滞疑。\n兴来光不惜，欢往迹如遗。\n岁晏罢行乐，层城间所思。\n夜魂灯处厌，朝髪镜前衰。\n忽枉崔骃什，兼流韦孟词。\n曲高弥寡和，主善代为师。\n齐戒观华玉，留连叹色丝。\n终慙起予者，何足与言诗。' },
  { title: '同刘给事城南宴集', author: '张说', poem: '水竹幽闲地，簪缨近侍臣。\n雍容乘暇日，潇洒出嚣尘。\n树对思朋鸟，池深入养鳞。\n管弦高逐吹，歌舞妙含春。\n老子叨专席，欢邀隔缙绅。\n此中情不浅，遥寄赏心人。' },
  { title: '温泉冯刘二监客舍观妓', author: '张说', poem: '温谷寒林薄，群游乐事多。\n佳人蹀骏马，乘月夜相过。\n秀色然红黛，娇香发绮罗。\n镜前鸾对舞，琴里凤传歌。\n妬宠倾新意，衔恩奈老何。\n为君留上客，欢笑敛双蛾。' },
  { title: '寄许八', author: '张说', poem: '万类春皆乐，徂颜独不怡。\n年来人更老，花发意先衰。\n乳鹊穿坛画，巢蜂触网丝。\n平生美容色，宿昔影中疑。\n远道何由梦，同心在者谁。\n西风欲谁语，悯默遂无词。' },
  { title: '送苏合宫颋', author: '张说', poem: '都邑群方首，商泉旧俗讹。\n变风须恺悌，成化伫弦歌。\n畴昔珪璋友，雍容文雅多。\n振缨游省闼，锵玉宰京河。\n别曲鸾初下，行轩雉尚过。\n百壶非饯意，流咏在人和。' },
  { title: '送乔安邑备', author: '张说', poem: '书阁移年岁，文明难复辞。\n欢言冬雪满，恨别夏云滋。\n外尹方为政，高明自不欺。\n老人骖驭往，童子狎雏嬉。\n日茂西河俗，寂寥东观期。\n遥怀秀才令，京洛见新诗。' },
  { title: '送赵二尚书彦昭北伐', author: '张说', poem: '虏地河冰合，边城备此时。\n兵连紫塞路，将举白云司。\n提劒荣中贵，衔珠盛出师。\n日华光组练，风色焰旌旗。\n投笔尊前起，横戈马上辞。\n梅花吹别引，杨柳赋归诗。' },
  { title: '石门别杨六钦望', author: '张说', poem: '燕人同窜越，万里自相哀。\n影响无期会，江山此地来。\n暮年伤泛梗，累日慰寒灰。\n潮水东南落，浮云西北回。\n俱看石门远，倚棹两悲哉。' },
  { title: '南中送北使二首 一', author: '张说', poem: '传闻合浦叶，曾向洛阳飞。\n何日南风至，还随北使归。\n红颜渡岭歇，白首对秋衰。\n高歌何由见，层堂不可违。\n谁怜炎海曲，泪尽血沾衣。' },
  { title: '南中送北使二首 二', author: '张说', poem: '待罪居重译，穷愁暮雨秋。\n山临鬼门路，城绕瘴江流。\n人事今如此，生涯尚可求。\n逢君入乡县，传我念京周。\n别恨归途远，离言暮景遒。\n夷歌翻下泪，芦酒未消愁。\n闻有胡兵急，深怀汉国羞。\n和亲先是诈，款塞果为讐。\n释系应分爵，蠲徒几复侯。\n廉颇诚未老，孙叔宜无谋。\n若道冯唐事，皇恩尚可收。' },
  { title: '送赵顺直郎中赴安西副大都督', author: '张说', poem: '绝镇功难立，悬军命匪轻。\n复承迁相后，弥重任贤情。\n将起神仙地，才称礼乐英。\n长心堪系虏，短语足论兵。\n日授休门法，星教置阵名。\n龙泉恩已着，燕颔相终成。\n月窟穷天远，河源入塞清。\n老天操别翰，承旨颂升平。' },
  { title: '送宋休远之蜀任', author: '张说', poem: '求友殊损益，行道异穷申。\n缀我平生气，吐赠薄游人。\n结恩事明主，忍爱远辞亲。\n色丽成都俗，膏腴蜀水滨。\n如何从宦子，坚白共缁磷。\n日月千龄旦，河山万族春。\n怀铅书瑞府，横草事边尘。\n不及安人吏，能令王化淳。' },
  { title: '岳州别梁六入朝', author: '张说', poem: '远莅长沙渚，欣逢贾谊才。\n江山疲应接，风日复晴开。\n江树云间断，湘山水上来。\n近洲朝鹭集，古戍夜猿哀。\n岸杼含苍捄，河蒲秀紫台。\n月余偏地赏，心尽故人杯。\n自我违京洛，嗟君此溯洄。\n容华因别老，交旧与年颓。\n梦见长安陌，朝宗实盛哉。' },
  { title: '相州冬日早衙', author: '张说', poem: '城外宵钟敛，闺中曙火残。\n朝光曜庭雪，宿冻聚池寒。\n正色临厅事，疑词定笔端。\n除苛囹圄息，伐枳吏人宽。\n河内功犹浅，淮阳疾未安。\n镜中星髪变，顿使世情阑。' },
  { title: '岳州西城', author: '张说', poem: '水国何辽旷，风波遂极天。\n西江三纪合，南浦二湖连。\n危堞临清境，烦忧暂豁然。\n九围观掌内，万象阅眸前。\n日去长沙渚，山横云梦田。\n汀葭变秋色，津树入寒烟。\n潜穴探灵诡，浮生揖圣仙。\n至今人不见，迹灭事空传。' },
  { title: '岳州观竞渡', author: '张说', poem: '画作飞凫艇，双双竞拂流。\n低装山色变，急棹水华浮。\n土尚三闾俗，江传二女游。\n齐歌迎孟姥，独舞送阳侯。\n鼓发南湖溠，标争西驿楼。\n并驱常诧速，非畏日光遒。' },
  { title: '对酒行巴陵作', author: '张说', poem: '留侯封万户，园令寿千金。\n本为成王业，初由赋上林。\n繁荣安足恃，霜露递相寻。\n鸟哭楚山外，猿啼湘水阴。\n梦中城阙近，天畔海云深。\n空对忘忧酌，离忧不去心。' },
  { title: '岳州宴姚绍之', author: '张说', poem: '杞梓滞江滨，光华向日新。\n难兄金作友，媚子玉为人。\n山水含秋兴，池亭借善邻。\n檐松风送静，院竹鸟来驯。\n翠斝吹黄菊，雕盘鲙紫鳞。\n缓歌将醉舞，为拂绣衣尘。' },
  { title: '岳州九日宴道观西阁', author: '张说', poem: '摇落长年叹，蹉跎远宦心。\n北风嘶代马，南浦宿阳禽。\n佳此黄花酌，酣余白首吟。\n凉云霾楚望，蒙雨蔽荆岑。\n登眺思清景，谁将眷浊阴。\n钓歌出江雾，樵唱入山林。\n鱼以嘉名采，木为美材侵。\n大道由中悟，逍遥匪外寻。\n参佐多君子，词华妙赏音。\n留题洞庭观，望古意何深。' },
  { title: '游洞庭湖', author: '张说', poem: '平湖晓望分，仙峤气氛氲。\n鼓枻乘清渚，寻峰弄白云。\n江寒天一色，日静水重纹。\n树坐参猿啸，沙行入鹭群。\n缘源斑筿密，罥径绿萝纷。\n洞穴传虚应，枫林觉自熏。\n双童有灵药，愿取献明君。' },
  { title: '巴丘春作', author: '张说', poem: '日出洞庭水，春山挂断霞。\n江涔相映发，卉木共纷华。\n湘戍南浮阔，荆关北望赊。\n湖阴窥魍魉，丘势辨巴蛇。\n岛户巢为馆，渔人艇作家。\n自怜心问景，三岁客长沙。' },
  { title: '岳州夜坐', author: '张说', poem: '炎洲苦三伏，永日卧孤城。\n赖此闲庭夜，萧条夜月明。\n独歌还太息，幽感见余声。\n江近鹤时呌，山深猿屡鸣。\n息心观有欲，弃知返无名。\n五十知天命，吾其达此生。' },
  { title: '别㴩湖', author: '张说', poem: '念别㴩湖去，浮舟更一临。\n千峰出浪险，万木抱烟深。\n南郡延恩渥，东山恋宿心。\n露花香欲醉，时鸟啭余音。\n涉趣皆留赏，无奇不徧寻。\n莫言山水间，幽意在鸣琴。' },
  { title: '伯奴边见归田赋因投赵侍御', author: '张说', poem: '尔家叹穷鸟，吾族赋归田。\n莫道荣枯异，同嗟世网牵。\n黄陵浮汨渚，青草会湘川。\n去国逾三岁，兹山老二年。\n寒鸮鸣舍下，昏虎卧篱前。\n客泪堪斑竹，离亭欲赠荃。\n放言久无次，触兴感成篇。' },
  { title: '清远江峡山寺', author: '张说', poem: '流落经荒外，逍遥此梵宫。\n云峰吐月白，石壁淡烟红。\n宝塔灵仙涌，悬龛造化功。\n天香涵竹气，虚呗引松风。\n檐牖飞花入，廊房激水通。\n猿鸣知谷静，鱼戏辨江空。\n静默将何贵，惟应心境同。' },
  { title: '春雨早雷', author: '张说', poem: '东北春风至，飘飘带雨来。\n拂黄先变柳，点素早惊梅。\n树蔼悬书阁，烟含作赋台。\n河鱼未上冻，江蛰已闻雷。\n美人宵梦着，金屏曙不开。\n无缘一启齿，空酌万年杯。' },
  { title: '赦归在道中作', author: '张说', poem: '陈焦心息尽，死意不期生。\n何幸光华旦，流人归上京。\n愁将网共解，服与代俱明。\n复是三阶正，还逢四海平。\n谁能定礼乐，为国着功成。' },
  { title: '喜度岭', author: '张说', poem: '东汉兴唐历，南河复禹谋。\n宁知瘴疠地，生入帝皇州。\n雷雨苏虫蛰，春阳放鸴鸠。\n洄沿炎海畔，登降闽山陬。\n岭路分中夏，川源得上流。\n见花便独笑，看草即忘忧。\n自始居重译，天星已再周。\n乡关绝归望，亲戚不相求。\n弃杖枯还植，穷鳞涸更浮。\n道消黄鹤去，运启白驹留。\n江妾晨炊黍，津童夜櫂舟。\n盛明良可遇，莫后洛城游。' },
  { title: '奉和圣制潼关口号应制', author: '张说', poem: '天德平无外，关门东复西。\n不将千里隔，何用一丸泥。' },
  { title: '奉萧令嵩酒幷诗', author: '张说', poem: '乐奏天恩满，杯来秋兴高。\n更蒙萧相国，对席饮醇醪。' },
  { title: '奉宇文黄门融酒', author: '张说', poem: '圣德垂甘露，天章下大风。\n又乘黄阁赏，愿作黑头公。' },
  { title: '奉裴中书光庭酒', author: '张说', poem: '西掖恩华降，南宫命席阑。\n讵知鸡树后，更接凤池欢。' },
  { title: '清夜酌', author: '张说', poem: '秋阴士多感，雨息夜无尘。\n清樽宜明月，复有平生人。' },
  { title: '醉中作', author: '张说', poem: '醉后乐无极，弥胜未醉时。\n动容皆是舞，出语总成诗。' },
  { title: '送梁知微渡海东', author: '张说', poem: '今日此相送，明年此相待。\n天上客星回，知君渡东海。' },
  { title: '寄刘道士舃', author: '张说', poem: '真人降紫气，邀我丹田宫。\n远寄双飞舄，飞飞不碍空。' },
  { title: '书香能和尚塔', author: '张说', poem: '大师捐世去，空余法力在。\n远寄无碍香，心随到南海。' },
  { title: '被使在蜀', author: '张说', poem: '即今三伏尽，尚自在临邛。\n归途千里外，秋月定相逢。' },
  { title: '正朝摘梅', author: '张说', poem: '蜀地寒犹暖，正朝发早梅。\n偏惊万里客，已复一年来。' },
  { title: '蜀道后期', author: '张说', poem: '客心争日月，来往预期程。\n秋风不相待，先至洛阳城。' },
  { title: '广州江中作', author: '张说', poem: '去国年方晏，愁心转不堪。\n离人与江水，终日向西南。' },
  { title: '江中诵经', author: '张说', poem: '实相归悬解，虚心暗在通。\n澄江明月内，应是色成空。' },
  { title: '江中遇黄领子刘隆', author: '张说', poem: '危石江中起，孤云岭上还。\n相逢皆得意，何处是乡关。' },
  { title: '钦州守岁', author: '张说', poem: '故岁今宵尽，新年明旦来。\n愁心随斗柄，东北望春回。' },
  { title: '岳州守岁二首 一', author: '张说', poem: '夜风吹醉舞，庭户对酣歌。\n愁逐前年少，欢迎今岁多。' },
  { title: '岳州守岁二首 二', author: '张说', poem: '桃枝堪辟恶，爆竹好惊眠。\n歌舞留今夕，犹言惜旧年。' },
  { title: '元朝', author: '张说', poem: '今岁元日乐，不谢往年春。\n知向来心道，谁为昨夜人。' },
  { title: '耗磨日饮二首 一', author: '张说', poem: '耗磨传兹日，纵横道未宜。\n但令不忌醉，翻是乐无为。' },
  { title: '耗磨日饮二首 二', author: '张说', poem: '上月今朝减，流传耗磨辰。\n还将不事事，同醉俗中人。' },
  { title: '耗磨日饮', author: '张说', poem: '春来半月度，俗忌一时闲。\n不酌他乡酒，惟堪对楚山。' },
  { title: '九日进茱萸山诗五首 一', author: '张说', poem: '家居洛阳下，举目见嵩山。\n刻作茱萸节，情生造化间。' },
  { title: '九日进茱萸山诗五首 二', author: '张说', poem: '黄花宜泛酒，青岳好登高。\n稽首明廷内，心为天下劳。' },
  { title: '九日进茱萸山诗五首 三', author: '张说', poem: '菊酒携山客，萸囊系牧童。\n路疑随大隗，心似问鸿蒙。' },
  { title: '九日进茱萸山诗五首 四', author: '张说', poem: '九日重阳数，三秋万实成。\n时来谒轩后，罢去坐蓬瀛。' },
  { title: '九日进茱萸山诗五首 五', author: '张说', poem: '晚节欢重九，高山上五千。\n醉中知遇圣，梦里见寻仙。' },
  { title: '岳州看黄叶', author: '张说', poem: '白首看黄叶，徂颜复几何。\n空慙棠树下，不见政成歌。' },
  { title: '岭南送使二首 一', author: '张说', poem: '狱中生白发，岭外罢红颜。\n古来相送处，凡得几人还。' },
  { title: '岭南送使二首 二', author: '张说', poem: '万里投荒裔，来时不见亲。\n一朝成白首，看取报家人。' },
  { title: '伤妓人董氏四首 一', author: '张说', poem: '董氏娇娆性，多为窈窕名。\n人随秋月落，韵入捣衣声。' },
  { title: '伤妓人董氏四首 二', author: '张说', poem: '粉蘂粘妆簏，金花竭翠条。\n夜台无戏伴，魂影向谁娇。' },
  { title: '伤妓人董氏四首 三', author: '张说', poem: '旧亭红粉阁，宿处白云关。\n春日双飞去，秋风独不还。' },
  { title: '伤妓人董氏四首 四', author: '张说', poem: '舞席沾残粉，歌梁委旧尘。\n独伤窗里月，不见帐中人。' },
  { title: '三月闺怨', author: '张说', poem: '三月时将尽，空房妾独居。\n蛾眉愁自结，鬓髪没情梳。' },
  { title: '破陈乐词二首 一', author: '张说', poem: '汉兵出顿金微，照日光明铁衣。\n百里火旛焰焰，千行云骑霏霏。\n蹙踏辽河自竭，鼓噪燕山可飞。\n正属四方朝贺，端知万舞皇威。' },
  { title: '破陈乐词二首 二', author: '张说', poem: '少年胆气凌云，共许骁雄出群。\n匹马城西挑战，单刀蓟北从军。\n一鼓鲜卑送款，五饵单于解纷。\n誓欲成名报国，羞将开合论勋。' },
  { title: '舞马词六首 一', author: '张说', poem: '万玉朝宗凤扆，千金率领龙媒。\n眄鼓凝骄躞蹀，听歌弄影徘徊。' },
  { title: '舞马词六首 二', author: '张说', poem: '天鹿遥征衞叔，日龙上借羲和。\n将共两骖争舞，来随八骏齐歌。' },
  { title: '舞马词六首 三', author: '张说', poem: '彩旄八佾成行，时龙五色因方。\n屈膝衔杯赴节，倾心献寿无疆。' },
  { title: '舞马词六首 四', author: '张说', poem: '帝皂龙驹沛艾，星兰骥子权奇。\n腾倚骧洋应节，繁骄接迹不移。' },
  { title: '舞马词六首 五', author: '张说', poem: '二圣先天合德，群灵率土可封。\n击石骖驔紫燕，𪭢金顾步苍龙。' },
  { title: '舞马词六首 六', author: '张说', poem: '圣君出震应箓，神马浮河献图。\n足踏天庭鼓舞，心将帝乐踌蹰。' },
  { title: '奉和三日祓禊渭滨应制', author: '张说', poem: '青郊上巳艳阳年，紫禁皇游祓渭川。\n幸得欢娱承湛露，心同草树乐春天。' },
  { title: '桃花园马上应制', author: '张说', poem: '林间艳色骄天马，苑里秾华伴丽人。\n愿逐南风飞帝席，年年含笑舞青春。' },
  { title: '奉和圣制幸韦嗣立山庄应制', author: '张说', poem: '西京上相出扶阳，东郊别业好池塘。\n自非仁智符天赏，安能日月共回光。' },
  { title: '奉和圣制同玉真公主游大哥山池题石壁', author: '张说', poem: '池如明镜月华开，山学香炉云气来。\n神藻飞为鹡鸰赋，仙声飏出凤皇台。' },
  { title: '十五日夜御前口号踏歌词二首 一', author: '张说', poem: '花蕚楼前雨露新，长安城里太平人。\n龙衔火树千重焰，鸡踏莲花万岁春。' },
  { title: '十五日夜御前口号踏歌词二首 二', author: '张说', poem: '帝宫三五戏春台，行雨流风莫妬来。\n西域灯轮千影合，东华金阙万重开。' },
  { title: '苏摩遮五首 一', author: '张说', poem: '摩遮本出海西胡，琉璃宝服紫髯胡。\n闻道皇恩遍宇宙，来将歌舞助欢娱。' },
  { title: '苏摩遮五首 二', author: '张说', poem: '绣装帕额宝花冠，夷歌骑舞借人看。\n自能激水成阴气，不虑今年寒不寒。' },
  { title: '苏摩遮五首 三', author: '张说', poem: '腊月凝阴积帝台，豪歌急鼓送寒来。\n油囊取得天河水，将添上寿万年杯。' },
  { title: '苏摩遮五首 四', author: '张说', poem: '寒气宜人最可怜，故将寒水散庭前。\n惟愿圣君无限寿，长取新年续旧年。' },
  { title: '苏摩遮五首 五', author: '张说', poem: '昭成皇后帝家亲，荣乐诸人不比伦。\n往日霜前花委地，今年雪后树逢春。' },
  { title: '三月三日定昆池奉和萧令得潭字韵', author: '张说', poem: '暮春三月日重三，春水桃花满禊潭。\n广乐逶迤天上下，仙舟摇衍镜中酣。' },
  { title: '和尹从事懋泛洞庭', author: '张说', poem: '平湖一望上连天，林景千寻下洞泉。\n忽惊水上光华满，疑是乘舟到日边。' },
  { title: '送梁六自洞庭山作', author: '张说', poem: '巴陵一望洞庭秋，日见孤峰水上浮。\n闻道神仙不可接，心随湖水共悠悠。' },
  { title: '同赵侍御望归舟', author: '张说', poem: '山庭迥迥面长川，江树重重极远烟。\n形影相追高翥鸟，心肠倂断北风船。' },
  { title: '襄阳路逢寒食', author: '张说', poem: '去年寒食洞庭波，今年寒食襄阳路。\n不辞着处寻山水，秪畏还家落春暮。' },
  { title: '咏方圆动静示李泌', author: '张说', poem: '方如棋局，圆如棋子。\n动如棋生，静如棋死。' },
  { title: '和尹懋登南楼', author: '张均', poem: '客来已两春，更瞻韶光早。\n花鸟既环合，江山复骈抱。\n楼形写北潭，堞势凌青岛。\n白云谢归鴈，驰怀洛阳道。' },
  { title: '江上逢春', author: '张均', poem: '离忧耿未和，春虑忽蹉跎。\n择木猿知去，寻泥燕独过。\n惊花飜霁日，垂柳拂烟波。\n激意屡怡赏，无如乡念何。' },
  { title: '九日巴丘登高', author: '张均', poem: '客心惊暮序，宾鴈下沧洲。\n共赏重阳节，言寻戏马游。\n湖风扶戍柳，江雨暗山楼。\n且酌东篱酒，聊祛南国忧。' },
  { title: '和尹懋秋夜游㴩湖二首 一', author: '张均', poem: '远水沈西日，寒沙聚夜鸥。\n平湖乘月满，飞棹接星流。\n黄叶鸣凄吹，苍葭扫暗洲。\n愿移沧浦赏，归待颍川游。' },
  { title: '和尹懋秋夜游㴩湖二首 二', author: '张均', poem: '湾潭幽意深，杳霭涌寒岑。\n石痕秋水落，岚气夕阳沈。\n澄彻天为底，渊玄月作心。\n青溪非大隐，归弄白云浔。' },
  { title: '岳阳晚景', author: '张均', poem: '晚景寒鵶集，秋风旅鴈归。\n水光浮日出，霞彩暎江飞。\n洲白芦花吐，园红柿叶稀。\n长沙卑湿地，九月未成衣。' },
  { title: '流合浦岭外作', author: '张均', poem: '瘴江西去火为山，炎徼南穷鬼作关。\n从此更投人境外，生涯应在有无间。' },
  { title: '奉和岳州山城', author: '张垍', poem: '郡馆临清赏，开扃坐白云。\n讼虚棠户曙，观静竹檐曛。\n悬榻迎宾下，趋庭学礼闻。\n风传琴上意，遥向日华纷。' },
  { title: '偶游龙门北溪忽怀骊山别业因以言志示弟淑奉呈诸大僚', author: '韦嗣立', poem: '幽谷杜陵边，风烟别几年。\n偶来伊水曲，溪嶂觉依然。\n傍浦怜芳树，寻崖爱绿泉。\n岭云随马足，山鸟向人前。\n地合心俱静，言因理自玄。\n短才叨重寄，尸禄愧妨贤。\n每挹挂冠侣，思从初服旋。\n稻粱仍欲报，岁月坐空捐。\n助岳无纤块，输溟谢末涓。\n还悟北辕失，方求南涧田。' },
  { title: '奉和九日幸临渭亭登高应制得深字', author: '韦嗣立', poem: '层观远沈沈，鸾旗九日临。\n帷宫压水岸，步辇入烟岑。\n枝上萸新采，樽中菊始斟。\n愿陪欢乐事，长与岁时深。' },
  { title: '奉和张岳州王潭州别诗二首 一', author: '韦嗣立', poem: '茂先王佐才，作牧楚江隈。\n登楼正欲赋，复遇仲宣来。\n黄鹄飞将远，雕龙文为开。\n宁知昔联事，听曲有余哀。' },
  { title: '奉和张岳州王潭州别诗二首 二', author: '韦嗣立', poem: '昔时陪二贤，缨冕会神仙。\n一去驰江海，相逢共播迁。\n无因千里驾，忽覩四愁篇。\n览讽欢何已，欢终徒怆然。' },
  { title: '奉和初春幸太平公主南庄应制', author: '韦嗣立', poem: '主第岩扃架鹊桥，天门阊阖降鸾镳。\n历乱旌旗转云树，参差台榭入烟霄。\n林间花杂平阳舞，谷里莺和弄玉箫。\n已陪沁水追欢日，行奉茅山访道朝。' },
  { title: '自汤还都经龙门北溪赠张左丞崔礼部崔光禄', author: '韦嗣立', poem: '栖闲有愚谷，好事枉朝轩。\n树接前驱拥，岩传后骑喧。\n褰帘出野院，植杖候柴门。\n既拂林下席，仍携池上樽。\n深期契幽赏，实谓展欢言。\n末眷诚未易，佳游时更敦。\n俄看啸俦侣，各已共飞𬸣。\n延睇尽朝日，长怀通夜魂。\n空闻岸竹动，徒见浦花繁。\n多愧春莺曲，相求意独存。' },
  { title: '酬崔光禄冬日述怀赠答', author: '韦嗣立', poem: '亭伯负高名，羽仪称上京。\n魏珠能烛乘，秦璧许连城。\n六月飞将远，三冬学已精。\n洛阳推贾谊，江夏贵黄琼。\n推演中都术，旋参河尹声。\n累迁登御府，移拜践名卿。\n庭聚歌钟丽，门罗棨戟荣。\n鹦杯飞广席，兽火列前楹。\n散诞林园意，殷勤敬爱情。\n无容抱衰疾，良宴每招迎。\n契得心逾重，言忘道益真。\n相勗忠义节，共谈词赋英。\n雕虫曾靡弃，白凤已先鸣。\n光接神愈骇，音来味不成。\n短歌甘自思，鸿藻弥难清。\n东里方希润，西河敢窃明。\n厚诬空见迫，丧德岂无诚。\n端守宫闱地，寒烟朝暮平。\n顾才无术浅，怀器识忧盈。\n月下对云阙，风前闻夜更。\n昌年虽共偶，欢会此难幷。\n为怜漳浦曲，沈痼有刘桢。' },
  { title: '上巳日祓禊渭滨应制', author: '韦嗣立', poem: '乘春祓禊逐风光，扈跸陪銮渭渚傍。\n还笑当时水滨老，衰年八十待文王。' },
  { title: '奉酬韦祭酒偶游龙门北溪忽怀骊山别业因以言志示弟淑奉呈诸大僚之作', author: '魏奉古', poem: '有美朝为贵，幽寻地自偏。\n践临伊水汭，想望灞池边。\n是遇皆新赏，兹游若旧年。\n藤萝隐路接，杨柳御沟联。\n道惬神情王，机忘俗理捐。\n遂初诚已重，兼济实为贤。\n迹是东山恋，心惟北阙悬。\n顾慙经拾紫，多谢赋思玄。\n未躧中林步，空承丽藻传。\n阳春和已寡，扣寂竟徒然。' },
  { title: '奉酬韦祭酒偶游龙门北溪忽怀骊山别业因以言志示弟淑并呈诸大僚之作', author: '崔日知', poem: '夙龄秉微尚，中年忽有邻。\n以兹山水癖，遂得狎通人。\n迨我咸京道，闻君别业新。\n岩前窥石镜，河畔踏芳茵。\n既怜伊浦绿，复忆灞池春。\n连词谢家子，同欢冀野宾。\n趣闲鱼共乐，情洽鸟来驯。\n讵念昔游者，祇命独留秦。\n萧条颖阳恋，冲漠汉阴真。\n无由陪胜躅，空此玩书筠。' },
  { title: '冬日述怀奉呈韦祭酒张左丞兰台名贤', author: '崔日知', poem: '弱龄好经籍，披卷即怡然。\n覃精四十载，驰骋数千言。\n孔壁采遗篆，周韦考绝编。\n袁公论劒术，孙子叙兵篇。\n鲁史君臣道，姬书日月悬。\n从师改炎燠，负笈遍山川。\n上异西河夏，中非北海玄。\n光荣拾青紫，名价接通贤。\n既重万锺乐，宁思二顷田。\n长戟同分虎，高冠亚附蝉。\n晚怀重虚旷，养志息雕镌。\n登高惭思拙，匠物谢情妍。\n不慕张平子，宁希王仲宣。\n谁谓登龙日，翻成刻鹄年。\n循循劳善诱，轧轧思微牵。\n琢磨才既竭，钻仰德弥坚。\n朽木诚为谕，扪心徒自怜。\n终期吞鸟梦，振翼上云烟。\n赋成先掷地，词高直掞天。\n更执抠衣礼，仍开函丈筵。\n雾披槐市蔼，水静璧池圆。\n愿逐从风叶，飞舞翰林前。' },
  { title: '奉酬韦嗣立祭酒偶游龙门北溪忽怀骊山别业因以言志示弟淑奉呈诸大僚之作', author: '崔泰之', poem: '关塞临伊水，骊山枕灞川。\n俱临隐路侧，同在帝城边。\n谢公兼出处，携妓玩林泉。\n鸣驺喷梅雪，飞盖曳松烟。\n闻琴幽谷里，看[弈]古岩前。\n落日低帏帐，归云绕管弦。\n叨荣惭北阙，微尚爱东田。\n寂寞灰心尽，萧条尘事捐。\n朝思登嶃绝，夜梦弄潺湲。\n宿怀南涧意，况覩北谿篇。' },
  { title: '同光禄弟冬日述怀', author: '崔泰之', poem: '吾族白眉良，才华动洛阳。\n观光初入仕，应宿始为郎。\n飞萤玩书籍，白凤吐文章。\n海卿逾往雅，河尹冠前张。\n择材绥鄢郢，殊化被江湘。\n高楼临广陌，甲第敞通庄。\n列馆邙山下，疏亭洛水傍。\n昌年赏丰陌，暇日悦林塘。\n衣冠皆秀彦，罗绮尽名倡。\n隔岸闻歌度，临池见舞行。\n门庭寒变色，棨戟日生光。\n穷阴方叆叇，杀气正苍茫。\n感时兴盛作，晚岁共多伤。\n积德韦丞相，通神张子房。\n吟草徧簪绂，逸韵合宫商。\n功名守留省，滥迹在文昌。\n家园遥可见，台寺近相望。\n无庸乘侍谒，有暇共翱翔。\n棣华依雁序，竹叶拂鸾觞。\n水坐怜秋月，山行弄晚芳。\n恩华慙服冕，友爱勗垂堂。\n无由报天德，相顾咏时康。' },
  { title: '奉和圣制送张尚书巡边', author: '崔泰之', poem: '南庭胡运尽，北斗将星飞。\n旗鼓临沙漠，旌旄出洛畿。\n关山遶玉塞，烽火映金微。\n屡献帷谋策，频承庙胜威。\n躞蹀临河骑，逶迤度陇旗。\n地脉平千古，天声振九围。\n车马生边气，戈鋋驻落晖。\n夏近蓬犹转，秋深草木腓。\n饯送纡天什，恩荣赐御衣。\n伫勒燕然颂，鸣驺计日归。' },
  { title: '春夜寓直凤阁怀群公', author: '魏知古', poem: '拜门传漏晚，寓直索居时。\n昔重安仁赋，今称伯玉诗。\n鸳池满不溢，鸡树久逾滋。\n夙夜怀山甫，清风咏所思。' },
  { title: '奉和春日途中喜雨应诏', author: '魏知古', poem: '皇舆向洛城，时雨应天行。\n丽日登岩送，阴云出野迎。\n濯枝林杏发，润叶渚蒲生。\n丝入纶言喜，花依锦字明。\n微臣忝东观，载笔伫西成。' },
  { title: '从猎渭川献诗', author: '魏知古', poem: '尝闻夏太康，五弟训禽荒。\n我后来冬狩，三驱盛礼张。\n顺时鹰隼击，讲事武功扬。\n奔走未及去，翾飞岂暇翔。\n非熊从渭水，瑞翟想陈仓。\n此欲诚难纵，兹游不可常。\n子云陈羽猎，僖伯谏渔棠。\n得失鉴齐楚，仁思念禹汤。\n雍熙亮在宥，亭毒匪多伤。\n辛甲今为史，虞箴遂孔彰。' },
  { title: '玄元观寻李先生不遇', author: '魏知古', poem: '羽客今何在，空寻伊洛间。\n忽闻归苦县，复想入函关。\n未作千年别，犹应七日还。\n神仙不可见，寂寞返蓬山。' },
  { title: '招谕有怀赠同行人', author: '李乂', poem: '远游冒艰阻，深入劳存谕。\n春去辞国门，秋还在边戍。\n轩车行未返，节序催难驻。\n陌上悲转蓬，园中想芳树。\n蜀山自纷纠，岷水恒奔注。\n临泛多苦怀，登攀寡欢趣。\n永夕飞淫雨，崇朝蒸毒雾。\n不求绥岭桃，宁美邛乡蒟。\n白浪行欲静，骢马何尝驱。\n愿接轺斾尘，联翩东北骛。' },
  { title: '春日侍宴芙蓉园应制', author: '李乂', poem: '水殿临丹籞，山楼绕翠微。\n昔游人托乘，今幸帝垂衣。\n涧筿缘峰合，岩花逗浦飞。\n朝来江曲地，无处不光辉。' },
  { title: '奉和登骊山高顶寓目应制', author: '李乂', poem: '崖𪩘万寻悬，居高敞御筵。\n行戈疑驻日，步辇若登天。\n城阙雾中近，关河云外连。\n谬陪登岱驾，欣奉济汾篇。' },
  { title: '奉和七夕两仪殿会宴应制', author: '李乂', poem: '桂宫明月夜，兰殿起秋风。\n云汉弥年阻，星筵此夕同。\n倏来疑有处，旋去已成空。\n睿作钧天响，魂飞在梦中。' },
  { title: '奉和春日游苑喜雨应诏', author: '李乂', poem: '仙跸九成台，香筵万寿杯。\n一旬初降雨，二月早闻雷。\n叶向朝霁密，花含宿润开。\n幸承天泽豫，无使日光催。' },
  { title: '奉和人日清晖阁宴群臣遇雪应制', author: '李乂', poem: '上日登楼赏，中天御辇飞。\n后庭联舞唱，前席仰恩辉。\n睿作风云起，农祥雨雪霏。\n幸陪人胜节，长愿奉垂衣。' },
  { title: '陪幸临渭亭遇雪应制', author: '李乂', poem: '青阳御紫微，白云下彤闱。\n浃壤流天霈，绵区洒帝辉。\n水如银度烛，云似玉披衣。\n为得因风起，还来就日飞。' },
  { title: '奉和九日侍宴应制得浓字', author: '李乂', poem: '望幸纡千乘，登高自九重。\n台疑临戏马，殿似接疏龙。\n捧箧萸香遍，称觞菊气浓。\n更看仙鹤舞，来此庆时雍。' },
  { title: '送沙门弘景道俊玄奘还荆州应制', author: '李乂', poem: '初日承归旨，秋风起赠言。\n汉珠留道味，江璧返真源。\n地出南关远，天回北斗尊。\n宁知一柱观，却启四禅门。' },
  { title: '奉和九月九日登慈恩寺浮图应制', author: '李乂', poem: '涌塔临玄地，高层瞰紫微。\n鸣銮陪帝出，攀橑翊天飞。\n庆洽重阳寿，文含列象辉。\n小臣叨载笔，欣此颂巍巍。' },
  { title: '闰九月九日幸总持寺登浮图应制', author: '李乂', poem: '清跸幸禅楼，前驱历御沟。\n还疑九日豫，更想六年游。\n圣藻辉缨络，仙花缀冕旒。\n所欣延亿载，宁祗庆重秋。' },
  { title: '侍宴长宁公主东庄应制', author: '李乂', poem: '紫禁乘宵动，青门访水嬉。\n贵游鳣序集，仙女凤楼期。\n合宴簪绅满，承恩雨露滋。\n北辰还捧日，东馆幸逢时。' },
  { title: '幸白鹿观应制', author: '李乂', poem: '制跸乘骊阜，回舆指凤京。\n南山四皓谒，西岳两童迎。\n云幄临悬圃，霞杯荐赤城。\n神明近兹地，何必往蓬瀛。' },
  { title: '次苏州', author: '李乂', poem: '洛渚问吴潮，吴门想洛桥。\n夕烟杨柳岸，春水木兰桡。\n城邑南楼近，星辰北斗遥。\n无因生羽翼，轻举托还飙。' },
  { title: '寄胡皓时在南中', author: '李乂', poem: '徭役苦流滞，风波限溯洄。\n江流通地骨，山道绕天台。\n有鸟图南去，无人见北来。\n闭门沧海曲，云雾待君开。' },
  { title: '饯许州宋司马赴任', author: '李乂', poem: '展骥旌时杰，谈鸡美代贤。\n暂离仙掖务，追送近郊筵。\n地惨金商节，人康璧假田。\n从来昆友事，咸以佩刀传。' },
  { title: '饯唐州高使君赴任', author: '李乂', poem: '淮源之水清，可以濯君缨。\n彼美称才杰，亲人伫政声。\n岁寒畴曩意，春晚别离情。\n终叹临岐远，行看拥传荣。' },
  { title: '哭仆射鄂公杨再思', author: '李乂', poem: '端揆凝邦绩，台阶阐国猷。\n方崇大厦栋，忽逝巨川舟。\n白日铭安在，清风颂独留。\n死生恩命毕，零落掩山丘。' },
  { title: '故赵王属赠黄门侍郎上官公挽词', author: '李乂', poem: '暮归泉壤隔，朝发城池恋。\n汉畤结愁阴，秦陵下悲霰。\n骎骎百驷驰，悯悯群龙饯。\n石马徒自施，玉人终不见。' },
  { title: '淮阳公主挽歌', author: '李乂', poem: '玉颜生汉渚，汤沐荣天女。\n金缕化邙尘，哀荣感路人。\n凤皇曾作伴，蝼蚁忽为亲。\n畴日成蹊处，秾华不复春。' },
  { title: '故西台侍郎上官公挽歌', author: '李乂', poem: '宇内文儒重，朝端礼命优。\n立言多启沃，论道盛谋猷。\n顾日琴安在，冲星剑不留。\n徒怀东武襚，更掩北原丘。' },
  { title: '高安公主挽歌二首 一', author: '李乂', poem: '汤沐三千赋，楼台十二重。\n银𬬻称贵幸，玉辇盛过逢。\n嫔则留中馈，娥辉没下舂。\n平阳百岁后，歌舞为谁容。' },
  { title: '高安公主挽歌二首 二', author: '李乂', poem: '宾衞俨相依，横门启曙扉。\n灵阴蟾兔缺，仙影凤皇飞。\n一水秋难渡，三泉夜不归。\n况临青女节，瑶草更前哀。' },
  { title: '奉和初春幸太平公主南庄应制', author: '李乂', poem: '平阳馆外有仙家，沁水园中好物华。\n地出东郊回日御，城临南斗度云车。\n风泉韵绕幽林竹，雨霰光摇杂树花。\n已庆时来千亿寿，还言日暮九重赊。' },
  { title: '兴庆池侍宴应制', author: '李乂', poem: '神池泛滥水盈科，仙跸纡徐步辇过。\n纵棹洄沿萍溜合，开轩眺赏麦风和。\n潭鱼在藻供游咏，谷鸟含樱入赋歌。\n寄语乘槎溟海客，回头来此问天河。' },
  { title: '侍宴安乐公主山庄应制', author: '李乂', poem: '金舆玉辇背三条，水阁山楼望九霄。\n野外初迷七圣道，河边忽覩二灵桥。\n悬冰滴滴依虬箭，清吹泠泠杂凤箫。\n回晚平阳歌舞合，前溪更转木兰桡。' },
  { title: '奉和春日幸望春宫应制', author: '李乂', poem: '东城结宇敞千寻，北阙回舆具四临。\n丽日祥烟承罕毕，轻荑弱草藉衣簪。\n秦商重沓云岩近，河渭萦纡雾壑深。\n谬接鹓鸿陪赏乐，还欣鱼鸟遂飞沈。' },
  { title: '人日重宴大明宫恩赐彩缕人胜应制', author: '李乂', poem: '诘旦行春上苑中，凭高却下大明宫。\n千年执象寰瀛泰，七日为人庆赏隆。\n铁凤曾𬸣摇瑞雪，铜乌细转入祥风。\n此时朝野欢无算，此岁云天乐未穷。' },
  { title: '享龙池乐第八章', author: '李乂', poem: '星分邑里四人居，水洊源流万顷余。\n魏国君王称象处，晋家蕃邸化龙初。\n青蒲暂似游梁马，绿藻还疑宴镐鱼。\n自有神灵滋液地，年年云物史官书。' },
  { title: '奉和幸礼部尚书窦希玠宅应制', author: '李乂', poem: '家住千门侧，亭临二水傍。\n贵游开北地，宸眷幸西乡。\n曳履迎中谷，鸣丝出后堂。\n浦疑观万象，峰似驻三光。\n草向琼筵乐，花承绣扆香。\n圣情思旧重，留饮赋雕章。' },
  { title: '奉和晦日幸昆明池应制', author: '李乂', poem: '玉辂寻春赏，金堤重晦游。\n川通黑水浸，地派紫泉流。\n晃朗扶桑出，绵联杞树周。\n乌疑填海处，人似隔河秋。\n劫尽灰犹识，年移石故留。\n汀洲归棹晚，箫鼓杂汾讴。' },
  { title: '奉和幸长安故城未央宫应制', author: '李乂', poem: '凤辇乘春陌，龙山访故台。\n北宫才尽处，南斗独昭回。\n肆览飞宸札，称觞引御杯。\n已观蓬海变，谁厌柏梁灾。\n代挹孙通礼，朝称贾谊才。\n忝侪文雅地，先后各时来。' },
  { title: '陪幸韦嗣立山庄应制', author: '李乂', poem: '枢掖调梅暇，林园种槿初。\n入朝荣劒履，退食偶琴书。\n地隐东岩室，天回北斗车。\n旌门临䆗窱，辇道属扶疎。\n云罕明丹谷，霜笳彻紫虚。\n水疑投石处，谿似钓璜余。\n帝泽颁巵酒，人欢颂里闾。\n一承黄竹咏，长奉白茆居。' },
  { title: '奉和幸望春宫送朔方军大总管张仁亶', author: '李乂', poem: '边郊草具腓，河塞有兵机。\n上宰调梅寄，元戎细柳威。\n武貔东道出，鹰隼北庭飞。\n玉匣谋中野，金舆下太微。\n投醪衔饯酌，缉衮事征衣。\n勿谓公孙老，行闻奏凯归。' },
  { title: '奉和幸三会寺应制', author: '李乂', poem: '睿德总无边，神臯择胜缘。\n二仪齐法驾，三会礼香筵。\n汉阙中黄近，秦山太白连。\n台疑观鸟日，池似刻鲸年。\n满月临真境，秋风入御弦。\n小臣叨下列，持管谬窥天。' },
  { title: '奉和幸大荐福寺', author: '李乂', poem: '象设隆新宇，龙潜想旧居。\n碧楼披玉额，丹仗导金舆。\n代日兴光近，周星掩曜初。\n空歌清沛筑，梵乐奏胡书。\n帝造环三界，天文贲六虚。\n康哉孝理日，崇德在真如。' },
  { title: '夏日都门送司马员外逸客孙员外佺北征', author: '李乂', poem: '日逐滋南寇，天威抚北垂。\n析珪行仗节，持印且分麾。\n羽檄双凫去，兵车驷马驰。\n虎旗悬气色，龙剑抱雄雌。\n候月期戡翦，经时念别离。\n坐闻关陇外，无复引弓儿。' },
  { title: '元日恩赐柏叶应制', author: '李乂', poem: '劲节凌冬劲，芳心待岁芳。\n能令人益寿，非止麝含香。' },
  { title: '侍宴桃花园咏桃花应制', author: '李乂', poem: '绮蕚成蹊遍籞芳，红英扑地满筵香。\n莫将秋宴传王母，来比春华奉圣皇。' },
  { title: '奉和三日祓禊渭滨', author: '李乂', poem: '上林花鸟暮春时，上巳陪游乐在兹。\n此日欣逢临渭赏，昔年空道济汾词。' },
  { title: '奉和幸韦嗣立山庄侍宴应制', author: '李乂', poem: '曲榭回廊绕涧幽，飞泉喷下溢池流。\n祗应感发明王梦，遂得邀迎圣帝游。' },
  { title: '侍宴安乐公主新宅应制', author: '李乂', poem: '牵牛南渡象昭回，学凤楼成帝女来。\n平旦鹓鸾歌舞席，方宵鹦鹉献酬杯。' },
  { title: '饯唐永昌', author: '李乂', poem: '田郎才貌出咸京，潘子文华向洛城。\n愿以深心留善政，当令强项谢高名。' },
  { title: '九日幸临渭亭登高应制得开字', author: '卢藏用', poem: '上月重阳满，中天万乘来。\n萸依佩里发，菊向酒边开。\n圣泽烟云动，宸文象纬回。\n小臣无以荅，愿奉亿千杯。' },
  { title: '奉和九月九日登慈恩寺浮图应制', author: '卢藏用', poem: '化塔龙山起，中天凤辇迂。\n彩旒牵画刹，杂珮冒香萸。\n宝叶擎千座，金英渍百盂。\n秋云飘圣藻，霄极捧连珠。' },
  { title: '饯唐州高使君赴任', author: '卢藏用', poem: '饯酒临丰树，褰帷出鲁阳。\n蕙兰春已晚，桐柏路犹长。\n祖逖方城镇，安期外氏乡。\n从来二千石，天子命唯良。' },
  { title: '饯许州宋司马赴任', author: '卢藏用', poem: '国为休征选，舆因仲举题。\n山川襄野隔，朋酒灞亭暌。\n零雨征轩骛，秋风别骥嘶。\n骊歌一曲罢，愁望正凄凄。' },
  { title: '奉和立春游苑迎春应制', author: '卢藏用', poem: '天游龙辇驻城𬮱，上苑迟光晚更新。\n瑶台半入黄山路，玉槛傍临玄霸津。\n梅香欲待歌前落，兰气先过酒上春。\n幸预柏台称献寿，愿陪千亩及农晨。' },
  { title: '奉和幸安乐公主山庄应制', author: '卢藏用', poem: '皇女璚台天汉浔，星桥月宇构山林。\n飞萝半拂银题影，瀑布环流玉砌阴。\n菊浦香随鹦鹉泛，箫楼韵逐凤凰吟。\n瑶池驻跸恩方久，璧月无文兴转深。' },
  { title: '夜宴安乐公主宅', author: '卢藏用', poem: '侯家主第一时新，上席华年不惜春。\n珠釭缀日那知夜，玉斝流霞畏底晨。' },
  { title: '九月九日幸临渭亭登高应制得涘字', author: '岑羲', poem: '重九开科历，千龄逢圣纪。\n爰豫瞩秦坰，升高临灞涘。\n玉醴浮仙菊，琼筵荐芳芷。\n一闻帝舜歌，欢娱良未已。' },
  { title: '奉和九月九日登慈恩寺浮屠应制', author: '岑羲', poem: '宝台耸天外，玉辇步云端。\n日丽重阳景，风摇季月寒。\n梵堂遥集鴈，帝乐近翔鸾。\n愿献延龄酒，长承湛露欢。' },
  { title: '饯唐州高使君', author: '岑羲', poem: '苍茫南塞地，明媚上春时。\n目极伤千里，怀君不自持。\n征车别岐路，斜日下崦嵫。\n一叹轺轩阻，悠悠即所思。' },
  { title: '奉和春日幸望春宫应制', author: '岑羲', poem: '和风助律应韶年，清跸乘高入望僊。\n花笑莺歌迎帝辇，云披日霁俯皇川。\n南山近压仙楼上，北斗平临御扆前。\n一奉恩荣同镐宴，空知率舞听薰弦。' },
  { title: '奉和幸安乐公主山庄应制', author: '岑羲', poem: '银牓重楼出雾开，金舆步辇向天来。\n泉声迥入吹箫曲，山势遥临献寿杯。\n帝女含笑流飞电，干文动色象昭回。\n诚愿北极拱尧日，微臣抃舞咏康哉。' },
  { title: '夜宴安乐公主新宅', author: '岑羲', poem: '金牓重楼开夜扉，琼筵爱客未言归。\n衔欢不觉银河曙，尽醉那知玉漏稀。' },
  { title: '仪坤庙乐章二首 一', author: '薛稷', poem: '阳灵配德，阴魄昭升。\n尧坛凤下，汉室龙兴。\n伣天作对，前旒是凝。\n化行南国，道盛西陵。\n造舟集灌，无德而称。\n我粢既洁，我醴既澄。\n阴阴灵庙，光灵若凭。\n德馨惟飨，孝思烝烝。' },
  { title: '仪坤庙乐章二首 二', author: '薛稷', poem: '乾道既亨，坤元以贞。\n肃雍攸在，辅佐斯成。\n外睦九族，内光一庭。\n克生睿哲，祚我休明。\n钦若徽范，悠哉淑灵。\n建兹清宫，于彼上京。\n缩茅以献，絜秬惟馨。\n实受其福，斯乎亿龄。' },
  { title: '九日幸临渭亭登高应制得历字', author: '薛稷', poem: '暮节乘原野，宣游俯崖壁。\n秋登华实满，气严鹰隼击。\n仙菊含霜泛，圣藻临云锡。\n愿陪九九辰，长奉千千历。' },
  { title: '慈恩寺九日应制', author: '薛稷', poem: '宝宫星宿劫，香塔鬼神功。\n王游盛尘外，睿览出区中。\n日宇开初景，天词掩大风。\n微臣谢时菊，薄采入芳丛。' },
  { title: '早春鱼亭山', author: '薛稷', poem: '春气动百草，纷荣时断续。\n白云自高妙，裴回空山曲。\n阳林花已红，寒涧苔未绿。\n伊余息人事，萧寂无营欲。\n客行虽云远，玩之聊自足。' },
  { title: '秋日还京陕西十里作', author: '薛稷', poem: '驱车越陕郊，北顾临大河。\n隔河望乡邑，秋风水增波。\n西登咸阳途，日暮忧思多。\n傅岩既纡郁，首山亦嵯峨。\n操筑无昔老，采薇有遗歌。\n客游节回换，人生知几何。' },
  { title: '奉和送金城公主适西蕃应制', author: '薛稷', poem: '天道宁殊俗，慈仁乃戢兵。\n怀荒寄赤子，忍爱鞠苍生。\n月下琼娥去，星分宝婺行。\n关山马上曲，相送不胜情。' },
  { title: '春日登楼野望', author: '薛稷', poem: '凭轩聊一望，春色几芬菲。\n野外烟初合，楼前花正飞。\n娇莺弄新响，斜日散余晖。\n谁忍孤游客，言念独依依。' },
  { title: '饯许州宋司马赴任', author: '薛稷', poem: '令弟与名兄，高才振两京。\n别序闻鸿燕，离章动鹡鸰。\n远朋驰翰墨，胜地写丹青。\n风月相思夜，劳望颍川星。' },
  { title: '奉和圣制春日幸望春宫应制', author: '薛稷', poem: '九春风景足林泉，四面云霞敞御筵。\n花镂黄山绣作苑，草图玄灞锦为川。\n飞觞竞醉心回日，走马争先眼着鞭。\n喜奉仙游归路远，直言行乐不言旋。' },
  { title: '奉和幸安乐公主山庄应制', author: '薛稷', poem: '主家园囿极新规，帝郊游豫奉天仪。\n欢宴瑶台镐京集，赏赐铜山蜀道移。\n曲阁交映金精板，飞花乱下珊瑚枝。\n借问今朝八龙驾，何如昔日望仙池。' },
  { title: '秋朝览镜', author: '薛稷', poem: '客心惊落木，夜坐听秋风。\n朝日看容鬓，生涯在镜中。' },
  { title: '夜宴安乐公主新宅', author: '薛稷', poem: '秦楼宴喜月裴回，妓筵银烛满庭开。\n坐中香气排花出，扇后歌声逐酒来。' },
  { title: '饯唐永昌', author: '薛稷', poem: '河洛风烟壮市朝，送君飞凫去渐遥。\n更思明年桃李月，花红柳绿宴浮桥。' },
  { title: '九日幸临渭亭登高应制得酒字', author: '马怀素', poem: '睿赏叶通三，宸游契重九。\n兰将叶布席，菊用香浮酒。\n落日下桑榆，秋风歇杨柳。\n幸齐东户庆，希荐南山寿。' },
  { title: '奉和九月九日登慈恩寺浮图应制', author: '马怀素', poem: '季月启重阳，金舆陟宝坊。\n御旗横日道，仙塔俨云庄。\n帝跸千官从，干词七曜光。\n顾慙文墨职，无以颂时康。' },
  { title: '奉和送金城公主适西蕃应制', author: '马怀素', poem: '帝子今何去？重姻适异方。\n离情怆宸掖，别路遶关梁。\n望绝园中柳，悲缠陌上桑。\n空余愿黄鹤，东顾忆回翔。' },
  { title: '饯许州宋司马赴任', author: '马怀素', poem: '颍川开郡邑，角宿分躔野。\n君非仲举才，谁是题舆者。\n悯悯琴上鹤，萧萧路傍马。\n严程若可留，别袂希再把。' },
  { title: '饯唐州高使君赴任', author: '马怀素', poem: '外牧资贤守，斯人奉帝俞。\n淮南膺建隼，渭北暂分符。\n坐叹烟波隔，行嗟物候殊。\n何年升美课，回首北城隅。' },
  { title: '奉和立春游苑迎春应制', author: '马怀素', poem: '玄籥飞灰出洞房，青郊迎气肇初阳。\n仙舆暂下宜春苑，御醴行开荐寿觞。\n映水轻苔犹隐绿，缘堤弱柳未舒黄。\n唯有裁花饰簪鬓，恒随圣藻狎年光。' },
  { title: '奉和圣制春日幸望春宫应制', author: '马怀素', poem: '彩仗雕舆俯碧浔，行春御气发皇心。\n摇风细柳萦驰道，映日轻花出禁林。\n遍野园亭开帟幕，连堤草树狎衣簪。\n谬参西掖沾尧酒，愿沐南薰解舜琴。' },
  { title: '奉和人日䜩大明宫恩赐彩缕人胜应制', author: '马怀素', poem: '日宇千门平旦开，天容万象列昭回。\n三阳候节金为胜，百福迎祥玉作杯。\n就暖风光偏着柳，辞寒雪影半藏梅。\n何幸得参词赋职，自怜终乏马卿才。' },
  { title: '奉和幸安乐公主山庄应制', author: '马怀素', poem: '主家台沼胜平阳，帝幸欢娱乐未央。\n掩映雕窗交极浦，参差绣户绕回塘。\n泉声百处传歌曲，树影千重对舞行。\n圣酒一沾何以报，唯欣颂德奉时康。' },
  { title: '兴庆池侍宴应制', author: '马怀素', poem: '积水逶迤绕直城，[含]虚皎镜有余清。\n图云曲榭连缇幕，映日中塘间彩旌。\n赏洽犹闻箫管沸，欢留更睹木兰轻。\n无劳海上寻仙客，即此蓬莱在帝京。' },
  { title: '夜宴安乐公主宅', author: '马怀素', poem: '凤楼䆗窱凌三袭，翠幌玲珑瞰九衢。\n复道中宵留宴衎，弥令上客想踟蹰。' },
  { title: '饯唐永昌', author: '马怀素', poem: '闻君出宰洛阳隅，宾友称觞饯路衢。\n别后相思在何处？祗应关下望仙凫。' },
  { title: '明冰篇', author: '富嘉谟', poem: '北陆苍茫河海凝，南山阑干昼夜冰。\n素彩峨峨明月升，深山穷谷不自见。\n安知采斵备嘉荐，阴房涸冱掩寒扇。\n阳春二月朝始暾，春光潭沱度千门。\n明冰时出御至尊，彤庭赫赫九仪备。\n腰玉煌煌千官事，明冰毕赋周在位。\n忆昨沙漠寒风涨，昆仑长河冰始壮。\n漫汗崚嶒积亭障，噰噰鸣雁江上来。\n禁苑池台冰复开，摇青涵绿映楼台。\n豳歌七月王风始，凿冰藏用昭物轨，四时不忒千万祀。' },
  { title: '长门怨', author: '吴少微', poem: '月出映层城，孤圆上太清。\n君王眷爱歇，枕席凉风生。\n怨咽不能寝，踟蹰步前楹。\n空阶白露色，百草寒虫鸣。\n念昔金房里，犹嫌玉座轻。\n如何娇所误，长夜泣恩情。' },
  { title: '和崔侍御日用游开化寺阁', author: '吴少微', poem: '左宪多才雄，故人尤鸷鹗。\n护赠单于使，休轺太原郭。\n馆次厌烦歊，清怀寻寂寞。\n西缘十里余，北上开化阁。\n初入云树间，冥蒙未昭廓。\n渐出栏榥外，万里秋景焯。\n岁晏风落山，天寒水归壑。\n览物颂幽景，三乘动玄钥。\n但敷利解言，永用忘昏着。' },
  { title: '哭富嘉谟', author: '吴少微', poem: '吾友适不死，於戏社稷臣。\n直禄非造利，长怀大庇人。\n乃通承明籍，遘此敦牂春。\n药厉其可畏，皇穹故匪仁。\n畴昔与夫子，孰云异天伦。\n同病一相失，茫茫不重陈。\n子之文章在，其殆尼父新。\n鼓兴斡河岳，贞词毒鬼神。\n可悲不可朽，车輤没荒榛。\n圣主贤为宝，吁兹大国贫。' },
  { title: '过汉故城', author: '吴少微', poem: '大汉昔未定，强秦犹擅场。\n中原逐鹿罢，高祖郁龙骧。\n经始谋帝座，兹焉壮未央。\n规模窥栋宇，表里浚城隍。\n群后崇长乐，中朝增建章。\n句陈被兰锜，乐府奏芝房。\n翡翠明珠帐，鸳鸯白玉堂。\n清晨宝鼎食，闲夜郁金香。\n天马来东道，佳人倾北方。\n何其赫隆盛，自谓宝灵长。\n历数有时尽，哀平嗟不昌。\n冰坚成巨猾，火德遂颓纲。\n奥位匪虚校，贪天竟速亡。\n魂神吁社稷，豹虎鬬岩廊。\n金狄移灞岸，铜盘向洛阳。\n君王无处所，年代几荒凉。\n宫阙谁家域，蓁芜罥我裳。\n井田唯有草，海水变为桑。\n昔在高门内，于今岐路傍。\n余基不可识，古墓列成行。\n狐兔惊魍魉，鸱鸟吓獝狂。\n空城寒日晚，平野暮云黄。\n烈烈樊青棘，萧萧吹白杨。\n千秋幷万岁，空使咏歌伤。' },
  { title: '古意', author: '吴少微', poem: '洛阳芳树向春开，洛阳女儿平旦来。\n流车走马纷相催，折芳瑶华向曲台。\n曲台自有千万行，重花累叶间垂杨。\n北林朝日境明光，南国微风苏合香。\n可怜窈窕女，不作邯郸娼。\n妙舞轻回拂长袖，高歌浩唱发清商。\n歌终舞罢欢无极，乐往悲来长叹息。\n阳春白日不少留，红荣碧树无颜色。\n碧树风花先春度，珠帘粉泽无人顾。\n如何年少忽迟暮，坐见明月与白露。\n明月白露夜已寒，香衣锦带空珊珊。\n今日阳春一妙曲，凤皇楼上与君弹。' },
  { title: '怨歌行', author: '吴少微', poem: '城南有怨妇，含情傍芳丛。\n自谓二八时，歌舞入汉宫。\n皇恩数流眄，承幸玉堂中。\n绿柏黄花催夜酒，锦衣罗袂逐春风。\n建章西宫焕若神，燕赵美女三千人。\n君王厌德不忘新，况群艳冶纷来陈。\n是时别君不再见，三十三春长信殿。\n长信重门昼掩关，清房晓帐幽且闲。\n绮窗虫网氛尘色，文轩莺对桃李颜。\n天王贵宫不贮老，浩然含泪今来还。\n自怜春色转晚暮，试逐佳游芳草路。\n小腰丽女夺人奇，金鞍少年曾不顾。\n归来谁为夫，请谢西家妇，莫辞先醉解罗襦。' },
  { title: '陇头水', author: '员半千', poem: '路出金河道，山连玉塞门。\n旌旗云里度，杨柳曲中喧。\n喋血多壮胆，裹革无怯魂。\n严霜敛曙色，大明辞朝暾。\n尘销营卒垒，沙静都尉垣。\n雾卷白山出，风吹黄叶翻。\n将军献凯入，万里绝河源。' },
  { title: '陇右途中遭非语', author: '员半千', poem: '赵有两毛遂，鲁闻二曾参。\n慈母犹且惑，况在行路心。\n冠冕无丑士，贿赂成知己。\n名利我所无，清浊谁见理。\n敝服空逢春，缓带不着身。\n出游非怀璧，何忧乎忌人。\n正须自保爱，振衣出世尘。' },
  { title: '仪坤庙乐章', author: '员半千', poem: '孝享云毕，维彻有章。\n云感玄羽，风凄素商。\n瞻望神座，祗恋匪遑。\n礼终乐阕，肃雍锵锵。' },
  { title: '铜雀妓', author: '王适', poem: '日暮铜雀迥，秋深玉座清。\n萧森松柏望，委郁绮罗情。\n君恩不再得，妾舞为谁轻。' },
  { title: '蜀中言怀', author: '王适', poem: '独坐年将暮，常怀志不通。\n有时须问影，无事却书空。\n弃置如天外，平生似梦中。\n蓬心犹是客，华髪欲成翁。\n迹滞魂逾窘，情乖路转穷。\n别离同夜月，愁思隔秋风。\n老少悲颜驷，盈虚悟翟公。\n时来不可问，何用求童蒙。' },
  { title: '古别离', author: '王适', poem: '昔岁惊杨柳，高楼悲独守。\n今年芳树枝，孤栖怨别离。\n珠帘昼不卷，罗幔晓长垂。\n苦调琴先觉，愁容镜独知。\n频年雁度无消息，罢却鸳文何用织。\n夜还罗帐空有情，春着裙腰自无力。\n青轩桃李落纷纷，紫庭兰蕙日氛氲。\n已能顦顇今如此，更复含情一待君。' },
  { title: '江上有怀', author: '王适', poem: '湛湛江水见底清，荷花莲子傍江生。\n采莲将欲寄同心，秋风落花空复情。\n櫂歌数曲如有待，正见明月度东海。\n海上云尽月苍苍，万里分辉满洛阳。\n洛阳闺阁夜何央，蛾眉婵娟断人肠。\n寂寥金屏空自掩，青荧银烛不生光。\n应怜水宿洞庭子，今夕迢遥天一方。' },
  { title: '江滨梅', author: '王适', poem: '忽见寒梅树，开花汉水滨。\n不知春色早，疑是弄珠人。' },
  { title: '临水亭', author: '王适', poem: '高馆基曾山，微幂生花草。\n傍对野村树，下临车马道。\n清朗悟心术，幽遐备瞻讨。\n回合峰隐云，联绵渚萦岛。\n气似沧洲胜，风为青春好。\n相及盛年时，无令叹衰老。' },
  { title: '长门怨', author: '齐澣', poem: '茕茕孤思逼，寂寂长门夜。\n妾妬亦知非，君恩那不借。\n携琴就玉阶，调悲声未谐。\n将心托明月，流影入君怀。' },
  { title: '仪坤庙乐章', author: '祝钦明', poem: '閟宫实实，清庙微微。\n降格无象，馨香有依。\n式昭纂庆，方融嗣徽。\n明禋是享，神保聿归。' },
  { title: '仪坤庙乐章', author: '刘知几', poem: '妙算申帷幄，神谋出庙廷。\n两阶文物备，七德武功成。\n校猎长杨苑，屯军细柳营。\n将军献凯入，歌舞溢重城。' },
  { title: '仪坤庙乐章', author: '胡雄', poem: '送文迎武递参差，一始一终光圣仪。\n四海生人歌有庆，千龄孝享肃无亏。' },
  { title: '仪坤庙乐章', author: '张齐贤', poem: '祼圭既濯，郁鬯既陈。\n画幕云举，黄流玉醇。\n仪充献酌，礼盛众禋。\n地察惟孝，愉焉飨亲。' },
  { title: '仪坤庙乐章', author: '郑善玉', poem: '酌郁既灌，取萧方𦶟。\n笾豆静器，簠簋芬𫗣。\n鱼腊荐美，牲牷表絜。\n是戢是将，载迎载列。' },
  { title: '仪坤庙乐章', author: '丘悦', poem: '孝哉我后，冲乎廻圣。\n道映重华，德辉文命。\n慕深视箧，情殷抚镜。\n万国移命，兆人承庆。' },
  { title: '芳树', author: '沈佺期', poem: '何地早芳菲，宛在长门殿。\n夭桃色若绶，秾李光如练。\n啼鸟弄花疎，游蜂饮香遍。\n叹息春风起，飘零君不见。' },
  { title: '长安道', author: '沈佺期', poem: '秦地平如掌，层城入云汉。\n楼阁九衢春，车马千门旦。\n绿槐开复合，红尘聚还散。\n日晚鬬鸡还，经过狭斜看。' },
  { title: '有所思', author: '沈佺期', poem: '君子事行役，再空芳岁期。\n美人旷延伫，万里浮云思。\n园槿绽红艳，郊桑柔绿滋。\n坐看长夏晚，秋月照罗帏。' },
  { title: '临高台', author: '沈佺期', poem: '高台临广陌，车马纷相续。\n回首思旧乡，云山乱心曲。\n远望河流缓，周看原野绿。\n向夕林鸟还，忧来飞景促。' },
  { title: '凤笙曲', author: '沈佺期', poem: '忆昔王子晋，凤笙游云空。\n挥手弄白日，安能恋青宫。\n岂无婵娟子，结念罗帏中。\n怜寿不贵色，身世两无穷。' },
  { title: '拟古别离', author: '沈佺期', poem: '白水东悠悠，中有西行舟。\n舟行有返櫂，水去无还流。\n奈何生别者，戚戚怀远游。\n远游谁当惜，所悲会难收。\n自君阒芳躧，青阳四五遒。\n皓月掩兰室，光风虚蕙楼。\n相思无明晦，长叹累冬秋。\n离居久迟暮，高驾何淹留。' },
  { title: '辛丑岁十月上幸长安时扈从出西岳作', author: '沈佺期', poem: '西镇何穹崇，壮哉信灵造。\n诸岭皆峻秀，中峰特美好。\n傍见巨掌存，势如石东倒。\n颇闻首阳去，开坼此河道。\n磅礴压洪源，巍峨壮清昊。\n云泉纷乱瀑，天磴屹横抱。\n子先呼其巅，宫女世不老。\n下有府君庙，历载传洒扫。\n皇明应天游，十月戒丰镐。\n微未忝闲从，兼得事苹藻。\n宿心爱兹山，意欲拾灵草。\n阴壑已永閟，云窦绝探讨。\n芳月期来过，回策思方浩。' },
  { title: '和杜麟台元志春情', author: '沈佺期', poem: '嘉树满中园，氛氲罗秀色。\n不见仙山云，倚琴空太息。\n沈思若在梦，缄怨似无忆。\n青春坐南移，白日忽西匿。\n蛾眉返清镜，闺中不相识。' },
  { title: '别侍御严凝', author: '沈佺期', poem: '七泽云梦林，三湘洞庭水。\n自古传剽俗，有时逋恶子。\n令君出使车，行迈方靡靡。\n静言芟枳棘，慎勿伤兰芷。' },
  { title: '送乔随州侃', author: '沈佺期', poem: '结交三十载，同游一万里。\n情为契阔生，心由别离死。\n拜恩前后人，从宦差池起。\n今尔归汉东，明珠报知己。' },
  { title: '送友人任括州', author: '沈佺期', poem: '青春浩无际，白日乃迟迟。\n胡为赏心客，叹迈此芳时。\n瓯粤迫兹守，京阙从此辞。\n茫茫理云帆，草草念行期。\n纷吾结远佩，帐饯出河湄。\n太息东流水，盈觞难再持。' },
  { title: '饯远', author: '沈佺期', poem: '任子徇遐禄，结友开旧襟。\n撰酌辍行叹，指途勤远心。\n秋皛澄回壑，霁色肃明林。\n暧然青轩暮，浩思非所任。' },
  { title: '同工部李侍郎适访司马子微', author: '沈佺期', poem: '紫微降天仙，丹地投云藻。\n上言华顶事，中问长生道。\n华顶居最高，大壑朝阳早。\n长生术何妙，童颜后天老。\n清晨朝凤京，静夜思鸿宝。\n凭崖饮蕙气，过涧摘灵草。\n人非冢已荒，海变田应燥。\n昔尝游此郡，三霜弄溟岛。\n绪言霞上开，机事尘外扫。\n顷来迫世务，清旷未云保。\n崎岖待漏恩，怵惕司言造。\n轩皇重斋拜，汉武爱祈祷。\n顺风怀崆峒，承露在丰镐。\n泠然魏轻驭，复得散幽抱。\n柱下留伯阳，储闱登四皓。' },
  { title: '自昌乐郡溯流至白石岭下行入郴州', author: '沈佺期', poem: '兹山界夷夏，天险横寥廓。\n太史漏登探，文命限开凿。\n北流自南泻，群峰回众壑。\n驰波如电腾，激石似雷落。\n崖留盘古树，涧蓄神农药。\n乳窦何淋漓，苔藓更彩错。\n娟娟潭里虹，渺渺滩边鹤。\n岁杪应流火，天高云物薄。\n金风吹绿梢，玉露洗红箨。\n溯舟始兴廨，登践桂阳郭。\n匍匐缘修坂，穹窿曳长䋏。\n碍林阻往来，遇堰每前却。\n救艰不遑饭，毕昏无暇泊。\n濯溪宁足惧，磴道谁云恶。\n我行山水间，湍险皆不若。\n安能独见闻，书此贻京洛。' },
  { title: '过蜀龙门', author: '沈佺期', poem: '龙门非禹凿，诡怪乃天功。\n西南出巴峡，不与众山同。\n长窦亘五里，宛转复嵌空。\n伏湍喣潜石，瀑水生轮风。\n流水无昼夜，喷薄龙门中。\n潭河势不测，藻葩垂彩虹。\n我行当季月，烟景共舂融。\n江关勤亦甚，𪩘崿意难穷。\n势将息机事，炼药此山东。' },
  { title: '入衞作', author: '沈佺期', poem: '淇上风日好，纷纷沿岸多。\n绿芳幸未歇，泛滥此明波。\n采蘩忆幽吹，理棹想荆歌。\n郁然怀君子，浩旷将如何。' },
  { title: '夜泊越州逢北使', author: '沈佺期', poem: '天地降雷雨，放逐还国都。\n重以风潮事，年月戒回舻。\n容颜荒外老，心想域中愚。\n憩泊在兹夜，炎云逐斗枢。\n𫗊{风兪}萦海若，霹雳耿天吴。\n鼇抃群岛失，鲸吞众流输。\n偶逢金华使，握手泪相濡。\n饥共噬齐枣，眠共席秦蒲。\n既北思攸济，将南睿所图。\n往来固无咎，何忽惮前桴。' },
  { title: '绍隆寺', author: '沈佺期', poem: '吾从释迦久，无上师涅槃。\n探道三十载，得道天南端。\n非胜适殊方，起諠归理难。\n放弃乃良缘，世虑不曾干。\n香界萦北渚，花龛隐南峦。\n危昂阶下石，演漾窗中澜。\n云盖看木秀，天空见藤盘。\n处俗勒宴坐，居贫业行坛。\n试将有漏躯，聊作无生观。\n了然究诸品，弥觉静者安。' },
  { title: '神龙初废逐南荒途出郴口北望苏耽山', author: '沈佺期', poem: '少曾读仙史，知有苏耽君。\n流望来南国，依然会昔闻。\n泊舟问耆老，遥指孤山云。\n孤山郴郡北，不与众山群。\n重崖下萦映，嶛峣上乣纷。\n碧峰泉附落，红壁树傍分。\n选地今方尔，升天因可云。\n不才予窜迹，羽化子遗芬。\n将览成麟凤，旋惊御鬼文。\n此中迷出处，含思独氛氲。' },
  { title: '初达驩州', author: '沈佺期', poem: '流子一十八，命予偏不偶。\n配远天遂穷，到迟日最后。\n水行儋耳国，陆行雕题薮。\n魂魄游鬼门，骸骨遗鲸口。\n夜则忍饥卧，朝则抱病走。\n搔首向南荒，拭泪看北斗。\n何年赦书来？重饮洛阳酒。' },
  { title: '被弹', author: '沈佺期', poem: '知人昔不易，举非贵易失。\n尔何按国章，无罪见呵叱。\n平生守直道，遂为众所嫉。\n少以文作吏，手不曾开律。\n一旦法相持，荒忙意如漆。\n幼子双囹圄，老夫一念室。\n昆弟两三人，相次俱囚桎。\n万铄当众怒，千谤无片实。\n庶以白黑谗，显此泾渭质。\n劾吏何咆哮，晨夜闻扑抶。\n事间拾虚证，理外存枉笔。\n怀痛不见伸，抱冤竟难悉。\n穷囚多垢腻，愁坐饶虮虱。\n三日唯一饭，两旬不再栉。\n是时盛夏中，暵赫多瘵疾。\n瞪目眠欲闭，暗呜气不出。\n有风自扶摇，鼓荡无伦匹。\n安得吹浮云，令我见白日。' },
  { title: '枉系二首 一', author: '沈佺期', poem: '吾怜曾家子，昔有投杼疑。\n吾怜姬公旦，非无鸱鸮诗。\n臣子竭忠孝，君亲惑谗欺。\n萋斐离骨肉，含愁兴此辞。' },
  { title: '枉系二首 二', author: '沈佺期', poem: '昔日公冶长，非罪遇缧絏。\n圣人降其子，古来叹独绝。\n我无毫髪瑕，苦心怀冰雪。\n今代多秀士，谁能继明辙。' },
  { title: '黄鹤', author: '沈佺期', poem: '黄鹤佐丹凤，不能群白鹇。\n拂云游四海，弄影到三山。\n遥忆君轩上，来下天池间。\n明珠世不重，知有报恩环。' },
  { title: '伤王学土', author: '沈佺期', poem: '闭囚断外事，昧坐半余朞。\n有言颕叔子，亡来已一时。\n初闻宛不信，中话涕涟洏。\n痛哉玄夜重，何遽青春姿。\n忆汝曾旅食，屡空瀍涧湄。\n吾徒禄未厚，筲斗愧相贻。\n原宪贫无愁，颜回乐自持。\n诏书择才善，君为王子师。\n宠儒名可尚，论秩官犹欺。\n化往不复见，情来安可思。\n目绝毫翰洒，耳无歌讽期。\n灵柩寄何处，精魂今何之？\n恨予在丹棘，不得看素旗。\n孀妻知己叹，幼子路人悲。\n感游值商日，绝弦留此词。' },
  { title: '古镜', author: '沈佺期', poem: '莓苔翳清池，虾蟆蚀明月。\n埋落今如此，照心未尝歇。\n愿垂拂拭恩，为君鉴玄髪。' },
  { title: '凤箫曲', author: '沈佺期', poem: '八月凉风动高阁，千金丽人卷绡幕。\n已怜池上歇芳菲，不念君恩坐摇落。\n世上荣华如转蓬，朝随阡陌暮云中。\n飞燕侍寝昭阳殿，班姬饮恨长信宫。\n长信宫，昭阳殿，春来歌舞妾自知，秋至帘栊君不见。\n昔时嬴女厌世纷，学吹凤箫乘彩云。\n含情转睐向萧史，千载红颜持赠君。' },
  { title: '古歌', author: '沈佺期', poem: '落叶流风向玉台，夜寒秋思洞房开。\n水晶帘外金波下，云母窗前银汉回。\n玉阶阴阴苔藓色，君王屡綦难再得。\n璇闺窈窕秋夜长，绣户徘徊明月光。\n燕姬彩帐芙蓉色，秦女金炉兰麝香。\n北斗七星横夜半，清歌一曲断君肠。' },
  { title: '七夕曝衣篇', author: '沈佺期', poem: '君不见昔日宜春太液边，披香画阁与天连。\n灯火灼烁九微暎，香气氛氲百和然。\n此夜星繁河正白，人传织女牵牛客。\n宫中扰扰曝衣楼，天上娥娥红粉席。\n曝衣何许曛半黄，宫中彩女提玉箱。\n珠履奔腾上兰砌，金梯宛转出梅梁。\n绛河里，碧烟上，双花伏兔画屏风，四子盘龙擎斗帐。\n舒罗散縠云雾开，缀玉垂珠星汉回。\n朝霞散彩羞衣架，晚月分光劣镜台。\n上有仙人长命绺，中看玉女迎欢绣。\n玳瑁帘中别作春，珊瑚窗里翻成昼。\n椒房金屋宠新流，意气娇奢不自由。\n汉文宜惜露台费，晋武须焚前殿裘。' },
  { title: '入少密溪', author: '沈佺期', poem: '云峰苔壁绕溪斜，江路香风夹岸花。\n树密不言通鸟道，鸡鸣始觉有人家。\n人家更在深岩口，涧水周流宅前后。\n游鱼瞥瞥双钓童，伐木丁丁一樵叟。\n自言避喧非避秦，薜衣耕凿帝尧人。\n相留且待鸡黍熟，夕卧深山萝月春。' },
  { title: '霹雳引', author: '沈佺期', poem: '岁七月，火伏而金生。\n客有鼓琴于门者，奏霹雳之商声。\n始戛羽以𬴃砉，终扣宫而砰駖。\n电耀耀兮龙跃，雷阗阗兮雨冥。\n气呜唅以会雅，态歘翕以横生。\n有如驱千旗，制五兵。\n截荒虺，斮长鲸。\n孰与广陵比，意别鹤俦精而已。\n俾我雄子魄动，毅夫髪立。\n怀恩不浅，武义双辑。\n视胡若芥，剪羯如拾。\n岂徒慷慨中筵，备群娱之翕习哉。' },
  { title: '立春日内出彩花应制', author: '沈佺期', poem: '合殿春应早，开箱彩预知。\n花迎宸翰发，叶待御筵披。\n梅讶香全少，桃惊色顿移。\n轻生承剪拂，长伴万年枝。' },
  { title: '晦日浐水应制', author: '沈佺期', poem: '素浐接宸居，青门盛祓除。\n摘兰喧凤野，浮藻溢龙渠。\n苑蝶飞殊懒，宫莺啭不疎。\n星移天上入，歌舞向储胥。' },
  { title: '奉和洛阳玩雪应制', author: '沈佺期', poem: '周王甲子旦，汉后德阳宫。\n洒瑞天庭里，惊春御苑中。\n氛氲生浩气，飒杳舞回风。\n宸藻光盈尺，赓歌乐岁丰。' },
  { title: '三日梨园侍宴', author: '沈佺期', poem: '九重驰道出，三巳禊堂开。\n画鹢中流动，青龙上苑来。\n野花飘御座，河柳拂天杯。\n日晚迎祥处，笙镛下帝台。' },
  { title: '幸梨园亭观打毬应制', author: '沈佺期', poem: '今春芳苑游，接武上琼楼。\n宛转萦香骑，飘飖拂画毬。\n俯身迎未落，回辔逐傍流。\n秖为看花鸟，时时误失筹。' },
  { title: '九日临渭亭侍宴应制得长字', author: '沈佺期', poem: '御气幸金方，凭高荐羽觞。\n魏文颁菊蕋，汉武赐萸房。\n秋变铜池色，晴添银树光。\n年年重九庆，日月奉天长。' },
  { title: '岁夜安乐公主满月侍宴', author: '沈佺期', poem: '除夜子星回，天孙满月杯。\n咏歌麟趾合，箫管凤雏来。\n岁炬常然桂，春盘预折梅。\n圣皇千万寿，垂晓御楼开。' },
  { title: '安乐公主移入新宅', author: '沈佺期', poem: '初闻衡汉来，移住斗城隈。\n锦帐迎风转，琼筵拂雾开。\n马香遗旧埒，凤吹绕新台。' },
  { title: '仙萼亭初成侍宴应制', author: '沈佺期', poem: '山中气色和，宸赏第中过。\n辇路披仙掌，帷宫拂帝萝。\n泉临香涧落，峰入翠云多。\n无异登玄圃，东南望白河。' },
  { title: '送金城公主适西蕃应制', author: '沈佺期', poem: '金牓扶丹掖，银河属紫阍。\n那堪将凤女，还以嫁乌孙。\n玉就歌中怨，珠辞掌上恩。\n西戎非我匹，明主至公存。' },
  { title: '幸白鹿观应制', author: '沈佺期', poem: '紫凤真人府，斑龙太上家。\n天流芝盖下，山转桂旗斜。\n圣藻垂寒露，仙杯落晚霞。\n唯应问王母，桃作几时花。' },
  { title: '洛阳道', author: '沈佺期', poem: '九门开洛邑，双阙对河桥。\n白日青春道，轩裳半下朝。\n乘羊稚子看，拾翠美人娇。\n行乐归恒晚，香尘扑地遥。' },
  { title: '骢马', author: '沈佺期', poem: '西北五花骢，来时道向东。\n四蹄碧玉片，双眼黄金瞳。\n鞍上留明月，嘶间动朔风。\n借君驰沛艾，一战取云中。' },
  { title: '铜雀台', author: '沈佺期', poem: '昔年分鼎地，今日望陵台。\n一旦雄图尽，千秋遗令开。\n绮罗君不见，歌舞妾空来。\n恩共漳河水，东流无重回。' },
  { title: '长门怨', author: '沈佺期', poem: '月皎风泠泠，长门次掖庭。\n玉阶闻坠叶，罗幌见飞萤。\n清露凝珠缀，流尘下翠屏。\n妾心君未察，愁叹剧繁星。' },
  { title: '巫山高二首 一', author: '沈佺期', poem: '巫山峰十二，合沓隐昭回。\n俯眺琵琶峡，平看云雨台。\n古槎天外倚，瀑水日边来。\n何忍猿啼夜，荆王枕席开。' },
  { title: '巫山高二首 二', author: '沈佺期', poem: '神女向高唐，巫山下夕阳。\n裴回作行雨，婉娈逐荆王。\n电影江前落，雷声峡外长。\n霁云无处所，台馆晓苍苍。' },
  { title: '巫山高', author: '沈佺期', poem: '巫山高不极，合沓状奇新。\n暗谷疑风雨，阴崖若鬼神。\n月明三峡曙，潮满九江春。\n为问阳台客，应知入梦人。' },
  { title: '七夕', author: '沈佺期', poem: '秋近雁行稀，天高鹊夜飞。\n妆成应懒织，今夕渡河归。\n月皎宜穿线，风轻得曝衣。\n来时不可觉，神验有光辉。' },
  { title: '春闺', author: '沈佺期', poem: '铁马三军去，金闺二月还。\n边愁离上国，春梦失阳关。\n池水琉璃净，园花玳瑁斑。\n岁华空自掷，忧思不胜颜。' },
  { title: '奉和圣制同皇太子游慈恩寺应制', author: '沈佺期', poem: '肃肃莲花界，荧荧贝叶宫。\n金人来梦里，白马出城中。\n涌塔初从地，焚香欲遍空。\n天歌应春籥，非是为春风。' },
  { title: '和洛州康士曹庭芝望月有怀', author: '沈佺期', poem: '天使下西楼，光含万象秋。\n台前疑挂镜，帘外似悬钩。\n张尹将眉学，班姬取扇俦。\n佳期应借问，为报在刀头。' },
  { title: '寿阳王花烛', author: '沈佺期', poem: '仙媛乘龙夕，天孙捧雁来。\n可怜桃李树，更遶凤皇台。\n烛送香车入，花临宝扇开。\n莫令银箭晓，为尽合欢杯。' },
  { title: '陇头水', author: '沈佺期', poem: '陇山飞落叶，陇雁度寒天。\n愁见三秋水，分为两地泉。\n西流入羗郡，东下向秦川。\n征客重回首，肝肠空自怜。' },
  { title: '关山月', author: '沈佺期', poem: '汉月生辽海，朣胧出半晖。\n合昏玄菟郡，中夜白登围。\n晕落关山迥，光含霜霰微。\n将军听晓角，战马欲南归。' },
  { title: '折杨柳', author: '沈佺期', poem: '玉窗朝日暎，罗帐春风吹。\n拭泪攀杨柳，长条踠地垂。\n白花飞历乱，黄鸟思参差。\n妾自肝肠断，傍人那得知。' },
  { title: '梅花落', author: '沈佺期', poem: '铁骑几时回，金闺怨早梅。\n雪寒花已落，风暖叶应开。\n夕逐新春管，香迎小岁杯。\n盛时何足贵，书里报轮台。' },
  { title: '紫骝马', author: '沈佺期', poem: '青玉紫骝鞍，骄多影屡盘。\n荷君能剪拂，躞蹀喷桑干。\n踠足追奔易，长鸣遇赏难。\n𪭢金一万里，霜露不辞寒。' },
  { title: '上之回', author: '沈佺期', poem: '制书下关右，天子问回中。\n坛𫮃经过远，威仪侍从雄。\n黄麾摇昼日，青幰曳松风。\n回望甘泉道，龙山隐汉宫。' },
  { title: '王昭君', author: '沈佺期', poem: '非君惜鸾殿，非妾妬蛾眉。\n薄命由骄虏，无情是画师。\n嫁来胡地日，不并汉宫时。\n心苦无聊赖，何堪马上辞。' },
  { title: '被试出塞', author: '沈佺期', poem: '十年通大漠，万里出长平。\n寒日生戈劒，阴云拂斾旌。\n饥乌啼旧垒，疲马恋空城。\n辛苦臯兰北，胡霜损汉兵。' },
  { title: '牛女', author: '沈佺期', poem: '粉席秋期缓，针楼别怨多。\n奔龙争度日，飞鹊乱填河。\n失喜先临镜，含羞未解罗。\n谁能留夜色，来夕倍还梭。' },
  { title: '杂诗三首 一', author: '沈佺期', poem: '落叶惊秋妇，高砧促暝机。\n蜘蛛寻月度，萤火傍人飞。\n清镜红埃入，孤灯绿焰微。\n怨啼能至晓，独自懒缝衣。' },
  { title: '杂诗三首 二', author: '沈佺期', poem: '妾家临渭北，春梦着辽西。\n何苦朝鲜郡，年年事鼓鼙。\n燕来红壁语，莺向绿窗啼。\n为许长相忆，阑干玉筯齐。' },
  { title: '杂诗三首 三', author: '沈佺期', poem: '闻道黄龙戍，频年不解兵。\n可怜闺里月，长在汉家营。\n少妇今春意，良人昨夜情。\n谁能将旗鼓，一为取龙城。' },
  { title: '剪彩', author: '沈佺期', poem: '宫女怜芳树，裁花竞早荣。\n寒依刀尺尽，春向绮罗生。\n弱蔕盘丝发，香蕤结素成。\n纤枝幸不弃，长就玉阶倾。' },
  { title: '和中书侍郎杨再思春夜宿直', author: '沈佺期', poem: '西禁青春满，南端皓月微。\n千庐宵驾合，五夜晓钟稀。\n星斗横纶阁，天河度琐闱。\n烟光章奏里，纷向夕郎飞。' },
  { title: '和常州崔使君寒食夜', author: '沈佺期', poem: '闻道清明近，春闱向夕阑。\n行游昼不厌，风物夜宜看。\n斗柄更初转，梅香暗里残。\n无劳秉华烛，晴月在南端。' },
  { title: '和崔正谏登秋日早朝', author: '沈佺期', poem: '鸡鸣朝谒满，露白禁门秋。\n爽气临旌戟，朝光暎冕旒。\n河宗来献宝，天子命焚裘。\n独负池阳议，言从建礼游。' },
  { title: '答宁处州书', author: '沈佺期', poem: '书报天中赦，人从海上闻。\n九泉开白日，六翮起青云。\n质幸恩先贷，情孤枉未分。\n自怜泾渭别，谁与奏明君。' },
  { title: '李舍人山园送庞邵', author: '沈佺期', poem: '符传有光辉，諠諠出帝畿。\n东隣借山水，南陌驻骖𬴂。\n握手凉风至，当歌秋日微。\n高幨去勿缓，人吏待霜威。' },
  { title: '送陆侍御余庆北使', author: '沈佺期', poem: '古人贵将命，之子出𬨎轩。\n受委当不辱，随时敢赠言。\n朔途际辽海，春思绕轘辕。\n安得回白日，留欢尽绿樽。' },
  { title: '洛州萧司兵谒兄还赴洛成礼', author: '沈佺期', poem: '棠棣日光辉，高襟应序归。\n来成鸿雁聚，去作凤皇飞。\n细草乘轻传，惊花惨别衣。\n灞亭春有酒，岐路惜芬菲。' },
  { title: '饯高唐州询', author: '沈佺期', poem: '弱冠相知早，中年不见多。\n生涯在王事，客鬓各蹉跎。\n良守初分岳，嘉声即润河。\n还从汉阙下，倾耳听中和。' },
  { title: '饯唐郎中洛阳令', author: '沈佺期', poem: '一台推往妙，三史伫来修。\n应宰凫还集，辞郎雉少留。\n郊筵乘落景，亭传理残秋。\n愿以弦歌暇，芝兰想旧游。' },
  { title: '乐城白鹤寺', author: '沈佺期', poem: '碧海开龙藏，青云起雁堂。\n潮声迎法鼓，雨气湿天香。\n树接前山暗，溪承瀑水凉。\n无言谪居远，清净得空王。' },
  { title: '游少林寺', author: '沈佺期', poem: '长歌游宝地，徙倚对珠林。\n雁塔风霜古，龙池岁月深。\n绀园澄夕霁，碧殿下秋阴。\n归路烟霞晚，山蝉处处吟。' },
  { title: '岳馆', author: '沈佺期', poem: '洞壑仙人馆，孤峰玉女台。\n空蒙朝气合，窈窕夕阳开。\n流涧含轻雨，虚岩应薄雷。\n正逢鸾与鹤，歌舞出天来。' },
  { title: '早发平昌岛', author: '沈佺期', poem: '解缆春风后，鸣榔晓涨前。\n阳乌出海树，云雁下江烟。\n积气冲长岛，浮光溢大川。\n不能怀魏阙，心赏独泠然。' },
  { title: '夜宿七盘岭', author: '沈佺期', poem: '独游千里外，高卧七盘西。\n晓月临窗近，天河入户低。\n芳春平仲绿，清夜子规啼。\n浮客空留听，褒城闻曙鸡。' },
  { title: '十三四时尝从巫峡过他日偶然有思', author: '沈佺期', poem: '小度巫山峡，荆南春欲分。\n使君滩上草，神女馆前云。\n树悉江中见，猿多天外闻。\n别来如梦里，一想一氛氲。' },
  { title: '岭表逢寒食', author: '沈佺期', poem: '岭外无寒食，春来不见饧。\n洛阳新甲子，何日是清明？\n花柳争朝发，轩车满路迎。\n帝乡遥可念，肠断报亲情。' },
  { title: '驩州南亭夜望', author: '沈佺期', poem: '昨夜南亭望，分明梦洛中。\n室家谁道别，儿女案尝同。\n忽觉犹言是，沈思始悟空。\n肝肠余几寸，拭泪坐春风。' },
  { title: '少游荆湘因有是题', author: '沈佺期', poem: '岘北焚蛟浦，巴东射雉田。\n岁时宜楚俗，耆旧在襄川。\n忆昨经过处，离今二十年。\n因君访生死，相识几人全。' },
  { title: '咸阳览古', author: '沈佺期', poem: '咸阳秦帝居，千载坐盈虚。\n版筑林光尽，坛场霤听疎。\n野桥疑望日，山火类焚书。\n唯有骊峰在，空闻厚葬余。' },
  { title: '览镜', author: '沈佺期', poem: '霏霏日摇蕙，骚骚风洒莲。\n时芳固相夺，俗态岂恒坚。\n恍忽夜川里，蹉跎朝镜前。\n红颜与壮志，太息此流年。' },
  { title: '题椰子树', author: '沈佺期', poem: '日南椰子树，香褭出风尘。\n丛生调木首，圆实槟榔身。\n玉房九霄露，碧叶四时春。\n不及涂林果，移根随汉臣。' },
  { title: '同狱者叹狱中无燕', author: '沈佺期', poem: '何许乘春燕，多知辨夏台。\n三时欲并尽，双影未尝来。\n食蕋嫌丛棘，衔泥怯死灰。\n不如黄雀语，能雪冶长猜。' },
  { title: '则天门赦改年', author: '沈佺期', poem: '圣人宥天下，幽钥动圜狴。\n六甲迎黄气，三元降紫泥。\n笼僮上西鼓，振迅广阳鸡。\n歌舞将金帛，汪洋被远黎。' },
  { title: '喜赦', author: '沈佺期', poem: '去岁投荒客，今春肆眚归。\n律通幽谷暖，盆举太阳辉。\n喜气迎冤气，青衣报白衣。\n还将合浦叶，俱向洛城飞。' },
  { title: '秦州薛都督挽词', author: '沈佺期', poem: '十里绛山幽，千年汾水流。\n碑传门客建，劒是故人留。\n陇树烟含夕，山门月对秋。\n古来钟鼎盛，共尽一蒿丘。' },
  { title: '天官崔侍郎夫人卢氏挽歌', author: '沈佺期', poem: '偕老言何谬，香魂事永违。\n潘鱼从此隔，陈凤宛然飞。\n埋镜泉中暗，藏镫地下微。\n犹凭少君术，仿佛覩容辉。' },
  { title: '章怀太子靖妃挽词', author: '沈佺期', poem: '彤史佳声载，青宫懿范留。\n形将鸾镜隐，魂伴凤笙游。\n送马嘶残日，新萤落晚秋。\n不知蒿里曙，空见陇云愁。' },
  { title: '奉和立春游苑迎春', author: '沈佺期', poem: '东郊暂转迎春仗，上苑初飞行庆杯。\n风射蛟冰千片断，气冲鱼钥九关开。\n林中觅草才生蕙，殿里争花并是梅。\n歌吹衔恩归路晚，栖乌半下凤城来。' },
  { title: '人日重宴大明宫赐彩缕人胜应制', author: '沈佺期', poem: '拂旦鸡鸣仙衞陈，凭高龙首帝城春。\n千官黼帐杯前寿，百福香匳胜里人。\n山鸟初来犹怯啭，林花未发已偷新。\n天文正应韶光转，设报悬知用此辰。' },
  { title: '奉和春初幸太平公主南庄应制', author: '沈佺期', poem: '主家山第早春归，御辇春游绕翠微。\n买地铺金曾作埒，寻河取石旧支机。\n云间树色千花满，竹里泉声百道飞。\n自有神仙鸣凤曲，并将歌舞报恩晖。' },
  { title: '奉和春日幸望春宫应制', author: '沈佺期', poem: '芳郊绿野散春晴，复道离宫烟雾生。\n杨柳千条花欲绽，蒲萄百丈蔓初萦。\n林香酒气元相入，鸟啭歌声各自成。\n定是风光牵宿醉，来晨复得幸昆明。' },
  { title: '侍宴安乐公主新宅应制', author: '沈佺期', poem: '皇家贵主好神仙，别业初开云汉边。\n山出尽如鸣凤岭，池成不让饮龙川。\n妆楼翠幌教春住，舞阁金铺借日悬。\n敬从乘舆来此地，称觞献寿乐钧天。' },
  { title: '龙池篇', author: '沈佺期', poem: '龙池跃龙龙已飞，龙德先天天不违。\n池开天汉分黄道，龙向天门入紫微。\n邸第楼台多气色，君王凫雁有光辉。\n为报寰中百川水，来朝此地莫东归。' },
  { title: '兴庆池侍宴应制', author: '沈佺期', poem: '碧水澄潭暎远空，紫云香驾御微风。\n汉家城阙疑天上，秦地山川似镜中。\n向浦回舟萍已绿，分林蔽殿槿初红。\n古来徒羡横汾赏，今日宸游圣藻雄。' },
  { title: '从幸香山寺应制', author: '沈佺期', poem: '南山奕奕通丹禁，北阙峨峨连翠云。\n岭上楼台千地起，城中钟鼓四天闻。\n旃檀晓阁金舆度，鹦鹉晴林采眊分。\n愿以醍醐参圣酒，还将[衹]苑当秋汾。' },
  { title: '红楼院应制', author: '沈佺期', poem: '红楼疑见白毫光，寺逼宸居福盛唐。\n支遁爱山情谩切，昙摩泛海路空长。\n经声夜息闻天语，炉气晨飘接御香。\n谁谓此中难可到，自怜深院得徊翔。' },
  { title: '再入道场纪事应制', author: '沈佺期', poem: '南方归去再生天，内殿今年异昔年。\n见辟乾坤新定位，看题日月更高悬。\n行随香辇登仙路，坐近炉烟讲法筵。\n自喜恩深陪侍从，两朝长在圣人前。' },
  { title: '嵩山石淙侍宴应制', author: '沈佺期', poem: '金舆旦下绿云衢，彩殿晴临碧涧隅。\n溪水泠泠杂行漏，山烟片片绕香炉。\n仙人六膳调神鼎，玉女三浆捧帝壶。\n自惜汾阳纡道驾，无如太室览真图。' },
  { title: '古意呈补阙乔知之', author: '沈佺期', poem: '卢家少妇郁金堂，海燕双栖玳瑁梁。\n九月寒砧催木叶，十年征戍忆辽阳。\n白狼河北音书断，丹凤城南秋夜长。\n谁谓含愁独不见，更教明月照流黄。' },
  { title: '遥同杜员外审言过岭', author: '沈佺期', poem: '天长地阔岭头分，去国离家见白云。\n洛浦风光何所似，崇山瘴疠不堪闻。\n南浮涨海人何处？北望衡阳雁几群。' },
  { title: '和上巳连寒食有怀京洛', author: '沈佺期', poem: '天津御柳碧遥遥，轩骑相从半下朝。\n行乐光辉寒食借，太平歌舞晚春饶。\n红妆楼下东回辇，青草洲边南渡桥。\n坐见司空扫西第，看君侍从落花朝。' },
  { title: '陪幸太平公主南庄诗', author: '沈佺期', poem: '主第山门起灞川，宸游风景入初年。\n凤皇楼下交天仗，乌鹊桥头敞御筵。\n往往花间逢彩石，时时竹里见红泉。\n今朝扈跸平阳馆，不羡乘槎云汉边。' },
  { title: '守岁应制', author: '沈佺期', poem: '南渡轻冰解渭桥，东方树色起招摇。\n天子迎春取今夜，王公献寿用明朝。\n殿上灯人争烈火，宫中侲子乱驱妖。\n宜将岁酒调神药，圣祚千春万国朝。' },
  { title: '陪幸韦嗣立山庄', author: '沈佺期', poem: '台阶好赤松，别业对青峰。\n茆室承三顾，花源接九重。\n虹旗萦秀木，凤辇拂疎筇。\n迳直千官拥，溪长万骑容。\n水堂开禹膳，山阁献尧钟。\n皇鉴清居远，天文睿奖浓。\n岩泉他夕梦，渔钓往年逢。\n共荣丞相府，偏降逸人封。' },
  { title: '扈从出长安应制', author: '沈佺期', poem: '汉宅规模壮，周都景命隆。\n西宾让东主，法驾幸天中。\n太史占星应，春官奏日同。\n旌门起长乐，帐殿出新丰。\n翕习黄山下，纡徐清渭东。\n金麾张画月，珠幰戴松风。\n是节严阴始，寒郊散野蓬。\n薄霜沾上路，残雪绕离宫。\n赐帛矜耆老，褰旒问小童。\n复除恩载洽，望秩礼新崇。\n臣忝承明召，多慙献赋雄。' },
  { title: '初冬从幸汉故青门应制', author: '沈佺期', poem: '汉王建都邑，渭水对青门。\n朝市俱东逝，坟陵共北原。\n荒凉萧相阙，芜没邵平园。\n全盛今何在，英雄难重论。\n故基仍岳立，遗堞尚云屯。\n当极土功壮，安知人力烦。\n天游戒东首，怀昔驻龙轩。\n何必金汤固，无如道德藩。\n微臣谅多幸，参乘偶殊恩。\n预此陈古事，敢奏兴亡言。' },
  { title: '昆明池侍宴应制', author: '沈佺期', poem: '武帝伐昆明，穿池习五兵。\n水同河汉在，馆有豫章名。\n我后光天德，垂衣文教成。\n黩兵非帝念，劳物岂皇情。\n春仗过鲸沼，云旗出凤城。\n灵鱼衔宝跃，仙女废机迎。\n柳拂旌门暗，兰依帐殿生。\n还如流水曲，日晚棹歌清。' },
  { title: '白莲花亭侍宴应制', author: '沈佺期', poem: '九日陪天仗，三秋幸禁林。\n霜威变绿树，云气落青岑。\n水殿黄花合，山亭绛叶深。\n朱旗夹小径，宝马驻清浔。\n苑吏收寒果，饔人膳野禽。\n承欢不觉暝，遥响素秋砧。' },
  { title: '仙萼池亭侍宴应制', author: '沈佺期', poem: '步辇寻丹嶂，行宫在翠微。\n川长看鸟灭，谷转听猿稀。\n天磴扶阶迥，云泉透户飞。\n闲花开石竹，幽叶吐蔷薇。\n径狭难留骑，亭寒欲进衣。\n白龟来献寿，仙吹返彤闱。' },
  { title: '奉和晦日驾幸昆明池应制', author: '沈佺期', poem: '法驾乘春转，神池象汉廻。\n双星移旧石，孤月隐残灰。\n战鹢逢时去，恩鱼望幸来。\n山花缇骑绕，堤柳幔城开。\n思逸横汾唱，欢留宴镐杯。\n微臣雕朽质，羞覩豫章材。' },
  { title: '奉和圣制幸礼部尚书窦希玠宅', author: '沈佺期', poem: '北阙垂旒暇，南宫听履廻。\n天临翔凤转，恩向跃龙开。\n兰气薰仙帐，榴花引御杯。\n水从金穴吐，云是玉衣来。\n池影摇歌席，林香散舞台。\n不知行漏晚，清跸尚裴徊。' },
  { title: '钓竿篇', author: '沈佺期', poem: '朝日敛红烟，垂竿向绿川。\n人疑天上坐，鱼似镜中悬。\n避檝时惊透，猜钩每误牵。\n湍危不理辖，潭静欲留船。\n钓玉君徒尚，征金我未贤。\n为看芳饵下，贪得会无筌。' },
  { title: '和户部岑尚书参迹枢揆', author: '沈佺期', poem: '大君制六合，良佐参万机。\n大业永开泰，臣道日光辉。\n盐梅和鼎食，家声众所归。\n汉章题楚劒，郑武袭缁衣。\n理识当朝远，文华振古希。\n风云神契合，舟檝道心微。\n庙堂喜容与，时物逓芳菲。\n御柳垂仙掖，公槐覆礼闱。\n昔陪鹓鹭后，今望鹍鹏飞。\n徒御清风颂，巴歌聊自挥。' },
  { title: '同李舍人冬日集安乐公主山池', author: '沈佺期', poem: '尝闻天女贵，家即帝宫连。\n亭插宜春果，山冲太液泉。\n桥低乌鹊夜，台起凤皇年。\n故事犹如此，新图更可怜。\n紫岩妆阁透，青嶂妓楼悬。\n峰夺香炉巧，池偷明镜圆。\n梅花寒待雪，桂叶晚留烟。\n兴尽方投辖，金声还复传。' },
  { title: '酬苏员外味道夏晚寓直省中见赠', author: '沈佺期', poem: '并命登仙阁，分曹直礼闱。\n大官供宿膳，侍史护朝衣。\n卷幔天河入，开窗月露微。\n小池残暑退，高树早凉归。\n冠劒无时释，轩车待漏飞。\n明朝题汉柱，三署有光辉。' },
  { title: '和韦舍人早朝', author: '沈佺期', poem: '阊阖连云起，岩廊拂雾开。\n玉珂龙影度，珠履雁行来。\n长乐宵钟尽，明光晓奏催。\n一经推旧德，五字擢英才。\n俨若神仙去，纷从霄汉廻。\n千春奉休历，分禁喜趋陪。' },
  { title: '自考功员外授给事中', author: '沈佺期', poem: '南省推丹地，东曹拜琐闱。\n惠移双管笔，恩降五时衣。\n出入宜真选，遭逢每滥飞。\n器慙公理拙，才谢子云微。\n案牍遗常礼，朋僚隔等威。\n上台行揖让，中禁动光辉。\n旭日千门起，初春八舍归。\n赠兰闻宿昔，谈树隐芳菲。\n何幸盐梅处，唯忧对问机。\n省躬知任重，宁止冒荣非。' },
  { title: '和元舍人万顷临池玩月戏为新体', author: '沈佺期', poem: '春风摇碧树，秋雾卷丹台。\n复有相宜夕，池清月正开。\n玉流含吹动，金魄度云来。\n熠爚光如沸，翩翾景若摧。\n半环投积草，碎璧聚流杯。\n夜久平无焕，天晴皎未𬯎。\n镜将池作匣，珠以岸为胎。\n有美司言暇，高兴独悠哉。\n挥翰初难拟，飞名岂易陪。\n夜光殊在握，了了见沈灰。' },
  { title: '酬杨给事兼见赠台中', author: '沈佺期', poem: '子云推辨博，公理擅词雄。\n始自尚书省，旋闻给事中。\n言从温室秘，籍向琐闱通。\n顾我叨郎署，慙无草奏功。\n分曹八舍断，解袂五时空。\n宿昔陪余论，平生赖击蒙。\n神仙应东掖，云雾限南宫。\n忽枉琼瑶赠，长歌兰渚风。' },
  { title: '九真山净居寺谒无碍上人', author: '沈佺期', poem: '大士生天竺，分身化日南。\n人中出烦恼，山下即伽蓝。\n小涧香为刹，危峰石作龛。\n候禅青鸽乳，窥讲白猿参。\n藤爱云间壁，花怜石下潭。\n泉行幽供好，林挂浴衣堪。\n弟子哀无识，医王惜未谈。\n机疑闻不二，蒙昧即朝三。\n欲究因缘理，聊宽放弃慙。\n超然虎溪夕，双树下虚岚。' },
  { title: '夜游', author: '沈佺期', poem: '今夕重门启，游春得夜芳。\n月华连昼色，灯影杂星光。\n南陌青丝骑，东邻红粉妆。\n管弦遥辨曲，罗绮暗闻香。\n人拥行歌路，车攒鬬舞场。\n经过犹未已，钟鼓出长杨。' },
  { title: '登瀛州南城楼寄远', author: '沈佺期', poem: '层城起丽谯，凭览出重霄。\n兹地多形胜，中天宛寂寥。\n四荣摩鹳鹤，百拱厉风飙。\n北际燕王馆，东连秦帝桥。\n晴光七郡满，春色两河遥。\n傲睨非吾土，踌躇适远嚣。\n离居欲有赠，春草寄长谣。' },
  { title: '塞北二首 一', author: '沈佺期', poem: '虏障天骄起，秦城地脉分。\n柏坛飞五将，梅吹动三军。\n锋刃奔涛色，旌旗焰火文。\n朔风吹汗漫，飘砾洒轒辒。\n海气如秋雨，边烽似夏云。\n二庭无岁月，百战有功勋。\n形影随鱼贯，音书在雁群。\n归来拜天子，凯乐助南薰。' },
  { title: '塞北二首 二', author: '沈佺期', poem: '胡骑犯边埃，风从丑上来。\n五原烽火急，六郡羽书催。\n冰壮飞狐[冷]，霜浓候雁哀。\n将军朝授钺，战士夜衔枚。\n紫塞金河里，葱山铁勒隈。\n莲花秋劒发，桂叶晓旗开。\n秘略三军动，妖氛百战摧。\n何言投笔去，终作勒铭回。' },
  { title: '李员外秦援宅观妓', author: '沈佺期', poem: '盈盈粉署郎，五日宴春光。\n选客虚前馆，徵声徧后堂。\n玉钗翠羽饰，罗袖郁金香。\n拂黛随时广，挑鬟出意长。\n啭歌遥合态，度舞暗成行。\n巧落梅庭里，斜光暎晓妆。' },
  { title: '送韦商州弼', author: '沈佺期', poem: '会府应文昌，商山镇国阳。\n闻君监郡史，𫏐罢尚书郎。\n王事嗟相失，人情贵不忘。\n累年同画省，四海接文场。\n点翰芳春色，传杯明月光。\n故交从此去，遥忆紫芝香。' },
  { title: '夏日梁王席送张岐州', author: '沈佺期', poem: '秦鸡常下雍，周凤昔鸣岐。\n此地推雄抚，惟良寄在斯。\n家传七豹贵，人擅八龙奇。\n高传生光彩，长林叹别离。\n天人开祖席，朝采候征麾。\n翠帟当郊敞，彤幨向野披。\n芃芃秋麦盛，苒苒夏条垂。\n奏计何时入？台阶望羽仪。' },
  { title: '夏日都门送司马员外逸客孙员外佺北征', author: '沈佺期', poem: '二庭追虏骑，六月动周师。\n庙略天人授，军麾相国持。\n复言征二妙，才命重当时。\n画省连征橐，横门共别词。\n云迎出塞马，风卷度河旗。\n计日方夷寇，旋闻杕杜诗。' },
  { title: '送卢管记仙客北伐', author: '沈佺期', poem: '羽檄西北飞，交城日夜围。\n庙堂盛征选，戎幕生光辉。\n雁行度函谷，马首向金微。\n湛湛山川暮，萧萧凉气稀。\n饯途予悯默，赴敌子英威。\n今日杨朱泪，无将洒铁衣。' },
  { title: '移禁司刑', author: '沈佺期', poem: '畴昔参乡赋，中年忝吏途。\n丹唇曾学史，白首不成儒。\n天子开昌箓，群生偶大炉。\n散材仍葺厦，弱羽遽[抟]扶。\n宠迈乘轩鹤，荣过食稻凫。\n何功游画省，何德理黄枢。\n吊影慙非据，倾心事远图。\n盗泉宁止渴，恶木匪投躯。\n任直翻多毁，安身遂少徒。\n一朝逢𫄙谬，三省竟无虞。\n白简初心屈，黄纱始望孤。\n患平终不怒，持劾每相驱。\n埋劒谁当辨，偷金以自诬。\n诱言虽委答，流议亦真符。\n首夏方忧圄，高秋独向隅。\n严城看熠耀，圜户对蜘蛛。\n累饷唯妻子，披冤是友于。\n物情牵倚伏，人事限荣枯。\n门客心谁在，隣交迹倘无。\n抚襟双涕落，危坐日忧趋。\n圣旨垂明德，冤囚岂滥诛。\n会希恩免理，终望罪矜愚。\n司寇宜哀狱，台庭幸恤辜。\n汉皇虚诏上，容有报恩珠。' },
  { title: '入鬼门关', author: '沈佺期', poem: '昔传瘴江路，今到鬼门关。\n土地无人老，流移几客还。\n自从别京洛，颓鬓与衰颜。\n夕宿含沙里，晨行冈路间。\n马危千仞谷，舟险万重湾。\n问我投何地？西南尽百蛮。' },
  { title: '三日独坐驩州思忆旧游', author: '沈佺期', poem: '两京多节物，三日最遨游。\n丽日风徐卷，香尘雨暂收。\n红桃初下地，绿柳半垂沟。\n童子成春服，宫人罢射鞲。\n禊堂通汉苑，解席绕秦楼。\n束皙言谈妙，张华史汉遒。\n无亭不驻马，何浦不横舟。\n舞籥千门度，帷屏百道流。\n金丸向鸟落，芳饵接鱼投。\n濯秽怜清浅，迎祥乐献酬。\n灵刍陈欲弃，神药曝应休。\n谁念招魂节，翻为御魅囚。\n朋从天外尽，心赏日南求。\n铜柱威丹徼，朱崖镇火陬。\n炎蒸连晓夕，瘴疠满冬秋。\n西水何时贷？南方讵可留。\n无人对炉酒，宁缓去乡忧。' },
  { title: '从驩州廨宅移住山间水亭赠苏使君', author: '沈佺期', poem: '遇坎即乘流，西南到火洲。\n鬼门应苦夜，瘴浦不宜秋。\n岁贷胸穿老，朝飞鼻饮头。\n死生离骨肉，荣辱间朋游。\n弃置一身在，平生万事休。\n鹰鹯遭误逐，豺虎怯真投。\n忆昨京华子，伤今边地囚。\n愿陪鹦鹉乐，希并鹧鸪留。\n日月渝乡思，烟花换客愁。\n幸逢苏伯玉，回借水亭幽。\n山柏张青盖，江蕉卷绿油。\n乘闲无火宅，因放有渔舟。\n适越心当是，居夷迹可求。\n古来尧禅舜，何必罪驩兜。' },
  { title: '赦到不得归题江上石', author: '沈佺期', poem: '家住东京里，身投南海西。\n风烟万里隔，朝夕几行啼。\n圣主讴歌洽，贤臣法令齐。\n忽闻铜柱使，走马报金鸡。\n弃市沾皇渥，投荒漏紫泥。\n魂疲山鹤路，心醉[跕]鸢溪。\n天鉴诛元恶，宸慈恤远黎。\n五方思寄刃，万姓喜然脐。\n自幼输丹恳，何尝玷白圭。\n承言窜遐魅，雪枉间深狴。\n坟垅无由谒，京华岂重跻。\n炎方谁谓广，地尽觉天低。\n百卉杂殊怪，昆虫理赖暌。\n闭藏元不蛰，摇落反生荑。\n疟瘴因兹苦，穷愁益复迷。\n火云蒸毒雾，阳雨濯阴霓。\n周乘安交趾，王恭辑画题。\n少宽穷涸鲋，犹愍触藩羝。\n配宅隣州廨，斑苗接野畦。\n山空闻鬬象，江静见游犀。\n翰墨思诸季，裁缝忆老妻。\n小儿应离褓，幼女未攀筓。\n梦蝶翻无定，蓍龟讵有倪。\n谁能竟此曲，曲尽气酸嘶。' },
  { title: '度安海入龙编', author: '沈佺期', poem: '我来交趾郡，南与贯胸连。\n四气分寒少，三光置日偏。\n尉佗曾驭国，翁仲久游泉。\n邑屋遗甿在，鱼盐旧产传。\n越人遥捧翟，汉将下看鸢。\n北斗崇山挂，南风涨海牵。\n别离频破月，容鬓骤催年。\n昆弟推由命，妻孥割付缘。\n梦来魂尚扰，愁委疾空缠。\n虚道崩城泪，明心不应天。' },
  { title: '从崇山向越常', author: '沈佺期', poem: '朝发崇山下，暮坐越常阴。\n西从杉谷度，北上竹溪深。\n竹溪道明水，杉谷古崇岑。\n差池将不合，缭绕复相寻。\n桂叶藏金屿，藤花闭石林。\n天窗虚的的，云窦下沈沈。\n造化功偏厚，真仙迹每临。\n岂徒探怪异，聊欲缓归心。' },
  { title: '哭苏眉州崔司业二公', author: '沈佺期', poem: '涣汗天中发，伶俜海外旋。\n长沙遇太守，问旧几人全。\n国宝亡双杰，天才丧两贤。\n大名齐弱岁，高德并中年。\n礼乐羊叔子，文章王仲宣。\n相看尚玄鬓，相次入黄泉。\n流放蛮陬阔，乡关帝里偏。\n亲朋云雾拥，生死岁时传。\n崔昔挥宸翰，苏尝济巨川。\n绛衣陪下列，黄合谬差肩。\n及此俱冥昧，云谁叙播迁。\n隼舆怀旧辙，鳣馆想虚筵。\n家爱方休杵，皇慈更撤县。\n铭旌西蜀路，骑吹北邙田。\n陇树应秋矣，江帆故杳然。\n罢琴明月夜，留劒白云天。\n涕泗湘潭水，凄凉衡峤烟。\n古来修短分，神理竟难筌。' },
  { title: '哭道土刘无得', author: '沈佺期', poem: '闻有玄都客，成仙不易祈。\n蓬莱向清浅，桃杏欲芳菲。\n缩地黄泉出，升天白日飞。\n少微星夜落，高掌露朝晞。\n吐甲龙应出，衔符鸟自归。\n国人思负局，天子惜被衣。\n花月留丹洞，琴笙阁翠微。\n嗟来子桑扈，尔独返于几。' },
  { title: '寒食', author: '沈佺期', poem: '普天皆灭焰，匝地尽藏烟。\n不知何处火？来就客心然。' },
  { title: '回波词', author: '沈佺期', poem: '回波尔时佺期，流向岭外生归。\n身名已蒙齿录，袍笏未复牙绯。' },
  { title: '上巳日祓禊渭滨应制', author: '沈佺期', poem: '宝马香车清渭滨，红桃碧柳禊堂春。\n皇情尚忆垂竿佐，天祚先呈捧劒人。' },
  { title: '奉和幸韦嗣立山庄应制', author: '沈佺期', poem: '东山朝日翠屏开，北阙晴空彩仗来。\n喜遇天文七曜动，少微今夜近三台。' },
  { title: '夜宴安乐公主宅', author: '沈佺期', poem: '濯龙门外主家亲，鸣凤楼中天上人。\n自有金杯迎甲夜，还将绮席代阳春。' },
  { title: '苑中遇雪应制', author: '沈佺期', poem: '北阙彤云掩曙霞，东风吹雪舞仙家。\n琼章定少千人和，银树长芳六出花。' },
  { title: '饯唐永昌', author: '沈佺期', poem: '洛阳旧有神明宰，辇毂由来天地中。\n余邑政成何足贵，因君取则四方同。' },
  { title: '狱中闻驾幸长安二首 一', author: '沈佺期', poem: '传闻圣旨向秦京，谁念羁囚滞洛城。\n扈从由来是方朔，为申冤气在长平。' },
  { title: '狱中闻驾幸长安二首 二', author: '沈佺期', poem: '无事今朝来下狱，谁期十月是横河。\n君看鹰隼俱堪击，为报蜘蛛收网罗。' },
  { title: '邙山', author: '沈佺期', poem: '北邙山上列坟茔，万古千秋对洛城。\n城中日夕歌钟起，山上唯闻松栢声。' },
  { title: '句', author: '沈佺期', poem: '周原五稼起，云海百川归。\n愿此零陵燕，长随征斾飞。' },
  { title: '陪张燕公登南楼', author: '赵冬曦', poem: '抑郁何以欢，阴氛亦登望。\n孤岛轻雾里，行舟白波上。\n目劳西北云，心醉东南嶂。\n昔日青谿子，胡然此无状。' },
  { title: '酬燕公出湖见寄', author: '赵冬曦', poem: '纶綍有成命，旌麾不可攀。\n湘川朝目断，荆阙夕波还。\n果枉东瞻唱，兴言夕放闲。\n携琴仙洞中，置酒㴩湖上。\n芳景恣行乐，谪居忽如忘。\n聚散本相因，离情自悲怅。\n鸾翮非常戢，鹏天会昭旷。\n永怀宛洛游，曾是弹冠望。' },
  { title: '奉和张燕公早霁南楼', author: '赵冬曦', poem: '方曙跻南楼，凭轩肆遐瞩。\n物华荡暄气，春景媚晴旭。\n川霁湘山孤，林芳楚郊缛。\n列岩重叠翠，远岸逶迤绿。\n风帆摩天垠，鱼艇散弯曲。\n鸿归鹤舞送，猨叫莺声续。\n群动皆熙熙，噫予独羁束。\n常钦才子意，忌𫛳伤踡跼。\n雅尚骚人文，怀沙何迫促。\n未知二贤意，去矣从所欲。' },
  { title: '㴩湖作', author: '赵冬曦', poem: '三湖返入两山间，畜作㴩湖弯复弯。\n暑雨奔流潭正满，微霜及潦水初还。\n水还波卷谿潭涸，绿草芊芊岸崭岝。\n适来飞櫂共回旋，已复扬鞭恣行乐。\n道旁耆老步跹跹，楚言兹事不知年。\n试就湖边披草径，莫疑东海变桑田。\n君讶今时尽陵陆，我看明岁更沦涟。\n来今自昔无终始，人事回环常若是。\n应思阙下声华日，谁谓江潭旅游子。\n初贞正喜固当然，往蹇来誉宜可俟。\n盈虚用舍轮舆旋，勿学灵均远问天。' },
  { title: '和燕公岳州山城', author: '赵冬曦', poem: '为吏恩犹旧，投沙惠此蒙。\n江边悠尔处，泗上宛然同。\n访道精言合，论经大义通。\n鸣琴有真气，况已沐清风。' },
  { title: '和尹懋秋夜游㴩湖二首 一', author: '赵冬曦', poem: '政理常多暇，方舟此溯洄。\n吹笙虚洞荅，举楫便风催。\n山暗云犹辨，潭幽月稍来。\n清谿无数曲，未尽莫先回。' },
  { title: '和尹懋秋夜游㴩湖二首 二', author: '赵冬曦', poem: '烟霭夕微蒙，幽湾赏未穷。\n舣舟待初月，褰幌招远风。\n鹤声聒前浦，渔火明暗丛。\n东山云壑意，不谓尔来同。' },
  { title: '陪燕公游㴩湖', author: '赵冬曦', poem: '江上多山水，招要步马来。\n琴将天籁合，酒共鸟声催。\n岩坐攀红药，谿行爱绿苔。\n所怀非此地，游望亦裴回。' },
  { title: '荅张燕公翻着葛巾见呈之作', author: '赵冬曦', poem: '美酒值芳春，醒余气益真。\n降欢时倒履，乘兴偶翻巾。\n徐榻思方建，左车理自均。\n傲然歌一曲，一醉濯缨人。' },
  { title: '奉荅燕公', author: '赵冬曦', poem: '语别意凄凄，零陵湘水西。\n佳人金谷返，爱子洞庭迷。\n旧馆逢花发，他山值鸟啼。\n江天千里望，谁见绿苹齐。' },
  { title: '奉和圣制同二相已下群官乐游园宴', author: '赵冬曦', poem: '爽垲三秦地，芳华二月初。\n酺承奠璧罢，宴是合钱余。\n柳翠垂堪结，桃红卷欲舒。\n从容会鹓鹭，延曼戏龙鱼。\n喜气流云物，欢声浃里闾。\n圣恩将报厚，请述记言书。' },
  { title: '奉和圣制荅张说扈从南出雀鼠谷', author: '赵冬曦', poem: '轩辕应顺动，力牧正趋陪。\n道合殷为砺，时行楚有材。\n省方西礼设，振旅北京回。\n地理分中壤，天文照上台。\n寒依汾谷去，春入晋郊来。\n窃比康衢者，长歌仰大哉。' },
  { title: '奉和圣制送张说上集贤学士赐宴赋得莲字', author: '赵冬曦', poem: '浅术方观海，深恩忽见天。\n学开丹殿籍，名与石渠贤。\n良辅膺休命，微生谬采甄。\n春余仍哢鸟，夏近未舒莲。\n牋札来宸禁，衣冠集诏筵。\n史臣知醉德，欲记升中年。' },
  { title: '陪张燕公行郡竹篱', author: '赵冬曦', poem: '良臣乃国宝，麾守去承明。\n外户人无闭，浮江兽已行。\n随来晋盗逸，民化蜀风清。\n郛郭从彝典，州闾荷德声。\n小人投天涯，流落巴丘城。\n所赖中和作，优游凿与耕。' },
  { title: '和燕公别㴩湖', author: '赵冬曦', poem: '南湖美泉石，君子玩幽奇。\n湾澳陪临泛，岩峿共践窥。\n秋风赪桂竦，春景绿杨垂。\n郢路委分竹，湘滨拥去麾。\n枉帆怀胜赏，留景惜差池。\n水木且不弃，情由良可知。' },
  { title: '奉酬燕公见归田赋垂赠之作', author: '赵冬曦', poem: '穷鸟婴笼缀，孤飞任播迁。\n鹪鹩王佐用，复此挫冲天。\n楚云何掩郁，湘水亦回邅。\n怀哉愧木鴈，忽尔枉兰荃。\n愈疾同枚叔，销忧比仲宣。\n归途书可畏，弱操石犹坚。\n覆载虽云广，涔阳直块然。' },
  { title: '和张燕公耗磨日饮 一', author: '赵冬曦', poem: '上月今朝减，流传耗磨辰。\n还将不事事，同醉俗中人。' },
  { title: '和张燕公耗磨日饮 二', author: '赵冬曦', poem: '春来半月度，俗忌一朝闲。\n不酌他乡酒，无堪对楚山。' },
  { title: '奉陪张燕公登南楼', author: '尹懋', poem: '君子每垂眷，江山共流眄。\n水远林外明，岩近雾中见。\n终日西北望，何处是京县。\n屡登高春台，徒使泪如霰。' },
  { title: '秋夜陪张丞相赵侍御游㴩湖二首 一', author: '尹懋', poem: '熊轼巴陵地，鹢舟湘水浔。\n江山与势远，泉石自幽深。\n杳霭入天壑，冥茫见道心。\n超然无俗事，清宴有空林。' },
  { title: '秋夜陪张丞相赵侍御游㴩湖二首 二', author: '尹懋', poem: '江上饶奇山，巑罗云水间。\n风和树色杂，苔古石文斑。\n巴俗将千溠，㴩湖凡几湾。\n嬉游竟不尽，乘月泛舟还。' },
  { title: '同燕公泛洞庭', author: '尹懋', poem: '风光淅淅草中飘，日彩荧荧水上摇。\n幸奏潇湘云壑意，山旁容与动仙桡。' },
  { title: '奉荅燕公', author: '王琚', poem: '郡远途且艰，宜悲良自得。\n胡为心独尔，惠好在南国。\n亦既清颜披，冏然良愿克。\n与君兰时会，群物如藻饰。\n烟景惜欢赏，云山起翰墨。\n接艺奇思微，偶谈玄言直。\n永日不知倦，逾旬犹谓亟。\n如何酌离尊，移櫂巴城侧。\n浦口劳长望，舟中独太息。\n疾风吹飞帆，倏忽南与北。\n目尽不复见，怀哉无终极。\n唯当衡峰上，遥辨湖水色。' },
  { title: '美女篇', author: '王琚', poem: '东邻美女实名倡，绝代容华无比方。\n浓纤得中非短长，红素天生谁饰妆。\n桂楼椒阁木兰堂，绣户雕轩文杏梁。\n屈曲屏风绕象床，萎蕤翠帐缀香囊。\n玉台龙镜洞彻光，金炉沈烟酷烈芳。\n遥闻行佩音锵锵，含娇欲笑出洞房。\n二八三五闺心切，褰帘卷幔迎春节。\n清歌始发词怨咽，鸣琴一弄心断绝。\n借问哀怨何所为，盛年情多心自悲。\n须臾破颜倏敛态，一悲一喜倂相宜。\n何能见此不注心，惜无媒氏为传音。\n可怜盈盈直千金，谁家君子为藁砧。' },
  { title: '自荆湖入朝至岳阳奉别张燕公', author: '王琚', poem: '五载朝天子，三湘逢旧僚。\n扁舟方辍櫂，清论遂终朝。\n远树烟间没，长江地际遥。\n帝城驰梦想，归帆满风飙。' },
  { title: '游㴩湖上寺', author: '王琚', poem: '春山临远壑，水木自幽清。\n夙昔怀微尚，兹焉一放情。\n云间听弄鸟，烟上摘初英。\n地僻方无闷，逾知道思精。' },
  { title: '和张燕公湘中九日登高', author: '阴行先', poem: '重阳初启节，无射正飞灰。\n寂寞风蝉至，连翩霜鴈来。\n山棠红叶下，岸菊紫花开。\n今日桓公座，多愧孟嘉才。' },
  { title: '奉别张岳州说二首 一', author: '王熊', poem: '长沙辞旧国，洞庭逢故人。\n薰兰敦久要，披雾转相亲。\n岁月空嗟老，江山不惜春。\n忽闻黄鹤曲，更作白头新。' },
  { title: '奉别张岳州说二首 二', author: '王熊', poem: '平生共风月，倏忽间山川。\n不期交淡水，暂得欵忘年。\n兴逸方罢钓，帆开欲解船。\n离心若危斾，朝夕为君悬。' },
  { title: '入朝别张燕公', author: '梁知微', poem: '华容佳山水，之子厌承明。\n符竹纡小郡，江湖被德声。\n三年计吏入，路指巴丘城。\n凫舟才结缆，驺驾已相迎。\n别离他乡酒，委曲故人情。\n孤屿早烟薄，长波晚气清。\n辛勤方远骛，胜赏屡难幷。\n回瞻洞庭浦，日暮愁云生。' },
  { title: '桐竹赠张燕公', author: '李伯鱼', poem: '北竹青桐北，南桐绿竹南。\n竹林君早爱，桐树我初贪。\n凤栖桐不媿，凤食竹何慙。\n栖食更如此，余非凤所堪。' },
  { title: '正朝上左相张燕公', author: '杨重玄', poem: '岁去愁终在，春还命不来。\n长吁问丞相，东阁几时开。' },
  { title: '道峡似巫山', author: '朱使欣', poem: '江如晓天静，石似暮云张。\n征帆一流览，宛若巫山阳。\n楚客思归路，秦人谪异乡。\n猨鸣孤月夜，再使泪沾裳。' },
  { title: '巫山高', author: '张循之', poem: '巫山高不极，合沓状奇新。\n暗谷疑风雨，阴崖若鬼神。\n月明三峡晓，潮满九江春。\n为问阳台客，应知入梦人。' },
  { title: '送泉州李使君之任', author: '张循之', poem: '傍海皆荒服，分符重汉臣。\n云山百越路，市井十洲人。\n执玉来朝远，还珠入贡频。\n连年不见雪，到处即行春。' },
  { title: '长门怨', author: '张循之', poem: '长门落景尽，洞房秋月明。\n玉阶草露积，金屋网尘生。\n妾妬今应改，君恩惜未平。\n寄语临邛客，何时作赋成。' },
  { title: '巫山', author: '张循之', poem: '流景一何速，年华不可追。\n解佩安所赠，怨咽空自悲。' },
  { title: '送王汶宰江阴', author: '张循之', poem: '郡北乘流去，花间竟日行。\n海鱼朝满市，江鸟夜喧城。\n让酒非关病，援琴不在声。\n应缘五斗米，数日滞渊明。' },
  { title: '婺州留别邓使君', author: '张循之', poem: '西掖驰名久，东阳出守时。\n江山婺女分，风月隐侯诗。\n别恨双溪急，留欢五马迟。\n回舟暎沙屿，未远剩相思。' },
  { title: '祭汾阴乐章 太和', author: '王晙', poem: '於穆圣皇，六叶重光。\n太原刻颂，后土疏场。\n宝鼎呈符，歊云孕祥。\n礼乐备矣，降福穰穰。' },
  { title: '大堤曲', author: '张柬之', poem: '南国多佳人，莫若大堤女。\n玉床翠羽帐，宝袜莲花距。\n魂处自目成，色授开心许。\n迢迢不可见，日暮空愁予。' },
  { title: '东飞伯劳歌', author: '张柬之', poem: '青田白鹤丹山凤，婺女姮娥两相送。\n谁家绝世绮帐前，艳粉红脂映宝钿。\n窈窕玉堂褰翠幙，参差绣户悬珠箔。\n绝世三五爱红妆，冶袖长裙兰麝香。\n春去花枝俄易改，可叹年光不相待。' },
  { title: '出塞', author: '张柬之', poem: '侠客重恩光，骢马饰金装。\n瞥闻传羽檄，驰突救边荒。\n歙野山川动，嚣天旌斾扬。\n吴钩明似月，楚劒利如霜。\n电断冲胡塞，风飞出洛阳。\n转战磨笄俗，横行戴斗乡。\n手擒郅支长，面缚谷蠡王。\n将军占太白，小妇怨流黄。\n騕褭青丝骑，娉婷红粉妆。\n三春莺度曲，八月鴈成行。\n谁堪坐愁思，罗袖拂空床。' },
  { title: '与国贤良夜歌二首 一', author: '张柬之', poem: '柳台临新堰，楼堞相重复。\n窈窕凤皇姝，倾城复倾国。' },
  { title: '与国贤良夜歌二首 二', author: '张柬之', poem: '杏间花照灼，楼上月裴回。\n带娇移玉柱，含笑捧金杯。' },
  { title: '咏屏风', author: '袁恕己', poem: '绮阁云霞满，芳林草树新。\n鸟惊疑欲曙，花笑不关春。\n山对弹琴客，谿留垂钓人。\n请看车马客，行处有风尘。' },
  { title: '书怀', author: '刘幽求', poem: '心为明时尽，君门尚不容。\n田园迷径路，归去欲何从。' },
  { title: '流所赠张锡', author: '章玄同', poem: '黄叶因风下，甘从洛浦隈。\n白云何所为，还出帝乡来。' },
  { title: '临高台', author: '王易从', poem: '汉主事[祁]连，良人在高阙。\n空台寂已暮，愁坐变容髪。\n泛艳春幌风，裴回秋户月。\n可怜军书断，空使流芳歇。' },
  { title: '初出京邑有怀旧林', author: '卢僎', poem: '赋生期独得，素业守微班。\n外忝文学知，鸿渐鹓鹭间。\n内倾水木趣，筑室依近山。\n晨趋天日[晏]，夕卧江海闲。\n松风生坐隅，仙禽舞亭湾。\n曙云林下客，霁月池上颜。\n虽曰坐郊园，静默非人寰。\n时步苍龙阙，宁异白云关。\n语济岂时顾，默善忘世攀。\n世网余何触，天涯谪南蛮。\n回首思洛阳，喟然悲贞艰。' },
  { title: '稍秋晓坐阁遇舟东下扬州既事寄上族父江阳令', author: '卢僎', poem: '虎啸山城晚，猨鸣江树秋。\n红林架落照，青峡送归流。\n归流赴淮海，征帆下扬州。\n族父江阳令，盛业继前修。\n文掩崔亭伯，德齐陈太丘。\n时哉惜未与，千载且为俦。\n忆昔山阳会，长怀东上游。\n称觞阮林下，赋雪谢庭幽。\n道浓礼自略，气舒文转遒。\n高情薄云汉，酣态坐芳洲。\n接席复连轸，出入陪华辀。\n独善与兼济，语默奉良筹。\n岁月欢无已，风雨暗飕飕。\n掌宪时持节，为邦邈海头。\n子人惠虽树，苍生望且留。\n微躬趋直道，神甸忝清猷。\n仙台适西步，蛮徼忽南浮。\n宇内皆安乐，天涯独远投。\n忠信徒坚仗，神明岂默詶。\n观生海漫漫，稽命天悠悠。\n云昏巴子峡，月远吴王楼。\n怀昔明不寐，悲令岁属周。\n喟无排云翮，暂得抒离忧。\n空洒沾红泪，万里逐行舟。' },
  { title: '让帝挽歌词二首 一', author: '卢僎', poem: '泰伯玄风远，延州德让行。\n阖棺追大节，树羽册鸿名。\n地户迎天仗，皇阶失帝兄。\n还闻汉明主，遗劒泣东平。' },
  { title: '让帝挽歌词二首 二', author: '卢僎', poem: '朝天驰马绝，册帝□宫祖。\n恍惚陵庙新，萧条池馆古。\n万化一朝空，哀乐此路同。\n西园有明月，修竹韵悲风。' },
  { title: '十月梅花书赠', author: '卢僎', poem: '君不见巴乡气候与华别，年年十月梅花发。\n上苑今应雪作花，宁知此地花为雪。\n自从迁播落黔巴，三见江上开新花。\n故园风花虚洛汭，穷峡凝雪度岁华。\n花情纵似河阳好，客心倍伤边候早。\n春候飒惊楼上梅，霜威未落江潭草。\n江水侵天去不还，楼花覆帘空坐攀。\n一向花前看白发，几回梦里忆红颜。\n红颜白发云泥改，何异桑田移碧海。\n却想华年故国时，唯余一片空心在。\n空心吊影向谁陈，云台仙阁旧游人。\n傥知巴树连冬发，应怜南国气长春。' },
  { title: '岁晚还京台望城阙成口号先赠交亲', author: '卢僎', poem: '紫陌开行树，朱城出晚霞。\n犹怜惯去国，疑是梦还家。\n风弱知催柳，林青觉待花。\n交亲望归骑，几处拥年华。' },
  { title: '送苏八给事出牧徐州用芳韵', author: '卢僎', poem: '金鼎属元方，璅闱连季常。\n畏盈聊出守，分命乃维良。\n晓骑辞朝远，春帆向楚常。\n贤哉谦自牧，天下咏余芳。' },
  { title: '上幸皇太子新院应制', author: '卢僎', poem: '佳气晓葱葱，干行入震宫。\n前星移北极，少海被南风。\n视膳铜楼下，吹笙玉座中。\n训深家以正，义举俗为公。\n父子成钊合，君臣禹启同。\n仰天歌圣道，犹愧乏雕虫。' },
  { title: '奉和李令扈从温泉宫赐游骊山韦侍郎别业', author: '卢僎', poem: '风后轩皇佐，云峰谢客居。\n承恩来翠岭，缔赏出丹除。\n飞盖松谿寂，清笳玉洞虚。\n窥岩详雾豹，过水略泉鱼。\n乡入无何有，时还上古初。\n伊臯羞过狭，魏丙服麤疎。\n白雪缘情降，青霞落卷舒。\n多惭郎署在，輙继国风余。' },
  { title: '季冬送户部郎中使黔府选补', author: '卢僎', poem: '握镜均荒服，分衡得大同。\n征贤一台上，补吏五谿中。\n雨露将天泽，文章播国风。\n汉庭睽直谅，楚峡望清通。\n马逐霜鸿渐，帆沿晓月空。\n还期凤池拜，照耀列星宫。' },
  { title: '途中口号', author: '卢僎', poem: '抱玉三朝楚，怀书十上秦。\n年年洛阳陌，花鸟弄归人。' },
  { title: '南望楼', author: '卢僎', poem: '去国三巴远，登楼万里春。\n伤心江上客，不是故乡人。' },
  { title: '临川送别', author: '卢僎', poem: '秋郊日半隐，野树烟初映。\n风水正萧条，那堪动离咏。' },
  { title: '题殿前桂叶', author: '卢僎', poem: '桂树生南海，芳香隔楚山。\n今朝天上见，疑是月中攀。' },
  { title: '奉和受图温洛应制', author: '牛凤及', poem: '八神扶玉辇，六羽警瑶谿。\n戒道伊川北，通津涧水西。\n御图开洛匮，刻石与天齐。\n瑞日波中上，仙禽雾里低。\n微臣矫羽翮，抃舞接鸾鹥。' },
  { title: '雅琴篇', author: '司马逸客', poem: '亭亭峄阳树，落落千万寻。\n独抱出云节，孤生不作林。\n影摇绿波水，彩绚丹霞岑。\n直干思有托，雅志期所任。\n匠者果留盼，雕斵为雅琴。\n文以楚山玉，错以昆吾金。\n虬凤吐奇状，商征含清音。\n清音雅调感君子，一抚一弄怀知己。\n不知钟期百年余，还忆朝朝几千里。\n马卿台上应芜没，阮籍帷前空已矣。\n山情水意君不知，拂匣调弦为谁理。\n调弦拂匣倍含情，况复空山秋月明。\n陇水悲风已呜咽，离鹍别鹤更凄清。\n将军塞外多奇操，中散林间有正声。\n正声谐风雅，欲竟此曲谁知者。\n自言幽隐乏先容，不道人物知音寡。\n谁能一奏和天地，谁能再抚欢朝野。\n朝野欢娱乐未央，车马骈阗盛彩章。\n岁岁汾川事箫鼓，朝朝伊水听笙簧。\n窈窕楼台临上路，妖娆歌舞出平阳。\n弹弦本自称仁祖，吹管由来许季长。\n犹怜雅歌淡无味，渌水白云谁相贵。\n还将逸词赏幽心，不觉繁声论远意。\n传闻帝乐奏钧天，傥冀微躬备五弦。\n愿持东武宫商韵，长奉南熏亿万年。' },
  { title: '三妇艳', author: '王绍宗', poem: '大妇能调瑟，中妇咏新诗。\n小妇独无事，花庭曳履綦。\n上客且安坐，春日正迟迟。' },
  { title: '别离怨', author: '郑遂初', poem: '荡子戍辽东，连年信不通。\n尘生锦步障，花送玉屏风。\n只怨红颜改，宁辞玉簟空。\n系书春雁足，早晚到云中。' },
  { title: '寒食', author: '李崇嗣', poem: '普天皆灭焰，匝地尽藏烟。\n不知何处火？来就客心然。' },
  { title: '览镜', author: '李崇嗣', poem: '岁去红颜尽，愁来白发新。\n今朝开镜匣，疑是别逢人。' },
  { title: '独愁', author: '李崇嗣', poem: '闻道成都酒，无钱亦可求。\n不知将几斗，销得此来愁。' },
  { title: '昭君怨三首 一', author: '东方虬', poem: '汉道方全盛，朝廷足武臣。\n何须薄命妾，辛苦事和亲。' },
  { title: '昭君怨三首 二', author: '东方虬', poem: '揜泪辞丹凤，衔悲向白龙。\n单于浪惊喜，无复旧时容。' },
  { title: '昭君怨三首 三', author: '东方虬', poem: '胡地无花草，春来不似春。\n自然衣带缓，非是为腰身。' },
  { title: '春雪', author: '东方虬', poem: '春雪满空来，触处似花开。\n不知园里树，若个是真梅。' },
  { title: '逸人歌赠李山人', author: '张楚金', poem: '上有尧兮下有田，眠松阳兮漱颍流。\n其貌古，其心幽，浩歌一曲兮林壑秋。\n道险可惊兮人莫用，乐天知命兮守岩洞。\n时击磬兮嗟鸣凤，吾欲知往古之不可追，自悠悠于凡梦。' },
  { title: '谪南海过始兴广胜寺果上人房', author: '房融', poem: '零落嗟残命，萧条托胜因。\n方烧三界火，遽洗六情尘。\n隔岭天花发，凌空月殿新。\n谁令乡国梦，终此学分身。' },
  { title: '咏院中藂竹', author: '吕太一', poem: '擢擢当轩竹，青青重岁寒。\n心贞徒见赏，箨小未成竿。' },
  { title: '和吕御史咏院中藂竹', author: '张纮', poem: '闻君庭竹咏，幽意岁寒多。\n叹息为冠小，良工将奈何。' },
  { title: '闺怨', author: '张纮', poem: '去年离别雁初归，今夜裁缝萤已飞。\n征客近来音信断，不知何处寄寒衣。' },
  { title: '行路难', author: '张纮', poem: '君不见温家玉镜台，提携抱屋九重来。\n君不见相如绿绮琴，一抚一拍凤凰音。\n人生意气须及早，莫负当年行乐心。\n荆王奏曲楚妃叹，曲尽欢终夜将半。\n朱楼银阁正平生，碧草青苔坐芜漫。\n当春对酒不须疑，视日相看能几时。\n春风吹尽燕初至，此时自为称君意。\n秋露萎草鸿始归，此时衰暮与君违。\n人生翻覆何常定，谁保容颜无是非。' },
  { title: '别亲朋', author: '郑蜀宾', poem: '畏途方万里，生涯近百年。\n不知将白首，何处入黄泉。' },
  { title: '海上作', author: '宋务光', poem: '旷哉潮汐池，大矣乾坤力。\n浩浩去无际，沄沄深不测。\n崩腾翕众流，泱漭环中国。\n鳞介错殊品，氛霞饶诡色。\n天波混莫分，岛树遥难识。\n汉主探灵怪，秦王恣游陟。\n搜奇大壑东，竦望成山北。\n方术徒相误，蓬莱安可得。\n吾君略仙道，至化孚淳默。\n惊浪晏穷溟，飞航通绝域。\n马韩底厥贡，龙伯修其职。\n粤我遘休明，匪躬期正直。\n敢输鹰隼执，以间豺狼忒。\n海路行已殚，𬨎轩未皇息。\n劳歌玄月暮，旅睇沧浪极。\n魏阙渺云端，驰心附归冀。' },
  { title: '回波辞', author: '李景伯', poem: '回波尔时酒巵，微臣职在箴规。\n侍䜩既过三爵，喧哗窃恐非仪。' },
  { title: '秋晚度废关', author: '李行言', poem: '秦郊平旧险，周德眷遗黎。\n始闻清夜柝，俄见落封泥。\n物色来无限，津途去不迷。\n空亭谁问马，闲戍但鸣鸡。\n山月寒弥净，河风晓更凄。\n赠言杨伯起，非复是关西。' },
  { title: '上元', author: '郭利贞', poem: '九陌连灯影，千门度月华。\n倾城出宝骑，匝路转香车。\n烂熳惟愁晓，周游不问家。\n更逢清管发，处处落梅花。' },
  { title: '赠皇甫侍御赴都八首 一', author: '元希声', poem: '东南之美，生于会稽。\n牛斗之气，蓄于昆溪。\n有瑶者玉，连城是齐。\n有威者凤，非梧不栖。' },
  { title: '赠皇甫侍御赴都八首 二', author: '元希声', poem: '猗嗟众珍，以况君子。\n公侯之胄，必复其始。\n利器长材，温仪峻峙。' },
  { title: '赠皇甫侍御赴都八首 三', author: '元希声', poem: '道心惟微，厥用允塞。\n德辉不泯，而映邦国。\n静以有神，动而作则。\n九臯千里，其声不忒。' },
  { title: '赠皇甫侍御赴都八首 四', author: '元希声', poem: '粤在古昔，分官厥初。\n刺邪矫枉，非贤勿居。\n棱棱直指，烈烈方书。\n苍玉鸣珮，绣衣登车。' },
  { title: '赠皇甫侍御赴都八首 五', author: '元希声', poem: '绰绰夫君，是膺柱下。\n准绳有望，名器无假。\n宠盖伯山，气雄公雅。\n立朝正色，俟我能者。' },
  { title: '赠皇甫侍御赴都八首 六', author: '元希声', poem: '载怀朋情，尝接闲宴。\n好洽昆弟，官联州县。\n如彼松竹，春荣冬蒨。\n柯叶蔼然，不渝霜霰。' },
  { title: '赠皇甫侍御赴都八首 七', author: '元希声', poem: '会合非我，关山坐违。\n离鸿晓引，别叶秋飞。\n𬴂骖徐动，尊饯相依。\n远情超忽，岐路光辉。' },
  { title: '赠皇甫侍御赴都八首 八', author: '元希声', poem: '金石其心，芝兰其室。\n言语方间，音徽自溢。\n肃子风威，严子霜质。\n赠言岁暮，以保贞吉。' },
  { title: '秋庭夜月有怀', author: '李澄之', poem: '游客三江外，单栖百虑违。\n山川忆处近，形影梦中归。\n夜月明虚帐，秋风入捣衣。\n从来不惯别，况属鴈南飞。' },
  { title: '明月', author: '李如璧', poem: '三五月华流炯光，可怜怀归郢路长。\n逾江越汉津无梁，遥遥永夜思茫茫。\n昭君失宠辞上宫，蛾眉婵娟卧毡穹。\n胡人琵琶弹北风，汉家音信绝南鸿。\n昭君此时怨画工，可怜明月光[朣]胧。\n节既秋兮天向寒，沅有漪兮湘有澜。\n沅湘𫄙合淼漫漫，洛阳才子忆长安。\n可怜明月复团团，逐臣恋主心愈恪。\n弃妻思君情不薄，已悲芳岁徒沦落。\n复恐红颜坐销铄，可怜明月方照灼，向影倾身比葵藿。' },
  { title: '严陵祠', author: '洪子舆', poem: '汉主召子陵，归宿洛阳殿。\n客星今安在，隐迹犹可见。\n水石空潺湲，松篁尚葱蒨。\n岸深翠阴合，川回白云徧。\n幽径滋芜没，荒祠幂霜霰。\n垂钓想遗芳，掇苹羞野荐。\n高风激终古，语理忘荣贱。\n方騐道可尊，山林情不变。' },
  { title: '度涂山', author: '寇泚', poem: '小年弄文墨，不识戎旅难。\n一朝事鞞鼓，策马度涂山。\n涂山横地轴，万里留荒服。\n悠悠征斾远，𬴂骖一何速。\n流月挥金戈，惊风折寒木。\n行闻汉飞将，还向臯兰宿。' },
  { title: '永泰公主挽歌二首 一', author: '吴兢', poem: '秾华从妇道，厘降适诸侯。\n河汉天孙合，潇湘帝子游。\n关雎方作训，鸣凤自相求。\n可叹凌波迹，东川遂不流。' },
  { title: '永泰公主挽歌二首 二', author: '吴兢', poem: '舜华徂北渚，宸思结南阳。\n盩绶哀荣备，游轩宠悼彰。\n三川谋远日，八水宅连冈。\n无复秦楼上，吹箫下凤皇。' },
  { title: '妾薄命', author: '武平一', poem: '有女妖且丽，裴回湘水湄。\n水湄兰杜芳，采之将寄谁。\n瓠犀发皓齿，双蛾颦翠眉。\n红脸如开莲，素肤若凝脂。\n绰约多逸态，轻盈不自持。\n尝矜绝代色，复恃倾城姿。\n子夫前入侍，飞燕复当时。\n正悦掌中舞，宁哀团扇诗。\n洛川昔云遇，高唐今尚违。\n幽合禽雀噪，闲阶草露滋。\n流景一何速，年华不可追。\n解佩安所赠，怨咽空自悲。' },
  { title: '奉和登骊山高顶寓目应制', author: '武平一', poem: '銮舆上碧天，翠帟拖晴烟。\n绝崿纡仙径，层岩敞御筵。\n云披丹凤阙，日下黑龙川。\n更覩南熏奏，流声入管弦。' },
  { title: '幸梨园观打毬应制', author: '武平一', poem: '令节重遨游，分镳应彩毬。\n骖驔廻上苑，蹀躞绕通沟。\n影就红尘没，光随赭汗流。\n赏阑清景暮，歌舞乐时休。' },
  { title: '奉和幸白鹿观应制', author: '武平一', poem: '玉府凌三曜，金坛驻六龙。\n彩旒悬倒景，羽盖偃乔松。\n玄圃灵芝秀，华池瑞液浓。\n谬因沾舜渥，长愿奉尧封。' },
  { title: '侍宴安乐公主新宅应制', author: '武平一', poem: '紫汉秦楼敞，黄山鲁馆开。\n簪裾分上席，歌舞列平台。\n马既如龙至，人疑学凤来。\n幸兹联棣萼，何以接邹枚。' },
  { title: '送金城公主适西蕃', author: '武平一', poem: '广化三边静，通烟四海安。\n还将膝下爱，特副域中欢。\n圣念飞玄藻，仙仪下白兰。\n日斜征盖没，归骑动鸣鸾。' },
  { title: '奉和幸新丰温泉宫应制', author: '武平一', poem: '秦王登碣石，周后袭昆仑。\n何必在遐远，方称万宇尊。\n我皇顺时豫，星驾动轩辕。\n雄戟交驰道，清笳度国门。\n回舆长乐观，校猎上林园。\n行漏移三象，连营总八屯。\n旌摇鹦鹉谷，骑转凤皇原。\n绝壁苍苔古，灵泉碧溜温。\n参差开水殿，䆗窱敞岩轩。\n丰邑模犹在，骊宫迹尚存。\n烟松衔翠幄，雪径遶花源。\n侍从推玄草，文章召虎贲。\n深仁浃夷夏，洪造溢乾坤。\n谬忝王枚列，多慙雨露恩。' },
  { title: '奉和幸韦嗣立山庄侍宴应制', author: '武平一', poem: '三光回斗极，万骑肃钩陈。\n地若游汾水，畋疑历渭滨。\n圆塘冰写镜，遥树露成春。\n弦奏鱼听曲，机忘鸟狎人。\n筑岩思感梦，磻石想垂纶。\n落景摇红壁，层阴结翠筠。\n素风纷可尚，玄泽蔼无垠。\n薄暮清笳动，天文焕紫宸。' },
  { title: '兴庆池侍宴应制', author: '武平一', poem: '銮舆羽驾直城隈，帐殿旌门此地开。\n皎洁灵潭图日月，参差画舸结楼台。\n波摇岸影随桡转，风送荷香逐酒来。\n愿奉圣情欢不极，长游云汉几昭回。' },
  { title: '奉和立春内出彩花树应制', author: '武平一', poem: '銮辂青旗下帝台，东郊上苑望春来。\n黄莺未解林间啭，红蘂先从殿里开。\n画阁条风初变柳，银塘曲水半含苔。\n欣逢睿藻光韶律，更促霞觞畏景催。' },
  { title: '奉和正旦赐宰臣栢叶应制', author: '武平一', poem: '绿叶迎春绿，寒枝历岁寒。\n愿持柏叶寿，长奉万年欢。' },
  { title: '游泾川琴溪', author: '武平一', poem: '环潭澄晓色，叠嶂照秋影。\n幽致欣所逢，纷虑自兹屏。' },
  { title: '夜宴安乐公主宅', author: '武平一', poem: '王孙帝女下仙台，金牓珠帘入夜开。\n遽惜琼筵欢正洽，唯愁银箭晓相催。' },
  { title: '奉和圣制幸韦嗣立山庄应制', author: '武平一', poem: '鸣銮赫奕下重楼，羽盖逍遥向一丘。\n汉日唯闻白衣宠，唐年更覩赤松游。' },
  { title: '饯唐永昌', author: '武平一', poem: '闻君墨绶出丹墀，双舃飞来伫有期。\n寄谢铜街攀柳日，无忘粉署握兰时。' },
  { title: '奉和圣制立春日侍宴内殿出剪彩花应制', author: '赵彦昭', poem: '剪彩迎初候，攀条故写真。\n花随红意发，叶就绿情新。\n嫩色惊衔燕，轻香误采人。\n应为熏风拂，能令芳树春。' },
  { title: '奉和人日清晖阁宴群臣遇雪应制', author: '赵彦昭', poem: '出震乘东陆，凭高御北辰。\n祥云应早岁，瑞雪候初旬。\n庭树千花发，阶蓂七叶新。\n幸承今日宴，长奉万年春。' },
  { title: '奉和七夕两仪殿会宴应制', author: '赵彦昭', poem: '青女三秋节，黄姑七日期。\n星桥度玉珮，云阁掩罗帷。\n河气通仙掖，天文入睿词。\n今宵望灵汉，应得见蛾眉。' },
  { title: '奉和九日幸临渭亭登高应制', author: '赵彦昭', poem: '秋豫凝仙览，宸游转翠华。\n呼鹰下鸟路，戏马出龙沙。\n紫菊宜新寿，丹萸辟旧邪。\n须陪长久宴，岁岁奉吹花。' },
  { title: '奉和九月九日登慈恩寺浮屠应制', author: '赵彦昭', poem: '出豫乘秋节，登高陟梵宫。\n皇心满尘界，佛迹现虚空。\n日月宜长寿，人天得大通。\n喜闻题宝偈，受记莫由同。' },
  { title: '安乐公主移入新宅侍宴应制同用开字', author: '赵彦昭', poem: '云物中京晓，天人外馆开。\n飞桥象河汉，悬牓学蓬莱。\n北阙临仙槛，南山送寿杯。\n一窥轮奂毕，惭恧栋梁材。' },
  { title: '奉和送金城公主适西蕃应制', author: '赵彦昭', poem: '圣后经纶远，谋臣计划多。\n受降追汉策，筑馆许戎和。\n俗化乌孙垒，春生积石河。\n六龙今出饯，双鹤愿为歌。' },
  { title: '奉和圣制登骊山高顶寓目应制', author: '赵彦昭', poem: '皇情遍九垓，御辇驻昭回。\n路若随天转，人疑近日来。\n河看大禹凿，山见巨灵开。\n愿扈登封驾，常持荐寿杯。' },
  { title: '奉和幸白鹿观应制', author: '赵彦昭', poem: '云骖驱半景，星跸坐中天。\n国诞玄宗圣，家寻碧落仙。\n玉杯鸾荐寿，宝算鹤知年。\n一覩光华旦，欣承道德篇。' },
  { title: '哭仆射鄂公杨再思', author: '赵彦昭', poem: '两揆光天秩，三朝奉帝熙。\n何言集大鸟，忽此丧元龟。\n坐叹公槐落，行闻宰树悲。\n壑舟今已去，宁有济川期。' },
  { title: '人日侍䜩大明宫应制', author: '赵彦昭', poem: '宝契无为属圣人，雕舆出幸玩芳辰。\n平楼半入南山雾，飞合旁临东墅春。\n夹路秾花千树发，垂轩弱柳万条新。\n处处风光今日好，年年愿奉属车尘。' },
  { title: '奉和初春幸太平公主南庄应制', author: '赵彦昭', poem: '主第岩扃驾鹊桥，天门阊阖降鸾镳。\n历乱旌旗转云树，参差台榭入烟霄。\n林间花杂平阳舞，谷里莺和弄玉箫。\n已陪沁水追欢日，行奉茅山访道朝。' },
  { title: '奉和幸安乐公主山庄应制', author: '赵彦昭', poem: '六龙齐轸御朝曦，双鹢维舟下绿池。\n飞观仰看云外耸，浮桥直见海中移。\n灵泉巧凿天孙渚，孝笋能抽帝女枝。\n幸愿一生同草树，年年岁岁乐于斯。' },
  { title: '奉和幸大荐福寺', author: '赵彦昭', poem: '宝地龙飞后，金身佛现时。\n千花开国界，万善累皇基。\n北阙承行幸，西园属住持。\n天衣拂旧石，王舍起新祠。\n刹凤迎雕辇，幡虹驻彩旗。\n同沾小雨润，窃仰大风诗。' },
  { title: '奉和幸长安故城未央宫应制', author: '赵彦昭', poem: '夙驾移天跸，凭轩览汉都。\n寒烟收紫禁，春色绕黄图。\n旧史遗陈迹，前王失霸符。\n山河寸土尽，宫观尺椽无。\n崇高惟在德，壮丽岂为谟。\n茨室留皇鉴，熏歌盛有虞。' },
  { title: '奉和幸韦嗣立山庄侍燕应制', author: '赵彦昭', poem: '贤族唯题里，儒门但署乡。\n何如表岩洞，宸翰发辉光。\n地在兹山曲，家临郃水阳。\n六龙驻旌罕，四牡耀旗常。\n北斗临台座，东山入庙堂。\n天高羽翼近，主圣股肱良。\n野竹池亭气，村花涧谷香。\n纵然怀豹隐，空愧蹑鹓行。' },
  { title: '奉和元日赐群臣栢叶应制', author: '赵彦昭', poem: '器乏雕梁器，材非构厦材。\n但将千岁叶，常奉万年杯。' },
  { title: '苑中人日遇雪应制', author: '赵彦昭', poem: '始见青云干律吕，俄逢瑞雪应阳春。\n今日回看上林树，梅花柳絮一时新。' },
  { title: '奉和圣制幸韦嗣立山庄应制', author: '赵彦昭', poem: '廊庙心存岩壑中，銮舆瞩在灞城东。\n逍遥自在蒙庄子，汉主徒言河上公。' },
  { title: '秋朝木芙蓉', author: '赵彦昭', poem: '水面芙蓉秋已衰，繁条偏是着花迟。\n平明露滴垂红脸，似有朝愁暮落时。' },
  { title: '侍宴桃花园咏桃花应制', author: '赵彦昭', poem: '红萼竞燃春苑曙，粉茸新吐御筵开。\n长年愿奉西王母，近侍惭无东朔才。' },
  { title: '奉和九日幸临渭亭登高应制得余字', author: '萧至忠', poem: '望幸三秋暮，登高九日初。\n朱旗巡汉苑，翠帟俯秦墟。\n宠极萸房遍，恩深菊酎余。\n承欢何以荅，万亿奉宸居。' },
  { title: '奉和九月九日登慈恩寺浮图应制', author: '萧至忠', poem: '天跸三乘启，星舆六辔行。\n登高凌宝塔，极目徧王城。\n神衞空中遶，仙歌云外清。\n重阳千万寿，率舞颂升平。' },
  { title: '奉和幸安乐公主山庄应制', author: '萧至忠', poem: '西郊窈窕凤皇台，北渚平明法驾来。\n匝地金声初度曲，周堂玉溜好传杯。\n湾路分游画舟转，岸门相向碧亭开。\n微臣此时承宴乐，髣髴疑从星汉回。' },
  { title: '送张亶赴朔方应制', author: '萧至忠', poem: '命将择耆年，图功胜必全。\n光辉万乘饯，威武二庭宣。\n中衢横鼓角，旷野蔽旌旃。\n推食天厨至，投醪御酒传。\n凉风过鴈苑，杀气下鸡田。\n分阃恩何极，临岐动睿篇。' },
  { title: '陪幸长宁公主林亭', author: '萧至忠', poem: '公主林亭地，清晨降玉舆。\n画桥飞渡水，仙阁逈临虚。\n新晴看蛱蝶，早夏摘芙蕖。\n文酒娱游盛，忻叨侍从余。' },
  { title: '陪幸五王宅', author: '萧至忠', poem: '北斗枢机任，西京肺腑亲。\n畴昔王门下，今兹制幸晨。\n恩来山水被，圣作管弦新。\n遶座薰红药，当轩暗绿筠。\n摘荷才早夏，听鸟尚余春。\n行漏金徒晓，风烟是观津。' },
  { title: '三会寺应制', author: '萧至忠', poem: '岧嶤仓史台，敞朗绀园开。\n戒旦壶人警，翻霜羽骑来。\n下辇登三袭，褰旒望九垓。\n林披馆陶牓，水浸昆明灰。\n网户飞花缀，幡竿度鸟回。\n豫游仙唱动，潇洒初尘埃。' },
  { title: '荐福寺应制', author: '萧至忠', poem: '地灵传景福，天驾俨钩陈。\n佳哉藩邸旧，赫矣梵宫新。\n香塔鱼山下，禅堂鴈水滨。\n珠幡映白日，镜殿写青春。\n甚懽延故吏，大觉拯生人。\n幸承歌颂末，长奉属车[尘]。' },
  { title: '陪游上苑遇雪', author: '萧至忠', poem: '龙骖晓入望春宫，正逢春雪舞春风。\n花光倂在天文上，寒气行销御酒中。' },
  { title: '奉和九日幸临渭亭登高应制得风字', author: '李迥秀', poem: '重九临商节，登高出汉宫。\n正逢萸实满，还对菊花丛。\n霁云开就日，仙藻丽秋风。\n微臣预在镐，窃抃遂无穷。' },
  { title: '奉和九月九日登慈恩寺浮图应制', author: '李迥秀', poem: '沙界人王塔，金绳梵帝游。\n言从[祇]树赏，行玩菊丛秋。\n御酒调甘露，天花拂彩旒。\n尧年将佛日，同此庆时休。' },
  { title: '奉和幸安乐公主山庄应制', author: '李迥秀', poem: '诘旦重门闻警跸，传言太主奏山林。\n是日回舆罗万骑，此时欢喜赐千金。\n鹭羽凤箫参乐曲，荻园竹径接帷阴。\n手舞足蹈方无已，万年千岁奉薰琴。' },
  { title: '夜宴安乐公主宅', author: '李迥秀', poem: '金牓岧嶤云里开，玉箫参差天际回。\n莫惊侧弁还归路，秖为平阳歌舞催。' },
  { title: '奉和九日幸临渭亭登高应制得亭字', author: '杨廉', poem: '远目瞰秦坰，重阳坐灞亭。\n既开黄菊酒，还降紫微星。\n箫鼓谙仙曲，山河入画屏。\n幸兹陪宴喜，无以效丹青。' },
  { title: '奉和九月九日登慈恩寺浮图应制', author: '杨廉', poem: '万乘临真境，重阳眺远空。\n慈云浮鴈塔，定水映龙宫。\n宝铎含飙响，仙轮带日红。\n天文将瑞色，辉焕满寰中。' },
  { title: '奉和九日幸临渭亭登高应制得枝字', author: '韦安石', poem: '重九开秋节，得一动宸仪。\n金风飘菊蘂，玉露泫萸枝。\n睿览八纮外，天文七曜披。\n临深应在即，居高岂忘危。' },
  { title: '侍宴旋师喜捷应制', author: '韦安石', poem: '蜂蚁屯夷落，熊罴逐汉飞。\n忘躯百战后，屈指一年归。\n厚眷纾天藻，深慈解御衣。\n兴酣歌舞出，朝野叹光辉。' },
  { title: '梁王宅侍宴应制同用风字', author: '韦安石', poem: '梁园开胜景，轩驾动宸衷。\n早荷承湛露，修竹引薰风。\n九酝倾钟石，百兽协丝桐。\n小臣陪宴镐，献寿奉维嵩。' },
  { title: '奉和九日幸临渭亭登高应制得明字', author: '窦希玠', poem: '銮舆巡上苑，凤驾瞰层城。\n御座丹乌丽，宸居白鹤惊。\n玉旗萦桂叶，金杯泛菊英。\n九晨陪圣膳，万岁奉承明。' },
  { title: '奉和九日幸临渭亭登高应制得臣字', author: '陆景初', poem: '九秋光顺豫，重节霁良辰。\n登高识汉苑，问道侍轩臣。\n菊花浮秬鬯，萸房插缙绅。\n圣化边陲谧，长洲鸿雁宾。' },
  { title: '奉和九日幸临渭亭登高应制得日字', author: '郑南金', poem: '重阳玉律应，万乘金舆出。\n风起韵虞弦，云开吐尧日。\n菊花浮圣酒，茱香挂衰质。\n欲知恩煦多，顺动观秋实。' },
  { title: '奉和九日幸临渭亭登高应制得直字', author: '李咸', poem: '重阳乘令序，四野开晴色。\n日月数初幷，乾坤圣登极。\n菊黄迎酒泛，松翠凌霜直。\n游海难为深，负山徒倦力。' },
  { title: '奉和九日幸临渭亭登高应制得花字', author: '赵彦伯', poem: '九日报仙家，三秋转岁华。\n呼鹰下鸟路，戏马出龙沙。\n簪挂丹萸蘂，杯浮紫菊花。\n所愿同微物，年年共辟邪。' },
  { title: '从宴桃花园咏桃花应制', author: '赵彦伯', poem: '红萼竞燃春苑曙，䒠茸新吐御筵开。\n长年愿奉西王䜩，近侍惭无东朔才。' },
  { title: '苑中遇雪应制', author: '赵彦伯', poem: '千钟圣酒御筵披，六出祥英乱遶枝。\n即此神仙对琼圃，何烦辙迹向瑶池。' },
  { title: '奉和九日幸临渭亭登高应制得樽字', author: '于经野', poem: '御气三秋节，登高九曲门。\n桂筵罗玉俎，菊醴溢芳樽。\n遵渚归鸿度，承云舞鹤𬸣。\n微臣滥陪赏，空荷圣明恩。' },
  { title: '奉和九日幸临渭亭登高应制得还字', author: '卢怀慎', poem: '时和素秋节，宸豫紫机关。\n鹤似闻琴至，人疑宴镐还。\n旷望临平野，潺湲俯瞑湾。\n无因酬大德，空此媿崇班。' },
  { title: '奉和圣制龙池篇', author: '卢怀慎', poem: '代邸东南龙跃泉，清漪碧浪远浮天。\n楼台影就波中出，日月光疑镜里悬。\n雁沼洄流成舜海，龟书荐社应尧年。\n大川既济慙为楫，报德空思奉细涓。' },
  { title: '奉和九月九日登慈恩寺浮图应制', author: '辛替否', poem: '洪慈均动植，至德俯深玄。\n出豫从初地，登高适梵天。\n白云飞御藻，慧日暖皇编。\n别有秋原藿，长倾雨露缘。' },
  { title: '奉和九月九日登慈恩寺浮图应制', author: '王景', poem: '玉辇移中禁，珠梯览四禅。\n重阶清汉接，飞窦紫霄悬。\n缀叶披天藻，吹花散御筵。\n无因銮跸暇，俱舞鹤林前。' },
  { title: '奉和九月九日登慈恩寺浮图应制', author: '毕干泰', poem: '鹦林花塔启，凤辇顺时游。\n重九昭皇庆，大千扬帝休。\n耆阇妙法阐，王舍睿文流。\n至德覃无极，小臣歌讵酬。' },
  { title: '奉和九月九日登慈恩寺浮图应制', author: '曲瞻', poem: '扈跸游玄地，陪仙瞰紫微。\n似迈铢衣刼，将同羽化飞。\n雕戈秋日丽，宝劒晓霜霏。\n献觞乘菊序，长愿奉天晖。' },
  { title: '奉和九月九日登慈恩寺浮图应制', author: '樊忱', poem: '净境重阳节，仙游万乘来。\n插萸登鹫岭，把菊坐蜂台。\n十地祥云合，三天瑞景开。\n秋风词更远，窃抃乐康哉。' },
  { title: '奉和九月九日登慈恩寺浮图应制', author: '孙佺', poem: '应节萸房满，初寒菊圃新。\n龙旗焕辰极，凤驾俨香𬮱。\n莲井偏宜夏，梅梁更若春。\n一忻陪鴈塔，还似得天身。' },
  { title: '奉和九月九日登慈恩寺浮图应制', author: '李从远', poem: '九月从时豫，三乘为法开。\n中霄日天子，半座宝如来。\n摘果珠盘献，攀萸玉辇回。\n愿将尘露点，遥奉光明台。' },
  { title: '奉和九月九日登慈恩寺浮图应制', author: '周利用', poem: '出豫乘金节，飞文焕日宫。\n萸房开圣酒，杏苑被玄功。\n塔向三天迥，禅收八解空。\n叨恩奉兰藉，终愧洽薰风。' },
  { title: '奉和九月九日登慈恩寺浮图应制', author: '张景源', poem: '飞塔凌霄起，宸游一届焉。\n金壶新泛菊，宝座即披莲。\n就日摇香辇，凭云出梵天。\n祥氛与佳色，相伴杂𬬻烟。' },
  { title: '奉和九月九日登慈恩寺浮图应制', author: '李恒', poem: '宝地隣丹掖，香台瞰碧云。\n河山天外出，城阙树中分。\n睿藻兰英秀，仙杯菊蘂薰。\n愿将今日乐，长奉圣明君。' },
  { title: '奉和九月九日登慈恩寺浮图应制', author: '张锡', poem: '九秋霜景净，千门晓望通。\n仙游光御路，瑞塔迥凌空。\n菊彩扬尧日，萸香遶舜风。\n天文丽辰象，窃抃仰层穹。' },
  { title: '晦日宴高文学林亭', author: '张锡', poem: '雪尽铜驼路，花照石崇家。\n年光开柳色，池影泛云华。\n赏洽情方远，春归景未赊。\n欲知多暇日，尊酒渍澄霞。' },
  { title: '奉和九月九日登慈恩寺浮图应制', author: '解琬', poem: '瑞塔临初地，金舆幸上方。\n空边有清净，觉处无馨香。\n雨霁微尘歛，风秋定水凉。\n兹辰采仙菊，荐寿庆重阳。' },
  { title: '晦日宴高氏林亭', author: '解琬', poem: '主第簪裾出，王畿春照华。\n山亭一以眺，城阙带烟霞。\n横堤列锦帐，傍浦驻香车。\n欢娱属晦节，酩酊未还家。' },
  { title: '侍宴长宁公主东庄应制', author: '郑愔', poem: '公门袭汉环，主第称秦玉。\n池架祥鳣序，山吹鸣凤曲。\n拂席萝薜垂，回舟芰荷触。\n平阳妙舞处，日暮清歌续。' },
  { title: '采莲曲', author: '郑愔', poem: '锦䋏沙棠舰，罗带石榴帬。\n绿潭采荷芰，清江日稍曛。\n鱼鸟争唼喋，花叶相芬氲。\n不觉芳洲暮，菱歌处处闻。' },
  { title: '夜游曲', author: '郑愔', poem: '汉室欢娱盛，魏国文雅遒。\n许史多暮宿，应陈从夜游。\n西园䜩公子，北里召王侯。\n讵似将军猎，空嗟亭尉留。' },
  { title: '少年行', author: '郑愔', poem: '颍川豪横客，咸阳轻薄儿。\n田窦方贵幸，赵李新相知。\n轩盖终朝集，笙竽此夜吹。\n黄金盈箧笥，白日忽西驰。' },
  { title: '中宗降诞日长宁公主满月侍宴应制', author: '郑愔', poem: '春殿猗兰美，仙阶柏树荣。\n地逢芳节应，时覩圣人生。\n月满增祥荚，天长发瑞灵。\n南山遥可献，常愿奉皇明。' },
  { title: '奉和幸上官昭容院献诗四首 一', author: '郑愔', poem: '地轴楼居远，天台阙路赊。\n何如游帝宅，即此对仙家。\n座拂金壶电，池摇玉酒霞。\n无云秦汉隔，别访武陵花。' },
  { title: '奉和幸上官昭容院献诗四首 二', author: '郑愔', poem: '尧茨姑射近，汉苑建章连。\n十五蓂知月，三千桃纪年。\n鸾歌随凤吹，鹤舞向鹍弦。\n更觅琼妃伴，来过玉女泉。' },
  { title: '奉和幸上官昭容院献诗四首 三', author: '郑愔', poem: '宫掖贤才重，山林高尚难。\n不言辞辇地，更有结庐欢。\n池栋清温燠，岩窗起沍寒。\n幽亭有仙桂，圣主万年看。' },
  { title: '奉和幸上官昭容院献诗四首 四', author: '郑愔', poem: '槎流天上转，茅宇禁中开。\n河鹊填桥至，山熊避槛来。\n庭花采菉蓐，岩石步莓苔。\n愿奉舆图泰，长开锦翰裁。' },
  { title: '送金城公主适西蕃应制', author: '郑愔', poem: '下嫁戎庭远，和亲汉礼优。\n笳声出虏塞，箫曲背秦楼。\n贵主悲黄鹤，征人怨紫骝。\n皇情眷亿兆，割念俯怀柔。' },
  { title: '奉和幸望春宫送朔方大总管张仁亶', author: '郑愔', poem: '御跸下都门，军麾出塞垣。\n长杨跨武骑，细柳接戎轩。\n睿曲风云动，边威鼓吹喧。\n坐帷将阃外，俱是报明恩。' },
  { title: '奉和九月九日登慈恩寺浮图应制', author: '郑愔', poem: '涌霄开宝塔，倒影驻仙舆。\n鴈子乘堂处，龙王起藏初。\n秋风圣主曲，佳气史官书。\n愿献重阳寿，承欢万岁余。' },
  { title: '铜雀妓', author: '郑愔', poem: '日斜漳浦望，风起邺台寒。\n玉座平生晚，金尊妓吹阑。\n舞余依帐泣，歌罢向陵看。\n萧索松风暮，愁烟入井阑。' },
  { title: '胡笳曲', author: '郑愔', poem: '汉将留边朔，遥遥岁序深。\n谁堪牧马思，正是胡笳吟。\n曲断关山月，声悲雨雪阴。\n传书问苏武，陵也独何心。' },
  { title: '折杨柳', author: '郑愔', poem: '青柳映红颜，黄云蔽紫关。\n忽闻边使出，枝叶为君攀。\n舞腰愁欲断，春心望不还。\n风花滚成雪，罗绮乱斑斑。' },
  { title: '秋闺', author: '郑愔', poem: '征客向轮台，幽闺寂不开。\n音书秋鴈断，机杼夜蛩催。\n虚幌风吹叶，闲阶露湿苔。\n自怜愁思影，常共月裴回。' },
  { title: '人日重宴大明宫恩赐彩缕人胜应制', author: '郑愔', poem: '琼殿含光映早轮，玉鸾严跸望初晨。\n池开冻水仙宫丽，树发寒花禁苑新。\n佳气裴回笼细网，残霙淅沥染轻尘。\n良时荷泽皆迎胜，穷谷晞阳犹未春。' },
  { title: '奉和春日幸望春宫', author: '郑愔', poem: '晨跸凌高转翠旌，春楼望远背朱城。\n忽排花上游天苑，却坐云边看帝京。\n百草香心初罥蝶，千林嫩叶始藏莺。\n幸同葵藿倾阳早，愿比盘根应候荣。' },
  { title: '奉和幸三会寺应制', author: '郑愔', poem: '鸟籀遗新阁，龙旗访古台。\n造书臣颉往，观迹帝羲来。\n睿览山川匝，宸心宇宙该。\n梵音随驻辇，天步接乘杯。\n旧苑经寒露，残池问劫灰。\n散花将捧日，俱喜圣慈开。' },
  { title: '奉和幸大荐福寺', author: '郑愔', poem: '旧邸三乘辟，佳辰万骑留。\n兰图奉叶偈，芝盖拂花楼。\n国会人王法，宫还天帝游。\n紫云成宝界，白水作禅流。\n鴈塔昌基远，鹦林睿藻抽。\n欣承大风曲，窃预小童讴。' },
  { title: '同韦舍人早朝', author: '郑愔', poem: '瑞阙龙居峻，宸庭凤掖深。\n才良寄天綍，趋拜侣朝簪。\n飞马看来影，喧车识驻音。\n重轩轻雾入，洞户落花侵。\n闻有题新翰，依然想旧林。\n同声慙卞玉，谬此托韦金。' },
  { title: '塞外三首 一', author: '郑愔', poem: '塞外萧条望，征人此路赊。\n边声乱朔马，秋色引胡笳。\n遥嶂侵归日，长城带晚霞。\n断蓬飞古戍，连鴈聚寒沙。\n海暗云无叶，山春雪作花。\n丈夫期报主，万里独辞家。' },
  { title: '塞外三首 二', author: '郑愔', poem: '荒垒三秋夕，穷郊万里平。\n海阴凝独树，日气下连营。\n戎斾霜旋重，边裘夜更轻。\n将军犹转战，都尉不成名。\n折柳悲春曲，吹笳断夜声。\n明年汉使返，须筑受降城。' },
  { title: '塞外三首 三', author: '郑愔', poem: '阳鸟南飞夜，阴山北地寒。\n汉家征戍客，年岁在楼兰。\n玉塞朔风起，金河秋月团。\n边声入鼓吹，霜气下旌竿。\n海外归书断，天涯旅鬓残。\n子卿犹奉使，常向节旄看。' },
  { title: '春怨', author: '郑愔', poem: '春朝物候妍，愁妇镜台前。\n风吹数蝶乱，露洗百花鲜。\n试出褰罗幌，还来着锦筵。\n曲中愁夜夜，楼上别年年。\n不及随萧史，高飞向紫烟。' },
  { title: '贬降至汝州广城驿', author: '郑愔', poem: '近郊凭汝海，遐服指江干。\n尚忆趋朝贵，方知失路难。\n曙宫平乐远，秋泽广城寒。\n岸苇新花白，山梨晚叶丹。\n乡关千里暮，岁序四时阑。\n函塞云间别，旋门雾里看。\n夙年追𫘧骥，暮节仰鹓鸾。\n疲驽劳垂耳，骞腾讵矫翰。\n将调梅铉实，不正李园冠。\n荆玉终无玷，随珠忽已弹。\n晓装违巩洛，夕梦在长安。\n北上频伤阮，西征未学潘。\n倾车无共辙，同派有殊澜。\n去去怀知己，何由报一餐。' },
  { title: '哭郎著作', author: '郑愔', poem: '诗礼康成学，文章贾谊才。\n巳年人得梦，庚日鸟为灾。\n书草藏天阁，琴声入夜台。\n荒阶罗驳藓，虚座网浮埃。\n白马宾徒散，青乌陇隧开。\n空怜门下客，怀旧几迟回。' },
  { title: '咏黄莺儿', author: '郑愔', poem: '欲啭声犹涩，将飞羽未调。\n高风不借便，何处得迁乔。' },
  { title: '百舌', author: '郑愔', poem: '百舌鸣高树，弄音无常则。\n借问声何烦，末俗不尚默。' },
  { title: '奉和圣制送张说上集贤学士赐宴', author: '源乾曜', poem: '盛业光书府，征人尽国英。\n丝纶贤得相，群俊学为名。\n宠命垂天锡，崇恩发睿情。\n熏风清禁籞，文殿述皇明。\n日霁庭阴出，池曛水气生。\n欢娱此无限，诗酒自相迎。' },
  { title: '奉和御制乾曜与张说宋璟同日上官命宴都堂赐诗', author: '源乾曜', poem: '睿作超千古，湛恩育万人。\n递迁俱荷泽，同拜忽为邻。\n道合徽音畅，芳辰景命新。\n鼓钟崇享礼，鹓鹭集朝伦。\n窃位思官谤，凋容谢木春。\n慙多无以叙，拙备实难陈。\n进绶怀三少，承光尽百身。\n自当归第日，何幸列宫臣。' },
  { title: '奉和圣制送张尚书巡边', author: '源乾曜', poem: '匈奴迩河朔，汉地须戎旅。\n天子择英才，朝端出监抚。\n流星下阊阖，宝钺专公辅。\n礼物生光辉，宸章备恩诩。\n有征视矛戟，制胜唯樽俎。\n彼美何壮哉，桓桓擅斯举。\n声华振台阁，功德标文武。\n奉国知命轻，忘家以身许。\n安人在勤恤，保大殚襟俯。\n此外无异言，同情报明主。' },
  { title: '禅社首乐章', author: '源乾曜', poem: '灵具醉，杳熙熙。\n灵将往，眇禗禗。\n愿明德，吐正词。\n烂遗光，流祯祺。' },
  { title: '奉和圣制送张说赴集贤院学士赐宴赋得虚字', author: '徐坚', poem: '崇文德化洽，新殿集贤初。\n庸菲参高选，首滥承明庐。\n殊私光辅弼，荣送列簪裾。\n座引中厨馔，杯锡上尊余。\n翠叶浓丹苑，晴空卷碧虚。\n忝同文史地，愿草登封书。' },
  { title: '奉和圣制送张说巡边', author: '徐坚', poem: '至德抚遐荒，神兵赴朔方。\n帝思元帅重，爰择股肱良。\n累相承安世，深筹协子房。\n寄崇专斧钺，礼备设坛场。\n鼙鼓喧雷电，戈劒凛风霜。\n四𬴂将戒道，十乘启先行。\n圣锡加恒数，天文耀宠光。\n出郊开帐饮，寅饯盛离章。\n雨濯梅林润，风清麦野凉。\n燕山应勒颂，麟阁伫名扬。' },
  { title: '奉和送金城公主适西蕃应制', author: '徐坚', poem: '星汉下天孙，车服降殊蕃。\n匣中词易切，马上曲虚繁。\n关塞移朱帐，风尘暗锦轩。\n箫声去日远，万里望河源。' },
  { title: '饯许州宋司马赴任', author: '徐坚', poem: '旧许星车转，神京祖帐开。\n断烟伤别望，零雨送离杯。\n辞燕依空遶，宾鸿入听哀。\n分襟与秋气，日夕共悲哉。' },
  { title: '饯唐永昌', author: '徐坚', poem: '郎官出宰赴伊瀍，征传骎骎灞水前。\n此时怅望新丰道，握手相看共黯然。' },
  { title: '送考功武员外学士使嵩山置舍利塔歌', author: '徐坚', poem: '伊川别骑，灞岸分筵。\n对三春之花月，览千里之风烟。\n望青山兮分地，见白云兮在天。\n寄愁心于樽酒，怆离绪于清弦。\n共握手而相顾，各衔凄而黯然。' },
  { title: '櫂歌行', author: '徐坚', poem: '櫂女饰银钩，新妆下翠楼。\n霜丝青桂檝，兰栧紫霞舟。\n水落金陵曙，风起洞庭秋。\n扣舷过曲浦，飞帆越回流。\n影入桃花浪，香飘杜若洲。\n洲长殊未返，萧散云霞晚。\n日下大江平，烟生归岸远。\n岸远闻潮波，争途游戏多。\n因声赵津女，来听采菱歌。' },
  { title: '送武进郑明府', author: '徐坚', poem: '弦歌试宰日，城阙赏心违。\n北谢苍龙去，南随黄鹄飞。\n夏云海中出，吴山江上微。\n甿谣岂云远，从此庆缁衣。' },
  { title: '仪坤庙乐章', author: '徐坚', poem: '於穆清庙，肃雍严祀。\n合福受厘，介以繁祉。' },
  { title: '祭汾阴乐章', author: '源光裕', poem: '方丘既膳，嘉飨载谧。\n斋敬毕诚，陶匏贵质。\n秀毕丰荐，芳俎盈实。\n永永福流，其升如日。' },
  { title: '奉和圣制送张说上集贤学士赐宴', author: '李元纮', poem: '硕儒延凤沼，金马被鸿私。\n馔玉趋丹禁，牋花降紫墀。\n衔恩倾旨酒，鼓舞咏康时。\n暂觏群书缉，逾昭盛业丕。\n接筵欣有命，搦管媿无词。\n自惊一何幸，太阳还及葵。' },
  { title: '绿墀怨', author: '李元纮', poem: '征马噪金珂，嫖姚向北河。\n绿苔行迹少，红粉泪痕多。\n宝屋粘花絮，银筝覆网罗。\n别君如昨日，青海雁频过。' },
  { title: '相思怨', author: '李元纮', poem: '望月思氛氲，朱衾嬾更熏。\n春生翡翠帐，花点石榴裠。\n燕语时惊妾，莺啼转忆君。\n交河一万里，仍隔数重云。' },
  { title: '奉和圣制送张说上集贤学士赐宴', author: '裴漼', poem: '问道图书盛，尊儒礼教兴。\n石渠因学广，金殿为贤升。\n日月恩光照，风云宠命膺。\n谋谟言可范，舟檝事斯凭。\n宴喜明时洽，光辉湛露凝。\n大哉尧作主，天下颂歌称。' },
  { title: '奉和御制旋师喜捷', author: '裴漼', poem: '殊类骄无长，王师示有征。\n中军才受律，妖寇已亡精。\n斩虏还遮塞，绥降更筑城。\n从来攻必克，天策振奇兵。' },
  { title: '奉和御制平胡', author: '裴漼', poem: '玄漠圣恩通，由来书轨同。\n忽闻窥月满，相聚寇云中。\n庙略占黄气，神兵出绛宫。\n将军行逐虏，使者亦和戎。\n一举轒辒灭，再麾沙漠空。\n直将威禁暴，非用武为雄。\n饮至明军礼，醻勋锡武功。\n干戈还载戢，文德在唐风。' },
  { title: '奉和圣制龙池篇', author: '裴漼', poem: '乾坤启圣吐龙泉，泉水年年胜一年。\n始看鱼跃方成海，即覩飞龙利在天。\n洲渚遥将银汉接，楼台直与紫微连。\n休气荣光恒不散，悬知此地是神仙。' },
  { title: '奉和圣制送张说上集贤学士赐宴', author: '刘升', poem: '图书应明主，策府宴嘉宾。\n台曜临东壁，干光自北辰。\n网罗穷象系，述作究天人。\n圣酒千钟洽，仙厨百味陈。\n成山徒可仰，涉海讵知津。\n幸逢文教盛，还覩颂声新。' },
  { title: '奉和圣制送张说上集贤学士赐宴', author: '萧嵩', poem: '帝曰简才能，旌贤在股肱。\n文章体一变，礼乐道逾弘。\n芸阁英华入，宾门鹓鹭登。\n恩筵过所望，圣泽实超恒。\n夏叶开红药，余花发紫藤。\n微臣亦何幸，叨此预文朋。' },
  { title: '奉和御制左丞相说右丞相璟太子少傅乾曜同日上官命宴都堂赐诗', author: '萧嵩', poem: '审官思共理，多士属惟唐。\n历选台庭旧，来熙帝业昌。\n入朝师百辟，论道协三光。\n垂拱咨元老，亲贤辅少阳。\n登庸崇礼送，宠德耀宸章。\n御酒飞觞洽，仙闱雅乐张。\n荷恩思有报，陈力媿无良。\n愿罄公忠节，同心奉我皇。' },
  { title: '奉和圣制送张说上集贤学士赐宴', author: '韦抗', poem: '广庭临璧沼，多士侍金闺。\n英宰文儒叶，明君日月齐。\n集贤光首拜，改殿发新题。\n早夏初移律，余花尚拂溪。\n壶觞接云上，经术引关西。\n圣德鸿名远，将陪玉检泥。' },
  { title: '奉和圣制送张说上集贤学士赐宴', author: '李暠', poem: '偃武尧风接，崇文汉道恢。\n集贤更内殿，清选自中台。\n佐命留侯业，词华博物才。\n天厨千品降，御酒百壶催。\n鹓鹭方成列，神仙喜暂陪。\n复欣同拜首，叨此颂良哉。' },
  { title: '奉和圣制送张说上集贤学士赐宴', author: '韦述', poem: '修文中禁启，改字令名加。\n台座征人杰，书坊应国华。\n赋诗开广宴，赐酒酌流霞。\n云散明金阙，池开照玉沙。\n掖垣留宿鸟，温树落余花。\n谬此天光及，衔恩醉日斜。' },
  { title: '晚渡伊水', author: '韦述', poem: '悠悠涉伊水，伊水清见石。\n是时春向深，两岸草如积。\n迢遰望洲屿，逶迤亘津陌。\n新树落疎红，遥原上深碧。\n回瞻洛阳苑，遽有长山隔。\n烟雾犹辨家，风尘已为客。\n登陟多异趣，往来见行役。\n云起早已昏，鸟飞日将夕。\n光阴逝不借，超然慕畴昔。\n远游亦何为？归来存竹帛。' },
  { title: '春日山庄', author: '韦述', poem: '初岁开韶月，田家喜载阳。\n晚晴摇水态，迟景荡山光。\n浦净渔舟远，花飞樵路香。\n自然成野趣，都使俗情忘。' },
  { title: '广陵送别宋员外佐越郑舍人还京', author: '韦述', poem: '朱绂临秦望，皇华赴洛桥。\n文章南渡越，书奏北归朝。\n树入江云尽，城衔海月遥。\n秋风将客思，川上晚萧萧。' },
  { title: '奉和圣制送张说上集贤学士赐宴', author: '陆坚', poem: '圣主崇文教，层霄降德音。\n尊贤泽既厚，式宴宠逾深。\n复有夔龙相，良哉简帝心。\n得人惟迈昔，多士谅推今。\n书殿荣光满，儒门喜气临。\n顾惟诚滥吹，徒此接衣簪。' },
  { title: '奉和圣制送张说上集贤学士赐宴', author: '程行谌', poem: '圣主崇文化，锵锵得盛才。\n相因归梦立，殿以集贤开。\n象系微言阐，诗书至道该。\n尧尊承帝泽，禹膳自天来。\n礼洽欢逾长，风恬暑更回。\n国朝将舜颂，同是一康哉。' },
  { title: '奉和圣制送张说上集贤学士赐宴', author: '褚秀', poem: '讲习延东观，趋陪盛北宫。\n惟师恢帝则，敷教叶天工。\n宣室恩尝异，金华礼更崇。\n洞门清永日，华绶接微风。\n萐降尧厨翠，榴开舜酒红。\n文思光万宇，高议待升中。' },
  { title: '奉和御制左丞相说右丞相璟太子少傅乾曜同日上官命都堂赐诗', author: '裴光庭', poem: '乐贤闻往诰，褒德偶兹辰。\n端揆升元老，师谋择累仁。\n紫庭崇让毕，粉署礼容陈。\n既荷恩荣旧，俱承宠命新。\n天文悬瑞色，圣酒泛华茵。\n杂遝喧箫鼓，欢娱洽搢绅。\n掖垣招近侍，虚薄[厕]清尘。\n共保坚贞节，常期雨露均。' },
  { title: '奉和圣制左丞相说右丞相璟太子少傅乾曜同日上官命宴都堂赐诗', author: '宇文融', poem: '申甫生周日，宣慈举舜年。\n何如偶昌运，比德迈前贤。\n宠获元良密，荣瞻端揆迁。\n职优三事老，位在百僚先。\n北极回宸渥，南宫饰御筵。\n飞文瑶札降，赐酒玉杯传。\n谬列台衡重，俱承雨露偏。\n誓将同竭力，相与效尘涓。' },
  { title: '奉和圣制同二相已下群官乐游园宴', author: '崔沔', poem: '五日酺才毕，千年乐未央。\n复承天所赐，终宴国之阳。\n地胜春逾好，恩深乐更张。\n落花飞广座，垂柳拂行觞。\n庶尹陪三史，诸侯具万方。\n酒酣同抃跃，歌舞咏时康。' },
  { title: '奉和圣制同二相已下群臣乐游园宴', author: '崔尚', poem: '春日照长安，皇恩宠庶官。\n合钱承罢宴，赐帛复追欢。\n供帐凭高列，城池入迥宽。\n花催相国醉，鸟和乐人弹。\n北阙云中见，南山树杪看。\n乐游宜缔赏，舞咏惜将阑。' },
  { title: '奉和圣制同二相以下群官乐游园宴', author: '胡皓', poem: '五酺终宴集，三锡又欢娱。\n仙阜崇高异，神州眺览殊。\n南山临皓雪，北阙对明珠。\n广座鹓鸿满，昌庭驷马趋。\n绮罗含草树，丝竹吐郊衢。\n衔杯不能罢，歌舞乐唐虞。' },
  { title: '奉和圣制送张尚书巡边', author: '胡皓', poem: '燕公为汉将，武德奉文思。\n利用经戎莽，英图叶圣诒。\n塞沙制长策，穷石卷摇旗。\n万里要相贺，三边又在兹。\n棱威方逐逐，谈笑坐怡怡。\n宠饯纷郊道，充厨竭御司。\n尝醪企行迈，听乐罢涟洏。\n衮旒垂翰墨，缨蕤迭赋诗。\n金山无积阻，玉树有华滋。\n请迨炎风暮，归旌候此时。' },
  { title: '和宋之问寒食题临江驿', author: '胡皓', poem: '闻道山阴会，仍为火忌辰。\n途中甘弃日，江上苦伤春。\n流水飜催泪，寒灰更伴人。\n丹心终不改，白发为谁新。' },
  { title: '出峡', author: '胡皓', poem: '巴东三峡尽，旷望九江开。\n楚塞云中出，荆门水上来。\n鱼龙潜啸雨，凫雁动成雷。\n南国秋风晚，客思几悠哉。' },
  { title: '同蔡孚起居咏鹦鹉', author: '胡皓', poem: '鹦鹉殊姿致，鸾皇得比肩。\n常寻金殿里，每话玉阶前。\n贾谊才方达，扬雄老未迁。\n能言既有地，何惜为闻天。' },
  { title: '大漠行', author: '胡皓', poem: '单于犯蓟堧，虏骑略萧边。\n南山木叶飞下地，北海蓬根乱上天。\n科斗连营太原道，鱼丽合阵武威川。\n三军遥倚伏，万里相驰逐。\n旌斾悠悠静潮源，鼙鼓喧喧动卢谷。\n穷徼出幽陵，吁嗟倦寝兴。\n马蹄冻溜石，胡毳煖生冰。\n云沙泱漭天光闭，河塞阴沈海色凝。\n崆峒北国谁能托，萧索边心常不乐。\n近见行人畏白龙，遥闻公主愁黄鹤。\n阳春半，岐路间，瑶台苑，玉门关。\n百花芳树红将歇，二月兰臯绿未还。\n阵云不散鱼龙水，雨雪犹飞鸿鹄山。\n山嶂緜连那可极，路远辛勤梦颜色。\n北堂萱草不寄来，东园桃李长相忆。\n汉将纷纭攻战盈，胡寇萧条幽朔清。\n韩昌拜节偏知送，郑吉驱旌坐见迎。\n火绝烟沈左西极，谷静山空右北平。\n但得将军能百胜，不须天子筑长城。' },
  { title: '朝退', author: '李适之', poem: '朱门长不闭，亲友恣相过。\n年今将半百，不乐复如何。' },
  { title: '罢相作', author: '李适之', poem: '避贤初罢相，乐圣且衔杯。\n为问门前客，今朝几个来。' },
  { title: '题汉州西湖', author: '房琯', poem: '高流缠峻隅，城下缅丘墟。\n决渠信浩荡，潭岛成江湖。\n结宇依回渚，水中信可居。\n三伏气不蒸，四达暑自徂。\n同人千里驾，邻国五马车。\n月出共登舟，风生随所如。\n举麾指极浦，欲极更盘纡。\n缭绕各殊致，夜尽情有余。\n遭乱意不开，即理还暂祛。\n安得长晤语，使我忧更除。' },
  { title: '咏方圆动静', author: '李泌', poem: '方如行义，圆如用智。\n动如逞才，静如遂意。' },
  { title: '长歌行', author: '李泌', poem: '天覆吾，地载吾，天地生吾有意无。\n不然绝粒升天衢，不然鸣珂游帝都。\n焉能不贵复不去，空作昂藏一丈夫。\n一丈夫兮一丈夫，千生气志是良图。\n请君看取百年事，业就扁舟泛五湖。' },
  { title: '奉和圣制中和节曲江宴百僚', author: '李泌', poem: '风俗时有变，中和节惟新。\n轩车双阙下，宴会曲江滨。\n金石何铿锵，簪缨亦纷纶。\n皇恩降自天，品物感知春。\n慈恩匝寰瀛，歌咏同君臣。' },
  { title: '奉和圣制重阳赐会聊示所怀', author: '李泌', poem: '大唐造昌运，品物荷时成。\n乘秋逢令节，锡宴欢群情。\n俯临秦山川，高会汉公卿。\n未追赤松子，且泛黄菊英。\n赓歌圣人作，海内同休明。' },
  { title: '句', author: '李泌', poem: '青青东门柳，岁晏复憔悴。\n良弓摧折久，谁识是龙韬。\n旋沫翻成碧玉池，添酥散出琉璃眼。' },
  { title: '享太庙乐章 广运舞', author: '郭子仪', poem: '于赫皇祖，昭明有融。\n惟文之德，惟武之功。\n河海静谧，车书混同。\n虔恭孝飨，穆穆玄风。' },
  { title: '享太庙乐章 保大舞', author: '郭子仪', poem: '於穆文考，圣神昭彰。\n箫勺群慝，含光远方。\n万物茂遂，九夷宾王。\n愔愔云韶，德音不忘。' },
  { title: '百子池', author: '张谔', poem: '旧闻百子汉家池，汉家渌水今逶迤。\n宫女厌镜笑窥池，身前影后不相见。' },
  { title: '东封山下宴群臣', author: '张谔', poem: '万里扈封峦，群公遇此欢。\n幔城连夜静，霜仗满空寒。\n辇路宵烟合，旌门晓月残。\n明朝陪圣主，山下礼圆坛。' },
  { title: '三日岐王宅', author: '张谔', poem: '玉女贵妃生，嫛婗始发声。\n金盆浴未了，绷子绣初成。\n翡翠雕芳缛，真珠帖小缨。\n何时学健步？鬬取落花轻。' },
  { title: '满月', author: '张谔', poem: '社金流茂祉，庭玉表奇才。\n竹似因谈植，兰疑入梦栽。\n乌将八子去，凤逐九雏来。\n今夜明珠色，当随满月开。' },
  { title: '岐王山亭', author: '张谔', poem: '王家傍绿池，春色正相宜。\n岂有楼台好，兼看草树奇。\n石榴天上叶，椰子日南枝。\n出入千门里，年年乐未移。' },
  { title: '岐王席上咏美人', author: '张谔', poem: '半额画双蛾，盈盈烛下歌。\n玉杯寒意少，金屋夜情多。\n香艳王分帖，裙娇敕赐罗。\n平阳莫相妬，唤出不如他。' },
  { title: '还京', author: '张谔', poem: '朱绂临秦望，皇华赴洛桥。\n文章南渡越，书奏北归朝。\n树入江云尽，城衔海月遥。\n秋风将客思，川上晚萧萧。' },
  { title: '赠吏部孙员外济', author: '张谔', poem: '天子爱贤才，星郎入拜来。\n明光朝半下，建礼直初回。\n名带含香发，文随绮幕开。\n披云自有镜，从此照仙台。' },
  { title: '送李著作倅杭州', author: '张谔', poem: '辍史空三署，题舆佐一方。\n祖筵开霁景，征陌直朝光。\n水陆风烟隔，秦吴道路长。\n伫闻敷善政，邦国咏惟康。' },
  { title: '九日', author: '张谔', poem: '秋来林下不知春，一种佳游事也均。\n绛叶从朝飞着夜，黄花开日未成旬。\n将曛陌树频惊鸟，半醉归途数问人。\n城远登高倂九日，茱萸凡作几年新。' },
  { title: '延平门高斋亭子应岐王教', author: '张谔', poem: '花源药屿凤城西，翠幕纱窗莺乱啼。\n昨夜蒲萄初上架，今朝杨柳半垂堤。\n片片仙云来渡水，双双燕子共衔泥。\n请语东风催后骑，倂将歌舞向前谿。' },
  { title: '九日宴', author: '张谔', poem: '秋叶风吹黄飒飒，晴云日照白鳞鳞。\n归来得问茱萸女，今日登高醉几人。' },
  { title: '从军', author: '刘庭琦', poem: '朔风吹寒塞，胡沙千万里。\n阵云出岱山，孤月生海水。\n决胜方求敌，衔恩本轻死。\n萧萧牧马鸣，中夜拔劒起。' },
  { title: '奉和圣制瑞雪篇', author: '刘庭琦', poem: '紫宸飞雪晓裴回，层阁重门雪照开。\n九衢皛耀浮埃尽，千品差池贽帛来。\n何处田中非种玉，谁家院里不生梅？\n埋云翳景无穷已，因风落地吹还起。\n先过翡翠宝房中，转入鸳鸯金殿里。\n美人含笑出联翩，艳逸相轻鬬容止。\n罗衣点着浑是花，玉手抟来半成水。\n奕奕纷纷何所如，顿忆杨园二月初。\n羞同班女高秋扇，欲照明王乙夜书。\n姑射山中符圣寿，芙蓉阙下降神车。\n愿随睿泽流无限，长报丰年贵有余。' },
  { title: '咏木槿树题武进文明府厅', author: '刘庭琦', poem: '物情良可见，人事不胜悲。\n莫恃朝荣好，君看暮落时。' },
  { title: '铜雀台', author: '刘庭琦', poem: '铜台宫观委灰尘，魏主园林漳水滨。\n即今西望犹堪思，况复当时歌舞人。' },
  { title: '失白鹰', author: '郑繇', poem: '白锦文章乱，丹霄羽翮齐。\n云中呼暂下，雪里放还迷。\n梁苑惊池鹜，陈仓拂野鸡。' },
  { title: '经慈涧题', author: '郑繇', poem: '岸与恩同广，波将慈共深。\n涓涓劳日夜，长似下流心。' },
  { title: '奉和御制平胡', author: '韩休', poem: '南牧正纷纷，长河起塞氛。\n玉符征选士，金钺拜将军。\n叠鼓摇边吹，连旌暗朔云。\n祅星乘夜落，害气入朝分。\n始见幽烽警，俄看烈火焚。\n功成奏凯乐，战罢策归勋。\n盛德陈清庙，神谟属大君。\n叨荣逢偃羽，率舞咏时文。' },
  { title: '奉和圣制送张说巡边', author: '韩休', poem: '一德光台象，三军掌夏卿。\n来威申庙略，出总叶师贞。\n受钺辞金殿，凭轩去鼎城。\n曙光摇组甲，疎吹绕云旌。\n左律方先凯，中鼙即训兵。\n定功彰武事，陈颂纪天声。\n祖宴初留赏，宸章更宠行。\n车徒零雨送，林野夕阴生。\n路极河流远，川长朔气平。\n南辕迟返斾，归奏谒承明。' },
  { title: '祭汾阴乐章', author: '韩休', poem: '於穆濬哲，维清缉熙。\n肃事昭配，永言孝思。\n涤濯静嘉，馨香在兹。\n神之听之，用受福厘。' },
  { title: '征君宅', author: '许景先', poem: '征君昔嘉遯，抗迹遗俗尘。\n了心悟有物，乘化游无垠。\n道丧历千载，复存颍阳真。\n上虞佳山水，晚岁耽隐沦。\n内史既解绶，支公亦相亲。\n儒道匪远理，意胜聊自欣。\n洄沿南谿夕，流浪东山春。\n石壁践丹景，金潭冒绿苹。\n探炼备海峤，赏心寓情人。\n奈何灵仙骨，锹翮瑶池津。\n寥寥虚白宇，夙剏招提因。\n家风缅多尚，玄德谢无邻。\n谬陪金门彦，矫迹侍紫宸。\n皇恩竟已矣，遗烈庶不泯。' },
  { title: '折柳篇', author: '许景先', poem: '春色东来度渭桥，青门垂柳百千条。\n长杨西连建章路，汉家林苑纷无数。\n萦花始遍合欢枝，游丝半罥相思树。\n春楼初日照南隅，柔条垂绿扫金铺。\n宝钗新梳倭堕髻，锦带交垂连理襦。\n自怜柳塞淹戎幕，银烛长啼愁梦着。\n芳树朝催玉管新，春风夜染罗衣薄。\n城头杨柳已如丝，今年花落去年时。\n折芳远寄相思曲，为惜容华难再持。' },
  { title: '奉和御制春台望', author: '许景先', poem: '睿德在青阳，高居视中县。\n秦城连凤阙，汉寝疏龙殿。\n文物照光辉，郊畿郁葱蒨。\n千门望成锦，八水明如练。\n复道晓光披，宸游出禁移。\n瑞气朝浮五云阁，祥光夜吐万年枝。\n兰叶负龟初荐祉，桐花集凤更来仪。\n秦汉生人凋力役，阿房甘泉构云碧。\n汾祠雍畤望通天，玉堂宣室坐长年。\n鼓钟西接咸阳观，苑囿南通鄠杜田。\n明主卑宫诫前失，辅德钦贤政惟一。\n昆虫不夭在春搜，稼穑常艰重农术。\n邦家已荷圣谟新，犹闻俭陋惜中人。\n豫奉北辰齐七政，长歌东武抃千春。' },
  { title: '阳春怨', author: '许景先', poem: '红树晓莺蹄，春风暖翠闺。\n雕笼熏绣被，珠履踏金堤。\n芍药花初吐，菖蒲叶正齐。\n藁砧当此日，行役向辽西。' },
  { title: '奉和圣制送张尚书巡边', author: '许景先', poem: '文武承邦式，风云感国祯。\n王师亲赋政，庙略久论兵。\n汉主知三杰，周官统六卿。\n四方分阃受，千里坐谋成。\n介胄辞前殿，壶觞宿左营。\n赏延颁赐重，宸赠出车荣。\n龙武三军气，鱼铃五校名。\n郊云驻旌羽，边吹引金钲。\n训旅方称德，安人更克贞。\n伫看铭石罢，同听凯歌声。' },
  { title: '咏史', author: '王丘', poem: '高洁非养正，盛名亦险艰。\n伟哉谢安石，携妓入东山。\n云岩响金奏，空水滟朱颜。\n兰露滋香泽，松风鸣珮环。\n歌声入空尽，舞影到池闲。\n杳眇同天上，繁华非代间。\n卷舒混名迹，纵诞无忧患。\n何必苏门子，冥然闭清关。' },
  { title: '奉和圣制荅张说扈从南出鼠雀谷之作', author: '王丘', poem: '襟带三秦接，旗常万乘过。\n阳原淑气早，阴谷沍寒多。\n花缛前茅仗，霜严后殿戈。\n代云开晋岭，江雁入汾河。\n北土分尧俗，南风动舜歌。\n一闻天乐唱，恭逐万人和。' },
  { title: '奉和圣制送张尚书巡边', author: '王丘', poem: '德业蕴时宗，幽符梦象通。\n台司计祈父，师律总元戎。\n出入敷能政，谋猷体至公。\n赠行光睿什，宴别感宸衷。\n文炳高天曜，恩垂湛露融。\n建牙之塞表，鸣鼓接云中。\n策密鬼神秘，威成剑骑雄。\n朔门正炎月，兵气已秋风。\n肃杀从此始，方知胡运穷。' },
  { title: '过贾六', author: '苏晋', poem: '主人病且闲，客来情弥适。\n一酌复一笑，不知日将夕。\n昨来属欢游，于今尽成昔。\n努力持所趣，空名定何益。' },
  { title: '奉和圣制送张说巡边', author: '苏晋', poem: '方汉比周年，兴王合在宣。\n亟闻降虏拜，复覩出师篇。\n祈父万邦式，英猷三略传。\n算车申夏政，茇舍启戎田。\n严问盟胡苑，军容济洛川。\n皇情怅关斾，诏饯列郊筵。\n路接禁园草，池分御井莲。\n离声轸去角，居念断归蝉。\n三捷岂云尔，七擒良信然。\n具僚诚寄望，奏凯秋风前。' },
  { title: '奉和圣制送张说巡边', author: '崔禹锡', poem: '供帐何煌煌，公其抚朔方。\n群僚咸饯酌，明主降离章。\n关塞重门下，郊岐禁苑傍。\n练兵宜雨洗，卧鼓候风凉。\n炎景宁云惮，神谋肃所将。\n旌摇天月迥，骑入塞云长。\n赫赫皇威振，油油圣泽滂。\n非惟按车甲，兼以正封疆。\n叱诧阴山道，澄清翰海阳。\n虏垣行决胜，台座伫为光。' },
  { title: '恩敕尚书省僚宴昆明池应制', author: '张嘉贞', poem: '灵沼初开汉，神池旧浴尧。\n昔人徒习武，明代此闻韶。\n地脉山川胜，天恩雨露饶。\n时光牵利舸，春淑覆柔条。\n芳酝酲千日，华牋落九霄。\n幸承欢赉重，不觉醉归遥。' },
  { title: '奉和早登太行山中言志应制', author: '张嘉贞', poem: '明发扈山巅，飞龙高在天。\n山南平对巩，山北远通燕。\n瞻彼冈峦峻，凭兹士马妍。\n九圻行若砥，万谷辗如川。\n罗网开三面，闾阎问百年。\n泽将春雪比，文共晓星连。\n徯后逢今圣，登台谢曩贤。\n唯余事君节，不让古人先。' },
  { title: '奉和圣制送张说巡边', author: '张嘉贞', poem: '天锡我宗盟，元戎付夏卿。\n多才兼将相，必勇独横行。\n经纬称人杰，文章作代英。\n山川看是阵，草木想为兵。\n不待河冰合，犹防塞月明。\n有谋当系丑，无战且绥氓。\n阃外传三略，云中冀一平。\n感恩同义激，怅别屡魂惊。\n直视前旌掣，遥闻后骑鸣。\n还期方定日，复此出郊迎。' },
  { title: '奉和圣制送张说巡边', author: '卢从愿', poem: '上将发文昌，中军静朔方。\n占星引旌节，择日拜坛场。\n礼乐临轩送，威声出塞扬。\n安边俟帷幄，制胜在岩廊。\n作鼓将军气，投醪壮士觞。\n戒途遵六月，离赠动三光。\n槐路清梅暑，蘅臯起麦凉。\n时文仰雄伯，耀武震遐荒。\n衽席知无战，兵戈示不忘。\n伫闻歌杕杜，凯入系名王。' },
  { title: '祭汾阴乐章', author: '卢从愿', poem: '坤元载物，阳乐发生。\n播植资始，品汇咸亨。\n列俎棋布，方坛砥平。\n神歆禋祀，后德惟明。' },
  { title: '长门怨', author: '袁晖', poem: '早知君爱歇，本自无萦妒。\n谁使恩情深，今来反相误。\n愁眠罗帐晓，泣坐金闺暮。\n独有梦中魂，犹言意如故。' },
  { title: '铜雀妓', author: '袁晖', poem: '君爱本相饶，从来似舞腰。\n那堪攀玉座，肠断望陵朝。\n怨着情无主，哀凝曲不调。\n况临松日暮，悲吹坐萧萧。' },
  { title: '正月闺情', author: '袁晖', poem: '正月金闺里，微风绣户间。\n晓魂怜别梦，春思逼啼颜。\n遶砌梅堪折，当轩树未攀。\n岁华庭北上，何日度阳关。' },
  { title: '二月闺情', author: '袁晖', poem: '二月韶光好，春风香气多。\n园中花巧笑，林里鸟能歌。\n有恨离琴瑟，无情着绮罗。\n更听春燕语，妾亦不如他。' },
  { title: '三月闺情', author: '袁晖', poem: '三月春将尽，空房妾独居。\n蛾眉愁自结，鬓髪没情梳。\n□□□□□，□□□□□。\n□□□□□，□□□□□。' },
  { title: '七月闺情', author: '袁晖', poem: '七月坐凉宵，金波满丽谯。\n容华芳意改，枕席怨情饶。\n锦字沾愁泪，罗裙缓细腰。\n不如银汉女，岁岁鹊成桥。' },
  { title: '奉和圣制荅张说扈从南出雀鼠谷之作', author: '袁晖', poem: '魏国山河险，周王警跸回。\n九旗云际出，万骑谷中来。\n石路行将尽，烟郊望忽开。\n赏矜垂柳报，春畏落花催。\n兴逸横汾什，恩褒作颂才。\n小臣瞻日月，延首咏康哉。' },
  { title: '奉和圣制送张尚书巡边', author: '袁晖', poem: '出师宣九命，分阃用三台。\n始应幕中画，言从天上来。\n丹青不独任，韬略遂双该。\n坐见威棱洽，弥彰事业恢。\n旌旗晓云送，鞞鼓朔风催。\n虏气消残月，边声韵落梅。\n羽书雄北地，龙漠寝南垓。\n宠战黄金尽，输诚白日回。\n离章宸翰发，祖䜩国门开。\n欲识恩华盛，平生文武材。' },
  { title: '奉和圣制荅张说扈从南出雀鼠谷', author: '王光庭', poem: '省俗恩将遍，巡方路稍回。\n寒随汾谷尽，春逐晋郊来。\n云骑传行漏，烟旄引从台。\n惠风初应律，和气正调梅。\n雅颂通宸咏，天文接曙台。\n灞陵桃李色，应待日华开。' },
  { title: '奉和圣制送张说巡边', author: '王光庭', poem: '贤相德符充，朝推文武雄。\n海波先若镜，关草豫从风。\n钺助将军勇，威成天子功。\n琼章九霄发，锡宴五衢通。\n玉辗龙盘带，金装凤勒骢。\n虎貔纷儗儗，河洛振熊熊。\n戈剑千霜白，旌旗万火红。\n示刑夷夏变，流惠鬼方同。\n寇息军容偃，尘销朔野空。\n用师敷礼乐，非是为獯戎。' },
  { title: '奉和圣制送张说巡边', author: '徐知仁', poem: '圣德膺三统，皇恩被八埏。\n大明均照物，小丑未宁边。\n国相台衡重，元戎庙略宣。\n紫泥方受命，黄石乃推贤。\n问辠阴山下，安人属国前。\n度关行照月，乘障坐消烟。\n北阙纡宸藻，南桥列祖筵。\n耀威当夏日，杀气指秋天。\n鞞鼓鼋鼍振，旌旗鸟兽悬。\n由来词翰手，今见勒燕然。' },
  { title: '奉和勅赐公主镜', author: '席豫', poem: '令节颁龙镜，仙辉下凤台。\n含灵万象入，写照百花开。\n色与皇明散，光随圣泽来。\n妍媸冰鉴里，从此愧非才。' },
  { title: '江行纪事二首 一', author: '席豫', poem: '飘飖任舟楫，回合傍江津。\n后浦情犹在，前山赏更新。\n树深烟幂幂，滩浅石磷磷。\n川路南行远，淹留惜此辰。' },
  { title: '江行纪事二首 二', author: '席豫', poem: '江汛春风势，山楼曙月辉。\n猿攀紫岩饮，鸟拂清潭飞。\n古树崩沙岸，新苔覆石矶。\n津途赏无限，征客𫏐忘归。' },
  { title: '奉和圣制答张说南出雀鼠谷', author: '席豫', poem: '鸣銮初幸代，旋盖欲横汾。\n山尽千旗出，郊平五校分。\n前林已暄景，后壑尚寒氛。\n风送箫韶曲，花铺黼黻文。\n盐梅推上宰，礼乐统中军。\n献赋纡天札，飘飖飞白云。' },
  { title: '奉和圣制送张说巡边', author: '席豫', poem: '圣主重兵权，分符属大贤。\n中军仍执政，丞相复巡边。\n翕习戎装动，张皇庙略宣。\n朝荣承睿札，野饯转行旃。\n亭障东缘海，沙场北际天。\n春冬见岩雪，朝夕候烽烟。\n已勒封山记，犹闻遣戍篇。\n五营将月合，八阵与云连。\n经略图方远，怀柔道更全。\n归来画麟阁，蔼蔼武功传。' },
  { title: '祭汾阴乐章', author: '韩思复', poem: '大乐和畅，殷荐明神。\n一降通感，八变必臻。\n有求斯应，无德不亲。\n降灵醉止，休征万人。' },
  { title: '祭汾阴乐章', author: '刘晃', poem: '大君出震，有事郊禋。\n斋戒既肃，馨香毕陈。\n乐和礼备，候暖风春。\n恭惟降福，实赖明神。' },
  { title: '唐禅社首乐章 顺和', author: '贺知章', poem: '至哉含柔德，万物资以生。\n常顺称厚载，流谦通变盈。\n圣心事能察，增广陈厥诚。\n黄祇僾如在，泰折俟咸亨。' },
  { title: '太和', author: '贺知章', poem: '肃我成命，于昭黄衹。\n裘冕而祀，陟降在斯。\n五音克备，八变聿施。\n缉熙肆靖，厥心匪离。' },
  { title: '太和 肃和', author: '贺知章', poem: '黄祇是祗，我其夙夜。\n夤畏诚絜，匪遑宁舍。\n礼以琮玉，荐厥茅藉。\n念兹降康，胡宁克暇。' },
  { title: '太和 雍和', author: '贺知章', poem: '夙夜宥密，不敢宁宴。\n五齐既陈，八音在县。\n粢盛以絜，房俎斯荐。\n惟德惟馨，尚兹克徧。' },
  { title: '太和 寿和', author: '贺知章', poem: '惟以明发，有怀载殷。\n乐盈而反，礼顺其禋。\n立清以献，荐欲是亲。\n於穆不已，裒对斯臻。' },
  { title: '太和 福和', author: '贺知章', poem: '穆穆天子，告成岱宗。\n大裘如濡，执珽有颙。\n乐以平志，礼以和容。\n上帝临我，云胡肃邕。' },
  { title: '太和 太和', author: '贺知章', poem: '昭昭有唐，天俾万国。\n列祖应命，四宗顺则。\n申锡无疆，宗我同德。\n曾孙继绪，享神配极。' },
  { title: '太和 晚发', author: '贺知章', poem: '江臯闻曙钟，轻栧理还舼。\n海潮夜约约，川露晨溶溶。\n始见沙上鸟，犹埋云外峰。\n故乡杳无际，明发怀朋从。' },
  { title: '奉和御制春台望', author: '贺知章', poem: '青阳布王道，玄览陶真性。\n欣若天下春，高逾域中圣。\n神臯类观赏，帝里如悬镜。\n缭绕八川浮，岧峣双阙映。\n晓色徧昭阳，晴云卷建章。\n华滋的皪丹青树，颢气氤氲金玉堂。\n尚有灵蛇下鄜畤，还征瑞宝入陈仓。\n自昔秦奢汉穷武，后庭万余宫百数。\n旗回五丈殿千门，连绵南隥出西垣。\n广画螓蛾夸窈窕，罗生玳瑁象昆仑。\n廼睠天晴兴隐恤，古来土木良非一。\n荆临章观赵丛台，何如尧阶将禹室。\n层栏䆗窱下龙舆，清管逶迤半绮疏。\n一听南风引鸾舞，长谣北极仰鹑居。' },
  { title: '望人家桃李花', author: '贺知章', poem: '山源夜雨度仙家，朝发东园桃李花。\n桃花红兮李花白，照灼城隅复南陌。\n南陌青楼十二重，春风桃李为谁容。\n弃置千金轻不顾，踟蹰五马谢相逢。\n徒言南国容华晚，遂叹西家飘落远。\n的皪长奉明光殿，氛氲半入披香苑。\n苑中珍木元自奇，黄金作叶白银枝。\n千年万岁不凋落，还将桃李更相宜。\n桃李从来露井傍，成蹊结影矜艳阳。\n莫道春花不可树，会持仙实荐君王。' },
  { title: '送人之军', author: '贺知章', poem: '常经绝脉塞，复见断肠流。\n送子成今别，令人起昔愁。\n陇云晴半雨，边草夏先秋。\n万里长城寄，无贻汉国忧。' },
  { title: '奉和圣制送张说上集贤学士赐宴赋得谟字', author: '贺知章', poem: '西学垂玄览，东堂发圣谟。\n天光烛武殿，时宰集鸿都。\n枯朽沾皇泽，翾飞舞帝梧。\n迹同游汗漫，荣是出泥涂。\n三叹承汤鼎，千欢接舜壶。\n微躯不可荅，空欲咏依蒲。' },
  { title: '奉和圣制送张说巡边', author: '贺知章', poem: '荒憬尽怀忠，梯航已自通。\n九攻虽不战，五月尚持戎。\n遣戍征周牒，恢边重汉功。\n选车命元宰，授律取文雄。\n胄出天弧上，谋成帝幄中。\n诏旗分夏物，专土锡唐弓。\n帐宿伊川右，钲传晋苑东。\n饔人藉蕡实，乐正理丝桐。\n岐陌涵余雨，离川照晚虹。\n恭闻咏方叔，千载舞皇风。' },
  { title: '题袁氏别业', author: '贺知章', poem: '主人不相识，偶坐为林泉。\n莫谩愁沽酒，囊中自有钱。' },
  { title: '咏柳', author: '贺知章', poem: '碧玉妆成一树高，万条垂下绿丝绦。\n不知细叶谁裁出，二月春风似剪刀。' },
  { title: '采莲曲', author: '贺知章', poem: '稽山罢雾郁嵯峨，镜水无风也自波。\n莫言春度芳菲尽，别有中流采芰荷。' },
  { title: '回乡偶书二首 一', author: '贺知章', poem: '少小离家老大回，乡音难改鬓毛衰。\n儿童相见不相识，笑问客从何处来。' },
  { title: '回乡偶书二首 二', author: '贺知章', poem: '离别家乡岁月多，近来人事半销磨。\n唯有门前镜湖水，春风不改旧时波。' },
  { title: '答朝士', author: '贺知章', poem: '钑镂银盘盛蛤蜊，镜湖莼菜乱如丝。\n乡曲近来隹此味，遮渠不道是吴儿。' },
  { title: '敬酬张九龄当涂界留赠之作', author: '裴耀卿', poem: '茂先寔王佐，仲举信时英。\n气覩冲天发，人将下榻迎。\n珪符肃有命，江国远徂征。\n九派期方越，千钧或所轻。\n高帆出风迥，孤屿入云平。\n遄迈嗟于役，离忧空自情。\n餙簪陪早岁，接壤厕专城。\n旷别心弥轸，宏规义转倾。\n徒然恨饥渴，况乃讽瑶琼。' },
  { title: '酬张九龄使风见示', author: '裴耀卿', poem: '兹地五湖隣，艰哉万里人。\n惊飙翻是托，危浪亦相因。\n宣室才华子，金闺讽议臣。\n承明有三人，去去速归轮。' },
  { title: '赠张丞相', author: '宋鼎', poem: '汉上登飞幰，荆南历旧居。\n已尝临砌橘，更覩跃池鱼。\n盛德继微渺，深衷能卷舒。\n义申蓬阁际，情切庙堂初。\n郡挹文章美，人怀燮理余。\n皇恩傥照亮，岂厌承明庐。' },
  { title: '酬故人还山', author: '宋鼎', poem: '举櫂乘春水，归山抚岁华。\n碧潭宵见月，红树晚开花。\n肃穆轻风度，依微隐径斜。\n危亭暗松石，幽涧落云霞。\n思鸟吟高树，游鱼戏浅沙。\n安知余兴尽，相望紫烟赊。' },
  { title: '和张荆州九龄晨出郡舍林下', author: '崔颂', poem: '优闲表政清，林薄赏秋成。\n江上悬晓月，往来亏复盈。\n天云抗真意，郡阁晦高名。\n坐啸应无欲，宁辜济物情。' },
  { title: '奉酬张洪州九龄江上见赠', author: '孙翃', poem: '受命谳封疆，逢君牧豫章。\n于焉审虞芮，复尔共舟航。\n怅别秋阴尽，怀归客思长。\n江臯枉离赠，持此慰他乡。' },
  { title: '古意赠孙翃', author: '徐仁友', poem: '南望缑氏岭，山居共涧阴。\n东西十数里，缅邈方寸心。\n云日落广厦，莺花对孤琴。\n琴中多苦调，凄切谁复寻。' },
  { title: '奉和姚令公驾幸温汤喜雪应制', author: '苏绾', poem: '汉主新丰邑，周王尚父师。\n云符沛童唱，雪应海神期。\n林变惊春早，山明讶夕迟。\n况逢温液霈，恩重御裘诗。' },
  { title: '咏月', author: '康庭芝', poem: '天使下西楼，光含万里秋。\n台前疑挂镜，帘外似悬钩。\n张尹将眉学，班姬取扇俦。\n佳期应借问，为报在刀头。' },
  { title: '山行见孤松成咏', author: '张宣明', poem: '孤松郁山椒，肃爽凌清霄。\n既挺千丈干，亦生百尺条。\n青青恒一色，落落非一朝。\n大厦今已构，惜哉无人招。\n寒霜十二月，枝叶独不凋。' },
  { title: '使至三姓咽面', author: '张宣明', poem: '昔闻班家子，笔砚忽然投。\n一朝抚长劒，万里入荒陬。\n岂不服艰险，只思清国讐。\n山川去何岁，霜露几逢秋。\n玉塞已遐廓，铁关方阻修。\n东都日窅窅，西海此悠悠。\n卒使功名建，长封万里侯。' },
  { title: '新都南亭别郭大元振', author: '卢崇道', poem: '竹径女萝蹊，莲洲文石隄。\n静深人俗断，寻玩往还迷。\n碧潭秀初月，素林惊夕栖。\n褰幌纳鸟侣，罢琴听猨啼。\n佳辰改宿昔，胜寄在暌携。\n长怀赏心爱，如玉复如珪。' },
  { title: '登翅头山题俨公石壁', author: '包融', poem: '晨登翅头山，山曛黄雾起。\n却瞻迷向背，直下失城市。\n暾日衔东郊，朝光生邑里。\n扫除诸烟氛，照出众楼雉。\n青为洞庭山，白是太湖水。\n苍茫远郊树，倏忽不相似。\n万象以区别，森然共盈几。\n坐令开心胸，渐觉落尘滓。\n北岩千余仞，结庐谁家子。\n愿陪中峰游，朝暮白云里。' },
  { title: '阮公啸台', author: '包融', poem: '荒台森荆杞，蒙笼无上路。\n传是古人迹，阮公长啸处。\n至今清风来，时时动林树。\n逝者共已远，升攀想遗趣。\n静然荒榛门，久之若有悟。\n灵光未歇灭，千载知仰慕。' },
  { title: '酬忠公林亭', author: '包融', poem: '江外有真隐，寂居岁已侵。\n结庐近西术，种树久成阴。\n人迹乍及户，车声遥隔林。\n自言解尘事，咫尺能辎尘。\n为道岂庐霍，会静由吾心。\n方秋院木落，仰望日萧森。\n持我兴来趣，采菊行相寻。\n尘念到门尽，远情对君深。\n一谈入理窟，再索破幽襟。\n安得山中信，致书移尚禽。' },
  { title: '送国子张主簿', author: '包融', poem: '湖岸缆初解，莺啼别离处。\n遥见舟中人，时时一回顾。\n坐悲芳岁晚，花落青轩树。\n春梦随我心，悠扬逐君去。' },
  { title: '和陈校书省中玩雪', author: '包融', poem: '芸阁朝来雪，飘飖正满空。\n褰开明月下，校理落花中。\n色向怀铅白，光因翰简融。\n能令草玄者，回思入流风。' },
  { title: '和崔会稽咏王兵曹厅前涌泉势城中字', author: '包融', poem: '茂德来征应，流泉入咏歌。\n含灵符上善，作字表中和。\n有草恒垂露，无风欲偃波。\n为看人共水，清白定谁多。' },
  { title: '赋得岸花临水发', author: '包融', poem: '笑笑傍溪花，丛丛逐岸斜。\n朝开川上日，夜发浦中霞。\n照灼如临镜，䒠茸胜浣纱。\n春来武陵道，几树落仙家。' },
  { title: '武陵桃源送人', author: '包融', poem: '武陵川径入幽遐，中有鸡犬秦人家。\n先时见者为谁耶，源水今流桃复花。' },
  { title: '和荐福寺英公新搆禅堂', author: '丁仙芝', poem: '上人久弃世，中道自忘筌。\n寂照出群有，了心清众缘。\n所以于此地，筑馆开青莲。\n果药罗砌下，烟虹垂户前。\n咒中洒甘露，指处流香泉。\n禅远目无事，体清宵不眠。\n枳闻庐山法，松入汉阳禅。\n一枕西山外，虚舟常浩然。' },
  { title: '赠朱中书', author: '丁仙芝', poem: '十年种田滨五湖，十年遭涝尽为芜。\n频年井税常不足，今年缗钱谁为输。\n东邻转谷五之利，西邻贩缯日已贵。\n而我守道不迁业，谁能肯敢效此事。\n紫微侍郎白虎殿，出入通籍回天眷。\n晨趋彩笔柏梁篇，昼出雕盘大官膳。\n会应怜尔居素约，可即长年守贫贱。' },
  { title: '戏赠姚侍御', author: '丁仙芝', poem: '繁霜晓幕鸣柏乌，待子兽炭然金炉。\n重门启锁紫髯胡，新披骢马陇西驹。\n头戴獬豸急晨趋，明光殿前见天子，今日应弹佞幸夫。' },
  { title: '余杭醉歌赠吴山人', author: '丁仙芝', poem: '晓幕红襟燕，春城白项乌。\n只来梁上语，不向府中趋。\n城头坎坎鼓声曙，满庭新种樱桃树。\n桃花昨夜撩乱开，当轩发色映楼台。\n十千兑得余杭酒，二月春城长命杯。\n酒后留君待明月，还将明月送君回。' },
  { title: '京中守岁', author: '丁仙芝', poem: '守岁多然烛，通宵莫掩扉。\n客愁当暗满，春色向明归。\n玉斗巡初匝，银河落渐微。\n开正献岁酒，千里间庭闱。' },
  { title: '渡扬子江', author: '丁仙芝', poem: '桂檝中流望，空波两畔明。\n林开扬子驿，山出润州城。\n海尽边阴静，江寒朔吹生。\n更闻风叶下，淅沥度秋声。' },
  { title: '长宁公主旧山池', author: '丁仙芝', poem: '平阳旧池馆，寂寞使人愁。\n座卷流黄簟，帘垂白玉钩。\n庭闲花自落，门闭水空流。\n追想吹箫处，应随仙鹤游。' },
  { title: '剡谿馆闻笛', author: '丁仙芝', poem: '夜久闻羗笛，寥寥虚客堂。\n山空响不散，谿静曲宜长。\n草木生边气，城池泛夕凉。\n虚然异风出，髣髴宿平阳。' },
  { title: '越裳贡白雉', author: '丁仙芝', poem: '圣哲承休运，伊夔列上台。\n覃恩丹徼远，入贡素翚来。\n北阙欣初见，南枝顾未回。\n歛容残雪净，矫翼片云开。\n驯扰将无惧，翻飞幸不猜。\n甘从上林里，饮啄自徘徊。' },
  { title: '江南曲五首 一', author: '丁仙芝', poem: '长干斜路北，近浦是儿家。\n有意来相访，明朝出浣纱。' },
  { title: '江南曲五首 二', author: '丁仙芝', poem: '发向横塘口，船开值急流。\n知郎旧时意，且请拢船头。' },
  { title: '江南曲五首 三', author: '丁仙芝', poem: '昨暝逗南陵，风声波浪阻。\n入浦不逢人，归家谁信汝。' },
  { title: '江南曲五首 四', author: '丁仙芝', poem: '未晓已成妆，乘潮去茫茫。\n因从京口渡，使报邵陵王。' },
  { title: '江南曲五首 五', author: '丁仙芝', poem: '始下芙蓉楼，言发瑯琊岸。\n急为打船开，恶许傍人见。' },
  { title: '句', author: '丁仙芝', poem: '穷花常闭户，秋城闻捣衣。\n树回早秋色，川长迟落晖。' },
  { title: '石桥琪树', author: '蔡隐丘', poem: '山上天将近，人间路渐遥。\n谁当云里见，知欲渡仙桥。' },
  { title: '奉和扈从温泉宫承恩赐浴', author: '蔡希周', poem: '天行云从指骊宫，浴日余波锡诏同。\n彩殿氤氲拥香溜，纱窗宛转闭和风。\n来将兰气冲皇泽，去引星文捧碧空。\n自怜遇坎便能止，愿托仙槎路未通。' },
  { title: '同家兄题渭南王公别业', author: '蔡希寂', poem: '好闲知在家，退迹何必深。\n不出人境外，萧条江海心。\n轩车自来往，空名对清阴。\n川涘将钓玉，乡亭期散金。\n素晖射流濑，翠色緜森林。\n曾为诗书癖，宁惟耕稼任。\n吾兄许微尚，枉道来相寻。\n朝庆老莱服，夕闲安道琴。\n文章遥颂美，寤寐增所钦。\n既郁苍生望，明时岂陆沈。' },
  { title: '登福先寺上方然公禅室', author: '蔡希寂', poem: '名都标佛刹，梵构临河干。\n举目上方峻，森森青翠攒。\n步登诸劫尽，忽造浮云端。\n当暑敞扃闼，却嫌𫄨绤寒。\n禅房最高顶，静者殊闲安。\n疎雨向空城，数峰帘外盘。\n午钟振衣坐，招我同一餐。\n真味杂饴露，众香唯茝兰。\n晚来恣偃俛，茶果仍留欢。' },
  { title: '陕中作', author: '蔡希寂', poem: '西别秦关近，东行陕服长。\n川原余让畔，歌吹忆遗棠。\n河水流城下，山云起路傍。\n更怜栖泊处，池馆绕林篁。' },
  { title: '洛阳客舍逢祖咏留宴', author: '蔡希寂', poem: '緜緜钟漏洛阳城，客舍贫居绝送迎。\n逢君贳酒因成醉，醉后焉知世上情。' },
  { title: '赠张敬微', author: '蔡希寂', poem: '大河东北望桃林，杂树冥冥结翠阴。\n不知君作神仙尉，特讶行来云雾深。' },
  { title: '江风行', author: '张潮', poem: '壻贫如珠玉，壻富如埃尘。\n贫时不忘旧，富日多宠新。\n妾本富家女，与君为偶匹。\n惠好一何深，中门不曾出。\n妾有绣衣裳，葳蕤金缕光。\n念君贫且贱，易此从远方。\n远方三千里，思君心未已。\n日暮情更来，空望去时水。\n孟夏麦始秀，江上多南风。\n商贾归欲尽，君今尚巴东。\n巴东有巫山，窈窕神女颜。\n常恐游此方，果然不知还。' },
  { title: '襄阳行', author: '张潮', poem: '玉盘转明珠，君心无定准。\n昨见襄阳客，剩说襄阳好无尽。\n襄汉水，岘山垂，汉水东流风北吹。\n只言一世长娇宠，那悟今朝见别离。\n君渡清羗渚，知人独不语。\n妾见鸟栖林，忆君相思深。\n莫作云间鸿，离声顾俦侣。\n尚如匣中劒，分形会同处。\n是君妇，识君情，怨君恨君为此行。\n下床一宿不可保，况乃万里襄阳城。\n襄阳传近大堤北，君到襄阳莫回惑。\n大堤诸女儿，怜钱不怜德。' },
  { title: '采莲词', author: '张潮', poem: '朝出沙头日正红，晚来云起半江中。\n赖逢邻女曾相识，并着莲舟不畏风。' },
  { title: '江南行', author: '张潮', poem: '茨菰叶烂别西湾，莲子花开犹未还。\n妾梦不离江水上，人传郎在凤凰山。' },
  { title: '长干行', author: '张潮', poem: '忆昔深闺里，烟尘不曾识。\n嫁与长干人，沙头候风色。\n五月南风兴，思君下巴陵。\n八月西风起，想君发[扬]子。\n去来悲如何，见少离别多。\n湘潭几日到，妾梦越风波。\n昨夜狂风度，吹折江头树。\n淼淼暗无边，行人在何处。\n北客真三公，朱衣满江中。\n薄暮来投宿，数朝不肯东。\n好乘浮云骢，佳期兰渚东。\n鸳鸯绿浦上，翡翠锦屏中。\n自怜十五余，颜色桃花红。\n那作商人妇，愁水复愁风。' },
  { title: '游栖霞寺', author: '张翚', poem: '跻险入幽林，翠微含竹殿。\n泉声无休歇，山色时隐见。\n潮来杂风雨，梅落成霜霰。\n一从方外游，顿觉尘心变。' },
  { title: '绝句', author: '张翚', poem: '茫茫烟上水，日暮阴云飞。\n孤坐正愁绪，湖南谁捣衣。' },
  { title: '潘司马别业', author: '周瑀', poem: '门对青山近，汀牵绿草长。\n寒深包晚橘，风紧落垂杨。\n湖畔闻渔唱，天边数鴈行。\n萧然有高士，清思满书堂。' },
  { title: '送潘三入京', author: '周瑀', poem: '故人嗟此别，相送出烟坰。\n柳色分官路，荷香入水亭。\n离歌未尽曲，酌酒共忘形。\n把手河桥上，孤山日暮青。' },
  { title: '临川山行', author: '周瑀', poem: '朝见青山雪，暮见青山云。\n云山无断绝，秋思日纷纷。' },
  { title: '清谿馆作', author: '谈戭', poem: '指途清谿里，左右唯深林。\n云蔽望乡处，雨愁为客心。\n遇人多物役，听鸟时幽音。\n何必沧浪水，庶兹浣尘襟。' },
  { title: '塞上', author: '殷遥', poem: '万里𬯎城在，三边虏气衰。\n沙填孤嶂角，烧断故关碑。\n马色经寒惨，雕声带晚悲。\n将军正闲暇，留客换歌辞。' },
  { title: '送友人下第归省', author: '殷遥', poem: '君此卜行日，高堂应梦归。\n莫将和氏泪，滴着老莱衣。\n岳雨连河细，田禽出麦飞。\n到家调膳后，吟好送斜晖。' },
  { title: '送杜士瞻楚州觐省', author: '殷遥', poem: '风流与才思，俱似晋时人。\n淮月归心促，江花入兴新。\n云深苍海暮，柳暗白门春。\n共道官犹小，怜君孝养亲。' },
  { title: '友人山亭', author: '殷遥', poem: '故人虽薄宦，往往涉清溪。\n凿牖对山月，褰裳拂涧霓。\n游鱼逆水上，宿鸟向风栖。\n一见桃花发，能令秦汉迷。' },
  { title: '春晚山行', author: '殷遥', poem: '寂历青山晚，山行趣不稀。\n野花成子落，江燕引雏飞。\n暗草薰苔径，晴杨扫石矶。\n俗人犹语此，余亦转忘归。' },
  { title: '寄张征古', author: '沈如筠', poem: '寂历远山意，微冥半空碧。\n绿萝无冬春，彩云竟朝夕。\n张子海内奇，久为岩中客。\n圣君当梦想，安得老松石。' },
  { title: '闺怨二首 一', author: '沈如筠', poem: '鴈尽书难寄，愁多梦不成。\n愿随孤月影，流照伏波营。' },
  { title: '闺怨二首 二', author: '沈如筠', poem: '陇底嗟长别，流襟一动君。\n何言幽咽所，更作死生分。' },
  { title: '寄天台司马道士', author: '沈如筠', poem: '河洲花艳爚，庭树光彩蒨。\n白云天台山，可思不可见。' },
  { title: '句', author: '沈如筠', poem: '思酸寒鴈断，淅沥秋树空。\n渔阳燕旧都，美女花不如。' },
  { title: '咏黄莺', author: '孙处玄', poem: '欲啭声犹涩，将飞羽未调。\n高风不借便，何处得迁乔。' },
  { title: '失题', author: '孙处玄', poem: '汉家轻壮士，无状杀彭王。\n一遇风尘起，令谁守四方。' },
  { title: '句', author: '孙处玄', poem: '残花与露落，堕叶随风翻。\n日侧南涧幽，风凝北林暮。' },
  { title: '折杨柳', author: '徐延寿', poem: '大道连国门，东西种杨柳。\n葳蕤君不见，袅娜垂来久。\n缘枝栖暝禽，雄去雌独吟。\n余花怨春尽，微月起秋阴。\n坐望窗中蝶，起攀枝上叶。\n好风吹长条，婀娜何如妾。\n妾见柳园新，高楼四五春。\n莫吹胡塞曲，愁杀陇头人。' },
  { title: '南州行', author: '徐延寿', poem: '摇艇至南国，国门连大江。\n中洲西边岸，数步一垂杨。\n金钏越溪女，罗衣胡粉香。\n织缣春卷幔，采蕨暝提筐。\n弄瑟娇垂幌，迎人笑下堂。\n河头浣衣处，无数紫鸳鸯。' },
  { title: '人日剪彩', author: '徐延寿', poem: '闺妇持刀坐，自怜裁剪新。\n叶催情缀色，花寄手成春。\n帖燕留妆户，黏鸡待饷人。\n擎来问夫壻，何处不如真。' },
  { title: '南中感怀', author: '樊晃', poem: '南路磋跎客未回，常嗟物候暗相催。\n四时不变江头草，十月先开岭上梅。' },
  { title: '和户部杨员外伯成寓直', author: '李憕', poem: '落日弥纶地，公才画省郎。\n词惊起草笔，坐引护衣香。\n双阙天河近，千门夕漏长。\n遥知台上宿，不独有文强。' },
  { title: '同望幸新亭赐钱公宴', author: '李憕', poem: '感梦通玄化，覃恩降紫宸。\n赐钱开汉府，分帛醉尧人。\n地隔朝宗庆，亭临卜洛新。\n行看广云雨，二月次东巡。' },
  { title: '奉和圣制从蓬莱向兴庆阁道中留春雨中春望之作应制', author: '李憕', poem: '别馆春还淑气催，三宫路转凤皇台。\n云飞北阙轻阴散，雨歇南山积翠来。\n御柳遥随天仗发，林花不待晓风开。\n已知圣泽深无限，更喜年芳入睿才。' },
  { title: '铜雀妓', author: '李邕', poem: '西陵望何及，弦管徒在兹。\n谁言死者乐，但令生者悲。\n丈夫有余志，儿女焉足私。\n扰扰多俗情，投迹互相师。\n直节岂感激，荒淫乃凄其。\n颍水有许由，西山有伯夷。\n颂声何寥寥，唯闻铜雀诗。\n君举良未易，永为后代嗤。' },
  { title: '咏云', author: '李邕', poem: '彩云惊岁晚，缭绕孤山头。\n散作五般色，凝为一段愁。\n影虽沈涧底，形在天际游。\n风动必飞去，不应长此留。' },
  { title: '登历下古城员外孙新亭', author: '李邕', poem: '吾宗固神秀，体物写谋长。\n形制开古迹，曾冰延乐方。\n太山雄地理，巨壑眇云庄。\n高兴汨烦促，永怀清典常。\n含弘知四大，出入见三光。\n负郭喜秔稻，安时歌吉祥。' },
  { title: '奉和初春幸太平公主南庄应制', author: '李邕', poem: '传闻银汉支机石，复见金舆出紫微。\n织女桥边乌鹊起，仙人楼上凤皇飞。\n流风入座飘歌扇，瀑水侵阶溅舞衣。\n今日还同犯牛斗，乘槎共逐海潮归。' },
  { title: '奉使登终南山', author: '王湾', poem: '常爱南山游，因而尽原隰。\n数朝至林岭，百仞登嵬岌。\n石壮马径穷，苔色步缘入。\n物奇春状改，气远天香集。\n虚洞策杖鸣，低云拂衣湿。\n倚岩见庐舍，入户欣拜揖。\n问性矜勤劳，示心教澄习。\n玉英时共饭，芝草为余拾。\n境绝人不行，潭深鸟空立。\n一乘从此授，九转兼是给。\n辞处若轻飞，憩来唯吐吸。\n闲襟超已胜，回路倏而及。\n烟色松上深，水流山下急。\n渐平逢车骑，向晚睨城邑。\n峰在野趣繁，尘飘宦情澁。\n辛苦久为吏，劳生何妄执。\n日暮怀此山，悠然赋斯什。' },
  { title: '晚夏马嵬卿叔池亭即事寄京都一二知己', author: '王湾', poem: '忝职畿甸淹，滥陪时俊后。\n才轻策疲劣，势薄常驱走。\n牵役劳风尘，秉心在岩薮。\n宗贤开别业，形胜代希偶。\n竹绕清渭滨，泉流白渠口。\n逡巡期赏会，挥忽变星斗。\n逮此乘务闲，因而访幽叟。\n入来殊景物，行复洗纷垢。\n林静秋色多，潭深月光厚。\n盛香莲近拆，新味瓜初剖。\n滞拙怀隐沦，书之寄良友。' },
  { title: '丽正殿赐宴同勒天前烟年四韵应制', author: '王湾', poem: '金殿忝陪贤，琼羞忽降天。\n鼎罗仙掖里，觞拜琐闱前。\n院逼青霄路，厨和紫禁烟。\n酒酣空忭舞，何以荅昌年。' },
  { title: '奉和贺监林月清酌', author: '王湾', poem: '华月当秋满，朝英假兴同。\n净林新霁入，规院小凉通。\n碎影行筵里，摇花落酒中。\n清宵凝爽意，倂此助文雄。' },
  { title: '次北固山下', author: '王湾', poem: '客路青山外，行舟绿水前。\n潮平两岸阔，风正一帆悬。\n海日生残夜，江春入旧年。\n乡书何处达，归雁洛阳边。' },
  { title: '观搊筝', author: '王湾', poem: '虚室有秦筝，筝新月复清。\n弦多弄委曲，柱促语分明。\n晓怨凝繁手，春娇入曼声。\n近来唯此乐，传得美人情。' },
  { title: '晚春诣苏州敬赠武员外', author: '王湾', poem: '苏台忆季常，飞櫂历江乡。\n持此功曹掾，初离华省郎。\n贵门生礼乐，明代秉文章。\n嘉郡位先进，鸿儒名重扬。\n爰从姻娅贬，岂失忠信防。\n万里行骥足，十年暌凤翔。\n回迁翊元圣，入拜伫惟良。\n别业对南浦，群书满北堂。\n意深投辖盛，才重接筵光。\n陋学叨铅简，弱龄许翰场。\n神驰劳旧国，颜展别殊方。\n际晓杂氛散，残春众物芳。\n烟和疎树满，雨续小谿长。\n旅拙感成慰，通贤顾不忘。\n从来琴曲罢，开匣为君张。' },
  { title: '秋夜寓直即事怀赠萧令公裴侍郎兼通简南省诸友人', author: '王湾', poem: '圣主万年兴，贤臣数载升。\n古灵传岳秀，宏量禀川澄。\n畿甸举长策，风霜秉直绳。\n出车遥俗震，登阁满朝称。\n赋简流亡辑，农安政理凭。\n还家新长幼，巡垅旧沟塍。\n忠梗大勋立，寰瀛堕业惩。\n焚香兼御史，悬镜委中丞。\n旟隼当朝立，台骢发郡乘。\n司徒汉家重，国典颍川征。\n云路俄平入，台阶忽上凌。\n秉钧调造化，宣綍慰黎烝。\n金省方秋作，瑶轩直夜凭。\n中书赠陈准，右相简王陵。\n三杰贤更穆，百僚欢且兢。\n摇怀及宾友，计曲辨淄渑。\n阊阖暝阴散，钩陈爽气凝。\n月深宫树转，河近禁楼冰。\n卑吏夙驱策，微涓效斗升。\n望麾宵继火，书板曙怀蒸。\n彼此虽流盼，规模转服膺。\n惠将霄汉隔，劳或岁时矜。\n位重恩宁滥，才轻慑不胜。\n林峦甘独往，疵贱苦相仍。\n敢忘衔花雀，思同附骥蝇。\n平生逐鸟雀，何日嗣苍鹰。' },
  { title: '哭补阙亡友綦毋学士', author: '王湾', poem: '明代资多士，儒林得异才。\n书从金殿出，人向玉墀来。\n词学张平子，风仪褚彦回。\n崇仪希上德，近侍接元台。\n曩契心期早，今游宴赏陪。\n屡迁君擢桂，分尉我从梅。\n忽遇乘轺客，云倾构厦材。\n泣为洹水化，叹作泰山颓。\n冀善初将慰，寻言半始猜。\n位联情易感，交密痛难裁。\n远日寒旌暗，长风古挽哀。\n寰中无旧业，行处有新苔。\n反哭魂犹寄，终丧子尚孩。\n葬田门吏给，坟木路人栽。\n遽泄悲成往，俄传宠令回。\n玄经贻石室，朱绂耀泉台。\n地古春长闭，天明夜不开。\n登山一临哭，挥泪满蒿莱。' },
  { title: '闰月七日织女', author: '王湾', poem: '耿耿曙河微，神仙此夜稀。\n今年七月闰，应得两回归。' },
  { title: '应诏赋得除夜', author: '史青', poem: '今岁今宵尽，明年明日催。\n寒随一夜去，春逐五更来。\n气色空中改，容颜暗里回。\n风光人不觉，已着后园梅。' },
  { title: '汴堤柳', author: '王泠然', poem: '隋家天子忆扬州，厌坐深宫傍海游。\n穿地凿山开御路，鸣笳叠鼓泛清流。\n流从巩北分河口，直到淮南种官柳。\n功成力尽人旋亡，代谢年移树空有。\n当时彩女侍君王，绣帐旌门对柳行。\n青叶交垂连幔色，白花飞度染衣香。\n今日摧残何用道，数里曾无一枝好。\n驿骑征帆损更多，山精野魅藏应老。\n凉风八月露为霜，日夜孤舟入帝乡。\n河畔时时闻木落，客中无不泪沾裳。' },
  { title: '夜光篇', author: '王泠然', poem: '游人夜到汝阳间，夜色冥蒙不解颜。\n谁家暗起寒山烧，因此明中得见山。\n山头山下须臾满，历险缘深无暂断。\n焦声散着群树鸣，炎气傍林一川暖。\n是时西北多海风，吹上连天光更雄。\n浊烟熏月黑，高艳𦶟云红。\n初谓炼丹仙灶里，还疑铸劒神谿中。\n划为飞电来照物，乍作流星并上空。\n西山无草光已灭，东顶荧荧犹未绝。\n沸汤空谷数道水，融盖阴崖几年雪。\n两京贫病若为居，四壁皆成凿照余。\n未得贵游同秉烛，唯将半影借披书。' },
  { title: '古木卧平沙', author: '王泠然', poem: '古木卧平沙，摧残岁月赊。\n有根横水石，无叶拂烟霞。\n春至苔为叶，冬来雪作花。\n不逢星汉使，谁辨是灵槎。' },
  { title: '淮南寄舍弟', author: '王泠然', poem: '昔予从不调，经岁旅淮源。\n念尔长相失，何时返故园。\n寄书迷处所，分袂隔凉温。\n远道俱为客，他乡共在原。\n归情春伴雁，愁泣夜随猨。\n愧见高堂上，朝朝独倚门。' },
  { title: '句', author: '王泠然', poem: '林狖欺童子，山精试老僧。\n陈兵劒阁山将动，饮马珠江水不流。\n官微思倚玉，文浅怯投珠。' },
  { title: '春江花月夜二首 一', author: '张子容', poem: '林花发岸口，气色动江新。\n此夜江中月，流光花上春。\n分明石潭里，宜照浣纱人。' },
  { title: '春江花月夜二首 二', author: '张子容', poem: '交甫怜瑶珮，仙妃难重期。\n沈沈绿江晚，惆怅碧云姿。\n初逢花上月，言是弄珠时。' },
  { title: '云阳驿陪崔使君邵道士夜宴', author: '张子容', poem: '一尉东南远，谁知此夜欢。\n诸侯倾皂盖，仙客整黄冠。\n染翰灯花满，飞觞云气寒。\n欣承国士遇，更借美人看。' },
  { title: '除夜乐城逢孟浩然', author: '张子容', poem: '远客襄阳郡，来过海岸家。\n樽开柏叶酒，灯发九枝花。\n妙曲逢卢女，高才得孟嘉。\n东山行乐意，非是竞繁华。' },
  { title: '送苏倩游天台', author: '张子容', poem: '灵异寻沧海，笙歌访翠微。\n江鸥迎共狎，云鹤待将飞。\n琪树尝仙果，琼楼试羽衣。\n遥知神女问，独怪阮郎归。' },
  { title: '泛永嘉江日暮回舟', author: '张子容', poem: '无云天欲暮，轻鹢大江清。\n归路烟中远，回舟月上行。\n傍潭窥竹暗，出屿见沙明。\n更值微风起，乘流丝管声。' },
  { title: '永嘉即事寄赣县袁少府瓘', author: '张子容', poem: '山绕楼台出，谿通里闬斜。\n曾为谢客郡，多有逐臣家。\n海气朝成雨，江天晚作霞。\n题书报贾谊，此湿似长沙。' },
  { title: '乐城岁日赠孟浩然', author: '张子容', poem: '土地穷瓯越，风光肇建寅。\n插桃销瘴疠，移竹近阶墀。\n半是吴风俗，仍为楚岁时。\n更逢习凿齿，言在汉川湄。' },
  { title: '永嘉作', author: '张子容', poem: '拙宦从江左，投荒更海边。\n山将孤屿近，水共恶谿连。\n地湿梅多雨，潭蒸竹起烟。\n未应悲晚髪，炎瘴苦华年。' },
  { title: '送孟八浩然归襄阳二首 一', author: '张子容', poem: '东越相逢地，西亭送别津。\n风潮看解缆，云海去愁人。\n乡在桃林岸，山连枫树春。\n因怀故园意，归与孟家邻。' },
  { title: '送孟八浩然归襄阳二首 二', author: '张子容', poem: '杜门不欲出，久与世情疎。\n以此为长策，劝君归旧庐。\n醉歌田舍酒，笑读古人书。\n好是一生事，无劳献子虚。' },
  { title: '贬乐城尉日作', author: '张子容', poem: '窜谪边穷海，川原近恶谿。\n有时闻虎啸，无夜不猿啼。\n地暖花长发，岩高日易低。\n故乡可忆处，遥指斗牛西。' },
  { title: '自乐城赴永嘉枉路泛白湖寄松阳李少府', author: '张子容', poem: '西行碍浅石，北转入谿桥。\n树色烟轻重，湖光风动摇。\n百花乱飞雪，万岭叠青霄。\n猿挂临潭筿，鸥迎出浦桡。\n惟应赏心客，兹路不言遥。' },
  { title: '九日陪润州邵使君登北固山', author: '张子容', poem: '五马向西椒，重阳坐丽谯。\n徐州带绿水，楚国在青霄。\n张幕连江树，开筵接海潮。\n凌云词客语，回雪无人娇。\n梅福惭仙吏，羊公赏下僚。\n新丰酒旧美，况是菊花朝。' },
  { title: '璧池望秋月', author: '张子容', poem: '凉夜窥清沼，池空水月秋。\n满轮沈玉镜，半魄落银钩。\n蟾影摇轻浪，菱花渡浅流。\n漏移光渐洁，云敛色偏浮。\n似璧悲三献，疑珠怯再投。\n能持千里意，来照楚乡愁。' },
  { title: '长安早春', author: '张子容', poem: '开国维东井，城池起北辰。\n咸歌太平日，共乐建寅春。\n雪尽黄山树，冰开黑水津。\n草迎金埒马，花伴玉楼人。\n鸿渐看无数，莺歌听欲频。\n何当桂枝擢，还及柳条新。' },
  { title: '赠司勋萧郎中', author: '张子容', poem: '作相开黄阁，为郎奏赤墀。\n君臣道合体，父子贵同时。\n国以推贤答，家无内举疑。\n凤池真水镜，兰省得华滋。\n未覩风流日，先闻新赋诗。\n江山清谢朓，花木媚丘迟。\n吏部来何暮，王言念在兹。\n丹青无不可，霖雨亦相期。\n昔我投荒处，孤烟望岛夷。\n群鸥终日狎，落叶数年悲。\n渔父留歌咏，江妃入兴词。\n今将献知己，相感勿吾欺。' },
  { title: '巫山', author: '张子容', poem: '巫岭岧峣天际重，佳期宿昔愿相从。\n朝云暮雨连天暗，神女知来第几峰。' },
  { title: '除日', author: '张子容', poem: '腊月今知晦，流年此夕除。\n拾樵供岁火，帖牖作春书。\n柳觉东风至，花疑小雪余。\n忽逢双鲤赠，言是上冰鱼。' },
  { title: '清谿泛舟', author: '张旭', poem: '旅人倚征棹，薄暮起劳歌。\n笑揽清谿月，清辉不厌多。' },
  { title: '桃花谿', author: '张旭', poem: '隐隐飞桥隔野烟，石矶西畔问渔船。\n桃花尽日随流水，洞在清谿何处边。' },
  { title: '山行留客', author: '张旭', poem: '山光物态弄春辉，莫为轻阴便拟归。\n纵使晴明无雨色，入云深处亦沾衣。' },
  { title: '春游值雨', author: '张旭', poem: '欲寻轩槛列清尊，江上烟云向晚昏。\n须倩东风吹散雨，明朝却待入华园。' },
  { title: '春草', author: '张旭', poem: '春草青青万里余，边城落日见离居。\n情知海上三年别，不寄云间一纸书。' },
  { title: '柳', author: '张旭', poem: '濯濯烟条拂地垂，城边楼畔结春思。\n请君细看风流意，未减灵和殿里时。' },
  { title: '南山', author: '贺朝', poem: '湖北雨初晴，湖南山尽见。\n岩岩石帆影，如得海风便。\n仙穴茅山峰，彩云时一见。\n邀君共探此，异箓残几卷。' },
  { title: '孤兴', author: '贺朝', poem: '晴日暖珠箔，夭桃色正新。\n红粉青镜中，娟娟可怜嚬。\n君子在遐险，蕙心谁见珍。\n罗幕空掩昼，玉颜静移春。\n江瑟语幽独，再三情未申。\n黄鹄千里翅，芳音迟所因。' },
  { title: '从军行', author: '贺朝', poem: '朔胡乘月寇边城，军书插羽刺中京。\n天子金坛拜飞将，单于玉塞振佳兵。\n骑射先鸣推任侠，龙韬决胜伫时英。\n闻有河湟客，愔愔理帷帟。\n常山启霸图，汜水先天策。\n衔珠浴铁向桑干，衅旗膏劒指乌丸。\n鸣鸡已报关山晓，来雁遥传沙塞寒。\n直为甘心从苦节，陇头流水鸣呜咽。\n边树萧萧不觉春，天山漠漠长飞雪。\n鱼丽阵接塞云平，雁翼营通海月明。\n始看晋幕飞鹅入，旋闻齐垒啼乌声。\n自从一戍燕支山，春光几度晋阳关。\n金河未转青丝骑，玉筯应啼红粉颜。\n鸿归燕相续，池边芳草绿。\n已见氛清细柳营，莫更春歌落梅曲。\n烽沈灶减静边亭，海[晏]山空肃已宁。\n行望凤京旋凯捷，重来麟阁画丹青。' },
  { title: '赋得游人久不归', author: '贺朝', poem: '乡关眇天末，引领怅怀归。\n羇旅久淫滞，物色屡芳菲。\n稍觉出意尽，行看蓬鬓稀。\n如何千里外，伫立沾裳衣。' },
  { title: '宿香山阁', author: '贺朝', poem: '暝上春山阁，梯云宿半空。\n轩窗闭潮海，枕席拂烟虹。\n朱网防栖鸽，纱灯护夕虫。\n一闻鸡唱晓，已见日曈曈。' },
  { title: '赠酒店胡姬', author: '贺朝', poem: '胡姬春酒店，弦管夜锵锵。\n红毾铺新月，貂裘坐薄霜。\n玉盘初鲙鲤，金鼎正烹羊。\n上客无劳散，听歌乐世娘。' },
  { title: '赋得春莺送友人二首 一', author: '贺朝', poem: '翅掩飞莺舞，啼恼婕妤悲。\n料取金闺意，因君问所思。' },
  { title: '赋得春莺送友人二首 二', author: '贺朝', poem: '流莺拂绣羽，二月上林期。\n待雪销金禁，衔花向玉墀。' },
  { title: '三日绿潭篇', author: '万齐融', poem: '春潭滉漾接隋宫，宫阙连延潭水东。\n苹苔嫩色涵波绿，桃李新花照底红。\n垂菱布藻如妆镜，丽日晴天相照暎。\n素影沈沈对蝶飞，金沙砾砾窥鱼泳。\n佳人祓禊赏韶年，倾国倾城并可怜。\n拾翠总来芳树下，踏青争遶绿潭边。\n公子王孙恣游玩，沙阳水曲情无厌。\n禽浮似挹羽觞杯，鳞跃疑投水心劒。\n金鞍玉勒骋轻肥，落絮红尘拥路飞。\n绿水残霞催席散，画楼初月待人归。' },
  { title: '仗劒行', author: '万齐融', poem: '昨夜星官动紫微，今年天子用武威。\n登车一呼风雷动，遥震阴山撼巍巍。\n胡骄子，当见旄头蚀应死。\n愿骑单马仗天威，挼取长绳缚虏归。\n仗劒遥叱路傍子，匈奴头血溅君衣。' },
  { title: '赠别江头', author: '万齐融', poem: '东南飞鸟处，言是故乡天。\n江上风花晚，君行定几千。\n计程频破月，数别屡开年。\n明岁浔阳水，相思寄采莲。' },
  { title: '送陈七还广陵', author: '万齐融', poem: '风流谁代子，虽有旧无双。\n欢酒言相送，愁弦意不降。\n落花馥河道，垂杨拂水窗。\n海潮与春梦，朝夕广陵江。' },
  { title: '游春', author: '邢巨', poem: '海岳三峰古，春皇二月寒。\n绿潭渔子钓，红树美人攀。\n弱蔓环沙屿，飞花点石关。\n谿山游未厌，琴酌弄晴湾。' },
  { title: '游宣州琴谿同武平一作', author: '邢巨', poem: '灵谿非人迹，仙意素所秉。\n鳞岭森翠微，澄潭照秋景。' },
  { title: '春江花月夜', author: '张若虚', poem: '春江潮水连海平，海上明月共潮生。\n滟滟随波千万里，何处春江无月明？\n江流宛转遶芳甸，月照花林皆似霰。\n空里流霜不觉飞，汀上白沙看不见。\n江天一色无纤尘，皎皎空中孤月轮。\n江畔何人初见月，江月何年初照人？\n人生代代无穷已，江月年年秖相似。\n不知江月待何人？但见长江送流水。\n白云一片去悠悠，青枫浦上不胜愁。\n谁家今夜扁舟子，何处相思明月楼？\n可怜楼上月裴回，应照离人妆镜台。\n玉户帘中卷不去，捣衣砧上拂还来。\n此时相望不相闻，愿逐月华流照君。\n鸿雁长飞光不度，鱼龙潜跃水成文。\n昨夜闲潭梦落花，可怜春半不还家。\n江水流春去欲尽，江潭落月复西斜。\n斜月沈沈藏海雾，碣石潇湘无限路。\n不知乘月几人归，落月摇情满江树。' },
  { title: '代答闺梦还', author: '张若虚', poem: '关塞年华早，楼台别望违。\n试衫着煖气，开镜觅春晖。\n燕入窥罗幕，蜂来上画衣。\n情催桃李艳，心寄管弦飞。\n妆洗朝相待，风花暝不归。\n梦魂何处入，寂寂掩重扉。' },
  { title: '洪州客舍寄柳博士芳', author: '薛业', poem: '去年燕巢主人屋，今年花发路傍枝。\n年年为客不到舍，旧国存亡那得知。' },
  { title: '晚秋赠张折冲', author: '薛业', poem: '都尉今无事，时清但闭关。\n夜霜戎马瘦，秋草射堂闲。\n位以穿杨得，名因折桂还。\n冯唐真不遇，叹息鬓毛斑。' },
  { title: '和左司张员外自洛使入京中路先赴长安逢立春日赠韦侍御等诸公', author: '孙逖', poem: '拜郎登省闼，奉使驰车乘。\n遥瞻使者星，便是郎官应。\n台妙时相许，皇华德弥称。\n二陕听风谣，三秦望形胜。\n此中暌益友，是日多诗兴。\n寒尽岁阴催，春归物华证。' },
  { title: '和登会稽山', author: '孙逖', poem: '稽山碧湖上，势入东溟尽。\n烟景昼清明，九峰争隐嶙。\n望中厌朱绂，俗内探玄牝。\n野老听鸣驺，山童拥行轸。\n仙花寒未落，古蔓柔堪引。\n竹磵入山多，松崖向天近。\n云从海天去，日就江村陨。\n能赋丘尝闻，和歌参不敏。\n冥搜信冲漠，多士期标准。\n愿奉濯缨心，长谣反招隐。' },
  { title: '送杨法曹按括州', author: '孙逖', poem: '东海天台山，南方缙云驿。\n溪澄问人隐，岩险烦登陟。\n潭壑随星使，轩车绕春色。\n傥寻琪树人，为报长相忆。' },
  { title: '葛山潭', author: '孙逖', poem: '圆潭写流月，晴明涵万象。\n仙翁何时还，绿水空荡漾。\n凉哉草木腓，白露沾人衣。\n犹醉空山里，时闻笙鹤飞。' },
  { title: '丹阳行', author: '孙逖', poem: '丹阳古郡洞庭阴，落日扁舟此路寻。\n传是东南旧都处，金陵中断碧江深。\n在昔风尘起，京都乱如毁。\n双阙戎虏间，千门战场里。\n传闻一马化为龙，南渡衣冠亦愿从。\n石头横帝里，京口拒戎锋。\n青枫林下回天跸，杜若洲前转国容。\n都门不见河阳树，辇道唯闻建业钟。\n中原悠悠几千里，欲扫欃枪未云已。\n英雄倾夺何纷然，一盛一衰如逝川。\n可怜宫观重江里，金镜相传三百年。\n自从龙见圣人出，六合车书混为一。\n昔年王气今何在，并向长安就尧日。\n荆榛古木闭荒阡，共道繁华不复全。\n赤县唯余江树月，黄图半入海人烟。\n暮来山水登临遍，览古愁吟泪如霰。\n唯有空城多白云，春风淡荡无人见。' },
  { title: '山阴县西楼', author: '孙逖', poem: '都邑西楼芳树间，逶迤霁色遶江山。\n山月夜从公署出，江云晚对讼庭还。\n谁知春色朝朝好，二月飞花满江草。\n一见湖边杨柳风，遥忆青青洛阳道。' },
  { title: '夜宿浙江', author: '孙逖', poem: '扁舟夜入江潭泊，露白风高气萧索。\n富春渚上潮未还，天姥岑边月初落。\n烟水茫茫多苦辛，更闻江上越人吟。\n洛阳城阙何时见，西北浮云朝暝深。' },
  { title: '春日留别', author: '孙逖', poem: '春路逶迤花柳前，孤舟晚泊就人烟。\n东山白云不可见，西陵江月夜娟娟。\n春江夜尽潮声度，征帆遥从此中去。\n越国山川看渐无，可怜愁思江南树。' },
  { title: '奉和四月三日上阳水窗赐宴应制得春字', author: '孙逖', poem: '今日逢初夏，欢游续旧旬。\n气和先作雨，恩厚别成春。\n凤吹临清洛，龙舆下紫宸。\n此中歌在藻，还见跃潜鳞。' },
  { title: '奉和登会昌山应制', author: '孙逖', poem: '岩磴列云旗，吾君访道时。\n干行万物覩，日驭六龙迟。\n望远回天顾，登高动睿词。\n愿因山作寿，长保会昌期。' },
  { title: '正月十五日夜应制', author: '孙逖', poem: '洛城三五夜，天子万年春。\n彩仗移双阙，琼筵会九宾。\n舞成苍颉字，灯作法王轮。\n不觉东方日，遥垂御藻新。' },
  { title: '奉和御制登鸳鸯楼即目应制', author: '孙逖', poem: '玉辇下离宫，琼楼上半空。\n方巡五年狩，更辟四门聪。\n井邑观秦野，山河念禹功。\n停銮留睿作，轩槛起南风。' },
  { title: '进船泛洛水应制', author: '孙逖', poem: '禁园纡睿览，仙櫂叶时游。\n洛北风花树，江南彩画舟。\n芳生兰蕙草，春入凤凰楼。\n兴尽离宫暮，烟光起夕流。' },
  { title: '和常州崔使君寒食夜', author: '孙逖', poem: '闻道清明近，春庭向夕阑。\n行游昼不厌，风物夜宜看。\n斗柄更初转，梅香暗里残。\n无劳秉华烛，清月在南端。' },
  { title: '和韦兄春日南亭宴兄弟', author: '孙逖', poem: '台阁升高位，园林隔旧乡。\n忽闻歌棣萼，还比报琼芳。\n门向宜春近，郊连御宿长。\n德星常有会，相望在文昌。' },
  { title: '奉和崔司马游云门寺', author: '孙逖', poem: '系马清溪树，禅门春气浓。\n香台花下出，讲坐竹间逢。\n觉路山童引，经行谷鸟从。\n更言穷寂灭，回策上南峰。' },
  { title: '酬万八贺九云门下归溪中作', author: '孙逖', poem: '晚从灵境出，林壑曙云飞。\n稍觉清溪尽，回瞻画刹微。\n独园余兴在，孤櫂宿心违。\n更忆登攀处，天香满袖归。' },
  { title: '春初送吕补阙往西岳勒碑得云字', author: '孙逖', poem: '刻石记天文，朝推谷子云。\n箧中缄圣札，岩下揖神君。\n语别梅初艳，为期草欲薰。\n往来春不尽，离思莫氛氲。' },
  { title: '送越州裴参军充使入京', author: '孙逖', poem: '日落川径寒，离心苦未安。\n客愁西向尽，乡梦北归难。\n霜果林中变，秋花水上残。\n明朝渡江后，云物向南看。' },
  { title: '送周判官往台州', author: '孙逖', poem: '吾宗长作赋，登陆访天台。\n星使行看入，云仙意转催。\n饮冰攀璀璨，驱传历莓苔。\n日暮东郊别，真情去不回。' },
  { title: '送魏骑曹充宇文侍御判官分按山南', author: '孙逖', poem: '云雨阳台路，光华驿骑巡。\n劝农开梦土，恤隐惠荆人。\n楼迥吟黄鹤，江长望白苹。\n观风布明诏，更是汉南春。' },
  { title: '送苏郎中绾出佐荆州', author: '孙逖', poem: '神仙久留滞，清切伫飞翻。\n忽佐南方牧，何时西掖垣。\n高车自兰省，便道出荆门。\n不见河梁别，空销郢路魂。' },
  { title: '冬末送魏起居赴京', author: '孙逖', poem: '大名将起魏，良史更逢迁。\n驿骑朝丹阙，关亭望紫烟。\n西京春色近，东观物华偏。\n早赴王正月，挥毫记首年。' },
  { title: '送李补阙摄御史充河西节度判官', author: '孙逖', poem: '昔年叨补衮，边地亦埋轮。\n官序慙先达，才名畏后人。\n西戎虽献款，上策耻和亲。\n早赴前军幕，长清外域尘。' },
  { title: '送赵评事摄御史监军岭南', author: '孙逖', poem: '议狱持邦典，临戎假宪威。\n风从阊阖去，霜入洞庭飞。\n篁竹迎金鼓，楼船引绣衣。\n明年拜真月，南斗使星归。' },
  { title: '送靳十五侍御使蜀', author: '孙逖', poem: '天使出霜台，行人择吏才。\n传车春色送，离兴夕阳催。\n驿遶巴江转，关迎劒道开。\n西南一何幸，前后二龙来。' },
  { title: '送李给事归徐州觐省', author: '孙逖', poem: '列位登青琐，还乡复彩衣。\n共言晨省日，便是昼游归。\n春水经梁宋，晴山入海沂。\n莫愁东路远，四牡正𬴂𬴂。' },
  { title: '送杜侍御赴上都', author: '孙逖', poem: '避马台中贵，登车岭外遥。\n还因贡赋礼，来谒大明朝。\n地入商山路，乡连渭水桥。\n承恩返南越，尊酒重相邀。' },
  { title: '送张环摄御史监南选', author: '孙逖', poem: '汉使得张纲，威名摄远方。\n恩沾柱下史，荣比选曹郎。\n江带黔中阔，山连峡水长。\n莫愁炎暑地，秋至有严霜。' },
  { title: '宴越府陈法曹西亭', author: '孙逖', poem: '公府西岩下，红亭间白云。\n雪梅初度腊，烟竹稍迎曛。\n水木涵澄景，帘栊引霁氛。\n江南归思逼，春鴈不堪闻。' },
  { title: '同邢判官寻龙湍观归湖中', author: '孙逖', poem: '星使下仙京，云湖喜昼晴。\n更从探穴处，还作櫂歌行。\n丝管荷风入，帘帷竹气清。\n莫愁归路远，水月夜虚明。' },
  { title: '寻龙湍', author: '孙逖', poem: '仙穴寻遗迹，轻舟爱水乡。\n溪流一曲尽，山路九峰长。\n渔父歌金洞，江妃舞翠房。\n遥怜葛仙宅，真气共微茫。' },
  { title: '宿云门寺阁', author: '孙逖', poem: '香阁东山下，烟花象外幽。\n悬灯千嶂夕，卷幔五湖秋。\n画壁余鸿鴈，纱窓宿斗牛。\n更疑天路近，梦与白云游。' },
  { title: '扬子江楼', author: '孙逖', poem: '扬子何年邑，雄图作楚关。\n江连二妃渚，云近八公山。\n驿道[青]枫外，人烟绿屿间。\n晚来潮正满，数处落帆还。' },
  { title: '淮阴夜宿二首 一', author: '孙逖', poem: '水国南无畔，扁舟北未期。\n乡情淮上失，归梦郢中疑。\n木落知寒近，山长见日迟。\n客行心绪乱，不及洛阳时。' },
  { title: '淮阴夜宿二首 二', author: '孙逖', poem: '永夕卧烟塘，萧条天一方。\n秋风淮水落，寒夜楚歌长。\n宿莽非中土，鲈鱼岂我乡。\n孤舟行已倦，南越尚茫茫。' },
  { title: '下京口埭夜行', author: '孙逖', poem: '孤帆度绿氛，寒浦落红曛。\n江树朝来出，吴歌夜渐闻。\n南溟接潮水，北斗近乡云。\n行役从兹去，归情入鴈群。' },
  { title: '山行遇雨', author: '孙逖', poem: '骤雨昼氤氲，空天望不分。\n暗山唯觉电，穷海但生云。\n涉涧猜行潦，缘崖畏宿氛。\n夜来江月霁，櫂唱此中闻。' },
  { title: '夜到润州', author: '孙逖', poem: '夜入丹阳郡，天高气象秋。\n海隅云汉转，江畔火星流。\n城郭传金柝，闾阎闭绿洲。\n客行凡几夜，新月再如钩。' },
  { title: '和常州崔使君咏后庭梅二首 一', author: '孙逖', poem: '闻唱梅花落，江南春意深。\n更传千里外，来入越人吟。\n弱干红妆倚，繁香翠羽寻。\n庭中自公日，歌舞向芳阴。' },
  { title: '和常州崔使君咏后庭梅二首 二', author: '孙逖', poem: '梅院重门掩，遥遥歌吹边。\n庭深人不见，春至曲能传。\n花落弹棋处，香来荐枕前。\n使君停五马，行乐此中偏。' },
  { title: '同和咏楼前海石榴二首 一', author: '孙逖', poem: '客自新亭郡，朝来数物华。\n传君妓楼好，初落海榴花。\n露色珠帘映，香风粉壁遮。\n更宜林下雨，日晚逐行车。' },
  { title: '同和咏楼前海石榴二首 二', author: '孙逖', poem: '海上移珍木，楼前咏所思。\n遥闻下车日，正在落花时。\n旧绿香行盖，新红洒步綦。\n从来寒不易，终见久逾滋。' },
  { title: '故右丞相赠太师燕文贞公挽词二首 一', author: '孙逖', poem: '海内文章伯，朝端礼乐英。\n一言兴宝运，三入济群生。\n命与才相偶，年将位不幷。\n台星忽已坼，流恸轸皇情。' },
  { title: '故右丞相赠太师燕文贞公挽词二首 二', author: '孙逖', poem: '甲第三重戟，高门四列侯。\n已成冠盖里，更有凤皇楼。\n人世方为乐，生涯遽若休。\n空余掌纶地，传庆百千秋。' },
  { title: '故陈州刺史赠兵部尚书韦公挽词', author: '孙逖', poem: '奕叶金章贵，连枝鼎位尊。\n台庭为凤穴，相府是鸰原。\n世阅空悲命，泉幽不返魂。\n惟余汉臣史，继术赞韦门。' },
  { title: '故程将军妻南阳郡夫人樊氏挽歌', author: '孙逖', poem: '德配程休甫，名高鲁季姜。\n宠荣苍玉珮，宴梦郁金堂。\n白日期偕老，幽泉忽悼亡。\n国风犹在咏，江汉近南阳。' },
  { title: '和上巳连寒食有怀京洛', author: '孙逖', poem: '天津御柳碧遥遥，轩骑相从半下朝。\n行乐光辉寒食借，太平歌舞晚春饶。\n红妆楼下东郊道，青草洲边南渡桥。\n坐见司空扫西第，看君侍从落花朝。' },
  { title: '和崔司马登称心山寺', author: '孙逖', poem: '郡府乘休日，王城访道初。\n觉花迎步履，香草藉行车。\n倚阁观无际，寻山坐太虚。\n岩空迷禹迹，海静望秦余。\n翡翠巢珠网，鹍鸡间绮疏。\n地灵资净土，水若护真如。\n宝树谁攀折，禅云自卷舒。\n晴分五湖势，烟合九夷居。\n生灭纷无象，窥临已得鱼。\n尝闻宝刀赠，今日奉琼琚。' },
  { title: '奉和李右相中书壁画山水', author: '孙逖', poem: '庙堂多暇日，山水契中情。\n欲写高深趣，还因藻绘成。\n九江临户牖，三峡绕檐楹。\n花柳穷年发，烟云逐意生。\n能令万里近，不觉四时行。\n气染荀香馥，光含乐镜清。\n咏歌齐出处，图画表冲盈。\n自保千年遇，何论八载荣。' },
  { title: '奉和李右相赏会昌林亭', author: '孙逖', poem: '贤相初陪跸，灵山本降神。\n作京雄近县，开阁宠平津。\n地胜林亭好，时清宴赏频。\n百泉萦草木，万井布郊畛。\n德与春和盛，功将造化邻。\n还嗤渭滨叟，岁晚独垂纶。' },
  { title: '和左衞武仓曹衞中对雨创韵赠右衞李骑曹', author: '孙逖', poem: '林父同官意，宣尼久敬交。\n文场刊玉篆，武事掌金铙。\n道合宜连茹，时清岂系匏。\n克勤居簿领，多暇屏讙𫍢。\n美酒怀公䜩，玄谈俟客嘲。\n薄云生北阙，飞雨自西郊。\n院暑便清旷，庭芜觉渐苞。\n高门关讵闭，逸韵柱难胶。\n枳棘鸾无叹，椅梧凤必巢。\n忽闻征竝作，观海媿堂坳。' },
  { title: '送新罗法师还国', author: '孙逖', poem: '异域今无外，高僧代所稀。\n苦心归寂灭，宴坐得精微。\n持钵何年至，传灯是日归。\n上卿挥别藻，中禁下禅衣。\n海阔杯还度，云遥锡更飞。\n此行迷处所，何以慰虔祈。' },
  { title: '送赵大夫护边', author: '孙逖', poem: '外域分都护，中台命职方。\n欲传清庙略，先取剧曹郎。\n已佩登坛印，犹怀伏奏香。\n百壶开祖饯，驷牡戒戎装。\n青海连西掖，黄河带北凉。\n关山瞻汉月，戈劒宿胡霜。\n体国才先着，论兵策复长。\n果持文武术，还继杜当阳。' },
  { title: '立秋日题安昌寺北山亭', author: '孙逖', poem: '楼观倚长霄，登攀及霁朝。\n高如石门顶，胜拟赤城标。\n天路云虹近，人寰气象遥。\n山围伯禹庙，江落伍胥潮。\n徂暑迎秋薄，凉风是日飘。\n果林余苦李，萍水覆甘蕉。\n览古嗟夷漫，凌空爱泬寥。\n更闻金刹下，钟梵晚萧萧。' },
  { title: '登越州城', author: '孙逖', poem: '越嶂绕层城，登临万象清。\n封圻沧海合，廛市碧湖明。\n晓日渔歌满，芳春櫂唱行。\n山风吹美箭，田雨润香秔。\n代阅英灵尽，人闲吏隐幷。\n赠言王逸少，已见曲池平。' },
  { title: '江行有怀', author: '孙逖', poem: '秋水明川路，轻舟转石圻。\n霜多山橘熟，寒至浦禽稀。\n飞席乘风势，回流荡日晖。\n昼行疑海若，夕梦识江妃。\n野霁看吴尽，天长望洛非。\n不知何岁月，一似暮潮归。' },
  { title: '长洲苑', author: '孙逖', poem: '吴王初鼎峙，羽猎骋雄才。\n辇道阊门出，军容茂苑来。\n山从列嶂转，江自绕林回。\n劒骑缘汀入，旌门隔屿开。\n合离纷若电，驰逐溢成雷。\n胜地虞人守，归舟汉女陪。\n可怜夷漫处，犹在洞庭隈。\n山静吟猿父，城空应雉媒。\n戎行委乔木，马迹尽黄埃。\n揽涕问遗老，繁华安在哉。' },
  { title: '和咏廨署有樱桃', author: '孙逖', poem: '上林天禁里，芳树有红樱。\n江国今来见，君门春意生。\n香从花绶转，色绕佩珠明。\n海鸟衔初实，吴姬扫落英。\n切将稀取贵，羞与众同荣。\n为此堪攀折，芳蹊处处成。' },
  { title: '同洛阳李少府观永乐公主入蕃', author: '孙逖', poem: '边地莺花少，年来未觉新。\n美人天上落，龙塞始应春。' },
  { title: '途中口号', author: '孙逖', poem: '邺城东北望陵台，珠翠繁华去不回。\n无复新妆艳红粉，空余故垄满青苔。' },
  { title: '晦日湖塘', author: '孙逖', poem: '吉日初成晦，方塘遍是春。\n落花迎二月，芳树历三旬。\n公子能留客，巫阳好解神。\n夜还何虑暗，秉烛向城𬮱。' },
  { title: '从军行', author: '崔国辅', poem: '塞北胡霜下，营州索兵救。\n夜里偷道行，将军马亦瘦。\n刀光照塞月，阵色明如昼。\n传闻贼满山，已共前锋鬬。' },
  { title: '杂诗', author: '崔国辅', poem: '逢着平乐儿，论交鞍马前。\n与酤一斗酒，恰用十千钱。\n后余在关内，作事多迍邅。\n何肯相救援，徒闻宝劒篇。' },
  { title: '古意', author: '崔国辅', poem: '红荷楚水曲，彪炳烁晨霞。\n未得两回摘，秋风吹却花。\n时芳不待妾，玉珮无处夸。\n悔不盛年时，嫁与青楼家。' },
  { title: '宿法华寺', author: '崔国辅', poem: '松雨时复滴，寺门清且凉。\n此心竟谁证，回憩支公床。\n壁画感灵迹，龛经传异香。\n独游寄象外，忽忽归南昌。' },
  { title: '题豫章馆', author: '崔国辅', poem: '杨柳映春江，江南转佳丽。\n吴门绿波里，越国青山际。\n游宦常往来，津亭暂临憩。\n驿前苍石没，浦外湖沙细。\n向晚宴且久，孤舟冏然逝。\n云留西北客，气歇东南帝。\n独有萋萋心，谁知怨芳岁。' },
  { title: '石头滩作', author: '崔国辅', poem: '怅矣秋风时，余临石头濑。\n因高见远境，尽此数州内。\n羽山数点青，海岸杂光碎。\n离离树木少，漭漭湖波大。\n日暮千里帆，南飞落天外。\n须臾遂入夜，楚色有微霭。\n寻远迹已穷，遗荣事多昧。\n一身犹未理，安得济时代。\n且泛朝夕潮，荷衣蕙为带。' },
  { title: '漂母岸', author: '崔国辅', poem: '泗水入淮处，南边古岸存。\n秦时有漂母，于此饭王孙。\n王孙初未遇，寄食何足论。\n后为楚王来，黄金答母恩。\n事迹遗在此，空伤千载魂。\n茫茫水中渚，上有一孤墩。\n遥望不可到，苍苍烟树昏。\n几年崩冢色，每日落潮痕。\n古地多陻圮，时哉不敢言。\n向夕泪沾裳，遂宿芦洲村。' },
  { title: '对酒吟', author: '崔国辅', poem: '行行日将夕，荒村古冢无人迹。\n蒙笼荆棘一鸟吟，屡唱提壶沽酒吃。\n古人不达酒不足，遗恨精灵传此曲。\n寄言世上诸少年，平生且尽杯中醁。' },
  { title: '奉和华清宫观行香应制', author: '崔国辅', poem: '天子蘂珠宫，楼台碧落通。\n豫游皆汗漫，斋处即崆峒。\n云物三光里，君臣一气中。\n道言何所说，宝历自无穷。' },
  { title: '七夕', author: '崔国辅', poem: '太守仙潢族，含情七夕多。\n扇风生玉漏，置水写银河。\n阁下陈书籍，闺中曝绮罗。\n遥思汉武帝，青鸟几时过。' },
  { title: '宿范浦', author: '崔国辅', poem: '月暗潮又落，西陵渡暂停。\n村烟和海雾，舟火乱江星。\n路转定山遶，塘连范浦横。\n鸱夷近何去，空山临沧溟。' },
  { title: '奉和圣制上巳祓禊应制', author: '崔国辅', poem: '元巳秦中节，吾君灞上游。\n鸣銮通禁苑，别馆遶芳洲。\n鹓鹭千官列，鱼龙百戏浮。\n桃花春欲尽，谷雨夜来收。\n庆向尧樽祝，欢从楚棹讴。\n逸诗何足对，窅作掩东周。' },
  { title: '九日侍宴应制', author: '崔国辅', poem: '运偶千年圣，时传九日神。\n尧樽列钟鼓，汉阙辟钩陈。\n金箓三清降，琼筵五老巡。\n始惊兰佩出，复咏柏梁新。\n云鴈楼前晚，霜花酒里春。\n欢娱无限极，书劒太平人。' },
  { title: '杭州北郭戴氏荷池送侯愉', author: '崔国辅', poem: '秋近万物肃，况当临水时。\n折花赠归客，离绪断荷丝。\n谁谓江国永，故人感在兹。\n道存过北郭，情极望东菑。\n乔木故园意，鸣蝉穷巷悲。\n扁舟竟何待，中路每迟迟。' },
  { title: '怨词二首 一', author: '崔国辅', poem: '妾有罗衣裳，秦王在时作。\n为舞春风多，秋来不堪着。' },
  { title: '怨词二首 二', author: '崔国辅', poem: '楼头桃李疎，池上芙蓉落。\n织锦犹未成，蛩声入罗幕。' },
  { title: '古意二首 一', author: '崔国辅', poem: '玉笼薰绣裳，着罢眠洞房。\n不能春风里，吹却兰麝香。' },
  { title: '古意二首 二', author: '崔国辅', poem: '种棘遮蘼芜，畏人来采杀。\n比至狂夫还，看看几花发。' },
  { title: '襄阳曲二首 一', author: '崔国辅', poem: '蕙草娇红萼，时光舞碧鸡。\n城中美年少，相见白铜鞮。' },
  { title: '襄阳曲二首 二', author: '崔国辅', poem: '少年襄阳地，来往襄阳城。\n城中轻薄子，知妾解秦筝。' },
  { title: '魏宫词', author: '崔国辅', poem: '朝日照红妆，拟上铜雀台。\n画眉犹未了，魏帝使人催。' },
  { title: '长信草', author: '崔国辅', poem: '长信宫中草，年年愁处生。\n故侵珠履迹，不使玉阶行。' },
  { title: '长乐少年行', author: '崔国辅', poem: '遗却珊瑚鞭，白马骄不行。\n章台折杨柳，春日路傍情。' },
  { title: '湖南曲', author: '崔国辅', poem: '湖南送君去，湖北送君归。\n湖里鸳鸯鸟，双双他自飞。' },
  { title: '中流曲', author: '崔国辅', poem: '归时日尚早，更欲向芳洲。\n渡口水流急，回船不自由。' },
  { title: '王孙游', author: '崔国辅', poem: '自与王孙别，频看黄鸟飞。\n应由春草误，着处不成归。' },
  { title: '采莲曲', author: '崔国辅', poem: '玉溆花争发，金塘水乱流。\n相逢畏相失，并着采莲舟。' },
  { title: '子夜冬歌', author: '崔国辅', poem: '寂寥抱冬心，裁罗又褧褧。\n夜久频挑灯，霜寒剪刀冷。' },
  { title: '丽人曲', author: '崔国辅', poem: '红颜称绝代，欲并真无侣。\n独有镜中人，由来自相许。' },
  { title: '小长干曲', author: '崔国辅', poem: '月暗送潮风，相寻路不通。\n菱歌唱不彻，知在此塘中。' },
  { title: '王昭君', author: '崔国辅', poem: '汉使南还尽，胡中妾独存。\n紫台绵望绝，秋草不堪论。' },
  { title: '秦女卷衣', author: '崔国辅', poem: '虽入秦帝宫，不上秦帝床。\n夜夜玉窗里，与他卷衣裳。' },
  { title: '今别离', author: '崔国辅', poem: '送别未能旋，相望连水口。\n船行欲映洲，几度急摇手。' },
  { title: '衞艳词', author: '崔国辅', poem: '淇上桑叶青，青楼含白日。\n比时遥望君，车马城中出。' },
  { title: '渭水西别李仑', author: '崔国辅', poem: '陇右长亭堠，山阴古塞秋。\n不知呜咽水，何事向西流。' },
  { title: '送韩十四被鲁王推递往济南府', author: '崔国辅', poem: '西候情何极，南冠怨有余。\n梁王虽好事，不察狱中书。' },
  { title: '白纻辞二首 一', author: '崔国辅', poem: '洛阳梨花落如霰，河阳桃叶生复齐。\n坐惜玉楼春欲尽，红绵粉絮裛妆啼。' },
  { title: '白纻辞二首 二', author: '崔国辅', poem: '董贤女弟在椒风，窈窕繁华贵后宫。\n璧带金釭皆翡翠，一朝零落变成空。' },
  { title: '九日', author: '崔国辅', poem: '江边枫落菊花黄，少长登高一望乡。\n九日陶家虽载酒，三年楚客已沾裳。' },
  { title: '孤寝怨', author: '崔珪', poem: '征戍动经年，含情拂玳筵。\n花飞织锦处，月落捣衣边。\n灯暗愁孤坐，床空怨独眠。\n自君辽海去，玉匣闭春弦。' },
  { title: '题武陵草堂', author: '杨浚', poem: '草堂列仙楼，上在青山顶。\n户外窥数峰，阶前对双井。\n雨来花尽湿，风度松初冷。\n登栈行不疲，入谿语弥静。\n云能去尘服，兼欲事金鼎。\n正直心所存，谄谀长自省。\n适知幽遁趣，已觉烦虑屏。\n更爱云林间，吾将卧南颍。' },
  { title: '广武怀古', author: '杨浚', poem: '河水城下流，登城望弥惬。\n海云飞不断，岸草绿相接。\n龙门无旧塲，武牢有遗堞。\n扼喉兵易守，扪指计何捷。\n天夺项氏谋，卒成汉家业。\n乡山遥可见，西顾泪盈睫。' },
  { title: '赠李郎中', author: '杨浚', poem: '仙郎早朝退，直省卧南轩。\n院竹自成赏，阶庭寂不喧。\n焚香开后阁，起草闭前门。\n礼乐风流美，光华星位尊。\n荣兼朱绂贵，交乃布衣存。\n是日登龙客，无忘君子恩。' },
  { title: '咏王大娘戴卒', author: '刘晏', poem: '楼前百戏竞争新，唯有长竿妙入神。\n谁谓绮罗[翻]有力，犹自嫌轻更着人。' },
  { title: '享太庙乐章', author: '刘晏', poem: '汉祚惟永，神功中兴。\n夙驱氛祲，天覆黎蒸。\n三光再朗，庶绩其凝。\n重熙累叶，景命是膺。' },
  { title: '鸿门行', author: '袁瓘', poem: '少年买意气，百金不辞费。\n学劒西入秦，结交北游魏。\n秦魏多豪人，与代亦殊伦。\n由来不相识，皆是暗相亲。\n宝马青丝辔，狐裘貂鼠服。\n晨过剧孟游，暮投咸阳宿。\n然诺本云云，诸侯莫不闻。\n犹思百战术，更逐李将军。\n始从灞陵下，遥遥度朔野。\n北风闻楚歌，南庭见胡马。\n胡马秋正肥，相邀夜合围。\n战酣烽火灭，路断救兵稀。\n白刃纵横逼，黄尘飞不息。\n虏骑血洒衣，单于泪沾臆。\n献凯云台中，自言塞上雄。\n将军行失势，部曲遂无功。\n新人不如旧，旧人不相救。\n万里长飘飖，十年计不就。\n弃置难重论，驱马度鸿门。\n行看楚汉事，不觉风尘昏。\n宝劒中夜抚，悲歌聊自舞。\n此曲不可终，曲终泪如雨。' },
  { title: '惠文太子挽歌', author: '袁瓘', poem: '寒仗丹旄引，阴堂白日违。\n暗灯明象物，画水湿灵衣。\n羽化淮王去，仙迎太子归。\n空余燕衔土，朝夕向陵飞。' },
  { title: '从军行', author: '李昂', poem: '汉家未得燕支山，征戍年年沙朔间。\n塞下长驱汗血马，云中恒闭玉门关。\n阴山翰海千万里，此日桑河冻流水。\n稽洛川边胡骑来，渔阳戍里烽烟起。\n长途羽檄何相望，天子按劒思北方。\n羽林练士拭金甲，将军校战出玉堂。\n幽陵异域风烟改，亭障连连古今在。\n夜闻鸿雁南渡河，晓望旌旗北临海。\n塞沙飞淅沥，遥裔连穷碛。\n玄漠云平初合阵，西山月出闻鸣镝。\n城南百战多苦辛，路傍死卧黄沙人。\n戎衣不脱随霜雪，汗马𫎺𧽼长被铁。\n杨叶楼中不寄书，莲花劒上空流血。\n匈奴未灭不言家，驱逐行行边徼赊。\n归心海外见明月，别思天边梦落花。\n天边回望何悠悠，芳树无人渡陇头。\n春云不变阳关雪，桑叶先知胡地秋。\n田畴不卖卢龙策，窦宪思勒燕然石。\n麾兵静北垂，此日交河湄。\n欲令塞上无干戚，会待单于系颈时。' },
  { title: '赋戚夫人楚舞歌', author: '李昂', poem: '定陶城中是妾家，妾年二八颜如花。\n闺中歌舞未终曲，天下死人如乱麻。\n汉王此地因征战，未出帘栊人已荐。\n风花菡萏落辕门，云雨裴回入行殿。\n日夕悠悠非旧乡，飘飘处处逐君王。\n闺门向里通归梦，银烛迎来在战场。\n相从顾恩不顾己，何异浮萍寄深水。\n逐战曾迷只轮下，随君几陷重围里。\n此时平楚复平齐，咸阳宫阙到关西。\n珠帘夕殿闻钟磬，白日秋天忆鼓鼙。\n君王纵恣翻成误，吕后由来有深妬。\n不奈君王容鬓衰，相存相顾能几时。\n黄泉白骨不可报，雀钗翠羽从此辞。\n君楚歌兮妾楚舞，脉脉相看两心苦。\n曲未终兮袂更扬，君流涕兮妾断肠。\n已见储君归惠帝，徒留爱子付周昌。' },
  { title: '夏晚初霁南省寓直用余字', author: '厍狄履温', poem: '薄宦因时泰，凉宵寓直初。\n沈沈仙阁闭，的的暗更徐。\n霁色连空上，炎氛入夜除。\n星回南斗落，月度北窗虚。\n待漏残灯照，含芳袭气余。\n寐来冠不解，奏罢草仍书。\n幕府慙良策，明曹媿散樗。\n命轻徒有报，义重更难疎。\n燕厦欣成托，鹓行滥所如。\n晨趋当及早，复此戒朝车。' },
  { title: '同皇甫兵曹天官寺浴室新成招友人赏会', author: '寇坦', poem: '温室欢初就，兰交托胜因。\n共听无漏法，兼濯有为尘。\n水洁三空性，香沾四大身。\n清心多善友，颂德慰同人。' },
  { title: '同张少府和厍狄员外夏晚初霁南省寓直时兼充节度判官之作', author: '寇坦', poem: '黄绶归休日，仙郎复奏余。\n晏居当夏晚，寓直会晴初。\n露散星文发，云披水镜虚。\n高才推独唱，嘉会喜连茹。\n月色摇春闼，香烟霭暝庐。\n千门传夜警，万象照阶除。\n少孺嘉能赋，文强阅赐书。\n兼曹谋未展，入幕志方摅。\n为奉灵台帛，恭先待漏车。\n贞标不可仰，空此乐樵渔。' },
  { title: '咏铜柱', author: '李休烈', poem: '天门街里倒天枢，火急先须卸火珠。\n计合一条丝线挽，何劳两县索人夫。' },
  { title: '送贺监归四明应制', author: '李林甫', poem: '挂冠知止足，岂独汉疏贤。\n入道求真侣，辞恩访列仙。\n睿文含日月，宸翰动云烟。\n鹤驾吴乡远，遥遥南斗边。' },
  { title: '奉和圣制次琼岳应制', author: '李林甫', poem: '东幸从人望，西巡顺物回。\n云收二华出，天转五星来。\n十月农初罢，三驱礼复开。\n更看琼岳上，佳气接神台。' },
  { title: '秋夜望月忆韩席等诸侍郎因以投赠', author: '李林甫', poem: '秋天碧云夜，明月悬东方。\n皓皓庭际色，稍稍林下光。\n桂华澄远近，璧彩散池塘。\n鸿雁飞难度，关山曲易长。\n揆予秉孤直，虚薄忝文昌。\n握镜惭先照，持衡媿后行。\n多才众君子，载笔久词场。\n作赋推潘岳，题诗许谢康。\n当时陪宴语，今夕恨相望。\n愿欲接高论，清晨朝建章。' },
  { title: '流崖州至鬼门关作', author: '杨炎', poem: '一去一万里，千知千不还。\n崖州何处在？生度鬼门关。' },
  { title: '赠元载歌妓', author: '杨炎', poem: '雪面淡眉天上女，凤箫鸾翅欲飞去。\n玉山翘翠步无尘，楚腰如柳不胜春。' },
  { title: '别妻王韫秀', author: '元载', poem: '年来谁不厌龙钟，虽在侯门似不容。\n看取海山寒翠树，苦遭霜霰到秦封。' },
  { title: '赋得云生栋梁间', author: '陈希烈', poem: '一片苍梧意，氤氲生栋梁。\n下帘山足暗，开户日添光。\n偏使衣裘润，能令枕簟凉。\n无心伴行雨，何必梦荆王。' },
  { title: '奉和圣制三月三日', author: '陈希烈', poem: '上巳迂龙驾，中流泛羽觞。\n酒因朝太子，诗为乐贤王。\n锦缆方舟渡，琼筵大乐张。\n风摇垂柳色，花发异林香。\n野老歌无事，朝臣饮岁芳。\n皇情被群物，中外洽恩光。' },
  { title: '省试白云起封中', author: '陈希烈', poem: '千年泰山顶，云起汉王封。\n不作奇峰状，宁分触石容。\n为霖虽易得，表圣自难逢。\n冉冉排空上，依依叠影重。\n素光非曳练，灵贶是从龙。\n岂学无心出，东西任所从。' },
  { title: '朗月行', author: '张渐', poem: '朗月照帘幌，清夜有余姿。\n洞房怨孤枕，挟琴爱前墀。\n萱草已数叶，梨花复徧枝。\n去岁草始荣，与君新相知。\n今年花未落，谁分生别离。\n代情难重论，人事好乖移。\n合比月华满，分同月易亏。\n亏月当再圆，人别星陨天。\n吾欲竟此曲，意深不可传。\n叹息孤鸾鸟，伤心明镜前。' },
  { title: '晓次荆江', author: '宋昱', poem: '孤舟大江水，水涉无昏曙。\n雨暗迷津时，云生望乡处。\n渔翁闲自乐，樵客纷多虑。\n秋色湖上山，归心日边树。\n徒称竹箭美，未得枫林趣。\n向夕垂钓还，吾从落潮去。' },
  { title: '题石窟寺', author: '宋昱', poem: '梵宇开金地，香龛凿铁围。\n影中群象动，空里众灵飞。\n檐牖笼朱旭，房廊挹翠微。\n瑞莲生佛步，瑶树挂天衣。\n邀福功虽在，兴王代久非。\n谁知云朔外，更覩化胡归。' },
  { title: '樟亭观涛', author: '宋昱', poem: '涛来势转雄，猎猎驾长风。\n雷震云霓里，山飞霜雪中。\n激流起平地，吹涝上侵空。\n翕辟乾坤异，盈虚日月同。\n艅艎从陆起，洲浦隔阡通。\n跳沫喷岩翠，翻波带景红。\n怒湍初抵北，却浪复归东。\n寂听堪增勇，晴看自发蒙。\n伍生传或谬，枚叟说难穷。\n来信应无已，申威亦匪躬。\n冲腾如决胜，回合似相攻。\n委质任平视，谁能涯始终。' },
  { title: '赠程秘书', author: '卢象', poem: '客自岐阳来，吐音若鸣凤。\n孤飞畏不偶，独立谁见用。\n忽从被褐中，召入承明宫。\n圣人借颜色，言事无不通。\n殷勤拯黎庶，感激论诸公。\n将相猜贾谊，图书归马融。\n顾余久寂寞，一岁麒麟阁。\n且共歌太平，勿嗟名宦薄。' },
  { title: '家叔征君东溪草堂二首 一', author: '卢象', poem: '开山十余里，青壁森相倚。\n欲识尧时天，东溪白云是。\n雷声转幽壑，云气杳流水。\n涧影生龙蛇，岩端翳柽梓。\n大道终不易，君恩曷能已。\n鹤羡无老时，龟言摄生理。\n浮年笑六甲，元化潜一指。\n未暇扫云梯，空慙阮氏子。' },
  { title: '家叔征君东溪草堂二首 二', author: '卢象', poem: '今朝共游者，得性闲未归。\n已到仙人家，莫惊鸥鸟飞。\n水深严子钓，松挂巢父衣。\n云气转幽寂，溪流无是非。\n名理未足羡，腥臊讵所希。\n自惟负贞意，何岁当食薇。' },
  { title: '乡试后自巩还田家因谢邻友见过之作', author: '卢象', poem: '鸡鸣出东邑，马倦登南峦。\n落日见桑柘，翳然丘中寒。\n邻家多旧识，投暝来相看。\n且问春税苦，兼陈行路难。\n园场近阴壑，草木易凋残。\n峰晴雪犹积，涧深冰已团。\n浮名知何用，岁晏不成欢。\n置酒共君饮，当歌聊自宽。' },
  { title: '青雀歌', author: '卢象', poem: '啾啾青雀儿，飞来飞去仰天池。\n逍遥饮啄安涯分，何假扶摇九万为。' },
  { title: '杂诗二首 一', author: '卢象', poem: '家居五原上，征战是平生。\n独负山西勇，谁当塞下名。\n死生辽海战，雨雪蓟门行。\n诸将封侯尽，论功独不成。' },
  { title: '杂诗二首 二', author: '卢象', poem: '君家御沟上，垂柳夹朱门。\n列鼎会中贵，鸣珂朝至尊。\n死生在片议，穷达由一言。\n须识苦寒士，莫矜狐白温。' },
  { title: '赠广川马先生', author: '卢象', poem: '经书满腹中，吾识广川翁。\n年老甘无位，家贫懒发蒙。\n人归洙泗学，歌盛舞雩风。\n愿接诸生礼，三年事马融。' },
  { title: '峡中作', author: '卢象', poem: '高唐几百里，树色接阳台。\n晚见江山霁，宵闻风雨来。\n云从三峡起，天向数峰开。\n灵境信难见，轻舟那可回。' },
  { title: '竹里馆', author: '卢象', poem: '江南冰不闭，山泽气潜通。\n腊月闻山鸟，寒崖见蛰熊。\n柳林春半合，荻笋乱无丛。\n回首金陵岸，依依向北风。' },
  { title: '永城使风', author: '卢象', poem: '长风起秋色，细雨含落晖。\n夕鸟向林去，晚帆相逐飞。\n虫声出乱草，水气薄行衣。\n一别故乡道，悠悠今始归。' },
  { title: '和徐侍郎丛筿咏', author: '卢象', poem: '中禁夕沈沈，幽篁别作林。\n色连鸡树近，影落凤池深。\n为重凌霜节，能虚应物心。\n年年承雨露，长对紫庭阴。' },
  { title: '驾幸温泉', author: '卢象', poem: '传闻圣主幸新丰，清跸鸣銮出禁中。\n细草终朝随步辇，垂杨几处绕行宫。\n千官扈从骊山北，万国来朝渭水东。\n此日小臣徒献赋，汉家谁复重[扬]雄。' },
  { title: '奉和张使君宴加朝散', author: '卢象', poem: '佐理星辰贵，分荣涣汗深。\n言从大夫后，用荅圣人心。\n骑拥轩裳客，鸾惊翰墨林。\n停杯歌麦秀，秉烛醉棠阴。\n爽气凌秋笛，轻寒散暝砧。\n秪应将四子，讲德谢知音。' },
  { title: '赠张均员外', author: '卢象', poem: '公门世绪昌，才子冠裴王。\n出自平津邸，还为吏部郎。\n神仙余气色，列宿动辉光。\n夜直南宫静，朝趋北禁长。\n时人归水镜，明主赐衣裳。\n翰苑飞鹦鹉，天池待凤凰。\n承欢畴日顾，未纪后时伤。\n去去图南远，微才幸不忘。' },
  { title: '送祖咏', author: '卢象', poem: '田家宜伏腊，岁晏子言归。\n石路雪初下，荒村鸡共飞。\n东原多烟火，北涧隐寒晖。\n满酌野人酒，倦闻邻女机。\n胡为困樵采，几日罢朝衣。' },
  { title: '送綦毋潜', author: '卢象', poem: '夫君不得意，本自沧海来。\n高足未云骋，虚舟空复回。\n淮南枫叶落，灞岸桃花开。\n出处暂为耳，沈浮安系哉。\n如何天覆物，还遣世遗才。\n欲识秦将汉，尝闻王与裴。\n离筵对寒食，别雨乘春雷。\n会有征书到，荷衣且漫裁。' },
  { title: '送赵都护赴安西', author: '卢象', poem: '下客候旌麾，元戎复在斯。\n门开都护府，兵动羽林儿。\n黠虏多翻覆，谋臣有别离。\n智同天所授，恩共日相随。\n汉使开宾幕，胡笳送酒巵。\n风霜迎马首，雨雪事鱼丽。\n上策应无战，深情属载驰。\n不应行万里，明主寄安危。' },
  { title: '追凉历下古城西北隅此地有清泉乔木', author: '卢象', poem: '谢朓出华省，王祥贻佩刀。\n前贤真可慕，衰病意空劳。\n贞悔不自卜，游随共尔曹。\n未能齐得丧，时复诵离骚。\n闲荫七贤地，醉餐三士桃。\n苍苔虞舜井，乔木古城壕。\n渔父偏相狎，尧年不可逃。\n蝉鸣秋雨霁，云白晓山高。\n咫尺传双鲤，吹嘘借一毛。\n故人皆得路，谁肯念同袍。' },
  { title: '戏赠邵使君张郎', author: '卢象', poem: '少妇石榴裙，新妆白玉面。\n能迷张公子，不许时相见。' },
  { title: '同王维过崔处士林亭', author: '卢象', poem: '映竹时闻转辘轳，当窗只见网蜘蛛。\n主人非病常高卧，环堵蒙笼一老儒。' },
  { title: '寄河上段十六', author: '卢象', poem: '与君相识即相亲，闻道君家住孟津。\n为见行舟试借问，客中时有洛阳人。' },
  { title: '寒食', author: '卢象', poem: '子推言避世，山火遂焚身。\n四海同寒食，千秋为一人。\n深冤何用道，峻迹古无邻。\n魂魄山河气，风雷御宇神。\n光烟榆柳灭，怨曲龙虵新。\n可叹文公霸，平生负此臣。' },
  { title: '八月十五日象自江东止田园移庄庆会未几归汶上小弟幼妹尤嗟其别兼赋是诗三首 一', author: '卢象', poem: '谢病始告归，依然入桑梓。\n家人皆伫立，相候衡门里。\n畴类皆长年，成人旧童子。\n上堂家庆毕，愿与亲姻迩。\n论旧或余悲，思存且相喜。\n田园转芜没，但有寒泉水。\n衰柳日萧条，秋光清邑里。\n入门乍如客，休骑非便止。\n中饮顾王程，离忧从此始。' },
  { title: '八月十五日象自江东止田园移庄庆会未几归汶上小弟幼妹尤嗟其别兼赋是诗三首 二', author: '卢象', poem: '两妹日长成，双鬟将及人。\n已能持宝瑟，自解掩罗巾。\n念昔别时小，未知疎与亲。\n今来识离恨，掩泪方殷勤。' },
  { title: '八月十五日象自江东止田园移庄庆会未几归汶上小弟幼妹尤嗟其别兼赋是诗三首 三', author: '卢象', poem: '小弟更孩幼，归来不相识。\n同居虽渐惯，见人犹默默。\n宛作越人言，殊乡甘水食。\n别此最为难，泪尽有余忆。' },
  { title: '叹白发', author: '卢象', poem: '我年一何长，鬓发日已白。\n俛仰天地间，能为几时客。\n惆怅故山云，裴回空日夕。\n何事与时人，东城复南陌。' },
  { title: '早秋宴张郎中海亭即事', author: '卢象', poem: '邑有弦歌宰，翔鸾狎野鸥。\n眷言华省旧，暂滞海池游。\n郁岛藏深竹，前谿对舞楼。\n更闻书即事，云物是新秋。' },
  { title: '句', author: '卢象', poem: '吴越山多秀，新安江甚清。\n书名会粹才偏逸，酒号屠苏味更醇。\n初疑轻烟淡古松，又似山开万仞峰。' },
  { title: '嵩山十志十首 其一', author: '卢鸿一', poem: '山为宅兮草为堂，芝兰兮药房。\n罗蘼芜兮拍薜荔，荃壁兮兰砌。\n蘼芜薜荔兮成草堂，阴阴邃兮馥馥香。\n中有人兮信宜常，读金书兮饮玉浆，童颜幽操兮不易长。' },
  { title: '嵩山十志十首 其二', author: '卢鸿一', poem: '天门豁兮仙台耸，杰屹崒兮零澒涌。\n穷三休兮旷一观，忽若登昆仑兮中期汗漫仙。\n耸天关兮倒景台，鲨颢气兮轶嚣埃。\n皎皎之子兮自独立，云可朋兮赮可吸，曾何荣辱之所及。' },
  { title: '嵩山十志十首 其三', author: '卢鸿一', poem: '紫岩隈兮青谿侧，云松烟茑兮千古色。\n芳靃蘼兮荫蒙茏，幽人构馆兮在其中。\n靃蘼蒙茏兮开樾馆，卧风霄兮坐赮旦。\n粤有宾兮时戾止，樵苏不爨兮清淡已，永岁终朝兮常若此。' },
  { title: '嵩山十志十首 其四', author: '卢鸿一', poem: '临泱漭兮背青荧，吐云烟兮合窅冥。\n怳欻翕兮杳幽霭，意缥缈兮群仙会。\n窅冥仙会兮枕烟庭，竦魂形兮凝视听。\n闻夫至诚必感兮祈此巅，契颢气，养丹田，终彷像兮觏灵仙。' },
  { title: '嵩山十志十首 其五', author: '卢鸿一', poem: '水攒冲兮石丛耸，焕云锦兮喷汹涌。\n苔駮荦兮草夤缘，芳幂幂兮濑溅溅。\n石攒丛兮云锦淙，波连珠兮文沓綘。\n有洁冥者媚此幽，漱灵液兮乐天休，实获我心兮夫何求。' },
  { title: '嵩山十志十首 其六', author: '卢鸿一', poem: '霏微阴壑兮气腾虹，迤逦危磴兮上凌空。\n青霞杪兮紫云垂，鸾歌凤舞兮吹参差。\n鸾吹凤舞兮期仙磴，鸿驾迎兮瑶华赠。\n山中人兮好神仙，想像闻此兮欲升烟，铸月炼液兮𥩟还年。' },
  { title: '嵩山十志十首 其七', author: '卢鸿一', poem: '灵矶盘礴兮溜奔错漱，冷风兮镇冥壑。\n研苔滋兮泉珠洁，一饮一憩兮气想灭。\n磷涟清淬兮涤烦矶，灵仙境兮仁智归。\n中有琴兮徽以玉，峨峨汤汤兮弹此曲，寄声知音兮同所欲。' },
  { title: '嵩山十志十首 其八', author: '卢鸿一', poem: '青崖阴兮月磵曲，重幽叠邃兮隐沦躅。\n草树緜幂兮翠蒙茏，当其无兮庭在中。\n当无有用兮幂翠庭，神可谷兮道可冥。\n有幽人兮张素琴，皇徽兮绿水阴，德之愔兮澹多心。' },
  { title: '嵩山十志十首 其九', author: '卢鸿一', poem: '岚气肃兮岩翠冥，空阴虚兮户芳迎。\n披蕙帐兮促萝筵，谈空空兮核元元。\n蕙帐萝筵兮洞元室，秘而幽兮真可吉。\n返自然兮道可冥，泽妙思兮草玄经，结幽门兮在黄庭。' },
  { title: '嵩山十志十首 其十', author: '卢鸿一', poem: '水碧色兮石金光，滟熠熠兮濙湟湟。\n泉葩映兮烟茑临，红灼灼，翠阴阴。\n翠相鲜兮金碧潭，霜天洞兮烟景涵。\n有幽人兮好冥绝，炳其焕兮凝其洁，悠悠千古长不灭。' },
  { title: '书殿赐宴应制', author: '徐安贞', poem: '校文常近日，赐宴忽升天。\n酒正传桮至，饔人捧案前。\n玉阶鸣溜水，清阁引归烟。\n共惜芸香暮，春风几万年。' },
  { title: '从驾温泉宫', author: '徐安贞', poem: '神女调温液，年年待圣人。\n试开临水殿，来洗属车尘。\n暖气随明主，恩波浃近臣。\n灵威自无极，从此献千春。' },
  { title: '送吕向补阙西岳勒碑', author: '徐安贞', poem: '圣作西山颂，君其出使年。\n勒碑悬日月，驱传接云烟。\n寒尽函关路，春归洛水边。\n别离能几许，朝暮玉墀前。' },
  { title: '送丹阳采访', author: '徐安贞', poem: '郡县分南国，皇华出圣朝。\n为怜乡櫂近，不道使车遥。\n旧俗吴三让，遗风汉六条。\n愿言除疾苦，天子听歌谣。' },
  { title: '送王判官', author: '徐安贞', poem: '明月开三峡，花源出五谿。\n城池青壁里，烟火绿林西。\n不畏王程促，惟愁仙路迷。\n巴东下归櫂，莫待夜猨啼。' },
  { title: '题襄阳图', author: '徐安贞', poem: '画得襄阳郡，依然见昔游。\n岘山思驻马，汉水忆回舟。\n丹壑常含霁，青林不换秋。\n图书空咫尺，千里意悠悠。' },
  { title: '程将军夫人挽诗', author: '徐安贞', poem: '琴瑟调双凤，和鸣不独飞。\n正歌春可乐，行泣露先晞。\n环珮声犹在，房栊梦不归。\n将军休沐日，谁劝着新衣。' },
  { title: '奉和喜雪应制', author: '徐安贞', poem: '两宫斋祭近登临，雨雪纷纷天昼阴。\n祗为经寒无瑞色，顿教正月满春林。\n蓬莱北上旌门暗，花萼南归马迹深。\n自有三农歌帝力，还将万庾荅尧心。' },
  { title: '闻邻家理筝', author: '徐安贞', poem: '北斗横天夜欲阑，愁人倚月思无端。\n忽闻画阁秦筝逸，知是邻家赵女弹。\n曲成虚忆青蛾敛，调急遥怜玉指寒。\n银锁重关听未辟，不如眠去梦中看。' },
  { title: '奉和圣制早度蒲津关', author: '徐安贞', poem: '仙掌临秦甸，虹桥辟晋关。\n两都分地险，一曲度河湾。\n路得津门要，时称古戍闲。\n城花春正发，岸柳曙堪攀。\n后乘犹临水，前旌欲换山。\n长安回望日，宸御六龙还。' },
  { title: '奉和圣制荅二相出雀鼠谷', author: '徐安贞', poem: '两臣初入梦，二月扈巡边。\n涧北寒犹在，山南春半传。\n颂声先奉御，辰象复回天。\n云日明千里，旌旗照一川。\n柳阴低辇路，草色变新田。\n还望汾阳近，宸游自窅然。' },
  { title: '奉和圣制荅张说南出雀鼠谷', author: '崔翘', poem: '硖路绕河汾，晴光拂曙氛。\n笳吟中岭树，仗入半峰云。\n顿觉山原尽，平看邑里分。\n早行芳草迥，晚憩好风熏。\n嘉颂推英宰，春游扈圣君。\n共欣承睿渥，日月照天文。' },
  { title: '送友人使夷陵', author: '崔翘', poem: '猨鸣三峡里，行客旧沾裳。\n复道从兹去，思君不暂忘。\n开襟春叶短，分手夏条长。\n独有幽庭桂，年年空自芳。' },
  { title: '郑郎中山亭', author: '崔翘', poem: '篆笔飞章暇，园亭染翰游。\n地奇人境别，事远俗尘收。\n书阁山云起，琴斋涧月留。\n泉清鳞影见，树密鸟声幽。\n杜馥熏梅雨，荷香送麦秋。\n无劳置驿骑，文酒可相求。' },
  { title: '奉和圣制荅张说扈从南出雀鼠谷', author: '梁升卿', poem: '何意重关道，千年过圣皇。\n幽林承睿泽，闲客见清光。\n日御仙途远，山灵寿域长。\n寒云入晋薄，春树隔汾香。\n国佐同时雨，天文属岁阳。\n从来汉家盛，未若此巡方。' },
  { title: '白云溪', author: '吴巩', poem: '山径入修篁，深林蔽日光。\n夏云生嶂远，瀑水引溪长。\n秀迹逢皆胜，清芬坐转凉。\n回看玉樽夕，归路赏前忘。' },
  { title: '题奉国寺', author: '陆海', poem: '新秋夜何爽，露下风转凄。\n一磐竹林外，千灯花塔西。' },
  { title: '题龙门寺', author: '陆海', poem: '窗灯林霭里，闻磬水声中。\n更与龙华会，炉烟满夕风。' },
  { title: '句', author: '陆海', poem: '忽然一曲称君心，破却中人百家产。\n城外平人驱欲尽，帐中犹打衮花毬。' },
  { title: '白牡丹', author: '裴士淹', poem: '长安年少惜春残，争认慈恩紫牡丹。\n别有玉盘乘露冷，无人起就月中看。' },
  { title: '和从叔禄愔元日早朝', author: '李元操', poem: '铜浑变秋节，玉律动年灰。\n暧暧城霞旦，隐隐禁门开。\n众灵凑仙府，百神朝帝台。\n叶令双凫至，梁王驷马来。\n戈鋋映林阙，歌管拂尘埃。\n保章望瑞气，尚书免火灾。\n冠冕多秀士，簪裾饶上才。\n谁怜张仲蔚，日暮反蒿莱。' },
  { title: '昭君怨', author: '顾朝阳', poem: '莫将铅粉匣，不用镜花光。\n一去边城路，何情更画妆。\n影销胡地月，衣尽汉宫香。\n妾死非关命，都缘怨断肠。' },
  { title: '西塞山下回舟作', author: '陶岘', poem: '匡庐旧业是谁主，吴越新居安此生。\n白发数茎归未得，青山一望计还成。\n鸦翻枫叶夕阳动，鹭立芦花秋水明。\n从此舍舟何所诣，酒旗歌扇正相迎。' },
  { title: '酬诸公见过', author: '王维', poem: '嗟予未丧，哀此孤生。\n屏居蓝田，薄地躬耕。\n岁[晏]输税，以奉粢盛。\n晨往东臯，草露未晞。\n暮看烟火，负担来归。\n我闻有客，足埽荆扉。\n箪食伊何，疈瓜抓枣。\n仰厕群贤，皤然一老。\n媿无莞簟，班荆席藁。\n泛泛登陂，折彼荷花。\n静观素鲔，俯映白沙。\n山鸟群飞，日隐轻霞。\n登车上马，倏忽云散。\n雀噪荒村，鸡鸣空馆。\n还复幽独，重欷累叹。' },
  { title: '奉和圣制登降圣观与宰臣等同望应制', author: '王维', poem: '凤扆朝碧落，龙图耀金镜。\n维岳降二臣，戴天临万姓。\n山川八校满，井邑三农竟。\n比屋皆可封，谁家不相庆。\n林疎远村出，野旷寒山静。\n帝城云里深，渭水天边映。\n佳气含风景，颂声溢歌咏。\n端拱能任贤，弥彰圣君圣。' },
  { title: '奉和圣制御春明楼临右相园亭赋乐贤诗应制', author: '王维', poem: '复道通长乐，青门临上路。\n遥闻凤吹喧，暗识龙舆度。\n褰旒明四目，伏槛纡三顾。\n小苑接侯家，飞甍暎宫树。\n商山原上碧，浐水林端素。\n银汉下天章，琼筵承湛露。\n将非富人宠，信以平戎故。\n从来简帝心，讵得回天步。' },
  { title: '奉和圣制送不蒙都护兼鸿胪卿归安西应制', author: '王维', poem: '上卿增命服，都护扬归斾。\n杂虏尽朝周，诸胡皆自郐。\n鸣笳瀚海曲，按节阳关外。\n落日下河源，寒山静秋塞。\n万方氛祲息，六合乾坤大。\n无战是天心，天心同覆载。' },
  { title: '扶南曲歌词五首 一', author: '王维', poem: '翠羽流苏帐，春眠曙不开。\n羞从面色起，娇逐语声来。\n早向昭阳殿，君王中使催。' },
  { title: '扶南曲歌词五首 二', author: '王维', poem: '堂上青弦动，堂前绮席陈。\n齐歌卢女曲，双舞洛阳人。\n倾国徒相看，宁知心所亲。' },
  { title: '扶南曲歌词五首 三', author: '王维', poem: '香气传空满，妆华影箔通。\n歌闻天仗外，舞出御楼中。\n日暮归何处，花间长乐宫。' },
  { title: '扶南曲歌词五首 四', author: '王维', poem: '宫女还金屋，将眠复畏明。\n入春轻衣好，半夜薄妆成。\n拂曙朝前殿，玉墀多珮声。' },
  { title: '扶南曲歌词五首 五', author: '王维', poem: '朝日照绮窗，佳人坐临镜。\n散黛恨犹轻，插钗嫌未正。\n同心勿遽游，幸待春妆竟。' },
  { title: '陇西行', author: '王维', poem: '十里一走马，五里一扬鞭。\n都护军书至，匈奴围酒泉。\n关山正飞雪，烽戍断无烟。' },
  { title: '从军行', author: '王维', poem: '吹角动行人，喧喧行人起。\n笳悲马嘶乱，争渡金河水。\n日暮沙漠陲，战声烟尘里。\n尽系名王颈，归来献天子。' },
  { title: '早春行', author: '王维', poem: '紫梅发初遍，黄鸟歌犹澁。\n谁家折杨女，弄春如不及。\n爱水看妆坐，羞人映花立。\n香畏风吹散，衣愁露沾湿。\n玉闺青门里，日落香车入。\n游衍益相思，含啼向彩帷。\n忆君长入梦，归晚更生疑。\n不及红檐燕，双栖绿草时。' },
  { title: '早朝', author: '王维', poem: '皎洁明星高，苍茫远天曙。\n槐雾暗不开，城鸦鸣稍去。\n始闻高阁声，莫辨更衣处。\n银烛已成行，金门俨驺驭。' },
  { title: '献始兴公', author: '王维', poem: '宁栖野树林，宁饮涧水流。\n不用坐[粱]肉，崎岖见王侯。\n鄙哉匹夫节，布褐将白头。\n任智诚则短，守任固其优。\n侧闻大君子，安问党与讐。\n所不卖公器，动为苍生谋。\n贱子跪自陈，可为帐下不。\n感激有公议，曲私非所求。' },
  { title: '赠从弟司库员外絿', author: '王维', poem: '少年识事浅，强学干名利。\n徒闻跃马年，苦无出人智。\n即事岂徒言，累官非不试。\n既寡遂性欢，恐招负时累。\n清冬见远山，积雪凝苍翠。\n浩然出东林，发我遗世意。\n惠连素清赏，夙语尘外事。\n欲缓携手期，流年一何驶。' },
  { title: '座上走笔赠薛璩慕容损', author: '王维', poem: '希世无高节，绝迹有卑栖。\n君徒视人文，吾固和天倪。\n缅然万物始，及与群物齐。\n分地依后稷，用天信重黎。\n春风何豫人，令我思东溪。\n草色有佳意，花枝稍含荑。\n更待风景好，与君藉萋萋。' },
  { title: '赠李颀', author: '王维', poem: '闻君饵丹砂，甚有好颜色。\n不知从今去，几时生羽翼。\n王母翳华芝，望尔昆仑侧。\n文螭从赤豹，万里方一息。\n悲哉世上人，甘此膻腥食。' },
  { title: '赠刘蓝田', author: '王维', poem: '篱间犬迎吠，出屋候荆扉。\n岁晏输井税，山村人夜归。\n晚田始家食，余布成我衣。\n讵肯无公事，烦君问是非。' },
  { title: '赠房卢氏琯', author: '王维', poem: '达人无不可，忘己爱苍生。\n岂复少十室，弦歌在两楹。\n浮人日已归，但坐事农耕。\n桑榆郁相望，邑里多鸡鸣。\n秋山一何净，苍翠临寒城。\n视事兼偃卧，对书不簪缨。\n萧条人吏疎，鸟雀下空庭。\n鄙夫心所尚，晚节异平生。\n将从海岳居，守静解天刑。\n或可累安邑，茅茨君试营。' },
  { title: '赠祖三咏', author: '王维', poem: '蟏蛸挂虚牖，蟋蟀鸣前除。\n岁晏凉风至，君子复何如。\n高馆阒无人，离居不可道。\n闲门寂已闭，落日照秋草。\n虽有近音信，千里阻河关。\n中复客汝颍，去年归旧山。\n结交二十载，不得一日展。\n贫病子既深，契阔余不浅。\n仲秋虽未归，暮秋以为期。\n良会讵几日，终日长相思。' },
  { title: '春夜竹亭赠钱少府归蓝田', author: '王维', poem: '夜静群动息，时闻隔林犬。\n却忆山中时，人家涧西远。\n羡君明发去，采蕨轻轩冕。' },
  { title: '戏赠张五弟𬤇三首 一', author: '王维', poem: '吾弟东山时，心尚一何远。\n日高犹自卧，钟动始能饭。\n领上髪未梳，床头书不卷。\n清川兴悠悠，空林对偃蹇。\n青苔石上净，细草松下软。\n窗外鸟声闲，阶前虎心善。\n徒然万象多，澹尔太虚缅。\n一知与物平，自顾为人浅。\n对君忽自得，浮念不烦遣。' },
  { title: '戏赠张五弟𬤇三首 二', author: '王维', poem: '张弟五车书，读书仍隐居。\n染翰过草圣，赋诗轻子虚。\n闭门二室下，隐居十年余。\n宛是野人野，时从渔夫渔。\n秋风自萧索，五柳高且疎。\n望此去人世，渡水向吾庐。\n岁晏同携手，只应君与予。' },
  { title: '戏赠张五弟𬤇三首 三', author: '王维', poem: '设罝守毚兔，垂钓伺游鳞。\n此是安口腹，非关慕隐沦。\n吾生好清净，蔬食去情尘。\n今子方豪荡，思为鼎食人。\n我家南山下，动息自遗身。\n入鸟不相乱，见兽皆相亲。\n云霞成伴侣，虚白侍衣巾。\n何事须夫子，邀予谷口真。' },
  { title: '胡居士卧病遗米因赠', author: '王维', poem: '了观四大因，根性何所有。\n妄计苟不生，是身孰休咎。\n色声何谓客，阴界复谁守。\n徒言莲花目，岂恶杨枝肘。\n既饱香积饭，不醉声闻酒。\n有无断常见，生灭幻梦受。\n即病即实相，趋空定狂走。\n无有一法真，无有一法垢。\n居士素通达，随宜善抖擞。\n床上无氊卧，镉中有粥否。\n斋时不乞食，定应空漱口。\n聊持数斗米，且救浮生取。' },
  { title: '赠裴十迪', author: '王维', poem: '风景日夕佳，与君赋新诗。\n澹然望远空，如意方支颐。\n春风动百草，兰蕙生我篱。\n暧暧日暖闺，田家来致词。\n欣欣春还臯，淡淡水生陂。\n桃李虽未开，荑萼满芳枝。\n请君理还策，敢告将农时。' },
  { title: '与胡居士皆病寄此诗兼示学人二首 一', author: '王维', poem: '一兴微尘念，横有朝露身。\n如是覩阴界，何方置我人。\n碍有固为主，趣空宁舍宾。\n洗心讵悬解，悟道正迷津。\n因爱果生病，从贪始觉贫。\n色声非彼妄，浮幻即吾真。\n四达竟何遣，万殊安可尘。\n胡生但高枕，寂寞与谁邻。\n战胜不谋食，理齐甘负薪。\n予若未始异，讵论疎与亲。' },
  { title: '与胡居士皆病寄此诗兼示学人二首 二', author: '王维', poem: '浮空徒漫漫，泛有定悠悠。\n无乘及乘者，所谓智人舟。\n讵舍贫病域，不疲生死流。\n无烦君喻马，任以我为牛。\n植福祠迦叶，求仁笑孔丘。\n何津不鼓櫂，何路不摧辀。\n念此闻思者，胡为多阻修。\n空虚花聚散，烦恼树稀稠。\n灭相成无记，生心坐有求。\n降吴复归蜀，不到莫相尤。' },
  { title: '奉寄韦太守陟', author: '王维', poem: '荒城自萧索，万里山河空。\n天高秋日逈，嘹唳闻归鸿。\n寒塘映衰草，高馆落疎桐。\n临此岁方[晏]，顾景咏悲翁。\n故人不可见，寂寞平陵东。' },
  { title: '林园即事寄舍弟𬘘', author: '王维', poem: '寓目一萧散，销忧冀俄顷。\n青草肃澄陂，白云移翠岭。\n后沔通河渭，前山包鄢郢。\n松含风里声，花对池中影。\n地多齐后㿉，人带荆州瘿。\n徒思赤笔书，讵有丹砂井。\n心悲常欲绝，髪乱不能整。\n青簟日何长，闲门昼方静。\n颓思茅檐下，弥伤好风景。' },
  { title: '至滑州隔河望黎阳忆丁三宇', author: '王维', poem: '隔河见桑柘，蔼蔼黎阳川。\n望望行渐远，孤峰没云烟。\n故人不可见，河水复悠然。\n赖有政声远，时闻行路传。' },
  { title: '秋夜独坐怀内弟崔兴宗', author: '王维', poem: '夜静群动息，蟪蛄声悠悠。\n庭槐北风响，日夕方高秋。\n思子整羽翰，及时当云浮。\n吾生将白首，岁晏思沧州。\n高足在旦暮，肯为南亩俦。' },
  { title: '和使君五郎西楼望远思归', author: '王维', poem: '高楼望所思，目极情未毕。\n枕上见千里，窗中窥万室。\n悠悠长路人，暧暧远郊日。\n惆怅极浦外，迢递孤烟出。\n能赋属上才，思归同下秩。\n故乡不可见，云水空如一。' },
  { title: '酬黎居士淅川作', author: '王维', poem: '侬家真个去，公定随侬否。\n着处是莲花，无心变杨柳。\n松龛藏药裹，石唇安茶臼。\n气味当共知，那能不携手。' },
  { title: '送魏郡李太守赴任', author: '王维', poem: '与君伯氏别，又欲与君离。\n君行无几日，当复隔山陂。\n苍茫秦川尽，日落桃林塞。\n独树临关门，黄河向天外。\n前经洛阳陌，宛洛故人稀。\n故人离别尽，淇上转骖𬴂。\n企予悲送远，惆怅睢阳路。\n古木官渡平，秋城邺宫故。\n想君行县日，其出从如云。\n遥思魏公子，复忆李将军。' },
  { title: '送陆员外', author: '王维', poem: '郎署有伊人，居然古人风。\n天子顾河北，诏书除征东。\n拜手辞上官，缓步出南宫。\n九河平原外，七国蓟门中。\n阴风悲枯桑，古塞多飞蓬。\n万里不见虏，萧条胡地空。\n无为费中国，更欲邀奇功。\n迟迟前相送，握手嗟异同。\n行当对侯归，肯访商山翁。' },
  { title: '送宇文太守赴宣城', author: '王维', poem: '寥落云外山，迢递舟中赏。\n铙吹发西江，秋空多清响。\n地迥古城芜，月明寒潮广。\n时赛敬亭神，复解罟师网。\n何处寄相思？南风吹五两。' },
  { title: '送綦毋秘书弃官还江东', author: '王维', poem: '明时久不达，弃置与君同。\n天命无怨色，人生有素风。\n念君拂衣去，四海将安穷。\n秋天万里净，日暮澄江空。\n清夜何悠悠，扣舷明月中。\n和光鱼鸟际，澹尔蒹葭丛。\n无庸客昭世，衰鬓日如蓬。\n顽疎暗人事，僻陋远天聪。\n微物纵可采，其谁为至公。\n余亦从此去，归耕为老农。' },
  { title: '奉送六舅归陆浑', author: '王维', poem: '伯舅吏淮泗，卓鲁方喟然。\n悠哉自不竞，退耕东臯田。\n条桑腊月下，种杏春风前。\n酌醴赋归去，共知陶令贤。' },
  { title: '送别', author: '王维', poem: '下马饮君酒，问君何所之。\n君言不得意，归卧南山陲。\n但去莫复问，白云无尽时。' },
  { title: '送张五归山', author: '王维', poem: '送君尽惆怅，复送何人归。\n几日同携手，一朝先拂衣。\n东山有茅屋，幸为埽荆扉。\n当亦谢官去，岂令心事违。' },
  { title: '齐州送祖三', author: '王维', poem: '相逢方一笑，相送还成泣。\n祖帐已伤离，荒城复愁入。\n天寒远山净，日暮长河急。\n解缆君已遥，望君犹伫立。' },
  { title: '送缙云苗太守', author: '王维', poem: '手疏谢明主，腰章为长吏。\n方从会稽邸，更发汝南骑。\n按节下松阳，清江响铙吹。\n露冕见三吴，方知百城贵。' },
  { title: '送从弟蕃游淮南', author: '王维', poem: '读书复骑射，带劒游淮阴。\n淮阴少年辈，千里远相寻。\n高义难自隐，明时宁陆沈。\n岛夷九州外，泉馆三山深。\n席帆聊问罪，卉服尽成擒。\n归来见天子，拜爵赐黄金。\n忽思鲈鱼鲙，复有沧洲心。\n天寒蒹葭渚，日落云梦林。\n江城下枫叶，淮上闻秋砧。\n送归青门外，车马去骎骎。\n惆怅新丰树，空余天际禽。' },
  { title: '送高适弟耽归临淮作', author: '王维', poem: '少年客淮泗，落魄居下邳。\n遨游向燕赵，结客过临淄。\n山东诸侯国，迎送纷交驰。\n自尔厌游侠，闭户方垂帷。\n深明戴家礼，颇学毛公诗。\n备知轻济道，高卧陶唐时。\n圣主诏天下，贤人不得遗。\n公吏奉𫄸组，安车去茅茨。\n君王苍龙阙，九门十二逵。\n群公朝谒罢，冠劒下丹墀。\n野鹤终踉跄，威凤徒参差。\n或问理人术，但致还山词。\n天书降北阙，赐帛归东菑。\n都门谢亲故，行路日逶迟。\n孤帆万里外，淼漫将何之。\n江天海陵郡，云日淮南祠。\n杳冥沧洲上，荡漭无人知。\n纬萧或卖药，出处安能期。' },
  { title: '送綦毋潜落第还乡', author: '王维', poem: '圣代无隐者，英灵尽来归。\n遂令东山客，不得顾采薇。\n既至君门远，孰云吾道非。\n江淮度寒食，京洛缝春衣。\n置酒临长道，同心与我违。\n行当浮桂櫂，未几拂荆扉。\n远树带行客，孤村当落晖。\n吾谋适不用，勿谓知音稀。' },
  { title: '送张舍人佐江州同薛璩十韵', author: '王维', poem: '束带趋承明，守官唯谒者。\n清晨听银蚪，薄暮辞金马。\n受辞未尝易，当是方知寡。\n清范何风流，高文有风雅。\n忽佐江上州，当自浔阳下。\n逆旅到三湘，长途应百舍。\n香炉远峰出，石镜澄湖泻。\n董奉杏成林，陶潜菊盈把。\n范蠡常好之，庐山我心也。\n送君思远道，欲以数行洒。' },
  { title: '送韦大夫东京留守', author: '王维', poem: '人外遗世虑，空端结遐心。\n曾是巢许浅，始知尧舜深。\n苍生讵有物，黄屋如乔林。\n上德抚神运，冲和穆宸襟。\n云雷康屯难，江海遂飞沈。\n天工寄人英，龙衮瞻君临。\n名器苟不假，保厘固其任。\n素质贯方领，清景照华簪。\n慷慨念王室，从容献官箴。\n云旗蔽三川，画角发龙吟。\n晨扬天汉声，夕卷大河阴。\n穷人业已宁，逆虏遗之擒。\n然后解金组，拂衣东山岑。\n给事黄门省，秋光正沈沈。\n壮心与身退，老病随年侵。\n君子从相访，重玄其可寻。' },
  { title: '资圣寺送甘二', author: '王维', poem: '浮生信如寄，薄宦夫何有。\n来往本无归，别离方此受。\n柳色蔼春余，槐阴清夏首。\n不觉御沟上，衔悲执桮酒。' },
  { title: '留别山中温古上人兄幷示舍弟缙', author: '王维', poem: '解薜登天朝，去师偶时哲。\n岂惟山中人，兼负松上月。\n宿昔同游止，致身云霞末。\n开轩临颍阳，卧视飞鸟没。\n好依盘石饭，屡对瀑泉渴。\n理齐小狎隐，道胜宁外物。\n舍弟官崇高，宗兄此削髪。\n荆扉但洒扫，乘闲当过歇。' },
  { title: '观别者', author: '王维', poem: '青青杨柳陌，陌上别离人。\n爱子游燕赵，高堂有老亲。\n不行无可养，行去百忧新。\n切切委兄弟，依依向四邻。\n都门帐饮毕，从此谢亲宾。\n挥涕逐前侣，含凄动征轮。\n车徒望不见，时见起行尘。\n吾亦辞家久，看之泪满巾。' },
  { title: '别弟缙后登青龙寺望蓝田山', author: '王维', poem: '陌上新离别，苍茫四郊晦。\n登高不见君，故山复云外。\n远树蔽行人，长天隐秋塞。\n心悲宦游子，何处飞征盖。' },
  { title: '别綦毋潜', author: '王维', poem: '端笏明光宫，历稔朝云陛。\n诏刊延阁书，高议平津邸。\n适意偶轻人，虚心削繁礼。\n盛得江左风，弥工建安体。\n高张多绝弦，截河有清济。\n严冬爽群木，伊洛方清泚。\n渭水冰下流，潼关雪中启。\n荷𦰏几时还，尘缨待君洗。' },
  { title: '晦日游大理韦卿城南别业四声依次用各六韵 一', author: '王维', poem: '与世澹无事，自然江海人。\n侧闻尘外游，解骖𨋗朱轮。\n平野照暄景，上天垂春云。\n张组竟北阜，泛舟过东邻。\n故乡信高会，牢醴及佳辰。\n幸同击壤乐，心荷尧为君。' },
  { title: '晦日游大理韦卿城南别业四声依次用各六韵 二', author: '王维', poem: '郊居杜陵下，永日同携手。\n仁里霭川阳，平原见峰首。\n园庐鸣春鸠，林薄媚新柳。\n上卿始登席，故老前为寿。\n临当游南陂，约略执桮酒。\n归欤绌微官，惆怅心自咎。' },
  { title: '晦日游大理韦卿城南别业四声依次用各六韵 三', author: '王维', poem: '冬中余雪在，墟上春流驶。\n风日畅怀抱，山川多秀气。\n雕胡先晨炊，庖脍亦云至。\n高情浪海岳，浮生寄天地。\n君子外簪缨，埃尘良不啻。\n所乐衡门中，陶然忘其贵。' },
  { title: '晦日游大理韦卿城南别业四声依次用各六韵 四', author: '王维', poem: '高馆临澄陂，旷然荡心目。\n淡荡动云天，玲珑映墟曲。\n鹊巢结空林，雉雊响幽谷。\n应接无闲暇，徘徊以踯躅。\n纡组上春堤，侧弁倚乔木。\n弦望忽已晦，后期洲应绿。' },
  { title: '冬日游览', author: '王维', poem: '步出城东门，试骋千里目。\n青山横苍林，赤日团平陆。\n渭北走邯郸，关东出函谷。\n秦地万方会，来朝九州牧。\n鸡鸣咸阳中，冠盖相追逐。\n丞相过列侯，群公饯光禄。\n相如方老病，独归茂陵宿。' },
  { title: '华岳', author: '王维', poem: '西岳出浮云，积雪在太清。\n连天凝黛色，百里遥青冥。\n白日为之寒，森沈华阴城。\n昔闻乾坤闭，造化生巨灵。\n右足踏方止，左手推削成。\n天地忽开拆，大河注东溟。\n遂为西峙岳，雄雄镇秦京。\n大君包覆载，至德被群生。\n上帝伫昭告，金天思奉迎。\n人祇望幸久，何独禅云亭。' },
  { title: '同卢拾遗过韦给事东山别业二十韵给事首春休沐维已陪游及乎是行亦预闻命会无车马不果斯诺', author: '王维', poem: '托身侍云陛，昧旦趋华轩。\n遂陪鹓鸿侣，霄汉同飞翻。\n君子垂惠顾，期我于田园。\n侧闻景龙际，亲降南面尊。\n万乘驻山外，顺风祈一言。\n高阳多夔龙，荆山积玙璠。\n盛德启前烈，大贤钟后昆。\n侍郎文昌宫，给事东掖垣。\n谒帝俱来下，冠盖盈丘樊。\n闺风首邦族，庭训延乡村。\n采地包山河，树井竟川原。\n岩端回绮槛，谷口开朱门。\n阶下群峰首，云中瀑水源。\n鸣玉满春山，列筵先朝暾。\n会舞何飒沓，击钟弥朝昏。\n是时阳和节，清昼犹未暄。\n蔼蔼树色深，嘤嘤鸟声繁。\n顾己负宿诺，延颈慙芳荪。\n蹇步守穷巷，高驾难攀援。\n素是独往客，脱冠情弥敦。' },
  { title: '蓝田山石门精舍', author: '王维', poem: '落日山水好，漾舟信归风。\n探奇不觉远，因以缘源穷。\n遥爱云木秀，初疑路不同。\n安知清流转，偶与前山通。\n舍舟理轻策，果然惬所适。\n老僧四五人，逍遥荫松栢。\n朝梵林未曙，夜禅山更寂。\n道心及牧童，世事问樵客。\n暝宿长林下，焚香卧瑶席。\n涧芳袭人衣，山月暎石壁。\n再寻畏迷误，明发更登历。\n笑谢桃源人，花红复来觌。' },
  { title: '青谿', author: '王维', poem: '言入黄花川，每逐青谿水。\n随山将万转，趣途无百里。\n声喧乱石中，色静深松里。\n漾漾泛菱荇，澄澄映葭苇。\n我心素已闲，清川澹如此。\n请留盘石上，垂钓将已矣。' },
  { title: '崔濮阳兄季重前山兴', author: '王维', poem: '秋色有佳兴，况君池上闲。\n悠悠西林下，自识门前山。\n千里横黛色，数峰出云间。\n嵯峨对秦国，合沓藏荆关。\n残雨斜日照，夕岚飞鸟还。\n故人今尚尔，叹息此颓颜。' },
  { title: '李处士山居', author: '王维', poem: '君子盈天阶，小人甘自免。\n方随炼金客，林上家绝𪩘。\n背岭花未开，入云树深浅。\n清昼犹自眠，山鸟时一啭。' },
  { title: '丁宇田家有赠', author: '王维', poem: '君心尚栖隐，久欲傍归路。\n在朝每为言，解印果成趣。\n晨鸡鸣邻里，群动从所务。\n农夫行饷田，闺妾起缝素。\n开轩御衣服，散帙理章句。\n时吟招隐诗，或制闲居赋。\n新晴望郊郭，日暎桑榆暮。\n阴昼小苑城，微明渭川树。\n揆予宅闾井，幽赏何由屡。\n道存终不忘，迹异难相遇。\n此时惜离别，再来芳菲度。' },
  { title: '渭川田家', author: '王维', poem: '斜阳照墟落，穷巷牛羊归。\n野老念牧童，倚杖候荆扉。\n雉雊麦苗秀，蚕眠桑叶稀。\n田夫荷锄至，相见语依依。\n即此羡闲逸，怅然吟式微。' },
  { title: '春中田园作', author: '王维', poem: '屋上春鸠鸣，村边杏花白。\n持斧伐远扬，荷锄觇泉脉。\n归燕识故巢，旧人看新历。\n临觞忽不御，惆怅远行客。' },
  { title: '过李楫宅', author: '王维', poem: '闲门秋草色，终日无车马。\n客来深巷中，犬吠寒林下。\n散髪时未簪，道书行尚把。\n与我同心人，乐道安贫者。\n一罢宜城酌，还归洛阳社。' },
  { title: '韦侍郎山居', author: '王维', poem: '幸忝君子顾，遂陪尘外踪。\n闲花满岩谷，瀑水映杉松。\n啼鸟忽临涧，归云时抱峰。\n良游盛簪绂，继迹多夔龙。\n讵枉青门道，胡闻长乐钟。\n清晨去朝谒，车马何从容。' },
  { title: '饭覆釜山僧', author: '王维', poem: '晚知清净理，日与人群疎。\n将候远山僧，先期埽弊庐。\n果从云峰里，顾我蓬蒿居。\n藉草饭松屑，焚香看道书。\n然灯昼欲尽，鸣磬夜方初。\n一悟寂为乐，此日闲有余。\n思归何必深，身世犹空虚。' },
  { title: '谒璇上人', author: '王维', poem: '少年不足言，识道年已长。\n事往安可悔，余生幸能养。\n誓从断臂血，不复婴世网。\n浮名寄缨珮，空性无羁鞅。\n夙承大导师，焚香此瞻仰。\n颓然居一室，覆载纷万象。\n高柳早鸎啼，长廊春雨响。\n床下阮家屐，窗前筇竹杖。\n方将见身云，陋彼示天壤。\n一心在法要，愿以无生奖。' },
  { title: '瓜园诗', author: '王维', poem: '余适欲锄瓜，倚锄听叩门。\n鸣驺导骢马，常从夹朱轩。\n穷巷正传呼，故人傥相存。\n携手追凉风，放心望乾坤。\n蔼蔼帝王州，宫观一何繁。\n林端出绮道，殿顶摇华幡。\n素怀在青山，若值白云屯。\n回风城西雨，返景原上村。\n前酌盈尊酒，往往闻清言。\n黄鹂啭深木，朱槿照中园。\n犹羡松下客，石上闻清猿。' },
  { title: '自大散以往深林密竹磴道盘曲四五十里至黄牛岭见黄花川', author: '王维', poem: '危径几万转，数里将三休。\n回环见徒侣，隐暎隔林丘。\n飒飒松上雨，潺潺石中流。\n静言深谿里，长啸高山头。\n望见南山阳，白露霭悠悠。\n青臯丽已净，绿树郁如浮。\n曾是厌蒙密，旷然销人忧。' },
  { title: '新晴野望', author: '王维', poem: '新晴原野旷，极目无氛垢。\n郭门临渡头，村树连谿口。\n白水明田外，碧峰出山后。\n农月无闲人，倾家事南亩。' },
  { title: '宿郑州', author: '王维', poem: '朝与周人辞，暮投郑人宿。\n他乡绝俦侣，孤客亲僮仆。\n宛洛望不见，秋霖晦平陆。\n田父草际归，村童雨中牧。\n主人东臯上，时稼遶茅屋。\n虫思机杼悲，雀喧禾黍熟。\n明当渡京水，昨晚犹金谷。\n此去欲何言，穷边狥微禄。' },
  { title: '早入荥阳界', author: '王维', poem: '泛舟入荥泽，兹邑乃雄藩。\n河曲闾阎隘，川中烟火繁。\n因人见风俗，入境闻方言。\n秋野田畴盛，朝光市井喧。\n渔商波上客，鸡犬岸旁村。\n前路白云外，孤帆安可论。' },
  { title: '渡河到清河作', author: '王维', poem: '泛舟大河里，积水穷天涯。\n天波忽开拆，郡邑千万家。\n行复见城市，宛然有桑麻。\n回瞻旧乡国，淼漫连云霞。' },
  { title: '苦热', author: '王维', poem: '赤日满天地，火云成山岳。\n草木尽焦卷，川泽皆竭涸。\n轻纨觉衣重，密树苦阴薄。\n莞簟不可近，𫄨绤再三濯。\n思出宇宙外，旷然在寥廓。\n长风万里来，江海荡烦浊。\n却顾身为患，始知心未觉。\n忽入甘露门，宛然清凉乐。' },
  { title: '纳凉', author: '王维', poem: '乔木万余株，清流贯其中。\n前临大川口，豁达来长风。\n涟漪涵白沙，素鲔如游空。\n偃卧盘石上，翻涛沃微躬。\n漱流复濯足，前对钓鱼翁。\n贪饵凡几许，徒思莲叶东。' },
  { title: '西施咏', author: '王维', poem: '艳色天下重，西施宁久微。\n朝仍越溪女，暮作吴宫妃。\n贱日岂殊众，贵来方悟稀。\n邀人傅香粉，不自着罗衣。\n君宠益娇态，君怜无是非。\n当时浣纱伴，莫得同车归。\n持谢邻家子，效颦安可希。' },
  { title: '李陵咏', author: '王维', poem: '汉家李将军，三代将门子。\n结发有奇策，少年成壮士。\n长驱塞上儿，深入单于垒。\n旌旗列相向，箫鼓悲何已。\n日暮沙漠陲，战声烟尘里。\n将令骄虏灭，岂独名王侍。\n既失大军援，遂婴穹庐耻。\n少小蒙汉恩，何堪坐思此。\n深衷欲有报，投躯未能死。\n引领望子卿，非君谁相理。' },
  { title: '济上四贤咏 崔录事', author: '王维', poem: '解印归田里，贤哉此丈夫。\n少年曾任侠，晚节更为儒。\n遯迹东山下，因家沧海隅。\n已闻能狎鸟，余欲共乘桴。' },
  { title: '济上四贤咏 成文学', author: '王维', poem: '宝劒千金装，登君白玉堂。\n身为平原客，家有邯郸娼。\n使气公卿坐，论心游侠场。\n中年不得意，谢病客游梁。' },
  { title: '济上四贤咏 郑霍二山人', author: '王维', poem: '翩翩繁华子，多出金张门。\n幸有先人业，早蒙明主恩。\n童年且未学，肉食骛华轩。\n岂乏中林士，无人荐至尊。\n郑公老泉石，霍子安丘樊。\n卖药不二价，著书盈万言。\n息阴无恶木，饮水必清源。\n吾贱不及议，斯人竟谁论。' },
  { title: '过太乙观贾生房', author: '王维', poem: '昔余栖遯日，之子烟霞邻。\n共携松叶酒，俱𥮾竹皮巾。\n攀林遍岩洞，采药无冬春。\n谬以道门子，征为骖御臣。\n常恐丹液就，先我紫阳宾。\n夭促万涂尽，哀伤百虑新。\n迹峻不容俗，才多反累真。\n泣对双泉水，还山无主人。' },
  { title: '燕子龛禅师', author: '王维', poem: '山中燕子龛，路剧羊肠恶。\n裂地竞盘屈，插天多峭崿。\n瀑泉吼而喷，怪石看欲落。\n伯禹访未知，五丁愁不凿。\n上人无生缘，生长居紫阁。\n六时自搥磬，一饮常带索。\n种田烧白云，斫漆响丹壑。\n行随拾栗猿，归对巢松鹤。\n时许山神请，偶逢洞仙博。\n救世多慈悲，即心无行作。\n周商倦积阻，蜀物多淹泊。\n岩腹乍旁穿，涧唇时外拓。\n桥因倒树架，栅值垂藤缚。\n鸟道悉已平，龙宫为之涸。\n跳波谁揭厉，绝壁免扪摸。\n山木日阴阴，结跏归旧林。\n一向石门里，任君春草深。' },
  { title: '羽林骑闺人', author: '王维', poem: '秋月临高城，城中管弦思。\n离人堂上愁，稚子阶前戏。\n出门复暎户，望望青丝骑。\n行人过欲尽，狂夫终不至。\n左右寂无言，相看共垂泪。' },
  { title: '偶然作六首 一', author: '王维', poem: '楚国有狂夫，茫然无心想。\n散髪不冠带，行歌南陌上。\n孔丘与之言，仁义莫能奖。\n未尝肯问天，何事须击壤。\n复笑采薇人，胡为乃长往。' },
  { title: '偶然作六首 二', author: '王维', poem: '田舍有老翁，垂白衡门里。\n有时农事闲，斗酒呼邻里。\n喧聒茅檐下，或坐或复起。\n短褐不为薄，园葵固足美。\n动则长子孙，不曾向城市。\n五帝与三王，古来称天子。\n干戈将揖让，毕竟何者是。\n得意苟为乐，野田安足鄙。\n且当放怀去，行行没余齿。' },
  { title: '偶然作六首 三', author: '王维', poem: '日夕见太行，沈吟未能去。\n问君何以然，世网婴我故。\n小妹日成长，兄弟未有娶。\n家贫禄既薄，储蓄非有素。\n几回欲奋飞，踟蹰复相顾。\n孙登长啸台，松竹有遗处。\n相去讵几许，故人在中路。\n爱染日已薄，禅寂日已固。\n忽乎吾将行，宁俟岁云暮。' },
  { title: '偶然作六首 四', author: '王维', poem: '陶潜任天真，其性颇躭酒。\n自从弃官来，家贫不能有。\n九月九日时，菊花空满手。\n中心窃自思，傥有人送否。\n白衣携壶觞，果来遗老叟。\n且喜得斟酌，安问升与斗。\n奋衣野田中，今日嗟无负。\n兀傲迷东西，蓑笠不能守。\n倾倒强行行，酣歌归五柳。\n生事不曾问，肯媿家中妇。' },
  { title: '偶然作六首 五', author: '王维', poem: '赵女弹箜篌，复能邯郸舞。\n夫壻轻薄儿，鬬鸡事齐主。\n黄金买歌笑，用钱不复数。\n许史相经过，高门盈四牡。\n客舍有儒生，昂藏出邹鲁。\n读书三十年，腰间无尺组。\n被服圣人教，一生自穷苦。' },
  { title: '偶然作六首 六', author: '王维', poem: '老来懒赋诗，惟有老相随。\n宿世谬词客，前身应画师。\n不能舍余习，偶被世人知。\n名字本皆是，此心还不知。' },
  { title: '寓言二首 一', author: '王维', poem: '朱绂谁家子，无乃金张孙。\n骊驹从白马，出入铜龙门。\n问尔何功德，多承明主恩。\n鬬鸡平乐馆，射雉上林园。\n曲陌车骑盛，高堂珠翠繁。\n奈何轩冕贵，不与布衣言。' },
  { title: '寓言二首 二', author: '王维', poem: '君家御沟上，垂柳夹朱门。\n列鼎会中贵，鸣珂朝至尊。\n生死在八议，穷达由一言。\n须识苦寒士，莫矜狐白温。' },
  { title: '冬夜书怀', author: '王维', poem: '冬宵寒且永，夜漏宫中发。\n草白霭繁霜，木衰澄清月。\n丽服暎颓颜，朱灯照华髪。\n汉家方尚少，顾影慙朝谒。' },
  { title: '送康太守', author: '王维', poem: '城下沧江水，江边黄鹤楼。\n朱阑将粉堞，江水映悠悠。\n铙吹发夏口，使君居上头。\n郭门隐枫岸，候吏趋芦洲。\n何异临川郡，还劳康乐侯。' },
  { title: '送权二', author: '王维', poem: '高人不可有，清论复何深。\n一见如旧识，一言知道心。\n明时当薄宦，解薜去中林。\n芳草空隐处，白云余故岑。\n韩侯久携手，河岳共幽寻。\n怅别千余里，临堂鸣素琴。' },
  { title: '休假还旧业便使', author: '王维', poem: '谢病始告归，依依入桑梓。\n家人皆𥩟立，相候衡门里。\n时辈皆长年，成人旧童子。\n上堂嘉庆毕，顾与姻亲齿。\n论旧忽余悲，目存皆相喜。\n田园转芜没，但有寒泉水。\n衰柳日萧条，秋光清邑里。\n入门乍如客，休骑非便止。\n中饮顾王程，离忧从此始。' },
  { title: '叹白髪', author: '王维', poem: '我年一何长，鬓髪日已白。\n俛仰天地间，能为几时客。\n惆怅故山云，俳徊空日夕。\n何事与时人，东城复南陌。' },
  { title: '别弟妹二首 一', author: '王维', poem: '两妹日成长，双鬟将及人。\n已能持宝瑟，自解掩罗巾。\n念昔别时小，未知疎与亲。\n今来始离恨，拭泪方殷勤。' },
  { title: '别弟妹二首 二', author: '王维', poem: '小弟更孩幼，归来不相识。\n同居虽渐惯，见人犹未觅。\n宛作越人语，殊甘水乡食。\n别此最为难，泪尽有余忆。' },
  { title: '哭殷遥', author: '王维', poem: '人生能几何，毕竟归无形。\n念君等为死，万事伤人情。\n慈母未及葬，一女才十龄。\n泱漭寒郊外，萧条闻哭声。\n浮云为苍茫，飞鸟不能鸣。\n行人何寂寞，白日自凄清。\n忆昔君在时，问我学无生。\n劝君苦不早，令君无所成。\n故人各有赠，又不及生平。\n负尔非一途，恸哭返柴荆。' },
  { title: '故南阳夫人樊氏挽歌', author: '王维', poem: '石窌恩荣重，金吾车骑盛。\n将朝每赠言，入室还相敬。\n叠鼓秋城动，悬旌寒日映。\n不言长不归，环珮犹将听。' },
  { title: '夷门歌', author: '王维', poem: '七雄雄雌犹未分，攻城杀将何纷纷。\n秦兵益围邯郸急，魏王不救平原君。\n公子为嬴停驷马，执辔愈恭意愈下。\n亥为屠肆鼓刀人，嬴乃夷门抱关者。\n非但慷慨献良谋，意气兼将身命酬。\n向风刎颈送公子，七十老翁何所求。' },
  { title: '陇头吟', author: '王维', poem: '长安少年游侠客，夜上戍楼看太白。\n陇头明月迥临关，陇上行人夜吹笛。\n关西老将不胜愁，驻马听之双泪流。\n身经大小百余战，麾下偏裨万户侯。\n苏武才为典属国，节旄落尽海西头。' },
  { title: '老将行', author: '王维', poem: '少年十五二十时，步行夺得胡马射。\n射杀中山白额虎，肯数邺下黄须儿。\n一身转战三千里，一劒曾当百万师。\n汉兵奋迅如霹雳，虏骑崩腾畏蒺藜。\n衞青不败由天幸，李广无功缘数奇。\n自从弃置便衰朽，世事磋跎成白首。\n昔时飞箭无全目，今日垂杨生左肘。\n路傍时卖故侯瓜，门前学种先生柳。\n苍茫古木连穷巷，寥落寒山对虚牖。\n誓令疏勒出飞泉，不似颍川空使酒。\n贺兰山下阵如云，羽檄交驰日夕闻。\n节使三河募年少，诏书五道出将军。\n试拂铁衣如雪色，聊持宝劒动星文。\n愿得燕弓射天将，耻令越甲鸣吴军。\n莫嫌旧日云中守，犹堪一战取功勋。' },
  { title: '燕支行', author: '王维', poem: '汉家天将才且雄，来时谒帝明光宫。\n万乘亲推双阙下，千官出饯五陵东。\n誓辞甲第金门里，身作长城玉塞中。\n衞霍才堪一骑将，朝廷不数贰师功。\n赵魏燕韩多劲卒，关西侠少何咆勃。\n报讐只是闻尝胆，饮酒不曾妨刮骨。\n画戟雕戈白日寒，连旗大斾黄尘没。\n叠鼓遥翻瀚海波，鸣笳乱动天山月。\n麒麟锦带佩吴钩，飒沓青骊跃紫骝。\n拔劒已断天骄臂，归鞍共饮月支头。\n汉兵大呼一当百，虏骑相看哭且愁。\n教战虽令赴汤火，终知上将先伐谋。' },
  { title: '桃源行', author: '王维', poem: '渔舟逐水爱山春，两岸桃花夹去津。\n坐看红树不知远，行尽青溪不见人。\n山口潜行始隈隩，山开旷望旋平陆。\n遥看一处攒云树，近入千家散花竹。\n樵客初传汉姓名，居人未改秦衣服。\n居人共住武陵源，还从物外起田园。\n月明松下房栊静，日出云中鸡犬喧。\n惊闻俗客争来集，竞引还家问都邑。\n平明闾巷埽花开，薄暮渔樵乘水入。\n初因避地去人间，及至成仙遂不还。\n峡里谁知有人事，世中遥望空云山。\n不疑灵境难闻见，尘心未尽思乡县。\n出洞无论隔山水，辞家终拟长游衍。\n自谓经过旧不迷，安知峰壑今来变。\n当时只记入山深，青溪几曲到云林。\n春来遍是桃花水，不辨仙源何处寻。' },
  { title: '洛阳女儿行', author: '王维', poem: '洛阳女儿对门居，才可容颜十五余。\n良人玉勒乘骢马，侍女金盘鲙鲤鱼。\n画阁朱楼尽相望，红桃绿柳垂檐向。\n罗帏送上七香车，宝扇迎归九华帐。\n狂夫富贵在青春，意气骄奢剧季伦。\n自怜碧玉亲教舞，不惜珊瑚持与人。\n春窗曙灭九微火，九微片片飞花璅。\n戏罢曾无理曲时，妆成秪是薰香坐。\n城中相识尽繁华，日夜经过赵李家。\n谁怜越女颜如玉，贫贱江头自浣纱。' },
  { title: '同崔傅答贤弟', author: '王维', poem: '洛阳才子姑苏客，桂苑殊非故乡陌。\n九江枫树几回青，一片扬州五湖白。\n扬州时有下江兵，兰陵镇前吹笛声。\n夜火人归富春郭，秋风鹤唳石头城。\n周郎陆弟为俦侣，对舞前溪歌白纻。\n曲几书留小史家，草堂棋赌山阴墅。\n衣冠若话外台臣，先数夫君席上珍。\n更闻台阁求三语，遥想风流第一人。' },
  { title: '赠吴官', author: '王维', poem: '长安客舍热如煮，无个茗糜难御暑。\n空摇白团其谛苦，欲向缥囊还归旅。\n江乡鲭鲊不寄来，秦人汤饼那堪许。\n不如侬家任挑达，草𪨗捞虾富春渚。' },
  { title: '故人张𬤇工诗善易卜兼能丹青草隶顷以诗见赠聊获酬之', author: '王维', poem: '不逐城东游侠儿，隐囊纱帽坐弹棋。\n蜀中夫子时开卦，洛下书生解咏诗。\n药阑花迳衡门里，时复据梧聊隐几。\n屏风误点惑孙郎，团扇草书轻内史。\n故园高枕度三春，永日垂帷绝四邻。\n自想蔡邕今已老，更将书籍使何人。' },
  { title: '送崔五太守', author: '王维', poem: '长安厩吏来到门，朱文露网动行轩。\n黄花县西九折坂，玉树宫南五丈原。\n襃斜谷中不容幰，唯有白云当露冕。\n子午山里杜鹃啼，嘉陵水头行客饭。\n劒门忽断蜀川开，万井双流满眼来。\n雾中远树刀州出，天际澄江巴字回。\n使君年纪三十余，少年白皙专城居。\n欲持画省郎官笔，回与临邛父老书。' },
  { title: '寒食城东即事', author: '王维', poem: '清溪一道穿桃李，演漾绿蒲涵白芷。\n溪上人家凡几家，落花半落东流水。\n蹴鞠屡过飞鸟上，秋千竞出垂杨里。\n少年分日作遨游，不用清明兼上巳。' },
  { title: '不遇咏', author: '王维', poem: '北阙献书寝不报，南山种田时不登。\n百人会中身不预，五侯门前心不能。\n身投河朔饮君酒，家在茂陵平安否。\n且此登山复临水，莫问春风动杨柳。\n今人昨人多自私，我心不说君应知。\n济人然后拂衣去，肯作徒尔一男儿。' },
  { title: '赠裴迪', author: '王维', poem: '不相见，不相见来久。\n日日泉水头，常忆同携手。\n携手本同心，复叹忽分襟。\n相忆今如此，相思深不深。' },
  { title: '青雀歌', author: '王维', poem: '青雀翅羽短，未能远食玉山禾。\n犹胜黄雀争上下，唧唧空仓复若何。' },
  { title: '黄雀痴', author: '王维', poem: '黄雀痴，黄雀痴，谓言青鷇是我儿。\n一一口衔食，养得成毛衣。\n到大啁啾解游飏，各自东西南北飞。\n薄暮空巢上，羇雌独自归。\n凤凰九雏亦如此，慎莫愁思顦顇损容辉。' },
  { title: '新秦郡松树歌', author: '王维', poem: '青青山上松，数里不见今更逢。\n不见君，心相忆，此心向君君应识。\n为君颜色高且闲，亭亭迥出浮云间。' },
  { title: '楡林郡歌', author: '王维', poem: '山头松柏林，山下泉声伤客心。\n千里万里春草色，黄河东流流不息。\n黄龙戍上游侠儿，愁逢汉使不相识。' },
  { title: '问寇校书双谿', author: '王维', poem: '君家少室西，为复少室东。\n别来几日今春风，新买双谿定何似。' },
  { title: '寄崇梵僧', author: '王维', poem: '崇梵僧，崇梵僧，秋归覆釜春不还。\n落花啼鸟纷纷乱，涧户山窗寂寂闲。\n峡里谁知有人事，郡中遥望空云山。' },
  { title: '同比部杨员外十五夜游有怀静者季', author: '王维', poem: '承明少休沐，建礼省文书。\n夜漏行人息，归鞍落日余。\n悬知三五夕，万户千门辟。\n夜出曙翻归，倾城满南陌。\n陌头驰骋尽繁华，王孙公子五侯家。\n由来月明如白日，共道春灯胜百花。\n聊看侍中千宝骑，强识小妇七香车。\n香车宝马共喧阗，个里多情侠少年。\n竞向长杨柳市北，肯过精舍竹林前。\n独有仙郎心寂寞，却将宴坐为行乐。\n傥觉忘怀共往来，幸沾同舍甘藜藿。' },
  { title: '荅张五弟', author: '王维', poem: '终南有茅屋，前对终南山。\n终年无客常闭关，终日无心长自闲。\n不妨饮酒复垂钓，君但能来相往还。' },
  { title: '雪中忆李楫', author: '王维', poem: '积雪满阡陌，故人不可期。\n长安千门复万户，何处躞蹀黄金羁。' },
  { title: '送李睢阳', author: '王维', poem: '将置酒，思悲翁。\n使君去，出城东。\n麦渐渐，雉子斑。\n槐阴阴，到潼关。\n骑连连，车迟迟。\n心中悲，宋又远。\n周间之，南淮夷。\n东齐儿，碎碎织练与素丝。\n游人贾客信难持，五谷前熟方可为。\n下车闭合君当思，天子当殿俨衣裳。\n大官尚食陈羽觞，彤庭散绶垂鸣珰。\n黄纸诏书出东厢，轻纨叠绮烂生光。\n宗室子弟君最贤，分忧当为百辟先。\n布衣一言相为死，何况圣主恩如天。\n鸾声哕哕鲁侯旗，明年上计朝京师。\n须忆今日斗酒别，慎勿富贵忘我为。' },
  { title: '奉和圣制天长节赐宰臣歌应制', author: '王维', poem: '太阳升兮照万方，开阊阖兮临玉堂。\n俨冕旒兮垂衣裳，金天净兮丽三光。\n彤庭曙兮延八荒，德合天兮礼神徧。\n灵芝生兮庆云见，唐尧后兮稷卨臣。\n匝宇宙兮华胥人，尽九服兮皆四邻，干降瑞兮坤降珍。' },
  { title: '登楼歌', author: '王维', poem: '聊上君兮高楼，飞甍鳞次兮在下。\n俯十二兮通衢，绿槐参差兮车马。\n却瞻兮龙首，前眺兮宜春。\n王畿郁兮千里，山河壮兮咸秦。\n舍人下兮青宫，据胡床兮书空。\n执戟疲于下位，老夫好隐兮墙东。\n亦幸有张伯英草圣兮龙腾蚪跃，摆长云兮捩回风。\n琥珀酒兮雕胡饭，君不御兮日将晚。\n秋风兮吹衣，夕鸟兮争返。\n孤砧发兮东城，林薄暮兮蝉声远。\n时不可兮再得，君何为兮偃蹇。' },
  { title: '双黄鹄歌送别', author: '王维', poem: '天路来兮双黄鹄，云上飞兮水上宿。\n抚翼和鸣整羽族，不得已，忽分飞。\n家在玉京朝紫微，主人临水送将归。\n悲笳嘹唳垂舞衣，宾欲散兮复相依。\n几往返兮极浦，尚裴回兮落晖。\n岸上火兮相迎，将夜入兮边城。\n鞍马归兮佳人散，怅离忧兮独含情。' },
  { title: '赠徐中书望终南山歌', author: '王维', poem: '晚下兮紫微，怅尘事兮多违。\n驻马兮双树，望青山兮不归。' },
  { title: '送友人归山歌二首 一', author: '王维', poem: '山寂寂兮无人，又苍苍兮多木。\n群龙兮满朝，君何为兮空谷。\n文寡和兮思深，道难知兮行独。\n悦石上兮流泉，与松间兮草屋。\n入云中兮养鸡，上山头兮抱犊。\n神与枣兮如瓜，虎卖杏兮收谷。\n愧不才兮妨贤，嫌既老兮贪禄。\n誓解印兮相从，何詹尹兮何卜。' },
  { title: '送友人归山歌二首 二', author: '王维', poem: '山中人兮欲归，云冥冥兮雨霏霏，水惊波兮翠菅靡。\n白鹭忽兮翻飞，君不可兮褰衣。\n山万重兮一云，混天地兮不分。\n树晻暧兮氛氲，猿不见兮空闻。\n忽山西兮夕阳，见东臯兮远村。\n平芜绿兮千里，眇惆怅兮思君。' },
  { title: '鱼山神女祠歌 迎神', author: '王维', poem: '坎坎击鼓，鱼山之下。\n吹洞箫，望极浦，女巫进，纷屡舞。\n陈瑶席，湛清酤，风凄凄兮夜雨。\n不知神之来兮不来，使我心兮苦复苦。' },
  { title: '鱼山神女祠歌 送神', author: '王维', poem: '纷进舞兮堂前，目眷眷兮琼筵。\n来不言兮意不传，作暮雨兮愁空山。\n悲急管兮思繁弦，神之驾兮俨欲旋。\n倏云收兮雨歇，山青青兮水潺湲。' },
  { title: '白鼋涡', author: '王维', poem: '南山之瀑水兮，激石瀥瀑似雷惊。\n人相对兮，不闻语声。\n翻涡跳沫兮苍苔湿，藓老且厚，春草为之不生。\n兽不敢惊动，鸟不敢飞鸣。\n白鼋涡涛戏濑兮，委身以纵横。\n王人之仁兮，不网不钓，得遂性以生成。' },
  { title: '宋进马哀词', author: '王维', poem: '背春涉夏兮，众木蔼以繁阴。\n连金华与玉堂兮，宫阁郁其沈沈。\n百官并入兮，何语笑之哑哑。\n君独静嘿以伤心，草王言兮不得辞。\n我悲减思兮少时，仆夫命驾兮。\n出阊阖，历通逵，陌上人兮如故。\n识不识兮往来，眼中不见兮吾儿。\n骖紫骝兮从青骊，低光垂彩兮。\n怳不知其所之，辟朱户兮望华轩。\n意斯子兮候门，忽思瘗兮城南。\n心瞀乱兮重昏，仰诉天之不仁兮。\n家唯一身，身止一子。\n何胤嗣之不繁，就单尠而又死。\n将清白兮遗谁，问诗礼兮已矣。\n哀从中兮不可胜，岂暇料余年兮复几。\n日黯黯兮颓晔，鸟翩翩兮疾飞。\n邈穷天兮不返，疑有日兮来归。\n静言思兮永绝，复惊叫兮沾衣。\n客有吊之者曰：观未始兮有物，同委蜕兮胡悲。\n且延陵兮未至，况西河兮不知。\n学无生兮庶可，幸能听于吾师。' },
  { title: '奉和圣制赐史供奉曲江䜩应制', author: '王维', poem: '侍从有邹枚，琼筵就水开。\n言陪柏梁宴，新下建章来。\n对酒山河满，移舟草树廻。\n天文同丽日，驻景惜行杯。' },
  { title: '从岐王过杨氏别业应教', author: '王维', poem: '杨子谈经所，淮王载酒过。\n兴阑啼鸟换，坐久落花多。\n迳转廻银烛，林开散玉珂。\n严城时未启，前路拥笙歌。' },
  { title: '从岐王夜宴衞家山池应教', author: '王维', poem: '座客香貂满，宫娃绮幔张。\n涧花轻粉色，山月少灯光。\n积翠纱窗暗，飞泉绣户凉。\n还将歌舞出，归路莫愁长。' },
  { title: '同崔员外秋宵寓直', author: '王维', poem: '建礼高秋夜，承明候晓过。\n九门寒漏彻，万井曙钟多。\n月迥藏珠斗，云消出绛河。\n更慙衰朽质，南陌共鸣珂。' },
  { title: '辋川闲居赠裴秀才迪', author: '王维', poem: '寒山转苍翠，秋水日潺湲。\n倚杖柴门外，临风听暮蝉。\n渡头余落日，墟里上孤烟。\n复值接舆醉，狂歌五柳前。' },
  { title: '寄荆州张丞相', author: '王维', poem: '所思竟何在，怅望深荆门。\n举世无相识，终身思旧恩。\n方将与农圃，艺植老丘园。\n目尽南飞鴈，何由寄一言。' },
  { title: '冬晚对雪忆胡居士家', author: '王维', poem: '寒更传晓箭，清镜览衰颜。\n隔牖风惊竹，开门雪满山。\n洒空深巷静，积素广庭闲。\n借问袁安舍，翛然尚闭关。' },
  { title: '和尹谏议史馆山池', author: '王维', poem: '云馆接天居，霓裳侍玉除。\n春池百子外，芳树万年余。\n洞有仙人箓，山藏太史书。\n君恩深汉帝，且莫上空虚。' },
  { title: '奉和杨驸马六郎秋夜即事', author: '王维', poem: '高楼月似霜，秋夜郁金堂。\n对坐弹卢女，同看舞凤凰。\n少儿多送酒，小玉更焚香。\n结束平阳骑，明朝入建章。' },
  { title: '酬虞部苏员外过蓝田别业不见留之作', author: '王维', poem: '贫居依谷口，乔木带荒村。\n石路枉廻驾，山家谁候门。\n渔舟胶冻浦，猎火烧寒原。\n唯有白云外，疎钟闻夜猿。' },
  { title: '酬比部杨员外暮宿琴台朝跻书阁率尔见赠之作', author: '王维', poem: '旧简拂尘看，鸣琴候月弹。\n桃源迷汉姓，松树有秦官。\n空谷归人少，青山背日寒。\n羡君栖隐处，遥望白云端。' },
  { title: '酬严少尹徐舍人见过不遇', author: '王维', poem: '公门暇日少，穷巷故人稀。\n偶值乘篮轝，非关避白衣。\n不知炊黍谷，谁解埽荆扉。\n君但倾茶椀，无妨骑马归。' },
  { title: '酬张少府', author: '王维', poem: '晚年唯好静，万事不关心。\n自顾无长策，空知返旧林。\n松风吹解带，山月照弹琴。\n君问穷通理，渔歌入浦深。' },
  { title: '酬贺四赠葛巾之作', author: '王维', poem: '野巾传惠好，兹贶重兼金。\n嘉此幽栖物，能齐隐吏心。\n早朝方暂挂，晚沐复来簪。\n坐觉嚣尘远，思君共入林。' },
  { title: '送丘为落第归江东', author: '王维', poem: '怜君不得意，况复柳条春。\n为客黄金尽，还家白发新。\n五湖三亩宅，万里一归人。\n知尔不能荐，羞称献纳臣。' },
  { title: '送李判官赴东江', author: '王维', poem: '闻道皇华使，方随皂盖臣。\n封章通左语，冠冕化文身。\n树色分扬子，潮声满富春。\n遥知辨璧吏，恩到泣珠人。' },
  { title: '送封太守', author: '王维', poem: '忽解羊头削，聊驰熊首轓。\n扬舲发夏口，按节向吴门。\n帆暎丹阳郭，枫攒赤岸村。\n百村多候吏，露冕一何尊。' },
  { title: '送严秀才还蜀', author: '王维', poem: '宁亲为令子，似舅即贤甥。\n别路经花县，还乡入锦城。\n山临青塞断，江向白云平。\n献赋何时至，明君忆长卿。' },
  { title: '送张判官赴河西', author: '王维', poem: '单车曾出塞，报国敢邀勋。\n见逐张征虏，今思霍冠军。\n沙平连白雪，蓬卷入黄云。\n慷慨倚长劒，高歌一送君。' },
  { title: '送岐州源长史归', author: '王维', poem: '握手一相送，心悲安可论。\n秋风正萧索，客散孟尝门。\n故驿通槐里，长亭下槿原。\n征西旧旌节，从此向河源。' },
  { title: '送张道士归山', author: '王维', poem: '先生何处去，王屋访茅君。\n别妇留丹诀，驱鸡入白云。\n人间若剩住，天上复离群。\n当作辽城鹤，仙歌使尔闻。' },
  { title: '同崔兴宗送衡岳瑗公南归', author: '王维', poem: '言从石菌阁，新下穆陵关。\n独向池阳去，白云留故山。\n绽衣秋日里，洗钵古松间。\n一施传心法，唯将戒定还。' },
  { title: '送钱少府还蓝田', author: '王维', poem: '草色日向好，桃源人去稀。\n手持平子赋，目送老莱衣。\n每候山樱发，时同海燕归。\n今年寒食酒，应是返柴扉。' },
  { title: '送丘为往唐州', author: '王维', poem: '宛洛有风尘，君行多苦辛。\n四愁连汉水，百口寄随人。\n槐色阴清昼，杨花惹暮春。\n朝端肯相送，天子绣衣臣。' },
  { title: '送元中丞转运江淮', author: '王维', poem: '薄赋归天府，轻徭赖使臣。\n欢沾赐帛老，恩及卷绡人。\n去问珠官俗，来经石𧉧春。\n东南御亭上，莫使有风尘。' },
  { title: '送崔九兴宗游蜀', author: '王维', poem: '送君从此去，转觉故人稀。\n徒御犹廻首，田园方掩扉。\n出门当旅食，中路授寒衣。\n江汉风流地，游人何岁归。' },
  { title: '送崔兴宗', author: '王维', poem: '已恨亲皆远，谁怜友复稀。\n君王未西顾，游宦尽东归。\n塞迥山河净，天长云树微。\n方同菊花节，相待洛阳扉。' },
  { title: '送平澹然判官', author: '王维', poem: '不识阳关路，新从定远侯。\n黄云断春色，画角起边愁。\n瀚海经年到，交河出塞流。\n须令外国使，知饮月氏头。' },
  { title: '送刘司直赴安西', author: '王维', poem: '绝域阳关道，胡沙与塞尘。\n三春时有雁，万里少行人。\n苜蓿随天马，葡萄逐汉臣。\n当令外国惧，不敢觅和亲。' },
  { title: '送赵都督赴代州得青字', author: '王维', poem: '天官动将星，汉上柳条青。\n万里鸣刁斗，三军出井陉。\n忘身辞凤阙，报国取龙庭。\n岂学书生辈，窗间老一经。' },
  { title: '送方城韦明府', author: '王维', poem: '遥思葭菼际，寥落楚人行。\n高鸟长淮水，平芜故郢城。\n使车听雉乳，县鼓应鸡鸣。\n若见州从事，无嫌手板迎。' },
  { title: '送李员外贤郎', author: '王维', poem: '少年何处去，负米上铜梁。\n借问阿戎父，知为童子郎。\n鱼牋请诗赋，橦布作衣裳。\n薏苡扶衰病，归来幸可将。' },
  { title: '送梓州李使君', author: '王维', poem: '万壑树参天，千山响杜鹃。\n山中一夜雨，树杪百重泉。\n汉女输橦布，巴人讼芋田。\n文翁翻教授，不敢倚先贤。' },
  { title: '送张五𬤇归宣城', author: '王维', poem: '五湖千万里，况复五湖西。\n渔浦南陵郭，人家春谷谿。\n欲归江淼淼，未到草萋萋。\n忆想兰陵镇，可宜猿更啼。' },
  { title: '送友人南归', author: '王维', poem: '万里春应尽，三江雁亦稀。\n连天汉水广，孤客郢城归。\n郧国稻苗秀，楚人菰米肥。\n悬知倚门望，遥识老莱衣。' },
  { title: '送贺遂员外外甥', author: '王维', poem: '南国有归舟，荆门溯上流。\n苍茫葭菼外，云水与昭丘。\n樯带城乌去，江连暮雨愁。\n猿声不可听，莫待楚山秋。' },
  { title: '送杨长史赴果州', author: '王维', poem: '襃斜不容幰，之子去何之。\n鸟道一千里，猿声十二时。\n官桥祭酒客，山木女郎祠。\n别后同明月，君应听子规。' },
  { title: '送邢桂州', author: '王维', poem: '铙吹喧京口，风波下洞庭。\n赭圻将赤岸，击汰复扬舲。\n日落江湖白，潮来天地青。\n明珠归合浦，应逐使臣星。' },
  { title: '送宇文三赴河西充行军司马', author: '王维', poem: '横吹杂繁笳，边风卷塞沙。\n还闻田司马，更逐李轻车。\n蒲类成秦地，莎车属汉家。\n当令犬戎国，朝聘学昆邪。' },
  { title: '送孙二', author: '王维', poem: '郊外谁相送，夫君道术亲。\n书生邹鲁客，才子洛阳人。\n祖席依寒草，行车起暮尘。\n山川何寂寞，长望泪沾巾。' },
  { title: '送崔三往密州觐省', author: '王维', poem: '南陌去悠悠，东郊不少留。\n同怀扇枕恋，独念倚门愁。\n路遶天山雪，家临海树秋。\n鲁连功未报，且莫蹈沧洲。' },
  { title: '送孟六归襄阳', author: '王维', poem: '杜门不复出，久与世情疎。\n以此为良策，劝君归旧庐。\n醉歌田舍酒，笑读古人书。\n好是一生事，无劳献子虚。' },
  { title: '初出济州别城中故人', author: '王维', poem: '微官易得罪，谪去济川阴。\n执政方持法，明君照此心。\n闾阎河润上，井邑海云深。\n纵有归来日，各愁年鬓侵。' },
  { title: '与卢象集朱家', author: '王维', poem: '主人能爱客，终日有逢迎。\n贳得新丰酒，复闻秦女筝。\n柳条疎客舍，槐叶下秋城。\n语笑且为乐，吾将达此生。' },
  { title: '登裴秀才迪小台', author: '王维', poem: '端居不出户，满目望云山。\n落日鸟边下，秋原人外闲。\n遥知远林际，不见此檐间。\n好客多乘月，应门莫上关。' },
  { title: '游李山人所居因题屋壁', author: '王维', poem: '世上皆如梦，狂来止自歌。\n问年松树老，有地竹林多。\n药倩韩康卖，门容尚子过。\n翻嫌枕席上，无那白云何。' },
  { title: '过崔驸马山池', author: '王维', poem: '画楼吹笛妓，金椀酒家胡。\n锦石称贞女，青松学大夫。\n脱貂贳桂醑，射雁与山厨。\n闻道高阳会，愚公谷正愚。' },
  { title: '过福禅师兰若', author: '王维', poem: '岩壑转微迳，云林隐法堂。\n羽人飞奏乐，天女跪焚香。\n竹外峰偏曙，藤阴水更凉。\n欲知禅坐久，行路长春芳。' },
  { title: '过香积寺', author: '王维', poem: '不知香积寺，数里入云峰。\n古木无人迳，深山何处钟。\n泉声咽危石，日色冷青松。\n薄暮空潭曲，安禅制毒龙。' },
  { title: '过感化寺昙兴上人山院', author: '王维', poem: '暮持筇竹杖，相待虎谿头。\n催客闻山响，归房逐水流。\n野花丛发好，谷鸟一声幽。\n夜坐空林寂，松风直似秋。' },
  { title: '夏日过青龙寺谒操禅师', author: '王维', poem: '龙钟一老翁，徐步谒禅宫。\n欲问义心义，遥知空病空。\n山河天眼里，世界法身中。\n莫怪销炎热，能生大地风。' },
  { title: '登辨觉寺', author: '王维', poem: '竹径从初地，莲峰出化城。\n窗中三楚尽，林上九江平。\n软草承趺坐，长松响梵声。\n空居法云外，观世得无生。' },
  { title: '喜祖三至留宿', author: '王维', poem: '门前洛阳客，下马拂征衣。\n不枉故人驾，平生多掩扉。\n行人返深巷，积雪带余晖。\n早岁同袍者，高车何处归。' },
  { title: '黎拾遗昕裴秀才迪见过秋夜对雨之作', author: '王维', poem: '促织鸣已急，轻衣行向重。\n寒灯坐高馆，秋雨闻疎钟。\n白法调狂象，玄言问老龙。\n何人顾蓬径，空愧求羊踪。' },
  { title: '慕容承携素馔见过', author: '王维', poem: '纱帽乌皮几，闲居懒赋诗。\n门看五柳识，年筭六身知。\n灵寿君王赐，雕胡弟子炊。\n空劳酒食馔，持底解人颐。' },
  { title: '晚春严少尹与诸公见过', author: '王维', poem: '松菊荒三迳，图书共五车。\n烹葵邀上客，看竹到贫家。\n鹊乳先春草，莺啼过落花。\n自怜黄髪暮，一倍惜年华。' },
  { title: '郑果州相过', author: '王维', poem: '丽日照残春，初晴草木新。\n床前磨镜客，树下灌园人。\n五马惊穷巷，双童逐老身。\n中厨办麤饭，当恕阮家贫。' },
  { title: '山居秋暝', author: '王维', poem: '空山新雨后，天气晚来秋。\n明月松间照，清泉石上流。\n竹喧归浣女，莲动下渔舟。\n随意春芳歇，王孙自可留。' },
  { title: '终南别业', author: '王维', poem: '中岁颇好道，晚家南山陲。\n兴来每独往，胜事空自知。\n行到水穷处，坐看云起时。\n偶然值林叟，谈笑无还期。' },
  { title: '归嵩山作', author: '王维', poem: '清川带长薄，车马去闲闲。\n流水如有意，暮禽相与还。\n荒城临古渡，落日满秋山。\n迢递嵩高下，归来且闭关。' },
  { title: '归辋川作', author: '王维', poem: '谷口疎钟动，渔樵稍欲稀。\n悠然远山暮，独向白云归。\n菱蔓弱难定，杨花轻易飞。\n东臯春草色，惆怅掩柴扉。' },
  { title: '韦给事山居', author: '王维', poem: '幽寻得此地，讵有一人曾。\n大壑随阶转，群山入户登。\n庖厨出深竹，印绶隔垂藤。\n即事辞轩冕，谁云病未能。' },
  { title: '山居即事', author: '王维', poem: '寂寞掩柴扉，苍茫对落晖。\n鹤巢松树遍，人访荜门稀。\n绿竹含新粉，红莲落故衣。\n渡头烟火起，处处采菱归。' },
  { title: '终南山', author: '王维', poem: '太乙近天都，连山接海隅。\n白云回望合，青霭入看无。\n分野中峰变，阴晴众壑殊。\n欲投人处宿，隔水问樵夫。' },
  { title: '辋川闲居', author: '王维', poem: '一从归白社，不复到青门。\n时倚檐前树，远看原上村。\n青菰临水拔，白鸟向山翻。\n寂寞於陵子，桔槔方灌园。' },
  { title: '春园即事', author: '王维', poem: '宿雨乘轻屐，春寒着弊袍。\n开畦分白水，间柳发红桃。\n草际成棋局，林端举桔槔。\n还持鹿皮几，日暮隐蓬蒿。' },
  { title: '淇上田园即事', author: '王维', poem: '屏居淇水上，东野旷无山。\n日隐桑柘外，河明闾井间。\n牧童望村去，猎犬随人还。\n静者亦何事，荆扉乘昼关。' },
  { title: '凉州郊外游望', author: '王维', poem: '野老才三户，边村少四邻。\n婆娑依里社，箫鼓赛田神。\n洒酒浇刍狗，焚香拜木人。\n女巫纷屡舞，罗袜自生尘。' },
  { title: '观猎', author: '王维', poem: '风劲角弓鸣，将军猎渭城。\n草枯鹰眼疾，雪尽马蹄轻。\n忽过新丰市，还归细柳营。\n回看射雕处，千里暮云平。' },
  { title: '春日上方即事', author: '王维', poem: '好读高僧传，时看辟谷方。\n鸠形将刻杖，龟壳用支床。\n柳色春山暎，梨花夕鸟藏。\n北窗桃李下，闲坐但焚香。' },
  { title: '汉江临泛', author: '王维', poem: '楚塞三湘接，荆门九派通。\n江流天地外，山色有无中。\n郡邑浮前浦，波澜动远空。\n襄阳好风日，留醉与山翁。' },
  { title: '泛前陂', author: '王维', poem: '秋空自明迥，况复远人间。\n畅以沙际鹤，兼之云外山。\n澄波澹将夕，清月皓方闲。\n此夜任孤櫂，夷犹殊未还。' },
  { title: '登河北城楼作', author: '王维', poem: '井邑傅岩上，客亭云雾间。\n高城眺落日，极浦暎苍山。\n岸火孤舟宿，渔家夕鸟还。\n寂寥天地暮，心与广川闲。' },
  { title: '千塔主人', author: '王维', poem: '逆旅逢佳节，征帆未可前。\n窗临汴河水，门渡楚人船。\n鸡犬散墟落，桑榆荫远田。\n所居人不见，枕席生云烟。' },
  { title: '使至塞上', author: '王维', poem: '单车欲问边，属国过居延。\n征蓬出汉塞，归雁入胡天。\n大漠孤烟直，长河落日圆。\n萧关逢候吏，都护在燕然。' },
  { title: '晚春归思', author: '王维', poem: '新妆可怜色，落日卷罗帷。\n𬬻气清珍簟，墙阴上玉墀。\n春虫飞网户，暮雀隐花枝。\n向晚多愁思，闲窗桃李时。' },
  { title: '戏题示萧氏甥', author: '王维', poem: '怜尔解临池，渠爷未学诗。\n老夫何足似，弊宅倘因之。\n芦笋穿荷叶，菱花罥雁儿。\n郗公不易胜，莫着外家欺。' },
  { title: '秋夜独坐', author: '王维', poem: '独坐悲双鬓，空堂欲二更。\n雨中山果落，灯下草虫鸣。\n白发终难变，黄金不可成。\n欲知除老病，唯有学无生。' },
  { title: '待储光羲不至', author: '王维', poem: '重门朝已启，起坐听车声。\n要欲闻清佩，方将出户迎。\n晚钟鸣上苑，疎雨过春城。\n了自不相顾，临堂空复情。' },
  { title: '听宫莺', author: '王维', poem: '春树遶宫墙，宫莺啭曙光。\n忽惊啼暂断，移处弄还长。\n隐叶栖承露，攀花出未央。\n游人未应返，为此始思乡。' },
  { title: '杂诗', author: '王维', poem: '双燕初命子，五桃新作花。\n王昌是东舍，宋玉次西家。\n小小能织绮，时时出浣纱。\n亲劳使君问，南陌驻香车。' },
  { title: '留别钱起', author: '王维', poem: '卑栖却得性，每与白云归。\n徇禄仍怀橘，看山免采薇。\n暮禽先去马，新月待开扉。\n霄汉时回首，知音青琐闱。' },
  { title: '留别丘为', author: '王维', poem: '归鞍白云外，缭绕出前山。\n今日又明日，自知心不闲。\n亲劳簪组送，欲趂莺花还。\n一步一回首，迟迟向近关。' },
  { title: '愚公谷三首 一', author: '王维', poem: '愚谷与谁去，唯将黎子同。\n非须一处住，不那两心空。\n宁问春将夏，谁论西复东。\n不知吾与子，若个是愚公。' },
  { title: '愚公谷三首 二', author: '王维', poem: '吾家愚谷里，此谷本来平。\n虽则行无迹，还能响应声。\n不随云色暗，只待日光明。\n缘底名愚谷，都由愚所成。' },
  { title: '愚公谷三首 三', author: '王维', poem: '借问愚公谷，与君聊一寻。\n不寻翻到谷，此谷不离心。\n行处曾无险，看时岂有深。\n寄言尘世客，何处欲归临。' },
  { title: '酬慕容十一', author: '王维', poem: '行行西陌返，驻幰问车公。\n挟毂双官骑，应门五尺僮。\n老年如塞北，强起离墙东。\n为报壶丘子，来人道姓蒙。' },
  { title: '过始皇墓', author: '王维', poem: '古墓成苍岭，幽宫象紫台。\n星辰七曜隔，河汉九泉开。\n有海人宁渡，无春雁不廻。\n更闻松韵切，疑是大夫哀。' },
  { title: '恭懿太子挽歌五首 一', author: '王维', poem: '何悟藏环早，才知拜璧年。\n翀天王子去，对日圣君怜。\n树转宫犹出，笳悲马不前。\n虽蒙绝驰道，京兆别开阡。' },
  { title: '恭懿太子挽歌五首 二', author: '王维', poem: '兰殿新恩切，椒宫夕临幽。\n白云随凤管，明月在龙楼。\n人向青山哭，天临渭水愁。\n鸡鸣常问膳，今恨玉京留。' },
  { title: '恭懿太子挽歌五首 三', author: '王维', poem: '骑吹凌霜发，旌旗夹路陈。\n凯容金节护，册命玉符新。\n傅母悲香褓，君家拥画轮。\n射熊今梦帝，秤象问何人。' },
  { title: '恭懿太子挽歌五首 四', author: '王维', poem: '苍舒留帝宠，子晋有仙才。\n五岁过人智，三天使鹤催。\n心悲阳禄馆，目断望思台。\n若道长安近，何为更不来。' },
  { title: '恭懿太子挽歌五首 五', author: '王维', poem: '西望昆池阔，东瞻下杜平。\n山朝豫章馆，树转凤凰城。\n五校连旗色，千门叠鼓声。\n金环如有验，还向画堂生。' },
  { title: '故太子太师徐公挽歌四首 一', author: '王维', poem: '功德冠群英，弥纶有大名。\n轩皇用风后，傅说是星精。\n就第优遗老，来朝诏不名。\n留侯常辟谷，何苦不长生。' },
  { title: '故太子太师徐公挽歌四首 二', author: '王维', poem: '谋猷为相国，翊戴奉宸舆。\n劒履升前殿，貂蝉托后车。\n齐侯疏土宇，汉室赖图书。\n僻处留田宅，仍才十顷余。' },
  { title: '故太子太师徐公挽歌四首 三', author: '王维', poem: '旧里趋庭日，新年置酒辰。\n闻诗鸾渚客，献赋凤楼人。\n北首辞明主，东堂哭大臣。\n犹思御朱辂，不惜[污]车茵。' },
  { title: '故太子太师徐公挽歌四首 四', author: '王维', poem: '久践中台座，终登上将坛。\n谁言断车骑，空忆盛衣冠。\n风日咸阳惨，笳箫渭水寒。\n无人当便阙，应罢太师官。' },
  { title: '故西河郡杜太守挽歌三首 一', author: '王维', poem: '天上去西征，云中护北平。\n生擒白马将，连破黑雕城。\n忽见刍灵苦，徒闻竹使荣。\n空留左氏传，谁继卜商名。' },
  { title: '故西河郡杜太守挽歌三首 二', author: '王维', poem: '返葬金符守，同归石窌妻。\n卷衣悲画翟，持翣待鸣鸡。\n容衞都人惨，山川驷马嘶。\n犹闻陇上客，相对哭征西。' },
  { title: '故西河郡杜太守挽歌三首 三', author: '王维', poem: '涂刍去国门，秘器出东园。\n太守留金印，夫人罢锦轩。\n旌旗转衰木，箫鼓上寒原。\n坟树应西靡，长思魏阙恩。' },
  { title: '达奚侍郎夫人寇氏挽词二首 一', author: '王维', poem: '束带将朝日，鸣环映牖辰。\n能令谏明主，相劝识贤人。\n遗挂空留壁，廻文日覆尘。' },
  { title: '达奚侍郎夫人寇氏挽词二首 二', author: '王维', poem: '女史悲彤管，夫人罢锦轩。\n卜茔占二室，行哭度千门。\n秋日光能淡，寒川波自翻。\n一朝成万古，松柏暗平原。' },
  { title: '送孙秀才', author: '王维', poem: '帝城风日好，况复建平家。\n玉枕双文簟，金盘五色瓜。\n山中无鲁酒，松下饭胡麻。\n莫厌田家苦，归期远复赊。' },
  { title: '奉和圣制庆玄元皇帝玉像之作应制', author: '王维', poem: '明君梦帝先，宝命上齐天。\n秦后徒闻乐，周王耻卜年。\n玉京移大像，金箓会群仙。\n承露调天供，临空敞御筵。\n斗廻迎寿酒，山近起𬬻烟。\n愿奉无为化，斋心学自然。' },
  { title: '奉和圣制与太子诸王三月三日龙池春禊应制', author: '王维', poem: '故事修春禊，新宫展豫游。\n明君移凤辇，太子出龙楼。\n赋掩陈王作，桮如洛水流。\n金人来捧劒，画鹢去回舟。\n苑树浮宫阙，天池照冕旒。\n宸章在云表，垂象满皇州。' },
  { title: '奉和圣制上巳于望春亭观禊饮应制', author: '王维', poem: '长乐青门外，宜春小苑东。\n楼开万井上，辇过百花中。\n画鹢移仙妓，金貂列上公。\n清歌邀落日，妙舞向春风。\n渭水明秦甸，黄山入汉宫。\n君王来祓禊，灞浐亦朝宗。' },
  { title: '奉和圣制暮春送朝集使归郡应制', author: '王维', poem: '万国仰宗周，衣冠拜冕旒。\n玉乘迎大客，金节送诸侯。\n祖席倾三省，褰帷向九州。\n杨花飞上路，槐色荫通沟。\n来预钧天乐，归分汉主忧。\n宸章类河汉，垂象满中州。' },
  { title: '三月三日曲江侍宴应制', author: '王维', poem: '万乘亲斋祭，千官喜豫游。\n奉迎从上苑，祓禊向中流。\n草树连容衞，山河对冕旒。\n画旗摇浦溆，春服满汀洲。\n仙籞龙媒下，神臯凤跸留。\n从今亿万岁，天宝纪春秋。' },
  { title: '奉和圣制重阳节宰臣及群官上寿应制', author: '王维', poem: '四海方无事，三秋大有年。\n百生无此日，万寿愿齐天。\n芍药和金鼎，茱萸插玳筵。\n玉堂开右个，天乐动宫悬。\n御柳疎秋景，城鸦拂曙烟。\n无穷菊花节，长奉柏梁篇。' },
  { title: '三月三日勤政楼侍宴应制', author: '王维', poem: '彩仗连宵合，琼楼拂曙通。\n年光三月里，宫殿百花中。\n不数秦王日，谁将洛水同。\n酒筵嫌落絮，舞袖怯春风。\n天保无为德，人欢不战功。\n仍临九衢宴，更达四门聪。' },
  { title: '奉和圣制十五夜然灯继以酺宴应制', author: '王维', poem: '上路笙歌满，春城漏刻长。\n游人多昼日，明月让灯光。\n鱼钥通翔凤，龙舆出建章。\n九衢陈广乐，百福透名香。\n仙伎来金殿，都人遶玉堂。\n定应偷妙舞，从此学新妆。\n奉引迎三事，司仪列万方。\n愿将天地寿，同以献君王。' },
  { title: '奉和圣制幸玉真公主山庄因题石壁十韵之作应制', author: '王维', poem: '碧落风烟外，瑶台道路赊。\n如何连帝苑，别自有仙家。\n此地回鸾驾，缘谿转翠华。\n洞中开日月，窗里发云霞。\n庭养冲天鹤，溪流上汉查。\n种田生白玉，泥灶化丹砂。\n谷静泉逾响，山深日易斜。\n御羹和石髓，香饭进胡麻。\n大道今无外，长生讵有涯。\n还瞻九霄上，来往五云车。' },
  { title: '春日直门下省早朝', author: '王维', poem: '骑省直明光，鸡鸣谒建章。\n遥闻侍中珮，暗识令君香。\n玉漏随铜史，天书拜夕郎。\n旌旗暎阊阖，歌吹满昭阳。\n官舍梅初紫，宫门柳欲黄。\n愿将迟日意，同与圣恩长。' },
  { title: '和仆射晋公扈从温汤', author: '王维', poem: '天子幸新丰，旌旗渭水东。\n寒山天仗外，温谷幔城中。\n奠玉群仙座，焚香太乙宫。\n出游逢牧马，罢猎见非熊。\n上宰无为化，明时太古同。\n灵芝三秀紫，陈粟万箱红。\n王礼奠儒教，天兵小战功。\n谋犹归哲匠，词赋属文宗。\n司谏方无阙，陈诗且未工。\n长吟吉甫颂，朝夕仰清风。' },
  { title: '和宋中丞夏日游福贤观天长寺寺即陈左相宅所施之作', author: '王维', poem: '已相殷王国，空余尚父谿。\n钓矶开月殿，筑道出云梯。\n积水浮香象，深山鸣白鸡。\n虚空陈伎乐，衣服制虹霓。\n墨点三千界，丹飞六一泥。\n桃源勿遽返，再访恐君迷。' },
  { title: '和陈监四郎秋雨中思从弟据', author: '王维', poem: '袅袅秋风动，凄凄烟雨繁。\n声连𫛛鹊观，色暗凤凰原。\n细柳疎高阁，轻槐落洞门。\n九衢行欲断，万井寂无喧。\n忽有愁霖唱，更陈多露言。\n平原思令弟，康乐谢贤昆。\n逸兴方三接，衰颜强七奔。\n相如今老病，归守茂陵园。' },
  { title: '上张令公', author: '王维', poem: '珥笔趋丹陛，垂珰上玉除。\n步檐青琐闼，方幰画轮车。\n市阅千金字，朝闻五色书。\n致君光帝典，荐士满公车。\n伏奏回金驾，横经重石渠。\n从兹罢角觝，且复幸储胥。\n天统知尧后，王章笑鲁初。\n匈奴遥俯伏，汉相俨簪裾。\n贾生非不遇，汲黯自堪疎。\n学易思求我，言诗或起予。\n当从大夫后，何惜隶人余。' },
  { title: '赠焦道士', author: '王维', poem: '海上游三岛，淮南预八公。\n坐知千里外，跳向一壶中。\n缩地朝珠阙，行天使玉童。\n饮人聊割酒，送客乍分风。\n天老能行气，吾师不养空。\n谢君徒雀跃，无可问鸿蒙。' },
  { title: '赠东岳焦炼师', author: '王维', poem: '先生千岁余，五岳遍曾居。\n遥识齐侯鼎，新过王母庐。\n不能师孔墨，何事问长沮。\n玉管时来凤，铜盘即钓鱼。\n竦身空里语，明目夜中书。\n自有还丹术，时论太素初。\n频蒙露版诏，时降软轮车。\n山静泉逾响，松高枝转疎。\n搘颐问樵客，世上复何如。' },
  { title: '送秘书晁监还日本国', author: '王维', poem: '积水不可极，安知沧海东。\n九州何处远，万里若乘空。\n向国唯看日，归帆但信风。\n鳌身暎天黑，鱼眼射波红。\n乡树扶桑外，主人孤岛中。\n别离方异域，音信若为通。' },
  { title: '送祢郎中', author: '王维', poem: '东郊春草色，驱马去悠悠。\n况复乡山外，猿啼湘水流。\n岛夷传露版，江馆候鸣驺。\n卉服为诸吏，珠官拜本州。\n孤鸎吟远墅，野杏发山邮。\n早晚方归奏，南中才忌秋。' },
  { title: '送李太守赴上洛', author: '王维', poem: '商山包楚邓，积翠蔼沈沈。\n驿路飞泉洒，关门落照深。\n野花开古戍，行客响空林。\n板屋春多雨，山城昼欲阴。\n丹泉通虢略，白羽抵荆岑。\n若见西山爽，应知黄绮心。' },
  { title: '送熊九赴任安阳', author: '王维', poem: '魏国应刘后，寂寥文雅空。\n漳河如旧日，之子继清风。\n阡陌铜台下，闾阎金虎中。\n送车盈灞上，轻骑出关东。\n相去千余里，西园明月同。' },
  { title: '山中示弟', author: '王维', poem: '山林吾丧我，冠带尔成人。\n莫学嵇康懒，且安原宪贫。\n山阴多北户，泉水在东邻。\n缘合妄相有，性空无所亲。\n安知广成子，不是老夫身。' },
  { title: '青龙寺昙璧上人兄院集', author: '王维', poem: '高处敞招提，虚空讵有倪。\n坐看南陌骑，下听秦城鸡。\n眇眇孤烟起，芊芊远树齐。\n青山万井外，落日五陵西。\n眼界今无染，心空安可迷。' },
  { title: '济州过赵叟家宴', author: '王维', poem: '虽与人境接，闭门成隐居。\n道言庄叟事，儒行鲁人余。\n深巷斜晖静，闲门高柳疎。\n荷锄修药圃，散帙曝农书。\n上客摇芳翰，中厨馈野蔬。\n夫君第高饮，景晏出林闾。' },
  { title: '春过贺遂员外药园', author: '王维', poem: '前年槿篱故，新作药栏成。\n香草为君子，名花是长卿。\n水穿盘石透，藤系古松生。\n画畏开厨走，来蒙到屣迎。\n蔗浆菰米饭，蒟酱露葵羹。\n颇识灌园意，于陵不自轻。' },
  { title: '过卢四员外宅看饭僧共题七韵', author: '王维', poem: '三贤异七贤，青眼慕青莲。\n乞饭从香积，裁衣学水田。\n上人飞锡杖，檀越施金钱。\n趺作檐前日，焚香竹下烟。\n寒空法云地，秋色净居天。\n身逐因缘法，心过次第禅。\n不须愁日暮，自有一灯然。' },
  { title: '河南严尹弟见宿弊庐访别人赋十韵', author: '王维', poem: '上客能论道，吾生学养蒙。\n贫交世情外，才子古人中。\n冠上方簪豸，车边已画熊。\n拂衣迎五马，垂手凭双童。\n花醥和松屑，茶香透竹丛。\n薄霜澄夜月，残雪带春风。\n古壁苍苔黑，寒山远烧红。\n眼看东候别，心事北川同。\n为学轻先辈，何能访老翁。\n欲知今日后，不乐为车公。' },
  { title: '投道一师兰若宿', author: '王维', poem: '一公栖太白，高顶出风烟。\n梵流诸壑遍，花雨一峰偏。\n迹为无心隐，名因立教传。\n鸟来还语法，客去更安禅。\n昼涉松路尽，暮投兰若边。\n洞房隐深竹，清夜闻遥泉。\n向是云霞里，今成枕席前。\n岂唯暂留宿，服事将穷年。' },
  { title: '游感化寺', author: '王维', poem: '翡翠香烟合，琉璃宝地平。\n龙宫连栋宇，虎穴傍檐楹。\n谷静唯松响，山深无鸟声。\n琼峰当户拆，金涧透林明。\n郢路云端逈，秦川雨外晴。\n鴈王衔果献，鹿女踏花行。\n抖擞辞贫里，归依宿化城。\n绕篱生野蕨，空馆发山樱。\n香饭青菰米，嘉蔬绿笋茎。\n誓陪清梵末，端坐学无生。' },
  { title: '游悟真寺', author: '王维', poem: '闻道黄金地，仍开白玉田。\n掷山移巨石，呪岭出飞泉。\n猛虎同三迳，愁猿学四禅。\n买香然绿桂，乞火踏红莲。\n草色摇霞上，松声泛月边。\n山河穷百二，世界接三千。\n梵宇聊凭视，王城遂渺然。\n灞陵才出树，渭水欲连天。\n远县分诸郭，孤村起白烟。\n望云思圣主，披雾隐群贤。\n薄宦惭尸素，终身拟尚玄。\n谁知草庵客，曾和柏梁篇。' },
  { title: '与苏卢二员外期游方丈寺而苏不至因有是作', author: '王维', poem: '共仰头陀行，能忘世谛情。\n回看双凤阙，相去一牛鸣。\n法向空林说，心随宝地平。\n手巾花氎净，香帔稻畦成。\n闻道邀同舍，相期宿化城。\n安知不来往，翻得似无生。' },
  { title: '晓行巴峡', author: '王维', poem: '际晓投巴峡，余春忆帝京。\n晴江一女浣，朝日众鸡鸣。\n水国舟中市，山桥树杪行。\n登高万井出，眺迥二流明。\n人作殊方语，鸎为故国声。\n赖多山水趣，稍解别离情。' },
  { title: '清如玉壶冰', author: '王维', poem: '玉壶何用好，偏许素冰居。\n未共销丹日，还同照绮疏。\n抱明中不隐，含净外疑虚。\n气似庭霜积，光言砌月余。\n晓凌飞鹊镜，宵暎聚萤书。\n若向夫君比，清心尚不如。' },
  { title: '赋得秋日悬清光', author: '王维', poem: '寥廓凉天静，晶明白日秋。\n圆光含万象，碎影入闲流。\n迥与青冥合，遥同江甸浮。\n昼阴殊众木，斜影下危楼。\n宋玉登高怨，张衡望远愁。\n余辉如可托，云路岂悠悠。' },
  { title: '东谿玩月', author: '王维', poem: '月从断山口，遥吐柴门端。\n万木分空霁，流阴中夜攒。\n光连虚象白，气与风露寒。\n谷静秋泉响，岩深青霭残。\n清灯入幽梦，破影抱空峦。\n恍惚琴窗里，松谿晓思难。' },
  { title: '田家', author: '王维', poem: '旧谷行将尽，良苗未可希。\n老年方爱粥，卒岁且无衣。\n雀乳青苔井，鸡鸣白板扉。\n柴车驾羸牸，草𪨗牧豪狶。\n夕雨红榴拆，新秋绿芋肥。\n饷田桑下憩，旁舍草中归。\n住处名愚谷，何烦问是非。' },
  { title: '沈十四拾遗新竹生读经处同诸公之作', author: '王维', poem: '闲居日清静，修竹自檀栾。\n嫩节留余箨，新丛出旧阑。\n细枝风响乱，疎影月光寒。\n乐府裁龙笛，渔家伐钓竿。\n何如道门里，青翠拂仙坛。' },
  { title: '哭褚司马', author: '王维', poem: '妄识皆心累，浮生定死媒。\n谁言老龙吉，未免伯牛灾。\n故有求仙药，仍余遯俗杯。\n山川秋树苦，窗户夜泉哀。\n尚忆青骡去，宁知白马来。\n汉臣修史记，莫蔽褚生才。' },
  { title: '过沈居士山居哭之', author: '王维', poem: '杨朱来此哭，桑扈返于真。\n独自成千古，依然旧四邻。\n闲檐喧鸟鹊，故榻满埃尘。\n曙月孤莺啭，空山五柳春。\n野花愁对客，泉水咽迎人。\n善卷明时隐，黔娄在日贫。\n逝川嗟尔命，丘井叹吾身。\n前后徒言隔，相悲讵几晨。' },
  { title: '奉和圣制从蓬莱向兴庆阁道中留春雨中春望之作应制', author: '王维', poem: '渭水自萦秦塞曲，黄山旧遶汉宫斜。\n銮舆迥出千门柳，阁道廻看上苑花。\n云里帝城双凤阙，雨中春树万人家。\n为乘阳气行时令，不是宸游玩物华。' },
  { title: '大同殿柱产玉芝龙池上有庆云神光照殿百官共覩圣恩便赐宴乐敢书即事', author: '王维', poem: '欲笑周文歌宴镐，遥轻汉武乐横汾。\n岂知玉殿生三秀，讵有铜池出五云。\n陌上尧樽倾北斗，楼前舜乐动南薰。\n共欢天意同人意，万岁千秋奉圣君。' },
  { title: '敕赐百官樱桃', author: '王维', poem: '芙蓉阙下会千官，紫禁朱樱出上[兰]。\n才是寝园春荐后，非关御苑鸟衔残。\n归鞍竞带青丝笼，中使频倾赤玉盘。\n饱食不须愁内热，大官还有蔗浆寒。' },
  { title: '敕借岐王九成宫避暑应教', author: '王维', poem: '帝子远辞丹凤阙，天书遥借翠微宫。\n隔窗云雾生衣上，卷幔山泉入镜中。\n林下水声喧语笑，岩间树色隐房栊。\n仙家未必能胜此，何事吹笙向碧空。' },
  { title: '和贾舍人早朝大明宫之作', author: '王维', poem: '绛帻鸡人送晓筹，尚衣方进翠云裘。\n九天阊阖开宫殿，万国衣冠拜冕旒。\n日色才临仙掌动，香烟欲傍衮龙浮。\n朝罢须裁五色诏，佩声归向凤池头。' },
  { title: '和太常韦主簿五郎温汤寓目之作', author: '王维', poem: '汉主离宫接露台，秦川一半夕阳开。\n青山尽是朱旗绕，碧涧翻从玉殿来。\n新丰树里行人度，小苑城边猎骑廻。\n闻道甘泉能献赋，悬知独有子云才。' },
  { title: '苑舍人能书梵字兼达梵音皆曲尽其妙戏为之赠', author: '王维', poem: '名儒待诏满公车，才子为郎典石渠。\n莲花法藏心悬悟，贝叶经文手自书。\n楚词共许胜杨马，梵字何人辨鲁鱼。\n故旧相望在三事，愿君莫厌承明庐。' },
  { title: '重酬苑郎中', author: '王维', poem: '何幸含香奉至尊，多慙未报主人恩。\n草木尽能酬雨露，荣枯安敢问乾坤。\n仙郎有意怜同舍，丞相无私断埽门。\n扬子解嘲徒自遣，冯唐已老复何论。' },
  { title: '酬郭给事', author: '王维', poem: '洞门高阁霭余辉，桃李阴阴柳絮飞。\n禁里疎钟官舍晚，省中啼鸟吏人稀。\n晨摇玉佩趋金殿，夕奉天书拜琐闱。\n强欲从君无那老，将因卧病解朝衣。' },
  { title: '出塞', author: '王维', poem: '居延城外猎天骄，白草连山野火烧。\n暮云空碛时驱马，秋日平原好射雕。\n护羗校尉朝乘障，破虏将军夜渡辽。\n玉靶角弓珠勒马，汉家将赐霍嫖姚。' },
  { title: '既蒙宥罪旋复拜官伏感圣恩窃书鄙意兼奉简新除使君等诸公', author: '王维', poem: '忽蒙汉诏还冠冕，始觉殷王解网罗。\n日比皇明犹自暗，天齐圣寿未云多。\n花迎喜气皆知笑，鸟识欢心亦解歌。\n闻道百城新佩印，还来双阙共鸣珂。' },
  { title: '送方尊师归嵩山', author: '王维', poem: '仙官欲往九龙潭，旄节朱幡倚石龛。\n山压天中半天上，洞穿江底出江南。\n瀑布杉松常带雨，夕阳苍翠忽成岚。\n借问迎来双白鹤，已曾衡岳送苏耽。' },
  { title: '送杨少府贬郴州', author: '王维', poem: '明到衡山与洞庭，若为秋月听猿声。\n愁看北渚三湘远，恶说南风五两轻。\n青草瘴时过夏口，白头浪里出湓城。\n长沙不久留才子，贾谊何须吊屈平。' },
  { title: '过乘如禅师萧居士嵩丘兰若', author: '王维', poem: '无着天亲弟与兄，嵩丘兰若一峰晴。\n食随鸣磬巢乌下，行踏空林落叶声。\n迸水定侵香案湿，雨花应共石床平。\n深洞长松何所有，俨然天竺古先生。' },
  { title: '春日与裴迪过新昌里访吕逸人不遇', author: '王维', poem: '桃源一向绝风尘，柳市南头访隐沦。\n到门不敢题凡鸟，看竹何须问主人。\n城上青山如屋里，东家流水入西邻。\n闭户著书多岁月，种松皆老作龙鳞。' },
  { title: '酌酒与裴迪', author: '王维', poem: '酌酒与君君自宽，人情翻覆似波澜。\n白首相知犹按劒，朱门先达笑弹冠。\n草色全经细雨湿，花枝欲动春风寒。\n世事浮云何足问，不如高卧且加餐。' },
  { title: '辋川别业', author: '王维', poem: '不到东山向一年，归来才及种春田。\n雨中草色绿堪染，水上桃花红欲然。\n优娄比丘经论学，伛偻丈人乡里贤。\n披衣倒屣且相见，相欢语笑衡门前。' },
  { title: '早秋山中作', author: '王维', poem: '无才不敢累明时，思向东谿守故篱。\n岂厌尚平婚嫁早，却嫌陶令去官迟。\n草间蛩响临秋急，山里蝉声薄暮悲。\n寂寞柴门人不到，空林独与白云期。' },
  { title: '积雨辋川庄作', author: '王维', poem: '积雨空林烟火迟，蒸藜炊黍饷东菑。\n漠漠水田飞白鹭，阴阴夏木啭黄鹂。\n山中习静观朝槿，松下清斋折露葵。\n野老与人争席罢，海鸥何事更相疑。' },
  { title: '听百舌鸟', author: '王维', poem: '上兰门外草萋萋，未央宫中花里栖。\n亦有相随过御苑，不知若个向金堤。\n入春解作千般语，拂曙能先百鸟啼。\n万户千门应觉晓，建章何必听鸣鸡。' },
  { title: '息夫人', author: '王维', poem: '莫以今时宠，难忘旧日恩。\n看花满眼泪，不共楚王言。' },
  { title: '班婕妤三首 一', author: '王维', poem: '玉窗萤影度，金殿人声绝。\n秋夜守罗帷，孤灯耿不灭。' },
  { title: '班婕妤三首 二', author: '王维', poem: '宫殿生秋草，君王恩幸疎。\n那堪闻凤吹，门外度金舆。' },
  { title: '班婕妤三首 三', author: '王维', poem: '怪来妆阁闭，朝下不相迎。\n总向春园里，花间笑语声。' },
  { title: '辋川集 孟城坳', author: '王维', poem: '新家孟城口，古木余衰柳。\n来者复为谁，空悲昔人有。' },
  { title: '辋川集 华子冈', author: '王维', poem: '飞鸟去不穷，连山复秋色。\n上下华子冈，惆怅情何极。' },
  { title: '辋川集 文杏馆', author: '王维', poem: '文杏裁为梁，香茅结为宇。\n不知栋里云，去作人间雨。' },
  { title: '辋川集 斤竹岭', author: '王维', poem: '檀栾暎空曲，青翠漾涟漪。\n暗入商山路，樵人不可知。' },
  { title: '辋川集 鹿柴', author: '王维', poem: '空山不见人，但闻人语响。\n返景入深林，复照青苔上。' },
  { title: '辋川集 木兰柴', author: '王维', poem: '秋山敛余照，飞鸟逐前侣。\n彩翠时分明，夕岚无处所。' },
  { title: '辋川集 茱萸沜', author: '王维', poem: '结实红且绿，复如花更开。\n山中傥留客，置此芙蓉杯。' },
  { title: '辋川集 宫槐陌', author: '王维', poem: '仄迳荫宫槐，幽阴多绿苔。\n应门但迎埽，畏有山僧来。' },
  { title: '辋川集 临湖亭', author: '王维', poem: '轻舸迎上客，悠悠湖上来。\n当轩对尊酒，四面芙蓉开。' },
  { title: '辋川集 南垞', author: '王维', poem: '轻舟南垞去，北垞淼难即。\n隔浦望人家，遥遥不相识。' },
  { title: '辋川集 欹湖', author: '王维', poem: '吹箫凌极浦，日暮送夫君。\n湖上一回首，青山卷白云。' },
  { title: '辋川集 柳浪', author: '王维', poem: '分行接绮树，倒影入清漪。\n不学御沟上，春风伤别离。' },
  { title: '辋川集 栾家濑', author: '王维', poem: '飒飒秋雨中，浅浅石溜泻。\n跳波自相溅，白鹭惊复下。' },
  { title: '辋川集 金屑泉', author: '王维', poem: '日饮金屑泉，少当千余岁。\n翠凤翊文螭，羽节朝玉帝。' },
  { title: '辋川集 白石滩', author: '王维', poem: '清浅白石滩，绿蒲向堪把。\n家住水东西，浣纱明月下。' },
  { title: '辋川集 北垞', author: '王维', poem: '北垞湖水北，杂树暎朱阑。\n逶迤南川水，明灭青林端。' },
  { title: '辋川集 竹里馆', author: '王维', poem: '独坐幽篁里，弹琴复长啸。\n深林人不知，明月来相照。' },
  { title: '辋川集 辛夷坞', author: '王维', poem: '木末芙蓉花，山中发红萼。\n涧户寂无人，纷纷开且落。' },
  { title: '辋川集 漆园', author: '王维', poem: '古人非傲吏，自阙经世务。\n偶寄一微官，婆娑数株树。' },
  { title: '辋川集 椒园', author: '王维', poem: '桂尊迎帝子，杜若赠佳人。\n椒浆奠瑶席，欲下云中君。' },
  { title: '皇甫岳云溪杂题五首 鸟鸣涧', author: '王维', poem: '人闲桂花落，夜静春山空。\n月出惊山鸟，时鸣春涧中。' },
  { title: '皇甫岳云溪杂题五首 莲花坞', author: '王维', poem: '日日采莲去，洲长多暮归。\n弄篙莫溅水，畏湿红莲衣。' },
  { title: '皇甫岳云溪杂题五首 鸬鹚堰', author: '王维', poem: '乍向红莲没，复出清蒲飏。\n独立何䙰褷，衔鱼古查上。' },
  { title: '皇甫岳云溪杂题五首 上平田', author: '王维', poem: '朝耕上平田，暮耕上平田。\n借问问津者，宁知沮溺贤。' },
  { title: '皇甫岳云溪杂题五首 萍池', author: '王维', poem: '春池深且广，会待轻舟回。\n靡靡绿萍合，垂杨埽复开。' },
  { title: '荅裴迪辋口遇雨忆终南山之作', author: '王维', poem: '淼淼寒流广，苍苍秋雨晦。\n君问终南山，心知白云外。' },
  { title: '山中寄诸弟妹', author: '王维', poem: '山中多法侣，禅诵自为群。\n城郭遥相望，唯应见白云。' },
  { title: '闻裴秀才迪吟诗因戏赠', author: '王维', poem: '猿吟一何苦，愁朝复悲夕。\n莫作巫峡声，肠断秋江客。' },
  { title: '赠韦穆十八', author: '王维', poem: '与君青眼客，共有白云心。\n不相东山去，日令春草深。' },
  { title: '临高台送黎拾遗', author: '王维', poem: '相送临高台，川原杳何极。\n日暮飞鸟还，行人去不息。' },
  { title: '别辋川别业', author: '王维', poem: '依迟动车马，惆怅出松萝。\n忍别青山去，其如绿水何。' },
  { title: '崔九弟欲往南山马上口号与别', author: '王维', poem: '城隅一分手，几日还相见。\n山中有桂花，莫待花如霰。' },
  { title: '题友人云母障子', author: '王维', poem: '君家云母障，时向野庭开。\n自有山泉入，非因采画来。' },
  { title: '红牡丹', author: '王维', poem: '绿艳闲且静，红衣浅复深。\n花心愁欲断，春色岂知心。' },
  { title: '左掖梨花', author: '王维', poem: '闲洒阶边草，轻随箔外风。\n黄莺弄不足，衔入未央宫。' },
  { title: '菩提寺禁口号又示裴迪', author: '王维', poem: '安得舍罗网，拂衣辞世喧。\n悠然策藜杖，归向桃花源。' },
  { title: '杂诗三首 一', author: '王维', poem: '家住孟津河，门对孟津口。\n常有江南船，寄书家中否。' },
  { title: '杂诗三首 二', author: '王维', poem: '君自故乡来，应知故乡事。\n来日绮窗前，寒梅着花未。' },
  { title: '杂诗三首 三', author: '王维', poem: '已见寒梅发，复闻啼鸟声。\n心心视春草，畏向阶前生。' },
  { title: '崔兴宗写真咏', author: '王维', poem: '画君年少时，如今君已老。\n今时新识人，知君旧时好。' },
  { title: '山茱萸', author: '王维', poem: '朱实山下开，清香寒更发。\n幸与丛桂花，窗前向秋月。' },
  { title: '相思', author: '王维', poem: '红豆生南国，秋来发故枝。\n愿君多采撷，此物最相思。' },
  { title: '书事', author: '王维', poem: '轻阴阁小雨，深院昼慵开。\n坐看苍苔色，欲上人衣来。' },
  { title: '哭孟浩然', author: '王维', poem: '故人不可见，汉水日东流。\n借问襄阳老，江山空蔡州。' },
  { title: '阙题二首 一', author: '王维', poem: '荆谿白石出，天寒红叶稀。\n山路元无雨，空翠湿人衣。' },
  { title: '阙题二首 二', author: '王维', poem: '相看不忍发，惨淡暮潮平。\n语罢更携手，月明洲渚生。' },
  { title: '田园乐七首 一', author: '王维', poem: '厌见千门万户，经过北里南邻。\n官府鸣珂有底，崆峒散髪何人。' },
  { title: '田园乐七首 二', author: '王维', poem: '再见封侯万户，立谈赐璧一双。\n讵胜耦耕南亩，何如高卧东窗。' },
  { title: '田园乐七首 三', author: '王维', poem: '采菱渡头风急，策杖林西日斜。\n杏树坛边渔父，桃花源里人家。' },
  { title: '田园乐七首 四', author: '王维', poem: '萋萋春草秋绿，落落长松夏寒。\n牛羊自归村巷，童稚不识衣冠。' },
  { title: '田园乐七首 五', author: '王维', poem: '山下孤烟远村，天边独树高原。\n一瓢颜回陋巷，五柳先生对门。' },
  { title: '田园乐七首 六', author: '王维', poem: '桃红复含宿雨，柳绿更带朝烟。\n花落家童未埽，莺啼山客犹眠。' },
  { title: '田园乐七首 七', author: '王维', poem: '酌酒会临泉水，抱琴好倚长松。\n南园露葵朝折，东谷黄粱夜舂。' },
  { title: '少年行四首 一', author: '王维', poem: '新丰美酒斗十千，咸阳游侠多少年。\n相逢意气为君饮，系马高楼垂柳边。' },
  { title: '少年行四首 二', author: '王维', poem: '出身仕汉羽林郎，初随骠骑战渔阳。\n孰知不向边庭苦，纵死犹闻侠骨香。' },
  { title: '少年行四首 三', author: '王维', poem: '一身能擘两雕弧，虏骑千重只似无。\n偏坐金鞍调白羽，纷纷射杀五单于。' },
  { title: '少年行四首 四', author: '王维', poem: '汉家君臣欢宴终，高议云台论战功。\n天子临轩赐侯印，将军佩出明光宫。' },
  { title: '赠裴旻将军', author: '王维', poem: '腰间宝劒七星文，臂上雕弓百战勋。\n见说云中擒黠虏，始知天上有将军。' },
  { title: '九月九日忆山东兄弟', author: '王维', poem: '独在异乡为异客，每逢佳节倍思亲。\n遥知兄弟登高处，遍插茱萸少一人。' },
  { title: '送王尊师归蜀中拜埽', author: '王维', poem: '大罗天上神仙客，濯锦江头花柳春。\n不为碧鸡称使者，唯令白鹤报乡人。' },
  { title: '渭城曲', author: '王维', poem: '渭城朝雨浥轻尘，客舍青青杨柳春。\n劝君更尽一杯酒，西出阳关无故人。' },
  { title: '齐州送祖二', author: '王维', poem: '送君南浦泪如丝，君向东州使我悲。\n为报故人顦顇尽，如今不似洛阳时。' },
  { title: '送韦评事', author: '王维', poem: '欲逐将军取右贤，沙场走马向居延。\n遥知汉使萧关外，愁见孤城落日边。' },
  { title: '灵云池送从弟', author: '王维', poem: '金杯缓酌清歌转，画舸轻移艳舞回。\n自叹鹡鸰临水别，不同鸿鴈向池来。' },
  { title: '送沈子归江东', author: '王维', poem: '杨柳渡头行客稀，罟师荡桨向临圻。\n唯有相思似春色，江南江北送君归。' },
  { title: '与卢员外象过崔处士兴宗林亭', author: '王维', poem: '绿树重阴盖四邻，青苔日厚自无尘。\n科头箕踞长松下，白眼看他世上人。' },
  { title: '寒食汜上作', author: '王维', poem: '广武城边逢暮春，汶阳归客泪沾巾。\n落花寂寂啼山鸟，杨柳青青渡水人。' },
  { title: '戏题辋川别业', author: '王维', poem: '柳条拂地不须折，松树披云从更长。\n藤花欲暗藏猱子，柏叶初齐养麝香。' },
  { title: '戏题盘石', author: '王维', poem: '可怜盘石临泉水，复有垂杨拂酒杯。\n若道春风不解意，何因吹送落花来。' },
  { title: '寄河上段十六', author: '王维', poem: '与君相见即相亲，闻道君家在孟津。\n为见行舟试借问，客中时有洛阳人。' },
  { title: '菩提寺禁裴迪来相看说逆贼等凝碧池上作音乐供奉人等举声便一时泪下私成口号诵示裴迪', author: '王维', poem: '万户伤心生野烟，百僚何日更朝天。\n秋槐叶落空宫里，凝碧池头奏管弦。' },
  { title: '凉州赛神', author: '王维', poem: '凉州城外少行人，百尺峰头望虏尘。\n健儿击鼓吹羌笛，共赛城东越骑神。' },
  { title: '剧嘲史寰', author: '王维', poem: '清风细雨湿梅花，骤马先过碧玉家。\n正值楚王宫里至，门前初下七香车。' },
  { title: '伊州歌', author: '王维', poem: '清风明月苦相思，荡子从戎十载余。\n征人去日慇懃嘱，归鴈来时数附书。' },
  { title: '送殷四葬', author: '王维', poem: '送君返葬石楼山，松栢苍苍宾驭还。\n埋骨白云长已矣，空余流水向人间。' },
  { title: '疑梦', author: '王维', poem: '莫惊宠辱空忧喜，莫计恩讐浪苦辛。\n黄帝孔丘何处问？安知不是梦中身。' },
  { title: '古离别', author: '王缙', poem: '下阶欲离别，相对映兰丛。\n含辞未及吐，泪落兰丛中。\n高堂静秋日，罗衣飘暮风。\n谁能待明月，回首见床空。' },
  { title: '青雀歌', author: '王缙', poem: '林间青雀儿，来往翩翩绕一枝。\n莫言不解衔环报，但闻君恩今若为。' },
  { title: '同王昌龄裴迪游青龙寺昙壁上人兄院集和兄维', author: '王缙', poem: '林中空寂舍，阶下终南山。\n高卧一床上，回看六合间。\n浮云几处灭，飞鸟何时还？\n问义天人接，无心世界闲。\n谁知大隐者，兄弟自追攀。' },
  { title: '别辋川别业', author: '王缙', poem: '山月晓仍在，林风凉不绝。\n殷勤如有情，惆怅令人别。' },
  { title: '与卢员外象过崔处士兴宗林亭', author: '王缙', poem: '身名不问十年余，老大谁能更读书。\n林中独酌邻家酒，门外时闻长者车。' },
  { title: '九日作', author: '王缙', poem: '莫将边地比京都，八月严霜草已枯。\n今日登高樽酒里，不知能有菊花无。' },
  { title: '送孙秀才', author: '王缙', poem: '帝城风日好，况复建平家。\n玉枕双纹簟，金盘五色瓜。\n山中无鲁酒，松下饭胡麻。\n莫厌田家苦，归期远复赊。' },
  { title: '游悟真寺', author: '王缙', poem: '闻道黄金地，仍开白玉田。\n掷山移巨石，呪岭出飞泉。\n猛虎同三径，愁猨学四禅。\n买香然绿桂，乞火蹈红莲。\n草色摇霞上，松声泛月边。\n山河穷百二，世界接三千。\n梵宇聊凭视，王城遂渺然。\n灞陵才出树，渭水欲连天。\n远县分朱郭，孤村起白烟。\n望云思圣主，披雾忆群贤。\n薄宦惭尸素，终身拟尚玄。\n谁知草庵客，曾和柏梁篇。' },
  { title: '青龙寺昙壁上人院集', author: '裴迪', poem: '灵境信为绝，法堂出尘氛。\n自然成高致，向下看浮云。\n迤逦峰岫列，参差闾井分。\n林端远堞见，风末疎钟闻。\n吾师久禅寂，在世超人群。' },
  { title: '青雀歌', author: '裴迪', poem: '动息自适性，不曾妄与燕雀群。\n幸忝鹓鸾早相识，何时提携致青云。' },
  { title: '游感化寺昙兴上人山院', author: '裴迪', poem: '不远灞陵边，安居向十年。\n入门穿竹径，留客听山泉。\n鸟啭深林里，心闲落照前。\n浮名竟何益，从此愿栖禅。' },
  { title: '夏日过青龙寺谒操禅师', author: '裴迪', poem: '安禅一室内，左右竹亭幽。\n有法知不染，无言谁敢酬。\n鸟飞争向夕，蝉噪已先秋。\n烦暑自兹适，清凉何所求。' },
  { title: '春日与王右丞过新昌里访吕逸人不遇', author: '裴迪', poem: '恨不逢君出荷蓑，青松白屋更无他。\n陶令五男曾不有，蒋生三径枉相过。\n芙蓉曲沼春流满，薜荔成帷晚霭多。\n闻说桃源好迷客，不如高卧眄庭柯。' },
  { title: '辋川集二十首 孟城坳', author: '裴迪', poem: '结庐古城下，时登古城上。\n古城非畴昔，今人自来往。' },
  { title: '辋川集二十首 华子冈', author: '裴迪', poem: '落日松风起，还家草露晞。\n云光侵履迹，山翠拂人衣。' },
  { title: '辋川集二十首 文杏馆', author: '裴迪', poem: '迢迢文杏馆，跻攀日已屡。\n南岭与北湖，前看复回顾。' },
  { title: '辋川集二十首 斤竹岭', author: '裴迪', poem: '明流纡且直，绿筿密复深。\n一径通山路，行歌望旧岑。' },
  { title: '辋川集二十首 鹿柴', author: '裴迪', poem: '日夕见寒山，便为独往客。\n不知深林事，但有麏麚迹。' },
  { title: '辋川集二十首 木兰柴', author: '裴迪', poem: '苍苍落日时，鸟声乱谿水。\n缘谿路转深，幽兴何时已。' },
  { title: '辋川集二十首 茱萸沜', author: '裴迪', poem: '飘香乱椒桂，布叶间檀栾。\n云日虽回照，森沈犹自寒。' },
  { title: '辋川集二十首 宫槐陌', author: '裴迪', poem: '门前宫槐陌，是向欹湖道。\n秋来山雨多，落叶无人扫。' },
  { title: '辋川集二十首 临湖亭', author: '裴迪', poem: '当轩弥滉漾，孤月正裴回。\n谷口猨声发，风传入户来。' },
  { title: '辋川集二十首 南垞', author: '裴迪', poem: '孤舟信一泊，南垞湖水岸。\n落日下崦嵫，清波殊淼漫。' },
  { title: '辋川集二十首 欹湖', author: '裴迪', poem: '空阔湖水广，青荧天色同。\n舣舟一长啸，四面来清风。' },
  { title: '辋川集二十首 柳浪', author: '裴迪', poem: '映池同一色，逐吹散如丝。\n结阴既得地，何谢陶家时。' },
  { title: '辋川集二十首 栾家濑', author: '裴迪', poem: '濑声喧极浦，沿涉向南津。\n泛泛鸥凫渡，时时欲近人。' },
  { title: '辋川集二十首 金屑泉', author: '裴迪', poem: '萦渟澹不流，金碧如可拾。\n迎晨含素华，独往事朝汲。' },
  { title: '辋川集二十首 白石滩', author: '裴迪', poem: '跂石复临水，弄波情未极。\n日下川上寒，浮云澹无色。' },
  { title: '辋川集二十首 北垞', author: '裴迪', poem: '南山北垞下，结宇临欹湖。\n每欲采樵去，扁舟出菰蒲。' },
  { title: '辋川集二十首 竹里馆', author: '裴迪', poem: '来过竹里馆，日与道相亲。\n出入唯山鸟，幽深无世人。' },
  { title: '辋川集二十首 辛夷坞', author: '裴迪', poem: '绿堤春草合，王孙自留玩/。\n况有辛夷花，色与芙蓉乱。' },
  { title: '辋川集二十首 漆园', author: '裴迪', poem: '好闲早成性，果此谐宿诺。\n今日漆园游，还同庄叟乐。' },
  { title: '辋川集二十首 椒园', author: '裴迪', poem: '丹刺罥人衣，芳香留过客。\n幸堪调鼎用，愿君垂采摘。' },
  { title: '辋口遇雨忆终南山因献王维', author: '裴迪', poem: '积雨晦空曲，平沙灭浮彩。\n辋水去悠悠，南山复何在。' },
  { title: '崔九欲往南山马上口号与别', author: '裴迪', poem: '归山深浅去，须尽丘壑美。\n莫学武陵人，暂游桃源里。' },
  { title: '与卢员外象过崔处士兴宗林亭', author: '裴迪', poem: '乔柯门里自成阴，散髪窗中曾不簪。\n逍遥且喜从吾事，荣宠从来非我心。' },
  { title: '西塔寺陆羽茶泉', author: '裴迪', poem: '竟陵西塔寺，踪迹尚空虚。\n不独支公住，曾经陆羽居。\n草堂荒产蛤，茶井冷生鱼。\n一汲清泠水，高风味有余。' },
  { title: '同王右丞送瑗公南归', author: '崔兴宗', poem: '行苦神亦秀，泠然谿上松。\n铜瓶与竹杖，来自祝融峰。\n常愿入灵岳，藏经访遗踪。\n南归见长老，且为说心胸。' },
  { title: '青雀歌', author: '崔兴宗', poem: '青扈绕青林，翩翾陋体一微禽。\n不应常在藩篱下，他日凌云谁见心。' },
  { title: '和王维敕赐百官樱桃', author: '崔兴宗', poem: '未央朝谒正逶迤，天上樱桃锡此时。\n朱实初传九华殿，繁花旧杂万年枝。\n未胜晏子江南橘，莫比潘家大谷梨。\n闻道令人好颜色，神农本草自应知。' },
  { title: '留别王维', author: '崔兴宗', poem: '驻马欲分襟，清寒御沟上。\n前山景气佳，独往还惆怅。' },
  { title: '酬王维卢象见过林亭', author: '崔兴宗', poem: '穷巷空林常闭关，悠然独卧对前山。\n今朝忽枉嵇生驾，倒屣开门遥解颜。' },
  { title: '送大理正摄御史判凉州别驾', author: '苑咸', poem: '天子念西疆，咨君去不遑。\n垂银棘庭印，持斧柏台纲。\n雪下天山白，泉枯塞草黄。\n伫闻河陇外，还继海沂康。' },
  { title: '酬王维', author: '苑咸', poem: '莲花梵字本从天，华省仙郎早悟禅。\n三点成伊犹有想，一观如幻自忘筌。\n为文已变当时体，入用还推间气贤。\n应同罗汉无名欲，故作冯唐老岁年。' },
  { title: '寻西山隐者不遇', author: '丘为', poem: '绝顶一茅茨，直[上]三十里。\n扣关无僮仆，窥室唯案几。\n若非巾柴车，应是钓秋水。\n差池不相见，黾勉空仰止。\n草色新雨中，松声晚牕里。\n及兹契幽绝，自足荡心耳。\n虽无宾主意，颇得清净理。\n兴尽方下山，何必待之子。' },
  { title: '题农父庐舍', author: '丘为', poem: '东风何时至，已绿湖上山。\n湖上春已早，田家日不闲。\n沟塍流水处，耒耜平芜间。\n薄暮饭牛罢，归来还闭关。' },
  { title: '泛若耶谿', author: '丘为', poem: '结庐若耶里，左右若耶水。\n无日不钓鱼，有时向城市。\n溪中水流急，渡口水流宽。\n每得樵风便，往来殊不难。\n一川草长绿，四时那得辨。\n短褐衣妻儿，余粮及鸡犬。\n日暮鸟雀稀，稚子呼牛归。\n住处无邻里，柴门独掩扉。' },
  { title: '湖中寄王侍御', author: '丘为', poem: '日日湖水上，好登湖上楼。\n终年不向郭，过午始梳头。\n尝自爱桮酒，得无相献酬。\n小僮能脍鲤，少妾事莲舟。\n每有南浦信，仍期后月游。\n方春转摇荡，孤兴时淹留。\n骢马真傲吏，翛然无所求。\n晨趋玉阶下，心许沧江流。\n少别如昨日，何言经数秋。\n应知方外事，独往非悠悠。' },
  { title: '登润州城', author: '丘为', poem: '天末江城晚，登临客望迷。\n春潮平岛屿，残雨隔虹蜺。\n鸟与孤帆远，烟和独树低。\n乡山何处是？目断广陵西。' },
  { title: '寻庐山崔征君', author: '丘为', poem: '日高鸡犬静，门掩向寒塘。\n夜竹深茅宇，秋亭冷石床。\n住山年已远，服药寿偏长。\n虚弃浮生者，相逢益自伤。' },
  { title: '留别王维', author: '丘为', poem: '归鞍白云外，缭绕出前山。\n今日又明日，自知心不闲。\n亲劳簪组送，欲趂莺花还。\n一步一回首，迟迟向近关。' },
  { title: '竹下残雪', author: '丘为', poem: '一点消未尽，孤月在竹阴。\n晴光夜转莹，寒气晓仍深。\n还对读书牖，且关乘兴心。\n已能依此地，终不傍瑶琴。' },
  { title: '送阎校书之越', author: '丘为', poem: '南入剡中路，草云应转微。\n湖边好花照，山口细泉飞。\n此地饶古迹，世人多忘归。\n经年松雪在，永日世情稀。\n芸阁应相望，芳时不可违。' },
  { title: '省试夏日可畏', author: '丘为', poem: '赫赫温风扇，炎炎夏日徂。\n火威驰迥野，畏景烁遥途。\n势矫翔阳翰，功分造化炉。\n禁城千品烛，黄道一轮孤。\n落照频空簟，余晖卷夕梧。\n如何倦游子，中路独踟蹰。' },
  { title: '左掖梨花', author: '丘为', poem: '冷艳全欺雪，余香乍入衣。\n春风且莫定，吹向玉阶飞。' },
  { title: '渡汉江', author: '丘为', poem: '漾舟汉江上，挂席候风生。\n临泛何容与，爱此江水清。\n芦洲隐遥嶂，露日隐孤城。\n自顾疎野性，难忘鸥鸟情。\n聊复与时顾，暂欲解尘缨。\n跋涉非吾愿，虚怀浩已盈。' },
  { title: '冬至下寄舍弟时应赴入京', author: '丘为', poem: '去去知未远，依依甚初别。\n他乡至下心，昨夜堦前雪。\n终日读书仍少孤，家贫兄弟未当途。\n适远才过宿舂料，相随惟一平头奴。\n男儿出门事四海，立身世业文章在。\n莫漫忆柴扉，驷马高车朝紫微。\n江南驿使不曾断，迎前为尔非春衣。' },
  { title: '送晁补阙归日本国', author: '赵骅', poem: '西掖承休澣，东隅返故林。\n来称郯子学，归是越人吟。\n马上秋郊远，舟中曙海阴。\n知君怀魏阙，万里独摇心。' },
  { title: '古游侠呈军中诸将', author: '崔颢', poem: '少年负胆气，好勇复知机。\n仗剑出门去，孤城逢合围。\n杀人辽水上，走马渔阳归。\n错落金锁甲，蒙茸貂鼠衣。\n还家行且猎，弓矢速如飞。\n地迥鹰犬疾，草深狐兔肥。\n腰间带两绶，转盼生光辉。\n顾谓今日战，何如随建威。' },
  { title: '赠轻车', author: '崔颢', poem: '悠悠远行归，经春涉长道。\n幽冀桑始青，洛阳蚕欲老。\n忆昨戎马地，别时心草草。\n烽火从北来，边城闭常早。\n平生少相遇，未得展怀抱。\n今日杯酒间，见君交情好。' },
  { title: '赠王威古', author: '崔颢', poem: '三十羽林将，出身常事边。\n春风吹浅草，猎骑何翩翩。\n插羽两相顾，鸣弓新上弦。\n射麋入深谷，饮马投荒泉。\n马上共倾酒，野中聊割鲜。\n相看未及饮，杂虏寇幽燕。\n烽火去不息，胡尘高际天。\n长驱救东北，战解城亦全。\n报国行赴难，古来皆共然。' },
  { title: '游天竺寺', author: '崔颢', poem: '晨登天竺山，山殿朝阳晓。\n厓泉争喷薄，江岫相萦绕。\n直上孤顶高，平看众峰小。\n南州十二月，地暖冰雪少。\n青翠满寒山，藤萝覆冬沼。\n花龛瀑布侧，青壁石林杪。\n鸣钟集人天，施饭聚猨鸟。\n洗意归清净，澄心悟空了。\n始知世上人，万物一何扰。' },
  { title: '入若耶溪', author: '崔颢', poem: '轻舟去何疾，已到云林境。\n起坐鱼鸟间，动摇山水影。\n岩中响自答，溪里言弥静。\n事事令人幽，停桡向余景。' },
  { title: '杂诗', author: '崔颢', poem: '可怜青铜镜，挂在白玉堂。\n玉堂有美女，娇弄明月光。\n罗袖拂金鹊，彩屏点红妆。\n妆罢含情坐，春风桃李香。' },
  { title: '结定襄郡狱效陶体', author: '崔颢', poem: '我在河东时，使往定襄里。\n定襄诸小儿，争讼纷城市。\n长老莫敢言，太守不能理。\n谤书盈几案，文墨相填委。\n牵引肆中翁，追呼田家子。\n我来折此狱，五听辨疑似。\n小大必以情，未尝施鞭箠。\n是时三月暮，遍野农桑起。\n里巷鸣春鸠，田园引流水。\n此乡多杂俗，戎夏殊音旨。\n顾问边塞人，劳情曷云已。' },
  { title: '长安道', author: '崔颢', poem: '长安甲第高入云，谁家居住霍将军。\n日晚朝回拥宾从，路傍揖拜何纷纷。\n莫言炙手手可热，须臾火尽灰亦灭。\n莫言贫贱即可欺，人生富贵自有时。\n一朝天子赐眼色，世上悠悠应始知。' },
  { title: '行路难', author: '崔颢', poem: '君不见建章宫中金明枝，万万长条拂地垂。\n二月三月花如霰，九重幽深君不见。\n艳彩朝含四宝宫，香风旦入朝云殿。\n汉家宫女春未阑，爱此芳香朝暮看。\n看来看去心不忘，攀折将安镜台上。\n双双素手剪不成，两两红妆笑相向。\n建章昨夜起春风，一花飞落长信宫。\n长信丽人见花泣，忆此珍树何嗟及。\n我昔初在昭阳时，朝攀暮折登玉墀。\n只言岁岁长相对，不悟今朝遥相思。' },
  { title: '孟门行', author: '崔颢', poem: '黄雀衔黄花，翩翩傍檐隙。\n本拟报君恩，如何反弹射。\n金罍美酒满座春，平原爱才多众宾。\n满堂尽是忠义士，何意得有谗谀人。\n谀言反复那可道，能令君心不自保。\n北园新栽桃李枝，根株未固何转移。\n成阴结实君自取，若问傍人那得知。' },
  { title: '渭城少年行', author: '崔颢', poem: '洛阳三月梨花飞，秦地行人春忆归。\n扬鞭走马城南陌，朝逢驿使秦川客。\n驿使前日发章台，传道长安春早来。\n棠梨宫中燕初至，葡萄馆里花正开。\n念此使人归更早，三月便达长安道。\n长安道上春可怜，摇风荡日曲江边。\n万户楼台临渭水，五陵花柳满秦川。\n秦川寒食盛繁华，游子春来不见家。\n鬬鸡下杜尘初合，走马章台日半斜。\n章台帝城称贵里，青楼日晚歌钟起。\n贵里豪家白马骄，五陵年少不相饶。\n双双挟弹来金市，两两鸣鞭上渭桥。\n渭城桥头酒新熟，金鞍白马谁家宿。\n可怜锦瑟筝琵琶，玉壶清酒就倡家。\n小妇春来不解羞，娇歌一曲杨柳花。' },
  { title: '卢姬篇', author: '崔颢', poem: '卢姬少小魏王家，绿鬓红唇桃李花。\n魏王绮楼十二重，水晶帘箔绣芙蓉。\n白玉栏干金作柱，楼上朝朝学歌舞。\n前堂后堂罗袖人，南窗北窗花发春。\n翠幌珠帘鬬丝管，一弹一奏云欲断。\n君王日晚下朝归，鸣环佩玉生光辉。\n人生今日得娇贵，谁道卢姬身细微。' },
  { title: '江畔老人愁', author: '崔颢', poem: '江南年少十八九，乘舟欲渡青溪口。\n青溪口边一老翁，鬓眉皓白已衰朽。\n自言家代仕梁陈，垂朱拖紫三十人。\n两朝出将复入相，五世叠鼓乘朱轮。\n父兄三叶皆尚主，子女四代为妃嫔。\n南山赐田接御苑，北宫甲第连紫宸。\n直言荣华未休歇，不觉山崩海将竭。\n兵戈乱入建康城，烟火连烧未央阙。\n衣冠士子陷锋刃，良将名臣尽埋没。\n山川改易失市朝，衢路纵横填白骨。\n老人此时尚少年，脱身走得投海边。\n罢兵岁余未敢出，去乡三载方来旋。\n蓬蒿忘却五城宅，草木不识青谿田。\n虽然得归到乡土，零丁贫贱长辛苦。\n采樵屡入历阳山，刈稻常过新林浦。\n少年欲知老人岁，岂知今年一百五。\n君今少壮我已衰，我昔少年君不睹。\n人生贵贱各有时，莫见羸老相轻欺。\n感君相问为君说，说罢不觉令人悲。' },
  { title: '邯郸宫人怨', author: '崔颢', poem: '邯郸陌上三月春，暮行逢见一妇人。\n自言乡里本燕赵，少小随家西入秦。\n母兄怜爱无俦侣，五岁名为阿娇女。\n七岁丰茸好颜色，八岁黠惠能言语。\n十三兄弟教诗书，十五青楼学歌舞。\n我家青楼临道傍，纱窗绮幔暗闻香。\n日暮笙歌君驻马，春日妆梳妾断肠。\n不用城南使君壻，本求三十侍中郎。\n何知汉帝好容色，玉辇携登归建章。\n建章宫殿不知数，万户千门深且长。\n百堵涂椒接青琐，九华阁道连洞房。\n水晶帘箔云母扇，琉璃窗牖玳瑁床。\n岁岁年年奉欢宴，娇贵荣华谁不羡。\n恩情莫比陈皇后，宠爱全胜赵飞燕。\n瑶房侍寝世莫知，金屋更衣人不见。\n谁言一朝复一日，君王弃世市朝变。\n宫车出葬茂陵田，贱妾独留长信殿。\n一朝太子升至尊，宫中人事如掌翻。\n同时侍女见谗毁，后来新人莫敢言。\n兄弟印绶皆被夺，昔年赏赐不复存。\n一旦放归旧乡里，乘车垂泪还入门。\n父母愍我曾富贵，嫁与西舍金王孙。\n念此翻覆复何道，百年盛衰谁能保。\n忆昨尚如春日花，悲今已作秋时草。\n少年去去莫停鞭，人生万事由上天。\n非我今日独如此，古今歇薄皆共然。' },
  { title: '川上女', author: '崔颢', poem: '川上女，晚妆鲜。\n日落青渚试轻檝，汀长花满正回船。\n暮来浪起风转紧，自言此去横塘近。\n绿江无伴夜独行，独行心绪愁无尽。' },
  { title: '鴈门胡人歌', author: '崔颢', poem: '高山代郡东接燕，鴈门胡人家近边。\n解放胡鹰逐塞鸟，能将代马猎秋田。\n山头野火寒多烧，雨里孤峰湿作烟。\n闻道辽西无鬬战，时时醉向酒家眠。' },
  { title: '代闺人答轻薄少年', author: '崔颢', poem: '妾家近隔凤凰池，粉壁纱窗杨柳垂。\n本期汉代金吾壻，误嫁长安游侠儿。\n儿家夫壻多轻薄，借客探丸重然诺。\n平明挟弹入新丰，日晚挥鞭出长乐。\n青丝白马冶游园，能使行人驻马看。\n自矜陌上繁华盛，不念闺中花鸟阑。\n花间陌上春将晚，走马鬬鸡犹未返。\n三时出望无消息，一去那知行近远。\n桃李花开覆井栏，朱楼落日卷帘看。\n愁来欲奏相思曲，抱得秦筝不忍弹。' },
  { title: '七夕', author: '崔颢', poem: '长安城中月如练，家家此夜持针线。\n仙裙玉佩空自知，天上人间不相见。\n长信深阴夜转幽，瑶堦金阁数萤流。\n班姬此夕愁无限，河汉三更看斗牛。' },
  { title: '长门怨', author: '崔颢', poem: '君王宠初歇，弃妾长门宫。\n紫殿青苔满，高楼明月空。\n夜愁生枕席，春意罢帘栊。\n泣尽无人问，容华落镜中。' },
  { title: '王家少妇', author: '崔颢', poem: '十五嫁王昌，盈盈入画堂。\n自矜年最少，复倚壻为郎。\n舞爱前谿绿，歌怜子夜长。\n闲来鬬百草，度日不成妆。' },
  { title: '岐王席观妓', author: '崔颢', poem: '二月春来半，宫中日渐长。\n柳垂金屋煖，花发玉楼香。\n拂匣先临镜，调笙更炙簧。\n还将歌舞态，只拟奉君王。' },
  { title: '上巳', author: '崔颢', poem: '巳日帝城春，倾都祓禊晨。\n停车须傍水，奏乐要惊尘。\n弱柳障行骑，浮桥拥看人。\n犹言日尚早，更向九龙津。' },
  { title: '赠梁州张都督', author: '崔颢', poem: '闻君为汉将，虏骑罢南侵。\n出塞清沙漠，还家拜羽林。\n风霜臣节苦，岁月主恩深。\n为语西河使，知余报国心。' },
  { title: '赠卢八象', author: '崔颢', poem: '客从巴水渡，传尔溯行舟。\n是日风波霁，高堂雨半收。\n青山满蜀道，绿水向荆州。\n不作书相问，谁能慰别愁。' },
  { title: '题潼关楼', author: '崔颢', poem: '客行逢雨霁，歇马上津楼。\n山势雄三辅，关门扼九州。\n川从陕路去，河遶华阴流。\n向晚登临处，风烟万里愁。' },
  { title: '题沈隐侯八咏楼', author: '崔颢', poem: '梁日东阳守，为楼望越中。\n绿窗明月在，青史古人空。\n江静闻山狖，川长数塞鸿。\n登临白云晚，流恨此遗风。' },
  { title: '晚入汴水', author: '崔颢', poem: '昨晚南行楚，今朝北溯河。\n客愁能几日，乡路渐无多。\n晴景摇津树，春风起棹歌。\n长淮亦已尽，宁复畏潮波。' },
  { title: '发锦沙村', author: '崔颢', poem: '北上途未半，南行岁已阑。\n孤舟下建德，江水入新安。\n海近山常雨，谿深地早寒。\n行行泊不可，须及子陵滩。' },
  { title: '送单于裴都护赴西河', author: '崔颢', poem: '征马去翩翩，城秋月正圆。\n单于莫近塞，都护欲临边。\n汉驿通烟火，胡沙乏井泉。\n功成须献捷，未必去经年。' },
  { title: '黄鹤楼', author: '崔颢', poem: '昔人已乘白云去，此地空余黄鹤楼。\n黄鹤一去不复返，白云千载空悠悠。\n晴川历历汉阳树，春草萋萋鹦鹉洲。\n日暮乡关何处是，烟波江上使人愁。' },
  { title: '行经华阴', author: '崔颢', poem: '岧嶤太华俯咸京，天外三峰削不成。\n武帝祠前云欲散，仙人掌上雨初晴。\n河山北枕秦关险，驿树西连汉畤平。\n借问路傍名利客，无如此处学长生。' },
  { title: '相逢行', author: '崔颢', poem: '妾年初二八，家住洛桥头。\n玉户临驰道，朱门近御沟。\n使君何假问，夫壻大长秋。\n女弟新承宠，诸兄近拜侯。\n春生百子殿，花发五城楼。\n出入千门里，年年乐未休。' },
  { title: '辽西作', author: '崔颢', poem: '燕郊芳岁晚，残雪冻边城。\n四月青草合，辽阳春水生。\n胡人正牧马，汉将日征兵。\n露重宝刀湿，沙虚金鼓鸣。\n寒衣着已尽，春服与谁成。\n寄语洛阳使，为传边塞情。' },
  { title: '奉和许给事夜直简诸公', author: '崔颢', poem: '西掖黄枢近，东曹紫禁连。\n地因才子拜，人用省郎迁。\n夜直千门静，河明万象悬。\n建章宵漏急，阊阖晓钟传。\n宠列貂蝉位，恩深侍从年。\n九重初起草，五夜即成篇。\n顾己无官次，循涯但自怜。\n远陪兰署作，空此仰神仙。' },
  { title: '舟行入剡', author: '崔颢', poem: '鸣棹下东阳，回舟入剡乡。\n青山行不尽，绿水去何长。\n地气秋仍湿，江风晚渐凉。\n山梅犹作雨，谿橘未知霜。\n谢客文逾盛，林公未可忘。\n多惭越中好，流恨阅时芳。' },
  { title: '澄水如鉴', author: '崔颢', poem: '圣贤将立喻，上善贮情深。\n洁白依全德，澄清有片心。\n浇浮知不挠，滥浊固难侵。\n方寸悬高鉴，生涯讵陆沈。\n对泉能自诫，如镜静相临。\n廉慎传家政，流芳合古今。' },
  { title: '长干曲四首 一', author: '崔颢', poem: '君家何处住？妾住在横塘。\n停船暂借问，或恐是同乡。' },
  { title: '长干曲四首 二', author: '崔颢', poem: '家临九江水，来去九江侧。\n同是长干人，自小不相识。' },
  { title: '长干曲四首 三', author: '崔颢', poem: '下渚多风浪，莲舟渐觉稀。\n那能不相待，独自逆潮归。' },
  { title: '长干曲四首 四', author: '崔颢', poem: '三江潮水急，五湖风浪涌。\n由来花性轻，莫畏莲舟重。' },
  { title: '维扬送友还苏州', author: '崔颢', poem: '长安南下几程途，得到邗沟吊绿芜。\n渚畔鲈鱼舟上钓，羡君归老向东吴。' },
  { title: '古意二首 一', author: '祖咏', poem: '夫差日淫放，举国求妃嫔。\n自谓得王宠，代间无美人。\n碧罗象天阁，坐辇乘芳春。\n宫女数千骑，常游江水滨。\n年深玉颜老，时薄花妆新。\n拭泪下金殿，娇多不顾身。\n生前妬歌舞，死后同灰尘。\n冢墓令人哀，哀于铜雀台。' },
  { title: '古意二首 二', author: '祖咏', poem: '楚王竟何去，独自留巫山。\n偏使世人见，迢迢江汉间。\n驻舟春谿里，誓愿拜灵颜。\n梦寐覩神女，金沙鸣珮环。\n闲艳绝世姿，令人气力微。\n含笑默不语，化作朝云飞。' },
  { title: '渡淮河寄平一', author: '祖咏', poem: '天色混波涛，岸阴匝村墅。\n微微汉祖庙，隐隐江陵渚。\n云树森已重，时明郁相拒。' },
  { title: '归汝坟山庄留别卢象', author: '祖咏', poem: '淹留岁将[晏]，久废南山期。\n旧业不见弃，还山从此辞。\n沤麻入南涧，刈麦向东菑。\n对酒鸡黍熟，闭门风雪时。\n非君一延首，谁慰遥相思。' },
  { title: '夕次圃田店', author: '祖咏', poem: '前路入郑郊，尚经百余里。\n马烦时欲歇，客归程未已。\n落日桑柘阴，遥村烟火起。\n西还不遑宿，中夜渡泾水。' },
  { title: '田家即事', author: '祖咏', poem: '旧居东臯上，左右俯荒村。\n樵路前傍岭，田家遥对门。\n欢娱始披拂，惬意在郊原。\n余霁荡川雾，新秋仍昼昏。\n攀条憩林麓，引水开泉源。\n稼穑岂云倦，桑麻今正繁。\n方求静者赏，偶与潜夫论。\n鸡黍何必具，吾心知道尊。' },
  { title: '扈从御宿池', author: '祖咏', poem: '君王既巡狩，辇道入秦京。\n远树低枪垒，孤峰入幔城。\n寒疎清禁漏，夜警羽林兵。\n谁念迷方客，长怀魏阙情。' },
  { title: '赠苗发员外', author: '祖咏', poem: '宿雨朝来歇，空山天气清。\n盘云双鹤下，隔水一蝉鸣。\n古道黄花落，平芜赤烧生。\n茂陵虽有病，犹得伴君行。' },
  { title: '答王维留宿', author: '祖咏', poem: '四年不相见，相见复何为。\n握手言未毕，却令伤别离。\n升堂还驻马，酌醴便呼儿。\n语嘿自相对，安用傍人知。' },
  { title: '长乐驿留别卢象裴总', author: '祖咏', poem: '朝来已握手，宿别更伤心。\n灞水行人渡，商山驿路深。\n故情君且足，谪宦我难任。\n直道皆如此，谁能泪满襟。' },
  { title: '送刘高邮棁使入都', author: '祖咏', poem: '常闻积归思，昨夜又兼秋。\n乡路京华远，王程江水流。\n吴歌喧两岸，楚客醉孤舟。\n渐觉潮初上，凄然多暮愁。' },
  { title: '宴吴王宅', author: '祖咏', poem: '吴王承国宠，列第禁城东。\n连夜征词客，当春试舞童。\n砌分池水岸，牕度竹林风。\n更待西园月，金尊乐未终。' },
  { title: '观华岳', author: '祖咏', poem: '西入秦关口，南瞻驿路连。\n彩云生阙下，松树到祠边。\n作镇当官道，雄都俯大川。\n莲峰径上处，仿佛有神仙。' },
  { title: '泗上冯使君南楼作', author: '祖咏', poem: '井邑连淮泗，南楼向晚过。\n望滩沙鹭起，寻岸浴童歌。\n近海云偏出，兼秋雨更多。\n明晨拟回棹，乡思恨风波。' },
  { title: '苏氏别业', author: '祖咏', poem: '别业居幽处，到来生隐心。\n南山当户牖，沣水映园林。\n屋覆经冬雪，庭昏未夕阴。\n寥寥人境外，闲坐听春禽。' },
  { title: '汝坟别业', author: '祖咏', poem: '失路农为业，移家到汝坟。\n独愁常废卷，多病久离群。\n鸟雀垂窻柳，虹霓出涧云。\n山中无外事，樵唱有时闻。' },
  { title: '陆浑水亭', author: '祖咏', poem: '昼眺伊川曲，岩间霁色明。\n浅沙平有路，流水漫无声。\n浴鸟沿波聚，潜鱼触钓惊。\n更怜春岸绿，幽意满前楹。' },
  { title: '过郑曲', author: '祖咏', poem: '路向荣川谷，晴来望尽通。\n细烟生水上，圆月在舟中。\n岸势迷行客，秋声乱草虫。\n旅怀劳自慰，淅淅有凉风。' },
  { title: '宿陈留李少府揆厅', author: '祖咏', poem: '相知有叔卿，讼简夜弥清。\n旅泊倦愁卧，堂空闻曙更。\n风帘摇烛影，秋雨带虫声。\n归思那堪说，悠悠限洛城。' },
  { title: '题韩少府水亭', author: '祖咏', poem: '梅福幽栖处，佳期不忘还。\n鸟吟当户竹，花绕傍池山。\n水气侵阶冷，松阴覆座闲。\n宁知武陵趣，宛在市朝间。' },
  { title: '题远公经台', author: '祖咏', poem: '兰若无人到，真僧出复稀。\n苔侵行道席，云湿坐禅衣。\n涧鼠缘香案，山蝉噪竹扉。\n世间长不见，宁止暂忘归。' },
  { title: '中峰居喜见苗发', author: '祖咏', poem: '自得中峰住，深林亦闭关。\n经秋无客到，入夜有僧还。\n暗涧泉声小，荒冈树影闲。\n高窻不可望，星月满空山。' },
  { title: '江南旅情', author: '祖咏', poem: '楚山不可极，归路但萧条。\n海色晴看雨，江声夜听潮。\n劒留南斗近，书寄北风遥。\n为报空潭橘，无媒寄洛桥。' },
  { title: '泊扬子津', author: '祖咏', poem: '才入维扬郡，乡关此路遥。\n林藏初过雨，风退欲归潮。\n江火明沙岸，云帆碍浦桥。\n客衣今日薄，寒气近来饶。' },
  { title: '晚泊金陵水亭', author: '祖咏', poem: '江亭当废国，秋景倍萧骚。\n夕照明残垒，寒潮涨古濠。\n就田看鹤大，隔水见僧高。\n无限前朝事，醒吟易觉劳。' },
  { title: '七夕', author: '祖咏', poem: '闺女求天女，更阑意未阑。\n玉庭开粉席，罗袖捧金盘。\n向月穿针易，临风整线难。\n不知谁得巧，明旦试相看。' },
  { title: '望蓟门', author: '祖咏', poem: '燕台一望客心惊，箫鼓喧喧汉将营。\n万里寒光生积雪，三边曙色动危旌。\n沙场烽火连胡月，海畔云山拥蓟城。\n少小虽非投笔吏，论功还欲请长缨。' },
  { title: '家园夜坐寄郭微', author: '祖咏', poem: '前堦微雨歇，开户散窥林。\n月出夜方浅，水凉池更深。\n余风生竹树，清露薄衣襟。\n遇物遂遥叹，怀人滋远心。\n依稀成梦想，影响绝徽音。\n谁念穷居者，明时嗟陆沈。' },
  { title: '酬汴州李别驾赠', author: '祖咏', poem: '秋风多客思，行旅厌艰辛。\n自洛非才子，游梁得主人。\n文章参末议，荣贱岂同伦。\n叹逝逢三演，怀贤忆四真。\n情因恩旧好，契托死生亲。\n所媿能投赠，清言益润身。' },
  { title: '清明宴司勋刘郎中别业', author: '祖咏', poem: '田家复近臣，行乐不违亲。\n霁日园林好，清明烟火新。\n以文长会友，唯德自成邻。\n池照窻阴晚，杯香药味春。\n檐前花覆地，竹外鸟窥人。\n何必桃源里，深居作隐沦。' },
  { title: '汝坟秋同仙州王长史翰闻百舌鸟', author: '祖咏', poem: '秋天闻好鸟，惊起出帘帷。\n却念殊方月，能鸣已后时。\n迁乔诚可早，出谷此何迟。\n顾影慙无对，怀群空所思。\n凄凉岁欲晚，萧索燕将辞。\n留听未终曲，弥令心独悲。\n高飞凭力致，巧啭任天姿。\n返覆知而静，间关断若遗。\n花繁上林路，霜落汝川湄。\n且长凌风翮，乘春自有期。' },
  { title: '送丘为下第', author: '祖咏', poem: '沧江一身客，献赋空十年。\n明主岂能好，今人谁举贤。\n国门税征驾，旅食谋归旋。\n皦日媚春水，绿苹香客船。\n无媒既不达，予亦思归田。' },
  { title: '寄王长史', author: '祖咏', poem: '汝颍俱宿好，往来托层峦。\n终日何寂寞，绕篱生蕙兰。' },
  { title: '别怨', author: '祖咏', poem: '送别到中流，秋船倚渡头。\n相看尚不远，未可即回舟。' },
  { title: '终南望余雪', author: '祖咏', poem: '终南阴岭秀，积雪浮云端。\n林表明霁色，城中增暮寒。' },
  { title: '湘夫人', author: '李颀', poem: '九嶷日已暮，三湘云复愁。\n窅霭罗袂色，潺湲江水流。\n佳期来北渚，捐佩在芳洲。' },
  { title: '塞下曲', author: '李颀', poem: '黄云雁门郡，日暮风沙里。\n千骑黑貂裘，皆称羽林子。\n金笳吹朔雪，铁马嘶云水。\n帐下饮蒲萄，平生寸心是。' },
  { title: '古塞下曲', author: '李颀', poem: '行人朝走马，直指蓟城傍。\n蓟城通漠北，万里别吾乡。\n海上千烽火，沙中百战场。\n军书发上郡，春色度河阳。\n褭褭汉宫柳，青青胡地桑。\n琵琶出塞曲，横笛断君肠。' },
  { title: '渔父歌', author: '李颀', poem: '白首何老人，蓑笠蔽其身。\n避世长不仕，钓鱼清江滨。\n浦沙明濯足，山月静垂纶。\n寓宿湍与濑，行歌秋复春。\n持竿湘岸竹，𦶟火芦洲薪。\n绿水饭香稻，青荷包紫鳞。\n于中还自乐，所欲全吾真。\n而笑独醒者，临流多苦辛。' },
  { title: '东京寄万楚', author: '李颀', poem: '濩落久无用，隐身甘采薇。\n仍闻薄宦者，还事田家衣。\n颍水日夜流，故人相见稀。\n春山不可望，黄鸟东南飞。\n濯足岂长往，一樽聊可依。\n了然潭上月，适我胷中机。\n在昔同门友，如今出处非。\n优游白虎殿，偃息青琐闱。\n且有荐君表，当看携手归。\n寄书不待面，兰茝空芳菲。' },
  { title: '寄焦炼师', author: '李颀', poem: '得道凡百岁，烧丹惟一身。\n悠悠孤峰顶，日见三花春。\n白鹤翠微里，黄精幽涧滨。\n始知世上客，不及山中人。\n仙境若在梦，朝云如可亲。\n何由覩颜色，挥手谢风尘。' },
  { title: '望鸣臯山白云寄洛阳卢主簿', author: '李颀', poem: '饮马伊水中，白云鸣臯上。\n氛氲山绝顶，行子时一望。\n照日龙虎姿，攒空冰雪状。\n嵡嵸殊未已，崚嶒忽相向。\n皎皎横绿林，霏霏澹青嶂。\n远映村更失，孤高鹤来傍。\n胜气欣有逢，仙游且难访。\n故人吏京剧，每事多闲放。\n室画峨眉峰，心格洞庭浪。\n惜哉清兴里，不见予所尚。' },
  { title: '寄万齐融', author: '李颀', poem: '名高不择仕，委世随虚舟。\n小邑常叹屈，故乡行可游。\n青枫半村户，香稻盈田畴。\n为政日清净，何人同海鸥。\n摇巾北林夕，把菊东山秋。\n对酒池云满，向家湖水流。\n岸阴止鸣鹄，山色映潜虬。\n靡靡俗中理，萧萧川上幽。\n昔年至吴郡，常隐临江楼。\n我有一书札，因之芳杜洲。' },
  { title: '赠张旭', author: '李颀', poem: '张公性嗜酒，豁达无所营。\n皓首穷草隶，时称太湖精。\n露顶据胡床，长呌三五声。\n兴来洒素壁，挥笔如流星。\n下舍风萧条，寒草满户庭。\n问家何所有，生事如浮萍。\n左手持蟹螯，右手执丹经。\n瞪目视霄汉，不知醉与醒。\n诸宾且方坐，旭日临东城。\n荷叶裹江鱼，白瓯贮香秔。\n微禄心不屑，放神于八纮。\n时人不识者，即是安期生。' },
  { title: '赠苏明府', author: '李颀', poem: '苏君年几许，状貌如玉童。\n采药傍梁宋，共言随日翁。\n常辞小县宰，一往东山东。\n不复有家室，悠悠人世中。\n子孙皆老死，相识悲转蓬。\n发白还更黑，身轻行若风。\n泛然无所系，心与孤云同。\n出入虽一杖，安然知始终。\n愿闻素女事，去采山花丛。\n诱我为弟子，逍遥寻葛洪。' },
  { title: '登首阳山谒夷齐庙', author: '李颀', poem: '古人已不见，乔木竟谁过。\n寂寞首阳山，白云空复多。\n苍苔归地骨，皓首采薇歌。\n毕命无怨色，成仁其若何。\n我来入遗庙，时候微清和。\n落日吊山鬼，回风吹女萝。\n石崖向西豁，引领望黄河。\n千里一飞鸟，孤光东逝波。\n驱车层城路，惆怅此岩阿。' },
  { title: '谒张果先生', author: '李颀', poem: '先生谷神者，甲子焉能计。\n自说轩辕师，于今几千岁。\n寓游城郭里，浪迹希夷际。\n应物云无心，逢时舟不系。\n餐霞断火粒，野服兼荷制。\n白雪净肌肤，青松养身世。\n韬精殊豹隐，炼骨同蝉蜕。\n忽去不知谁，偶来宁有契。\n二仪齐寿考，六合随休憩。\n彭耼犹婴孩，松期且微细。\n尝闻穆天子，更忆汉皇帝。\n亲屈万乘尊，将穷四海裔。\n车徒徧草木，锦帛招谈说。\n八骏空往还，三山转亏蔽。\n吾君感至德，玄老欣来诣。\n受箓金殿开，清斋玉堂闭。\n笙歌迎拜首，羽帐崇严衞。\n禁柳垂香𬬻，宫花拂仙袂。\n祈年宝祚广，致福苍生惠。\n何必待龙髯，鼎成方取济。' },
  { title: '光上座廊下众山五韵', author: '李颀', poem: '名岳在庑下，吾师居一床。\n每闻楞伽经，只对清翠光。\n百谷聚雪色，莓苔侵屋梁。\n气盘古壁转，势引幽堦长。\n愿游薜叶下，日见金𬬻香。' },
  { title: '九月九日刘十八东堂集', author: '李颀', poem: '风俗尚九日，此情安可忘。\n菊花辟恶酒，汤饼茱萸香。\n云入授衣假，风吹闲宇凉。\n主人尽欢意，林景昼微茫。\n清切晚砧动，东西归鸟行。\n淹留怅为别，日醉秋云光。' },
  { title: '宋少府东谿泛舟', author: '李颀', poem: '登岸还入舟，水禽惊笑语。\n晚叶低众色，湿云带残暑。\n落日乘醉归，溪流复几许。' },
  { title: '与诸公游济渎泛舟', author: '李颀', poem: '济水出王屋，其源来不穷。\n洑泉数眼沸，平地流清通。\n皇帝崇祀典，诏书视三公。\n分官祷灵庙，奠璧沈河宫。\n神应每如荅，松篁气葱茏。\n苍螭送飞雨，赤鲤喷回风。\n洒酒布瑶席，吹箫下玉童。\n玄冥掌阴事，祝史告年丰。\n百谷趋潭底，三光悬镜中。\n浅深露沙石，苹藻生虚空。\n晚景临泛美，亭臯轻霭红。\n晴山傍舟楫，白鹭惊丝桐。\n我本家颍北，开门见维嵩。\n焉知松峰外，又有天坛东。\n左手正接䍠，浩歌眄青穹。\n夷犹傲清吏，偃仰狎渔翁。\n对此川上闲，非君谁与同。\n霜凝远村渚，月静蒹葭丛。\n兹境信难遇，为欢殊未终。\n淹留怅言别，烟屿夕微蒙。' },
  { title: '送綦毋三谒房给事', author: '李颀', poem: '夫子大名下，家无钟石储。\n惜哉湖海上，曾校蓬莱书。\n外物非本意，此生空澹如。\n所思但乘兴，远适唯单车。\n高道时坎坷，故交愿吹嘘。\n徒言青琐闼，不爱承明庐。\n百里人户满，片言争讼疎。\n手持莲花经，目送飞鸟余。\n晚景南路别，炎云中伏初。\n此行傥不遂，归食芦洲鱼。' },
  { title: '送刘四', author: '李颀', poem: '爱君少岐嶷，高视白云乡。\n九岁能属文，谒帝游明光。\n奉诏赤墀下，拜为童子郎。\n尔来屡迁易，三度尉洛阳。\n洛阳十二门，官寺郁相望。\n青槐罗四面，渌水贯中央。\n听讼破秋毫，应物利干将。\n辞满如脱屣，立言无否臧。\n岁暮风雪暗，秦中川路长。\n行人饮腊酒，立马带晨霜。\n生事岂须问，故园寒草荒。\n从今署右职，莫笑在农桑。' },
  { title: '送裴腾', author: '李颀', poem: '养德为众许，森然此丈夫。\n放情白云外，爽气连虬须。\n衡镜合知子，公心谁谓无。\n还令不得意，单马遂长驱。\n桑野蚕忙时，怜君久踟蹰。\n新晴荷卷叶，孟夏雉将雏。\n令弟为县尹，高城汾水隅。\n相将簿领闲，倚望恒峰孤。\n香露团百草，紫梨分万株。\n归来授衣假，莫使故园芜。' },
  { title: '送司农崔丞', author: '李颀', poem: '黄鹂鸣官寺，香草色未已。\n同时皆省郎，而我独留此。\n维监太仓粟，常对府小史。\n清阴罗广庭，政事如流水。\n奉使往长安，今承朝野欢。\n宰臣应记识，明主必迁官。\n塞外貔将虎，池中鸳与鸾。\n词人洞箫赋，公子鵕䴊冠。\n邑里春方晚，昆明花欲阑。\n行行取高位，当使路傍看。' },
  { title: '送崔侍御赴京', author: '李颀', poem: '绿槐荫长路，骏马垂青丝。\n柱史谒承明，翩翩将有期。\n千官大朝日，奏事临赤墀。\n肃肃仪仗里，风生鹰隼姿。\n一从登甲科，三拜皆宪司。\n按俗又如此，为郎何太迟。\n送君暮春月，花落城南陲。\n惜别醉芳草，前山劳梦思。' },
  { title: '春送从叔游襄阳', author: '李颀', poem: '言别恨非一，弃置我宗英。\n向用五经笥，今为千里行。\n裹粮顾庭草，羸马诘朝鸣。\n斗酒对寒食，杂花宜晚晴。\n春衣采洲路，夜饮南阳城。\n客梦岘山晓，渔歌江水清。\n楚俗少相知，远游难称情。\n同人应馆谷，刺史在郊迎。\n只合侍丹扆，翻令辞上京。\n时方春欲暮，叹息向流莺。' },
  { title: '赠别高三十五', author: '李颀', poem: '五十无产业，心轻百万资。\n屠酤亦与群，不问君是谁。\n饮酒或垂钓，狂歌兼咏诗。\n焉知汉高士，莫识越鸱夷。\n寄迹栖霞山，蓬头睢水湄。\n忽然辟命下，众谓趋丹墀。\n沐浴着赐衣，西来马行迟。\n能令相府重，且有函关期。\n僶俛从寸禄，旧游梁宋时。\n皤皤邑中叟，相候鬓如丝。\n官舍柳林静，河梁杏叶滋。\n摘芳云景[晏]，把手秋蝉悲。\n小县情未惬，折腰君莫辞。\n吾观主人意，不久召京师。' },
  { title: '崔五宅送刘跂入京', author: '李颀', poem: '行人惜寸景，系马暂留欢。\n昨日辞小沛，何时到长安。\n乡中饮酒礼，客里行路难。\n清洛云鸿度，故关风日寒。\n维将道可乐，不念身无官。\n生事东山远，田园芳岁阑。\n东归余谢病，西去子加餐。\n宋伯非徒尔，明时正可干。\n躬耕守贫贱，失计在林端。\n宿昔奉颜色，慙无双玉盘。' },
  { title: '送马录事赴永阳', author: '李颀', poem: '子为郡从事，主印清淮边。\n谈笑一州里，从容群吏先。\n手持三尺令，遣决如流泉。\n太守既相许，诸公谁不然。\n孤城连海树，万室带山烟。\n春日谿湖净，芳洲葭菼连。\n炊秔蟹螯熟，下筯鲈鱼鲜。\n野鹤宿檐际，楚云飞面前。\n听歌送离曲，且驻木兰船。\n赠尔八行字，当闻佳政传。' },
  { title: '临别送张𬤇入蜀', author: '李颀', poem: '出门便为客，惘然悲徒御。\n四海维一身，茫茫欲何去？\n经山复历水，百恨将千虑。\n劒阁望梁州，是君断肠处。\n孤云伤客心，落日感君深。\n梦里蒹葭渚，天边橘柚林。\n蜀江流不测，蜀路险难寻。\n木有相思号，猿多愁苦音。\n莫向愚山隐，愚山地非近。\n故乡可归来，眼见芳菲尽。' },
  { title: '送王昌龄', author: '李颀', poem: '漕水东去远，送君多暮情。\n淹留野寺出，向背孤山明。\n前望数千里，中无蒲稗生。\n夕阳满舟檝，但爱微波清。\n举酒林月上，解衣沙鸟鸣。\n夜来莲花界，梦里金陵城。\n叹息此离别，悠悠江海行。' },
  { title: '留别王卢二拾遗', author: '李颀', poem: '此别不可道，此心当报谁。\n春风灞水上，饮马桃花时。\n误作好文士，只令游宦迟。\n留书下朝客，我有故山期。' },
  { title: '赠别穆元林', author: '李颀', poem: '贰职久辞满，藏名三十年。\n丹墀策频献，白首官不迁。\n明主日征士，吏曹何忽贤。\n空怀济世业，欲棹沧浪船。\n举酒洛门外，送君春海边。\n彼乡有令弟，小邑试烹鲜。\n转浦云壑媚，涉江花岛连。\n绿芳暗楚水，白鸟飞吴烟。\n赠赆亦奚贵，流乱期早旋。\n金闺会通籍，生事岂徒然。' },
  { title: '不调归东川别业', author: '李颀', poem: '寸禄言可取，托身将见遗。\n慙无匹夫志，悔与名山辞。\n绂冕谢知己，林园多后时。\n葛巾方濯足，蔬食但垂帷。\n十室对河岸，渔樵祗在兹。\n青郊香杜若，白水映茅茨。\n昼景彻云树，夕阴澄古逵。\n渚花独开晚，田鹤静飞迟。\n且复乐生事，前贤为我师。\n清歌聊鼓楫，永日望佳期。' },
  { title: '晚归东园', author: '李颀', poem: '出郭喜见山，东行亦未远。\n夕阳带归路，霭霭秋稼晚。\n樵者乘霁归，野夫及星饭。\n请谢朱轮客，垂竿不复返。' },
  { title: '龙门西峰晓望刘十八不至', author: '李颀', poem: '春台临永路，跂足望行子。\n片片云触峰，离离鸟渡水。\n丛林远山上，霁景杂花里。\n不见携手人，下山采绿芷。' },
  { title: '裴尹东溪别业', author: '李颀', poem: '公才廊庙器，官亚河南守。\n别墅临都门，惊湍激前后。\n旧交与群从，十日一携手。\n幅巾望寒山，长啸对高柳。\n清欢信可尚，散吏亦何有。\n岸雪清城阴，水光远林首。\n闲观野人筏，或饮川上酒。\n幽云澹徘徊，白鹭飞左右。\n庭竹垂卧内，村烟隔南阜。\n始知物外情，簪绂同刍狗。' },
  { title: '无尽上人东林禅居', author: '李颀', poem: '草堂每多暇，时谒山僧门。\n所对但群木，终朝无一言。\n我心爱流水，此地临清源。\n含吐山上日，蔽亏松外村。\n孤峰隔身世，百衲老寒暄。\n禅户积朝雪，花龛来暮猿。\n顾余守耕稼，十载隐田园。\n萝筿慰舂汲，岩潭恣讨论。\n泄云岂知限，至道莫探元。\n且愿启关锁，于焉微尚存。' },
  { title: '题綦毋校书别业', author: '李颀', poem: '常称挂冠吏，昨日归沧洲。\n行客暮帆远，主人庭树秋。\n岂伊问天命，但欲为山游。\n万物我何有，白云空自幽。\n萧条江海上，日夕见丹丘。\n生事非渔钓，赏心随去留。\n惜哉旷微月，欲济无轻舟。\n倏忽令人老，相思河水流。' },
  { title: '题卢道士房', author: '李颀', poem: '秋砧响落木，共坐茅君家。\n惟见两童子，林前汲井华。\n空坛静白日，神鼎飞丹砂。\n麈尾拂霜草，金铃摇霁霞。\n上章人世隔，看[弈]桐阴斜。\n稽首问仙要，黄精堪饵花。' },
  { title: '题神力师院', author: '李颀', poem: '大师神杰貌，五岳森禅房。\n坚持日月珠，豁见沧江长。\n随病拔诸苦，致身如法王。\n阶庭药草徧，饭食天花香。\n树色向高阁，昼阴横半墙。\n每闻第一义，心净琉璃光。' },
  { title: '题僧房双桐', author: '李颀', poem: '青桐双拂日，傍带凌霄花。\n绿叶传僧磬，清阴润井华。\n谁能事音律，焦尾蔡邕家。' },
  { title: '粲公院各赋一物得初荷', author: '李颀', poem: '微风和众草，大叶长圆阴。\n晴露珠共合，夕阳花映深。\n从来不着水，清净本因心。' },
  { title: '李兵曹壁画山水各赋得桂水帆', author: '李颀', poem: '片帆浮桂水，落日天涯时。\n飞鸟看共度，闲云相与迟。\n长波无晓夜，泛泛欲何之。' },
  { title: '题合欢', author: '李颀', poem: '开花复卷叶，艳眼又惊心。\n蝶遶西枝露，风披东干阴。\n黄衫漂细蘂，时拂女郎砧。' },
  { title: '古从军行', author: '李颀', poem: '白日登山望烽火，黄昏饮马傍交河。\n行人刁斗风沙暗，公主琵琶幽怨多。\n野云万里无城郭，雨雪纷纷连大漠。\n胡鴈哀鸣夜夜飞，胡儿眼泪双双落。\n闻道玉门犹被遮，应将性命逐轻车。\n年年战骨埋荒外，空见蒲桃入汉家。' },
  { title: '行路难', author: '李颀', poem: '汉家名臣杨德祖，四代五公享茅土。\n父子兄弟绾银黄，跃马鸣珂朝建章。\n火浣单衣绣方领，茱萸锦带玉盘囊。\n宾客填街复满座，片言出口生辉光。\n世人逐势争奔走，沥胆堕肝惟恐后。\n当时一顾登青云，自谓生死长随君。\n一朝谢病还乡里，穷巷苍苔绝知己。\n秋风落叶闭重门，昨日论交竟谁是。\n薄俗嗟嗟难重陈，深山麋鹿可为邻。\n鲁连所以蹈东海，古往今来称达人。' },
  { title: '缓歌行', author: '李颀', poem: '小来托身攀贵游，倾财破产无所忧。\n暮拟经过石渠署，朝将出入铜龙楼。\n结交杜陵轻薄子，谓言可生复可死。\n一沈一浮会有时，弃我翻然如脱屣。\n男儿立身须自强，十年闭户颍水阳。\n业就功成见明主，击钟鼎食坐华堂。\n二八蛾眉梳堕马，美酒清歌曲房下。\n文昌宫中赐锦衣，长安陌上退朝归。\n五陵宾从莫敢视，三省官僚揖者稀。\n早知今日读书是，悔作从前任侠非。' },
  { title: '琴歌', author: '李颀', poem: '主人有酒欢今夕，请奏鸣琴广陵客。\n月照城头乌半飞，霜凄万树风入衣。\n铜𬬻华烛烛增辉，初弹渌水后楚妃。\n一声已动物皆静，四座无言星欲稀。\n清淮奉使千余里，敢告云山从此始。' },
  { title: '放歌行荅从弟墨卿', author: '李颀', poem: '小来好文耻学武，世上功名不解取。\n虽沾寸禄已后时，徒欲出身事明主。\n柏梁赋诗不及宴，长楸走马谁相数。\n歛迹俛眉心自甘，高歌击节声半苦。\n由是蹉跎一老夫，养鸡牧豕东城隅。\n空歌汉代萧相国，肯事霍家冯子都。\n徒尔当年声籍籍，滥作词林两京客。\n故人斗酒安陵桥，黄鸟春风洛阳陌。\n吾家令弟才不羁，五言破的人共推。\n兴来逸气若涛涌，千里长江归海时。\n别离短景何萧索，佳句相思能间作。\n举头遥望鲁阳山，木叶纷纷向人落。' },
  { title: '王母歌', author: '李颀', poem: '武皇斋戒承华殿，端拱须臾王母见。\n霓旌照耀麒麟车，羽盖淋漓孔雀扇。\n手指交梨遣帝食，可以长生临宇县。\n头上复戴九星冠，总领玉童坐南面。\n欲闻要言今告汝，帝乃焚香请此语。\n若能炼魄去三尸，后当见我天皇所。\n顾谓侍女董双成，酒阑可奏云和笙。\n红霞白日俨不动，七龙五凤纷相迎。\n惜哉志骄神不悦，叹息马蹄与车辙。\n复道歌钟杳将暮，深宫桃李花成雪。\n为看青玉五枝灯，蟠螭吐火光欲绝。' },
  { title: '鲛人歌', author: '李颀', poem: '鲛人潜织水底居，侧身上下随游鱼。\n轻绡文彩不可识，夜夜澄波连月色。\n有时寄宿来城市，海岛青冥无极已。\n泣珠报恩君莫辞，今年相见明年期。\n始知万族无不有，百尺深泉架户牖。\n鸟没空山谁复望，一望云涛堪白首。' },
  { title: '夏宴张兵曹东堂', author: '李颀', poem: '重林华屋堪避暑，况乃烹鲜会佳客。\n主人三十朝大夫，满座森然见矛戟。\n北窓卧簟连心花，竹里蝉鸣西日斜。\n羽扇摇风却珠汗，玉盆贮水割甘瓜。\n云峰峨峨自冰雪，坐对芳樽不知热。\n醉来但挂葛巾眠，莫道明朝有离别。' },
  { title: '同张员外𬤇詶荅之作', author: '李颀', poem: '洛中高士日沈冥，手自灌园方带经。\n王湛床头见周易，长康传里好丹青。\n鹖冠葛屦无名位，博[弈]赋诗聊遣意。\n清言只到衞家儿，用笔能夸钟太尉。\n东篱二月种兰荪，穷巷人稀鸟雀喧。\n闻道郎官问生事，肯令鬓发老柴门。' },
  { title: '欲之新乡荅崔颢綦毋潜', author: '李颀', poem: '数年作吏家屡空，谁道黑头成老翁。\n男儿在世无产业，行子出门如转蓬。\n吾属交欢此何夕，南家捣衣动归客。\n铜𬬻将炙相欢饮，星宿纵横露华白。\n寒风卷叶度滹沱，飞雪布地悲峨峨。\n孤城日落见栖鸟，马上时闻渔者歌。\n明朝东路把君手，腊日辞君期岁首。\n自知寂寞无去思，敢望县人致牛酒。' },
  { title: '荅高三十五留别便呈于十一', author: '李颀', poem: '累荐贤良皆不就，家近陈留访耆旧。\n韩康虽复在人间，王霸终思隐岩窦。\n清冷池水灌园蔬，万物沧江心澹如。\n妻子欢同五株柳，云山老对一床书。\n昨日公车见三事，明君赐衣遣为吏。\n怀章不使郡邸惊，待诏初从阙庭至。\n散诞由来自不羁，低头授职尔何为。\n故园壁挂乌纱帽，官舍尘生白接䍠。\n寄书寂寂於陵子，蓬蒿没身胡不仕。\n藜羹被褐环堵中，岁晚将贻故人耻。' },
  { title: '送康洽入京进乐府歌', author: '李颀', poem: '识子十年何不遇，只爱欢游两京路。\n朝吟左氏娇女篇，夜诵相如美人赋。\n长安春物旧相宜，小苑蒲萄花满枝。\n柳色偏浓九华殿，莺声醉杀五陵儿。\n曳裾此日从何所，中贵由来尽相许。\n白裌春衫仙吏赠，乌皮隐几台郎与。\n新诗乐府唱堪愁，御妓应传𫛛鹊楼。\n西上虽因长公主，终须一见曲陵侯。' },
  { title: '送刘十', author: '李颀', poem: '三十不官亦不娶，时人焉识道高下。\n房中唯有老氏经，枥上空余少游马。\n往来嵩华与函秦，放歌一曲前山春。\n西林独鹤引闲步，南涧飞泉清角巾。\n前年上书不得意，归卧东窓兀然醉。\n诸兄相继掌青史，第五之名齐骠骑。\n烹葵摘果告我行，落日夏云纵复横。\n闻道谢安掩口笑，知君不免为苍生。' },
  { title: '送王道士还山', author: '李颀', poem: '嵩阳道士餐柏实，居处三花对石室。\n心穷伏火阳精丹，口诵淮王万毕术。\n自言神诀不可求，我师闻之玄圃游。\n出入彤庭佩金印，承恩赫赫如王侯。\n双峰树下曾受业，应传肘后长生法。\n吾闻仙地多后身，安知不是具茨人。\n玉膏清泠瀑泉水，白云谿中日方此。\n后今不见数十年，鬓发颜容只如是。\n先生舍我欲何归，竹杖黄裳登翠微。\n当有岩前白蝙蝠，迎君日暮双来飞。' },
  { title: '别梁锽', author: '李颀', poem: '梁生倜傥心不羁，途穷气盖长安儿。\n回头转眄似雕鹗，有志飞鸣人岂知。\n虽云四十无禄位，曾与大军掌书记。\n抗辞请刃诛部曲，作色论兵犯二帅。\n一言不合龙頟侯，击劒拂衣从此弃。\n朝朝饮酒黄公垆，脱帽露顶争叫呼。\n庭中犊鼻昔尝挂，怀里琅玕今在无。\n时人见子多落魄，共笑狂歌非远图。\n忽然遣跃紫骝马，还是昂藏一丈夫。\n洛阳城头晓霜白，层冰峨峨满川泽。\n但闻行路吟新诗，不叹举家无担石。\n莫言贫贱长可欺，覆篑成山当有时。\n莫言富归长可托，木槿朝看暮还落。\n不见古时塞上翁，倚伏由来任天作。\n去去沧波勿复陈，五湖三江愁杀人。' },
  { title: '送从弟游江淮兼谒鄱阳刘太守', author: '李颀', poem: '都门柳色朝朝新，念尔今为江上人。\n穆陵关带清风远，彭蠡湖连芳草春。\n泊舟借问西林寺，晓听猿声在山翠。\n浔阳北望鸿鴈回，湓水东流客心醉。\n须知圣代举贤良，不使遗才滞一方。\n应见鄱阳虎符守，思归共指白云乡。' },
  { title: '双笋歌送李回兼呈刘四', author: '李颀', poem: '并抽新笋色渐绿，迥出空林双碧玉。\n春风解箨雨润根，一枝半叶清露痕。\n为君当面拂云日，孤生四远何足论。\n再三抱此怅为别，嵩洛故人与之说。' },
  { title: '送刘四赴夏县', author: '李颀', poem: '九霄特立红鸾姿，万仞孤生玉树枝。\n刘侯致身能若此，天骨自然多叹美。\n声名播扬二十年，足下长途几千里。\n举世皆亲丞相阁，我心独爱伊川水。\n脱略势利犹埃尘，啸傲时人而已矣。\n新诗数岁即文雄，上书昔召蓬莱宫。\n明主拜官麒麟阁，光车骏马看玉童。\n高人往来庐山远，隐士往来张长公。\n扶南甘蔗甜如蜜，杂以荔枝龙州橘。\n赤县繁词满剧曹，白云孤峰晖永日。\n朝持手板望飞鸟，暮诵楞伽对空室。\n一朝出宰汾河间，明府下车人吏闲。\n端坐讼庭更无事，开门咫尺巫咸山。\n男耕女织蒙惠化，麦熟雉鸣长秋稼。\n明年九府议功时，五辟三征当在兹。\n闻道桐乡有遗老，邑中还欲置生祠。' },
  { title: '少室雪晴送王宁', author: '李颀', poem: '少室众峰几峰别，一峰晴见一峰雪。\n隔城半山连青松，素色峨峨千万重。\n过景斜临不可道，白云欲尽难为容。\n行人与我玩幽境，北风切切吹衣冷。\n惜别浮桥驻马时，举头试望南山岭。' },
  { title: '送陈章甫', author: '李颀', poem: '四月南风大麦黄，枣花未落桐阴长。\n青山朝别暮还见，嘶马出门思旧乡。\n陈侯立身何坦荡，虬须虎眉仍大颡。\n腹中贮书一万卷，不肯低头在草莽。\n东门酤酒饮我曹，心轻万事皆鸿毛。\n醉卧不知白日暮，有时空望孤云高。\n长河浪头连天黑，津口停舟渡不得。\n郑国游人未及家，洛阳行子空叹息。\n闻道故林相识多，罢官昨日今如何。' },
  { title: '听安万善吹觱篥歌', author: '李颀', poem: '南山截竹为觱篥，此乐本自龟兹出。\n流传汉地曲转奇，凉州胡人为我吹。\n傍邻闻者多叹息，远客思乡皆泪垂。\n世人解听不解赏，长飙风中自来往。\n枯桑老柏寒飕飗，九雏鸣凤乱啾啾。\n龙吟虎啸一时发，万籁百泉相与秋。\n忽然更作渔阳掺，黄云萧条白日暗。\n变调如闻杨柳春，上林繁花照眼新。\n岁夜高堂列明烛，美酒一杯声一曲。' },
  { title: '魏仓曹东堂柽树', author: '李颀', poem: '爱君双柽一树奇，千叶齐生万叶垂。\n长头拂石带烟雨，独立空山人莫知。\n攒青蓄翠阴满屋，紫穗红英曾断目。\n洛阳墨客游云间，若到麻源第三谷。' },
  { title: '照公院双橙', author: '李颀', poem: '种橙夹阶生得地，细叶隔帘见双翠。\n抽条向长未及肩，泉水遶根日三四。\n青青何必楚人家，带雨凝烟新着花。\n永愿香炉洒甘露，夕阳时映东枝斜。' },
  { title: '爱敬寺古藤歌', author: '李颀', poem: '古藤池水盘树根，左攫右拏龙虎蹲。\n横空直上相陵突，丰茸离𫄥若无骨。\n风雷霹雳连黑枝，人言其下藏妖魑。\n空庭落叶乍开合，十月苦寒常倒垂。\n忆昨花飞满空殿，密叶吹香饭僧遍。\n南阶双桐一百尺，相与年年老霜霰。' },
  { title: '崔五六图屏风各赋一物得乌孙佩刀', author: '李颀', poem: '乌孙腰间佩两刀，刃可吹毛锦为带。\n握手枕宿穹庐室，马上割飞翳螉塞。\n执之魍魉谁能前，气凛清风沙漠边。\n磨用阴山一片玉，洗将胡地独流泉。\n主人屏风写奇状，铁鞘金镮俨相向。\n回头瞪目时一看，使予心在江湖上。' },
  { title: '古意', author: '李颀', poem: '男儿事长征，少小幽燕客。\n赌胜马蹄下，由来轻七尺。\n杀人莫敢前，须如猬毛磔。\n黄云陇底白雪飞，未得报恩不能归。\n辽东小妇年十五，惯弹琵琶解歌舞。\n今为羗笛出塞声，使我三军泪如雨。' },
  { title: '采莲', author: '李颀', poem: '越溪女，越溪莲，齐菡萏，双婵娟。\n嬉游向何处，采摘且同船。\n浩唱发容与，清波生漪涟。\n时逢岛屿泊，几伴鸯鸳眠。\n襟袖既盈溢，馨香亦相传。\n薄暮归去来，苎罗生碧烟。' },
  { title: '杂兴', author: '李颀', poem: '沈沈牛渚矶，旧说多灵怪。\n行人夜秉生犀烛，洞照洪深辟滂湃。\n乘车驾马往复旋，赤绂朱冠何伟然。\n波惊海若潜幽石，龙抱胡髯卧黑泉。\n水滨丈人曾有语，物或恶之当害汝。\n武昌妖梦果为灾，百代英威埋鬼府。\n青青兰艾本殊香，察见泉鱼固不祥。\n济水自清河自浊，周公大圣接舆狂。\n千年魑魅逢华表，九日茱萸作佩囊。\n善恶死生齐一贯，祗应斗酒任苍苍。' },
  { title: '绝缨歌', author: '李颀', poem: '楚王宴客章华台，章华美人善歌舞。\n玉颜艳艳空相向，满堂目成不得语。\n红烛灭，芳酒阑，罗衣半醉春夜寒。\n绝缨解带一为欢，君王赦过不之罪。\n暗中珠翠鸣珊珊，宁爱贤，不爱色。\n青娥买死谁能识，果却一军全社稷。' },
  { title: '郑樱桃歌', author: '李颀', poem: '石季龙，僭天禄，擅雄豪，美人姓郑名樱桃。\n樱桃美颜香且泽，娥娥侍寝专宫掖。\n后庭卷衣三万人，翠眉清镜不得亲。\n宫军女骑一千匹，繁花照耀漳河春。\n织成花映红纶巾，红旗掣曳卤簿新。\n鸣鼙走马接飞鸟，铜驮瑟瑟随去尘。\n凤阳重门如意馆，百尺金梯倚银汉。\n自言富贵不可量，女为公主男为王。\n赤花双簟珊瑚床，盘龙斗帐琥珀光。\n淫昏伪位神所恶，灭石者陵终不悟。\n邺城苍苍白露微，世事翻覆黄云飞。' },
  { title: '送刘昱', author: '李颀', poem: '八月寒苇花，秋江浪头白。\n北风吹五两，谁是浔阳客。\n鸬鹚山头微雨晴，扬州郭里暮潮生。\n行人夜宿金陵渚，试听沙边有鴈声。' },
  { title: '送郝判官', author: '李颀', poem: '楚城木叶落，夏口青山遍。\n鸿鴈向南时，君乘使者传。\n枫林带水驿，夜火明山县。\n千里送行人，蔡州如眼见。\n江连清汉东逶迤，遥望荆云相蔽亏。\n应问襄阳旧风俗，为余骑马习家池。' },
  { title: '送刘方平', author: '李颀', poem: '绮纨游上国，多作少年行。\n二十二词赋，惟君着美名。\n童颜且白皙，佩德如瑶琼。\n荀氏风流盛，胡家公子清。\n有才不偶谁之过，肯即藏锋事高卧。\n洛阳草色犹自春，游子东归喜拜亲。\n漳水桥头值鸣鴈，朝歌县北少行人。\n别离斗酒心相许，落日青郊半微雨。\n请君骑马望西陵，为我殷勤吊魏武。' },
  { title: '听董大弹胡笳声兼寄语弄房给事', author: '李颀', poem: '蔡女昔造胡笳声，一弹一十有八拍。\n胡人落泪沾边草，汉使断肠对归客。\n古戍苍苍烽火寒，大荒沈沈飞雪白。\n先拂商弦后角羽，四郊秋叶惊摵摵。\n董夫子，通神明，深山窃听来妖精。\n言迟更速皆应手，将往复旋如有情。\n空山百鸟散还合，万里浮云阴且晴。\n嘶酸雏鴈失群夜，断绝胡儿恋母声。\n川为净其波，鸟亦罢其鸣。\n乌孙部落家乡远，逻娑沙尘哀怨生。\n幽音变调忽飘洒，长风吹林雨堕瓦。\n迸泉飒飒飞木末，野鹿呦呦走堂下。\n长安城连东掖垣，凤凰池对青琐门。\n高才脱略名与利，日夕望君抱琴至。' },
  { title: '弹棋歌', author: '李颀', poem: '崔侯善弹棋，巧妙尽于此。\n蓝田美玉清如砥，白黑相分十二子。\n联翩百中皆造微，魏文手巾不足比。\n缘边度陇未可嘉，鸟跂星悬危复斜。\n回飙转指速飞电，拂四取五旋风花。\n坐中齐声称绝艺，仙人六博何能继。\n一别常山道路遥，为余更作三五势。' },
  { title: '送山阴姚丞携妓之任兼寄苏少府', author: '李颀', poem: '东风香草路，南客心容与。\n白皙吴王孙，青蛾柳家女。\n都门数骑出，河口片帆举。\n夜簟眠橘洲，春衫傍枫屿。\n山阴政简甚从容，到罢惟求物外踪。\n落日花边剡溪水，晴烟竹里会稽峰。\n才子风流苏伯玉，同官晓暮应相逐。\n加飡共爱鲈鱼肥，醒酒仍怜甘蔗熟。\n知君练思本清新，季子如今得为邻。\n他日知寻始宁墅，题诗早晚寄西人。' },
  { title: '寄镜湖朱处士', author: '李颀', poem: '澄霁晚流阔，微风吹绿苹。\n鳞鳞远峰见，淡淡平湖春。\n芳草日堪把，白云心所亲。\n何时可为乐，梦里东山人。' },
  { title: '宴陈十六楼', author: '李颀', poem: '西楼对金谷，此地古人心。\n白日落庭内，黄花生涧阴。\n四邻见疎木，万井度寒砧。\n石上题诗处，千年留至今。' },
  { title: '送相里造入京', author: '李颀', poem: '子月过秦正，寒云覆洛城。\n嗟君未得志，犹作苦辛行。\n煖酒嫌衣薄，瞻风候雨晴。\n春官含笑待，驱马速前程。' },
  { title: '送钱子入京', author: '李颀', poem: '夜梦还京北，乡心恨捣衣。\n朝逢入秦使，走马唤君归。\n驿路清霜下，关门黄叶稀。\n还家应信宿，看子速如飞。' },
  { title: '送綦毋三寺中赋得纱灯', author: '李颀', poem: '禅室吐香烬，轻纱笼翠烟。\n长绳挂青竹，百尺垂红莲。\n熠爚众星下，玲珑双塔前。\n含光待明发，此别岂徒然。' },
  { title: '送人尉闽中', author: '李颀', poem: '可叹芳菲日，分为万里情。\n阊门折垂柳，御苑听残莺。\n海戍通闽邑，江航过楚城。\n客心君莫问，春草是王程。' },
  { title: '送人归沔南', author: '李颀', poem: '梅花今正发，失路复何如。\n旧国云山在，新年风景余。\n春饶汉阳梦，日寄武陵书。\n可即明时老，临川莫羡鱼。' },
  { title: '送卢逸人', author: '李颀', poem: '洛阳为此别，携手更何时。\n不复人间见，祗应海上期。\n清谿入云木，白首卧茅茨。\n共惜卢敖去，天边望所思。' },
  { title: '送顾朝阳还吴', author: '李颀', poem: '寂寞俱不偶，裹粮空入秦。\n宦途已可识，归卧包山春。\n旧国指飞鸟，沧波愁旅人。\n开樽洛水上，怨别柳花新。' },
  { title: '送窦参军', author: '李颀', poem: '城南送归客，举酒对林峦。\n暄鸟迎风啭，春衣度雨寒。\n桃花开翠幕，柳色拂金鞍。\n公子何时至，无令芳草阑。' },
  { title: '望秦川', author: '李颀', poem: '秦川朝望迥，日出正东峰。\n远近山河净，逶迤城阙重。\n秋声万户竹，寒色五陵松。\n客有归欤叹，凄其霜露浓。' },
  { title: '觉公院施鸟石台', author: '李颀', poem: '石台置香饭，斋后施诸禽。\n童子亦知善，众生无惧心。\n苔痕苍晓露，盘势出香林。\n锡杖或围绕，吾师一念深。' },
  { title: '篱笋', author: '李颀', poem: '东园长新笋，映日复穿篱。\n迸出依青嶂，攒生半绿池。\n色因林向背，行逐地高卑。\n但恐春将老，青青独尔为。' },
  { title: '达奚吏部夫人寇氏挽歌', author: '李颀', poem: '存殁令名传，青青松柏田。\n事姑称孝妇，生子继先贤。\n露湿铭旌重，风吹卤簿前。\n阴堂从此闭，谁诵女师篇。' },
  { title: '寄司勋卢员外', author: '李颀', poem: '流澌腊月下河阳，草色新年发建章。\n秦地立春传太史，汉宫题柱忆仙郎。\n归鸿欲度千门雪，侍女新添五夜香。\n早晚荐雄文似者，故人今已赋长杨。' },
  { title: '寄綦毋三', author: '李颀', poem: '新加大邑绶仍黄，近与单车去洛阳。\n顾眄一过丞相府，风流三接令公香。\n南川稉稻花侵县，西岭云霞色满堂。\n共道进贤蒙上赏，看君几岁作台郎。' },
  { title: '送魏万之京', author: '李颀', poem: '朝闻游子唱离歌，昨夜微霜初渡河。\n鸿鴈不堪愁里听，云山况是客中过。\n关城树色催寒近，御苑砧声向晚多。\n莫见长安行乐处，空令岁月易蹉跎。' },
  { title: '送李回', author: '李颀', poem: '知君官属大司农，诏幸骊山职事雄。\n岁发金钱供御府，昼看仙液注离宫。\n千岩曙雪旌门上，十月寒花辇路中。\n不覩声明与文物，自伤流滞去关东。' },
  { title: '宿莹公禅房闻梵', author: '李颀', poem: '花宫仙梵远微微，月隐高城钟漏稀。\n夜动霜林惊落叶，晓闻天籁发清机。\n萧条已入寒空静，飒沓仍随秋雨飞。\n始觉浮生无住着，顿令心地欲皈依。' },
  { title: '题璇公山池', author: '李颀', poem: '远公遯迹庐山岑，开士幽居祇树林。\n片石孤峰窥色相，清池皓月照禅心。\n指挥如意天花落，坐卧闲房春草深。\n此外俗尘都不染，惟余玄度得相寻。' },
  { title: '题卢五旧居', author: '李颀', poem: '物在人亡无见期，闲庭系马不胜悲。\n窓前绿竹生空地，门外青山如旧时。\n怅望秋天鸣坠叶，巑岏枯柳宿寒鸱。\n忆君泪落东流水，岁岁花开知为谁。' },
  { title: '赠别张兵曹', author: '李颀', poem: '汉家萧相国，功盖五诸侯。\n勋业河山重，丹青锡命优。\n君为禁脔壻，争看玉人游。\n荀令焚香日，潘郎振藻秋。\n新成鹦鹉赋，能衣鹔鹴裘。\n不惮轩车远，仍寻薜荔幽。\n苑梨飞绛叶，伊水净寒流。\n雪满故关道，云遮祥凤楼。\n一身轻寸禄，万物任虚舟。\n别后如相问，沧波双白鸥。' },
  { title: '宿香山寺石楼', author: '李颀', poem: '夜宿翠微半，高楼闻暗泉。\n渔舟带远火，山磬发孤烟。\n衣拂云松外，门清河汉边。\n峰峦低枕席，世界接人天。\n霭霭花出雾，辉辉星映川。\n东林曙莺满，惆怅欲言旋。' },
  { title: '圣善阁送裴迪入京', author: '李颀', poem: '云华满高阁，苔色上钩栏。\n药草空阶静，梧桐返照寒。\n清吟可愈疾，携手暂同欢。\n堕叶和金磬，饥乌鸣露盘。\n伊流惜东别，灞水向西看。\n旧托含香署，云霄何足难。' },
  { title: '奉送漪叔游颍川兼谒淮阳太守', author: '李颀', poem: '罢吏今何适，辞家方独行。\n嵩阳入归梦，颍水半前程。\n闻道淮阳守，东南卧理清。\n郡斋观政日，人马望乡情。\n叠岭雪初霁，寒砧霜后鸣。\n临川嗟拜手，寂寞事躬耕。' },
  { title: '二妃庙送裴侍御使桂阳', author: '李颀', poem: '沅上秋草晚，苍苍尧女祠。\n无人见精魄，万古寒猿悲。\n桂水身殁后，椒浆神降时。\n回云迎赤豹，骤雨飒文狸。\n受命出炎海，焚香征楚词。\n乘骢感遗迹，一吊清川湄。' },
  { title: '送暨道士还玉清观', author: '李颀', poem: '仙宫有名籍，度世吴江𣸣。\n大道本无我，青春长与君。\n中州俄已到，至理得而闻。\n明主降黄屋，时人看白云。\n空山何窈窕，三秀日氛氲。\n遂此留书客，超遥烟驾分。' },
  { title: '送刘主簿归金坛', author: '李颀', poem: '与子十年旧，其如离别何。\n宦游邻故国，归梦是沧波。\n京口青山远，金陵芳草多。\n云帆晓容裔，江日昼清和。\n县郭舟人饮，津亭渔者歌。\n茅山有仙洞，羡尔再经过。' },
  { title: '送卢少府赴延陵', author: '李颀', poem: '问君从宦所，何日府中趋。\n遥指金陵县，青山天一隅。\n行人怀寸禄，小吏献新图。\n北固波涛险，南天风俗殊。\n春江连橘柚，晚景媚菰蒲。\n漠漠花生渚，亭亭云过湖。\n滩沙映村火，水雾歛樯乌。\n回首东门路，乡书不可无。' },
  { title: '送皇甫曾游襄阳山水兼谒韦太守', author: '李颀', poem: '岘山枕襄阳，滔滔江汉长。\n山深卧龙宅，水净斩蛟乡。\n元凯春秋传，昭明文选堂。\n风流满今古，烟岛思微茫。\n白鴈暮冲雪，青林寒带霜。\n芦花独戍晚，柑实万家香。\n旧国欲兹别，轻舟眇未央。\n百花亭漫漫，一柱观苍苍。\n按俗荆南牧，持衡吏部郎。\n逢君立五马，应醉习家塘。' },
  { title: '龙门送裴侍御监五岭选', author: '李颀', poem: '万里番禺地，官人继帝忧。\n君为柱下史，将命出东周。\n歇马傍川路，张灯临石楼。\n棱棱静疎木，濞濞响寒流。\n榔叶四荒外，梅花五岭头。\n明珠尉佗国，翠羽夜郎洲。\n夷俗富珍产，土风资宦游。\n心清物不杂，弊革事无留。\n举善必称最，持奸当去尤。\n何辞桂江远，今日用贤秋。' },
  { title: '送乔琳', author: '李颀', poem: '草绿小平津，花开伊水滨。\n今君不得意，孤负帝乡春。\n口不言金帛，心常任屈伸。\n阮公惟饮酒，陶令肯羞贫。\n阳羡风流地，沧海游寓人。\n菱歌五湖远，桂树八公邻。\n青鸟迎孤棹，白云随一身。\n潮随秣陵上，月映石头新。\n未可逃名利，应须在缙绅。\n汀洲芳杜色，劝尔暂垂纶。' },
  { title: '题少府监李丞山池', author: '李颀', poem: '能向府亭内，置兹山与林。\n他人骕骦马，而我薜萝心。\n雨止禁门肃，莺啼官柳深。\n长廊閟军器，积水背城阴。\n窓外王孙草，床头中散琴。\n清风多仰慕，吾亦尔知音。' },
  { title: '长寿寺粲公院新甃井', author: '李颀', poem: '僧房来往久，露井每同观。\n白石抱新甃，苍苔依旧栏。\n空瓶宛转下，长绠辘轳盘。\n境界因心净，泉源见底寒。\n钟鸣时灌顶，对此日闲安。' },
  { title: '魏仓曹宅各赋一物得当轩石竹', author: '李颀', poem: '罗生殊众色，独为表华滋。\n虽杂蕙兰处，无争桃李时。\n同人趋府暇，落日后庭期。\n密叶散红点，灵条惊紫蕤。\n芳菲看不厌，采摘愿来兹。' },
  { title: '奉送五叔入京兼寄綦毋三', author: '李颀', poem: '云阴带残日，怅别此何时。\n欲望黄山道，无由见所思。' },
  { title: '寄韩鹏', author: '李颀', poem: '为政心闲物自闲，朝看飞鸟暮飞还。\n寄书河上神明宰，羡尔城头姑射山。' },
  { title: '百花原', author: '李颀', poem: '百花原头望京师，黄河水流无已时。\n穷秋旷野行人绝，马首东来知是谁。' },
  { title: '遇刘五', author: '李颀', poem: '洛阳一别梨花新，黄鸟飞飞逢故人。\n携手当年共为乐，无惊蕙草惜残春。' },
  { title: '送崔婴赴汉阳', author: '李颀', poem: '中外相连弟与兄，新加小县子男名。\n才年三十佩铜印，知尔弦歌汉水清。' },
  { title: '送五叔入京兼寄綦毋三', author: '李颀', poem: '吏部明年拜官后，西城必与故人期。\n寄书春草年年色，莫道相逢玉女祠。' },
  { title: '野老曝背', author: '李颀', poem: '百岁老翁不种田，惟知曝背乐残年。\n有时扪虱独搔首，目送归鸿篱下眠。' },
  { title: '送东阳王太守', author: '李颀', poem: '江臯杜蘅绿，芳草日迟迟。\n桧楫今何去，星郎出守时。\n彤襜问风俗，明主寄惸嫠。\n令下不徒尔，人和当在兹。\n昔年经此地，微月有佳期。\n洞口桂花白，岩前春草滋。\n素沙静津濑，青壁带川坻。\n野鹤每孤立，林鼯常昼悲。' },
  { title: '咏张𬤇山水', author: '李颀', poem: '小山破体闲支策，落日梨花照空壁。\n诗堪记室妬风流，画与将军作勍敌。' },
  { title: '失题', author: '李颀', poem: '紫极殿前朝伏奏，龙华会里日相望。\n别离岁岁如流水，谁辨他乡与故乡。' },
  { title: '冬夜寓居寄储太祝', author: '綦毋潜', poem: '自为洛阳客，夫子吾知音。\n尽义能下士，时人无此心。\n奈何离居夜，巢鸟悲空林。\n愁坐至月上，复闻南邻砧。' },
  { title: '春泛若耶溪', author: '綦毋潜', poem: '幽意无断绝，此去随所偶。\n晚风吹行舟，花路入溪口。\n际夜转西壑，隔山望南斗。\n潭烟飞溶溶，林月低向后。\n生事且弥漫，愿为持竿叟。' },
  { title: '题鹤林寺', author: '綦毋潜', poem: '道林隐形胜，向背临层霄。\n松覆山殿[冷]，花藏谿路遥。\n珊珊宝幡挂，焰焰明灯烧。\n迟日半空谷，春风连上潮。\n少凭水木兴，暂令身心调。\n愿谢携手客，兹山禅诵饶。' },
  { title: '题栖霞寺', author: '綦毋潜', poem: '南山势回合，灵境依此住。\n殿转云崖阴，僧探石泉度。\n龙蛇争翕习，神鬼皆密护。\n万壑奔道场，群峰向双树。\n天花飞不着，水月白成路。\n今日观身我，归心复何处。' },
  { title: '送储十二还庄城', author: '綦毋潜', poem: '西坂何缭绕，青林问子家。\n天寒噪野雀，日晚度城鸦。\n寂历道傍树，曈昽原上霞。\n兹情不可说，长恨隐沦赊。' },
  { title: '送章彝下第', author: '綦毋潜', poem: '长安渭桥路，行客别时心。\n献赋温泉毕，无媒魏阙深。\n黄莺啼就马，白日暗归林。\n三十名未立，君还惜寸阴。' },
  { title: '送崔员外黔中监选', author: '綦毋潜', poem: '持衡出帝畿，星指夜郎飞。\n神女云迎马，荆门雨湿衣。\n听猿收泪罢，系鴈待书稀。\n蛮貊虽殊俗，知君肝胆微。' },
  { title: '送贾恒明府兼寄温张二司户', author: '綦毋潜', poem: '越客新安别，秦人旧国情。\n舟乘晚风便，月带上潮平。\n花路西施石，云峰句践城。\n明州报两掾，相忆二毛生。' },
  { title: '送宋秀才', author: '綦毋潜', poem: '冠古积荣盛，当时数戟门。\n旧交丞相子，继世五侯孙。\n长劒倚天外，短书盈万言。\n秋风一送别，江上黯消魂。' },
  { title: '送平判官入秦', author: '綦毋潜', poem: '谪远自安命，三年已忘归。\n同声愿执手，驿骑到门扉。\n云是帝乡去，军书谒紫微。\n曾为金马客，向日泪沾衣。' },
  { title: '送郑务拜伯父', author: '綦毋潜', poem: '名公作逐臣，驱马拂行尘。\n旧国问郧子，劳歌过郢人。\n一川花送客，二月柳宜春。\n奉料竹林兴，宽怀此别晨。' },
  { title: '题招隐寺绚公房', author: '綦毋潜', poem: '开士度人久，空岩花雾深。\n徒知燕坐处，不见有为心。\n兰若门对壑，田家路隔林。\n还言证法性，归去比黄金。' },
  { title: '宿太平观', author: '綦毋潜', poem: '夕到玉京寝，窅冥云汉低。\n魂交仙室蝶，曙听羽人鸡。\n滴沥花上露，清泠松下谿。\n明当访真隐，挥手入无倪。' },
  { title: '题灵隐寺山顶禅院', author: '綦毋潜', poem: '招提此山顶，下界不相闻。\n塔影挂清汉，钟声和白云。\n观空静室掩，行道众香焚。\n且驻西来驾，人天日未曛。' },
  { title: '若耶溪逢孔九', author: '綦毋潜', poem: '相逢此溪曲，胜托在烟霞。\n潭影竹间动，岩阴檐外斜。\n人言上皇代，犬吠武陵家。\n借问淹留日，春风满若耶。' },
  { title: '宿龙兴寺', author: '綦毋潜', poem: '香刹夜忘归，松青古殿扉。\n灯明方丈室，珠系比丘衣。\n白日传心静，青莲喻法微。\n天花落不尽，处处鸟衔飞。' },
  { title: '题沈东美员外山池', author: '綦毋潜', poem: '仙郎偏好道，凿沼象瀛洲。\n鱼乐随情性，船行任去留。\n秦人辨鸡犬，尧日识巢由。\n归客衡门外，仍怜返景幽。' },
  { title: '茅山洞口', author: '綦毋潜', poem: '华阳仙洞口，半岭拂云看。\n窈窕穿苔壁，差池对石坛。\n方随地脉转，稍觉水晶寒。\n未果变金骨，归来兹路难。' },
  { title: '过方尊师院', author: '綦毋潜', poem: '羽客北山寻，草堂松径深。\n养神宗示法，得道不知心。\n洞户逢双履，寥天有一琴。\n更登玄圃上，仍种杏成林。' },
  { title: '经陆补阙隐居', author: '綦毋潜', poem: '不敢要君征亦起，致君全得似唐虞。\n谠言昨叹离天听，新象今闻入县图。\n琴锁坏窗风自响，鹤归乔木隐难呼。\n学书弟子何人在，点检犹存谏草无。' },
  { title: '登天竺寺', author: '綦毋潜', poem: '郡有化城最，西穷叠嶂深。\n松门当涧口，石路在峰心。\n幽见夕阳霁，高逢暮雨阴。\n佛身瞻绀发，宝地践黄金。\n云向竹谿尽，月从花洞临。\n因物成真悟，遗世在兹岑。' },
  { title: '满公房', author: '綦毋潜', poem: '世界莲花藏，行人香火缘。\n灯王照不尽，中夜寂相传。' },
  { title: '过融上人兰若', author: '綦毋潜', poem: '山头禅室挂僧衣，窗外无人溪鸟飞。\n黄昏半在下山路，却听钟声连翠微。' },
  { title: '早发上东门', author: '綦毋潜', poem: '十五能行西入秦，三十无家作路人。\n时命不将明主合，布衣空染洛阳尘。' },
  { title: '祇园寺', author: '綦毋潜', poem: '宝坊求往迹，神理驻沿洄。\n鴈塔酬前愿，王身更后来。\n加持将暝合，朗悟豁然开。\n两世分明见，余生复几哉。' },
  { title: '送集贤学士伊阙史少府放归江东觐省', author: '綦毋潜', poem: '墨客钟张侣，材高吴越珍。\n千门来谒帝，驷马去荣亲。\n吏邑沿清洛，乡山指白苹。\n归期应不远，当及未央春。' },
  { title: '述韦昭应画犀牛', author: '储光羲', poem: '遐方献文犀，万里随南金。\n大邦柔远人，以之居山林。\n食棘无秋冬，绝流无浅深。\n双角前崭崭，三蹄下骎骎。\n朝贤壮其容，未能辨其音。\n有我衰鸟郎，新邑长鸣琴。\n陛阁飞嘉声，丘甸盈仁心。\n闲居命国工，作绘北堂阴。\n眈眈若有神，庶比来仪禽。\n昔有舞天庭，为君奏龙吟。' },
  { title: '献王威仪', author: '储光羲', poem: '入与真主言，有骑天马来。\n但有华清宫，不用神明台。\n肃肃长自闲，门静无人开。' },
  { title: '野田黄雀行', author: '储光羲', poem: '啧啧野田雀，不知躯体微。\n闲穿深蒿里，争食复争飞。\n穷老一颓舍，枣多桑树稀。\n无枣犹可食，无桑何以衣。\n萧条空仓暮，相引时来归。\n斜路岂不捷，渚田岂不肥。\n水长路且坏，恻恻与心违。' },
  { title: '樵父词', author: '储光羲', poem: '山北饶朽木，山南多枯枝。\n枯枝作采薪，爨室私自知。\n诘朝砺斧寻，视暮行歌归。\n先雪隐薜荔，迎暄卧茅茨。\n清涧日濯足，乔木时曝衣。\n终年登险阻，不复忧安危。\n荡漾与神游，莫知是与非。' },
  { title: '渔父词', author: '储光羲', poem: '泽鱼好鸣水，溪鱼好上流。\n渔梁不得意，下渚潜垂钩。\n乱荇时碍楫，新芦复隐舟。\n静言念终始，安坐看沈浮。\n素发随风扬，远心与云游。\n逆浪还极浦，信潮下沧洲。\n非为徇形役，所乐在行休。' },
  { title: '牧童词', author: '储光羲', poem: '不言牧田远，不道牧陂深。\n所念牛驯扰，不乱牧童心。\n圆笠覆我首，长蓑披我襟。\n方将忧暑雨，亦以惧寒阴。\n大牛隐层坂，小牛穿近林。\n同类相鼓舞，触物成讴吟。\n取乐须臾间，宁问声与音。' },
  { title: '采莲词', author: '储光羲', poem: '浅渚荇花繁，深潭菱叶疎。\n独往方自得，耻邀淇上姝。\n广江无术阡，大泽绝方隅。\n浪中海童语，流下鲛人居。\n春鴈时隐舟，新萍复满湖。\n采采乘日暮，不思贤与愚。' },
  { title: '采菱词', author: '储光羲', poem: '浊水菱叶肥，清水菱叶鲜。\n义不游浊水，志士多苦言。\n潮没具区薮，潦深云梦田。\n朝随北风去，暮逐南风旋。\n浦口多渔家，相与邀我船。\n饭稻以终日，羹莼将永年。\n方冬水物穷，又欲休山樊。\n尽室相随从，所贵无忧患。' },
  { title: '射雉词', author: '储光羲', poem: '曝暄理新翳，迎春射鸣雉。\n原田遥一色，臯陆旷千里。\n遥闻咿喔声，时见双飞起。\n幂䍥疎蒿下，毰毸深丛里。\n顾敌已忘生，争雄方决死。\n仁心贵勇义，岂能复伤此。\n超遥下故墟，迢递回高畤。\n大夫昔何苦，取笑欢妻子。' },
  { title: '猛虎词', author: '储光羲', poem: '寒亦不忧雪，饥亦不食人。\n人肉岂不甘，所恶伤明神。\n太室为我宅，孟门为我邻。\n百兽为我膳，五龙为我宾。\n蒙马一何威，浮江一以仁。\n彩章耀朝日，爪牙雄武臣。\n高云逐气浮，厚地随声震。\n君能贾余勇，日夕长相亲。' },
  { title: '渭桥北亭作', author: '储光羲', poem: '停车渭阳暮，望望入秦京。\n不见鹓鸾道，如闻歌吹声。\n乡魂涉江水，客路指蒲城。\n独有故楼月，今来亭上明。' },
  { title: '述华清宫五首 一', author: '储光羲', poem: '上在蓬莱宫，莫若居华清。\n朝朝礼玄阁，日日闻体轻。\n大圣不私己，精禋为群氓。' },
  { title: '述华清宫五首 二', author: '储光羲', poem: '上出蓬莱时，六龙俨齐首。\n长道舒羽仪，彤云暎前后。\n天声殷宇宙，真气到林薮。' },
  { title: '述华清宫五首 三', author: '储光羲', poem: '昔在轩辕朝，五城十二楼。\n今我神泉宫，独在骊山陬。\n群方趋顺动，百辟随天游。' },
  { title: '述华清宫五首 四', author: '储光羲', poem: '正月开阳和，通门缉元化。\n穆穆睟容归，岂为明灯夜。\n高山大风起，肃肃随龙驾。' },
  { title: '述华清宫五首 五', author: '储光羲', poem: '上林神君宫，此地即明庭。\n山开鸿蒙色，天转招摇星。\n三雪报大有，孰为非我灵。' },
  { title: '杂咏五首 石子松', author: '储光羲', poem: '盘石青岩下，松生盘石中。\n冬春无异色，朝暮有清风。\n五鬣何人采，西山旧两童。' },
  { title: '杂咏五首 架檐藤', author: '储光羲', poem: '得从轩墀下，殊胜松柏林。\n生枝逐架远，吐叶向门深。\n何许答君子，檐间朝暝阴。' },
  { title: '杂咏五首 池边鹤', author: '储光羲', poem: '舞鹤傍池边，水清毛羽鲜。\n立如依岸雪，飞似向池泉。\n江海虽言旷，无如君子前。' },
  { title: '杂咏五首 钓鱼湾', author: '储光羲', poem: '垂钓绿湾春，春深杏花乱。\n潭清疑水浅，荷动知鱼散。\n日暮待情人，维舟绿杨岸。' },
  { title: '杂咏五首 幽人居', author: '储光羲', poem: '幽人下山径，去去夹青林。\n滑处莓苔湿，暗中萝薜深。\n春朝烟雨散，犹带浮云阴。' },
  { title: '题太玄观', author: '储光羲', poem: '门外车马喧，门里宫殿清。\n行即翳若木，坐即吹玉笙。\n所喧既非我，真道其冥冥。' },
  { title: '至嵩阳观观即天皇故宅', author: '储光羲', poem: '真人上清室，乃在中峰前。\n花雾生玉井，霓裳画列仙。\n念兹宫故宇，多此地新泉。\n松柏有清阴，薜萝亦自妍。\n一闻步虚子，又话逍遥篇。\n忽若在云汉，风中意泠然。' },
  { title: '贻韦炼师', author: '储光羲', poem: '精思莫知日，意静如空虚。\n三鸟自来去，九光遥卷舒。\n新池近天井，玉宇停云车。\n余亦苦山路，洗心祈道书。' },
  { title: '霁后贻马十二巽', author: '储光羲', poem: '高天风雨散，清气在园林。\n况我夜初静，当轩鸣绿琴。\n云开北堂月，庭满南山阴。\n不见长裾者，空歌游子吟。' },
  { title: '题陆山人楼', author: '储光羲', poem: '暮声杂初鴈，夜色涵早秋。\n独见海中月，照君池上楼。\n山云拂高栋，天汉入云流。\n不惜朝光满，其如千里游。' },
  { title: '献八舅东归', author: '储光羲', poem: '高位莫能舍，舍之世所贤。\n云车游日华，岂比龙楼前。\n寝疾乃就枕，情感唯灵仙。\n帝鸿思道宗，臣彭亦长年。\n天书加羽服，又许归东川。\n镜水涵太清，禹山朝上玄。\n诚亡真混沌，玉立方婵娟。\n素业作仙居，子孙当自传。\n门多松柏树，箧有逍遥篇。\n独往不可群，沧海成桑田。' },
  { title: '泛茅山东溪', author: '储光羲', poem: '清晨登仙峰，峰远行未极。\n江海霁初景，草木含新色。\n而我任天和，此时聊动息。\n望乡白云里，发棹清溪侧。\n松柏生深山，无心自贞直。' },
  { title: '吃茗粥作', author: '储光羲', poem: '当昼暑气盛，鸟雀静不飞。\n念君高梧阴，复解山中衣。\n数片远云度，曾不蔽炎晖。\n淹留膳茶粥，共我饭蕨薇。\n敝庐既不远，日暮徐徐归。' },
  { title: '游茅山五首 一', author: '储光羲', poem: '十年别乡县，西去入皇州。\n此意在观国，不言空远游。\n九衢平若水，利往无轻舟。\n北洛反初路，东江还故丘。\n春山多秀木，碧涧尽清流。\n不见子桑扈，当从方外求。' },
  { title: '游茅山五首 二', author: '储光羲', poem: '世业传儒行，行成非不荣。\n其如怀独善，况以闻长生。\n家近华阳洞，早年深此情。\n巾车云路入，理棹瑶溪行。\n天地朝光满，江山春色明。\n王庭有轩冕，此日方知轻。' },
  { title: '游茅山五首 三', author: '储光羲', poem: '平生非作者，望古怀清芬。\n心以道为际，行将时不群。\n兹山在人境，灵贶久传闻。\n远势一峰出，近形千嶂分。\n冬春有茂草，朝暮多鲜云。\n此去亦何极，但言西日曛。' },
  { title: '游茅山五首 四', author: '储光羲', poem: '昔贤居柱下，今我去人间。\n良以直心旷，兼之外视闲。\n垂纶非钓国，好学异希颜。\n落日登高屿，悠然望远山。\n溪流碧水去，云带清阴还。\n想见中林士，岩扉长不关。' },
  { title: '游茅山五首 五', author: '储光羲', poem: '名岳征仙事，清都访道书。\n山门入松柏，天路涵空虚。\n南极见朝采，西潭闻夜渔。\n远心尚云宿，浪迹出林居。\n为己存实际，忘形同化初。\n此行良已矣，不乐复何如。' },
  { title: '述降圣观', author: '储光羲', poem: '一山尽天苑，一峰开道宫。\n道花飞羽衞，天鸟游云空。\n玉殿俯玄水，春旗摇素风。\n夹门小松柏，覆井新梧桐。\n自昔大仙下，乃知元化功。\n神皇作桂馆，此意与天通。' },
  { title: '题眄上人禅居', author: '储光羲', poem: '真王清净子，燕居复行心。\n结宇邻居邑，寤言非远寻。\n丹青丈室满，草树一庭深。\n秀色玄冬发，交枝白日阴。\n江流暎朱户，山鸟鸣香林。\n独住已寂寂，安知浮与沈。' },
  { title: '过新丰道中', author: '储光羲', poem: '西下长乐坂，东入新丰道。\n雨多车马稀，道上生秋草。\n太阴蔽臯陆，莫知晚与早。\n雷雨杳冥冥，川谷漫浩浩。\n诏书植嘉木，众言桃李好。\n自媿无此容，归从汉阴老。' },
  { title: '夜到洛口入黄河', author: '储光羲', poem: '河洲多青草，朝暮增客愁。\n客愁惜朝暮，枉渚𫏐停舟。\n中宵大川静，解缆逐归流。\n浦溆既清旷，沿洄非阻修。\n登舻望落月，击汰悲新秋。\n倘遇乘槎客，永言星汉游。' },
  { title: '使过弹筝峡作', author: '储光羲', poem: '鸟雀知天雪，群飞复群鸣。\n原田无遗粟，日暮满空城。\n达士忧世务，鄙夫念王程。\n晨过弹筝峡，马足凌兢行。\n双壁隐灵曜，莫能知晦明。\n皑皑坚冰白，漫漫阴云平。\n始信古人言，苦节不可贞。' },
  { title: '泊舟贻潘少府', author: '储光羲', poem: '行子苦风潮，维舟未能发。\n宵分卷前幔，卧视清秋月。\n四泽蒹葭深，中洲烟火绝。\n苍苍水雾起，落落疎星没。\n所遇尽渔商，与言多楚越。\n其如念极浦，又以思明哲。\n常若千里余，况之异乡别。' },
  { title: '仲夏入园中东陂', author: '储光羲', poem: '方塘深且广，伊昔俯吾庐。\n环岸垂绿柳，盈泽发红蕖。\n上延北原秀，下属幽人居。\n暑雨若混沌，清明如空虚。\n此乡多隐逸，水陆见樵渔。\n废赏亦何贵，为欢良易摅。\n且言重观国，当此赋归欤。' },
  { title: '效古二首 一', author: '储光羲', poem: '晨登凉风台，暮走邯郸道。\n曜灵何赫烈，四野无青草。\n大军北集燕，天子西居镐。\n妇人役州县，丁男事征讨。\n老幼相别离，哭泣无昏早。\n稼穑既殄绝，川泽复枯槁。\n旷哉远此忧，冥冥商山皓。' },
  { title: '效古二首 二', author: '储光羲', poem: '东风吹大河，河水如倒流。\n河洲尘沙起，有若黄云浮。\n赪霞烧广泽，洪曜赫高丘。\n野老泣相语，无地可荫休。\n翰林有客卿，独负苍生忧。\n中夜起踯躅，思欲献厥谋。\n君门峻且深，踠足空夷犹。' },
  { title: '杂诗二首 一', author: '储光羲', poem: '混沌本无象，末路多是非。\n达士志寥廓，所在能忘禨。\n耕凿时未至，还山聊采薇。\n虎豹对我蹲，𬸚𬸦旁我飞。\n仙人空中来，谓我勿复归。\n格泽为君驾，虹蜺为君衣。\n西游昆仑墟，可与世人违。' },
  { title: '杂诗二首 二', author: '储光羲', poem: '秋气肃天地，太行高崔嵬。\n猨狖清夜吟，其声一何哀。\n寂寞掩圭荜，梦寐游蓬莱。\n琪树远亭亭，玉堂云中开。\n洪崖吹箫管，玉女飘飖来。\n雨师既先后，道路无纤埃。\n鄙哉楚襄王，独好阳云台。' },
  { title: '陆著作挽歌 一', author: '储光羲', poem: '世业江湖侧，郊原休沐处。\n独言五日归，未道千秋去。\n乡亭春水绿，昌阁寒光暮。\n昔为昼锦游，今成逝川路。' },
  { title: '陆著作挽歌 二', author: '储光羲', poem: '归路秦城下，寒云惨平田。\n故园沧海边，绿柳覆平川。\n送客异他日，还舟殊昔年。\n华亭有明月，长向陇头悬。' },
  { title: '陆著作挽歌 三', author: '储光羲', poem: '剑水千人石，荆江万里流。\n英英有君子，才德满中州。\n明道俟良佐，惟贤初薄游。\n生涯一朝尽，寂寞夜台幽。' },
  { title: '陆著作挽歌 四', author: '储光羲', poem: '金堂策令名，仙掖居清位。\n鸣玉朝双阙，垂缨游两地。\n朝夕既论思，春秋仍书事。\n何言鲁声伯，忽下琼珠泪。' },
  { title: '陆著作挽歌 五', author: '储光羲', poem: '令德弃人世，明朝降宠章。\n起居存有位，著作没为郎。\n寒水落南浦，月华虚北堂。\n松门一长想，仿佛见清扬。' },
  { title: '山居贻裴十二迪', author: '储光羲', poem: '落叶满山砌，苍烟埋竹扉。\n远怀青冥士，书劒常相依。\n霜卧眇兹地，琴言纷已违。\n衡阳今万里，南雁将何归。\n出径惜松引，入舟怜钓矶。\n西林有明月，夜久空微微。' },
  { title: '秦中岁晏马舍人宅宴集', author: '储光羲', poem: '冬暮久无乐，西行至长安。\n故人处东第，清夜多新欢。\n广庭竹阴静，华池月色寒。\n知音尽词客，方见交情难。' },
  { title: '荐玄德公庙', author: '储光羲', poem: '神道本无已，成化亦自然。\n君居寥天上，德在玉华泉。\n真游践王豫，永日迟云仙。\n表微在营道，明祀将祈年。\n灵山俯新邑，松上生彩烟。\n岂知穆天子，远去瑶池边。' },
  { title: '上长史王公责躬', author: '储光羲', poem: '覆舟无伯夷，覆车无仲尼。\n自咎失明义，宁由贝锦诗。\n松柏日已坚，桃李日以滋。\n顾己独暗昧，所居成蒺藜。\n大贤荐时文，丑妇用蛾眉。\n惕惕愧不已，岂敢论其私。\n方朔既有言，子建亦有诗。\n恻隐及先世，析薪成自悲。\n灵鸟酬德辉，黄雀报仁慈。\n若公庶伏罪，此事安能迟。' },
  { title: '至岳寺即大通大照禅塔上温上人', author: '储光羲', poem: '秋山下暎宫，宫色宜朝阳。\n迢递在半岭，参差非一行。\n燕息云满门，出游花隐房。\n二尊此成道，禅宇遥相望。\n凤铎天中鸣，岩梯松下长。\n山墟响信鼓，蘅薄生蕙香。\n起灭一以雪，往来亦诚亡。\n悲哉门弟子，要自知心长。' },
  { title: '终南幽居献苏侍郎三首时拜太祝未上 一', author: '储光羲', poem: '暮春天气和，登岭望层城。\n朝日悬清景，巍峨宫殿明。\n圣君常临朝，达士复悬衡。\n道近燕艮足，归来卧山楹。\n灵堦曝仙书，深室炼金英。\n春岩松柏秀，晨路鹍鸡鸣。\n羽化既有言，无然悲不成。' },
  { title: '终南幽居献苏侍郎三首时拜太祝未上 二', author: '储光羲', poem: '中岁尚微道，始知将谷神。\n抗策还南山，水木自相亲。\n深林开一道，青嶂成四邻。\n平明去采薇，日入行刈薪。\n云归万壑暗，雪罢千崖春。\n始看玄鸟来，已见瑶华新。\n寄言搴芳者，无乃后时人。' },
  { title: '终南幽居献苏侍郎三首时拜太祝未上 三', author: '储光羲', poem: '卜筑青岩里，云萝四垂阴。\n虚室若无人，乔木自成林。\n时有清风至，侧闻樵采音。\n凤皇鸣南冈，望望隔层岑。\n既言山路远，复道溪流深。\n偓佺空中游，虬龙水间吟。\n何当见轻翼，为我达远心。' },
  { title: '题应圣观', author: '储光羲', poem: '空中望小山，山下见余雪。\n皎皎河汉女，在兹养真骨。\n登门骇天书，启籥问仙诀。\n池光摇水雾，灯色连松月。\n合甎起花台，折草成玉节。\n天鸡弄白羽，王母垂玄发。\n北有上年宫，一路在云霓。\n上心方向道，时复朝金阙。' },
  { title: '至闲居精舍呈正上人', author: '储光羲', poem: '太室三招提，其趣皆不同。\n不同非一趣，况是天游宫。\n双岭前夹门，阁道复横空。\n宝坊若花积，宛转不可穷。\n流泉自成池，清松信饶风。\n秋晏景气逈，皛明丹素功。\n将近隐者邻，远与西山通。\n大师假惠照，念以息微躬。' },
  { title: '酬綦毋校书梦耶溪见赠之作', author: '储光羲', poem: '校文在仙掖，每有沧洲心。\n况以北窗下，梦游清溪阴。\n春看湖水漫，夜入回塘深。\n往往缆垂葛，出舟望前林。\n山人松下饭，钓客芦中吟。\n小隐何足贵，长年固可寻。\n还车首东道，惠言若黄金。\n以我采薇意，传之天姥岑。' },
  { title: '田家即事', author: '储光羲', poem: '蒲叶日已长，杏花日已滋。\n老农要看此，贵不违天时。\n迎晨起饭牛，双驾耕东菑。\n蚯蚓土中出，田乌随我飞。\n群合乱啄噪，嗷嗷如道饥。\n我心多恻隐，顾此两伤悲。\n拨食与田乌，日暮空筐归。\n亲戚更相诮，我心终不移。' },
  { title: '同王十三维偶然作十首 一', author: '储光羲', poem: '仲夏日中时，草木看欲燋。\n田家惜工力，把锄来东臯。\n顾望浮云阴，往往误伤苗。\n归来悲困极，兄嫂共相𫍢。\n无钱可沽酒，何以解劬劳？\n夜深星汉明，庭宇虚寥寥。\n高柳三五株，可以独逍遥。' },
  { title: '同王十三维偶然作十首 二', author: '储光羲', poem: '北山种松柏，南山种蒺藜。\n出入虽同趣，所向各有宜。\n孔丘贵仁义，老氏好无为。\n我心若虚空，此道将安施。\n暂过伊阙间，晼晚三伏时。\n高阁入云中，芙蓉满清池。\n要自非我室，还望南山陲。' },
  { title: '同王十三维偶然作十首 三', author: '储光羲', poem: '野老本贫贱，冒暑锄瓜田。\n一畦未及终，树下高枕眠。\n荷𦰏者谁子，皤皤来息肩。\n不复问乡墟，相见但依然。\n腹中无一物，高话羲皇年。\n落日临层隅，逍遥望晴川。\n使妇提蚕筐，呼儿榜渔船。\n悠悠泛绿水，去摘浦中莲。\n莲花艳且美，使我不能还。' },
  { title: '同王十三维偶然作十首 四', author: '储光羲', poem: '浮云在虚空，随风复卷舒。\n我心方处顺，动作何忧虞。\n但言婴世网，不复得间居。\n迢递别东国，超遥来西都。\n见人乃恭敬，曾不问贤愚。\n虽若不能言，中心亦难诬。\n故乡满亲戚，道远情日疎。\n偶欲陈此意，复无南飞凫。' },
  { title: '同王十三维偶然作十首 五', author: '储光羲', poem: '草木花叶生，相与命为春。\n当非草木意，信是故时人。\n静念恻群物，何由知至真。\n狂歌问夫子，夫子莫能陈。\n凤皇飞且鸣，容裔下天津。\n清净无言语，兹焉庶可亲。' },
  { title: '同王十三维偶然作十首 六', author: '储光羲', poem: '黄河流向东，弱水流向西。\n趋舍各有异，造化安能齐。\n妾本邯郸女，生长在丛台。\n既闻容见宠，复想玄为妻。\n刻画尚风流，幸会君招携。\n逶迤歌舞座，婉娈芙蓉闺。\n日月方向除，恩爱忽焉暌。\n弃置谁复道，但悲生不谐。\n羡彼匹妇意，偕老常同栖。' },
  { title: '同王十三维偶然作十首 七', author: '储光羲', poem: '日暮登春山，山鲜云复轻。\n远近看春色，踟蹰新月明。\n仙人浮丘公，对月时吹笙。\n丹鸟飞熠熠，苍蝇乱营营。\n群动汩吾真，讹言伤我情。\n安得如子晋，与之游太清。' },
  { title: '同王十三维偶然作十首 八', author: '储光羲', poem: '耽耽铜鞮宫，遥望长数里。\n宾客无多少，出入皆珠履。\n朴儒亦何为，辛苦读旧史。\n不道无家舍，效他养妻子。\n冽冽玄冬暮，衣裳无准拟。\n偶然着道书，神人养生理。\n公卿时见赏，赐赉难具纪。\n莫问身后事，且论朝夕是。' },
  { title: '同王十三维偶然作十首 九', author: '储光羲', poem: '空山暮雨来，众鸟竟栖息。\n斯须照夕阳，双双复抚翼。\n我念天时好，东田有稼穑。\n浮云蔽川原，新流集沟洫。\n裴回顾衡宇，僮仆邀我食。\n卧览床头书，睡看机中织。\n想见明膏煎，中夜起唧唧。' },
  { title: '同王十三维偶然作十首 十', author: '储光羲', poem: '四邻竞丰屋，我独好卑室。\n窈窕高台中，时闻抚新瑟。\n狂飙动地起，拔木乃非一。\n相顾始知悲，中心忧且栗。\n蚩蚩命子弟，恨不居高秩。\n日入宾从归，清晨冠盖出。\n中庭有奇树，荣早衰复疾。\n此道犹不知，微言安可述。' },
  { title: '升天行贻卢六健', author: '储光羲', poem: '真人居阆风，时奏清商音。\n听者即王母，泠泠和瑟琴。\n坐对三花枝，行随五云阴。\n天长昆仑小，日久蓬莱深。\n上由玉华宫，下视首阳岑。\n神州亦清净，要自有浮沈。\n恻恻苦哉行，呱呱游子吟。\n庐山逢若士，思欲化黄金。\n雨雪没太山，谁能无归心。\n逍遥在云汉，可以来相寻。' },
  { title: '田家杂兴八首 一', author: '储光羲', poem: '春至鸧鹒鸣，薄言向田墅。\n不能自力作，黾勉娶邻女。\n既念生子孙，方思广田圃。\n闲时相顾笑，喜悦好禾黍。\n夜夜登啸台，南望洞庭渚。\n百草被霜露，秋山响砧杵。\n却羡故年时，中情无所取。' },
  { title: '田家杂兴八首 二', author: '储光羲', poem: '众人耻贫贱，相与尚膏腴。\n我情既浩荡，所乐在畋渔。\n山泽时晦暝，归家𫏐闲居。\n满园植葵藿，绕屋树桑榆。\n禽雀知我闲，翔集依我庐。\n所愿在优游，州县莫相呼。\n日与南山老，兀然倾一壶。' },
  { title: '田家杂兴八首 三', author: '储光羲', poem: '逍遥阡陌上，远近无相识。\n落日照秋山，千岩同一色。\n网罟绕深莽，鹰鹯始轻翼。\n猎马既如风，奔兽莫敢息。\n驻旗沧海上，犒士吴宫侧。\n楚国有夫人，性情本贞直。\n鲜禽徒自致，终岁竟不食。' },
  { title: '田家杂兴八首 四', author: '储光羲', poem: '田家趋垅亩，当昼掩虚关。\n邻里无烟火，儿童共幽闲。\n桔槔悬空圃，鸡犬满桑间。\n时来农事隙，采药游名山。\n但言所采多，不念路险艰。\n人生如蜉蝣，一往不可攀。\n君看西王母，千载美容颜。' },
  { title: '田家杂兴八首 五', author: '储光羲', poem: '平生养情性，不复计忧乐。\n去家行卖畚，留滞南阳郭。\n秋至黍苗黄，无人可刈获。\n稚子朝未饭，把竿逐鸟雀。\n忽见梁将军，乘车出宛洛。\n意气轶道路，光辉满墟落。\n安知负薪者，咥咥笑轻薄。' },
  { title: '田家杂兴八首 六', author: '储光羲', poem: '楚山有高士，梁国有遗老。\n筑室既相邻，向田复同道。\n糗糒常共饭，儿孙每更抱。\n忘此耕耨劳，媿彼风雨好。\n蟪蛄鸣空泽，𫛸鴂伤秋草。\n日夕寒风来，衣裳苦不早。' },
  { title: '田家杂兴八首 七', author: '储光羲', poem: '梧桐荫我门，薜荔网我屋。\n迢迢两夫妇，朝出暮还宿。\n稼穑既自种，牛羊还自牧。\n日旰懒耕锄，登高望川陆。\n空山足禽兽，墟落多乔木。\n白马谁家儿，联翩相驰逐。' },
  { title: '田家杂兴八首 八', author: '储光羲', poem: '种桑百余树，种黍三十亩。\n衣食既有余，时时会亲友。\n夏来菰米饭，秋至菊花酒。\n孺人喜逢迎，稚子解趋走。\n日暮闲园里，团团荫榆柳。\n酩酊乘夜归，凉风吹户牖。\n清浅望河汉，低昂看北斗。\n数瓮犹未开，明朝能饮否。' },
  { title: '题辨觉精舍', author: '储光羲', poem: '朝随秋云阴，乃至青松林。\n花阁空中远，方池岩下深。\n竹风乱天语，溪响成龙吟。\n试问真君子，游山非世心。' },
  { title: '题慎言法师故房', author: '储光羲', poem: '精庐不住子，自有无生乡。\n过客知何道，裴回雁子堂。\n浮云归故岭，落月还西方。\n日夕虚空里，时时闻异香。' },
  { title: '石瓮寺', author: '储光羲', poem: '遥山起真宇，西向尽花林。\n下见宫殿小，上看廊庑深。\n苑花落池水，天语闻松音。\n君子又知我，焚香期化心。' },
  { title: '题崔山人别业', author: '储光羲', poem: '南阳隐居者，筑室丹溪源。\n溪冷惧秋[晏]，室寒欣景暾。\n山鸡鸣菌阁，水雾入衡门。\n东岭或舒啸，北窗时讨论。\n封君渭阳竹，逸士汉阴园。\n何必崆峒上，独为尧所尊。' },
  { title: '行次田家澳梁作', author: '储光羲', poem: '田家俯长道，邀我避炎氛。\n当暑日方昼，高天无片云。\n桑间禾黍气，柳下牛羊群。\n野雀栖空屋，晨昏不复闻。\n前登澳梁坂，极望温泉分。\n逆旅方三舍，西山犹未曛。' },
  { title: '昭圣观', author: '储光羲', poem: '主家隐溪口，微路入花源。\n数日朝青阁，彩云犹在门。\n双楼夹一殿，玉女侍玄元。\n扶橑尽蟠木，步櫩多画繙。\n新松引天籁，小柏绕山樊。\n坐弄竹阴远，行随溪水喧。\n石池辨春色，林兽知人言。\n未逐凤皇去，真宫在此原。' },
  { title: '题辛道士房', author: '储光羲', poem: '全神不言命，所尚道家流。\n迨此远南楚，遂令思北游。\n先生秀衡岳，玉立居玄丘。\n门带江山静，房随瑶草幽。\n逍遥三花发，罔象五云浮。\n自有太清纪，曾垂华发忧。\n大年方橐籥，小智即蜉蝣。\n七日赤龙至，莫令余独留。' },
  { title: '登秦岭作时陷贼归国', author: '储光羲', poem: '朝出猛兽林，躨跜登高峰。\n僮仆履云雾，随我行太空。\n羲和舒灵晖，倏忽西极通。\n回首望泾渭，隐隐如长虹。\n九逵合苍芜，五陵遥瞳蒙。\n鹿游大明殿，雾湿华清宫。\n网罗蠛蠓时，顾齿熊罴锋。\n失途走江汉，不能有其功。\n气逐招遥星，魂随阊阖风。\n惟言宇宙清，复使车书同。\n林木被繁霜，合沓连山红。\n鹏鹗励羽翼，俯视荆棘丛。\n誓将食鸧鸮，然后归崆峒。' },
  { title: '晦日任桥池亭', author: '储光羲', poem: '温泉作天邑，直北开新洲。\n未有菰蒲生，即闻凫雁游。\n六亭在高岸，数岛居中流。\n晦日望清波，相与期泛游。\n西道苦转毂，北隄疲行舟。\n清泠水木阴，才可适我忧。' },
  { title: '望幸亭', author: '储光羲', poem: '五年一巡狩，西幸过东畿。\n周国易居守，周人多怨思。\n君王敷惠政，程作贵从时。\n大厦非一木，沈沈临九逵。\n庆云宿飞栋，嘉树罗青墀。\n疎屏宜朝享，方塘堪水嬉。\n云中仰华盖，桁下望春旗。\n天意知如此，星言归洛师。' },
  { title: '哥舒大夫颂德', author: '储光羲', poem: '天纪启真命，君生臣亦生。\n乃知赤帝子，复有苍龙精。\n神武建皇极，文昌开将星。\n超超渭滨器，落落山西名。\n画阃入受脤，凿门出扞城。\n戎人昧正朔，我有轩辕兵。\n陇路起丰镐，关云随斾旌。\n河湟训兵甲，义勇方横行。\n韩魏多锐士，蹶张在幕庭。\n大非四决轧，石堡高峥嵘。\n攻伐若振槁，孰云非神明。\n嘉谋即天意，骤胜由师贞。\n枯草被西陆，烈风昏太清。\n戢戈旄头落，牧马昆仑平。\n宾从俨冠盖，封山纪天声。\n来朝芙蓉阙，鸣玉飘华缨。\n直道济时宪，天邦遂轻刑。\n抗书报知己，松柏亦以荣。\n嘉命列上第，德辉照天京。\n在车持简墨，粲粲皆词英。\n顾我抢榆者，莫能翔青冥。\n游燕非骐骥，踯躅思长鸣。' },
  { title: '安宜园林献高使君', author: '储光羲', poem: '直道已三出，幸从江上回。\n新居茅茨逈，起见秋云开。\n十里次舟楫，二桥交往来。\n楚言满邻里，鴈呌喧池台。\n鱼鳖乐仁政，浮沈亦至哉。\n小山宜大隐，要自望蓬莱。' },
  { title: '河中望鸟滩作贻吕四郎中', author: '储光羲', poem: '河流有深曲，舟子莫能知。\n弭棹临沙屿，微吟西日驰。\n平明春色霁，两岸好风吹。\n去去川途尽，悠悠亲友离。\n汉宫成羽翼，伊水弄参差。\n为惜淮南子，如何攀桂枝。' },
  { title: '秦中初霁献给事二首 一', author: '储光羲', poem: '渭水收暮雨，处处多新泽。\n宫苑傍山明，云林带天碧。\n君子耸高驾，英声邈今昔。\n锵珮出中台，彯缨入仙掖。\n夙心幸清鉴，晚志欣良觌。\n鸣盗非足征，愿言同下客。' },
  { title: '秦中初霁献给事二首 二', author: '储光羲', poem: '南国久为思，西都尝作宾。\n云开天地色，日照山河春。\n善听在知己，扬光唯达人。\n妙年弄柔翰，弱冠偶良晨。\n擢第文昌阁，还家沧海滨。\n寸心何所望，东掖有贤臣。' },
  { title: '晚次东亭献郑州宋使君文', author: '储光羲', poem: '自初宾上国，乃到邹人乡。\n曾点与曾子，俱升阙里堂。\n武皇恢大略，逸翮思寥廓。\n三居清宪台，两拜文昌阁。\n为道既贞信，处名犹謇谔。\n铁柱励风威，锦轴含光辉。\n夜闻持简立，朝看伏奏归。\n洞门清珮响，广路玉珂飞。\n骧首入丹掖，抟空趋太微。\n丝纶逢圣主，出入飘华组。\n愔愔宿帝梧，侃侃居文府。\n海内语三独，朝端谋六户。\n善计在弘羊，清严归仲举。\n侍郎跨方朔，中丞蔑周处。\n天眷择循良，惟贤降宠章。\n分符指聊摄，为政本农桑。\n籍籍歌五袴，祁祁颂千箱。\n随车微雨洒，逐扇清风飏。\n既以迁列国，复兹邻帝乡。\n褰帷乃仍旧，坐啸非更张。\n居敬物无扰，履端人自康。\n薄游出京邑，引领东南望。\n林晚鸟雀噪，田秋稼穑黄。\n成臯天地险，广武征战场。\n道丧苦兵赋，时来开井疆。\n霏霏渠门色，晻晻制岩光。\n徒念京索近，犹悲溱洧长。\n大明潜照耀，淑慝自昭彰。\n昔岁幸西土，今兹归洛阳。\n同焉知郑伯，当辅我周王。' },
  { title: '秋次霸亭寄申大', author: '储光羲', poem: '橘柚植寒陵，芙蓉蔕修坂。\n无言不得意，得意何由展。\n况我行且徒，而君往犹蹇。\n既伤人事近，复言天道远。\n薄暮入空亭，中夜不能饭。\n南听鸿雁尽，西见招摇转。\n千门汉主宫，百里周王苑。\n杲杲初景出，油油鲜云卷。\n会朝幸岁正，校猎从新狝。\n念君久京国，双涕如露泫。\n无人荐子云，太息竟谁辨。' },
  { title: '舟中别武金坛', author: '储光羲', poem: '曰予轻皎洁，坦率宾混元。\n忽乃异群萃，高歌信陵门。\n信陵好宾客，清夜开华轩。\n月光丽池阁，野气浮林园。\n偶坐烂明星，归志潜崩奔。\n漾舟清潭里，慰我别离魂。\n落日下西山，左右惨无言。\n萧条风雨散，窅霭江湖昏。\n秋荷尚幽郁，暮鸟复翩翻。\n纸笔亦何为，写我心中冤。' },
  { title: '巩城东庄道中作', author: '储光羲', poem: '北陵散寒鸟，西山照初日。\n婉娈晋阳京，踟蹰野人室。\n南轩草间去，后乘林中出。\n霭霭长路暖，迟迟狭路归。\n蜉蝣时蔽月，枳棘复伤衣。\n城上东风起，河边早雁飞。\n夏王纪冬令，殷人乃正月。\n涯口度新云，山阴留故雪。\n幸逢耆耋话，余待亲隣别。\n总辔出丛薄，歇鞍登峻隅。\n春源既荡漭，伏战亦睢盱。\n未获遵平道，徒言信薄夫。' },
  { title: '赴冯翊作', author: '储光羲', poem: '本自江海人，且无寥廓志。\n大明耀天宇，霭霭风雨被。\n迢递别荆吴，飘飖涉沂泗。\n广川俟舟檝，峻坂伤骐骥。\n蹭蹬失归道，崎岖从下位。\n西出太华阴，北走少梁地。\n葱茏墟落色，泱漭关河气。\n耻从侠烈游，甘为刀笔吏。\n宝劒茱萸匣，岂忘知音贵。\n大道且泛然，沈浮未云异。' },
  { title: '晚霁中园喜赦作', author: '储光羲', poem: '五月黄梅时，阴气蔽远迩。\n浓云连晦朔，菰菜生隣里。\n落日烧霞明，农夫知雨止。\n几悲衽席湿，长叹垣墙毁。\n曭朗天宇开，家族跃以喜。\n涣汗发大号，坤元更资始。\n散衣出中园，小径尚滑履。\n池光摇万象，倏忽灭复起。\n嘉树如我心，欣欣岂云已。' },
  { title: '观范阳递俘', author: '储光羲', poem: '北河旄星陨，鬼方狝林胡。\n群师舞弓矢，电发归燕墟。\n皇皇轩辕君，赞赞臯陶谟。\n方思壮军实，远近递生俘。\n车马践大逵，合沓成深渠。\n牧人过橐𫘞，校正引𫘦𬳿。\n烈风朝送寒，云雪霭天隅。\n草木同一色，谁能辨荣枯。\n四履封元戎，百金酬勇夫。\n大邦武功爵，固与炎皇殊。' },
  { title: '次天元十载华阴发兵作时有郎官点发', author: '储光羲', poem: '鬼方生猃狁，时寇卢龙营。\n帝念霍嫖姚，诏发咸林兵。\n天星下文阁，简师临我城。\n三陌观勇夫，五饵谋长缨。\n雷野大车发，震云灵鼓鸣。\n太华色莽苍，清渭风交横。\n胡马悲雨雪，诗人歌斾旌。\n阏氏为女奴，单于作边氓。\n神皇麒麟阁，大将不书名。' },
  { title: '送丘健至州敕放作时任下邽县', author: '储光羲', poem: '太史登观台，天街耀旄头。\n大君忽霆震，诏爵冠军侯。\n南必梁孙源，西将圉昆丘。\n河陇征击卒，虎符到我州。\n朝集咸林城，师言乱啁啾。\n杀气变木德，凛凛如高秋。\n元戎启神皇，庙堂发嘉谋。\n息兵业稼穑，归马复休牛。\n和风开阴雪，大耀中天流。\n欢声殷河岳，涵荡非烟浮。\n邦牧新下车，德礼彼甿讴。\n乾坤日交泰，吾亦遂优游。' },
  { title: '登商丘', author: '储光羲', poem: '河水日夜流，客心多殷忧。\n维梢历宋国，结缆登商丘。\n汉皇封子弟，周室命诸侯。\n摇摇世祀怨，伤古复兼秋。\n鸣鸿念极浦，征旅慕前俦。\n太息梁王苑，时非牧马游。' },
  { title: '群鸦咏', author: '储光羲', poem: '新宫骊山阴，龙衮时出豫。\n朝阳照羽仪，清吹肃逵路。\n群鸦随天车，夜满新丰树。\n所思在腐余，不复忧霜露。\n河低宫阁深，灯影鼓钟曙。\n缤纷集寒枝，矫翼时相顾。\n冢宰收琳琅，侍臣尽鸳鹭。\n高举摩太清，永绝矰缴惧。\n兹禽亦翱翔，不以微小故。' },
  { title: '尚书省受誓诫贻太庙裴丞', author: '储光羲', poem: '皇家有恒宪，斋祭崇明祀。\n严车伊洛间，受誓文昌里。\n沈沈云阁见，稍稍城乌起。\n曙色照衣冠，虚庭鸣劒履。\n裴回念私觌，怅望临清汜。\n点翰欲何言，相思从此始。' },
  { title: '夏日寻蓝田唐丞登高宴集', author: '储光羲', poem: '东望春明门，驾言聊出游。\n南行小径尽，绿竹临清流。\n君出罢六安，居此澹忘忧。\n园林与城市，闾里随人幽。\n披颜辟衡闱，置酒登崇丘。\n山河临咫尺，宇宙穷寸眸。\n是时春载阳，佳气满皇州。\n宫殿碧云里，鸳鸯初命俦。\n良辰方在兹，志士安得休。\n成名苟有地，何必东陵侯。' },
  { title: '田家即事答崔二东臯作四首 一', author: '储光羲', poem: '玄鸟双双飞，杏林初发花。\n喣媮命僮仆，可以树桑麻。\n清旦理犂锄，日入未还家。' },
  { title: '田家即事答崔二东臯作四首 二', author: '储光羲', poem: '有客山中至，言传故人讯。\n荡漾敷远情，飘飖吐清韵。\n猗欤春臯上，无乃成秋兴。' },
  { title: '田家即事答崔二东臯作四首 三', author: '储光羲', poem: '念别求须臾，忽至嘤鸣时。\n菜田烧故草，初树养新枝。\n所寓非幽深，梦寐相追随。' },
  { title: '田家即事答崔二东臯作四首 四', author: '储光羲', poem: '依依亲陇亩，寂寂无隣里。\n不闻鸡犬音，日见和风起。\n赖君遗掞藻，忧来散能弭。' },
  { title: '敬酬陈掾亲家翁秋夜有赠', author: '储光羲', poem: '大姬配胡公，位乃三恪宾。\n盛德百代祀，斯言良不泯。\n敬仲为齐卿，当国名益震。\n仲举登宰辅，太丘荣缙绅。\n武皇受瑶图，爵士封其新。\n繁祉既骤集，裔孙生贤臣。\n特达逾珪璋，节操方松筠。\n云汉一矫翼，天池三振鳞。\n曳裾朝赤墀，酌醴侍紫宸。\n大君锡车马，时复过平津。\n言则广台阶，道亦资天均。\n清秋忽高兴，震藻若有神。\n曜曜趋宫廷，洸洸迈徐陈。\n镐京既赐第，门巷交朱轮。\n方将袭伊臯，永以崇夏殷。\n宗党无远近，敬恭依仁人。\n雪尽宇宙暄，雁归沧海春。\n沈吟白华颂，帝闼降丝纶。\n驿骑及芜城，相逢在郊鄄。\n别离旷南北，谴谪罹苦辛。\n昼游还荆吴，迷方客咸秦。\n惟贤惠重义，男女期嘉姻。\n梧桐生朝阳，𫛸鴂鸣萧晨。\n岂不畏时暮，坎𡒄无与邻。\n中夜凉风来，顾我阙音尘。\n琼瑶不遐弃，寤寐如日新。' },
  { title: '苏十三瞻登玉泉寺峰入寺中见赠作', author: '储光羲', poem: '庆门叠华组，盛列钟英彦。\n贞信发天姿，文明叶邦选。\n为情贵深远，作德齐隐见。\n别业在春山，怀归出芳甸。\n逖听多时友，招邀及浮贱。\n朝沿霸水穷，暮瞩蓝田徧。\n百花照阡陌，万木森乡县。\n涧净绿萝深，岩暄新鸟转。\n依然造华薄，豁尔开灵院。\n淹留火禁辰，愉乐弦歌宴。\n肃肃列樽俎，锵锵引缨弁。\n天籁激微风，阳光轹奔箭。\n以兹小人腹，不胜君子馔。\n是日既低迷，中宵方眄眩。\n枕上思独往，胸中理交战。\n碧云暗雨来，旧原芳色变。\n欢然自此绝，心赏何由见。\n鸿蒙已笑云，列缺仍挥电。\n忽与去人远，俄逢归者便。\n想像玉泉宫，依稀明月殿。\n峰峦如登陟，水木以游衍。\n息心幸自忘，点翰仍留眷。\n恨无荆文璧，以答丹青绚。' },
  { title: '酬李处士山中见赠', author: '储光羲', poem: '厥初游太学，相与极周旋。\n含采共朝暮，知言同古先。\n孟阳题劒阁，子云献甘泉。\n斯须旷千里，婉娩将十年。\n今来艳阳月，好鸟鸣翩翩。\n同声既求友，不肖亦怀贤。\n引领迟芳信，果枉瑶华篇。\n成颂非其德，高文徒自妍。\n声尘邈超越，比兴起孤绝。\n始信郢中人，乃能歌白雪。\n跂予北堂夜，摇笔酬明哲。\n绿竹动清风，层轩静华月。\n想像南山下，恬然谢朝列。\n犹恐𫛸鴂鸣，坐看芳草歇。\n邀以青松色，同之白华洁。\n永愿登龙门，相将持此节。' },
  { title: '同诸公秋日游昆明池思古', author: '储光羲', poem: '仆人理车骑，西出金光逵。\n苍苍白帝郊，我将游灵池。\n太阴连晦朔，雨与天根违。\n凄风披田原，横污益山陂。\n农畯尽颠沛，顾望稼穑悲。\n皇灵恻群甿，神政张天维。\n坤纪戮屏翳，元纲扶逶迤。\n回塘清沧流，大曜悬金晖。\n秋色浮浑沌，清光随涟漪。\n豫章尽莓苔，柳杞成枯枝。\n骤闻汉天子，征彼西南夷。\n伐棘开洪渊，秉旄训我师。\n震云灵鼍鼓，照水蛟龙旗。\n锐士千万人，猛气如熊罴。\n刑罚一以正，干戈自有仪。\n坐作河汉倾，进退楼船飞。\n羽发鸿鴈落，桧动芙蓉披。\n峨峨三云宫，肃肃振旅归。\n恶德忽小丑，器用穷地赀。\n上兵贵伐谋，此道不能为。\n吁哉蒸人苦，始曰征伐非。\n穆穆轩辕朝，耀德守方陲。\n君臣日安闲，远近无怨思。\n石鲸既蹭蹬，女牛亦流离。\n㺍獭游渚隅，葭芦生漘湄。\n坎埳四十里，填淤今已微。\n江伯方翱翔，天吴亟往来。\n桑榆惨无色，伫立暮霏霏。\n老幼樵木还，宾从回鞿羁。\n帝梦鲜鱼索，明月当报时。' },
  { title: '同诸公登慈恩寺塔', author: '储光羲', poem: '金祠起真宇，直上青云垂。\n地静我亦闲，登之秋清时。\n苍芜宜春苑，片碧昆明池。\n谁道天汉高，逍遥方在兹。\n虚形宾太极，携手行翠微。\n雷雨傍杳冥，鬼神中躨跜。\n灵变在倏忽，莫能穷天涯。\n冠上阊阖开，履下鸿雁飞。\n宫室低逦迤，群山小参差。\n俯仰宇宙空，庶随了义归。\n崱屴非大厦，久居亦以危。' },
  { title: '同诸公秋霁曲江俯见南山', author: '储光羲', poem: '天静终南高，俯暎江水明。\n有若蓬莱下，浅深见澄瀛。\n群峰悬中流，石壁如瑶琼。\n鱼龙隐苍翠，鸟兽游清泠。\n菰蒲林下秋，薜荔波中轻。\n山戛浴兰阯，水若居云屏。\n岚气浮渚宫，孤光随曜灵。\n阴阴豫章馆，宛宛百花亭。\n大君及群臣，[宴]乐方嘤鸣。\n吾党二三子，萧辰怡性情。\n逍遥沧洲时，乃在长安城。' },
  { title: '同诸公送李云南伐蛮', author: '储光羲', poem: '昆明滨滇池，蠢尔敢逆常。\n天星耀𫓧锧，吊彼西南方。\n冢宰统元戎，太守齿军行。\n囊括千万里，矢谟在庙堂。\n耀耀金虎符，一息到炎荒。\n搜兵自交趾，茇舍出泸阳。\n群山高崭岩，凌越如鸟翔。\n封豕骤跧伏，巨象遥披攘。\n回溪深天渊，揭厉逾舟梁。\n玄武扫孤蜮，蛟龙除方良。\n雷霆随神兵，硼磕动穹苍。\n斩伐若草木，系缧同犬羊。\n余丑隐弭河，啁啾乱行藏。\n君子恶薄险，王师耻重伤。\n广车设罝梁，太白收光芒。\n边吏静县道，新书行纪纲。\n劒关掉鞅归，武弁朝建章。\n龙楼加命服，獬豸拥秋霜。\n邦人颂灵旗，侧听何洋洋。\n京观在七德，休哉我神皇。' },
  { title: '奉和韦判官献侍郎叔除河东采访使', author: '储光羲', poem: '天卿小冢宰，道大名亦大。\n丑正在权臣，建旟千里外。\n楚山俯江汉，汴水连谯沛。\n两持方伯珪，再转诸侯盖。\n恬淡轻黜陟，优游邈千载。\n乾象变台衡，群贤尽交泰。\n聿徕股肱郡，河岳即襟带。\n盛德滋冀方，仁风清汾浍。\n四封尽高足，相府轺车最。\n超超青云器，婉婉竹林会。\n贱士敢知言，成颂文明代。\n燕雀依大厦，期之保贞悔。' },
  { title: '同王十三维哭殷遥', author: '储光羲', poem: '生理无不尽，念君在中年。\n游道虽未深，举世莫能贤。\n筮仕苦贫贱，为客少田园。\n膏腴不可求，乃在许西偏。\n四邻尽桑柘，咫尺开墙垣。\n内艰未及虞，形影随化迁。\n茅茨俯苫盖，双殡两楹间。\n时闻孤女号，逈出陌与阡。\n慈乌乱飞鸣，猛兽亦以跧。\n故人王夫子，静念无生篇。\n哀乐久已绝，闻之将泫然。\n太阳蔽空虚，雨雪浮苍山。\n迢遰亲灵榇，顾予悲绝弦。\n处顺与安时，及此乃空言。' },
  { title: '贻丁主簿仙芝别', author: '储光羲', poem: '赫赫明天子，翘翘群秀才。\n昭昭皇宇广，隐隐云门开。\n摇曳君初起，联翩予复来。\n兹年不得意，相命游灵台。\n骅骝多逸气，琳瑯有清响。\n联行击水飞，独影凌虚上。\n关河施芳听，江海徼新赏。\n歛袵归故山，敷言播天壤。\n云峰虽有异，楚越幸相亲。\n既别复游处，道深情更殷。\n下愚忝闻见，上德犹邅迍。\n偃仰东城曲，栖迟依水滨。\n脱巾从会府，结绶归海裔。\n亲知送河门，邦族迎江澨。\n夫子安恬淡，他人怅迢递。\n飞艎既眇然，洲渚徒亏蔽。\n人谋固无准，天德谅难知。\n高名处下位，逸翮栖卑枝。\n去去水中沚，摇摇天一涯。\n蓬壶不可见，来泛跃龙池。' },
  { title: '京口送别王四谊', author: '储光羲', poem: '江上枫林秋，江中秋水流。\n清晨惜分袂，秋日尚同舟。\n落潮洗鱼浦，倾荷枕驿楼。\n明年菊花熟，洛东泛觞游。' },
  { title: '同房宪部应旋', author: '储光羲', poem: '衡山法王子，慧见息诸苦。\n落发自南州，燕居在西土。\n养正不因晦，得中宁患旅。\n旷然长虚闲，即理寄行补。\n四句了自性，一音亦非取。\n橘柚故园枝，随人植庭户。\n我地少安住，念天时启处。\n宪卿文昌归，愉悦来晤语。\n车骑践香草，仆人沐花雨。\n长风散繁云，万里静天宇。\n起灭信易觉，清真知有所。\n逍遥高殿阴，六月无炎暑。\n微言发新偈，粲粲如悬圃。\n直心视惠光，在此大法鼓。' },
  { title: '奉别长史庾公太守徐公应召', author: '储光羲', poem: '烈风起江汉，白浪忽如山。\n方伯骤勤王，杞人亦忧天。\n酆镐顷霾晦，云龙召我贤。\n车骑北艰苦，艅艎西溯沿。\n水灵静湍濑，猛兽趋后先。\n龙楼开新阳，万里出云间。\n宇宙既焜耀，崇德济巨川。\n受命在神宗，振兵犹轩辕。\n煌煌逾涿鹿，穆穆更坤元。\n明王朝太阶，远迩望嘉言。\n游子淡何思，江湖将永年。' },
  { title: '狱中贻姚张薛李郑柳诸公', author: '储光羲', poem: '直道时莫亲，起羞见谗口。\n舆人是非怪，西子言有咎。\n诬善不足悲，失听一何丑。\n大来敢遐望，小往且虚受。\n中夜囹圄深，初秋缧绁久。\n疎萤出暗草，朔风鸣衰柳。\n河汉低在户，蟏蛸垂向牖。\n雁声远天末，凉气生霁后。\n负户愁读书，劒光忿冲斗。\n哀哀害神理，恻恻伤慈母。\n妻子垂涕泣，家僮日奔走。\n书词苦人吏，馈食劳交友。\n寒服犹未成，繁霜渐将厚。\n吉凶问詹尹，倚伏信北叟。\n鬼哭知己冤，鸟言诚所诱。\n诸公深惠爱，朝夕相左右。\n束湿虽欲操，钩金庶无负。\n伤罗念摇翮，踠足思骧首。\n瑾瑜颇匿瑕，邦国方含垢。\n眷言出深穽，永日常携手。' },
  { title: '贻鼓吹李丞时信安王北伐李公王之所器者也', author: '储光羲', poem: '北伐昧天造，王师示有征。\n辕门统元律，帝室命宗英。\n灵威方首事，仗钺按边城。\n膏雨被春草，黄云浮太清。\n文儒托后乘，武旅趋前旌。\n出车发西洛，营军临北平。\n曰予深固陋，志气颇纵横。\n尝思骠骑幕，愿逐嫖姚兵。\n惟贤美无度，海内依扬声。\n河间旧相许，车骑日逢迎。\n折节下谋士，深心论客卿。\n忠言虽未列，庶以知君诚。' },
  { title: '贻刘高士别', author: '储光羲', poem: '夙驾出东城，城傍早霞散。\n初日照龙阙，峨峨在天半。\n壮哉丽百常，美矣崇两观。\n俯视趋朝客，簪珮何璀璨。\n而我送将归，裴回霸陵岸。\n北云去吴越，南雁离江汉。\n伊昔蹈丘园，翩翩理文翰。\n高谈闵仲叔，逸气刘公干。\n每言竹柏贞，尝轻朝市玩。\n山昼猿狖静，溪曛鱼鸟乱。\n宁止卧崆峒，直云期汗漫。\n圣君既理历，族士咸炳焕。\n矫首来天池，振羽泛漪澜。\n元淑命不达，伯鸾吟可叹。\n东去姑苏台，乃过陟阳馆。\n舍辔函关道，浮舟沧海畔。\n耳目旷暄凉，怀抱盈悲惋。\n沈沈青岁晚，霭霭秋云换。\n自言永遁栖，无复从羁绊。\n挥手谢知己，知己莫能赞。' },
  { title: '山中贻崔六琪华', author: '储光羲', poem: '恍惚登高岭，裴回看落日。\n遥想仲长园，如亲幼安室。\n春渚菖蒲登，山中拨谷鸣。\n相思不道远，太息未知情。\n意君来此地，时复疎林薄。\n中夜扫闲门，迎晨闭菌阁。\n屣履清池上，家童奉信归。\n忧随落花散，目送归云飞。\n故交在天末，心知复千里。\n无人暂往来，独作中林士。' },
  { title: '贻余处士', author: '储光羲', poem: '故园至新浦，遥复未百里。\n北望是他邦，纷吾即游士。\n潮来津门启，罢楫信流水。\n客意乃成欢，舟人亦相喜。\n迟迟菱荇上，泛泛孤蒲里。\n渐闻商旅喧，犹见凫鹥起。\n市亭忽云构，方物如山峙。\n吴王昔丧元，隋帝又灭祀。\n停舻一以眺，太息兴亡理。\n秋苑故池田，宫门新柳杞。\n我行苦炎月，乃及清昊始。\n此地日逢迎，终思隐君子。\n莫言异舒卷，形音在心耳。' },
  { title: '刘先生闲居', author: '储光羲', poem: '高第后归道，乃居玉华宫。\n逍遥人间世，不异浮丘公。\n甘寝何秉羽，出门忽从戎。\n方将游昆仑，又欲小崆峒。\n进退既在我，归来长安中。\n焚香东海君，侍坐西山童。\n善行无辙迹，吾亦安能穷。\n但见神色闲，中心如虚空。\n期之比天老，真德辅帝鸿。' },
  { title: '京口题崇上人山亭', author: '储光羲', poem: '清旦历香岩，岩径纡复直。\n花林开宿雾，游目清霄极。\n分明窗户中，远近山川色。\n金沙童子戏，香饭诸天食。\n呌呌海鸿声，轩轩江燕翼。\n寄言清静者，闾阎徒自踣。' },
  { title: '朝邑蔡主簿期不会二首 一', author: '储光羲', poem: '下位日趋走，久之宾会疎。\n空迟偶词赋，所媿比园庐。\n朝念池上酌，暮逢林下书。\n方将固封守，暂欲混畋渔。\n衰柳隐长路，秋云满太虚。\n遥遥望左右，日入未回车。' },
  { title: '朝邑蔡主簿期不会二首 二', author: '储光羲', poem: '日入清风至，知君在西偏。\n车舆既成列，宾仆复能贤。\n迢递下墟坂，逍遥看井田。\n苍山起暮雨，极浦浮长烟。\n服义大如志，交欢数尽年。\n宁言十余里，不见空来还。' },
  { title: '巩城南河作寄徐三景晖', author: '储光羲', poem: '初年雨候迟，巩洛河流小。\n摇摇芳草岸，屡见春山晓。\n清露洗云林，轻波戏鱼鸟。\n唯言故人远，不念乡川眇。\n舟檝去潆廻，湍溆行奔峭。\n寄书千里路，莫道南鸿少。' },
  { title: '贻阎处士防卜居终南', author: '储光羲', poem: '春风摇杂树，言别还江汜。\n坚冰生绿潭，又客三千里。\n兆梦唯颜色，悬情乃文史。\n涤耳贵清言，披欢迟玉趾。\n秦城疑旧庐，伫立问焉如。\n稚子跪而说，还山将隐居。\n竹林既深远，松宇复清虚。\n迹逈事多逸，心安趣有余。\n石门动高韵，草堂新著书。\n骞飞久超绝，蹇足空踌躇。\n犹有昔时意，望君当照车。\n驱车当六国，何以须潜默。\n圣主常征贤，群公每举德。\n此时方独往，身志将何欲。\n愿谢山中人，廻车首归躅。' },
  { title: '新丰作贻殷四校书', author: '储光羲', poem: '汉皇思旧邑，秦地作新丰。\n南出华阳路，西分长乐宫。\n安知天地久，不与昔年同。\n鸡犬暮声合，城池秋霁空。\n纷吾从此去，望极咸阳中。\n不见芸香阁，徒思文雅雄。' },
  { title: '华阳作贻祖三咏', author: '储光羲', poem: '朝行敷水上，暮出华山东。\n高馆宿初静，长亭秋转空。\n日余久沦汨，重此闻霜风。\n淅沥入溪树，飕飗惊夕鸿。\n[凄]然望伊洛，如见息阳宫。\n旧识无高位，新知尽固穷。\n夫君独轻举，远近善文雄。\n岂念千里驾，崎岖秦塞中。' },
  { title: '贻袁三拾遗谪作', author: '储光羲', poem: '倾盖洛之滨，依然心事亲。\n龙门何以峻，曾是好词人。\n珥笔朝文陛，含章讽紫宸。\n帝城多壮观，被服长如春。\n天子俭为德，而能清约身。\n公卿尽虚位，天下自趣尘。\n如君物望美，令德声何已。\n高帝黜儒生，文皇谪才子。\n朝廷非不盛，谴谪良难恃。\n路出大江阴，川行碧峰里。\n斯言徒自玷，白玉岂为滓。\n希声尽众人，深识唯知己。\n知己怨生离，悠悠天一涯。\n寸心因梦断，孤愤为年移。\n花满芙蓉阙，春深朝夕池。\n空令千万里，长望白云垂。' },
  { title: '洛中贻朝校书衡朝即日本人也', author: '储光羲', poem: '万国朝天中，东隅道最长。\n吾生美无度，高驾仕春坊。\n出入蓬山里，逍遥伊水傍。\n伯鸾游太学，中夜一相望。\n落日悬高殿，秋风入洞房。\n屡言相去远，不觉生朝光。' },
  { title: '贻崔太祝', author: '储光羲', poem: '天都分礼阁，肃肃临清渠。\n春山照前屏，高槐荫内除。\n惟贤尚廪禄，弟去兄来居。\n文雅更骧首，风流信有余。\n中年幸从事，乃遇两吹嘘。\n何以知君子，交情复淡如。' },
  { title: '贻王处士子文', author: '储光羲', poem: '春草生洞渚，春风入上林。\n春臯有黄鹤，抚翮未扬音。\n王屋尝嘉遁，伊川复陆沈。\n张弦鹍鸡弄，闭室蓬蒿深。\n避地歌三乐，游山赋九吟。\n大君思左右，无乃化黄金。' },
  { title: '献华阴罗丞别', author: '储光羲', poem: '华山薄游者，玄发当青春。\n道德同仙吏，尊卑即丈人。\n县城俯京路，获见官舍里。\n淹留琼树枝，谑浪春泉水。\n昔余在天目，总角奉游从。\n寒暑递来往，今复莲花峰。\n别情无远近，道别方愁予。\n孰想古人言，乃知悲风雨。' },
  { title: '闲居', author: '储光羲', poem: '薄游何所媿，所媿在闲居。\n亲故不来往，中园时读书。\n步栏滴余雪，春塘抽新蒲。\n梧桐渐覆井，时鸟自相呼。\n悠然念故乡，乃在天一隅。\n安得如浮云，来往方须臾。' },
  { title: '送恂上人还吴', author: '储光羲', poem: '洛城本天邑，洛水即天池。\n君王既行幸，法子复来仪。\n虚室香花满，清川杨柳棰。\n乘闲道归去，远意谁能知。' },
  { title: '送周十一', author: '储光羲', poem: '秋风陨群木，众草下严霜。\n复问子何如？自言之帝乡。\n岂无亲所爱，将欲济时康。\n握手别征驾，返悲岐路长。' },
  { title: '新丰主人', author: '储光羲', poem: '新丰主人新酒熟，旧客还归旧堂宿。\n满酌香含北砌花，盈尊色泛南轩竹。\n云散天高秋月明，东家少女解秦筝。\n醉来忘却巴陵道，梦中疑是洛阳城。' },
  { title: '登戏马台作', author: '储光羲', poem: '君不见宋公仗钺诛燕后，英雄踊跃争趋走。\n小会衣冠吕梁壑，大征甲卒碻磝口。\n天门神武树元勋，九日茱萸飨六军。\n泛泛楼船游极浦，摇摇歌吹动浮云。\n居人满目市朝变，覇业犹存齐楚甸。\n泗水南流桐柏川，沂山北走瑯琊县。\n沧海沈沈晨雾开，彭城烈烈秋风来。\n少年自古未得意，日暮萧条登古台。' },
  { title: '贻从军行', author: '储光羲', poem: '取胜小非用，来朝明光殿，东平不足先。\n梦出凤林间，梦还沧海阙。\n万里尽阴色，岂为我离别。\n马上吹笛起寒风，道傍舞劒飞春雪。\n男儿悬弧非一日，君去成高节。' },
  { title: '酬李壶关奉使行县忆诸公', author: '储光羲', poem: '青枫江上沧浪吟，白月宫中鹦鹉林。\n非有净清心，同道同房若断金。\n离居忽有云山意，清韵遥转舟檝事。\n去时能忆竹园游，来时莫忘桃园记。' },
  { title: '蔷薇', author: '储光羲', poem: '袅袅长数寻，青青不作林。\n一茎独秀当庭心，数枝分作满庭阴。\n春日迟迟欲将半，庭影离离正堪玩。\n枝上莺娇不畏人，叶底蛾飞自相乱。\n秦家女儿爱芳菲，画眉相伴采葳蕤。\n高处红须欲就手，低边绿刺已牵衣。\n蒲萄架上朝光满，杨柳园中暝鸟飞。\n连袂踏歌从此去，风吹香气逐人归。' },
  { title: '同张侍御宴北楼', author: '储光羲', poem: '今之太守古诸侯，出入双旌垂七旒。\n朝览干戈时听讼，暮延宾客复登楼。\n西山漠漠崦嵫色，北渚沈沈江汉流。\n良宵清净方高会，绣服光辉联皂盖。\n鱼龙恍惚堦墀下，云雾杳冥窗户外。\n水灵慷慨行泣珠，游女飘飖思解佩。\n苍苍低月半遥城，落落疎星满太清。\n不分开襟悲楚奏，愿言吹笛退胡兵。\n轩后青丘埋䝟貐，周王白羽扫欃枪。\n期君武节朝龙阙，余亦翱翔归玉京。' },
  { title: '临江亭五咏 一', author: '储光羲', poem: '晋家南作帝，京镇北为关。\n江水中分地，城楼下带山。\n金陵事已往，青盖理无还。\n落日空亭上，愁看龙尾湾。' },
  { title: '临江亭五咏 二', author: '储光羲', poem: '山横小苑前，路尽大江边。\n此地兴王业，无如宋主贤。\n潮生建业水，风散广陵烟。\n直望[清]波里，秪言别有天。' },
  { title: '临江亭五咏 三', author: '储光羲', poem: '城头落暮晖，城外捣秋衣。\n江水青云挹，芦花白雪飞。\n南州王气疾，东国海风微。' },
  { title: '临江亭五咏 四', author: '储光羲', poem: '古木啸寒禽，层城带夕阴。\n梁园多绿柳，楚岸尽枫林。\n山际空为险，江流长自深。\n平生何以恨，天地本无心。' },
  { title: '临江亭五咏 五', author: '储光羲', poem: '京山千里过，孤愤望中来。\n江势将天合，城门向水开。\n落霞明楚岸，夕露湿吴台。' },
  { title: '饯张七琚任宗城即环之季也同产八人俱以才名知', author: '储光羲', poem: '他日曾游魏，魏家余趾存。\n可怜宫殿所，但见桑榆繁。\n此去拜新职，为荣近故园。\n高阳八才子，况复在君门。' },
  { title: '留别安庆李太守', author: '储光羲', poem: '明牧念行子，又言悲解携。\n初筵方落日，醉止到鸣鸡。\n过客来自北，大军居在西。\n兵家如讨逆，敢以庶盘溪。' },
  { title: '洛阳东门送别', author: '储光羲', poem: '东城别故人，腊月迟芳辰。\n不惜孤舟去，其如两地春。\n花明洛阳苑，水绿小平津。\n是日不相见，莺声徒自新。' },
  { title: '汉阳即事', author: '储光羲', poem: '楚国千里远，孰知方寸违。\n春游欢有客，夕寝赋无衣。\n江水带冰绿，桃花随雨飞。\n九歌有深意，捐佩乃言归。' },
  { title: '泊江潭贻马校书', author: '储光羲', poem: '明月挂青天，遥遥如目前。\n故人游画阁，却望似云边。\n水宿依渔父，歌声好采莲。\n采莲江上曲，今夕为君传。' },
  { title: '送沈校书吴中搜书', author: '储光羲', poem: '郊外亭臯远，野中岐路分。\n苑门临渭水，山翠杂春云。\n秦阁多遗典，吴台访阙文。\n君王思校理，莫滞清江𣸣。' },
  { title: '寒夜江口泊舟', author: '储光羲', poem: '寒潮信未起，出浦缆孤舟。\n一夜苦风浪，自然增旅愁。\n吴山迟海月，楚火照江流。\n欲有知音者，异乡谁可求。' },
  { title: '苑外至龙兴院作', author: '储光羲', poem: '朝游天苑外，忽见法筵开。\n山势当空出，云阴满地来。\n疎钟清月殿，幽梵静花台。\n日暮香林下，飘飘仙步回。' },
  { title: '题虬上人房', author: '储光羲', poem: '禅宫分两地，释子一为心。\n入道无来去，清言见古今。\n江寒池水绿，山[暝]竹园深。\n别有中天月，遥遥散夕阴。' },
  { title: '咏山泉', author: '储光羲', poem: '山中有流水，借问不知名。\n映地为天色，飞空作雨声。\n转来深涧满，分出小池平。\n恬澹无人见，年年长自清。' },
  { title: '贻主客吕郎中', author: '储光羲', poem: '上士既开天，中朝为得贤。\n青云方羽翼，画省比神仙。\n委佩云霄里，含香日月前。\n君王傥借问，客有上林篇。' },
  { title: '京口留别徐大补阙赵二零陵', author: '储光羲', poem: '皇州月初晓，处处鼓钟喧。\n树出蓬莱殿，城开阊阖门。\n近臣朝琐闼，词客向文园。\n独有三川路，空伤游子魂。' },
  { title: '答王十三维', author: '储光羲', poem: '门生故来往，知欲命浮觞。\n忽奉朝青阁，回车入上阳。\n落花满春水，疎柳映新塘。\n是日归来暮，劳君奏雅章。' },
  { title: '奉和中书徐侍郎中书省玩白云寄颕阳赵大', author: '储光羲', poem: '青阙朝初退，白云遥在天。\n非关取雷雨，故欲伴神仙。\n泛滟鹓池曲，飘飖琐闼前。\n犹多远山意，幸入侍臣篇。' },
  { title: '和张太祝冬祭马步', author: '储光羲', poem: '故坛何肃肃，中野自无喧。\n烈火见陈信，飏言闻永存。\n房星隐曙色，朔风动寒原。\n今日歌天马，非关征大宛。' },
  { title: '祭风伯坛应张太祝作', author: '储光羲', poem: '圣主御青春，纶言命使臣。\n将修风伯祀，更福太平人。\n帟幕宵联事，坛场晓降神。\n帝心矜动物，非为属车人。' },
  { title: '寻徐山人遇马舍人', author: '储光羲', poem: '泊舟伊川右，正见野人归。\n日暮春山绿，我心清且微。\n岩声风雨度，水气云霞飞。\n复有金门客，来参萝薜衣。' },
  { title: '夜观妓', author: '储光羲', poem: '白雪宜新舞，清宵召楚妃。\n娇童携锦荐，侍女整罗衣。\n花映垂鬟转，香迎步履飞。\n徐徐歛长袖，双烛送将归。' },
  { title: '洛桥送别', author: '储光羲', poem: '河桥送客舟，河水正安流。\n远见轻桡动，遥怜故国游。\n海禽逢早鴈，江月值新秋。\n一听南津曲，分明散别愁。' },
  { title: '秦中送人觐省', author: '储光羲', poem: '二月清江外，遥遥饯故人。\n南山晴有雪，东陌霁无尘。\n骑别章台晚，舟行洛水春。\n知君梁苑去，日见白华新。' },
  { title: '洛中送人还江东', author: '储光羲', poem: '洛城春雨霁，相送下江乡。\n树绿天津道，山明伊水阳。\n孤舟从此去，客思一何长。\n直望清波里，唯余落日光。' },
  { title: '送姚六昆客任会稽何大蹇任孟县', author: '储光羲', poem: '越城临渤澥，晋国在河汾。\n仙绶两乡意，青郊一路分。\n野棠春未发，田雀暮成群。\n他日思吴会，尝因西北云。' },
  { title: '洛潭送人觐省', author: '储光羲', poem: '清洛带芝田，东流入大川。\n舟轻水复急，别望杳如仙。\n细草生春岸，明霞散早天。\n送君唯一曲，当是白华篇。' },
  { title: '送人随大夫和蕃', author: '储光羲', poem: '西方有六国，国国愿来宾。\n圣主今无外，怀柔遣使臣。\n大夫开幕府，才子作行人。\n解劒聊相送，边城二月春。' },
  { title: '仲夏饯魏四河北觐叔', author: '储光羲', poem: '落日临御沟，送君还北州。\n树凉征马去，路暝归人愁。\n吴岳夏云尽，渭河秋水流。\n东篱摘芳菊，想见竹林游。' },
  { title: '送人寻裴斐', author: '储光羲', poem: '柱史回清宪，谪居临汉川。\n迟君千里驾，方外赏云泉。\n路断因春水，山深隔暝烟。\n湘江见游女，寄摘一枝莲。' },
  { title: '陇头水送别', author: '储光羲', poem: '相送陇山头，东西陇水流。\n从来心胆盛，今日为君愁。\n暗雪迷征路，寒云隐戍楼。\n唯余旌斾影，相逐去悠悠。' },
  { title: '送王上人还襄阳', author: '储光羲', poem: '朝看法云散，知有至人还。\n送客临伊水，行车出故关。\n天花满南国，精舍在空山。\n虽复时来去，中心长日闲。' },
  { title: '官庄池观竞渡', author: '储光羲', poem: '落日吹箫管，清池发櫂歌。\n船争先后渡，岸激去来波。\n水叶藏鱼鸟，林花间绮罗。\n踟蹰仙女处，犹似望天河。' },
  { title: '重寄虬上人', author: '储光羲', poem: '一作云峰别，三看花柳朝。\n青山隔远路，明月空长霄。\n鹊浴西江雨，鸡鸣东海潮。\n此情劳梦寐，况道双林遥。' },
  { title: '蓝上茅茨期王维补阙', author: '储光羲', poem: '山中人不见，云去夕阳过。\n浅濑寒鱼少，丛兰秋蝶多。\n老年疎世事，幽性乐天和。\n酒熟思才子，谿头望玉珂。' },
  { title: '大酺得长字韵时任安宜尉', author: '储光羲', poem: '大道启元命，时人居太康。\n中朝发玄泽，下国被天光。\n明诏始端午，初筵当履霜。\n鼓鼙迎爽气，羽籥映新阳。\n太守即悬圃，淮夷成葆疆。\n小臣慙下位，拜手颂灵长。' },
  { title: '同张侍御鼎和京兆萧兵曹华岁晚南园', author: '储光羲', poem: '公府传休沐，私庭效陆沈。\n方知从大隐，非复在幽林。\n阙下忠贞志，人间孝友心。\n既将冠盖雅，仍与薜萝深。\n寒变中园柳，春归上苑禽。\n池涵青草色，山带白云阴。\n潘岳闲居赋，钟期流水琴。\n一经当自足，何用遗黄金。' },
  { title: '奉酬张五丈垂赠', author: '储光羲', poem: '彩服去江汜，白云生大梁。\n星辰动异色，羔鴈成新行。\n日望天朝近，时忧郢路长。\n情言间薖轴，惠念及沧浪。\n松柏以之茂，江湖亦自忘。\n贾生方吊屈，岂敢比南昌。' },
  { title: '秦中守岁', author: '储光羲', poem: '众星已穷次，青帝方行春。\n永感易成戚，离居难重陈。\n阖门守初夜，燎火到清晨。\n或念无生法，多伤未出尘。\n广庭日将晏，虚室自为宾。\n愿以桑榆末，常逢甲子新。' },
  { title: '献高使君大酺作', author: '储光羲', poem: '肃穆郊禋毕，工歌赏事幷。\n三朝遵湛露，一道洽仁明。\n布德言皆应，无为物自成。\n花添罗绮色，莺乱管弦声。\n独有同高唱，空陪乐太平。' },
  { title: '荥阳马氏二子', author: '储光羲', poem: '圣君封太岳，十月建行旃。\n辇路开千里，寒云霁九天。\n故人多侍从，二子留伊川。\n河兖冰初合，关城月屡圆。\n暝过荥水上，闻说郑卿贤。\n材蔽行人右，名居东里先。\n制岩开别业，桑柘亦依然。\n待至金园侧，相将居一廛。' },
  { title: '观竞渡', author: '储光羲', poem: '大夫沈楚水，千祀国人哀。\n习櫂江流长，迎神雨雾开。\n标随绿云动，船逆清波来。\n下怖鱼龙起，上惊凫鴈回。\n能令秋大有，鼓吹远相催。' },
  { title: '太学贻张筠', author: '储光羲', poem: '璧池忝门子，俄顷变炎凉。\n绿竹深虚馆，清流响洞房。\n园林在建业，新友去咸阳。\n中夜鼓钟静，初秋漏刻长。\n浮云开太室，华盖上明堂。\n空此远相望，劳歌还自伤。' },
  { title: '洛阳道五首献吕四郎中 一', author: '储光羲', poem: '洛水春冰开，洛城春水绿。\n朝看大道上，落花乱马足。' },
  { title: '洛阳道五首献吕四郎中 二', author: '储光羲', poem: '剧孟不知名，千金买宝剑/。\n出入平津邸，自言娇且艳。' },
  { title: '洛阳道五首献吕四郎中 三', author: '储光羲', poem: '大道直如发，春日佳气多。\n五陵贵公子，双双鸣玉珂。' },
  { title: '洛阳道五首献吕四郎中 四', author: '储光羲', poem: '春风二月时，道傍柳堪把。\n上枝覆官阁，下枝覆车马。' },
  { title: '洛阳道五首献吕四郎中 五', author: '储光羲', poem: '洛水照千门，千门碧空里。\n少年不得志，走马游新市。' },
  { title: '同武平一员外游湖', author: '储光羲', poem: '竹吹留歌扇，莲香入舞衣。\n前溪多曲溆，乘兴莫先归。' },
  { title: '长安道 一', author: '储光羲', poem: '鸣鞭过酒肆，袨服游倡门。\n百万一时尽，含情无片言。' },
  { title: '长安道 二', author: '储光羲', poem: '西行一千里，暝色生寒树。\n暗闻歌吹声，知是长安路。' },
  { title: '江南曲四首 一', author: '储光羲', poem: '绿江深见底，高浪直翻空。\n惯是湖边住，舟轻不畏风。' },
  { title: '江南曲四首 二', author: '储光羲', poem: '逐流牵荇叶，绿岸摘芦苗。\n为惜鸳鸯鸟，轻轻动画桡。' },
  { title: '江南曲四首 三', author: '储光羲', poem: '日暮长江里，相邀归渡头。\n落花如有意，来去逐船流。' },
  { title: '江南曲四首 四', author: '储光羲', poem: '隔江看树色，沿月听歌声。\n不是长干住，那从此路行。' },
  { title: '关山月', author: '储光羲', poem: '一鴈过连营，繁霜覆古城。\n胡笳在何处？半夜起边声。' },
  { title: '玉真公主山居', author: '储光羲', poem: '山北天泉苑，山西凤女家。\n不言沁园好，独隐武陵花。' },
  { title: '沧浪峡', author: '储光羲', poem: '沧浪临古道，道上若成尘。\n自有沧浪峡，谁为无事人。' },
  { title: '奉真观', author: '储光羲', poem: '真门逈向北，驰道直向西。\n为与天光近，云色成虹霓。' },
  { title: '明妃曲四首 一', author: '储光羲', poem: '西行陇上泣胡天，南向云中指渭川。\n毳幕夜来时宛转，何由得似汉王边。' },
  { title: '明妃曲四首 二', author: '储光羲', poem: '胡王知妾不胜悲，乐府皆传汉国辞。\n朝来马上箜篌引，稍似宫中闲夜时。' },
  { title: '明妃曲四首 三', author: '储光羲', poem: '日暮惊沙乱雪飞，傍人相劝易罗衣。\n强来前殿看歌舞，共待单于夜猎归。' },
  { title: '明妃曲四首 四', author: '储光羲', poem: '彩骑双双引宝车，羌笛两两奏胡笳。\n若为别得横桥路，莫隐宫中玉树花。' },
  { title: '同武平一员外游湖五首时武贬金坛令 一', author: '储光羲', poem: '红荷碧筿夜相鲜，皂盖兰桡浮翠筵。\n舟中对舞邯郸曲，月下双弹卢女弦。' },
  { title: '同武平一员外游湖五首时武贬金坛令 二', author: '储光羲', poem: '青林碧屿暗相期，缓楫挥觥欲赋诗。\n借问高歌凡几转，河低月落五更时。' },
  { title: '同武平一员外游湖五首时武贬金坛令 三', author: '储光羲', poem: '朝来仙阁听弦歌，暝入花亭见绮罗。\n池边命酒怜风月，浦口回船惜芰荷。' },
  { title: '同武平一员外游湖五首时武贬金坛令 四', author: '储光羲', poem: '朦胧竹影蔽岩扉，淡荡荷风飘舞衣。\n舟寻绿水宵将半，月隐青林人未归。' },
  { title: '同武平一员外游湖五首时武贬金坛令 五', author: '储光羲', poem: '花潭竹屿傍幽蹊，画檝浮空入夜溪。\n芰荷覆水船难进，歌舞留人月易低。' },
  { title: '题茅山华阳洞', author: '储光羲', poem: '华阳洞口片云飞，细雨蒙蒙欲湿衣。\n玉箫遍满仙坛上，应是茅家兄弟归。' },
  { title: '寄孙山人', author: '储光羲', poem: '新林二月孤舟还，水满清江花满山。\n借问故园隐君子，时时来往住人间。' },
  { title: '变行路难', author: '王昌龄', poem: '向晚横吹悲，风动马嘶合。\n前趋引旗节，千里阵云帀。\n单于下阴山，砂砾空飒飒。\n封侯取一战，岂复念闺合。' },
  { title: '塞下曲四首 一', author: '王昌龄', poem: '蝉鸣空桑林，八月萧关道。\n出塞入塞寒，处处黄芦草。\n从来幽幷客，皆共尘沙老。\n莫学游侠儿，矜夸紫骝好。' },
  { title: '塞下曲四首 二', author: '王昌龄', poem: '饮马渡秋水，水寒风似刀。\n平沙日未没，黯黯见临洮。\n昔日长城战，咸言意气高。\n黄尘足今古，白骨乱蓬蒿。' },
  { title: '塞下曲四首 三', author: '王昌龄', poem: '奉诏甘泉宫，总征天下兵。\n朝廷备礼出，郡国豫郊迎。\n纷纷几万人，去者无全生。\n臣愿节宫廐，分以赐边城。' },
  { title: '塞下曲四首 四', author: '王昌龄', poem: '边头何惨惨，已葬霍将军。\n部曲皆相吊，燕南代北闻。\n功勋多被黜，兵马亦寻分。\n更遣黄龙戍，唯当哭塞云。' },
  { title: '塞上曲', author: '王昌龄', poem: '秋风夜渡河，吹却鴈门桑。\n遥见胡地猎，鞲马宿严霜。\n五道分兵去，孤军百战场。\n功多翻下狱，士卒但心伤。' },
  { title: '从军行二首 一', author: '王昌龄', poem: '向夕临大荒，朔风轸归虑。\n平沙万里余，飞鸟宿何处？\n虏骑猎长原，翩翩傍河去。\n边声摇白草，海气生黄雾。\n百战苦风尘，十年履霜露。\n虽投定远笔，未坐将军树。\n早知行路难，悔不理章句。' },
  { title: '从军行二首 二', author: '王昌龄', poem: '秋草马蹄轻，角弓持弦急。\n去为龙城战，正值胡兵袭。\n军气横大荒，战酣日将入。\n长风金鼓动，白露铁衣湿。\n四起愁边声，南庭时伫立。\n断蓬孤自转，寒雁飞相及。\n万里云沙涨，平原冰霰涩。\n惟闻汉使还，独向刀环泣。' },
  { title: '少年行二首 一', author: '王昌龄', poem: '西陵侠少年，送客短长亭。\n青槐夹两道，白马如流星。\n闻道羽书急，单于寇井陉。\n气高轻赴难，谁顾燕山铭。' },
  { title: '少年行二首 二', author: '王昌龄', poem: '走马远相寻，西楼下夕阴。\n结交期一劒，留意赠千金。\n高阁歌声远，重门柳色深。\n夜阑须尽饮，莫负百年心。' },
  { title: '长歌行', author: '王昌龄', poem: '旷野饶悲风，飕飕黄蒿草。\n系马倚白杨，谁知我怀抱。\n所是同袍者，相逢尽衰老。\n北登汉家陵，南望长安道。\n下有枯树根，上有鼯鼠窠。\n高皇子孙尽，千载无人过。\n宝玉频发掘，精灵其奈何？\n人生须达命，有酒且长歌。' },
  { title: '悲哉行', author: '王昌龄', poem: '勿听白头吟，人间易忧怨。\n若非沧浪子，安得从所愿。\n北上太行山，临风阅吹万。\n长云数千里，倏忽还肤寸。\n观其微灭时，精意莫能论。\n百年不容息，是处生意蔓。\n始悟海上人，辞君永飞遯。' },
  { title: '古意', author: '王昌龄', poem: '桃花四面发，桃叶一枝开。\n欲暮黄鹂啭，伤心玉镜台。\n清筝向明月，半夜春风来。' },
  { title: '放歌行', author: '王昌龄', poem: '南渡洛阳津，西望十二楼。\n明堂坐天子，月朔朝诸侯。\n清乐动千门，皇风被九州。\n庆云从东来，泱漭抱日流。\n升平贵论道，文墨将何求？\n有诏征草泽，微诚将献谋。\n冠冕如星罗，拜揖曹与周。\n望尘非吾事，入赋且迟留。\n幸蒙国士识，因脱负薪裘。\n今者放歌行，以慰梁甫愁。\n但营数斗禄，奉养每丰羞。\n若得金膏遂，飞云亦何俦。' },
  { title: '越女', author: '王昌龄', poem: '越女作桂舟，还将桂为楫。\n湖上水渺漫，清江不可涉。\n摘取芙蓉花，莫摘芙蓉叶。\n将归问夫壻，颜色何如妾。' },
  { title: '郑县宿陶太公馆中赠冯六元二', author: '王昌龄', poem: '儒有轻王侯，脱略当事务。\n本家蓝田下，非为渔弋故。\n无何困躬耕，且欲驰永路。\n幽居与君近，出谷同所骛。\n昨日辞石门，五年变秋露。\n云龙未相感，干谒亦已屡。\n子为黄绶羁，余忝蓬山顾。\n京门望西岳，百里见郊树。\n飞雨祠上来，霭然关中暮。\n驱车郑城宿，秉烛论往素。\n山月出华阴，开此河渚雾。\n清光比故人，豁达展心晤。\n冯公尚戢翼，元子仍跼步。\n拂衣易为高，沦迹难有趣。\n张范善终始，吾等岂不慕。\n罢酒当凉风，屈伸备冥数。' },
  { title: '听弹风入松阕赠杨补阙', author: '王昌龄', poem: '商风入我弦，夜竹深有露。\n弦悲与林寂，清景不可度。\n寥落幽居心，飕飗青松树。\n松风吹草白，溪水寒日暮。\n声意去复还，九变待一顾。\n空山多雨雪，独立君始悟。' },
  { title: '缑氏尉沈兴宗置酒南谿留赠', author: '王昌龄', poem: '林色与溪古，深篁引幽翠。\n山尊在渔舟，棹月情已醉。\n始穷清源口，壑绝人境异。\n春泉滴空崖，萌草拆阴地。\n久之风榛寂，远闻樵声至。\n海雁时独飞，永然沧洲意。\n古时青冥客，灭迹沦一尉。\n吾子踌躇心，岂其纷埃事。\n缑峰信所克，济北余乃遂。\n齐物意已会，息肩理犹未。\n卷舒形性表，脱略贤哲议。\n仲月期角巾，饭僧嵩阳寺。' },
  { title: '为张僓赠阎使臣', author: '王昌龄', poem: '哀哀献玉人，楚国同悲辛。\n泣尽继以血，何由辨其真。\n赖承琢磨惠，复使光辉新。\n犹畏谗口疾，弃之如埃尘。' },
  { title: '赠史昭', author: '王昌龄', poem: '东林月未升，廓落星与汉。\n是夕鸿始来，斋中起长叹。\n怀哉望南浦，眇然夜将半。\n但有秋水声，愁使心神乱。\n握中何为赠，瑶草已衰散。\n海鳞未化时，各在天一岸。' },
  { title: '秋山寄陈谠言', author: '王昌龄', poem: '岩间寒事早，众山木已黄。\n北风何萧萧，兹夕露为霜。\n感激未能寐，中宵时慨慷。\n黄虫初悲鸣，玄鸟去我梁。\n独卧时易晚，离群情更伤。\n思君若不及，鸿雁今南翔。' },
  { title: '出郴山口至叠石湾野人室中寄张十一', author: '王昌龄', poem: '槠柟无冬春，柯叶连峰稠。\n阴壁下苍黑，烟含清江楼。\n景开独沿曳，响答随兴酬。\n旦夕望吾友，如何迅孤舟。\n叠沙积为岗，崩剥雨露幽。\n石脉尽横亘，潜潭何时流。\n既见万古色，颇尽一物由。\n永与世人远，气还草木收。\n盈缩理无余，今往何必忧。\n郴土群山高，耆老如中州。\n孰云议舛降，岂是娱宦游。\n阴火昔所伏，丹砂将尔谋。\n昨临苏耽井，复向衡阳求。\n同疚来相依，脱身当有筹。\n数月乃离居，风湍成阻修。\n野人善竹器，童子能谿讴。\n寒夜波荡漾，羇鸿去悠悠。' },
  { title: '宿灞上寄侍御玙弟', author: '王昌龄', poem: '独饮灞上亭，寒山青门外。\n长云骤落日，桑枣寂已晦。\n古人驱驰者，宿此凡几代。\n佐邑由东南，岂不知进退。\n吾宗秉全璞，楚得璆琳最。\n茅山就一征，柏署起三载。\n道契非物理，神交无留碍。\n知我沧溟心，脱略腐儒辈。\n孟冬銮舆出，阳谷群臣会。\n半夜驰道喧，五侯拥轩盖。\n是时燕齐客，献术蓬瀛内。\n甚悦我皇心，得与王母对。\n贱臣欲干谒，稽首期殒碎。\n哲弟感我情，问易穷否泰。\n良马足尚踠，宝刀光未淬。\n昨闻羽书飞，兵气连朔塞。\n诸将多失律，庙堂始追悔。\n安能召书生，愿得论要害。\n戎夷非草木，侵逐使狼狈。\n虽有屠城功，亦有降虏辈。\n兵粮如山积，恩泽如雨霈。\n羸卒不可兴，碛地无足爱。\n若用匹夫策，坐令军围溃。\n不费黄金资，宁求白璧赉。\n明主忧既远，边事亦可大。\n荷宠务推诚，离言深慷慨。\n霜摇直指草，烛引明光珮。\n公论日夕阻，朝廷磋跎会。\n孤城海门月，万里流光带。\n不应百尺松，空老钟山霭。' },
  { title: '次汝中寄河南陈赞府', author: '王昌龄', poem: '汝山方联延，伊水才明灭。\n遥见入楚云，又此空馆月。\n纷然驰梦想，不谓远离别。\n京邑多欢娱，衡湘𫏐沿越。\n明湖春草遍，秋桂白花发。\n岂惟长思君，日夕在魏阙。' },
  { title: '同从弟销南斋玩月忆山阴崔少府', author: '王昌龄', poem: '高卧南斋时，开帷月初吐。\n清辉淡水木，演漾在窗户。\n苒苒几盈虚，澄澄变今古。\n美人清江畔，是夜越吟苦。\n千里其如何，微风吹兰杜。' },
  { title: '代扶风主人答', author: '王昌龄', poem: '杀气凝不流，风悲日彩寒。\n浮埃起四远，游子弥不欢。\n依然宿扶风，沽酒聊自宽。\n寸心亦未理，长铗谁能弹。\n主人就我饮，对我还慨叹。\n便泣数行泪，因歌行路难。\n十五役边地，三回讨楼兰。\n连年不解甲，积日无所餐。\n将军降匈奴，国使没桑干。\n去时三十万，独自还长安。\n不信沙场苦，君看刀箭瘢。\n乡亲悉零落，冢墓亦摧残。\n仰攀青松枝，恸绝伤心肝。\n禽兽悲不去，路傍谁忍看。\n幸逢休明代，寰宇静波澜。\n老马思伏枥，长鸣力已殚。\n少年与运会，何事发悲端。\n天子初封禅，贤良刷羽翰。\n三边悉如此，否泰亦须观。' },
  { title: '酬鸿胪裴主簿雨后北楼见赠', author: '王昌龄', poem: '暮霞照新晴，归云犹相逐。\n有怀晨昏暇，想见登眺目。\n问礼侍彤襜，题诗访茅屋。\n高楼多古今，陈事满陵谷。\n地久微子封，台余孝王筑。\n裴回顾霄汉，豁达俯川陆。\n远水对孤城，长天向乔木。\n公门何清静，列戟森已肃。\n不叹携手稀，常思着鞭速。\n终当拂羽翰，轻举随鸿鹄。' },
  { title: '送任五之桂林', author: '王昌龄', poem: '楚客醉孤舟，越水将引棹。\n山为两乡别，月带千里貌。\n羇谴同缯纶，僻幽闻虎豹。\n桂林寒色在，苦节知所效。' },
  { title: '山中别庞十', author: '王昌龄', poem: '幽娟松筿径，月出寒蝉鸣。\n散发卧其下，谁知孤隐情。\n吟时白云合，钓处玄潭清。\n琼树方杳霭，凤兮保其贞。' },
  { title: '留别伊阙张少府郭大都尉', author: '王昌龄', poem: '迁客就一醉，主人空金罍。\n江湖青山底，欲去仍裴回。\n郭侯未相识，策马伊川来。\n把手相劝勉，不应老尘埃。\n孟阳逢山旧，仙馆留清才。\n日晚劝趣别，风长云逐开。\n幸随板舆远，负谴何忧哉。\n唯有仗忠信，音书报云雷。' },
  { title: '送韦十二兵曹', author: '王昌龄', poem: '县职如长缨，终日检我身。\n平明趋郡府，不得展故人。\n故人念江湖，富贵如埃尘。\n迹在戎府掾，心游天台春。\n独立浦边鹤，白云长相亲。\n南风忽至吴，分散还入秦。\n寒夜天光白，海净月色真。\n对坐论岁暮，弦悲岂无因。\n平生驰驱分，非谓桮酒仁。\n出处两不合，忠贞何由伸。\n看君孤舟去，且欲歌垂纶。' },
  { title: '东京府县诸公与綦毋潜李颀相送至白马寺宿', author: '王昌龄', poem: '鞍马上东门，裴回入孤舟。\n贤豪相追送，即櫂千里流。\n赤岸落日在，空波微烟收。\n薄宦忘机括，醉来即淹留。\n月明见古寺，林外登高楼。\n南风开长廊，夏夜如凉秋。\n江月照吴县，西归梦中游。' },
  { title: '送东林廉上人归庐山', author: '王昌龄', poem: '石溪流已乱，苔径人渐微。\n日暮东林下，山僧还独归。\n昔为庐峰意，况与远公违。\n道性深寂寞，世情多是非。\n会寻名山去，岂复望清辉。' },
  { title: '留别武陵袁丞', author: '王昌龄', poem: '皇恩暂迁谪，待罪逢知己。\n从此武陵溪，孤舟二千里。\n桃花遗古岸，金涧流春水。\n谁识马将军，忠贞抱生死。' },
  { title: '别刘谞', author: '王昌龄', poem: '天地寒更雨，苍茫楚城阴。\n一尊广陵酒，十载衡阳心。\n倚仗不可料，悲欢岂易寻。\n相逢成远别，后会何如今。\n身在江海上，云连京国深。\n行当务功业，策马何骎骎。' },
  { title: '岳阳别李十七越宾', author: '王昌龄', poem: '相逢楚水寒，舟在洞庭驿。\n具陈江波事，不异沦弃迹。\n杉上秋雨声，悲切蒹葭夕。\n弹琴收余响，来送千里客。\n平明孤帆心，岁晚济代策。\n时在身未充，潇湘不盈画。\n湖小洲渚联，澹淡烟景碧。\n鱼鳖自有性，龟龙无能易。\n谴黜同所安，风土任所适。\n闭门观玄化，携手遗损益。' },
  { title: '留别岑参兄弟', author: '王昌龄', poem: '江城建业楼，山尽沧海头。\n副职守兹县，东南櫂孤舟。\n长安故人宅，秣马经前秋。\n便以风雪暮，还为纵饮留。\n貂蝉七叶贵，鸿鹄万里游。\n何必念钟鼎，所在烹肥牛。\n为君啸一曲，且莫弹箜篌。\n徒见枯者艳，谁言直如钩。\n岑家双琼树，腾光难为俦。\n谁言青门悲，俯期吴山幽。\n日西石门峤，月吐金陵洲。\n追随探灵怪，岂不骄王侯。' },
  { title: '送刘眘虚归取宏词解', author: '王昌龄', poem: '太清闻海鹤，游子引乡眄。\n声随羽仪远，势与归云便。\n青桂春再荣，白云暮来变。\n迁飞在礼仪，岂复泪如霰。' },
  { title: '巴陵别刘处士', author: '王昌龄', poem: '刘生隐岳阳，心远洞庭水。\n偃帆入山郭，一宿楚云里。\n竹映秋馆深，月寒江风起。\n烟波桂阳接，日夕数千里。\n袅袅清夜猿，孤舟坐如此。\n湘中有来鴈，雨雪候音旨。' },
  { title: '宿裴氏山庄', author: '王昌龄', poem: '苍苍竹林暮，吾亦知所投。\n静坐山斋月，清溪闻远流。\n西峰下微雨，向晓白云收。\n遂解尘中组，终南春可游。' },
  { title: '淇上酬薛据兼寄郭微', author: '王昌龄', poem: '自从别京华，我心乃萧索。\n十年守章句，万里空寥落。\n北上登蓟门，茫茫见沙漠。\n倚劒对风尘，慨然思衞霍。\n拂衣去燕赵，驱马怅不乐。\n天长沧洲路，日暮邯郸郭。\n酒肆或淹留，渔泽屡栖泊。\n独行备艰难，孰辞千鼎镬。\n皇情念淳古，时俗何浮薄。\n理道须任贤，安人在求瘼。\n故交负奇才，逸气包謇谔。\n隐轸经济策，纵横建安作。\n才望忽先鸣，风期无宿诺。\n飘飖劳州县，迢递限言谑。\n东驰眇贝丘，西顾弥虢略。\n淇水徒自深，浮云不堪托。\n吾谋适可用，天道岂辽廓。\n不然买山田，一身与耕凿。' },
  { title: '咏史', author: '王昌龄', poem: '荷畚至洛阳，杖策游北门。\n天下尽兵甲，豺狼满中原。\n明夷方遘患，顾我徒崩犇。\n自慙菲薄才，误蒙国士恩。\n位重任亦重，时危志弥敦。\n西北未及终，东南不可吞。\n进则耻保躬，退乃为触藩。\n叹息嵩山老，而后知其尊。' },
  { title: '杂兴', author: '王昌龄', poem: '握中铜匕首，粉剉楚山铁。\n义士频报雠，杀人不曾缺。\n可悲燕丹事，终被狼虎灭。\n一举无两全，荆轲遂为血。\n诚知匹夫勇，何取万人杰。\n无道吞诸侯，坐见九州裂。' },
  { title: '秋兴', author: '王昌龄', poem: '日暮西北堂，凉风洗修木。\n著书在南窗，门馆常肃肃。\n苔草延古意，视听转幽独。\n或问余所营，刈黍就寒谷。' },
  { title: '斋心', author: '王昌龄', poem: '女萝覆石壁，溪水幽蒙胧。\n紫葛蔓黄花，娟娟寒露中。\n朝饮花上露，夜卧松下风。\n云英化为水，光采与我同。\n日月荡精魄，寥寥天宇空。' },
  { title: '独游', author: '王昌龄', poem: '林卧情每闲，独游景常晏。\n时从灞陵下，垂钓往南涧。\n手携双鲤鱼，目送千里鴈。\n悟彼飞有适，知此罹忧患。\n放之清冷泉，因得省疎慢。\n永怀青岑客，廻首白云间。\n神超物无违，岂系名与宦。' },
  { title: '香积寺礼拜万廻平等二圣僧塔', author: '王昌龄', poem: '真无御化来，借有乘化归。\n如彼双塔内，孰能知是非。\n愚也骇苍生，圣哉为帝师。\n当为时世出，不由天地资。\n万廻主此方，平等性无违。\n今我一礼心，亿劫同不移。\n肃肃松柏下，诸天来有时。' },
  { title: '就道士问周易参同契', author: '王昌龄', poem: '仙人骑白鹿，发短耳何长。\n时余采菖蒲，忽见嵩之阳。\n稽首求丹经，乃出怀中方。\n披读了不悟，归来问嵇康。\n嗟余无道骨，发我入太行。' },
  { title: '诸官游招隐寺', author: '王昌龄', poem: '山馆人已空，青萝换风雨。\n自从永明世，月向龙宫吐。\n凿井长幽泉，白云今如古。\n应真坐松柏，锡杖挂窗户。\n口云七十余，能救诸有苦。\n回指岩树花，如闻道场鼓。\n金色身壤灭，真如性无主。\n僚友同一心，清光遣谁取。' },
  { title: '宴南亭', author: '王昌龄', poem: '寒江暎村林，亭上纳鲜洁。\n楚客共闲饮，静坐金管阕。\n酣竟日入山，暝来云归穴。\n城楼空杳霭，猿鸟备清切。\n物状如丝纶，上心为予决。\n访君东溪事，早晚樵路绝。' },
  { title: '何九于客舍集', author: '王昌龄', poem: '客有住桂阳，亦如巢林鸟。\n罍觞且终宴，功业曾未了。\n山月空霁时，江明高楼晓。\n门前泊舟檝，行次入松筿。\n此意投赠君，沧波风褭褭。' },
  { title: '洛阳尉刘晏与府掾诸公茶集天宫寺岸道上人房', author: '王昌龄', poem: '良友呼我宿，月明悬天宫。\n道安风尘外，洒扫青林中。\n削去府县理，豁然神机空。\n自从三湘还，始得今夕同。\n旧居太行北，远宦沧溟东。\n各有四方事，白云处处通。' },
  { title: '观江淮名胜图', author: '王昌龄', poem: '刻意吟云山，尤知隐沦妙。\n远公何为者，再诣临海峤。\n而我高其风，披图得遗照。\n援毫无逃境，遂展千里眺。\n淡扫荆门烟，明标赤城烧。\n青葱林间岭，隐见淮海徼。\n但指香炉顶，无闻白猿啸。\n沙门既云灭，独往岂殊调。\n感对怀拂衣，胡宁事渔钓。\n安期始遗舃，千古谢荣耀。\n投迹庶可齐，沧浪有孤棹。' },
  { title: '灞上闲居', author: '王昌龄', poem: '鸿都有归客，偃卧滋阳村。\n轩冕无枉顾，清川照我门。\n空林网夕阳，寒鸟赴荒园。\n廓落时得意，怀哉莫与言。\n庭前有孤鹤，欲啄常翩翻。\n为我衔素书，吊彼颜与原。\n二君既不朽，所以慰其魂。' },
  { title: '风凉原上作', author: '王昌龄', poem: '阴岑宿云归，烟雾湿松柏。\n风凄日初晓，下岭望川泽。\n远山无晦明，秋水千里白。\n佳气盘未央，圣人在凝碧。\n关门阻天下，信是帝王宅。\n海内方晏然，庙堂有奇策。\n时贞守全运，罢去游说客。\n予忝兰台人，幽寻免贻责。' },
  { title: '裴六书堂', author: '王昌龄', poem: '闲堂闭空阴，竹林但清响。\n窗下长啸客，区中无遗想。\n经纶精微言，兼济当独往。' },
  { title: '江上闻笛', author: '王昌龄', poem: '横笛怨江月，扁舟何处寻。\n声长楚山外，曲绕胡关深。\n相去万余里，遥传此夜心。\n寥寥浦溆寒，响尽惟幽林。\n不知谁家子，复奏邯郸音。\n水客皆拥棹，空霜遂盈襟。\n羸马望北走，迁人悲越吟。\n何当边草白，旌节陇城阴。' },
  { title: '太湖秋夕', author: '王昌龄', poem: '水宿烟雨寒，洞庭霜落微。\n月明移舟去，夜静魂梦归。\n暗觉海风度，萧萧闻鴈飞。' },
  { title: '赵十四兄见访', author: '王昌龄', poem: '客来舒长簟，开合延清风。\n但有无弦琴，共君尽尊中。\n晚来常读易，顷者欲还嵩。\n世事何须道，黄精且养蒙。\n嵇康殊寡识，张翰独知终。\n忽忆鲈鱼鲙，扁舟往江东。' },
  { title: '过华阴', author: '王昌龄', poem: '云起太华山，云山互明灭。\n东峰始含景，了了见松雪。\n羇人感幽栖，窅暎转奇绝。\n欣然忘所疲，永望吟不辍。\n信宿百余里，出关玩新月。\n何意昨来心，遇物遂迁别。\n人生屡如此，何以肆愉悦。' },
  { title: '九江口作', author: '王昌龄', poem: '漭漭江势阔，雨开浔阳秋。\n驿门是高岸，望尽黄芦洲。\n水与五谿合，心期万里游。\n明时无弃才，谪去随孤舟。\n鸷鸟立寒木，丈夫佩吴钩。\n何当报君恩，却系单于头。' },
  { title: '大梁途中作', author: '王昌龄', poem: '怏怏步长道，客行渺无端。\n郊原欲下雪，天地棱棱寒。\n当时每酣醉，不觉行路难。\n今日无酒钱，凄惶向谁叹。' },
  { title: '途中作', author: '王昌龄', poem: '游人愁岁晏，早起遵王畿。\n坠叶吹未晓，疎林月微微。\n惊禽栖不定，寒兽相因依。\n叹此霜露下，复闻鸿雁飞。\n渺然江南意，惜与中途违。\n羇旅悲壮发，别离念征衣。\n永图岂劳止，明节期所归。\n宁厌楚山曲，无人长掩扉。' },
  { title: '山行入泾州', author: '王昌龄', poem: '倦此山路长，停骖问宾御。\n林峦信回惑，白日落何处。\n徙倚望长风，滔滔引归虑。\n微雨随云收，蒙蒙傍山去。\n西临有边邑，北走尽亭戍。\n泾水横白烟，州城隐寒树。\n所嗟异风俗，已自少情趣。\n岂伊怀土多，触目忻所遇。' },
  { title: '小敷谷龙潭祠作', author: '王昌龄', poem: '崖谷歕疾流，地中有雷集。\n百泉势相荡，巨石皆却立。\n跳波沸峥嵘，深处不可挹。\n昏为蛟龙怒，清见云雨入。\n灵怪祟偏祠，废兴自兹邑。\n沈淫顷多昧，檐宇遂不葺。\n吾闻被明典，盛德惟世及。\n生人载山川，血食报原隰。\n岂伊骇微险，将以循甿揖。\n口飞振吕梁，忠信亦我习。\n波流浸已广，悔吝在所汲。\n谿水有清源，褰裳靡沾湿。' },
  { title: '段宥廰孤桐', author: '王昌龄', poem: '凤皇所宿处，月暎孤桐寒。\n槁叶零落尽，空柯苍翠残。\n虚心谁能见，直影非无端。\n响发调尚苦，清商劳一弹。' },
  { title: '琴', author: '王昌龄', poem: '孤桐秘虚鸣，朴素传幽真。\n髣髴弦指外，遂见初古人。\n意远风雪苦，时来江山春。\n高宴未终曲，谁能辨经纶。' },
  { title: '初日', author: '王昌龄', poem: '初日净金闺，先照床前暖。\n斜光入罗幕，稍稍亲丝管。\n云发不能梳，杨花更吹满。' },
  { title: '失题', author: '王昌龄', poem: '奸雄乃得志，遂使群心摇。\n赤风荡中原，烈火无遗巢。\n一人计不用，万里空萧条。' },
  { title: '赠宇文中丞', author: '王昌龄', poem: '仆本濩落人，辱当州郡使。\n量力颇及早，谢归今即已。\n萧萧若凌虚，衿带顷消靡。\n车服卒然来，涔阳作游子。\n郁郁寡开颜，默默独行李。\n忽逢平生友，一笑方在此。\n秋清宁风日，楚思浩云水。\n为语弋林者，冥冥鸿远矣。' },
  { title: '箜篌引', author: '王昌龄', poem: '卢谿郡南夜泊舟，夜闻两岸羌戎讴。\n其时月黑猿啾啾，微雨沾衣令人愁。\n有一迁客登高楼，不言不寐弹箜篌。\n弹作蓟门桑叶秋，风沙飒飒青冢头。\n将军铁骢汗血流，深入匈奴战未休。\n黄旗一点兵马收，乱杀胡人积如丘。\n疮病驱来配边州，仍披漠北羔羊裘。\n颜色饥枯掩面羞，眼眶泪滴深两眸。\n思还本乡食牦牛，欲语不得指咽喉。\n或有强壮能吚嚘，意说被他边将雠。\n五世属藩汉主留，碧毛毡帐河曲游。\n橐𫘞五万部落稠，勅赐飞凤金兜鍪。\n为君百战如过筹，静扫阴山无鸟投。\n家藏铁券特承优，黄金千斤不称求。\n九族分离作楚囚，深谿寂寞弦苦幽。\n草木悲感声飕飗，仆本东山为国忧。\n明光殿前论九畴，簏读兵书尽冥搜。\n为君掌上施权谋，洞晓山川无与俦。\n紫宸诏发远怀柔，摇笔飞霜如夺钩。\n鬼神不得知其由，怜爱苍生比蚍蜉。\n朔河屯兵须渐抽，尽遣降来拜御沟。' },
  { title: '乌栖曲', author: '王昌龄', poem: '白马逐朱车，黄昏入狭邪。\n柳树乌争宿，争枝未得飞上屋。\n东房少妇壻从军，每听乌啼知夜分。' },
  { title: '城傍曲', author: '王昌龄', poem: '秋风鸣桑条，草白狐兔骄。\n邯郸饮来酒未消，城北原平掣皂雕。\n射杀空营两腾虎，廻身却月佩弓弰。' },
  { title: '行路难', author: '王昌龄', poem: '双丝作绠系银瓶，百尺寒泉辘轳上。\n悬丝一绝不可望，似妾倾心在君掌。\n人生意气好迁捐，只重狂花不重贤。\n宴罢调筝奏离鹤，廻娇转盼泣君前。\n君不见眼前事，岂保须臾心勿异。\n西山日下雨足稀，侧有浮云无所寄。\n但愿莫忘前者言，剉骨黄尘亦无愧。\n行路难，劝君酒，莫辞烦，美酒千钟犹可尽，心中片愧何可论。\n一闻汉主思故剑，使妾长嗟万古魂。' },
  { title: '奉赠张荆州', author: '王昌龄', poem: '祝融之峰紫云衔，翠如何其雪崭嵓。\n邑西有路缘石壁，我欲从之卧穹嵌。\n鱼有心兮脱网罟，江无人兮鸣枫杉。\n王君飞舄仍未去，苏耽宅中意遥缄。' },
  { title: '驾出长安', author: '王昌龄', poem: '圣德超千古，皇风扇九围。\n天廻万象出，驾动六龙飞。\n淑气来黄道，祥云覆紫微。\n太平多扈从，文物有光辉。' },
  { title: '驾幸河东', author: '王昌龄', poem: '晋水千庐合，汾桥万国从。\n开唐天业盛，入沛圣恩浓。\n下辇廻三象，题碑任六龙。\n睿明悬日月，千岁此时逢。' },
  { title: '胡笳曲', author: '王昌龄', poem: '城南虏已合，一夜几重围。\n自有金笳引，能沾出塞衣。\n听临关月苦，清入海风微。\n三奏高楼晓，胡人掩涕归。' },
  { title: '潞府客亭寄崔凤童', author: '王昌龄', poem: '萧条郡城闭，旅馆空寒烟。\n秋月对愁客，山钟摇暮天。\n新知偶相访，斗酒情依然。\n一宿阻长会，清风徒满川。' },
  { title: '和振上人秋夜怀士会', author: '王昌龄', poem: '白露伤草木，山风吹夜寒。\n遥林梦亲友，高兴发云端。\n郭外秋声急，城边月色残。\n瑶琴多远思，更为客中弹。' },
  { title: '送李擢游江东', author: '王昌龄', poem: '清洛日夜涨，微风引孤舟。\n离肠便千里，远梦生江楼。\n楚国橙橘暗，吴门烟雨愁。\n东南具今古，归望山云秋。' },
  { title: '沙苑南渡头', author: '王昌龄', poem: '秋雾连云白，归心浦溆悬。\n津人空守缆，村馆复临川。\n篷隔苍茫雨，波连演漾田。' },
  { title: '客广陵', author: '王昌龄', poem: '楼头广陵近，九月在南徐。\n秋色明海县，寒烟生里闾。\n夜帆归楚客，昨日度江书。\n为问易名叟，垂纶不见鱼。' },
  { title: '静法师东斋', author: '王昌龄', poem: '筑室在人境，遂得真隐情。\n春尽草木变，雨来池馆清。\n琴书全雅道，视听已无生。\n闭户脱三界，白云自虚盈。' },
  { title: '素上人影塔', author: '王昌龄', poem: '物化同枯木，希夷明月珠。\n本来生灭尽，何者是虚无。\n一坐看如故，千龄独向隅。\n至人非别有，方外不应殊。' },
  { title: '遇薛明府谒聪上人', author: '王昌龄', poem: '欣逢柏梁故，共谒聪公禅。\n石室无人到，绳床见虎眠。\n阴崖常抱雪，枯涧为生泉。\n出处虽云异，同欢在法筵。' },
  { title: '谒焦炼师', author: '王昌龄', poem: '中峰青苔壁，一点云生时。\n岂意石堂里，得逢焦炼师。\n炉香净琴案，松影闲瑶墀。\n拜受长年药，翩翻西海期。' },
  { title: '宿京江口期刘昚虚不至', author: '王昌龄', poem: '霜天起长望，残月生海门。\n风静夜潮满，城高寒气昏。\n故人何寂寞，久已乖清言。\n明发不能寐，徒盈江上尊。' },
  { title: '寒食即事', author: '王昌龄', poem: '晋阳寒食地，风俗旧来传。\n雨灭龙蛇火，春生鸿雁天。\n泣多流水涨，歌发舞云旋。\n西见之推庙，空为人所怜。' },
  { title: '九日登高', author: '王昌龄', poem: '青山远近带皇州，霁景重阳上北楼。\n雨歇亭臯仙菊润，霜飞天苑御梨秋。\n茱萸插鬓花宜寿，翡翠横钗舞作愁。\n谩说陶潜篱下醉，何曾得见此风流。' },
  { title: '万岁楼', author: '王昌龄', poem: '江上巍巍万岁楼，不知经历几千秋。\n年年喜见山长在，日日悲看水独流。\n猿狖何曾离暮岭，鸬鹚空自泛寒洲。\n谁堪登望云烟里，向晚茫茫发旅愁。' },
  { title: '夏月花萼楼酺宴应制', author: '王昌龄', poem: '土德三元正，尧心万国同。\n汾阴备冬礼，长乐应和风。\n赐庆垂天泽，流欢旧渚宫。\n楼台生海上，箫鼓出天中。\n雾晓筵初接，宵长曲未终。\n雨随青幕合，月照舞罗空。\n玉陛分朝列，文章发圣聪。\n愚臣忝书赋，歌咏颂丝桐。' },
  { title: '送欧阳会稽之任', author: '王昌龄', poem: '怀禄贵心赏，东流山水长。\n官移会稽郡，地迩上虞乡。\n缓带屏纷杂，渔舟临讼堂。\n逶迤回谿趣，猿啸飞鸟行。\n万室霁朝雨，千峰迎夕阳。\n辉辉远洲暎，暧暧澄湖光。\n白发有高士，青春期上皇。\n应须枉车歇，为我访荷裳。' },
  { title: '同王维集青龙寺昙壁上人兄院五韵', author: '王昌龄', poem: '本来清净所，竹树引幽阴。\n檐外含山翠，人间出世心。\n圆通无有象，圣境不能侵。\n真是吾兄法，何妨友弟深。\n天香自然会，灵异识钟音。' },
  { title: '东谿玩月', author: '王昌龄', poem: '月从断山口，遥吐柴门端。\n万木分空霁，流阴中夜攒。\n光连虚象白，气与风露寒。\n谷静秋泉响，岩深青霭残。\n澄清入幽梦，破影抱空峦。\n恍惚琴窗里，松谿晓思难。' },
  { title: '朝来曲', author: '王昌龄', poem: '月昃鸣珂动，花连绣户春。\n盘龙玉台镜，唯待画眉人。' },
  { title: '从军行', author: '王昌龄', poem: '大将军出战，白日暗榆关。\n三面黄金甲，单于破胆还。' },
  { title: '答武陵田太守', author: '王昌龄', poem: '仗劒行千里，微躯感一言。\n曾为大梁客，不负信陵恩。' },
  { title: '题灞池二首 一', author: '王昌龄', poem: '腰镰欲何之，东园刈秋韭。\n世事不复论，悲歌和樵叟。' },
  { title: '题灞池二首 二', author: '王昌龄', poem: '开门望长川，薄暮见渔者。\n借问白头翁，垂纶几年也。' },
  { title: '题僧房', author: '王昌龄', poem: '椶榈花满院，苔藓入闲房。\n彼此名言绝，空中闻异香。' },
  { title: '击磬老人', author: '王昌龄', poem: '双峰褐衣久，一磬白眉长。\n谁识野人意，徒看春草芳。' },
  { title: '送胡大', author: '王昌龄', poem: '荆门不堪别，况乃潇湘秋。\n何处遥望君，江边明月楼。' },
  { title: '送郭司仓', author: '王昌龄', poem: '暎门淮水绿，留骑主人心。\n明月随良掾，春潮夜夜深。' },
  { title: '送李十五', author: '王昌龄', poem: '怨别秦楚深，江中秋云起。\n天长杳无隔，月影在寒水。' },
  { title: '送张四', author: '王昌龄', poem: '枫林已愁暮，楚水复堪悲。\n别后冷山月，清猿无断时。' },
  { title: '武陵田太守席送司马卢谿', author: '王昌龄', poem: '诸侯分楚郡，饮饯五谿春。\n山水清晖远，俱怜一逐臣。' },
  { title: '送谭八之桂林', author: '王昌龄', poem: '客心仍在楚，江馆复临湘。\n别意猿鸟外，天寒桂水长。' },
  { title: '送刘十五之郡', author: '王昌龄', poem: '平明江雾寒，客马江上发。\n扁舟事洛阳，窅窅含楚月。' },
  { title: '从军行七首 一', author: '王昌龄', poem: '烽火城西百尺楼，黄昏独上海风秋。\n更吹羌笛关山月，无那金闺万里愁。' },
  { title: '从军行七首 二', author: '王昌龄', poem: '琵琶起舞换新声，总是关山旧别情。\n撩乱边愁听不尽，高高秋月照长城。' },
  { title: '从军行七首 三', author: '王昌龄', poem: '关城榆叶早疎黄，日暮云沙古战场。\n表请回军掩尘骨，莫教兵士哭龙荒。' },
  { title: '从军行七首 四', author: '王昌龄', poem: '青海长云暗雪山，孤城遥望玉门关。\n黄沙百战穿金甲，不破楼兰终不还。' },
  { title: '从军行七首 五', author: '王昌龄', poem: '大漠风尘日色昏，红旗半卷出辕门。\n前军夜战洮河北，已报生擒吐谷浑。' },
  { title: '从军行七首 六', author: '王昌龄', poem: '胡瓶落膊紫薄汗，碎叶城西秋月团。\n明敕星驰封宝劒，辞君一夜取楼兰。' },
  { title: '从军行七首 七', author: '王昌龄', poem: '玉门山嶂几千重，山北山南总是烽。\n人依远戍须看火，马踏深山不见踪。' },
  { title: '出塞二首 一', author: '王昌龄', poem: '秦时明月汉时关，万里长征人未还。\n但使龙城飞将在，不教胡马度阴山。' },
  { title: '出塞二首 二', author: '王昌龄', poem: '骝马新跨白玉鞍，战罢沙场月色寒。\n城头铁鼓声犹振，匣里金刀血未干。' },
  { title: '采莲曲二首 一', author: '王昌龄', poem: '吴姬越艳楚王妃，争弄莲舟水湿衣。\n来时浦口花迎入，采罢江头月送归。' },
  { title: '采莲曲二首 二', author: '王昌龄', poem: '荷叶罗裙一色裁，芙蓉向脸两边开。\n乱入池中看不见，闻歌始觉有人来。' },
  { title: '殿前曲二首 一', author: '王昌龄', poem: '贵人妆梳殿前催，香风吹入殿后来。\n仗引笙歌大宛马，白莲花发照池台。' },
  { title: '殿前曲二首 二', author: '王昌龄', poem: '胡部笙歌西殿头，梨园弟子和凉州。\n新声一段高楼月，圣主千秋乐未休。' },
  { title: '春宫曲', author: '王昌龄', poem: '昨夜风开露井桃，未央前殿月轮高。\n平阳歌舞新承宠，帘外春寒赐锦袍。' },
  { title: '西宫春怨', author: '王昌龄', poem: '西宫夜静百花香，欲卷珠帘春恨长。\n斜抱云和深见月，朦胧树色隐昭阳。' },
  { title: '西宫秋怨', author: '王昌龄', poem: '芙蓉不及美人妆，水殿风来珠翠香。\n谁分含啼掩秋扇，空悬明月待君王。' },
  { title: '长信秋词五首 一', author: '王昌龄', poem: '金井梧桐秋叶黄，珠帘不卷夜来霜。\n熏笼玉枕无颜色，卧听南宫清漏长。' },
  { title: '长信秋词五首 二', author: '王昌龄', poem: '高殿秋砧响夜阑，霜深犹忆御衣寒。\n银灯青琐裁缝歇，还向金城明主看。' },
  { title: '长信秋词五首 三', author: '王昌龄', poem: '奉帚平明金殿开，且将团扇暂裴回。\n玉颜不及寒鸦色，犹带[昭]阳日影来。' },
  { title: '长信秋词五首 四', author: '王昌龄', poem: '真成薄命久寻思，梦见君王觉后疑。\n火照西宫知夜饮，分明复道奉恩时。' },
  { title: '长信秋词五首 五', author: '王昌龄', poem: '长信宫中秋月明，昭阳殿下捣衣声。\n白露堂中细草迹，红罗帐里不胜情。' },
  { title: '青楼曲二首 一', author: '王昌龄', poem: '白马金鞍从武皇，旌旗十万宿长杨。\n楼头小妇鸣筝坐，遥见飞尘入建章。' },
  { title: '青楼曲二首 二', author: '王昌龄', poem: '驰道杨花满御沟，红妆缦绾上青楼。\n金章紫绶千余骑，夫壻朝回初拜侯。' },
  { title: '青楼怨', author: '王昌龄', poem: '香帏风动花入楼，高调鸣筝缓夜愁。\n肠断关山不解说，依依残月下帘钩。' },
  { title: '浣纱女', author: '王昌龄', poem: '钱塘江边是谁家，江上女儿全胜花。\n吴王在时不得出，今日公然来浣纱。' },
  { title: '闺怨', author: '王昌龄', poem: '闺中少妇不曾愁，春日凝妆上翠楼。\n忽见陌头杨柳色，悔教夫壻觅封侯。' },
  { title: '甘泉歌', author: '王昌龄', poem: '乘舆执玉已登坛，细草沾衣春殿寒。\n昨夜云生拜初月，万年甘露水晶盘。' },
  { title: '萧驸马宅花烛', author: '王昌龄', poem: '青鸾飞入合欢宫，紫凤衔花出禁中。\n可怜今夜千门里，银汉星回一道通。' },
  { title: '观猎', author: '王昌龄', poem: '角鹰初下秋草稀，铁骢抛鞚去如飞。\n少年猎得平原兔，马后横捎意气归。' },
  { title: '寄穆侍御出幽州', author: '王昌龄', poem: '一从恩谴度潇湘，塞北江南万里长。\n莫道蓟门书信少，鴈飞犹得到衡阳。' },
  { title: '寄陶副使', author: '王昌龄', poem: '闻道将军破海门，如何远谪渡湘沅。\n春来明主封西岳，自有还君紫绶恩。' },
  { title: '至南陵答皇甫岳', author: '王昌龄', poem: '与君同病复漂沦，昨夜宣城别故人。\n明主恩深非岁久，长江还共五谿滨。' },
  { title: '西江寄越弟', author: '王昌龄', poem: '南浦逢君岭外还，沅谿更远洞庭山。\n尧时恩泽如春雨，梦里相逢同入关。' },
  { title: '李四仓曹宅夜饮', author: '王昌龄', poem: '霜天留后故情欢，银烛金炉夜不寒。\n欲问吴江别来意，青山明月梦中看。' },
  { title: '宴春源', author: '王昌龄', poem: '源向春城花几重，江明深翠引诸峰。\n与君醉失松溪路，山馆寥寥传暝钟。' },
  { title: '龙标野宴', author: '王昌龄', poem: '沅溪夏晚足凉风，春酒相携就竹丛。\n莫道弦歌愁远谪，青山明月不曾空。' },
  { title: '听流人水调子', author: '王昌龄', poem: '孤舟微月对枫林，分付鸣筝与客心。\n岭色千重万重雨，断弦收与泪痕深。' },
  { title: '梁苑', author: '王昌龄', poem: '梁园秋竹古时烟，城外风悲欲暮天。\n万乘旌旗何处在？平台宾客有谁怜。' },
  { title: '武陵龙兴观黄道士房问易因题', author: '王昌龄', poem: '斋心问易太阳宫，八卦真形一气中。\n仙老言余鹤飞去，玉清坛上雨蒙蒙。' },
  { title: '送魏二', author: '王昌龄', poem: '醉别江楼橘柚香，江风引雨入舟凉。\n忆君遥在潇湘月，愁听清猿梦里长。' },
  { title: '别李浦之京', author: '王昌龄', poem: '故园今在灞陵西，江畔逢君醉不迷。\n小弟邻庄尚渔猎，一封书寄数行啼。' },
  { title: '送狄宗亨', author: '王昌龄', poem: '秋在水清山暮蝉，洛阳树色鸣臯烟。\n送君归去愁不尽，又惜空度凉风天。' },
  { title: '送薛大赴安陆', author: '王昌龄', poem: '津头云雨暗湘山，迁客离忧楚地颜。\n遥送扁舟安陆郡，天边何处穆陵关。' },
  { title: '芙蓉楼送辛渐二首 一', author: '王昌龄', poem: '寒雨连天夜入湖，平明送客楚山孤。\n洛阳亲友如相问，一片冰心在玉壶。' },
  { title: '芙蓉楼送辛渐二首 二', author: '王昌龄', poem: '丹阳城南秋海阴，丹阳城北楚云深。\n高楼送客不能醉，寂寂寒江明月心。' },
  { title: '重别李评事', author: '王昌龄', poem: '莫道秋江离别难，舟船明日是长安。\n吴姬缓舞留君醉，随意青枫白露寒。' },
  { title: '别陶副使归南海', author: '王昌龄', poem: '南越归人梦海楼，广陵新月海亭秋。\n宝刀留赠长相忆，当取戈船万户侯。' },
  { title: '送人归江夏', author: '王昌龄', poem: '寒江绿水楚云深，莫道离忧迁远心。\n晓夕双帆归鄂渚，愁将孤月梦中寻。' },
  { title: '送李五', author: '王昌龄', poem: '玉盌金罍倾送君，江西日入起黄云。\n扁舟乘月暂来去，谁道沧浪吴楚分。' },
  { title: '送十五舅', author: '王昌龄', poem: '深林秋水近日空，归棹演漾清阴中。\n夕浦离觞意何已，草根寒露悲鸣虫。' },
  { title: '留别郭八', author: '王昌龄', poem: '长亭驻马未能前，井邑苍茫含暮烟。\n醉别何须更惆怅，回头不语但垂鞭。' },
  { title: '送窦七', author: '王昌龄', poem: '清江月色傍林秋，波上荧荧望一舟。\n鄂渚轻帆须早发，江边明月为君留。' },
  { title: '巴陵送李十二', author: '王昌龄', poem: '摇曳巴陵洲渚分，清江传语便风闻。\n山长不见秋城色，日暮蒹葭空水云。' },
  { title: '送裴图南', author: '王昌龄', poem: '黄河渡头归问津，离家几日茱萸新。\n漫道闺中飞破镜，犹看陌上别行人。' },
  { title: '留别司马太守', author: '王昌龄', poem: '辰阳太守念王孙，远谪沅谿何可论。\n黄鹤青云当一举，明珠吐着抱君恩。' },
  { title: '卢溪主人', author: '王昌龄', poem: '武陵溪口驻扁舟，溪水随君向北流。\n行到荆门上三峡，莫将孤月对猿愁。' },
  { title: '送程六', author: '王昌龄', poem: '冬夜伤离在五溪，青鱼雪落鲙橙虀。\n武冈前路看斜月，片片舟中云向西。' },
  { title: '送朱越', author: '王昌龄', poem: '远别舟中蒋山暮，君行举首燕城路。\n蓟门秋月隐黄云，期向金陵醉江树。' },
  { title: '别辛渐', author: '王昌龄', poem: '别馆萧条风雨寒，扁舟月色渡江看。\n酒酣不识关西道，却望春江云尚残。' },
  { title: '送柴侍御', author: '王昌龄', poem: '流水通波接武冈，送君不觉有离伤。\n青山一道同云雨，眀月何曽是两乡。' },
  { title: '送万大归长沙', author: '王昌龄', poem: '桂阳秋水长沙县，楚竹离声为君变。\n青山隐隐孤舟微，白鹤双飞忽相见。' },
  { title: '送吴十九往沅陵', author: '王昌龄', poem: '沅江流水到辰阳，谿口逢君驿路长。\n远谪谁知望雷雨，明年春水共还乡。' },
  { title: '别皇甫五', author: '王昌龄', poem: '溆浦潭阳隔楚山，离尊不用起愁颜。\n明祠灵响期昭应，天泽俱从此路还。' },
  { title: '送崔参军往龙溪', author: '王昌龄', poem: '龙溪只在龙标上，秋月孤山两相向。\n谴谪离心是丈夫，鸿恩共侍春江涨。' },
  { title: '送郑判官', author: '王昌龄', poem: '东楚吴山驿树微，轺车衔命奉恩辉。\n英僚携出新丰酒，半道遥看骢马归。' },
  { title: '送姚司法归吴', author: '王昌龄', poem: '吴掾留觞楚郡心，洞庭秋雨海门阴。\n但令意远扁舟近，不道沧江百丈深。' },
  { title: '送高三之桂林', author: '王昌龄', poem: '留君夜饮对潇湘，从此归舟客梦长。\n岭上梅花侵雪暗，归时还拂桂花香。' },
  { title: '旅望', author: '王昌龄', poem: '白花原头望京师，黄河水流无尽时。\n穷秋旷野行人绝，马首东来知是谁。' },
  { title: '题朱炼师山房', author: '王昌龄', poem: '叩齿焚香出世尘，斋坛鸣磬步虚人。\n百花仙酝能留客，一饭胡麻度几春。' },
  { title: '武陵开元观黄炼师院三首 一', author: '王昌龄', poem: '松间白发黄尊师，童子烧香禹步时。\n欲访桃源入溪路，忽闻鸡犬使人疑。' },
  { title: '武陵开元观黄炼师院三首 二', author: '王昌龄', poem: '先贤盛说桃花源，尘忝何堪武陵郡。\n闻道秦时避地人，至今不与人通问。' },
  { title: '武陵开元观黄炼师院三首 三', author: '王昌龄', poem: '山观空虚清静门，从官役吏扰尘喧。\n暂因问俗到真境，便欲投诚依道源。' },
  { title: '河上老人歌', author: '王昌龄', poem: '河上老人坐古槎，合丹只用青莲花。\n至今八十如四十，口道沧溟是我家。' },
  { title: '春怨', author: '王昌龄', poem: '音书杜绝白狼西，桃李无颜黄鸟啼。\n寒雁春深归去尽，出门肠断草萋萋。' },
  { title: '句', author: '王昌龄', poem: '朝荐抱良策，独倚江城楼。\n昨从金陵邑，远谪沅溪滨。\n娟魄已三孕。\n驾幸温泉日，严霜子月初。\n长亭酒未醒，千里风动地。\n苍荻寒沧江，石头岸边饮。\n天仗森森练雪凝，身骑铁骢自臂鹰。' },
  { title: '送陆擢', author: '常建', poem: '圣代多才俊，陆生何考槃。\n南山高松树，不合空摧残。\n九月湖上别，北风秋雨寒。\n殷勤叹孤凤，早食金琅玕。' },
  { title: '送李十一尉临溪', author: '常建', poem: '泠泠花下琴，君唱渡江吟。\n天际一帆影，预悬离别心。\n以言神仙尉，因致瑶华音。\n回轸抚商调，越溪澄碧林。' },
  { title: '江上琴兴', author: '常建', poem: '江上调玉琴，一弦清一心。\n泠泠七弦遍，万木澄幽阴。\n能使江月白，又令江水深。\n始知梧桐枝，可以徽黄金。' },
  { title: '湖中晚霁', author: '常建', poem: '湖广舟自轻，江天欲澄霁。\n是时清楚望，气色犹霾曀。\n踟蹰金霞白，波上日初丽。\n烟虹落镜中，树木生天际。\n杳杳涯欲辨，蒙蒙云复闭。\n言乘星汉明，又覩寰瀛势。\n微兴从此惬，悠然不知岁。\n试歌沧浪清，遂觉乾坤细。\n岂念客衣薄，将期永投袂。\n迟回渔父间，一鴈声嘹唳。' },
  { title: '宿王昌龄隐居', author: '常建', poem: '清溪深不测，隐处唯孤云。\n松际露微月，清光犹为君。\n茅亭宿花影，药院滋苔纹。\n余亦谢时去，西山鸾鹤群。' },
  { title: '送楚十少府', author: '常建', poem: '微风吹霜气，寒影明前除。\n落日未能别，萧萧林木虚。\n愁烟闭千里，仙尉其何如。\n因送别鹤操，赠之双鲤鱼。\n鲤鱼在金盘，别鹤哀有余。\n心事则如此，请君开素书。' },
  { title: '张山人弹琴', author: '常建', poem: '君去芳草绿，西峰弹玉琴。\n岂惟丘中赏，兼得清烦襟。\n朝从山口还，出岭闻清音。\n了然云霞气，照见天地心。\n玄鹤下澄空，翩翩舞松林。\n改弦扣商声，又听飞龙吟。\n稍觉此身妄，渐知仙事深。\n其将炼金鼎，永矣投吾簪。' },
  { title: '白湖寺后溪宿云门', author: '常建', poem: '落日山水清，乱流鸣淙淙。\n旧蒲雨抽节，新花水对窓。\n溪中日已没，归鸟多为双。\n杉松引直路，出谷临前湖。\n洲渚晚色静，又观花与蒲。\n入溪复登岭，草浅寒流速。\n圆月明高峰，春山因独宿。\n松阴澄初夜，曙色分远目。\n日出城南隅，青青媚川陆。\n乱花覆东郭，碧气销长林。\n四郊一清影，千里归寸心。\n前瞻王程促，却恋云门深。\n毕景有余兴，到家弹玉琴。' },
  { title: '闲斋卧病行药至山馆稍次湖亭二首 一', author: '常建', poem: '旬时结阴霖，帘外初白日。\n斋沐清病容，心魂畏虚室。\n闲梅照前户，明镜悲旧质。' },
  { title: '闲斋卧病行药至山馆稍次湖亭二首 二', author: '常建', poem: '行药至石壁，东风变萌芽。\n主人门外绿，小隐湖中花。\n时物堪独往，春帆宜别家。\n辞君向沧海，烂熳从天涯。' },
  { title: '塞上曲', author: '常建', poem: '翩翩云中使，来问太原卒。\n百战苦不归，刀头怨明月。\n塞云随阵落，寒日傍城没。\n城下有寡妻，哀哀哭枯骨。' },
  { title: '仙谷遇毛女意知是秦宫人', author: '常建', poem: '溪口水石浅，泠泠明药丛。\n入溪双峰峻，松栝疎幽风。\n垂岭枝袅袅，翳泉花蒙蒙。\n夤缘霁人目，路尽心弥通。\n盘石横阳崖，前流殊未穷。\n回潭清云影，弥漫长天空。\n水边一神女，千岁为玉童。\n羽毛经汉代，珠翠逃秦宫。\n目觌神已寓，鹤飞言未终。\n祈君青云秘，愿谒黄仙翁。\n尝以耕玉田，龙鸣西顶中。\n金梯与天接，几日来相逢。' },
  { title: '梦太白西峰', author: '常建', poem: '梦寐升九崖，杳霭逢元君。\n遗我太白峰，寥寥辞垢氛。\n结宇在星汉，宴林闭氤氲。\n檐楹覆余翠，巾舄生片云。\n时往溪水间，孤亭昼仍曛。\n松峰引天影，石濑清霞文。\n恬目缓舟趣，霁心投鸟群。\n春风又摇櫂，潭岛花纷纷。' },
  { title: '鄂渚招王昌龄张偾', author: '常建', poem: '刈芦旷野中，沙土飞黄云。\n天晦无精光，茫茫悲远君。\n楚山隔湘水，湖畔落日曛。\n春鴈又北飞，音书固难闻。\n谪居未为叹，谗枉何由分。\n午日逐蛟龙，宜为吊冤文。\n翻覆古共然，名宦安足云。\n贫士任枯槁，捕鱼清江𣸣。\n有时荷鉏犂，旷野自耕耘。\n不然春山隐，溪涧花氤氲。\n山鹿自有场，贤达亦顾群。\n二贤归去来，世上徒纷纷。' },
  { title: '春词二首 一', author: '常建', poem: '菀菀黄柳丝，蒙蒙杂花垂。\n日高红妆卧，倚对春光迟。\n宁知傍淇水，騕褭黄金羁。' },
  { title: '春词二首 二', author: '常建', poem: '翳翳陌上桑，南枝交北堂。\n美人金梯出，素手自提筐。\n非但畏蚕饥，盈盈娇路傍。' },
  { title: '晦日马镫曲稍次中流作', author: '常建', poem: '夜寒宿芦苇，晓色明西林。\n初日在川上，便澄游子心。\n秦天无纤翳，郊野浮春阴。\n波静随钓鱼，舟小绿水深。\n出浦见千里，旷然谐远寻。\n扣船应渔父，因唱沧浪吟。' },
  { title: '古意', author: '常建', poem: '牧马古道傍，道傍多古墓。\n萧条愁杀人，蝉鸣白杨树。\n回头望京邑，合沓生尘雾。\n富贵安可常，归来保贞素。' },
  { title: '宿五度溪仙人得道处', author: '常建', poem: '五度溪上花，生根依两崖。\n二月寻片云，愿宿秦人家。\n上见悬崖崩，下见白水湍。\n仙人弹碁处，石上青萝盘。\n无处求玉童，翳翳唯林峦。\n前溪遇新月，聊取玉琴弹。' },
  { title: '西山', author: '常建', poem: '一身为轻舟，落日西山际。\n常随去帆影，远接长天势。\n物象归余清，林峦分夕丽。\n亭亭碧流暗，日入孤霞继。\n渚日远阴映，湖云尚明霁。\n林昏楚色来，岸远荆门闭。\n至夜转清逈，萧萧北风厉。\n沙边鴈鹭泊，宿处蒹葭蔽。\n圆月逗前浦，孤琴又摇曳。\n泠然夜遂深，白露沾人袂。' },
  { title: '春词', author: '常建', poem: '阶下草犹短，墙头梨花白。\n织女高楼上，停梭顾行客。\n问君在何所，青鸟舒锦翮。' },
  { title: '赠三侍御', author: '常建', poem: '高山临大泽，正月芦花干。\n阳色薰两崖，不改青松寒。\n士贤守孤贞，古来皆共难。\n明君错甚才，台上飞三鸾。\n操与霜雪明，量与江海宽。\n束身视天涯，安能穷波澜。\n孤鹤在枳棘，一枝非所安。\n逸翮望绝霄，见欲凌云端。\n层台何其高，山石流洪湍。\n固知非天池，鸣跃同所欢。\n谁念独枯槁，四十长江干。\n责躬贵知己，效拙从一官。\n折翮悲高风，苦饥候朝飡。\n湖月映大海，天空何漫漫。\n托身未知所，谋道庶不刊。\n吟彼乔木诗，一夕常三叹。' },
  { title: '第三峰', author: '常建', poem: '西山第三顶，茅宇依双松。\n杳杳欲至天，云梯升几重。\n莹魄澄玉虚，以求鸾鹤踪。\n逶迤非天人，执节乘赤龙。\n旁映白日光，缥缈轻霞容。\n孤辉上烟雾，余影明心胸。\n愿与黄麒麟，欲飞而莫从。\n因寂清万象，轻云自中峰。\n山暝学栖鸟，月来随暗蛬。\n寻空静余响，袅袅云溪钟。' },
  { title: '古兴', author: '常建', poem: '汉上逢老翁，江口为僵尸。\n白发沾黄泥，遗骸集乌鸱。\n机巧自此忘，精魄今何之。\n风吹钓竿折，鱼跃安能施。\n白水明汀洲，菰蒲冒深陂。\n唯留扁舟影，系在长江湄。\n突兀枯松枝，悠扬女萝丝。\n托身难凭依，生死焉相知。\n徧观今时人，举世皆尔为。\n将军死重围，汉卒犹争驰。\n百马同一衔，万轮同一规。\n名与身孰亲，君子宜固思。' },
  { title: '高楼夜弹筝', author: '常建', poem: '高楼百余尺，直上江水平。\n明月照人苦，开帘弹玉筝。\n山高猿狖急，天静鸿鴈鸣。\n曲度犹未终，东峰霞半生。' },
  { title: '客有自燕而归哀其老而赠之', author: '常建', poem: '羸马朝自燕，一身为二连。\n忆亲拜孤冢，移葬双陵前。\n幽愿从此毕，劒心因获全。\n孟冬寒气盛，抚辔告言旋。\n碣石海北门，余寇惟朝鲜。\n离离一寒骑，袅袅驰白天。\n生别皆自取，况为士卒先。\n寸心渔阳兴，落日旌竿悬。' },
  { title: '白龙窟泛舟寄天台学道者', author: '常建', poem: '夕映翠山深，余晖在龙窟。\n扁舟沧浪意，澹澹花影没。\n西浮入天色，南望对云阙。\n因忆莓苔峰，初阳濯玄发。\n泉萝两幽映，松鹤间清越。\n碧海莹子神，玉膏泽人骨。\n忽然为枯木，微兴遂如兀。\n应寂中有天，明心外无物。\n环回从所泛，夜静犹不歇。\n澹然意无限，身与波上月。' },
  { title: '张天师草堂', author: '常建', poem: '灵溪宴清宇，傍倚枯松根。\n花药绕方丈，瀑泉飞至门。\n四气闭炎热，两崖改明昏。\n夜深月𫏐皎，亭午朝始暾。\n信是天人居，幽幽寂无喧。\n万壑应鸣磬，诸峰接一魂。\n遂登仙子谷，因醉田生樽。\n时节开玉书，窅映飞天言。\n心化便无影，目精焉累烦。\n忽而与霄汉，寥落空南轩。' },
  { title: '古意三首 一', author: '常建', poem: '二妃方访舜，万里南方悬。\n远道隔江汉，孤舟无岁年。\n不知苍梧处，气尽呼青天。\n愁泪变楚竹，蛾眉丧湘川。\n后人立为庙，累世称其贤。\n过客设祠祭，孤狸来坐边。\n怀古未忍还，猿吟彻空山。' },
  { title: '古意三首 二', author: '常建', poem: '明月照高阁，彩女褰罗幕。\n歌舞临碧云，箫声沸珠箔。\n青鸾临南海，天上双白鹤。\n万里齐翼飞，意求君门乐。\n玉霄九重闭，金锁夜不开。\n两翅自无力，愁鸣云外来。\n态深入空贵，世屈无良媒。\n俛仰顾中禁，东飞白玉台。' },
  { title: '古意三首 三', author: '常建', poem: '楚王竟何去，独自留巫山。\n偏使世人见，迢迢江汉间。\n驻舟春溪里，皆愿拜灵颜。\n寤寐见神女，金沙鸣珮环。\n闲艳绝世姿，令人气力微。\n含笑竟不语，化作朝云飞。' },
  { title: '渔浦', author: '常建', poem: '春至百草绿，陂泽闻鸧鹒。\n别家投钓翁，今世沧浪情。\n沤纻为缊袍，折麻为长缨。\n荣誉失本真，怪人浮此生。\n碧水月自阔，安流净而平。\n扁舟与天际，独往谁能名。' },
  { title: '空灵山应田叟', author: '常建', poem: '湖南无村落，山舍多黄茆。\n淳朴如太古，其人居鸟巢。\n牧童唱巴歌，野老亦献嘲。\n泊舟问溪口，言语皆哑咬。\n土俗不尚农，岂暇论肥硗。\n莫傜射禽兽，浮客烹鱼鲛。\n余亦罘罝人，获麋今尚苞。\n敬君中国来，愿以充其庖。\n日入闻虎鬬，空山满咆哮。\n怀人虽共安，异域终难交。\n白水可洗心，采薇可为肴。\n曳策背落日，江风鸣梢梢。' },
  { title: '太公哀晚遇', author: '常建', poem: '日出渭流白，文王畋猎时。\n钓翁在芦苇，川泽无熊罴。\n诏书起遗贤，匹马令致辞。\n因称江海人，臣老筋力衰。\n迟迟诣天车，快快悟灵龟。\n兵马更不猎，君臣皆共怡。\n同车至咸阳，心影无磷缁。\n四牡玉墀下，一言为帝师。\n王侯拥朱门，轩盖曜长逵。\n古来荣华人，遭遇谁知之。\n落日悬桑榆，光景有顿亏。\n倏忽天地人，虽贵将何为。' },
  { title: '昭君墓', author: '常建', poem: '汉宫岂不死，异域伤独没。\n万里驮黄金，蛾眉为枯骨。\n回车夜出塞，立马皆不发。\n共恨丹青人，坟上哭明月。' },
  { title: '吊王将军墓', author: '常建', poem: '嫖姚北伐时，深入强千里。\n战余落日黄，军败鼓声死。\n尝闻汉飞将，可夺单于垒。\n今与山鬼邻，残兵哭辽水。' },
  { title: '张公子行', author: '常建', poem: '日出乘钓舟，袅袅持钓竿。\n涉淇傍荷花，骢马闲金鞍。\n侠客白云中，腰间悬辘轳。\n出门事嫖姚，为君西击胡。\n胡兵汉骑相驰逐，转战孤军西海北。\n百尺旌竿沈黑云，边笳落日不堪闻。' },
  { title: '题破山寺后禅院', author: '常建', poem: '清晨入古寺，初日照高林。\n竹迳通幽处，禅房花木深。\n山光悦鸟性，潭影空人心。\n万籁此都寂，但余钟磬音。' },
  { title: '送李大都护', author: '常建', poem: '单于虽不战，都护事边深。\n君执幕中秘，能为高士心。\n海头近初月，碛里多愁阴。\n西望郭犹子，将分泪满襟。' },
  { title: '潭州留别', author: '常建', poem: '贤达不相识，偶然交已深。\n宿帆谒郡佐，怅别依禅林。\n湘水流入海，楚云千里心。\n望君杉松夜，山月清猿吟。' },
  { title: '听琴秋夜赠寇尊师', author: '常建', poem: '琴当秋夜听，况是洞中人。\n一指指应法，一声声爽神。\n寒虫临砌急，清吹褭灯频。\n何必钟期耳，高闲自可亲。' },
  { title: '泊舟盱眙', author: '常建', poem: '泊舟淮水次，霜降夕流清。\n夜久潮侵岸，天寒月近城。\n平沙依鴈宿，候馆听鸡鸣。\n乡国云霄外，谁堪羁旅情。' },
  { title: '江行', author: '常建', poem: '平湖四无际，此夜泛孤舟。\n明月异方意，吴歌令客愁。\n乡园碧云外，兄弟渌江头。\n万里无归信，伤心看斗牛。' },
  { title: '燕居', author: '常建', poem: '青苔常满路，流水复入林。\n远与市朝隔，日闻鸡犬深。\n寥寥丘中想，渺渺湖上心。\n啸傲转无欲，不知成陆沈。' },
  { title: '送宇文六', author: '常建', poem: '花映垂杨汉水清，微风林里一枝轻。\n即今江北还如此，愁杀江南离别情。' },
  { title: '落第长安', author: '常建', poem: '家园好在尚留秦，耻作明时失路人。\n恐逢故里莺花笑，且向长安度一春。' },
  { title: '塞下', author: '常建', poem: '铁马胡裘出汉营，分麾百道救龙城。\n左贤未遁旌竿折，过在将军不在兵。' },
  { title: '题法院', author: '常建', poem: '胜景门闲对远山，竹深松老半含烟。\n皓月殿中三度磬，水晶宫里一僧禅。' },
  { title: '岭猿', author: '常建', poem: '杳杳褭褭清且切，鹧鸪飞处又斜阳。\n相思岭上相思泪，不到三声合断肠。' },
  { title: '三日寻李九庄', author: '常建', poem: '雨歇杨林东渡头，永和三日荡轻舟。\n故人家在桃花岸，直到门前溪水流。' },
  { title: '塞下曲四首 一', author: '常建', poem: '玉帛朝回望帝乡，乌孙归去不称王。\n天涯静处无征战，兵气销为日月光。' },
  { title: '塞下曲四首 二', author: '常建', poem: '北海阴风动地来，明君祠上望龙堆。\n髑髅皆是长城卒，日暮沙场飞作灰。' },
  { title: '塞下曲四首 三', author: '常建', poem: '龙鬬雌雄势已分，山崩鬼哭恨将军。\n黄河直北千余里，冤气苍茫成黑云。' },
  { title: '塞下曲四首 四', author: '常建', poem: '因嫁单于怨在边，蛾眉万古葬胡天。\n汉家此去三千里，青冢常无草木烟。' },
  { title: '戏题湖上', author: '常建', poem: '湖上老人坐矶头，湖里桃花水却流。\n竹竿袅袅白波际，不知何者吞吾钩。' },
  { title: '吴故宫', author: '常建', poem: '越女歌长君且听，芙蓉香满水边城。\n岂知一日终非主，犹自如今有怨声。' },
  { title: '从军行', author: '杜𬱟', poem: '秋草马蹄轻，角弓持弦急。\n去为龙城候，正值胡兵袭。\n军气横大荒，战酣日将入。\n长风金鼓动，白露铁衣湿。\n四起愁边声，南辕时伫立。\n断蓬孤自转，寒雁飞相及。\n万里云沙涨，平川冰霰溢。\n夜闻汉使归，独向刀环泣。' },
  { title: '故绛行', author: '杜𬱟', poem: '君不见铜鞮观，数里城池已芜漫。\n君不见虒祁宫，几重台榭亦微蒙。\n介马兵车全盛时，歌童舞女妖艳姿。\n一代繁华皆共绝，九原唯望冢累累。' },
  { title: '少年行三首 一', author: '李嶷', poem: '十八羽林郎，戎衣侍汉王。\n臂鹰金殿侧，挟弹玉舆傍。\n驰道春风起，陪游出建章。' },
  { title: '少年行三首 二', author: '李嶷', poem: '侍猎长杨下，承恩更射飞。\n尘生马影灭，箭落雁行稀。\n薄暮随天仗，联翩入琐闱。' },
  { title: '少年行三首 三', author: '李嶷', poem: '玉劒膝边横，金杯马上倾。\n朝游茂陵道，夜宿凤凰城。\n豪吏多猜忌，无劳问姓名。' },
  { title: '淮南秋夜呈周偘', author: '李嶷', poem: '天净河汉高，夜闲砧杵发。\n清秋忽如此，离恨应难歇。\n风乱池上萍，露光竹间月。\n与君共游处，勿作他乡别。' },
  { title: '林园秋夜作', author: '李嶷', poem: '林卧避残暑，白云长在天。\n赏心既如此，对酒非徒然。\n月色徧秋露，竹声兼夜泉。\n凉风怀袖里，兹意与谁传。' },
  { title: '读前汉外戚传', author: '李嶷', poem: '人录尚书事，家临御路傍。\n凿池通渭水，避暑借明光。\n印绶妻封邑，轩车子拜郎。\n宠因宫掖里，势极必先亡。' },
  { title: '春怨', author: '崔亘', poem: '夜尽梦初惊，纱窗早雾明。\n晓妆脂粉薄，春服绮罗轻。\n妾有今朝恨，君无旧日情。\n愁来理弦管，皆是断肠声。' },
  { title: '古歌二首 一', author: '蒋维翰', poem: '美人怨何深，含情倚金阁。\n不嚬复不语，红泪双双落。' },
  { title: '古歌二首 二', author: '蒋维翰', poem: '美人闭红烛，独作裁新锦。\n频放剪刀声，夜寒知未寝。' },
  { title: '春夜裁缝', author: '蒋维翰', poem: '珠箔因风起，飞蛾入最能。\n不教人夜作，方便杀明灯。' },
  { title: '春女怨', author: '蒋维翰', poem: '白玉堂前一树梅，今朝忽见数花开。\n儿家门户寻常闭，春色因何入得来。' },
  { title: '怨歌', author: '蒋维翰', poem: '百尺珠楼临狭斜，新妆能唱美人车。\n皆言贱妾红颜好，要自狂夫不忆家。' },
  { title: '小山歌', author: '万楚', poem: '人说淮南有小山，淮王昔日此登仙。\n城中鸡犬皆飞去，山上坛场今宛然。\n世人贵身不贵寿，共笑华阳洞天口。\n不知金石变长年，谩在人间恋携手。\n君能举帆至淮南，家住盱眙余先谙。\n桐柏乱流平入海，茱萸一曲沸成潭。\n忆记来时魂悄悄，想见仙山众峰小。\n今日长歌思不堪，君行为报三青鸟。' },
  { title: '题江潮庄壁', author: '万楚', poem: '田家喜秋熟，岁[晏]林叶稀。\n禾黍积场圃，𣙁梨垂户扉。\n野闲犬时吠，日暮牛自归。\n时复落花酒，茅斋堪解衣。' },
  { title: '咏帘', author: '万楚', poem: '玳瑁昔称华，玲珑薄绛纱。\n钩衔门势曲，节乱水纹斜。\n日弄长飞鸟，风摇不卷花。\n自当分内外，非是为骄奢。' },
  { title: '茱萸女', author: '万楚', poem: '山阴柳家女，九日采茱萸。\n复得东邻伴，双为陌上姝。\n插枝着高髻，结子置长裾。\n作性常迟缓，非关诧丈夫。\n平明折林樾，日入返城隅。\n侠客要罗袖，行人挑短书。\n蛾眉自有主，年少莫踟蹰。' },
  { title: '五日观妓', author: '万楚', poem: '西施谩道浣春纱，碧玉今时鬬丽华。\n眉黛夺将萱草色，红裙妬杀石榴花。\n新歌一曲令人艳，醉舞双眸敛鬓斜。\n谁道五丝能续命，却令今日死君家。' },
  { title: '骢马', author: '万楚', poem: '金络青骢白玉鞍，长鞭紫陌野游盘。\n朝驱东道尘恒灭，暮到河源日未阑。\n汗血每随边地苦，蹄伤不惮陇阴寒。\n君能一饮长城窟，为报天山行路难。' },
  { title: '题情人药栏', author: '万楚', poem: '敛眉语芳草，何许太无情。\n正见离人别，春心相向生。' },
  { title: '河上逢落花', author: '万楚', poem: '河水浮落花，花流东不息。\n应见浣纱人，为道长相忆。' },
  { title: '宁王山池', author: '范朝', poem: '水势临阶转，峰形对路开。\n槎从天上得，石是海边来。\n瑞草分丛种，祥花间色栽。\n旧传词赋客，唯见有邹枚。' },
  { title: '题石瓮寺', author: '范朝', poem: '胜境宜长望，迟春好散愁。\n关连四塞起，河带八川流。\n复磴承香阁，重岩映彩楼。\n为临温液近，偏美圣君游。' },
  { title: '田家', author: '杨颜', poem: '小园足生事，寻胜日倾壶。\n莳蔬利于鬻，才青摘已无。\n四邻依野竹，日夕采其枯。\n田家心适时，春色徧桑榆。' },
  { title: '后庭怨', author: '王𬤇', poem: '君不见红闺少女端正时，夭夭桃李仙容姿。\n幸得君王怜巧笑，披香殿里荐蛾眉。\n蛾眉双双人共进，常恐妾身从此摈。\n甄妃为妬出层宫，班女因猜下长信。\n长信宫门闭不开，昭阳歌吹风送来。\n梦中魂魄犹言是，觉后精神尚未回。\n念君娇爱无终始，使妾长啼后庭里。\n独立每看斜日尽，孤眠直至残灯死。\n秋日闻虫翡翠帘，春晴照面鸳鸯水。\n红颜旧来花不胜，白发如今雪相似。\n传闻纨扇恩未歇，预想蛾眉上初月。\n如君贵伪不贵真，还同弃妾逐新人。\n借问南山松叶意，何如北砌槿花新。' },
  { title: '夜坐看搊筝', author: '王𬤇', poem: '调筝夜坐灯光里，却挂罗帷露纤指。\n朱弦一一声不同，玉柱连连影相似。\n不知何处学新声？曲曲弹来未覩名。\n应是石家金谷里，流传未满洛阳城。' },
  { title: '长信怨', author: '王𬤇', poem: '飞燕倚身轻，争人巧笑名。\n生君弃妾意，增妾怨君情。\n日落昭阳壁，秋来长信城。\n寥寥金殿里，歌吹夜无声。' },
  { title: '闺情', author: '王𬤇', poem: '日暮裁缝歇，深嫌气力微。\n才能收箧笥，嬾起下帘帷。\n怨坐空然烛，愁眠不解衣。\n昨来频梦见，夫婿莫应知。' },
  { title: '十五夜观灯', author: '王𬤇', poem: '暂得金吾夜，通看火树春。\n停车傍明月，走马入红尘。\n妓杂歌偏胜，场移舞更新。\n应须尽记取，说向不来人。' },
  { title: '除夜', author: '王𬤇', poem: '今岁今宵尽，明年明日催。\n寒随一夜去，春逐五更来。\n气色空中改，容颜暗里回。\n风光人不觉，已着后园梅。' },
  { title: '闻漏', author: '王岳灵', poem: '建礼含香处，重城待漏臣。\n徐闻传凤诏，晓唱辨鸡人。\n银箭残将尽，铜壶漏更新。\n催筹当午夜，移刻及三辰。\n杳杳从天远，泠泠出禁频。\n直疑残漏曙，肃肃对钩陈。' },
  { title: '送沈芳谒李观察求仕进', author: '周万', poem: '往日长安路，欢游不惜年。\n为贪卢女曲，用尽沈郎钱。\n身老方投刺，途穷始着鞭。\n犹闻有知己，此去不徒然。' },
  { title: '古塞下曲', author: '陶翰', poem: '进军飞狐北，穷寇势将变。\n日落沙尘昏，背河更一战。\n骍马黄金勒，雕弓白羽箭。\n射杀左贤王，归奏未央殿。\n欲言塞下事，天子不召见。\n东出咸阳门，哀哀泪如霰。' },
  { title: '燕歌行', author: '陶翰', poem: '请君留楚调，听我吟燕歌。\n家在辽水头，边风意气多。\n出身为汉将，正值戎未和。\n雪中凌天山，冰上渡交河。\n大小百余战，封侯竟蹉跎。\n归来灞陵下，故旧无相过。\n雄劒委尘匣，空门垂雀罗。\n玉簪还赵女，宝瑟付齐娥。\n昔日不为乐，时哉今奈何。' },
  { title: '望太华赠卢司仓', author: '陶翰', poem: '行吏到西华，乃观三峰壮。\n削成元气中，杰出天河上。\n如有飞动色，不知青冥状。\n巨灵安在哉，厥迹犹可望。\n方此顾行旅，末由饬仙装。\n葱茏记星坛，明灭数云嶂。\n良友垂真契，宿心所微尚。\n敢投归山吟，霞径一相访。' },
  { title: '赠郑员外', author: '陶翰', poem: '骢马拂绣裳，按兵辽水阳。\n西分鴈门骑，北逐楼烦王。\n闻道五军集，相邀百战场。\n风沙暗天起，虏骑森已行。\n儒服揖诸将，雄谋吞大荒。\n金门来见谒，朱绂生辉光。\n数年侍御史，稍迁尚书郎。\n人生志气立，所贵功业昌。\n何必守章句，终年事铅黄。\n同时献赋客，尚在东陵傍。' },
  { title: '赠房侍御', author: '陶翰', poem: '志士固不羁，与道常周旋。\n进则天下仰，已之能晏然。\n褐衣东府召，执简南台先。\n雄义每特立，犯颜岂图全。\n谪居东南远，逸气吟芳荃。\n适会寥廓趣，清波更夤缘。\n扁舟入五湖，发缆洞庭前。\n浩荡临海曲，迢遥济江壖。\n征奇忽忘返，遇兴将弥年。\n乃悟范生智，足明渔父贤。\n郡临新安渚，佳赏此城偏。\n日夕对层岫，云霞映晴川。\n闲居恋秋色，偃卧含贞坚。\n倚伏聊自化，行藏互推迁。\n君其振羽翮，岁晏将冲天。' },
  { title: '晚出伊阙寄河南裴中丞', author: '陶翰', poem: '退无偃息资，进无当代策。\n冉冉时将暮，坐为周南客。\n前登阙塞门，永眺伊城陌。\n长川黯已空，千里寒气白。\n家本渭水西，异日同所适。\n秉志师禽尚，微言祖庄易。\n一辞林壑间，共系风尘役。\n交朋忽先进，天道何纷剧。\n岂念嘉遯时，依依偶沮溺。' },
  { title: '送朱大出关', author: '陶翰', poem: '楚客西上书，十年不得意。\n平生相知者，晚节心各异。\n长揖五侯门，拂衣谢中贵。\n丈夫多别离，各有四方事。\n拔劒因高歌，萧萧北风至。\n故人有斗酒，是夜共君醉。\n努立强加餐，当年莫相弃。' },
  { title: '宿天竺寺', author: '陶翰', poem: '松柏乱岩口，山西微径通。\n天开一峰见，宫阙生虚空。\n正殿倚霞壁，千楼标石丛。\n夜来猨鸟静，钟梵响云中。\n岑翠映湖月，泉声乱溪风。\n心超诸境外，了与悬解同。\n明发唯改视，朝日长崖东。\n湖色浓荡漾，海光渐曈朦。\n葛仙迹尚在，许氏道犹崇。\n独往古来事，幽怀期二公。' },
  { title: '出萧关怀古', author: '陶翰', poem: '驱马击长劒，行役至萧关。\n悠悠五原上，永眺关河前。\n北虏三十万，此中常控弦。\n秦城亘宇宙，汉帝理旌旃。\n刁斗鸣不息，羽书日夜传。\n五军计莫就，三策议空全。\n大漠横万里，萧条绝人烟。\n孤城当瀚海，落日照[祁]连。\n怆矣苦寒奏，怀哉式微篇。\n更悲秦楼月，夜夜出胡天。' },
  { title: '南楚怀古', author: '陶翰', poem: '南国久芜漫，我来空郁陶。\n君看章华宫，处处生黄蒿。\n但见陵与谷，岂知贤与豪。\n精魂托古木，宝玉捐江臯。\n倚棹下晴景，回舟随晚涛。\n碧云暮寥落，湖上秋天高。\n往事那堪问，此心徒自劳。\n独余湘水上，千载闻离骚。' },
  { title: '经杀子谷', author: '陶翰', poem: '扶苏秦帝子，举代称其贤。\n百万犹在握，可争天下权。\n束身就一劒，壮志皆弃捐。\n塞下有遗迹，千龄人共传。\n疎芜尽荒草，寂历空寒烟。\n到此尽垂泪，非我独潸然。' },
  { title: '早过临淮', author: '陶翰', poem: '夜来三渚风，晨过临淮岛。\n湖中海气白，城上楚云早。\n鳞鳞鱼浦帆，漭漭芦洲草。\n川路日浩荡，惄焉心如捣。\n且言任倚伏，何暇念枯槁。\n范子名屡移，蘧公志常保。\n古人去已久，此理今难道。' },
  { title: '乘潮至渔浦作', author: '陶翰', poem: '舣棹乘早潮，潮来如风雨。\n樟台忽已隐，界峰莫及覩。\n崩腾心为失，浩荡目无主。\n豗𢟸浪始闻，漾漾入鱼浦。\n云景共澄霁，江山相吞吐。\n伟哉造化工，此事从终古。\n流沫诚足诫，商歌调易苦。\n颇因忠信全，客心犹栩栩。' },
  { title: '秋山夕兴', author: '陶翰', poem: '山月松筿下，月明山景鲜。\n聊为高秋酌，复此清夜弦。\n晤语方获志，栖心亦弥年。\n尚言兴未逸，更理逍遥篇。' },
  { title: '送集贤学士伊阙史少府敕放归江东觐省', author: '陶翰', poem: '墨客钟张侣，材高吴越珍。\n千门来谒帝，驷马去荣亲。\n吏邑沿清洛，乡山指白苹。\n归期应不远，当及未央春。' },
  { title: '送金卿归新罗', author: '陶翰', poem: '奉义朝中国，殊恩及远臣。\n乡心遥渡海，客路再经春。\n落日谁同望，孤舟独可亲。\n拂波衔木鸟，偶宿泣珠人。\n礼乐夷风变，衣冠汉制新。\n青云已干吕，知汝重来宾。' },
  { title: '柳陌听早莺', author: '陶翰', poem: '忽来枝上啭，还似谷中声。\n乍使香闺静，偏伤远客情。\n间关难辨处，断续若频惊。\n玉勒留将久，青楼梦不成。\n千门候晓发，万井报春生。\n徒有知音赏，慙非臯鹤鸣。' },
  { title: '逢雪宿芙蓉山主人', author: '刘长卿', poem: '日暮苍山远，天寒白屋贫。\n柴门闻犬吠，风雪夜归人。' },
  { title: '送张起崔载华之闽中', author: '刘长卿', poem: '朝无寒士达，家在旧山贫。\n相送天涯里，怜君更远人。' },
  { title: '赠秦系征君', author: '刘长卿', poem: '群公谁让位，五柳独知贫。\n惆怅青山路，烟霞老此人。' },
  { title: '秦系顷以家事获谤因出旧山每荷观察崔公见知欲归未遂感其流寓诗以赠之', author: '刘长卿', poem: '初迷武陵路，复出孟尝门。\n回首江南岸，青山与旧恩。' },
  { title: '夜中对雪赠秦系时秦初与谢氏离婚谢氏在越', author: '刘长卿', poem: '月明花满地，君自忆山阴。\n谁遣因风起，纷纷乱此心。' },
  { title: '湘妃', author: '刘长卿', poem: '帝子不可见，秋风来暮思。\n婵娟湘江月，千载空蛾眉。' },
  { title: '斑竹', author: '刘长卿', poem: '苍梧千载后，斑竹对湘沅。\n欲识湘妃怨，枝枝满泪痕。' },
  { title: '春草宫怀古', author: '刘长卿', poem: '君王不可见，芳草旧宫春。\n犹带罗裙色，青青向楚人。' },
  { title: '正朝览镜作', author: '刘长卿', poem: '憔悴逢新岁，茅扉见旧春。\n朝来明镜里，不忍白头人。' },
  { title: '瓜洲道中送李端公南渡后归扬州道中寄', author: '刘长卿', poem: '片帆何处去，匹马独归迟。\n惆怅江南北，青山欲暮时。' },
  { title: '送张十八归桐庐', author: '刘长卿', poem: '归人乘野艇，带月过江村。\n正落寒潮水，相随夜到门。' },
  { title: '过白鹤观寻岑秀才不遇', author: '刘长卿', poem: '不知方外客，何事锁空房。\n应向桃源里，教他唤阮郎。' },
  { title: '听弹琴', author: '刘长卿', poem: '泠泠七丝上，静听松风寒。\n古调虽自爱，今人多不弹。' },
  { title: '游南园偶见在阴墙下葵因以成咏', author: '刘长卿', poem: '此地常无日，青青独在阴。\n太阳偏不及，非是未倾心。' },
  { title: '入百丈涧见桃花晚开', author: '刘长卿', poem: '百丈深涧里，过时花欲妍。\n应缘地势下，遂使春风偏。' },
  { title: '送子壻崔真甫李穆往扬州四首 一', author: '刘长卿', poem: '渡口发梅花，山中动泉脉。\n芜城春草生，君作扬州客。' },
  { title: '送子壻崔真甫李穆往扬州四首 二', author: '刘长卿', poem: '半逻莺满树，新年人独还。\n落花逐流水，共到茱萸湾。' },
  { title: '送子壻崔真甫李穆往扬州四首 三', author: '刘长卿', poem: '雁还空渚在，人去落潮翻。\n临水独挥手，残阳归掩门。' },
  { title: '送子壻崔真甫李穆往扬州四首 四', author: '刘长卿', poem: '狎鸟携稚子，钓鱼终老身。\n殷勤嘱归客，莫话桃源人。' },
  { title: '寄龙山道士许法棱', author: '刘长卿', poem: '悠悠白云里，独住青山客。\n林下昼焚香，桂花同寂寂。' },
  { title: '送方外上人', author: '刘长卿', poem: '孤云将野鹤，岂向人间住。\n莫买沃洲山，时人已知处。' },
  { title: '送灵澈上人', author: '刘长卿', poem: '苍苍竹林寺，杳杳钟声晚。\n荷笠带夕阳，青山独归远。' },
  { title: '茱萸湾北荅崔载华问', author: '刘长卿', poem: '荒凉野店绝，迢遰人烟远。\n苍苍古木中，多是隋家苑。' },
  { title: '赴楚州次自田途中阻浅问张南史', author: '刘长卿', poem: '楚城今近远，积霭寒塘暮。\n水浅舟且迟，淮潮至何处。' },
  { title: '江中对月', author: '刘长卿', poem: '空洲夕烟敛，望月秋江里。\n历历沙上人，月中孤渡水。' },
  { title: '碧涧别墅喜皇甫侍御相访', author: '刘长卿', poem: '荒村带返照，落叶乱纷纷。\n古路无行客，寒山独见君。\n野桥经雨断，涧水向田分。\n不为怜同病，何人到白云。' },
  { title: '初到碧涧招明契上人', author: '刘长卿', poem: '渐老知身累，初寒曝背眠。\n白云留永日，黄叶减余年。\n猨护窗前树，泉浇谷后田。\n沃洲能共隐，不用道林钱。' },
  { title: '送少微上人游天台', author: '刘长卿', poem: '石桥人不到，独往更迢迢。\n乞食山家少，寻钟野路遥。\n松门风自埽，瀑布雪难消。\n秋夜闻清梵，余音逐海潮。' },
  { title: '却归睦州至七里滩下作', author: '刘长卿', poem: '南归犹谪宦，独上子陵滩。\n江树临洲晚，沙禽对水寒。\n山开斜照在，石浅乱流难。\n惆怅梅花发，年年此地看。' },
  { title: '对酒寄严维', author: '刘长卿', poem: '陋巷喜阳和，衰颜对酒歌。\n嬾从华发乱，闲任白云多。\n郡简容垂钓，家贫学弄梭。\n门前七里濑，早晚子陵过。' },
  { title: '新年作', author: '刘长卿', poem: '乡心新岁切，天畔独潸然。\n老至居人下，春归在客先。\n岭猨同旦暮，江柳共风烟。\n已是长沙傅，从今又几年。' },
  { title: '朱放自杭州与故里相使君立碑回因以奉简吏部杨侍郎制文', author: '刘长卿', poem: '片石羊公后，凄凉江水滨。\n好辞千古事，堕泪万家人。\n𫛳集占书久，鸾回刻篆新。\n不堪相顾恨，文字日生尘。' },
  { title: '送宣尊师醮毕归越', author: '刘长卿', poem: '吹箫江上晚，惆怅别茅君。\n踏火能飞雪，登刀入白云。\n晨香长日在，夜磬满山闻。\n挥手桐溪路，无情水亦分。' },
  { title: '送裴使君赴荆南充行军司马', author: '刘长卿', poem: '盛府南门寄，前程积水中。\n月明临夏口，山晚望巴东。\n故节辞江郡，寒笳发渚宫。\n汉川风景好，遥羡逐羊公。' },
  { title: '送裴郎中贬吉州', author: '刘长卿', poem: '乱军交白刃，一骑出黄尘。\n汉节同归阙，江帆共逐臣。\n猨愁歧路晚，梅作异方春。\n知己酂侯在，应怜脱粟人。' },
  { title: '酬皇甫侍御见寄时前相国姑臧公初临郡', author: '刘长卿', poem: '离别江南北，汀洲叶再黄。\n路遥云共水，砧迥月如霜。\n岁俭依仁政，年衰忆故乡。\n伫看宣室召，汉法倚张纲。' },
  { title: '月下呈章秀才', author: '刘长卿', poem: '自古悲摇落，谁人奈此何。\n夜蛬偏傍枕，寒鸟数移柯。\n向老三年谪，当秋百感多。\n家贫惟好月，空媿子猷过。' },
  { title: '酬张夏', author: '刘长卿', poem: '几岁依穷海，颓年惜故阴。\n剑寒空有气，松老欲无心。\n玩雪劳相访，看山正独吟。\n孤舟且莫去，前路水云深。' },
  { title: '送李使君贬连州', author: '刘长卿', poem: '独过长沙去，谁堪此路愁。\n秋风散千骑，寒雨泊孤舟。\n贾谊辞明主，萧何识故侯。\n汉廷当自召，湘水但空流。' },
  { title: '秋夜北山精舍观体如师梵', author: '刘长卿', poem: '焚香奏仙呗，向夕遍空山。\n清切兼秋远，威仪对月闲。\n静分岩响荅，散逐海潮还。\n幸得风吹去，随人到世间。' },
  { title: '酬张夏雪夜赴州访别途中苦寒作', author: '刘长卿', poem: '扁舟乘兴客，不惮苦寒行。\n晚暮相依分，江潮欲别情。\n水声冰下咽，砂路雪中平。\n旧劒锋铓尽，应嫌赠脱轻。' },
  { title: '寻洪尊师不遇', author: '刘长卿', poem: '古木无人地，来寻羽客家。\n道书堆玉案，仙帔叠青霞。\n鹤老难知岁，梅寒未作花。' },
  { title: '喜鲍禅师自龙山至', author: '刘长卿', poem: '故居何日下，春草欲芊芊。\n犹对山中月，谁听石上泉。\n猨声知后夜，花发见流年。\n杖锡闲来往，无心到处禅。' },
  { title: '送方外上人之常州依萧使君', author: '刘长卿', poem: '宰臣思得度，鸥鸟恋为群。\n远客回飞锡，空山卧白云。\n夕阳孤艇去，秋水两溪分。\n归共临川史，同翻贝叶文。' },
  { title: '宿北山禅寺兰若', author: '刘长卿', poem: '上方鸣夕磬，林下一僧还。\n密行传人少，禅心对虎闲。\n青松临古路，白月满寒山。\n旧识窗前桂，经霜更待攀。' },
  { title: '赴新安别梁侍郎', author: '刘长卿', poem: '新安君莫问，此路水云深。\n江海无行迹，孤舟何处寻。\n青山空向泪，白月岂知心。\n纵有余生在，终伤老病侵。' },
  { title: '江州留别薛六柳八二员外', author: '刘长卿', poem: '江海相逢少，东南别处长。\n独行风袅袅，相去水茫茫。\n白首辞同舍，青山背故乡。\n离心与潮信，每日到浔阳。' },
  { title: '和州留别穆郎中', author: '刘长卿', poem: '播迁悲远道，摇落感衰容。\n今日犹多难，何年更此逢。\n世交黄叶散，乡路白云重。\n明发看烟树，唯闻江北钟。' },
  { title: '和州送人归复郢', author: '刘长卿', poem: '因家汉水曲，相送掩柴扉。\n故郢生秋草，寒江澹落晖。\n绿林行客少，赤壁住人稀。\n独过浔阳去，潮归人不归。' },
  { title: '送金昌宗归钱塘', author: '刘长卿', poem: '新家浙江上，独泛落潮归。\n秋水照华发，凉风生褐衣。\n柴门嘶马少，藜杖拜人稀。\n惟有陶潜柳，萧条对掩扉。' },
  { title: '酬张夏别后道中见寄', author: '刘长卿', poem: '离群方岁晏，谪宦在天涯。\n暮雪同行少，寒潮欲上迟。\n海鸥知吏傲，砂鹤见人衰。\n只畏生秋草，西归亦未期。' },
  { title: '新安奉送穆谕德归朝赋得行字', author: '刘长卿', poem: '九重宣室召，万里建溪行。\n事直皇天在，归迟白发生。\n用材身复起，覩圣眼犹明。\n离别寒江上，潺湲若有情。' },
  { title: '偶然作', author: '刘长卿', poem: '野寺长依止，田家或往还。\n老农开古地，夕鸟入寒山。\n书劒身同废，烟霞吏共闲。\n岂能将白发，扶杖出人间。' },
  { title: '送州人孙沅自本州却归句章新营所居', author: '刘长卿', poem: '故里归成客，新家去未安。\n诗书满蜗舍，征税及渔竿。\n火种山田薄，星居海岛寒。\n怜君不得已，步步别离难。' },
  { title: '送李员外使还苏州兼呈前袁州李使君赋得长字袁州即员外之从兄', author: '刘长卿', poem: '别离共成怨，衰老更难忘。\n夜月留同舍，秋风在远乡。\n朱弦徐向烛，白发强临觞。\n归献西陵作，谁知此路长。' },
  { title: '酬李员外从崔录事载华宿三河戍先见寄', author: '刘长卿', poem: '寒江鸣石濑，归客夜初分。\n人语空山答，猨声独戍闻。\n迟来朝及暮，愁去水连云。\n岁晚心谁在，青山见此君。' },
  { title: '见秦系离婚后出山居作', author: '刘长卿', poem: '岂知偕老重，垂老绝良姻。\n郗氏诚难负，朱家自媿贫。\n绽衣留欲故，织锦罢经春。\n何况蘼芜绿，空山不见人。' },
  { title: '酬秦系', author: '刘长卿', poem: '鹤书犹未至，那出白云来。\n旧路经年别，寒潮每日回。\n家空归海燕，人老发江梅。\n最忆门前柳，闲居手自栽。' },
  { title: '岁日作', author: '刘长卿', poem: '建寅回北斗，看历占春风。\n律变沧江外，年加白发中。\n春衣试稚子，寿酒劝衰翁。\n今日阳和发，荣枯岂不同。' },
  { title: '题元录事开元所居', author: '刘长卿', poem: '幽居萝薜情，高卧纪纲行。\n鸟散秋鹰下，人闲春草生。\n冒风归野寺，收印出山城。\n今日新安郡，因君水更清。' },
  { title: '送崔载华张起之闽中', author: '刘长卿', poem: '不识闽中路，遥知别后心。\n猨声入岭切，鸟道问人深。\n旅食过夷落，方言会越音。\n西征开幕府，早晚用陈琳。' },
  { title: '送张司直赴岭南谒张尚书', author: '刘长卿', poem: '番禺万里路，远客片帆过。\n盛府依横海，荒祠拜伏波。\n人经秋瘴变，鸟坠火云多。\n诚惮炎洲里，无如一顾何。' },
  { title: '寄会稽公徐侍郎', author: '刘长卿', poem: '摇落淮南叶，秋风想越吟。\n皱枚入梁苑，逸少在山阴。\n老鹤无衰貌，寒松有本心。\n圣朝难税驾，惆怅白云深。' },
  { title: '送朱山人放越州贼退后归山阴别业', author: '刘长卿', poem: '越州初罢战，江上送归桡。\n南渡无来客，西陵自落潮。\n空城垂故柳，旧业废春苗。\n闾里相逢少，莺花共寂寥。' },
  { title: '秋夜肃公房喜普门上人自阳羡山至', author: '刘长卿', poem: '山栖久不见，林下偶同游。\n早晚来香积，何人住沃洲。\n寒禽惊后夜，古木带高秋。\n却入千峰去，孤云不可留。' },
  { title: '送李秘书却赴南中', author: '刘长卿', poem: '却到番禺日，应伤昔所依。\n炎洲百口住，故国几人归。\n路识梅花在，家存棣萼稀。\n独逢回雁去，犹作旧行飞。' },
  { title: '过前安宜张明府郊居', author: '刘长卿', poem: '寂寥东郭外，白首一先生。\n解印孤琴在，移家五柳成。\n夕阳临水钓，春雨向田耕。' },
  { title: '使回次杨柳过元八所居', author: '刘长卿', poem: '君家杨柳渡，来往落帆过。\n绿竹经寒在，青山欲暮多。\n薜萝诚可恋，婚嫁复如何。\n无奈闲门外，渔翁夜夜歌。' },
  { title: '送李侍御贬郴州', author: '刘长卿', poem: '洞庭波渺渺，君去吊灵均。\n几路三湘水，全家万里人。\n听猨明月夜，看柳故年春。\n忆想汀洲畔，伤心向白苹。' },
  { title: '寄普门上人', author: '刘长卿', poem: '白云幽卧处，不向世人传。\n闻在千峰里，心知独夜禅。\n辛勤羞薄禄，依止爱闲田。\n惆怅王孙草，青青又一年。' },
  { title: '逢郴州使因寄郑协律', author: '刘长卿', poem: '相思楚天外，梦寐楚猨吟。\n更落淮南叶，难为江上心。\n衡阳问人远，湘水向君深。' },
  { title: '岳阳馆中望洞庭湖', author: '刘长卿', poem: '万古巴丘戍，平湖此望长。\n问人何淼淼，愁暮更苍苍。\n叠浪浮元气，中流没太阳。\n孤舟有归客，早晚达潇湘。' },
  { title: '巡去岳阳却归鄂州使院留别郑洵侍御先曾谪居此州', author: '刘长卿', poem: '何事长沙谪，相逢楚水秋。\n暮帆归夏口，寒雨对巴丘。\n帝子椒浆奠，骚人木叶愁。\n惟怜万里外，离别洞庭头。' },
  { title: '夏口送屈突司直使湖南', author: '刘长卿', poem: '共悲来夏口，何事更南征。\n雾露行人少，潇湘春草生。\n莺啼何处梦，猨啸若为声。\n风月新年好，悠悠远客情。' },
  { title: '代边将有怀', author: '刘长卿', poem: '少年辞魏阙，白首向沙场。\n瘦马恋秋草，征人思故乡。\n暮笳吹寒月，晓甲带胡霜。\n自到云中郡，于今百战强。' },
  { title: '雨中过员稷巴陵山居赠别', author: '刘长卿', poem: '怜君洞庭上，白发向人垂。\n积雨悲幽独，长江对别离。\n牛羊归故道，猨鸟聚寒枝。\n明发遥相望，云山不可知。' },
  { title: '送李中丞之襄州', author: '刘长卿', poem: '流落征南将，曾驱十万师。\n罢归无旧业，老去恋明时。\n独立三朝识，轻生一劒知。\n茫茫汉江上，日暮复何之。' },
  { title: '奉使至申州伤经陷没', author: '刘长卿', poem: '举目伤芜没，何年此战争。\n归人失旧里，老将守孤城。\n废戍山烟出，荒田野火行。\n独怜浉水上，时乱亦能清。' },
  { title: '穆陵关北逢人归渔阳', author: '刘长卿', poem: '逢君穆陵路，匹马向桑干。\n楚国苍山古，幽州白日寒。\n城池百战后，耆旧几家残。\n处处蓬蒿遍，归人掩泪看。' },
  { title: '安州道中经浐水有怀', author: '刘长卿', poem: '征途逢浐水，忽似到秦川。\n借问朝天处，犹看落日边。\n映沙晴漾漾，出涧夜溅溅。\n欲寄西归恨，微波不可传。' },
  { title: '步登夏口古城作', author: '刘长卿', poem: '平芜连古堞，远客此沾衣。\n高树朝光上，空城秋气归。\n微明汉水极，摇落楚人稀。\n但见荒郊外，寒鵶暮暮飞。' },
  { title: '赠别卢司直之闽中', author: '刘长卿', poem: '尔来多不见，此去又何之。\n华发同今日，流芳似旧时。\n洲长春色遍，汉广夕阳迟。\n岁岁王孙草，空怜无处期。' },
  { title: '酬郭夏人日长沙感怀见赠', author: '刘长卿', poem: '旧俗欢犹在，怜君恨独深。\n新年向国泪，今日倚门心。\n岁去随湘水，春生近桂林。\n流莺且莫弄，江畔正行吟。' },
  { title: '赴巴南书情寄故人', author: '刘长卿', poem: '南过三湘去，巴人此路偏。\n谪居秋瘴里，归处夕阳边。\n直道天何在，愁容镜亦怜。\n裁书欲谁诉，无泪可潸然。' },
  { title: '余干旅舍', author: '刘长卿', poem: '摇落暮天迥，青枫霜叶稀。\n孤城向水闭，独鸟背人飞。\n渡口月初上，邻家渔未归。\n乡心正欲绝，何处捣寒衣。' },
  { title: '登思禅寺上方题修竹茂松', author: '刘长卿', poem: '上方幽且暮，台殿隐蒙笼。\n远磬秋山里，清猨古木中。\n众溪连竹路，诸岭共松风。\n傥许栖林下，甘成白首翁。' },
  { title: '恩敕重推使牒追赴苏州次前溪馆作', author: '刘长卿', poem: '渐入云峰里，愁看驿路闲。\n乱鵶投落日，疲马向空山。\n且喜怜非罪，何心恋末班。\n天南一万里，谁料得生还。' },
  { title: '北归次秋浦界清溪馆', author: '刘长卿', poem: '万里猨啼断，孤村客暂依。\n雁过彭蠡暮，人向宛陵稀。\n旧路青山在，余生白首归。\n渐知行近北，不见鹧鸪飞。' },
  { title: '谪官后却归故村将过虎丘怅然有作', author: '刘长卿', poem: '万事依然在，无如岁月何。\n邑人怜白发，庭树长新柯。\n故老相逢少，同官不见多。\n唯余旧山路，惆怅枉帆过。' },
  { title: '重推后却赴岭外待进止寄元侍郎', author: '刘长卿', poem: '却访巴人路，难期国士恩。\n白云从出岫，黄叶已辞根。\n大造功何薄，长年气尚冤。\n空令数行泪，来往落湘沅。' },
  { title: '秋杪江亭有作', author: '刘长卿', poem: '寂寞江亭下，江枫秋气斑。\n世情何处澹，湘水向人闲。\n寒渚一孤雁，夕阳千万山。\n扁舟如落叶，此去未知还。' },
  { title: '送郑司直归上都', author: '刘长卿', poem: '岁岁逢离别，蹉跎江海滨。\n宦游成楚老，乡思逐秦人。\n马首归何日，莺啼又一春。\n因君报情旧，闲慢欲垂纶。' },
  { title: '送灵澈上人归嵩阳兰若', author: '刘长卿', poem: '南地随缘久，东林几岁空。\n暮山门独掩，春草路难通。\n作梵连松韵，焚香入桂丛。\n唯将旧缾钵，却寄白云中。' },
  { title: '却赴南邑留别苏台知己', author: '刘长卿', poem: '又过梅岭上，岁岁此枝寒。\n落日孤舟去，青山万里看。\n猨声湘水静，草色洞庭宽。\n已料生涯事，唯应把钓竿。' },
  { title: '和灵一上人新泉', author: '刘长卿', poem: '东林一泉出，复与远公期。\n石浅寒流处，山空夜落时。\n梦闲闻细响，虑澹对清漪。\n动静皆无意，唯应达者知。' },
  { title: '送李挚赴延陵令', author: '刘长卿', poem: '清风季子邑，想见下车时。\n向水弹琴静，看山采菊迟。\n明君加印绶，廉使托惸[嫠]。\n旦暮华阳洞，云峰若有期。' },
  { title: '奉送裴员外赴上都', author: '刘长卿', poem: '彤襜江上远，万里诏书催。\n独过浔阳去，空怜潮信回。\n离心秋草绿，挥手暮帆开。\n想见秦城路，人看五马来。' },
  { title: '长沙桓王墓下别李纾张南史', author: '刘长卿', poem: '长沙千载后，春草独萋萋。\n流水朝将暮，行人东复西。\n碑苔几字灭，山木万株齐。\n伫立伤今古，相看惜解携。' },
  { title: '送侯御赴黔中充判官', author: '刘长卿', poem: '不识黔中路，今看遣使臣。\n猨啼万里客，鸟似五湖人。\n地远官无法，山深俗岂淳。\n须令荒徼外，亦解惧埋轮。' },
  { title: '秋日登吴公台上寺远眺寺即陈将吴明彻战场', author: '刘长卿', poem: '古台摇落后，秋日望乡心。\n野寺人来少，云峰水隔深。\n夕阳依旧垒，寒磬满空林。\n惆怅南朝事，长江独至今。' },
  { title: '淮上送梁二恩命追赴上都', author: '刘长卿', poem: '贾生年最少，儒行汉庭闻。\n拜手卷黄纸，回身谢白云。\n故关无去客，春草独随君。\n淼淼长淮水，东西自此分。' },
  { title: '送崔升归上都', author: '刘长卿', poem: '旧寺寻遗绪，归心逐去尘。\n早莺何处客，古木几家人。\n白发经多难，沧洲欲暮春。\n临期数行泪，为尔一沾巾。' },
  { title: '过李将军南郑林园观妓', author: '刘长卿', poem: '郊原风日好，百舌弄何频。\n小妇秦家女，将军天上人。\n鸦归长郭暮，草映大堤春。\n客散垂杨下，通桥车马尘。' },
  { title: '送严侍御充东畿观察判官', author: '刘长卿', poem: '洛阳征战后，君去问凋残。\n云月临南至，风霜向北寒。\n故园经乱久，古木隔林看。\n谁访江城客，年年守一官。' },
  { title: '送王端公入奏上都', author: '刘长卿', poem: '旧国无家访，临歧亦羡归。\n途经百战后，客过二陵稀。\n秋草通征骑，寒城背落晖。\n行当蒙顾问，吴楚岁频饥。' },
  { title: '送营田判官郑侍御赴上都', author: '刘长卿', poem: '上国三千里，西还及岁芳。\n故山经乱在，春日送归长。\n晓奏趋双阙，秋成报万箱。\n幸论开济力，已实海陵仓。' },
  { title: '送李校书赴东浙幕府', author: '刘长卿', poem: '方从大夫后，南去会稽行。\n淼淼沧江外，青青春草生。\n芸香辞乱事，梅吹听军声。\n应访王家宅，空怜江水平。' },
  { title: '清明后登城眺望', author: '刘长卿', poem: '风景清明后，云山睥睨前。\n百花如旧日，万井出新烟。\n草色无空地，江流合远天。\n长安在何处？遥指夕阳边。' },
  { title: '陪王明府泛舟', author: '刘长卿', poem: '花县弹琴暇，樵风载酒时。\n山含秋色近，鸟度夕阳迟。\n出没凫成浪，蒙笼竹亚枝。\n云峰逐人意，来去解相随。' },
  { title: '送度支留后若侍御之歙州便赴信州省觐', author: '刘长卿', poem: '国用忧钱谷，朝推此任难。\n即山榆荚变，降雨稻花残。\n林响朝登岭，江喧夜过滩。\n遥知骢马色，应待倚门看。' },
  { title: '余干夜宴奉饯前苏州韦使君新除婺州作', author: '刘长卿', poem: '复拜东阳郡，遥驰北阙心。\n行春五马急，向夜一猨深。\n山过康郎近，星看婺女临。\n幸容栖托分，犹恋旧棠阴。' },
  { title: '晚次苦竹馆却忆干越旧游', author: '刘长卿', poem: '匹马风尘色，千峰旦暮时。\n遥看落日尽，独向远山迟。\n故驿花临道，荒村竹映篱。\n谁怜却回首，步步恋南枝。' },
  { title: '送李二十四移家之江州', author: '刘长卿', poem: '烟尘犹满目，歧路易沾衣。\n逋客多南渡，征鸿自北飞。\n九江春草绿，千里暮潮归。\n别后难相访，全家隐钓矶。' },
  { title: '送卢判官南湖', author: '刘长卿', poem: '漾舟仍载酒，愧尔意相宽。\n草色南湖绿，松声小署寒。\n水禽前后起，花屿往来看。\n已作沧洲调，无心恋一官。' },
  { title: '送张栩扶侍之睦州', author: '刘长卿', poem: '遥忆新安旧，扁舟复却还。\n浅深看水石，来往逐云山。\n入县余花在，过门故柳闲。\n东征随子去，皆隐薜萝间。' },
  { title: '集梁耿开元寺所居院', author: '刘长卿', poem: '到君幽卧处，为我埽莓苔。\n花雨晴天落，松风终日来。\n路经深竹过，门向远山开。\n岂得长高枕，中朝正用才。' },
  { title: '赠西邻卢少府', author: '刘长卿', poem: '篱落能相近，渔樵偶复同。\n苔封三径绝，溪向数家通。\n犬吠寒烟里，鵶鸣夕照中。\n时因杖藜次，相访竹林东。' },
  { title: '游休禅师双峰寺', author: '刘长卿', poem: '双扉碧峰际，遥向夕阳开。\n飞锡方独往，孤云何事来。\n寒潭映白月，秋雨上青苔。\n相送东郊外，羞看骢马回。' },
  { title: '廨中见桃花南枝已开北枝未发因寄杜副端', author: '刘长卿', poem: '何意同根本，开花每后时。\n应缘去日远，独自发春迟。\n结实恩难忘，无言恨岂知。\n年光不可待，空羡向南枝。' },
  { title: '奉送卢员外之饶州', author: '刘长卿', poem: '天书万里至，旌斾上江飞。\n日向鄱阳近，应看吴岫微。\n暮帆何处落？潮水背人归。\n风土无劳问，南枝黄叶稀。' },
  { title: '送处士归州因寄林山人', author: '刘长卿', poem: '陵阳不可见，独往复如何。\n旧邑云山里，扁舟来去过。\n鸟声春谷静，草色太湖多。\n傥宿荆溪夜，相思渔者歌。' },
  { title: '移使鄂州次岘阳馆怀旧居', author: '刘长卿', poem: '多慙恩未报，敢问路何长。\n万里通秋雁，千峰共夕阳。\n旧游成远道，此去更违乡。\n草露深山里，朝朝落客裳。' },
  { title: '送齐郎中赴海州', author: '刘长卿', poem: '华省占星动，孤城望日遥。\n直庐收旧草，行县及新苗。\n沧海天连水，青山暮与朝。\n闾阎几家散，应待下车招。' },
  { title: '重阳日鄂城楼送屈突司直', author: '刘长卿', poem: '登高复送远，惆怅洞庭秋。\n风景同前古，云山满上游。\n苍苍来暮雨，淼淼逐寒流。\n今日关中事，萧何共尔忧。' },
  { title: '更被奏留淮南送从弟罢使江东', author: '刘长卿', poem: '又作淮南客，还悲木叶声。\n寒潮落瓜步，秋色上芜城。\n王事何时尽？沧洲羡尔行。\n青山将绿水，惆怅不胜情。' },
  { title: '经漂母墓', author: '刘长卿', poem: '昔贤怀一饭，兹事已千秋。\n古墓樵人识，前朝楚水流。\n渚苹行客荐，山木杜鹃愁。\n春草茫茫绿，王孙旧此游。' },
  { title: '送李端公赴东都', author: '刘长卿', poem: '轩辕征战后，江海别离长。\n远客归何处，平芜满故乡。\n夕阳帆杳杳，旧里树苍苍。\n惆怅蓬山下，琼枝不可忘。' },
  { title: '送王员外归朝', author: '刘长卿', poem: '往来无尽目，离别要逢春。\n海内罹多事，天涯见近臣。\n芳时万里客，乡路独归人。\n魏阙心常在，随君亦向秦。' },
  { title: '送蒋侍御入秦', author: '刘长卿', poem: '朝见及芳菲，恩荣出紫微。\n晚光临仗奏，春色共西归。\n楚客移家老，秦人访旧稀。\n因君乡里去，为埽故园扉。' },
  { title: '洞庭驿逢郴州使还寄李汤司马', author: '刘长卿', poem: '洞庭秋水阔，南望过衡峰。\n远客潇湘里，归人何处逢。\n孤云飞不定，落叶去无踪。\n莫使沧浪叟，长歌笑尔容。' },
  { title: '送舍弟之鄱阳居', author: '刘长卿', poem: '鄱阳寄家处，自别掩柴扉。\n故里人何在，沧波孤客稀。\n湖山春草遍，云木夕阳微。\n南去逢回鴈，应怜相背飞。' },
  { title: '送裴二十端公使岭南', author: '刘长卿', poem: '苍梧万里路，空见白云来。\n远国知何在，怜君去未回。\n桂林无叶落，梅岭自花开。\n陆贾千年后，谁看朝汉台。' },
  { title: '过桃花夫人庙', author: '刘长卿', poem: '寂寞应千岁，桃花想一枝。\n路人看古木，江月向空祠。\n云雨飞何处，山川是旧时。\n独怜春草色，犹似忆佳期。' },
  { title: '鄂渚送池州程使君', author: '刘长卿', poem: '萧萧五马动，欲别谢临川。\n落日芜湖色，空山梅冶烟。\n江湖通廨舍，楚老拜戈船。\n风化东南满，行舟来去传。' },
  { title: '送友人西上', author: '刘长卿', poem: '羁心不自解，有别会沾衣。\n春草连天积，五陵远客归。\n十年经转战，几处便芳菲。\n想见函关路，行人去亦稀。' },
  { title: '送梁郎中赴吉州', author: '刘长卿', poem: '遥想庐陵郡，还听叔度歌。\n旧官移上象，新令布中和。\n看竹经霜少，闻猨带雨多。\n但愁征拜日，无奈借留何。' },
  { title: '过湖南羊处士别业', author: '刘长卿', poem: '杜门成白首，湖上寄生涯。\n秋草芜三径，寒塘独一家。\n鸟归村落尽，水向县城斜。\n自有东篱菊，年年解作花。' },
  { title: '送河南元判官赴河南句当苗税充百官俸钱', author: '刘长卿', poem: '春草长河曲，离心共渺然。\n方收汉家俸，独向汶阳田。\n鸟雀空城在，榛芜旧路迁。\n山东征战苦，几处有人烟。' },
  { title: '夏中崔中丞宅见海红摇落一花独开', author: '刘长卿', poem: '何事一花残，闲庭百草阑。\n绿滋经雨发，红艳隔林看。\n竟日余香在，过时独秀难。\n共怜芳意晚，秋露未须团。' },
  { title: '使还至菱陂驿渡浉水作', author: '刘长卿', poem: '清川已再涉，疲马共西还。\n何事行人倦，终年流水闲。\n孤烟飞广泽，一鸟向空山。\n愁入云峰里，苍苍闭古关。' },
  { title: '送齐郎中典括州', author: '刘长卿', poem: '星象移何处，旌麾独向东。\n劝耕沧海畔，听讼白云中。\n树色双溪合，猨声万岭同。\n石门康乐住，几里枉帆通。' },
  { title: '过隐空和尚故居', author: '刘长卿', poem: '自从飞锡去，人到沃洲稀。\n林下期何在，山中春独归。\n踏花寻旧径，映竹掩空扉。\n寥落东峰上，犹堪静者依。' },
  { title: '过萧尚书故居见李花感而成咏', author: '刘长卿', poem: '手植已芳菲，心伤故径微。\n往年啼鸟至，今日主人非。\n满地谁当埽，随风岂复归。\n空怜旧阴在，门客共沾衣。' },
  { title: '送袁处士', author: '刘长卿', poem: '闲田北川下，静者去躬耕。\n万里空江菼，孤舟过郢城。\n种荷依野水，移柳待山莺。\n出处安能问，浮云岂有情。' },
  { title: '酬李侍御登岳阳见寄', author: '刘长卿', poem: '想见孤舟去，无由此路寻。\n暮帆遥在眼，春色独何心。\n绿水潇湘阔，青山鄠杜深。\n谁当北风至，为尔一开襟。' },
  { title: '喜晴', author: '刘长卿', poem: '晓日西风转，秋天万里明。\n湖天一种色，林鸟百般声。\n霁景浮云满，游丝暎水轻。\n今朝江上客，凡慰几人情。' },
  { title: '夏口送徐郎中归朝', author: '刘长卿', poem: '星象南宫远，风流上客稀。\n九重思晓奏，万里见春归。\n棹发空江响，城孤落日晖。\n离心与杨柳，临水更依依。' },
  { title: '鄂渚听杜别驾弹胡琴', author: '刘长卿', poem: '文姬留此曲，千载一知音。\n不解胡人语，空留楚客心。\n听随边草动，意入陇云深。\n何事长江上，萧萧出塞吟。' },
  { title: '过鹦鹉洲王处士别业', author: '刘长卿', poem: '白首此为渔，青山对结庐。\n问人寻野笋，留客馈家蔬。\n古柳依沙发，春苗带雨锄。\n共怜芳杜色，终日伴闲居。' },
  { title: '寄万州崔使君', author: '刘长卿', poem: '时艰方用武，儒者任浮沈。\n摇落秋江暮，怜君巴峡深。\n丘门多白首，蜀郡满青襟。\n自解书生咏，愁猨莫夜吟。' },
  { title: '送马秀才移家京洛便赴举', author: '刘长卿', poem: '自从为楚客，不复扫荆扉。\n劒共丹诚在，书随白发归。\n旧游经乱静，后进识君稀。\n空把相如赋，何人荐礼闱。' },
  { title: '送南特进赴归行营', author: '刘长卿', poem: '闻道军书至，扬鞭不问家。\n虏云连白草，汉月到黄沙。\n汗马河源饮，烧羌陇坻遮。\n翩翩新结束，去逐李轻车。' },
  { title: '送道标上人归南岳', author: '刘长卿', poem: '悠然倚孤棹，却忆卧中林。\n江草将归远，湘山独往深。\n白云留不住，渌水去无心。\n衡岳千峰乱，禅房何处寻。' },
  { title: '送梁侍御巡永州', author: '刘长卿', poem: '萧萧江雨暮，客散野亭空。\n忧国天涯去，思乡岁暮同。\n到时猨未断，回处水应穷。\n莫望零陵路，千峰万木中。' },
  { title: '岁夜喜魏万成郭夏雪中相寻', author: '刘长卿', poem: '新年欲变柳，旧客共沾衣。\n岁夜犹难尽，乡春又独归。\n寒灯映虚牖，暮雪掩闲扉。\n且莫乘船去，平生相访稀。' },
  { title: '送蔡侍御赴上都', author: '刘长卿', poem: '迟迟立驷马，久客恋潇湘。\n明日谁同路，新年独到乡。\n孤烟向驿远，积雪去关长。\n秦地看春色，南枝不可忘。' },
  { title: '晦日陪辛大夫宴南亭', author: '刘长卿', poem: '月晦逢休澣，年光逐宴移。\n早莺留客醉，春日为人迟。\n蓂草全无叶，梅花遍压枝。\n政闲风景好，莫比岘山时。' },
  { title: '送独孤判官赴岭', author: '刘长卿', poem: '伏波初树羽，待尔静川鳞。\n岭海看飞鸟，天涯问远人。\n苍梧云里夕，青草嶂中春。\n遥想文身国，迎舟拜使臣。' },
  { title: '长沙馆中与郭夏对雨', author: '刘长卿', poem: '长沙积雨晦，深巷绝人幽。\n润上春衣冷，声连暮角愁。\n云横全楚地，树暗古湘洲。\n杳蔼江天外，空堂生百忧。' },
  { title: '陪辛大夫西亭宴观妓', author: '刘长卿', poem: '歌舞怜迟日，旌麾映早春。\n莺窥陇西将，花对洛阳人。\n醉罢知何事，恩深忘此身。\n任他行雨去，归路裛香尘。' },
  { title: '题魏万成江亭', author: '刘长卿', poem: '萧条方岁晏，牢落对空洲。\n才出时人右，家贫湘水头。\n苍山隐暮雪，白鸟没寒流。\n不是莲花府，冥冥不可求。' },
  { title: '春过裴虬郊园', author: '刘长卿', poem: '郊原春欲暮，桃杏落纷纷。\n何处随芳草，留家寄白云。\n听莺情念友，看竹恨无君。\n长啸高台上，南风冀尔闻。' },
  { title: '送韦赞善使岭南', author: '刘长卿', poem: '欲逐楼船将，方安卉服夷。\n炎洲经瘴远，春水上泷迟。\n岁贡随重译，年芳徧四时。\n番禺静无事，空咏饮泉诗。' },
  { title: '送乔判官赴福州', author: '刘长卿', poem: '扬帆向何处，插羽逐征东。\n夷落人烟迥，王程鸟路通。\n江流回涧底，山色聚闽中。\n君去凋残后，应怜百越空。' },
  { title: '送李补阙之上都', author: '刘长卿', poem: '独归西掖去，难接后尘游。\n向日三千里，朝天十二楼。\n路看新柳夕，家对旧山秋。\n惆怅离心远，沧江空自流。' },
  { title: '送袁明府之任', author: '刘长卿', poem: '既有亲人术，还逢试吏年。\n蓬蒿千里闭，村树几家全。\n雪覆淮南道，春生颍谷烟。\n何时当莅政，相府待闻天。' },
  { title: '海盐官舍早春', author: '刘长卿', poem: '小邑沧洲吏，新年白首翁。\n一官如远客，万事极飘蓬。\n柳色孤城里，莺声细雨中。\n羁心早已乱，何事更春风。' },
  { title: '南湖送徐二十七西上', author: '刘长卿', poem: '家在横塘曲，那能万里违。\n门临秋水掩，帆带夕阳飞。\n傲俗宜纱帽，干时倚布衣。\n独将湖上月，相逐去还归。' },
  { title: '曲阿对月别岑况徐说', author: '刘长卿', poem: '金陵已芜没，函谷复烟尘。\n犹见南朝月，还随上国人。\n白云心自远，沧海意相亲。\n何事须成别，汀洲欲暮春。' },
  { title: '送李侍御贬鄱阳', author: '刘长卿', poem: '回车仍昨日，谪去已秋风。\n干越知何处，云山只向东。\n暮天江色里，田鹤稻花中。\n却见鄱阳吏，犹应旧马骢。' },
  { title: '送路少府使东京便应制举', author: '刘长卿', poem: '故人西奉使，胡骑正纷纷。\n旧国无来信，春江独送君。\n五言凌白雪，六翮向青云。\n谁念沧州吏，忘机鸥鸟群。' },
  { title: '松江独宿', author: '刘长卿', poem: '洞庭初下叶，孤客不胜愁。\n明月天涯夜，青山江上秋。\n一官成白首，万里寄沧洲。\n久被浮名系，能无媿海鸥。' },
  { title: '寻白石山真禅师旧草堂', author: '刘长卿', poem: '惆怅云山暮，闲门独不开。\n何时飞杖锡，终日闭苍苔。\n隔岭春犹在，无人燕亦来。\n谁堪暝投处，空复一猨哀。' },
  { title: '送行军张司马罢使回', author: '刘长卿', poem: '时危身赴敌，事往任浮沈。\n末路三江去，当时百战心。\n春风吴苑绿，古木剡山深。\n千里沧波上，孤舟不可寻。' },
  { title: '喜李翰自越至', author: '刘长卿', poem: '南浮沧海上，万里到吴台。\n久别长相忆，孤舟何处来。\n春风催客醉，江月向人开。\n羡尔无羁束，沙鸥独不猜。' },
  { title: '罪所留系寄张十四', author: '刘长卿', poem: '不见君来久，冤深意未传。\n冶长空得罪，夷甫岂言钱。\n直道天何在，愁容镜亦怜。\n因书欲自诉，无泪可潸然。' },
  { title: '送勤照和尚往睢阳赴太守请', author: '刘长卿', poem: '燃灯传七祖，杖锡为诸侯。\n来去云无意，东西水自流。\n青山春满目，白日夜随舟。\n知到梁园下，苍生赖此游。' },
  { title: '长门怨', author: '刘长卿', poem: '何事长门闭，珠帘只自垂。\n月移深殿早，春向后宫迟。\n蕙草生闲地，梨花发旧枝。\n芳菲自恩幸，看着被风吹。' },
  { title: '过横山顾山人草堂', author: '刘长卿', poem: '只见山相掩，谁言路尚通。\n人来千嶂外，犬吠百花中。\n细草香飘雨，垂杨闲卧风。\n却寻樵径去，惆怅绿溪东。' },
  { title: '送李校书适越谒杜中丞', author: '刘长卿', poem: '江风处处尽，旦暮水空波。\n摇落行人去，云山向越多。\n陈蕃悬榻待，谢客枉帆过。\n相见耶溪路，逶迤入薜萝。' },
  { title: '秋夜雨中诸公过灵光寺所居', author: '刘长卿', poem: '晤语青莲舍，重门闭夕阴。\n向人寒烛静，带雨夜钟沈。\n流水从他事，孤云任此心。\n不能捐斗粟，终日媿瑶琴。' },
  { title: '西庭夜燕喜评事兄拜会', author: '刘长卿', poem: '犹是南州吏，江城又一春。\n隔帘湖上月，对酒眼中人。\n棘寺初衔命，梅仙已误身。\n无心羡荣禄，唯待却垂纶。' },
  { title: '寻南溪常山道人隐居', author: '刘长卿', poem: '一路经行处，莓苔见履痕。\n白云依静渚，春草闭闲门。\n过雨看松色，随山到水源。\n溪花与禅意，相对亦忘言。' },
  { title: '扬州雨中张十宅观妓', author: '刘长卿', poem: '夜色带春烟，灯花拂更然。\n残粧添石黛，艳舞落金钿。\n掩笑频欹扇，迎歌乍动弦。\n不知巫峡雨，何事海西边。' },
  { title: '赴宣州使院夜宴寂上人房留辞前苏州韦使君', author: '刘长卿', poem: '白云乖始愿，沧海有微波。\n恋旧争趋府，临危欲负戈。\n春归花殿暗，秋傍竹房多。\n耐可机心息，其如羽檄何。' },
  { title: '送薛承矩秩满北游', author: '刘长卿', poem: '匹马向何处，北游殊未还。\n寒云带飞雪，日暮雁门关。\n一路傍汾水，数州看晋山。\n知君喜初服，秪爱此身闲。' },
  { title: '饯别王十一南游', author: '刘长卿', poem: '望君烟水阔，挥手泪沾巾。\n飞鸟没何处，青山空向人。\n长江一帆远，落日五湖春。\n谁见汀洲上，相思愁白苹。' },
  { title: '送严维尉诸暨', author: '刘长卿', poem: '爱尔文章远，还家印绶荣。\n退公兼色养，临下带乡情。\n乔木映官舍，春山宜县城。\n应怜钓台石，闲却为浮名。' },
  { title: '送李七之莋水谒张相公', author: '刘长卿', poem: '惆怅青春晚，慇懃浊酒垆。\n后时长劒涩，斜日片帆孤。\n东阁邀才子，南昌老腐儒。\n梁国旧相识，谁忆卧江湖。' },
  { title: '送崔处士先适越', author: '刘长卿', poem: '山阴好云物，此去又春风。\n越鸟闻花里，曹娥想镜中。\n小江潮易满，万井水皆通。\n徒羡扁舟客，微官事不同。' },
  { title: '奉陪使君西庭送淮西魏判官', author: '刘长卿', poem: '羽檄催归恨，春风醉别颜。\n能邀五马送，自逐一星还。\n破竹从军乐，看花听讼闲。\n遥知用兵处，多在八公山。' },
  { title: '狱中见壁画佛', author: '刘长卿', poem: '不谓衔冤处，而能窥大悲。\n独栖丛棘下，还见雨花时。\n地狭青莲小，城高白日迟。\n幸亲方便力，犹畏毒龙欺。' },
  { title: '送许拾遗还京', author: '刘长卿', poem: '万里辞三殿，金陵到旧居。\n文星出西掖，卿月在南徐。\n故里惊朝服，高堂捧诏书。\n暂容乘驷马，谁许恋鲈鱼。' },
  { title: '送张七判官还京觐省', author: '刘长卿', poem: '春兰方可采，此去叶初齐。\n函谷莺声里，秦山马首西。\n庭闱新栢署，门馆旧桃蹊。\n春色长安道，相随入禁闺。' },
  { title: '送孙莹京监擢第归蜀觐省', author: '刘长卿', poem: '适贺一枝新，旋惊万里分。\n礼闱称独步，太学许能文。\n征马望春草，行人看暮云。\n遥知倚门处，江树正氛氲。' },
  { title: '送史九赴任宁陵兼呈单父史八时监察五兄初入台', author: '刘长卿', poem: '趋府弟联兄，看君此去荣。\n春随千里道，河带万家城。\n绣服棠花映，青袍草色迎。\n梁园修竹在，持赠结交情。' },
  { title: '卧病喜田九见寄', author: '刘长卿', poem: '卧来能几日，春事已依然。\n不解谢公意，翻令静者便。\n庭阴残旧雪，柳色带新年。\n寂寞深村里，唯君相访偏。' },
  { title: '重过宣峰寺山房寄灵一上人', author: '刘长卿', poem: '西陵潮信满，岛屿入中流。\n越客依风水，相思南渡头。\n寒光生极浦，暮雪映沧洲。\n何事扬帆去，空惊海上鸥。' },
  { title: '云门寺访灵一上人', author: '刘长卿', poem: '所思劳日夕，惆怅去西东。\n禅客知何在，春山到处同。\n独行残雪里，相见白云中。\n请近东林寺，穷年事远公。' },
  { title: '送陆羽之茅山寄李延陵', author: '刘长卿', poem: '延陵衰草遍，有路问茅山。\n鸡犬驱将去，烟霞拟不还。\n新家彭泽县，旧国穆陵关。\n处处逃名姓，无名亦是闲。' },
  { title: '寄灵一上人初还云门', author: '刘长卿', poem: '寒霜白云里，法侣自相携。\n竹迳通城下，松风隔水西。\n方同沃洲去，不作武陵迷。\n髣髴知心处，高峰是会稽。' },
  { title: '寄灵一上人', author: '刘长卿', poem: '高僧本姓竺，开士旧名林。\n一去春山里，千峰不可寻。\n新年芳草遍，终日白云深。\n欲徇微官去，悬知讶此心。' },
  { title: '送韩司直', author: '刘长卿', poem: '游吴还入越，来往任风波。\n复送王孙去，其如春草何。\n岸明残雪在，潮满夕阳多。\n季子杨柳庙，停舟试一过。' },
  { title: '酬李郎中夜登苏州城楼见寄', author: '刘长卿', poem: '辛勤万里道，萧索九秋残。\n日照闽中夜，天凝海上寒。\n客程无地远，主意在人安。\n遥寄登楼作，空知行路难。' },
  { title: '送人游越', author: '刘长卿', poem: '未习风波事，初为吴越游。\n露沾湖色晓，月照海门秋。\n梅市门何在，兰亭水尚流。\n西陵待潮处，落日满扁舟。' },
  { title: '赠普门上人', author: '刘长卿', poem: '支公身欲老，长在沃洲多。\n惠力堪传教，禅心久伏魔。\n山云随坐夏，江草伴头陀。\n借问回心后，贤愚去几何。' },
  { title: '送康判官往新安', author: '刘长卿', poem: '不向新安去，那知江路长。\n猨声近庐霍，水色胜潇湘。\n驿路收残雨，渔家带夕阳。\n何须愁旅泊，使者有辉光。' },
  { title: '送顾长', author: '刘长卿', poem: '由来山水客，复道向新安。\n半是乘槎便，全非行路难。\n晨装林月在，野饭浦沙寒。\n严子千年后，何人钓旧滩。' },
  { title: '九日登李明府北楼', author: '刘长卿', poem: '九日登高望，苍苍远树低。\n人烟湖草里，山翠县楼西。\n霜降鸿声切，秋深客思迷。\n无劳白衣酒，陶令自相携。' },
  { title: '同诸公登楼', author: '刘长卿', poem: '秋草行将暮，登楼客思惊。\n千家同霁色，一鴈报寒声。\n北望无乡信，东游滞客行。\n今君佩铜墨，还有越乡情。' },
  { title: '送友人南游', author: '刘长卿', poem: '不愁寻水远，自爱逐连山。\n虽在春风里，犹从芳草间。\n去程何用计，胜事且相关。\n旅逸同群鸟，悠悠往复还。' },
  { title: '送裴二十一', author: '刘长卿', poem: '多病长无事，开筵暂送君。\n正愁帆带雨，莫望水连云。\n客思闲偏极，川程远更分。\n不须论早晚，惆怅又离群。' },
  { title: '送张判官罢使东归', author: '刘长卿', poem: '白首辞知己，沧洲忆旧居。\n落潮回野艇，积雪卧官庐。\n范叔寒犹在，周王岁欲除。\n春山数亩地，归去带经鉏。' },
  { title: '早春', author: '刘长卿', poem: '微雨夜来歇，江南春色回。\n本惊时不住，还恐老相催。\n人好千场醉，花无百日开。\n岂堪沧海畔，为客十年来。' },
  { title: '送青苗郑判官归江西', author: '刘长卿', poem: '三苗余古地，五稼满秋田。\n来问周公税，归输汉俸钱。\n江城寒背日，湓水暮连天。\n南楚凋残后，疲民赖尔怜。' },
  { title: '过包尊师山院', author: '刘长卿', poem: '卖药曾相识，吹萧此复闻。\n杏花谁是主，桂树独留君。\n漱玉临丹井，围碁访白云。\n道经今为写，不虑惜鹅群。' },
  { title: '故女道士婉仪太原郭氏挽歌词 一', author: '刘长卿', poem: '作范宫闱睦，归真道艺超。\n驭风仙路远，背日帝宫遥。\n鸾殿空留处，霓裳已罢朝。\n淮王哀不尽，松柏但萧萧。' },
  { title: '故女道士婉仪太原郭氏挽歌词 二', author: '刘长卿', poem: '宫禁恩长隔，神仙道已分。\n人间惊早露，天上失朝云。\n逝水年无限，佳城日易曛。\n箫声将薤曲，哀断不堪闻。' },
  { title: '少年行', author: '刘长卿', poem: '射飞夸侍猎，行乐爱联镳。\n荐枕青蛾艳，鸣鞭白马骄。\n曲房珠翠合，深巷管弦调。\n日晚春风里，衣香满路飘。' },
  { title: '归弋阳山居留别卢邵二侍御', author: '刘长卿', poem: '渺渺归何处，沿流附客船。\n久依鄱水住，频税越人田。\n偶俗机偏少，安闲性所便。\n祗应君少惯，又欲寄林泉。' },
  { title: '赴江西湖上赠皇甫曾之宣州', author: '刘长卿', poem: '莫恨扁舟去，川途我更遥。\n东西潮渺渺，离别雨萧萧。\n流水通春谷，青山过板桥。\n天涯有来客，迟尔访渔樵。' },
  { title: '湘中纪行十首 湘妃庙', author: '刘长卿', poem: '荒祠古木暗，寂寂此江𣸣。\n未作湘南雨，知为何处云。\n苔痕断珠履，草色带罗裙。\n莫唱迎仙曲，空山不可闻。' },
  { title: '湘中纪行十首 斑竹岩', author: '刘长卿', poem: '苍梧在何处，斑竹自成林。\n点点留残泪，枝枝寄此心。\n寒山响易满，秋水影偏深。\n欲觅樵人路，蒙笼不可寻。' },
  { title: '湘中纪行十首 洞山阳', author: '刘长卿', poem: '旧日仙成处，荒林客到稀。\n白云将犬去，芳草任人归。\n空谷无行径，深山少落晖。\n桃园几家住，谁为扫荆扉。' },
  { title: '湘中纪行十首 云母溪', author: '刘长卿', poem: '云母映溪水，溪流知几春。\n深藏武陵客，时过洞庭人。\n白发惭皎镜，清光媚奫沦。\n寥寥古松下，岁晚挂头巾。' },
  { title: '湘中纪行十首 赤沙湖', author: '刘长卿', poem: '茫茫葭菼外，一望一沾衣。\n秋水连天阔，涔阳何处归。\n沙鸥积暮雪，川日动寒晖。\n楚客来相问，孤舟泊钓矶。' },
  { title: '湘中纪行十首 秋云岭', author: '刘长卿', poem: '山色无定姿，如烟复如黛。\n孤峰夕阳后，翠岭秋天外。\n云起遥蔽亏，江回频向背。\n不知今远近，到处犹相对。' },
  { title: '湘中纪行十首 花石潭', author: '刘长卿', poem: '江枫日摇落，转爱寒潭静。\n水色淡如空，山光复相映。\n人闲流更慢，鱼戏波难定。\n楚客往来多，偏知白鸥性。' },
  { title: '湘中纪行十首 石围峰', author: '刘长卿', poem: '前山带秋色，独往秋江晚。\n叠嶂入云多，孤峰去人远。\n[夤]缘不可到，苍翠空在眼。\n渡口问渔家，桃源路深浅。' },
  { title: '湘中纪行十首 浮石濑', author: '刘长卿', poem: '秋月照潇湘，月明闻荡桨。\n石横晚濑急，水落寒沙广。\n众岭猨啸重，空江人语响。\n清晖朝复暮，如待扁舟赏。' },
  { title: '湘中纪行十首 横龙渡', author: '刘长卿', poem: '空传古岸下，曾见蛟龙去。\n秋水晚沈沈，犹疑在深处。\n乱声沙上石，倒影云中树。\n独见一扁舟，樵人往来渡。' },
  { title: '杂咏八首上礼部李侍郎 幽琴', author: '刘长卿', poem: '月色满轩白，琴声宜夜阑。\n飗飗青丝上，静听松风寒。\n古调虽自爱，今人多不弹。\n向君投此曲，所贵知音难。' },
  { title: '杂咏八首上礼部李侍郎 晚桃', author: '刘长卿', poem: '四月深涧底，桃花方欲然。\n宁知地势下，遂使春风偏。\n此意颇堪惜，无言谁为传。\n过时君未赏，空媚幽林前。' },
  { title: '杂咏八首上礼部李侍郎 疲马', author: '刘长卿', poem: '玄黄一疲马，筋力尽胡尘。\n骧首北风夕，徘徊鸣向人。\n谁怜弃置久，欲与驽骀亲。\n犹恋长城外，青青寒草春。' },
  { title: '杂咏八首上礼部李侍郎 春镜', author: '刘长卿', poem: '宝镜凌曙开，含虚净如水。\n独悬秦台上，万象清光里。\n岂虑高鉴偏，但防流尘委。\n不知娉婷色，回照今何似。' },
  { title: '杂咏八首上礼部李侍郎 古劒', author: '刘长卿', poem: '龙泉闲古匣，苔藓沦此地。\n何意久藏锋，翻令世人弃。\n铁衣今正涩，宝刃犹可试。\n傥遇拂拭恩，应知剸犀利。' },
  { title: '杂咏八首上礼部李侍郎 旧井', author: '刘长卿', poem: '旧井依旧城，寒水深洞彻。\n下看百余尺，一镜光不灭。\n素绠久未垂，清凉尚含洁。\n岂能无汲引，长讶君恩绝。' },
  { title: '杂咏八首上礼部李侍郎 白鹭', author: '刘长卿', poem: '亭亭常独立，川上时延颈。\n秋水寒白毛，夕阳吊孤影。\n幽姿闲自媚，逸翮思一骋。\n如有长风吹，青云在俄顷。' },
  { title: '杂咏八首上礼部李侍郎 寒釭', author: '刘长卿', poem: '向夕灯稍进，空堂弥寂寞。\n光寒对愁人，时复一花落。\n但恐明见累，何愁暗难托。\n恋君秋夜永，无使兰膏薄。' },
  { title: '寄李侍御', author: '刘长卿', poem: '旧国人未归，芳洲草还碧。\n年年湖上亭，怅望江南客。\n骢马入关西，白云独何适。\n相思烟水外，唯有心不隔。' },
  { title: '晚泊湘江怀故人', author: '刘长卿', poem: '天涯片云去，遥指帝乡忆。\n惆怅增暮情，潇湘复秋色。\n扁舟宿何处，落日羡归翼。\n万里无故人，江鸥不相识。' },
  { title: '过鄥三湖上书斋', author: '刘长卿', poem: '何事东南客，忘机一钓竿。\n酒香开瓮老，湖色对门寒。\n向郭青山送，临池白鸟看。\n见君能浪迹，予亦厌微官。' },
  { title: '从军六首 一', author: '刘长卿', poem: '回看虏骑合，城下汉兵稀。\n白刃两相向，黄云愁不飞。\n手中无尺铁，徒欲突重围。' },
  { title: '从军六首 二', author: '刘长卿', poem: '目极鴈门道，青青边草春。\n一身事征战，匹马同苦辛。\n末路成白首，功归天下人。' },
  { title: '从军六首 三', author: '刘长卿', poem: '倚劒白日暮，望乡登戍楼。\n北风吹羌笛，此夜关山愁。\n回首不无意，滹河空自流。' },
  { title: '从军六首 四', author: '刘长卿', poem: '黄沙一万里，白首无人怜。\n报国劒已折，归乡身幸全。\n单于古台下，边色寒苍然。' },
  { title: '从军六首 五', author: '刘长卿', poem: '落日更萧条，北风动枯草。\n将军追虏骑，夜失阴山道。\n战败仍树勋，韩彭但空老。' },
  { title: '从军六首 六', author: '刘长卿', poem: '草枯秋塞上，望见渔阳郭。\n胡马嘶一声，汉兵泪双落。\n谁为吮疮者，此事今人薄。' },
  { title: '龙门八咏 阙口', author: '刘长卿', poem: '秋山日摇落，秋水急波澜。\n独见鱼龙气，长令烟雨寒。\n谁穷造化力，空向两崖看。' },
  { title: '龙门八咏 水东渡', author: '刘长卿', poem: '山叶傍崖赤，千峰秋色多。\n夜泉发清响，寒渚生微波。\n稍见沙上月，归人争渡河。' },
  { title: '龙门八咏 福公塔', author: '刘长卿', poem: '寂寞对伊水，经行长未还。\n东流自朝暮，千载空云山。\n谁见白鸥鸟，无心洲渚间。' },
  { title: '龙门八咏 远公龛', author: '刘长卿', poem: '松路向精舍，花龛归老僧。\n闲云随锡杖，落日低金绳。\n入夜翠微里，千峰明一灯。' },
  { title: '龙门八咏 石楼', author: '刘长卿', poem: '隐隐见花阁，隔河映青林。\n水田秋鴈下，山寺夜钟深。\n寂寞群动息，风泉清道心。' },
  { title: '龙门八咏 下山', author: '刘长卿', poem: '谁识往来意，孤云长自闲。\n风寒未渡水，日暮更看山。\n木落众峰出，龙宫苍翠间。' },
  { title: '龙门八咏 水西渡', author: '刘长卿', poem: '伊水摇镜光，纤鳞如不隔。\n千龛道傍古，一鸟沙上白。\n何事还山云，能留向城客。' },
  { title: '龙门八咏 渡水', author: '刘长卿', poem: '日暮下山来，千山暮钟发。\n不知波上棹，还弄山中月。\n伊水连白云，东南远明灭。' },
  { title: '月下听砧', author: '刘长卿', poem: '夜静掩寒城，清砧发何处？\n声声捣秋月，肠断卢龙戍。\n未得寄征人，愁霜复愁露。' },
  { title: '送丘为赴上都', author: '刘长卿', poem: '帝乡何处是，歧路空垂泣。\n楚思愁暮多，川程带潮急。\n潮归人不归，独向空塘立。' },
  { title: '题大理黄主簿湖上高斋', author: '刘长卿', poem: '闭门湖水畔，自与白鸥亲。\n竟日窗中岫，终年林下人。\n俗轻儒服弊，家厌法官贫。\n多雨茅檐夜，空洲草径春。\n桃源君莫爱，且作汉朝臣。' },
  { title: '平蕃曲三首 一', author: '刘长卿', poem: '吹角报蕃营，回军欲洗兵。\n已教青海外，自筑汉家城。' },
  { title: '平蕃曲三首 二', author: '刘长卿', poem: '渺渺戍烟孤，茫茫塞草枯。\n陇头那用闭，万里不防胡。' },
  { title: '平蕃曲三首 三', author: '刘长卿', poem: '绝漠大军还，平沙独戍闲。\n空留一片石，万古在燕山。' },
  { title: '送郑说之歙州谒薛侍郎', author: '刘长卿', poem: '漂泊来千里，讴谣满百城。\n汉家尊太守，鲁国重诸生。\n俗变人难理，江传水至清。\n船经危石住，路入乱山行。\n老得沧州趣，春伤白首情。\n尝闻马南郡，门下有康成。' },
  { title: '题独孤使君湖上林亭', author: '刘长卿', poem: '出树倚朱阑，吹铙引上官。\n老农持锸拜，时稼卷帘看。\n水对登龙净，山当建隼寒。\n夕阳湖草动，秋色渚田宽。\n渤海人无事，荆州客独安。\n谢公何足比，来往石门难。' },
  { title: '酬滁州李十六使君见赠', author: '刘长卿', poem: '满镜悲华发，空山寄此身。\n白云家自有，黄卷业长贫。\n嬾任垂竿老，狂因酿黍春。\n桃花迷圣代，桂树狎幽人。\n幢盖方临郡，柴荆忝作邻。\n但愁千骑至，石路却生尘。' },
  { title: '送严维赴河南充严中丞幕府', author: '刘长卿', poem: '久别耶溪客，来乘使者轩。\n用才荣入幕，扶病喜同樽。\n山屐留何处，江帆去独翻。\n暮情辞镜水，秋梦识云门。\n莲府开花萼，桃园寄子孙。\n何当举严助，徧沐汉朝恩。' },
  { title: '酬包谏议佶见寄之什', author: '刘长卿', poem: '佐郡媿顽疎，殊方亲里闾。\n家贫寒未度，身老岁将除。\n过雪山僧至，依阳野客舒。\n药陈随远宦，梅发对幽居。\n落日栖鸮鸟，行人遗鲤鱼。\n高文不可和，空媿学相如。' },
  { title: '栖霞寺东峰寻南齐明征君故居', author: '刘长卿', poem: '山人今不见，山鸟自相从。\n长啸辞明主，终身卧此峰。\n泉源通石径，磵户掩尘容。\n古墓依寒草，前朝寄老松。\n片云生断壁，万壑遍疎钟。\n惆怅空归去，犹疑林下逢。' },
  { title: '奉和赵给事使君留赠李婺州舍人兼谢舍人别驾之什', author: '刘长卿', poem: '便道访情亲，东方千骑尘。\n禁深分直夜，地远独行春。\n绛阙辞明主，沧洲识近臣。\n云山随候吏，鸡犬逐归人。\n庭顾婆娑老，邦传蔽芾新。\n玄晖翻佐理，闻到郡斋频。' },
  { title: '行营酬吕侍御时尚书问罪襄阳军次汉东境上侍御以州邻寇贼复有水火迫于征税诗以见谕', author: '刘长卿', poem: '不敢淮南卧，来趋汉将营。\n受辞瞻左钺，扶疾往前旌。\n井税鹑衣乐，壶浆鹤发迎。\n水归余断岸，烽至掩孤城。\n晚日归千骑，秋风合五兵。\n孔璋才素健，早晚檄书成。' },
  { title: '登迁仁楼酬子壻李穆', author: '刘长卿', poem: '临风敞丽谯，落日听吹铙。\n归路空回首，新章已在腰。\n非才受官谤，无政作人谣。\n俭岁安三户，余年寄六条。\n春芜生楚国，古树过隋朝。\n赖有东床客，池塘免寂寥。' },
  { title: '别李氏女子', author: '刘长卿', poem: '念尔嫁犹近，稚年那别亲。\n临歧方教诲，所贵和六姻。\n俛首戴荆钗，欲拜凄且嚬。\n本来儒家子，莫耻梁鸿贫。\n汉川若可涉，水清石磷磷。\n天涯远乡妇，月下孤舟人。' },
  { title: '长沙早春雪后临湘水呈同游诸子', author: '刘长卿', poem: '汀洲暖渐渌，烟景淡相和。\n举目方如此，归心岂奈何。\n日华浮野雪，春色染湘波。\n北渚生芳草，东风变旧柯。\n江山古思远，猨鸟暮情多。\n君问渔人意，沧浪自有歌。' },
  { title: '自道林寺西入石路至麓山寺过法崇禅师故居', author: '刘长卿', poem: '山僧候谷口，石路拂莓苔。\n深入泉源去，遥从树杪回。\n香随青霭散，钟过白云来。\n野雪空斋掩，山风古殿开。\n桂寒知自发，松老问谁栽。\n惆怅湘江水，何人更渡杯。' },
  { title: '和袁郎中破贼后军行过剡中山水谨上太尉', author: '刘长卿', poem: '剡路除荆棘，王师罢鼓鼙。\n农归沧海畔，围解赤城西。\n赦罪春阳发，收兵太白低。\n远峰来马首，横笛入猨啼。\n兰渚催新幄，桃源识故蹊。\n已闻开阁待，谁许卧东溪。' },
  { title: '送郑十二还庐山别业', author: '刘长卿', poem: '浔阳数亩宅，归卧掩柴关。\n谷口何人待，门前秋草闲。\n忘机卖药罢，无语杖藜还。\n旧笋成寒竹，空斋向暮山。\n水流经舍下，云去到人间。\n桂树花应发，因行寄一攀。' },
  { title: '至饶州寻陶十七不在寄赠', author: '刘长卿', poem: '谪宦投东道，逢君已北辕。\n孤蓬向何处，五柳不开门。\n去国空回首，怀贤欲诉冤。\n梅枝横岭峤，竹路过湘源。\n月下高秋雁，天南独夜猨。\n离心与流水，万里共朝昏。' },
  { title: '奉陪郑中丞自宣州解印与诸姪宴余干后溪', author: '刘长卿', poem: '迹远亲鱼鸟，功成厌鼓鼙。\n林中阮生集，池上谢公题。\n户牖垂藤合，藩离插槿齐。\n夕阳山向背，春草水东西。\n度雨诸峰出，看花几路迷。\n何劳问秦汉，更入武陵溪。' },
  { title: '同诸公袁郎中宴筵喜加章服', author: '刘长卿', poem: '手诏来筵上，腰金向粉闱。\n勋名传旧阁，蹈舞着新衣。\n白社同游在，沧洲此会稀。\n寒笳发后殿，秋草送西归。\n世难常摧敌，时闲已息机。\n鲁连功可让，千载一相挥。' },
  { title: '毘陵送邹结先赴河南充判官', author: '刘长卿', poem: '王事相逢少，云山奈别何。\n芳年临水怨，瓜步上潮过。\n客路方经楚，乡心共渡河。\n凋残春草在，离乱故城多。\n罢战逢时泰，轻徭伫俗和。\n东西此分手，惆怅恨烟波。' },
  { title: '送徐大夫赴广州', author: '刘长卿', poem: '上将坛场拜，南荒羽檄招。\n远人来百越，元老事三朝。\n雾绕龙山暗，山连象郡遥。\n路分江淼淼，军动马萧萧。\n画角知秋气，楼船逐暮潮。\n当令输贡赋，不使外夷骄。' },
  { title: '九日题蔡国公主楼', author: '刘长卿', poem: '主第人何在，重阳客暂寻。\n水余龙镜色，云罢凤箫音。\n暗牖藏昏晓，苍苔换古今。\n晴山卷幔出，秋草闭门深。\n篱菊仍新吐，庭槐尚旧阴。\n年年画梁燕，来去岂无心。' },
  { title: '送荀八过山阴旧县兼寄剡中诸官', author: '刘长卿', poem: '访旧山阴县，扁舟到海涯。\n故林嗟满岁，春草忆佳期。\n晚景千峰乱，晴江一鸟迟。\n桂香留客处，枫暗泊舟时。\n旧石曹娥篆，空山夏禹祠。\n剡溪多隐吏，君去道相思。' },
  { title: '奉饯元侍郎加豫章采访兼赐章服', author: '刘长卿', poem: '任重兼乌府，时平偃豹韬。\n澄清湘水变，分别楚山高。\n花对彤襜发，霜和白雪操。\n黄金装旧马，青草换新袍。\n岭暗猿啼月，江寒鹭映涛。\n豫章生宇下，无使翳篷蒿。' },
  { title: '奉饯郎中四兄罢余杭太守承恩加侍御史充行军司马赴汝南行营', author: '刘长卿', poem: '星使三江上，天波万里通。\n权分金节重，恩借铁冠雄。\n梅吹前军发，棠阴旧府空。\n残春锦障外，初日羽旗东。\n岸柳遮浮鹢，江花隔避骢。\n离心在何处，芳草满吴宫。' },
  { title: '送贾侍御克复后入京', author: '刘长卿', poem: '对酒心不乐，见君动行舟。\n回看暮帆隐，独向空江愁。\n晴云淡初夜，春塘深慢流。\n温颜风霜霁，喜气烟尘收。\n驰驲数千里，朝天十二楼。\n因之报亲爱，白发生沧洲。' },
  { title: '会稽王处士草堂壁画衡霍诸山', author: '刘长卿', poem: '粉壁衡霍近，群峰如可攀。\n能令堂上客，见尽湖南山。\n青翠数千仞，飞来方丈间。\n归云无处灭，去鸟何时还？\n胜事日相对，主人常独闲。\n稍看林壑晚，佳气生重关。' },
  { title: '惠福寺与陈留诸官茶会', author: '刘长卿', poem: '到此机事遣，自嫌尘网迷。\n因知万法幻，尽与浮云齐。\n疎竹映高枕，空花随杖藜。\n香飘诸天外，日隐双林西。\n傲吏方见狎，真僧幸相携。\n能令归客意，不复还东溪。' },
  { title: '金陵西泊舟临江楼', author: '刘长卿', poem: '萧条金陵郭，旧是帝王州。\n日暮望乡处，云边江树秋。\n楚云不可托，楚水只堪愁。\n行客千万里，沧波朝暮流。\n迢迢洛阳梦，独卧清川楼。\n异乡共如此，孤帆难久游。' },
  { title: '题灵祐上人法华院木兰花', author: '刘长卿', poem: '庭种南中树，年华几度新。\n已依初地长，独发旧园春。\n映日成华盖，摇风散锦茵。\n色空荣落处，香醉往来人。\n菡萏千灯遍，芳菲一雨均。\n高柯傥为檝，渡海有良因。' },
  { title: '宿严维宅送包佶', author: '刘长卿', poem: '江湖同避地，分首自依依。\n尽室今为客，惊秋空念归。\n岁储无别墅，寒服羡邻机。\n草色春桥晚，蝉声江树稀。\n夜深宜共醉，时难忍相违。\n何事随阳雁，汀洲忽背飞。' },
  { title: '送从弟贬袁州', author: '刘长卿', poem: '何事成迁客，思归不见乡。\n游吴经万里，吊屈向三湘。\n水与荆巫接，山通鄢郢长。\n名羞黄绶系，身是白眉郎。\n独结南枝恨，应思北雁行。\n忧来沽楚酒，老鬓莫凝霜。' },
  { title: '无锡东郭送友人游越', author: '刘长卿', poem: '客路风霜晓，郊原春兴余。\n平芜不可望，游子去何如。\n烟水乘湖阔，云山适越初。\n旧都怀作赋，古穴觅藏书。\n碑缺曹娥宅，林荒逸少居。\n江湖无限意，非独为樵渔。' },
  { title: '送邵州判官往南', author: '刘长卿', poem: '看君发原隰，驷牡志皇皇。\n始罢沧江令，还随粉署郎。\n海沂军未息，河兖岁仍荒。\n征税人全少，榛芜虏近亡。\n新知行宋远，相望隔淮长。\n早晚裁书寄，银钩伫八行。' },
  { title: '出丰县界寄韩明府', author: '刘长卿', poem: '回首古原上，未能辞旧乡。\n西风收暮雨，隐隐分芒砀。\n贤友此为邑，令名满徐方。\n音容想在眼，暂若升琴堂。\n疲马顾春草，行人看夕阳。\n自非传尺素，谁为论中肠。' },
  { title: '别陈留诸官', author: '刘长卿', poem: '恋此东道主，能令西上迟。\n徘徊暮郊别，惆怅秋风时。\n上国邈千里，夷门难再期。\n行人望落日，归马嘶空陂。\n不愧宝刀赠，维怀琼树枝。\n音尘倘未接，梦寐徒相思。' },
  { title: '观李凑所画美人障子', author: '刘长卿', poem: '爱尔含天姿，丹青有殊智。\n无间已得象，象外更生意。\n西子不可见，千载无重还。\n空令浣沙态，犹在含毫间。\n一笑岂易得，双蛾如有情。\n窗风不举袖，但觉罗衣轻。\n华堂翠幕春风来，内阁金屏曙色开。\n此中一见乱人目，只疑行到云阳台。' },
  { title: '送史判官奏事之灵武兼寄巴西亲故', author: '刘长卿', poem: '中州日纷梗，天地何时泰。\n独有西归心，遥悬夕阳外。\n故人奉章奏，此去论利害。\n阳雁南渡江，征骖去相背。\n因君欲寄远，何处问亲爱。\n空使沧洲人，相思减衣带。' },
  { title: '自鄱阳还道中寄褚征君', author: '刘长卿', poem: '南风日夜起，万里孤帆漾。\n元气连洞庭，夕阳落波上。\n故人烟水隔，复此遥相望。\n江信久寂寥，楚云独惆怅。\n爱君清川口，弄月时櫂唱。\n白首无子孙，一生自疎旷。' },
  { title: '石梁湖有寄', author: '刘长卿', poem: '故人千里道，沧波一年别。\n夜上明月楼，相思楚天阔。\n潇潇清秋暮，袅袅凉风发。\n湖色淡不流，沙鸥远还灭。\n烟波日已远，音问日已绝。\n岁晏空含情，江臯绿芳歇。' },
  { title: '送沈少府之任淮南', author: '刘长卿', poem: '惜君滞南楚，枳棘徒栖凤。\n独与千里帆，春风远相送。\n此行山水好，时物亦应众。\n一鸟飞长淮，百花满云梦。\n相期丹霄路，遥听清风颂。\n勿为州县卑，时来自为用。' },
  { title: '严子濑东送马处直归苏', author: '刘长卿', poem: '望君舟已远，落日潮未退。\n目送沧海帆，人行白云外。\n江中远回首，波上生微霭。\n秋色姑苏台，寒流子陵濑。\n相送苦易散，动别知难会。\n从此日相思，空令减衣带。' },
  { title: '宿怀仁县南湖寄东海荀处士', author: '刘长卿', poem: '向夕歛微雨，晴开湖上天。\n离人正惆怅，新月愁婵娟。\n伫立白沙曲，相思沧海边。\n浮云自来去，此意谁能传。\n一水不相见，千峰随客船。\n寒塘起孤雁，夜色分盐田。\n时复一延首，忆君如眼前。' },
  { title: '初至洞庭怀灞陵别业', author: '刘长卿', poem: '长安邈千里，日夕怀双阙。\n已是洞庭人，犹看灞陵月。\n谁堪去乡意，亲戚想天末。\n昨夜梦中归，烟波觉来阔。\n江臯见芳草，孤客心欲绝。\n岂讶青春来，但伤经时别。\n长天不可望，鸟与浮云没。' },
  { title: '题萧郎中开元寺新构幽寂亭', author: '刘长卿', poem: '康乐爱山水，赏心千载同。\n结茅依翠微，伐木开蒙笼。\n孤峰倚青霄，一径去不穷。\n候客石苔上，礼僧云树中。\n旷然见沧洲，自远来清风。\n五马留谷口，双旌薄烟虹。\n沈沈众香积，眇眇诸天空。\n独往应未遂，苍生思谢公。' },
  { title: '同姜濬题裴式微余干东斋', author: '刘长卿', poem: '世事终成梦，生涯欲半过。\n白云心已矣，沧海意如何。\n藜杖全吾道，榴花养太和。\n春风骑马醉，江月钓鱼歌。\n散帙看虫蠹，开门见雀罗。\n远山终日在，芳草傍人多。\n吏体庄生傲，方言楚俗譌。\n屈平君莫吊，肠断洞庭波。' },
  { title: '赠元容州', author: '刘长卿', poem: '拥旌临合浦，上印卧长沙。\n海徼长无戍，湘山独种畬。\n政传通岁贡，才惜过年华。\n万里依孤劒，千峰寄一家。\n累征期旦暮，未起恋烟霞。\n避世歌芝草，休官醉菊花。\n旧游如梦里，此别是天涯。\n何事沧波上，漂漂逐海槎。' },
  { title: '夏口送长宁杨明府归荆南因寄幕府诸公', author: '刘长卿', poem: '关西杨太尉，千载德犹闻。\n白日俱终老，清风独至君。\n身承远祖遗，才出众人群。\n举世贪荆玉，全家恋楚云。\n向烟帆杳杳，临水叶纷纷。\n草覆昭丘绿，江从夏口分。\n高名光盛府，异姓宠殊勋。\n百越今无事，南征欲罢军。' },
  { title: '奉和杜相公新移长兴宅呈元相公', author: '刘长卿', poem: '间世生贤宰，同心奉至尊。\n功高开北第，机静灌中园。\n入并蝉冠影，归分骑士喧。\n窗闻汉宫漏，家识杜陵源。\n献替常焚藁，优闲独对萱。\n花香逐荀令，草色对王孙。\n有地先开阁，何人不扫门。\n江湖难自退，明主托元元。' },
  { title: '湖南使还留辞辛大夫', author: '刘长卿', poem: '王师劳近甸，兵食仰诸侯。\n天子无南顾，元勋在上游。\n大才生间气，盛业拯横流。\n风景随摇笔，山川入运筹。\n羽觞交饯席，旄节对归舟。\n莺识春深恨，猿知日去愁。\n别离花寂寂，南北水悠悠。\n唯有家兼国，终身共所忧。' },
  { title: '泛曲阿后湖简同游诸公', author: '刘长卿', poem: '元气浮积水，沈沈深不流。\n春风万顷绿，映带至徐州。\n为客难适意，逢君方暂游。\n夤缘白苹际，日暮沧浪舟。\n渡口微月进，林西残雨收。\n水云去仍湿，沙鹤鸣相留。\n且习子陵隐，能忘生事忧。\n此中深有意，非为钓鱼钩。' },
  { title: '北游酬孟云卿见寄', author: '刘长卿', poem: '忽忽忘前事，事愿能相乖。\n衣马日羸弊，谁辨行与才。\n善道居贫贱，洁服蒙尘埃。\n行行无定止，懔坎难归来。\n慈母忧疾疹，室家念栖莱。\n幸君夙姻亲，深见中外怀。\n俟子惜时节，怅望临高台。' },
  { title: '冬夜宿扬州开元寺烈公房送李侍御之江东', author: '刘长卿', poem: '迁客投百越，穷阴淮海凝。\n中原驰困兽，万里栖饥鹰。\n寂寂连宇下，爱君心自弘。\n空堂来霜气，永夜清明灯。\n发后望烟水，相思劳寝兴。\n暮帆背楚郭，江色浮金陵。\n此去尔何恨，近名予未能。\n炉峰若便道，为访东林僧。' },
  { title: '南楚怀古', author: '刘长卿', poem: '南国久芜没，我来空郁陶。\n君看章华宫，处处生蓬蒿。\n但见陵与谷，岂知贤与豪。\n精魂托古木，宝劒捐江臯。\n倚棹下晴景，回舟随晚涛。\n碧云暮寥落，湖上秋天高。\n往事那堪问，此心徒自劳。\n独余湘水上，千载闻离骚。' },
  { title: '上湖田馆南楼忆朱晏', author: '刘长卿', poem: '漂泊日复日，洞庭今更秋。\n白云如有意，万里望孤舟。\n何事爱成别，空令登此楼。\n天光映波动，月影随江流。\n鹤唳静寒渚，猿啼深夜洲。\n归期诚已促，清景仍相留。\n顷者慕独往，尔来悲远游。\n风波自此去，桂水空离忧。' },
  { title: '送姚八之句容旧任便归江南', author: '刘长卿', poem: '故人还水国，春色动离忧。\n碧草千万里，沧江朝暮流。\n桃花迷旧路，萍叶荡归舟。\n远戍看京口，空城问石头。\n折芳佳丽地，望月西南楼。\n猨鸟共孤屿，烟波连数州。\n谁家过楚老，何处恋江鸥。\n尺素能相报，湖山若个忧。' },
  { title: '睢阳赠李司仓', author: '刘长卿', poem: '白露变时候，蛬声暮啾啾。\n飘飘洛阳客，惆怅梁园秋。\n只为乏生计，尔来成远游。\n一身不家食，万事从人求。\n且喜接余论，足堪资小留。\n寒城落日后，砧杵令人愁。\n归路岁时尽，长河朝夕流。\n非君深意愿，谁复能相忧。' },
  { title: '杪秋洞庭中怀亡道士谢太虚', author: '刘长卿', poem: '漂泊日复日，洞庭今更秋。\n青枫亦何意，此夜催人愁。\n惆怅客中月，徘徊江上楼。\n心知楚天远，目送沧波流。\n羽客久已殁，微言无处求。\n空余白云在，容与随孤舟。\n千里杳难望，一身当独游。\n故园复何许，江海徒迟留。' },
  { title: '同郭参谋咏崔仆射淮南节度使厅前竹', author: '刘长卿', poem: '昔种梁王苑，今移汉将坛。\n蒙笼低冕过，青翠卷帘看。\n得地移根远，经霜抱节难。\n开花成凤实，嫩笋长鱼竿。\n蔼蔼军容静，萧萧郡宇宽。\n细音和角暮，疎影上门寒。\n湘浦何年变，山阳几处残。\n不知轩屏侧，岁晚对袁安。' },
  { title: '硖石遇雨宴前主簿从兄子英宅', author: '刘长卿', poem: '县城苍翠里，客路两崖开。\n硖石云漠漠，东风吹雨来。\n吾兄此为吏，薄宦知无媒。\n方寸抱秦镜，声名传楚材。\n折腰五斗间，僶俛随尘埃。\n秩满少余俸，家贫仍散财。\n谁言次东道，暂预倾金罍。\n虽欲少留此，其如归限催。' },
  { title: '江中晚钓寄荆南一二相识', author: '刘长卿', poem: '楚郭微雨收，荆门遥在目。\n漾舟水云里，日暮春江绿。\n霁华静洲渚，暝色连松竹。\n月出波上时，人归渡头宿。\n一身已无累，万事更何欲。\n渔父自夷犹，白鸥不羁束。\n既怜沧浪水，复爱沧浪曲。\n不见眼中人，相思心断续。' },
  { title: '九日岳阳待黄遂张涣', author: '刘长卿', poem: '别君颇已久，离念与时积。\n楚水空浮烟，江楼望归客。\n徘徊正伫想，髣髴如暂觌。\n心目徒自亲，风波尚相隔。\n青林泊舟处，猿鸟愁孤驿。\n遥见郭外山，苍然雨中夕。\n季鹰久疎旷，叔度早畴昔。\n反櫂来何迟，黄花候君摘。' },
  { title: '题王少府尧山隐处简陆鄱阳', author: '刘长卿', poem: '故人沧洲吏，深与世情薄。\n解印二十年，委身在丘壑。\n买田楚山下，妻子自耕凿。\n群动心有营，孤云本无着。\n因收谿上钓，遂接林中酌。\n对酒春日长，山村杏花落。\n陆生鄱阳令，独步建溪作。\n早晚休此官，随君永栖托。' },
  { title: '晚次湖口有怀', author: '刘长卿', poem: '霭然空水合，目极平江暮。\n南望天无涯，孤帆落何处。\n顷为衡湘客，颇见湖山趣。\n朝气和楚云，夕阳映江树。\n帝乡劳想望，万里心来去。\n白发生扁舟，沧波满归路。\n秋风今已至，日夜雁南度。\n木叶辞洞庭，纷纷落无数。' },
  { title: '陪元侍御游支硎山寺', author: '刘长卿', poem: '支公去已久，寂寞龙华会。\n古木闭空山，苍然暮相对。\n林峦非一状，水石有余态。\n密竹藏晦明，群峰争向背。\n峰峰带落日，步步入青霭。\n香气空翠中，猿声暮云外。\n留连南台客，想像西方内。\n因逐溪水还，观心两无碍。' },
  { title: '桂阳西州晚泊古桥村住人', author: '刘长卿', poem: '洛阳别离久，江上心可得。\n惆怅增暮情，潇湘复秋色。\n故山隔何处，落日羡归翼。\n沧海空自流，白鸥不相识。\n悲蛬满荆渚，辍櫂徒沾臆。\n行客念寒衣，主人愁夜织。\n帝乡片云去，遥寄千里忆。\n南路随天长，征帆杳无极。' },
  { title: '夕次檐石湖梦洛阳亲故', author: '刘长卿', poem: '天涯望不尽，日暮愁独去。\n万里云海空，孤帆向何处。\n寄身烟波里，颇得湖山趣。\n江气和楚云，秋声乱枫树。\n如何异乡县，日复怀亲故。\n遥与洛阳人，相逢梦中路。\n不堪明月里，更值清秋暮。\n倚棹对沧波，归心共谁语。' },
  { title: '按覆后归睦州赠苗侍御', author: '刘长卿', poem: '地远心难达，天高谤易成。\n羊肠留覆辙，虎口脱余生。\n直氏偷金枉，于家决狱明。\n一言知己重，片议杀身轻。\n日下人谁忆，天涯客独行。\n年光销蹇步，秋气入衰情。\n建德知何在，长江问去程。\n孤舟百口渡，万里一猿声。\n落日开乡路，空山向郡城。\n岂令冤气积，千古在长平。' },
  { title: '奉寄婺州李使君舍人', author: '刘长卿', poem: '建隼罢鸣珂，初传来暮歌。\n渔樵识太古，草树得阳和。\n东道诸生从，南依远客过。\n天清婺女出，土厚绛人多。\n永日空相望，流年复几何。\n崖开当夕照，叶去逐寒波。\n眼暗经难受，身闲劒懒磨。\n似鸮占贾谊，上马试廉颇。\n穷分安藜藿，衰容胜薜萝。\n只应随越鸟，南翥托高柯。' },
  { title: '哭魏兼遂', author: '刘长卿', poem: '古今俱此去，修短竟谁分。\n樽酒空如在，弦琴肯重闻。\n一门同逝水，万事共浮云。\n旧馆何人宅，空山远客坟。\n艰危贫且共，少小秀而文。\n独行依穷巷，全身出乱军。\n岁时长寂寞，烟月自氛氲。\n垅树随人古，山门对日曛。\n泛舟悲向子，留劒赠徐君。\n来去云阳路，伤心江水𣸣。' },
  { title: '负谪后登干越亭作', author: '刘长卿', poem: '天南愁望绝，亭上柳条新。\n落日独归鸟，孤舟何处人。\n生涯投越徼，世业陷胡尘。\n杳杳钟陵暮，悠悠鄱水春。\n秦台悲白首，楚泽怨青苹。\n草色迷征路，莺声伤逐臣。\n独醒空取笑，直道不容身。\n得罪风霜苦，全生天地仁。\n青山数行泪，沧海一穷鳞。\n牢落机心尽，惟怜鸥鸟亲。' },
  { title: '留题李明府霅溪水堂', author: '刘长卿', poem: '寥寥此堂上，幽意复谁论。\n落日无王事，青山在县门。\n云峰向高枕，渔钓入前轩。\n晚竹疎帘影，春苔双履痕。\n荷香随坐卧，湖色映晨昏。\n虚牖闲生白，鸣琴静对言。\n暮禽飞上下，春水带清浑。\n远岸谁家柳，孤烟何处村。\n谪居投瘴疠，离思过湘沅。\n从此扁舟去，谁堪江浦猿。' },
  { title: '入白沙渚夤缘二十五里至石窟山下怀天台陆山人', author: '刘长卿', poem: '远屿霭将夕，玩幽行自迟。\n归人不计日，流水闲相随。\n辍棹古崖口，扪萝春景迟。\n偶因回舟次，宁与前山期。\n对此瑶草色，怀君琼树枝。\n浮云去寂寞，白鸟相因依。\n何事爱高隐，但令劳远思。\n穷年卧海峤，永望愁天涯。\n吾亦从此去，扁舟何所之？\n迢迢江上帆，千里东风吹。' },
  { title: '禅智寺上方怀演和尚寺即和尚所创', author: '刘长卿', poem: '绝𪩘东林寺，高僧惠远公。\n买园隋苑下，持钵楚城中。\n斗极千灯近，烟波万井通。\n远山低月殿，寒木露花宫。\n绀宇焚香净，沧州摆雾空。\n鴈来秋色里，曙起早潮东。\n飞锡今何在？苍生待发蒙。\n白云翻送客，庭树自辞风。\n舍筏追开士，回舟狎钓翁。\n平生江海意，惟共白鸥同。' },
  { title: '贾侍郎自会稽使回篇什盈卷兼蒙见寄一首与余有挂冠之期因书数事率成十韵', author: '刘长卿', poem: '江上逢星使，南来自会稽。\n惊年一叶落，按俗五花嘶。\n上国悲芜梗，中原动鼓鼙。\n报恩看铁劒，衔命出金闺。\n风物催归绪，云峰发咏题。\n天长百越外，潮上小江西。\n鸟道通闽岭，山光落剡溪。\n暮帆千里思，秋夜一猨啼。\n柏树荣新垅，桃源忆故蹊。\n若能为休去，行复草萋萋。' },
  { title: '秋日夏口涉汉阳献李相公', author: '刘长卿', poem: '日望衡门处，心知汉水𣸣。\n偶乘青雀舫，还在白鸥群。\n间气生灵秀，先朝翼戴勋。\n藏弓身已退，焚藳事难闻。\n旧业成青草，全家寄白云。\n松萝长稚子，风景逐新文。\n山带寒城出，江依古岸分。\n楚歌悲远客，羌笛怨孤军。\n鼎罢调梅久，门看种药勤。\n十年犹去国，黄叶又纷纷。' },
  { title: '归沛县道中晚泊留侯城', author: '刘长卿', poem: '访古此城下，子房安在哉？\n白云去不反，危堞空崔嵬。\n伊昔楚汉时，颇闻经济才。\n运筹风尘下，能使天地开。\n蔓草日已积，长松日已摧。\n功名满青史，祠庙唯苍苔。\n百里暮程远，孤舟川上回。\n进帆东风便，转岸前山来。\n楚水澹相引，沙鸥闲不猜。\n扣舷从此去，延首仍裴回。' },
  { title: '关门望华山', author: '刘长卿', poem: '客路瞻太华，三峰高际天。\n夏云亘百里，合沓遥相连。\n雷雨飞半腹，太阳在其巅。\n翠微关上近，瀑布林梢悬。\n爱此众容秀，能令西望偏。\n徘徊忘暝色，泱漭成阴烟。\n会是朝百灵，亦闻会群仙。\n琼浆岂易挹，毛女非空传。\n髣髴仍伫想，幽期如眼前。\n金天有青庙，松柏隐苍然。' },
  { title: '奉陪萧使君入鲍达洞寻灵山寺', author: '刘长卿', poem: '山居秋更鲜，秋江相映碧。\n独临沧洲路，如待挂帆客。\n遂使康乐侯，披榛着双屐。\n入云开岭道，永日寻泉脉。\n古寺隐青冥，空中寒磬夕。\n苍苔绝行径，飞鸟无去迹。\n树杪下归人，水声过幽石。\n任情趣逾远，移步奇屡易。\n萝木静蒙蒙，风烟深寂寂。\n徘徊未能去，畏共桃源隔。' },
  { title: '孙权故城下怀古兼送友人归建业', author: '刘长卿', poem: '雄图争割据，神器终不守。\n上下武昌城，长江竟何有。\n古来壮台榭，事往悲陵阜。\n寥落几家人，犹依数株柳。\n威灵绝想像，芜没空林薮。\n野径春草中，郊扉夕阳后。\n逢君从此去，背楚方东走。\n烟际指金陵，潮时过湓口。\n行人已何在，临水徒挥手。\n惆怅不能归，孤帆没云久。' },
  { title: '宿双峰寺寄卢七李十六', author: '刘长卿', poem: '寥寥禅诵处，满室虫丝结。\n独与山中人，无心生复灭。\n徘徊双峰下，惆怅双峰月。\n杳杳暮猿深，苍苍古松列。\n玩奇不可尽，渐远更幽绝。\n林暗僧独归，石寒泉且咽。\n竹房响轻吹，萝径阴余雪。\n卧涧晓何迟，背岩春未发。\n此游诚多趣，独往共谁阅。\n得意空自归，非君岂能说。' },
  { title: '京口怀洛阳旧居兼寄广陵二三知己', author: '刘长卿', poem: '川阔悲无梁，蔼然沧波夕。\n天涯一飞鸟，日暮南徐客。\n气混京口云，潮吞海门石。\n孤帆候风进，夜色带江白。\n一水阻佳期，相望空脉脉。\n那堪岁芳尽，更使春梦积。\n故国胡尘飞，远山楚云隔。\n家人想何在，庭草为谁碧。\n惆怅空伤情，沧浪有余迹。\n严陵七里滩，携手同所适。' },
  { title: '登扬州栖灵寺塔', author: '刘长卿', poem: '北塔凌空虚，雄观压川泽。\n亭亭楚云外，千里看不隔。\n遥对黄金台，浮辉乱相射。\n盘梯接元气，半壁栖夜魄。\n稍登诸劫尽，若骋排霄翮。\n向是沧洲人，已为青云客。\n雨飞千栱霁，日在万家夕。\n鸟处高却低，天涯远如迫。\n江流入空翠，海峤现微碧。\n向暮期下来，谁堪复行役。' },
  { title: '湖上遇郑田', author: '刘长卿', poem: '故人青云器，何意常窘迫。\n三十犹布衣，怜君头已白。\n谁言此相见，暂得话畴昔。\n旧业今已芜，还乡返为客。\n扁舟伊独往，斗酒君自适。\n沧洲不可涯，孤帆去无迹。\n杯中忽复醉，湖上生月魄。\n湛湛江色寒，蒙蒙水云夕。\n风波易迢遰，千里如咫尺。\n回首人已遥，南看楚天隔。' },
  { title: '雨中登沛县楼赠表兄郭少府', author: '刘长卿', poem: '楚泽秋更远，云雷有时作。\n晚陂带残雨，白水昏漠漠。\n伫立收烟氛，洗然静寥廓。\n卷帘高楼上，万里看日落。\n为客频改弦，辞家尚如昨。\n故山今不见，此鸟那可托。\n小邑务常闲，吾兄宦何薄。\n高标青云器，独立沧江鹤。\n惠爱原上情，慇懃丘中诺。\n何当遂良愿，归卧青山郭。' },
  { title: '灞东晚晴简同行薛弃朱训', author: '刘长卿', poem: '客心豁初霁，霁色暝玄灞。\n西向看夕阳，曈曈映桑柘。\n二贤诚逸足，千里陪征驾。\n古树枳道傍，人烟杜陵下。\n伊余在羁束，且复随造化。\n好道当有心，营生苦无暇。\n高贤幸兹偶，英达穷王霸。\n迢遰客王程，裴回主人夜。\n一薫知异质，片玉谁齐价。\n同结丘中缘，尘埃自兹谢。' },
  { title: '对雨赠济阴马少府考城蒋少府兼献成武五兄南华二兄', author: '刘长卿', poem: '繁云兼家思，弥望连济北。\n日暮微雨中，州城带秋色。\n萧条主人静，落叶飞不息。\n乡梦寒更频，虫声夜相逼。\n二贤纵横器，久滞徒劳职。\n笑语和风骚，雍容事文墨。\n吾兄即时彦，前路良未测。\n秋水百丈清，寒松一枝直。\n此心欲引托，谁为生羽翼。\n且复顿归鞍，杯中雪胸臆。' },
  { title: '李侍御河北使回至东京相访', author: '刘长卿', poem: '故人南台秀，夙擅中朝美。\n拥传从北来，飞霜日千里。\n贫居幸相访，顾我柴门里。\n却讶绣衣人，仍交布衣士。\n王程遽尔迫，别恋从此始。\n浊酒未暇斟，清文颇垂示。\n回瞻骢马速，但见行尘起。\n日暮汀洲寒，春风渡流水。\n草色官道边，桃花御沟里。\n天涯一鸟夕，惆怅知何已。' },
  { title: '吴中闻潼关失守因奉寄淮南萧判官', author: '刘长卿', poem: '一鴈飞吴天，羁人伤暮律。\n松江风袅袅，波上片帆疾。\n木落姑苏台，霜收洞庭橘。\n萧条长洲外，唯见寒山出。\n胡马嘶秦云，汉兵乱相失。\n关中因窃据，天下共忧栗。\n南楚有琼枝，相思怨瑶瑟。\n一身寄沧洲，万里看白日。\n赴敌甘负戈，论兵勇投笔。\n临风但攘臂，择木将委质。\n不如归远山，云卧饭松栗。' },
  { title: '哭张员外继', author: '刘长卿', poem: '恸哭钟陵下，东流与别离。\n二星来不返，双劒没相随。\n独继先贤传，谁刊有道碑。\n故园荒岘曲，旅榇寄天涯。\n白简曾连拜，沧洲每共思。\n抚孤怜齿穉，叹逝顾身衰。\n泉壤成终古，云山若在时。\n秋风邻笛发，寒日寝门悲。\n世难愁归路，家贫缓葬期。\n旧宾伤未散，夕临咽常迟。\n自此辞张邵，何由见戴逵。\n独闻山吏部，流涕访孤儿。' },
  { title: '登东海龙兴寺高顶望海简演公', author: '刘长卿', poem: '朐山压海口，永望开禅宫。\n元气远相合，太阳生其中。\n豁然万里余，独为百川雄。\n白波走雷电，黑雾藏鱼龙。\n变化非一状，晴明分众容。\n烟开秦帝桥，隐隐横残虹。\n蓬岛如在眼，羽人那可逢。\n偶闻真僧言，甚与静者同。\n幽意颇相惬，赏心殊未穷。\n花间午时梵，云外春山钟。\n谁念遽成别，自怜归所从。\n他时相忆处，惆怅西南峰。' },
  { title: '奉送从兄罢官之淮南', author: '刘长卿', poem: '何事浮溟渤，元戎弃镆鎁。\n渔竿吾道在，鸥鸟世情赊。\n玄发他乡换，沧洲此路遐。\n溯沿随桂檝，醒醉任松华。\n离别谁堪道，艰危更可嗟。\n兵锋摇海内，王命隔天涯。\n钟漏移长乐，衣冠接永嘉。\n还当拂氛祲，那复卧云霞。\n溪路漫冈转，夕阳归鸟斜。\n万艘江县郭，一树海人家。\n挥袂看朱绂，扬帆指白沙。\n春风独回首，愁思极如麻。' },
  { title: '落第赠杨侍御兼拜员外仍充安大夫判官赴范阳', author: '刘长卿', poem: '职副旌旄重，才兼识量通。\n使车遥肃物，边策远和戎。\n掷地金声着，从军宝劒雄。\n官成稽古力，名达济时功。\n肃穆乌台上，雍容粉署中。\n含香初待漏，持简旧生风。\n黠吏偏惊隼，贪夫辄避骢。\n且知荣已隔，谁谓道仍同。\n念旧追连茹，谋生任转蓬。\n泣连三献玉，疮惧再伤弓。\n恋土函关外，瞻尘灞水东。\n他时书一札，犹冀问途穷。' },
  { title: '初贬南巴至鄱阳题李嘉祐江亭', author: '刘长卿', poem: '巴峤南行远，长江万里随。\n不才甘谪去，流水亦何之。\n地远明君弃，天高酷吏欺。\n清山独往路，芳草未归时。\n流落还相见，悲懽话所思。\n猜嫌伤薏苡，愁暮向江篱。\n柳色迎高坞，荷衣照下帷。\n水云初起重，暮鸟远来迟。\n白首看长劒，沧洲寄钓丝。\n沙鸥惊小吏，湖月上高枝。\n稚子能吴语，新文怨楚辞。\n怜君不得意，川谷自逶迤。' },
  { title: '自紫阳观至华阳洞宿侯尊师草堂简同游李延年', author: '刘长卿', poem: '石门媚烟景，句曲盘江甸。\n南向佳气浓，数峰遥隐见。\n渐临华阳口，云路入葱蒨。\n七曜悬洞宫，五云抱仙殿。\n银函竟谁发，金液徒堪荐。\n千载空桃花，秦人深不见。\n东溪喜相遇，贞白如会面。\n青鸟来去闲，红霞朝夕变。\n一从换仙骨，万里乘飞电。\n萝月延步虚，松花醉闲宴。\n幽人即长往，茂宰应交战。\n明发归琴堂，知君嬾为县。' },
  { title: '奉使新安自桐庐县经严陵钓台宿七里滩下寄使院诸公', author: '刘长卿', poem: '悠然钓台下，怀古时一望。\n江水自潺湲，行人独惆怅。\n新安从此始，桂檝方荡漾。\n回转百里间，青山千万状。\n连崖去不断，对岭遥相向。\n夹岸黛色愁，沈沈绿波上。\n夕阳留古木，水鸟拂寒浪。\n月下扣舷声，烟中采菱唱。\n犹怜负羁束，未暇依清旷。\n牵役徒自劳，近名非所向。\n何时故山里，却醉松花酿。\n回首唯白云，孤舟复谁访。' },
  { title: '题虎丘寺', author: '刘长卿', poem: '青林虎丘寺，林际翠微路。\n仰见山僧来，遥从飞鸟处。\n兹峰沦宝玉，千载唯丘墓。\n埋劒人空传，凿山龙已去。\n扪萝披翳荟，路转夕阳遽。\n虎啸崖谷寒，猿鸣杉松暮。\n裴回北楼上，江海穷一顾。\n日映千里帆，鸦归万家树。\n𫏐因惬所适，果得损外虑。\n庭暗栖闲云，檐香滴甘露。\n久迷空寂理，多为繁华故。\n永欲投死生，余生岂能误。' },
  { title: '奉饯郑中丞罢浙西节度还京', author: '刘长卿', poem: '天上移将星，元戎罢龙节。\n三军含怨慕，横吹声断绝。\n五马嘶城隅，万人卧车辙。\n沧洲浮云暮，杳杳去帆发。\n回首不问家，归心遥向阙。\n烟波限吴楚，日夕事淮越。\n吊影失所依，侧身随下列。\n孤蓬飞不定，长劒光未灭。\n绿绮为谁弹，绿芳堪自撷。\n怅然江南春，独此湖上月。\n千里怀去思，百忧变华发。\n颂声满江海，今古流不竭。' },
  { title: '送裴四判官赴河西军试', author: '刘长卿', poem: '吏道岂易惬，如君谁与俦。\n逢时将骋骥，临事无全牛。\n鲍叔幸相知，田苏颇同游。\n英资挺孤秀，清论含古流。\n出塞佐持简，辞家拥鸣驺。\n宪台贵公举，幕府资良筹。\n武士伫明试，皇华难久留。\n阳关望天尽，洮水令人愁。\n万里看一鸟，旷然烟霞收。\n晚花对古戍，春雪含边州。\n道路难暂隔，音尘那可求。\n他时相望处，明月西南楼。' },
  { title: '旅次丹阳郡遇康侍御宣慰召募兼别岑单父', author: '刘长卿', poem: '客心暮千里，回首烟花繁。\n楚水渡归梦，春江连故园。\n羁人怀上国，骄虏窥中原。\n胡马暂为害，汉臣多负恩。\n羽书昼夜飞，海内风尘昏。\n双鬓日已白，孤舟心且论。\n绣衣从此来，汗马宣王言。\n忧愤激忠勇，悲欢动黎元。\n南徐争赴难，发卒如云屯。\n倚劒看太白，洗兵临海门。\n故人亦沧洲，少别堪伤魂。\n积翠下京口，归潮落山根。\n如何天外帆，又此波上尊。\n空使忆君处，莺声催泪痕。' },
  { title: '客舍赠别韦九建赴任河南韦十七造赴任郑县就便觐省', author: '刘长卿', poem: '与子颇畴昔，常时仰英髦。\n弟兄尽公器，诗赋凌风骚。\n顷者游上国，独能光选曹。\n香名冠二陆，精鉴逢山涛。\n且副倚门望，莫辞趋府劳。\n桃花照彩服，草色连青袍。\n征马临素浐，离人倾浊醪。\n华山微雨霁，祠上残云高。\n而我倦栖屑，别君良郁陶。\n春风亦未已，旅思空滔滔。\n拙分甘弃置，穷居长蓬蒿。\n人生未鹍化，物议如鸿毛。\n迢递两乡别，殷勤一宝刀。' },
  { title: '送元八游汝南', author: '刘长卿', poem: '元生实奇迈，幸此论畴昔。\n刀笔素推高，锋铓久无敌。\n纵横济时意，跌宕过人迹。\n破产供酒钱，盈门皆食客。\n田园顷失计，资用深相迫。\n生事诚可忧，严装远何适。\n世情薄恩义，俗态轻穷厄。\n四海金虽多，其如向人惜。\n迢递朗陵道，怅望都门夕。\n向别伊水南，行看楚云隔。\n繁蝉动高柳，疋马嘶平泽。\n潢潦今正深，陂湖未澄碧。\n人生不得已，自可甘形役。\n勿复尊前酒，离居剩凄戚。' },
  { title: '奉和李大夫同吕评事太行苦热行兼寄院中诸公仍呈王员外', author: '刘长卿', poem: '迢递太行路，自古称险恶。\n千骑俨欲前，群峰望如削。\n火云从中出，仰视飞鸟落。\n汗马卧高原，危旌倚长薄。\n清风竟不至，赤日方煎铄。\n石枯山木燋，鳞穷水泉涸。\n九重今旰食，万里传明略。\n诸将候轩车，元凶愁鼎镬。\n何劳短兵接，自有长缨缚。\n通越事岂难，渡泸功未博。\n朝辞羊肠阪，夕望贝丘郭。\n漳水斜遶营，常山遥入幕。\n永怀姑苏下，遥寄建安作。\n白雪和难成，沧波意空托。\n陈琳书记好，王粲从军乐。\n早晚归汉廷，随公上麟阁。' },
  { title: '洛阳主簿叔知和驿承恩赴选伏辞一首', author: '刘长卿', poem: '仲父王佐材，屈身仇香位。\n一从理京剧，万事皆容易。\n则知无不可，通变有余地。\n器宇溟渤宽，文锋镆铘利。\n憧憧洛阳道，日夕皇华使。\n二载出江亭，一心奉王事。\n功成良可录，道在知无愧。\n天府留香名，铨闱就明试。\n赋诗皆旧友，攀辙多新吏。\n彩服辞高堂，青袍拥征骑。\n此行季春月，时物正鲜媚。\n官柳阴相连，桃花色如醉。\n长安想在目，前路遥髣髴。\n落日看华山，关门逼青翠。\n行襜稍已隔，结恋无能慰。\n谁念尊酒间，裴回竹林意。' },
  { title: '题冤句宋少府厅留别', author: '刘长卿', poem: '宋侯人之秀，独步南曹吏。\n世上无此才，天生一公器。\n尚甘黄绶屈，未适青云意。\n洞澈万顷陂，昂藏千里骥。\n从宦闻苦节，应物推高谊。\n薄俸不自资，倾家共人费。\n顾予倦栖托，终日忧穷匮。\n开口即有求，私心岂无愧。\n幸逢东道主，因辍西征骑。\n对话堪息机，披文欲忘味。\n壶觞招过客，几案无留事。\n绿树映层城，苍苔覆闲地。\n一言重然诺，累夕陪宴慰。\n何意秋风来，飒然动归思。\n留欢殊自惬，去念能为累。\n草色愁别时，槐花落行次。\n临期仍把手，此会良不易。\n他日琼树枝，相思劳梦寐。' },
  { title: '罢摄官后将还旧居留辞李侍御', author: '刘长卿', poem: '江海今为客，风波失所依。\n白云心已负，黄绶计仍非。\n累辱群公荐，频沾一尉微。\n去缘焚玉石，来为采葑菲。\n州县名何在，渔樵事亦违。\n故山桃李月，初服薜萝衣。\n熊轼分朝寄，龙韬解贼围。\n风谣传吏体，云物助兵威。\n白云飘辞律，青春发礼闱。\n引军横吹动，援翰捷书挥。\n草映翻营绿，花临檄羽飞。\n全吴争转战，狂虏怯知机。\n忆昨趋金节，临时废玉徽。\n俗流应不厌，静者或相讥。\n世难慵干谒，时闲喜放归。\n潘郎悲白发，谢客爱清辉。\n樗散材因弃，交亲迹已稀。\n独愁看五柳，无事掩双扉。\n世累多行路，生涯向钓矶。\n榜连溪水碧，家羡渚田肥。\n旅食伤飘梗，岩栖忆采薇。\n悠然独归去，回首望旌旗。' },
  { title: '赠别于群投笔赴安西', author: '刘长卿', poem: '风流一才子，经史仍满腹。\n心镜万象生，文锋众人服。\n顷游灵台下，频弃荆山玉。\n蹭蹬空数年，裴回冀微禄。\n朅来投笔砚，长揖谢亲族。\n且欲图变通，安能守拘束。\n本持乡曲誉，肯料泥涂辱。\n谁谓命迍邅，还令计反复。\n西戎今未弭，胡骑屯山谷。\n坐恃龙豹韬，全轻蜂虿毒。\n拂衣从此去，拥传一何速。\n元帅许提携，他人伫瞻瞩。\n出门寡俦侣，矧乃无僮仆。\n黠虏时相逢，黄沙暮愁宿。\n萧条远回首，万里如在目。\n汉境天西穷，[胡]山海边绿。\n想闻羌笛处，泪尽关山曲。\n地阔鸟飞迟，风寒马毛缩。\n边愁殊浩荡，离思空断续。\n塞上归限赊，尊前别期促。\n知君志不小，一举凌鸿鹄。\n且愿乐从军，功名在殊俗。' },
  { title: '送薛据宰涉县', author: '刘长卿', poem: '故人河山秀，独立风神异。\n人许白眉长，天姿青云器。\n雄辞变文名，高价喧时议。\n下笔盈万言，皆合古人意。\n一从负能名，数载犹卑位。\n宝劒诚可用，烹鲜是虚弃。\n昔闻在河上，高卧自无事。\n几案终日闲，蒲鞭使人畏。\n顷因岁月满，方谢风尘吏。\n颂德有舆人，荐贤逢八使。\n栖鸾往已屈，驯雀今可嗣。\n此道如不移，云霄坐应致。\n县前漳水绿，郭外晋山翠。\n日得谢客游，时堪陶令醉。\n前期今尚远，握手空宴慰。\n驿路疎柳长，春城百花媚。\n裴回白日隐，暝色含天地。\n一鸟向灞陵，孤云送行骑。\n夫君多述作，而我常讽味。\n赖有琼瑶资，能宽别离思。\n槐阴覆堂殿，苔色上阶砌。\n鸟倦自归飞，云闲独空㵝。\n既将慕幽绝，兼欲看定慧。\n遇物忘世缘，还家嬾生计。\n无生妄已息，有妄心可制。\n心镜常虚明，时人自沦翳。' },
  { title: '早春赠别赵居士还江左时长卿下第归嵩阳旧居', author: '刘长卿', poem: '见君风尘里，意出风尘外。\n自有沧洲期，含情十余载。\n深居凤城曲，日预龙华会。\n果得僧家缘，能遗俗人态。\n一身今已适，万物知何爱。\n悟法电已空，看心水无碍。\n且将穷妙理，兼欲寻胜概。\n何独谢客游，当为远公辈。\n放舟驰楚郭，负杖辞秦塞。\n目送南飞云，令人想吴会。\n遥思旧游处，髣髴疑相对。\n夜火金陵城，春烟石头濑。\n沧波极天末，万里明如带。\n一片孤客帆，飘然向青霭。\n楚天合江气，云色常霮䨴。\n隐见湖中山，相连数州内。\n君行意可得，全与时人背。\n归路随枫林，还乡念莼菜。\n顾予尚羁束，何幸承眄睐。\n素愿徒自勤，清机本难逮。\n累幸忝宾荐，末路逢沙汰。\n濩落名不成，裴回意空大。\n逢时虽贵达，守道甘易退。\n逆旅乡梦频，春风客心碎。\n别君日已远，离念无明晦。\n予亦返柴荆，山田事耕耒。' },
  { title: '夜宴洛阳程九主簿宅送杨三山人往天台寻智者禅师隐居', author: '刘长卿', poem: '东林问逋客，何处栖幽偏？\n满腹万余卷，息机三十年。\n志图良已久，鬓发空苍然。\n调啸寄疎旷，形骸如弃捐。\n本家关西族，别业嵩阳田。\n云卧能独往，山栖幸周旋。\n垂竿不在鱼，卖药不为钱。\n藜杖闲倚壁，松花常醉眠。\n顷辞青溪隐，来访赤县仙。\n南亩自甘贱，中朝唯爱贤。\n仍空世谛法，远结天台缘。\n魏阙从此去，沧洲知所便。\n主人琼枝秀，宠别瑶华篇。\n落日扫尘榻，春风吹客船。\n此行颇自适，物外谁能牵。\n弄棹白苹里，挂帆飞鸟边。\n落潮见孤屿，彻底观澄涟。\n雁过湖上月，猿声峰际天。\n群峰趋海峤，千里黛相连。\n遥倚赤城上，曈曈初日圆。\n昔闻智公隐，此地常安禅。\n千载已如梦，一灯今尚传。\n云龛闭遗影，石窟无人烟。\n古寺暗乔木，春崖鸣细泉。\n流尘既寂寞，缅想增婵娟。\n山鸟怨庭树，门人思步莲。\n夷犹怀永路，怅望临清川。\n渔人来梦里，沙鸥飞眼前。\n独游岂易惬，群动多相缠。\n羡尔五湖夜，往来闲扣舷。' },
  { title: '寻张逸人山居', author: '刘长卿', poem: '危石才通鸟道，空山更有人家。\n桃源定在深处，涧水浮来落花。' },
  { title: '发越州赴润州使院留别鲍侍御', author: '刘长卿', poem: '对水看山别离，孤舟日暮行迟。\n江南江北春草，独向金陵去时。' },
  { title: '送陆[澧]还吴中', author: '刘长卿', poem: '瓜步寒潮送客，杨柳暮雨沾衣。\n故山南望何处，秋草连天独归。' },
  { title: '苕溪酬梁耿别后见寄', author: '刘长卿', poem: '清川永路何极，落日孤舟解携。\n鸟向平芜远近，人随流水东西。\n白云千里万里，明月前溪后溪。\n惆怅长沙谪去，江潭芳草萋萋。' },
  { title: '蛇浦桥下重送严维', author: '刘长卿', poem: '秋风飒飒鸣条，风月相和寂寥。\n黄叶一离一别，青山暮暮朝朝。\n寒江渐出高岸，古木犹依断桥。\n明日行人已远，空余泪滴回潮。' },
  { title: '七里滩重送', author: '刘长卿', poem: '秋江渺渺水空波，越客孤舟欲榜歌。\n手折衰杨悲老大，故人零落已无多。' },
  { title: '家园瓜熟是故萧相公所遗瓜种凄然感旧因赋此诗', author: '刘长卿', poem: '事去人亡迹自留，黄花绿蒂不胜愁。\n谁能更向青门外，秋草茫茫觅故侯。' },
  { title: '重送裴郎中贬吉州', author: '刘长卿', poem: '猿啼客散暮江头，人自伤心水自流。\n同作逐臣君更远，青山万里一孤舟。' },
  { title: '寻盛禅师兰若', author: '刘长卿', poem: '秋草黄花覆古阡，隔林何处起人烟。\n山僧独在山中老，唯有寒松见少年。' },
  { title: '寄许尊师', author: '刘长卿', poem: '独上云梯入翠微，蒙蒙烟雪映岩扉。\n世人知在中峰里，遥礼青山恨不归。' },
  { title: '酬李穆见寄', author: '刘长卿', poem: '孤舟相访至天涯，万转云山路更赊。\n欲扫柴门迎远客，青苔黄叶满贫家。' },
  { title: '送王司马秩满西归', author: '刘长卿', poem: '汉主何时放逐臣？江边几度送归人。\n同官岁岁先辞满，唯有青山伴老身。' },
  { title: '寄别朱拾遗', author: '刘长卿', poem: '天书远召沧浪客，几度临岐病未能。\n江海茫茫春欲遍，行人一骑发金陵。' },
  { title: '会赦后酬主簿所问', author: '刘长卿', poem: '江南海北长相忆，浅水深山独掩扉。\n重见太平身已老，桃源久住不能归。' },
  { title: '赠秦系', author: '刘长卿', poem: '向风长啸戴纱巾，野鹤由来不可亲。\n明日东归变名姓，五湖烟水觅何人。' },
  { title: '酬灵彻公相招', author: '刘长卿', poem: '石磵泉声久不闻，独临长路雪纷纷。\n如今渐欲生黄发，愿脱头冠与白云。' },
  { title: '赠崔九载华', author: '刘长卿', poem: '怜君一见一悲歌，岁岁无如老去何。\n白屋渐看秋草没，青云莫道故人多。' },
  { title: '同崔载华赠日本聘使', author: '刘长卿', poem: '怜君异域朝周远，积水连天何处通。\n遥指来从初日外，始知更有扶桑东。' },
  { title: '送建州陆使君', author: '刘长卿', poem: '汉庭初拜建安侯，天子临轩寄所忧。\n从此向南无限路，双旌已去水悠悠。' },
  { title: '送秦侍御外甥张篆之福州谒鲍大夫秦侍御与大夫有旧', author: '刘长卿', poem: '万里闽中去渺然，孤舟水上入寒烟。\n辕门拜首儒衣弊，貌似牢之岂不怜。' },
  { title: '闻奉迎皇太后使沈判官至因有此作', author: '刘长卿', poem: '长乐宫人扫落花，君王正候五云车。\n万方臣妾同瞻望，疑在曾城阿母家。' },
  { title: '送刘萱之道州谒崔大夫', author: '刘长卿', poem: '沅水悠悠湘水春，临岐南望一沾巾。\n信陵门下三千客，君到长沙见几人。' },
  { title: '过郑山人所居', author: '刘长卿', poem: '寂寂孤莺啼杏园，寥寥一犬吠桃源。\n落花芳草无寻处，万壑千峰独闭门。' },
  { title: '奉送贺若郎中贼退后之杭州', author: '刘长卿', poem: '江上初收战马尘，莺声柳色待行春。\n双旌谁道来何暮，万井如今有几人。' },
  { title: '瓜洲驿重送梁郎中赴吉州', author: '刘长卿', poem: '渺渺云山去几重，依依独听广陵钟。\n明朝借问南来客，五马双旌何处逢。' },
  { title: '奉使鄂渚至乌江道中作', author: '刘长卿', poem: '沧洲不复恋鱼竿，白发那堪戴铁冠。\n客路向南何处是，芦花千里雪漫漫。' },
  { title: '新息道中作', author: '刘长卿', poem: '萧条独向汝南行，客路多逢汉骑营。\n古木苍苍离乱后，几家同住一孤城。' },
  { title: '春日宴魏万成湘水亭', author: '刘长卿', poem: '何年家住此江滨，几度门前北渚春。\n白发乱生相顾老，黄莺自语岂知人。' },
  { title: '重送道标上人', author: '刘长卿', poem: '衡阳千里去人稀，遥逐孤云入翠微。\n春草青青新覆地，深山无路若为归。' },
  { title: '送李判官之润州行营', author: '刘长卿', poem: '万里辞家事鼓鼙，今陵驿路楚云西。\n江春不肯留归客，草色青青送马蹄。' },
  { title: '将赴南巴至余干别李十二', author: '刘长卿', poem: '江上花催问礼人，鄱阳莺报越乡春。\n谁怜此别悲欢异，万里青山送逐臣。' },
  { title: '时平后春日思归', author: '刘长卿', poem: '一尉何曾及布衣，时平却忆卧柴扉。\n故园柳色催南客，春水桃花待北归。' },
  { title: '送陶十赴杭州摄掾', author: '刘长卿', poem: '莫叹江城一掾卑，沧洲未是阻心期。\n浙中山色千万状，门外潮声朝暮时。' },
  { title: '使还七里濑上逢薛承规赴江西贬官', author: '刘长卿', poem: '迁客归人醉晚寒，孤舟暂泊子陵滩。\n怜君更去三千里，落日青山江上看。' },
  { title: '使回赴苏州道中作', author: '刘长卿', poem: '春风何事远相催，路尽天涯始却回。\n万里无人空楚水，孤帆送客到鱼台。' },
  { title: '昭阳曲', author: '刘长卿', poem: '昨夜承恩宿未央，罗衣犹带御衣香。\n芙蓉帐小云屏暗，杨柳风多水殿凉。' },
  { title: '罪所留系每夜闻长洲军笛声', author: '刘长卿', poem: '白日浮云闭不开，黄沙谁问冶长猜。\n只怜横笛关山月，知处愁人夜夜来。' },
  { title: '赠微上人', author: '刘长卿', poem: '禅门来往翠微间，万里千峰在剡山。\n何时共到天台里，身与浮云处处闲。' },
  { title: '东湖送朱逸人归', author: '刘长卿', poem: '山色湖光并在东，扁舟归去有樵风。\n莫道野人无外事，开田凿井白云中。' },
  { title: '舟中送李十八', author: '刘长卿', poem: '释子身心无有分，独将衣钵去人群。\n相思晚望西林寺，唯有钟声出白云。' },
  { title: '送李穆归淮南', author: '刘长卿', poem: '扬州春草新年绿，未去先愁去不归。\n淮水问君来早晚，老人偏畏过芳菲。' },
  { title: '晚春归山居题窗前竹', author: '刘长卿', poem: '溪上残春黄鸟稀，辛夷花尽杏花飞。\n始怜幽竹山窗下，不改清阴待我归。' },
  { title: '送卢侍御赴河北', author: '刘长卿', poem: '谪居为别倍伤情，何事从戎独远行。\n千里按图收故地，三军罢战及春耕。\n江天渺渺鸿初去，漳水悠悠草欲生。\n莫学仲连逃海上，田单空愧取聊城。' },
  { title: '送子壻崔真父归长城', author: '刘长卿', poem: '送君巵酒不成欢，幼女辞家事伯鸾。\n桃叶宜人诚可咏，柳花如雪若为看。\n心怜稚齿鸣环去，身愧衰颜对玉难。\n惆怅暮帆何处落，青山无限水漫漫。' },
  { title: '送陆[澧]仓曹西上', author: '刘长卿', poem: '长安此去欲何依，先达谁当荐陆机。\n日下凤翔双阙迥，雪中人去二陵稀。\n舟从故里难移棹，家住寒塘独掩扉。\n临水自伤流落久，赠君空有泪沾衣。' },
  { title: '送柳使君赴袁州', author: '刘长卿', poem: '宜阳出守新恩至，京口因家始愿违。\n五柳闭门高士去，三苗按节远人归。\n月明江路闻猨断，花暗山城见吏稀。\n惟有郡斋窗里岫，朝朝空对谢玄晖。' },
  { title: '戏题赠二小男', author: '刘长卿', poem: '异乡流落频生子，几许悲欢并在身。\n欲并老容羞白发，每看儿戏忆青春。\n未知门户谁堪主，且免琴书别与人。\n何幸暮年方有后，举家相对却沾巾。' },
  { title: '谪官后卧病官舍简贺兰侍郎', author: '刘长卿', poem: '青春衣绣共称宜，白首垂丝恨不遗。\n江上几回今夜月，镜中无复少年时。\n生还北阙谁相引，老向南邦众所悲。\n岁岁任他芳草绿，长沙未有定归期。' },
  { title: '岁日见新历因寄都官裴郎中', author: '刘长卿', poem: '青阳振蛰初颁历，白首衔冤欲问天。\n绛老更能经几岁，贾生何事又三年。\n愁占蓍草终难决，病对椒花倍自怜。\n若道平分四时气，南枝为底发春偏。' },
  { title: '江州重别薛六柳八二员外', author: '刘长卿', poem: '生涯岂料承优诏，世事空知学醉歌。\n江上月明胡鴈过，淮南木落楚山多。\n寄身且喜沧洲近，顾影无如白发何。\n今日龙钟人共弃，媿君犹遣慎风波。' },
  { title: '青溪口送人归岳州', author: '刘长卿', poem: '洞庭何处鴈南飞，江菼苍苍客去稀。\n帆带夕阳千里没，天连秋水一人归。\n黄花裛露开沙岸，白鸟衔鱼上钓矶。\n岐路相逢无可赠，老年空有泪沾衣。' },
  { title: '送灵澈上人还越中', author: '刘长卿', poem: '禅客无心杖锡还，沃洲深处草堂闲。\n身随敝屦经残雪，手绽寒衣入旧山。\n独向青溪依树下，空留白日在人间。\n那堪别后长相忆，云木苍苍但闭关。' },
  { title: '送耿拾遗归上都', author: '刘长卿', poem: '若为天畔独归秦，对水看山欲暮春。\n穷海别离无限路，隔河征战几归人。\n长安万里传双泪，建德千峰寄一身。\n想到邮亭愁驻马，不堪西望见风尘。' },
  { title: '和樊使君登润州城楼', author: '刘长卿', poem: '山城迢遰敞高楼，露冕吹铙居上头。\n春草连天随北望，夕阳浮水共东流。\n江田漠漠全吴地，野树苍苍故蒋州。\n王粲尚为南郡客，别来何处更销忧。' },
  { title: '饯王相公出牧括州', author: '刘长卿', poem: '缙云讵比长沙远，出牧犹承明主恩。\n城对寒山开画戟，路飞秋叶转朱轓。\n江潮淼淼连天望，旌斾悠悠上岭翻。\n萧索庭槐空闭合，旧人谁到翟公门。' },
  { title: '题灵祐和尚故居', author: '刘长卿', poem: '叹逝翻悲有此身，禅房寂寞见流尘。\n多时行径空秋草，几日浮生哭故人。\n风竹自吟遥入磬，雨花随泪共沾巾。\n残经窗下依然在，忆得山中问许询。' },
  { title: '寻龙井杨老', author: '刘长卿', poem: '柴门草舍绝风尘，空谷耕田学子真。\n泉咽恐劳经陇底，山深不觉有秦人。\n手栽松树苍苍老，身卧桃园寂寂春。\n唯有胡麻当鸡黍，白云来往未嫌贫。' },
  { title: '见故人李均所借古镜恨其未获归府斯人已亡怆然有作', author: '刘长卿', poem: '故人留镜无归处，今日怀君试暂窥。\n岁久岂堪尘自入，夜长应待月相随。\n空怜琼树曾临匣，犹见菱花独映池。\n所恨平生还不早，如今始挂陇头枝。' },
  { title: '闻虞沔州有替将归上都登汉东城寄赠', author: '刘长卿', poem: '淮南摇落客心悲，涢水悠悠怨别离。\n早鴈初辞旧关塞，秋风先入古城池。\n腰章建隼皇恩赐，露冕临人白发垂。\n惆怅恨君先我去，汉阳耆老忆旌麾。' },
  { title: '献淮宁军节度使李相公', author: '刘长卿', poem: '建牙吹角不闻喧，三十登坛众所尊。\n家散万金酬士死，身留一剑答君恩。\n渔阳老将多回席，鲁国诸生半在门。\n白马翩翩春草细，郊原西去猎平原。' },
  { title: '观校猎上淮西相公', author: '刘长卿', poem: '龙骧校猎邵陵东，野火初烧楚泽空。\n师事黄公千战后，身骑白马万人中。\n笳随晚吹吟边草，箭没寒云落塞鸿。\n三十拥旄谁不羡，周郎少小立奇功。' },
  { title: '送皇甫曾赴上都', author: '刘长卿', poem: '东游久与故人违，西去荒凉旧路微。\n秋草不生三径处，行人独向五陵归。\n离心日远如流水，回首川长共落晖。\n楚客岂劳伤此别，沧江欲暮自沾衣。' },
  { title: '送李录事兄归襄邓', author: '刘长卿', poem: '十年多难与君同，几处移家逐转蓬。\n白首相逢征战后，青春已过乱离中。\n行人杳杳看西月，归马萧萧向北风。\n汉水楚云千万里，天涯此别恨无穷。' },
  { title: '汉阳献李相公', author: '刘长卿', poem: '退身高卧楚城幽，独掩闲门汉水头。\n春草雨中行径没，暮山江上卷帘愁。\n几人犹忆孙弘阁，百口同乘范蠡舟。\n早晚却还丞相印，十年空被白云留。' },
  { title: '长沙过贾谊宅', author: '刘长卿', poem: '三年谪宦此栖迟，万古惟留楚客悲。\n秋草独寻人去后，寒林空见日斜时。\n汉文有道恩犹薄，湘水无情吊岂知。\n寂寂江山摇落处，怜君何事到天涯。' },
  { title: '奉酬辛大夫喜湖南腊月连日降雪见示之作', author: '刘长卿', poem: '长沙耆旧拜旌麾，喜见江潭积雪时。\n柳絮三冬先北地，梅花一夜徧南枝。\n初开窗阁寒光满，欲掩军城暮色迟。\n闾里何人不相庆，万家同唱郢中词。' },
  { title: '登余干古县城', author: '刘长卿', poem: '孤城上与白云齐，万古荒凉楚水西。\n官舍已空秋草绿，女墙犹在夜乌啼。\n平江渺渺来人远，落日亭亭向客低。\n沙鸟不知陵谷变，朝飞暮去弋阳溪。' },
  { title: '将赴岭外留题萧寺远公院', author: '刘长卿', poem: '竹房遥闭上方幽，苔径苍苍访昔游。\n内史旧山空日暮，南朝古木向人秋。\n天香月色同僧室，叶落猨啼傍客舟。\n此去播迁明主意，白云何事欲相留。' },
  { title: '初闻贬谪续喜量移登干越亭赠郑校书', author: '刘长卿', poem: '青青草色满江洲，万里伤心水自流。\n越鸟岂知南国远，江花独向北人愁。\n生涯已逐沧浪去，冤气初逢涣汗收。\n何事还邀迁客醉，春风日夜待归舟。' },
  { title: '北归入至德州界偶逢洛阳邻家李光宰', author: '刘长卿', poem: '生涯心事已蹉跎，旧路依然此重过。\n近北始知黄叶落，向南空见白云多。\n炎州日日人将老，寒渚年年水自波。\n华发相逢俱若是，故园秋草复如何。' },
  { title: '自江西归至旧任官舍赠袁赞府', author: '刘长卿', poem: '却见同官喜复悲，此生何幸有归期。\n空庭客至逢摇落，旧邑人稀经乱离。\n湘路来过回鴈处，江城卧听捣衣时。\n南方风土劳君问，贾谊长沙岂不知。' },
  { title: '赴南中题褚少府湖上亭子', author: '刘长卿', poem: '种田东郭傍春陂，万事无情把钓丝。\n绿竹放侵行径里，青山常对卷帘时。\n纷纷花落门空闭，寂寂莺啼日更迟。\n从此别君千万里，白云流水忆佳期。' },
  { title: '上巳日越中与鲍侍郎泛舟耶溪', author: '刘长卿', poem: '兰桡缦转傍汀沙，应接云峰到若耶。\n旧浦满来移渡口，垂杨深处有人家。\n永和春色千年在，曲水乡心万里赊。\n君见渔船时借问，前洲几路入烟花。' },
  { title: '双峰下哭故人李宥', author: '刘长卿', poem: '怜君孤垅寄双峰，埋骨穷泉复几重。\n白露空沾九原草，青山犹闭数株松。\n图书经乱知何在，妻子因贫失所从。\n惆怅东臯却归去，人间无处更相逢。' },
  { title: '使次安陆寄友人', author: '刘长卿', poem: '新年草色远萋萋，久客将归失路蹊。\n暮雨不知涢口处，春风只到穆陵西。\n孤城尽日空花落，三户无人自鸟啼。\n君在江南相忆否，门前五柳几枝低。' },
  { title: '哭陈歙州', author: '刘长卿', poem: '千秋万古葬平原，素业清风及子孙。\n旅榇归程伤道路，举家行哭向田园。\n空山寂寂开新垅，乔木苍苍掩旧门。\n儒行公才竟何在，独怜棠树一枝存。' },
  { title: '酬屈突陜', author: '刘长卿', poem: '落叶纷纷满四邻，萧条环堵绝风尘。\n乡看秋草归无路，家对寒江病且贫。\n藜杖懒迎征骑客，菊花能醉去官人。\n怜君计划谁知者，但见蓬蒿空没身。' },
  { title: '送惠法师游天台因怀智大师故居', author: '刘长卿', poem: '翠屏瀑水知何在，鸟道猨啼过几重。\n落日独摇金策去，深山谁向石桥逢。\n定攀岩下丛生桂，欲买云中若个峰。\n忆想东林禅诵处，寂寥惟听旧时钟。' },
  { title: '自夏口至鹦鹉洲夕望岳阳寄源中丞', author: '刘长卿', poem: '[汀]洲无浪复无烟，楚客相思益渺然。\n汉口夕阳斜渡鸟，洞庭秋水远连天。\n孤城背岭寒吹角，独戍临江夜泊船。\n贾谊上书忧汉室，长沙谪去古今怜。' },
  { title: '送侯中丞流康州', author: '刘长卿', poem: '长江极目带枫林，匹马孤云不可寻。\n迁播共知臣道枉，猜谗却为主恩深。\n辕门画角三军思，驿路青山万里心。\n北阙九重谁许屈，独看湘水泪沾襟。' },
  { title: '别严士元', author: '刘长卿', poem: '春风倚棹阖闾城，水国春寒阴复晴。\n细雨湿衣看不见，闲花落地听无声。\n日斜江上孤帆影，草绿湖南万里情。\n东道若逢相识问，青袍今日误儒生。' },
  { title: '避地江东留别淮南使院诸公', author: '刘长卿', poem: '长安路绝鸟飞通，万里孤云西复东。\n旧业已应成茂草，余生只是任飘蓬。\n何辞向物开秦镜，却使他人得楚弓。\n此去行持一竿竹，等闲将狎钓渔翁。' },
  { title: '罪所上御史惟则', author: '刘长卿', poem: '误因微禄滞南昌，幽系圜扉昼夜长。\n黄鹤翅垂同燕雀，青松心在任风霜。\n斗间谁与看冤气，盆下无由见太阳。\n贤达不能同感激，更于何处问苍苍。' },
  { title: '送台州李使君兼寄题国清寺', author: '刘长卿', poem: '露冕新承明主恩，山城别是武陵源。\n花间五马时行县，山外千峰常在门。\n晴江洲渚带春草，古寺杉松深暮猨。\n知到应真飞锡处，因君一想已忘言。' },
  { title: '狱中闻收东京有赦', author: '刘长卿', poem: '传闻阙下降丝纶，为报关东灭虏尘。\n壮志已怜成白首，余生犹待发青春。\n风霜何事偏伤物，天地无情亦爱人。\n持法不须张密网，恩波自解惜枯鳞。' },
  { title: '温汤客舍', author: '刘长卿', poem: '冬狩温泉岁欲阑，宫城佳气晚宜看。\n汤熏仗里千旗暖，雪照山边万井寒。\n君门献赋谁相达，客舍无钱輙自安。\n且喜礼闱秦镜在，还将妍丑付春官。' },
  { title: '送孙逸归庐山', author: '刘长卿', poem: '𬬻峰绝顶楚云衔，楚客东归栖此岩。\n彭蠡湖边香橘柚，浔阳郭外暗枫杉。\n青山不断三湘道，飞鸟空随万里帆。\n常爱此中多胜事，新诗他日伫开缄。' },
  { title: '送马秀才落第归江南', author: '刘长卿', poem: '南客怀归乡梦频，东门怅别柳条新。\n慇懃斗酒城阴暮，荡漾孤舟楚水春。\n湘竹旧斑思帝子，江蓠初绿怨骚人。\n怜君此去未得意，陌上愁看泪满巾。' },
  { title: '送常十九归嵩少故林', author: '刘长卿', poem: '迢迢此恨杳无涯，楚泽嵩丘千里赊。\n岐路别时惊一叶，云林归处忆三花。\n秋天苍翠寒飞鴈，古堞萧条晚噪鵶。\n他日山中逢胜事，桃源洞里几人家。' },
  { title: '送宇文迁明府赴洪州张观察追摄丰城令', author: '刘长卿', poem: '送君不复远为心，余亦扁舟湘水阴。\n路逐山光何处尽，春随草色向南深。\n陈蕃待客应悬榻，宓贱之官独抱琴。\n傥见主人论谪宦，尔来空有白头吟。' },
  { title: '送李将军', author: '刘长卿', poem: '征西诸将一如君，报德谁能不顾勋。\n身逐塞鸿来万里，手披荒草看孤坟。\n擒生绝漠经胡雪，怀旧长沙哭楚云。\n归去萧条灞陵上，几人看葬李将军。' },
  { title: '西陵寄一上人', author: '刘长卿', poem: '东山访道成开士，南渡隋阳作本师。\n了义惠心能善诱，吴风越俗罢淫祠。\n室中时见天人命，物外长悬海岳期。\n多谢清言异玄度，悬河高论有谁持。' },
  { title: '赋得', author: '刘长卿', poem: '莺啼燕语报新年，马邑龙堆路几千。\n家住层城临汉苑，[心]随明月到胡天。\n机中锦字论长恨，楼上花枝笑独眠。\n为问元戎窦车骑，何时返斾勒燕然。' },
  { title: '三月李明府后亭泛舟', author: '刘长卿', poem: '江南风景复如何，闻道新亭更欲过。\n处处纫兰春浦渌，萋萋籍草远山多。\n壶觞须就陶彭泽，时俗犹传晋永和。\n更待持桡徐转去，微风落日水增波。' },
  { title: '喜朱拾遗承恩拜命赴任上都', author: '刘长卿', poem: '诏书征拜脱荷裳，身去东山闭草堂。\n阊阖九天通奏籍，华亭一鹤在朝行。\n沧洲离别风烟远，青琐幽深漏刻长。\n今日却回垂钓处，海鸥相见已高翔。' },
  { title: '郧上送韦司士归上都旧业', author: '刘长卿', poem: '前朝旧业想遗尘，今日他乡独尔身。\n郧地国除为过客，杜陵家在有何人。\n苍苔白露生三径，古木寒蝉满四邻。\n西去茫茫问归路，关河渐近泪盈巾。' },
  { title: '感怀', author: '刘长卿', poem: '秋风落叶正堪悲，黄菊残花欲待谁。\n水近偏逢寒气早，山深常见日光迟。\n愁中卜命看周易，梦里招魂读楚词。\n自笑不如湘浦鴈，飞来即是北归时。' },
  { title: '送杨于陵归宋汴州别业', author: '刘长卿', poem: '半山溪雨带斜晖，向水残花映客衣。\n旅食嗟余当岁晚，能文似汝少年稀。\n新河柳色千株暗，故国云帆万里归。\n离乱要知君到处，寄书须及鴈南飞。' },
  { title: '送崔使君赴寿州', author: '刘长卿', poem: '列郡专城分国忧，彤幨皂盖古诸侯。\n仲华遇主年犹少，公瑾论功位已酬。\n草色青青迎建隼，蝉声处处杂鸣驺。\n千里相思如可见，淮南木叶正惊秋。' },
  { title: '上阳宫望幸', author: '刘长卿', poem: '玉辇西巡久未还，春光犹入上阳间。\n万木长承新雨露，千门空对旧河山。\n深花寂寂宫城闭，细草青青御路闲。\n独见彩云飞不尽，只应来去候龙颜。' },
  { title: '过裴舍人故居', author: '刘长卿', poem: '惨惨天寒独掩扃，纷纷黄叶满空庭。\n孤坟何处依山木，百口无家学水萍。\n篱花犹及重阳发，邻笛那堪落日听。\n书幌无人长不卷，秋来芳草自为萤。' },
  { title: '登松江驿楼北望故园', author: '刘长卿', poem: '泪尽江楼北望归，田园已陷百重围。\n平芜万里无人去，落日千山空鸟飞。\n孤舟漾漾寒潮小，极浦苍苍远树微。\n白鸥渔父徒相待，未扫欃枪嬾息机。' },
  { title: '秋夜有怀高三十五适兼呈空上人', author: '刘长卿', poem: '晚节逢君趣道深，结茅栽树近东林。\n吾师几度曾摩顶，高士何年遂发心。\n北渚三更闻过鴈，西城万里动寒砧。\n不见支公与玄度，相思拥膝坐长吟。' },
  { title: '送孔巢父赴河南军', author: '刘长卿', poem: '江南相送隔烟波，况复新秋一鴈过。\n闻道全军征北虏，又言诗将会南河。\n边心冉冉乡人绝，寒色青青战马多。\n共许陈琳工奏记，知君名行未蹉跎。' },
  { title: '登润州万岁楼', author: '刘长卿', poem: '高楼独上思依依，极浦遥山合翠微。\n江客不堪频北望，寒鸿何事又南飞。\n垂山古渡寒烟积，瓜步空洲远树稀。\n闻道王师犹转战，更能谈笑解重围。' },
  { title: '江楼送太康郭主簿赴岭南', author: '刘长卿', poem: '对酒怜君安可论，当官爱士如平原。\n料钱用尽却为谤，食客空多谁报恩。\n万里孤舟向南越，苍梧云中暮帆灭。\n树色应无江北秋，天涯尚见淮阳月。\n驿路南随桂水流，猨声不绝到炎州。\n青山落日那堪望，谁见思君江上楼。' },
  { title: '客舍喜郑三见寄', author: '刘长卿', poem: '客舍逢君未换衣，闭门愁见桃花飞。\n遥想故园今已尔，家人应念行人归。\n寂寞垂杨映深曲，长安日暮灵台宿。\n穷巷无人鸟雀闲，空庭新雨莓苔绿。\n北中分与故交疎，何幸仍回长者车。\n十年未称平生意，好得辛勤谩读书。' },
  { title: '送贾三北游', author: '刘长卿', poem: '贾生未达犹窘迫，身驰匹马邯郸陌。\n片云郊外遥送人，斗酒城边暮留客。\n顾予他日仰时髦，不堪此别相思劳。\n雨色新添漳水绿，夕阳远照苏门高。\n把袂相看衣共缁，穷愁只是惜良时。\n亦知到处逢下榻，莫滞秋风西上期。' },
  { title: '齐一和尚影堂', author: '刘长卿', poem: '一公住世忘世纷，暂来复去谁能分。\n身寄虚空如过客，心将生灭是浮云。\n萧散浮云往不还，凄凉遗教殁仍传。\n旧地愁看双树在，空堂只是一灯悬。\n一灯长照恒河沙，双树犹落诸天花。\n天花寂寂香深殿，苔藓苍苍閟虚院。\n昔余精念访禅扉，常接微言清道机。\n今来寂寞无所得，唯共门人泪满衣。' },
  { title: '颍川留别司仓李万', author: '刘长卿', poem: '故人早负干将器，谁言未展平生意。\n想君畴昔高步时，肯料如今折腰事。\n且知投刃皆若虚，日挥案牍常有余。\n槐暗公庭趋小吏，荷香陂水脍鲈鱼。\n客里相逢款话深，如何岐路剩沾襟。\n白云西上催归念，颍水东流是别心。\n落日征骖随去尘，含情挥手背城𬮱。\n已恨良时空此别，不堪秋草更愁人。' },
  { title: '听笛歌', author: '刘长卿', poem: '旧游怜我长沙谪，载酒沙头送迁客。\n天涯望月自沾衣，江上何人复吹笛。\n横笛能令孤客愁，渌波淡淡如不流。\n商声寥亮羽声苦，江天寂历江枫秋。\n静听关山闻一叫，三湘月色悲猨啸。\n又吹杨柳激繁音，千里春色伤人心。\n随风飘向何处落，唯见曲尽平湖深。\n明发与君离别后，马上一声堪白首。' },
  { title: '时平后送范伦归安州', author: '刘长卿', poem: '昨闻战罢图麟阁，破虏收兵卷戎幕。\n沧海初看汉月明，紫微已见胡星落。\n忆昔扁舟此南渡，荆棘烟尘满归路。\n与君携手姑苏台，望乡一日登几回。\n白云飞鸟去寂寞，吴山楚岫空崔嵬。\n事往时平还旧丘，青青春草近家愁。\n洛阳举目今谁在，颍水无情应自流。\n吴苑西人去欲稀，留连一日空知非。\n江潭岁尽愁不尽，鸿鴈春归身未归。\n万里遥悬帝乡忆，五年空带风尘色。\n却到长安逢故人，不道姓名应不识。' },
  { title: '小鸟篇上裴尹', author: '刘长卿', poem: '藩篱小鸟何甚微，翩翩日夕空此飞。\n只缘六翮不自致，长似孤云无所依。\n西城黯黯斜晖落，众鸟纷纷皆有托。\n独立虽轻燕雀群，孤飞远惧鹰鹯搏。\n自怜天上青云路，吊影徘徊独愁暮。\n衔花纵有报恩时，择木谁容托身处。\n岁月蹉跎飞不进，羽毛鹪顇何人问。\n遶树空随乌鹊惊，巢林只有鹪鹩分。\n主人庭中荫乔木，爱此清阴欲栖宿。\n少年挟弹遥相猜，遂使惊飞往复回。\n不辞奋翼向君去，唯怕金丸随后来。' },
  { title: '登吴古城歌', author: '刘长卿', poem: '登古城兮思古人，感贤达兮同埃尘。\n望平原兮寄远目，叹姑苏兮聚麋鹿。\n黄池高会事未终，沧海横流人荡复。\n伍员杀身谁不冤，竟看墓树如所言。\n越王尝胆安可敌，远取石田何所益。\n一朝空谢会稽人，万古犹伤甬东客。\n黍离离兮城坡坨，牛羊践兮牧竖歌。\n野无人兮秋草绿，园为墟兮古木多。\n白杨萧萧悲故柯，黄雀啾啾争晚禾。\n荒阡断兮谁重过，孤舟逝兮愁若何。\n天寒日暮江枫落，叶去辞风水自波。' },
  { title: '疲兵篇', author: '刘长卿', poem: '骄虏乘秋下蓟门，阴山日夕烟尘昏。\n三军疲马力已尽，百战残兵功未论。\n阵云泱漭屯塞北，羽书纷纷来不息。\n孤城望处增断肠，折剑看时可沾臆。\n元戎日夕且歌舞，不念关山久辛苦。\n自矜倚剑气凌云，却笑闻笳泪如雨。\n万里飘飖空此身，十年征战老胡尘。\n赤心报国无片赏，白首还家有几人。\n朔风萧萧动枯草，旌旗猎猎榆关道。\n汉月何曾照客心，胡笳只解催人老。\n军前仍欲破重围，闺里犹应愁未归。\n小妇十年啼夜织，行人九月忆寒衣。\n饮马滹河晚更清，行吹羗笛远归营。\n只恨汉家多苦战，徒遗金镞满长城。' },
  { title: '新安送陆[澧]归江阴', author: '刘长卿', poem: '新安路，人来去。\n早潮复晚潮，明日知何处。\n潮水无情亦解归，自怜长在新安住。' },
  { title: '弄白鸥歌', author: '刘长卿', poem: '泛泛江上鸥，毛衣皓如雪。\n朝飞潇湘水，夜宿洞庭月。\n归客正夷犹，爱此沧江闲白鸥。' },
  { title: '长沙赠衡岳祝融峰般若禅师', author: '刘长卿', poem: '般若公，般若公，负钵何时下祝融。\n归路却看飞鸟外，禅房空掩白云中。\n桂花寥寥闲自落，流水无心西复东。' },
  { title: '赠湘南渔父', author: '刘长卿', poem: '闻君何所适，暮暮逢烟水。\n独与不系舟，往来楚云里。\n钓鱼非一岁，终日只如此。\n日落江清桂檝迟，纤鳞百尺深可窥。\n沈钩垂饵不在得，白首沧浪空自知。' },
  { title: '明月湾寻贺九不遇', author: '刘长卿', poem: '楚水日夜绿，傍江春草滋。\n青青遥满目，万里伤心归。\n故人川上复何之，明月湾南空所思。\n故人不在明月在，谁见孤舟来去时。' },
  { title: '题曲阿三昧王佛殿前孤石', author: '刘长卿', poem: '孤石自何处，对之疑旧游。\n氛氲岘首夕，苍翠剡中秋。\n迥出群峰当殿前，雪山灵鹫慙贞坚。\n一片孤云长不去，莓苔古色空苍然。' },
  { title: '送友人东归', author: '刘长卿', poem: '对酒灞亭暮，相看愁自深。\n河边草已绿，此别难为心。\n关路迢迢匹马归，垂杨寂寂数莺飞。\n怜君献策十余载，今日犹为一布衣。' },
  { title: '入桂渚次砂牛石穴', author: '刘长卿', poem: '扁舟傍归路，日暮潇湘深。\n湘水清见底，楚云淡无心。\n片帆落桂渚，独夜依枫林。\n枫林月出猨声苦，桂渚天寒桂花吐。\n此中无处不堪愁，江客相看泪如雨。' },
  { title: '严陵钓台送李康成赴江东使', author: '刘长卿', poem: '潺湲子陵濑，髣髴如在目。\n七里人已非，千年水空绿。\n新安江上孤帆远，应逐枫林万余转。\n古台落日共萧条，寒水无波更清浅。\n台上渔竿不复持，却令猨鸟向人悲。\n滩声山翠至今在，迟尔行舟晚泊时。' },
  { title: '送姨子弟往南郊', author: '刘长卿', poem: '一展慰久阔，寸心仍未伸。\n别时两童稚，及此俱成人。\n那堪适会面，遽已悲分首。\n客路向楚云，河桥对衰柳。\n送君匹马别河桥，汝南山郭寒萧条。\n今我单车复西上，郎去灞陵转惆怅。\n何处共伤离别心，明月亭亭两乡望。' },
  { title: '铜雀台', author: '刘长卿', poem: '娇爱更何日，高台空数层。\n含啼映双袖，不忍看西陵。\n漳河东流无复来，百花辇路为苍苔。\n[青]楼月夜长寂寞，碧云日暮空徘徊。\n君不见邺中万事非昔时，古人不在今人悲。\n春风不逐君王去，草色年年旧宫路。\n宫中歌舞已浮云，空指行人往来处。' },
  { title: '王昭君歌', author: '刘长卿', poem: '自矜娇艳色，不顾丹青人。\n那知粉绘能相负，却使容华翻误身。\n上马辞君嫁骄虏，玉颜对人啼不语。\n北风鴈急浮云秋，万里独见黄河流。\n纤腰不复汉宫宠，双蛾长向胡天愁。\n琵琶弦中苦调多，萧萧羌笛声相和。\n谁怜一曲传乐府，能使千秋伤绮罗。' },
  { title: '送杜越江佐觐省往新安江', author: '刘长卿', poem: '去帆楚天外，望远愁复积。\n想见新安江，扁舟一行客。\n清流数千丈，底下看白石。\n色混元气深，波连洞庭碧。\n鸣桹去未已，前路行可觌。\n猨鸟悲啾啾，杉松雨声夕。\n送君东赴归宁期，新安江水远相随。\n见说江中孤屿在，此行应赋谢公诗。' },
  { title: '湘中忆归', author: '刘长卿', poem: '终日空理棹，经年犹别家。\n顷来行已远，弥觉天无涯。\n白云意自深，沧海梦难隔。\n迢递万里帆，飘飖一行客。\n独怜西江外，远寄风波里。\n平湖流楚天，孤鴈渡湘水。\n湘流澹澹空愁予，猨啼啾啾满南楚。\n扁舟泊处闻此声，江客相看泪如雨。' },
  { title: '送郭六侍从之武陵郡', author: '刘长卿', poem: '常爱武陵郡，羡君将远寻。\n空怜世界迫，孤负桃源心。\n洛阳遥想桃源隔，野水闲流春自碧。\n花下常迷楚客船，洞中时见秦人宅。\n落日相看斗酒前，送君南望但依然。\n河梁马首随春草，江路猨声愁暮天。\n丈人别乘佐分忧，才子趋庭兼胜游。\n澧浦荆门行可见，知君诗兴满沧洲。' },
  { title: '山鸜鹆歌', author: '刘长卿', poem: '山鸜鹆，长在此山吟古木。\n嘲唽相呼响空谷，哀鸣万变如成曲。\n江南逐臣悲放逐，倚树听之心断续。\n巴人峡里自闻猨，燕客水头空击筑。\n山鸜鹆，一生不及双黄鹄。\n朝去秋田啄残粟，暮入寒林啸群族。\n鸣相逐，啄残粟，食不足。\n青云杳杳无力飞，白露苍苍抱枝宿。\n不知何事守空山，万壑千峰自愁独。' },
  { title: '望龙山怀道士许法棱', author: '刘长卿', poem: '心惆怅，望龙山。\n云之际，鸟独还。\n悬崖绝壁几千丈，绿萝袅袅不可攀。\n龙山高，谁能践。\n灵原中，苍翠晚。\n岚烟瀑水如向人，终日迢迢空在眼。\n中有一人披霓裳，诵经山顶飧琼浆。\n空林闲坐独焚香，真官列侍俨成行。\n朝入青霄礼玉堂，夜扫白云眠石床。\n桃花洞里居人满，桂树山中住日长，龙山高高遥相望。' },
  { title: '戏赠干越尼子歌', author: '刘长卿', poem: '鄱阳女子年十五，家本秦人今在楚。\n厌向春江空浣沙，龙宫落发披袈裟。\n五年持戒长一食，至今犹自颜如花。\n亭亭独立青莲下，忍草禅枝绕精舍。\n自用黄金买地居，能嫌碧玉随人嫁。\n北客相逢疑姓秦，铅花抛却仍青春。\n一花一竹如有意，不语不笑能留人。\n黄鹂欲栖白日暮，天香未散经行处。\n却对香炉闲诵经，春泉漱玉寒泠泠。\n云房寂寂夜钟后，吴音清切令人听。\n人听吴音歌一曲，杳然如在诸天宿。\n谁堪世事更相牵，惆怅回船江水渌。' },
  { title: '游四窗', author: '刘长卿', poem: '四明山绝奇，自古说登陆。\n苍崖倚天立，覆石如覆屋。\n玲珑开户牖，落落明四目。\n箕星分南野，有斗挂檐北。\n日月居东西，朝昏互出没。\n我来游其间，寄傲巾半幅。\n白云本无心，悠然伴幽独。\n对此脱尘鞅，顿忘荣与辱。\n长笑天地宽，仙风吹佩玉。' },
  { title: '和中丞出使恩命过终南别业', author: '刘长卿', poem: '不过林园久，多因宠遇偏。\n故山长寂寂，春草过年年。\n花待朝衣间，云迎驿骑连。\n松萝深旧合，樵木散闲田。\n拜阙贪摇珮，看琴懒更弦。\n君恩催早入，已梦[傅]岩边。' },
  { title: '岳阳楼', author: '刘长卿', poem: '行尽清溪日已蹉，云容山影两嵯峨。\n楼前归客怨秋梦，湖上美人疑夜歌。\n独坐高高风势急，平湖渺渺月明多。\n终期一艇载樵去，来往片帆愁白波。' },
  { title: '春望寄王涔阳', author: '刘长卿', poem: '清明别后雨晴时，极浦空颦一望眉。\n湖畔春山烟点点，云中远树墨离离。\n依微水戍闻钲鼓，掩映沙村见酒旗。\n风煖草长愁自醉，行吟无处寄相思。' },
  { title: '留辞', author: '刘长卿', poem: '南楚迢迢通汉口，西江淼淼去扬州。\n春风已遣归心促，纵复芳菲不可留。' },
  { title: '题杼山癸亭得暮字', author: '颜真卿', poem: '杼山多幽绝，胜事盈跬步。\n前者虽登攀，淹留恨晨暮。\n及兹纡胜引，曾是美无度。\n歘构三癸亭，实为陆生故。\n高贤能剏物，疏凿皆有趣。\n不越方丈间，居然云霄遇。\n巍峨倚修岫，旷望临古渡。\n左右苔石攒，低昂桂枝蠹。\n山僧狎猨狖，巢鸟来枳椇。\n俯视何楷台，傍瞻戴颙路。\n迟回未能下，夕照明村树。' },
  { title: '谢陆处士杼山折青桂花见寄之什', author: '颜真卿', poem: '群子游杼山，山寒桂花白。\n绿荑含素蕚，采折自逋客。\n忽枉岩中诗，芳香润金石。\n全高南越蠹，岂谢东堂策。\n会惬名山期，从君恣幽觌。' },
  { title: '赠裴将军', author: '颜真卿', poem: '大君制六合，猛将清九垓。\n战马若龙虎，腾凌何壮哉。\n将军临八荒，烜赫耀英材。\n劒舞若游电，随风萦且回。\n登高望天山，白云正崔巍。\n入阵破骄虏，威名雄震雷。\n一射百马倒，再射万夫开。\n匈奴不敢敌，相呼归去来。\n功成报天子，可以画麟台。' },
  { title: '赠僧皎然', author: '颜真卿', poem: '秋意西山多，别岑萦左次。\n缮亭历三癸，趾趾邻什寺。\n元化隐灵踪，始君启高致。\n诛榛养翘楚，鞭草理芳穗。\n俯砌披水容，逼天扫峰翠。\n境新耳目换，物远风尘异。\n倚石忘世情，援云得真意。\n嘉林幸勿剪，禅侣欣可庇。\n卫法大臣过，佐游群英萃。\n龙池护清激，虎节到深邃。\n徒想嵊顶期，于今没遗记。' },
  { title: '咏陶渊明', author: '颜真卿', poem: '张良思报韩，龚胜耻事新。\n狙击不肯就，舍生悲缙绅。\n呜呼陶渊明，奕叶为晋臣。\n自以公相后，每怀宗国屯。\n题诗庚子岁，自谓羲皇人。\n手持山海经，头戴漉酒巾。\n兴逐孤云外，心随还鸟泯。' },
  { title: '三言拟五杂组二首 一', author: '颜真卿', poem: '五杂组，绣与锦。\n往复还，兴又寝。\n不得已，病伏枕。' },
  { title: '三言拟五杂组二首 二', author: '颜真卿', poem: '五杂组，甘咸醋。\n往复还，乌与兔。\n不得已，韶光度。' },
  { title: '使过瑶台寺有怀圆寂上人', author: '颜真卿', poem: '上人居此寺，不出三十年。\n万法元无着，一心唯趣禅。\n忽纡尘外轸，远访区中缘。\n及尔不复见，支提犹岌然。' },
  { title: '登平望桥下作', author: '颜真卿', poem: '登桥试长望，望极与天平。\n际海蒹葭色，终朝凫鴈声。\n近山犹髣髴，远水忽微明。\n更览诸公作，知高题柱名。' },
  { title: '刻清远道士诗因而继作', author: '颜真卿', poem: '不到东西寺，于今五十春。\n朅来从旧赏，林壑宛相亲。\n吴子多藏日，秦王厌胜辰。\n劒池穿万仞，盘石坐千人。\n金气腾为虎，琴台化若神。\n登坛仰生一，舍宅叹珣珉。\n中岭分双树，回峦绝四邻。\n窥临江海接，崇饰四时新。\n客有神仙者，于兹雅丽陈。\n名高清远峡，文聚斗牛津。\n迹异心宁间，声同质岂均。\n悠然千载后，知我揖光尘。' },
  { title: '杂诗六首 一', author: '李华', poem: '黄钟扣元音，律吕更循环。\n邪气悖正声，郑卫生其间。\n典乐忽涓微，波浪与天浑。\n嘈嘈鸱枭动，好鸟徒緜蛮。\n王吉归乡里，甘心长闭关。' },
  { title: '杂诗六首 二', author: '李华', poem: '玄黄与丹青，五气之正色。\n圣人端其源，上下皆有则。\n齐侯好紫衣，魏帝妇人饰。\n女奴厌金翠，倾海未满臆。\n何忍严子陵，羊裘死荆棘。' },
  { title: '杂诗六首 三', author: '李华', poem: '甘酸不私人，元和运五行。\n生人受其用，味正心亦平。\n爪牙相践伤，日与性命争。\n圣人不能绝，钻燧与炮烹。\n嗜欲乘此炽，百金资一倾。\n正销神耗衰，邪胜体充盈。\n颜子有余乐，瓢中寒水清。' },
  { title: '杂诗六首 四', author: '李华', poem: '阴魄沦宇宙，太阳假其明。\n臣道不敢专，由此见亏盈。\n未闻东菑稼，一气嘉谷成。\n上天降寒暑，地利乃可生。\n葛藟附柔木，繁阴蔽曾原。\n风霜摧枝干，不复庇本根。\n女萝依松柏，然后得长存。' },
  { title: '杂诗六首 五', author: '李华', poem: '孔光尊董贤，胡广惭李固。\n儒风冠天下，而乃败王度。\n绛侯与愽陆，忠朴受遗顾。\n求名不考实，文弊反成蠹。' },
  { title: '杂诗六首 六', author: '李华', poem: '结交得书生，书生钝且直。\n争权复争利，终不得其力。\n我逢纵横者，是我牙与翼。\n相旋如疾风，竝命趋紫极。\n奔车得停轨，风火何相逼。\n仁义岂有常，肝胆反为贼。\n勿嫌书生直，钝直深可忆。' },
  { title: '咏史十一首 一', author: '李华', poem: '昂藏獬豸兽，出自太平年。\n乱代乃潜伏，纵人为祸愆。\n尝闻断马劒，每壮朱云贤。\n身死名不灭，寒风吹[墓]田。\n精灵如有在，幽愤满松烟。' },
  { title: '咏史十一首 二', author: '李华', poem: '汉皇修雅乐，乘舆临太学。\n三老与五更，天王亲割牲。\n一人调风俗，万国和且平。\n单于骤款塞，武库欲销兵。\n文物此朝盛，君臣何穆清。\n至今壝坛下，如有箫韶声。' },
  { title: '咏史十一首 三', author: '李华', poem: '巢许在嵩颍，陶唐不得臣。\n九州尚洗耳，一命安能亲。\n緜邈数千祀，丘中谁隐沦。\n朝游公卿府，夕是山林人。\n蒲帛扬侧陋，薜萝为缙绅。\n九重念入梦，三事思降神。\n且设庭中燎，宁窥泉下鳞。' },
  { title: '咏史十一首 四', author: '李华', poem: '汉时征百粤，杨仆将楼船。\n幕府功未立，江湖已骚然。\n岛夷非敢乱，政暴地仍偏。\n得罪因怀璧，防身辄控弦。\n三军求裂土，万里讵闻天。\n魏阙心犹在，旗门首已悬。\n如何得良吏，一为制方圆。' },
  { title: '咏史十一首 五', author: '李华', poem: '秦灭汉帝兴，南山有遗老。\n危冠揖万乘，幸得厌征讨。\n当君逐鹿时，臣等已枯槁。\n宁知市朝变，但觉林泉好。\n高卧三十年，相看成四皓。\n帝言翁甚善，见顾何不早。\n咸称太子仁，重义亦尊道。\n侧闻骊姬事，申生不自保。\n暂出商山云，朅来趋洒扫。\n东宫成羽翼，楚舞伤怀抱。\n后代无其人，戾园满秋草。' },
  { title: '咏史十一首 六', author: '李华', poem: '日照昆仑上，羽人披羽衣。\n乘龙驾云雾，欲往心无违。\n此山在西北，乃是神仙国。\n灵气皆自然，求之不可得。\n何为汉武帝，精思徧群山。\n糜费巨万计，宫车终不还。\n苍苍茂陵树，足以戒人间。' },
  { title: '咏史十一首 七', author: '李华', poem: '天生忠与义，本以佐雍熙。\n何意李司隶，而当昏乱时。\n古坟襄城野，斜径横秋陂。\n况不禁樵采，茅莎无孑遗。\n高标尚可仰，精爽今何之。\n一忤中常侍，衔冤谁见知。\n尝观党锢传，抚卷不胜悲。' },
  { title: '咏史十一首 八', author: '李华', poem: '文侯耽郑卫，一听一忘餐。\n白雪燕姬舞，朱弦赵女弹。\n淫声流不返，慆荡日无端。\n献岁受朝时，鸣钟䜩百官。\n两床陈管磬，九奏殊未阑。\n对此唯恐卧，更能整衣冠。' },
  { title: '咏史十一首 九', author: '李华', poem: '蜀主相诸葛，功高名亦尊。\n驱驰千万众，怒目瞰中原。\n曹伯任公孙，国亡身不存。\n社宫久芜没，白鴈犹飞翻。\n勿言君臣合，可以济黎元。\n为蜀谅不易，如曹难复论。' },
  { title: '咏史十一首 十', author: '李华', poem: '六国韩最弱，末年尤畏秦。\n郑生为韩计，且欲疲秦人。\n利物可分社，原情堪灭身。\n咸阳古城下，万顷稻苗新。' },
  { title: '咏史十一首 十一', author: '李华', poem: '沂水春可涉，泮宫映杨叶。\n丽色异人间，珊珊摇珮环。\n展禽恒独处，深巷生禾黍。\n城上飞海云，城中暗春雨。\n适来鸣珮者，复是谁家女。\n泥沾珠缀履，雨湿翠毛簪。\n电影开莲脸，雷声飞蕙心。\n自言沂水曲，采萍兼采菉。\n归迳虽可寻，天阴光景促。\n怜君贞且独，愿许君家宿。\n徒劳惜衾枕，了不顾双蛾。\n艳质诚可重，淫风如礼何。\n周王惑襃姒，城阙成陂陁。' },
  { title: '云母泉诗', author: '李华', poem: '晨登玄石岭，岭上寒松声。\n朗日风雨霁，高秋天地清。\n山门开古寺，石窦含纯精。\n洞彻净金界，夤缘流玉英。\n泽药滋畦茂，气染茶瓯馨。\n饮液尽眉寿，飡和皆体平。\n琼浆驻容发，甘露莹心灵。\n岱谷谢巧妙，匡山徒有名。\n愿言构蓬荜，荷锸引泠泠。\n访道出人世，招贤依福庭。\n此心不能已，寤寐见吾兄。\n曾结颍阳契，穷年无所成。\n东西同放逐，蛇豕尚纵横。\n江汉阻携手，天涯万里情。\n恩光起憔悴，西上谒承明。\n秋色变江树，相思纷以盈。\n猨啼巴丘戍，月上武陵城。\n共恨川路永，无由会友生。\n云泉不可忘，何日遂躬耕。' },
  { title: '仙游寺', author: '李华', poem: '舍事入樵迳，云木深谷口。\n万壑移晦明，千峰转前后。\n嶷然龙潭上，石势若奔走。\n开拆秋天光，崩腾夏雷吼。\n灵谿自兹去，纡直互纷纠。\n听声静复喧，望色无更有。\n冥冥翠微下，高殿映杉柳。\n滴滴洞穴中，悬泉响相扣。\n昔时秦王女，羽化年代久。\n日暮松风来，箫声生左右。\n早窥神仙箓，愿结芝术友。\n安得羡门方，青囊系吾肘。' },
  { title: '春游吟', author: '李华', poem: '初春遍芳甸，千里蔼盈瞩。\n美人摘新英，步步玩春绿。\n所思杳何处，宛在吴江曲。\n可怜不得共芳菲，日暮归来泪满衣。' },
  { title: '长门怨', author: '李华', poem: '弱体鸳鸯荐，啼妆翡翠衾。\n鸦鸣秋殿晓，人静禁门深。\n每忆椒房宠，那堪永巷阴。\n自惊罗带缓，非复旧来心。' },
  { title: '奉使朔方赠郭都护', author: '李华', poem: '绝塞临光禄，孤营佐贰师。\n铁衣山月冷，金鼓朔风悲。\n都护征兵日，将军破虏时。\n扬鞭玉关道，回首望旌旗。' },
  { title: '尚书都堂瓦松', author: '李华', poem: '华省秘仙踪，高堂露瓦松。\n叶因春后长，花为雨来浓。\n影混鸳鸯色，光含翡翠容。\n天然斯所寄，地势太无从。\n接栋临双阙，连甍近九重。\n宁知深涧底，霜雪岁兼封。' },
  { title: '海上生明月', author: '李华', poem: '皎皎秋中月，团团海上生。\n影开金镜满，轮抱玉壶清。\n渐出三山岊，将凌一汉横。\n素娥尝药去，乌鹊遶枝惊。\n照水光偏白，浮云色最明。\n此时尧砌下，蓂荚自将荣。' },
  { title: '晚日湖上寄所思', author: '李华', poem: '与君为近别，不啻远相思。\n落日平湖上，看山对此时。' },
  { title: '寄从弟', author: '李华', poem: '眼病身亦病，浮生已半空。\n迢迢千里月，应与惠连同。' },
  { title: '奉寄彭城公', author: '李华', poem: '公子三千客，人人愿报恩。\n应怜抱关者，贫病老夷门。' },
  { title: '春行寄兴', author: '李华', poem: '宜阳城下草萋萋，涧水东流复向西。\n芳树无人花自落，春山一路鸟空啼。' },
  { title: '江有枫一篇十章 一', author: '萧颖士', poem: '江有枫，其叶蒙蒙。\n我友自东，于以游从。' },
  { title: '江有枫一篇十章 二', author: '萧颖士', poem: '山有槭，其叶漠漠。\n我友徂北，于以休息。' },
  { title: '江有枫一篇十章 三', author: '萧颖士', poem: '想彼槭矣，亦类其枫。\n矧伊怀人，而忘其东。' },
  { title: '江有枫一篇十章 四', author: '萧颖士', poem: '东可游矣，会之丘矣。\n于山于水，于庙于寺。\n于亭于里，君子游焉。\n于以宴喜，其乐亹亹。' },
  { title: '江有枫一篇十章 五', author: '萧颖士', poem: '粤东可居，彼吴之墟。\n有田有庭，有朋有书。\n有莼有鱼，君子居焉。\n惟以宴醑，其乐徐徐。' },
  { title: '江有枫一篇十章 六', author: '萧颖士', poem: '我朋在矣，彼陆之子。\n如松如杞，淑问不已。' },
  { title: '江有枫一篇十章 七', author: '萧颖士', poem: '我友于征，彼郑之子。\n如琇如英，德音孔明。' },
  { title: '江有枫一篇十章 八', author: '萧颖士', poem: '我思震泽，菱芡幕幕。\n寤寐如觌，我思剡谿。\n杉筿萋萋，寤寐无迷。' },
  { title: '江有枫一篇十章 九', author: '萧颖士', poem: '有鸟有鸟，粤鸥与鹭。\n浮湍戏渚，皓然洁素。\n忘其猜妒，彼何人斯，曾足伤惧。' },
  { title: '江有枫一篇十章 十', author: '萧颖士', poem: '此惧惟何，惧寘于罗。\n彼骄者子，谗言孔多。\n我闻先师，体命委和。\n公伯之愬，则如予何。\n怅然山河，惟以啸歌，其忧也哉。' },
  { title: '菊荣一篇五章 一', author: '萧颖士', poem: '采采者菊，芬其荣斯。\n紫英黄萼，照灼丹墀。\n恺悌君子，佩服攸宜。\n王国是维，大君是毗。\n贻尔子孙，百禄萃之。' },
  { title: '菊荣一篇五章 二', author: '萧颖士', poem: '采采者菊，于邑之城。\n旧根新茎，布叶垂英。\n彼美淑人，应家之祯。\n有弦既鸣，我政则平。\n宜尔栋崇，必复其庆。' },
  { title: '菊荣一篇五章 三', author: '萧颖士', poem: '采采者菊，于邦之府。\n阴槐翳柳，迩楹近宇。\n彼劳者子，喧卑是处。\n慨其莫知，蕴结谁语。\n企彼高人，色斯遐举。' },
  { title: '菊荣一篇五章 四', author: '萧颖士', poem: '采采者菊，于宾之馆。\n既低其枝，又弱其干。\n有斐君子，是焉披玩。\n良辰旨酒，宴饮无算。\n怆其仳别，终然永叹。' },
  { title: '菊荣一篇五章 五', author: '萧颖士', poem: '岁方晏矣，霜露残促。\n谁其荣斯，有英者菊。\n岂微春华，懿此贞色。\n人之侮我，混于薪棘。\n诗人有言，好是正直。' },
  { title: '凉雨一章', author: '萧颖士', poem: '习习凉风，泠泠浮飙。\n君子乐胥，于其宾僚。\n有女斯夭，式歌且谣。\n欲言终宥，惟以招邀，于胥乐兮。' },
  { title: '有竹一篇七章', author: '萧颖士', poem: '有竹斯竿，于阁之前。\n君子秉心，惟其贞坚兮。\n有竿斯竹，于阁之侧。\n君子秉操，惟其正直兮。\n彼蔚者竹，萧其森矣。\n有开者合，宛其深矣。\n回檐幽砌，如翼如齿。\n冬之霄，霰雪斯瀌。\n我有金𬬻，熺其以歊。\n夏之日，炎景斯郁。\n我有珍簟，凄其以栗。\n彼纷者务，体其豫矣。\n有旨者酒，欢其且矣。\n友僚萃止，跗蕚载韡。\n彼美公之姓兮，那欤应积庆兮，期子惟去之柄兮。' },
  { title: '有竹一篇七章 一', author: '萧颖士', poem: '有竹斯竿，于阁之前。\n君子秉心，惟其贞坚兮。' },
  { title: '有竹一篇七章 二', author: '萧颖士', poem: '有竿斯竹，于阁之侧。\n君子秉操，惟其正直兮。' },
  { title: '有竹一篇七章 三', author: '萧颖士', poem: '彼蔚者竹，萧其森矣。\n有开者合，宛其深矣。\n回檐幽砌，如翼如齿。' },
  { title: '有竹一篇七章 四', author: '萧颖士', poem: '冬之霄，霰雪斯瀌。\n我有金𬬻，熺其以歊。' },
  { title: '有竹一篇七章 五', author: '萧颖士', poem: '夏之日，炎景斯郁。\n我有珍簟，凄其以栗。' },
  { title: '有竹一篇七章 六', author: '萧颖士', poem: '彼纷者务，体其豫矣。\n有旨者酒，欢其且矣。\n友僚萃止，跗蕚载韡。' },
  { title: '江有归舟三章 一', author: '萧颖士', poem: '江有归舟，亦乱其流。\n之子言旋，嘉名孔修。\n扬于王庭，允焯其休。' },
  { title: '江有归舟三章 二', author: '萧颖士', poem: '舟既归止，人亦荣止。\n兄矣弟矣，孝斯践矣。\n称觞燕喜，于岵于屺。' },
  { title: '江有归舟三章 三', author: '萧颖士', poem: '彼游惟帆，匪风不扬。\n有彬伊父，匪学不彰。\n予其怀而，勉尔无忘。' },
  { title: '过河滨和文学张志尹', author: '萧颖士', poem: '隆古日以远，举世丧其淳。\n慷慨怀黄虞，化理何由臻。\n步出城西门，裴回见河滨。\n当其侧陋时，河水清且潾。\n沧桑一以变，莽然翳荆榛。\n至化无苦窳，宇宙将陶甄。\n太息感悲泉，人往迹未湮。\n瑟瑟寒原暮，冷风吹衣巾。\n顾我谫劣质，希圣杳无因。\n且尽登临意，斗酒欢相亲。' },
  { title: '舟中遇陆棣兄西归数日得广陵二三子书知迟晚次沙垫西岸作', author: '萧颖士', poem: '林乌遥岸鸣，早知东方曙。\n波上风雨歇，舟人叫将去。\n苍苍前洲日，的的回沙鹭。\n水气清晓阴，滩声隐川雾。\n旧山劳魂想，忆人阻洄溯。\n信宿千里余，佳期曷由遇。\n前程入楚乡，弭棹问维扬。\n但见土音异，始知程路长。\n寥寥晚空静，漫漫风淮凉。\n云景信可美，风潮殊未央。\n故人江臯上，永日念容光。\n中路枉尺书，谓余琼树芳。\n深期结晤语，竟夕恨相望。\n冀愿崇朝霁，吾其一苇航。' },
  { title: '重阳日陪元鲁山德秀登北城瞩对新霁因以赠别', author: '萧颖士', poem: '山县遶古堞，悠悠快登望。\n雨余秋天高，目尽无隐状。\n绵连滍川回，杳渺鸦路深。\n彭泽兴不浅，临风动归心。\n赖兹琴堂暇，傲睨倾菊酒。\n人和岁已登，从政复何有。\n远山十里碧，一道衔长云。\n青霞半落日，混合疑晴曛。\n渐闻惊栖羽，坐叹清夜月。\n中欢怆有违，行子念明发。\n仅能泯宠辱，未免伤别离。\n江湖不可忘，风雨劳相思。\n明时当盛才，短伎安所设。\n何日谢百里，从君汉之澨。' },
  { title: '留别二三子得韵字', author: '萧颖士', poem: '二纪尚雌伏，徒然忝先进。\n英英尔众贤，名实郁双振。\n残春惜将别，清洛行不近。\n相与爱后时，无令孤逸韵。' },
  { title: '仰荅韦司业垂访五首 一', author: '萧颖士', poem: '呦呦食苹鹿，常饮清泠川。\n但悦丰草美，宁知牢馔鲜。\n主人有幽意，将以充林泉。\n罗网幸免伤，蒙君复羁牵。\n高堂列众宾，广座鸣清弦。\n俯仰转惊惕，裴回独忧煎。\n缅怀云岩路，欲往无由缘。\n物各有所好，违之伤自然。' },
  { title: '仰荅韦司业垂访五首 二', author: '萧颖士', poem: '神龟在南国，缅邈湘川阴。\n游止莲叶上，岁时嘉树林。\n毒虫且不近，斤斧何由寻。\n错落负奇文，荧煌耀丹金。\n江山万里余，淮海阻且深。\n独保贞素质，不为寒暑侵。\n一逢盛明代，应见通灵心。' },
  { title: '仰荅韦司业垂访五首 三', author: '萧颖士', poem: '晋代有儒臣，当年富词藻。\n立言寄青史，将以赞王道。\n辽落缅岁时，辛勤历江岛。\n且言风波倦，探涉岂为宝。\n不遇庾征西，云谁展怀抱。\n士贫乏知己，安得成所好。' },
  { title: '仰荅韦司业垂访五首 四', author: '萧颖士', poem: '彭阳昔游说，愿谒南郢都。\n王果尚未达，况从夷节谟。\n岂知晋叔向，无罪婴囚拘。\n临难俟解纷，独知[祁]大夫。\n举讐且不弃，何必论亲疎。\n夫子觉者也，其能遗我乎。' },
  { title: '仰荅韦司业垂访五首 五', author: '萧颖士', poem: '关西一公子，年貌独青春。\n被褐来上京，翳然声未振。\n中郎何为者，倒屣惊座宾。\n词赋岂不佳，盛名亦相因。\n为君奏此曲，此曲多苦辛。\n千载不可诬，孰言今无人。' },
  { title: '答邹象先', author: '萧颖士', poem: '桂枝常共擢，茅茨冀同荐。\n一命何阻修，载驰各川县。\n壮图悲岁月，明代耻贫贱。\n回首无津梁，祗令二毛变。' },
  { title: '蒙山作', author: '萧颖士', poem: '东蒙镇海沂，合沓余百里。\n清秋净氛霭，崖崿隐天起。\n于役劳往还，息徒暂攀跻。\n将穷绝迹处，偶得冥心理。\n云气杂虹霓，松声乱风水。\n微明绿林际，杳窱丹洞里。\n仙鸟时可闻，羽人邈难视。\n此焉多深邃，贤达昔所止。\n子尚捐俗纷，季随蹑遐轨。\n蕴真道弥旷，怀古情未已。\n白鹿凡几游，黄精复奚似。\n顾予尚牵缠，家业重书史。\n少学务从师，壮年贵趋仕。\n方驰桂林誉，未暇桃源美。\n岁暮期再寻，幽哉羡门子。' },
  { title: '早春过七岭寄题硖石裴丞厅壁', author: '萧颖士', poem: '出硖寄趣少，晚行偏忆君。\n依然向来处，官路谿边云。\n兹路岂不剧，能无俗累纷。\n槐阴永未合，泉声细犹闻。\n弥叹春罢酒，牵卑从此分。\n登高望城入，斜影半风薰。' },
  { title: '送张翚下第归江东', author: '萧颖士', poem: '俱飞仍失路，彩服迩清波。\n地积东南美，朝遗甲乙科。\n客愁千里别，春色五湖多。\n明日旧山去，其如相望何。' },
  { title: '越江秋曙', author: '萧颖士', poem: '扁舟东路远，晓月下江𣸣。\n潋滟信潮上，苍茫孤屿分。\n林声寒动叶，水气曙连云。\n暾日浪中出，榜歌天际闻。\n伯鸾常去国，安道惜离群。\n延首剡谿近，咏言怀数君。' },
  { title: '山庄月夜作', author: '萧颖士', poem: '献书嗟弃置，疲拙归田园。\n且事计然策，将符公冶言。\n桑榆清暮景，鸡犬应遥村。\n蚕罢里闾晏，麦秋田野喧。\n涧声连枕簟，峰势入阶轩。\n未奏东山妓，先倾北海尊。\n陇瓜香早熟，庭果落初繁。\n更惬野人意，农谈朝竟昏。' },
  { title: '古意', author: '崔曙', poem: '绿笋总成竹，红花亦成子。\n能当此时好，独自幽闺里。\n夜夜苦更长，愁来不如死。' },
  { title: '宿大通和尚塔敬赠如上人兼呈常孙二山人', author: '崔曙', poem: '支公已寂灭，影塔山上古。\n更有真僧来，道场救诸苦。\n一承微妙法，寓宿清净土。\n身心能自观，色相了无取。\n森森松映月，漠漠云近户。\n岭外飞电明，夜来前山雨。\n然灯见栖鸽，作礼闻信鼓。\n晓霁南轩开，秋华净天宇。\n愿言出世尘，谢尔申及甫。' },
  { title: '送薛据之宋州', author: '崔曙', poem: '无媒嗟失路，有道亦乘流。\n客处不堪别，异乡应共愁。\n我生早孤贱，沦落居此州。\n风土至今忆，山河皆昔游。\n一从文章事，两京春复秋。\n君去问相识，几人今白头。' },
  { title: '山下晚晴', author: '崔曙', poem: '寥寥远天净，谿路何空蒙。\n斜光照疎雨，秋气生白虹。\n云尽山色暝，萧条西北风。\n故林归宿处，一叶下梧桐。' },
  { title: '颍阳东溪怀古', author: '崔曙', poem: '灵溪氛雾歇，皎镜清心颜。\n空色不映水，秋声多在山。\n世人久疎旷，万物皆自闲。\n白鹭寒更浴，孤云晴未还。\n昔时让王者，此地闭玄关。\n无以蹑高步，凄凉岑壑间。' },
  { title: '早发交崖山还太室作', author: '崔曙', poem: '东林气微白，寒鸟急高翔。\n吾亦自兹去，北山归草堂。\n仲冬正三五，日月遥相望。\n萧萧过颍上，昽昽辨少阳。\n川冰生积雪，野火出枯桑。\n独往路难尽，穷阴人易伤。\n伤此无衣客，如何蒙雪霜。' },
  { title: '奉试明堂火珠', author: '崔曙', poem: '正位开重屋，凌空出火珠。\n夜来双月满，曙后一星孤。\n天净光难灭，云生望欲无。\n遥知太平代，国宝在名都。' },
  { title: '途中晓发', author: '崔曙', poem: '晓霁长风里，劳歌赴远期。\n云轻归海疾，月满下山迟。\n旅望因高尽，乡心遇物悲。\n故林遥不见，况在落花时。' },
  { title: '缑山庙', author: '崔曙', poem: '遗庙宿阴阴，孤峰映绿林。\n步随仙路远，意入道门深。\n涧水流年月，山云变古今。\n祗闻风竹里，犹有凤笙音。' },
  { title: '同诸公谒启母祠', author: '崔曙', poem: '閟宫凌紫微，芳草闭闲扉。\n帝子复何在，王孙游不归。\n春风鸣玉珮，暮雨拂灵衣。\n岂但湘江口，能令怀二妃。' },
  { title: '九日登望仙台呈刘明府容', author: '崔曙', poem: '汉文皇帝有高台，此日登临曙色开。\n三晋云山皆北向，二陵风雨自东来。\n关门令尹谁能识，河上仙翁去不回。\n且欲近寻彭泽宰，陶然共醉菊花杯。' },
  { title: '奉酬中书相公至日圆丘摄事合于中书后阁宿斋移止于集贤院叙怀见寄之作', author: '崔曙', poem: '典籍开书府，恩荣避鼎司。\n郊丘资有事，斋戒守无为。\n宿雾蒙琼树，余香覆玉墀。\n进经逢乙夜，展礼值明时。\n勋共山河列，名同竹帛垂。\n年年佐尧舜，相与致雍熙。' },
  { title: '登水门楼见亡友张贞期题望黄河诗因以感兴', author: '崔曙', poem: '吾友东南美，昔闻登此楼。\n人随川上逝，书向壁中留。\n严子好真隐，谢公耽远游。\n清风初作颂，暇日复销忧。\n时与文字古，迹将山水幽。\n已孤苍生望，空见黄河流。\n流落年将晚，悲凉物已秋。\n天高不可问，掩泣赴行舟。' },
  { title: '对雨送郑陵', author: '崔曙', poem: '别愁复经雨，别泪还如霰。\n寄心海上云，千里常相见。' },
  { title: '嵩山寻冯炼师不遇', author: '崔曙', poem: '青溪访道凌烟曙，王子仙成已飞去。\n更值空山雷雨时，云林薄暮归何处。' },
  { title: '赠唐祖二子', author: '王翰', poem: '鸿飞遵枉渚，鹿鸣思故群。\n物情尚劳爱，况乃予别君。\n别时花始发，别后兰再薰。\n瑶觞滋白露，宝瑟凝凉氛。\n裴徊北林月，怅望南山云。\n云月渺千里，音徽不可闻。' },
  { title: '飞燕篇', author: '王翰', poem: '孝成皇帝本娇奢，行幸平阳公主家。\n可怜女儿三五许，䒠茸惜是一园花。\n歌舞向来人不贵，一旦逢君感君意。\n君心见赏不见忘，姊妹双飞入紫房。\n紫房彩女不得见，专荣固宠昭阳殿。\n红妆宝镜珊瑚台，青琐银簧云母扇。\n日夕风传歌舞声，祗扰长信忧人情。\n长信忧人气欲绝，君王歌吹终不歇。\n朝弄琼箫下彩云，夜踏金梯上明月。\n明月薄蚀阳精昏，娇妬倾城惑至尊。\n已见白虹横紫极，复闻飞燕啄皇孙。\n皇孙不死燕啄折，女弟一朝如火绝。\n明明天子咸戒之，赫赫宗周襃姒灭。\n古来贤圣叹狐裘，一国荒淫万国羞。\n安得上方断马劒，斩取朱门公子头。' },
  { title: '饮马长城窟行', author: '王翰', poem: '长安少年无远图，一生惟羡执金吾。\n麒麟前殿拜天子，走马西击长城胡。\n胡沙猎猎吹人面，汉虏相逢不相见。\n遥闻鼙鼓动地来，传道单于夜犹战。\n此时顾恩宁顾身，为君一行摧万人。\n壮士挥戈回白日，单于溅血染朱轮。\n归来饮马长城窟，长城道傍多白骨。\n问之耆老何代人，云是秦王筑城卒。\n黄昏塞北无人烟，鬼哭啾啾声沸天。\n无罪见诛功不赏，孤魂流落此城边。\n当昔秦王按劒起，诸侯膝行不敢视。\n富国强兵二十年，筑怨兴徭九千里。\n秦王筑城何太愚，天实亡秦非北胡。\n一朝祸起萧墙内，渭水咸阳不复都。' },
  { title: '赋得明星玉女坛送廉察尉华阴', author: '王翰', poem: '洪河之南曰秦镇，发地削成五千仞。\n三峰离地皆倚天，唯独中峰特修峻。\n上有明星玉女祠，祠坛高眇路逶迤。\n三十六梯入河汉，樵人往往见蛾眉。\n蛾眉婵娟又宜笑，一见樵人下灵庙。\n仙车欲驾五云飞，香扇斜开九华照。\n含情迟伫惜韶年，愿侍君边复中旋。\n江妃玉佩留为念，嬴女银箫空自怜。\n仙俗途殊两情遽，感君无尽辞君去。\n遥见明星是妾家，风飘雪散不知处。\n故人家在西长安，卖药往来投此山。\n彩云荡漾不可见，绿萝蒙茸鸟绵蛮。\n欲求玉女长生法，日夜烧香应自还。' },
  { title: '春女行', author: '王翰', poem: '紫台穹跨连绿波，红轩铪匝垂纤罗。\n中有一人金作面，隔幌玲珑遥可见。\n忽闻黄鸟鸣且悲，镜边含笑着春衣。\n罗袖婵娟似无力，行拾落花比容色。\n落花一度无再春，人生作乐须及辰。\n君不见楚王台上红颜子，今日皆成狐兔尘。' },
  { title: '古娥眉怨', author: '王翰', poem: '君不见宜春苑中九华殿，飞阁连连直如发。\n白日全含朱鸟窓，流云半入苍龙阙。\n宫中彩女夜无事，学凤吹箫弄清越。\n珠帘北卷待凉风，绣户南开向明月。\n忽闻天子忆蛾眉，宝凤衔花揲两螭。\n传声走马开金屋，夹路鸣环上玉墀。\n长乐彤庭宴华寝，三千美人曳花锦。\n灯前含笑更罗衣，帐里承恩荐瑶枕。\n不意君心半路回，求仙别作望仙台。\n琳琅禁闼遥相忆，紫翠岩房昼不开。\n欲向人间种桃实，先从海底觅蓬莱。\n蓬来可求不可上，孤舟飘缈知何往。\n黄金作盘铜作茎，青天白露掌中擎。\n王母嫣然感君意，云车羽斾欲相迎。\n飞廉观前空怨慕，少君何事须相误。\n一朝埋没茂陵田，贱妾蛾眉不重顾。\n宫车晚出向南山，仙卫逶迤去不还。\n朝晡泣对麒麟树，树下苍苔日渐斑。\n人生百年夜将半，对酒长歌莫长叹。\n情知白日不可私，一死一生何足筭。' },
  { title: '子夜春歌', author: '王翰', poem: '春气满林香，春游不可忘。\n落花吹欲尽，垂柳折还长。\n桑女淮南曲，金鞍塞北装。\n行行小垂手，日暮渭川阳。' },
  { title: '奉和圣制同二相已下群官乐游园宴', author: '王翰', poem: '未极人心畅，如何帝道明。\n仍嫌酺宴促，复宠乐游行。\n陆海披珍藏，天河直斗城。\n四关青霭合，数处白云生。\n饪𫗧调元气，歌钟溢雅声。\n空惭尧舜日，至德杳难名。' },
  { title: '奉和圣制送张说上集贤院学士赐宴得筵字', author: '王翰', poem: '东堂起集贤，贵得从神仙。\n首命台阶老，将崇御府员。\n送人锵玉佩，中使拂琼筵。\n和乐薰风解，湛恩时雨连。\n长材成磊落，短翮强翩翾。\n徒仰蓬莱地，何阶不让缘。' },
  { title: '奉和圣制送张尚书巡边', author: '王翰', poem: '紫绶尚书印，朱𫐌丞相车。\n登朝身许国，出阃将辞家。\n不惮炎蒸苦，亲尝走集赊。\n选徒军有政，誓卒尔无哗。\n帝乐风初起，王城日半斜。\n宠行流圣作，寅饯照台华。\n骑历河南树，旌摇塞北沙。\n荣怀应尽服，严杀已先加。\n业峻灵祇保，功成道路嗟。\n宁如凿空使，远致石榴花。' },
  { title: '凉州词二首 一', author: '王翰', poem: '葡萄美酒夜光杯，欲饮琵琶马上催。\n醉卧沙场君莫笑，古来征战几人回。' },
  { title: '凉州词二首 二', author: '王翰', poem: '秦中花鸟已应阑，塞外风沙犹自寒。\n夜听胡笳折杨柳，教人意气忆长安。' },
  { title: '春日归思', author: '王翰', poem: '杨柳青青杏发花，年光误客转思家。\n不知湖上菱歌女，几个春舟在若耶。' },
  { title: '观蛮童为伎之作', author: '王翰', poem: '长裙锦带还留客，广额青蛾亦效嚬。\n共惜不成金谷妓，虚令看杀玉车人。' },
  { title: '古别离', author: '孟云卿', poem: '朝日上高台，离人怨秋草。\n但见万里天，不见万里道。\n君行本迢远，苦乐良难保。\n宿昔梦同衾，忧心常倾倒。\n含酸欲谁诉，展转伤怀抱。\n结发年已迟，征行去何早。\n寒暄有时谢，憔悴难再好。\n人皆算年寿，死者何曾老。\n少壮无见期，水深风浩浩。' },
  { title: '今别离', author: '孟云卿', poem: '结发生别离，相思复相保。\n如何日已久，五变庭中草。\n渺渺大海途，悠悠吴江岛。\n但恐不出门，出门无远道。\n远道行既难，家贫衣复单。\n严风吹积雪，晨起鼻何酸。\n人生各有志，岂不怀所安。\n分明天上日，生死愿同欢。' },
  { title: '悲哉行', author: '孟云卿', poem: '孤儿去慈亲，远客丧主人。\n莫吟苦辛曲，此曲谁忍闻。\n可闻不可说，去去无期别。\n行人念前程，不待参辰没。\n朝亦常苦饥，暮亦常苦饥。\n飘飘万余里，贫贱多是非。\n少年莫远游，远游多不归。' },
  { title: '行行且游猎篇', author: '孟云卿', poem: '少年多武力，勇气冠幽州。\n何以纵心赏，马啼春草头。\n迟迟平原上，狐兔奔林丘。\n猛虎忽前逝，俊鹰连下鞲。\n俯身逐南北，轻捷固难俦。\n所发无不中，失之如我讐。\n岂唯务驰骋，猗尔暴田畴。\n残杀非不痛，古来良有由。' },
  { title: '古挽歌', author: '孟云卿', poem: '草草闾巷喧，涂车俨成位。\n冥冥何所须，尽我生人意。\n北邙路非远，此别终天地。\n临穴频抚棺，至哀反无泪。\n尔形未衰老，尔息才童稚。\n骨肉安可离，皇天若容易。\n房帷即灵帐，庭宇为哀次。\n薤露歌若斯，人生尽如寄。' },
  { title: '放歌行', author: '孟云卿', poem: '吾观天地图，世界亦可小。\n落落大海中，飘浮数洲岛。\n贤愚与蚁虱，一种同草草。\n地脉日夜流，天衣有时扫。\n东山谒居士，了我生死道。\n目见难噬脐，心通可亲脑。\n轩皇竟磨灭，周孔亦衰老。\n永谢当时人，吾将宝非宝。' },
  { title: '伤怀赠故人', author: '孟云卿', poem: '稍稍晨鸟翔，淅淅草上霜。\n人生早罹苦，寿命恐不长。\n二十学已成，三十名不彰。\n岂无同门友，贵贱易中肠。\n驱马行万里，悠悠过帝乡。\n幸因弦歌末，得上君子堂。\n众乐互喧奏，独子备笙簧。\n坐中无知音，安得神扬扬。\n愿因高风起，上感白日光。' },
  { title: '邺城怀古', author: '孟云卿', poem: '朝发淇水南，将寻北燕路。\n魏家旧城阙，寥落无人住。\n伊昔天地屯，曹公独中据。\n群臣将北面，白日忽西暮。\n三台竟寂寞，万事良难固。\n雄图安在哉？衰草沾霜露。\n崔嵬长河北，尚见应刘墓。\n古树藏龙蛇，荒茅伏狐兔。\n永怀故池馆，数子连章句。\n逸兴驱山河，雄词变云雾。\n我行覩遗迹，精爽如可遇。\n斗酒将酹君，悲风白杨树。' },
  { title: '伤情', author: '孟云卿', poem: '为长心易忧，早孤意常伤。\n出门先踌躇，入户亦彷徨。\n此生一何苦，前事安可忘。\n兄弟先我没，孤幼盈我傍。\n旧居近东南，河水新为梁。\n松柏今在兹，安忍思故乡。\n四时与日月，万物各有常。\n秋风已一起，草木无不霜。\n行行当自勉，不忍再思量。' },
  { title: '伤时二首 一', author: '孟云卿', poem: '徘回宋郊上，不覩平生亲。\n独立正伤心，悲风来孟津。\n大方载群物，生死有常伦。\n虎豹不相食，哀哉人食人。\n岂伊逢世运，天道亮云云。' },
  { title: '伤时二首 二', author: '孟云卿', poem: '太空流素月，三五何明明。\n光耀侵白日，贤愚迷至精。\n四时更变化，天道有亏盈。\n常恐今夜没，须臾还复生。' },
  { title: '田园观雨兼晴后作', author: '孟云卿', poem: '贫贱少情欲，借荒种南陂。\n我非老农圃，安得良土宜。\n秋成不廉俭，岁余多馁饥。\n顾视仓廪间，有粮不成炊。\n晨登南园上，暮歇清蝉悲。\n早苗既芃芃，晚田尚离离。\n五行孰堪废，万物当及时。\n贤哉数夫子，开翅慎勿迟。' },
  { title: '汴河阻风', author: '孟云卿', poem: '清晨自梁宋，挂席之楚荆。\n出浦风渐恶，傍滩舟欲横。\n大河喷东注，群动皆窅冥。\n白雾鱼龙气，黑云牛马形。\n苍茫迷所适，危安惧暂宁。\n信此天地内，孰为身命轻。\n丈夫苟未达，所向须存诚。\n前路舍舟去，东南仍晓晴。' },
  { title: '行路难', author: '孟云卿', poem: '君不见高山万仞连苍旻，天长地久成埃尘。\n君不见长松百尺多劲节，狂风暴雨终摧折。\n古今何事无圣贤，吾爱伯阳真乃天。\n金堂玉阙朝群仙，拍手东海成桑田。\n海中之水慎勿枯，乌鸢啄蚌伤明珠。\n行路难，艰险莫踟蹰。' },
  { title: '途中寄友人', author: '孟云卿', poem: '昔时闻远路，谓是等闲行。\n及到求人地，始知为客情。\n事将公道背，尘遶马蹄生。\n傥使长如此，便堪休去程。' },
  { title: '寒食', author: '孟云卿', poem: '二月江南花满枝，他乡寒食远堪悲。\n贫居往往无烟火，不独明朝为子推。' },
  { title: '新安江上寄处士', author: '孟云卿', poem: '深潭与浅滩，万转出新安。\n人远禽鱼静，山空水木寒。\n啸起青苹末，吟瞩白云端。\n即事遂幽赏，何必挂儒冠。' },
  { title: '句', author: '孟云卿', poem: '群物归大化，六龙颓西荒。\n安知浮云外，日月不运行。' },
  { title: '闻笛', author: '张巡', poem: '岧嶤试一临，虏骑附城阴。\n不辨风尘色，安知天地心。\n营开边月近，战苦阵云深。\n旦夕更楼上，遥闻横笛音。' },
  { title: '守睢阳作', author: '张巡', poem: '接战春来苦，孤城日渐危。\n合围侔月晕，分守若鱼丽。\n屡厌黄尘起，时将白羽挥。\n裹疮犹出阵，饮血更登陴。\n忠信应难敌，坚贞谅不移。\n无人报天子，心计欲何施。' },
  { title: '题衡阳泗州寺', author: '张抃', poem: '一水悠悠百粤通，片帆无奈信秋风。\n几层峡浪寒舂月，尽日江天雨打篷。\n漂泊渐摇青草外，乡关谁念雪园东。\n未知今夜依何处，一点渔灯出苇丛。' },
  { title: '古意二首 一', author: '贺兰进明', poem: '秦庭初指鹿，群盗满山东。\n忤意皆诛死，所言谁肯忠。\n武关犹未启，兵入望夷宫。\n为祟非泾水，人君道自穷。' },
  { title: '古意二首 二', author: '贺兰进明', poem: '崇兰生涧底，香气满幽林。\n采采欲为赠，何人是同心。\n日暮徙盈把，裴回忧思深。\n慨然纫杂佩，重奏丘中琴。' },
  { title: '行路难五首 一', author: '贺兰进明', poem: '君不见岩下井，百尺不及泉。\n君不见山上苗，数寸凌云烟。\n人生赋命亦如此，何苦太息自忧煎。\n但愿亲友长含笑，相逢不乏杖头钱。\n寒夜邀欢须秉烛，岂得常思花柳年。' },
  { title: '行路难五首 二', author: '贺兰进明', poem: '君不见门前柳，荣耀暂时萧索久。\n君不见陌上花，狂风吹去落谁家。\n邻家思妇见之叹，蓬首不梳心历乱。\n盛年夫壻长别离，岁暮相逢色已换。' },
  { title: '行路难五首 三', author: '贺兰进明', poem: '君不见芳树枝，春花落尽蜂不窥。\n君不见梁上泥，秋风始高燕不栖。\n荡子从军事征战，[蛾]眉婵娟守空闺。\n独宿自然堪下泪，况复时闻乌夜啼。' },
  { title: '行路难五首 四', author: '贺兰进明', poem: '君不见云中月，暂盈还复缺。\n君不见林下风，声远意难穷。\n亲故平生或聚散，欢娱未尽尊酒空。\n叹息青青陵上柏，岁寒能有几人同。' },
  { title: '行路难五首 五', author: '贺兰进明', poem: '君不见东流水，一去无穷已。\n君不见西郊云，日夕空氛氲。\n群鴈裴回不能去，一鴈悲鸣复失群。\n人生结交在终始，莫以升沈中路分。' },
  { title: '夜渡江', author: '闾丘晓', poem: '舟人自相报，落日下芳潭。\n夜火连淮市，春风满客帆。\n水穷沧海畔，路尽小山南。\n且喜乡园近，言荣意未甘。' },
  { title: '奉和刘采访缙云南岭作', author: '庾光先', poem: '百越城池枕海圻，永嘉山水复相依。\n悬萝弱筿垂清浅，宿雨朝暾和翠微。\n鸟讶山经传不尽，花随月令数仍稀。\n幸陪谢客题诗句，谁与王孙此地归。' },
  { title: '思归寄东林澈上人', author: '韦丹', poem: '王事纷纷无暇日，浮生冉冉只如云。\n已为平子归休计，五老岩前必共闻。' },
  { title: '荅澈公', author: '韦丹', poem: '空山泉落松窗静，闲地草生春日迟。\n白发渐多身未退，依依常在永禅师。' },
  { title: '洛出书', author: '萧昕', poem: '海内昔凋瘵，天网斯浡潏。\n龟灵启圣图，龙马负书出。\n大哉明德盛，远矣彝伦秩。\n地敷作乂功，人免为鱼恤。\n既彰千国理，岂止百川溢。\n永赖至于今，畴庸未云毕。' },
  { title: '临风舒锦', author: '萧昕', poem: '丽锦疋云终，襜襜展向风。\n花开翻覆翠，色乱动摇红。\n缕散悠扬里，文回照灼中。\n低垂疑步障，吹起作晴虹。\n既与丘迟梦，深知卓氏功。\n还乡将制服，从此表亨通。' },
  { title: '东皇太一词', author: '李希仲', poem: '吉日初齐戒，灵巫穆上皇。\n焚香布瑶席，鸣珮奠椒浆。\n缓舞花飞满，清歌水去长。\n回波送神曲，云雨满潇湘。' },
  { title: '蓟北行二首 一', author: '李希仲', poem: '旄头有精芒，胡骑猎秋草。\n羽檄南渡河，边庭用兵早。\n汉家爱征战，宿将今已老。\n辛苦羽林儿，从戎榆关道。' },
  { title: '蓟北行二首 二', author: '李希仲', poem: '一身救边速，烽火通蓟门。\n前军飞鸟断，格鬬尘沙昏。\n寒日鼓声急，单于夜将奔。\n当须徇忠义，身死报国恩。' },
  { title: '送妻', author: '杨志坚', poem: '平生志业在琴诗，头上如今有二丝。\n渔父尚知谿谷暗，山妻不信出身迟。\n荆钗任意撩新鬓，明镜从他别画眉。\n今日便同行路客，相逢即是下山时。' },
  { title: '从张丞相游南纪城猎戏赠裴迪张参军', author: '孟浩然', poem: '从禽非吾乐，不好云梦田。\n岁暮登城望，偏令相思悬。\n公卿有几几，车骑何翩翩。\n世禄金张贵，官曹幕府贤。\n顺时行杀气，飞刃争割鲜。\n十里届宾馆，徵声匝妓筵。\n高标回落日，平楚散芳烟。\n何意狂歌客，从公亦在旃。' },
  { title: '登江中孤屿赠白云先生王迥', author: '孟浩然', poem: '悠悠清水江，水落沙屿出。\n回潭石下深，绿筿岸傍密。\n鲛人潜不见，渔父歌自逸。\n忆与君别时，泛舟如昨日。\n夕阳开返照，中坐兴非一。\n南望鹿门山，归来恨如失。' },
  { title: '晚春卧病寄张八', author: '孟浩然', poem: '南陌春将晚，北窗犹卧病。\n林园久不游，草木一何盛。\n狭迳花障迷，闲庭竹扫净。\n翠羽戏兰苕，赪鳞动荷柄。\n念我平生好，江乡远从政。\n云山阻梦思，衾枕劳歌咏。\n歌咏复何为，同心恨别离。\n世途皆自媚，流俗寡相知。\n贾谊才空逸，安仁鬓欲丝。\n遥情每东注，奔晷复西驰。\n常恐填沟壑，无由振羽仪。\n穷通若有命，欲向论中推。' },
  { title: '秋登兰山寄张五', author: '孟浩然', poem: '北山白云里，隐者自怡悦。\n相望试登高，心飞逐鸟灭。\n愁因薄暮起，兴是清秋发。\n时见归村人，沙行渡头歇。\n天边树若荠，江畔舟如月。\n何当载酒来，共醉重阳节。' },
  { title: '入峡寄弟', author: '孟浩然', poem: '吾昔与尔辈，读书常闭门。\n未尝冒湍险，岂顾垂堂言。\n自此历江湖，辛勤难具论。\n往来行旅弊，开凿禹功存。\n壁立千峰峻，潨流万壑奔。\n我来凡几宿，无夕不闻猿。\n浦上摇归恋，舟中失梦魂。\n泪沾明月峡，心断鹡鸰原。\n离阔星难聚，秋深露已繁。\n因君下南楚，书此示乡园。' },
  { title: '湖中旅泊寄阎九司户防', author: '孟浩然', poem: '桂水通百越，扁舟期晓发。\n荆云蔽三巴，夕望不见家。\n襄王梦行雨，才子谪长沙。\n长沙饶瘴疠，胡为苦留滞。\n久别思款颜，承欢怀接袂。\n接袂杳无由，徒增旅泊愁。\n清猿不可听，沿月下湘流。' },
  { title: '大堤行寄万七', author: '孟浩然', poem: '大堤行乐处，车马相驰突。\n岁岁春草生，踏青二三月。\n王孙挟珠弹，游女矜罗袜。\n携手今莫同，江花为谁发。' },
  { title: '仲夏归汉南园寄京邑耆旧', author: '孟浩然', poem: '尝读高士传，最嘉陶征君。\n日耽田园趣，自谓羲皇人。\n予复何为者，栖栖徒问津。\n中年废丘壑，上国旅风尘。\n忠欲事明主，孝思侍老亲。\n归来当炎夏，耕稼不及春。\n扇枕北窗下，采芝南涧滨。\n因声谢同列，吾慕颍阳真。' },
  { title: '题云门山寄越府包户曹徐起居', author: '孟浩然', poem: '我行适诸越，梦寐怀所欢。\n久负独往愿，今来恣游盘。\n台岭践磴石，耶溪溯林湍。\n舍舟入香界，登阁憩旃檀。\n晴山秦望近，春水镜湖宽。\n远怀伫应接，卑位徒劳安。\n白云日夕滞，沧海去来观。\n故国眇天末，良朋在朝端。' },
  { title: '宿扬子津寄润州长山刘隐士', author: '孟浩然', poem: '所思在建业，欲往大江深。\n日夕望京口，烟波愁我心。\n心驰茅山洞，目极枫树林。\n不见少微星，星霜劳夜吟。' },
  { title: '书怀贻京邑同好', author: '孟浩然', poem: '维先自邹鲁，家世重儒风。\n诗体袭遗训，趋庭沾末躬。\n昼夜常自强，词翰颇亦工。\n三十既成立，嗟吁命不通。\n慈亲向羸老，喜惧在深衷。\n甘脆朝不足，箪瓢夕屡空。\n执鞭慕夫子，捧檄怀毛公。\n感激遂弹冠，安能守固穷。\n当途诉知己，投剌匪求蒙。\n秦楚邈离异，飜飞何日同。' },
  { title: '还山贻湛法师', author: '孟浩然', poem: '幼闻无生理，常欲观此身。\n心迹罕兼遂，[崎岖]多在尘。\n晚途归旧壑，偶与支公邻。\n导以微妙法，结为清净因。\n烦恼业顿舍，山林情转殷。\n朝来问疑义，夕话得清真。\n墨妙称古绝，词华惊世人。\n禅房闭虚静，花药连冬春。\n平石籍琴砚，落泉洒衣巾。\n欲知冥灭意，朝夕海鸥驯。' },
  { title: '夏日南亭怀辛大', author: '孟浩然', poem: '山光忽西落，池月渐东上。\n散发乘夕凉，开轩卧闲敞。\n荷风送香气，竹露滴清响。\n欲取鸣琴弹，恨无知音赏。\n感此怀故人，中宵劳梦想。' },
  { title: '秋宵月下有怀', author: '孟浩然', poem: '秋空明月悬，光彩露沾湿。\n惊鹊栖未定，飞萤卷帘入。\n庭槐寒影疎，邻杵夜声急。\n佳期旷何许，望望空伫立。' },
  { title: '将适天台留别临安李主簿', author: '孟浩然', poem: '枳棘君尚栖，匏瓜吾岂系。\n念离当夏首，漂泊指炎裔。\n江海非堕游，田园失归计。\n定山既早发，渔浦亦宵济。\n泛泛随波澜，行行任舻枻。\n故林日已远，群木坐成翳。\n羽人在丹丘，吾亦从此逝。' },
  { title: '送丁大凤进士赴举呈张九龄', author: '孟浩然', poem: '吾观鹪鹩赋，君负王佐才。\n惜无金张援，十上空归来。\n弃置乡园老，翻飞羽翼摧。\n故人今在位，歧路莫迟回。' },
  { title: '送吴悦游韶阳', author: '孟浩然', poem: '五色怜凤雏，南飞适鹧鸪。\n楚人不相识，何处求椅梧。\n去去日千里，茫茫天一隅。\n安能与斥鷃，决起但枪榆。' },
  { title: '适越留别谯县张主簿申屠少府', author: '孟浩然', poem: '朝乘汴河流，夕次谯县界。\n幸值西风吹，得与故人会。\n君学梅福隐，余从伯鸾迈。\n别后能相思，浮云在吴会。' },
  { title: '送陈七赴西军', author: '孟浩然', poem: '吾观非常者，碌碌在目前。\n君负鸿鹄志，蹉跎书劒年。\n一闻边烽动，万里忽争先。\n余亦赴京国，何当献凯还。' },
  { title: '送从弟邕下第后寻会稽', author: '孟浩然', poem: '疾风吹征帆，倏尔向空没。\n千里在俄顷，三江坐超忽。\n向来共欢娱，日夕成楚越。\n落羽更分飞，谁能不惊骨。' },
  { title: '送辛大之鄂渚不及', author: '孟浩然', poem: '送君不相见，日暮独愁绪。\n江上空裴回，天边迷处所。\n郡邑经樊邓，山河入嵩汝。\n蒲轮去渐遥，石径徒延伫。' },
  { title: '江上别流人', author: '孟浩然', poem: '以我越乡客，逢君谪居者。\n分飞黄鹤楼，流落苍梧野。\n驿使乘云去，征帆沿溜下。\n不知从此分，还袂何时把。' },
  { title: '宴包二融宅', author: '孟浩然', poem: '闲居枕清洛，左右接大野。\n门庭无杂宾，车辙多长者。\n是时方盛夏，风物自潇洒。\n五日休沐归，相携竹林下。\n开襟成欢趣，对酒不能罢。\n烟暝栖鸟迷，余将归白社。' },
  { title: '与王昌龄宴王道士房', author: '孟浩然', poem: '归来卧青山，常梦游清都。\n漆园有傲吏，惠好在招呼。\n书幌神仙箓，画屏山海图。\n酌霞复对此，宛似入蓬壶。' },
  { title: '襄阳公宅饮', author: '孟浩然', poem: '窈窕夕阳佳，䒠茸春色好。\n欲觅淹留处，无过狭斜道。\n绮席卷龙须，香杯浮码碯。\n北林积修树，南池生别岛。\n手拨金翠花，心迷玉红草。\n谈笑光六义，发论明三倒。\n座非陈子惊，门还魏公扫。\n荣辱应无间，欢娱当共保。' },
  { title: '寻香山湛上人', author: '孟浩然', poem: '朝游访名山，山远在空翠。\n氛氲亘百里，日入行始至。\n杖策寻故人，解鞭暂停骑。\n石门殊豁险，篁迳转森邃。\n法侣欣相逢，清谈晓不寐。\n平生慕真隐，累日探奇异。\n野老朝入田，山僧暮归寺。\n松泉多逸响，苔壁饶古意。\n谷口闻钟声，林端识香气。\n愿言投此山，身世两相弃。' },
  { title: '云门寺西六七里闻符公兰若最幽与薛八同往', author: '孟浩然', poem: '谓予独迷方，逢子亦在野。\n结交指松柏，问法寻兰若。\n小溪劣容舟，怪石屡惊马。\n所居最幽绝，所住皆静者。\n云簇兴座隅，天空落阶下。\n上人亦何闻，尘念都已舍。\n四禅合真如，一切是虚假。\n愿承甘露润，喜得惠风洒。\n依止托山门，谁能效丘也。' },
  { title: '宿天台桐柏观', author: '孟浩然', poem: '海行信风帆，夕宿逗云岛。\n缅寻沧洲趣，近爱赤城好。\n扪萝亦践苔，辍櫂恣探讨。\n息阴憩桐柏，采秀弄芝草。\n鹤唳清露垂，鸡鸣信潮早。\n愿言解缨绂，从此去烦恼。\n高步凌四明，玄踪得三老。\n纷吾远游意，学彼长生道。\n日夕望三山，云涛空浩浩。' },
  { title: '岘潭作', author: '孟浩然', poem: '石潭傍隈隩，沙岸晓夤缘。\n试垂竹竿钓，果得槎头鳊。\n美人骋金错，纤手脍红鲜。\n因谢陆内史，莼羹何足传。' },
  { title: '题终南翠微寺空上人房', author: '孟浩然', poem: '翠微终南里，雨后宜返照。\n闭关久沈冥，杖策一登眺。\n遂造幽人室，始知静者妙。\n儒道虽异门，云林颇同调。\n两心相喜得，毕景共谈笑。\n暝还高窗眠，时见远山烧。\n缅怀赤城标，更忆临海峤。\n风泉有清音，何必苏门啸。' },
  { title: '初春汉中漾舟', author: '孟浩然', poem: '羊公岘山下，神女汉臯曲。\n雪罢冰复开，春潭千丈绿。\n轻舟恣来往，探玩无厌足。\n波影摇妓钗，沙光逐人目。\n倾杯鱼鸟醉，联句鸎花续。\n良会难再逢，日入须秉烛。' },
  { title: '宿业师山房期丁大不至', author: '孟浩然', poem: '夕阳度西岭，群壑倏已暝。\n松月生夜凉，风泉满清听。\n樵人归欲尽，烟鸟栖初定。\n之子期宿来，孤琴候萝迳。' },
  { title: '耶溪泛舟', author: '孟浩然', poem: '落景馀清辉，轻桡弄溪渚。\n澄明爱水物，临泛何容与。\n白首垂钓翁，新妆浣纱女。\n相看似相识，脉脉不得语。' },
  { title: '彭蠡湖中望庐山', author: '孟浩然', poem: '太虚生月晕，舟子知天风。\n挂席候明发，眇漫平湖中。\n中流见匡阜，势压九江雄。\n黤黕容霁色，峥嵘当晓空。\n香炉初上日，瀑布喷成虹。\n久欲追尚子，况兹怀远公。\n我来限于役，未暇息微躬。\n淮海途将半，星霜岁欲穷。\n寄言岩栖者，毕趣当来同。' },
  { title: '登鹿门山', author: '孟浩然', poem: '清晓因兴来，乘流越江岘。\n沙禽近方识，浦树遥莫辨。\n渐至鹿门山，山明翠微浅。\n岩潭多屈曲，舟檝屡回转。\n昔闻庞德公，采药遂不返。\n金涧饵芝术，石床卧苔藓。\n纷吾感耆旧，结揽事攀践。\n隐迹今尚存，高风邈已远。\n白云何时去，丹桂空偃蹇。\n探讨意未穷，回艇夕阳晚。' },
  { title: '游明禅师西山兰若', author: '孟浩然', poem: '西山多奇状，秀出倚前楹。\n停午收彩翠，夕阳照分明。\n吾师住其下，禅坐证无生。\n结庐就嵌窟，剪苕通往行。\n谈空对樵叟，授法与山精。\n日暮方辞去，田园归冶城。' },
  { title: '登望楚山最高顶', author: '孟浩然', poem: '山水观形胜，襄阳美会稽。\n最高唯望楚，曾未一攀跻。\n石壁疑削成，众山比全低。\n晴明试登陟，目极无端倪。\n云梦掌中小，武陵花处迷。\n暝还归骑下，萝月映深谿。' },
  { title: '疾愈过龙泉寺精舍呈易业二公', author: '孟浩然', poem: '停午闻山钟，起行散愁疾。\n寻林采芝去，转谷松翠密。\n傍见精舍开，长廊饭僧毕。\n石渠流雪水，金子耀霜橘。\n竹房思旧游，过憩终永日。\n入洞窥石髓，傍崖采蜂蜜。\n日暮辞远公，虎溪相送出。' },
  { title: '万山潭作', author: '孟浩然', poem: '垂钓坐盘石，水清心亦闲。\n鱼行潭树下，猿挂岛藤间。\n游女昔解佩，传闻于此山。\n求之不可得，沿月櫂歌还。' },
  { title: '与黄侍御北津泛舟', author: '孟浩然', poem: '津无蛟龙患，日夕常安流。\n本欲避骢马，何如同鹢舟。\n岂伊今日幸，曾是昔年游。\n莫奏琴中鹤，且随波上鸥。\n隄缘九里郭，山面百城楼。\n自顾躬耕者，才非管乐俦。\n闻君荐草泽，从此泛沧洲。' },
  { title: '洗然弟竹亭', author: '孟浩然', poem: '吾与二三子，平生结交深。\n俱怀鸿鹄志，昔有鹡鸰心。\n逸气假毫翰，清风在竹林。\n达是酒中趣，琴上偶然音。' },
  { title: '山中逢道士云公', author: '孟浩然', poem: '春余草木繁，耕种满田园。\n酌酒聊自劝，农夫安与言。\n忽闻荆山子，时出桃花源。\n采樵过北谷，卖药来西村。\n村烟日云夕，榛路有归客。\n杖策前相逢，依然是畴昔。\n邂逅欢觏止，殷勤叙离隔。\n谓予搏扶桑，轻举振六翮。\n奈何偶昌运，独见遗草泽。\n既笑接舆狂，仍怜孔丘厄。\n物情趋势利，吾道贵闲寂。\n偃息西山下，门庭罕人迹。\n何时还清溪，从尔炼丹液。' },
  { title: '越中逢天台太乙子', author: '孟浩然', poem: '仙穴逢羽人，停舻向前拜。\n问余涉风水，何处远行迈。\n登陆寻天台，顺流下吴会。\n兹山夙所尚，安得问灵怪。\n上逼青天高，俯临沧海大。\n鸡鸣见日出，常觌仙人斾。\n往来赤城中，逍遥白云外。\n莓苔异人间，瀑布当空界。\n福庭长自然，华顶旧称最。\n永此从之游，何当济所届。' },
  { title: '家园卧疾毕太祝曜见寻', author: '孟浩然', poem: '伏枕旧游旷，笙簧劳梦思。\n平生重交结，迨此令人疑。\n冰室无煖气，炎云空赫曦。\n隙驹不暂驻，日听凉蝉悲。\n壮图哀未立，斑白恨吾衰。\n夫子自南楚，缅怀嵩汝期。\n顾予衡茅下，兼致禀物资。\n脱分趋庭礼，殷勤伐木诗。\n脱君车前鞅，设我园中葵。\n斗酒须寒兴，明朝难重持。' },
  { title: '白云先生王迥见访', author: '孟浩然', poem: '闲归日无事，云卧昼不起。\n有客款柴扉，自云巢居子。\n居闲好芝术，采药来城市。\n家在鹿门山，常游涧泽水。\n手持白羽扇，脚步青芒履。\n闻道鹤书征，临流还洗耳。' },
  { title: '田园作', author: '孟浩然', poem: '弊庐隔尘喧，惟先养恬素。\n卜邻近三径，植果盈千树。\n粤余任推迁，三十犹未遇。\n书劒时将晚，丘园日已暮。\n晨兴自多怀，昼坐常寡悟。\n冲天羡鸿鹄，争食羞鸡骛。\n望断金马门，劳歌采樵路。\n乡曲无知己，朝端乏亲故。\n谁能为扬雄，一荐甘泉赋。' },
  { title: '采樵作', author: '孟浩然', poem: '采樵入深山，山深树重叠。\n桥崩卧槎拥，路险垂藤接。\n日落伴将稀，山风拂萝衣。\n长歌负轻策，平野望烟归。' },
  { title: '自浔阳泛舟经明海', author: '孟浩然', poem: '大江分九流，淼淼成水乡。\n舟子乘利涉，往来至浔阳。\n因之泛五湖，流浪经三湘。\n观涛壮枚发，吊屈痛沈湘。\n魏阙心恒在，金门诏不忘。\n遥怜上林雁，冰泮也回翔。' },
  { title: '早发渔浦潭', author: '孟浩然', poem: '东旭早光芒，渚禽已惊聒。\n卧闻渔浦口，桡声暗相拨。\n日出气象分，始知江湖阔。\n美人常晏起，照影弄流沫。\n饮水畏惊猿，祭鱼时见獭。\n舟行自无闷，况值晴景豁。' },
  { title: '经七里滩', author: '孟浩然', poem: '予奉垂堂诫，千金非所轻。\n为多山水乐，频作泛舟行。\n五岳追向子，三湘吊屈平。\n湖经洞庭阔，江入新安清。\n复闻严陵濑，乃在兹湍路。\n叠障数百里，沿洄非一趣。\n彩翠相氛氲，别流乱奔注。\n钓矶平可坐，苔磴滑难步。\n猨饮石下潭，鸟还日边树。\n观奇恨来晚，倚櫂惜将暮。\n挥手弄潺湲，从兹洗尘虑。' },
  { title: '岁暮海上作', author: '孟浩然', poem: '仲尼既云殁，余亦浮于海。\n昏见斗柄回，方知岁星改。\n虚舟任所适，垂钓非有待。\n为问乘槎人，沧洲复谁在。' },
  { title: '南归阻雪', author: '孟浩然', poem: '我行滞宛许，日夕望京豫。\n旷野莽茫茫，乡山在何处。\n孤烟村际起，归雁天边去。\n积雪复平臯，饥鹰捉寒兔。\n少年弄文墨，属意在章句。\n十上耻还家，裴回守归路。' },
  { title: '听郑五愔弹琴', author: '孟浩然', poem: '阮籍推名饮，清风满竹林。\n半酣下衫袖，拂拭龙唇琴。\n一杯弹一曲，不觉夕阳沈。\n予意在山水，闻之谐夙心。' },
  { title: '同张明府清镜叹', author: '孟浩然', poem: '妾有盘龙镜，清光常昼发。\n自从生尘埃，有若雾中月。\n愁来试取照，坐叹生白发。\n寄语边塞人，如何久离别。' },
  { title: '庭橘', author: '孟浩然', poem: '明发览群物，万木何阴森。\n凝霜渐渐水，庭橘似悬金。\n女伴争攀摘，摘窥碍叶深。\n竝生怜共蒂，相示感同心。\n骨刺红罗被，香黏翠羽簪。\n擎来玉盘里，全胜在幽林。' },
  { title: '早梅', author: '孟浩然', poem: '园中有早梅，年例犯寒开。\n少妇曾攀折，将归插镜台。\n犹言看不足，更欲剪刀裁。' },
  { title: '清明即事', author: '孟浩然', poem: '帝里重清明，人心自愁思。\n车声上路合，柳色东城翠。\n花落草齐生，鸎飞蝶双戏。\n空堂坐相忆，酌茗聊代醉。' },
  { title: '和卢明府送郑十三还京兼寄之什', author: '孟浩然', poem: '昔时风景登临地，今日衣冠送别筵。\n醉坐自倾彭泽酒，思归长望白云天。\n洞庭一叶惊秋早，濩落空嗟滞江岛。\n寄语朝廷当世人，何时重见长安道。' },
  { title: '高阳池送朱二', author: '孟浩然', poem: '当昔襄阳雄盛时，山公常醉习家池。\n池边钓女日相随，妆成照影竞来窥。\n澄波澹澹芙蓉发，绿岸毵毵杨柳垂。\n一朝物变人亦非，四面荒凉人径稀。\n意气豪华何处在，空余草露湿罗衣。\n此地朝来饯行者，翻向此中牧征马。\n征马分飞日渐斜，见此空为人所嗟。\n殷勤为访桃源路，予亦归来松子家。' },
  { title: '鹦鹉洲送王九之江左', author: '孟浩然', poem: '昔登江上黄鹤楼，遥爱江中鹦鹉洲。\n洲势逶迤遶碧流，鸳鸯㶉𫛶满滩头。\n滩头日落沙碛长，金沙熠熠动飙光。\n舟人牵锦缆，浣女结罗裳。\n月明全见芦花白，风起遥闻杜若香，君行采采莫相忘。' },
  { title: '送王七尉松滋得阳台云', author: '孟浩然', poem: '君不见巫山神女作行云，霏红沓翠晓氛氲。\n婵娟流入楚王梦，倏忽还随零雨分。\n空中飞去复飞来，朝朝暮暮下阳台。\n愁君此去为仙尉，便逐行云去不回。' },
  { title: '夜归鹿门山歌', author: '孟浩然', poem: '山寺钟鸣昼已昏，渔梁渡头争渡喧。\n人随沙路向江村，余亦乘舟归鹿门。\n鹿门月照开烟树，忽到庞公栖隐处。\n岩扉松径长寂寥，惟有幽人夜来去。' },
  { title: '长乐宫', author: '孟浩然', poem: '秦城旧来称窈窕，汉家更衣应不少。\n红粉邀君在何处，青楼苦夜长难晓。\n长乐宫中钟暗来，可怜歌舞惯相催。\n欢娱此事今寂寞，惟有年年陵树哀。' },
  { title: '示孟郊', author: '孟浩然', poem: '蔓草蔽极野，兰芝结孤根。\n众音何其繁，伯牙独不喧。\n当时高深意，举世无能分。\n钟期一见知，山水千秋闻。\n尔其保静节，薄俗徒云云。' },
  { title: '和张丞相春朝对雪', author: '孟浩然', poem: '迎气当春至，承恩喜雪来。\n润从河汉下，花逼艳阳开。\n不覩丰年瑞，焉知燮理才。\n撒盐如可拟，愿糁和羹梅。' },
  { title: '和张明府登鹿门作', author: '孟浩然', poem: '忽示登高作，能宽旅寓情。\n弦歌既多暇，山水思微清。\n草得风光动，虹因雨气成。\n谬承巴里和，非敢应同声。' },
  { title: '和张二自穰县还途中遇雪', author: '孟浩然', poem: '风吹沙海雪，渐作柳园春。\n宛转随香骑，轻盈伴玉人。\n歌疑郢中客，态比洛川神。\n今日南归楚，双飞似入秦。' },
  { title: '和贾主簿弁九日登岘山', author: '孟浩然', poem: '楚万重阳日，群公赏䜩来。\n共乘休沐暇，同醉菊花杯。\n逸思高秋发，欢情落景催。\n国人咸寡和，遥媿洛阳才。' },
  { title: '望洞庭湖赠张丞相', author: '孟浩然', poem: '八月湖水平，涵虚混太清。\n气蒸云梦泽，波撼岳阳城。\n欲济无舟楫，端居耻圣明。\n坐观垂钓者，空有羡鱼情。' },
  { title: '赠道士参寥', author: '孟浩然', poem: '蜀琴久不弄，玉匣细尘生。\n丝脆弦将断，金徽色尚荣。\n知音徒自惜，聋俗本相轻。\n不遇钟期听，谁知鸾凤声。' },
  { title: '京还赠张维', author: '孟浩然', poem: '拂衣何处去，高枕南山南。\n欲徇五斗禄，其如七不堪。\n早朝非晚起，束带异抽簪。\n因向智者说，游鱼思旧潭。' },
  { title: '题李十四庄兼赠綦毋校书', author: '孟浩然', poem: '闻君息阴地，东郭柳林间。\n左右瀍涧水，门庭缑氏山。\n抱琴来取醉，垂钓坐乘闲。\n归客莫相待，寻源殊未还。' },
  { title: '九日龙沙作寄刘大眘虚', author: '孟浩然', poem: '龙沙豫章北，九日挂帆过。\n风俗因时见，湖山发兴多。\n客中谁送酒，櫂里自成歌。\n歌竟乘流去，滔滔任夕波。' },
  { title: '寄赵正字', author: '孟浩然', poem: '正字芸香阁，幽人竹素园。\n经过宛如昨，归卧寂无喧。\n高鸟能择木，羚羊漫触藩。\n物情今已见，从此愿忘言。' },
  { title: '洞庭湖寄阎九', author: '孟浩然', poem: '洞庭秋正阔，余欲泛归船。\n莫辨荆吴地，唯余水共天。\n渺弥江树没，合沓海潮连。\n迟尔为舟楫，相将济巨川。' },
  { title: '秦中感秋寄远上人', author: '孟浩然', poem: '一丘常欲卧，三径苦无资。\n北土非吾愿，东林怀我师。\n黄金然桂尽，壮志逐年衰。\n日夕凉风至，闻蝉但益悲。' },
  { title: '宿永嘉江寄山阴崔少府国辅', author: '孟浩然', poem: '我行穷水国，君使入京华。\n相去日千里，孤帆天一涯。\n卧闻海潮至，起视江月斜。' },
  { title: '上巳洛中寄王九迥', author: '孟浩然', poem: '卜洛成周地，浮杯上巳筵。\n鬬鸡寒食下，走马射堂前。\n垂柳金堤合，平沙翠幕连。\n不知王逸少，何处会群贤。' },
  { title: '闻裴侍御朏自襄州司户除豫州司户因以投寄', author: '孟浩然', poem: '故人荆府掾，尚有柏台威。\n移职自樊衍，芳声闻帝畿。\n昔余卧林巷，载酒过柴扉。\n松菊无时赏，乡园欲懒归。' },
  { title: '江上寄山阴崔少府国辅', author: '孟浩然', poem: '春堤杨柳发，忆与故人期。\n草木本无意，荣枯自有时。\n山阴定远近，江上日相思。\n不及兰亭会，空吟祓禊诗。' },
  { title: '夜泊庐江闻故人在东寺以诗寄之', author: '孟浩然', poem: '江路经庐阜，松门入虎谿。\n闻君寻寂乐，清夜宿招提。\n石镜山精怯，禅枝怖鸽栖。\n一灯如悟道，为照客心迷。' },
  { title: '宿桐庐江寄广陵旧游', author: '孟浩然', poem: '山暝闻猿愁，沧江急夜流。\n风鸣两岸叶，月照一孤舟。\n建德非吾土，维扬忆旧游。\n还将两行泪，遥寄海西头。' },
  { title: '南还舟中寄袁太祝', author: '孟浩然', poem: '沿溯非便习，风波厌苦辛。\n忽闻迁谷鸟，来报五陵春。\n岭北回征帆，巴东问故人。\n桃源何处是，游子正迷津。' },
  { title: '东陂遇雨率尔贻谢南池', author: '孟浩然', poem: '田家春事起，丁壮就东陂。\n殷殷雷声作，森森雨足垂。\n海虹晴始见，河柳润初移。\n予意在耕凿，因君问土宜。' },
  { title: '行至汝坟寄卢征君', author: '孟浩然', poem: '行乏憩予驾，依然见汝坟。\n洛川方罢雪，嵩嶂有残云。\n曳曳半空里，明明五色分。\n聊题一时兴，因寄卢征君。' },
  { title: '寄天台道士', author: '孟浩然', poem: '海上求仙客，三山望几时。\n焚香宿华顶，裛露采灵芝。\n屡蹑莓苔滑，将寻汗漫期。\n倘因松子去，长与世人辞。' },
  { title: '唐城馆中早发寄杨使君', author: '孟浩然', poem: '犯霜驱晓驾，数里见唐城。\n旅馆归心逼，荒村客思盈。\n访人留后信，策蹇赴前程。\n欲识离魂断，长空听雁声。' },
  { title: '涧南即事贻皎上人', author: '孟浩然', poem: '弊庐在郭外，素产惟田园。\n左右林野旷，不闻朝市喧。\n钓竿垂北涧，樵唱入南轩。\n书取幽栖事，将寻静者论。' },
  { title: '重酬李少府见赠', author: '孟浩然', poem: '养疾衡檐下，由来浩气真。\n五行将禁火，十步任寻春。\n致敬惟桑梓，邀欢即主人。\n回看后雕色，青翠有松筠。' },
  { title: '九日怀襄阳', author: '孟浩然', poem: '去国似如昨，倏然经杪秋。\n岘山不可见，风景令人愁。\n谁采篱下菊，应闲池上楼。\n宜城多美酒，归与葛彊游。' },
  { title: '初出关旅亭夜坐怀王大校书', author: '孟浩然', poem: '向夕槐烟起，葱茏池馆曛。\n客中无偶坐，关外惜离群。\n烛至萤光灭，荷枯雨滴闻。\n永怀芸阁友，寂寞滞[扬]云。' },
  { title: '人日登南阳驿门亭子怀汉川诸友', author: '孟浩然', poem: '朝来登陟处，不似艳阳时。\n异县殊风物，羁怀多所思。\n剪花惊岁早，看柳讶春迟。\n未有南飞雁，裁书欲寄谁。' },
  { title: '早寒江上有怀', author: '孟浩然', poem: '木落雁南度，北风江上寒。\n我家襄水上，遥隔楚云端。\n乡泪客中尽，孤帆天际看。\n迷津欲有问，平海夕漫漫。' },
  { title: '闲园怀苏子', author: '孟浩然', poem: '林园虽少事，幽独自多违。\n向夕开帘坐，庭阴落景微。\n鸟过烟树宿，萤傍水轩飞。\n感念同怀子，京华去不归。' },
  { title: '同卢明府饯张郎中除义王府司马海园作', author: '孟浩然', poem: '上国山河列，贤王邸第开。\n故人分职去，潘令宠行来。\n冠盖趋梁苑，江湘失楚材。\n豫愁轩骑动，宾客散池台。' },
  { title: '送张子容进士赴举', author: '孟浩然', poem: '夕曛山照灭，送客出柴门。\n惆怅野中别，殷勤岐路言。\n茂林予偃息，乔木尔飞翻。\n无使谷风诮，须令友道存。' },
  { title: '送张参明经举兼向泾州觐省', author: '孟浩然', poem: '十五彩衣年，承欢慈母前。\n孝廉因岁贡，怀橘向秦川。\n四座推文举，中郎许仲宣。\n泛舟江上别，谁不仰神仙。' },
  { title: '送张祥之房陵', author: '孟浩然', poem: '我家南渡头，惯习野人舟。\n日夕弄清浅，林湍逆上流。\n山河据形胜，天地生豪酋。\n君意在利往，知音期自投。' },
  { title: '送吴宣从事', author: '孟浩然', poem: '才有幕中士，宁无塞上勋。\n汉兵将灭虏，王粲始从军。\n旌斾边庭去，山川地脉分。\n平生一匕首，感激赠夫君。' },
  { title: '送桓子之郢城礼', author: '孟浩然', poem: '闻君驰彩骑，躞蹀指南荆。\n为结潘杨好，言过鄢郢城。\n摽梅诗有赠，羔雁礼将行。\n今夜神仙女，应来感梦情。' },
  { title: '留别王侍御维', author: '孟浩然', poem: '寂寂竟何待，朝朝空自归。\n欲寻芳草去，惜与故人违。\n当路谁相假，知音世所稀。\n秪应守索寞，还掩故园扉。' },
  { title: '早春润州送从弟还乡', author: '孟浩然', poem: '兄弟游吴国，庭闱恋楚关。\n已多新岁感，更饯白眉还。\n归泛西江水，离筵北固山。\n乡园欲有赠，梅柳着先攀。' },
  { title: '岘山饯房琯崔宗之', author: '孟浩然', poem: '贵贱平生隔，轩车是日来。\n青阳一觏止，云路豁然开。\n祖道衣冠列，分亭驿骑催。\n方期九日聚，还待二星回。' },
  { title: '送谢录事之越', author: '孟浩然', poem: '清旦江天迥，凉风西北吹。\n白云向吴会，征帆亦相随。\n想到耶溪日，应探禹穴奇。\n仙书倘相示，予在此山陲。' },
  { title: '洛中送奚三还扬州', author: '孟浩然', poem: '水国无边际，舟行共使风。\n羡君从此去，朝夕见乡中。\n予亦离家久，南归恨不同。\n音书若有问，江上会相逢。' },
  { title: '送告八从军', author: '孟浩然', poem: '男儿一片气，何必五车书。\n好勇方过我，多才便起予。\n运筹将入幕，养拙就闲居。\n正待功名遂，从君继两疎。' },
  { title: '送元公之鄂渚寻观主张骖鸾', author: '孟浩然', poem: '桃花春水涨，之子忽乘流。\n岘首辞蛟浦，江中问鹤楼。\n赠君青竹杖，送尔白苹洲。\n应是神仙子，相期汗漫游。' },
  { title: '送王五昆季省觐', author: '孟浩然', poem: '公子恋庭闱，劳歌涉海涯。\n水乘舟檝去，亲望老莱归。\n斜日催乌鸟，清江照彩衣。\n平生急难意，遥仰鹡鸰飞。' },
  { title: '送崔遏', author: '孟浩然', poem: '片玉来夸楚，治中作主人。\n江山增润色，词赋动阳春。\n别馆当虚敞，离情任吐伸。\n因声两京旧，谁念卧漳滨。' },
  { title: '送卢少府使入秦', author: '孟浩然', poem: '楚关望秦国，相去千里余。\n州县勤王事，山河转使车。\n祖筵江上列，离恨别前书。\n愿及芳年赏，娇莺二月初。' },
  { title: '送袁十岭南寻弟', author: '孟浩然', poem: '早闻牛渚咏，今见鹡鸰心。\n羽翼嗟零落，悲鸣别故林。\n苍梧白云远，烟水洞庭深。\n万里独飞去，南风迟尔音。' },
  { title: '永嘉别张子容', author: '孟浩然', poem: '旧国余归楚，新年子北征。\n挂帆愁海路，分手恋朋情。\n日夕故园意，汀洲春草生。' },
  { title: '东京留别诸公', author: '孟浩然', poem: '吾道昧所适，驱车还向东。\n主人开旧馆，留客醉新丰。\n树绕温泉绿，尘遮晚日红。\n拂衣从此去，高步蹑华嵩。' },
  { title: '送袁太祝尉豫章', author: '孟浩然', poem: '何幸遇休明，观光来上京。\n相逢武陵客，独送豫章行。\n随牒牵黄绶，离群会墨卿。\n江南佳丽地，山水旧难名。' },
  { title: '都下送辛大之鄂', author: '孟浩然', poem: '南国辛居士，言归旧竹林。\n未逢调鼎用，徒有济川心。\n予亦忘机者，田园在汉阴。\n因君故乡去，遥寄式微吟。' },
  { title: '送席大', author: '孟浩然', poem: '惜尔怀其宝，迷邦倦客游。\n江山历全楚，河洛越成周。\n道路疲千里，乡园老一丘。\n知君命不偶，同病亦同忧。' },
  { title: '送贾升主簿之荆府', author: '孟浩然', poem: '奉使推能者，勤王不暂闲。\n观风随按察，乘骑度荆关。\n送别登何处，开筵旧岘山。\n征轩明日远，空望郢门间。' },
  { title: '送王大校书', author: '孟浩然', poem: '导漾自嶓冢，东流为汉川。\n维桑君有意，解缆我开筵。\n云雨从兹别，林端意渺然。\n尺书能不恡，时望鲤鱼传。' },
  { title: '游江西留别富阳裴刘二少府', author: '孟浩然', poem: '西上游江西，临流恨解携。\n千山叠成嶂，万水泻为溪。\n石浅流难溯，藤长险易跻。\n谁怜问津者，岁晏此中迷。' },
  { title: '广陵别薛八', author: '孟浩然', poem: '士有不得志，栖栖吴楚间。\n广陵相遇罢，彭蠡泛舟还。\n樯出江中树，波连海上山。\n风帆明日远，何处更追攀。' },
  { title: '送洗然弟进士举', author: '孟浩然', poem: '献策金门去，承欢彩服违。\n以吾一日长，念尔聚星稀。\n昏定须温席，寒多未授衣。\n桂枝如已擢，早逐雁南飞。' },
  { title: '崔明府宅夜观妓', author: '孟浩然', poem: '白日既云暮，朱颜亦已酡。\n画堂初点烛，金幌半垂罗。\n长袖平阳曲，新声子夜歌。\n从来惯留客，兹夕为谁多。' },
  { title: '同卢明府早秋宴张郎中海亭', author: '孟浩然', poem: '侧听弦歌宰，文书游夏徒。\n故园欣赏竹，为邑幸来苏。\n华省曾联事，仙舟复与俱。\n欲知临泛久，荷露渐成珠。' },
  { title: '卢明府早秋宴张郎中海园即事得秋字', author: '孟浩然', poem: '邑有弦歌宰，翔鸾狎野鸥。\n眷言华省旧，暂拂海池游。\n郁岛藏深竹，前溪对舞楼。\n更闻书即事，云物是清秋。' },
  { title: '宴荣二山池', author: '孟浩然', poem: '甲第开金穴，荣期乐自多。\n枥嘶支遁马，池养右军鹅。\n竹引携琴入，花邀载酒过。\n山公来取醉，时唱接䍠歌。' },
  { title: '夏日与崔二十一同集卫明府宅', author: '孟浩然', poem: '言避一时暑，池亭五月开。\n喜逢金马客，同饮玉人杯。\n舞鹤乘轩至，游鱼拥钓来。\n座中殊未起，箫管莫相催。' },
  { title: '清明日宴梅道士房', author: '孟浩然', poem: '林卧愁春尽，开轩览物华。\n忽逢青鸟使，邀入赤松家。\n丹灶初开火，仙桃正落花。\n童颜若可驻，何惜醉流霞。' },
  { title: '寒夜张明府宅宴', author: '孟浩然', poem: '瑞雪初盈尺，寒宵始半更。\n列筵邀酒伴，刻烛限诗成。\n香炭金炉煖，娇弦玉指清。\n醉来方欲卧，不觉晓鸡鸣。' },
  { title: '宴张别驾新斋', author: '孟浩然', poem: '世业传珪组，江城佐股肱。\n高斋征学问，虚薄滥先登。\n讲论陪诸子，文章得旧朋。\n士元多赏激，衰病恨无能。' },
  { title: '与诸子登岘山', author: '孟浩然', poem: '人事有代谢，往来成古今。\n江山留胜迹，我辈复登临。\n水落鱼梁浅，天寒梦泽深。\n羊公碑字在，读罢泪沾襟。' },
  { title: '与杭州薛司户登樟亭楼作', author: '孟浩然', poem: '水楼一登眺，半出青林高。\n帟幕英僚敞，芳筵下客叨。\n山藏伯禹穴，城压伍胥涛。\n今日观溟涨，垂纶学钓鼇。' },
  { title: '寻天台山', author: '孟浩然', poem: '吾友太乙子，餐霞卧赤城。\n欲寻华顶去，不惮恶谿名。\n歇马凭云宿，扬帆截海行。\n高高翠微里，遥见石梁横。' },
  { title: '同曹三御史行泛湖归越', author: '孟浩然', poem: '秋入诗人意，巴歌和者稀。\n泛湖同逸旅，吟会是思归。\n白简徒推荐，沧洲已拂衣。\n杳冥云外去，谁不羡鸿飞。' },
  { title: '晚泊浔阳望庐山', author: '孟浩然', poem: '挂席几千里，名山都未逢。\n泊舟浔阳郭，始见香炉峰。\n尝读远公传，永怀尘外踪。\n东林精舍近，日暮但闻钟。' },
  { title: '陪张丞相登嵩阳楼', author: '孟浩然', poem: '独步人何在，嵩阳有故楼。\n岁寒问耆旧，行县拥诸候。\n林莽北弥望，沮漳东会流。\n客中遇知己，无复越乡忧。' },
  { title: '武陵泛舟', author: '孟浩然', poem: '武陵川路狭，前櫂入花林。\n莫测幽源里，仙家信几深。\n水回青嶂合，云度绿溪阴。\n坐听闲猿啸，弥清尘外心。' },
  { title: '与颜钱塘登障楼望潮作', author: '孟浩然', poem: '百里闻雷震，鸣弦暂辍弹。\n府中连骑出，江上待潮观。\n照日秋云廻，浮天渤澥宽。\n惊涛来似雪，一坐凛生寒。' },
  { title: '姚开府山池', author: '孟浩然', poem: '主人新邸第，相国旧池台。\n馆是招贤辟，楼因教舞开。\n轩车人已散，箫管凤初来。\n今日龙门下，谁知文举才。' },
  { title: '夏日浮舟过陈大水亭', author: '孟浩然', poem: '水亭凉气多，闲櫂晚来过。\n涧影见松竹，潭香闻芰荷。\n野童扶醉舞，山鸟助酣歌。\n幽赏未云徧，烟光奈夕何。' },
  { title: '与白明府游江', author: '孟浩然', poem: '故人来自远，邑宰复初临。\n执手恨为别，同舟无异心。\n沿洄洲渚趣，演漾弦歌音。\n谁识躬耕者，年年梁甫吟。' },
  { title: '游凤林寺西岭', author: '孟浩然', poem: '共喜年华好，来游水石间。\n烟容开远树，春色满幽山。\n壶酒朋情洽，琴歌野兴闲。\n莫愁归路暝，招月伴人还。' },
  { title: '秋日陪李侍御渡松滋江', author: '孟浩然', poem: '南纪西江阔，皇华御史雄。\n截流宁假楫，挂席自生风。\n僚宷争攀鹢，鱼龙亦避骢。\n坐听白[雪]唱，翻入櫂歌中。' },
  { title: '陪独孤使君同与萧员外证登万山亭', author: '孟浩然', poem: '万山青嶂曲，千骑使君游。\n神女鸣环佩，仙郎接献酬。\n遍观云梦野，自爱江城楼。\n何必东南守，空传沈隐侯。' },
  { title: '秋登张明府海亭', author: '孟浩然', poem: '海亭秋日望，委曲见江山。\n染翰聊题壁，倾壶一解颜。\n歌逢彭泽令，归赏故园间。\n予亦将琴史，栖迟共取闲。' },
  { title: '临涣裴明府席遇张十一房六', author: '孟浩然', poem: '河县柳林边，河桥晚泊船。\n文叨才子会，官喜故人连。\n笑语同今夕，轻肥异往年。\n晨风理归櫂，吴楚各依然。' },
  { title: '梅道士水亭', author: '孟浩然', poem: '傲吏非凡吏，名流即道流。\n隐居不可见，高论莫能酬。\n水接仙源近，山藏鬼谷幽。\n再来迷处所，花下问渔舟。' },
  { title: '游景空寺兰若', author: '孟浩然', poem: '龙象经行处，山腰度石关。\n屡迷青嶂合，时爱绿萝闲。\n宴息花林下，高谈竹屿间。\n寥寥隔尘事，疑是入鸡山。' },
  { title: '陪李侍御访聪上人禅居', author: '孟浩然', poem: '欣逢柏台友，共谒聪公禅。\n石室无人到，绳床见虎眠。\n阴崖常抱雪，枯涧为生泉。\n出处虽云异，同欢在法筵。' },
  { title: '游精思观回王白云在后', author: '孟浩然', poem: '出谷未停午，到家日已曛。\n回瞻下山路，但见牛羊群。\n樵子暗相失，草虫寒不闻。\n衡门犹未掩，伫立望夫君。' },
  { title: '夏日辨玉法师茅斋', author: '孟浩然', poem: '夏日茅斋里，无风坐亦凉。\n竹林深笋穊，藤架引梢长。\n燕觅巢窠处，蜂来造蜜房。\n物华皆可玩，花橤四时芳。' },
  { title: '与张折冲游耆阇寺', author: '孟浩然', poem: '释子弥天秀，将军武库才。\n横行塞北尽，独步汉南来。\n贝叶传金口，山楼作赋开。\n因君振嘉藻，江楚气雄哉。' },
  { title: '游精思题观主山房', author: '孟浩然', poem: '误入桃源里，初怜竹迳深。\n方知仙子宅，未有世人寻。\n舞鹤过闲砌，飞猿啸密林。\n渐通玄妙理，深得坐忘心。' },
  { title: '宿立公房', author: '孟浩然', poem: '支遁初求道，深公笑买山。\n何如石岩趣，自入户庭间。\n苔润春泉满，萝轩夜月闲。\n能令许玄度，吟卧不知还。' },
  { title: '寻陈逸人故居', author: '孟浩然', poem: '人事一朝尽，荒芜三径休。\n始闻漳浦卧，奄作岱宗游。\n池水犹含墨，风云已落秋。\n今宵泉壑里，何处觅藏舟。' },
  { title: '寻梅道士', author: '孟浩然', poem: '彭泽先生柳，山阴道士鹅。\n我来从所好，停策汉阴多。\n重以观鱼乐，因之鼓枻歌。\n崔徐迹未朽，千载揖清波。' },
  { title: '陪姚使君题惠上人房', author: '孟浩然', poem: '带雪梅初煖，含烟柳尚青。\n来窥童子偈，得听法王经。\n会理知无我，观空厌有形。\n迷心应觉悟，客思未遑宁。' },
  { title: '晚春题远上人南亭', author: '孟浩然', poem: '给园支遁隐，虚寂养身和。\n春晚群木秀，间关黄鸟歌。\n林栖居士竹，池养右军鹅。\n炎月北窗下，清风期再过。' },
  { title: '题大禹寺义公禅房', author: '孟浩然', poem: '义公习禅处，结构依空林。\n户外一峰秀，阶前群壑深。\n夕阳连雨足，空翠落庭阴。\n看取莲花净，应知不染心。' },
  { title: '寻白鹤岩张子容隐居', author: '孟浩然', poem: '白鹤青岩半，幽人有隐居。\n阶庭空水石，林壑罢樵渔。\n岁月青松老，风霜苦竹疎。\n覩兹怀旧业，回策返吾庐。' },
  { title: '题融公兰若', author: '孟浩然', poem: '精舍买金开，流泉遶砌回。\n芰荷薰讲席，松柏映香台。\n法雨晴飞去，天花昼下来。\n谈玄殊未已，归骑夕阳催。' },
  { title: '过景空寺故融公兰若', author: '孟浩然', poem: '池上青莲宇，林间白马泉。\n故人成异物，过客独潸然。\n既礼新松塔，还寻旧石筵。\n平生竹如意，犹挂草堂前。' },
  { title: '题张野人园庐', author: '孟浩然', poem: '与君园庐竝，微尚颇亦同。\n耕钓方自逸，壶觞趣不空。\n门无俗士驾，人有上皇风。\n何处先贤传，惟称庞德公。' },
  { title: '李少府与杨九再来', author: '孟浩然', poem: '弱岁早登龙，今来喜再逢。\n如何春月柳，犹忆岁寒松。\n烟火临寒食，笙歌达曙钟。\n喧喧鬬鸡道，行乐羡朋从。' },
  { title: '寻张五回夜园作', author: '孟浩然', poem: '闻就庞公隐，移居近洞湖。\n兴来林是竹，归卧谷名愚。\n挂席樵风便，开轩琴月孤。\n岁寒何用赏，霜落故园芜。' },
  { title: '裴司士员司户见寻', author: '孟浩然', poem: '府僚能枉驾，家酝复新开。\n落日池上酌，清风松下来。\n厨人具鸡黍，稚子摘杨梅。\n谁道山公醉，犹能骑马回。' },
  { title: '春中喜王九相寻', author: '孟浩然', poem: '二月湖水清，家家春鸟鸣。\n林花扫更落，径草踏还生。\n酒伴来相命，开尊共解酲。\n当杯已入手，歌妓莫停声。' },
  { title: '李氏园林卧疾', author: '孟浩然', poem: '我爱陶家趣，园林无俗情。\n春雷百卉坼，寒食四邻清。\n伏枕嗟公干，归山羡子平。\n年年白社客，空滞洛阳城。' },
  { title: '过故人庄', author: '孟浩然', poem: '故人具鸡黍，邀我至田家。\n绿树村边合，青山郭外斜。\n开筵面场圃，把酒话桑麻。\n待到重阳日，还来就菊花。' },
  { title: '张七及辛大见寻南亭醉作', author: '孟浩然', poem: '山公能饮酒，居士好弹筝。\n世外交初得，林中契已幷。\n纳凉风飒至，逃暑日将倾。\n便就南亭里，余尊惜解酲。' },
  { title: '岁暮归南山', author: '孟浩然', poem: '北阙休上书，南山归敝庐。\n不才明主弃，多病故人疎。\n白发催年老，青阳逼岁除。\n永怀愁不寐，松月夜窗虚。' },
  { title: '南山下与老圃期种瓜', author: '孟浩然', poem: '樵牧南山近，林闾北郭赊。\n先人留素业，老圃作邻家。\n不种千株橘，惟资五色瓜。\n邵平能就我，开径剪蓬麻。' },
  { title: '溯江至武昌', author: '孟浩然', poem: '家本洞湖上，岁时归思催。\n客心徒欲速，江路苦邅回。\n残冻因风解，新正度腊开。\n行看武昌柳，髣髴映楼台。' },
  { title: '舟中晓望', author: '孟浩然', poem: '挂席东南望，青山水国遥。\n舳舻争利涉，来往接风潮。\n问我今何去，天台访石桥。\n坐看霞色晓，疑是赤城标。' },
  { title: '自洛之越', author: '孟浩然', poem: '皇皇三十载，书劒两无成。\n山水寻吴越，风尘厌洛京。\n扁舟泛湖海，长揖谢公卿。\n且乐杯中物，谁论世上名。' },
  { title: '途中遇晴', author: '孟浩然', poem: '已失巴陵雨，犹逢蜀坂泥。\n天开斜景遍，山出晚云低。\n余湿犹沾草，残流尚入溪。\n今宵有明月，乡思远凄凄。' },
  { title: '归至郢中', author: '孟浩然', poem: '远游经海峤，返櫂归山阿。\n日夕见乔木，乡关在伐柯。\n愁随江路尽，喜入郢门多。\n左右看桑土，依然即匪他。' },
  { title: '夕次蔡阳馆', author: '孟浩然', poem: '日暮马行疾，城荒人住稀。\n听歌知近楚，投馆忽如归。\n鲁堰田畴广，章陵气色微。\n明朝拜嘉庆，须着老莱衣。' },
  { title: '他乡七夕', author: '孟浩然', poem: '他乡逢七夕，旅馆益羇愁。\n不见穿针妇，空怀故国楼。\n绪风初减热，新月始临秋。\n谁忍窥河汉，迢迢问斗牛。' },
  { title: '夜泊牛渚趁薛八船不及', author: '孟浩然', poem: '星罗牛渚夕，风退鹢舟迟。\n浦溆尝同宿，烟波忽间之。\n榜歌空里失，船火望中疑。\n明发泛潮海，茫茫何处期。' },
  { title: '晓入南山', author: '孟浩然', poem: '瘴气晓氛氲，南山复水云。\n鲲飞今始见，鸟堕旧来闻。\n地接长沙近，江从汨渚分。\n贾生曾吊屈，予亦痛斯文。' },
  { title: '夜渡湘水', author: '孟浩然', poem: '客舟贪利涉，暗里渡湘川。\n露气闻芳杜，歌声识采莲。\n榜人投岸火，渔子宿潭烟。\n行侣时相问，浔阳何处边。' },
  { title: '赴京途中遇雪', author: '孟浩然', poem: '迢递秦京道，苍茫藏暮天。\n穷阴连晦朔，积雪满山川。\n落雁迷沙渚，饥乌集野田。\n客愁空伫立，不见有人烟。' },
  { title: '途次望乡', author: '孟浩然', poem: '客行愁落日，乡思重相催。\n况在他山外，天寒夕鸟来。\n雪深迷郢路，云暗失阳台。\n可叹凄惶子，高歌谁为媒。' },
  { title: '永嘉上浦馆逢张八子容', author: '孟浩然', poem: '逆旅相逢处，江村日暮时。\n众山遥对酒，孤屿共题诗。\n廨宇邻蛟室，人烟接岛夷。\n乡园万余里，失路一相悲。' },
  { title: '宿武阳即事', author: '孟浩然', poem: '川暗夕阳尽，孤舟泊岸初。\n岭猿相呌啸，潭嶂似空虚。\n就枕灭明烛，扣舷闻夜渔。\n鸡鸣问何处，人物是秦余。' },
  { title: '渡扬子江', author: '孟浩然', poem: '桂檝中流望，京江两畔明。\n林开扬子驿，山出润州城。\n海尽边阴静，江寒朔吹生。\n更闻枫叶下，淅沥度秋声。' },
  { title: '田家元日', author: '孟浩然', poem: '昨夜斗回北，今朝岁起东。\n我年已强仕，无禄尚忧农。\n桑野就耕父，荷锄随牧童。\n田家占气候，共说此年丰。' },
  { title: '九日得新字', author: '孟浩然', poem: '初九未成旬，重阳即此晨。\n登高闻古事，载酒访幽人。\n落帽恣欢饮，授衣同试新。\n茱萸正可佩，折取寄情亲。' },
  { title: '除夜乐城逢张少府', author: '孟浩然', poem: '云海泛瓯闽，风潮泊岛滨。\n何知岁除夜，得见故乡亲。\n余是乘槎客，君为失路人。\n平生复能几，一别十余春。' },
  { title: '岁除夜会乐城张少府宅', author: '孟浩然', poem: '畴昔通家好，相知无间然。\n续明催画烛，守岁接长筵。\n旧曲梅花唱，新正柏酒传。\n客行随处乐，不见度年年。' },
  { title: '寒夜', author: '孟浩然', poem: '闺夕绮窗闭，佳人罢缝衣。\n理琴开宝匣，就枕卧重帏。\n夜久灯花落，薰笼香气微。\n锦衾重自煖，遮莫晓霜飞。' },
  { title: '赋得盈盈楼上女', author: '孟浩然', poem: '夫壻久离别，青楼空望归。\n妆成卷帘坐，愁思嬾缝衣。\n燕子家家入，杨花处处飞。\n空床难独守，谁为报金徽。' },
  { title: '春意', author: '孟浩然', poem: '佳人能画眉，妆罢出帘帷。\n照水空自爱，折花将遗谁。\n春情多艳逸，春意倍相思。\n愁心极杨柳，一种乱如丝。' },
  { title: '闺情', author: '孟浩然', poem: '一别隔炎凉，君衣忘短长。\n裁缝无处等，以意忖情量。\n畏瘦疑伤窄，防寒更厚装。\n半啼封裹了，知欲寄谁将。' },
  { title: '美人分香', author: '孟浩然', poem: '艳色本倾城，分香更有情。\n髻鬟垂欲解，眉黛拂能轻。\n舞学平阳态，歌翻子夜声。\n春风狭斜道，含笑待逢迎。' },
  { title: '伤岘山云表观主', author: '孟浩然', poem: '少小学书劒，秦吴多岁年。\n归来一登眺，陵谷尚依然。\n岂意餐霞客，溘随朝露先。\n因之问闾里，把臂几人全。' },
  { title: '题梧州陈司马山斋', author: '孟浩然', poem: '南国无霜霰，连年对物华。\n青林暗换叶，红橤亦开花。\n春去无山鸟，秋来见海槎。\n流芳虽可悦，会自泣长沙。' },
  { title: '岁除夜有怀', author: '孟浩然', poem: '迢递三巴路，羁危万里身。\n乱山残雪夜，孤灯异乡人。\n渐与骨肉远，转于奴仆亲。\n那堪正飘泊，来日岁华新。' },
  { title: '登安阳城楼', author: '孟浩然', poem: '县城南面汉江流，江涨开成南雍州。\n才子乘春来骋望，群公暇日坐销忧。\n楼台晚映青山郭，罗绮晴骄绿水洲。\n向夕波摇明月动，更疑神女弄珠游。' },
  { title: '登万岁楼', author: '孟浩然', poem: '万岁楼头望故乡，独令乡思更茫茫。\n天寒雁度堪垂泪，日落猿啼欲断肠。\n曲引古堤临冻浦，斜分远岸近枯杨。\n今朝偶见同袍友，却喜家书寄八行。' },
  { title: '除夜有怀', author: '孟浩然', poem: '五更钟漏欲相催，四气推迁往复回。\n帐里残灯才去熖，炉中香气尽成灰。\n渐看春逼芙蓉枕，顿觉寒销竹叶杯。\n守岁家家应未卧，相思那得梦魂来。' },
  { title: '春情', author: '孟浩然', poem: '青楼晓日珠帘映，红粉春妆宝镜催。\n已厌交欢怜枕席，相将游戏绕池台。\n坐时衣带萦纤草，行即裙裾扫落梅。\n更道明朝不当作，相期共鬬管弦来。' },
  { title: '长安早春', author: '孟浩然', poem: '关戍惟东井，城池起北辰。\n咸歌太平日，共乐建寅春。\n雪尽青山树，冰开黑水滨。\n草迎金埒马，花伴玉楼人。\n鸿渐看无数，莺歌听欲频。\n何当遂荣擢，归及柳条新。' },
  { title: '荆门上张丞相', author: '孟浩然', poem: '共理分荆国，招贤媿不材。\n召南风更阐，丞相阁还开。\n觏止欣眉睫，沈沦拔草莱。\n坐登徐孺榻，频接李膺杯。\n始慰蝉鸣柳，俄看雪间梅。\n四时年籥尽，千里客程催。\n日下瞻归翼，沙边厌曝鳃。\n伫闻宣室召，星象列三台。' },
  { title: '陪张丞相登荆城楼因寄蓟州张使君及浪泊戍主刘家', author: '孟浩然', poem: '蓟门天北畔，铜柱日南端。\n出守声弥远，投荒法未宽。\n侧身聊倚望，携手莫同欢。\n白璧无瑕玷，青松有岁寒。\n府中丞相阁，江上使君滩。\n兴尽回舟去，方知行路难。' },
  { title: '陪张丞相祠紫盖山途经玉泉寺', author: '孟浩然', poem: '望秩宣王命，斋心待漏行。\n青衿列胄子，从事有参卿。\n五马寻归路，双林指化城。\n闻钟度门近，照胆玉泉清。\n皂盖依松憩，缁徒拥锡迎。\n天宫上兜率，沙界豁迷明。\n欲就终焉志，恭闻智者名。\n人随逝水没，波逐覆舟倾。\n想像若在眼，周流空复情。\n谢公还欲卧，谁与济苍生。' },
  { title: '陪张丞相自松滋江东泊渚宫', author: '孟浩然', poem: '放溜下松滋，登舟命檝师。\n讵忘经济日，不惮沍寒时。\n洗帻岂独古，濯缨良在兹。\n政成人自理，机息鸟无疑。\n云物凝孤屿，江山辨四维。\n晚来风稍急，冬至日行迟。\n腊响惊云梦，渔歌激楚辞。\n渚宫何处是，川暝欲安之。' },
  { title: '和张判官登万山亭因赠洪府都督韩公', author: '孟浩然', poem: '韩公是襄士，日赏城西岑。\n结搆意不浅，岩潭趣转深。\n皇华一动咏，荆国几谣吟。\n旧径兰勿剪，新堤柳欲阴。\n砌傍余怪石，沙上有闲禽。\n自牧豫章郡，空瞻枫树林。\n因声寄流水，善听在知音。\n耆旧眇不接，崔徐无处寻。\n物情多贵远，贤俊岂无今。\n迟尔长江暮，澄清一洗心。' },
  { title: '和宋太史北楼新亭', author: '孟浩然', poem: '返耕意未遂，日夕登城隅。\n谁道山林近，坐为符竹拘。\n丽谯非改作，轩槛是新图。\n远水自嶓冢，长云吞具区。\n愿随江燕贺，羞逐府僚趋。\n欲识狂歌者，丘园一竖儒。' },
  { title: '赠萧少府', author: '孟浩然', poem: '上德如流水，安仁道若山。\n闻君秉高节，而得奉清颜。\n鸿渐升仪羽，牛刀列下班。\n处腴能不润，居剧体常闲。\n去诈人无谄，除邪吏息奸。\n欲知清与洁，明月照澄湾。' },
  { title: '秦中苦雨思归赠袁左丞贺侍郎', author: '孟浩然', poem: '苦学三十载，闭门江汉阴。\n用贤遭圣日，羇旅属秋霖。\n岂直昏垫苦，亦为权势沈。\n二毛催白发，百镒罄黄金。\n泪忆岘山堕，愁怀湘水深。\n谢公积愤懑，庄舃空谣吟。\n跃马非吾事，狎鸥宜我心。\n寄言当路者，去矣北山岑。' },
  { title: '同张明府碧溪赠答', author: '孟浩然', poem: '别业闻新制，同声和者多。\n还看碧溪答，不羡绿珠歌。\n自有阳台女，朝朝拾翠过。\n绮筵铺锦绣，妆牖闭藤萝。\n秩满休闲日，春余景气和。\n仙凫能作伴，罗袜共凌波。\n曲岛寻花药，回潭折芰荷。\n更怜斜日照，红粉艳青娥。' },
  { title: '久滞越中贻谢南池会稽贺少府', author: '孟浩然', poem: '陈平无产业，尼父倦东西。\n负郭昔云翳，问津今亦迷。\n未能忘魏阙，空此滞秦稽。\n两见夏云起，再闻春鸟啼。\n怀仙梅福市，访旧若耶溪。\n圣主贤为宝，君何隐遯栖。' },
  { title: '送韩使君除洪州都曹', author: '孟浩然', poem: '述职抚荆衡，分符袭宠荣。\n往来看拥传，前后赖专城。\n勿翦棠犹在，波澄水更清。\n重推江汉理，旋改豫章行。\n召父多遗爱，羊公有令名。\n衣冠列祖道，耆旧拥前旌。\n岘首晨风送，江陵夜火迎。\n无才慙孺子，千里媿同声。' },
  { title: '送莫甥兼诸昆弟从韩司马入西军', author: '孟浩然', poem: '念尔习诗礼，未曾违户庭。\n平生早偏露，万里更飘零。\n坐弃三牲养，行观八阵形。\n饰装辞故里，谋策赴边庭。\n壮志吞鸿鹄，遥心伴鹡鸰。\n所从文且武，不战自应宁。' },
  { title: '岘山送萧员外之荆州', author: '孟浩然', poem: '岘山江岸曲，郢水郭门前。\n自古登临处，非今独黯然。\n亭楼明落照，井邑秀通川。\n涧竹生幽兴，林风入管弦。\n再飞鹏激水，一举鹤冲天。\n伫立三荆使，看君驷马旋。' },
  { title: '送王昌龄之岭南', author: '孟浩然', poem: '洞庭去远近，枫叶早惊秋。\n岘首羊公爱，长沙贾谊愁。\n土毛无缟纻，乡味有槎头。\n已抱沈痼疾，更贻魑魅忧。\n数年同笔砚，兹夕间衾裯。\n意气今何在，相思望斗牛。' },
  { title: '岘山送张去非游巴东', author: '孟浩然', poem: '岘山南郭外，送别每登临。\n沙岸江村近，松门山寺深。\n一言予有赠，三峡尔将寻。\n祖席宜城酒，征途云梦林。\n蹉跎游子意，眷恋故人心。\n去矣勿淹滞，巴东猿夜吟。' },
  { title: '奉先张明府休沐还乡海亭宴集', author: '孟浩然', poem: '自君理畿甸，予亦经江淮。\n万里书信断，数年云雨乖。\n归来休澣日，始得赏心谐。\n朱绂恩虽重，沧州趣每怀。\n树低新舞阁，山对旧书斋。\n何以发秋兴，阴虫鸣夜堦。' },
  { title: '宴张记室宅', author: '孟浩然', poem: '甲第金张馆，门庭车骑多。\n家封汉阳郡，文会楚材过。\n曲岛浮觞酌，前山入咏歌。\n妓堂花映发，书阁柳逶迤。\n玉指调筝柱，金泥饰舞罗。\n宁知书劒者，岁月独蹉跎。' },
  { title: '宴崔明府宅夜观妓', author: '孟浩然', poem: '画堂观妙妓，长夜正留宾。\n烛吐莲花艳，妆成桃李春。\n髻鬟低舞席，衫袖掩歌唇。\n汗湿偏宜粉，罗轻讵着身。\n调移筝柱促，欢会酒杯频。\n倘使曹王见，应嫌洛浦神。' },
  { title: '卢明府九日岘山宴袁使君张郎中崔员外', author: '孟浩然', poem: '宇宙谁开辟，江山此郁盘。\n登临今古用，风俗岁时观。\n地理荆州分，天涯楚塞宽。\n百城今刺史，华省旧郎官。\n共美重阳节，俱怀落帽欢。\n酒邀彭泽载，琴辍武城弹。\n献寿先浮菊，寻幽或藉兰。\n烟虹铺藻翰，松竹挂衣冠。\n叔子神如在，山公兴未阑。\n传闻骑马醉，还向习池看。' },
  { title: '登龙兴寺阁', author: '孟浩然', poem: '阁道乘空出，披轩远目开。\n逶迤见江势，客至屡缘回。\n兹郡何填委，遥山复几哉。\n苍苍皆草木，处处尽楼台。\n骤雨一阳散，行舟四海来。\n鸟归余兴远，周览更裴回。' },
  { title: '登总持寺浮图', author: '孟浩然', poem: '半空跻宝塔，晴望尽京华。\n竹遶渭川遍，山连上苑斜。\n四门开帝宅，阡陌俯人家。\n累劫从初地，为童忆聚沙。\n一窥功德见，弥益道心加。\n坐觉诸天近，空香送落花。' },
  { title: '与崔二十一游镜湖寄包贺二公', author: '孟浩然', poem: '试览镜湖物，中流到底清。\n不知鲈鱼味，但识鸥鸟情。\n帆得樵风送，春逢谷雨晴。\n将探夏禹穴，稍背越王城。\n府掾有包子，文章推贺生。\n沧浪醉后唱，因此寄同声。' },
  { title: '夜登孔伯昭南楼时沈太清朱升在座', author: '孟浩然', poem: '谁家无风月，此地有琴尊。\n山水会稽郡，诗书孔氏门。\n再来值秋杪，高阁夜无喧。\n华烛罢然蜡，清弦方奏鹍。\n沈生隐侯胤，朱子买臣孙。\n好我意不浅，登兹共话言。' },
  { title: '陪卢明府泛舟回作', author: '孟浩然', poem: '百里行春返，清流逸兴多。\n鹢舟随雁泊，江火共星罗。\n已救田家旱，仍医俗化讹。\n文章推后辈，风雅激颓波。\n高岸迷陵谷，新声满櫂歌。\n犹怜不才子，白首未登科。' },
  { title: '腊月八日于剡县石城寺礼拜', author: '孟浩然', poem: '石壁开金像，香山倚铁围。\n下生弥勒见，回向一心归。\n竹柏禅庭古，楼台世界稀。\n夕岚增气色，余照发光辉。\n讲席邀谈柄，泉堂施浴衣。\n愿承功德水，从此濯尘机。' },
  { title: '同独孤使君东斋作', author: '孟浩然', poem: '郎官旧华省，天子命分忧。\n襄土岁频旱，随车雨再流。\n云阴自南楚，河润及东周。\n廨宇宜新霁，田家贺有秋。\n竹间残照入，池上夕阳浮。\n寄谢东阳守，何如八咏楼。' },
  { title: '同王九题就师山房', author: '孟浩然', poem: '晚憩支公室，故人逢右军。\n轩窗避炎暑，翰墨动新文。\n竹蔽檐前日，雨随堦下云。\n周游清荫徧，吟卧夕阳曛。\n江静櫂歌歇，溪深樵语闻。\n归途未忍去，携手恋清芬。' },
  { title: '冬至后过吴张二子檀溪别业', author: '孟浩然', poem: '卜筑因自然，檀溪不更穿。\n园庐二友接，水竹数家连。\n直与南山对，非关选地偏。\n草堂时偃曝，兰枻日周旋。\n外事情都远，中流性所便。\n闲垂太公钓，兴发子猷船。\n余亦幽栖者，经过窃慕焉。\n梅花残腊月，柳色半春天。\n鸟泊随阳雁，鱼藏缩项鳊。\n停杯问山简，何似习池边。' },
  { title: '韩大使东斋会岳上人诸学士', author: '孟浩然', poem: '郡守虚陈榻，林间召楚材。\n山川祈雨毕，云物喜晴开。\n抗礼尊缝掖，临流揖渡杯。\n徒攀朱仲李，谁荐和羹梅。\n翰墨缘情制，高深以意裁。\n沧洲趣不远，何必问蓬莱。' },
  { title: '上巳日涧南园期王山人陈七诸公不至', author: '孟浩然', poem: '摇艇候明发，花源弄晚春。\n在山怀绮季，临汉忆荀陈。\n上巳期三月，浮杯兴十旬。\n坐歌空有待，行乐恨无邻。\n日晚兰亭北，烟开曲水滨。\n浴蚕逢姹女，采艾值幽人。\n石壁堪题序，沙场好解绅。\n群公望不至，虚掷此芳晨。' },
  { title: '齿坐呈山南诸隐', author: '孟浩然', poem: '习公有遗坐，高在白云陲。\n樵子不见识，山僧赏自知。\n以余为好事，携手一来窥。\n竹露闲夜滴，松风清昼吹。\n从来抱微尚，况复感前规。\n于此无奇策，苍生奚以为。' },
  { title: '来阇黎新亭作', author: '孟浩然', poem: '八解禅林秀，三明给苑才。\n地偏香界远，心净水亭开。\n傍险山查立，寻幽石迳回。\n瑞花长自下，灵药岂须栽。\n碧网交红树，清泉尽绿苔。\n戏鱼闻法聚，闲鸟诵经来。\n弃象玄应悟，忘言理必该。\n静中何所得，吟咏也徒哉。' },
  { title: '西山寻辛谔', author: '孟浩然', poem: '漾舟寻水便，因访故人居。\n落日清川里，谁言独羡鱼。\n石潭窥洞彻，沙岸历纡徐。\n竹屿见垂钓，茅斋闻读书。\n款言忘景夕，清兴属凉初。\n回也一瓢饮，贤哉常晏如。' },
  { title: '题长安主人壁', author: '孟浩然', poem: '久废南山田，叨陪东阁贤。\n欲随平子去，犹未献甘泉。\n枕籍琴书满，褰帷远岫连。\n我来如昨日，庭树忽鸣蝉。\n促织惊寒女，秋风感长年。\n授衣当九月，无褐竟谁怜。' },
  { title: '行出东山望汉川', author: '孟浩然', poem: '异县非吾土，连山尽绿篁。\n平田出郭少，盘坂入云长。\n万壑归于汉，千峰划彼苍。\n猿声乱楚峡，人语带巴乡。\n石上攒椒树，藤间缀蜜房。\n雪余春未煖，岚解昼初阳。\n征马疲登顿，归帆爱渺茫。\n坐欣沿溜下，信宿见维桑。' },
  { title: '夜泊宣城界', author: '孟浩然', poem: '西塞沿江岛，南陵问驿楼。\n湖平津济阔，风止客帆收。\n去去怀前浦，茫茫泛夕流。\n石逢罗刹碍，山泊敬亭幽。\n火识梅根冶，烟迷杨叶洲。\n离家复水宿，相伴赖沙鸥。' },
  { title: '下灨石', author: '孟浩然', poem: '灨石三百里，沿洄千嶂间。\n沸声常活活，洊势亦潺潺。\n跳沫鱼龙沸，垂藤猿狖攀。\n榜人苦奔峭，而我忘险难。\n放溜情弥惬，登舻目自闲。\n暝帆何处宿，遥指落星湾。' },
  { title: '初年乐城馆中卧疾怀归作', author: '孟浩然', poem: '异县天隅僻，孤帆海畔过。\n往来乡信断，留滞客情多。\n腊月闻雷震，东风感岁和。\n蛰虫惊户穴，巢鹊眄庭柯。\n徒对芳尊酒，其如伏枕何。\n归屿理舟楫，江海正无波。' },
  { title: '醉后赠马四', author: '孟浩然', poem: '四海重然诺，吾尝闻白眉。\n秦城游侠客，相得半酣时。' },
  { title: '赠王九', author: '孟浩然', poem: '日暮田家远，山中勿久淹。\n归人须早去，稚子望陶潜。' },
  { title: '登岘山亭寄晋陵张少府', author: '孟浩然', poem: '岘首风湍急，云帆若鸟飞。\n凭轩试一问，张翰欲来归。' },
  { title: '送朱大入秦', author: '孟浩然', poem: '游人武陵去，宝劒直千金。\n分手脱相赠，平生一片心。' },
  { title: '送友人之京', author: '孟浩然', poem: '君登青云去，予望青山归。\n云山从此别，泪湿薜萝衣。' },
  { title: '送张郎中迁京', author: '孟浩然', poem: '碧溪常共赏，朱邸忽迁荣。\n豫有相思意，闻君琴上声。' },
  { title: '同张将蓟门观灯', author: '孟浩然', poem: '异俗非乡俗，新年改故年。\n蓟门看火树，疑是烛龙然。' },
  { title: '张郎中梅园中', author: '孟浩然', poem: '绮席铺兰杜，珠盘折芰荷。\n故园留不住，应是恋弦歌。' },
  { title: '北涧泛舟', author: '孟浩然', poem: '北涧流恒满，浮舟触处通。\n沿洄自有趣，何必五湖中。' },
  { title: '春晓', author: '孟浩然', poem: '春眠不觉晓，处处闻啼鸟。\n夜来风雨声，花落知多少。' },
  { title: '洛中访袁拾遗不遇', author: '孟浩然', poem: '洛阳访才子，江岭作流人。\n闻说梅花早，何如北地春。' },
  { title: '寻菊花潭主人不遇', author: '孟浩然', poem: '行至菊花潭，村西日已斜。\n主人登高去，鸡犬空在家。' },
  { title: '檀溪寻故人', author: '孟浩然', poem: '花伴成龙竹，池分跃马溪。\n田园人不见，疑向洞中栖。' },
  { title: '扬子津望京口', author: '孟浩然', poem: '北固临京口，夷山近海滨。\n江风白浪起，愁杀渡头人。' },
  { title: '同储十二洛阳道中作', author: '孟浩然', poem: '珠弹繁华子，金羁游侠人。\n酒酣白日暮，走马入红尘。' },
  { title: '初下浙江舟中口号', author: '孟浩然', poem: '八月观潮罢，三江越海浔。\n回瞻魏阙路，空复子牟心。' },
  { title: '宿建德江', author: '孟浩然', poem: '移舟泊烟渚，日暮客愁新。\n野旷天低树，江清月近人。' },
  { title: '问舟子', author: '孟浩然', poem: '向夕问舟子，前程复几多。\n湾头正堪泊，淮里足风波。' },
  { title: '戏题', author: '孟浩然', poem: '客醉眠未起，主人呼解酲。\n已言鸡黍熟，复道瓮头清。' },
  { title: '凉州词 一', author: '孟浩然', poem: '浑成紫檀金屑文，作得琵琶声入云。\n胡地迢迢三万里，那堪马上送明君。' },
  { title: '凉州词 二', author: '孟浩然', poem: '异方之乐令人悲，羌笛胡笳不用吹。\n坐看今夜关山月，思杀边城游侠儿。' },
  { title: '送新安张少府归秦中', author: '孟浩然', poem: '试登秦岭望秦川，遥忆青门春可怜。\n仲月送君从此去，瓜时须及邵平田。' },
  { title: '送杜十四之江南', author: '孟浩然', poem: '荆吴相接水为乡，君去春江正淼茫。\n日暮征帆何处泊，天涯一望断人肠。' },
  { title: '渡浙江问舟中人', author: '孟浩然', poem: '潮落江平未有风，扁舟共济与君同。\n时时引领望天末，何处青山是越中。' },
  { title: '初秋', author: '孟浩然', poem: '不觉初秋夜渐长，清风习习重凄凉。\n炎炎暑退茅斋静，堦下丛莎有露光。' },
  { title: '过融上人兰若', author: '孟浩然', poem: '山头禅室挂僧衣，窗外无人水鸟飞。\n黄昏半在下山路，却听泉声恋翠微。' },
  { title: '句', author: '孟浩然', poem: '微云淡河汉，疎雨滴梧桐。\n逐逐怀良驭，萧萧顾乐鸣。' },
  { title: '古风 一', author: '李白', poem: '大雅久不作，吾衰竟谁陈。\n王风委蔓草，战国多荆榛。\n龙虎相啖食，兵戈逮狂秦。\n正声何微茫，哀怨起骚人。\n扬马激颓波，开流荡无垠。\n废兴虽万变，宪章亦已沦。\n自从建安来，绮丽不足珍。\n圣代复元古，垂衣贵清真。\n群才属休明，乘运共跃鳞。\n文质相炳焕，众星罗秋旻。\n我志在删述，垂辉暎千春。\n希圣如有立，绝笔于获麟。' },
  { title: '古风 二', author: '李白', poem: '蟾蜍薄太清，蚀此瑶台月。\n圆光亏中天，金魄遂沦没。\n䗖𬟽入紫微，大明夷朝晖。\n浮云隔两曜，万象昏阴霏。\n萧萧长门宫，昔是今已非。\n桂蠹花不实，天霜下严威。\n沈叹终永夕，感我涕沾衣。' },
  { title: '古风 三', author: '李白', poem: '秦皇扫六合，虎视何雄哉。\n飞劒决浮云，诸侯尽西来。\n明断自天启，大略驾群才。\n收兵铸金人，函谷正东开。\n铭功会稽岭，骋望瑯琊台。\n刑徒七十万，起土骊山隈。\n尚采不死药，茫然使心哀。\n连弩射海鱼，长鲸正崔嵬。\n额鼻象五岳，扬波喷云雷。\n鬐鬣蔽青天，何由覩蓬莱。\n徐[巿]载秦女，楼船几时迥。\n但见三泉下，金棺葬寒灰。' },
  { title: '古风 四', author: '李白', poem: '凤飞九千仞，五章备彩珍。\n衔书且虚归，空入周与秦。\n横绝历四海，所居未得邻。\n吾营紫河车，千载落风尘。\n药物秘海岳，采铅青溪滨。\n时登大楼山，举手望仙真。\n羽驾灭去影，飙车绝廻轮。\n尚恐丹液迟，志愿不及申。\n徒霜镜中发，羞彼鹤上人。\n桃李何处开，此花非我春。\n唯应清都境，长与韩众亲。' },
  { title: '古风 五', author: '李白', poem: '太白何苍苍，星辰上森列。\n去天三百里，邈尔与世绝。\n中有绿发翁，披云卧松雪。\n不笑亦不语，冥栖在岩穴。\n我来逢真人，长跪问宝诀。\n粲然启玉齿，授以炼药说。\n铭骨传其语，竦身已电灭。\n仰望不可及，苍然五情热。\n吾将营丹砂，永与世人别。' },
  { title: '古风 六', author: '李白', poem: '代马不思越，越禽不恋燕。\n情性有所习，土风固其然。\n昔别雁门关，今戍龙庭前。\n惊沙乱海日，飞雪迷胡天。\n虮虱生虎鹖，心魂逐旌旃。\n苦战功不赏，忠诚难可宣。\n谁怜李飞将，白首没三边。' },
  { title: '古风 七', author: '李白', poem: '五鹤西北来，飞飞凌太清。\n仙人绿云上，自道安期名。\n两两白玉童，双吹紫鸾笙。\n去影忽不见，回风送天声。\n我欲一问之，飘然若流星。\n愿餐金光草，寿与天齐倾。' },
  { title: '古风 八', author: '李白', poem: '咸阳二三月，宫柳黄金枝。\n绿帻谁家子，卖珠轻薄儿。\n日暮醉酒归，白马骄且驰。\n意气人所仰，冶游方及时。\n子云不晓事，晚献长杨辞。\n赋达身已老，草玄鬓若丝。\n投阁良可叹，但为此辈嗤。' },
  { title: '古风 九', author: '李白', poem: '庄周梦胡蝶，胡蝶为庄周。\n一体更变易，万事良悠悠。\n乃知蓬莱水，复作清浅流。\n青门种瓜人，旧日东陵侯。\n富贵故如此，营营何所求。' },
  { title: '古风 十', author: '李白', poem: '齐有倜傥生，鲁连特高妙。\n明月出海底，一朝开光曜。\n却秦振英声，后世仰末照。\n意轻千金赠，愿向平原笑。\n吾亦澹荡人，拂衣可同调。' },
  { title: '古风 十一', author: '李白', poem: '黄河走东溟，白日落西海。\n逝川与流光，飘忽不相待。\n春容舍我去，秋发已衰改。\n人生非寒松，年貌岂长在。\n吾当乘云螭，吸景驻光彩。' },
  { title: '古风 十二', author: '李白', poem: '松柏本孤直，难为桃李颜。\n昭昭严子陵，垂钓沧波间。\n身将客星隐，心与浮云闲。\n长揖万乘君，还归富春山。\n清风洒六合，邈然不可攀。\n使我长叹息，冥栖岩石间。' },
  { title: '古风 十三', author: '李白', poem: '君平既弃世，世亦弃君平。\n观变穷太易，探元化群生。\n寂寞缀道论，空帘闭幽情。\n驺虞不虚来，𬸚𬸦有时鸣。\n安知天汉上，白日悬高名。\n海客去已久，谁人测沈冥。' },
  { title: '古风 十四', author: '李白', poem: '胡关饶风沙，萧索竟终古。\n木落秋草黄，登高望戎虏。\n荒城空大漠，边邑无遗堵。\n白骨横千霜，嵯峨蔽榛莽。\n借问谁凌虐，天骄毒威武。\n赫怒我圣皇，劳师事鼙鼓。\n阳和变杀气，发卒骚中土。\n三十六万人，哀哀泪如雨。\n且悲就行役，安得营农圃。\n不见征戍儿，岂知关山苦。\n李牧今不在，边人饲豺虎。' },
  { title: '古风 十五', author: '李白', poem: '燕昭延郭隗，遂筑黄金台。\n剧辛方赵至，邹衍复齐来。\n奈何青云士，弃我如尘埃。\n珠玉买歌笑，糟糠养贤才。\n方知黄鹤举，千里独裴回。' },
  { title: '古风 十六', author: '李白', poem: '宝劒双蛟龙，雪花照芙蓉。\n精光射天地，雷腾不可冲。\n一去别金匣，飞沈失相从。\n风胡灭已久，所以潜其锋。\n吴水深万丈，楚山邈千重。\n雌雄终不隔，神物会当逢。' },
  { title: '古风 十七', author: '李白', poem: '金华牧羊儿，乃是紫烟客。\n我愿从之游，未去发已白。\n不知繁华子，扰扰何所迫。\n昆山采琼蘂，可以炼精魄。' },
  { title: '古风 十八', author: '李白', poem: '天津三月时，千门桃与李。\n朝为断肠花，暮逐东流水。\n前水复后水，古今相续流。\n新人非旧人，年年桥上游。\n鸡鸣海色动，谒帝罗公侯。\n月落西上阳，余辉半城楼。\n衣冠照云日，朝下散皇州。\n鞍马如飞龙，黄金络马头。\n行人皆辟易，志气横嵩丘。\n入门上高堂，列鼎错珍羞。\n香风引赵舞，清管随齐讴。\n七十紫鸳鸯，双双戏庭幽。\n行乐争昼夜，自言度千秋。\n功成身不退，自古多愆尤。\n黄犬空叹息，绿珠成衅讐。\n何如鸱夷子，散发櫂扁舟。' },
  { title: '古风 十九', author: '李白', poem: '西岳莲花山，迢迢见明星。\n素手把芙蓉，虚步蹑太清。\n霓裳曳广带，飘拂升天行。\n邀我登云台，高揖卫叔卿。\n恍恍与之去，驾鸿凌紫冥。\n俯视洛阳川，茫茫走胡兵。\n流血涂野草，豺狼尽冠缨。' },
  { title: '古风 二十', author: '李白', poem: '昔我游齐都，登华不注峰。\n兹山何峻秀，绿翠如芙蓉。\n萧飒古仙人，了知是赤松。\n借予一白鹿，自挟两青龙。\n含笑凌倒景，欣然愿相从。\n泣与亲友别，欲语再三咽。\n勗君青松心，努力保霜雪。\n世路多险艰，白日欺红颜。\n分手各千里，去去何时还。\n在世复几时，倏如飘风度。\n空闻紫金经，白首愁相误。\n抚己忽自笑，沈吟为谁故。\n名利徒煎熬，安得闲余步。\n终留赤玉舄，东上蓬莱路。\n秦帝如我求，苍苍但烟雾。' },
  { title: '古风 二十一', author: '李白', poem: '郢客吟白雪，遗响飞青天。\n徒劳歌此曲，举世谁为传。\n试为巴人唱，和者乃数千。\n吞声何足道，叹息空凄然。' },
  { title: '古风 二十二', author: '李白', poem: '秦水别陇首，幽咽多悲声。\n胡马顾朔雪，躞蹀长嘶鸣。\n感物动我心，缅然含归情。\n昔视秋蛾飞，今见春蚕生。\n袅袅桑柘叶，萋萋柳垂荣。\n急节谢流水，羁心摇悬旌。\n挥涕且复去，恻怆何时平。' },
  { title: '古风 二十三', author: '李白', poem: '秋露白如玉，团团下庭绿。\n我行忽见之，寒早悲岁促。\n人生鸟过目，胡乃自结束。\n景公一何愚，牛山泪相续。\n物苦不知足，得陇又望蜀。\n人心若波澜，世路有屈曲。\n三万六千日，夜夜当秉烛。' },
  { title: '古风 二十四', author: '李白', poem: '大车扬飞尘，亭午暗阡陌。\n中贵多黄金，连云开甲宅。\n路逢鬬鸡者，冠盖何辉赫。\n鼻息干虹蜺，行人皆怵惕。\n世无洗耳翁，谁知尧与跖。' },
  { title: '古风 二十五', author: '李白', poem: '世道日交丧，浇风散淳源。\n不采芳桂枝，反栖恶木根。\n所以桃李树，吐花竟不言。\n大运有兴没，群动争飞奔。\n归来广成子，去入无穷门。' },
  { title: '古风 二十六', author: '李白', poem: '碧荷生幽泉，朝日艳且鲜。\n秋花冒绿水，密叶罗青烟。\n秀色空绝世，馨香竟谁传。\n坐看飞霜满，凋此红芳年。\n结根未得所，愿托华池边。' },
  { title: '古风 二十七', author: '李白', poem: '燕赵有秀色，绮楼青云端。\n眉目艳皎月，一笑倾城欢。\n常恐碧草晚，坐泣秋风寒。\n纤手怨玉琴，清晨起长叹。\n焉得偶君子，共乘双飞鸾。' },
  { title: '古风 二十八', author: '李白', poem: '容颜若飞电，时景如飘风。\n草绿霜已白，日西月复东。\n华鬓不耐秋，飒然成衰蓬。\n古来贤圣人，一一谁成功。\n君子变猿鹤，小人为沙虫。\n不及广成子，乘云驾轻鸿。' },
  { title: '古风 二十九', author: '李白', poem: '三季分战国，七雄成乱麻。\n王风何怨怒，世道终纷拏。\n至人洞玄象，高举凌紫霞。\n仲尼欲浮海，吾祖之流沙。\n圣贤共沦没，临岐胡咄嗟。' },
  { title: '古风 三十', author: '李白', poem: '玄风变太古，道丧无时还。\n扰扰季叶人，鸡鸣趋四关。\n但识金马门，谁知蓬莱山。\n白首死罗绮，笑歌无时闲。\n绿酒哂丹液，青娥凋素颜。\n大儒挥金椎，琢之诗礼间。\n苍苍三株树，冥目焉能攀。' },
  { title: '古风 三十一', author: '李白', poem: '郑客西入关，行行未能已。\n白马华山君，相逢平原里。\n璧遗镐池君，明年祖龙死。\n秦人相谓曰，吾属可去矣。\n一往桃花源，千春隔流水。' },
  { title: '古风 三十二', author: '李白', poem: '蓐收肃金气，西陆弦海月。\n秋蝉号阶轩，感物忧不歇。\n良辰竟何许，大运有沦忽。\n天寒悲风生，夜久众星没。\n恻恻不忍言，哀歌逮明发。' },
  { title: '古风 三十三', author: '李白', poem: '北溟有巨鱼，身长数千里。\n仰喷三山雪，横吞百川水。\n凭陵随海运，𬊤赫因风起。\n吾观摩天飞，九万方未已。' },
  { title: '古风 三十四', author: '李白', poem: '羽檄如流星，虎符合专城。\n喧呼救边急，群鸟皆夜鸣。\n白日曜紫微，三公运权衡。\n天地皆得一，澹然四海清。\n借问此何为，荅言楚征兵。\n渡泸及五月，将赴云南征。\n怯卒非战士，炎方难远行。\n长号别严亲，日月惨光晶。\n泣尽继以血，心摧两无声。\n困兽当猛虎，穷鱼饵奔鲸。\n千去不一回，投躯岂全生。\n如何舞干戚，一使有苗平。' },
  { title: '古风 三十五', author: '李白', poem: '丑女来效颦，还家惊四隣。\n寿陵失本步，笑杀邯郸人。\n一曲斐然子，雕虫丧天真。\n棘刺造沐猴，三年费精神。\n功成无所用，楚楚且华身。\n大雅思文王，颂声久崩沦。\n安得郢中质，一挥成斧斤。' },
  { title: '古风 三十六', author: '李白', poem: '抱玉入楚国，见疑古所闻。\n良宝终见弃，徒劳三献君。\n直木忌先伐，芳兰哀自焚。\n盈满天所损，沈冥道为群。\n东海沈碧水，西关乘紫云。\n鲁连及柱史，可以蹑清芬。' },
  { title: '古风 三十七', author: '李白', poem: '燕臣昔恸哭，五月飞秋霜。\n庶女号苍天，震风击齐堂。\n精诚有所感，造化为悲伤。\n而我竟何辜，远身金殿傍。\n浮云蔽紫闼，白日难回光。\n群沙秽明珠，众草凌孤芳。\n古来共叹息，流泪空沾裳。' },
  { title: '古风 三十八', author: '李白', poem: '孤兰生幽园，众草共芜没。\n虽照阳春晖，复悲高秋月。\n飞霜早淅沥，绿艳恐休歇。\n若无清风吹，香气为谁发。' },
  { title: '古风 三十九', author: '李白', poem: '登高望四海，天地何漫漫。\n霜被群物秋，风飘大荒寒。\n荣华东流水，万事皆波澜。\n白日掩徂辉，浮云无定端。\n梧桐巢燕雀，枳棘栖鸳鸾。\n且复归去来，劒歌行路难。' },
  { title: '古风 四十', author: '李白', poem: '凤饥不啄粟，所食唯琅玕。\n焉能与群鸡，刺蹙争一餐。\n朝鸣昆丘树，夕饮砥柱湍。\n归飞海路远，独宿天霜寒。\n幸遇王子晋，结交青云端。\n怀恩未得报，感别空长叹。' },
  { title: '古风 四十一', author: '李白', poem: '朝弄紫沂海，夕披丹霞裳。\n挥手折若木，拂此西日光。\n云卧游八极，玉颜已千霜。\n飘飘入无倪，稽首祈上皇。\n呼我游太素，玉杯赐琼浆。\n一餐历万岁，何用还故乡。\n永随长风去，天外恣飘扬。' },
  { title: '古风 四十二', author: '李白', poem: '摇裔双白鸥，鸣飞沧江流。\n宜与海人狎，岂伊云鹤俦。\n寄形宿沙月，沿芳戏春洲。\n吾亦洗心者，忘机从尔游。' },
  { title: '古风 四十三', author: '李白', poem: '周穆八荒意，汉皇万乘尊。\n淫乐心不极，雄豪安足论。\n西海宴王母，北宫邀上元。\n瑶水闻遗歌，玉杯竟空言。\n灵迹成蔓草，徒悲千载魂。' },
  { title: '古风 四十四', author: '李白', poem: '绿萝纷葳蕤，缭绕松栢枝。\n草木有所托，岁寒尚不移。\n奈何夭桃色，坐叹葑菲诗。\n玉颜艳红彩，云发非素丝。\n君子恩已毕，贱妾将何为。' },
  { title: '古风 四十五', author: '李白', poem: '八荒驰惊飙，万物尽凋落。\n浮云蔽颓阳，洪波振大壑。\n龙凤脱罔罟，飘飖将安托。\n去去乘白驹，空山咏场藿。' },
  { title: '古风 四十六', author: '李白', poem: '一百四十年，国容何赫然。\n隐隐五凤楼，峨峨横三川。\n王侯象星月，宾客如云烟。\n鬬鸡金宫里，蹴鞠瑶台边。\n举动摇白日，指挥回青天。\n当涂何翕忽，失路长弃捐。\n独有扬执戟，闭关草太玄。' },
  { title: '古风 四十七', author: '李白', poem: '桃花开东园，含笑夸白日。\n偶蒙东风荣，生此艳阳质。\n岂无佳人色，但恐花不实。\n宛转龙火飞，零落早相失。\n讵知南山松，独立自萧𫗋。' },
  { title: '古风 四十八', author: '李白', poem: '秦皇按宝劒，赫怒震威神。\n逐日巡海右，驱石驾沧津。\n征卒空九宇，作桥伤万人。\n但求蓬岛药，岂思农鳸春。\n力尽功不赡，千载为悲辛。' },
  { title: '古风 四十九', author: '李白', poem: '美人出南国，灼灼芙蓉姿。\n皓齿终不发，芳心空自持。\n由来紫宫女，共妬青蛾眉。\n归去潇湘沚，沈吟何足悲。' },
  { title: '古风 五十', author: '李白', poem: '宋国梧台东，野人得燕石。\n夸作天下珍，却哂赵王璧。\n赵璧无缁磷，燕石非贞真。\n流俗多错误，岂知玉与珉。' },
  { title: '古风 五十一', author: '李白', poem: '殷后乱天纪，楚怀亦已昏。\n夷羊满中野，菉葹盈高门。\n比干谏而死，屈平窜湘源。\n虎口何婉娈，女媭空婵媛。\n彭咸久沦没，此意与谁论。' },
  { title: '古风 五十二', author: '李白', poem: '青春流惊湍，朱明骤回薄。\n不忍看秋蓬，飘扬竟何托。\n光风灭兰蕙，白露洒葵藿。\n美人不我期，草木日零落。' },
  { title: '古风 五十三', author: '李白', poem: '战国何纷纷，兵戈乱浮云。\n赵倚两虎鬬，晋为六卿分。\n奸臣欲窃位，树党自相群。\n果然田成子，一旦杀齐君。' },
  { title: '古风 五十四', author: '李白', poem: '倚劒登高台，悠悠送春目。\n苍榛蔽层丘，琼草隐深谷。\n凤鸟鸣西海，欲集无珍木。\n鸒斯得所居，蒿下盈万族。\n晋风日已颓，穷途方恸哭。' },
  { title: '古风 五十五', author: '李白', poem: '齐瑟弹东吟，秦弦弄西音。\n慷慨动颜魄，使人成荒淫。\n彼美佞邪子，婉娈来相寻。\n一笑双白璧，再歌千黄金。\n珍色不贵道，讵惜飞光沈。\n安识紫霞客，瑶台鸣素琴。' },
  { title: '古风 五十六', author: '李白', poem: '越客采明珠，提携出南隅。\n清辉照海月，美价倾皇都。\n献君君按劒，怀宝空长吁。\n鱼目复相哂，寸心增烦纡。' },
  { title: '古风 五十七', author: '李白', poem: '羽族禀万化，小大各有依。\n周周亦何辜，六翮掩不挥。\n愿衔众禽翼，一向黄河飞。\n飞者莫我顾，叹息将安归。' },
  { title: '古风 五十八', author: '李白', poem: '我到巫山渚，寻古登阳台。\n天空彩云灭，地远清风来。\n神女去已久，襄王安在哉。\n荒淫竟沦替，樵牧徒悲哀。' },
  { title: '古风 五十九', author: '李白', poem: '恻恻泣路岐，哀哀悲素丝。\n路岐有南北，素丝易变移。\n万事固如此，人生无定期。\n田窦相倾夺，宾客互盈亏。\n世途多飜覆，交道方崄巇。\n斗酒强然诺，寸心终自疑。\n张陈竟火灭，萧朱亦星离。\n众鸟集荣柯，穷鱼守枯池。\n嗟嗟失权客，勤问何所规。' },
  { title: '远别离', author: '李白', poem: '远别离，古有皇英之二女，乃在洞庭之南，潇湘之浦。\n海水直下万里深，谁人不言此离苦。\n日惨惨兮云冥冥，猩猩啼烟兮鬼啸雨。\n我纵言之将何补，皇穹窃恐不照余之忠诚。\n云凭凭兮欲吼怒，尧舜当之亦禅禹。\n君失臣兮龙为鱼，权归臣兮鼠变虎。\n或言尧幽囚，舜野死。\n九疑联绵皆相似，重瞳孤坟竟何是。\n帝子泣兮绿云间，随风波兮去无还。\n恸哭兮远望，见苍梧之深山。\n苍梧山崩湘水绝，竹上之泪乃可灭。' },
  { title: '公无渡河', author: '李白', poem: '黄河西来决昆仑，咆哮万里触龙门。\n波滔天，尧咨嗟，大禹理百川，儿啼不窥家。\n杀湍烟洪水，九州始蚕麻。\n其害乃去，茫然风沙。\n被发之叟狂而痴，清晨临流欲奚为。\n旁人不惜妻止之，公无渡河苦渡之。\n虎可搏，河难凭，公果溺死流海湄。\n有长鲸白齿若雪山，公乎公乎挂罥于其间，箜篌所悲竟不还。' },
  { title: '蜀道难', author: '李白', poem: '噫吁戏！危乎高哉！蜀道之难难于上青天！蚕丛及鱼凫，开国何茫然。\n尔来四万八千岁，不与秦塞通人烟。\n西当太白有鸟道，可以横绝峨眉巅。\n地崩山摧壮士死，然后天梯石栈相钩连。\n上有六龙回日之高标，下有冲波逆折之回川。\n黄鹤之飞尚不得过，猨猱欲度愁攀援。\n青泥何盘盘，百步九折萦岩峦。\n扪参历井仰胁息，以手抚膺坐长叹。\n问君西游何时还？畏途巉岩不可攀。\n但见悲鸟号古木，雄飞雌从绕林间。\n又闻子规啼夜月，愁空山，蜀道之难难于上青天，使人听此凋朱颜。\n连峰去天不盈尺，枯松倒挂倚绝壁。\n飞湍瀑流争喧豗，砅厓转石万壑雷。\n其险也如此，嗟尔远道之人胡为乎来哉！劒阁峥嵘而崔嵬，一夫当关，万夫莫开。\n所守或匪亲，化为狼与豺。\n朝避猛虎，夕避长蛇。\n磨牙吮血，杀人如麻。\n锦城虽云乐，不如早还家。\n蜀道之难难于上青天，侧身西望长咨嗟。' },
  { title: '梁甫吟', author: '李白', poem: '长啸梁甫吟，何时见阳春。\n君不见朝歌屠叟辞棘津，八十西来钓渭滨。\n宁羞白发照清水，逢时吐气思经纶。\n广张三千六百钓，风期暗与文王亲。\n大贤虎变愚不测，当年颇似寻常人。\n君不见高阳酒徒起草中，长揖山东隆准公。\n入门不拜骋雄辩，两女辍洗来趋风。\n东下齐城七十二，指挥楚汉如旋蓬。\n狂客落魄尚如此，何况壮士当群雄。\n我欲攀龙见明主，雷公砰訇震天鼓。\n帝傍投壶多玉女，三时大笑开电光。\n倏烁晦冥起风雨，阊阖九门不可通。\n以额扣关阍者怒，白日不照吾精诚。\n杞国无事忧天倾，䝟貐磨牙竞人肉。\n驺虞不折生草茎，手接飞猱搏雕虎。\n侧足焦原未言苦，智者可卷愚者豪。\n世人见我轻鸿毛，力排南山三壮士，齐相杀之费二桃。\n吴楚弄兵无剧孟，亚夫咍尔为徒劳。\n梁甫吟，梁甫吟，声正悲。\n张公两龙劒，神物合有时。\n风云感会起屠钓，大人𡸣屼当安之。' },
  { title: '乌夜啼', author: '李白', poem: '黄云城边乌欲栖，归飞哑哑枝上啼。\n机中织锦秦川女，碧纱如烟隔窗语。\n停梭怅然忆远人，独宿孤房泪如雨。' },
  { title: '乌栖曲', author: '李白', poem: '姑苏台上乌栖时，吴王宫里醉西施。\n吴歌楚舞欢未毕，青山欲衔半边日。' },
  { title: '战城南', author: '李白', poem: '去年战桑干源，今年战葱河道。\n洗兵条支海上波，放马天山雪中草。\n万里长征战，三军尽衰老。\n匈奴以杀戮为耕作，古来唯见白骨黄沙田。\n秦家筑城避胡处，汉家还有烽火然。\n烽火然不息，征战无已时。\n野战格鬬死，败马号鸣向天悲。\n乌鸢啄人肠，衔飞上挂枯树枝。\n士卒涂草莽，将军空尔为。\n乃知兵者是凶器，圣人不得已而用之。' },
  { title: '将进酒', author: '李白', poem: '君不见黄河之水天上来，奔流到海不复回。\n君不见高堂明镜悲白发，朝如青丝暮成雪。\n人生得意须尽欢，莫使金樽空对月。\n天生我材必有用，千金散尽还复来。\n烹羊宰牛且为乐，会须一饮三百杯。\n岑夫子，丹丘生，将进酒，君莫停。\n与君歌一曲，请君为我侧耳听。\n钟鼓馔玉不足贵，但愿长醉不愿醒。\n古来圣贤皆寂寞，惟有饮者留其名。\n陈王昔时宴平乐，斗酒十千恣讙谑。\n主人何为言少钱，径须沽取对君酌。\n五花马，千金裘，呼儿将出换美酒，与尔同销万古愁。' },
  { title: '行行游且猎篇', author: '李白', poem: '边城儿，生年不读一字书，但将游猎夸轻趫。\n胡马秋肥宜白草，骑来蹑影何矜骄。\n金鞭拂雪挥鸣鞘，半酣呼鹰出远郊。\n弓弯满月不虚发，双鸧迸落连飞髇。\n海边观者皆辟易，猛气英风振沙碛。\n儒生不及游侠人，白首下帷复何益。' },
  { title: '飞龙引二首 一', author: '李白', poem: '黄帝铸鼎于荆山，炼丹砂。\n丹砂成黄金，骑龙飞上太清家。\n云愁海思令人嗟，宫中彩女颜如花。\n飘然挥手凌紫霞，从风纵体登鸾车。\n登鸾车，侍轩辕。\n遨游青天中，其乐不可言。' },
  { title: '飞龙引二首 二', author: '李白', poem: '鼎湖流水清且闲，轩辕去时有弓劒。\n古人传道留其间，后宫婵娟多花颜。\n乘鸾飞烟亦不还，骑龙攀天造天关。\n造天关，闻天语，长云河车载玉女。\n载玉女，过紫皇，紫皇乃赐白兔所捣之药方，后天而老雕三光。\n下视瑶池见王母，蛾眉萧飒如秋霜。' },
  { title: '天马歌', author: '李白', poem: '天马来出月支窟，背为虎文龙翼骨。\n嘶青云，振绿发，兰筋权奇走灭没。\n腾昆仑，历西极，四足无一蹶。\n鸡鸣刷燕晡秣越，神行电迈蹑慌惚。\n天马呼，飞龙趋，目明长庚臆双凫。\n尾如流星首渴乌，口喷红光汗沟朱。\n曾陪时龙蹑天衢，羁金络月照皇都。\n逸气棱棱凌九区，白璧如山谁敢沽。\n回头笑紫燕，但觉尔辈愚。\n天马奔，恋君轩，駷跃惊矫浮云飜。\n万里足踯躅，遥瞻阊阖门。\n不逢寒风子，谁采逸景孙。\n白云在青天，丘陵远崔嵬。\n盐车上峻坂，倒行逆施畏日晚。\n伯乐翦拂中道遗，少尽其力老弃之。\n愿逢田子方，恻然为我悲。\n虽有玉山禾，不能疗苦饥。\n严霜五月凋桂枝，伏枥衔冤摧两眉。\n请君赎献穆天子，犹堪弄影舞瑶池。' },
  { title: '行路难三首 一', author: '李白', poem: '金樽清酒斗十千，玉盘珍羞直万钱。\n停杯投筯不能食，拔劒四顾心茫然。\n欲渡黄河冰塞川，将登太行雪满山。\n闲来垂钓碧溪上，忽复乘舟梦日边。\n行路难，行路难，多岐路，今安在。\n长风破浪会有时，直挂云帆济沧海。' },
  { title: '行路难三首 二', author: '李白', poem: '大道如青天，我独不得出。\n羞逐长安社中儿，赤鸡白狗赌梨栗。\n弹劒作歌奏苦声，曳裾王门不称情。\n淮阴市井笑韩信，汉朝公卿忌贾生。\n君不见昔时燕家重郭隗，拥篲折节无嫌猜。\n剧辛乐毅感恩分，输肝剖胆效英才。\n昭王白骨萦烂草，谁人更扫黄金台。\n行路难，归去来。' },
  { title: '行路难三首 三', author: '李白', poem: '有耳莫洗颍川水，有口莫食首阳蕨。\n含光混世贵无名，何用孤高比云月。\n吾观自古贤达人，功成不退皆殒身。\n子胥既弃吴江上，屈原终投湘水滨。\n陆机雄才岂自保，李斯税驾苦不早。\n华亭鹤唳讵可闻，上蔡苍鹰何足道。\n君不见吴中张翰称达生，秋风忽忆江东行。\n且乐生前一杯酒，何须身后千载名。' },
  { title: '长相思', author: '李白', poem: '长相思，在长安，络纬秋啼金井阑。\n微霜凄凄簟色寒，孤灯不明思欲绝。\n卷帷望月空长叹，美人如花隔云端。\n上有青冥之长天，下有渌水之波澜。\n天长路远魂飞苦，梦魂不到关山难。\n长相思，摧心肝。' },
  { title: '上留田行', author: '李白', poem: '行至上留田，孤坟何峥嵘。\n积此万古恨，春草不复生。\n悲风四边来，肠断白杨声。\n借问谁家地，埋没蒿里茔。\n古老向余言，言是上留田。\n蓬科马鬣今已平，昔之弟死兄不葬，他人于此举铭旌。\n一鸟死，百鸟鸣，一兽走，百兽惊。\n桓山之禽别离苦，欲去回翔不能征。\n田氏仓卒骨肉分，青天白日摧紫荆。\n交柯之木本同形，东枝顦顇西枝荣。\n无心之物尚如此，参商胡乃寻天兵。\n孤竹延陵，让国扬名。\n高风缅邈，颓波激清。\n尺布之谣，塞耳不能听。' },
  { title: '春日行', author: '李白', poem: '深宫高楼入紫清，金作蛟龙盘绣楹。\n佳人当窗弄白日，弦将手语弹鸣筝。\n春风吹落君王耳，此曲乃是升天行。\n因出天池泛蓬瀛，楼船蹙沓波浪惊。\n三千双蛾献歌笑，挝钟考鼓宫殿倾。\n万姓聚舞歌太平，我无为，人自宁。\n三十六帝欲相迎，仙人飘翩下云𫐌。\n帝不去，留镐京。\n安能为轩辕，独往入窅冥。\n小臣拜献南山寿，陛下万古垂鸿名。' },
  { title: '前有一樽酒行二首 一', author: '李白', poem: '春风东来忽相过，金樽渌酒生微波。\n落花纷纷稍觉多，美人欲醉朱颜酡。\n青轩桃李能几何，流光欺人忽蹉砣。\n君起舞，日西夕，当年意气不肯平，白发如丝叹何益。' },
  { title: '前有一樽酒行二首 二', author: '李白', poem: '琴奏龙门之绿桐，玉壶美酒清若空。\n催弦拂柱与君饮，看朱成碧颜始红。\n胡姬貌如花，当垆笑春风。\n笑春风，舞罗衣，君今不醉将安归。' },
  { title: '夜坐吟', author: '李白', poem: '冬夜夜寒觉夜长，沈吟久坐坐北堂。\n冰合井泉月入闺，金缸青凝照悲啼。\n金缸灭，啼转多。\n掩妾泪，听君歌。\n歌有声，妾有情。\n情声合，两无违。\n一语不入意，从君万曲梁尘飞。' },
  { title: '野田黄雀行', author: '李白', poem: '游莫逐炎洲翠，栖莫近吴宫燕。\n吴宫火起焚巢窠，炎洲逐翠遭网罗。\n萧条两翅蓬蒿下，纵有鹰鹯奈若何。' },
  { title: '箜篌谣', author: '李白', poem: '攀天莫登龙，走山莫骑虎。\n贵贱结交心不移，唯有严陵及光武。\n周公称大圣，管蔡宁相容。\n汉谣一斗粟，不与淮南舂。\n兄弟尚路人，吾心安所从。\n他人方寸间，山海几千重。\n轻言托朋友，对面九疑峰。\n开花必早落，桃李不如松。' },
  { title: '雉朝飞', author: '李白', poem: '麦陇青青三月时，白雉朝飞挟两雌。\n锦衣绣翼何离褷，犊牧采薪感之悲。\n春天和，白日暖。\n啄食饮泉勇气满，争雄鬬死绣颈断。\n雉子班奏急管弦，倾心酒美尽玉椀。\n枯杨枯杨尔生稊，我独七十而孤栖。\n弹弦写恨意不尽，瞑目归黄泥。' },
  { title: '上云乐', author: '李白', poem: '金天之西，白日所没。\n康老胡雏，生彼月窟。\n巉岩容仪，戌削风骨。\n碧玉炅炅双目瞳，黄金拳拳两鬓红。\n华盖垂下睫，嵩岳临上唇。\n不覩诡谲貌，岂知造化神。\n大道是文康之严父，元气乃文康之老亲。\n抚顶弄盘古，推车转天轮。\n云见日月初生时，铸冶火精与水银。\n阳乌未出谷，顾兔半藏身。\n女娲戏黄土，团作愚下人。\n散在六合间，蒙蒙若沙尘。\n生死了不尽，谁明此胡是仙真。\n西海栽若木，东溟植扶桑。\n别来几多时，枝叶万里长。\n中国有七圣，半路颓洪荒。\n陛下应运起，龙飞入咸阳。\n赤眉立盆子，白水兴汉光。\n叱咤四海动，洪涛为簸扬。\n举足蹋紫微，天关自开张。\n老胡感至德，东来进仙倡。\n五色师子，九苞凤皇。\n是老胡鸡犬，鸣舞飞帝乡。\n淋漓飒沓，进退成行。\n能胡歌，献汉酒。\n跪双膝，立两肘。\n散花指天举素手，拜龙颜，献圣寿。\n北斗戾，南山摧。\n天子九九八十一万岁，长倾万岁杯。' },
  { title: '白鸠辞', author: '李白', poem: '铿鸣钟，考朗鼓。\n歌白鸠，引拂舞。\n白鸠之白谁与隣，霜衣雪襟诚可珍。\n含哺七子能平均，食不噎，性安驯，首农政，鸣阳春。\n天子刻玉杖，镂形赐耆人。\n白鹭之白非纯真，外洁其色心匪仁。\n阙五德，无司晨，胡为啄我葭下之紫鳞。\n鹰鹯雕鹗，贪而好杀。\n凤凰虽大圣，不愿以为臣。' },
  { title: '日出行', author: '李白', poem: '日出东方隈，似从地底来。\n历天又入海，六龙所舍安在哉？\n其始与终古不息，人非元气安得与之久裴徊。\n草不谢荣于春风，木不怨落于秋天。\n谁挥鞭策驱四运，万物兴歇皆自然。\n羲和羲和，汝奚汨没于荒淫之波。\n鲁阳何德，驻景挥戈。\n逆道违天，矫诬实多。\n吾将囊括大块，浩然与溟涬同科。' },
  { title: '胡无人', author: '李白', poem: '严风吹霜海草凋，筋干精坚胡马骄。\n汉家战士三十万，将军兼领霍嫖姚。\n流星白羽腰间插，劒花秋莲光出匣。\n天兵照雪下玉关，虏箭如沙射金甲。\n云龙风虎尽交回，太白入月敌可摧。\n敌可摧，旄头灭，履胡之肠涉胡血。\n悬胡青天上，埋胡紫塞傍。\n胡无人，汉道昌。' },
  { title: '北风行', author: '李白', poem: '烛龙栖寒门，光曜犹旦开。\n日月照之何不及此，唯有北风号怒天上来。\n燕山雪花大如席，片片吹落轩辕台。\n幽州思妇十二月，停歌罢笑双蛾摧。\n倚门望行人，念君长城苦寒良可哀。\n别时提劒救边去，遗此虎纹金鞞靫。\n中有一双白羽箭，蜘蛛结网生尘埃。\n箭空在，人今战死不复回。\n不忍见此物，焚之已成灰。\n黄河捧土尚可塞，北风雨雪恨难裁。' },
  { title: '侠客行', author: '李白', poem: '赵客缦胡缨，吴钩霜雪明。\n银鞍照白马，飒沓如流星。\n十步杀一人，千里不留行。\n事了拂衣去，深藏身与名。\n闲过信陵饮，脱劒膝前横。\n将炙啖朱亥，持觞劝侯嬴。\n三杯吐然诺，五岳倒为轻。\n眼花耳热后，意气素霓生。\n救赵挥金槌，邯郸先震惊。\n千秋二壮士，烜赫大梁城。\n纵死侠骨香，不慙世上英。\n谁能书合下，白首太玄经。' },
  { title: '关山月', author: '李白', poem: '明月出天山，苍茫云海间。\n长风几万里，吹度玉门关。\n汉下白登道，胡窥青海湾。\n由来征战地，不见有人还。\n[戍]客望边色，思归多苦颜。\n高楼当此夜，叹息未应闲。' },
  { title: '独漉篇', author: '李白', poem: '独漉水中泥，水浊不见月。\n不见月尚可，水深行人没。\n越鸟从南来，胡鹰亦北渡。\n我欲弯弓向天射，惜其中道失归路。\n落叶别树，飘零随风。\n客无所托，悲与此同。\n罗帏舒卷，似有人开。\n明月直入，无心可猜。\n雄劒挂壁，时时龙鸣。\n不断犀象，绣涩苔生。\n国耻未雪，何由成名。\n神鹰梦泽，不顾鸱鸢。\n为君一击，鹏[抟]鹏九天。' },
  { title: '登高丘而望远', author: '李白', poem: '登高丘，望远海。\n六鼇骨已霜，三山流安在。\n扶桑半摧折，白日沈光彩。\n银台金阙如梦中，秦皇汉武空相待。\n精卫费木石，鼋鼍无所凭。\n君不见骊山茂陵尽灰灭，牧羊之子来攀登。\n盗贼劫宝玉，精灵竟何能。\n穷兵黩武今如此，鼎湖飞龙安可乘。' },
  { title: '阳春歌', author: '李白', poem: '长安白日照春空，绿杨结烟垂袅风。\n披香殿前花始红，流芳发色绣户中。\n绣户中，相经过，飞燕皇后轻身舞，紫宫夫人绝世歌。' },
  { title: '杨叛儿', author: '李白', poem: '君歌杨叛儿，妾劝新丰酒。\n何许最关人，乌啼白门柳。\n乌啼隐杨花，君醉留妾家。\n博山炉中沈香火，双烟一气凌紫霞。' },
  { title: '双燕离', author: '李白', poem: '双燕复双燕，双飞令人羡。\n玉楼珠阁不独栖，金窗绣户长相见。\n柏梁失火去，因入吴王宫。\n吴宫又焚荡，雏尽巢亦空。\n憔悴一身在，孀雌忆故雄。\n双飞难再得，伤我寸心中。' },
  { title: '山人劝酒', author: '李白', poem: '苍苍云松，落落绮皓。\n春风尔来为阿谁，蝴蝶忽然满芳草。\n秀眉霜雪颜桃花，骨青髓绿长美好。\n称是秦时避世人，劝酒相欢不知老。\n各守麋鹿志，耻随龙虎争。\n歘起佐太子，汉王乃复惊。\n顾谓戚夫人，彼翁羽翼成。\n归来商山下，泛若云无情。\n举觞酹巢由，洗耳何独清。\n浩歌望嵩岳，意气还相倾。' },
  { title: '于阗采花', author: '李白', poem: '于阗采花人，自言花相似。\n明妃一朝西入胡，胡中美女多羞死。\n乃知汉地多名姝，胡中无花可方比。\n丹青能令丑者妍，无盐翻在深宫里。\n自古妬蛾眉，胡沙埋皓齿。' },
  { title: '鞠歌行', author: '李白', poem: '玉不自言如桃李，鱼目笑之卞和耻。\n楚国青蝇何太多，连城白璧遭谗毁。\n荆山长号泣血人，忠臣死为刖足鬼。\n听曲知宁戚，夷吾因小妻。\n秦穆五羊皮，买死百里奚。\n洗拂青云上，当时贱如泥。\n朝歌鼓刀叟，虎变磻谿中。\n一举钓六合，遂荒营丘东。\n平生渭水曲，谁识此老翁。\n奈何今之人，双目送飞鸿。' },
  { title: '幽涧泉', author: '李白', poem: '拂彼白石，弹吾素琴。\n幽涧愀兮流泉深，善手明徽高张清。\n心寂历似千古，松飕飗兮万寻。\n中见愁猨吊影而危处兮，呌秋木而长吟。\n客有哀时失职而听者，泪淋浪以沾襟。\n乃缉商辍羽，潺湲成音。\n吾但写声发情于妙指，殊不知此曲之古今。\n幽涧泉，鸣深林。' },
  { title: '王昭君二首 一', author: '李白', poem: '汉家秦地月，流影照明妃。\n一上玉关道，天涯去不归。\n汉月还从东海出，明妃西嫁无来日。\n燕支长寒雪作花，蛾眉憔悴没胡沙。\n生乏黄金枉图画，死留青冢使人嗟。' },
  { title: '王昭君二首 二', author: '李白', poem: '昭君拂玉鞍，上马啼红颊。\n今日汉宫人，明朝胡地妾。' },
  { title: '中山孺子妾歌', author: '李白', poem: '中山孺子妾，特以色见珍。\n虽然不如延年妹，亦是当时绝世人。\n桃李出深井，花艳惊上春。\n一贵复一贱，关天岂由身。\n芙蓉老秋霜，团扇羞网尘。\n戚姬髡发入舂市，万古共悲辛。' },
  { title: '荆州歌', author: '李白', poem: '白帝城边足风波，瞿塘五月谁敢过。\n荆州麦熟茧成蛾，缫丝忆君头绪多，拨谷飞鸣奈妾何。' },
  { title: '雉子斑', author: '李白', poem: '辟邪伎作鼓吹惊，雉子班之奏曲成，喔咿振迅欲飞鸣。\n扇锦翼，雄风生。\n双雌同饮啄，趫悍谁能争。\n乍向草中耿介死，不求黄金笼下生。\n天地至广大，何惜遂物情。\n善卷让天子，务光亦逃名。\n所贵旷士怀，朗然合太清。' },
  { title: '相逢行', author: '李白', poem: '相逢红尘内，高揖黄金鞭。\n万户垂杨里，君家阿那边。' },
  { title: '有所思', author: '李白', poem: '我思仙人乃在碧海之东隅，海寒多天风，白波连山倒蓬壶。\n长鲸喷涌不可涉，抚心茫茫泪如珠。\n西来青鸟东飞去，愿寄一书谢麻姑。' },
  { title: '久别离', author: '李白', poem: '别来几春未还家，玉窗五见樱桃花。\n况有锦字书，开缄使人嗟。\n至此肠断彼心绝，云鬟绿鬓罢梳结，愁如回飙乱白雪。\n去年寄书报阳台，今年寄书重相催。\n东风兮东风，为我吹行云使西来。\n待来竟不来，落花寂寂委清苔。' },
  { title: '白头吟', author: '李白', poem: '锦水东北流，波荡双鸳鸯。\n雄巢汉宫树，雌弄秦草芳。\n宁同万死碎绮翼，不忍云间两分张。\n此时阿娇正娇妬，独坐长门愁日暮。\n但愿君恩顾妾深，岂惜黄金买词赋。\n相如作赋得黄金，丈夫好新多异心。\n一朝将聘茂陵女，文君因赠白头吟。\n东流不作西归水，落花辞条羞故林。\n兔丝固无情，随风任倾倒。\n谁使女萝枝，而来强萦抱。\n两草犹一心，人心不如草。\n莫卷龙须席，从他生网丝。\n且留琥珀枕，或有梦来时。\n覆水再收岂满杯，弃妾已去难重回。\n古来得意不相负，祇今惟见青陵台。' },
  { title: '采莲曲', author: '李白', poem: '若耶谿傍采莲女，笑隔荷花共人语。\n日照新妆水底明，风飘香袂空中举。\n岸上谁家游冶郎，三三五五暎垂杨。\n紫骝嘶入落花去，见此踟蹰空断肠。' },
  { title: '临江王节士歌', author: '李白', poem: '洞庭白波木叶稀，燕鸿始入吴云飞。\n吴云寒，燕鸿苦，风号沙宿潇湘浦。\n节士悲秋泪如雨，白日当天心。\n照之可以事明主，壮士愤，雄风生。\n安得倚天劒，跨海斩长鲸。' },
  { title: '司马将军歌', author: '李白', poem: '狂风吹古月，窃弄章华台。\n北落明星动光彩，南征猛将如云雷。\n手中电击倚天劒，直斩长鲸海水开。\n我见楼船壮心目，颇似龙骧下三蜀。\n扬兵习战张虎旗，江中白浪如银屋。\n身居玉帐临河魁，紫髯若戟冠崔嵬。\n细柳开营揖天子，始知灞上为婴孩。\n羌笛横吹阿亸回，向月楼中吹落梅。\n将军自起舞长劒，壮士呼声动九垓。\n功成献凯见明主，丹青画象麒麟台。' },
  { title: '君道曲', author: '李白', poem: '大君若天覆，广运无不至。\n轩后爪牙尝先太山稽，如心之使臂。\n小白鸿翼于夷吾，刘葛鱼水本无二。\n土校可成墙，积德为厚地。' },
  { title: '结袜子', author: '李白', poem: '燕南壮士吴门豪，筑中置铅鱼隐刀。\n感君恩重许君命，太山一掷轻鸿毛。' },
  { title: '结客少年场行', author: '李白', poem: '紫燕黄金瞳，啾啾摇绿鬉。\n平明相驰逐，结客洛门东。\n少年学劒术，凌轹白猨公。\n珠袍曳锦带，匕首插吴鸿。\n由来万夫勇，挟此生雄风。\n托交从剧孟，买醉入新丰。\n笑尽一杯酒，杀人都市中。\n羞道易水寒，从令日贯虹。\n燕丹事不立，虚没秦帝宫。\n舞阳死灰人，安可与成功。' },
  { title: '长干行二首 一', author: '李白', poem: '妾发初覆额，折花门前剧。\n郎骑竹马来，绕床弄青梅。\n同居长干里，两小无嫌猜。\n十四为君妇，羞颜未尝开。\n低头向暗壁，千唤不一回。\n十五始展眉，愿同尘与灰。\n常存抱柱信，岂上望夫台。\n十六君远行，瞿塘滟滪堆。\n五月不可触，猨声天上哀。\n门前迟行迹，一一生绿苔。\n苔深不能扫，落叶秋风早。\n八月胡蝶来，双飞西园草。\n感此伤妾心，坐愁红颜老。\n早晚下三巴，预将书报家。\n相迎不道远，直至长风沙。' },
  { title: '长干行二首 二', author: '李白', poem: '忆妾深闺里，烟尘不曾识。\n嫁与长干人，沙头候风色。\n五月南风兴，思君下巴陵。\n八月西风起，想君发扬子。\n去来悲如何，见少离别多。\n湘潭几日到，妾梦越风波。\n昨夜狂风度，吹折江头树。\n淼淼暗无边，行人在何处？\n好乘浮云骢，佳期兰渚东。\n鸳鸯绿蒲上，翡翠锦屏中。\n自怜十五余，颜色桃花红。\n那作商人妇，愁水复愁风。' },
  { title: '古朗月行', author: '李白', poem: '小时不识月，呼作白玉盘。\n又疑瑶台镜，飞在白云端。\n仙人垂两足，桂树作团团。\n白兔捣药成，问言与谁餐。\n蟾蜍蚀圆影，大明夜已残。\n羿昔落九乌，天人清且安。\n阴精此沦惑，去去不足观。\n忧来其如何，凄怆摧心肝。' },
  { title: '上之回', author: '李白', poem: '三十六离宫，楼台与天通。\n阁道步行月，美人愁烟空。\n恩疎宠不及，桃李伤春风。\n淫乐意何极，金舆向回中。\n万乘出黄道，千旗扬彩虹。\n前军细柳北，后骑甘泉东。\n岂问渭川老，宁邀襄野童。\n但慕瑶池宴，归来乐未穷。' },
  { title: '独不见', author: '李白', poem: '白马谁家子，黄龙边塞儿。\n天山三丈雪，岂是远行时。\n春蕙忽秋草，莎鸡鸣西池。\n风摧寒椶响，月入霜闺悲。\n忆与君别年，种桃齐蛾眉。\n桃今百余尺，花落成枯枝。\n终然独不见，流泪空自知。' },
  { title: '白纻辞三首 一', author: '李白', poem: '扬清歌，发皓齿，北方佳人东隣子。\n且吟白纻停绿水，长袖拂面为君起。\n寒云夜卷霜海空，胡风吹天飘塞鸿。\n玉颜满堂乐未终，馆娃日落歌吹蒙。' },
  { title: '白纻辞三首 二', author: '李白', poem: '月寒江清夜沈沈，美人一笑千黄金。\n垂罗舞縠扬哀音，郢中白雪且莫吟。\n子夜吴歌动君心，动君心，冀君赏。\n愿作天池双鸳鸯，一朝飞去青云上。' },
  { title: '白纻辞三首 三', author: '李白', poem: '吴刀剪彩缝舞衣，明妆丽服夺春晖。\n扬眉转袖若雪飞，倾城独立世所稀。\n激楚结风醉忘归，高堂月落烛已微，玉钗挂缨君莫违。' },
  { title: '鸣雁行', author: '李白', poem: '胡雁鸣，辞燕山，昨发委羽朝度关。\n一一衔芦枝，南飞散落天地间。\n连行接翼往复还，客居烟波寄湘吴。\n凌霜触雪毛体枯，畏逢矰缴惊相呼。\n闻弦虚坠良可吁，君更弹射何为乎。' },
  { title: '妾薄命', author: '李白', poem: '汉帝宠阿娇，贮之黄金屋。\n咳唾落九天，随风生珠玉。\n宠极爱还歇，妬深情却疎。\n长门一步地，不肯暂回车。\n雨落不上天，水覆难再收。\n君情与妾意，各自东西流。\n昔日芙蓉花，今成断根草。\n以色事他人，能得几时好。' },
  { title: '幽州胡马客歌', author: '李白', poem: '幽州胡马客，绿眼虎皮冠。\n笑拂两只箭，万人不可干。\n弯弓若转月，白雁落云端。\n双双掉鞭行，游猎向楼兰。\n出门不顾后，报国死何难。\n天骄五单于，狼戾好凶残。\n牛马散北海，割鲜若虎餐。\n虽居燕支山，不道朔雪寒。\n妇女马上笑，颜如赪玉盘。\n飜飞射鸟兽，花月醉雕鞍。\n旄头四光芒，争战若蜂攒。\n白刃洒赤血，流沙为之丹。\n名将古谁是，疲兵良可叹。\n何时天狼灭，父子得闲安。' },
  { title: '门有车马客行', author: '李白', poem: '门有车马宾，金鞍曜朱轮。\n谓从丹霄落，乃是故乡亲。\n呼儿扫中堂，坐客论悲辛。\n对酒两不饮，停觞泪盈巾。\n叹我万里游，飘飘三十春。\n空谈帝王略，紫绶不挂身。\n雄劒藏玉匣，阴符生素尘。\n廓落无所合，流离湘水滨。\n借问宗党间，多为泉下人。\n生苦百战役，死托万鬼隣。\n北风扬胡沙，埋翳周与秦。\n大运且如此，苍穹宁匪仁。\n恻怆竟何道，存亡任大钧。' },
  { title: '君子有所思行', author: '李白', poem: '紫阁连终南，青冥天倪色。\n凭崖望咸阳，宫阙罗北极。\n万井惊画出，九衢如弦直。\n渭水银河清，横天流不息。\n朝野盛文物，衣冠何翕赩。\n厩马散连山，军容威绝域。\n伊臯运元化，卫霍输筋力。\n歌钟乐未休，荣去老还逼。\n圆光过满缺，太阳移中昃。\n不散东海金，何争西飞匿。\n无作牛山悲，恻怆泪沾臆。' },
  { title: '东海有勇妇', author: '李白', poem: '梁山感杞妻，恸哭为之倾。\n金石忽𫏐开，都由激深情。\n东海有勇妇，何惭苏子卿。\n学劒越处子，超然若流星。\n损躯报夫雠，万死不顾生。\n白刃耀素雪，苍天感精诚。\n十步两躩跃，三呼一交兵。\n斩首掉国门，蹴踏五藏行。\n豁此伉俪愤，粲然大义明。\n北海李使君，飞章奏天庭。\n舍罪警风俗，流芳播沧瀛。\n名在列女籍，竹帛已光荣。\n淳于免诏狱，汉主为缇萦。\n津妾一櫂歌，脱父于严刑。\n十子若不肖，不如一女英。\n豫让斩空衣，有心竟无成。\n要离杀庆忌，壮夫所素轻。\n妻子亦何辜，焚之买虚声。\n岂如东海妇，事立独扬名。' },
  { title: '黄葛篇', author: '李白', poem: '黄葛生洛溪，黄花自绵幂。\n青烟蔓长条，缭绕几百尺。\n闺人费素手，采缉作𫄨绤。\n缝为绝国衣，远寄日南客。\n苍梧大火落，暑服莫轻掷。\n此物虽过时，是妾手中迹。' },
  { title: '白马篇', author: '李白', poem: '龙马花雪毛，金鞍五陵豪。\n秋霜切玉劒，落日明珠袍。\n鬬鸡事万乘，轩盖一何高。\n弓摧南山虎，手接太行猱。\n酒后竞风采，三杯弄宝刀。\n杀人如剪草，剧孟同游遨。\n发愤去函谷，从军向临洮。\n叱咤万战场，匈奴尽奔逃。\n归来使酒气，未肯拜萧曹。\n羞入原宪室，荒淫隐蓬蒿。' },
  { title: '凤吹笙曲', author: '李白', poem: '仙人十五爱吹笙，学得昆丘彩凤鸣。\n始闻炼气餐金液，复道朝天赴玉京。\n玉京迢迢几千里，凤笙去去无穷已。\n欲叹离声发绛唇，更嗟别调流纤指。\n此时惜别讵堪闻，此地相看未忍分。\n重吟真曲和清吹，却奏仙歌响绿云。\n绿云紫气向函关，访道应寻缑氏山。\n莫学吹笙王子晋，一遇浮丘断不还。' },
  { title: '怨歌行', author: '李白', poem: '十五入汉宫，花颜笑春红。\n君王选玉色，侍寝金屏中。\n荐枕娇夕月，卷衣恋春风。\n宁知赵飞燕，夺宠恨无穷。\n沈忧能伤人，绿鬓成霜蓬。\n一朝不得意，世事徒为空。\n鹔鹴换美酒，舞衣罢雕龙。\n寒苦不忍言，为君奏丝桐。\n肠断弦亦绝，悲心夜忡忡。' },
  { title: '塞下曲六首 一', author: '李白', poem: '五月天山雪，无花祗有寒。\n笛中闻折柳，春色未曾看。\n晓战随金鼓，宵眠抱玉鞍。\n愿将腰下劒，直为斩楼兰。' },
  { title: '塞下曲六首 二', author: '李白', poem: '天兵下北荒，胡马欲南饮。\n横戈从百战，直为衔恩甚。\n握雪海上餐，拂沙陇头寝。\n何当破月氏，然后方高枕。' },
  { title: '塞下曲六首 三', author: '李白', poem: '骏马似风飙，鸣鞭出渭桥。\n弯弓辞汉月，插羽破天骄。\n阵解星芒尽，营空海雾消。\n功成画麟阁，独有霍嫖姚。' },
  { title: '塞下曲六首 四', author: '李白', poem: '白马黄金塞，云砂遶梦思。\n那堪愁苦节，远忆边城儿。\n萤飞秋窗满，月度霜闺迟。\n摧残梧桐叶，萧飒沙棠枝。\n无时独不见，流泪空自知。' },
  { title: '塞下曲六首 五', author: '李白', poem: '塞虏乘秋下，天兵出汉家。\n将军分虎竹，战士卧龙沙。\n边月随弓影，胡霜拂劒花。\n玉关殊未入，少妇莫长嗟。' },
  { title: '塞下曲六首 六', author: '李白', poem: '烽火动沙漠，连照甘泉云。\n汉皇按劒起，还召李将军。\n兵气天上合，鼓声陇底闻。\n横行负勇气，一战净妖氛。' },
  { title: '来日大难', author: '李白', poem: '来日一身，携粮负薪。\n道长食尽，苦口焦唇。\n今日醉饱，乐过千春。\n仙人相存，诱我远学。\n海凌三山，陆憩五岳。\n乘龙天飞，目瞻两角。\n授以仙药，金丹满握。\n蟪蛄蒙恩，深愧短促。\n思填东海，强衔一木。\n道重天地，轩师广成。\n蝉翼九五，以求长生。\n下士大笑，如苍蝇声。' },
  { title: '塞上曲', author: '李白', poem: '大汉无中策，匈奴犯渭桥。\n五原秋草绿，胡马一何骄。\n命将征西极，横行阴山侧。\n燕支落汉家，妇女无华色。\n转战渡黄河，休兵乐事多。\n萧条清万里，瀚海寂无波。' },
  { title: '玉阶怨', author: '李白', poem: '玉阶生白露，夜久侵罗袜。\n却下水晶帘，玲珑望秋月。' },
  { title: '襄阳曲四首 一', author: '李白', poem: '襄阳行乐处，歌舞白铜鞮。\n江城回渌水，花月使人迷。' },
  { title: '襄阳曲四首 二', author: '李白', poem: '山公醉酒时，酩酊高阳下。\n头上白接䍠，倒着还骑马。' },
  { title: '襄阳曲四首 三', author: '李白', poem: '岘山临汉江，水绿沙如雪。\n上有堕泪碑，青苔久磨灭。' },
  { title: '襄阳曲四首 四', author: '李白', poem: '且醉习家池，莫看堕泪碑。\n山公欲上马，笑杀襄阳儿。' },
  { title: '大堤曲', author: '李白', poem: '汉水临襄阳，花开大堤暖。\n佳期大堤下，泪向南云满。\n春风无复情，吹我梦魂散。\n不见眼中人，天长音信断。' },
  { title: '宫中行乐词八首 一', author: '李白', poem: '小小生金屋，盈盈在紫微。\n山花插宝髻，石竹绣罗衣。\n每出深宫里，常随步辇归。\n只愁歌舞散，化作彩云飞。' },
  { title: '宫中行乐词八首 二', author: '李白', poem: '柳色黄金嫩，梨花白雪香。\n玉楼巢翡翠，金殿锁鸳鸯。\n选妓随雕辇，征歌出洞房。\n宫中谁第一，飞燕在昭阳。' },
  { title: '宫中行乐词八首 三', author: '李白', poem: '卢橘为秦树，蒲萄出汉宫。\n烟花宜落日，丝管醉春风。\n笛奏龙吟水，箫鸣凤下空。\n君王多乐事，还与万方同。' },
  { title: '宫中行乐词八首 四', author: '李白', poem: '玉树春归日，金宫乐事多。\n后庭朝未入，轻辇夜相过。\n笑出花间语，娇来竹下歌。\n莫教明月去，留着醉嫦蛾。' },
  { title: '宫中行乐词八首 五', author: '李白', poem: '绣户香风暖，纱窗曙色新。\n宫花争笑日，池草暗生春。\n绿树闻歌鸟，青楼见舞人。\n昭阳桃李月，罗绮自相亲。' },
  { title: '宫中行乐词八首 六', author: '李白', poem: '今日明光里，还须结伴游。\n春风开紫殿，天乐下朱楼。\n艳舞全知巧，娇歌半欲羞。\n更怜花月夜，宫女笑藏钩。' },
  { title: '宫中行乐词八首 七', author: '李白', poem: '寒雪梅中尽，春风柳上归。\n宫莺娇欲醉，檐燕语还飞。\n迟日明歌席，新花艳舞衣。\n晚来移彩仗，行乐泥光辉。' },
  { title: '宫中行乐词八首 八', author: '李白', poem: '水绿南薰殿，花红北阙楼。\n莺歌闻太液，凤吹绕瀛洲。\n素女鸣珠珮，天人弄彩毬。\n今朝风日好，宜入未央游。' },
  { title: '清平调词三首 一', author: '李白', poem: '云想衣裳花想容，春风拂槛露华浓。\n若非群玉山头见，会向瑶台月下逢。' },
  { title: '清平调词三首 二', author: '李白', poem: '一枝秾艳露凝香，云雨巫山枉断肠。\n借问汉宫谁得似，可怜飞燕倚新妆。' },
  { title: '清平调词三首 三', author: '李白', poem: '名花倾国两相欢，长得君王带笑看。\n觧释春风无限恨，沈香亭北倚阑干。' },
  { title: '入朝曲', author: '李白', poem: '金陵控海浦，渌水带吴京。\n铙歌列骑吹，飒沓引公卿。\n槌钟速严妆，伐鼓启重城。\n天子凭玉几，劒履若云行。\n日出照万户，簪裾烂明星。\n朝罢沐浴闲，遨游阆风亭。\n济济双阙下，欢娱乐恩荣。' },
  { title: '秦女休行', author: '李白', poem: '西门秦氏女，秀色如琼花。\n手挥白杨刀，清昼杀讐家。\n罗袖洒赤血，英气凌紫霞。\n直上西山去，关吏相邀遮。\n壻为燕国王，身被诏狱加。\n犯刑若履虎，不畏落爪牙。\n素颈未及断，摧眉伏泥沙。\n金鸡忽放赦，大辟得宽赊。\n何慙聂政姊，万古共惊嗟。' },
  { title: '秦女卷衣', author: '李白', poem: '天子居未央，妾侍卷衣裳。\n顾无紫宫宠，敢拂黄金床。\n水至亦不去，熊来尚可当。\n微身奉日月，飘若萤之光。\n愿君采葑菲，无以下体妨。' },
  { title: '东武吟', author: '李白', poem: '好古笑流俗，素闻贤达风。\n方希佐明主，长揖辞成功。\n白日在高天，回光烛微躬。\n恭承凤凰诏，歘起云萝中。\n清切紫霄迥，优游丹禁通。\n君王赐颜色，声价凌烟虹。\n乘舆拥翠盖，扈从金城东。\n宝马丽绝景，锦衣入新丰。\n依岩望松雪，对酒鸣丝桐。\n因学扬子云，献赋甘泉宫。\n天书美片善，清芬播无穷。\n归来入咸阳，谈笑皆王公。\n一朝去金马，飘落成飞蓬。\n宾客日疎散，玉樽亦已空。\n才力犹可倚，不慙世上雄。\n闲作东武吟，曲尽情未终。\n书此谢知己，吾寻黄绮翁。' },
  { title: '邯郸才人嫁为厮养卒妇', author: '李白', poem: '妾本崇台女，扬蛾入丹阙。\n自倚颜如花，宁知有凋歇。\n一辞玉阶下，去若朝云没。\n每忆邯郸城，深宫梦秋月。\n君王不可见，惆怅至明发。' },
  { title: '出自蓟北门行', author: '李白', poem: '虏阵横北荒，胡星耀精芒。\n羽书速惊电，烽火昼连光。\n虎竹救边急，戎车森已行。\n明主不安席，按劒心飞扬。\n推毂出猛将，连旗登战场。\n兵威冲绝幕，杀气凌穹苍。\n列卒赤山下，开营紫塞傍。\n孟冬风沙紧，旌旗飒凋伤。\n画角悲海月，征衣卷天霜。\n挥刃斩楼兰，弯弓射贤王。\n单于一平荡，种落自奔亡。\n收功报天子，行歌归咸阳。' },
  { title: '洛阳陌', author: '李白', poem: '白玉谁家郎，回车渡天津。\n看花东陌上，惊动洛阳人。' },
  { title: '北上行', author: '李白', poem: '北上何所苦，北上缘太行。\n磴道盘且峻，巉岩凌穹苍。\n马足蹶侧石，车轮摧高冈。\n沙尘接幽州，烽火连朔方。\n杀气毒劒戟，严风裂衣裳。\n奔鲸夹黄河，凿齿屯洛阳。\n前行无归日，返顾思旧乡。\n惨戚冰雪里，悲号绝中肠。\n尺布不掩体，皮肤剧枯桑。\n汲水涧谷阻，采薪陇坂长。\n猛虎又掉尾，磨牙皓秋霜。\n草木不可餐，饥饮零露浆。\n叹此北上苦，停骖为之伤。\n何日王道平，开颜覩天光。' },
  { title: '短歌行', author: '李白', poem: '白日何短短，百年苦易满。\n苍穹浩茫茫，万劫太极长。\n麻姑垂两鬓，一半已成霜。\n天公见玉女，大笑亿千场。\n吾欲揽六龙，回车挂扶桑。\n北斗酌美酒，劝龙各一觞。\n富贵非所愿，与人驻颜光。' },
  { title: '空城雀', author: '李白', poem: '嗷嗷空城雀，身计何戚促。\n本与鹪鹩群，不随凤凰族。\n提携四黄口，饮乳未尝足。\n食君糠粃余，尝恐乌鸢逐。\n耻涉太行险，羞营覆车粟。\n天命有定端，守分绝所欲。' },
  { title: '发白马', author: '李白', poem: '将军发白马，旌节度黄河。\n箫鼓聒川岳，沧溟涌涛波。\n武安有振瓦，易水无寒歌。\n铁骑若雪山，饮流涸滹沱。\n扬兵猎月窟，转战略朝那。\n倚劒登燕然，边烽列嵯峨。\n萧条万里外，耕作五原多。\n一扫清大漠，包虎戢金戈。' },
  { title: '陌上桑', author: '李白', poem: '美女渭桥东，春还事蚕作。\n五马如飞龙，青丝结金络。\n不知谁家子，调笑来相谑。\n妾本秦罗敷，玉颜艳名都。\n绿条映素手，采桑向城隅。\n使君且不顾，况复论秋胡。\n寒螀爱碧草，鸣凤栖青梧。\n托心自有处，但怪旁人愚。\n徒令白日暮，高驾空踟蹰。' },
  { title: '枯鱼过河泣', author: '李白', poem: '白龙改常服，偶被豫且制。\n谁使尔为鱼，徒劳诉天帝。\n作书报鲸鲵，勿恃风涛势。\n涛落归泥沙，翻遭蝼蚁噬。\n万乘慎出入，柏人以为识。' },
  { title: '丁督护歌', author: '李白', poem: '云阳上征去，两岸饶商贾。\n吴牛喘月时，拖船一何苦。\n水浊不可饮，壶浆半成土。\n一唱督护歌，心摧泪如雨。\n万人凿磐石，无由达江浒。\n君看石芒砀，掩泪悲千古。' },
  { title: '千里思', author: '李白', poem: '李陵没胡沙，苏武还汉家。\n迢迢五原关，朔雪乱边花。\n一去隔绝国，思归但长嗟。\n鸿雁向西北，因书报天涯。' },
  { title: '树中草', author: '李白', poem: '鸟衔野田草，误入枯桑里。\n客土植危根，逢春犹不死。\n草木虽无情，因依尚可生。\n如何同枝叶，各自有枯荣。' },
  { title: '君马黄', author: '李白', poem: '君马黄，我马白。\n马色虽不同，人心本无隔。\n共作游冶盘，双行洛阳陌。\n长劒既照曜，高冠何赩赫。\n各有千金裘，俱为五侯客。\n猛虎落陷穽，壮夫时屈厄。\n相知在急难，独好亦何益。' },
  { title: '拟古', author: '李白', poem: '融融白玉辉，暎我青蛾眉。\n宝镜似空水，落花如风吹。\n出门望帝子，荡漾不可期。\n安得黄鹤羽，一报佳人知。' },
  { title: '折杨柳', author: '李白', poem: '垂杨拂绿水，摇艳东风年。\n花明玉关雪，叶暖金牕烟。\n美人结长想，对此心凄然。\n攀条折春色，远寄龙庭前。' },
  { title: '少年子', author: '李白', poem: '青云年少子，挟弹章台左。\n鞍马四边开，突如流星过。\n金丸落飞鸟，夜入琼楼卧。\n夷齐是何人，独守西山饿。' },
  { title: '紫骝马', author: '李白', poem: '紫骝行且嘶，双翻碧玉蹄。\n卧流不肯渡，似惜锦障泥。\n白雪关山远，黄云海戍迷。\n挥鞭万里去，安得念春闺。' },
  { title: '少年行二首 一', author: '李白', poem: '击筑饮美酒，劒歌易水湄。\n经过燕太子，结托幷州儿。\n少年负壮气，奋烈自有时。\n因击鲁句践，争博勿相欺。' },
  { title: '少年行二首 二', author: '李白', poem: '五陵年少金市东，银鞍白马度春风。\n落花踏尽游何处，笑入胡姬酒肆中。' },
  { title: '白鼻䯄', author: '李白', poem: '银鞍白鼻䯄，绿地障泥锦。\n细雨春风花落时，挥鞭直就胡姬饮。' },
  { title: '豫章行', author: '李白', poem: '胡风吹代马，北拥鲁阳关。\n吴兵照海雪，西讨何时还。\n半渡上辽津，黄云惨无颜。\n老母与子别，呼天野草间。\n白马绕旌旗，悲鸣相追攀。\n白杨秋月苦，早落豫章山。\n本为休明人，斩虏素不闲。\n岂惜战鬬死，为君扫凶顽。\n精感石没羽，岂云惮险艰。\n楼船若鲸飞，波荡落星湾。\n此曲不可奏，三军鬓成斑。' },
  { title: '沐浴子', author: '李白', poem: '沐芳莫弹冠，浴兰莫振衣。\n处世忌太洁，至人贵藏晖。\n沧浪有钓叟，吾与尔同归。' },
  { title: '高句骊', author: '李白', poem: '金花折风帽，白马小迟回。\n翩翩舞广袖，似鸟海东来。' },
  { title: '舍利弗', author: '李白', poem: '金绳界宝地，珍木荫瑶池。\n云间妙音奏，天际法蠡吹。' },
  { title: '静夜思', author: '李白', poem: '床前看月光，疑是地上霜。\n举头望山月，低头思故乡。' },
  { title: '渌水曲', author: '李白', poem: '渌水明秋月，南湖采白苹。\n荷花娇欲语，愁杀荡舟人。' },
  { title: '凤凰曲', author: '李白', poem: '嬴女吹玉箫，吟弄天上春。\n青鸾不独去，更有携手人。\n影灭彩云断，遗声落西秦。' },
  { title: '凤台曲', author: '李白', poem: '尝闻秦帝女，传得凤凰声。\n是日逢仙子，当时别有情。\n人吹彩箫去，天借绿云迎。\n曲在身不返，空余弄玉名。' },
  { title: '从军行', author: '李白', poem: '从军玉门道，逐虏金微山。\n笛奏梅花曲，刀开明月环。\n鼓声鸣海上，兵气拥云间。\n愿斩单于首，长驱静铁关。' },
  { title: '秋思', author: '李白', poem: '春阳如昨日，碧树鸣黄鹂。\n芜然蕙草暮，飒尔凉风吹。\n天秋木叶下，月冷莎鸡悲。\n坐愁群芳歇，白露凋华滋。' },
  { title: '春思', author: '李白', poem: '燕草如碧丝，秦桑低绿枝。\n当君怀归日，是妾断肠时。\n春风不相识，何事入罗帏。' },
  { title: '子夜吴歌 春歌', author: '李白', poem: '秦地罗敷女，采桑绿水边。\n素手青条上，红妆白日鲜。\n蚕饥妾欲去，五马莫留连。' },
  { title: '子夜吴歌 夏歌', author: '李白', poem: '镜湖三百里，菡萏发荷花。\n五月西施采，人看隘若耶。\n回舟不待月，归去越王家。' },
  { title: '子夜吴歌 秋歌', author: '李白', poem: '长安一片月，万户捣衣声。\n秋风吹不尽，总是玉关情。\n何日平胡虏，良人罢远征。' },
  { title: '子夜吴歌 冬歌', author: '李白', poem: '明朝驿使发，一夜絮征袍。\n素手抽针冷，那堪把剪刀。\n裁缝寄远道，几日到临洮。' },
  { title: '对酒行', author: '李白', poem: '松子栖金华，安期入蓬海。\n此人古之仙，羽化竟何在。\n浮生速流电，倏忽变光彩。\n天地无凋换，容颜有迁改。\n对酒不肯饮，含情欲谁待。' },
  { title: '估客行', author: '李白', poem: '海客乘天风，将船远行役。\n譬如云中鸟，一去无踪迹。' },
  { title: '捣衣篇', author: '李白', poem: '闺里佳人年十余，嚬蛾对影恨离居。\n忽逢江上春归燕，衔得云中尺素书。\n玉手开缄长叹息，狂夫犹戍交河北。\n万里交河水北流，愿为双燕泛中洲。\n君边云拥青丝骑，妾处苔生红粉楼。\n楼上春风日将歇，谁能揽镜看愁发。\n晓吹员管随落花，夜捣戎衣向明月。\n明月高高刻漏长，真珠帘箔掩兰堂。\n横垂宝幄同心结，半拂琼筵苏合香。\n琼筵宝幄连枝锦，灯烛荧荧照孤寝。\n有便凭将金剪刀，为君留下相思枕。\n摘尽庭兰不见君，红巾拭泪生氤氲。\n明年若更征边塞，愿作阳台一叚云。' },
  { title: '少年行', author: '李白', poem: '君不见淮南少年游侠客，白日毬猎夜拥掷。\n呼卢百万终不惜，报雠千里如咫尺。\n少年游侠好经过，浑身装束皆绮罗。\n蕙兰相随喧妓女，风光去处满笙歌。\n骄矜自言不可有，侠士堂中养来久。\n好鞍好马乞与人，十千五千旋沽酒。\n赤心用尽为知己，黄金不惜栽桃李。\n桃李栽来几度春，一回花落一回新。\n府县尽为门下客，王侯皆是平交人。\n男儿百年且乐命，何须徇书受贫病。\n男儿百年且荣身，何须徇节甘风尘。\n衣冠半是征战士，穷儒浪作林泉民。\n遮莫枝根长百丈，不如当代多还往。\n遮莫姻亲连帝城，不如当身自簪缨。\n看取富贵眼前者，何用悠悠身后名。' },
  { title: '长歌行', author: '李白', poem: '桃李待日开，荣华照当年。\n东风动百物，草木尽欲言。\n枯枝无丑叶，涸水吐清泉。\n大力运天地，羲和无停鞭。\n功名不早着，竹帛将何宣。\n桃李务青春，谁能贯白日。\n富贵与神仙，蹉跎成两失。\n金石犹销铄，风霜无久质。\n畏落日月后，强欢歌与酒。\n秋霜不惜人，倏忽侵蒲柳。' },
  { title: '长相思 一', author: '李白', poem: '日色已尽花含烟，月明欲素愁不眠。\n赵瑟初停凤凰柱，蜀琴欲奏鸳鸯弦。\n此曲有意无人传，愿随春风寄燕然，忆君迢迢隔青天。\n昔日横波目，今成流泪泉。\n不信妾肠断，归来看取明镜前。' },
  { title: '长相思 二', author: '李白', poem: '美人在时花满堂，美人去后空余床。\n床中绣被卷不寝，至今三载犹闻香。\n香亦竟不灭，人亦竟不来。\n相思黄叶落，白露点青苔。' },
  { title: '猛虎行', author: '李白', poem: '朝作猛虎行，暮作猛虎吟。\n肠断非关陇头水，泪下不为雍门琴。\n旌旗缤纷两河道，战鼓惊山欲颠倒。\n秦人半作燕地囚，胡马翻衔洛阳草。\n一输一失关下兵，朝降夕叛幽蓟城。\n巨鼇未斩海水动，鱼龙奔走安得宁。\n颇似楚汉时，翻覆无定止。\n朝过博浪沙，暮入淮阴市。\n张良未遇韩信贫，刘项存亡在两臣。\n𫏐到下邳受兵略，来投漂母作主人。\n贤哲栖栖古如此，今时亦弃青云士。\n有策不敢犯龙鳞，窜身南国避胡尘。\n宝书玉劒挂高阁，金鞍骏马散故人。\n昨日方为宣城客，掣铃交通二千石。\n有时六博快壮心，遶床三匝呼一掷。\n楚人每道张旭奇，心藏风云世莫知。\n三吴邦伯皆顾盼，四海雄侠两追随。\n萧曹曾作沛中吏，攀龙附凤当有时。\n溧阳酒楼三月春，杨花茫茫愁杀人。\n胡雏绿眼吹玉笛，吴歌白纻飞梁尘。\n丈夫相见且为乐，槌牛挝鼓会众宾。\n我从此去钓东海，得鱼笑寄情相亲。' },
  { title: '去妇词', author: '李白', poem: '古来有弃妇，弃妇有归处。\n今日妾辞君，辞君遣何去。\n本家零落尽，恸哭来时路。\n忆昔未嫁君，闻君却周旋。\n绮罗锦绣段，有赠黄金千。\n十五许嫁君，二十移所天。\n自从结发日未几，离君缅山川。\n家家尽欢喜，孤妾长自怜。\n幽闺多怨思，盛色无十年。\n相思若循还，枕席生流泉。\n流泉咽不扫，独梦关山道。\n及此见君归，君归妾已老。\n物情恶衰贱，新宠方妍好。\n掩泪出故房，伤心剧秋草。\n自妾为君妻，君东妾在西。\n罗帏到晓恨，玉貌一生啼。\n自从离别久，不觉尘埃厚。\n尝嫌玳瑁孤，犹羡鸳鸯偶。\n岁华逐霜霰，贱妾何能久。\n寒沼落芙蓉，秋风散杨柳。\n以比顦顇颜，空持旧物还。\n余生欲何寄，谁肯相牵攀。\n君恩既断绝，相见何年月。\n悔倾连理杯，虚作同心结。\n女萝附青松，贵欲相依投。\n浮萍失绿水，教作若为流。\n不叹君弃妾，自叹妾缘业。\n忆昔初嫁君，小姑才倚床。\n今日妾辞君，小姑如妾长。\n回头语小姑，莫嫁如兄夫。' },
  { title: '襄阳歌', author: '李白', poem: '落日欲没岘山西，倒着接䍠花下迷。\n襄阳小儿齐拍手，拦街争唱白铜鞮。\n傍人借问笑何事，笑杀山翁醉似泥。\n鸬鹚杓，鹦鹉杯，百年三万六千日，一日须倾三百杯。\n遥看汉水鸭头绿，恰似葡萄初酦醅。\n此江若变作春酒，垒曲便筑糟丘台。\n千金骏马换小妾，笑坐雕鞍歌落梅。\n车傍侧挂一壶酒，凤笙龙管行相摧。\n咸阳市中叹黄犬，何如月下倾金罍。\n君不见晋朝羊公一片石，龟头剥落生莓苔。\n泪亦不能为之堕，心亦不能为之哀。\n清风朗月不用一钱买，玉山自倒非人推。\n舒州杓，力士铛，李白与尔同死生。\n襄王云雨今安在，江水东流猨夜声。' },
  { title: '南都行', author: '李白', poem: '南都信佳丽，武阙横西关。\n白水真人居，万商罗鄽阛。\n高楼对紫陌，甲第连青山。\n此地多英豪，邈然不可攀。\n陶朱与五羖，名播天壤间。\n丽华秀玉色，汉女娇朱颜。\n清歌遏流云，艳舞有余闲。\n遨游盛宛洛，冠盖随风还。\n走马红阳城，呼鹰白河湾。\n谁识卧龙客，长吟愁鬓斑。' },
  { title: '江上吟', author: '李白', poem: '木兰之枻沙棠舟，玉箫金管坐两头。\n美酒尊中置千斛，载妓随波任去留。\n仙人有待乘黄鹤，海客无心随白鸥。\n屈平词赋悬日月，楚王台榭空山丘。\n兴酣落笔摇五岳，诗成笑傲凌沧洲。\n功名富贵若长在，汉水亦应西北流。' },
  { title: '侍从宜春苑奉诏赋龙池柳色初青听新莺百啭歌', author: '李白', poem: '东风已绿瀛洲草，紫殿红楼觉春好，池南柳色半青青。\n萦烟袅娜拂绮城，垂丝百尺挂雕楹。\n上有好鸟相和鸣，间关早得春风情。\n春风卷入碧云去，千门万户皆春声。\n是时君王在镐京，五云垂晖耀紫清。\n仗出金宫随日转，天回玉辇绕花行。\n始向蓬莱看舞鹤，还过茝石听新莺。\n新莺飞绕上林苑，愿入箫韶杂凤笙。' },
  { title: '玉壶吟', author: '李白', poem: '烈士击玉壶，壮心惜暮年。\n三杯拂劒舞秋月，忽然高咏涕泗涟。\n凤凰初下紫泥诏，谒帝称觞登御筵。\n揄扬九重万乘主，谑浪赤墀青琐贤。\n朝天数换飞龙马，勅赐珊瑚白玉鞭。\n世人不识东方朔，大隐金门是谪仙。\n西施宜笑复宜嚬，丑女效之徒累身。\n君王虽爱蛾眉好，无奈宫中妬杀人。' },
  { title: '豳歌行上新平长史兄粲', author: '李白', poem: '豳谷稍稍振庭柯，泾水浩浩扬湍波。\n哀鸿酸嘶暮声急，愁云苍惨寒气多。\n忆昨去家此为客，荷花初红柳条碧。\n中宵出饮三百杯，明朝归揖二千石。\n宁知流寓变光辉，胡霜萧飒绕客衣。\n寒灰寂寞凭谁暖，落叶飘扬何处归。\n吾兄行乐穷曛旭，满堂有美颜如玉。\n赵女长歌入彩云，燕姬醉舞娇红烛。\n狐裘兽炭酌流霞，壮士悲吟宁见嗟。\n前荣后枯相翻覆，何惜余光及棣华。' },
  { title: '西岳云台歌送丹丘子', author: '李白', poem: '西岳峥嵘何壮哉，黄河如丝天际来。\n黄河万里触山动，盘涡毂转秦地雷。\n荣光休气纷五彩，千年一清圣人在。\n巨灵咆哮擘两山，洪波喷箭射东海。\n三峰却立如欲摧，翠崖丹谷高掌开。\n白帝金精运元气，石作莲花云作台。\n云台阁道连窈冥，中有不死丹丘生。\n明星玉女备洒扫，麻姑搔背指爪轻。\n我皇手把天地户，丹丘谈天与天语。\n九重出入生光辉，东来蓬莱复西归。\n玉浆傥惠故人饮，骑二茅龙上天飞。' },
  { title: '元丹丘歌', author: '李白', poem: '元丹丘，爱神仙，朝饮颍川之清流，暮还嵩岑之紫烟，三十六峰长周旋。\n长周旋，蹑星虹，身骑飞龙耳生风。\n横河跨海与天通，我知尔游心无穷。' },
  { title: '扶风豪士歌', author: '李白', poem: '洛阳三月飞胡沙，洛阳城中人怨嗟。\n天津流水波赤血，白骨相撑如乱麻。\n我亦东奔向吴国，浮云四塞道路赊。\n东方日出啼早鸦，城门人开扫落花。\n梧桐杨柳拂金井，来醉扶风豪士家。\n扶风豪士天下奇，意气相倾山可移。\n作人不倚将军势，饮酒岂顾尚书期。\n雕盘绮食会众客，吴歌赵舞香风吹。\n原尝春陵六国时，开心写意君所知。\n堂中各有三千士，明日报恩知是谁。\n抚长劒，一扬眉，清水白石何离离。\n脱吾帽，向君笑，饮君酒，为君吟。\n张良未逐赤松去，桥边黄石知我心。' },
  { title: '同族弟金城尉叔卿烛照山水壁画歌', author: '李白', poem: '高堂粉壁图蓬瀛，烛前一见沧洲清。\n洪波汹涌山峥嵘，皎若丹丘隔海望赤城。\n光中乍喜岚气灭，谓逢山阴晴后雪。\n回溪碧流寂无喧，又如秦人月下窥花源。\n了然不觉清心魂，祗将叠嶂鸣秋猨。\n与君对此欢未歇，放歌行吟达明发。\n却顾海客扬云帆，便欲因之向溟渤。' },
  { title: '白毫子歌', author: '李白', poem: '淮南小山白毫子，乃在淮南小山里。\n夜卧松下云，朝餐石中髓。\n小山连緜向江开，碧峰巉岩绿水回。\n余配白毫子，独酌流霞杯。\n拂花弄琴坐青苔，绿萝树下春风来。\n南窗萧飒松声起，凭崖一听清心耳。\n可得见，未得亲。\n八公携手五云去，空余桂树愁杀人。' },
  { title: '梁园吟', author: '李白', poem: '我浮黄云去京阙，挂席欲进波连山。\n天长水阔厌远涉，访古始及平台间。\n平台为客忧思多，对酒遂作梁园歌。\n却忆蓬池阮公咏，因吟渌水扬洪波。\n洪波浩荡迷旧国，路远西归安可得。\n人生达命岂暇愁，且饮美酒登高楼。\n平头奴子摇大扇，五月不热疑清秋。\n玉盘杨梅为君设，吴盐如花皎白雪。\n持盐把酒但饮之，莫学夷齐事高洁。\n昔人豪贵信陵君，今人耕种信陵坟。\n荒城虚照碧山月，古木尽入苍梧云。\n粱王宫阙今安在？枚马先归不相待。\n舞影歌声散绿池，空余汴水东流海。\n沈吟此事泪满衣，黄金买醉未能归。\n连呼五白行六博，分曹赌酒酣驰辉。\n歌且谣，意方远，东山高卧时起来，欲济苍生未应晚。' },
  { title: '鸣臯歌送岑征君', author: '李白', poem: '若有人兮思鸣臯，阻积雪兮心烦劳。\n洪河凌竞不可以径度，冰龙鳞兮难容舠。\n邈仙山之峻极兮，闻天籁之嘈嘈。\n霜厓缟皓以合沓兮，若长风扇海涌沧溟之波涛。\n玄猨绿罴，舔舕崟岌。\n危柯振石，骇胆栗魄，群呼而相号。\n峰峥嵘以路绝，挂星辰于岩㟼。\n送君之归兮，动鸣臯之新作。\n交鼓吹兮弹丝，觞清泠之池阁。\n君不行兮何待，若反顾之黄鹤。\n扫梁园之群英，振大雅于东洛。\n巾征轩兮历阻折，寻幽居兮越𪩘崿。\n盘白石兮坐素月，琴松风兮寂万壑。\n望不见兮心氛氲，萝冥冥兮霰纷纷。\n水横洞以下渌，波小声而上闻。\n虎啸谷而生风，龙藏溪而吐云。\n寡鹤清唳，饥鼯嚬呻。\n魂独处此幽默兮，愀空山而愁人。\n鸡聚族以争食，凤孤飞而无隣。\n蝘蜓嘲龙，鱼目混珍。\n嫫母衣锦，西施负薪。\n若使巢由桎梏于轩冕兮，亦奚异乎夔龙蹩躠于风尘。\n哭何苦而救楚，笑何夸而却秦。\n吾诚不能学二子沽名矫节以耀世兮，固将弃天地而遗身。\n白鸥兮飞来，长与君兮相亲。' },
  { title: '鸣臯歌奉饯从翁清归五厓山居', author: '李白', poem: '忆昨鸣臯梦里还，手弄素月清潭间。\n觉时枕席非碧山，侧身西望阻秦关。\n麒膦阁上春还早，著书却忆伊阳好。\n青松来风吹古道，绿萝飞花覆烟草。\n我家仙翁爱清真，才雄草圣凌古人，欲卧鸣臯绝世尘。\n鸣臯微茫在何处？五厓峡水横樵路。\n身披翠云裘，袖拂紫烟去。\n去时应过嵩少间，相思为折三花树。' },
  { title: '劳劳亭歌', author: '李白', poem: '金陵劳劳送客堂，蔓草离离生道傍。\n古情不尽东流水，此地悲风愁白杨。\n我乘素舸同康乐，朗咏清川飞夜霜。\n昔闻牛渚吟五章，今来何谢袁家郎。\n苦竹寒声动秋月，独宿空帘归梦长。' },
  { title: '横江词六首 一', author: '李白', poem: '人道横江好，侬道横江恶。\n一风三日吹倒山，白浪高于瓦官阁。' },
  { title: '横江词六首 二', author: '李白', poem: '海潮南去过浔阳，牛渚由来险马当。\n横江欲渡风波恶，一水牵愁万里长。' },
  { title: '横江词六首 三', author: '李白', poem: '横江西望阻西秦，汉水东连扬子津。\n白浪如山那可渡，狂风愁杀峭帆人。' },
  { title: '横江词六首 四', author: '李白', poem: '海神来过恶风回，浪打天门石壁开。\n浙江八月何如此，涛似连山喷雪来。' },
  { title: '横江词六首 五', author: '李白', poem: '横江馆前津吏迎，向余东指海云生。\n郎今欲渡缘何事，如此风波不可行。' },
  { title: '横江词六首 六', author: '李白', poem: '月晕天风雾不开，海鲸东蹙百川回。\n惊波一起三山动，公无渡河归去来。' },
  { title: '金陵城西楼月下吟', author: '李白', poem: '金陵夜寂凉风发，独上高楼望吴越。\n白云暎水摇空城，白露垂珠滴秋月。\n月下沈吟久不归，古来相接眼中稀。\n解道澄江净如练，令人长忆谢玄晖。' },
  { title: '东山吟', author: '李白', poem: '携妓东土山，怅然悲谢安。\n我妓今朝如花月，他妓古坟荒草寒。\n白鸡梦后三百岁，洒酒浇君同所欢。\n酣来自作青海舞，秋风吹落紫绮冠。\n彼亦一时，此亦一时，浩浩洪流之咏何必奇。' },
  { title: '僧伽歌', author: '李白', poem: '真僧法号号僧伽，有时与我论三车。\n问言诵咒几千徧，口道恒河沙复沙。\n此僧本住南天竺，为法头陀来此国。\n戒得长天秋月明，心如世上青莲色。\n意清净，貌棱棱，亦不减，亦不增。\n瓶里千年铁柱骨，手中万岁胡孙藤。\n嗟予落魄江淮久，罕遇真僧说空有。\n一言散尽波罗夷，再礼浑除犯轻垢。' },
  { title: '白云歌送刘十六归山', author: '李白', poem: '楚山秦山皆白云，白云处处长随君。\n长随君，君入楚山里，云亦随君渡湘水。\n湘水上，女萝衣，白云堪卧君早归。' },
  { title: '白云歌送友人', author: '李白', poem: '楚山秦山多白云，白云䖏䖏长随君。\n君今还入楚山里，云亦随君渡湘水。\n水上女萝衣白云，早卧早行君早起。' },
  { title: '金陵歌送别范宣', author: '李白', poem: '石头巉岩如虎踞，凌波欲过沧江去。\n钟山龙盘走势来，秀色横分历阳树。\n四十余帝三百秋，功名事迹随东流。\n白马小儿谁家子，泰清之岁来关囚。\n金陵昔时何壮哉，席卷英豪天下来。\n冠盖散为烟雾尽，金舆玉座成寒灰。\n扣劒悲吟空咄嗟，梁陈白骨乱如麻。\n天子龙沈景阳井，谁歌玉树后庭花。\n此地伤心不能道，目下离离长春草。\n送尔长江万里心，他年来访南山老。' },
  { title: '笑歌行', author: '李白', poem: '笑矣乎，笑矣乎！君不见曲如钩，古人知尔封公侯。\n君不见直如弦，古人知尔死道边。\n张仪所以只掉三寸舌，苏秦所以不垦二倾田。\n笑矣乎，笑矣乎！君不见沧浪老人歌一曲，还道沧浪濯吾足。\n平生不解谋此身，虚作离骚遣人读。\n笑矣乎，笑矣乎！赵有豫让楚屈平，卖身买得千年名。\n巢由洗耳有何益，夷齐饿死终无成。\n君爱身后名，我爱眼前酒。\n饮酒眼前乐，虚名何处有。\n男儿穷通当有时，曲腰向君君不知。\n猛虎不看几上肉，洪𬬻不铸囊中锥。\n笑矣乎，笑矣乎！宁武子，朱买臣，扣角行歌背负薪。\n今日逢君君不识，岂得不如佯狂人。' },
  { title: '悲歌行', author: '李白', poem: '悲来乎，悲来乎！主人有酒且莫斟，听我一曲悲来吟。\n悲来不吟还不笑，天下无人知我心。\n君有数斗酒，我有三尺琴。\n琴鸣酒乐两相得，一杯不啻千钧金。\n悲来乎，悲来乎！天虽长，地虽久，金玉满堂应不守。\n富贵百年能几何，死生一度人皆有。\n孤猨坐啼坟上月，且须一尽杯中酒。\n悲来乎，悲来乎！凤皇不至河无图，微子去之箕子奴。\n汉帝不忆李将军，楚王放却屈大夫。\n悲来乎，悲来乎！秦家李斯早追悔，虚名拨向身之外。\n范子何曾爱五湖，功成名遂身自退。\n劒是一夫用，书能知姓名。\n惠施不肯干万乘，卜式未必穷一经。\n还须黑头取方伯，莫谩白首为儒生。' },
  { title: '秋浦歌十七首 一', author: '李白', poem: '秋浦长似秋，萧条使人愁。\n客愁不可度，行上东大楼。\n正西望长安，下见江水流。\n寄言向江水，汝意忆侬不。\n遥传一掬泪，为我达扬州。' },
  { title: '秋浦歌十七首 二', author: '李白', poem: '秋浦猨夜愁，黄山堪白头。\n清溪非陇水，翻作断肠流。\n欲去不得去，薄游成久游。\n何年是归日，雨泪下孤舟。' },
  { title: '秋浦歌十七首 三', author: '李白', poem: '秋浦锦驼鸟，人间天上稀。\n山鸡羞渌水，不敢照毛衣。' },
  { title: '秋浦歌十七首 四', author: '李白', poem: '两鬓入秋浦，一朝飒已衰。\n猨声催白发，长短尽成丝。' },
  { title: '秋浦歌十七首 五', author: '李白', poem: '秋浦多白猨，超腾若飞雪。\n牵引条上儿，饮弄水中月。' },
  { title: '秋浦歌十七首 六', author: '李白', poem: '愁作秋浦客，强看秋浦花。\n山川如剡县，风日似长沙。' },
  { title: '秋浦歌十七首 七', author: '李白', poem: '醉上山公马，寒歌宁戚牛。\n空吟白石烂，泪满黑貂裘。' },
  { title: '秋浦歌十七首 八', author: '李白', poem: '秋浦千重岭，水车岭最奇。\n天倾欲堕石，水拂寄生枝。' },
  { title: '秋浦歌十七首 九', author: '李白', poem: '江祖一片石，青天扫画屏。\n题诗留万古，绿字锦苔生。' },
  { title: '秋浦歌十七首 十', author: '李白', poem: '千千石楠树，万万女贞林。\n山山白鹭满，涧涧白猨吟。\n君莫向秋浦，猨声碎客心。' },
  { title: '秋浦歌十七首 十一', author: '李白', poem: '逻人（一作「叉」）横鸟道，江祖出鱼梁。\n水急客舟（一作「行」）疾，山花拂面香。' },
  { title: '秋浦歌十七首 十二', author: '李白', poem: '水如一匹练，此地即平天。\n耐可乘明月，看花上酒船。' },
  { title: '秋浦歌十七首 十三', author: '李白', poem: '渌水净素月，月明白鹭飞。\n郎听采菱女，一道夜歌归。' },
  { title: '秋浦歌十七首 十四', author: '李白', poem: '炉火照天地，红星乱紫烟。\n赧郎明月夜，歌曲动寒川。' },
  { title: '秋浦歌十七首 十五', author: '李白', poem: '白发三千丈，缘愁似个长。\n不知明镜里，何处得秋霜。' },
  { title: '秋浦歌十七首 十六', author: '李白', poem: '秋浦田舍翁，采鱼水中宿。\n妻子张白鹇，结罝暎深竹。' },
  { title: '秋浦歌十七首 十七', author: '李白', poem: '桃波（一作「陂」）一步地，了了语声闻。\n暗与山僧别，低头礼白云。' },
  { title: '当涂赵炎少府粉图山水歌', author: '李白', poem: '峨眉高出西极天，罗浮直与南溟连。\n名公绎思挥彩笔，驱山走海置眼前。\n满堂空翠如可扫，赤城霞气苍梧烟。\n洞庭潇湘意渺绵，三江七泽情洄沿。\n惊涛汹涌向何处，孤舟一去迷归年。\n征帆不动亦不旋，飘如随风落天边。\n心摇目断兴难尽，几时可到三山巅。\n西峰峥嵘喷流泉，横石蹙水波潺湲。\n东厓合沓蔽轻雾，深林杂树空芊绵。\n此中冥昧失昼夜，隐几寂听无鸣蝉。\n长松之下列羽客，对坐不语南昌仙。\n南昌仙人赵夫子，妙年历落青云士。\n讼庭无事罗众宾，杳然如在丹青里。\n五色粉图安足珍，真仙可以全吾身。\n若待功成拂衣去，武陵桃花笑杀人。' },
  { title: '永王东巡歌十一首 一', author: '李白', poem: '永王正月东出师，天子遥分龙虎旗。\n楼船一举风波静，江汉翻为雁鹜池。' },
  { title: '永王东巡歌十一首 二', author: '李白', poem: '三川北虏乱如麻，四海南奔似永嘉。\n但用东山谢安石，为君谈笑静胡沙。' },
  { title: '永王东巡歌十一首 三', author: '李白', poem: '雷鼓嘈嘈喧武昌，云旗猎猎过寻阳。\n秋毫不犯三吴悦，春日遥看五色光。' },
  { title: '永王东巡歌十一首 四', author: '李白', poem: '龙蟠虎踞帝王州，帝子金陵访古丘。\n春风试暖昭阳殿，明月还过𫛛鹊楼。' },
  { title: '永王东巡歌十一首 五', author: '李白', poem: '二帝巡游俱未回，五陵松栢使人哀。\n诸侯不救河南地，更喜贤王远道来。' },
  { title: '永王东巡歌十一首 六', author: '李白', poem: '丹阳北固是吴关，画出楼台云水间。\n千岩烽火连沧海，两岸旌旗绕碧山。' },
  { title: '永王东巡歌十一首 七', author: '李白', poem: '王出三山按五湖，楼船跨海次陪都。\n战舰森森罗虎士，征帆一一引龙驹。' },
  { title: '永王东巡歌十一首 八', author: '李白', poem: '长风挂席势难回，海动山倾古月摧。\n君看帝子浮江日，何似龙骧出峡来。' },
  { title: '永王东巡歌十一首 九', author: '李白', poem: '祖龙浮海不成桥，汉武寻阳空射蛟。\n我王楼舰轻秦汉，却似文皇欲渡辽。' },
  { title: '永王东巡歌十一首 十', author: '李白', poem: '帝宠贤王入楚关，扫清江汉始应还。\n初从云梦开朱邸，更取金陵作小山。' },
  { title: '永王东巡歌十一首 十一', author: '李白', poem: '试借君王玉马鞭，指挥戎虏坐琼筵。\n南风一扫胡尘静，西入长安到日边。' },
  { title: '上皇西巡南京歌十首 一', author: '李白', poem: '胡尘轻拂建章台，圣主西巡蜀道来。\n劒壁门高五千尺，石为楼阁九天开。' },
  { title: '上皇西巡南京歌十首 二', author: '李白', poem: '九天开出一成都，万户千门入画图。\n草树云山如锦绣，秦川得及此间无。' },
  { title: '上皇西巡南京歌十首 三', author: '李白', poem: '华阳春树号新丰，行入新都若旧宫。\n柳色未饶秦地绿，花光不灭上阳红。' },
  { title: '上皇西巡南京歌十首 四', author: '李白', poem: '谁道君王行路难，六龙西幸万人欢。\n地转锦江成渭水，天回玉垒作长安。' },
  { title: '上皇西巡南京歌十首 五', author: '李白', poem: '万国同风共一时，锦江何谢曲江池。\n石镜更明天上月，后宫亲得照蛾眉。' },
  { title: '上皇西巡南京歌十首 六', author: '李白', poem: '濯锦清江万里流，云帆龙舸下扬州。\n北地虽夸上林苑，南京还有散花楼。' },
  { title: '上皇西巡南京歌十首 七', author: '李白', poem: '锦水东流绕锦城，星桥北挂象天星。\n四海此中朝圣主，峨眉山下列仙庭。' },
  { title: '上皇西巡南京歌十首 八', author: '李白', poem: '秦开蜀道置金牛，汉水元通星汉流。\n天子一行遗圣迹，锦城长作帝王州。' },
  { title: '上皇西巡南京歌十首 九', author: '李白', poem: '水绿天青不起尘，风光和暖胜三秦。\n万国烟花随玉辇，西来添作锦江春。' },
  { title: '上皇西巡南京歌十首 十', author: '李白', poem: '劒阁重关蜀北门，上皇归马若云屯。\n少帝长安开紫极，双悬日月照乾坤。' },
  { title: '峨眉山月歌', author: '李白', poem: '峨眉山月半轮秋，影入平羌江水流。\n夜发清溪向三峡，思君不见下渝州。' },
  { title: '峨眉山月歌送蜀僧晏入中京', author: '李白', poem: '我在巴东三峡时，西看明月忆峨眉。\n月出峨眉照沧海，与人万里长相随。\n黄鹤楼前月华白，此中忽见峨眉客。\n峨眉山月还送君，风吹西到长安陌。\n长安大道横九天，峨眉山月照秦川。\n黄金狮子乘高座，白玉麈尾谈重玄。\n我似浮云𣨼吴越，君逢圣主游丹阙。\n一振高名满帝都，归时还弄峨眉月。' },
  { title: '赤壁歌送别', author: '李白', poem: '二龙争战决雌雄，赤壁楼船扫地空。\n烈火张天照云海，周瑜于此破曹公。\n君去沧江望澄碧，鲸鲵唐突留余迹。\n一一书来报故人，我欲因之壮心魄。' },
  { title: '江夏行', author: '李白', poem: '忆昔娇小姿，春心亦自持。\n为言嫁夫壻，得免长相思。\n谁知嫁商贾，令人却愁苦。\n自从为夫妻，何曾在乡土。\n去年下扬州，相送黄鹤楼。\n眼看帆去远，心逐江水流。\n只言期一载，谁谓历三秋。\n使妾肠欲断，恨君情悠悠。\n东家西舍同时发，北去南来不逾月。\n未知行李游何方，作个音书能断绝。\n适来往南浦，欲问西江船。\n正见当垆女，红粧二八年。\n一种为人妻，独自多悲凄。\n对镜便垂泪，逢人只欲啼。\n不如轻薄儿，旦暮长相随。\n悔作商人妇，青春长别离。\n如今正好同懽乐，君去容华谁得知。' },
  { title: '怀仙歌', author: '李白', poem: '一鹤东飞过沧海，放心散漫知何在。\n仙人浩歌望我来，应攀玉树长相待。\n尧舜之事不足惊，自余嚣嚣直可轻。\n巨鼇莫戴三山去，我欲蓬莱顶上行。' },
  { title: '玉真仙人词', author: '李白', poem: '玉真之仙人，时往太华峰。\n清晨鸣天鼓，飙歘腾双龙。\n弄电不辍手，行云本无踪。\n几时入少室，王母应相逢。' },
  { title: '清溪行', author: '李白', poem: '清溪清我心，水色异诸水。\n借问新安江，见底何如此。\n人行明镜中，鸟度屏风里。\n向晚猩猩啼，空悲远游子。' },
  { title: '詶殷明佐见赠五云裘歌', author: '李白', poem: '我吟谢朓诗上语，朔风飒飒吹飞雨。\n谢朓已没青山空，后来继之有殷公。\n粉图珍裘五云色，晔如晴天散彩虹。\n文章彪炳光陆离，应是素娥玉女之所为。\n轻如松花落金粉，浓似苔锦含碧滋。\n远山积翠横海岛，残霞飞丹暎江草。\n凝毫采掇花露容，几年功成夺天造。\n故人赠我我不违，着令山水含清晖。\n顿惊谢康乐，诗兴生我衣。\n襟前林壑敛暝色，袖上云霞收夕霏。\n群仙长叹惊此物，千厓万岭相萦郁。\n身骑白鹿行飘飖，手翳紫芝笑披拂。\n相如不足跨鹔鹴，王恭鹤氅安可方。\n瑶台雪花数千点，片片吹落春风香。\n为君持此凌苍苍，上朝三十六玉皇。\n下窥夫子不可及，矫首相思空断肠。' },
  { title: '临路歌', author: '李白', poem: '大鹏飞兮振八裔，中天摧兮力不济。\n余风激兮万世，游扶桑兮挂石袂。\n后人得之传此，仲尼亡兮谁为出涕。' },
  { title: '古意', author: '李白', poem: '君为女萝草，妾作兔丝花。\n轻条不自引，为逐春风斜。\n百丈托远松，缠绵成一家。\n谁言会面易，各在青山厓。\n女萝发馨香，兔丝断人肠。\n枝枝相纠结，叶叶竞飘扬。\n生子不知根，因谁共芬芳。\n中巢双翡翠，上宿紫鸳鸯。\n若识二草心，海潮亦可量。' },
  { title: '山鹧鸪词', author: '李白', poem: '苦竹岭头秋月辉，苦竹南枝鹧鸪飞。\n嫁得燕山胡雁壻，欲衔我向雁门归。\n山鸡翟雉来相劝，南禽多被北禽欺。\n紫塞严霜如劒戟，苍梧欲巢难背违。\n我今誓死不能去，哀鸣惊呌泪沾衣。' },
  { title: '历阳壮士勤将军名思齐歌', author: '李白', poem: '太古历阳郡，化为洪川在。\n江山犹郁盘，龙虎秘光彩。\n蓄泄数千载，风云何霮䨴。\n特生勤将军，神力百夫倍。' },
  { title: '草书歌行', author: '李白', poem: '少年上人号怀素，草书天下称独步。\n墨池飞出北溟鱼，笔锋杀尽中山兔。\n八月九月天气凉，酒徒词客满高堂。\n牋麻素绢排数厢，宣州石砚墨色光。\n吾师醉后倚绳床，须臾扫尽数千张。\n飘风骤雨惊飒飒，落花飞雪何茫茫。\n起来向壁不停手，一行数字大如斗。\n怳怳如闻神鬼惊，时时只见龙蛇走。\n左盘右蹙如惊电，状同楚汉相攻战。\n湖南七郡凡几家，家家屏障书题徧。\n王逸少，张伯英，古来几许浪得名。\n张颠老死不足数，我师此义不师古。\n古来万事贵天生，何必要公孙大娘浑脱舞。' },
  { title: '和卢侍御通塘曲', author: '李白', poem: '君夸通塘好，通塘胜耶溪。\n通塘在何处，远在寻阳西。\n青萝袅袅挂烟树，白鹇处处聚沙堤。\n石门中断平湖出，百丈金潭照云日。\n何处沧浪垂钓翁，鼓櫂渔歌趣非一。\n相逢不相识，出没绕通塘。\n浦边清水明素足，别有浣沙吴女郎。\n行尽绿潭潭转幽，疑是武陵春碧流。\n秦人鸡犬桃花里，将比通塘渠见羞。\n通塘不忍别，十去九迟回。\n偶逢佳境心已醉，忽有一鸟从天来。\n月出青山送行子，四边苦竹秋声起。\n长吟白雪望星河，双垂两足扬素波。\n梁鸿德耀会稽日，宁知此中乐事多。' },
  { title: '赠孟浩然', author: '李白', poem: '吾爱孟夫子，风流天下闻。\n红颜弃轩冕，白首卧松云。\n醉月频中圣，迷花不事君。\n高山安可仰，徒此揖清芬。' },
  { title: '赠从兄襄阳少府皓', author: '李白', poem: '结发未识事，所交尽豪雄。\n却秦不受赏，击晋宁为功。\n小节岂足言，退耕舂陵东。\n归来无产业，生事如转蓬。\n一朝乌裘敝，百镒黄金空。\n弹劒徒激昂，出门悲路穷。\n吾兄青云士，然诺闻诸公。\n所以陈片言，片言贵情通。\n棣华傥不接，甘与秋草同。' },
  { title: '淮海对雪赠傅霭', author: '李白', poem: '朔雪落吴天，从风渡溟渤。\n海树成阳春，江沙浩明月。\n兴从剡溪起，思绕梁园发。\n寄君郢中歌，曲罢心断绝。' },
  { title: '赠徐安宜', author: '李白', poem: '白田见楚老，歌咏徐安宜。\n制锦不择地，操刀良在兹。\n清风动百里，惠化闻京师。\n浮人若云归，耕种满郊岐。\n川光净麦陇，日色明桑枝。\n讼息但长啸，宾来或解颐。\n青橙拂户牖，白水流园池。\n游子滞安邑，怀恩未忍辞。\n翳君树桃李，岁晚托深期。' },
  { title: '赠任城卢主簿', author: '李白', poem: '海鸟知天风，窜身鲁门东。\n临觞不能饮，矫翼思凌空。\n钟鼓不为乐，烟霜谁与同。\n归飞未忍去，流泪谢鸳鸿。' },
  { title: '早秋赠裴十七仲堪', author: '李白', poem: '远海动风色，吹愁落天涯。\n南星变大火，热气余丹霞。\n光景不可回，六龙转天车。\n荆人泣美玉，鲁叟悲匏瓜。\n功业若梦里，抚琴发长嗟。\n裴生信英迈，屈起多才华。\n历抵海岱豪，结交鲁朱家。\n复携两少女，艳色惊荷葩。\n双歌入青云，但惜白日斜。\n穷溟出宝贝，大泽饶龙蛇。\n明主傥见收，烟霞路非赊。\n时命若不会，归应炼丹砂。' },
  { title: '赠范金卿二首 一', author: '李白', poem: '君子枉清盼，不知东走迷。\n离家来几月，络纬鸣中闺。\n桃李君不言，攀花愿成蹊。\n那能吐芳信，惠好相招携。\n我有结绿珍，久藏浊水泥。\n时人弃此物，乃与燕珉齐。\n摭拭欲赠之，申眉路无梯。\n辽东慙白豕，楚客羞山鸡。\n徒有献芹心，终流泣玉啼。\n祗应自索漠，留舌示山妻。' },
  { title: '赠范金卿二首 二', author: '李白', poem: '范宰不买名，弦歌对前楹。\n为邦默自化，日觉冰壶清。\n百里鸡犬静，千庐机杼鸣。\n浮人少荡析，爱客多逢迎。\n游子覩嘉政，因之听颂声。' },
  { title: '赠瑕丘王少府', author: '李白', poem: '皎皎鸾凤姿，飘飘神仙气。\n梅生亦何事，来作南昌尉。\n清风佐鸣琴，寂寞道为贵。\n一见过所闻，操持难与群。\n毫挥鲁邑讼，目送瀛洲云。\n我隐屠钓下，尔当玉石分。\n无由接高论，空此仰清芬。' },
  { title: '东鲁见狄博通', author: '李白', poem: '去年别我向何处，有人传道游江东。\n谓言挂席度沧海，却来应是无长风。' },
  { title: '见京兆韦参军量移东阳二首 一', author: '李白', poem: '潮水还归海，流人却到吴。\n相逢问愁苦，泪尽日南珠。' },
  { title: '见京兆韦参军量移东阳二首 二', author: '李白', poem: '闻说金华渡，东连五百滩。\n全胜若耶好，莫道此行难。\n猨啸千谿合，松风五月寒。\n他年一携手，摇艇入新安。' },
  { title: '赠丹阳横山周处士惟长', author: '李白', poem: '周子横山隐，开门临城隅。\n连峰入户牖，胜概凌方壶。\n时作白纻词，放歌丹阳湖。\n水色傲溟渤，川光秀菰蒲。\n当其得意时，心与天壤俱。\n闲云随舒卷，安识身有无。\n抱石耻献玉，沈泉笑探珠。\n羽化如可作，相携上清都。' },
  { title: '玉真公主别馆苦雨赠卫尉张卿二首 一', author: '李白', poem: '秋坐金张馆，繁阴昼不开。\n空烟迷雨色，萧飒望中来。\n翳翳昏垫苦，沈沈忧恨催。\n清秋何以慰，白酒盈吾杯。\n吟咏思管乐，此人已成灰。\n独酌聊自勉，谁贵经纶才。\n弹劒谢公子，无鱼良可哀。' },
  { title: '玉真公主别馆苦雨赠卫尉张卿二首 二', author: '李白', poem: '苦雨思白日，浮云何由卷。\n稷卨和天人，阴阳乃骄蹇。\n秋霖剧倒井，昏雾横绝𪩘。\n欲往咫尺涂，遂成山川限。\n潨潨奔溜闻，浩浩惊波转。\n泥沙塞中途，牛马不可辨。\n饥从漂母食，闲缀羽陵简。\n园家逢秋蔬，藜藿不满眼。\n蟏蛸结思幽，蟋蟀伤褊浅。\n厨灶无青烟，刀机生绿藓。\n投筯解鹔鹴，换酒醉北堂。\n丹徒布衣者，慷慨未可量。\n何时黄金盘，一斛荐槟榔。\n功成拂衣去，摇曳沧洲傍。' },
  { title: '赠韦秘书子春二首 一', author: '李白', poem: '谷口郑子真，躬耕在岩石。\n高名动京师，天下皆籍籍。\n斯人竟不起，云卧从所适。\n苟无济代心，独善亦何益。\n惟君家世者，偃息逢休明。\n谈天信浩荡，说劒纷纵横。\n谢公不徒然，起来为苍生。\n秘书何寂寂，无乃羁豪英。\n且复归碧山，安能恋金阙。\n旧宅樵渔地，蓬蒿已应没。\n却顾女几峰，胡颜见云月。' },
  { title: '赠韦秘书子春二首 二', author: '李白', poem: '徒为风尘苦，一官已白须。\n气同万里合，访我来琼都。\n披云覩青天，扪虱话良图。\n留侯将绮里，出处未云殊。\n终与安社稷，功成去五湖。' },
  { title: '赠韦侍御黄裳二首 一', author: '李白', poem: '太华生长松，亭亭凌霜雪。\n天与百尺高，岂为微飙折。\n桃李卖阳艳，路人行且迷。\n春光扫地尽，碧叶成黄泥。\n愿君学长松，慎勿作桃李。\n受屈不改心，然后知君子。' },
  { title: '赠韦侍御黄裳二首 二', author: '李白', poem: '见君乘骢马，知上太山道。\n此地果摧轮，全身以为宝。\n我如丰年玉，弃置秋田草。\n但勖冰壶心，无为叹衰老。' },
  { title: '赠薛校书', author: '李白', poem: '我有吴越曲，无人知此音。\n姑苏成蔓草，麋鹿空悲吟。\n未夸观涛作，空郁钓鼇心。\n举手谢东海，虚行归故林。' },
  { title: '赠何七判官昌浩', author: '李白', poem: '有时忽惆怅，匡坐至夜分。\n平明空啸咤，思欲解世纷。\n心随长风去，吹散万里云。\n羞作济南生，九十诵古文。\n不然拂劒起，沙漠收奇勋。\n老死阡陌间，何因扬清芬。\n夫子今管乐，英才冠三军。\n终与同出处，岂将沮溺群。' },
  { title: '读诸葛武侯传书怀赠长安崔少府叔封昆季', author: '李白', poem: '汉道昔云季，群雄方战争。\n霸图各未立，割据资豪英。\n赤伏起颓运，卧龙得孔明。\n当其南阳时，陇亩躬自耕。\n鱼水三顾合，风云四海生。\n武侯立岷蜀，壮志吞咸京。\n何人先见许，但有崔州平。\n余亦草间人，颇怀拯物情。\n晚途值子玉，华发同衰荣。\n托意在经济，结交为弟兄。\n毋令管与鲍，千载独知名。' },
  { title: '赠郭将军', author: '李白', poem: '将军少年出武威，入掌银台护紫微。\n平明拂劒朝天去，薄暮垂鞭醉酒归。\n爱子临风吹玉笛，美人向月舞罗衣。\n畴昔雄豪如梦里，相逢且欲醉春晖。' },
  { title: '驾去温泉后赠杨山人', author: '李白', poem: '少年落魄楚汉间，风尘萧瑟多苦颜。\n自言管葛竟谁许，长吁莫错还闭关。\n一朝君王垂拂拭，剖心输丹雪胸臆。\n忽蒙白日回景光，直上青云生羽翼。\n幸陪鸾辇出鸿都，身骑飞龙天马驹。\n王公大人借颜色，金璋紫绶来相趋。\n当时结交何纷纷，片言道合惟有君。\n待吾尽节报明主，然后相携卧白云。' },
  { title: '温泉侍从归逢故人', author: '李白', poem: '汉帝长杨苑，夸胡羽猎归。\n子云叨侍从，献赋有光辉。\n激赏摇天笔，承恩赐御衣。\n逢君奏明主，他日共飜飞。' },
  { title: '赠裴十四', author: '李白', poem: '朝见裴叔则，朗如行玉山。\n黄河落天走东海，万里写入胸怀间。\n身骑白鼋不敢度，金高南山买君顾。\n裴回六合无相知，飘若浮云且西去。' },
  { title: '赠崔侍郎', author: '李白', poem: '黄河二尺鲤，本在孟津居。\n点额不成龙，归来伴凡鱼。\n故人东海客，一见借吹嘘。\n风涛傥相见，更欲凌昆墟。' },
  { title: '述德兼陈情上哥舒大夫', author: '李白', poem: '天为国家孕英才，森森矛戟拥灵台。\n浩荡深谋喷江海，纵横逸气走风雷。\n丈夫立身有如此，一呼三军皆披靡。\n卫青谩作大将军，白起真成一竖子。' },
  { title: '赠参寥子', author: '李白', poem: '白鹤飞天书，南荆访高士。\n五云在岘山，果得参寥子。\n肮脏辞故园，昂藏入君门。\n天子分玉帛，百官接话言。\n毫墨时洒落，探玄有奇作。\n着论穷天人，千春秘麟阁。\n长揖不受官，拂衣归林峦。\n余亦去金马，藤萝同所欢。\n相思在何处，桂树青云端。' },
  { title: '赠饶阳张司户燧', author: '李白', poem: '朝饮苍梧泉，夕栖碧海烟。\n宁知鸾凤意，远托椅桐前。\n慕蔺岂曩古，攀嵇是当年。\n愧非黄石老，安识子房贤。\n功业嗟落日，容华弃徂川。\n一语已道意，三山期着鞭。\n蹉跎人间世，寥落壶中天。\n独见游物祖，探元穷化先。\n何当共携手，相与排冥筌。' },
  { title: '赠清漳明府姪聿', author: '李白', poem: '我李百万叶，柯条布中州。\n天开青云器，日为苍生忧。\n小邑且割鸡，大刀伫烹牛。\n雷声动四境，惠与清漳流。\n弦歌咏唐尧，脱落隐簪组。\n心和得天真，风俗犹太古。\n牛羊散阡陌，夜寝不扃户。\n问此何以然，贤人宰吾土。\n举邑树桃李，垂阴亦流芬。\n河堤绕绿水，桑柘连青云。\n赵女不冶容，提笼昼成群。\n缲丝鸣机杼，百里声相闻。\n讼息鸟下堦，高卧披道帙。\n蒲鞭挂檐枝，示耻无扑抶。\n琴清月当户，人寂风入室。\n长啸无一言，陶然上皇逸。\n白玉壶冰水，壶中见底清。\n清光洞毫发，皎洁照群情。\n赵北美佳政，燕南播高名。\n过客览行谣，因之诵德声。' },
  { title: '赠临洺县令皓弟', author: '李白', poem: '陶令去彭泽，茫然太古心。\n大音自成曲，但奏无弦琴。\n钓水路非远，连鼇意何深。\n终期龙伯国，与尔相招寻。' },
  { title: '赠郭季鹰', author: '李白', poem: '河东郭有道，于世若浮云。\n盛德无我位，清光独暎君。\n耻将鸡并食，长与凤为群。\n一击九千仞，相期凌紫氛。' },
  { title: '邺中赠王大', author: '李白', poem: '一身竟无托，远与孤蓬征。\n千里失所依，复将落叶幷。\n中途偶良朋，问我将何行。\n欲献济时策，此心谁见明。\n君王制六合，海塞无交兵。\n壮士伏草间，沈忧乱纵横。\n飘飘不得意，昨发南都城。\n紫燕枥下嘶，青萍匣中鸣。\n投躯寄天下，长啸寻豪英。\n耻学瑯琊人，龙蟠事躬耕。\n富贵吾自取，建功及春荣。\n我愿执尔手，尔方达我情。\n相知同一己，岂惟弟与兄。\n抱子弄白云，琴歌发清声。\n临别意难尽，各希存令名。' },
  { title: '赠华州王司士', author: '李白', poem: '淮水不绝涛澜高，盛德未泯生英髦。\n知君先负庙堂器，今日还须赠宝刀。' },
  { title: '赠卢征君昆弟', author: '李白', poem: '明主访贤逸，云泉今已空。\n二卢竟不起，万乘高其风。\n河上喜相得，壶中趣每同。\n沧州即此地，观化游无穷。\n水落海上清，鼇背覩方蓬。\n与君弄倒景，携手凌星虹。' },
  { title: '赠新平少年', author: '李白', poem: '韩信在淮阴，少年相欺凌。\n屈体若无骨，壮心有所凭。\n一遭龙颜君，啸咤从此兴。\n千金答漂母，万古共嗟称。\n而我竟何为，寒苦坐相仍。\n长风入短袂，两手如怀冰。\n故友不相恤，新交宁见矜。\n摧残槛中虎，羁绁鞲上鹰。\n何时腾风云，搏击申所能。' },
  { title: '走笔赠独孤驸马', author: '李白', poem: '都尉朝天跃马归，香风吹人花乱飞。\n银鞍紫鞚照云日，左顾右盼生光辉。\n是时仆在金门里，待诏公车谒天子。\n长揖蒙垂国士恩，壮心剖出酬知己。\n一别蹉跎朝市间，青云之交不可攀。\n傥其公子重回顾，何必侯嬴长抱关。' },
  { title: '赠嵩山焦炼师', author: '李白', poem: '二室凌青天，三花含紫烟。\n中有蓬海客，宛疑麻姑仙。\n道在喧莫染，迹高想已绵。\n时餐金鹅蘂，屡读青苔篇。\n八极恣游憩，九垓长周旋。\n下瓢酌颍水，舞鹤来伊川。\n还归空山上，独拂秋霞眠。\n萝月挂朝镜，松风鸣夜弦。\n潜光隐嵩岳，炼魄栖云幄。\n霓裳何飘飖，凤吹转緜邈。\n愿同西王母，下顾东方朔。\n紫书傥可传，铭骨誓相学。' },
  { title: '口号赠征君鸿', author: '李白', poem: '陶令辞彭泽，梁鸿入会稽。\n我寻高士传，君与古人齐。\n云卧留丹壑，天书降紫泥。\n不知杨伯起，早晚向关西。' },
  { title: '上李邕', author: '李白', poem: '大鹏一日同风起，抟摇直上九万里。\n假令风歇时下来，犹能簸却沧溟水。\n世人见我恒殊调，闻余大言皆冷笑。\n宣父犹能畏后生，丈夫未可轻年少。' },
  { title: '赠张公洲革处士', author: '李白', poem: '列子居郑圃，不将众庶分。\n革侯遁南浦，常恐楚人闻。\n抱瓮灌秋蔬，心闲游天云。\n每将瓜田叟，耕种汉水𣸣。\n时登张公洲，入兽不乱群。\n井无桔槔事，门绝刺绣文。\n长揖二千石，远辞百里君。\n斯为真隐者，吾党慕清芬。' },
  { title: '秋日炼药院镊白发赠元六兄林宗', author: '李白', poem: '木落识岁秋，瓶冰知天寒。\n桂枝日已绿，拂雪凌云端。\n弱龄接光景，矫翼攀鸿鸾。\n投分三十载，荣枯同所欢。\n长吁望青云，镊白坐相看。\n秋颜入晓镜，壮发凋危冠。\n穷与鲍生贾，饥从漂母餐。\n时来极天人，道在岂吟叹。\n乐毅方适赵，苏秦初说韩。\n卷舒固在我，何事空摧残。' },
  { title: '书情题蔡舍人雄', author: '李白', poem: '尝高谢太傅，携妓东山门。\n楚舞醉碧云，吴歌断清猨。\n𫏐因苍生起，谈笑安黎元。\n余亦爱此人，丹霄冀飞飜。\n遭逢圣明主，敢进兴亡言。\n白璧竟何辜，青蝇遂成冤。\n一朝去京国，十载客梁园。\n猛犬吠九关，杀人愤精魂。\n皇穹雪冤枉，白日开氛昏。\n泰阶得夔龙，桃李满中原。\n倒海索明月，凌山采芳荪。\n媿无横草功，虚负雨露恩。\n迹谢云台阁，心随天马辕。\n夫子王佐才，而今复谁论。\n层飙振六翮，不日思腾骞。\n我纵五湖櫂，烟涛恣崩奔。\n梦钓子陵湍，英风缅犹存。\n彼希客星隐，弱植不足援。\n千里一回首，万里一长歌。\n黄鹤不复来，清风愁奈何。\n舟浮潇湘月，山倒洞庭波。\n投汨笑古人，临濠得天和。\n闲时田亩中，搔背牧鸡鹅。\n别离解相访，应在武陵多。' },
  { title: '忆襄阳旧游赠马少府巨', author: '李白', poem: '昔为大堤客，曾上山公楼。\n开牕碧嶂满，拂镜沧江流。\n高冠佩雄劒，长揖韩荆州。\n此地别夫子，今来思旧游。\n朱颜君未老，白发我先秋。\n壮志恐蹉跎，功名若云浮。\n归心结远梦，落日悬春愁。\n空思羊叔子，堕泪岘山头。' },
  { title: '对雪献从兄虞城宰', author: '李白', poem: '昨夜梁园里，弟寒兄不知。\n庭前看玉树，肠断忆连枝。' },
  { title: '访道安陵遇盖还为余造真箓临别留赠', author: '李白', poem: '清水见白石，仙人识青童。\n安陵盖夫子，十岁与天通。\n悬河与微言，谈论安可穷。\n能令二千石，抚背惊神聪。\n挥毫赠新诗，高价掩山东。\n至今平原客，感激慕清风。\n学道北海仙，传书蘂珠宫。\n丹田了玉阙，白日思云空。\n为我草真箓，天人慙妙工。\n七元洞豁落，八角辉星虹。\n三灾荡璇玑，蛟龙翼微躬。\n举手谢天地，虚无齐始终。\n黄金满高堂，荅荷难克充。\n下笑世上士，沈魂北罗酆。\n昔日万乘坟，今成一科蓬。\n赠言若可重，实此轻华嵩。' },
  { title: '赠崔郎中宗之', author: '李白', poem: '胡雁拂海翼，翱翔鸣素秋。\n惊云辞沙朔，飘荡迷河洲。\n有如飞蓬人，去逐万里游。\n登高望浮云，仿佛如旧丘。\n日从海傍没，水向天边流。\n长啸倚孤劒，目极心悠悠。\n岁晏归去来，富贵安可求。\n仲尼七十说，历聘莫见收。\n鲁连逃千金，珪组岂可酬。\n时哉苟不会，草木为我俦。\n希君同携手，长往南山幽。' },
  { title: '赠崔咨议', author: '李白', poem: '绿骥本天马，素非伏枥驹。\n长嘶向清风，倏忽凌九区。\n何言西北至，却走东南隅。\n世道有飜覆，前期难豫图。\n希君一翦拂，犹可骋中衢。' },
  { title: '赠升州王使君忠臣', author: '李白', poem: '六代帝王国，三吴佳丽城。\n贤人当重寄，天子借高名。\n巨海一边静，长江万里清。\n应须救赵策，未肯弃侯嬴。' },
  { title: '赠别从甥高五', author: '李白', poem: '鱼目高泰山，不如一玙璠。\n贤甥即明月，声价动天门。\n能成吾宅相，不减魏阳元。\n自顾寡筹略，功名安所存。\n五木思一掷，如绳系穷猨。\n枥中骏马空，堂上醉人喧。\n黄金久已罄，为报故交恩。\n闻君陇西行，使我惊心魂。\n与尔共飘飖，云天各飞飜。\n江水流或卷，此心难具论。\n贫家羞好客，语拙觉辞繁。\n三朝空错莫，对饭却惭冤。\n自笑我非夫，生事多契阔。\n蓄积万古愤，向谁得开豁。\n天地一浮云，此身乃毫末。\n忽见无端倪，太虚可包括。\n去去何足道，临岐空复愁。\n肝胆不楚越，山河亦衾裯。\n云龙若相从，明主会见收。\n成功解相访，溪水桃花流。' },
  { title: '赠裴司马', author: '李白', poem: '翡翠黄金缕，绣成歌舞衣。\n若无云间月，谁可比光辉。\n秀色一如此，多为众女讥。\n君恩移昔爱，失宠秋风归。\n愁苦不窥隣，泣上流黄机。\n天寒素手冷，夜长烛复微。\n十日不满匹，鬓蓬乱若丝。\n犹是可怜人，容华世中稀。\n向君发皓齿，顾我莫相违。' },
  { title: '叙旧赠江阳宰陆调', author: '李白', poem: '泰伯让天下，仲雍扬波涛。\n清风荡万古，迹与星辰高。\n开吴食东溟，陆氏世英髦。\n多君秉古节，岳立冠人曹。\n风流少年时，京洛事游遨。\n腰间延陵劒，玉带明珠袍。\n我昔鬬鸡徒，连延五陵豪。\n邀遮相组织，呵吓来煎熬。\n君开万丛人，鞍马皆辟易。\n告急清宪台，脱余北门厄。\n间宰江阳邑，翦棘树兰芳。\n城门何肃穆，五月飞秋霜。\n好鸟集珍木，高才列华堂。\n时从府中归，丝管俨成行。\n但苦隔远道，无由共衔觞。\n江北荷花开，江南杨梅熟。\n正好饮酒时，怀贤在心目。\n挂席拾海月，乘风下长川。\n多沽新丰醁，满载剡溪船。\n中途不遇人，直到尔门前。\n大笑同一醉，取乐平生年。' },
  { title: '赠从孙义兴宰铭', author: '李白', poem: '天子思茂宰，天枝得英才。\n朗然清秋月，独出映吴台。\n落笔生绮绣，操刀振风雷。\n蠖屈虽百里，鹏骞望三台。\n退食无外事，琴堂向山开。\n绿水寂以闲，白云有时来。\n河阳富奇藻，彭泽纵名杯。\n所恨不见之，犹如仰昭回。\n元恶昔滔天，疲人散幽草。\n惊川无活鳞，举邑罕遗老。\n誓雪会稽耻，将奔宛陵道。\n亚相素所重，投刃应桑林。\n独坐伤激扬，神融一开襟。\n弦歌欣再理，和乐醉人心。\n蠹政除害马，倾巢有归禽。\n壶浆候君来，聚舞共讴吟。\n农人弃簔笠，蚕女堕缨簪。\n欢笑相拜贺，则知惠爱深。\n历职吾所闻，称贤尔为最。\n化洽一邦上，名驰三江外。\n峻节贯云霄，通方堪远大。\n能文变风俗，好客留轩盖。\n他日一来游，因之严光濑。' },
  { title: '草创大还赠柳官迪', author: '李白', poem: '天地为橐籥，周流行太易。\n造化合元符，交媾腾精魄。\n自然成妙用，孰知其指的。\n罗络四季间，绵微无一隙。\n日月更出没，双光岂云只。\n姹女乘河车，黄金充辕轭。\n执枢相管辖，摧伏伤羽翮。\n朱鸟张炎威，白虎守本宅。\n相煎成苦老，消铄凝津液。\n髣髴明窗尘，死灰同至寂。\n捣冶入赤色，十二周律历。\n赫然称大还，与道本无隔。\n白日可抚弄，清都在咫尺。\n北酆落死名，南斗上生籍。\n抑予是何者，身在方士格。\n才术信纵横，世途自轻掷。\n吾求仙弃俗，君晓损胜益。\n不向金阙游，思为玉皇客。\n鸾车速风电，龙骑无鞭策。\n一举上九天，相携同所适。' },
  { title: '赠崔司户文昆季', author: '李白', poem: '双珠出海底，俱是连城珍。\n明月两特达，余辉傍照人。\n英声振名都，高价动殊邻。\n岂伊箕山故，特以风期亲。\n惟昔不自媒，担簦西入秦。\n攀龙九天上，忝列岁星臣。\n布衣侍丹墀，密勿草丝纶。\n才微惠渥重，谗巧生缁磷。\n一去已十载，今来复盈旬。\n清霜入晓鬓，白露生衣巾。\n侧见绿水亭，开门列华茵。\n千金散义士，四坐无凡宾。\n欲折月中桂，持为寒者薪。\n路傍已窃笑，天路将何因。\n垂恩傥丘山，报德有微身。' },
  { title: '赠溧阳宋少府陟', author: '李白', poem: '李斯未相秦，且逐东门兔。\n宋玉事襄王，能为高唐赋。\n常闻绿水曲，忽此相逢遇。\n扫洒青天开，豁然披云雾。\n葳甤紫鸾鸟，巢在昆山树。\n惊风西北吹，飞落南溟去。\n早怀经济策，特受龙颜顾。\n白玉栖青蝇，君臣忽行路。\n人生感分义，贵欲呈丹素。\n何日清中原，相期廓天步。' },
  { title: '戏赠郑溧阳', author: '李白', poem: '陶令日日醉，不知五柳春。\n素琴本无弦，漉酒用葛巾。\n清风北牕下，自谓羲皇人。\n何时到栗里，一见平生亲。' },
  { title: '赠僧崖公', author: '李白', poem: '昔在朗陵东，学禅白眉空。\n大地了镜彻，回旋寄轮风。\n揽彼造化力，持为我神通。\n晚谒泰山君，亲见日没云。\n中夜卧山月，拂衣逃人群。\n授余金仙道，旷劫未始闻。\n冥机发天光，独朗谢垢氛。\n虚舟不系物，观化游江𣸣。\n江𣸣遇同声，道崖乃僧英。\n说法动海岳，游方化公卿。\n手秉玉麈尾，如登白楼亭。\n微言注百川，亹亹信可听。\n一风鼓群有，万籁各自鸣。\n启闭八牕牖，托宿掣电霆。\n自言历天台，搏壁蹑翠屏。\n凌兢石桥去，恍惚入青冥。\n昔往今来归，绝景无不经。\n何日更携手，乘杯向蓬瀛。' },
  { title: '游溧阳北湖亭望瓦屋山怀古赠同旅', author: '李白', poem: '朝登北湖亭，遥望瓦屋山。\n天清白露下，始觉秋风还。\n游子托主人，仰观眉睫间。\n目色送飞鸿，邈然不可攀。\n长吁相劝勉，何事来吴关。\n闻有贞义女，振穷溧水湾。\n清光了在眼，白日如披颜。\n高坟五六墩，崒兀栖猛虎。\n遗迹翳九泉，芳名动千古。\n子胥昔乞食，此女倾壶浆。\n运开展宿愤，入楚鞭平王。\n凛冽天地间，闻名若怀霜。\n壮夫或未达，十步九太行。\n与君拂衣去，万里同翱翔。' },
  { title: '醉后赠从甥高镇', author: '李白', poem: '马上相逢揖马鞭，客中相见客中怜。\n欲邀击筑悲歌饮，正值倾家无酒钱。\n江东风光不借人，枉杀落花空自春。\n黄金逐手快意尽，昨日破产今朝贫。\n丈夫何事空啸傲，不如烧却头上巾。\n君为进士不得进，我被秋霜生旅鬓。\n时清不及英豪人，三尺童儿重廉蔺。\n匣中盘劒装䱜鱼，闲在腰间未用渠。\n且将换酒与君醉，醉归托宿吴专诸。' },
  { title: '崔秋浦柳少府', author: '李白', poem: '秋浦旧萧索，公庭人吏稀。\n因君树桃李，此地忽芳菲。\n摇笔望白云，开帘当翠微。\n时来引山月，纵酒酣清晖。\n而我爱夫子，淹留未忍归。' },
  { title: '赠崔秋浦三首 一', author: '李白', poem: '吾爱崔秋浦，宛然陶令风。\n门前五杨柳，井上二梧桐。\n山鸟下厅事，檐花落酒中。\n怀君未忍去，惆怅意无穷。' },
  { title: '赠崔秋浦三首 二', author: '李白', poem: '崔令学陶令，北牕常昼眠。\n抱琴时弄月，取意任无弦。\n见客但倾酒，为官不爱钱。\n东臯春事起，种黍早归田。' },
  { title: '赠崔秋浦三首 三', author: '李白', poem: '河阳花作县，秋浦玉为人。\n地逐名贤好，风随惠化春。\n水从天汉落，山逼画屏新。\n应念金门客，投沙吊楚臣。' },
  { title: '望九华赠青阳韦仲堪', author: '李白', poem: '昔在九江上，遥望九华峰。\n天河挂绿水，秀出九芙蓉。\n我欲一挥手，谁人可相从。\n君为东道主，于此卧云松。' },
  { title: '赠王判官时余归隐居庐山屏风叠', author: '李白', poem: '昔别黄鹤楼，蹉跎淮海秋。\n俱飘零落叶，各散洞庭流。\n中年不相见，蹭蹬游吴越。\n何处我思君，天台绿萝月。\n会稽风月好，却遶剡溪回。\n云山海上出，人物镜中来。\n一度浙江北，十年醉楚台。\n荆门倒屈宋，梁苑倾邹枚。\n苦笑我夸诞，知音安在哉。\n大盗割鸿沟，如风扫秋叶。\n吾非济代人，且隐屏风叠。\n中夜天中望，忆君思见君。\n明朝拂衣去，永与海鸥群。' },
  { title: '在水军宴赠幕府诸侍御', author: '李白', poem: '月化五白龙，翻飞凌九天。\n胡沙惊北海，电扫洛阳川。\n虏箭雨宫阙，皇舆成播迁。\n英王受庙略，秉钺清南边。\n云旗卷海雪，金戟罗江烟。\n聚散百万人，弛张在一贤。\n霜台降群彦，水国奉戎旃。\n绣服开宴语，天人借楼船。\n如登黄金台，遥谒紫霞仙。\n卷身编蓬下，冥机四十年。\n宁知草间人，腰下有龙泉。\n浮云在一决，誓欲清幽燕。\n愿与四座公，静谈金匮篇。\n齐心戴朝恩，不惜微躯捐。\n所冀旄头灭，功成追鲁连。' },
  { title: '赠武十七谔幷序', author: '李白', poem: '马如一匹练，明日过吴门。\n乃是要离客，西来欲报恩。\n笑开燕匕首，拂拭竟无言。\n狄犬吠清洛，天津成塞垣。\n爱子隔东鲁，空悲断肠猨。\n林回弃白璧，千里阻同奔。\n君为我致之，轻赍涉淮原。\n精诚合天道，不媿远游魂。' },
  { title: '赠闾丘宿松', author: '李白', poem: '阮籍为太守，乘驴上东平。\n剖竹十日间，一朝风化清。\n偶来拂衣去，谁测主人情。\n夫子理宿松，浮云知古城。\n扫地物莽然，秋来百草生。\n飞鸟还旧巢，迁人返躬耕。\n何慙宓子贱，不减陶渊明。\n吾知千载后，却掩二贤名。' },
  { title: '狱中上崔相涣', author: '李白', poem: '胡马渡洛水，血流征战场。\n千门闭秋景，万姓危朝霜。\n贤相燮元气，再欣海县康。\n台庭有夔龙，列宿粲成行。\n羽翼三元圣，发辉两太阳。\n应念覆盆下，雪泣拜天光。' },
  { title: '中丞宋公以吴兵三千赴河南军次寻阳脱余之囚参谋幕府因赠之', author: '李白', poem: '独坐清天下，专征出海隅。\n九江皆渡虎，三郡尽还珠。\n组练明秋浦，楼船入郢都。\n风高初选将，月满欲平胡。\n杀气横千里，军声动九区。\n白猨慙劒术，黄石借兵符。\n戎虏行当翦，鲸鲵立可诛。\n自怜非剧孟，何以佐良图。' },
  { title: '流夜郎赠辛判官', author: '李白', poem: '昔在长安醉花柳，五侯七贵同杯酒。\n气岸遥凌豪士前，风流肯落他人后。\n夫子红颜我少年，章台走马着金鞭。\n文章献纳麒麟殿，歌舞淹留玳瑁筵。\n与君自谓长如此，宁知草动风尘起。\n函谷忽惊胡马来，秦宫桃李向明开。\n我愁远谪夜郎去，何日金鸡放赦回。' },
  { title: '赠刘都使', author: '李白', poem: '东平刘公干，南国秀余芳。\n一鸣即朱绂，五十佩银章。\n饮冰事戎幕，衣锦华水乡。\n铜官几万人，诤讼清玉堂。\n吐言贵珠玉，落笔回风霜。\n而我谢明主，衔哀投夜郎。\n归家酒债多，门客粲成行。\n高谈满四座，一日倾千觞。\n所求竟无绪，裘马欲摧藏。\n主人若不顾，明发钓沧浪。' },
  { title: '赠常侍御', author: '李白', poem: '安石在东山，无心济天下。\n一起振横流，功成复潇洒。\n大贤有卷舒，季叶轻风雅。\n匡复属何人，君为知音者。\n传闻武安将，气振长平瓦。\n燕赵期洗清，周秦保宗社。\n登朝若有言，为访南迁贾。' },
  { title: '赠易秀才', author: '李白', poem: '少年解长劒，投赠即分离。\n何不断犀象，精光暗往时。\n蹉跎君自惜，窜逐我因谁。\n地远虞翻老，秋深宋玉悲。\n空摧芳桂色，不屈古松姿。\n感激平生意，劳歌寄此辞。' },
  { title: '江夏使君叔席上赠史郎中', author: '李白', poem: '凤凰丹禁里，衔出紫泥书。\n昔放三湘去，今还万死余。\n仙郎久为别，客舍问何如。\n涸辙思流水，浮云失旧居。\n多慙华省贵，不以逐臣疎。\n复如竹林下，叨陪芳宴初。\n希君生羽翼，一化北溟鱼。' },
  { title: '博平郑太守自庐山千里相寻入江夏北市门见访却之武陵立马赠别', author: '李白', poem: '大梁贵公子，气盖苍梧云。\n若无三千客，谁道信陵君。\n救赵复存魏，英威天下闻。\n邯郸能屈节，访博从毛薛。\n夷门得隐沦，而与侯生亲。\n仍要鼓刀者，乃是袖槌人。\n好士不尽心，何能保其身。\n多君重然诺，意气遥相托。\n五马入市门，金鞍照城郭。\n都忘虎竹贵，且与荷衣乐。\n去去桃花源，何时见归轩。\n相思无终极，肠断朗江猨。' },
  { title: '江上赠窦长史', author: '李白', poem: '汉求季布鲁朱家，楚逐伍胥去章华。\n万里南迁夜郎国，三年归及长风沙。\n闻道青云贵公子，锦帆游戏西江水。\n人疑天上坐楼船，水净霞明两重绮。\n相约相期何太深，棹歌摇艇月中寻。\n不同珠履三千客，别欲论交一片心。' },
  { title: '赠王汉阳', author: '李白', poem: '天落白玉棺，王乔辞叶县。\n一去未千年，汉阳复相见。\n犹乘飞凫舃，尚识仙人面。\n鬓发何青青，童颜皎如练。\n吾曾弄海水，清浅嗟三变。\n果惬麻姑言，时光速流电。\n与君数杯酒，可以穷欢宴。\n白云归去来，何事坐交战。' },
  { title: '赠汉阳辅录事二首 一', author: '李白', poem: '闻君罢官意，我抱汉川湄。\n借问久疎索，何如听讼时。\n天清江月白，心静海鸥知。\n应念投沙客，空余吊屈悲。' },
  { title: '赠汉阳辅录事二首 二', author: '李白', poem: '鹦鹉洲横汉阳渡，水引寒烟没江树。\n南浦登楼不见君，君今罢官在何处？\n汉口双鱼白锦鳞，令传尺素报情人。\n其中字数无多少，祗是相思秋复春。' },
  { title: '江夏赠韦南陵冰', author: '李白', poem: '胡骄马惊沙尘起，胡雏饮马天津水。\n君为张掖近酒泉，我窜三巴九千里。\n天地再新法令宽，夜郎迁客带霜寒。\n西忆故人不可见，东风吹梦到长安。\n宁期此地忽相遇，惊喜茫如堕烟雾。\n玉箫金管喧四筵，苦心不得申长句。\n昨日绣衣倾绿尊，病如桃李竟何言。\n昔骑天子大宛马，今乘款段诸侯门。\n赖遇南平豁方寸，复兼夫子持清论。\n有似山开万里云，四望青天解人闷。\n人闷还心闷，苦辛长苦辛。\n愁来饮酒二千石，寒灰重暖生阳春。\n山公醉后能骑马，别是风流贤主人。\n头陀云月多僧气，山水何曾称人意。\n不然鸣笳按鼓戏沧流，呼取江南女儿歌櫂讴。\n我且为君槌碎黄鹤楼，君亦为吾倒却鹉鹦洲。\n赤壁争雄如梦里，且须歌舞宽离忧。' },
  { title: '赠卢司户', author: '李白', poem: '秋色无远近，出门尽寒山。\n白云遥相识，待我苍梧间。\n借问卢耽鹤，西飞几岁还。' },
  { title: '赠从弟南平太守之遥二首 一', author: '李白', poem: '少年不得意，落魄无安居。\n愿随任公子，欲钓吞舟鱼。\n常时饮酒逐风景，壮心遂与功名疎。\n兰生谷底人不锄，云在高山空卷舒。\n汉家天子驰驷马，赤军蜀道迎相如。\n天门九重谒圣人，龙颜一解四海春。\n彤庭左右呼万岁，拜贺明主收沈沦。\n翰林秉笔回英眄，麟阁峥嵘谁可见。\n承恩初入银台门，著书独在金銮殿。\n龙钩雕镫白玉鞍，象床绮席黄金盘。\n当时笑我微贱者，却来请谒为交欢。\n一朝谢病游江海，畴昔相知几人在。\n前门长揖后门关，今日结交明日改。\n爱君山岳心不移，随君云雾迷所为。\n梦得池塘生春草，使我长价登楼诗。\n别后遥传临海作，可见羊何共和之。' },
  { title: '赠从弟南平太守之遥二首 二', author: '李白', poem: '东平与南平，今古两步兵。\n素心爱美酒，不是顾专城。\n谪官桃源去，寻花几处行。\n秦人如旧识，出户笑相迎。' },
  { title: '赠潘侍御论钱少阳', author: '李白', poem: '绣衣柱史何昂藏，铁冠白笔横秋霜。\n三军论事多引纳，堦前虎士罗干将。\n虽无二十五老者，且有一翁钱少阳。\n眉如松雪齐四皓，调笑可以安储皇。\n君能礼此最下士，九州拭目瞻清光。' },
  { title: '赠柳圆', author: '李白', poem: '竹实满秋浦，凤来何苦饥。\n还同月下鹊，三绕未安枝。\n夫子即琼树，倾柯拂羽仪。\n怀君恋明德，归去日相思。' },
  { title: '流夜郎半道承恩放还兼欣克复之美书怀示息秀才', author: '李白', poem: '黄口为人罗，白龙乃鱼服。\n得罪岂怨天，以愚陷网目。\n鲸鲵未翦灭，豺狼屡翻覆。\n悲作楚地囚，何日秦庭哭。\n遭逢二明主，前后两迁逐。\n去国愁夜郎，投身窜荒谷。\n半道雪屯蒙，旷如鸟出笼。\n遥欣克复美，光武安可同。\n天子巡劒阁，储皇守扶风。\n扬袂正北辰，开襟揽群雄。\n胡兵出月窟，雷破关之东。\n左扫因右拂，旋收洛阳宫。\n回舆入咸京，席卷六合通。\n叱咤开帝业，手成天地功。\n大驾还长安，两日忽再中。\n一朝让宝位，劒玺传无穷。\n媿无秋豪力，谁念矍铄翁。\n弋者何所慕，高飞仰冥鸿。\n弃劒学丹砂，临𬬻双玉童。\n寄言息夫子，岁晚陟方蓬。' },
  { title: '赠张相镐二首 一', author: '李白', poem: '神器难窃弄，天狼窥紫宸。\n六龙迁白日，四海暗胡尘。\n昊穹降元宰，君子方经纶。\n澹然养浩气，歘起持大钧。\n秀骨象山岳，英谋合鬼神。\n佐汉解鸿门，生唐为后身。\n拥旄秉金钺，伐鼓乘朱轮。\n虎将如雷霆，总戎向东巡。\n诸侯拜马首，猛士骑鲸鳞。\n泽被鱼鸟悦，令行草木春。\n圣智不失时，建功及良辰。\n丑虏安足纪，可贻帼与巾。\n倒泻溟海珠，尽为入幕珍。\n冯异献赤伏，邓生倏来臻。\n庶同昆阳举，再覩汉仪新。\n昔为管将鲍，中奔吴隔秦。\n一生欲报主，百代思荣亲。\n其事竟不就，哀哉难重陈。\n卧病宿松山，苍茫空四邻。\n风云激壮志，枯槁惊常伦。\n闻君自天来，目张气益振。\n亚夫得剧孟，敌国空无人。\n扪虱对桓公，愿得论悲辛。\n大块方噫气，何辞鼓青苹。\n斯言傥不合，归老汉江滨。' },
  { title: '赠张相镐二首 二', author: '李白', poem: '本家陇西人，先为汉边将。\n功略葢天地，名飞青云上。\n苦战竟不侯，富年颇惆怅。\n世传崆峒勇，气激金风壮。\n英烈遗厥孙，百代神犹王。\n十五观奇书，作赋凌相如。\n龙颜惠殊宠，麟阁凭天居。\n晚途未云已，蹭蹬遭谗毁。\n想像晋末时，崩腾胡尘起。\n衣冠陷锋镝，戎虏盈朝市。\n石勒窥神州，刘聪劫天子。\n抚劒夜吟啸，雄心日千里。\n誓欲斩鲸鲵，澄清洛阳水。\n六合洒霖雨，万物无雕枯。\n我挥一杯水，自笑何区区。\n因人耻成事，贵欲决良图。\n灭虏不言功，飘然陟蓬壶。\n惟有安期舃，留之沧海隅。' },
  { title: '闻谢杨儿吟猛虎词因此有赠', author: '李白', poem: '同州隔秋浦，闻吟猛虎词。\n晨朝来借问，知是谢杨儿。' },
  { title: '宿清溪主人', author: '李白', poem: '夜到清溪宿，主人碧岩里。\n檐楹挂星斗，枕席响风水。\n月落西山时，啾啾夜猨起。' },
  { title: '系寻阳上崔相涣三首 一', author: '李白', poem: '邯郸四十万，同日陷长平。\n能回造化笔，或冀一人生。' },
  { title: '系寻阳上崔相涣三首 二', author: '李白', poem: '毛遂不堕井，曾参宁杀人。\n虚言误公子，投杼惑慈亲。\n白璧双明月，方知一玉真。' },
  { title: '系寻阳上崔相涣三首 三', author: '李白', poem: '虚传一片雨，枉作阳台神。\n纵为梦里相随去，不是襄王倾国人。' },
  { title: '巴陵赠贾舍人', author: '李白', poem: '贾生西望忆京华，湘浦南迁莫怨嗟。\n圣主恩深汉文帝，怜君不遣到长沙。' },
  { title: '赠别舍人弟台卿之江南', author: '李白', poem: '去国客行远，还山秋梦长。\n梧桐落金井，一叶飞银床。\n觉罢揽明镜，鬓毛飒已霜。\n良图委蔓草，古貌成枯桑。\n欲道心下事，时人疑夜光。\n因为洞庭叶，飘落之潇湘。\n令弟经济士，谪居我何伤。\n潜虬隐尺水，着论谈兴亡。\n客遇王子乔，口传不死方。\n入洞过天地，登真朝玉皇。\n吾将抚尔背，挥手遂翱翔。' },
  { title: '醉后赠王历阳', author: '李白', poem: '书秃千兔毫，诗裁两牛腰。\n笔踪起龙虎，舞袖拂云霄。\n双歌二胡姬，更奏远清朝。\n举酒挑朔雪，从君不相饶。' },
  { title: '赠历阳褚司马', author: '李白', poem: '北堂千万寿，侍奉有光辉。\n先同稚子舞，更着老莱衣。\n因为小儿啼，醉倒月下归。\n人闻无此乐，此乐世中稀。' },
  { title: '对雪醉后赠王历阳', author: '李白', poem: '有身莫犯飞龙鳞，有手莫辫猛虎须。\n君看昔日汝南市，白头仙人隐玉壶。\n子猷闻风动窻竹，相邀共醉杯中绿。\n历阳何异山阴时，白雪飞花乱人目。\n君家有酒我何愁，客多乐酣秉烛游。\n谢尚自能鸜鹆舞，相如免脱鹔鹴裘。\n清晨鼓櫂过江去，千里相思明月楼。' },
  { title: '赠宣城赵太守悦', author: '李白', poem: '赵得宝符盛，山河功业存。\n三千堂上客，出入拥平原。\n六国扬清风，英声何喧喧。\n大贤茂远业，虎竹光南藩。\n错落千丈松，虬龙盘古根。\n枝下无俗草，所植唯兰荪。\n忆在南阳时，始承国士恩。\n公为柱下史，脱绣归田园。\n伊昔簪白笔，幽都逐游魂。\n持斧冠三军，霜清天北门。\n差池宰两邑，鹗立重飞翻。\n焚香入兰台，起草多芳言。\n夔龙一顾重，矫翼凌翔鹓。\n赤县扬雷声，彊项闻至尊。\n惊飙颓秀木，迹屈道弥敦。\n出牧历三郡，所居猛兽奔。\n迁人同卫鹤，谬上懿公轩。\n自笑东郭履，侧慙狐白温。\n闲吟步竹石，精义忘朝昏。\n顦顇成丑士，风云何足论。\n狝猴骑土牛，羸马夹双辕。\n愿借羲皇景，为人照覆盆。\n溟海不振荡，何由纵鹏鲲。\n所期玄津白，倜傥假腾骞。' },
  { title: '赠从弟宣州长史昭', author: '李白', poem: '淮南望江南，千里碧山对。\n我行倦过之，半落青天外。\n宗英佐雄郡，水陆相控带。\n长川豁中流，千里泻吴会。\n君心亦如此，包纳无小大。\n摇笔起风霜，推诚结仁爱。\n讼庭垂桃李，宾馆罗轩盖。\n何意苍梧云，飘然忽相会。\n才将圣不偶，命与时俱背。\n独立山海间，空老圣明代。\n知音不易得，抚劒增感慨。\n当结九万期，中途莫先退。' },
  { title: '于五松山赠南陵常赞府', author: '李白', poem: '为草当作兰，为木当作松。\n兰秋香风远，松寒不改容。\n松兰相因依，萧艾徒丰茸。\n鸡与鸡幷食，鸾与鸾同枝。\n拣珠去沙砾，但有珠相随。\n远客投名贤，真堪写怀抱。\n若惜方寸心，待谁可倾倒。\n虞卿弃赵相，便与魏齐行。\n海上五百人，同日死田横。\n当时不好贤，岂传千古名。\n愿君同心人，于我少留情。\n寂寂还寂寂，出门迷所适。\n长铗归来乎，秋风思归客。' },
  { title: '自梁园至敬亭山见会公谈陵阳山水兼期同游因有此赠', author: '李白', poem: '我随秋风来，瑶草恐衰歇。\n中途寡名山，安得弄云月。\n渡江如昨日，黄叶向人飞。\n敬亭惬素尚，弭櫂流清辉。\n冰谷明且秀，陵峦抱江城。\n粲粲吴与史，衣冠耀天京。\n水国饶英奇，潜光卧幽草。\n会公真名僧，所在即为宝。\n开堂振白拂，高论横青云。\n雪山扫粉壁，墨客多新文。\n为余话幽栖，且述陵阳美。\n天开白龙潭，月映清秋水。\n黄山望石柱，突兀谁开张。\n黄鹤久不来，子安在苍茫。\n东南焉可穷，山鸟飞绝处。\n稠叠千万峰，相连入云去。\n闻此期振策，归来空闭关。\n相思如明月，可望不可攀。\n何当移白足，早晚凌苍山。\n且寄一书札，令予解愁颜。' },
  { title: '赠友人三首 一', author: '李白', poem: '兰生不当户，别是闲庭草。\n夙被霜露欺，红荣已先老。\n谬接瑶华枝，结根君王池。\n顾无馨香美，叨沐清风吹。\n余芳若可佩，卒岁长相随。' },
  { title: '赠友人三首 二', author: '李白', poem: '袖中赵匕首，买自徐夫人。\n玉匣闭霜雪，经燕复历秦。\n其事竟不捷，沦落归沙尘。\n持此愿投赠，与君同急难。\n荆卿一去后，壮士多摧残。\n长号易水上，为我扬波澜。\n凿井当及泉，张帆当济川。\n廉夫唯重义，骏马不劳鞭。\n人生贵相知，何必金与钱。' },
  { title: '赠友人三首 三', author: '李白', poem: '慢世薄功业，非无胷中画。\n谑浪万古贤，以为儿童剧。\n立产如广费，匡君怀长策。\n但苦山北寒，谁知道南宅。\n岁酒上逐风，霜鬓两边白。\n蜀主思孔明，晋家望安石。\n时人列五鼎，谈笑期一掷。\n虎伏被胡尘，渔歌游海滨。\n弊裘耻妻嫂，长劒托交亲。\n夫子秉家义，群公难与隣。\n莫持西江水，空许东溟臣。\n他日青云去，黄金报主人。' },
  { title: '陈情赠友人', author: '李白', poem: '延陵有宝劒，价重千黄金。\n观风历上国，暗许故人深。\n归来挂坟松，万古知其心。\n懦夫感达节，壮士激青衿。\n鲍生荐夷吾，一举置齐相。\n斯人无良朋，岂有青云望。\n临财不苟取，推分固词让。\n后世称其贤，英风邈难尚。\n论交但若此，友道孰云丧。\n多君骋逸藻，掩映当时人。\n舒文振颓波，秉德冠彝伦。\n卜居乃此地，共井为比隣。\n清琴弄云月，美酒娱冬春。\n薄德中见捐，忽之如遗尘。\n英豪未豹变，自古多艰辛。\n他人纵以疎，君意宜独亲。\n奈何成离居，相去复几许。\n飘风吹云霓，蔽目不得语。\n投珠冀相报，按劒恐相距。\n所思采芳兰，欲赠隔荆渚。\n沈忧心若醉，积恨泪如雨。\n愿假东壁辉，余光照贫女。' },
  { title: '赠从弟冽', author: '李白', poem: '楚人不识凤，重价求山鸡。\n献主昔云是，今来方觉迷。\n自居漆园北，久别咸阳西。\n风飘落日去，节变流莺啼。\n桃李寒未开，幽关岂来蹊。\n逢君发花萼，若与青云齐。\n及此桑叶绿，春蚕起中闺。\n日出布谷鸣，田家拥锄犂。\n顾余乏尺土，东作谁相携。\n傅说降霖雨，公输造云梯。\n羌戎事未息，君子悲涂泥。\n报国有长策，成功羞执珪。\n无由谒明主，杖策还蓬藜。\n他年尔相访，知我在磻溪。' },
  { title: '赠闾丘处士', author: '李白', poem: '贤人有素业，乃在沙塘陂。\n竹影扫秋月，荷衣落古池。\n闲读山海经，散帙卧遥帷。\n且耽田家乐，遂旷林中期。\n野酌劝芳酒，园蔬烹露葵。\n如能树桃李，为我结茅茨。' },
  { title: '赠钱征君少阳', author: '李白', poem: '白玉一杯酒，绿杨三月时。\n春风余几日，两鬓各成丝。\n秉烛唯须饮，投竿也未迟。\n如逢渭川猎，犹可帝王师。' },
  { title: '赠宣州灵源寺仲濬公', author: '李白', poem: '敬亭白云气，秀色连苍梧。\n下映双溪水，如天落镜湖。\n此中积龙象，独许濬公殊。\n风韵逸江左，文章动海隅。\n观心同水月，解领得明珠。\n今日逢支遁，高谈出有无。' },
  { title: '赠僧朝美', author: '李白', poem: '水客凌洪波，长鲸涌溟海。\n百川随龙舟，嘘吸竟安在。\n中有不死者，探得明月珠。\n高价倾宇宙，余辉照江湖。\n苞卷金缕褐，萧然若空无。\n谁人识此宝，窃笑有狂夫。\n了心何言说，各勉黄金躯。' },
  { title: '赠僧行融', author: '李白', poem: '梁有汤惠休，常从鲍照游。\n峨眉史怀一，独映陈公出。\n卓绝二道人，结交凤与麟。\n行融亦俊发，吾知有英骨。\n海若不隐珠，骊龙吐明月。\n大海乘虚舟，随波任安流。\n赋诗旃檀阁，纵酒鹦鹉洲。\n待我适东越，相携上白楼。' },
  { title: '赠黄山胡公求白鹇', author: '李白', poem: '请以双白璧，买君双白鹇。\n白鹇白如锦，白雪耻容颜。\n照影玉潭里，刷毛琪树间。\n夜栖寒月静，朝步落花闲。\n我愿得此鸟，玩之坐碧山。\n胡公能辍赠，笼寄野人还。' },
  { title: '登敬亭山南望怀古赠窦主簿', author: '李白', poem: '敬亭一回首，目尽天南端。\n仙者五六人，常闻此游盘。\n谿流琴高水，石耸麻姑坛。\n白龙降陵阳，黄鹤呼子安。\n羽化骑日月，云行翼鸳鸾。\n下视宇宙间，四溟皆波澜。\n汰绝目下事，从之复何难。\n百岁落半途，前期浩漫漫。\n彊食不成味，清晨起长叹。\n愿随子明去，炼火烧金丹。' },
  { title: '经乱后将避地剡中留赠崔宣城', author: '李白', poem: '双鹅飞洛阳，五马渡江徼。\n何意上东门，胡雏更长啸。\n中原走豺虎，烈火焚宗庙。\n太白昼经天，颓阳掩余照。\n王城皆荡复，世路成奔峭。\n四海望长安，嚬眉寡西笑。\n苍生疑落叶，白骨空相吊。\n连兵似雪山，破敌谁能料。\n我垂北溟翼，且学南山豹。\n崔子贤主人，欢娱每相召。\n胡床紫玉笛，却坐青云呌。\n杨花满州城，置酒同临眺。\n忽思剡溪去，水石远清妙。\n雪尽天地明，风开湖山貌。\n闷为洛生咏，醉发吴越调。\n赤霞动金光，日足森海峤。\n独散万古意，闲垂一溪钓。\n猨近天上啼，人移月边櫂。\n无以墨绶苦，来求丹砂要。\n华发长折腰，将贻陶公诮。' },
  { title: '献从叔当涂宰阳冰', author: '李白', poem: '金镜霾六国，亡新乱天经。\n焉知高光起，自有羽翼生。\n萧曹安𡸣屼，耿贾摧欃枪。\n吾家有季父，杰出圣代英。\n虽无三台位，不借四豪名。\n激昂风云气，终协龙虎精。\n弱冠燕赵来，贤彦多逢迎。\n鲁连善谈笑，季布折公卿。\n遥知礼数绝，常恐不合幷。\n惕想结宵梦，素心久已冥。\n顾慙青云器，谬奉玉樽倾。\n山阳五百年，绿竹忽再荣。\n高歌振林木，大笑喧雷霆。\n落笔洒篆文，崩云使人惊。\n吐辞又炳焕，五色罗华星。\n秀句满江国，高才掞天庭。\n宰邑艰难时，浮云空古城。\n居人若薙草，扫地无纤茎。\n惠泽及飞走，农夫尽归耕。\n广汉水万里，长流玉琴声。\n雅颂播吴越，还如泰阶平。\n小子别金陵，来时白下亭。\n群凤怜客鸟，差池相哀鸣。\n各拔五色毛，意重泰山轻。\n赠微所费广，斗水浇长鲸。\n弹劒歌苦寒，严风起前楹。\n月衔天门晓，霜落牛渚清。\n长叹即归路，临川空屏营。' },
  { title: '书怀赠南陵常赞府', author: '李白', poem: '岁星入汉年，方朔见明主。\n调笑当时人，中天谢云雨。\n一去麒麟阁，遂将朝市乖。\n故交不过门，秋草日上阶。\n当时何特达，独与我心谐。\n置酒凌歊台，欢娱未曾歇。\n歌动白纻山，舞回天门月。\n问我心中事，为君前致辞。\n君看我才能，何似鲁仲尼。\n大圣犹不遇，小儒安足悲。\n云南五月中，频丧渡泸师。\n毒草杀汉马，张兵夺云旗。\n至今西二河，流血拥僵尸。\n将无七擒略，鲁女惜园葵。\n咸阳天下枢，累岁人不足。\n虽有数斗玉，不如一盘粟。\n赖得契宰衡，持钓慰风俗。\n自顾无所用，辞家方来归。\n霜惊壮士发，泪满逐臣衣。\n以此不安席，蹉跎身世违。\n终当灭卫谤，不受鲁人讥。' },
  { title: '赠汪伦', author: '李白', poem: '李白乘舟将欲行，忽闻岸上踏歌声。\n桃花潭水深千尺，不及汪伦送我情。' },
  { title: '安陆白兆山桃花嵒寄刘侍御绾', author: '李白', poem: '云卧三十年，好闲复爱仙。\n蓬壶虽冥绝，鸾鹤心悠然。\n归来桃花嵒，得憩云窗眠。\n对岭人共语，饮潭猨相连。\n时升翠微上，邈若罗浮巅。\n两岑抱东壑，一嶂横西天。\n树杂日易隐，崖倾月难圆。\n芳草换野色，飞萝摇春烟。\n入远构石室，选幽开上田。\n独此林下意，杳无区中缘。\n永辞霜台客，千载方来旋。' },
  { title: '淮南卧病书怀寄蜀中赵征君蕤', author: '李白', poem: '吴会一浮云，飘如远行客。\n功业莫从就，岁光屡奔迫。\n良图俄弃损，衰疾乃绵剧。\n古琴藏虚匣，长劒挂空壁。\n楚冠怀钟仪，越吟比庄舃。\n国门遥天外，乡路远山隔。\n朝忆相如台，夜梦子云宅。\n旅情初结缉，秋气方寂历。\n风入松下清，露出草间白。\n故人不可见，幽梦谁与适。\n寄书西飞鸿，赠尔慰离析。' },
  { title: '寄弄月溪吴山人', author: '李白', poem: '尝闻庞德公，家住洞湖水。\n终身栖鹿门，不入襄阳市。\n夫君弄明月，灭景清淮里。\n高踪邈难追，可与古人比。\n清扬杳莫覩，白云空望美。\n待我辞人间，携手访松子。' },
  { title: '秋山寄卫尉张卿及王征君', author: '李白', poem: '何以折相赠，白花青桂枝。\n月华若夜雪，见此令人思。\n虽然剡溪兴，不异山阴时。\n明发怀二子，空吟招隐诗。' },
  { title: '望终南山寄紫阁隐者', author: '李白', poem: '出门见南山，引领意无限。\n秀色难为名，苍翠日在眼。\n有时白云起，天际自舒卷。\n心中与之然，托兴每不浅。\n何当造幽人，灭迹栖绝𪩘。' },
  { title: '夕霁杜陵登楼寄韦繇', author: '李白', poem: '浮阳灭霁景，万物生秋容。\n登楼送远目，伏槛观群峰。\n原野旷超缅，关河纷杂重。\n清晖映竹日，翠色明云松。\n蹈海寄遐想，还山迷旧踪。\n徒然迫晚暮，未果谐心胷。\n结桂空伫立，折麻恨莫从。\n思君达永夜，长乐闻疎钟。' },
  { title: '秋夜宿龙门香山寺奉寄王方城十七丈奉国莹上人从弟幼成令问', author: '李白', poem: '朝发汝海东，暮栖龙门中。\n水寒夕波急，木落秋山空。\n望极九霄迥，赏幽万壑通。\n目皓沙上月，心清松下风。\n玉斗横网户，银河耿花宫。\n兴在趣方逸，欢余情未终。\n凤驾忆王子，虎溪怀远公。\n桂枝坐萧瑟，棣华不复同。\n流恨寄伊水，盈盈焉可穷。' },
  { title: '春日独坐寄郑明府', author: '李白', poem: '燕麦青青游子悲，河堤弱柳郁金枝。\n长条一拂春风去，尽日飘扬无定时。\n我在河南别离久，那堪坐此对窻牖。\n情人道来竟不来，何人共醉新丰酒。' },
  { title: '寄淮南友人', author: '李白', poem: '红颜悲旧国，青岁歇芳洲。\n不待金门诏，空持宝劒游。\n海云迷驿道，江月隐乡楼。\n复作淮南客，因逢桂树留。' },
  { title: '沙丘城下寄杜甫', author: '李白', poem: '我来竟何事，高卧沙丘城。\n城边有古树，日夕连秋声。\n鲁酒不可醉，齐歌空复情。\n思君若汶水，浩荡寄南征。' },
  { title: '闻丹丘子于城北营石门幽居中有高凤遗迹仆离群远怀亦有栖遁之志因叙旧以寄之', author: '李白', poem: '春华沧江月，秋色碧海云。\n离居盈寒暑，对此长思君。\n思君楚水南，望君淮山北。\n梦魂虽飞来，会面不可得。\n畴昔在嵩阳，同衾卧羲皇。\n绿萝笑簪绂，丹壑贱岩廊。\n晚途各分析，乘兴任所适。\n仆在雁门关，君为峨眉客。\n心悬万里外，影滞两乡隔。\n长劒复归来，相逢洛阳陌。\n陌上何喧喧，都令心意烦。\n迷津觉路失，托势随风飜。\n以兹谢朝列，长啸归故园。\n故园恣闲逸，求古散缥帙。\n久欲入名山，婚娶殊未毕。\n人生信多故，世事岂惟一。\n念此忧如焚，怅然若有失。\n闻君卧石门，宿昔契弥敦。\n方从桂树隐，不羡桃花源。\n高风起遐旷，幽人迹复存。\n松风清瑶瑟，溪月湛芳樽。\n安居偶佳赏，丹心期此论。' },
  { title: '淮阴书怀寄王宗成', author: '李白', poem: '沙墩至梁苑，二十五长亭。\n大舶夹双𫇛，中流鹅鹳鸣。\n云天扫空碧，川岳涵余清。\n飞凫从西来，适与佳兴幷。\n眷言王乔舃，婉娈故人情。\n复此亲懿会，而增交道荣。\n沿洄且不定，飘忽怅徂征。\n暝投淮阴宿，欣得漂母迎。\n斗酒烹黄鸡，一餐感素诚。\n予为楚壮士，不是鲁诸生。\n有德必报之，千金耻为轻。\n缅书羇孤意，远寄櫂歌声。' },
  { title: '闻王昌龄左迁龙标遥有此寄', author: '李白', poem: '杨花落尽子规啼，闻道龙标过五溪。\n我寄愁心与明月，随风直到夜郎西。' },
  { title: '寄王屋山人孟大融', author: '李白', poem: '我昔东海上，劳山餐紫霞。\n亲见安期公，食枣大如瓜。\n中年谒汉主，不惬还归家。\n朱颜谢春辉，白发见生涯。\n所期就金液，飞步登云车。\n愿随夫子天坛上，闲与仙人扫落花。' },
  { title: '忆旧游寄谯郡元参军', author: '李白', poem: '忆昔洛阳董糟丘，为余天津桥南造酒楼。\n黄金白璧买歌笑，一醉累月轻王侯。\n海内贤豪青云客，就中与君心莫逆。\n迥山转海不作难，倾情倒意无所惜。\n我向淮南攀桂枝，君留洛北愁梦思。\n不忍别，还相随，相随迢迢访仙城。\n三十六曲水回萦，一溪初入千花明。\n万壑度尽松风声，银鞍金络倒平地，汉东太守来相迎。\n紫阳之真人，邀我吹玉笙。\n餐霞楼上动仙乐，嘈然宛似鸾凤鸣。\n袖长管催欲轻举，汉中太守醉起舞。\n手持锦袍覆我身，我醉横眠枕其股。\n当筵意气凌九霄，星离雨散不终朝，分飞楚关山水遥。\n余既还山寻故巢，君亦归家渡渭桥。\n君家严君勇貔虎，作尹幷州遏戎虏。\n五月相呼度太行，摧轮不道羊肠苦。\n行来北凉岁月深，感君贵义轻黄金。\n琼杯绮食青玉案，使我醉饱无归心。\n时时出向城西曲，晋祠流水如碧玉。\n浮舟弄水箫鼓鸣，微波龙鳞莎草绿。\n兴来携妓恣经过，其若杨花似雪何。\n红粧欲醉宜斜日，百尺清潭写翠娥。\n翠娥婵娟初月辉，美人更唱舞罗衣。\n清风吹歌人空去，歌曲自绕行云飞。\n此时行乐难再遇，西游因献长杨赋。\n北阙青云不可期，东山白首还归去。\n渭桥南头一遇君，酂台之北又离群。\n问余别恨知多少，落花春暮争纷纷。\n言亦不可尽，情亦不可极。\n呼儿长跪缄此辞，寄君千里遥相忆。' },
  { title: '月夜江行寄崔员外宗之', author: '李白', poem: '飘飘江风起，萧飒海树秋。\n登舻美清夜，挂席移轻舟。\n月随碧山转，水合青天流。\n杳如星河上，但觉云林幽。\n归路方浩浩，徂川去悠悠。\n徒悲蕙草歇，复听菱歌愁。\n岸曲迷后浦，沙明瞰前洲。\n怀君不可见，望远增离忧。' },
  { title: '宿白鹭洲寄杨江宁', author: '李白', poem: '朝别朱雀门，暮栖白鹭洲。\n波光摇海月，星影入城楼。\n望美金陵宰，如思琼树忧。\n徒令魂入梦，飜觉夜成秋。\n绿水解人意，为余西北流。\n因声玉琴里，荡漾寄君愁。' },
  { title: '新林浦阻风寄友人', author: '李白', poem: '潮水定可信，天风难与期。\n清晨西北转，薄暮东南吹。\n以此难挂席，佳期益相思。\n海月破圆影，菰蒋生绿池。\n昨日北湖梅，开花已满枝。\n今朝东门柳，夹道垂青丝。\n岁物忽如此，我来定几时。\n纷纷江上雪，草草客中悲。\n明发新林浦，空吟谢朓诗。' },
  { title: '寄韦南陵冰余江上乘兴访之遇寻颜尚书笑有此赠', author: '李白', poem: '南船正东风，北船来自缓。\n江上相逢借问君，语笑未了风吹断。\n闻君携伎访情人，应为尚书不顾身。\n堂上三千珠履客，瓮中百斛金陵春。\n恨我阻此乐，淹留楚江滨。\n月色醉远客，山花开欲然。\n春风狂杀人，一日剧三年。\n乘兴嫌太迟，焚却子猷船。\n梦见五柳枝，已堪挂马鞭。\n何日到彭泽，长歌陶令前。' },
  { title: '题情深树寄象公', author: '李白', poem: '肠断枝上猨，泪添山下樽。\n白云见我去，亦为我飞翻。' },
  { title: '北山独酌寄韦六', author: '李白', poem: '巢父将许由，未闻买山隐。\n道存迹自高，何惮去人近。\n纷吾下兹岭，地闲喧亦泯。\n门横群岫开，水凿众泉引。\n屏高而在云，窦深莫能准。\n川光昼昏凝，林气夕凄紧。\n于焉摘朱果，兼得养玄牝。\n坐月观宝书，拂霜弄瑶轸。\n倾壶事幽酌，顾影还独尽。\n念君风尘游，傲尔令自哂。' },
  { title: '寄当涂赵少府炎', author: '李白', poem: '晚登高楼望，木落双江清。\n寒山饶积翠，秀色连州城。\n目送楚云尽，心悲胡雁声。\n相思不可见，回首故人情。' },
  { title: '寄东鲁二稚子', author: '李白', poem: '吴地桑叶绿，吴蚕已三眠。\n我家寄东鲁，谁种龟阴田。\n春事已不及，江行复茫然。\n南风吹归心，飞堕酒楼前。\n楼东一株桃，枝叶拂青烟。\n此树我所种，别来向三年。\n桃今与楼齐，我行尚未旋。\n娇女字平阳，折花倚桃边。\n折花不见我，泪下如流泉。\n小儿名伯禽，与姊亦齐肩。\n双行桃树下，抚背复谁怜。\n念此失次第，肝肠日忧煎。\n裂素写远意，因之汶阳川。' },
  { title: '独酌清溪江石上寄权昭夷', author: '李白', poem: '我携一樽酒，独上江祖石。\n自从天地开，更长几千尺。\n举杯向天笑，天回日西照。\n永愿坐此石，长垂严陵钓。\n寄谢山中人，可与尔同调。' },
  { title: '禅房怀友人岑伦', author: '李白', poem: '婵娟罗浮月，摇艳桂水云。\n美人竟独往，而我安得群。\n一朝语笑隔，万里懽情分。\n沈吟彩霞没，梦寐群芳歇。\n归鸿渡三湘，游子在百粤。\n边尘染衣劒，白日雕华发。\n春风变楚关，秋声落吴山。\n草木结悲绪，风沙凄苦颜。\n朅来已永久，颓思如循环。\n飘飘限江裔，想像空留滞。\n离忧每醉心，别泪徒盈袂。\n坐愁青天末，出望黄云蔽。\n目极何悠悠，梅花南岭头。\n空长灭征鸟，水阔无还舟。\n宝劒终难托，金囊非易求。\n归来傥有问，桂树山之幽。' },
  { title: '庐山谣寄卢侍御虚舟', author: '李白', poem: '我本楚狂人，凤歌笑孔丘。\n手持绿玉杖，朝别黄鹤楼。\n五岳寻仙不辞远，一生好入名山游。\n庐山秀出南斗傍，屏风九叠云锦张，影落明湖青黛光。\n金阙前开二峰长，银河倒挂三石梁。\n香炉瀑布遥相望，回厓沓嶂凌苍苍。\n翠影红霞映朝日，鸟飞不到吴天长。\n登高壮观天地间，大江茫茫去不还。\n黄云万里动风色，白波九道流雪山。\n好为庐山谣，兴因庐山发。\n闲窥石镜清我心，谢公行处苍苔没。\n早服还丹无世情，琴心三叠道初成。\n遥见仙人彩云里，手把芙蓉朝玉京。\n先期汗漫九垓上，愿接卢敖游太清。' },
  { title: '下寻阳城泛彭蠡寄黄判官', author: '李白', poem: '浪动灌婴井，寻阳江上风。\n开帆入天镜，直向彭湖东。\n落景转疎雨，晴云散远空。\n名山发佳兴，清赏亦何穷。\n石镜挂遥月，香炉灭彩虹。\n相思俱对此，举目与君同。' },
  { title: '书情寄从弟邠州长史昭', author: '李白', poem: '自笑客行久，我行定几时。\n绿杨已可折，攀取最长枝。\n翩翩弄春色，延伫寄相思。\n谁言贵此物，意愿重琼蕤。\n昨梦见惠连，朝吟谢公诗。\n东风引碧草，不觉生华池。\n临玩忽云夕，杜鹃夜鸣悲。\n怀君芳岁歇，庭树落红滋。' },
  { title: '寄王汉阳', author: '李白', poem: '南湖秋月白，王宰夜相邀。\n锦帐郎官醉，罗衣舞女娇。\n笛声喧沔鄂，歌曲上云霄。\n别后空愁我，相思一水遥。' },
  { title: '春日归山寄孟浩然', author: '李白', poem: '朱绂遗尘境，青山谒梵筵。\n金绳开觉路，宝筏度迷川。\n岭树攒飞栱，嵒花覆谷泉。\n墖形标海月，楼势出江烟。\n香气三天下，钟声万壑连。\n荷秋珠已满，松密盖初圆。\n鸟聚疑闻法，龙参若护禅。\n媿非流水韵，叨入伯牙弦。' },
  { title: '流夜郎永华寺寄寻阳群官', author: '李白', poem: '朝别凌烟楼，贤豪满行舟。\n暝投永华寺，宾散予独醉。\n愿结九江流，添成万行泪。\n写意寄庐岳，何当来此地。\n天命有所悬，安得苦愁思。' },
  { title: '流夜郎至西塞驿寄裴隐', author: '李白', poem: '扬帆借天风，水驿苦不缓。\n平明及西塞，已先投沙伴。\n回峦引群峰，横蹙楚山断。\n砯冲万壑会，震沓百川满。\n龙怪潜溟波，俟时救炎旱。\n我行望雷雨，安得沾枯散。\n鸟去天路长，人愁春光短。\n空将泽畔吟，寄尔江南管。' },
  { title: '自汉阳病酒归寄王明府', author: '李白', poem: '去岁左迁夜郎道，琉璃砚水长枯槁。\n今年敕放巫山阳，蛟龙笔翰生辉光。\n圣主还听子虚赋，相如却与论文章。\n愿扫鹦鹉洲，与君醉百场。\n啸起白云飞七泽，歌吟渌水动三湘。\n莫惜连船沽美酒，千金一掷买春芳。' },
  { title: '望汉阳柳色寄王宰', author: '李白', poem: '汉阳江上柳，望客引东枝。\n树树花如雪，纷纷乱若丝。\n春风传我意，草木别前知。\n寄谢弦歌宰，西来定未迟。' },
  { title: '江夏寄汉阳辅录事', author: '李白', poem: '谁道此水广，狭如一匹练。\n江夏黄鹤楼，青山汉阳县。\n大语犹可闻，故人难可见。\n君草陈琳檄，我书鲁连箭。\n报国有壮心，龙颜不回眷。\n西飞精卫鸟，东海何由填。\n鼓角徒悲鸣，楼船习征战。\n抽劒步霜月，夜行空庭徧。\n长呼结浮云，埋没顾荣扇。\n他日观军容，投壶接高宴。' },
  { title: '早春寄王汉阳', author: '李白', poem: '闻道春还未相识，走傍寒梅访消息。\n昨夜东风入武阳，陌头杨柳黄金色。\n碧水浩浩云茫茫，美人不来空断肠。\n预拂青山一片石，与君连日醉壶觞。' },
  { title: '江上寄巴东故人', author: '李白', poem: '汉水波浪远，巫山云雨飞。\n东风吹客梦，西落此中时。\n觉后思白帝，佳人与我违。\n瞿塘饶贾客，音信莫令稀。' },
  { title: '江上寄元六林宗', author: '李白', poem: '霜落江始寒，枫叶绿未脱。\n客行悲清秋，永路苦不达。\n沧波眇川汜，白日隐天末。\n停櫂依林峦，惊猿相呌聒。\n夜分河汉转，起视溟涨阔。\n凉风何萧萧，流水鸣活活。\n浦沙净如洗，海月明可掇。\n兰交空怀思，琼树讵解渴。\n勗哉沧洲心，岁晚庶不夺。\n幽赏颇自得，兴远与谁豁。' },
  { title: '寄从弟宣州长史昭', author: '李白', poem: '尔佐宣州郡，守官清且闲。\n常夸云月好，邀我敬亭山。\n五落洞庭叶，三江游未还。\n相思不可见，叹息损朱颜。' },
  { title: '泾溪东亭寄郑少府谔', author: '李白', poem: '我游东亭不见君，沙上行将白鹭群。\n白鹭行时散飞去，又如雪点青山云。\n欲往泾溪不辞远，龙门蹙波虎眼转。\n杜鹃花开春已阑，归向陵阳钓鱼晚。' },
  { title: '宣州九日闻崔四侍御与宇文太守游敬亭余时登响山不同此赏醉后寄崔侍御二首 一', author: '李白', poem: '九日茱萸熟，插鬓伤早白。\n登高望山海，满目悲古昔。\n远访投沙人，因为逃名客。\n故交竟谁在，独有崔亭伯。\n重阳不相知，载酒任所适。\n手持一枝菊，调笑二千石。\n日暮岸帻归，传呼隘阡陌。\n彤襜双白鹿，宾从何辉赫。\n夫子在其间，遂成云霄隔。\n良辰与美景，两地方虚掷。\n晚从南峰归，萝月下水壁。\n却登郡楼望，松色寒转碧。\n咫尺不可亲，弃我如遗舃。' },
  { title: '宣州九日闻崔四侍御与宇文太守游敬亭余时登响山不同此赏醉后寄崔侍御二首 二', author: '李白', poem: '九卿天上落，五马道傍来。\n列戟朱门晓，褰帏碧嶂开。\n登高望远海，召客得英才。\n紫绶懽情洽，黄花逸兴催。\n山从图上见，溪即镜中回。\n遥羡重阳作，应过戏马台。' },
  { title: '寄崔侍御', author: '李白', poem: '宛溪霜夜听猿愁，去国长为不系舟。\n独怜一雁飞南海，却羡双溪解北流。\n高人屡解陈蕃榻，过客难登谢朓楼。\n此处别离同落叶，朝朝分散敬亭秋。' },
  { title: '泾溪南蓝山下有落星潭可以卜筑余泊舟石上寄何判官昌浩', author: '李白', poem: '蓝岑竦天壁，突兀如鲸额。\n奔蹙横澄潭，势吞落星石。\n沙带秋月明，水摇寒山碧。\n佳镜宜缓櫂，清辉能留客。\n恨君阻欢游，使我自惊惕。\n所期俱卜筑，结茅炼金液。' },
  { title: '早过漆林渡寄万巨', author: '李白', poem: '西经大蓝山，南来漆林渡。\n水色倒空青，林烟横积素。\n漏流昔吞翕，沓浪竞奔注。\n潭落天上星，龙开水中雾。\n峣岩注公栅，突兀陈焦墓。\n岭峭纷上干，川明屡回顾。\n因思万夫子，解渴同琼树。\n何日覩清光，相欢咏佳句。' },
  { title: '游敬亭寄崔侍御', author: '李白', poem: '我家敬亭下，輙继谢公作。\n相去数百年，风期宛如昨。\n登高素秋月，下望青山郭。\n俯视鸳鸯群，饮啄自鸣跃。\n夫子虽蹭蹬，瑶台雪中鹤。\n独立窥浮云，其心在寥廓。\n时来顾我笑，一饭葵与藿。\n世路如秋风，相逢尽萧索。\n腰间玉具劒，意许无遗诺。\n壮士不可轻，相期在云阁。' },
  { title: '三山望金陵寄殷淑', author: '李白', poem: '三山怀谢朓，水澹望长安。\n芜没河阳县，秋江正北看。\n卢龙霜气冷，𫛛鹊月光寒。\n耿耿忆琼树，天涯寄一懽。' },
  { title: '自金陵溯流过白璧山玩月达天门寄句容王主簿', author: '李白', poem: '沧江溯流归，白璧见秋月。\n秋月照白璧，皓如山阴雪。\n幽人停宵征，贾客忘早发。\n进帆天门山，回首牛渚没。\n川长信风来，日出宿雾歇。\n故人在咫尺，新赏成胡越。\n寄君青兰花，惠好庶不绝。' },
  { title: '寄上吴王三首 一', author: '李白', poem: '淮王爱八公，携手绿云中。\n小子忝枝叶，亦攀丹桂丛。\n谬以词赋重，而将枚马同。\n何日背淮水，东之观土风。' },
  { title: '寄上吴王三首 二', author: '李白', poem: '坐啸庐江静，闲闻进玉觞。\n去时无一物，东壁挂胡床。' },
  { title: '寄上吴王三首 三', author: '李白', poem: '英明庐江守，声誉广平籍。\n洒扫黄金台，招邀青云客。\n客曾与天通，出入清禁中。\n襄王怜宋玉，愿入兰台宫。' },
  { title: '秋日鲁郡尧祠亭上宴别杜补阙范侍御', author: '李白', poem: '我觉秋兴逸，谁云秋兴悲。\n山将落日去，水与晴空宜。\n鲁酒白玉壶，送行驻金羁。\n歇鞍憩古木，解带挂横枝。\n歌鼓川上亭，曲度神飙吹。\n云归碧海夕，鴈没青天时。\n相失各万里，茫然空尔思。' },
  { title: '别鲁颂', author: '李白', poem: '谁道泰山高，下却鲁连节。\n谁云秦军众，摧却鲁连舌。\n独立天地间，清风洒兰雪。\n夫子还倜傥，攻文继前烈。\n错落石上松，无为秋霜折。\n赠言镂宝刀，千岁庶不灭。' },
  { title: '别中都明府兄', author: '李白', poem: '吾兄诗酒继陶君，试宰中都天下闻。\n东楼喜奉连枝会，南陌愁为落叶分。\n城隅渌水明秋日，海上青山隔暮云。\n取醉不辞留夜月，鴈行中断惜离群。' },
  { title: '梦游天姥吟留别', author: '李白', poem: '海客谈瀛洲，烟涛微茫信难求。\n越人语天姥，云霓明灭或可覩。\n天姥连天向天横，势拔五岳掩赤城。\n天台四万八千丈，对此欲倒东南倾。\n我欲因之梦吴越，一夜飞度镜湖月。\n湖月照我影，送我至剡溪。\n谢公宿处今尚在，渌水荡漾清猨啼。\n脚着谢公屐，身登青云梯。\n半壁见海日，空中闻天鸡。\n千岩万转路不定，迷花倚石忽已暝。\n熊咆龙吟殷岩泉，栗深林兮惊层巅。\n云青青兮欲雨，水澹澹兮生烟。\n列缺霹雳，丘峦崩摧。\n洞天石扇，訇然中开。\n青冥浩荡不见底，日月照耀金银台。\n霓为衣兮风为马，云之君兮纷纷而来下。\n虎鼓瑟兮鸾回车，仙之人兮列如麻。\n忽魂悸以魄动，怳惊起而长嗟。\n惟觉时之枕席，失向来之烟霞。\n世间行乐亦如此，古来万事东流水。\n别君去时何时还，且放白鹿青崖间，须行即骑访名山。\n安能摧眉折腰事权贵？\n使我不得开心颜。' },
  { title: '留别曹南群官之江南', author: '李白', poem: '我昔钓白龙，放龙溪水傍。\n道成本欲去，挥手凌苍苍。\n时来不关人，谈笑游轩皇。\n献纳少成事，归休辞建章。\n十年罢西笑，览镜如秋霜。\n闭劒琉璃匣，炼丹紫翠房。\n身佩豁落图，腰垂虎鞶囊。\n仙人驾彩凤，志在穷遐荒。\n恋子四五人，裴回未翱翔。\n东流送白日，骤歌兰蕙芳。\n仙宫两无从，人间久摧藏。\n范蠡说句践，屈平去怀王。\n飘飘紫霞心，流浪忆江乡。\n愁为万里别，复此一衔觞。\n淮水帝王州，金陵绕丹阳。\n楼台照海色，衣马摇川光。\n及此北望君，相思泪成行。\n朝云落梦渚，瑶草空高堂。\n帝子隔洞庭，青枫满潇湘。\n怀君路绵邈，览古情凄凉。\n登岳眺百川，杳然万恨长。\n知恋峨眉去，弄景偶骑羊。' },
  { title: '留别于十一兄逖裴十三游塞垣', author: '李白', poem: '太公渭川水，李斯上蔡门。\n钓周猎秦安黎元，小鱼㕙兔何足言。\n天张云卷有时节，吾徒莫叹羝触藩。\n于公白首大梁野，使人怅望何可论。\n既知朱亥为壮士，且愿束心秋毫里。\n秦赵虎争血中原，当去抱关救公子。\n裴生览千古，龙鸾炳文章。\n悲吟雨雪动林木，放书辍劒思高堂。\n劝尔一杯酒，拂尔裘上霜。\n尔为我楚舞，吾为尔楚歌。\n且探虎穴向沙漠，鸣鞭走马凌黄河。\n耻作易水别，临岐泪滂沱。' },
  { title: '留别王司马嵩', author: '李白', poem: '鲁连卖谈笑，岂是顾千金。\n陶朱虽相越，本有五湖心。\n余亦南阳子，时为梁甫吟。\n苍山容偃蹇，白日惜颓侵。\n愿一佐明主，功成还旧林。\n西来何所为，孤劒托知音。\n鸟爱碧山远，鱼游沧海深。\n呼鹰过上蔡，卖畚向嵩岑。\n他日闲相访，丘中有素琴。' },
  { title: '夜别张五', author: '李白', poem: '吾多张公子，别酌酣高堂。\n听歌舞银烛，把酒轻罗裳。\n横笛弄秋月，琵琶弹陌桑。\n龙泉解锦带，为尔倾千觞。' },
  { title: '魏郡别苏明府因北游', author: '李白', poem: '魏都接燕赵，美女夸芙蓉。\n淇水流碧玉，舟车日奔冲。\n青楼夹两岸，万室喧歌钟。\n天下称豪贵，游此每相逢。\n洛阳苏季子，劒戟森词锋。\n六印虽未佩，轩车若飞龙。\n黄金数百镒，白璧有几双。\n散尽空掉臂，高歌赋还邛。\n落魄乃如此，何人不相从。\n远别隔两河，云山杳千重。\n何时更杯酒，再得论心胸。' },
  { title: '留别西河刘少府', author: '李白', poem: '秋发已种种，所为竟无成。\n闲倾鲁壶酒，笑对刘公荣。\n谓我是方朔，人间落岁星。\n白衣千万乘，何事去天庭。\n君亦不得意，高歌羡鸿冥。\n世人若醯鸡，安可识梅生。\n虽为刀笔吏，缅怀在赤城。\n余亦如流萍，随波乐休明。\n自有两少妾，双骑骏马行。\n东山春酒绿，归隐谢浮名。' },
  { title: '颍阳别元丹丘之淮阳', author: '李白', poem: '吾将元夫子，异姓为天伦。\n本无轩裳契，素以烟霞亲。\n尝恨迫世网，铭意俱未伸。\n松柏虽寒苦，羞逐桃李春。\n悠悠市朝间，玉颜日缁磷。\n所失重山岳，所得轻埃尘。\n精魄渐芜秽，衰老相凭因。\n我有锦囊诀，可以持君身。\n当餐黄金药，去为紫阳宾。\n万事难并立，百年犹崇晨。\n别尔东南去，悠悠多悲辛。\n前志庶不易，远途期所遵。\n已矣归去来，白云飞天津。' },
  { title: '留别广陵诸公', author: '李白', poem: '忆昔作少年，结交赵与燕。\n金羁络骏马，锦带横龙泉。\n寸心无疑事，所向非徒然。\n晚节觉此疎，猎精草太玄。\n空名束壮士，薄俗弃高贤。\n中回圣明顾，挥翰凌云烟。\n骑虎不敢下，攀龙忽堕天。\n还家守清真，孤洁励秋蝉。\n炼丹费火石，采药穷山川。\n卧海不关人，租税辽东田。\n乘兴忽复起，櫂歌溪中船。\n临醉谢葛强，山公欲倒鞭。\n狂歌自此别，垂钓沧浪前。' },
  { title: '广陵赠别', author: '李白', poem: '玉瓶沽美酒，数里送君还。\n系马垂杨下，衔杯大道间。\n天边看渌水，海上见青山。\n兴罢各分袂，何须醉别颜。' },
  { title: '别储邕之剡中', author: '李白', poem: '借问剡中道，东南指越乡。\n舟从广陵去，水入会稽长。\n竹色溪下绿，荷花镜里香。\n辞君向天姥，拂石卧秋霜。' },
  { title: '留别金陵诸公', author: '李白', poem: '海水昔飞动，三龙纷战争。\n钟山危波澜，倾侧骇奔鲸。\n黄旗一扫荡，割壤开吴京。\n六代更霸王，遗迹见都城。\n至今秦淮间，礼乐秀群英。\n地扇邹鲁学，诗腾颜谢名。\n五月金陵西，祖余白下亭。\n欲寻庐峰顶，先遶汉水行。\n香炉紫烟灭，瀑布落太清。\n若攀星辰去，挥手缅含情。' },
  { title: '口号', author: '李白', poem: '食出野田美，酒临远水倾。\n东流若未尽，应见别离情。' },
  { title: '金陵酒肆留别', author: '李白', poem: '风吹柳花满店香，吴姬压酒唤客尝。\n金陵子弟来相送，欲行不行各尽觞。\n请君试问东流水，别意与之谁短长。' },
  { title: '金陵白下亭留别', author: '李白', poem: '驿亭三杨树，正当白下门。\n吴烟暝长条，汉水啮古根。\n向来送行处，回首阻笑言。\n别后若见之，为余一攀翻。' },
  { title: '别东林寺僧', author: '李白', poem: '东林送客处，月出白猨啼。\n笑别庐山远，何烦过虎溪。' },
  { title: '窜夜郎于乌江留别宗十六璟', author: '李白', poem: '君家全盛日，台鼎何陆离。\n斩鼇翼娲皇，炼石补天维。\n一回日月顾，三入凤皇池。\n失势青门傍，种瓜复几时。\n犹会众宾客，三千光路岐。\n皇恩雪愤懑，松柏含荣滋。\n我非东床人，令姊忝齐眉。\n浪迹未出世，空名动京师。\n适遭云罗解，翻谪夜郎悲。\n拙妻莫邪劒，及此二龙随。\n慙君湍波苦，千里远从之。\n白帝晓猨断，黄牛过客迟。\n遥瞻明月峡，西去益相思。' },
  { title: '留别龚处士', author: '李白', poem: '龚子栖闲地，都无人世喧。\n柳深陶令宅，竹暗辟疆园。\n我去黄牛峡，遥愁白帝猨。\n赠君卷葹草，心断竟何言。' },
  { title: '赠别郑判官', author: '李白', poem: '窜逐勿复哀，惭君问寒灰。\n浮云本无意，吹落章华台。\n远别泪空尽，长愁心已摧。\n二年吟泽畔，顦顇几时回。' },
  { title: '黄鹤楼送孟浩然之广陵', author: '李白', poem: '故人西辞黄鹤楼，烟花三月下扬州。\n孤帆远影碧山尽，唯见长江天际流。' },
  { title: '将游衡岳过汉阳双松亭留别族弟浮屠谈皓', author: '李白', poem: '秦欺赵氏璧，却入邯郸宫。\n本是楚家玉，还来荆山中。\n丹彩泻沧溟，精辉凌白虹。\n青蝇一相点，流落此时同。\n卓绝道门秀，谈玄乃支公。\n延萝结幽居，剪竹绕芳丛。\n凉花拂户牖，天籁鸣虚空。\n忆我初来时，蒲萄开景风。\n今兹大火落，秋叶黄梧桐。\n水色梦沅湘，长沙去何穷。\n寄书访衡峤，但与南飞鸿。' },
  { title: '留别贾舍人至二首 一', author: '李白', poem: '大梁白云起，飘飖来南洲。\n裴回苍梧野，十见罗浮秋。\n鼇抃山海倾，四溟扬洪流。\n意欲托孤凤，从之摩天游。\n凤苦道路难，翱翔还昆丘。\n不肯衔我去，哀鸣慙不周。\n远客谢主人，明珠难暗投。\n拂拭倚天劒，西登岳阳楼。\n长啸万里风，扫清胷中忧。\n谁念刘越石，化为绕指柔。' },
  { title: '留别贾舍人至二首 二', author: '李白', poem: '秋风吹胡霜，凋此檐下芳。\n折芳怨岁晚，离别凄以伤。\n谬攀青琐贤，延我于北堂。\n君为长沙客，我独之夜郎。\n劝此一杯酒，岂惟道路长。\n割珠两分赠，寸心贵不忘。\n何必儿女仁，相看泪成行。' },
  { title: '渡荆门送别', author: '李白', poem: '渡远荆门外，来从楚国游。\n山随平野尽，江入大荒流。\n月下飞天镜，云生结海楼。\n仍连故乡水，万里送行舟。' },
  { title: '闻李太尉大举秦兵百万出征东南懦夫请缨冀申一割之用半道病还留别金陵崔侍御十九韵', author: '李白', poem: '秦出天下兵，蹴踏燕赵倾。\n黄河饮马竭，赤羽连天明。\n太尉杖旄钺，云旗绕彭城。\n三军受号令，千里肃雷霆。\n函谷绝飞鸟，武关拥连营。\n意在斩巨鼇，何论鲙长鲸。\n恨无左军略，多愧鲁连生。\n拂劒照严霜，雕戈鬘胡缨。\n愿雪会稽耻，将期报恩荣。\n半道谢病还，无因东南征。\n亚夫未见顾，剧孟阻先行。\n天夺壮士心，长吁别吴京。\n金陵遇太守，倒屣相逢迎。\n群公咸祖饯，四座罗朝英。\n初发临沧观，醉栖征虏亭。\n旧国见秋月，长江流寒声。\n帝车信回转，河汉复纵横。\n孤凤向西海，飞鸿辞北溟。\n因之出寥廓，挥手谢公卿。' },
  { title: '别韦少府', author: '李白', poem: '西出苍龙门，南登白鹿原。\n欲寻商山皓，犹恋汉皇恩。\n水国远行迈，仙经深讨论。\n洗心向溪月，清耳敬亭猨。\n筑室在人境，闭门无世喧。\n多君枉高驾，赠我以微言。\n交乃意气合，道因风雅存。\n别离有相思，瑶瑟与金樽。' },
  { title: '南陵别儿童入京', author: '李白', poem: '白酒新熟山中归，黄鸡啄黍秋正肥。\n呼童烹鸡酌白酒，儿女嬉笑牵人衣。\n高歌取醉欲自慰，起舞落日争光辉。\n游说万乘苦不早，着鞭跨马涉远道。\n会稽愚妇轻买臣，余亦辞家西入秦。\n仰天大笑出门去，我辈岂是蓬蒿人。' },
  { title: '别山僧', author: '李白', poem: '何处名僧到水西，乘舟弄月宿泾溪。\n平明别我上山去，手携金策踏云梯。\n腾身转觉三天近，举足回看万岭低。\n谑浪肯居支遁下，风流还与远公齐。\n此度别离何日见，相思一夜暝猨啼。' },
  { title: '赠别王山人归布山', author: '李白', poem: '王子析道论，微言破秋毫。\n还归布山隐，兴入天云高。\n尔去安可迟，瑶草恐衰歇。\n我心亦怀归，屡梦松上月。\n傲然遂独往，长啸开岩扉。\n林壑久已芜，石道生蔷薇。\n愿言弄笙鹤，岁晚来相依。' },
  { title: '江夏别宋之悌', author: '李白', poem: '楚水清若空，遥将碧海通。\n人分千里外，兴在一杯中。\n谷鸟吟晴日，江猨啸晚风。\n平生不下泪，于此泣无穷。' },
  { title: '南阳送客', author: '李白', poem: '斗酒勿为薄，寸心贵不忘。\n坐惜故人去，偏令游子伤。\n离颜怨芳草，春思结垂杨。\n挥手再三别，临岐空断肠。' },
  { title: '送张舍人之江东', author: '李白', poem: '张翰江东去，正值秋风时。\n天清一鴈远，海阔孤帆迟。\n白日行欲暮，沧波杳难期。\n吴洲如见月，千里幸相思。' },
  { title: '送当涂赵少府赴长芦', author: '李白', poem: '我来扬都市，送客回轻舠。\n因夸楚太子，便覩广陵涛。\n仙尉赵家玉，英风凌四豪。\n维舟至长芦，目送烟云高。\n摇扇对酒楼，持袂把蟹螯。\n前途傥相思，登岳一长谣。' },
  { title: '送友人寻越中山水', author: '李白', poem: '闻道稽山去，偏宜谢客才。\n千岩泉洒落，万壑树萦回。\n东海横秦望，西陵遶越台。\n湖清霜镜晓，涛白雪山来。\n八月枚乘笔，三吴张翰杯。\n此中多逸兴，早晚向天台。' },
  { title: '送族弟凝之滁求婚崔氏', author: '李白', poem: '与尔情不浅，忘筌已得鱼。\n玉台挂宝镜，持此意何如。\n坦腹东床下，由来志气疎。\n遥知向前路，掷果定盈车。' },
  { title: '送友人游梅湖', author: '李白', poem: '送君游梅湖，应见梅花发。\n有使寄我来，无令红芳歇。\n暂行新林浦，定醉金陵月。\n莫惜一鴈书，音尘坐胡越。' },
  { title: '送崔十二游天竺寺', author: '李白', poem: '还闻天竺寺，梦想怀东越。\n每年海树霜，桂子落秋月。\n送君游此地，已属流芳歇。\n待我来岁行，相随浮溟渤。' },
  { title: '送杨山人归天台', author: '李白', poem: '客有思天台，东行路超忽。\n涛落浙江秋，沙明浦阳月。\n今游方厌楚，昨梦先归越。\n且尽秉烛欢，无辞凌晨发。\n我家小阮贤，剖竹赤城边。\n诗人多见重，官烛未曾然。\n兴引登山屐，情催泛海船。\n石桥如可度，携手弄云烟。' },
  { title: '送温处士归黄山白鹅峰旧居', author: '李白', poem: '黄山四千仞，三十二莲峰。\n丹崖夹石柱，菡萏金芙蓉。\n伊昔升绝顶，下窥天目松。\n仙人炼玉处，羽化留余踪。\n亦闻温伯雪，独往今相逢。\n采秀辞五岳，攀岩历万重。\n归休白鹅岭，渴饮丹砂井。\n凤吹我时来，云车尔当整。\n去去陵阳东，行行芳桂丛。\n回溪十六度，碧嶂尽晴空。\n他日还相访，乘桥蹑彩虹。' },
  { title: '送方士赵叟之东平', author: '李白', poem: '长桑晓洞视，五藏无全牛。\n赵叟得秘诀，还从方士游。\n西过获麟台，为我吊孔丘。\n念别复怀古，潸然空泪流。' },
  { title: '送韩准裴政孔巢父还山', author: '李白', poem: '猎客张兔罝，不能挂龙虎。\n所以青云人，高歌在岩户。\n韩生信英彦，裴子含清真。\n孔侯复秀出，俱与云霞亲。\n峻节凌远松，同衾卧盘石。\n斧冰嗽寒泉，三子同二屐。\n时时或乘兴，往往云无心。\n出山揖牧伯，长啸轻衣簪。\n昨宵梦里还，云弄竹溪月。\n今晨鲁东门，帐饮与君别。\n雪崖滑去马，萝径迷归人。\n相思若烟草，历乱无冬春。' },
  { title: '送杨少府赴选', author: '李白', poem: '大国置衡镜，准平天地心。\n群贤无邪人，朗鉴穷情深。\n吾君咏南风，衮冕弹鸣琴。\n时泰多美士，京国会缨簪。\n山苗落涧底，幽松出高岑。\n夫子有盛才，主司得球琳。\n流水非郑曲，前行遇知音。\n衣工剪绮绣，一悮伤千金。\n何惜刀尺余，不裁寒女衾。\n我非弹冠者，感别但开襟。\n空谷无白驹，贤人岂悲吟。\n大道安弃物，时来或招寻。\n尔见山吏部，当应无陆沈。' },
  { title: '对雪奉饯任城六父秩满归京', author: '李白', poem: '龙虎谢鞭策，鹓鸾不司晨。\n君看海上鹤，何似笼中鹑。\n独用天地心，浮云乃吾身。\n虽将簪组狎，若与烟霞亲。\n季父有英风，白眉超常伦。\n一官即梦寐，脱屐归西秦。\n窦公敞华筵，墨客尽来臻。\n燕歌落胡鴈，郢曲回阳春。\n征马百度嘶，游车动行尘。\n踌躇未忍去，恋此四座人。\n饯离驻高驾，惜别空殷勤。\n何时竹林下，更与步兵邻。' },
  { title: '鲁郡尧祠送吴五之瑯琊', author: '李白', poem: '尧没三千岁，青松古庙存。\n送行奠桂酒，拜舞清心魂。\n日色促归人，连歌倒芳樽。\n马嘶俱醉起，分手更何言。' },
  { title: '鲁郡尧祠送窦明府薄华还西京', author: '李白', poem: '朝策犂眉䯄，举鞭力不堪。\n强扶愁疾向何处，角巾微服尧祠南。\n长杨扫地不见日，石门喷作金沙潭。\n笑夸故人指绝境，山光水色青于蓝。\n庙中往往来击鼓，尧本无心尔何苦。\n门前长跪双石人，有女如花日歌舞。\n银鞍绣毂往复回，簸林蹶石鸣风雷。\n远烟空翠时明灭，白鸥历乱长飞雪。\n红泥亭子赤阑干，碧流环转青锦湍。\n深沈百丈洞海底，那知不有蛟龙蟠。\n君不见绿珠潭水流东海，绿珠红粉沈光彩。\n绿珠楼下花满园，今日曾无一枝在。\n昨夜秋声阊阖来，洞庭木落骚人哀。\n遂将三五少年辈，登高远望形神开。\n生前一笑轻九鼎，魏武何悲铜雀台。\n我歌白云倚牕牖，尔闻其声但挥手。\n长风吹月度海来，遥劝仙人一杯酒。\n酒中乐酣宵向分，举觞酹尧尧可闻。\n何不令臯繇拥篲横八极，直上青天挥浮云。\n高阳小饮真琐琐，山公酩酊何如我。\n竹林七子去道赊，兰亭雄笔安足夸。\n尧祠笑杀五湖水，至今顦悴空荷花。\n尔向西秦我东越，暂向瀛洲访金阙。\n蓝田太白若可期，为余扫洒石上月。' },
  { title: '金乡送韦八之西京', author: '李白', poem: '客自长安来，还归长安去。\n狂风吹我心，西挂咸阳树。\n此情不可道，此别何时遇。\n望望不见君，连山起烟雾。' },
  { title: '送薛九被谗去鲁', author: '李白', poem: '宋人不辨玉，鲁贱东家丘。\n我笑薛夫子，胡为两地游。\n黄金消众口，白璧竟难投。\n梧桐生蒺藜，绿竹乏佳实。\n凤凰宿谁家，遂与群鸡匹。\n田家养老马，穷士归其门。\n蛾眉笑躄者，宾客去平原。\n却斩美人首，三千还骏奔。\n毛公一挺劒，楚赵两相存。\n孟尝习狡兔，三窟赖冯谖。\n信陵夺兵符，为用侯生言。\n春申一何愚，刎首为李园。\n贤哉四公子，抚掌黄泉里。\n借问笑何人，笑人不好士。\n尔去且勿諠，桃李竟何言。\n沙丘无漂母，谁肯饭王孙。' },
  { title: '单父东楼秋夜送族弟沈之秦', author: '李白', poem: '尔从咸阳来，问我何劳苦。\n沐猴而冠不足言，身骑土牛滞东鲁。\n沈弟欲行凝弟留，孤飞一雁秦云秋。\n坐来黄叶落四五，北斗已挂西城楼。\n丝桐感人弦亦绝，满堂送君皆惜别。\n卷帘见月清兴来，疑是山阴夜中雪。\n明日斗酒别，惆怅清路尘。\n遥望长安日，不见长安人。\n长安宫阙九天上，此地曾经为近臣。\n一朝复一朝，发白心不改。\n屈原憔悴滞江潭，亭伯流离放辽海。\n折翮翻飞随转蓬，闻弦坠虚下霜空。\n圣朝久弃青云士，他日谁怜张长公。' },
  { title: '送族弟凝至晏堌', author: '李白', poem: '雪满原野白，戎装出盘游。\n挥鞭布猎骑，四顾登高丘。\n兔起马足间，苍鹰下平畴。\n喧呼相驰逐，取乐销人忧。\n舍此戒禽荒，微声列齐讴。\n鸣鸡发晏堌，别雁惊涞沟。\n西行有东音，寄与长河流。' },
  { title: '鲁城北郭曲腰桑下送张子还嵩阳', author: '李白', poem: '送别枯桑下，凋叶落半空。\n我行懵道远，尔独知天风。\n谁念张仲蔚，还依蒿与蓬。\n何时一杯酒，更与李膺同。' },
  { title: '送鲁郡刘长史迁弘农长史', author: '李白', poem: '鲁国一杯水，难容横海鳞。\n仲尼且不敬，况乃寻常人。\n白玉换斗粟，黄金买尺薪。\n闭门木叶下，始觉秋非春。\n闻君向西迁，地即鼎湖邻。\n宝镜匣苍藓，丹经埋素尘。\n轩后上天时，攀龙遗小臣。\n及此留惠爱，庶几风化淳。\n鲁缟如白烟，五缣不成束。\n临行赠贫交，一尺重山岳。\n相国齐晏子，赠行不及言。\n托阴当树李，忘忧当树萱。\n他日见张禄，绨袍怀旧恩。' },
  { title: '送族弟单父主簿凝摄宋城主簿至郭南月桥却回栖霞山留饮赠之', author: '李白', poem: '吾家青萍剑，操割有余闲。\n往来纠二邑，此去何时还。\n鞍马月桥南，光辉岐路间。\n贤豪相追饯，却到栖霞山。\n群花散芳园，斗酒开离颜。\n乐酣相顾起，征马无由攀。' },
  { title: '鲁郡东石门送杜二甫', author: '李白', poem: '醉别复几日，登临徧池台。\n何时石门路，重有金樽开。\n秋波落泗水，海色明徂徕。\n飞蓬各自远，且尽手中杯。' },
  { title: '鲁郡尧祠送张十四游河北', author: '李白', poem: '猛虎伏尺草，虽藏难蔽身。\n有如张公子，肮脏在风尘。\n岂无横腰劒，屈彼淮阴人。\n击筑向北燕，燕歌易水滨。\n归来泰山上，当与尔为邻。' },
  { title: '杭州送裴大泽赴庐州长史', author: '李白', poem: '西江天柱远，东越海门深。\n去割慈亲恋，行忧报国心。\n好风吹落日，流水引长吟。\n五月披裘者，应知不取金。' },
  { title: '灞陵行送别', author: '李白', poem: '送君灞陵亭，灞水流浩浩。\n上有无花之古树，下有伤心之春草。\n我向秦人问路岐，云是王粲南登之古道。\n古道连绵走西京，紫阙落日浮云生。\n正当今夕断肠处，黄鹂愁绝不忍听。' },
  { title: '送贺监归四明应制', author: '李白', poem: '久辞荣禄遂初衣，曾向长生说息机。\n真诀自从茅氏得，恩波宁阻洞庭归。\n瑶台含雾星辰满，仙峤浮空岛屿微。\n借问欲栖珠树鹤，何年却向帝城飞。' },
  { title: '送窦司马贬宜春', author: '李白', poem: '天马白银鞍，亲承明主欢。\n鬬鸡金宫里，射鴈碧云端。\n堂上罗中贵，歌钟清夜阑。\n何言谪南国，拂剑坐长叹。\n赵璧为谁点，隋珠枉被弹。\n圣朝多雨露，莫厌此行难。' },
  { title: '送羽林陶将军', author: '李白', poem: '将军出使拥楼船，江上旌旗拂紫烟。\n万里横戈探虎穴，三杯拔剑舞龙泉。\n莫道词人无胆气，临行将赠绕朝鞭。' },
  { title: '送程刘二侍郎兼独孤判官赴安西幕府', author: '李白', poem: '安西幕府多材雄，喧喧惟道三数公。\n绣衣貂裘明积雪，飞书走檄如飘风。\n朝辞明主出紫宫，银鞍送别金城空。\n天外飞霜下葱海，火旗云马生光彩。\n胡塞清尘几日归，汉家草绿遥相待。' },
  { title: '送姪良携二妓赴会稽戏有此赠', author: '李白', poem: '携妓东山去，春光半道催。\n遥看若桃李，双入镜中开。' },
  { title: '送贺宾客归越', author: '李白', poem: '镜湖流水漾清波，狂客归舟逸兴多。\n山阴道士如相见，应写黄庭换白鹅。' },
  { title: '送张遥之寿阳幕府', author: '李白', poem: '寿阳信天险，天险横荆关。\n苻坚百万众，遥阻八公山。\n不假筑长城，大贤在其间。\n战夫若熊虎，破敌有余闲。\n张子勇且英，少轻卫霍孱。\n投躯紫髯将，千里望风颜。\n勗尔効才略，功成衣锦还。' },
  { title: '送裴十八图南归嵩山二首 一', author: '李白', poem: '何处可为别，长安青绮门。\n胡姬招素手，延客醉金樽。\n临当上马时，我独与君言。\n风吹芳兰折，日没鸟雀喧。\n举手指飞鸿，此情难具论。\n同归无早晚，颍水有清源。' },
  { title: '送裴十八图南归嵩山二首 二', author: '李白', poem: '君思颍水绿，忽复归嵩岑。\n归时莫洗耳，为我洗其心。\n洗心得真情，洗耳徒买名。\n谢公终一起，相与济苍生。' },
  { title: '同王昌龄送族弟襄归桂阳二首 一', author: '李白', poem: '秦地见碧草，楚谣对清樽。\n把酒尔何思，鹧鸪啼南园。\n余欲罗浮隐，犹怀明主恩。\n踌躇紫宫恋，孤负沧洲言。\n终然无心云，海上同飞翻。\n相期乃不浅，幽桂有芳根。' },
  { title: '同王昌龄送族弟襄归桂阳二首 二', author: '李白', poem: '尔家何在潇湘川，青莎白石长沙边。\n昨梦江花照江日，几枝正发东牕前。\n觉来欲往心悠然，魂随越鸟飞南天。\n秦云连山海相接，桂水横烟不可涉。\n送君此去令人愁，风帆茫茫隔河洲。\n春潭琼草绿可折，西寄长安明月楼。' },
  { title: '送外甥郑灌从军三首 一', author: '李白', poem: '六博争雄好彩来，金盘一掷万人开。\n丈夫赌命报天子，当斩胡头衣锦回。' },
  { title: '送外甥郑灌从军三首 二', author: '李白', poem: '丈八蛇矛出陇西，弯弧拂箭白猨啼。\n破胡必用龙韬策，积甲应将熊耳齐。' },
  { title: '送外甥郑灌从军三首 三', author: '李白', poem: '月蚀西方破敌时，及瓜归日未应迟。\n斩胡血变黄河水，枭首当悬白鹊旗。' },
  { title: '送于十八应四子举落第还嵩山', author: '李白', poem: '吾祖吹橐籥，天人信森罗。\n归根复太素，群动熙元和。\n炎炎四真人，摛辩若涛波。\n交流无时寂，杨墨日成科。\n夫子闻洛诵，夸才才固多。\n为金好踊跃，久客方蹉跎。\n道可束卖之，五宝溢山河。\n劝君还嵩丘，开酌盼庭柯。\n三花如未落，乘兴一来过。' },
  { title: '送别', author: '李白', poem: '寻阳五溪水，沿洄直入巫山里。\n胜境由来人共传，君到南中自称美。\n送君别有八月秋，飒飒芦花复益愁。\n云帆望远不相见，日暮长江空自流。' },
  { title: '送族弟绾从军安西', author: '李白', poem: '汉家兵马乘北风，鼓行而西破犬戎。\n尔随汉将出门去，剪虏若草收奇功。\n君王按剑望边色，旄头已落胡天空。\n匈奴系头数应尽，明年应入蒲萄宫。' },
  { title: '送梁公昌从信安北征', author: '李白', poem: '入幕推英选，捐书事远戎。\n高谈百战术，郁作万夫雄。\n起舞莲花剑，行歌明月弓。\n将飞天地阵，兵出塞垣通。\n祖席留丹景，征麾拂彩虹。\n旋应献凯入，麟阁伫深功。' },
  { title: '送白利从金吾董将军西征', author: '李白', poem: '西羌延国讨，白起佐军威。\n剑决浮云气，弓弯明月辉。\n马行边草绿，旌卷曙霜飞。\n抗手凛相顾，寒风生铁衣。' },
  { title: '送张秀才从军', author: '李白', poem: '六驳食猛虎，耻从驽马群。\n一朝长鸣去，矫若龙行云。\n壮士怀远略，志存解世纷。\n周粟犹不顾，齐珪安肯分。\n抱剑辞高堂，将投崔冠军。\n长策扫河洛，宁亲归汝坟。\n当令千古后，麟阁着奇勋。' },
  { title: '送崔度还吴', author: '李白', poem: '幽燕沙雪地，万里尽黄云。\n朝吹归秋雁，南飞日几群。\n中有孤凤雏，哀鸣九天闻。\n我乃重此鸟，彩章五色分。\n胡为杂凡禽，雏鹜轻贱君。\n举手捧尔足，疾心若火焚。\n拂羽泪满面，送之吴江𣸣。\n去影忽不见，踌躇日将曛。' },
  { title: '送祝八之江东赋得浣纱石', author: '李白', poem: '西施越溪女，明艳光云海。\n未入吴王宫殿时，浣纱古石今犹在。\n桃李新开映古查，菖蒲犹短出平沙。\n昔时红粉照流水，今日青苔覆落花。\n君去西秦适东越，碧山青江几超忽。\n若到天涯思故人，浣纱石上窥明月。' },
  { title: '送侯十一', author: '李白', poem: '朱亥已击晋，侯嬴尚隐身。\n时无魏公子，岂贵抱关人。\n余亦不火食，游梁同在陈。\n空余湛卢剑，赠尔托交亲。' },
  { title: '鲁中送二从弟赴举之西京', author: '李白', poem: '鲁客向西笑，君门若梦中。\n霜凋逐臣发，日忆明光宫。\n复羡二龙去，才华冠世雄。\n平衢骋高足，逸翰凌长风。\n舞袖拂秋月，歌筵闻蚤鸿。\n送君日千里，良会何由同。' },
  { title: '奉饯高尊师如贵道士传道箓毕归北海', author: '李白', poem: '道隐不可见，灵书藏洞天。\n吾师四万劫，历世遰相传。\n别杖留青竹，行歌蹑紫烟。\n离心无远近，长在玉京悬。' },
  { title: '金陵送张十一再游东吴', author: '李白', poem: '张翰黄花句，风流五百年。\n谁人今继作，夫子世称贤。\n再动游吴櫂，还浮入海船。\n春光白门柳，霞色赤城天。\n去国难为别，思归各未旋。\n空余贾生泪，相顾共凄然。' },
  { title: '送纪秀才游越', author: '李白', poem: '海水不满眼，观涛难称心。\n即知蓬莱石，却是巨鼇簪。\n送尔游华顶，令余发舃吟。\n仙人居射的，道士住山阴。\n禹穴寻溪入，云门隔岭深。\n绿萝秋月夜，相忆在鸣琴。' },
  { title: '送长沙陈太守二首 一', author: '李白', poem: '长沙陈太守，逸气凌青松。\n英主赐五马，本是天池龙。\n湘水回九曲，衡山望五峰。\n荣君按节去，不及远相从。' },
  { title: '送长沙陈太守二首 二', author: '李白', poem: '七郡长沙国，南连湘水滨。\n定王垂舞袖，地窄不回身。\n莫小二千石，当安远俗人。\n洞庭乡路远，遥羡锦衣春。' },
  { title: '送杨燕之东鲁', author: '李白', poem: '关西杨伯起，汉日旧称贤。\n四代三公族，清风播人天。\n夫子华阴居，开门对玉莲。\n何事历衡霍，云帆今始还。\n君坐稍解颜，为君歌此篇。\n我固侯门士，谬登圣主筵。\n一辞金华殿，蹭蹬长江边。\n二子鲁门东，别来已经年。\n因君此中去，不觉泪如泉。' },
  { title: '送蔡山人', author: '李白', poem: '我本不弃世，世人自弃我。\n一乘无倪舟，八极纵远柂。\n燕客期跃马，唐生安敢讥。\n采珠勿惊龙，大道可暗归。\n故山有松月，迟尔玩清晖。' },
  { title: '送萧三十一之鲁中兼问稚子伯禽', author: '李白', poem: '六月南风吹白沙，吴牛喘月气成霞。\n水国郁蒸不可处，时炎道远无行车。\n夫子如何涉江路，云帆袅袅金陵去。\n高堂倚门望伯鱼，鲁中正是趋庭处。\n我家寄在沙丘傍，三年不归空断肠。\n君行既识伯禽子，应驾小车骑白羊。' },
  { title: '送杨山人归嵩山', author: '李白', poem: '我有万古宅，嵩阳玉女峰。\n长留一片月，挂在东溪松。\n尔去掇仙草，菖蒲花紫茸。\n岁晚或相访，青天骑白龙。' },
  { title: '送殷淑三首 一', author: '李白', poem: '海水不可解，连江夜为潮。\n俄然蒲屿阔，岸去酒船遥。\n惜别耐取醉，鸣榔且长谣。\n天明尔当去，应便有风飘。' },
  { title: '送殷淑三首 二', author: '李白', poem: '白鹭洲前月，天明送客回。\n青龙山后日，早出海云来。\n流水无情去，征帆逐吹开。\n相看不忍别，更进手中杯。' },
  { title: '送殷淑三首 三', author: '李白', poem: '痛饮龙筇下，灯青月复寒。\n醉歌惊白鹭，半夜起沙滩。' },
  { title: '送岑征君归鸣臯山', author: '李白', poem: '岑公相门子，雅望归安石。\n奕世皆夔龙，中台竟三拆。\n至人达机兆，高揖九州伯。\n奈何天地间，而作隐沦客。\n贵道能全真，潜辉卧幽邻。\n探元入窅默，观化游无垠。\n光武有天下，严陵为故人。\n虽登洛阳殿，不屈巢由身。\n余亦谢明主，今称偃蹇臣。\n登高览万古，思与广成邻。\n蹈海宁受赏，还山非问津。\n西来一摇扇，共拂元规尘。' },
  { title: '送范山人归泰山', author: '李白', poem: '鲁客抱白鹤，别余往泰山。\n初行若片云，杳在青崖间。\n高高至天门，日观近可攀。\n云山望不及，此去何时还。' },
  { title: '送韩侍御之广德', author: '李白', poem: '昔日绣衣何足荣，今宵贳酒与君倾。\n暂就东山赊月色，酣歌一夜送泉明。' },
  { title: '送通禅师还南陵隐静寺', author: '李白', poem: '我闻隐静寺，山水多奇踪。\n岩种朗公橘，门深杯渡松。\n道人制猛虎，振锡还孤峰。\n他日南陵下，相期谷口逢。' },
  { title: '送友人', author: '李白', poem: '青山横北郭，白水遶东城。\n此地一为别，孤蓬万里征。\n浮云游子意，落日故人情。\n挥手自兹去，萧萧班马鸣。' },
  { title: '江上送女道士褚三清游南岳', author: '李白', poem: '吴江女道士，头戴莲花巾。\n霓衣不湿雨，特异阳台云。\n足下远游履，凌波生素尘。\n寻仙向南岳，应见魏夫人。' },
  { title: '送友人入蜀', author: '李白', poem: '见说蚕丛路，崎岖不易行。\n山从人面起，云傍马头生。\n芳树笼秦栈，春流遶蜀城。\n升沉应已定，不必问君平。' },
  { title: '送李青归南叶阳川', author: '李白', poem: '伯阳仙家子，容色如青春。\n日月秘灵洞，云霞辞世人。\n化心养精魄，隐几窅天真。\n莫作千年别，归来城郭新。' },
  { title: '送舍弟', author: '李白', poem: '吾家白额驹，远别临东道。\n他日相思一梦君，应得池塘生春草。' },
  { title: '送别得书字', author: '李白', poem: '水色南天远，舟行若在虚。\n迁人发佳兴，吾子访闲居。\n日落看归鸟，潭澄羡跃鱼。\n圣朝思贾谊，应降紫泥书。' },
  { title: '送曲十少府', author: '李白', poem: '试发清秋兴，因为吴会吟。\n碧云歛海色，流水折江心。\n我有延陵剑，君无陆贾金。\n艰难此为别，惆怅一何深。' },
  { title: '送张秀才谒高中丞', author: '李白', poem: '秦帝沦玉镜，留侯降氛氲。\n感激黄石老，经过沧海君。\n壮士挥金槌，报讐六国闻。\n智勇冠终古，萧陈难与群。\n两龙争鬬时，天地动风云。\n酒酣舞长剑，仓卒解汉纷。\n宇宙初倒悬，鸿沟势将分。\n英谋信奇绝，夫子扬清芬。\n胡月入紫微，三光乱天文。\n高公镇淮海，谈笑却妖氛。\n采尔幕中画，戡难光殊勋。\n我无燕霜感，玉石俱烧焚。\n但洒一行泪，临岐竟何云。' },
  { title: '寻阳送弟昌峒鄱阳司马作', author: '李白', poem: '桑落洲渚连，沧江无云烟。\n浔阳非剡水，忽见子猷船。\n飘然欲相近，来迟杳若仙。\n人乘海上月，帆落湖中天。\n一覩无二诺，朝懽更胜昨。\n尔则吾惠连，吾非尔康乐。\n朱绂白银章，上官佐鄱阳。\n松门拂中道，石镜回清光。\n摇扇及于越，水亭风气凉。\n与尔期此亭，期在秋月满。\n时过或未来，两乡心已断。\n吴山对楚岸，彭蠡当中州。\n相思定如此，有穷尽年愁。' },
  { title: '饯校书叔云', author: '李白', poem: '少年费白日，歌笑矜朱颜。\n不知忽已老，喜见春风还。\n惜别且为欢，裴回桃李间。\n看花饮美酒，听鸟临晴山。\n向晚竹林寂，无人空闭关。' },
  { title: '送王孝廉觐省', author: '李白', poem: '彭蠡将天合，姑苏在日边。\n宁亲候海色，欲动孝廉船。\n窈窕晴江转，参差远岫连。\n相思无昼夜，东泣似长川。' },
  { title: '同吴王送杜秀芝赴举入京', author: '李白', poem: '秀才何翩翩，王许回也贤。\n暂别庐江守，将游京兆天。\n秋山宜落日，秀水出寒烟。\n欲折一枝桂，还来雁沼前。' },
  { title: '洞庭醉后送绛州吕使君果流澧州', author: '李白', poem: '昔别若梦中，天涯忽相逢。\n洞庭破秋月，纵酒开愁容。\n赠剑刻玉字，延平两蛟龙。\n送君不尽意，书及雁回峰。' },
  { title: '与诸公送陈郎将归衡阳', author: '李白', poem: '衡山苍苍入紫冥，下看南极老人星。\n回飙吹散五峰雪，往往飞花落洞庭。\n气清岳秀有如此，郎将一家拖金紫。\n门前食客乱浮云，世人皆比孟尝君。\n江上送行无白璧，临歧惆怅若为分。' },
  { title: '送赵判官赴黔府中丞叔幕', author: '李白', poem: '廓落青云心，交结黄金尽。\n富贵翻相忘，令人忽自哂。\n蹭蹬鬓毛斑，盛时难再还。\n巨源咄石生，何事马蹄间。\n绿萝长不厌，却欲还东山。\n君为鲁曾子，拜揖高堂里。\n叔继赵平原，偏承明主恩。\n风霜推独坐，旌节镇雄藩。\n虎士秉金钺，蛾眉开玉樽。\n才高幕下去，义重林中言。\n水宿五溪月，霜啼三峡猨。\n东风春草绿，江上候归轩。' },
  { title: '送陆判官往琵琶峡', author: '李白', poem: '水国秋风夜，殊非远别时。\n长安如梦里，何日是归期。' },
  { title: '送梁四归东平', author: '李白', poem: '玉壶挈美酒，送别强为欢。\n大火南星月，长郊北路难。\n殷王期负鼎，汶水起垂竿。\n莫学东山卧，参差老谢安。' },
  { title: '江夏送友人', author: '李白', poem: '雪点翠云裘，送君黄鹤楼。\n黄鹤振玉羽，西飞帝王州。\n凤无瑯玕实，何以赠远游。\n裴回相顾影，泪下汉江流。' },
  { title: '送郄昂谪巴中', author: '李白', poem: '瑶草寒不死，移植沧江滨。\n东风洒雨露，会入天地春。\n予若洞庭叶，随波送逐臣。\n思归未可得，书此谢情人。' },
  { title: '江夏送张丞', author: '李白', poem: '欲别心不忍，临行情更亲。\n酒倾无限月，客醉几重春。\n藉草依流水，攀花赠远人。\n送君从此去，回首泣迷津。' },
  { title: '赋得白鹭鸶送宋少府入三峡', author: '李白', poem: '白鹭拳一足，月明秋水寒。\n人惊远飞去，直向使君滩。' },
  { title: '送二季之江东', author: '李白', poem: '初发强中作，题诗与惠连。\n多惭一日长，不及二龙贤。\n西塞当中路，南风欲进船。\n云峰出远海，帆影挂清川。\n禹穴藏书地，匡山种杏田。\n此行俱有适，迟尔早归旋。' },
  { title: '江西送友人之罗浮', author: '李白', poem: '桂水分五岭，衡山朝九疑。\n乡关渺安西，流浪将何之。\n素色愁明湖，秋渚晦寒姿。\n畴昔紫芳意，已过黄发期。\n君王纵疎散，云壑借巢夷。\n尔去之罗浮，我还憩峨眉。\n中阔道万里，霞月遥相思。\n如寻楚狂子，琼树有芳枝。' },
  { title: '宣州谢朓楼饯别校书叔云', author: '李白', poem: '弃我去者昨日之日不可留，乱我心者今日之日多烦忧。\n长风万里送秋雁，对此可以酣高楼。\n蓬莱文章建安骨，中间小谢又清发。\n俱怀逸兴壮思飞，欲上青天览日月。\n抽刀断水水更流，举杯销愁愁更愁。\n人生在世不称意，明朝散发弄扁舟。' },
  { title: '宣城送刘副使入秦', author: '李白', poem: '君即刘越石，雄豪冠当时。\n凄清横吹曲，慷慨扶风词。\n虎啸俟腾跃，鸡鸣遭乱离。\n千金市骏马，万里逐王师。\n结交楼烦将，侍从羽林儿。\n统兵捍吴越，豺虎不敢窥。\n大勋竟莫叙，已过秋风吹。\n秉钺有季公，凛然负英姿。\n寄深且戎幕，望重必台司。\n感激一然诺，纵横两无疑。\n伏奏归北阙，鸣驺忽西驰。\n列将咸出祖，英僚惜分离。\n斗酒满四筵，歌啸宛溪湄。\n君携东山妓，我咏北门诗。\n贵贱交不易，恐伤中园葵。\n昔赠紫骝驹，今倾白玉巵。\n同欢万斛酒，未足解相思。\n此别又千里，秦吴渺天涯。\n月明关山苦，水剧陇头悲。\n借问几时还，春风入黄池。\n无令长相忆，折断绿杨枝。' },
  { title: '泾川送族弟𬭚', author: '李白', poem: '泾川三百里，若耶羞见之。\n锦石照碧山，两边白鹭鸶。\n佳境千万曲，客行无歇时。\n上有琴高水，下有陵阳祠。\n仙人不见我，明月空相知。\n问我何事来，卢敖结幽期。\n蓬山振雄笔，绣服挥清词。\n江湖发秀色，草木含荣滋。\n置酒送惠连，吾家称白眉。\n愧无海峤作，敢阙河梁诗。\n见尔复几朝，俄然告将离。\n中流漾彩鹢，列岸丛金羁。\n叹息苍梧凤，分栖琼树枝。\n清晨各飞去，飘落天南垂。\n望极落日尽，秋深暝猨悲。\n寄情与流水，但有长相思。' },
  { title: '五松山送殷淑', author: '李白', poem: '秀色发江左，风流奈若何。\n仲文了不还，独立扬清波。\n载酒五松山，颓然白云歌。\n中天度落月，万里遥相过。\n抚酒惜此月，流光畏蹉跎。\n明日别离去，连峰郁嵯峨。' },
  { title: '送崔氏昆季之金陵', author: '李白', poem: '放歌倚东楼，行子期晓发。\n秋风渡江来，吹落山上月。\n主人出美酒，灭烛延清光。\n二崔向金陵，安得不尽觞。\n水客弄归櫂，云帆卷轻霜。\n扁舟敬亭下，五两先飘扬。\n峡石入水花，碧流日更长。\n思君无岁月，西笑阻河梁。' },
  { title: '登黄山凌歊台送族弟溧阳尉济充泛舟赴华阴', author: '李白', poem: '鸾乃凤之族，翱翔紫云霓。\n文章辉五色，双在琼树栖。\n一朝各飞去，凤与鸾俱啼。\n炎赫五月中，朱曦烁河堤。\n尔从泛舟役，使我心魂凄。\n秦地无碧草，南云喧鼓鼙。\n君王减玉膳，早起思鸣鸡。\n漕引救关辅，疲人免涂泥。\n宰相作霖雨，农夫得耕犂。\n静者伏草间，群才满金闺。\n空手无壮士，穷居使人低。\n送君登黄山，长啸倚天梯。\n小舟若凫鴈，大舟若鲸鲵。\n开帆散长风，舒卷与云齐。\n日入牛渚晦，苍然夕烟迷。\n相思定何许，杳在洛阳西。' },
  { title: '送储邕之武昌', author: '李白', poem: '黄鹤西楼月，长江万里情。\n春风三十度，空忆武昌城。\n送尔难为别，衔杯惜未倾。\n湖连张乐地，山逐泛舟行。\n诺为楚人重，诗传谢朓清。\n沧浪吾有曲，寄入櫂歌声。' },
  { title: '詶谈少府', author: '李白', poem: '一尉居倏忽，梅生有僊骨。\n三事或可羞，匈奴哂千秋。\n壮士屈黄绶，浪迹寄沧洲。\n昨观荆岘作，如从云汉游。\n老夫当暮矣，蹀足惧骅骝。' },
  { title: '詶宇文少府见赠桃竹书筒', author: '李白', poem: '桃竹书筒绮绣文，良工巧妙称绝群。\n灵心圆映三江月，彩质叠成五色云。\n中藏宝诀峨眉去，千里提携长忆君。' },
  { title: '五月东鲁行荅汶上君', author: '李白', poem: '五月梅始黄，蚕凋桑柘空。\n鲁人重织作，机杼鸣帘栊。\n顾余不及仕，学剑来山东。\n举鞭访前途，获笑汶上翁。\n下愚忽壮士，未足论穷通。\n我以一箭书，能取聊城功。\n终然不受赏，羞与时人同。\n西归去直道，落日昏阴虹。\n此去尔勿言，甘心为转蓬。' },
  { title: '早秋单父南楼詶窦公衡', author: '李白', poem: '白露见日灭，红颜随霜凋。\n别君若俯仰，春芳辞秋条。\n泰山嵯峨夏云在，疑是白波涨东海。\n散为飞雨川上来，遥帷却卷清浮埃。\n知君独坐青轩下，此时结念同所怀。\n我闭南楼看道书，幽帘清寂在仙居。\n曾无好事来相访，赖尔高文一起予。' },
  { title: '山中问荅', author: '李白', poem: '问余何意栖碧山，笑而不荅心自闲。\n桃花流水窅然去，别有天地非人间。' },
  { title: '荅友人赠乌纱帽', author: '李白', poem: '领得乌纱帽，全胜白接䍠。\n山人不照镜，稚子道相宜。' },
  { title: '詶张司马赠墨', author: '李白', poem: '上党碧松烟，夷陵丹砂末。\n兰麝凝珍墨，精光乃堪掇。\n黄头奴子双鸦鬟，锦囊养之怀袖间。\n今日赠予兰亭去，兴来洒笔会稽山。' },
  { title: '荅湖州迦叶司马问白是何人', author: '李白', poem: '青莲居士谪仙人，酒肆藏名三十春。\n湖州司马何须问，金粟如来是后身。' },
  { title: '荅长安崔少府叔封游终南翠微寺太宗皇帝金沙泉见寄', author: '李白', poem: '河伯见海若，傲然夸秋水。\n小物昧远图，宁知通方士。\n多君紫霄意，独往苍山里。\n地古寒云深，岩高长风起。\n初登翠微岭，复憩金沙泉。\n践苔朝霜滑，弄波夕月圆。\n饮彼石下流，结萝宿溪烟。\n鼎湖梦渌水，龙驾空茫然。\n早行子午关，却登山路远。\n拂琴听霜猨，灭烛乃星饭。\n人烟无明异，鸟道绝往返。\n攀厓倒青天，下视白日晚。\n既过石门隐，还唱石潭歌。\n涉雪搴紫芳，濯缨想清波。\n此人不可见，此地君自过。\n为余谢风泉，其如幽意何。' },
  { title: '詶崔五郎中', author: '李白', poem: '朔云横高天，万里起秋色。\n壮士心飞扬，落日空叹息。\n长啸出原野，凛然寒风生。\n幸遭圣明时，功业犹未成。\n奈何怀良图，郁悒独愁坐。\n杖策寻英豪，立谈乃知我。\n崔公生民秀，缅邈青云姿。\n制作参造化，托讽含神祇。\n海岳尚可倾，吐诺终不移。\n是时霜飙寒，逸兴临华池。\n起舞拂长剑，四座皆扬眉。\n因得穷懽情，赠我以新诗。\n又结汗漫期，九垓远相待。\n举身憩蓬壶，濯足弄沧海。\n从此凌倒景，一去无时还。\n朝游明光宫，暮入阊阖关。\n但得长把袂，何必嵩丘山。' },
  { title: '以诗代书荅元丹丘', author: '李白', poem: '青鸟海上来，今朝发何处。\n口衔云锦字，与我忽飞去。\n鸟去凌紫烟，书留绮窗前。\n开缄方一笑，乃是故人传。\n故人深相勗，忆我劳心曲。\n离居在咸阳，三见秦草绿。\n置书双袂间，引领不暂闲。\n长望杳难见，浮云横远山。' },
  { title: '金门荅苏秀才', author: '李白', poem: '君还石门日，朱火始改木。\n春草如有情，山中尚含绿。\n折芳愧遥忆，永路当自勗。\n远见故人心，平生以此足。\n巨海纳百川，麟阁多才贤。\n献书入金阙，酌醴奉琼筵。\n屡忝白云唱，恭闻黄竹篇。\n恩光照拙薄，云汉希腾迁。\n铭鼎倘云逐，扁丹方渺然。\n我留在金门，君去卧丹壑。\n未果三山期，遥欣一丘乐。\n玄珠寄象罔，赤水非寥廓。\n愿狎东海鸥，共营西山药。\n栖岩君寂灭，处世余龙蠖。\n良辰不同赏，永日应闲居。\n鸟吟檐间树，花落窗下书。\n缘溪见绿筿，隔岫窥红蕖。\n采薇行笑歌，眷我情何已。\n月出石镜间，松鸣风琴里。\n得心自虚妙，外物空颓靡。\n身世如两忘，从君老烟水。' },
  { title: '詶坊州王司马与阎正字对雪见赠', author: '李白', poem: '游子东南来，自宛适京国。\n飘然无心云，倏忽复西北。\n访戴昔未偶，寻嵇此相得。\n愁颜发新懽，终宴叙前识。\n阎公汉庭旧，沈郁富才力。\n价重铜龙楼，声高重门侧。\n宁期此相遇，华馆陪游息。\n积雪明远峰，寒城锁春色。\n主人苍生望，假我青云翼。\n风水如见资，投竿佐皇极。' },
  { title: '詶中都小吏携斗酒双鱼于逆旅见赠', author: '李白', poem: '鲁酒若琥珀，汶鱼紫锦鳞。\n山东豪吏有俊气，手携此物赠远人。\n意气相倾两相顾，斗酒双鱼表情素。\n双鳃呀呷鳍鬣张，𫏆刺银盘欲飞去。\n呼儿拂几霜刃挥，红肌花落白雪霏。\n为君下筯一餐饱，醉着金鞍上马归。' },
  { title: '詶张卿夜宿南陵见赠', author: '李白', poem: '月出鲁城东，明如天上雪。\n鲁女惊莎鸡，鸣机应秋节。\n当君相思夜，火落金风高。\n河汉挂户牖，欲济无轻舠。\n我昔辞林丘，云龙忽相见。\n客星动太微，朝去洛阳殿。\n尔来得茂彦，七叶仕汉余。\n身为下邳客，家有圯桥书。\n傅说未梦时，终当起岩野。\n万古骑辰星，光辉照天下。\n与君各未遇，长策委蒿莱。\n宝刀隐玉匣，锈涩空莓苔。\n遂令世上愚，轻我土与灰。\n一朝攀龙去，鼃黾安在哉？\n故山定有酒，与尔倾金罍。' },
  { title: '詶岑勋见寻就元丹丘对酒相待以诗见招', author: '李白', poem: '黄鹤东南来，寄书写心曲。\n倚松开其缄，忆我肠断续。\n不以千里遥，命驾来相招。\n中逢元丹丘，登岭宴碧霄。\n对酒忽思我，长啸临清飙。\n蹇予未相知，茫茫绿云垂。\n俄然素书及，解此长渴饥。\n策马望山月，途穷造阶墀。\n喜兹一会面，若覩琼树枝。\n忆君我远来，我懽方速至。\n开颜酌美酒，乐极忽成醉。\n我情既不浅，君意方亦深。\n相知两相得，一顾轻千金。\n且向山客笑，与君论素心。' },
  { title: '荅从弟幼成过西园见赠', author: '李白', poem: '一身自潇洒，万物何嚣諠。\n拙薄谢明时，栖闲归故园。\n二季过旧壑，四邻驰华轩。\n衣剑照松宇，宾徒光石门。\n山童荐珍果，野老开芳樽。\n上陈樵渔事，下叙农圃言。\n昨来荷花满，今见兰苕繁。\n一笑复一歌，不知夕景昏。\n醉罢同所乐，此情难具论。' },
  { title: '詶王补阙惠翼庄庙宋丞泚赠别', author: '李白', poem: '学道三千春，自言羲和人。\n轩盖宛若梦，云松长相亲。\n偶将二公合，复与三山邻。\n喜结海上契，自为天外宾。\n鸾翮我先铩，龙性君莫驯。\n朴散不尚古，时讹皆失真。\n勿踏荒溪坡，朅来浩然津。\n薜带何辞楚，桃源堪避秦。\n世迫且离别，心在期隐沦。\n酬赠非炯诫，永言铭佩绅。' },
  { title: '詶裴侍御对雨感时见赠', author: '李白', poem: '雨色秋来寒，风严清江爽。\n孤高绣衣人，潇洒青霞赏。\n平生多感激，忠义非外奖。\n祸连积怨生，事及徂川往。\n楚邦有壮士，鄢郢翻扫荡。\n申包哭秦庭，泣血将安仰。\n鞭尸辱已及，堂上罗宿莽。\n颇似今之人，蟊贼陷忠谠。\n渺然一水隔，何由税归鞅。\n日夕听猨怨，怀贤盈梦想。' },
  { title: '詶崔侍御', author: '李白', poem: '严陵不从万乘游，归卧空山钓碧流。\n自是客星辞帝座，元非太白醉扬州。' },
  { title: '玩月金陵城西孙楚酒楼达曙歌吹日晚乘醉着紫绮裘乌纱巾与酒客数人櫂歌秦淮往石头访崔四侍御', author: '李白', poem: '昨玩西城月，青天垂玉钩。\n朝沽金陵酒，歌吹孙楚楼。\n忽忆绣衣人，乘船往石头。\n草裹乌纱巾，倒被紫绮裘。\n两岸拍手笑，疑是王子猷。\n酒客十数公，崩腾醉中流。\n谑浪櫂海客，喧呼傲阳侯。\n半道逢吴姬，卷帘出揶揄。\n我忆君到此，不知狂与羞。\n一月一见君，三杯便回桡。\n舍舟共连袂，行上南渡桥。\n兴发歌绿水，秦客为之摇。\n鸡鸣复相招，清宴逸云霄。\n赠我数百字，字字凌风飙。\n系之衣裘上，相忆每长谣。' },
  { title: '江上答崔宣城', author: '李白', poem: '太华三芙蓉，明星玉女峰。\n寻仙下西岳，陶令忽相逢。\n问我将何事，湍波历几重。\n貂裘非季子，鹤氅似王恭。\n谬忝燕台召，而陪郭隗踪。\n水流知入海，云去或从龙。\n树绕芦洲月，山鸣鹊镇钟。\n还期如可访，台岭荫长松。' },
  { title: '答族姪僧中孚赠玉泉仙人掌茶', author: '李白', poem: '常闻玉泉山，山洞多乳窟。\n仙鼠如白鸦，倒悬清溪月。\n茗生此中石，玉泉流不歇。\n根柯洒芳津，采服润肌骨。\n丛老卷绿叶，枝枝相接连。\n曝成仙人掌，似拍洪崖肩。\n举世未见之，其名定谁传。\n宗英乃禅伯，投赠有佳篇。\n清镜烛无盐，顾惭西子妍。\n朝坐有余兴，长吟播诸天。' },
  { title: '詶裴侍御留岫师弹琴见寄', author: '李白', poem: '君同鲍明远，邀彼休上人。\n鼓琴乱白雪，秋变江上春。\n瑶草绿未衰，攀翻寄情亲。\n相思两不见，流泪空盈巾。' },
  { title: '张相公出镇荆州寻除太子詹事余时流夜郎行至江夏与张公去千里公因太府丞王昔使车寄罗衣二事及五月五日赠余诗余答以此诗', author: '李白', poem: '张衡殊不乐，应有四愁诗。\n慙君锦绣段，赠我慰相思。\n鸿鹄复矫翼，凤凰忆故池。\n荣乐一如此，商山老紫芝。' },
  { title: '醉后荅丁十八以诗讥余搥碎黄鹤楼', author: '李白', poem: '黄鹤高楼已槌碎，黄鹤仙人无所依。\n黄鹤上天诉玉帝，却放黄鹤江南归。\n神明太守再雕饰，新图粉壁还芳菲。\n一州笑我为狂客，少年往往来相讥。\n君平帘下谁家子，云是辽东丁令威。\n作诗调我惊逸兴，白云遶笔窗前飞。\n待取明朝酒醒罢，与君烂漫寻春晖。' },
  { title: '荅裴侍御先行至石头驿以书见招期月满泛洞庭', author: '李白', poem: '君至石头驿，寄书黄鹤楼。\n开缄识远意，速此南行舟。\n风水无定准，湍波或滞留。\n忆昨新月生，西檐若琼钩。\n今来何所似，破镜悬清秋。\n恨不三五明，平湖泛澄流。\n此欢竟莫遂，狂杀王子猷。\n巴陵定遥远，持赠解人忧。' },
  { title: '荅高山人兼呈权顾二侯', author: '李白', poem: '虹霓掩天光，哲后起康济。\n应运生夔龙，开元扫氛翳。\n太微廓金镜，端拱清遐裔。\n轻尘集嵩岳，虚点盛明意。\n谬挥紫泥诏，献纳青云际。\n谗惑英主心，恩疎佞臣计。\n仿徨庭阙下，叹息光阴逝。\n未作仲宣诗，先流贾生涕。\n挂帆秋江上，不为云罗制。\n山海向东倾，百川无尽势。\n我于鸱夷子，相去千余岁。\n运阔英达稀，同风遥执袂。\n登舻望远水，忽见沧浪枻。\n高士何处来，虚舟渺安系。\n衣貌本淳古，文章多佳丽。\n延引故乡人，风义未沦替。\n顾侯达语默，权子识通蔽。\n曾是无心云，俱为此留滞。\n双萍易飘转，独鹤思凌厉。\n明晨去潇湘，共谒苍梧帝。' },
  { title: '荅杜秀才五松见赠', author: '李白', poem: '昔献长杨赋，天开云雨欢。\n当时待诏承明里，皆道扬雄才可观。\n勅赐飞龙二天马，黄金络头白玉鞍。\n浮云蔽日去不返，总为秋风摧紫兰。\n角巾东出商山道，采秀行歌咏芝草。\n路逢园绮笑向人，两君解来一何好。\n闻道金陵龙虎盘，还同谢朓望长安。\n千峰夹水向秋浦，五松名山当夏寒。\n铜井炎炉歊九天，赫如铸鼎荆山前。\n陶公瞿铄呵赤电，回禄睢盱扬紫烟。\n此中岂是久留处，便欲烧丹从列仙。\n爱听松风且高卧，飕飕吹尽炎氛过。\n登崖独立望九州，阳春欲奏谁相和。\n闻君往年游锦城，章仇尚书倒屣迎。\n飞笺洛绎奏明主，天书降问回恩荣。\n肮脏不能就珪组，至今空扬高蹈名。\n夫子工文绝世奇，五松新作天下推。\n吾非谢尚邀彦伯，异代风流各一时。\n一时相逢乐在今，袖拂白云开素琴，弹为三峡流泉音。\n从兹一别武陵去，去后桃花春水深。' },
  { title: '至陵阳山登天柱石詶韩侍御见招隐黄山', author: '李白', poem: '韩众骑白鹿，西往华山中。\n玉女千余人，相随在云空。\n见我传秘诀，精诚与天通。\n何意到陵阳，游目送飞鸿。\n天子昔避狄，与君亦乘骢。\n拥兵五陵下，长策遏胡戎。\n时泰解绣衣，脱身若飞蓬。\n鸾凤翻羽翼，啄粟坐樊笼。\n海鹤一笑之，思归向辽东。\n黄山过石柱，𪩘崿上攒丛。\n因巢翠玉树，忽见浮丘公。\n又引王子乔，吹笙舞松风。\n朗咏紫霞篇，请开蘂珠宫。\n步纲绕碧落，倚树招青童。\n何日可携手，遗形入无穷。' },
  { title: '詶崔十五见招', author: '李白', poem: '尔有鸟迹书，相招琴溪饮。\n手迹尺素中，如天落云锦。\n读罢向空笑，疑君在我前。\n长吟字不灭，怀袖且三年。' },
  { title: '荅王十二寒夜独酌有怀', author: '李白', poem: '昨夜吴中雪，子猷佳兴发。\n万里浮云卷碧山，青天中道流孤月。\n孤月沧浪河汉清，北斗错落长庚明。\n怀余对酒夜霜白，玉床金井水峥嵘。\n人生飘忽百年内，且须酣畅万古情。\n君不能狸膏金距学鬬鸡，坐令鼻息吹虹霓。\n君不能学哥舒横行青海夜带刀，西屠石堡取紫袍。\n吟诗作赋北牕里，万言不直一杯水。\n世人闻此皆掉头，有如东风射马耳。\n鱼目亦笑我，请与明月同。\n骅骝拳跼不能食，蹇驴得志鸣春风。\n折杨皇华合流俗，晋君听琴枉清角。\n巴人谁肯和阳春，楚地由来贱奇璞。\n黄金散尽交不成，白首为儒身被轻。\n一谈一笑失颜色，苍蝇贝锦喧谤声。\n曾参岂是杀人者，谗言三及慈母惊。\n与君论心握君手，荣辱于余亦何有。\n孔圣犹闻伤凤麟，董龙更是何鸡狗。\n一生傲岸苦不谐，恩疎媒劳志多乖。\n严陵高揖汉天子，何必长剑拄颐事玉阶。\n达亦不足贵，穷亦不足悲。\n韩信羞将绛灌比，祢衡耻逐屠沽儿。\n君不见李北海，英风豪气今何在？\n君不见裴尚书，土坟三尺蒿棘居。\n少年早欲五湖去，见此弥将钟鼎疎。' },
  { title: '游南阳白水登石激作', author: '李白', poem: '朝涉白水源，暂与人俗疎。\n岛屿佳境色，江天涵清虚。\n目送去海云，心闲游川鱼。\n长歌尽落日，乘月归田庐。' },
  { title: '游南阳清泠泉', author: '李白', poem: '惜彼落日暮，爱此寒泉清。\n西辉逐流水，荡漾游子情。\n空歌望云月，曲尽长松声。' },
  { title: '寻鲁城北范居士失道落苍耳中见范置酒摘苍耳作', author: '李白', poem: '雁度秋色远，日静无云时。\n客心不自得，浩漫将何之。\n忽忆范野人，闲园养幽姿。\n茫然起逸兴，但恐行来迟。\n城壕失往路，马首迷荒陂。\n不惜翠云裘，遂为苍耳欺。\n入门且一笑，把臂君为谁。\n酒客爱秋蔬，山盘荐霜梨。\n他筵不下筯，此席忘朝饥。\n酸枣垂北郭，寒瓜蔓东篱。\n还倾四五酌，自咏猛虎词。\n近作十日欢，远为千载期。\n风流自簸荡，谑浪偏相宜。\n酣来上马去，却笑高阳池。' },
  { title: '东鲁门泛舟二首 一', author: '李白', poem: '日落沙明天倒开，波摇石动水萦回。\n轻舟泛月寻溪转，疑是山隐雪后来。' },
  { title: '东鲁门泛舟二首 二', author: '李白', poem: '水作青龙盘石堤，桃花夹岸鲁门西。\n若教月下乘舟去，何啻风流到剡溪。' },
  { title: '秋猎孟诸夜归置酒单父东楼观妓', author: '李白', poem: '倾晖速短炬，走海无停川。\n冀餐圆丘草，欲以还颓年。\n此事不可得，微生若浮烟。\n骏发跨名驹，雕弓控鸣弦。\n鹰豪鲁草白，狐兔多肥鲜。\n邀遮相驰逐，遂出城东田。\n一扫四野空，喧呼鞍马前。\n归来献所获，炮炙宜霜天。\n出舞两美人，飘飖若云仙。\n留欢不知疲，清晓方来旋。' },
  { title: '游泰山六首 一', author: '李白', poem: '四月上泰山，石屏御道开。\n六龙过万壑，涧谷随萦回。\n马迹遶碧峰，于今满青苔。\n飞流洒绝𪩘，水急松声哀。\n北眺崿嶂奇，倾崖向东摧。\n洞门闭石扇，地底兴云雷。\n登高望蓬瀛，想象金银台。\n天门一长啸，万里清风来。\n玉女四五人，飘飖下九垓。\n含笑引素手，遗我流霞杯。\n稽首再拜之，自愧非仙才。\n旷然小宇宙，弃世何悠哉。' },
  { title: '游泰山六首 二', author: '李白', poem: '清晓骑白鹿，直上天门山。\n山际逢羽人，方瞳好容颜。\n扪萝欲就语，却掩青云关。\n遗我鸟迹书，飘然落岩间。\n其字乃上古，读之了不闲。\n感此三叹息，从师方未还。' },
  { title: '游泰山六首 三', author: '李白', poem: '平明登日观，举手开云关。\n精神四飞扬，如出天地间。\n黄河从西来，窈窕入远山。\n凭崖揽八极，目尽长空闲。\n偶然值青童，绿发双云鬟。\n笑我晚学仙，蹉跎凋朱颜。\n踌躇忽不见，浩荡难追攀。' },
  { title: '游泰山六首 四', author: '李白', poem: '清斋三千日，裂素写道经。\n吟诵有所得，众神卫我形。\n云行信长风，飒若羽翼生。\n攀崖上日观，伏槛窥东溟。\n海色动远山，天鸡已先鸣。\n银台出倒景，白浪翻长鲸。\n安得不死药，高飞向蓬瀛。' },
  { title: '游泰山六首 五', author: '李白', poem: '日观东北倾，两崖夹双石。\n海水落眼前，天光遥空碧。\n千峰争攒聚，万壑绝凌历。\n缅彼鹤上仙，去无云中迹。\n长松入云汉，远望不盈尺。\n山花异人间，五月雪中白。\n终当遇安期，于此炼玉液。' },
  { title: '游泰山六首 六', author: '李白', poem: '朝饮王母池，暝投天门关。\n独抱绿绮琴，夜行青山间。\n山明月露白，夜静松风歇。\n仙人游碧峰，处处笙歌发。\n寂静娱清晖，玉真连翠微。\n想象鸾凤舞，飘飖龙虎衣。\n扪天摘匏瓜，恍惚不忆归。\n举手弄清浅，误攀织女机。\n明晨坐相失，但见五云飞。' },
  { title: '秋夜与刘砀山泛宴喜亭池', author: '李白', poem: '明宰试舟楫，张灯宴华池。\n文招梁苑客，歌动郢中儿。\n月色望不尽，空天交相宜。\n令人欲泛海，只待长风吹。' },
  { title: '携妓登梁王栖霞山孟氏桃园中', author: '李白', poem: '碧草已满地，柳与梅争春。\n谢公自有东山妓，金屏笑坐如花人。\n今日非昨日，明日还复来。\n白发对绿酒，强歌心已摧。\n君不见梁王池上月，昔照梁王樽酒中。\n梁王已去明月在，黄鹂愁醉啼春风。\n分明感激眼前事，莫惜醉卧桃园东。' },
  { title: '与从姪杭州刺史良游天竺寺', author: '李白', poem: '挂席凌蓬丘，观涛憩樟楼。\n三山动逸兴，五马同遨游。\n天竺森在眼，松风飒惊秋。\n览云测变化，弄水穷清幽。\n叠嶂隔遥海，当轩写归流。\n诗成傲云月，佳趣满吴洲。' },
  { title: '同友人舟行游台越作', author: '李白', poem: '楚臣伤江枫，谢客拾海月。\n怀沙去潇湘，挂席泛溟渤。\n蹇予访前迹，独往造穷发。\n古人不可攀，去若浮云没。\n愿言弄倒景，从此炼真骨。\n华顶窥绝溟，蓬壶望超忽。\n不知青春度，但怪绿芳歇。\n空持钓鼇心，从此谢魏阙。' },
  { title: '下终南山过斛斯山人宿置酒', author: '李白', poem: '暮从碧山下，山月随人归。\n却顾所来径，苍苍横翠微。\n相携及田家，童稚开荆扉。\n绿竹入幽径，青萝拂行衣。\n欢言得所憩，美酒聊共挥。\n长歌吟松风，曲尽河星稀。\n我醉君复乐，陶然共忘机。' },
  { title: '朝下过卢郎中叙旧游', author: '李白', poem: '君登金华省，我入银台门。\n幸遇圣明主，俱承云雨恩。\n复此休浣时，闲为畴昔言。\n却话山海事，宛然林壑存。\n明湖思晓月，叠嶂忆清猿。\n何由返初服，田野醉芳樽。' },
  { title: '侍从游宿温泉宫作', author: '李白', poem: '羽林十二将，罗列应星文。\n霜仗悬秋月，霓旌卷夜云。\n严更千户肃，清乐九天闻。\n日出瞻佳气，葱葱绕圣君。' },
  { title: '邯郸南亭观妓', author: '李白', poem: '歌鼓燕赵儿，魏姝弄鸣丝。\n粉色艳日彩，舞袖拂花枝。\n把酒顾美人，请歌邯郸词。\n清筝何缭绕，度曲绿云垂。\n平原君安在，科斗生古池。\n座客三千人，于今知有谁。\n我辈不作乐，但为后代悲。' },
  { title: '春日游罗敷潭', author: '李白', poem: '行歌入谷口，路尽无人跻。\n攀崖度绝壑，弄水寻回溪。\n云从石上起，客到花间迷。\n淹留未尽兴，日落群峰西。' },
  { title: '春陪商州裴使君游石娥溪', author: '李白', poem: '裴公有僊标，拔俗数千丈。\n澹荡沧洲云，飘飖紫霞想。\n剖竹商洛间，政成心已闲。\n萧条出世表，冥寂闭玄关。\n我来属芳节，解榻时相悦。\n褰帷对云峰，扬袂指松雪。\n𫏐出东城边，遂游西岩前。\n横天耸翠壁，喷壑鸣红泉。\n寻幽殊未歇，爱此春光发。\n溪傍饶名花，石上有好月。\n命驾归去来，露华生翠苔。\n淹留惜将晚，复听清猨哀。\n清猨断人肠，游子思故乡。\n明发首东路，此懽焉可忘。' },
  { title: '陪从祖济南太守泛鹊山湖三首 一', author: '李白', poem: '初谓鹊山近，宁知湖水遥。\n此行殊访戴，自可缓归桡。' },
  { title: '陪从祖济南太守泛鹊山湖三首 二', author: '李白', poem: '湖阔数千里，湖光摇碧山。\n湖西正有月，独送李膺还。' },
  { title: '陪从祖济南太守泛鹊山湖三首 三', author: '李白', poem: '水入北湖去，舟从南浦回。\n遥看鹊山转，却似送人来。' },
  { title: '春日陪杨江宁及诸官宴北湖感古作', author: '李白', poem: '昔闻颜光禄，攀龙宴京湖。\n楼船入天镜，帐殿开云衢。\n君王歌大风，如乐丰沛都。\n延年献佳作，邈与诗人俱。\n我来不及此，独立钟山孤。\n杨宰穆清风，芳声腾海隅。\n英僚满四座，粲若琼林敷。\n鹢首弄倒景，蛾眉缀明珠。\n新弦采梨园，古舞娇吴歈。\n曲度绕云汉，听者皆欢娱。\n鸡栖何嘈嘈，沿月沸笙竽。\n古之帝宫苑，今乃人樵苏。\n感此劝一觞，愿君覆瓢壶。\n荣盛当作乐，无令后贤吁。' },
  { title: '宴郑参卿山池', author: '李白', poem: '尔恐碧草晚，我畏朱颜移。\n愁看杨花飞，置酒正相宜。\n歌声送落日，舞影回清池。\n今夕不尽杯，留欢更邀谁。' },
  { title: '游谢氏山亭', author: '李白', poem: '沦老卧江海，再欢天地清。\n病闲久寂寞，岁物徒芬荣。\n借君西池游，聊以散我情。\n扫雪松下去，扪萝石道行。\n谢公池塘上，春草飒已生。\n花枝拂人来，山鸟向我鸣。\n田家有美酒，落日与之倾。\n醉罢弄归月，遥欣稚子迎。' },
  { title: '把酒问月', author: '李白', poem: '青天有月来几时，我今停杯一问之。\n人攀明月不可得，月行却与人相随。\n皎如飞镜临丹阙，绿烟灭尽清辉发。\n但见宵从海上来，宁知晓向云间没。\n白兔捣药秋复春，嫦娥孤栖与谁邻。\n今人不见古时月，今月曾经照古人。\n古人今人若流水，共看明月皆如此。\n唯愿当歌对酒时，月光长照金樽里。' },
  { title: '同族姪评事黯游昌禅师山池二首 一', author: '李白', poem: '远公爱康乐，为我开禅关。\n萧然松石下，何异清凉山。\n花将色不染，水与心俱闲。\n一坐度小劫，观空天地间。' },
  { title: '同族姪评事黯游昌禅师山池二首 二', author: '李白', poem: '客来花雨际，秋水落金池。\n片石寒青锦，疎杨挂绿丝。\n高僧拂玉柄，童子献霜梨。\n惜去爱佳景，烟萝欲暝时。' },
  { title: '金陵凤凰台置酒', author: '李白', poem: '置酒延落景，金陵凤凰台。\n长波写万古，心与云俱开。\n借问往昔时，凤凰为谁来。\n凤凰去已久，正当今日回。\n明君越羲轩，天老坐三台。\n豪士无所用，弹弦醉金罍。\n东风吹山花，安可不尽杯。\n六帝没幽草，深宫冥绿苔。\n置酒勿复道，歌钟但相催。' },
  { title: '秋浦清溪雪夜对酒客有唱山鹧鸪者', author: '李白', poem: '披君貂襜褕，对君白玉壶。\n雪花酒上灭，顿觉夜寒无。\n客有桂阳至，能吟山鹧鸪。\n清风动窗竹，越鸟起相呼。\n持此足为乐，何烦笙与竽。' },
  { title: '与周刚清溪玉镜潭宴别', author: '李白', poem: '康乐上官去，永嘉游石门。\n江亭有孤屿，千载迹犹存。\n我来游秋浦，三入桃陂源。\n千峰照积雪，万壑尽啼猨。\n兴与谢公合，文因周子论。\n扫厓去落叶，席月开清樽。\n溪当大楼南，溪水正南奔。\n回作玉镜潭，澄明洗心魂。\n此中得佳境，可以绝嚣喧。\n清夜方归来，酣歌出平原。\n别后经此地，为余谢兰荪。' },
  { title: '游秋浦白笴陂二首 一', author: '李白', poem: '何处夜行好，月明白笴陂。\n山光摇积雪，猨影挂寒枝。\n但恐佳景晚，小令归櫂移。\n人来有清兴，及此有相思。' },
  { title: '游秋浦白笴陂二首 二', author: '李白', poem: '白笴夜长啸，爽然溪谷寒。\n鱼龙动陂水，处处生波澜。\n天借一明月，飞来碧云端。\n故乡不可见，肠断正西看。' },
  { title: '宴陶家亭子', author: '李白', poem: '曲巷幽人宅，高门大士家。\n池开照胆镜，林吐破颜花。\n绿水藏春日，青轩秘晚霞。\n若闻弦管妙，金谷不能夸。' },
  { title: '在水军宴韦司马楼船观妓', author: '李白', poem: '摇曳帆在空，清流顺归风。\n诗因鼓吹发，酒为劒歌雄。\n对舞青楼妓，双鬟白玉童。\n行云且莫去，留醉楚王宫。' },
  { title: '流夜郎至江夏陪长史叔及薛明府宴兴德寺南阁', author: '李白', poem: '绀殿横江上，青山落镜中。\n岸回沙不尽，日暎水成空。\n天乐流香阁，莲舟飏晚风。\n恭陪竹林宴，留醉与陶公。' },
  { title: '泛沔州城南郎官湖', author: '李白', poem: '张公多逸兴，共泛沔城隅。\n当时秋月好，不减武昌都。\n四座醉清光，为欢古来无。\n郎官爱此水，因号郎官湖。\n风流若未减，名与此山俱。' },
  { title: '陪侍郎叔游洞庭醉后三首 一', author: '李白', poem: '今日竹林宴，我家贤侍郎。\n三杯容小阮，醉后发清狂。' },
  { title: '陪侍郎叔游洞庭醉后三首 二', author: '李白', poem: '船上齐桡乐，湖心泛月归。\n白鸥闲不去，争拂酒筵飞。' },
  { title: '陪侍郎叔游洞庭醉后三首 三', author: '李白', poem: '刬却君山好，平铺湘水流。\n巴陵无限酒，醉杀洞庭秋。' },
  { title: '夜泛洞庭寻裴侍御清酌', author: '李白', poem: '日晚湘水绿，孤舟无端倪。\n明湖涨秋月，独泛巴陵西。\n过憩裴逸人，岩居陵丹梯。\n抱琴出深竹，为我弹鹍鸡。\n曲尽酒亦倾，北窗醉如泥。\n人生且行乐，何必组与珪。' },
  { title: '陪族叔刑部侍郎晔及中书贾舍人至游洞庭五首 一', author: '李白', poem: '洞庭西望楚江分，水尽南天不见云。\n日落长沙秋色远，不知何处吊湘君。' },
  { title: '陪族叔刑部侍郎晔及中书贾舍人至游洞庭五首 二', author: '李白', poem: '南湖秋水夜无烟，耐可乘流直上天。\n且就洞庭赊月色，将船买酒白云边。' },
  { title: '陪族叔刑部侍郎晔及中书贾舍人至游洞庭五首 三', author: '李白', poem: '洛阳才子谪湘川，元礼同舟月下仙。\n记得长安还欲笑，不知何处是西天。' },
  { title: '陪族叔刑部侍郎晔及中书贾舍人至游洞庭五首 四', author: '李白', poem: '洞庭湖西秋月辉，潇湘江北早鸿飞。\n醉客满船歌白苎，不知霜露入秋衣。' },
  { title: '陪族叔刑部侍郎晔及中书贾舍人至游洞庭五首 五', author: '李白', poem: '帝子潇湘去不还，空余秋草洞庭间。\n淡扫明湖开玉镜，丹青画出是君山。' },
  { title: '楚江黄龙矶南宴杨执戟治楼', author: '李白', poem: '五月入五洲，碧山对青楼。\n故人杨执戟，春赏楚江流。\n一见醉漂月，三杯歌櫂讴。\n桂枝攀不尽，他日更相求。' },
  { title: '铜官山醉后绝句', author: '李白', poem: '我爱铜官乐，千年未拟还。\n要须回舞袖，拂尽五松山。' },
  { title: '与南陵常赞府游五松山', author: '李白', poem: '安石泛溟渤，独啸长风还。\n逸韵动海上，高情出人间。\n灵异可并迹，澹然与世闲。\n我来五松下，置酒穷跻攀。\n征古绝遗老，因名五松山。\n五松何清幽，胜境美沃州。\n萧飒鸣洞壑，终年风雨秋。\n响入百泉去，听如三峡流。\n剪竹扫天花，且从傲吏游。\n龙堂若可憩，吾欲归精修。' },
  { title: '宣城青溪', author: '李白', poem: '青溪胜桐庐，水木有佳色。\n山貌日高古，石容天倾侧。\n彩鸟昔未名，白猨初相识。\n不见同怀人，对之空叹息。' },
  { title: '与谢良辅游泾川陵岩寺', author: '李白', poem: '乘君素舸泛泾西，宛似云门对若溪。\n且从康乐寻山水，何必东游入会稽。' },
  { title: '游水西简郑明府', author: '李白', poem: '天宫水西寺，云锦照东郭。\n清湍鸣回溪，绿水遶飞阁。\n凉风日潇洒，幽客时憩泊。\n五月思貂裘，谓言秋霜落。\n石萝引古蔓，岸笋开新箨。\n吟玩空复情，相思尔佳作。\n郑公诗人秀，逸韵宏寥廓。\n何当一来游，惬我雪山诺。' },
  { title: '九日登山', author: '李白', poem: '渊明归去来，不与世相逐。\n为无杯中物，遂偶本州牧。\n因招白衣人，笑酌黄花菊。\n我来不得意，虚过重阳时。\n题舆何俊发，遂结城南期。\n筑土按响山，俯临宛水湄。\n胡人呌玉笛，越女弹霜丝。\n自作英王胄，斯乐不可窥。\n赤鲤涌琴高，白龟道冯夷。\n灵仙如仿佛，奠酹遥相知。\n古来登高人，今复几人在。\n沧洲违宿诺，明日犹可待。\n连山似惊波，合沓出溟海。\n扬袂挥四座，酩酊安所知。\n齐歌送清扬，起舞乱参差。\n宾随落叶散，帽逐秋风吹。\n别后登此台，愿言长相思。' },
  { title: '九日', author: '李白', poem: '今日云景好，水绿秋山明。\n携壶酌流霞，搴菊泛寒荣。\n地远松石古，风扬弦管清。\n窥觞照欢颜，独笑还自倾。\n落帽醉山月，空歌怀友生。' },
  { title: '九日龙山饮', author: '李白', poem: '九日龙山饮，黄花笑逐臣。\n醉看风落帽，舞爱月留人。' },
  { title: '九月十日即事', author: '李白', poem: '昨日登高罢，今朝更举觞。\n菊花何太苦，遭此两重阳。' },
  { title: '陪族叔当涂宰游化城寺升公清风亭', author: '李白', poem: '化城若化出，金牓天宫开。\n疑是海上云，飞空结楼台。\n升公湖上秀，粲然有辩才。\n济人不利己，立俗无嫌猜。\n了见水中月，青莲出尘埃。\n闲居清风亭，左右清风来。\n当暑阴广殿，太阳为裴回。\n茗酌待幽客，珍盘荐雕梅。\n飞文何洒落，万象为之摧。\n季父拥鸣琴，德声布云雷。\n虽游道林室，亦举陶潜杯。\n清乐动诸天，长松自吟哀。\n留欢若可尽，劫石乃成灰。' },
  { title: '登锦城散花楼', author: '李白', poem: '日照锦城头，朝光散花楼。\n金窗夹绣户，珠箔悬银钩。\n飞梯绿云中，极目散我忧。\n暮雨向三峡，春江绕双流。\n今来一登望，如上九天游。' },
  { title: '登峨眉山', author: '李白', poem: '蜀国多仙山，峨眉邈难匹。\n周流试登览，绝怪安可息。\n青冥倚天开，彩错疑画出。\n泠然紫霞赏，果得锦囊术。\n云间吟琼箫，石上弄宝瑟。\n平生有微尚，欢笑自此毕。\n烟容如在颜，尘累忽相失。\n傥逢骑羊子，携手凌白日。' },
  { title: '大庭库', author: '李白', poem: '朝登大庭库，云物何苍然。\n莫辨陈郑火，空霾邹鲁烟。\n我来寻梓慎，观化入寥天。\n古木朔气多，松风如五弦。\n帝图终冥没，叹息满山川。' },
  { title: '登单父陶少府半月台', author: '李白', poem: '陶公有逸兴，不与常人俱。\n筑台像半月，回向高城隅。\n置酒望白云，商飙起寒梧。\n秋山入远海，桑柘罗平芜。\n水色渌且明，令人思镜湖。\n终当过江去，爱此暂踟蹰。' },
  { title: '天台晓望', author: '李白', poem: '天台邻四明，华顶高百越。\n门标赤城霞，楼栖沧岛月。\n凭高登远览，直下见溟渤。\n云垂大鹏翻，波动巨鼇没。\n风潮争汹涌，神怪何翕忽。\n观奇迹无倪，好道心不歇。\n攀条摘朱实，服药炼金骨。\n安得生羽毛，千春卧蓬阙。' },
  { title: '早望海霞边', author: '李白', poem: '四明三千里，朝起赤城霞。\n日出红光散，分辉照雪厓。\n一餐咽琼液，五内发金沙。\n举手何所待，青龙白虎车。' },
  { title: '焦山望寥山', author: '李白', poem: '石壁望松寥，宛然在碧霄。\n安得五彩虹，驾天作长桥。\n仙人如爱我，举手来相招。' },
  { title: '杜陵绝句', author: '李白', poem: '南登杜陵上，北望五陵间。\n秋水明落日，流光灭远山。' },
  { title: '登太白峰', author: '李白', poem: '西上太白峰，夕阳穷登攀。\n太白与我语，为我开天关。\n愿乘泠风去，直出浮云间。\n举手可近月，前行若无山。\n一别武功去，何时复见还。' },
  { title: '登邯郸洪波台置酒观发兵', author: '李白', poem: '我把两赤羽，来游燕赵间。\n天狼正可射，感激无时闲。\n观兵洪波台，倚劒望玉关。\n请缨不系越，且向燕然山。\n风引龙虎旗，歌钟昔追攀。\n击筑落高月，投壶破愁颜。\n遥知百战胜，定扫鬼方还。' },
  { title: '登新平楼', author: '李白', poem: '去国登兹楼，怀归伤暮秋。\n天长落日远，水净寒波流。\n秦云起岭树，胡雁飞沙洲。\n苍苍几万里，目极令人愁。' },
  { title: '谒老君庙', author: '李白', poem: '先君怀圣德，灵庙肃神心。\n草合人踪断，尘浓鸟迹深。\n流沙丹灶灭，关路紫烟沈。\n独伤千载后，空余松柏林。' },
  { title: '秋日登扬州西灵塔', author: '李白', poem: '宝塔凌苍苍，登攀览四荒。\n顶高元气合，标出海云长。\n万象分空界，三天接画梁。\n水摇金刹影，日动火珠光。\n鸟拂琼帘度，霞连绣栱张。\n目随征路断，心逐去帆扬。\n露浴梧楸白，霜催橘柚黄。\n玉毫如可见，于此照迷方。' },
  { title: '登金陵冶城西北谢安墩', author: '李白', poem: '晋室昔横溃，永嘉遂南奔。\n沙尘何茫茫，龙虎鬬朝昏。\n胡马风汉草，天骄蹙中原。\n哲匠感颓运，云鹏忽飞翻。\n组练照楚国，旌旗连海门。\n西秦百万众，戈甲如云屯。\n投鞭可填江，一埽不足论。\n皇运有返正，丑虏无遗魂。\n谈笑遏横流，苍生望斯存。\n冶城访古迹，犹有谢安墩。\n凭览周地险，高标绝人喧。\n想像东山姿，缅怀右军言。\n梧桐识嘉树，蕙草留芳根。\n白鹭暎春洲，青龙见朝暾。\n地古云物在，台倾禾黍繁。\n我来酌清波，于此树名园。\n功成拂衣去，归入武陵源。' },
  { title: '登瓦官阁', author: '李白', poem: '晨登瓦官阁，极眺金陵城。\n钟山对北户，淮水入南荣。\n漫漫雨花落，嘈嘈天乐鸣。\n两廊振法鼓，四角吟风筝。\n杳出霄汉上，仰攀日月行。\n山空霸气灭，地古寒阴生。\n寥廓云海晚，苍茫宫观平。\n门余阊阖字，楼识凤凰名。\n雷作百山动，神扶万栱倾。\n灵光何足贵，长此镇吴京。' },
  { title: '登梅冈望金陵赠族姪高座寺僧中孚', author: '李白', poem: '钟山抱金陵，霸气昔腾发。\n天开帝王居，海色照宫阙。\n群峰如逐鹿，奔走相驰突。\n江水九道来，云端遥明没。\n时迁大运去，龙虎势休歇。\n我来属天清，登览穷楚越。\n吾宗挺禅伯，特秀鸾凤骨。\n众星罗青天，明者独有月。\n冥居顺生理，草木不剪伐。\n烟窗引蔷薇，石壁老野蕨。\n吴风谢安屐，白足傲履韈。\n几宿一下山，萧然忘干谒。\n谈经演金偈，降鹤舞海雪。\n时闻天香来，了与世事绝。\n佳游不可得，春风惜远别。\n赋诗留岩屏，千载庶不灭。' },
  { title: '登金陵凤凰台', author: '李白', poem: '凤凰台上凤凰游，凤去台空江自流。\n吴宫花草埋幽径，晋代衣冠成古丘。\n三山半落青天外，二水中分白鹭洲。\n总为浮云能蔽日，长安不见使人愁。' },
  { title: '望庐山瀑布水二首 一', author: '李白', poem: '西登香炉峰，南见瀑布水。\n挂流三百丈，喷壑数十里。\n歘如飞电来，隐若白虹起。\n初惊河汉落，半洒云天里。\n仰观势转雄，壮哉造化功。\n海风吹不断，江月照还空。\n空中乱潨射，左右洗青壁。\n飞珠散轻霞，流沫沸穹石。\n而我乐名山，对之心益闲。\n无论潄琼液，还得洗尘颜。\n且谐宿所好，永愿辞人间。' },
  { title: '望庐山瀑布水二首 二', author: '李白', poem: '日照香炉生紫烟，遥看瀑布挂前川。\n飞流直下三千尺，疑是银河落九天。' },
  { title: '登庐山五老峰', author: '李白', poem: '庐山东南五老峰，青天削出金芙蓉。\n九江秀色可揽结，吾将此地巢云松。' },
  { title: '江上望皖公山', author: '李白', poem: '奇峰出奇云，秀木含秀气。\n清宴皖公山，巉绝称人意。\n独游沧江上，终日淡无味。\n但爱兹岭高，何由讨灵异。\n默然遥相许，欲徃心莫遂。\n待吾还丹成，投迹归此地。' },
  { title: '望黄鹤楼', author: '李白', poem: '东望黄鹤山，雄雄半空出。\n四面生白云，中峰倚红日。\n岩峦行穹跨，峰嶂亦冥密。\n颇闻列仙人，于此学飞术。\n一朝向蓬海，千载空石室。\n金灶生烟埃，玉潭秘清谧。\n地古遗草木，庭寒老芝术。\n蹇予羡攀跻，因欲保闲逸。\n观奇徧诸岳，兹岭不可匹。\n结心寄青松，永悟客情毕。' },
  { title: '鹦鹉洲', author: '李白', poem: '鹦鹉来过吴江水，江上洲传鹦鹉名。\n鹦鹉西飞陇山去，芳洲之树何青青。\n烟开兰叶香风暖，岸夹桃花锦浪生。\n迁客此时徒极目，长洲孤月向谁明。' },
  { title: '九日登巴陵置酒望洞庭水军', author: '李白', poem: '九日天气清，登高无秋云。\n造化辟川岳，了然楚汉分。\n长风鼓横波，合沓蹙龙文。\n忆昔传游豫，楼船壮横汾。\n今兹讨鲸鲵，旌斾何缤纷。\n白羽落酒樽，洞庭罗三军。\n黄花不掇手，战鼓遥相闻。\n劒舞转颓阳，当时日停曛。\n酣歌激壮士，可以摧妖氛。\n龌龊东篱下，渊明不足群。' },
  { title: '秋登巴陵望洞庭', author: '李白', poem: '清晨登巴陵，周览无不极。\n明湖暎天光，彻底见秋色。\n秋色何苍然，际海俱澄鲜。\n山青灭远树，水绿无寒烟。\n来帆出江中，去鸟向日边。\n风清长沙浦，山空云梦田。\n瞻光惜颓发，阅水悲徂年。\n北渚既荡漾，东流自潺湲。\n郢人唱白雪，越女歌采莲。\n听此更肠断，凭厓泪如泉。' },
  { title: '与夏十二登岳阳楼', author: '李白', poem: '楼观岳阳尽，川逈洞庭开。\n雁引愁心去，山衔好月来。\n云间连下榻，天上接行杯。\n醉后凉风起，吹人舞袖回。' },
  { title: '登巴陵开元寺西阁赠衡岳僧方外', author: '李白', poem: '衡岳有阐士，五峰秀真骨。\n见君万里心，海水照秋月。\n大臣南溟去，问道皆请谒。\n洒以甘露言，清凉润肌发。\n明湖落天镜，香阁凌银阙。\n登眺餐惠风，新花期启发。' },
  { title: '与贾至舍人于龙兴寺剪落梧桐枝望㴩湖', author: '李白', poem: '剪落青梧枝，㴩湖坐可窥。\n雨洗秋山净，林光澹碧滋。\n水闲明镜转，云绕画屏移。\n千古风流事，名贤共此时。' },
  { title: '挂席江上待月有怀', author: '李白', poem: '待月月未出，望江江自流。\n倏忽城西郭，青天悬玉钩。\n素华虽可揽，清景不可游。\n耿耿金波里，空瞻𫛛鹊楼。' },
  { title: '金陵望汉江', author: '李白', poem: '汉江回万里，派作九龙盘。\n横溃豁中国，崔嵬飞迅湍。\n六帝沦亡后，三吴不足观。\n我君混区宇，垂拱众流安。\n今日任公子，沧浪罢钓竿。' },
  { title: '秋登宣城谢朓北楼', author: '李白', poem: '江城如画里，山晓望晴空。\n两水夹明镜，双桥落彩虹。\n人烟寒橘柚，秋色老梧桐。\n谁念北楼上，临风怀谢公。' },
  { title: '望天门山', author: '李白', poem: '天门中断楚江开，碧水东流至北回。\n两岸青山相对出，孤帆一片日边来。' },
  { title: '望木瓜山', author: '李白', poem: '早起见日出，暮见栖鸟还。\n客心自酸楚，况对木瓜山。' },
  { title: '登敬亭北二小山余时送客逢崔侍御并登此地', author: '李白', poem: '送客谢亭北，逢君纵酒还。\n屈盘戏白马，大笑上青山。\n回鞭指长安，西日落秦关。\n帝乡三千里，杳在碧云间。' },
  { title: '过崔八丈水亭', author: '李白', poem: '高阁横秀气，清幽并在君。\n檐飞宛溪水，窗落敬亭云。\n猨啸风中断，渔歌月里闻。\n闲随白鸥去，沙上自为群。' },
  { title: '登广武古战场怀古', author: '李白', poem: '秦鹿奔野草，逐之若飞蓬。\n项王气盖世，紫电明双瞳。\n呼吸八千人，横行起江东。\n赤精斩白帝，叱咤入关中。\n两龙不并跃，五纬与天同。\n楚灭无英图，汉兴有成功。\n按劒清八极，归酣歌大风。\n伊昔临广武，连兵决雌雄。\n分我一杯羹，太皇乃汝翁。\n战争有古迹，壁垒颓层穹。\n猛虎啸洞壑，饥鹰鸣秋空。\n翔云列晓阵，杀气赫长虹。\n拨乱属豪圣，俗儒安可通。\n沈湎呼竖子，狂言非至公。\n抚掌黄河曲，嗤嗤阮嗣宗。' },
  { title: '安州应城玉女汤作', author: '李白', poem: '神女殁幽境，汤池流大川。\n阴阳结炎炭，造化开灵泉。\n地底烁朱火，沙傍歊素烟。\n沸珠跃明月，皎镜函空天。\n气浮兰芳满，色涨桃花然。\n精览万殊入，潜行七泽连。\n愈疾功莫尚，变盈道乃全。\n濯濯气清泚，晞发弄潺湲。\n散下楚王国，分浇宋玉田。\n可以奉巡幸，奈何隔穷偏。\n独随朝宗水，赴海输微涓。' },
  { title: '之广陵宿常二南郭幽居', author: '李白', poem: '绿水接柴门，有如桃花源。\n忘忧或假草，满院罗丛萱。\n[暝]色湖上来，微雨飞南轩。\n故人宿茅宇，夕鸟栖杨园。\n还惜诗酒别，深为江海言。\n明朝广陵道，独忆此倾樽。' },
  { title: '夜下征虏亭', author: '李白', poem: '船下广陵去，月明征虏亭。\n山花如绣颊，江火似流萤。' },
  { title: '下途归石门旧居', author: '李白', poem: '吴山高，越水清，握手无言伤别情。\n将欲辞君挂帆去，离魂不散烟郊树。\n此心郁怅谁能论，有愧叨承国士恩。\n云物共倾三月酒，岁时同饯五侯门。\n羡君素书尝满案，含丹照白霞色烂。\n余尝学道穷冥筌，梦中往往游仙山。\n何当脱屣谢时去，壶中别有日月天。\n俛仰人间易凋朽，钟峰五云在轩牖。\n惜别愁窥玉女窗，归来笑把洪厓手。\n隐居寺，隐居山，陶公炼液栖其间。\n灵神闭气昔登攀，恬然但觉心绪闲。\n数人不知几甲子，昨夜犹带冰霜颜。\n我离虽则岁物改，如今了然失所在。\n别君莫道不尽欢，悬知乐客遥相待。\n石门流水徧桃花，我亦曾到秦人家。\n不知何处得鸡豕，就中仍见繁桑麻。\n翛然远与世事间，装鸾驾鹤又复远。\n何必长从七贵游，劳生徒聚万金产。\n挹君去，长相思，云游雨散从此辞。\n欲知怅别心易苦，向暮春风杨柳丝。' },
  { title: '客中行', author: '李白', poem: '兰陵美酒郁金香，玉椀盛来琥珀光。\n但使主人能醉客，不知何处是他乡。' },
  { title: '太原早秋', author: '李白', poem: '岁落众芳歇，时当大火流。\n霜威出塞早，云色渡河秋。\n梦绕边城月，心飞故国楼。\n思归若汾水，无日不悠悠。' },
  { title: '奔亡道中五首 一', author: '李白', poem: '苏武天山上，田横海岛边。\n万重关塞断，何日是归年。' },
  { title: '奔亡道中五首 二', author: '李白', poem: '亭伯去安在，李陵降未归。\n愁容变海色，短服改胡衣。' },
  { title: '奔亡道中五首 三', author: '李白', poem: '谈笑三军却，交游七贵疎。\n仍留一只箭，未射鲁连书。' },
  { title: '奔亡道中五首 四', author: '李白', poem: '函谷如玉关，几时可生还。\n洛阳为易水，嵩岳是燕山。\n俗变羗胡语，人多沙塞颜。\n申包惟恸哭，七日鬓毛斑。' },
  { title: '奔亡道中五首 五', author: '李白', poem: '淼淼望湖水，青青芦叶齐。\n归心落何处，日没大江西。\n歇马傍春草，欲行远道迷。\n谁忍子规鸟，连声向我啼。' },
  { title: '郢门秋怀', author: '李白', poem: '郢门一为客，巴月三成弦。\n朔风正摇落，行子愁归旋。\n杳杳山外日，茫茫江上天。\n人迷洞庭水，雁度潇湘烟。\n清旷谐宿好，缁磷及此年。\n百龄何荡漾，万化相推迁。\n空谒苍梧帝，徒寻溟海仙。\n已闻蓬海浅，岂见三桃圆。\n倚劒增浩叹，扪襟还自怜。\n终当游五湖，濯足沧浪泉。' },
  { title: '至鸭栏驿上白马矶赠裴侍御', author: '李白', poem: '侧叠万古石，横为白马矶。\n乱流若电转，举櫂扬珠辉。\n临驿卷缇幕，升堂接绣衣。\n情亲不避马，为我解霜威。' },
  { title: '荆门浮舟望蜀江', author: '李白', poem: '春水月峡来，浮舟望安极。\n正是桃花流，依然锦江色。\n江色绿且明，茫茫与天平。\n逶迤巴山尽，摇曳楚云行。\n雪照聚沙雁，花飞出谷莺。\n芳洲却已转，碧树森森迎。\n流目浦烟夕，扬帆海月生。\n江陵识遥火，应到渚宫城。' },
  { title: '上三峡', author: '李白', poem: '巫山夹青天，巴水流若兹。\n巴水忽可尽，青天无到时。\n三朝上黄牛，三暮行太迟。\n三朝又三暮，不觉鬓成丝。' },
  { title: '自巴东舟行经瞿唐峡登巫山最高峰晚还题壁', author: '李白', poem: '江行几千里，海月十五圆。\n始经瞿唐峡，遂步巫山巅。\n巫山高不穷，巴国尽所历。\n日边攀垂萝，霞外倚穹石。\n飞步凌绝顶，极目无纤烟。\n却顾失舟壑，仰观临青天。\n青天若可扪，银汉去安在。\n望云知苍梧，记水辨瀛海。\n周游孤光晚，历览幽意多。\n积雪照空谷，悲风鸣森柯。\n归途行欲曛，佳趣尚未歇。\n江寒早啼猨，松暝已吐月。\n月色何悠悠，清猨响啾啾。\n辞山不忍听，挥策还孤舟。' },
  { title: '早发白帝城', author: '李白', poem: '朝辞白帝彩云间，千里江陵一日还。\n两岸猨声啼不尽，轻舟已过万重山。' },
  { title: '秋下荆门', author: '李白', poem: '霜落荆门江树空，布帆无恙挂秋风。\n此行不为鲈鱼鲙，自爱名山入剡中。' },
  { title: '江行寄远', author: '李白', poem: '刳木出吴楚，危槎百余尺。\n疾风吹片帆，日暮千里隔。\n别时酒犹在，已为异乡客。\n思君不可得，愁见江水碧。' },
  { title: '宿五松山下荀媪家', author: '李白', poem: '我宿五松下，寂寥无所欢。\n田家秋作苦，邻女夜舂寒。\n跪进雕胡饭，月光明素盘。\n令人惭漂母，三谢不能餐。' },
  { title: '下泾县陵阳溪至澁滩', author: '李白', poem: '澁滩鸣嘈嘈，两山足猨猱。\n白波若卷雪，侧足不容舠。\n渔子与舟人，撑折万张篙。' },
  { title: '下陵阳沿高溪三门六剌滩', author: '李白', poem: '三门横峻滩，六剌走波澜。\n石惊虎伏起，水状龙萦盘。\n何慙七里濑，使我欲垂竿。' },
  { title: '夜泊黄山闻殷十四吴吟', author: '李白', poem: '昨夜谁为吴会吟，风生万壑振空林。\n龙惊不敢水中卧，猨啸时闻岩下音。\n我宿黄山碧溪月，听之却罢松间琴。\n朝来果是沧洲逸，酤酒醍盘饭霜栗。\n半酣更发江海声，客愁顿向杯中失。' },
  { title: '宿𫚥湖', author: '李白', poem: '鸡鸣发黄山，暝投𫚥湖宿。\n白雨暎寒山，森森似银竹。\n提携采铅客，结荷水边沐。\n半夜四天开，星河烂人目。\n明晨大楼去，冈陇多屈伏。\n当与持斧翁，前溪伐云木。' },
  { title: '西施', author: '李白', poem: '西施越溪女，出自苎萝山。\n秀色掩今古，荷花羞玉颜。\n浣纱弄碧水，自与清波闲。\n皓齿信难开，沈吟碧云间。\n句践征绝艳，扬蛾入吴关。\n提携馆娃宫，杳渺讵可攀。\n一破夫差国，千秋竟不还。' },
  { title: '王右军', author: '李白', poem: '右军本清真，潇洒出风尘。\n山阴过羽客，爱此好鹅宾。\n扫素写道经，笔精妙入神。\n书罢笼鹅去，何曾别主人。' },
  { title: '上元夫人', author: '李白', poem: '上元谁夫人，偏得王母娇。\n嵯峨三角髻，余发散垂腰。\n裘披青毛锦，身着赤霜袍。\n手提嬴女儿，闲与凤吹箫。\n眉语两自笑，忽然随风飘。' },
  { title: '苏台览古', author: '李白', poem: '旧苑荒台杨柳新，菱歌清唱不胜春。\n只今惟有西江月，曾照吴王宫里人。' },
  { title: '越中览古', author: '李白', poem: '越王句践破吴归，义士还乡尽锦衣。\n宫女如花满春殿，只今惟有鹧鸪飞。' },
  { title: '商山四皓', author: '李白', poem: '白发四老人，昂藏南山侧。\n偃卧松雪间，冥翳不可识。\n云窗拂青霭，石壁横翠色。\n龙虎方战争，于焉自休息。\n秦人失金镜，汉祖升紫极。\n阴虹浊太阳，前星遂沦匿。\n一行佐明圣，倏起生羽翼。\n功成身不居，舒卷在胸臆。\n窅冥合元化，茫昧信难测。\n飞声塞天衢，万古仰遗则。' },
  { title: '过四皓墓', author: '李白', poem: '我行至商洛，幽独访神仙。\n园绮复安在，云萝尚宛然。\n荒凉千古迹，芜没四坟连。\n伊昔炼金鼎，何年闭玉泉。\n陇寒惟有月，松古渐无烟。\n木魅风号去，山精雨啸旋。\n紫芝高咏罢，青史旧名传。\n今日并如此，哀哉信可怜。' },
  { title: '岘山怀古', author: '李白', poem: '访古登岘首，凭高眺襄中。\n天清远峰出，水落寒沙空。\n弄珠见游女，醉酒怀山公。\n感叹发秋兴，长松鸣夜风。' },
  { title: '苏武', author: '李白', poem: '苏武在匈奴，十年持汉节。\n白雁上林飞，空传一书札。\n牧羊边地苦，落日归心绝。\n渴饮月窟冰，肌餐天上雪。\n东还沙塞远，北怆河梁别。\n泣把李陵衣，相看泪成血。' },
  { title: '经下邳圯桥怀张子房', author: '李白', poem: '子房未虎啸，破产不为家。\n沧海得壮士，椎秦博浪沙。\n报韩虽不成，天地皆振动。\n潜匿游下邳，岂曰非智勇。\n我来圯桥上，怀古钦英风。\n惟见碧流水，曾无黄石公。\n叹息此人去，萧条徐泗空。' },
  { title: '金陵三首 一', author: '李白', poem: '晋家南渡日，此地旧长安。\n地即帝王宅，山为龙虎盘。\n金陵空壮观，天堑净波澜。\n醉客回桡去，吴歌且自欢。' },
  { title: '金陵三首 二', author: '李白', poem: '地拥金陵势，城回江水流。\n当时百万户，夹道起朱楼。\n亡国生春草，离宫没古丘。\n空余后湖月，波上对江州。' },
  { title: '金陵三首 三', author: '李白', poem: '六代兴亡国，三杯为尔歌。\n苑方秦地少，山似洛阳多。\n古殿吴花草，深宫晋绮罗。\n并随人事灭，东逝与沧波。' },
  { title: '秋夜板桥浦泛月独酌怀谢朓', author: '李白', poem: '天上何所有，迢迢白玉绳。\n斜低建章阙，耿耿对金陵。\n汉水旧如练，霜江夜清澄。\n长川泻落月，洲渚晓寒凝。\n独酌板桥浦，古人谁可征。\n玄晖难再得，洒酒气填膺。' },
  { title: '入彭蠡经松门观石镜缅怀谢康乐题诗书游览之志', author: '李白', poem: '谢公之彭蠡，因此游松门。\n余方窥石镜，兼得穷江源。\n将欲继风雅，岂徒清心魂。\n前赏逾所见，后来道空存。\n况属临泛美，而无洲渚喧。\n漾水向东去，漳流直南奔。\n空蒙三川夕，回合千里昏。\n青桂隐遥月，绿枫鸣愁猨。\n水碧或可采，金精秘莫论。\n吾将学仙去，冀与琴高言。' },
  { title: '庐江主人妇', author: '李白', poem: '孔雀东飞何处栖，庐江小吏仲卿妻。\n为客裁缝君自见，城乌独宿夜空啼。' },
  { title: '陪宋中丞武昌夜饮怀古', author: '李白', poem: '清景南楼夜，风流在武昌。\n庾公爱秋月，乘兴坐胡床。\n龙笛吟寒水，天河落晓霜。\n我心还不浅，怀古醉余觞。' },
  { title: '望鹦鹉洲怀祢衡', author: '李白', poem: '魏帝营八极，蚁观一祢衡。\n黄祖斗筲人，杀之受恶名。\n吴江赋鹦鹉，落笔超群英。\n锵锵振金玉，句句欲飞鸣。\n鸷鹗啄孤凤，千春伤我情。\n五岳起方寸，隐然讵可平。\n才高竟何施，寡识冒天刑。\n至今芳洲上，兰蕙不忍生。' },
  { title: '宿巫山下', author: '李白', poem: '昨夜巫山下，猨声梦里长。\n桃花飞绿水，三月下瞿塘。\n雨色风吹去，南行拂楚王。\n高丘怀宋玉，访古一沾裳。' },
  { title: '金陵白杨十字巷', author: '李白', poem: '白杨十字巷，北夹湖沟道。\n不见吴时人，空生唐年草。\n天地有反复，宫城尽倾倒。\n六帝余古丘，樵苏泣遗老。' },
  { title: '谢公亭', author: '李白', poem: '谢公离别处，风景每生愁。\n客散青天月，山空碧水流。\n池花春暎日，窗竹夜鸣秋。\n今古一相接，长歌怀旧游。' },
  { title: '纪南陵题五松山', author: '李白', poem: '圣达有去就，潜光愚其德。\n鱼与龙同池，龙去鱼不测。\n当时版筑辈，岂知傅说情。\n一朝和殷羹，光气为列星。\n伊尹生空桑，捐庖佐皇极。\n桐宫放太甲，摄政无愧色。\n三年帝道明，委质终辅翼。\n旷哉至人心，万古可为则。\n时命或大缪，仲尼将奈何。\n鸾凤忽覆巢，麒麟不来过。\n龟山蔽鲁国，有斧且无柯。\n归来归去来，宵济越洪波。' },
  { title: '夜泊牛渚怀古', author: '李白', poem: '牛渚西江夜，青天无片云。\n登舟望秋月，空忆谢将军。\n余亦能高咏，斯人不可闻。\n明朝挂帆席，枫叶落纷纷。' },
  { title: '姑孰十咏 姑孰溪', author: '李白', poem: '爱此溪水闲，乘流兴无极。\n漾楫怕鸥惊，垂竿待鱼食。\n波飜晓霞影，岸叠春山色。\n何处浣纱人，红颜未相识。' },
  { title: '姑孰十咏 丹阳湖', author: '李白', poem: '湖与元气连，风波浩难止。\n天外贾客归，云间片帆起。\n龟游莲叶上，鸟宿芦花里。\n少女櫂归舟，歌声逐流水。' },
  { title: '姑孰十咏 谢公宅', author: '李白', poem: '青山日将暝，寂寞谢公宅。\n竹里无人声，池中虚月白。\n荒庭衰草徧，废井苍苔积。\n惟有清风闲，时时起泉石。' },
  { title: '姑孰十咏 陵歊台', author: '李白', poem: '旷望登古台，台高极人目。\n叠嶂列远空，杂花间平陆。\n闲云入窗牖，野翠生松竹。\n欲览碑上文，苔侵岂堪读。' },
  { title: '姑孰十咏 桓公井', author: '李白', poem: '桓公名已古，废井曾未竭。\n石甃冷苍苔，寒泉湛孤月。\n秋来桐暂落，春至桃还发。\n路远人罕窥，谁能见清彻。' },
  { title: '姑孰十咏 慈姥竹', author: '李白', poem: '野竹攒石生，含烟暎江岛。\n翠色落波深，虚声带寒早。\n龙吟曾未听，凤曲吹应好。\n不学蒲柳凋，贞心尝自保。' },
  { title: '姑孰十咏 望夫山', author: '李白', poem: '颙望临碧空，怨情感离别。\n江草不知愁，岩花但争发。\n云山万重隔，音信千里绝。\n春去秋复来，相思几时歇。' },
  { title: '姑孰十咏 牛渚矶', author: '李白', poem: '绝壁临巨川，连峰势相向。\n乱石流洑间，回波自成浪。\n但惊群木秀，莫测精灵状。\n更听猨夜啼，忧心醉江上。' },
  { title: '姑孰十咏 灵墟山', author: '李白', poem: '丁令辞世人，拂衣向仙路。\n伏炼九丹成，方随五云去。\n松萝蔽幽洞，桃杏深隐处。\n不知曾化鹤，辽海归几度。' },
  { title: '姑孰十咏 天门山', author: '李白', poem: '逈出江山上，双峰自相对。\n岸暎松色寒，石分浪花碎。\n参差远天际，缥缈晴霞外。\n落日舟去遥，回首沈青霭。' },
  { title: '与元丹丘方城寺谈玄作', author: '李白', poem: '茫茫大梦中，惟我独先觉。\n腾转风火来，假合作容貌。\n灭除昏疑尽，领略入精要。\n澄虑观此身，因得通寂照。\n朗悟前后际，始知金仙妙。\n幸逢禅居人，酌玉坐相召。\n彼我俱若丧，云山岂殊调。\n清风生虚空，明月见谈笑。\n怡然青莲宫，永愿姿游眺。' },
  { title: '寻高凤石门山中元丹丘', author: '李白', poem: '寻幽无前期，乘兴不觉远。\n苍厓渺难涉，白日忽欲晚。\n未穷三四山，已历千万转。\n寂寂闻猨愁，行行见云收。\n高松来好月，空谷宜清秋。\n溪深古雪在，石断寒泉流。\n峰峦秀中天，登眺不可尽。\n丹丘遥相呼，顾我忽而哂。\n遂造穷谷间，始知静者闲。\n留欢达永夜，清晓方言还。' },
  { title: '安州般若水阁纳凉喜遇薛员外乂', author: '李白', poem: '翛然金园赏，远近含晴光。\n楼台成海气，草木皆天香。\n忽逢青云士，共解丹霞裳。\n水退池上热，风生松下凉。\n吞讨破万象，搴窥临众芳。\n而我遗有漏，与君用无方。\n心垢都已灭，永言题禅房。' },
  { title: '鲁中都东楼醉起作', author: '李白', poem: '昨日东楼醉，还应倒接䍠。\n阿谁扶上马，不省下楼时。' },
  { title: '对酒醉题屈突明府厅', author: '李白', poem: '陶令八十日，长歌归去来。\n故人建昌宰，借问几时回。\n风落吴江雪，纷纷入酒杯。\n山翁今已醉，舞袖为君开。' },
  { title: '月下独酌四首 一', author: '李白', poem: '花间一壶酒，独酌无相亲。\n举杯邀明月，对影成三人。\n月既不解饮，影徒随我身。\n暂伴月将影，行乐须及春。\n我歌月裴回，我舞影零乱。\n醒时同交欢，醉后各分散。\n永结无情游，相期邈云汉。' },
  { title: '月下独酌四首 二', author: '李白', poem: '天若不爱酒，酒星不在天。\n地若不爱酒，地应无酒泉。\n天地既爱酒，爱酒不愧天。\n已闻清比圣，复道浊如贤。\n贤圣既已饮，何必求神仙。\n三杯通大道，一斗合自然。\n但得酒中趣，勿为醒者传。' },
  { title: '月下独酌四首 三', author: '李白', poem: '三月咸阳城，千花昼如锦。\n谁能春独愁，对此径须饮。\n穷通与修短，造化夙所禀。\n一樽齐死生，万事固难审。\n醉后失天地，兀然就孤枕。\n不知有吾身，此乐最为甚。' },
  { title: '月下独酌四首 四', author: '李白', poem: '穷愁千万端，美酒三百杯。\n愁多酒虽少，酒倾愁不来。\n所以知酒圣，酒酣心自开。\n辞粟卧首阳，屡空饥颜回。\n当代不乐饮，虚名安用哉。\n蟹螯即金液，糟丘是蓬莱。\n且须饮美酒，乘月醉高台。' },
  { title: '春归终南山松龛旧隐', author: '李白', poem: '我来南山阳，事事不异昔。\n却寻溪中水，还望岩下石。\n蔷薇缘东窗，女萝遶北壁。\n别来能几日，草木长数尺。\n且复命酒樽，独酌陶永夕。' },
  { title: '冬夜醉宿龙门觉起言志', author: '李白', poem: '醉来脱宝劒，旅憩高堂眠。\n中夜忽惊觉，起立明灯前。\n开轩聊直望，晓雪河冰壮。\n哀哀歌苦寒，郁郁独惆怅。\n傅说版筑臣，李斯鹰犬人。\n歘起匡社稷，宁复长艰辛。\n而我胡为者，叹息龙门下。\n富贵未可期，殷忧向谁写。\n去去泪满襟，举声梁甫吟。\n青云当自致，何必求知音。' },
  { title: '寻山僧不遇作', author: '李白', poem: '石径入丹壑，松门闭青苔。\n闲阶有鸟迹，禅室无人开。\n窥窗见白拂，挂壁生尘埃。\n使我空叹息，欲去仍裴回。\n香云徧山起，花雨从天来。\n已有空乐好，况闻青猨哀。\n了然绝世事，此地方悠哉。' },
  { title: '过汪氏别业二首 一', author: '李白', poem: '游山谁可游，子明与浮丘。\n叠岭碍河汉，连峰横斗牛。\n汪生面北阜，池馆清且幽。\n我来感意气，搥炰列珍羞。\n扫石待归月，开池涨寒流。\n酒酣益爽气，为乐不知秋。' },
  { title: '过汪氏别业二首 二', author: '李白', poem: '畴昔未识君，知君好贤才。\n随山起馆宇，凿石营池台。\n星火五月中，景风从南来。\n数枝石榴发，一丈荷花开。\n恨不当此时，相过醉金罍。\n我行值木落，月苦清猨哀。\n永夜达五更，吴歈送琼杯。\n酒酣欲起舞，四座歌相催。\n日出远海明，轩车且裴回。\n更游龙潭去，枕石拂莓苔。' },
  { title: '待酒不至', author: '李白', poem: '玉壶系青丝，沽酒来何迟。\n山花向我笑，正好衔杯时。\n晚酌东窗下，流莺复在兹。\n春风与醉客，今日乃相宜。' },
  { title: '独酌', author: '李白', poem: '春草如有意，罗生玉堂阴。\n东风吹愁来，白发坐相侵。\n独酌劝孤影，闲歌面芳林。\n长松尔何知，萧瑟为谁吟。\n手舞石上月，膝横花间琴。\n过此一壶外，悠悠非我心。' },
  { title: '友人会宿', author: '李白', poem: '涤荡千古愁，留连百壶饮。\n良宵宜清谈，皓月未能寝。\n醉来卧空山，天地即衾枕。' },
  { title: '春日独酌二首 一', author: '李白', poem: '东风扇淑气，水木荣春晖。\n白日照绿草，落花散且飞。\n孤云还空山，众鸟各已归。\n彼物皆有托，吾生独无依。\n对此石上月，长醉歌芳菲。' },
  { title: '春日独酌二首 二', author: '李白', poem: '我有紫霞想，缅怀沧洲间。\n思对一壶酒，澹然万事闲。\n横琴倚高松，把酒望远山。\n长空去鸟没，落日孤云还。\n但恐光景晚，宿昔成秋颜。' },
  { title: '金陵江上遇蓬池隐者', author: '李白', poem: '心爱名山游，身随名山远。\n罗浮麻姑台，此去或未返。\n遇君蓬池隐，就我石上饭。\n空言不成欢，强笑惜日晚。\n绿水向雁门，黄云蔽龙山。\n叹息两客鸟，裴回吴越间。\n共语一执手，留连夜将久。\n解我紫绮裘，且换金陵酒。\n酒来笑复歌，兴酣乐事多。\n水影弄月色，清光奈愁何。\n明晨挂帆席，离恨满沧波。' },
  { title: '月夜听卢子顺弹琴', author: '李白', poem: '闲坐夜明月，幽人弹素琴。\n忽闻悲风调，宛若寒松吟。\n白雪乱纤手，绿水清虚心。\n钟期久已没，世上无知音。' },
  { title: '清溪半夜闻笛', author: '李白', poem: '羗笛梅花引，吴溪陇水情。\n寒山秋浦月，肠断玉关声。' },
  { title: '日夕山中忽然有怀', author: '李白', poem: '久卧青山云，遂为青山客。\n山深云更好，赏弄终日夕。\n月衔楼间峰，泉潄阶下石。\n素心自此得，真趣非外惜。\n鼯啼桂方秋，风灭籁归寂。\n缅思洪厓术，欲往沧海隔。\n云车来何迟，抚几空叹息。' },
  { title: '夏日山中', author: '李白', poem: '嬾摇白羽扇，躶体青林中。\n脱巾挂石壁，露顶洒松风。' },
  { title: '山中与幽人对酌', author: '李白', poem: '两人对酌山花开，一杯一杯复一杯。\n我醉欲眠卿且去，明朝有意抱琴来。' },
  { title: '春日醉起言志', author: '李白', poem: '处世若大梦，胡为劳其生。\n所以终日醉，颓然卧前楹。\n觉来盼庭前，一鸟花间鸣。\n借问此何时，春风语流莺。\n感之欲叹息，对酒还自倾。\n浩歌待明月，曲尽已忘情。' },
  { title: '庐山东林寺夜怀', author: '李白', poem: '我寻青莲宇，独往谢城阙。\n霜清东林钟，水白虎溪月。\n天香生虚空，天乐鸣不歇。\n宴坐寂不动，大千入毫发。\n湛然冥真心，旷劫断出没。' },
  { title: '寻雍尊师隐居', author: '李白', poem: '群峭碧摩天，逍遥不记年。\n拨云寻古道，倚石听流泉。\n花暖青牛卧，松高白鹤眠。\n语来江色暮，独自下寒烟。' },
  { title: '与史郎中钦听黄鹤楼上吹笛', author: '李白', poem: '一为迁客去长沙，西望长安不见家。\n黄鹤楼中吹玉笛，江城五月落梅花。' },
  { title: '对酒', author: '李白', poem: '劝君莫拒杯，春风笑人来。\n桃李如旧识，倾花向我开。\n流莺啼碧树，明月窥金罍。\n昨日朱颜子，今日白发催。\n棘生石虎殿，鹿走姑苏台。\n自古帝王宅，城阙闭黄埃。' },
  { title: '醉题王汉阳厅', author: '李白', poem: '我似鹧鸪鸟，南迁嬾北飞。\n时寻汉阳令，取醉月中归。' },
  { title: '嘲王历阳不肯饮酒', author: '李白', poem: '地白风色寒，雪花大如手。\n笑杀陶渊明，不饮杯中酒。\n浪抚一张琴，虚栽五株柳。\n空负头上巾，吾于尔何有。' },
  { title: '独坐敬亭山', author: '李白', poem: '众鸟高飞尽，孤云独去闲。\n相看两不厌，只有敬亭山。' },
  { title: '自遣', author: '李白', poem: '对酒不觉暝，落花盈我衣。\n醉起步溪月，鸟还人亦稀。' },
  { title: '访戴天山道士不遇', author: '李白', poem: '犬吠水声中，桃花带雨浓。\n树深时见鹿，溪午不闻钟。\n野竹分青霭，飞泉挂碧峰。\n无人知所去，愁倚两三松。' },
  { title: '秋日与张少府楚城韦公藏书高斋作', author: '李白', poem: '日下空庭暮，城荒古迹余。\n地形连海尽，天影落江虚。\n旧赏人虽隔，新知乐未疎。\n彩云思作赋，丹壁间藏书。\n楂拥随流叶，萍开出水鱼。\n夕来秋兴满，回首意何如。' },
  { title: '秋夜独坐怀故山', author: '李白', poem: '小隐慕安石，远游学屈平。\n天书访江海，云卧起咸京。\n入侍瑶池宴，出陪玉辇行。\n夸胡新赋作，谏猎短书成。\n但奉紫霄顾，非邀青史名。\n庄周空说劒，墨翟耻论兵。\n拙薄遂疎绝，归闲事耦耕。\n顾无苍生望，空爱紫芝荣。\n寥落暝霞色，微茫旧壑情。\n秋山绿萝月，今夕为谁明。' },
  { title: '忆崔郎中宗之游南阳遗吾孔子琴抚之潸然感旧', author: '李白', poem: '昔在南阳城，唯餐独山蕨。\n忆与崔宗之，白水弄素月。\n时过菊潭上，纵酒无休歇。\n泛此黄金花，颓然清歌发。\n一朝摧玉树，生死殊飘忽。\n留我孔子琴，琴存人已殁。\n谁传广陵散，但哭邙山骨。\n泉户何时明，长扫狐兔窟。' },
  { title: '忆东山二首 一', author: '李白', poem: '不向东山久，蔷薇几度花。\n白云还自散，明月落谁家。' },
  { title: '忆东山二首 二', author: '李白', poem: '我今携谢妓，长啸绝人群。\n欲报东山客，开关扫白云。' },
  { title: '望月有怀', author: '李白', poem: '清泉暎疎松，不知几千古。\n寒月摇清波，流光入窗户。\n对此空长吟，思君意何深。\n无因见安道，兴尽愁人心。' },
  { title: '对酒忆贺监二首 一', author: '李白', poem: '四明有狂客，风流贺季真。\n长安一相见，呼我谪仙人。\n昔好杯中物，翻为松下尘。\n金龟换酒处，却忆泪沾巾。' },
  { title: '对酒忆贺监二首 二', author: '李白', poem: '狂客归四明，山阴道士迎。\n敕赐镜湖水，为君台沼荣。\n人亡余故宅，空有荷花生。\n念此杳如梦，凄然伤我情。' },
  { title: '重忆一首', author: '李白', poem: '欲向江东去，定将谁举杯。\n稽山无贺老，却櫂酒船回。' },
  { title: '春滞沅湘有怀山中', author: '李白', poem: '沅湘春色还，风暖烟草绿。\n古之伤心人，于此肠断续。\n予非怀沙客，但美采菱曲。\n所愿归东山，寸心于此足。' },
  { title: '落日忆山中', author: '李白', poem: '雨后烟景绿，晴天散余霞。\n东风随春归，发我枝上花。\n花落时欲暮，见此令人嗟。\n愿游名山去，学道飞丹砂。' },
  { title: '忆秋浦桃花旧游时窜夜郎', author: '李白', poem: '桃花春水生，白石今出没。\n摇荡女萝枝，半摇青天月。\n不知旧行径，初拳几枝蕨。\n三载夜郎还，于兹炼金骨。' },
  { title: '越中秋怀', author: '李白', poem: '越水遶碧山，周回数千里。\n乃是天镜中，分明画相似。\n爱此从冥搜，永怀临湍游。\n一为沧波客，十见红蕖秋。\n观涛壮天险，望海令人愁。\n路遐迫西照，岁晚悲东流。\n何必探禹穴，逝将归蓬丘。\n不然五湖上，亦可乘扁舟。' },
  { title: '效古二首 一', author: '李白', poem: '朝入天苑中，谒帝蓬莱宫。\n青山映辇道，碧树摇苍空。\n谬题金闺籍，得与银台通。\n待诏奉明主，抽毫颂清风。\n归时落日晚，躞蹀浮云骢。\n人马本无意，飞驰自豪雄。\n入门紫鸳鸯，金井双梧桐。\n清歌弦古曲，美酒沽新丰。\n快意且为乐，列筵坐群公。\n光景不可留，生世如转蓬。\n早达胜晚遇，羞比垂钓翁。' },
  { title: '效古二首 二', author: '李白', poem: '自古有秀色，西施与东邻。\n蛾眉不可妬，况乃效其𪾸。\n所以尹婕妤，羞见邢夫人。\n低头不出气，塞默少精神。\n寄语无盐子，如君何足珍。' },
  { title: '拟古十二首 一', author: '李白', poem: '青天何历历，明星如白石。\n黄姑与织女，相去不盈尺。\n银河无鹊桥，非时将安适。\n闺人理纨素，游子悲行役。\n瓶冰知冬寒，霜露欺远客。\n客似秋叶飞，飘飖不言归。\n别后罗带长，愁宽去时衣。\n乘月托宵梦，因之寄金徽。' },
  { title: '拟古十二首 二', author: '李白', poem: '高楼入青天，下有白玉堂。\n明月看欲堕，当窗悬清光。\n遥夜一美人，罗衣沾秋霜。\n含情弄柔瑟，弹作陌上桑。\n弦声何激烈，风卷遶飞梁。\n行人皆踯躅，栖鸟起回翔。\n但写妾意苦，莫辞此曲伤。\n愿逢同心者，飞作紫鸳鸯。' },
  { title: '拟古十二首 三', author: '李白', poem: '长绳难系日，自古共悲辛。\n黄金高北斗，不惜买阳春。\n石火无留光，还如世中人。\n即事已如梦，后来我谁身。\n提壶莫辞贫，取酒会四邻。\n仙人殊恍惚，未若醉中真。' },
  { title: '拟古十二首 四', author: '李白', poem: '清都绿玉树，灼烁瑶台春。\n攀花弄秀色，远赠天仙人。\n香风送紫蘂，直到扶桑津。\n取掇世上艳，所贵心之珍。\n相思传一笑，聊欲示情亲。' },
  { title: '拟古十二首 五', author: '李白', poem: '今日风日好，明日恐不如。\n春风笑于人，何乃愁自居。\n吹箫舞彩凤，酌醴鲙神鱼。\n千金买一醉，取乐不求余。\n达士遗天地，东门有二疏。\n愚夫同瓦石，有才知卷舒。\n无事作悲苦，块然涸辙鱼。' },
  { title: '拟古十二首 六', author: '李白', poem: '运速天地闭，胡风结飞霜。\n百草死冬月，六龙颓西荒。\n太白出东方，彗星扬精光。\n鸳鸯非越鸟，何为眷南翔。\n惟昔鹰将犬，今为侯与王。\n得水成蛟龙，争池夺凤凰。\n北斗不酌酒，南箕空簸扬。' },
  { title: '拟古十二首 七', author: '李白', poem: '世路今太行，回车竟何托。\n万族皆凋枯，遂无少可乐。\n旷野多白骨，幽魂共销铄。\n荣贵当及时，春华宜照灼。\n人非昆山玉，安得长璀错。\n身没期不朽，荣名在麟阁。' },
  { title: '拟古十二首 八', author: '李白', poem: '月色不可扫，客愁不可道。\n玉露生秋衣，流萤飞百草。\n日月终销毁，天地同枯槁。\n蟪蛄啼青松，安见此树老。\n金丹宁误俗，昧者难精讨。\n尔非千岁翁，多恨去世早。\n饮酒入玉壶，藏身以为宝。' },
  { title: '拟古十二首 九', author: '李白', poem: '生者为过客，死者为归人。\n天地一逆旅，同悲万古尘。\n月兔空捣药，扶桑已成薪。\n白骨寂无言，青松岂知春。\n前后更叹息，浮荣安足珍。' },
  { title: '拟古十二首 十', author: '李白', poem: '仙人骑彩凤，昨下阆风岑。\n海水三清浅，桃源一见寻。\n遗我绿玉桮，兼之紫琼琴。\n杯以倾美酒，琴以闲素心。\n二物非世有，何论珠与金。\n琴弹松里风，桮劝天上月。\n风月长相知，世人何倏忽。' },
  { title: '拟古十二首 十一', author: '李白', poem: '涉江弄秋水，爱此荷花鲜。\n攀荷弄其珠，荡漾不成圆。\n佳人彩云里，欲赠隔远天。\n相思无由见，怅望凉风前。' },
  { title: '拟古十二首 十二', author: '李白', poem: '去去复去去，辞君还忆君。\n汉水既殊流，楚山亦此分。\n人生难称意，岂得长为群。\n越燕喜海日，燕鸿思朔云。\n别久容华晚，琅玕不能饭。\n日落知天昏，梦长觉道远。\n望夫登高山，化石竟不返。' },
  { title: '感兴六首 一', author: '李白', poem: '瑶姬天帝女，精彩化朝云。\n宛转入宵梦，无心向楚君。\n锦衾抱秋月，绮席空兰芬。\n茫昧竟谁测，虚传宋玉文。' },
  { title: '感兴六首 二', author: '李白', poem: '洛浦有宓妃，飘飖雪争飞。\n轻云拂素月，了可见清辉。\n解珮欲西去，含情讵相违。\n香尘动罗袜，绿水不沾衣。\n陈王徒作赋，神女岂同归。\n好色伤大雅，多为世所讥。' },
  { title: '感兴六首 三', author: '李白', poem: '裂素持作书，将寄万里怀。\n眷眷待远信，竟岁无人来。\n征鸿务随阳，又不为我栖。\n委之在深箧，蠹鱼坏其题。\n何如投水中，流落他人开。\n不惜他人开，但恐生是非。' },
  { title: '感兴六首 四', author: '李白', poem: '十五游神仙，仙游未曾歇。\n吹笙坐松风，泛瑟窥海月。\n西山玉童子，使我炼金骨。\n欲逐黄鹤飞，相呼向蓬阙。' },
  { title: '感兴六首 五', author: '李白', poem: '西国有美女，结楼青云端。\n蛾眉艳晓月，一笑倾城欢。\n高节不可夺，炯心如凝丹。\n常恐彩色晚，不为人所观。\n安得配君子，共乘双飞鸾。' },
  { title: '感兴六首 六', author: '李白', poem: '嘉谷隐丰草，草深苗且稀。\n农夫既不异，孤穗将安归。\n常恐委畴陇，忽与秋蓬飞。\n乌得荐宗庙，为君生光辉。' },
  { title: '寓言三首 一', author: '李白', poem: '周公负斧扆，成王何夔夔。\n武王昔不豫，剪爪投河湄。\n贤圣遇谗慝，不免人君疑。\n天风拔大木，禾黍咸伤萎。\n管蔡扇苍蝇，公赋鸱鸮诗。\n金縢若不启，忠信谁明之。' },
  { title: '寓言三首 二', author: '李白', poem: '摇裔双彩凤，婉娈三青禽。\n往还瑶台里，鸣舞玉山岑。\n以欢秦娥意，复得王母心。\n区区精卫鸟，衔木空哀吟。' },
  { title: '寓言三首 三', author: '李白', poem: '长安春色归，先入青门道。\n绿杨不自持，从风欲倾倒。\n海燕还秦宫，双飞入帘栊。\n相思不相见，托梦辽城东。' },
  { title: '秋夕旅怀', author: '李白', poem: '凉风度秋海，吹我乡思飞。\n连山去无际，流水何时归。\n目极浮云色，心断明月晖。\n芳草歇柔艳，白露催寒衣。\n梦长银汉落，觉罢天星稀。\n含悲想旧国，泣下谁能挥。' },
  { title: '感遇四首 一', author: '李白', poem: '吾爱王子晋，得道伊洛滨。\n金骨既不毁，玉颜长自春。\n可怜浮丘公，猗靡与情亲。\n举首白日间，分明谢时人。\n二仙去已远，梦想空殷勤。' },
  { title: '感遇四首 二', author: '李白', poem: '可叹东篱菊，茎疎叶且微。\n虽言异兰蕙，亦自有芳菲。\n未泛盈樽酒，徒沾清露辉。\n当荣君不采，飘落欲何依。' },
  { title: '感遇四首 三', author: '李白', poem: '昔余闻姮娥，窃药驻云发。\n不自娇玉颜，方希炼金骨。\n飞去身莫返，含笑坐明月。\n紫宫夸蛾眉，随手会凋歇。' },
  { title: '感遇四首 四', author: '李白', poem: '宋玉事楚王，立身本高洁。\n巫山赋彩云，郢路歌白雪。\n举国莫能和，巴人皆卷舌。\n一感登徒言，恩情遂中绝。' },
  { title: '翰林读书言怀呈集贤诸学士', author: '李白', poem: '晨趋紫禁中，夕待金门诏。\n观书散遗帙，探古穷至妙。\n片言苟会心，掩卷忽而笑。\n青蝇易相点，白雪难同调。\n本是疎散人，屡贻褊促诮。\n云天属清朗，林壑忆游眺。\n或时清风来，闲倚栏下啸。\n严光桐庐溪，谢客临海峤。\n功成谢人间，从此一投钓。' },
  { title: '寻阳紫极宫感秋作', author: '李白', poem: '何处闻秋声，翛翛北窗竹。\n回薄万古心，揽之不盈掬。\n静坐观众妙，浩然媚幽独。\n白云南山来，就我檐下宿。\n嬾从唐生决，羞访季主卜。\n四十九年非，一往不可复。\n野情转萧洒，世道有飜覆。\n陶令归去来，田家酒应熟。' },
  { title: '江上秋怀', author: '李白', poem: '餐霞卧旧壑，散发谢远游。\n山蝉号枯桑，始复知天秋。\n朔雁别海裔，越燕辞江楼。\n飒飒风卷沙，茫茫雾萦洲。\n黄云结暮色，白水扬寒流。\n恻怆心自悲，潺湲泪难收。\n蘅兰方萧瑟，长叹令人愁。' },
  { title: '秋夕书怀', author: '李白', poem: '北风吹海鴈，南渡落寒声。\n感此潇湘客，凄其流浪情。\n海怀结沧洲，霞想游赤城。\n始探蓬壶事，旋觉天地轻。\n澹然吟高秋，闲卧瞻太清。\n萝月掩空幕，松霜结前楹。\n灭见息群动，猎微穷至精。\n桃花有源水，可以保吾生。' },
  { title: '避地司空原言怀', author: '李白', poem: '南风昔不竞，豪圣思经纶。\n刘琨与祖逖，起舞鸡鸣晨。\n虽有匡济心，终为乐祸人。\n我则异于是，潜光皖水滨。\n卜筑司空原，北将天柱邻。\n雪霁万里月，云开九江春。\n俟乎泰阶平，然后托微身。\n倾家事金鼎，年貌可长新。\n所愿得此道，终然保清真。\n弄景奔日驭，攀星戏河津。\n一随王乔去，长年玉天宾。' },
  { title: '上崔相百忧章', author: '李白', poem: '共公赫怒，天维中摧。\n鲲鲸喷荡，扬涛起雷。\n鱼龙陷人，成此祸胎。\n火焚昆山，玉石相磓。\n仰希霖雨，洒宝炎煨。\n箭发石开，戈挥日回。\n邹衍恸哭，燕霜飒来。\n微诚不感，犹絷夏台。\n苍鹰搏攫，丹棘崔嵬。\n豪圣凋枯，王风伤哀。\n斯文未丧，东岳岂颓。\n穆逃楚难，邹脱吴灾。\n见机苦迟，二公所咍。\n骥不骤进，麟何来哉。\n星离一门，草掷二孩。\n万愤结习，忧从中催。\n金瑟玉壶，尽为愁媒。\n举酒太息，泣血盈桮。\n台星再朗，天纲重恢。\n屈法申恩，弃瑕取材。\n冶长非罪，尼父无猜。\n覆盆傥举，应照寒灰。' },
  { title: '万愤词投魏郎中', author: '李白', poem: '海水渤潏，人罹鲸鲵。\n蓊胡沙而四塞，始滔天于燕齐。\n何六龙之浩荡，迁白日于秦西。\n九土星分，嗷嗷栖栖。\n南冠君子，呼天而啼。\n恋高堂而掩泣，泪血地而成泥。\n狱户春而不草，独幽怨而沈迷。\n兄九江兮弟三峡，悲羽化之难齐。\n穆陵关北愁爱子，豫章天南隔老妻。\n一门骨肉散百草，遇难不复相提携。\n树榛拔桂，囚鸾宠鸡。\n舜昔授禹，伯成耕犂。\n德自此衰，吾将安栖。\n好我者恤我，不好我者何忍临危而相挤。\n子胥鸱夷，彭越醢醯。\n自古豪烈，胡为此繄。\n苍苍之天，高乎视低。\n如其听卑，脱我牢狴。\n傥辨美玉，君收白珪。' },
  { title: '荆州贼平临洞庭言怀作', author: '李白', poem: '修蛇横洞庭，吞象临江岛。\n积骨成巴陵，遗言闻楚老。\n水穷三苗国，地窄三湘道。\n岁[晏]天峥嵘，时危人枯槁。\n思归阻丧乱，去国伤怀抱。\n郢路方丘墟，章华亦倾倒。\n风悲猨啸苦，木落鸿飞早。\n日隐西赤沙，月明东城草。\n关河望已绝，氛雾行当扫。\n长呌天可闻，吾将问苍昊。' },
  { title: '览镜书怀', author: '李白', poem: '得道无古今，失道还衰老。\n自笑镜中人，白发如霜草。\n扪心空叹息，问影何枯槁。\n桃李竟何言，终成南山皓。' },
  { title: '田园言怀', author: '李白', poem: '贾谊三年谪，班超万里侯。\n何如牵白犊，饮水对清流。' },
  { title: '江南春怀', author: '李白', poem: '青春几何时，黄鸟鸣不歇。\n天涯失乡路，江外老华发。\n心飞秦塞云，影滞楚关月。\n身世殊烂漫，田园久芜没。\n岁[晏]何所从，长歌谢金阙。' },
  { title: '听蜀僧濬弹琴', author: '李白', poem: '蜀僧抱绿绮，西下峨眉峰。\n为我一挥手，如听万壑松。\n客心洗流水，余响入霜钟。\n不觉碧山暮，秋云暗几重。' },
  { title: '鲁东门观刈蒲', author: '李白', poem: '鲁国寒事早，初霜刈渚蒲。\n挥镰若转月，拂水生连珠。\n此草最可珍，何必贵龙须。\n织作玉床席，欣承清夜娱。\n罗衣能再拂，不畏素尘芜。' },
  { title: '咏邻女东窗海石榴', author: '李白', poem: '鲁女东窗下，海榴世所稀。\n珊瑚映绿水，未足比光辉。\n清香随风发，落日好鸟归。\n愿为东南枝，低举拂罗衣。\n无由共攀折，引领望金扉。' },
  { title: '南轩松', author: '李白', poem: '南轩有孤松，柯叶自绵幂。\n清风无闲时，潇洒终日夕。\n阴生古苔绿，色染秋烟碧。\n何当凌云霄，直上数千尺。' },
  { title: '咏山樽二首 一', author: '李白', poem: '蟠木不雕饰，且将斤斧疎。\n樽成山岳势，材是栋梁余。\n外与金罍并，中涵玉醴虚。\n慙君垂拂拭，遂忝玳筵居。' },
  { title: '咏山樽二首 二', author: '李白', poem: '拥肿寒山木，嵌空成酒樽。\n愧无江海量，偃蹇在君门。' },
  { title: '初出金门寻王侍御不遇咏壁上鹦鹉', author: '李白', poem: '落羽辞金殿，孤鸣咤绣衣。\n能言终见弃，还向陇西飞。' },
  { title: '紫藤树', author: '李白', poem: '紫藤挂云木，花蔓宜阳春。\n密叶隐歌鸟，香风留美人。' },
  { title: '观放白鹰二首 一', author: '李白', poem: '八月边风高，胡鹰白锦毛。\n孤飞一片雪，百里见秋毫。' },
  { title: '观放白鹰二首 二', author: '李白', poem: '寒冬十二月，苍鹰八九毛。\n寄言燕雀莫相啅，自有云霄万里高。' },
  { title: '观博平王志安少府山水粉图', author: '李白', poem: '粉壁为空天，丹青状江海。\n游云不知归，日见白鸥在。\n博平真人王志安，沈吟至此愿挂冠。\n松溪石磴带秋色，愁客思归坐晓寒。' },
  { title: '题雍丘崔明府丹灶', author: '李白', poem: '美人为政本忘机，服药求仙事不违。\n叶县已泥丹灶毕，瀛洲当伴赤松归。\n先师有诀神将助，大圣无心火自飞。\n九转但能生羽翼，双凫忽去定何依。' },
  { title: '观元丹丘坐巫山屏风', author: '李白', poem: '昔游三峡见巫山，见画巫山宛相似。\n疑是天边十二峰，飞入君家彩屏里。\n寒松萧瑟如有声，阳台微茫如有情。\n锦衾瑶席何寂寂，楚王神女徒盈盈。\n高咫尺，如千里，翠屏丹崖灿如绮。\n苍苍远树围荆门，历历行舟泛巴水。\n水石潺湲万壑分，烟光草色俱氛氲。\n溪花笑日何年发，江客听猨几岁闻。\n使人对此心缅邈，疑入嵩丘梦彩云。' },
  { title: '求崔山人百丈崖瀑布图', author: '李白', poem: '百丈素崖裂，四山丹壁开。\n龙潭中喷射，昼夜生风雷。\n但见瀑泉落，如潨云汉来。\n闻君写真图，岛屿备萦回。\n石黛刷幽草，曾青泽古苔。\n幽缄傥相传，何必向天台。' },
  { title: '见野草中有曰白头翁者', author: '李白', poem: '醉入田家去，行歌荒野中。\n如何青草里，亦有白头翁。\n折取对明镜，宛将衰鬓同。\n微芳似相诮，留恨向东风。' },
  { title: '流夜郎题葵叶', author: '李白', poem: '慙君能卫足，叹我远移根。\n白日如分照，还归守故园。' },
  { title: '茔禅师房观山海图', author: '李白', poem: '真僧闭精宇，灭迹含达观。\n列嶂图云山，攒峰入霄汉。\n丹崖森在目，清昼疑卷幔。\n蓬壶来轩窗，瀛海入几案。\n烟涛争喷薄，岛屿相凌乱。\n征帆飘空中，瀑水洒天半。\n峥嵘若可陟，想像徒盈叹。\n杳与真心冥，遂谐静者玩。\n如登赤城里，揭步沧洲畔。\n即事能娱人，从兹得消散。' },
  { title: '白鹭鹚', author: '李白', poem: '白鹭下秋水，孤飞如坠霜。\n心闲且未去，独立沙洲傍。' },
  { title: '咏槿', author: '李白', poem: '园花笑芳年，池草艳春色。\n犹不如槿花，婵娟玉阶侧。\n芬荣何夭促，零落在瞬息。\n岂若琼树枝，终岁长翕赩。' },
  { title: '咏桂', author: '李白', poem: '世人种桃李，皆在金张门。\n攀折争捷径，及此春风暄。\n一朝天霜下，荣耀难久存。\n安知南山桂，绿叶垂芳根。\n清阴亦可托，何惜树君园。' },
  { title: '白胡桃', author: '李白', poem: '红罗袖里分明见，白玉盘中看却无。\n疑是老僧休念诵，腕前推下水晶珠。' },
  { title: '巫山枕障', author: '李白', poem: '巫山枕障画高丘，白帝城边树色秋。\n朝云夜入无行处，巴水横天更不流。' },
  { title: '南奔书怀', author: '李白', poem: '遥夜何漫漫，空歌白石烂。\n宁戚未匡齐，陈平终佐汉。\n搀抢扫河洛，直割鸿沟半。\n历数方未迁，云雷屡多难。\n天人秉旄钺，虎竹光藩翰。\n侍笔黄金台，传觞青玉案。\n不因秋风起，自有思归叹。\n主将动谗疑，王师忽离叛。\n自来白沙上，鼓噪丹阳岸。\n宾御如浮云，从风各消散。\n舟中指可掬，城上骸争爨。\n草草出近关，行行昧前算。\n南奔剧星火，北寇无涯畔。\n顾乏七宝鞭，留连道傍玩。\n太白夜食昴，长虹日中贯。\n秦赵兴天兵，茫茫九州乱。\n感遇明主恩，颇高祖逖言。\n过江誓流水，志在清中原。\n拔剑击前柱，悲歌难重论。' },
  { title: '题随州紫阳先生壁', author: '李白', poem: '神农好长生，风俗久已成。\n复闻紫阳客，早署丹台名。\n喘息餐妙气，步虚吟真声。\n道与古仙合，心将元化幷。\n楼疑出蓬海，鹤似飞玉京。\n松雪窗外晓，池水阶下明。\n忽耽笙歌乐，颇失轩冕情。\n终愿惠金液，提携凌太清。' },
  { title: '题元丹丘山居', author: '李白', poem: '故人栖东山，自爱丘壑美。\n青春卧空林，白日犹不起。\n松风清襟袖，石潭洗心耳。\n羡君无纷喧，高枕碧霞里。' },
  { title: '题元丹丘颍阳山居', author: '李白', poem: '仙游渡颍水，访隐同元君。\n忽遗苍生望，独与洪崖群。\n卜地初晦迹，兴言且成文。\n却顾北山断，前瞻南岭分。\n遥通汝海月，不隔嵩丘云。\n之子合逸趣，而我钦清芬。\n举迹倚松石，谈笑迷朝曛。\n益愿狎青鸟，拂衣栖江𣸣。' },
  { title: '题瓜州新河饯族叔舍人贲', author: '李白', poem: '齐公凿新河，万古流不绝。\n丰功利生人，天地同朽灭。\n两桥对双阁，芳树有行列。\n爱此如甘棠，谁云敢攀折。\n吴关倚此固，天险自兹设。\n海水落斗门，湖平见沙汭。\n我行送季父，弭櫂徒流悦。\n杨花满江来，疑是龙山雪。\n惜此林下兴，怆为山阳别。\n瞻望清路尘，归来空寂灭。' },
  { title: '洗脚亭', author: '李白', poem: '白道向姑熟，洪亭临道傍。\n前有昔时井，下有五丈床。\n樵女洗素足，行人歇金装。\n西望白鹭洲，芦花似朝霜。\n送君此时去，回首泪成行。' },
  { title: '劳劳亭', author: '李白', poem: '天下伤心处，劳劳送客亭。\n春风知别苦，不遣柳条青。' },
  { title: '题金陵王处士水亭', author: '李白', poem: '王子耽玄言，贤豪多在门。\n好鹅寻道士，爱竹啸名园。\n树色老荒苑，池光荡华轩。\n此堂见明月，更忆陆平原。\n埽拭青玉簟，为余置金尊。\n醉罢欲归去，花枝宿鸟喧。\n何时复来此，再得洗嚣烦。' },
  { title: '题嵩山逸人元丹丘山居', author: '李白', poem: '家本紫云山，道风未沦落。\n沈怀丹丘志，冲赏归寂寞。\n朅来游闽荒，扪涉穷禹凿。\n夤缘泛潮海，偃蹇陟庐霍。\n凭雷蹑天窗，弄影憩霞阁。\n且欣登眺美，颇惬隐沦诺。\n三山旷幽期，四岳聊所托。\n故人契嵩颖，高义炳丹雘。\n灭迹遗纷嚣，终言本峰壑。\n自矜林湍好，不羡朝市乐。\n偶与真意幷，顿觉世情薄。\n尔能折芳桂，吾亦采兰若。\n拙妻好乘鸾，娇女爱飞鹤。\n提携访神仙，从此炼金药。' },
  { title: '题江夏修静寺', author: '李白', poem: '我家北海宅，作寺南江滨。\n空庭无玉树，高殿坐幽人。\n书带留青草，琴堂幂素尘。\n平生种桃李，寂灭不成春。' },
  { title: '题宛溪馆', author: '李白', poem: '吾怜宛溪好，百尺照心明。\n何谢新安水，千寻见底清。\n白沙留月色，绿竹助秋声。\n却笑严湍上，于今独擅名。' },
  { title: '题东谿公幽居', author: '李白', poem: '杜陵贤人清且廉，东溪卜筑岁将淹。\n宅近青山同谢朓，门垂碧柳似陶潜。\n好鸟迎春歌后院，飞花送酒舞前檐。\n客到但知留一醉，盘中秪有水晶盐。' },
  { title: '嘲鲁儒', author: '李白', poem: '鲁叟谈五经，白发死章句。\n问以经济策，茫如坠烟雾。\n足着远游履，首戴方山巾。\n缓步从直道，未行先起尘。\n秦家丞相府，不重褒衣人。\n君非叔孙通，与我本殊伦。\n时事且未达，归耕汶水滨。' },
  { title: '惧谗', author: '李白', poem: '二桃杀三士，讵假劒如霜。\n众女妬蛾眉，双花竞春芳。\n魏姝信郑褏，掩袂对怀王。\n一惑巧言子，朱颜成死伤。\n行将泣团扇，戚戚愁人肠。' },
  { title: '观猎', author: '李白', poem: '太守耀清威，乘闲弄晚晖。\n江沙横猎骑，山火遶行围。\n箭逐云鸿落，鹰随月兔飞。\n不知白日暮，欢赏夜方归。' },
  { title: '观胡人吹笛', author: '李白', poem: '胡人吹玉笛，一半是秦声。\n十月吴山晓，梅花落敬亭。\n愁闻出塞曲，泪满逐臣缨。\n却望长安道，空怀恋主情。' },
  { title: '军行', author: '李白', poem: '骝马新跨白玉鞍，战罢沙场月色寒。\n城头铁鼓声犹震，匣里金刀血未干。' },
  { title: '平虏将军妻', author: '李白', poem: '平虏将军妇，入门二十年。\n君心自有悦，妾宠岂能专。\n出解床前帐，行吟道上篇。\n古人不唾井，莫忘昔缠绵。' },
  { title: '春夜洛城闻笛', author: '李白', poem: '谁家玉笛暗飞声，散入春风满洛城。\n此夜曲中闻折柳，何人不起故园情。' },
  { title: '嵩山采菖蒲者', author: '李白', poem: '神仙多古貌，双耳下垂肩。\n嵩岳逢汉武，疑是九疑仙。\n我来采菖蒲，服食可延年。\n言终忽不见，灭影入云烟。\n喻帝竟莫悟，终归茂陵田。' },
  { title: '金陵听韩侍御吹笛', author: '李白', poem: '韩公吹玉笛，倜傥流英音。\n风吹绕钟山，万壑皆龙吟。\n王子停凤管，师襄掩瑶琴。\n余韵度江去，天涯安可寻。' },
  { title: '流夜郎闻酺不预', author: '李白', poem: '北阙圣人歌太康，南冠君子窜遐荒。\n汉酺闻奏钧天乐，愿得风吹到夜郎。' },
  { title: '放后遇恩不沾', author: '李白', poem: '天作云与雷，霈然德泽开。\n东风日本至，白雉越裳来。\n独弃长沙国，三年未许回。\n何时入宣室，更问洛阳才。' },
  { title: '宣城见杜鹃花', author: '李白', poem: '蜀国曾闻子规鸟，宣城还见杜鹃花。\n一呌一回肠一断，三春三月忆三巴。' },
  { title: '白田马上闻莺', author: '李白', poem: '黄鹂啄紫椹，五月鸣桑枝。\n我行不记日，误作阳春时。\n蚕老客未归，白田已缲丝。\n驱马又前去，扪心空自悲。' },
  { title: '三五七言', author: '李白', poem: '秋风清，秋月明。\n落叶聚还散，寒鸦栖复惊。\n相思相见知何日，此时此夜难为情。' },
  { title: '杂诗', author: '李白', poem: '白日与明月，昼夜尚不闲。\n况尔悠悠人，安得久世间。\n传闻海水上，乃有蓬莱山。\n玉树生绿叶，灵仙每登攀。\n一食驻玄发，再食留红颜。\n吾欲从此去，去之无时还。' },
  { title: '寄远十一首 一', author: '李白', poem: '三鸟别王母，衔书来见过。\n肠断若剪弦，其如愁思何。\n遥知玉窗里，纤手弄云和。\n奏曲有深意，青松交女萝。\n写水山井中，同泉岂殊波。\n秦心与楚恨，皎皎为谁多。' },
  { title: '寄远十一首 二', author: '李白', poem: '青楼何所在，乃在碧云中。\n宝镜挂秋水，罗衣轻春风。\n新妆坐落日，怅望金屏空。\n念此送短书，愿因双飞鸿。' },
  { title: '寄远十一首 三', author: '李白', poem: '本作一行书，殷勤道相忆。\n一行复一行，满纸情何极。\n瑶台有黄鹤，为报青楼人。\n朱颜凋落尽，白发一何新。\n自知未应还，离居经三春。\n桃李今若为，当窗发光彩。\n莫使香风飘，留与红芳待。' },
  { title: '寄远十一首 四', author: '李白', poem: '玉[筯]落春镜，坐愁湖阳水。\n闻与阴丽华，风烟接邻里。\n青春已复过，白日忽相催。\n但恐荷花晚，令人意已摧。\n相思不惜梦，日夜向阳台。' },
  { title: '寄远十一首 五', author: '李白', poem: '远忆巫山阳，花明渌江暖。\n踌躇未得往，泪向南云满。\n春风复无情，吹我梦魂断。\n不见眼中人，天长音信短。' },
  { title: '寄远十一首 六', author: '李白', poem: '阳台隔楚水，春草生黄河。\n相思无日夜，浩荡若流波。\n流波向海去，欲见终无因。\n遥将一点泪，远寄如花人。' },
  { title: '寄远十一首 七', author: '李白', poem: '妾在舂陵东，君居汉江岛。\n一日望花光，往来成白道。\n一为云雨别，此地生秋草。\n秋草秋蛾飞，相思愁落晖。\n何由一相见，灭烛解罗衣。' },
  { title: '寄远十一首 八', author: '李白', poem: '忆昨东园桃李红碧枝，与君此时初别离。\n金瓶落井无消息，令人行叹复坐思。\n坐思行叹成楚越，春风玉颜畏销歇。\n碧窗纷纷下落花，青楼寂寂空明月。\n两不见，但相思，空留锦字表心素，至今缄愁不忍窥。' },
  { title: '寄远十一首 九', author: '李白', poem: '长短春草绿，缘阶如有情。\n卷施心独苦，抽却死还生。\n覩物知妾意，希君种后庭。\n闲时当采掇，念此莫相轻。' },
  { title: '寄远十一首 十', author: '李白', poem: '鲁缟如玉霜，笔题月氏书。\n寄书白鹦鹉，西海慰离居。\n行数虽不多，字字有委曲。\n天末如见之，开缄泪相续。\n泪尽恨转深，千里同此心。\n相思千万里，一书值千金。' },
  { title: '寄远十一首 十一', author: '李白', poem: '爱君芙蓉婵娟之艳色，色可餐兮难再得。\n怜君冰玉清逈之明心，情不极兮意已深。\n朝共琅玕之绮食，夜同鸳鸯之锦衾。\n恩情婉娈忽为别，使人莫错乱愁心。\n乱愁心，涕如雪，寒灯厌梦魂欲绝。\n觉来相思生白发，盈盈汉水若可越。\n可惜凌波步罗韤，美人美人兮归去来，莫作朝云暮雨兮飞阳台。' },
  { title: '长信宫', author: '李白', poem: '月皎昭阳殿，霜清长信宫。\n天行乘玉辇，飞燕与君同。\n别有欢娱处，承恩乐未穷。\n谁怜团扇妾，独坐怨秋风。' },
  { title: '长门怨二首 一', author: '李白', poem: '天回北斗挂西楼，金屋无人萤火流。\n月光欲到长门殿，别作深宫一段愁。' },
  { title: '长门怨二首 二', author: '李白', poem: '桂殿长愁不记春，黄金四屋起秋尘。\n夜悬明镜青天上，独照长门宫里人。' },
  { title: '春怨', author: '李白', poem: '白马金羁辽海东，罗帷绣被卧春风。\n落月低轩窥烛尽，飞花入户笑床空。' },
  { title: '代赠远', author: '李白', poem: '妾本洛阳人，狂夫幽燕客。\n渴饮易水波，由来多感激。\n胡马西北驰，香騣摇绿丝。\n鸣鞭从此去，逐虏荡边陲。\n昔去有好言，不言久离别。\n燕支多美女，走马轻风雪。\n见此不记人，恩情云雨绝。\n啼流玉筯尽，坐恨金闺切。\n织锦作短书，肠随回文结。\n相思欲有寄，恐君不见察。\n焚之扬其灰，手迹自此灭。' },
  { title: '陌上赠美人', author: '李白', poem: '骏马骄行踏落花，垂鞭直拂五云车。\n美人一笑褰珠箔，遥指红楼是妾家。' },
  { title: '闺情', author: '李白', poem: '流水去绝国，浮云辞故关。\n水或恋前浦，云犹归旧山。\n恨君流沙去，弃妾渔阳间。\n玉筯夜垂流，双双落朱颜。\n黄鸟坐相悲，绿杨谁更攀。\n织锦心草草，挑灯泪斑斑。\n窥镜不自识，况乃狂夫还。' },
  { title: '代别情人', author: '李白', poem: '清水本不动，桃花发岸傍。\n桃花弄水色，波荡摇春光。\n我悦子容艳，子倾我文章。\n风吹绿琴去，曲度紫鸳鸯。\n昔作一水鱼，今成两枝鸟。\n哀哀长鸡鸣，夜夜达五晓。\n起折相思树，归赠知寸心。\n覆水不可收，行云难重寻。\n天涯有度鸟，莫绝瑶华音。' },
  { title: '代秋情', author: '李白', poem: '几日相别离，门前生穞葵。\n寒蝉聒梧桐，日夕长鸣悲。\n白露湿萤火，清霜凌兔丝。\n空掩紫罗袂，长啼无尽时。' },
  { title: '怨情', author: '李白', poem: '新人如花虽可宠，故人似玉由来重。\n花性飘扬不自持，玉心皎洁终不移。\n故人昔新今尚故，还见新人有故时。\n请看陈后黄金屋，寂寂珠帘生网丝。' },
  { title: '湖边采莲妇', author: '李白', poem: '小姑织白纻，未解将人语。\n大嫂采芙蓉，溪湖千万重。\n长兄行不在，莫使外人逢。\n愿学秋胡妇，贞心比古松。' },
  { title: '代寄情楚词体', author: '李白', poem: '君不来兮，徒蓄怨积思而孤吟。\n云阳一去已远，隔巫山绿水之沈沈。\n留余香兮染绣被，夜欲寝兮愁人心。\n朝驰余马于青楼，怳若空而夷犹。\n浮云深兮不得语，却惆怅而怀忧。\n使青鸟兮衔书，恨独宿兮伤离居。\n何无情而雨绝，梦虽往而交疎。\n横流涕而长嗟，折芳洲之瑶华。\n送飞鸟以极目，怨夕阳之西斜。\n愿为连根同死之秋草，不作飞空之落花。' },
  { title: '学古思边', author: '李白', poem: '衔悲上陇首，肠断不见君。\n流水若有情，幽哀从此分。\n苍茫愁边色，惆怅落日曛。\n山外接远天，天际复有云。\n白雁从中来，飞鸣苦难闻。\n足系一书札，寄言难离群。\n离群心断绝，十见花成雪。\n胡地无春晖，征人行不归。\n相思杳如梦，珠泪湿罗衣。' },
  { title: '思边', author: '李白', poem: '去年何时君别妾，南园绿草飞蝴蝶。\n今岁何时妾忆君，西山白雪暗晴云。\n玉关去此三千里，欲寄音书那可闻。' },
  { title: '口号吴王美人半醉', author: '李白', poem: '风动荷花水殿香，姑苏台上宴吴王。\n西施醉舞娇无力，笑倚东窗白玉床。' },
  { title: '代美人愁镜二首 一', author: '李白', poem: '明明金鹊镜，了了玉台前。\n拂拭交冰月，光辉何清圆。\n红颜老昨日，白发多去年。\n铅粉坐相误，照来空凄然。' },
  { title: '代美人愁镜二首 二', author: '李白', poem: '美人赠此盘龙之宝镜，烛我金缕之罗衣。\n时将红袖拂明月，为惜普照之余晖。\n影中金鹊飞不灭，台下青鸾思独绝。\n藳砧一别若箭弦，去有日，来无年。\n狂风吹却妾心断，玉筯幷堕菱花前。' },
  { title: '赠段七娘', author: '李白', poem: '罗韤凌波生网尘，那能得计访情亲。\n千杯绿酒何辞醉，一面红妆恼杀人。' },
  { title: '别内赴征三首 一', author: '李白', poem: '王命三征去未还，明朝离别出吴关。\n白玉高楼看不见，相思须上望夫山。' },
  { title: '别内赴征三首 二', author: '李白', poem: '出门妻子强牵衣，问我西行几日归。\n归时傥佩黄金印，莫学苏秦不下机。' },
  { title: '别内赴征三首 三', author: '李白', poem: '翡翠为楼金作梯，谁人独宿倚门啼。\n夜坐寒灯连晓月，行行泪尽楚关西。' },
  { title: '秋浦寄内', author: '李白', poem: '我今寻阳去，辞家千里余。\n结荷倦水宿，却寄大雷书。\n虽不同辛苦，怆离各自居。\n我自入秋浦，三年北信疎。\n红颜愁落尽，白发不能除。\n有客自梁苑，手携五色鱼。\n开鱼得锦字，归问我何如。\n江山虽道阻，意合不为殊。' },
  { title: '自代内赠', author: '李白', poem: '宝刀截流水，无有断绝时。\n妾意逐君行，缠绵亦如之。\n别来门前草，秋巷春转碧。\n埽尽更还生，萋萋满行迹。\n鸣凤始相得，雄惊雌各飞。\n游云落何山，一往不见归。\n估客发大楼，知君在秋浦。\n梁苑空锦衾，阳台梦行雨。\n妾家三作相，失势去西秦。\n犹有旧歌管，凄清闻四邻。\n曲度入紫云，啼无眼中人。\n妾似井底桃，开花向谁笑。\n君如天上月，不肯一回照。\n窥镜不自识，别多憔悴深。\n安得秦吉了，为人道寸心。' },
  { title: '秋浦感主人归燕寄内', author: '李白', poem: '霜凋楚关木，始知杀气严。\n寥寥金天廓，婉婉绿红潜。\n胡燕别主人，双双语前檐。\n三飞四回顾，欲去复相瞻。\n岂不恋华屋，终然谢珠帘。\n我不及此鸟，远行岁已淹。\n寄书道中叹，泪下不能缄。' },
  { title: '送内寻庐山女道士李腾空二首 一', author: '李白', poem: '君寻腾空子，应到碧山家。\n水舂云母确，风埽石楠花。\n若爱幽居好，相邀弄紫霞。' },
  { title: '送内寻庐山女道士李腾空二首 二', author: '李白', poem: '多君相门女，学道爱神仙。\n素手掬青霭，罗衣曳紫烟。\n一往屏风叠，乘鸾着玉鞭。' },
  { title: '赠内', author: '李白', poem: '三百六十日，日日醉如泥。\n虽为李白妇，何异太常妻。' },
  { title: '在浔阳非所寄内', author: '李白', poem: '闻难知恸哭，行啼入府中。\n多君同蔡琰，流泪请曹公。\n知登吴章岭，昔与死无分。\n崎岖行石道，外折入青云。\n相见若悲歌，哀声那可闻。' },
  { title: '南流夜郎寄内', author: '李白', poem: '夜郎天外怨离居，明月楼中音信疎。\n北雁春归看欲尽，南来不得豫章书。' },
  { title: '越女词五首 一', author: '李白', poem: '长干吴儿女，眉目艳新月。\n屐上足如霜，不着鸦头袜。' },
  { title: '越女词五首 二', author: '李白', poem: '吴儿多白皙，好为荡舟剧。\n卖眼掷春心，折花调行客。' },
  { title: '越女词五首 三', author: '李白', poem: '耶溪采莲女，见客櫂歌回。\n笑入荷花去，佯羞不出来。' },
  { title: '越女词五首 四', author: '李白', poem: '东阳素足女，会稽素舸郎。\n相看月未堕，白地断肝肠。' },
  { title: '越女词五首 五', author: '李白', poem: '镜湖水如月，耶溪女似雪。\n新妆荡新波，光景两奇绝。' },
  { title: '浣纱石上女', author: '李白', poem: '玉面耶溪女，青娥红粉妆。\n一双金齿屐，两足白如霜。' },
  { title: '示金陵子', author: '李白', poem: '金陵城东谁家子，窃听琴声碧窗里。\n落花一片天上来，随人直渡西江水。\n楚歌吴语娇不成，似能未能最有情。\n谢公正要东山妓，携手林泉处处行。' },
  { title: '出妓金陵子呈卢六四首 一', author: '李白', poem: '安石东山三十春，傲然携妓出风尘。\n楼中见我金陵子，何似阳台云雨人。' },
  { title: '出妓金陵子呈卢六四首 二', author: '李白', poem: '南国新丰酒，东山小妓歌。\n对君君不乐，花月奈愁何。' },
  { title: '出妓金陵子呈卢六四首 三', author: '李白', poem: '东道烟霞主，西江诗酒筵。\n相逢不觉醉，日堕历阳川。' },
  { title: '出妓金陵子呈卢六四首 四', author: '李白', poem: '小妓金陵歌楚声，家僮丹砂学凤鸣。\n我亦为君饮清酒，君心不肯向人倾。' },
  { title: '巴女词', author: '李白', poem: '巴水急如箭，巴船去若飞。\n十月三千里，郎行几岁归。' },
  { title: '哭晁卿衡', author: '李白', poem: '日本晁卿辞帝都，征帆一片绕蓬壶。\n明月不归沈碧海，白云愁色满苍梧。' },
  { title: '自溧水道哭王炎三首 一', author: '李白', poem: '白杨双行行，白马悲路傍。\n晨兴见晓月，更似发云阳。\n溧水通吴关，逝川去未央。\n故人万化尽，闭骨茅山冈。\n天上坠玉棺，泉中掩龙章。\n名飞日月上，义与风云翔。\n逸气竟莫展，英图俄夭伤。\n楚国一老人，来嗟龚胜亡。\n有言不可道，雪泣忆兰芳。' },
  { title: '自溧水道哭王炎三首 二', author: '李白', poem: '王公希代宝，弃世一何早。\n吊死不及哀，殡宫已秋草。\n悲来欲脱劒，挂向何枝好。\n哭向茅山虽未摧，一生泪尽丹阳道。' },
  { title: '自溧水道哭王炎三首 三', author: '李白', poem: '王家碧瑶树，一树忽先摧。\n海内故人泣，天涯吊鹤来。\n未成霖雨用，先失济川材。\n一罢广陵散，鸣琴更不开。' },
  { title: '哭宣城善酿纪叟', author: '李白', poem: '纪叟黄泉里，还应酿老春。\n夜台无晓日，沽酒与何人。' },
  { title: '宣城哭蒋征君华', author: '李白', poem: '敬亭埋玉树，知是蒋征君。\n安得相如草，空余封禅文。\n池台空有月，词赋旧凌云。\n独挂延陵劒，千秋在古坟。' },
  { title: '月夜金陵怀古', author: '李白', poem: '苍苍金陵月，空悬帝王州。\n天文列宿在，霸业大江流。\n绿水绝驰道，青松摧古丘。\n台倾𫛛鹊观，宫没凤凰楼。\n别殿悲清暑，芳园罢乐游。\n一闻歌玉树，萧瑟后庭秋。' },
  { title: '冬日归旧山', author: '李白', poem: '未洗染尘缨，归来芳草平。\n一条藤径绿，万点雪峰晴。\n地冷叶先尽，谷寒云不行。\n嫩篁侵舍密，古树倒江横。\n白犬离村吠，苍苔壁上生。\n穿厨孤雉过，临屋旧猨鸣。\n木落禽巢在，篱疎兽路成。\n拂床苍鼠走，倒箧素鱼惊。\n洗砚修良策，敲松拟素贞。\n此时重一去，去合到三清。' },
  { title: '望夫石', author: '李白', poem: '髣髴古容仪，含愁带曙辉。\n露如今日泪，苔似昔年衣。\n有恨同湘女，无言类楚妃。\n寂然芳霭内，犹若待夫归。' },
  { title: '对雨', author: '李白', poem: '卷帘聊举目，露湿草绵芊。\n古岫藏云毳，空庭织碎烟。\n水纹愁不起，风线重难牵。\n尽日扶犂叟，往来江树前。' },
  { title: '晓晴', author: '李白', poem: '野凉疎雨歇，春色徧萋萋。\n鱼跃青池满，莺吟绿树低。\n野花妆面湿，山草纽斜齐。\n零落残雪片，风吹挂竹谿。' },
  { title: '初月', author: '李白', poem: '玉蟾离海上，白露湿花时。\n云畔风生爪，沙头水浸眉。\n乐哉弦管客，愁杀战征儿。\n因绝西园赏，临风一咏诗。' },
  { title: '雨后望月', author: '李白', poem: '四郊阴霭散，开户半蟾生。\n万里舒霜合，一条江练横。\n出时山眼白，高后海心明。\n为惜如团扇，长吟到五更。' },
  { title: '赋得鹤送史司马赴崔相公幕', author: '李白', poem: '峥嵘丞相府，清切凤凰池。\n羡尔瑶台鹤，高栖琼树枝。\n归飞晴日好，吟弄惠风吹。\n正有乘轩乐，初当学舞时。\n珍禽在罗网，微命若游丝。\n愿托周周羽，相衔汉水湄。' },
  { title: '送客归吴', author: '李白', poem: '江村秋雨歇，酒尽一帆飞。\n路历波涛去，家惟坐卧归。\n岛花开灼灼，汀柳细依依。\n别后无余事，还应埽钓矶。' },
  { title: '送友生游峡中', author: '李白', poem: '风静杨柳垂，看花又别离。\n几年同在此，今日各驱驰。\n峡里闻猨呌，山头见月时。\n殷勤一杯酒，珍重岁寒姿。' },
  { title: '送袁明府任长沙', author: '李白', poem: '别离杨柳青，樽酒表丹诚。\n古道携琴去，深山见峡迎。\n暖风花绕树，秋雨草沿城。\n自此长江内，无因夜犬惊。' },
  { title: '邹衍谷', author: '李白', poem: '燕谷无煖气，穷岩闭严阴。\n邹子一吹律，能回天地心。' },
  { title: '杂言用投丹阳知己兼奉宣慰判官', author: '李白', poem: '客从昆仑来，遗我双玉璞。\n云是古之得道者西王母食之余，食之可以凌太虚。\n受之颇谓绝今昔，求识江淮人犹乎比石。\n如今虽在卞和手，□□正憔悴。\n了了知之亦何益，恭闻士有调相如。\n始从镐京还，复欲镐京去。\n能上秦王殿，何时回光一相眄。\n欲投君，保君年，幸君持取无弃捐。\n无弃捐，服之与君俱神仙。' },
  { title: '观鱼潭', author: '李白', poem: '观鱼碧潭上，木落潭水清。\n日暮紫鳞跃，圆波处处生。\n凉烟浮竹尽，秋月照沙明。\n何必沧浪去，兹焉可濯缨。' },
  { title: '自广平乘醉走马六十里至邯郸登城楼览古书怀', author: '李白', poem: '醉骑白花马，西走邯郸城。\n扬鞭动柳色，写鞚春风生。\n入郭登高楼，山川与云平。\n深宫翳绿草，万事伤人情。\n相如章华巅，猛气折秦嬴。\n两虎不可鬬，廉公终负荆。\n提携袴中儿，杵臼及程婴。\n立孤就白刃，必死耀丹诚。\n平原三千客，谈笑尽豪英。\n毛君能颕脱，二国且同盟。\n皆为黄泉土，使我涕纵横。\n磊磊石子冈，萧萧白杨声。\n诸贤没此地，碑版有残铭。\n太古共今时，由来互哀荣。\n伤哉何足道，感激仰空名。\n赵俗爱长劒，文儒少逢迎。\n闲从博陵游，畅饮雪朝酲。\n歌酣易水动，鼓震丛台倾。\n日落把烛归，凌晨向燕京。\n方陈五饵策，一使胡尘清。' },
  { title: '宣州长史弟昭赠余琴谿中双舞鹤诗以见志', author: '李白', poem: '令弟佐宣城，赠余琴谿鹤。\n谓言天涯雪，忽向窗前落。\n白玉为毛衣，黄金不肯博。\n背风振六翮，对舞临山阁。\n顾我如有情，长鸣似相托。\n何当驾此物，与尔腾寥廓。' },
  { title: '题舒州司空山瀑布', author: '李白', poem: '断崖如削瓜，岚光破崖绿。\n天河从中来，白云涨川谷。\n玉案赤文字，世眼不可读。\n摄身凌青霄，松风拂我足。' },
  { title: '金陵新亭', author: '李白', poem: '金陵风景好，豪士集新亭。\n举目山河异，偏伤周𫖮情。\n四坐楚囚悲，不忧社稷倾。\n王公何慷慨，千载仰雄名。' },
  { title: '上清宝鼎诗 一', author: '李白', poem: '我居清空表，君处红埃中。\n仙人持玉尺，废君多少才。\n玉尺不可尽，君才无时休。' },
  { title: '上清宝鼎诗 二', author: '李白', poem: '咽服十二环，奄有仙人房。\n暮骑紫麟去，海气侵肌凉。\n赠我累累珠，靡靡明月光。' },
  { title: '题许宣平庵壁', author: '李白', poem: '我吟传舍咏，来访真人居。\n烟岭迷高迹，云林隔太虚。\n窥庭但萧瑟，倚杖空踌躇。\n应化辽天鹤，归当千岁余。' },
  { title: '戏赠杜甫', author: '李白', poem: '饭颗山头逢杜甫，顶戴笠子日卓午。\n借问别来太瘦生，总为从前作诗苦。' },
  { title: '春感诗', author: '李白', poem: '茫茫南与北，道直事难谐。\n榆荚钱生树，杨花玉糁街。\n尘萦游子面，蝶弄美人钗。\n却忆青山上，云门掩竹斋。' },
  { title: '白微时募县小吏入令卧内尝驱牛经堂下令妻怒将加诘责白亟以诗谢云', author: '李白', poem: '素面倚栏钩，娇声出外头。\n若非是织女，何得问牵牛。' },
  { title: '句', author: '李白', poem: '焰随红日去，烟逐暮云飞。\n绿鬓随波散，红颜逐浪无。\n因何逢伍相，应是想秋胡。\n举袖露条脱，招我饭胡麻。' },
  { title: '拟古诗十二首 一', author: '韦应物', poem: '辞君远行迈，饮此长恨端。\n已谓道里远，如何中险艰。\n流水赴大壑，孤云还暮山。\n无情尚有归，行子何独难。\n驱车背乡园，朔风卷行迹。\n严冬霜断肌，日入不遑息。\n忧欢容发变，寒暑人事易。\n中心君讵知，冰玉徒贞白。' },
  { title: '拟古诗十二首 二', author: '韦应物', poem: '黄鸟何关关，幽兰亦靡靡。\n此时深闺妇，日照纱窗里。\n娟娟双青娥，微微启玉齿。\n自惜桃李年，误身游侠子。\n无事久离别，不知今生死。' },
  { title: '拟古诗十二首 三', author: '韦应物', poem: '峨峨高山巅，浼浼青川流。\n世人不自悟，驰谢如惊飍。\n百金非所重，厚意良难得。\n旨酒亲与朋，芳年乐京国。\n京城繁华地，轩盖凌晨出。\n垂杨十二衢，隐暎金张室。\n汉宫南北对，飞观齐白日。\n游泳属芳时，平生自云毕。' },
  { title: '拟古诗十二首 四', author: '韦应物', poem: '绮楼何氛氲，朝日正杲杲。\n四壁含清风，丹霞射其牖。\n玉颜上哀啭，绝耳非世有。\n但感离恨情，不知谁家妇。\n孤云忽无色，边马为回首。\n曲绝碧天高，余声散秋草。\n徘徊帷中意，独夜不堪守。\n思逐朔风翔，一去千里道。' },
  { title: '拟古诗十二首 五', author: '韦应物', poem: '嘉树蔼初绿，靡芜吐幽芳。\n君子不在赏，寄之云路长。\n路长信难越，惜此芳时歇。\n孤鸟去不还，缄情向天末。' },
  { title: '拟古诗十二首 六', author: '韦应物', poem: '月满秋夜长，惊乌号北林。\n天河横未落，斗柄当西南。\n寒蛩悲洞房，好鸟无遗音。\n商飙一夕至，独宿怀重衾。\n旧交日千里，隔我浮与沈。\n人生岂草木，寒暑移此心。' },
  { title: '拟古诗十二首 七', author: '韦应物', poem: '酒星非所酌，月桂不为食。\n虚薄空有名，为君长叹息。\n兰蕙虽可怀，芳香与时息。\n岂如凌霜叶，岁暮蔼颜色。\n折柔将有赠，延意千里客。\n草木知贱微，所贵寒不易。' },
  { title: '拟古诗十二首 八', author: '韦应物', poem: '神州高爽地，遐瞰靡不通。\n寒月野无绿，寥寥天宇空。\n阴阳不停驭，贞脆各有终。\n汾沮何鄙俭，考槃何退穷。\n反志解牵跼，无为尚劳躬。\n美人夺南国，一笑开芙蓉。\n清镜理容发，褰帘出深重。\n艳曲呈皓齿，舞罗不堪风。\n慊慊情有待，赠芳为我容。\n可嗟青楼月，流影君帷中。' },
  { title: '拟古诗十二首 九', author: '韦应物', poem: '春至林木变，洞房夕含清。\n单居谁能裁，好鸟对我鸣。\n良人久燕赵，新爱移平生。\n别时双鸳绮，留此千恨情。\n碧草生旧迹，绿琴歇芳声。\n思将魂梦欢，反侧寐不成。\n揽衣迷所次，起望空前庭。\n孤影中自恻，不知双涕零。' },
  { title: '拟古诗十二首 十', author: '韦应物', poem: '秋天无留景，万物藏光辉。\n落叶随风起，愁人独何依。\n华月屡圆缺，君还浩无期。\n如何雨绝天，一去音问违。' },
  { title: '拟古诗十二首 十一', author: '韦应物', poem: '有客天一方，寄我孤桐琴。\n迢迢万里隔，托此传幽音。\n冰霜中自结，龙凤相与吟。\n弦以明直道，漆以固交深。' },
  { title: '拟古诗十二首 十二', author: '韦应物', poem: '白日淇上没，空闺生远愁。\n寸心不可限，淇水长悠悠。\n芳树自妍芳，春禽自相求。\n徘徊东西厢，孤妾谁与俦。\n年华逐丝泪，一落俱不收。' },
  { title: '杂体五首 一', author: '韦应物', poem: '沈沈匣中镜，为此尘垢蚀。\n辉光何所如，月在云中黑。\n南金既雕错，鞶带共辉饰。\n空存鉴物名，坐使妍蚩惑。\n美人竭肝胆，思照冰玉色。\n自非磨莹工，日日空叹息。' },
  { title: '杂体五首 二', author: '韦应物', poem: '古宅集祆鸟，群号枯树枝。\n黄昏窥人室，鬼物相与期。\n居人不安寝，搏击思此时。\n岂无鹰与鹯，饱肉不肯飞。\n既乖逐鸟节，空养凌云姿。\n孤负肉食恩，何异城上鸱。' },
  { title: '杂体五首 三', author: '韦应物', poem: '春罗双鸳鸯，出自寒夜女。\n心精烟雾色，指历千万绪。\n长安贵豪家，妖艳不可数。\n裁此百日功，唯将一朝舞。\n舞罢复裁新，岂思劳者苦。' },
  { title: '杂体五首 四', author: '韦应物', poem: '同声自相应，体质不必齐。\n谁知贾人铎，能使大乐谐。\n铿锵发宫征，和乐变其哀。\n人神既昭享，凤鸟亦下来。\n岂非至贱物，一奏升天阶。\n物情苟有合，莫问玉与泥。' },
  { title: '杂体五首 五', author: '韦应物', poem: '碌碌荆山璞，卞和献君门。\n荆璞非有求，和氏非有恩。\n所献知国宝，至公不待言。\n是非吾欲默，此道今岂存。' },
  { title: '与友生野饮效陶体', author: '韦应物', poem: '携酒花林下，前有千载坟。\n于时不共酌，奈此泉下人。\n始自玩芳物，行当念徂春。\n聊舒远世踪，坐望还山云。\n且遂一欢笑，焉知贱与贫。' },
  { title: '效何水部二首 一', author: '韦应物', poem: '玉宇含清露，香笼散轻烟。\n应当结沈抱，难从兹夕眠。' },
  { title: '效何水部二首 二', author: '韦应物', poem: '夕漏起遥恨，虫响乱秋阴。\n反复相思字，中有故人心。' },
  { title: '效陶彭泽', author: '韦应物', poem: '霜露悴百草，时菊独妍华。\n物性有如此，寒暑其奈何。\n掇英泛浊醪，日入会田家。\n尽醉茅檐下，一生岂在多。' },
  { title: '大梁亭会李四栖梧作', author: '韦应物', poem: '梁王昔爱才，千古化不泯。\n至今蓬池上，远集八方宾。\n车马平明合，城郭满埃尘。\n逢君一相许，岂要平生亲。\n入仕三十载，如何独未伸。\n英声久籍籍，台阁多故人。\n置酒发清弹，相与乐佳辰。\n孤亭得长望，白日下广津。\n富贵良可取，朅来西入秦。\n秋风旦夕起，安得客梁陈。' },
  { title: '燕李录事', author: '韦应物', poem: '与君十五侍皇闱，晓拂炉烟上赤墀。\n花开汉苑经过处，雪下骊山沐浴时。\n近臣零落今犹在，仙驾飘飖不可期。\n此日相逢思旧日，一杯成喜亦成悲。' },
  { title: '淮上喜会梁川故人', author: '韦应物', poem: '江汉曾为客，相逢每醉还。\n浮云一别后，流水十年间。\n欢笑情如旧，萧疎鬓已斑。\n何因北归去，淮上对秋山。' },
  { title: '扬州偶会前洛阳卢耿主簿', author: '韦应物', poem: '楚塞故人稀，相逢本不期。\n犹存袖里字，忽怪鬓中丝。\n客舍盈樽酒，江行满箧诗。\n更能连骑出，还似洛桥时。' },
  { title: '贾常侍林亭燕集', author: '韦应物', poem: '高贤侍天陛，迹显心独幽。\n朱轩骛关右，池馆在东周。\n缭绕接都城，氤氲望嵩丘。\n群公尽词客，方驾永日游。\n朝旦气候佳，逍遥写烦忧。\n绿林蔼已布，华沼澹不流。\n没露摘幽草，涉烟玩轻舟。\n圆荷既出水，广厦可淹留。\n放神遗所拘，觥罚屡见酬。\n乐燕良未极，安知有沈浮。\n醉罢各云散，何当复相求。' },
  { title: '月下会徐十一草堂', author: '韦应物', poem: '空斋无一事，岸帻故人期。\n暂辍观书夜，还题玩月诗。\n远钟高枕后，清露卷帘时。\n暗觉新秋近，残河欲曙迟。' },
  { title: '移疾会诗客元生与释子法朗因贻诸祠曹', author: '韦应物', poem: '对此嘉树林，独有戚戚颜。\n抱瘵知旷职，淹旬非乐闲。\n释子来问讯，诗人亦扣关。\n道同意暂遣，客散疾徐还。\n园径自幽静，玄蝉噪其间。\n高牕瞰远郊，暮色起秋山。\n英曹幸休暇，悢悢心所攀。' },
  { title: '慈恩伽蓝清会', author: '韦应物', poem: '素友俱薄世，屡招清景赏。\n鸣钟悟音闻，宿昔心已往。\n重门相洞达，高宇亦遐朗。\n岚岭晓城分，清阴夏条长。\n氲氛芳台馥，萧散竹池广。\n平荷随波泛，廻飙激林响。\n蔬食遵道侣，泊怀遗滞想。\n何彼尘昏人，区区在天壤。' },
  { title: '夜偶诗客操公作', author: '韦应物', poem: '尘襟一潇洒，清夜得禅公。\n远自鹤林寺，了知人世空。\n惊禽翻暗叶，流水注幽丛。\n多谢非玄度，聊将诗兴同。' },
  { title: '与韩库部会王祠曹宅作', author: '韦应物', poem: '闲门荫堤柳，秋渠含夕清。\n微风送荷气，坐客散尘缨。\n守默共无恡，抱冲俱寡营。\n良时颇高会，琴酌共开情。' },
  { title: '晦日处士叔园林燕集', author: '韦应物', poem: '遽看蓂叶尽，坐阙芳年赏。\n赖此林下期，清风涤烦想。\n始萌动新煦，佳禽发幽响。\n岚岭对高斋，春流灌蔬壤。\n罇酒遗形迹，道言屡开奖。\n幸蒙终夕懽，聊用税归鞅。' },
  { title: '扈亭西陂燕赏', author: '韦应物', poem: '杲杲朝阳时，悠悠清陂望。\n嘉树始氤氲，春游方浩荡。\n况逢文翰侣，爱此孤舟漾。\n绿野际遥波，横云分叠嶂。\n公堂日为倦，幽襟自兹旷。\n有酒今满盈，愿君尽弘量。' },
  { title: '西郊燕集', author: '韦应物', poem: '济济众君子，高宴及时光。\n群山霭遐瞩，绿野布熙阳。\n列坐遵曲岸，披襟袭兰芳。\n野庖荐嘉鱼，激涧泛羽觞。\n众鸟鸣茂林，绿草延高冈。\n盛时易徂谢，浩思坐飘飏。\n眷言同心友，兹游安可忘。' },
  { title: '春宵燕万年吉少府中孚南馆', author: '韦应物', poem: '始见斗柄廻，复兹霜月霁。\n河汉上纵横，春城夜迢递。\n宾筵接时彦，乐燕凌芳岁。\n稍爱清觞满，仰叹高文丽。\n欲去返郊扉，端为一欢滞。' },
  { title: '滁州园池燕元氏亲属', author: '韦应物', poem: '日暮游清池，疎林罗高天。\n余绿飘霜露，夕气变风烟。\n水门架危阁，竹亭列广筵。\n一展私姻礼，屡叹芳樽前。\n感往在兹会，伤离属颓年。\n明晨复云去，且愿此流连。' },
  { title: '郡楼春燕', author: '韦应物', poem: '众乐杂军鞞，高楼邀上客。\n思逐花光乱，赏余山景夕。\n为郡访雕瘵，守程难损益。\n聊假一杯欢，暂忘终日迫。' },
  { title: '南塘泛舟会元六昆季', author: '韦应物', poem: '端居倦时燠，轻舟泛廻塘。\n微风飘襟散，横吹绕林长。\n云澹水容夕，雨微荷气凉。\n一写悁勤意，宁用诉华觞。' },
  { title: '郡斋雨中与诸文士燕集', author: '韦应物', poem: '兵卫森画戟，宴寝凝清香。\n海上风雨至，逍遥池阁凉。\n烦疴近消散，嘉宾复满堂。\n自慙居处崇，未覩斯民康。\n理会是非遣，性达形迹忘。\n鲜肥属时禁，蔬果幸见尝。\n俯饮一杯酒，仰聆金玉章。\n神欢体自轻，意欲凌风翔。\n吴中盛文史，群彦今汪洋。\n方知大藩地，岂曰财赋疆。' },
  { title: '军中冬燕', author: '韦应物', poem: '沧海已云晏，皇恩犹念勤。\n式燕徧恒秩，柔远及斯人。\n兹邦实大藩，伐鼓军乐陈。\n是时冬服成，戎士气益振。\n虎竹谬朝寄，英贤降上宾。\n旋罄周旋礼，媿无海陆珍。\n庭中九剑阑，堂上歌吹新。\n光景不知晚，觥酌岂言频。\n单醪昔所感，大醵况同忻。\n顾谓军中士，仰答何由申。' },
  { title: '司空主簿琴席', author: '韦应物', poem: '烟华方散薄，蕙气犹含露。\n澹景发清琴，幽期默玄悟。\n流连白雪意，断续廻风度。\n掩抑虽已终，忡忡在幽素。' },
  { title: '与村老对饮', author: '韦应物', poem: '鬓眉雪色犹嗜酒，言辞淳朴古人风。\n乡村年少生离乱，见话先朝如梦中。' },
  { title: '城中卧疾知阎薛二子屡从邑令饮因以赠之', author: '韦应物', poem: '车马日萧萧，胡不枉我庐。\n方来从令饮，卧病独何如。\n秋风起汉臯，开户望平芜。\n即此恡音素，焉知中密疎。\n渴者不思火，寒者不求水。\n人生羁寓时，去就当如此。\n犹希心异迹，眷眷存终始。' },
  { title: '听嘉陵江水声寄深上人', author: '韦应物', poem: '凿崖泄奔湍，称古神禹迹。\n夜喧山门店，独宿不安席。\n水性自云静，石中本无声。\n如何两相激，雷转空山惊。\n贻之道门旧，了此物我情。' },
  { title: '高陵书情寄三原卢少府', author: '韦应物', poem: '直方难为进，守此微贱班。\n开卷不及顾，沈埋案牍间。\n兵凶久相践，徭赋岂得闲。\n促戚下可哀，宽政身致患。\n日夕思自退，出门望故山。\n君心傥如此，携手相与还。' },
  { title: '假中对雨呈县中僚友', author: '韦应物', poem: '却足甘为笑，闲居梦杜陵。\n残莺知夏浅，社雨报年登。\n流麦非关忘，收书独不能。\n自然忧旷职，缄此谢良朋。' },
  { title: '赠萧河南', author: '韦应物', poem: '厌剧辞京县，褒贤待诏书。\n酂侯方继业，潘令且闲居。\n霁后三川冷，秋深万木疎。\n对琴无一事，新兴复何如。' },
  { title: '示从子河南尉班', author: '韦应物', poem: '拙直余恒守，公方尔所存。\n同占朱鸟克，俱起小人言。\n立政思悬棒，谋身类触藩。\n不能林下去，祗恋府廷恩。' },
  { title: '趋府候晓呈两县僚友', author: '韦应物', poem: '趋府不遑安，中宵出户看。\n满天星尚在，近壁烛仍残。\n立马频惊曙，垂帘却避寒。\n可怜同宦者，应悟下流难。' },
  { title: '赠李儋', author: '韦应物', poem: '丝桐本异质，音响合自然。\n吾观造化意，二物相因缘。\n误触龙凤啸，静闻寒夜泉。\n心神自安宅，烦虑顿可捐。\n何因知久要，丝白漆亦坚。' },
  { title: '赠卢嵩', author: '韦应物', poem: '百川注东海，东海无虚盈。\n泥滓不能浊，澄波非益清。\n恬然自安流，日照万里晴。\n云物不隐象，三山共分明。\n奈何疾风怒，忽若砥柱倾。\n海水虽无心，洪涛亦相惊。\n怒号在倏忽，谁识变化情。' },
  { title: '寄冯着', author: '韦应物', poem: '春雷起萌蛰，土壤日已疎。\n胡能遭盛明，才俊伏里闾。\n偃仰遂真性，所求惟斗储。\n披衣出茅屋，盥漱临清渠。\n吾道亦自适，退身保玄虚。\n幸无职事牵，且览案上书。\n亲友各驰骛，谁当访敝庐。\n思君在何夕，明月照广除。' },
  { title: '早春对雪寄前殿中元侍御', author: '韦应物', poem: '扫雪开幽径，端居望故人。\n犹残腊月酒，更值早梅春。\n几日东城陌，何时曲水滨。\n闻闲且共赏，莫待绣衣新。' },
  { title: '赠王侍御', author: '韦应物', poem: '心同野鹤与尘远，诗似冰壶见底清。\n府县同趋昨日事，升沈不改故人情。\n上阳秋晚萧萧雨，洛水寒来夜夜声。\n自叹犹为折腰吏，可怜骢马路傍行。' },
  { title: '将往江淮寄李十九儋', author: '韦应物', poem: '燕燕东向来，文鹓亦西飞。\n如何不相见，羽翼有高卑。\n徘徊到河洛，华屋未及窥。\n秋风飘我行，远与淮海期。\n廻首隔烟雾，遥遥两相思。\n阳春自当返，短翮欲追随。' },
  { title: '自巩洛舟行入黄河即事寄府县僚友', author: '韦应物', poem: '夹水苍山路向东，东南山豁大河通。\n寒树依微远天外，夕阳明灭乱流中。\n孤村几岁临伊岸，一鴈初晴下朔风。\n为报洛桥游宦侣，扁舟不系与心同。' },
  { title: '寄卢庾', author: '韦应物', poem: '悠悠远离别，分此欢会难。\n如何两相近，反使心不安。\n乱发思一栉，垢衣思一浣。\n岂如望友生，对酒起长叹。\n时节异京洛，孟冬天未寒。\n广陵多车马，日夕自游盘。\n独我何耿耿，非君谁为欢。' },
  { title: '发广陵留上家兄兼寄上长沙', author: '韦应物', poem: '将违安可怀，宿恋复一方。\n家贫无旧业，薄宦各飘飏。\n执板身有属，淹时心恐惶。\n拜言不得留，声结泪满裳。\n漾漾动行舫，亭亭远相望。\n离晨苦须臾，独往道路长。\n萧条风雨过，得此海气凉。\n感秋意已违，况自结中肠。\n推道固当遣，及情岂所忘。\n何时共还归，举翼鸣春阳。' },
  { title: '初发扬子寄元大校书', author: '韦应物', poem: '凄凄去亲爱，泛泛入烟雾。\n归棹洛阳人，残钟广陵树。\n今朝此为别，何处还相遇。\n世事波上舟，沿洄安得住。' },
  { title: '淮上即事寄广陵亲故', author: '韦应物', poem: '前舟已眇眇，欲渡谁相持。\n秋山起暮钟，楚雨连沧海。\n风波离思满，宿昔容鬓改。\n独鸟下东南，广陵何处在。' },
  { title: '寄洪州幕府二十一侍御', author: '韦应物', poem: '忽报南昌令，乘骢入郡城。\n同时趋府客，此日望尘迎。\n文苑台中妙，冰壶幕下清。\n洛阳相去远，犹使故林荣。' },
  { title: '经少林精舍寄都邑亲友', author: '韦应物', poem: '息驾依松岭，高阁一攀缘。\n前瞻路已穷，既诣喜更延。\n出𪩘听万籁，入林濯幽泉。\n鸣钟生道心，暮磬空云烟。\n独往虽暂适，多累终见牵。\n方思结茅地，归息期暮年。' },
  { title: '同长源归南徐寄子西子烈有道', author: '韦应物', poem: '东洛何萧条，相思邈遐路。\n策驾复谁游，入门无与晤。\n还因送归客，达此缄中素。\n屡暌心所欢，岂得颜如故。\n所欢不可暌，严霜晨凄凄。\n如彼万里行，孤妾守空闺。\n临觞一长叹，素欲何时谐。' },
  { title: '雪中闻李儋过门不访聊以寄赠', author: '韦应物', poem: '度门能不访，冒雪屡西东。\n已想人如玉，遥怜马似骢。\n乍迷金谷路，稍变上阳宫。\n还比相思意，纷纷正满空。' },
  { title: '同德精舍养疾寄河南兵曹东厅掾', author: '韦应物', poem: '逍遥东城隅，双树寒葱蒨。\n广庭流华月，高阁凝余霰。\n杜门非养素，抱疾阻良䜩。\n孰谓无他人，思君岁云变。\n官曹亮先忝，陈躅慙俊彦。\n岂知晨与夜，相代不相见。\n缄书问所如，詶藻当芬绚。' },
  { title: '同德寺雨后寄元侍御李博士', author: '韦应物', poem: '川上风雨来，须臾满城阙。\n岧峣青莲界，萧条孤兴发。\n前山遽已净，阴霭夜来歇。\n乔木生夏凉，流云吐华月。\n严城自有限，一水非难越。\n相望曙河远，高斋坐超忽。' },
  { title: '同德阁期元侍御李博士不至各投赠二首 一', author: '韦应物', poem: '庭树忽已暗，故人那不来。\n祗因厌烦暑，永日坐霜台。' },
  { title: '同德阁期元侍御李博士不至各投赠二首 二', author: '韦应物', poem: '官荣多所系，闲居亦愆期。\n高阁犹相望，青山欲暮时。' },
  { title: '使云阳寄府曹', author: '韦应物', poem: '夙驾祗府命，冒炎不遑息。\n百里次云阳，闾阎问漂溺。\n上天屡愆气，胡不均寸泽。\n仰瞻乔树巅，见此洪流迹。\n良苗免湮没，蔓草生宿昔。\n颓墉满故墟，喜返将安宅。\n周旋涉涂潦，侧峭缘沟脉。\n仁贤忧斯民，贱子甘所役。\n公堂众君子，言笑思与觌。' },
  { title: '过扶风精舍旧居简朝宗巨川兄弟', author: '韦应物', poem: '佛刹出高树，晨光闾井中。\n年深念陈迹，迨此独忡忡。\n零落逢故老，寂寥悲草虫。\n旧宇多改构，幽篁延本丛。\n栖止事如昨，芳时去已空。\n佳人亦携手，再往今不同。\n新文聊感旧，想子意无穷。' },
  { title: '赠令狐士曹', author: '韦应物', poem: '秋檐滴滴对床寝，山路迢迢联骑行。\n到家俱及东篱菊，何事先归半日程。' },
  { title: '赠冯着', author: '韦应物', poem: '契阔仕两京，念子亦飘蓬。\n方来属追往，十载事不同。\n岁晏乃云至，微褐还未充。\n惨凄游子情，风雪自关东。\n华觞发懽颜，嘉藻播清风。\n始此盈抱恨，旷然一夕中。\n善蕴岂轻售，怀才希国工。\n谁当念素士，零落岁华空。' },
  { title: '对雨寄韩库部协', author: '韦应物', poem: '飒至池馆凉，霭然和晓雾。\n萧条集新荷，氤氲散高树。\n闲居兴方澹，默想心已屡。\n暂出仍湿衣，况君东城住。' },
  { title: '寄子西', author: '韦应物', poem: '夏景已难度，怀贤思方续。\n乔树落疎阴，微风散烦燠。\n伤离枉芳札，忻遂见心曲。\n蓝上舍已成，田家雨新足。\n托邻素多欲，残帙犹见束。\n日夕上高斋，但望东原绿。' },
  { title: '县内闲居赠温公', author: '韦应物', poem: '满郭春[风]岚已昏，鸦栖散吏掩重门。\n虽居世网常清净，夜对高僧无一言。' },
  { title: '对雪赠徐秀才', author: '韦应物', poem: '靡靡寒欲收，霭霭阴还结。\n晨起望南端，千林散春雪。\n妍光属瑶阶，乱绪陵新节。\n无为掩扉卧，独守袁生辙。' },
  { title: '西郊游宴寄赠邑僚李巽', author: '韦应物', poem: '升阳暧春物，置酒临芳席。\n高宴阙英僚，众宾寡懽怿。\n是时尚多垒，板筑兴颓壁。\n羇旅念越疆，领徒方祗役。\n如何嘉会日，当子忧勤夕。\n西郊郁已茂，春岚重如积。\n何当返徂雨，杂英纷可惜。' },
  { title: '对雨赠李主簿高秀才', author: '韦应物', poem: '逦迤曙云薄，散漫东风来。\n青山满春野，微雨洒轻埃。\n吏局劳佳士，宾筵得上才。\n终朝狎文墨，高兴共徘徊。' },
  { title: '休沐东还胄贵里示端', author: '韦应物', poem: '宦游三十载，田野久已疎。\n休沐遂兹日，一来还故墟。\n山明宿雨霁，风煖百卉舒。\n泓泓野泉洁，熠熠林光初。\n竹木稍摧翳，园场亦荒芜。\n俯惊鬓已衰，周览昔所娱。\n存没恻私怀，迁变伤里闾。\n欲言少留心，中复畏简书。\n世道良自退，荣名亦空虚。\n与子终携手，岁晏当来居。' },
  { title: '朝请后还邑寄诸友生', author: '韦应物', poem: '宰邑分甸服，夙驾朝上京。\n是时当暮春，休沐集友生。\n抗志青云表，俱践高世名。\n樽酒且欢乐，文翰亦纵横。\n良游昔所希，累䜩夜复明。\n晨露含瑶琴，夕风殒素英。\n一旦遵归路，伏轼出京城。\n谁言再念别，忽若千里行。\n闲合寡喧讼，端居结幽情。\n况兹昼方永，展转何由平。' },
  { title: '沣上西斋寄诸友', author: '韦应物', poem: '绝岸临西野，旷然尘事遥。\n清川下逦迤，茅栋上岧峣。\n玩月爱佳夕，望山属清朝。\n俯砌视归翼，开襟纳远飙。\n等陶辞小秩，效朱方负樵。\n闲游忽无累，心迹随景超。\n明世重才彦，雨露降丹霄。\n群公正云集，独予忻寂寥。' },
  { title: '独游西斋寄崔主簿', author: '韦应物', poem: '同心忽已别，昨事方成昔。\n幽径还独寻，绿苔见行迹。\n秋斋正萧散，烟水易昏夕。\n忧来结几重，非君不可释。' },
  { title: '紫阁东林居士叔缄赐松英丸捧对忻喜盖非尘侣之所当服輙献诗代启', author: '韦应物', poem: '碧涧苍松五粒稀，侵云采去露沾衣。\n夜启群僊合灵药，朝思俗侣寄将归。\n道场斋戒今初服，人事荤膻已觉非。\n一望岚峰拜还使，腰间铜印与心违。' },
  { title: '秋集罢还途中作谨献寿春公黎公', author: '韦应物', poem: '束带自衡门，奉命宰王畿。\n君侯枉高鉴，举善掩瑕疵。\n斯民本已安，工拙两无施。\n何以酬明德，岁晏不磷缁。\n时节乃来集，欣怀方载驰。\n平明大府开，一得拜光辉。\n温如春风至，肃若严霜威。\n群属所载瞻，而忘倦与饥。\n公堂燕华筵，礼罢复言辞。\n将从平门道，憩车沣水湄。\n山川降嘉岁，草木蒙润滋。\n孰云还本邑，怀恋独迟迟。' },
  { title: '闲居赠友', author: '韦应物', poem: '补吏多下迁，罢归聊自度。\n园庐既芜没，烟景空澹泊。\n闲居养疴瘵，守素甘葵藿。\n颜鬓日衰耗，冠带亦寥落。\n青苔已生路，绿筠始分箨。\n夕气下遥阴，微风动疎薄。\n草玄良见诮，杜门无请托。\n非君好事者，谁来顾寂寞。' },
  { title: '四禅精舍登览悲旧寄朝宗巨川兄弟', author: '韦应物', poem: '萧散人事忧，迢遰古原行。\n春风日已暄，百草亦复生。\n跻阁谒金像，攀云造禅扃。\n新景林际曙，杂花川上明。\n徂岁方缅邈，陈事尚纵横。\n温泉有佳气，驰道指京城。\n携手思故日，山河留恨情。\n存者邈难见，去者已冥冥。\n临风一长恸，谁畏行路惊。' },
  { title: '善福阁对雨寄李儋幼遐', author: '韦应物', poem: '飞阁凌太虚，晨跻郁峥嵘。\n惊飙触悬槛，白云冒层甍。\n太阴布其地，密雨垂八纮。\n仰观固不测，俯视但冥冥。\n感此穷秋气，沈郁命友生。\n及时未高步，羇旅游帝京。\n圣朝无隐才，品物俱昭形。\n国士秉绳墨，何以表坚贞。\n寸心东北驰，思与一会幷。\n我车夙已驾，将逐晨风征。\n郊涂住成淹，默默阻中情。' },
  { title: '寺居独夜寄崔主簿', author: '韦应物', poem: '幽人寂不寐，木叶纷纷落。\n寒雨暗深更，流萤度高阁。\n坐使青灯晓，还伤夏衣薄。\n宁知岁方晏，离居更萧索。' },
  { title: '九日沣上作寄崔主簿倬二李端击', author: '韦应物', poem: '凄凄感时节，望望临沣涘。\n翠岭明华秋，高天澄遥滓。\n川寒流愈迅，霜交物初委。\n林叶索已空，晨禽迎飙起。\n时菊乃盈泛，浊醪自为美。\n良游虽可娱，殷念在之子。\n人生不自省，营欲无终已。\n孰能同一酌，陶然冥斯理。' },
  { title: '西郊养疾闻畅校书有新什见赠久伫不至先寄此诗', author: '韦应物', poem: '养病惬清夏，郊园敷卉木。\n牕夕含涧凉，雨余爱筠绿。\n披怀始高咏，对琴转幽独。\n仰子游群英，吐词如兰馥。\n还闻枉嘉藻，伫望延昏旭。\n唯见草青青，闭户沣水曲。' },
  { title: '沣上寄幼遐', author: '韦应物', poem: '寂寞到城阙，惆怅返柴荆。\n端居无所为，念子远徂征。\n夏昼人已息，我怀独未宁。\n忽从东斋起，兀兀寻涧行。\n罥罣丛榛密，披玩孤花明。\n旷然西南望，一极山水情。\n周览同游处，逾恨阻音形。\n壮图非旦夕，君子勤令名。\n勿复久留燕，蹉跎在北京。' },
  { title: '善福精舍示诸生', author: '韦应物', poem: '湛湛嘉树阴，清露夜景沈。\n悄然群物寂，高阁似阴岑。\n方以玄默处，岂为名迹侵。\n法妙不知归，独此抱冲襟。\n斋舍无余物，陶器与单衾。\n诸生时列坐，共爱风满林。' },
  { title: '晚出沣上赠崔都水', author: '韦应物', poem: '临流一舒啸，望山意转延。\n隔林分落景，余霞明远川。\n首起趣东作，已看耘夏田。\n一从民里居，岁月再徂迁。\n昧质得全性，世名良自牵。\n行忻携手归，聊复饮酒眠。' },
  { title: '寓居沣上精舍于张二舍人', author: '韦应物', poem: '万木丛云出香阁，西连碧涧竹林园。\n高斋犹宿远山曙，微霰下庭寒雀喧。\n道心淡泊对流水，生事萧疎空掩门。\n时忆故交那得见，晓排阊阖奉明恩。' },
  { title: '开元观怀旧寄李二韩二裴四兼呈崔郎中严家令', author: '韦应物', poem: '宿昔清都燕，分散各西东。\n车马行迹在，霜雪竹林空。\n方轸故五念，谁复一樽同。\n聊披道书暇，还此听松风。' },
  { title: '春日郊居寄万年吉少府中孚三原少府伟夏侯校书审', author: '韦应物', poem: '谷鸟时一啭，田园春雨余。\n光风动林早，高牕照日初。\n独饮涧中水，吟咏老氏书。\n城阙应多事，谁忆此闲居。' },
  { title: '沣上醉题寄涤武', author: '韦应物', poem: '芳园知夕燕，西郊已独还。\n谁言不同赏，俱是醉花间。' },
  { title: '西郊期涤武不至书示', author: '韦应物', poem: '山高鸣过雨，涧树落残花。\n非关春不待，当由期自赊。' },
  { title: '沣上对月寄孔谏议', author: '韦应物', poem: '思怀在云阙，泊素守中林。\n出处虽殊迹，明月两知心。' },
  { title: '将往滁城恋新竹简崔都水示端', author: '韦应物', poem: '停车欲去绕丛竹，偏爱新筠十数竿。\n莫遣儿童触琼粉，留待幽人廻日看。' },
  { title: '还阙首途寄精舍亲友', author: '韦应物', poem: '休沐日云满，冲然将罢观。\n严车候门侧，晨起正朝冠。\n山泽含余雨，川涧注惊湍。\n揽辔遵东路，廻首一长叹。\n居人已不见，高阁在林端。' },
  { title: '秋夜南宫寄沣上弟及诸生', author: '韦应物', poem: '暝色起烟阁，沈抱积离忧。\n况兹风雨夜，萧条梧叶秋。\n空宇感凉至，颓颜惊岁周。\n日夕游阙下，山水忆同游。' },
  { title: '途中书情寄沣上两弟因送二甥却还', author: '韦应物', poem: '华簪岂足恋，幽林徒自违。\n遥知别后意，寂寞掩郊扉。\n廻首昆池上，更羡尔同归。' },
  { title: '雪夜下朝呈省中一绝', author: '韦应物', poem: '南望青山满禁闱，晓陪鸳鹭正差池。\n共爱朝来何处雪，蓬莱宫里拂松枝。' },
  { title: '寄柳州韩司户郎中', author: '韦应物', poem: '达识与昧机，智殊迹同静。\n于焉得携手，屡赏清夜景。\n潇洒陪高咏，从容羡华省。\n一逐风波迁，南登桂阳岭。\n旧里门空掩，欢游事皆屏。\n怅望城阙遥，幽居时序永。\n春风吹百卉，和煦变闾井。\n独闷终日眠，篇书不复省。\n唯当望雨露，沾子荒遐境。' },
  { title: '寄令狐侍郎', author: '韦应物', poem: '三山有琼树，霜雪色逾新。\n始自风尘交，中结绸缪姻。\n西掖方掌诰，南宫复司春。\n夕燕华池月，朝奉玉阶尘。\n众宝归和氏，吹嘘多俊人。\n群公共然诺，声问迈时伦。\n孤鸿既高举，燕雀在荆榛。\n翔集且不同，岂不欲殷勤。\n一旦迁南郡，江湖渺无垠。\n宠辱良未定，君子岂缁磷。\n寒暑已推斥，别离生苦辛。\n非将会面目，书札何由申。' },
  { title: '闲居寄端及重阳', author: '韦应物', poem: '山明野寺曙钟微，雪满幽林人迹稀。\n闲居寥落生高兴，无事风尘独不归。' },
  { title: '园林晏起寄昭应韩明府卢主簿', author: '韦应物', poem: '田家已耕作，井屋起晨烟。\n园林鸣好鸟，闲居犹独眠。\n不觉朝已晏，起来望青天。\n四体一舒散，情性亦忻然。\n还复茅檐下，对酒思数贤。\n束带理官府，简牍盈目前。\n当念中林赏，览物遍山川。\n上非遇明世，庶以道自全。' },
  { title: '寄大梁诸友', author: '韦应物', poem: '分竹守南谯，弭节过梁池。\n雄都众君子，出饯拥河湄。\n燕谑始云洽，方舟已解维。\n一为风水便，但见山川驰。\n昨日次睢阳，今夕宿符离。\n云树怆重叠，烟波念还期。\n相敦在勤事，海内方劳师。' },
  { title: '新秋夜寄诸弟', author: '韦应物', poem: '两地俱秋夕，相望共星河。\n高梧一叶下，空斋归思多。\n方用忧人瘼，况自抱微疴。\n无将别来近，颜鬓已蹉跎。' },
  { title: '郊园闻蝉寄诸弟', author: '韦应物', poem: '去岁郊园别，闻蝉在兰省。\n今岁卧南谯，蝉鸣归路永。\n夕响依山谷，余悲散秋景。\n缄书报此时，此心方耿耿。' },
  { title: '寄中书刘舍人', author: '韦应物', poem: '云霄路竟别，中年迹暂同。\n比翼趋丹陛，连骑下南宫。\n佳咏邀清月，幽赏滞芳藂。\n迨予一出守，与子限西东。\n晨露方怆怆，离抱更忡忡。\n忽睹九天诏，秉纶归国工。\n玉座浮香气，秋禁散凉风。\n应向横门度，环珮杳玲珑。\n光辉恨未瞩，归思坐难通。\n苍苍松桂姿，想在掖垣中。' },
  { title: '郡斋感秋寄诸弟', author: '韦应物', poem: '首夏辞旧国，穷秋卧滁城。\n方如昨日别，忽觉徂岁惊。\n高阁收烟雾，池水晚澄清。\n户牖已凄爽，晨夜感深情。\n昔游郎署间，是月天气晴。\n授衣还西郊，晓露田中行。\n采菊投酒中，昆弟自同倾。\n簪组聊挂壁，焉知有世荣。\n一旦居远郡，山川间音形。\n大道庶无累，及兹念已盈。' },
  { title: '郡中对雨赠元锡兼简杨凌', author: '韦应物', poem: '宿雨冒空山，空城响秋叶。\n沈沈暮色至，凄凄凉气入。\n萧条林表散，的砾荷上集。\n夜雾着衣重，新苔侵履湿。\n遇兹端忧日，赖与嘉宾接。' },
  { title: '冬至夜寄京师诸弟兼怀崔都水', author: '韦应物', poem: '理郡无异政，所忧在素飡。\n徒令去京国，羁旅当岁寒。\n子月生一气，阳景极南端。\n已怀时节感，更抱别离酸。\n私燕席云罢，还斋夜方阑。\n邃幕沈空宇，孤灯照床单。\n应同兹夕念，宁忘故岁欢。\n川途恍悠邈，涕下一阑干。' },
  { title: '元日寄诸弟兼呈崔都水', author: '韦应物', poem: '一从守兹郡，两鬓生素发。\n新正加我年，故岁去超忽。\n淮滨益时候，了似仲秋月。\n川谷风景温，城池草木发。\n高斋属多暇，惆怅临芳物。\n日月昧还期，念君何时歇。' },
  { title: '寄职方刘郎中', author: '韦应物', poem: '相闻二十载，不得展平生。\n一夕南宫遇，聊用写中情。\n端服光朝次，群烈慕英声。\n归来坐粉闱，挥笔乃纵横。\n始陪文翰游，欢燕难久幷。\n予因谬忝出，君为沈疾婴。\n别离寒暑过，荏苒春草生。\n故园兹日隔，新禽池上鸣。\n郡中永无事，归思徒自盈。' },
  { title: '社日寄崔都水及诸弟群属', author: '韦应物', poem: '山郡多暇日，社时放吏归。\n坐阁独成闷，行塘阅清辉。\n春风动高柳，芳园掩夕扉。\n遥思里中会，心绪怅微微。' },
  { title: '寒食日寄诸弟', author: '韦应物', poem: '禁火暧佳辰，念离独伤抱。\n见此野田花，心思杜陵道。\n联骑定何时，予今颜已老。' },
  { title: '三月三日寄诸弟兼怀崔都水', author: '韦应物', poem: '暮节看已谢，兹晨愈可惜。\n风澹意伤春，池寒花敛夕。\n对酒始依依，怀人还的的。\n谁当曲水行，相思寻旧迹。' },
  { title: '赠李儋侍御', author: '韦应物', poem: '风光山郡少，来看广陵春。\n残花犹待客，莫问意中人。' },
  { title: '寄杨协律', author: '韦应物', poem: '吏散门阁掩，鸟鸣山郡中。\n远念长江别，俯觉座隅空。\n舟泊南池雨，簟卷北楼风。\n并罢芳樽燕，为怆昨时同。' },
  { title: '郡斋赠王卿', author: '韦应物', poem: '无术谬称简，素餐空自嗟。\n秋斋雨成滞，山药寒始华。\n濩落人皆笑，幽独岁逾赊。\n唯君出尘意，赏爱似山家。' },
  { title: '简恒璨', author: '韦应物', poem: '室虚多凉气，天高属秋时。\n空庭夜风雨，草木晓离披。\n简书日云旷，文墨谁复持。\n聊因遇澄静，一与道人期。' },
  { title: '闲居寄诸弟', author: '韦应物', poem: '秋艸生庭白露时，故园诸弟益相思。\n尽日高斋无一事，芭蕉叶上独题诗。' },
  { title: '登楼寄王卿', author: '韦应物', poem: '踏阁攀林恨不同，楚云沧海思无穷。\n数家砧杵秋山下，一郡荆榛寒雨中。' },
  { title: '寄畅当', author: '韦应物', poem: '寇贼起东山，英俊方未闲。\n闻君新应募，籍籍动京关。\n出身文翰场，高步不可攀。\n青袍未及解，白羽插腰间。\n昔为琼树枝，今有风霜颜。\n秋郊细柳道，走马一夕还。\n丈夫当为国，破敌如摧山。\n何必事州府，坐使鬓毛斑。' },
  { title: '赠崔员外', author: '韦应物', poem: '一别十年事，相逢淮海滨。\n还思洛阳日，更话府中人。\n且对清觞满，宁知白发新。\n怱怱何处去，车马冒风尘。' },
  { title: '寄李儋元锡', author: '韦应物', poem: '去年花里逢君别，今日花开已一年。\n世事茫茫难自料，春愁黯黯独成眠。\n身多疾病思田里，邑有流亡愧俸钱。\n闻道欲来相问讯，西楼望月几廻圆。' },
  { title: '京师叛乱寄诸弟', author: '韦应物', poem: '弱冠遭世难，二纪犹未平。\n羇离官远郡，虎豹满西京。\n上怀犬马恋，下有骨肉情。\n归去在何时，流泪忽沾缨。\n忧来上北楼，左右但军营。\n函谷行人绝，淮南春草生。\n鸟鸣野田间，思忆故园行。\n何当四海晏，甘与齐民耕。' },
  { title: '赠琮公', author: '韦应物', poem: '山僧一相访，吏案正盈前。\n出处似殊致，喧静两皆禅。\n暮春华池宴，清夜高斋眠。\n此道本无得，宁复有忘筌。' },
  { title: '寄诸弟', author: '韦应物', poem: '岁暮兵戈乱京国，帛书间道访存亡。\n还信忽从天上落，唯知彼此泪千行。' },
  { title: '寄恒璨', author: '韦应物', poem: '心绝去来缘，迹顺人间事。\n独寻秋草径，夜宿寒山寺。\n今日郡斋闲，思问楞伽字。' },
  { title: '简郡中诸生', author: '韦应物', poem: '守郡卧秋阁，四面尽荒山。\n此时听夜雨，孤灯照窗间。\n药园日芜没，书帷长自闲。\n惟当上客至，论诗一解颜。' },
  { title: '寄全椒山中道士', author: '韦应物', poem: '今朝郡斋冷，忽念山中客。\n涧底束荆薪，归来煮白石。\n欲持一瓢酒，远慰风雨夕。\n落叶满空山，何处寻行迹。' },
  { title: '寄释子良史酒', author: '韦应物', poem: '秋山僧冷病，聊寄三五杯。\n应泻山瓢里，还寄此瓢来。' },
  { title: '重寄', author: '韦应物', poem: '复寄满瓢去，定见空瓢来。\n若不打瓢破，终当费酒材。' },
  { title: '答释子良史送酒瓢', author: '韦应物', poem: '此瓢今已到，山瓢知已空。\n且饮寒塘水，遥将回也同。' },
  { title: '简陟巡建三甥', author: '韦应物', poem: '忽羡后生连榻话，独依寒烛一斋空。\n时流欢笑事从别，把酒吟诗待尔同。' },
  { title: '览襃子卧病一绝聊以题示', author: '韦应物', poem: '念子抱沈疾，霜露变滁城。\n独此高窗下，自然无世情。' },
  { title: '寄璨师', author: '韦应物', poem: '林院生夜色，西廊上纱灯。\n时忆长松下，独坐一山僧。' },
  { title: '寄卢陟', author: '韦应物', poem: '柳叶遍寒塘，晓霜凝高阁。\n累日此流连，别来成寂寞。' },
  { title: '途中寄杨邈裴绪示襃子', author: '韦应物', poem: '上宰领淮右，下国属星驰。\n雾野腾晓骑，霜竿裂冻旗。\n萧萧陟连冈，莽莽望空陂。\n风截鴈嘹泪，云惨树参差。\n高斋明月夜，中庭松桂姿。\n当暌一酌恨，况此两旬期。' },
  { title: '宿永阳寄璨律师', author: '韦应物', poem: '遥知郡斋夜，冻雪封松竹。\n时有山僧来，悬灯独自宿。' },
  { title: '雪行寄襃子', author: '韦应物', poem: '淅沥覆寒骑，飘飖暗川容。\n行子郡城晓，披云看杉松。' },
  { title: '寄裴处士', author: '韦应物', poem: '春风驻游骑，晚景澹山晖。\n一问清泠子，独掩荒园扉。\n草木雨来长，里闾人到稀。\n方从广陵宴，花落未言归。' },
  { title: '偶入西斋院示释子恒璨', author: '韦应物', poem: '僧斋地虽密，忘子迹要赊。\n一来非问讯，自是看山花。' },
  { title: '示全真元常', author: '韦应物', poem: '余辞郡符去，尔为外事牵。\n宁知风雪夜，复此对床眠。\n始话南池饮，更咏西楼篇。\n无将一会易，岁月坐推迁。' },
  { title: '寄刘尊师', author: '韦应物', poem: '世间荏苒萦此身，长望碧山到无因。\n白鹤徘徊看不去，遥知下有清都人。' },
  { title: '寄庐山椶衣居士', author: '韦应物', poem: '兀兀山行无处归，山中猛虎识椶衣。\n俗客欲寻应不遇，云溪道士见犹稀。' },
  { title: '因省风俗与从姪成绪游山水中道先归寄示', author: '韦应物', poem: '累宵同燕酌，十舍携征骑。\n始造双林寂，遐搜洞府秘。\n群峰绕盘郁，悬泉仰特异。\n阴壑云松埋，阳崖烟花媚。\n每虑观省牵，中乖游践志。\n我尚山水行，子归栖息地。\n一操临流袂，上耸干云辔。\n独往倦危途，怀冲寡幽致。\n赖尔还都期，方将登楼迟。' },
  { title: '寒食寄京师诸弟', author: '韦应物', poem: '雨中禁火空斋冷，江上流莺独坐听。\n把酒看花想诸弟，杜陵寒食草青青。' },
  { title: '岁日寄京师诸[季]端武等', author: '韦应物', poem: '献岁抱深恻，侨居念归缘。\n常患亲爱离，始觉世务牵。\n少事河阳府，晚守淮南壖。\n平生几会散，已及蹉跎年。\n昨日罢符竹，家贫遂留连。\n部曲多已去，车马不复全。\n闲将酒为偶，默以道自诠。\n听松南岩寺，见月西涧泉。\n为政无异术，当责岂望迁。\n终理来时装，归凿杜陵田。' },
  { title: '简卢陟', author: '韦应物', poem: '可怜白雪曲，未遇知音人。\n恓惶戎旅下，蹉跎淮海滨。\n涧树含朝雨，山鸟哢余春。\n我有一瓢酒，可以慰风尘。' },
  { title: '西涧即事示卢陟', author: '韦应物', poem: '寝扉临碧涧，晨起澹忘情。\n空林细雨至，圆文遍水生。\n永日无余事，山中伐木声。\n知子尘喧久，暂可散烦缨。' },
  { title: '登郡寄京师诸季淮南子弟', author: '韦应物', poem: '始罢永阳守，复卧浔阳楼。\n悬槛飘寒雨，危堞侵江流。\n迨兹闻雁夜，重忆别离秋。\n徒有盈樽酒，镇此百端忧。' },
  { title: '寄黄尊师', author: '韦应物', poem: '结茅种杏在云端，扫雪焚香宿石坛。\n灵祇不许世人到，忽作雷风登岭难。' },
  { title: '寄黄刘二尊师', author: '韦应物', poem: '庐山两道士，各在一峰居。\n矫掌白云表，晞发阳和初。\n清夜降真侣，焚香满空虚。\n中有无为乐，自然与世疎。\n道尊不可屈，符守岂暇余。\n高斋遥致敬，愿示一编书。' },
  { title: '秋夜寄丘二十二员外', author: '韦应物', poem: '怀君属秋夜，散步咏凉天。\n山空松子落，幽人应未眠。' },
  { title: '赠丘员外二首 一', author: '韦应物', poem: '高词弃浮靡，贞行表乡闾。\n未真南宫拜，聊偃东山居。\n大藩本多事，日与文章疎。\n每一覩之子，高咏遂起予。\n宵昼方连燕，烦恡亦顿祛。\n格言雅诲阙，善谑矜数余。\n久跼思游旷，穷惨遇阳舒。\n虎丘惬登眺，吴门怅踌躇。\n方此恋携手，岂云还旧墟。\n告诸吴子弟，文学为何如。' },
  { title: '赠丘员外二首 二', author: '韦应物', poem: '迹与孤云远，心将野鹤俱。\n那同石氏子，每到府门趋。' },
  { title: '赠李判官', author: '韦应物', poem: '良玉定为宝，长材世所稀。\n佐幕方巡郡，奏命布恩威。\n食蔬程独守，饮冰节靡违。\n决狱兴邦颂，高文禀天机。\n宾馆在林表，望山启西扉。\n下有千亩田，泱漭吴土肥。\n始耕已见获，袗𫄨今授衣。\n政拙劳详省，淹留未得归。\n虽慙且忻愿，日夕覩光辉。' },
  { title: '寄皎然上人', author: '韦应物', poem: '吴兴老释子，野雪盖精庐。\n诗名徒自振，道心长晏如。\n想兹栖禅夜，见月东峰初。\n鸣钟惊岩壑，焚香满空虚。\n叨慕端成旧，未识岂为疎。\n愿以碧云思，方君怨别余。\n茂苑文华地，流水古僧居。\n何当一游咏，倚阁吟踌躇。' },
  { title: '赠旧识', author: '韦应物', poem: '少年游太学，负气蔑诸生。\n蹉跎三十载，今日海隅行。' },
  { title: '复理西斋寄丘员外', author: '韦应物', poem: '前岁理西斋，得与君子同。\n迨兹已一周，怅望临春风。\n始自疎林竹，还复长榛丛。\n端正良难久，芜秽易为功。\n援斧开众郁，如师启群蒙。\n庭宇还清旷，烦抱亦舒通。\n海隅雨雪霁，春序风景融。\n时物方如故，怀贤思无穷。' },
  { title: '和张舍人夜直中书寄吏部刘员外', author: '韦应物', poem: '西垣草诏罢，南宫忆上才。\n月临兰殿出，凉自凤池来。\n松桂生丹禁，鸳鹭集云台。\n托身各有所，相望徒徘徊。' },
  { title: '和李二主簿寄淮上綦毋三', author: '韦应物', poem: '满城怜傲吏，终日赋新诗。\n请报淮阴客，春帆浪作期。' },
  { title: '寄二严', author: '韦应物', poem: '丝竹久已懒，今日遇君忺。\n打破蜘蛛千道网，总为鹡鸰两个严。' },
  { title: '李五席送李主簿归西台', author: '韦应物', poem: '请告严程尽，西归道路寒。\n欲陪鹰隼集，犹恋鹡鸰单。\n洛邑人全少，嵩高雪尚残。\n满台谁不故，报我在微官。' },
  { title: '送崔押衙相州', author: '韦应物', poem: '礼乐儒家子，英豪燕赵风。\n驱鸡尝理邑，走马却从戎。\n白刃千夫辟，黄金四海同。\n嫖姚恩顾下，诸将指挥中。\n别路怜芳草，归心伴塞鸿。\n邺城新骑满，魏帝旧台空。\n望阙应怀恋，遭时贵立功。\n万方如已静，何处欲输忠。' },
  { title: '送宣城路录事', author: '韦应物', poem: '江上宣城郡，孤舟远到时。\n云林谢家宅，山水敬亭祠。\n纲纪多闲日，观游得赋诗。\n都门且尽醉，此别数年期。' },
  { title: '送李十四山东游', author: '韦应物', poem: '圣朝有遗逸，披胆谒至尊。\n岂是贸荣宠，誓将救元元。\n权豪非所便，书奏寝禁门。\n高歌长安酒，忠愤不可吞。\n欻来客河洛，日与静者论。\n济世飜小事，丹砂驻精魂。\n东游无复系，梁楚多大蕃。\n高论动侯伯，疎怀脱尘喧。\n送君都门野，饮我林中樽。\n立马望东道，白云满梁园。\n踟蹰欲何赠，空是平生言。' },
  { title: '送李二归楚州', author: '韦应物', poem: '情人南楚别，复咏在原诗。\n忽此嗟歧路，还令泣素丝。\n风波朝夕远，音信往来迟。\n好去扁舟客，青云何处期。' },
  { title: '送阎采赴东川辟', author: '韦应物', poem: '冰炭俱可怀，孰云热与寒。\n何如结发友，不得携手懽。\n晨登严霜野，送子天一端。\n祗承简书命，俯仰豸角冠。\n上陟白云峤，下冥玄壑湍。\n离群自有托，历险得所安。\n当念反穷巷，登朝成慨叹。' },
  { title: '送令狐岫宰恩阳', author: '韦应物', poem: '大雪天地闭，群山夜来晴。\n居家犹苦寒，子有千里行。\n行行安得辞，荷此蒲璧荣。\n贤豪争追攀，饮饯出西京。\n樽酒岂不欢，暮春自有程。\n离人起视日，仆御促前征。\n逶迟岁已穷，当造巴子城。\n和风被草木，江水日夜清。\n从来知善政，离别慰友生。' },
  { title: '送冯着受李广州署为录事', author: '韦应物', poem: '郁郁杨柳枝，萧萧征马悲。\n送君灞陵岸，纠郡南海湄。\n名在翰墨场，群公正追随。\n如何从此去，千里万里期。\n大海吞东南，横岭隔地维。\n建邦临日域，温燠御四时。\n百国共臻奏，珍奇献京师。\n富豪虞兴戎，绳墨不易持。\n州伯荷天宠，还当翊丹墀。\n子为门下生，终始岂见遗。\n所愿酌贪泉，心不为磷缁。\n上将玩国士，下以报渴饥。' },
  { title: '送元仓曹归广陵', author: '韦应物', poem: '官闲得去住，告别恋音徽。\n旧国应无业，他乡到是归。\n楚山明月满，淮甸夜钟微。\n何处孤舟泊，遥遥心曲违。' },
  { title: '送唐明府赴溧水', author: '韦应物', poem: '三为百里宰，已过十余年。\n祗叹官如旧，旋闻邑屡迁。\n鱼盐滨海利，姜蔗傍湖田。\n到此安甿俗，琴堂又晏然。' },
  { title: '喜于广陵拜觐家兄奉送发还池州', author: '韦应物', poem: '青青连枝树，苒苒久别离。\n客游广陵中，俱到若有期。\n俯仰叙存殁，哀肠发酸悲。\n收情且为欢，累日不知饥。\n夙驾多所迫，复当还归池。\n长安三千里，岁晏独何为。\n南出登阊门，惊飙左右吹。\n所别谅非远，要令心不怡。' },
  { title: '送章八元秀才擢第往上都应制', author: '韦应物', poem: '决胜文场战已酣，行应辟命复才堪。\n旅食不辞游阙下，春衣未换报江南。\n天边宿鸟生归思，关外晴山满夕岚。\n立马欲从何处别，都门杨柳正毵毵。' },
  { title: '送张侍御秘书江左觐省', author: '韦应物', poem: '莫叹都门路，归无驷马车。\n绣衣犹在箧，芸阁已观书。\n沃野收红稻，长江钓白鱼。\n晨飡亦可荐，名利欲何如。' },
  { title: '赋得鼎门送卢耿赴任', author: '韦应物', poem: '名因定鼎地，门对凿龙山。\n水北楼台近，城南车马还。\n稍开芳野静，欲掩暮钟闲。\n去此无嗟屈，前贤尚抱关。' },
  { title: '赋得浮云起离色送郑述诚', author: '韦应物', poem: '游子欲言去，浮云那得知。\n偏能见行色，自是独伤离。\n晚带城遥暗，秋生峰尚奇。\n还因朔吹断，匹马与相随。' },
  { title: '饯雍聿之潞州谒李中丞', author: '韦应物', poem: '郁郁雨相遇，出门草青青。\n酒酣拔劒舞，慷慨送子行。\n驱马涉大河，日暮怀洛京。\n前登太行路，志士亦未平。\n薄游五府都，高步振英声。\n主人才且贤，重士百金轻。\n丝竹促飞觞，夜醼达晨星。\n娱乐易淹暮，谅在执高情。' },
  { title: '上东门会送李幼举南游徐方', author: '韦应物', poem: '离弦既罢弹，罇酒亦已阑。\n听我歌一曲，南徐在云端。\n云端虽云邈，行路本非难。\n诸侯皆爱才，公子远结欢。\n济济都门宴，将去复盘桓。\n令姿何昂昂，良马远游冠。\n意气且为别，由来非所叹。' },
  { title: '送洛阳韩丞东游', author: '韦应物', poem: '仙鸟何飘飖，绿衣翠为襟。\n顾我差池羽，咬咬怀好音。\n徘徊洛阳中，游戏清川浔。\n神交不在结，欢爱自中心。\n驾言忽徂征，云路邈且深。\n朝游尚同啄，夕息当异林。\n出饯宿东郊，列筵属城阴。\n举酒欲为乐，忧怀方沈沈。' },
  { title: '送郑长源', author: '韦应物', poem: '少年一相见，飞辔河洛间。\n欢游不知罢，中路忽言还。\n泠泠鹍弦哀，悄悄冬夜闲。\n丈夫虽耿介，远别多苦颜。\n君行拜高堂，速驾难久攀。\n鸡鸣俦侣发，朔雪满河关。\n须臾在今夕，罇酌且循环。' },
  { title: '送李儋', author: '韦应物', poem: '别离何从生，乃在亲爱中。\n反念行路子，拂衣自西东。\n日昃不留宴，严车出崇墉。\n行游非所乐，端忧道未通。\n春野百卉发，清川思无穷。\n芳时坐离散，世事谁可同。\n归当掩重关，默默想音容。' },
  { title: '赋得暮雨送李胄', author: '韦应物', poem: '楚江微雨里，建业暮钟时。\n漠漠帆来重，冥冥鸟去迟。\n海门深不见，浦树远含滋。\n相送情无限，沾襟比散丝。' },
  { title: '留别洛京亲友', author: '韦应物', poem: '握手出都门，驾言适京师。\n岂不怀旧庐，惆怅与子辞。\n丽日坐高阁，清觞醼华池。\n昨游倏已过，后遇良未知。\n念结路方永，岁阴野无晖。\n单车我当前，暮雪子独归。\n临流一相望，零泪忽沾衣。' },
  { title: '赋得沙际路送从叔象', author: '韦应物', poem: '独树沙边人迹稀，欲行愁远暮钟时。\n野泉几处侵应尽，不过山僧知问谁。' },
  { title: '送榆次林明府', author: '韦应物', poem: '无嗟千里远，亦是宰王畿。\n策马雨中去，逢人关外稀。\n邑传榆石在，路遶晋山微。\n别思方萧索，新秋一叶飞。' },
  { title: '杂言送黎六郎', author: '韦应物', poem: '冰壶见底未见清，少年如玉有诗名。\n闻话嵩峰多野寺，不嫌黄绶向阳城。\n朱门严训朝辞去，骑出东郊满飞絮。\n河南庭下拜府君，阳城归路山氛氲。\n山氛氲，长不见，钓台水渌荷已生，少姨庙寒花始徧。\n县闲吏傲与尘隔，移竹疏泉常岸帻。\n莫言去作折腰官，岂似长安折腰客。' },
  { title: '天长寺上方别子西有道', author: '韦应物', poem: '假邑非拙素，况乃别伊人。\n聊登释氏居，携手恋兹晨。\n高旷出尘表，逍遥涤心神。\n青山对芳苑，列树遶通津。\n车马无时绝，行子倦风尘。\n今当遵往路，伫立欲何申。\n唯持贞白志，以慰心所亲。' },
  { title: '送黎六郎赴阳翟少府', author: '韦应物', poem: '试吏向嵩阳，春山踯躅芳。\n腰垂新绶色，衣满旧芸香。\n乔树别时绿，客程关外长。\n祗应传善政，日夕慰高堂。' },
  { title: '送别覃孝廉', author: '韦应物', poem: '思亲自当去，不第未蹉跎。\n家住青山下，门前芳草多。\n秭归通远徼，巫峡注惊波。\n州举年年事，还期复几何。' },
  { title: '送开封卢少府', author: '韦应物', poem: '雄藩车马地，作尉有光辉。\n满席宾常侍，阗街烛夜归。\n关河征斾远，烟树夕阳微。\n到处无留滞，梁园花欲稀。' },
  { title: '送槐广落第归扬州', author: '韦应物', poem: '下第常称屈，少年心独轻。\n拜亲归海畔，似舅得诗名。\n晚对青山别，遥寻芳草行。\n还期应不远，寒露湿芜城。' },
  { title: '送汾城王主簿', author: '韦应物', poem: '少年初带印，汾上又经过。\n芳草归时徧，情人故郡多。\n禁钟春雨细，宫树野烟和。\n相望东桥别，微风起夕波。' },
  { title: '送渑池崔主簿', author: '韦应物', poem: '邑带洛阳道，年年应此行。\n当时匹马客，今日县人迎。\n暮雨投关郡，春风别帝城。\n东西殊不远，朝夕待佳声。' },
  { title: '送颜司议使蜀访图书', author: '韦应物', poem: '轺驾一封急，蜀门千岭曛。\n讵分江转字，但见路缘云。\n山馆夜听雨，秋猿独呌群。\n无为久留滞，圣主待遗文。' },
  { title: '奉送从兄宰晋陵', author: '韦应物', poem: '东郊暮草歇，千里夏云生。\n立马愁将夕，看山独送行。\n依微吴苑树，迢递晋陵城。\n慰此断行别，邑人多颂声。' },
  { title: '赠别河南李功曹', author: '韦应物', poem: '耿耿抱私戚，寥寥独掩扉。\n临觞自不饮，况与故人违。\n故人方琢磨，瓌朗代所稀。\n宪礼更右职，文翰洒天机。\n聿来自东山，群彦仰余辉。\n谈笑取高第，绾绶即言归。\n洛都游燕地，千里及芳菲。\n今朝章台别，杨柳亦依依。\n云霞未改色，山川犹夕晖。\n忽复不相见，心思乱霏霏。' },
  { title: '送五经赵随登科授广德尉', author: '韦应物', poem: '明经有清秩，当在石渠中。\n独往宣城郡，高斋谒谢公。\n寒原正芜漫，夕鸟自西东。\n秋日不堪别，凄凄多朔风。' },
  { title: '宴别幼遐与君贶兄弟', author: '韦应物', poem: '乖阙意方弭，安知忽来翔。\n累日重欢宴，一旦复离伤。\n置酒慰兹夕，秉烛坐华堂。\n契阔未及展，晨星出东方。\n征人惨已辞，车马俨成装。\n我怀自无欢，原野满春光。\n群水含时泽，野雉鸣朝阳。\n平生有壮志，不觉泪沾裳。\n况自守空宇，日夕但徬徨。' },
  { title: '送宣州周录事', author: '韦应物', poem: '清时重儒士，纠郡属伊人。\n薄游长安中，始得一交亲。\n英豪若云集，饯别塞城𬮱。\n高驾临长路，日夕起风尘。\n方念清宵宴，已度芳林春。\n从兹一分手，缅邈吴与秦。\n但覩年运驶，安知后会因。\n唯当存令德，可以解悁勤。' },
  { title: '谢栎阳令归西郊赠别诸友生', author: '韦应物', poem: '结发仕州县，蹉跎在文墨。\n徒有排云心，何由生羽翼。\n幸遭明盛日，万物蒙生植。\n独此抱微疴，颓然谢斯职。\n世道方荏苒，郊园思偃息。\n为欢日已延，君子情未极。\n驰觞忽云晏，高论良难测。\n游步清都宫，迎风嘉树侧。\n晨起西郊道，原野分黍稷。\n自乐陶唐人，服勤在微力。\n伫君列丹陛，出处两为得。' },
  { title: '送端东行', author: '韦应物', poem: '世承清白遗，躬服古人言。\n从官俱守道，归来共闭门。\n驱车何处去，暮雪满平原。' },
  { title: '送姚孙还河中', author: '韦应物', poem: '上国旅游罢，故园生事微。\n风尘满路起，行人何处归。\n留思芳树饮，惜别暮春晖。\n几日投关郡，河山对掩扉。' },
  { title: '始除尚书郎别善福精舍', author: '韦应物', poem: '简略非世器，委身同草木。\n逍遥精舍居，饮酒自为足。\n累日曾一栉，对书常懒读。\n社腊会高年，山川恣游瞩。\n明世方选士，中朝悬美禄。\n除书忽到门，冠带便拘束。\n愧忝郎署迹，谬蒙君子录。\n俯仰垂华缨，飘飖翔轻毂。\n行将亲爱别，恋此西涧曲。\n远峰明夕川，夏雨生众绿。\n迅风飘野路，廻首不遑宿。\n明晨下烟阁，白云在幽谷。' },
  { title: '送常侍御却使西蕃', author: '韦应物', poem: '归奏圣朝行万里，却衔天诏报蕃臣。\n本是诸生守文墨，今将匹马静烟尘。\n旅宿关河逢暮雨，春耕亭障识遗民。\n此去多应收故地，宁辞沙塞往来频。' },
  { title: '送郗詹事', author: '韦应物', poem: '圣朝列群彦，穆穆佐休明。\n君子独知止，悬车守国程。\n忠良信旧德，文学播英声。\n既获天爵美，况将齿位幷。\n书奏蒙省察，命驾乃东征。\n皇恩赐印绶，归为田里荣。\n朝野同称叹，园绮郁齐名。\n长衢轩葢集，饮饯出西京。\n时属春阳节，草木已含英。\n洛川当盛宴，斯焉为达生。' },
  { title: '送苏评事', author: '韦应物', poem: '季弟仕谯都，元兄坐兰省。\n言访始忻忻，念离当耿耿。\n嵯峨夏云起，迢遰山川永。\n登高望去尘，纷思终难整。' },
  { title: '送李侍御益赴幽州幕', author: '韦应物', poem: '二十挥篇翰，三十穷典坟。\n辟书五府至，名为四海闻。\n始从车骑幕，今赴嫖姚军。\n契阔晚相遇，草戚遽离群。\n悠悠行子远，眇眇川途分。\n登高望燕代，日夕生夏云。\n司徒拥精甲，誓将除国氛。\n儒生幸持斧，可以佐功勋。\n无言羽书急，坐阙相思文。' },
  { title: '自尚书郎出为滁州刺史', author: '韦应物', poem: '少年不远仕，秉笏东西京。\n中岁守淮郡，奉命乃征行。\n素慙省阁姿，况忝符竹荣。\n効愚方此始，顾私岂获幷。\n徘徊亲交恋，怆悢昆友情。\n日暮风雪起，我去子还城。\n登涂建隼旟，勒驾望承明。\n云台焕中天，龙阙郁上征。\n晨兴奉早朝，玉露沾华缨。\n一朝从此去，服膺理庶甿。\n皇恩傥岁月，归服厕群英。' },
  { title: '送元锡杨凌', author: '韦应物', poem: '荒林翳山郭，积水成秋晦。\n端居意自违，况别亲与爱。\n欢筵慊未足，离灯悄已对。\n还当掩郡阁，伫君方此会。' },
  { title: '送杨氏女', author: '韦应物', poem: '永日方戚戚，出门复悠悠。\n女子今有行，大江溯轻舟。\n尔辈况无恃，抚念益慈柔。\n幼为长所育，两别泣不休。\n对此结中肠，义往难复留。\n自小阙内训，事姑贻我忧。\n赖兹托令门，仁恤庶无尤。\n贫俭诚所尚，资从岂待周。\n孝恭遵妇道，容止顺其猷。\n别离在今晨，见尔当何秋。\n居闲始自遣，临感忽难收。\n归来视幼女，零泪缘缨流。' },
  { title: '送中弟', author: '韦应物', poem: '秋风入疎户，离人起晨朝。\n山郡多风雨，西楼更萧条。\n嗟予淮海老，送子关河遥。\n同来不同去，沈忧宁复消。' },
  { title: '寄别李儋', author: '韦应物', poem: '首戴惠文冠，心有决胜筹。\n翩翩四五骑，结束向幷州。\n名在相公幕，丘山恩未酬。\n妻子不及顾，亲友安得留。\n宿昔同文翰，交分共绸缪。\n忽枉别离札，涕泪一交流。\n远郡卧残疾，凉气满西楼。\n想子临长路，时当淮海秋。' },
  { title: '送仓部萧员外院长存', author: '韦应物', poem: '襆被蹉跎老江国，情人邂逅此相逢。\n不随鸳鹭朝天去，遥想蓬莱台阁重。' },
  { title: '送王校书', author: '韦应物', poem: '同宿高斋换时节，共看移石复栽杉。\n送君江浦已惆怅，更上西楼看远帆。' },
  { title: '送丘员外还山', author: '韦应物', poem: '长栖白云表，𫏐访高斋宿。\n还辞郡邑諠，归泛松江渌。\n结茅隐苍岭，伐薪响深谷。\n同是山中人，不知往来躅。\n灵芝非庭草，辽鹤委池鹜。\n终当署里门，一表高阳族。' },
  { title: '重送丘二十二还临平山居', author: '韦应物', poem: '岁中始再觏，方来又解携。\n才留野艇语，已忆故山栖。\n幽涧人夜汲，深林鸟长啼。\n还持郡斋酒，慰子霜露凄。' },
  { title: '送郑端公弟移院常州', author: '韦应物', poem: '时瞻宪臣重，礼为内兄全。\n公程傥见责，私爱信不愆。\n况昔陪朝列，今兹俱海壖。\n清觞方对酌，天书忽告迁。\n岂徒咫尺地，使我心思绵。\n应当自此始，归拜云台前。' },
  { title: '送房杭州', author: '韦应物', poem: '专城未四十，暂谪岂蹉跎。\n风雨吴门夜，恻怆别情多。' },
  { title: '送陆侍御还越', author: '韦应物', poem: '居藩久不乐，遇子聊一欣。\n英声颇籍甚，交辟迺时珍。\n绣衣过旧里，骢马辉四邻。\n敬恭尊郡守，牋简具州民。\n谬忝诚所愧，思怀方见申。\n置榻宿清夜，加笾醼良辰。\n遵涂还盛府，行舫遶长津。\n自有贤方伯，得此文翰宾。' },
  { title: '听江笛送陆侍御', author: '韦应物', poem: '远听江上笛，临觞一送君。\n还愁独宿夜，更向郡斋闻。' },
  { title: '送丘员外归山居', author: '韦应物', poem: '郡阁始嘉宴，青山忆旧居。\n为君量革履，且愿住蓝轝。' },
  { title: '送崔叔清游越', author: '韦应物', poem: '忘兹适越意，爱我郡斋幽。\n野情岂好谒，诗兴一相留。\n远水带寒树，阊门望去舟。\n方伯怜文士，无为成滞游。' },
  { title: '送云阳邹儒立少府侍奉还京师', author: '韦应物', poem: '建中即藩守，天宝为侍臣。\n历观两都士，多阅诸侯人。\n邹生乃后来，英俊亦罕伦。\n为文颇瓌丽，禀度自贞醇。\n甲科推令名，延阁播芳尘。\n再命趋王畿，请告奉慈亲。\n一钟信荣禄，可以展欢欣。\n昆弟俱时秀，长衢当自伸。\n聊从郡阁暇，美此时景新。\n方将极娱宴，已复及离晨。\n省署慙再入，江海绵十春。\n今日阊门路，握手子归秦。' },
  { title: '送豆卢策秀才', author: '韦应物', poem: '岁交冰未泮，地卑海气昏。\n子有京师游，始发吴阊门。\n新黄含远林，微绿生陈根。\n诗人感时节，行道当忧烦。\n古来濩落者，俱不事田园。\n文如金石韵，岂乏知音言。\n方辞郡斋榻，为酌离亭罇。\n无为倦羁旅，一去高飞翻。' },
  { title: '送王卿', author: '韦应物', poem: '别酌春林啼鸟稀，双旌背日晚风吹。\n却忆回来花已尽，东郊立马望城池。' },
  { title: '送刘评事', author: '韦应物', poem: '声华满京洛，藻翰发阳春。\n未遂鹓鸿举，尚为江海宾。\n吴中高宴罢，西上一游秦。\n已想函关道，游子冒风尘。\n笼禽羡归翼，远守怀交亲。\n况复岁云暮，凛凛冰霜辰。\n旭霁开郡阁，宠饯集文人。\n洞庭摘朱实，松江献白鳞。\n丈夫岂恨别，一酌且欢忻。' },
  { title: '送雷监赴阙庭', author: '韦应物', poem: '才大无不备，出入为时须。\n雄藩精理行，秘府擢文儒。\n诏书忽已至，焉得久踟躅。\n方舟趂朝谒，观者盈路衢。\n广筵列众宾，送爵无停迂。\n攀饯诚怆恨，贺荣且欢娱。\n长陪柏梁宴，日向丹墀趋。\n时方重右职，蹉跎独海隅。' },
  { title: '送秦系赴润州', author: '韦应物', poem: '近作新婚镊白髯，长怀旧卷映蓝衫。\n更欲携君虎丘寺，不知方伯望征帆。' },
  { title: '送孙征赴云中', author: '韦应物', poem: '黄骢少年舞双戟，目视傍人皆辟易。\n百战会夸陇上儿，一身复作云中客。\n寒风动地气苍芒，横吹先悲出塞长。\n敲石军中传夜火，斧冰河畔汲朝浆。\n前锋直指阴山外，虏骑纷纷翦应碎。\n匈奴破尽看君归，金印酬功如斗大。' },
  { title: '期卢嵩枉书称日暮无马不赴以诗答', author: '韦应物', poem: '佳期不可失，终愿枉衡门。\n南陌人犹度，西林日未昏。\n庭前空倚杖，花里独留罇。\n莫道无来驾，知君有短辕。' },
  { title: '任洛阳丞答前长安田少府问', author: '韦应物', poem: '相逢且对酒，相问欲何如。\n数岁犹卑吏，家人笑著书。\n告归应未得，荣宦又知疎。\n日日生春草，空令忆旧居。' },
  { title: '假中枉卢二十二书亦称卧疾兼讶李二久不访问以诗答书因亦戏李二', author: '韦应物', poem: '微官何事劳趋走，服药闲眠养不才。\n花里棋盘憎鸟污，枕边书卷讶风开。\n故人问讯缘同病，芳月相思阻一杯。\n应笑王戎成俗物，遥持麈尾独徘徊。' },
  { title: '酬卢嵩秋夜见寄五韵', author: '韦应物', poem: '乔木生夜凉，月华满前墀。\n去君咫尺地，劳君千里思。\n素秉栖遁志，况贻招隐诗。\n坐见林木荣，愿赴沧洲期。\n何能待岁晏，携手当此时。' },
  { title: '酬郑户曹骊山感怀', author: '韦应物', poem: '苍山何郁盘，飞阁凌上清。\n先帝昔好道，下元朝百灵。\n白云已萧条，麋鹿但纵横。\n泉水今尚煖，旧林亦青青。\n我念绮襦岁，扈从当太平。\n小臣职前驱，驰道出灞亭。\n翻翻日月旗，殷殷鼙鼓声。\n万马自腾骧，八骏按辔行。\n日出烟峤绿，氛氲丽层甍。\n登临起遐想，沐浴懽圣情。\n朝燕咏无事，时丰贺国祯。\n日和弦管音，下使万室听。\n海内凑朝贡，贤愚共欢荣。\n合沓车马喧，西闻长安城。\n事往世如寄，感深迹所经。\n申章报兰藻，一望双涕零。' },
  { title: '答李澣三首 一', author: '韦应物', poem: '孤客逢春暮，缄情寄旧游。\n海隅人使远，书到洛阳秋。' },
  { title: '答李澣三首 二', author: '韦应物', poem: '马卿犹有壁，渔父自无家。\n想子今何处，扁舟隐荻花。' },
  { title: '答李澣三首 三', author: '韦应物', poem: '林中观易罢，溪上对鸥闲。\n楚俗饶辞客，何人最往还。' },
  { title: '酬柳郎中春日归扬州南郭见别之作', author: '韦应物', poem: '广陵三月花正开，花里逢君醉一廻。\n南北相过殊不远，暮潮从去早潮来。' },
  { title: '酬豆卢仓曹题库壁见示', author: '韦应物', poem: '掾局劳才子，新诗动洛川。\n运筹知决胜，聚米似论边。\n宴罢常分骑，晨趋又比肩。\n莫嗟年鬓改，郎署定推先。' },
  { title: '酬李儋', author: '韦应物', poem: '开门临广陌，旭旦车驾喧。\n不见同心友，徘徊忧且烦。\n都城二十里，居在艮与坤。\n人生所各务，乖阔累朝昏。\n湛湛罇中酒，青青芳树园。\n缄情未及发，先此枉玙璠。\n迈世超高躅，寻流得真源。\n明当策疲马，与子同笑言。' },
  { title: '酬元伟过洛阳夜燕', author: '韦应物', poem: '三载寄关东，所懽皆远违。\n思怀方耿耿，忽得观容辉。\n亲燕在良夜，欢携辟中闱。\n问我犹杜门，不能奋高飞。\n明灯照四隅，炎炭正可依。\n清觞虽云酌，所媿乏珍肥。\n晨装复当行，寥落星已稀。\n何以慰心曲，伫子西还归。' },
  { title: '酬韩质舟行阻冻', author: '韦应物', poem: '晨坐枉嘉藻，持此慰寝兴。\n中获辛苦奏，长河结阴冰。\n皓曜群玉发，凄清孤景凝。\n至柔反成坚，造化安可恒。\n方舟未得行，凿饮空兢兢。\n寒苦弥时节，待泮岂所能。\n何必涉广川，荒衢且升腾。\n殷勤宣中意，庶用达吾朋。' },
  { title: '李博士弟以余罢官居同德精舍共有伊陆名山之期久而未去枉诗见问中云宋生昔登览未云那能顾蓬荜直寄鄙怀聊以为答', author: '韦应物', poem: '初夏息众缘，双林对禅客。\n枉兹芳兰藻，促我幽人策。\n冥搜企前哲，逸句陈往迹。\n髣髴陆浑南，迢递千峰碧。\n从来迟高驾，自顾无物役。\n山水心所娱，如何更朝夕。\n晨兴涉清洛，访子高阳宅。\n莫言往来疎，驽马知阡陌。' },
  { title: '寄酬李博士永宁主簿叔厅见待', author: '韦应物', poem: '解鞍先几日，款曲见新诗。\n定向公堂醉，遥怜独去时。\n叶沾寒雨落，钟度远山迟。\n晨策已云整，当同林下期。' },
  { title: '荅令狐士曹独孤兵曹联骑暮归望山见寄', author: '韦应物', poem: '共爱青山住近南，行牵吏役背双骖。\n枉书独宿对流水，遥羡归时满夕岚。' },
  { title: '荅李博士', author: '韦应物', poem: '休沐去人远，高斋出林杪。\n晴山多碧峰，颢气疑秋晓。\n端居喜良友，枉使千里路。\n缄书当夏时，开缄时已度。\n檐雏已飖飏，荷露方萧飒。\n梦远竹窗幽，行稀兰径合。\n旧居共南北，往来只如昨。\n问君今为谁，日夕度清洛。' },
  { title: '荅刘西曹', author: '韦应物', poem: '公馆夜云寂，微凉群树秋。\n西曹得时彦，华月共淹留。\n长啸举清觞，志气谁与俦。\n千龄事虽邈，俯念忽已周。\n篇翰如云兴，京洛颇优游。\n诠文不独古，理妙即同流。\n浅劣见推许，恐为识者尤。\n空慙文璧赠，日夕不能酬。' },
  { title: '荅贡士黎逢', author: '韦应物', poem: '茂等方上达，诸生安可希。\n栖神澹物表，涣汗布令词。\n如彼昆山玉，本自有光辉。\n鄙人徒区区，称叹亦何为。\n弥月旷不接，公门但驱驰。\n兰章忽有赠，持用慰所思。\n不见心尚密，况当相见时。' },
  { title: '答韩库部', author: '韦应物', poem: '良玉表贞度，丽藻颇为工。\n名列金闺籍，心与素士同。\n日晏下朝来，车马自生风。\n清宵有佳兴，皓月直南宫。\n矫翮方上征，顾我邈忡忡。\n岂不愿攀举，执事府庭中。\n智乖时亦蹇，才大命有通。\n还当以道推，解组守蒿蓬。' },
  { title: '荅崔主簿倬', author: '韦应物', poem: '朗月分林霭，遥管动离声。\n故驩良已阻，空宇澹无情。\n窈窕云雁没，苍茫河汉横。\n兰草不可荅，冲襟徒自盈。' },
  { title: '荅徐秀才', author: '韦应物', poem: '铅钝谢贞器，时秀猥见称。\n岂如白玉仙，方与紫霞升。\n清诗舞艳雪，孤抱莹玄冰。\n一枝非所贵，怀书思武陵。' },
  { title: '荅东林道士', author: '韦应物', poem: '紫阁西边第几峰，茅斋夜雪虎行踪。\n遥看黛色知何处，欲出山门寻暮钟。' },
  { title: '荅长宁令杨辙', author: '韦应物', poem: '皓月升林表，公堂满清辉。\n嘉宾自远至，觞饮夜何其。\n宰邑视京县，归来无寸资。\n瓌文溢众宝，雅正得吾师。\n广川含澄澜，茂树擢华滋。\n短才何足数，枉赠媿妍词。\n欢盼良见属，素怀亦已披。\n何意云栖翰，不嫌蓬艾卑。\n但恐河汉没，回车首路岐。' },
  { title: '荅冯鲁秀才', author: '韦应物', poem: '晨坐枉琼藻，知子返中林。\n澹然山景晏，泉谷响幽禽。\n髣髴谢尘迹，逍遥舒道心。\n顾我腰间绶，端为华发侵。\n簿书劳应对，篇翰旷不寻。\n薄田失锄耨，生苗安可任。\n徒令慙所问，想望东山岑。' },
  { title: '荅崔主簿问兼简温上人', author: '韦应物', poem: '缘情生众累，晚悟依道流。\n诸境一已寂，了将身世浮。\n闲居澹无味，忽复四时周。\n靡靡芳草积，稍稍新篁抽。\n即此抱余素，块然诚寡俦。\n自适一忻意，愧蒙君子忧。' },
  { title: '清都观荅幼遐', author: '韦应物', poem: '逍遥仙家子，日夕朝玉皇。\n兴高清露没，渴饮琼华浆。\n解组一来款，披衣拂天香。\n粲然顾我笑，绿简发新章。\n泠泠如玉音，馥馥若兰芳。\n浩意坐盈此，月华殊未央。\n却念諠哗日，何由得清凉。\n疎松抗高殿，密竹阴长廊。\n荣名等粪土，携手随风翔。' },
  { title: '善福精舍荅韩司录清都观会宴见忆', author: '韦应物', poem: '弱志厌众纷，抱素寄精庐。\n皦皦仰时彦，闷闷独为愚。\n之子亦辞秩，高踪罢驰驱。\n忽因西飞禽，赠我以琼琚。\n始表仙都集，复言欢乐殊。\n人生各有因，契阔不获俱。\n一来田野中，日与人事疎。\n水木澄秋景，逍遥清赏余。\n枉驾怀前诺，引领岂斯须。\n无为便高翔，邈矣不可迂。' },
  { title: '荅长安丞裴说', author: '韦应物', poem: '出身忝时士，于世本无机。\n爰以林壑趣，遂成顽钝姿。\n临流意已凄，采菊露未稀。\n举头见秋山，万事都若遗。\n独践幽人踪，邈将亲友违。\n髦士佐京邑，怀念枉贞词。\n久雨积幽抱，清罇宴良知。\n从容操剧务，文翰方见推。\n安能戢羽翼，顾此林栖时。' },
  { title: '奉酬处士叔见示', author: '韦应物', poem: '挂缨守贫贱，积雪卧郊园。\n叔父亲降趾，壶觞携到门。\n高斋乐宴罢，清夜道心存。\n即此同疎氏，可以一忘言。' },
  { title: '荅库部韩郎中', author: '韦应物', poem: '高士不羁世，颇将荣辱齐。\n适委华冕去，欲还幽林栖。\n虽怀承明恋，忻与物累暌。\n逍遥观运流，谁复职端倪。\n而我岂高致，偃息平门西。\n愚者世所遗，沮溺共耕犂。\n风雪积深夜，园田掩荒蹊。\n幸蒙相思札，款曲期见携。' },
  { title: '荅畅校书当', author: '韦应物', poem: '偶然弃官去，投迹在田中。\n日出照茅屋，园林养愚蒙。\n虽云无一资，罇酌会不空。\n且忻百谷成，仰叹造化功。\n出入与民伍，作事靡不同。\n时伐南涧竹，夜还沣水东。\n贫蹇自成退，岂为高人踪。\n览君金玉篇，彩色发我容。\n日月欲为报，方春已徂冬。' },
  { title: '荅崔都水', author: '韦应物', poem: '深夜竹亭雪，孤灯案上书。\n不遇无为化，谁复得闲居。' },
  { title: '酬令狐司录善福精舍见赠', author: '韦应物', poem: '野寺望山雪，空斋对竹林。\n我以养愚地，生君道者心。' },
  { title: '沣上精舍荅赵氏外生伉', author: '韦应物', poem: '远迹出尘表，寓身双树林。\n如何小子伉，亦有超世心。\n担书从我游，携手广川阴。\n云开夏郊绿，景晏青山沈。\n对榻遇清夜，献诗合雅音。\n所推苟礼数，于性道岂深。\n隐拙在冲默，经世昧古今。\n无为率尔言，可以致华簪。' },
  { title: '荅赵氏生伉', author: '韦应物', poem: '暂与云林别，忽陪鸳鹭翔。\n看山不得去，知尔独相望。' },
  { title: '荅端', author: '韦应物', poem: '郊园夏雨歇，闲院绿阴生。\n职事方无効，幽赏独违情。\n物色坐如见，离抱怅多盈。\n况感夕凉气，闻此乱蝉鸣。' },
  { title: '答史馆张学士段柳庶子学士集贤院看花见寄兼呈柳学士', author: '韦应物', poem: '班杨秉文史，对院自为邻。\n余香掩阁去，迟日看花频。\n似雪飘阊阖，从风点近臣。\n南宫有芳树，不竝禁垣春。' },
  { title: '荅王郎中', author: '韦应物', poem: '卧阁枉芳藻，览旨怅秋晨。\n守郡犹羁寓，无以慰嘉宾。\n野旷归云尽，天清晓露新。\n池荷凉已至，牕梧落渐频。\n风物殊京国，邑里但荒榛。\n赋繁属军兴，政拙媿斯人。\n髦士久台阁，中路一漂沦。\n归当列盛朝，岂念卧淮滨。' },
  { title: '荅王卿送别', author: '韦应物', poem: '去马嘶春草，归人立夕阳。\n元知数日别，要使两情伤。' },
  { title: '荅裴丞说归京所献', author: '韦应物', poem: '执事颇勤久，行去亦伤乖。\n家贫无僮仆，吏卒升寝斋。\n衣服藏内箧，药草曝前阶。\n谁复知次第，濩落且安排。\n还期在岁晏，何以慰吾怀。' },
  { title: '答裴处士', author: '韦应物', poem: '遗民爱精舍，乘犊入青山。\n来署高阳里，不遇白衣还。\n礼贤方化俗，闻风自款关。\n况子逸群士，栖息蓬蒿间。' },
  { title: '荅杨奉礼', author: '韦应物', poem: '多病守山郡，自得接嘉宾。\n不见三四日，旷若十余旬。\n临觞独无味，对榻已生尘。\n一咏舟中作，洒雪忽惊新。\n烟波见栖旅，景物具昭陈。\n秋塘唯落叶，野寺不逢人。\n白事廷吏简，闲居文墨亲。\n高天池阁静，寒菊霜露频。\n应当整孤棹，归来展殷勤。' },
  { title: '答端', author: '韦应物', poem: '坐忆故园人已老，宁知远郡雁还来。\n长瞻西北是归路，独上城楼日几廻。' },
  { title: '答僴奴重阳二甥', author: '韦应物', poem: '弃职曾守拙，玩幽遂忘喧。\n山涧依硗𥕂，竹树荫清源。\n贫居烟火湿，岁熟梨枣繁。\n风雨飘茅屋，蒿草没瓜园。\n群属相欢悦，不觉过朝昏。\n有时看禾黍，落日上秋原。\n饮酒任真性，挥笔肆狂言。\n一朝忝兰省，三载居远藩。\n复与诸弟子，篇翰每相敦。\n西园休习射，南池对芳樽。\n山药经雨碧，海榴凌霜飜。\n念尔不同此，怅然复一论。\n重阳守故家，僴子旅湘沅。\n俱有缄中藻，恻恻动离魂。\n不知何日见，衣上泪空存。' },
  { title: '荅重阳', author: '韦应物', poem: '省札陈往事，怆忆数年中。\n一身朝北阙，家累守田农。\n望山亦临水，暇日每来同。\n性情一疎散，园林多清风。\n忽复隔淮海，梦想在沣东。\n病来经时节，起见秋塘空。\n城郭连榛岭，鸟雀噪沟丛。\n坐使惊霜鬓，撩乱已如蓬。' },
  { title: '酬刘侍郎使君', author: '韦应物', poem: '琼树凌霜雪，葱蒨如芳春。\n英贤虽出守，本自玉阶人。\n宿昔陪郎署，出入仰清尘。\n孰云俱列郡，比德岂为邻。\n风雨飘海气，清凉悦心神。\n重门深夏昼，赋诗延众宾。\n方以岁月旧，每蒙君子亲。\n继作郡斋什，远赠荆山珍。\n高闲庶务理，游眺景物新。\n朋友亦远集，燕酌在佳辰。\n始唱已慙拙，将酬益难伸。\n濡毫意僶俛，一用写悁勤。' },
  { title: '答令狐侍郎', author: '韦应物', poem: '一凶廼一吉，一是复一非。\n孰能逃斯理，亮在识其微。\n三黜故无愠，高贤当庶几。\n但以亲交恋，音容邈难希。\n况昔别离久，俱忻藩守归。\n朝宴方陪厕，山川又乖违。\n吴门冒海雾，峡路凌连矶。\n同会在京国，相望涕沾衣。\n明时重英才，当复列彤闱。\n白玉虽尘垢，拂拭还光辉。' },
  { title: '酬张协律', author: '韦应物', poem: '昔人鬻舂地，今人复一贤。\n属余藩守日，方君卧病年。\n丽思阻文宴，芳踪阙宾筵。\n经时岂不怀，欲往事屡牵。\n公府适烦倦，开缄莹新篇。\n非将握中宝，何以比其妍。\n感兹栖寓词，想复疴瘵缠。\n空宇风霜交，幽居情思绵。\n当以贫非病，孰云白未玄。\n邑中有其人，憔倅即我愆。\n由来牧守重，英俊得荐延。\n匪人等鸿毛，斯道何由宣。\n遭时无早晚，蕴器俟良缘。\n观文心未衰，勿药疾当痊。\n晨期简牍罢，驰慰子忡然。' },
  { title: '荅秦十四校书', author: '韦应物', poem: '知掩山扉三十秋，鱼须翠碧弃床头。\n莫道谢公方在郡，五言今日为君休。' },
  { title: '答宾', author: '韦应物', poem: '斜月才鉴帷，凝霜偏冷枕。\n持情须耿耿，故作单床寝。' },
  { title: '答郑骑曹青橘绝句', author: '韦应物', poem: '怜君卧病思新橘，试摘犹酸亦未黄。\n书后欲题三百颗，洞庭须待满林霜。' },
  { title: '奉和圣制重阳日赐宴', author: '韦应物', poem: '圣心忧万国，端居在穆清。\n玄功致海[晏]，锡䜩表文明。\n恩属重阳节，雨应此时晴。\n寒菊生池苑，高树出宫城。\n捧藻千官处，垂戒百王程。\n复覩开元日，臣愚献颂声。' },
  { title: '和吴舍人早春归沐西亭言志', author: '韦应物', poem: '晓漏戒中禁，清香肃朝衣。\n一门双掌诰，伯侍仲言归。\n亭高性情旷，职密交游稀。\n赋诗乐无事，解带偃南扉。\n阳春美时泽，旭霁望山晖。\n幽禽响未转，东原绿犹微。\n名虽列僊爵，心已遣尘机。\n即事同岩隐，圣渥良难违。' },
  { title: '奉和张大夫戏示青山郎', author: '韦应物', poem: '天生逸世姿，竹马不曾骑。\n览卷冰将释，援毫露欲垂。\n金貂传几叶，玉树长新枝。\n荣禄何妨早，甘罗亦小儿。' },
  { title: '答河南李士巽题香山寺', author: '韦应物', poem: '洛都游宦日，少年携手行。\n投杯起芳席，总辔振华缨。\n关塞有佳气，岩开伊水清。\n攀林憩佛寺，登高望都城。\n蹉跎二十载，世务各所营。\n兹赏长在梦，故人安得幷。\n前岁守九江，恩诏赴咸京。\n因涂再登历，山河属晴明。\n寂寞僧侣少，苍茫林木成。\n墙宇或崩剥，不见旧题名。\n旧游况存殁，独此泪交横。\n交横谁与同，书壁贻友生。\n今兹守吴郡，绵思方未平。\n子复经陈迹，一感我深情。\n远蒙恻怆篇，中有金玉声。\n反复终难答，金玉尚为轻。' },
  { title: '答故人见谕', author: '韦应物', poem: '素寡名利心，自非周圆器。\n徒以岁月资，屡蒙藩条寄。\n时风重书札，物情敦货遗。\n机杼十缣单，慵疎百函愧。\n常负交亲责，且为一官累。\n况本濩落人，归无置锥地。\n省己已知非，枉书见深致。\n虽欲效区区，何由枉其志。' },
  { title: '酬阎员外陟', author: '韦应物', poem: '寒夜阻良觌，丛竹想幽居。\n虎符[予]已误，金丹子何如。\n䜩集观农暇，笙歌听讼余。\n虽蒙一言教，自愧道情疎。' },
  { title: '酬秦征君徐少府春日见寄', author: '韦应物', poem: '终日愧无政，与君聊散襟。\n城根山半腹，亭影水中心。\n朗咏竹牕静，野情花迳深。\n那能有余兴，不作剡溪寻。' },
  { title: '冬夜宿司空曙野居因寄酬赠', author: '韦应物', poem: '南北与山邻，蓬庵庇一身。\n繁霜疑有雪，荒草似无人。\n遂性在耕稼，所交唯贱贫。\n何掾张椽傲，每重德璋亲。' },
  { title: '长安遇冯着', author: '韦应物', poem: '客从东方来，衣上灞陵雨。\n问客何为来，采山因买斧。\n冥冥花正开，飏飏燕新乳。\n昨别今已春，鬓丝生几缕。' },
  { title: '将发楚州经宝应县访李二忽于州馆相遇月夜书事因简李宝应', author: '韦应物', poem: '孤舟欲夜发，祗为访情人。\n此地忽相遇，留连意更新。\n停杯嗟别久，对月言家贫。\n一问临邛令，如何待上宾。' },
  { title: '广陵遇孟九云卿', author: '韦应物', poem: '雄藩本帝都，游士多俊贤。\n夹河树郁郁，华馆千里连。\n新知虽满堂，中意颇未宣。\n忽逢翰林友，欢乐斗酒前。\n高文激颓波，四海靡不传。\n西施且一笑，众女安得妍。\n明月满淮海，哀鸿逝长天。\n所念京国远，我来君欲还。' },
  { title: '淮上遇洛阳李主簿', author: '韦应物', poem: '结茅临古渡，卧见长淮流。\n窗里人将老，门前树已秋。\n寒山独过雁，暮雨远来舟。\n日夕逢归客，那能忘旧游。' },
  { title: '路逢崔元二侍御避马见招以诗见赠', author: '韦应物', poem: '一台称二妙，归路望行尘。\n俱是攀龙客，空为避马人。\n见招翻跼蹐，相问良殷勤。\n日日吟趋府，弹冠岂有因。' },
  { title: '逢杨开府', author: '韦应物', poem: '少事武皇帝，无赖恃恩私。\n身作里中横，家藏亡命儿。\n朝持樗蒲局，暮窃东邻姬。\n司隶不敢捕，立在白玉墀。\n骊山风雪夜，长杨羽猎时。\n一字都不识，饮酒肆顽痴。\n武皇升仙去，憔悴被人欺。\n读书事已晚，把笔学题诗。\n两府始收迹，南宫谬见推。\n非才果不容，出守抚惸嫠。\n忽逢杨开府，论旧涕俱垂。\n坐客何由识，惟有故人知。' },
  { title: '休暇日访王侍御不遇', author: '韦应物', poem: '九日驱驰一日闲，寻君不遇又空还。\n怪来诗思清人骨，门对寒流雪满山。' },
  { title: '因省风俗访道士姪不见题壁', author: '韦应物', poem: '去年涧水今亦流，去年杏花今又拆。\n山人归来问是谁，还是去年行春客。' },
  { title: '有所思', author: '韦应物', poem: '借问堤上柳，青青为谁春。\n空游昨日地，不见昨日人。\n缭绕万家井，往来车马尘。\n莫道无相识，要非心所亲。' },
  { title: '暮相思', author: '韦应物', poem: '朝出自不还，暮归花尽发。\n岂无终日会，惜此花间月。\n空馆忽相思，微钟坐来歇。' },
  { title: '夏夜忆卢嵩', author: '韦应物', poem: '霭霭高馆暮，开轩涤烦襟。\n不知湘雨来，潇洒在幽林。\n炎月得凉夜，芳樽谁与斟。\n故人南北居，累月间徽音。\n人生无闲日，欢会当在今。\n反侧候天旦，层城苦沈沈。' },
  { title: '春思', author: '韦应物', poem: '野花如雪绕江城，坐见年芳忆帝京。\n阊阖晓开凝碧树，曾陪鸳鹭听流莺。' },
  { title: '春中忆元二', author: '韦应物', poem: '雨歇万井春，柔条已含绿。\n徘徊洛阳陌，惆怅杜陵曲。\n游丝正高下，啼鸟还断续。\n有酒今不同，思君莹如玉。' },
  { title: '怀素友子西', author: '韦应物', poem: '广陌竝游骑，公堂接华襟。\n方欢遽见别，永日独沈吟。\n阶暝流暗驶，气疎露已侵。\n层城湛深夜，片月生幽林。\n往款良未遂，来觌旷无音。\n恒当清觞宴，思子玉山岑。\n耿耿何以写，密言空委心。' },
  { title: '对韩少尹所赠砚有怀', author: '韦应物', poem: '故人谪遐远，留砚宠斯文。\n白水浮香墨，清池满夏云。\n念离心已永，感物思徒纷。\n未有桂阳使，裁书一报君。' },
  { title: '月晦忆去年与亲友曲水游䜩', author: '韦应物', poem: '晦赏念前岁，京国结良俦。\n骑出宣平里，饮对曲池流。\n今朝隔天末，空园伤独游。\n雨歇林光变，塘绿鸟声幽。\n凋甿积逋税，华鬓集新秋。\n谁言恋虎符，终当还旧丘。' },
  { title: '清明日忆诸弟', author: '韦应物', poem: '冷食方多病，开襟一忻然。\n终令思故郡，烟火满晴川。\n杏粥犹堪食，榆羹已稍煎。\n唯恨乖亲燕，坐度此芳年。' },
  { title: '池上怀王卿', author: '韦应物', poem: '幽居捐世事，佳雨散园芳。\n入门霭已绿，水禽鸣春塘。\n重云始成夕，忽霁尚残阳。\n轻舟因风泛，郡阁望苍苍。\n私燕阻外好，临欢一停觞。\n兹游无时尽，旭日愿相将。' },
  { title: '立夏日忆京师诸弟', author: '韦应物', poem: '改序念芳辰，烦襟倦日永。\n夏木已成阴，公门昼恒静。\n长风始飘阁，叠云才吐岭。\n坐想离居人，还当惜徂景。' },
  { title: '晓至园中忆诸弟崔都水', author: '韦应物', poem: '山郭恒悄悄，林月亦娟娟。\n景清神已澄，事简虑绝牵。\n秋塘徧衰草，晓露洗红莲。\n不见心所爱，兹赏岂为妍。' },
  { title: '怀瑯琊深标二释子', author: '韦应物', poem: '白云埋大壑，阴崖滴夜泉。\n应居西石室，月照山苍然。' },
  { title: '雨夜感怀', author: '韦应物', poem: '微雨洒高林，尘埃自萧散。\n耿耿心未平，沈沈夜方半。\n独惊长簟冷，遽觉愁鬓换。\n谁能当此夕，不有盈襟叹。' },
  { title: '云阳馆怀谷口', author: '韦应物', poem: '清泚阶下流，云自谷口源。\n念昔白衣士，结庐在石门。\n道高杳无累，景静得忘言。\n山夕绿阴满，世移清赏存。\n吏役岂遑暇，幽怀复朝昏。\n云泉非所濯，萝月不可援。\n长往遂真性，暂游恨卑喧。\n出身既事世，高躅难等论。' },
  { title: '忆沣上幽居', author: '韦应物', poem: '一来当复去，犹此厌樊笼。\n况我林栖子，朝服坐南宫。\n唯独问啼鸟，还如沣水东。' },
  { title: '重九登滁城楼忆前岁九日归沣上赴崔都水及诸弟䜩集凄然怀旧', author: '韦应物', poem: '今日重九䜩，去岁在京师。\n聊廻出省步，一赴郊园期。\n嘉节始云迈，周辰已及兹。\n秋山满清景，当赏属乖离。\n凋散民里阔，摧翳众木衰。\n楼中一长啸，恻怆起凉飔。' },
  { title: '始夏南园思旧里', author: '韦应物', poem: '夏首云物变，雨余草木繁。\n池荷初帖水，林花已扫园。\n萦丛蝶尚乱，依阁鸟犹喧。\n对此残芳月，忆在汉陵原。' },
  { title: '登蒲塘驿沿路见泉谷邨墅忽想京师旧居追怀昔年', author: '韦应物', poem: '青山导骑遶，春风行斾舒。\n均徭视属城，问疾躬里闾。\n烟水依泉谷，川陆散樵渔。\n忽念故园日，复忆骊山居。\n荏苒斑鬓及，梦寝婚宦初。\n不觉平生事，咄嗟二纪余。\n存殁阔已永，悲多欢自疎。\n高秩非为美，阑干泪盈裾。' },
  { title: '经函谷关', author: '韦应物', poem: '洪河绝山根，单轨出其侧。\n万古为要枢，往来何时息。\n秦皇即恃险，海内被吞食。\n及嗣同覆颠，咽喉莫能塞。\n炎灵讵西驾，娄子非经国。\n徒欲扼诸侯，不知恢至德。\n圣朝及天宝，豺虎起东北。\n下沈战死魂，上结穷冤色。\n古今虽共守，成败良可识。\n藩屏无俊贤，金汤独何力。\n[驰]车一登眺，感慨中自恻。' },
  { title: '经武功旧宅', author: '韦应物', poem: '兹邑昔所游，嘉会常在目。\n历载俄二九，始往今来复。\n戚戚居人少，茫茫野田绿。\n风雨经旧墟，毁垣迷往躅。\n门临川流驶，树有羇雌宿。\n多累恒悲往，长年觉时速。\n欲去中复留，徘徊结心曲。' },
  { title: '往云门郊居涂经廻流作', author: '韦应物', poem: '兹晨乃休暇，适往田家庐。\n原谷径涂涩，春阳草木敷。\n才遵板桥曲，复此清涧纡。\n崩壑方见射，廻流忽已舒。\n明灭泛孤景，杳霭含夕虚。\n无将为邑志，一酌澄波余。' },
  { title: '乘月过西郊渡', author: '韦应物', poem: '远山含紫氛，春野霭云暮。\n值此归时月，留连西涧渡。\n谬当文墨会，得与群英遇。\n赏逐乱流翻，心将清景悟。\n行车俨未转，芳草空盈步。\n已举候亭火，犹爱村原树。\n还当守故扃，怅恨秉幽素。' },
  { title: '晚归沣川', author: '韦应物', poem: '凌雾朝阊阖，落日返清川。\n簪组方暂解，临水一翛然。\n昆弟忻来集，童稚满眼前。\n适意在无事，携手望秋田。\n南岭横爽气，高林绕遥阡。\n野庐不锄理，翳翳起荒烟。\n名秩斯逾分，廉退媿不全。\n已想平门路，晨骑复言旋。' },
  { title: '授衣还田里', author: '韦应物', poem: '公门悬甲令，澣濯遂其私。\n晨起怀怆恨，野田寒露时。\n气收天地广，风凄草木衰。\n山明始重叠，川浅更逶迤。\n烟火生闾里，禾黍积东菑。\n终然可乐业，时节一来斯。' },
  { title: '夕次盱眙县', author: '韦应物', poem: '落帆逗淮镇，停舫临孤驿。\n浩浩风起波，冥冥日沈夕。\n人归山郭暗，雁下芦洲白。\n独夜忆秦关，听钟未眠客。' },
  { title: '春月观省属城始憩东西林精舍', author: '韦应物', poem: '因时省风俗，布惠迨高年。\n建隼出浔阳，整驾游山川。\n白云敛晴壑，群峰列遥天。\n嵚㟢石门状，杳霭香炉烟。\n榛荒屡罥罣，偪侧殆覆颠。\n方臻释氏庐，时物屡华妍。\n昙远昔经始，于兹閟幽玄。\n东西竹林寺，灌注寒涧泉。\n人事即云泯，岁月复已绵。\n殿宇余丹绀，磴阁峭欹悬。\n佳士亦栖息，善身绝尘缘。\n今我蒙朝寄，教化敷里鄽。\n道妙茍为得，出处理无偏。\n心当同所尚，迹岂辞缠牵。' },
  { title: '自蒲塘驿廻驾经历山水', author: '韦应物', poem: '馆宿风雨滞，始晴行盖转。\n浔阳山水多，草木俱纷衍。\n崎岖缘碧涧，苍翠践苔藓。\n高树夹潺湲，崩石横阴𪩘。\n野杏依寒拆，余云冒岚浅。\n性惬形岂劳，境殊路遗缅。\n忆昔终南下，佳游亦屡展。\n时禽下流暮，纷思何由遣。' },
  { title: '山行积雨归途始霁', author: '韦应物', poem: '揽辔穷登降，阴雨遘二旬。\n但见白云合，不睹岩中春。\n急涧岂易揭，峻涂良难遵。\n深林猿声冷，沮洳虎迹新。\n始霁升阳景，山水阅清晨。\n杂花积如雾，百卉萋已陈。\n鸣驺屡骧首，归路自忻忻。' },
  { title: '伤逝', author: '韦应物', poem: '染白一为黑，焚木尽成灰。\n念我室中人，逝去亦不廻。\n结发二十载，宾敬如始来。\n提携属时屯，契阔忧患灾。\n柔素亮为表，礼章夙所该。\n仕公不及私，百事委令才。\n一旦入闺门，四屋满尘埃。\n斯人既已矣，触物但伤摧。\n单居移时节，泣涕抚婴孩。\n知妄谓当遣，临感要难裁。\n梦想忽如睹，惊起复徘徊。\n此心良无已，遶屋生蒿莱。' },
  { title: '往富平伤怀', author: '韦应物', poem: '晨起凌严霜，恸哭临素帷。\n驾言百里涂，恻怆复何为。\n昨者仕公府，属城常载驰。\n出门无所忧，返室亦熙熙。\n今者掩筠扉，但闻童稚悲。\n丈夫须出入，顾尔内无依。\n衔恨已酸骨，何况苦寒时。\n单车路萧条，廻首长逶迟。\n飘风忽截野，嘹唳雁起飞。\n昔时同往路，独往今讵知。' },
  { title: '出还', author: '韦应物', poem: '昔出喜还家，今还独伤意。\n入室掩无光，衔哀写虚位。\n凄凄动幽幔，寂寂惊寒吹。\n幼女复何知，时来庭下戏。\n咨嗟日复老，错莫身如寄。\n家人劝我飡，对案空垂泪。' },
  { title: '冬夜', author: '韦应物', poem: '杳杳日云夕，郁结谁为开。\n单衾自不暖，霜霰已皑皑。\n晚岁沦夙志，惊鸿感深哀。\n深哀当何为，桃李忽凋摧。\n帏怅徒自设，冥寞岂复来。\n平生虽恩重，迁去托穷埃。\n抱此女曹恨，顾非高世才。\n振衣中夜起，河汉尚裴回。' },
  { title: '送终', author: '韦应物', poem: '奄忽逾时节，日月获其良。\n萧萧车马悲，祖载发中堂。\n生平同此居，一旦异存亡。\n斯须亦何益，终复委山冈。\n行出国南门，南望郁苍苍。\n日入乃云造，恸哭宿风霜。\n晨迁俯玄庐，临诀但遑遑。\n方当永潜翳，仰视白日光。\n俯仰遽终毕，封树已荒凉。\n独留不得还，欲去结中肠。\n童稚知所失，啼号捉我裳。\n既事犹仓卒，岁月始难忘。' },
  { title: '除日', author: '韦应物', poem: '思怀耿如昨，季月已云暮。\n忽惊年复新，独恨人成故。\n冰池始泮绿，梅楥还飘素。\n淑景方转延，朝朝自难度。' },
  { title: '对芳树', author: '韦应物', poem: '迢迢芳园树，列映清池曲。\n对此伤人心，还如故时绿。\n风条洒余霭，露叶承新旭。\n佳人不再攀，下有往来躅。' },
  { title: '月夜', author: '韦应物', poem: '皓月流春城，华露积芳草。\n坐念绮窗空，翻伤清景好。\n清景终若斯，伤多人自老。' },
  { title: '叹杨花', author: '韦应物', poem: '空蒙不自定，况值暄风度。\n旧赏逐流年，新愁忽盈素。\n才萦下苑曲，稍满东城路。\n人意有悲欢，时芳独如故。' },
  { title: '过昭国里故第', author: '韦应物', poem: '不复见故人，一来过故宅。\n物变知景暄，心伤觉时寂。\n池荒野筠合，庭绿幽草积。\n风散花意谢，鸟还山光夕。\n宿昔方同赏，讵知今念昔。\n缄室在东厢，遗器不忍觌。\n柔翰全分意，芳巾尚染泽。\n残工委筐箧，余素经刀尺。\n收此还我家，将还复愁惕。\n永绝携手欢，空存旧行迹。\n冥冥独无语，杳杳将何适。\n唯思今古同，时缓伤与戚。' },
  { title: '夏日', author: '韦应物', poem: '已谓心苦伤，如何日方永。\n无人不昼寝，独坐山中静。\n悟澹将遣虑，学空庶遗境。\n积俗易为侵，愁来复难整。' },
  { title: '端居感怀', author: '韦应物', poem: '沈沉积素抱，婉婉属之子。\n永日独无言，忽惊振衣起。\n方如在帏室，复悟永终已。\n稚子伤恩绝，盛时若流水。\n暄凉同寡趣，朗晦俱无理。\n寂性常喻人，滞情今在己。\n空房欲云暮，巢燕亦来止。\n夏木遽成阴，绿苔谁复履。\n感至竟何方，幽独长如此。' },
  { title: '悲纨扇', author: '韦应物', poem: '非关秋节至，讵是恩情改。\n掩嚬人已无，委箧凉空在。\n何言永不发，暗使销光彩。' },
  { title: '闲斋对雨', author: '韦应物', poem: '幽独自盈抱，阴淡亦连朝。\n空斋对高树，疎雨共萧条。\n巢燕翻泥湿，蕙花依砌消。\n端居念往事，倏忽苦惊飙。' },
  { title: '林园晚霁', author: '韦应物', poem: '雨歇见青山，落日照林园。\n山多烟鸟乱，林清风景翻。\n提携唯子弟，萧散在琴言。\n同游不同意，耿耿独伤魂。\n寂寞钟已尽，如何还入门。' },
  { title: '秋夜二首 一', author: '韦应物', poem: '庭树转萧萧，阴虫还戚戚。\n独向高斋眠，夜闻寒雨滴。\n微风时动牖，残灯尚留壁。\n惆怅平生怀，偏来委今夕。' },
  { title: '秋夜二首 二', author: '韦应物', poem: '霜露已凄凄，星汉复昭回。\n朔风中夜起，惊鸿千里来。\n萧条凉叶下，寂寞清砧哀。\n岁晏仰空宇，心事若寒灰。' },
  { title: '感梦', author: '韦应物', poem: '岁月转芜漫，形影长寂寥。\n髣髴觏微梦，感叹起中宵。\n绵思霭流月，惊魂飒廻飙。\n谁念兹夕永，坐令颜鬓凋。' },
  { title: '同德精舍旧居伤怀', author: '韦应物', poem: '洛京十载别，东林访旧扉。\n山河不可望，存没意多违。\n时迁迹尚在，同去独来归。\n还见窗中鸽，日暮遶庭飞。' },
  { title: '悲故交', author: '韦应物', poem: '白璧众求瑕，素丝易成污。\n万里颠沛还，高堂已长暮。\n积愤方盈抱，缠哀忽逾度。\n念子从此终，黄泉竟谁诉。\n一为时事感，岂独平生故。\n唯见荒丘原，野草涂朝露。' },
  { title: '张彭州前与缑氏冯少府各惠寄一篇多故未答张已云没因追哀叙事兼远简冯生', author: '韦应物', poem: '君昔掌文翰，西垣复石渠。\n朱衣乘白马，辉光照里闾。\n余时忝南省，接䜩媿空虚。\n一别守兹郡，蹉跎岁再除。\n长怀关河表，永日简牍余。\n郡中有方塘，凉阁对红蕖。\n金玉蒙远贶，篇咏见吹嘘。\n未答平生意，已没九原居。\n秋风吹寝门，长恸涕涟如。\n覆视缄中字，奄为昔人书。\n发鬓已云白，交友日雕疎。\n冯生远同恨，憔悴在田庐。' },
  { title: '东林精舍见故殿中郑侍御题诗追旧书情涕泗横集因寄呈阎澧州冯少府', author: '韦应物', poem: '仲月景气佳，东林一登历。\n中有故人诗，凄凉在高壁。\n精思长悬世，音容已归寂。\n墨泽传洒余，磨灭亲翰迹。\n平生忽如梦，百事皆成昔。\n结骑京华年，挥文箧笥积。\n朝廷重英彦，时辈分珪璧。\n永谢柏梁陪，独阙金门籍。\n方婴存殁感，岂暇林泉适。\n雨余山景寒，风散花光夕。\n新知虽满堂，故情谁能觌。\n唯当同时友，缄寄空凄戚。' },
  { title: '同李二过亡友郑子故第', author: '韦应物', poem: '客车名未灭，没世恨应长。\n斜月知何照，幽林判自芳。\n故人惊逝水，寒雀噪空墙。\n不是平生旧，遗踪要可伤。' },
  { title: '话旧', author: '韦应物', poem: '存亡三十载，事过悉成空。\n不惜沾衣泪，并话一宵中。' },
  { title: '至开化里寿春公故宅', author: '韦应物', poem: '宁知府中吏，故宅一徘徊。\n历阶存往敬，瞻位泣余哀。\n废井没荒草，阴牖生绿笞。\n门前车马散，非复昔时来。' },
  { title: '睢阳感怀', author: '韦应物', poem: '豺虎犯天纲，升平无内备。\n长驱阴山卒，略践三河地。\n张侯本忠烈，济世有深智。\n坚壁梁宋间，远筹吴楚利。\n穷年方绝输，邻援皆携贰。\n使者哭其庭，救兵终不至。\n重围虽可越，藩翰谅难弃。\n饥喉待危巢，悬命中路坠。\n甘从锋刃毙，莫夺坚贞志。\n宿将降贼庭，儒生独全义。\n空城唯白骨，同往无贱贵。\n哀哉岂独今，千载当歔欷。' },
  { title: '广德中洛阳作', author: '韦应物', poem: '生长太平日，不知太平欢。\n今还洛阳中，感此方苦酸。\n饮药本攻病，毒肠翻自残。\n王师涉河洛，玉石俱不完。\n时节屡迁斥，山河长郁盘。\n萧条孤烟绝，日入空城寒。\n蹇劣乏高步，缉遗守微官。\n西怀咸阳道，踯躅心不安。' },
  { title: '阊门怀古', author: '韦应物', poem: '独鸟下高树，遥知吴苑园。\n凄凉千古事，日暮倚阊门。' },
  { title: '感事', author: '韦应物', poem: '霜雪皎素丝，何意坠墨池。\n青苍犹可濯，黑色不可移。\n女工再三叹，委弃当此时。\n岁寒虽无褐，机杼谁肯施。' },
  { title: '感镜', author: '韦应物', poem: '铸镜广陵市，菱花匣中发。\n夙昔尝许人，镜成人已没。\n如冰结圆器，类璧无丝发。\n形影终不临，清光殊不歇。\n一感平生言，松枝树秋月。' },
  { title: '叹白发', author: '韦应物', poem: '还同一叶落，对此孤镜晓。\n丝缕乍难分，杨花复相遶。\n时役人易衰，吾年白犹少。' },
  { title: '登高望洛城作', author: '韦应物', poem: '高台造云端，遐瞰周四垠。\n雄都定鼎地，势据万国尊。\n河岳出云雨，土圭酌乾坤。\n舟通南越贡，城背北邙原。\n帝宅夹清洛，丹霞捧朝暾。\n葱茏瑶台榭，𥦖窱双阙门。\n十载构屯难，兵戈若云屯。\n膏腴满榛芜，比屋空毁垣。\n圣主乃东眷，俾贤拯元元。\n熙熙居守化，泛泛太府恩。\n至损当受益，苦寒必生温。\n平明四城开，稍见市井喧。\n坐感理乱迹，永怀经济言。\n吾生自不达，空鸟何翩翻。\n天高水流远，日晏城郭昏。\n裴回讫旦夕，聊用写忧烦。' },
  { title: '同德寺阁集眺', author: '韦应物', poem: '芳节欲云晏，游遨乐相从。\n高阁照丹霞，飗飗含远风。\n寂寥氛氲廓，超忽神虑空。\n旭日霁皇州，岧峣见两宫。\n嵩少多秀色，群山莫与崇。\n三川浩东注，瀍涧亦来同。\n阴阳降大和，宇宙得其中。\n舟车满川陆，四国靡不通。\n旧堵今即葺，庶甿亦已丰。\n周览思自奋，行当遇时邕。' },
  { title: '登宝意寺上方旧游', author: '韦应物', poem: '翠岭香台出半天，万家烟树满晴川。\n诸僧近住不相识，坐听微钟记往年。' },
  { title: '登乐游庙作', author: '韦应物', poem: '高原出东城，郁郁见咸阳。\n上有千载事，乃自汉宣皇。\n颓壖久凌迟，陈迹翳丘荒。\n春草虽复绿，惊风但飘扬。\n周览京城内，双阙起中央。\n微钟何处来，暮色忽苍苍。\n歌吹喧万井，车马塞康庄。\n昔人岂不尔，百世同一伤。\n归当守冲漠，迹寓心自忘。' },
  { title: '登西南冈卜居遇雨寻竹浪至沣壖萦带数里清流茂树云物可赏', author: '韦应物', poem: '登高创危构，林表见川流。\n微雨飒已至，萧条川气秋。\n下寻密竹尽，忽旷沙际游。\n纡曲水分野，绵延稼盈畴。\n寒花明废墟，樵牧笑榛丘。\n云水成阴澹，竹树更清幽。\n适自恋佳赏，复兹永日留。' },
  { title: '沣上与幼遐月夜登西冈玩花', author: '韦应物', poem: '置酒临高隅，佳人自城阙。\n已玩满川花，还看满川月。\n花月方浩然，赏心何由歇。' },
  { title: '台上迟客', author: '韦应物', poem: '高台一悄望，远树间朝晖。\n但见东西骑，坐令心赏违。\n始霁郊原绿，暮春啼鸟稀。\n徒然对芳物，何能独醉归。' },
  { title: '登楼', author: '韦应物', poem: '兹楼日登眺，流岁暗蹉跎。\n坐厌淮南守，秋山红树多。' },
  { title: '善福寺阁', author: '韦应物', poem: '残霞照高阁，青山出远林。\n晴明一登望，潇洒此幽襟。' },
  { title: '楼中月夜', author: '韦应物', poem: '端令倚悬槛，长望抱沈忧。\n宁知故园月，今夕在兹楼。\n衰莲送余馥，华露湛新秋。\n坐见苍林变，清辉怆已休。' },
  { title: '寒食后北楼作', author: '韦应物', poem: '园林过新节，风花乱高阁。\n遥闻击鼓声，蹴鞠军中乐。' },
  { title: '夜望', author: '韦应物', poem: '南楼夜已寂，暗鸟动林间。\n不见城郭事，沈沈唯四山。' },
  { title: '晚登郡阁', author: '韦应物', poem: '怅然高阁望，已掩东城关。\n春风偏送柳，夜景欲沈山。' },
  { title: '登重玄寺阁', author: '韦应物', poem: '时暇陟云构，晨霁澄景光。\n始见吴都大，十里郁苍苍。\n山川表明丽，湖海吞大荒。\n合沓臻水陆，骈阗会四方。\n俗繁节又暄，雨顺物亦康。\n禽鱼各翔泳，草木遍芬芳。\n于兹省甿俗，一用劝农桑。\n诚知虎符忝，但恨归路长。' },
  { title: '观早朝', author: '韦应物', poem: '伐鼓通严城，车马溢广躔。\n煌煌列明烛，朝服照华鲜。\n金门杳深沈，尚听清漏传。\n河汉忽已没，司阍启晨关。\n丹殿据龙首，崔嵬对南山。\n寒生千门里，日照双阙间。\n禁旅下成列，炉香起中天。\n辉辉覩明圣，济济行俊贤。\n媿无鸳鹭姿，短翮空飞还。\n谁当假毛羽，云路相追攀。' },
  { title: '陪元侍御春游', author: '韦应物', poem: '何处醉春风，长安西复东。\n不因俱罢职，岂得此时同。\n贳酒宣平里，寻芳下苑中。\n往来杨柳陌，犹避昔年骢。' },
  { title: '游龙门香山泉', author: '韦应物', poem: '山水本自佳，游人已忘虑。\n碧泉更幽绝，赏爱未能去。\n潺湲写幽磴，缭绕带嘉树。\n激转忽殊流，归泓又同注。\n羽觞自成玩，永日亦延趣。\n灵草有时香，仙源不知处。\n还当候圆月，携手重游寓。' },
  { title: '龙门游眺', author: '韦应物', poem: '凿山导伊流，中断若天辟。\n都门遥相望，佳气生朝夕。\n素怀出尘意，适有携手客。\n精舍遶层阿，千龛邻峭壁。\n缘云路犹缅，憩涧钟已寂。\n花树发烟华，淙流散石脉。\n长啸招远风，临潭漱金碧。\n日落望都城，人间何役役。' },
  { title: '洛都游寓', author: '韦应物', poem: '东风日已和，元化亮无私。\n草木同时植，生条有高卑。\n罢官守园庐，岂不怀渴饥。\n穷通非所干，跼促当何为。\n佳辰幸可游，亲友亦相追。\n朝从华林宴，暮返东城期。\n掇英出兰臯，玩月步川坻。\n轩冕诚可慕，所忧在絷维。' },
  { title: '再游龙门怀旧侣', author: '韦应物', poem: '两山郁相对，晨策方上干。\n霭霭眺都城，悠悠俯清澜。\n邈矣二三子，兹焉屡游盘。\n良时忽已周，独往念前欢。\n好鸟始云至，众芳亦未阑。\n遇物岂殊昔，慨伤自有端。' },
  { title: '庄严精舍游集', author: '韦应物', poem: '良游因时暇，乃在西南隅。\n绿烟凝层城，丰草满通衢。\n精舍何崇旷，烦跼一弘舒。\n架虹施广荫，构云眺八区。\n既此尘境远，忽闻幽鸟殊。\n新林泛景光，丛绿含露濡。\n永日亮难遂，平生少欢娱。\n谁能遽还归，幸与高士俱。' },
  { title: '府舍月游', author: '韦应物', poem: '官舍耿深夜，佳月喜同游。\n横河俱半落，泛露忽惊秋。\n散彩疎群树，分规澄素流。\n心期与浩景，苍苍殊未收。' },
  { title: '任鄠令渼陂游眺', author: '韦应物', poem: '野水滟长塘，烟花乱晴日。\n氤氲绿树多，苍翠千山出。\n游鱼时可见，新荷尚未密。\n屡往心独闲，恨无理人术。' },
  { title: '西郊游瞩', author: '韦应物', poem: '东风散余沍，陂水淡已绿。\n烟芳何处寻，杳蔼春山曲。\n新禽哢暄节，晴光泛嘉木。\n一与诸君游，华觞忻见属。' },
  { title: '再游西郊渡', author: '韦应物', poem: '水曲一追游，游人重怀恋。\n婵娟昨夜月，还向波中见。\n惊禽栖不定，流芳寒未徧。\n携手更何时，伫看花似霰。' },
  { title: '月溪与幼遐君贶同游', author: '韦应物', poem: '岸筿覆廻溪，廻溪曲如月。\n沈沈水容绿，寂寂流莺歇。\n浅石方凌乱，游禽时出没。\n半雨夕阳霏，缘源杂花发。\n明晨重来此，同心应已阙。' },
  { title: '与幼遐君贶兄弟同游白家竹潭', author: '韦应物', poem: '清赏非素期，偶游方自得。\n前登绝岭险，下视深潭黑。\n密竹已成暮，归云殊未极。\n春鸟依谷暄，紫兰含幽色。\n已将芳景遇，复款平生忆。\n终念一欢别，临风还默默。' },
  { title: '秋夕西斋与僧神静游', author: '韦应物', poem: '晨登西斋望，不觉至夕曛。\n正当秋夏交，原野起烟氛。\n坐听凉飙举，华月稍披云。\n漠漠山犹隐，滟滟川始分。\n物幽夜更殊，境静兴弥臻。\n息机非傲世，于时乏嘉闻。\n究空自为理，况与释子群。' },
  { title: '观田家', author: '韦应物', poem: '微雨众卉新，一雷惊蛰始。\n田家几日闲，耕种从此起。\n丁壮俱在野，场圃亦就理。\n归来景常晏，饮犊西涧水。\n饥劬不自苦，膏泽且为喜。\n仓廪无宿储，徭役犹未已。\n方慙不耕者，禄食出闾里。' },
  { title: '园亭览物', author: '韦应物', poem: '积雨时物变，夏绿满园新。\n残花已落实，高笋半成筠。\n守此幽栖地，自是忘机人。' },
  { title: '观沣水涨', author: '韦应物', poem: '夏雨万壑凑，沣涨暮浑浑。\n草木盈川谷，澶漫一平吞。\n槎梗方弥泛，涛沫亦洪翻。\n北来注泾渭，所过无安源。\n云岭同昏黑，观望悸心魂。\n舟人空敛棹，风波正自奔。' },
  { title: '陪王卿郎中游南池', author: '韦应物', poem: '鹓鸿俱失侣，同为此地游。\n露浥荷花气，风散柳园秋。\n烟草凝衰屿，星汉泛归流。\n林高初上月，塘深未转舟。\n清言屡往复，华樽始献酬。\n终忆秦川赏，端坐起离忧。' },
  { title: '南园陪王卿游瞩', author: '韦应物', poem: '形迹虽拘检，世事澹无心。\n郡中多山水，日夕听幽禽。\n几阁文墨暇，园林春景深。\n杂花芳意散，绿池暮色沈。\n君子有高躅，相携在幽寻。\n一酌何为贵，可以写冲襟。' },
  { title: '游西山', author: '韦应物', poem: '时事方扰扰，幽赏独悠悠。\n弄泉朝涉涧，采石夜归州。\n挥翰题苍峭，下马历嵌丘。\n所爱唯山水，到此即淹留。' },
  { title: '春游南亭', author: '韦应物', poem: '川明气已变，岩寒云尚拥。\n南亭草心绿，春塘泉脉动。\n景煦听禽响，雨余看柳重。\n逍遥池馆华，益媿专城宠。' },
  { title: '再游西山', author: '韦应物', poem: '南谯古山郡，信是高人居。\n自叹乏弘量，终朝亲簿书。\n于时忽命驾，秋野正萧疎。\n积逋诚待责，寻山亦有余。\n测测石泉冷，暧暧烟谷虚。\n中有释门子，种果结茅庐。\n出身厌名利，遇境即踌躇。\n守直虽多忤，视险方晏如。\n况将尘埃外，襟抱从此舒。' },
  { title: '游灵岩寺', author: '韦应物', poem: '始入松路永，独忻山寺幽。\n不知临绝槛，乃见西江流。\n吴岫分烟景，楚甸散林丘。\n方悟关塞眇，重轸故园愁。\n闻钟戒归骑，憩涧惜良游。\n地疎泉谷狭，春深草木稠。\n兹焉赏未极，清景期杪秋。' },
  { title: '与卢陟同游永定寺北池僧斋', author: '韦应物', poem: '密竹行已远，子归啼更深。\n绿池芳草气，闲斋春树阴。\n晴蝶飘兰迳，游蜂遶花心。\n不遇君携手，谁复此幽寻。' },
  { title: '游溪', author: '韦应物', poem: '野水烟鹤唳，楚天云雨空。\n玩舟清景晚，垂钓绿蒲中。\n落花飘旅衣，归流澹清风。\n缘源不可极，远树但青葱。' },
  { title: '游开元精舍', author: '韦应物', poem: '夏衣始轻体，游步爱僧居。\n果园新雨后，香台照日初。\n绿阴生昼静，孤花表春余。\n符竹方为累，形迹一来疎。' },
  { title: '襄武馆游眺', author: '韦应物', poem: '州民知礼让，讼简得遨游。\n高亭凭古地，山川当暮秋。\n是时秔稻熟，西望尽田畴。\n仰恩慙政拙，念劳喜岁收。\n澹泊风景晏，缭绕云树幽。\n节往情恻恻，天高思悠悠。\n嘉宾幸云集，芳罇始淹留。\n还希习池赏，聊以驻鸣驺。' },
  { title: '秋景诣瑯瑘精舍', author: '韦应物', poem: '屡访尘外迹，未穷幽赏情。\n高秋天景远，始见山水清。\n上陟岩殿憩，暮看云壑平。\n苍茫寒色起，迢递晚钟鸣。\n意有清夜恋，身为符守婴。\n悟言缁衣子，萧洒中林行。' },
  { title: '同韩郎中闲庭南望秋景', author: '韦应物', poem: '朝下抱余素，地高心本闲。\n如何趋府客，罢秩见秋山。\n疎树共寒意，游禽同暮还。\n因君悟清景，西望一开颜。' },
  { title: '慈恩精舍南池作', author: '韦应物', poem: '清境岂云远，炎氛忽如遗。\n重门布绿阴，菡萏满广池。\n石发散清浅，林光动涟漪。\n缘崖摘紫房，扣槛集灵龟。\n浥浥余露气，馥馥幽襟披。\n积喧忻物旷，耽玩觉景驰。\n明晨复趋府，幽赏当反思。' },
  { title: '雨夜宿清都观', author: '韦应物', poem: '灵飙动阊阖，微雨洒瑶林。\n复此新秋夜，高阁正沈沈。\n旷岁恨殊迹，兹夕一披襟。\n洞户含凉气，网轩构层阴。\n况自展良友，芳罇遂盈斟。\n适悟委前妄，清言怡道心。\n岂恋腰间绶，如彼笼中禽。' },
  { title: '善福精舍秋夜迟诸君', author: '韦应物', poem: '广庭独闲步，夜色方湛然。\n丹阁已排云，皓月更高悬。\n繁露降秋节，苍林郁芊芊。\n仰观天气凉，高咏古人篇。\n抚己亮无庸，结交赖群贤。\n属予翘思时，方子中夜眠。\n相去隔城阙，佳期屡徂迁。\n如何日夕待，见月三四圆。' },
  { title: '东郊', author: '韦应物', poem: '吏舍跼终年，出郊旷清曙。\n杨柳散和风，青山澹吾虑。\n依丛适自憩，缘涧还复去。\n微雨霭芳原，春鸠鸣何处？\n乐幽心屡止，遵事迹犹遽。\n终罢斯结庐，慕陶真可庶。' },
  { title: '秋郊作', author: '韦应物', poem: '清露澄境远，旭日照林初。\n一望秋山净，萧条形迹疎。\n登原忻时稼，采菊行故墟。\n方愿沮溺耦，淡泊守田庐。' },
  { title: '行宽禅师院', author: '韦应物', poem: '北望极长廊，斜扉映藂竹。\n亭午一来寻，院幽僧亦独。\n唯闻山鸟啼，爱此林下宿。' },
  { title: '神静师院', author: '韦应物', poem: '青苔幽巷徧，新林露气微。\n经声在深竹，高斋独掩扉。\n憩树爱岚岭，听禽悦朝晖。\n方耽静中趣，自与尘事违。' },
  { title: '精舍纳凉', author: '韦应物', poem: '山景寂已晦，野寺变苍苍。\n夕风吹高殿，露叶散林光。\n清钟始戒夜，幽禽尚归翔。\n谁复掩扉卧，不咏南轩凉。' },
  { title: '蓝岭精舍', author: '韦应物', poem: '石壁精舍高，排云聊直上。\n佳游惬始愿，忘险得前赏。\n崖倾景方晦，谷转川如掌。\n绿林含萧条，飞阁起弘敞。\n道人上方至，清夜还独往。\n日落群山阴，天秋百泉响。\n所嗟累已成，安得长偃仰。' },
  { title: '道晏寺主院', author: '韦应物', poem: '北邻有幽竹，潜筠穿我庐。\n往来地已密，心乐道者居。\n残花廻往节，轻条荫夏初。\n闻钟北牕起，啸傲永日余。' },
  { title: '义演法师西斋', author: '韦应物', poem: '结茅临绝岸，隔水闻清磬。\n山水旷萧条，登临散情性。\n稍指缘原骑，还寻汲涧迳。\n长啸倚亭树，怅然川光暝。' },
  { title: '澄秀上座院', author: '韦应物', poem: '缭绕西南隅，鸟声转幽静。\n秀公今不在，独礼高僧影。\n林下器未收，何人适煮茗。' },
  { title: '至西峰兰若受田妇馈', author: '韦应物', poem: '攀崖复缘涧，遂造幽人居。\n鸟鸣泉谷暖，土起萌甲舒。\n聊登石楼憩，下玩潭中鱼。\n田妇有嘉献，泼撒新岁余。\n常怪投钱饮，事与贤达疎。\n今我何为答，鳏寡欲焉如。' },
  { title: '昙智禅师院', author: '韦应物', poem: '高年不复出，门径众草生。\n时夏方新雨，果药发余荣。\n疎澹下林景，流暮幽禽情。\n身名两俱遣，独此野寺行。' },
  { title: '起度律师同居东斋院', author: '韦应物', poem: '释子喜相偶，幽林俱避喧。\n安居同僧夏，清夜讽道言。\n对阁景恒晏，步庭阴始繁。\n逍遥无一事，松风入南轩。' },
  { title: '游瑯瑘山寺', author: '韦应物', poem: '受命恤人隐，兹游久未遑。\n鸣驺响幽涧，前旌耀崇冈。\n青冥台砌寒，绿褥草木香。\n填壑跻花界，叠石构云房。\n经制随岩转，缭绕岂定方。\n新泉泄阴壁，高萝荫绿塘。\n攀林一栖止，饮水得清凉。\n物累诚可遣，疲甿终未忘。\n还归坐郡阁，但见山苍苍。' },
  { title: '同越瑯瑘山', author: '韦应物', poem: '石门有雪无形迹，松壑凝烟满众香。\n余食施庭寒鸟下，破衣挂树老僧亡。' },
  { title: '诣西山深师', author: '韦应物', poem: '曹溪旧弟子，何缘住此山。\n世有征战事，心将流水闲。\n埽林驱虎出，宴坐一林间。\n藩守宁为重，拥骑造云关。' },
  { title: '寻简寂观瀑布', author: '韦应物', poem: '蹑石欹危过急涧，攀崖迢递弄悬泉。\n犹将虎竹为身累，欲付归人绝世缘。' },
  { title: '简寂观西涧瀑布下作', author: '韦应物', poem: '淙流绝壁散，虚烟翠涧深。\n丛际松风起，飘来洒尘襟。\n窥萝玩猿鸟，解组傲云林。\n茶果邀真侣，觞酌洽同心。\n旷岁怀兹赏，行春始重寻。\n聊将横吹笛，一写山水音。' },
  { title: '游南斋', author: '韦应物', poem: '池上鸣佳禽，僧斋日幽寂。\n高林晚露清，红药无人摘。\n春水不生烟，荒冈筠翳石。\n不应朝夕游，良为蹉跎客。' },
  { title: '南园', author: '韦应物', poem: '清露夏天晓，荒园野气通。\n水禽遥泛雪，池莲迥披红。\n幽林讵知暑，环舟似不穷。\n顿洒尘喧意，长啸满襟风。' },
  { title: '西亭', author: '韦应物', poem: '亭宇丽朝景，帘牖散暄风。\n小山初构石，珍树正然红。\n弱藤已扶树，幽兰欲成丛。\n芳心幸如此，佳人时不同。' },
  { title: '夏景园庐', author: '韦应物', poem: '群木昼阴静，北牕凉气多。\n闲居逾时节，夏云已嵯峨。\n搴叶爱繁绿，缘涧弄惊波。\n岂为论夙志，对此青山阿。' },
  { title: '夏至避暑北池', author: '韦应物', poem: '昼晷已云极，宵漏自此长。\n未及施政教，所忧变炎凉。\n公门日多暇，是月农稍忙。\n高居念田里，苦热安可当。\n亭午息群物，独游爱方塘。\n门闭阴寂寂，城高树苍苍。\n绿筠尚含粉，圆荷始散芳。\n于焉洒烦抱，可以对华觞。' },
  { title: '题从姪成绪西林精舍书斋', author: '韦应物', poem: '栖身齿多暮，息心君独少。\n慕谢始精文，依僧欲观妙。\n冽泉前堦注，清池北窗照。\n果药杂芬敷，松筠疎蒨峭。\n屡跻幽人境，每肆芳辰眺。\n采栗玄猿窟，撷芝丹林峤。\n纻衣岂寒御，蔬食非饥疗。\n虽甘巷北单，岂塞青紫耀。\n郡有优贤榻，朝编贡士诏。\n欲同朱轮载，勿惮移文诮。' },
  { title: '题郑弘宪侍御遗爱草堂', author: '韦应物', poem: '居士近依僧，青山结茅屋。\n疎松映岚晚，春池含苔绿。\n繁华冒阳岭，新禽响幽谷。\n长啸攀乔林，慕兹高世躅。' },
  { title: '同元锡题瑯瑘寺', author: '韦应物', poem: '适从郡邑喧，又兹三伏热。\n山中清景多，石罅寒泉洁。\n花香天界事，松竹人间别。\n殿分岚岭明，磴临悬壑绝。\n昏旭穷陟降，幽显尽披阅。\n嵚骇风雨区，寒知龙蛇穴。\n情虚澹泊生，境寂尘妄灭。\n经世岂非道，无为厌车辙。' },
  { title: '题郑拾遗草堂', author: '韦应物', poem: '借地结茅栋，横竹挂朝衣。\n秋园雨中绿，幽居尘事违。\n阴井夕虫乱，高林霜果稀。\n子有白云意，构此想岩扉。' },
  { title: '咏玉', author: '韦应物', poem: '乾坤有精物，至宝无文章。\n雕琢为世器，真性一朝伤。' },
  { title: '咏露珠', author: '韦应物', poem: '秋荷一滴露，清夜坠玄天。\n将来玉盘上，不定始知圆。' },
  { title: '咏水精', author: '韦应物', poem: '映物随颜色，含空无表里。\n持来向明月，的皪愁成水。' },
  { title: '咏珊瑚', author: '韦应物', poem: '绛树无花叶，非石亦非琼。\n世人何处得，蓬莱石上生。' },
  { title: '咏瑠璃', author: '韦应物', poem: '有色同寒冰，无物隔纤尘。\n象筵看不见，堪将对玉人。' },
  { title: '咏琥珀', author: '韦应物', poem: '曾为老茯神，本是寒松液。\n蚊蚋落其中，千年犹可觌。' },
  { title: '咏晓', author: '韦应物', poem: '军中始吹角，城上河初落。\n深沈犹隐帷，晃朗先分阁。' },
  { title: '咏夜', author: '韦应物', poem: '明从何处去，暗从何处来。\n但觉年年老，半是此中催。' },
  { title: '咏声', author: '韦应物', poem: '万物自生听，太空恒寂寥。\n还从静中起，却向静中消。' },
  { title: '任洛阳丞请告一首', author: '韦应物', poem: '方凿不受圆，直木不为轮。\n揆材各有用，反性生苦辛。\n折腰非吾事，饮水非吾贫。\n休告卧空馆，养病绝嚣尘。\n游鱼自成族，野鸟亦有群。\n家园杜陵下，千岁心氛氲。\n天晴嵩山高，雪后河洛春。\n乔木犹未芳，百草日已新。\n著书复何为，当去东臯耘。' },
  { title: '县斋', author: '韦应物', poem: '仲春时景好，草木渐舒荣。\n公门且无事，微雨园林清。\n决决水泉动，忻忻众鸟鸣。\n闲斋始延瞩，东作兴庶甿。\n既事玩文墨，抱冲披道经。\n于焉日淡泊，徒使芳尊盈。' },
  { title: '晚出府舍与独孤兵曹令狐士曹南寻朱雀街归里第', author: '韦应物', poem: '分曹幸同简，联骑方惬素。\n还从广陌归，不觉青山暮。\n翻翻鸟未没，杳杳钟犹度。\n寻草远无人，望山多枉路。\n聊参世士迹，尝得静者顾。\n出入虽见牵，忘身缘所晤。' },
  { title: '休暇东斋', author: '韦应物', poem: '由来束带士，请谒无朝暮。\n公暇及私身，何能独闲步。\n摘叶爱芳在，扪竹怜粉汚。\n岸帻偃东斋，夏天清晓露。\n怀仙阅真诰，贻友题幽素。\n荣达颇知疎，恬然自成度。\n绿苔日已满，幽寂谁来顾。' },
  { title: '夜直省中', author: '韦应物', poem: '河汉有秋意，南宫生早凉。\n玉漏殊杳杳，云阙更苍苍。\n华灯发新燄，轻烟浮夕香。\n顾迹知为忝，束带愧周行。' },
  { title: '郡内闲居', author: '韦应物', poem: '栖息绝尘侣，孱钝得自怡。\n腰悬竹使符，心与庐山缁。\n永日一酣寝，起坐兀无思。\n长廊独看雨，众药发幽姿。\n今夕已云罢，明晨复如斯。\n何事能为累，宠辱岂要辞。' },
  { title: '燕居即事', author: '韦应物', poem: '萧条竹林院，风雨丛兰折。\n幽鸟林上啼，青苔人迹绝。\n燕居日已永，夏木纷成结。\n几阁积群书，时来北窗阅。' },
  { title: '幽居', author: '韦应物', poem: '贵贱虽异等，出门皆有营。\n独无外物牵，遂此幽居情。\n微雨夜来过，不知春草生。\n青山忽已曙，鸟雀绕舍鸣。\n时与道人偶，或随樵者行。\n自当安蹇劣，谁谓薄世荣。' },
  { title: '野居书情', author: '韦应物', poem: '世事日可见，身名良蹉跎。\n尚瞻白云岭，聊作负薪歌。' },
  { title: '郊居言志', author: '韦应物', poem: '负暄衡门下，望云归远山。\n但要尊中物，余事岂相关。\n交无是非责，且得任疎顽。\n日夕临清涧，逍遥思虑闲。\n出去唯空屋，弊箦委窗间。\n何异林栖鸟，恋此复来还。\n世荣斯独已，颓志亦何攀。\n唯当岁丰熟，闾里一欢颜。' },
  { title: '夏景端居即事', author: '韦应物', poem: '北斋有凉气，嘉树对层城。\n重门永日掩，清池夏云生。\n遇此庭讼简，始闻蝉初鸣。\n逾怀故园怆，默默以缄情。' },
  { title: '始至郡', author: '韦应物', poem: '湓城古雄郡，横江千里驰。\n高树上迢递，峻堞绕欹危。\n井邑烟火晚，郊原草树滋。\n洪流荡北阯，崇岭郁南圻。\n斯民本乐生，逃逝竟何为。\n旱岁属荒歉，旧逋积如坻。\n到郡方逾月，终朝理乱丝。\n宾朋未及䜩，简牍已云疲。\n昔贤播高风，得守愧无施。\n岂待干戈戢，且愿抚惸嫠。' },
  { title: '郡中西斋', author: '韦应物', poem: '似与尘境绝，萧条斋舍秋。\n寒花独经雨，山禽时到州。\n清觞养真气，玉书示道流。\n岂将符守恋，幸已栖心幽。' },
  { title: '新理西斋', author: '韦应物', poem: '方将甿讼理，久翳西斋居。\n草木无行次，闲暇一芟除。\n春阳土脉起，膏泽发生初。\n养条刊朽枿，护药锄秽芜。\n稍稍觉林耸，历历忻竹疎。\n始见庭宇旷，顿令烦抱舒。\n兹焉即可爱，何必是吾庐。' },
  { title: '晓坐西斋', author: '韦应物', poem: '冬冬城鼓动，稍稍林鵶去。\n柳意不胜春，岩光已知曙。\n寝斋有单祶，灵药为朝茹。\n盥漱忻景清，焚香澄神虑。\n公门自常事，道心宁易处。' },
  { title: '郡斋卧疾绝句', author: '韦应物', poem: '香炉宿火灭，兰灯宵影微。\n秋斋独卧病，谁与覆寒衣。' },
  { title: '寓居永定精舍', author: '韦应物', poem: '政拙忻罢守，闲居初理生。\n家贫何由往，梦想在京城。\n野寺霜露月，农兴羁旅情。\n聊租二顷田，方课子弟耕。\n眼暗文字废，身闲道心精。\n即与人群远，岂谓是非婴。' },
  { title: '永定寺喜辟强夜至', author: '韦应物', poem: '子有新岁庆，独此苦寒归。\n夜叩竹林寺，山行雪满衣。\n深炉正燃火，空斋共掩扉。\n还将一尊对，无言百事违。' },
  { title: '野居', author: '韦应物', poem: '结发屡辞秩，立身本疎慢。\n今得罢守归，幸无世欲患。\n栖止且偏僻，嬉游无早晏。\n逐兔上坡冈，捕鱼缘赤涧。\n高歌意气在，贳酒贫居惯。\n时启北窗扉，岂将文墨间。' },
  { title: '同襃子秋斋独宿', author: '韦应物', poem: '山月皎如烛，风霜时动竹。\n夜半鸟惊栖，窗间人独宿。' },
  { title: '饵黄精', author: '韦应物', poem: '灵药出西山，服食采其根。\n九蒸换凡骨，经着上世言。\n候火起中夜，馨香满南轩。\n斋居感众灵，药术启妙门。\n自怀物外心，岂与俗士论。\n终期脱印绶，永与天壤存。' },
  { title: '昭国里第听元老师弹琴', author: '韦应物', poem: '竹林高宇霜露清，朱丝玉徽多故情。\n暗识啼乌与别鹤，秪缘中有断肠声。' },
  { title: '野次听元昌奏横吹', author: '韦应物', poem: '立马莲塘吹横笛，微风动柳生水波。\n北人听罢泪将落，南朝曲中怨更多。' },
  { title: '楼中阅清管', author: '韦应物', poem: '山阳遗韵在，林端横吹惊。\n响迥凭高阁，曲怨绕秋城。\n淅沥危叶振，萧瑟凉气生。\n始遇兹管赏，已怀故园情。' },
  { title: '寒食', author: '韦应物', poem: '晴明寒食好，春园百卉开。\n彩绳拂花去，轻毬度阁来。\n长歌送落日，缓吹逐残杯。\n非关无烛罢，良为羁思催。' },
  { title: '七夕', author: '韦应物', poem: '人世拘形迹，别去间山川。\n岂意灵仙偶，相望亦弥年。\n夕衣清露湿，晨驾秋风前。\n临欢定不住，当为何所牵。' },
  { title: '九日', author: '韦应物', poem: '今朝把酒复惆怅，忆在杜陵田舍时。\n明年九日知何处，世难还家未有期。' },
  { title: '秋夜', author: '韦应物', poem: '暗窗凉叶动，秋天寝席单。\n忧人半夜起，明月在林端。\n一与清景遇，每忆平生欢。\n如何方恻怆，披衣露更寒。' },
  { title: '秋夜一绝', author: '韦应物', poem: '高阁渐凝露，凉叶稍飘闱。\n忆在南宫直，夜长钟漏稀。' },
  { title: '滁城对雪', author: '韦应物', poem: '晨起满闱雪，忆朝阊阖时。\n玉座分曙早，金炉上烟迟。\n飘散云台下，凌乱桂树姿。\n厕迹鸳鹭末，蹈舞丰年期。\n今朝覆山郡，寂寥复何为。' },
  { title: '雪中', author: '韦应物', poem: '空堂岁已晏，密室独安眠。\n厌筿夜偏积，覆阁晓逾妍。\n连山暗古郡，惊风散一川。\n此时骑马出，忽省京华年。' },
  { title: '咏春雪', author: '韦应物', poem: '裴回轻雪意，似惜艳阳时。\n不悟风花冷，翻令梅柳迟。' },
  { title: '对春雪', author: '韦应物', poem: '萧屑杉松声，寂寥寒夜虑。\n州贫人吏稀，雪满山城曙。\n春塘看幽谷，栖禽愁未去。\n开闱正乱流，宁辨花枝处。' },
  { title: '对残灯', author: '韦应物', poem: '独照碧窗久，欲随寒烬灭。\n幽人将遽眠，解带翻成结。' },
  { title: '对芳尊', author: '韦应物', poem: '对芳尊，醉来百事何足论。\n遥见青山始一醒，欲着接[䍠]还复昏。' },
  { title: '夜对流萤作', author: '韦应物', poem: '月暗竹亭幽，萤光拂席流。\n还思故园夜，更度一年秋。\n自惬观书兴，何慙秉烛游。\n府中徒冉冉，明发好归休。' },
  { title: '对新篁', author: '韦应物', poem: '新绿苞初解，嫩气笋犹香。\n含露渐舒叶，抽丛稍自长。\n清晨止亭下，独爱此幽篁。' },
  { title: '夏花明', author: '韦应物', poem: '夏条绿已密，朱蕚缀明鲜。\n炎炎日正午，灼灼火俱燃。\n翻风适自乱，照水复成妍。\n归视窗间字，荧煌满眼前。' },
  { title: '对萱草', author: '韦应物', poem: '何人树萱草，对此郡斋幽。\n本是忘忧物，今夕重生忧。\n丛疎露始滴，芳余蝶尚留。\n还思杜陵圃，离披风雨秋。' },
  { title: '见紫荆花', author: '韦应物', poem: '杂英纷已积，含芳独暮春。\n还如故园树，忽忆故园人。' },
  { title: '玩萤火', author: '韦应物', poem: '时节变衰草，物色近新秋。\n度月影才敛，绕竹光复流。' },
  { title: '对杂花', author: '韦应物', poem: '朝红争景新，夕素含露翻。\n妍姿如有意，流芳复满园。\n单栖守远郡，永日掩重门。\n不与花为偶，终遣与谁言。' },
  { title: '种药', author: '韦应物', poem: '好读神农书，多识药草名。\n持缣购山客，移莳罗众英。\n不改幽涧色，宛如此地生。\n汲井既蒙泽，插楥亦扶倾。\n阴颖夕房敛，阳条夏花明。\n悦玩从兹始，日夕绕庭行。\n州民自寡讼，养闲非政成。' },
  { title: '西涧种柳', author: '韦应物', poem: '宰邑乖所愿，僶俛愧昔人。\n聊将休暇日，种柳西涧滨。\n置锸息微倦，临流睇归云。\n封壤自人力，生条在阳春。\n成阴岂自取，为茂属佗辰。\n延咏留佳赏，山水变夕曛。' },
  { title: '种瓜', author: '韦应物', poem: '率性方卤莽，理生尤自疎。\n今年学种瓜，园圃多荒芜。\n众草同雨露，新苗独翳如。\n直以春窘迫，过时不得锄。\n田家笑枉费，日夕转空虚。\n信非吾侪事，且读古人书。' },
  { title: '喜园中茶生', author: '韦应物', poem: '洁性不可污，为饮涤尘烦。\n此物信灵味，本自出山原。\n聊因理郡余，率尔植荒园。\n喜随众草长，得与幽人言。' },
  { title: '移海榴', author: '韦应物', poem: '叶有苦寒色，山中霜霰多。\n虽此蒙阳景，移根意如何。' },
  { title: '郡斋移杉', author: '韦应物', poem: '[擢]干方数尺，幽姿已苍然。\n结根西山寺，来植郡斋前。\n新含野露气，稍静高窗眠。\n虽为赏心遇，岂有岩中缘。' },
  { title: '花径', author: '韦应物', poem: '山花夹径幽，古甃生苔涩。\n胡床理事余，玉琴承露湿。\n朝与诗人赏，夜携禅客入。\n自是尘外踪，无令吏趋急。' },
  { title: '慈恩寺南池秋荷咏', author: '韦应物', poem: '对殿含凉气，裁规覆清沼。\n衰红受露多，余馥依人少。\n萧萧远尘迹，飒飒凌秋晓。\n节谢客来稀，回塘方独遶。' },
  { title: '题桐叶', author: '韦应物', poem: '参差剪绿绮，潇洒覆琼柯。\n忆在沣东寺，偏书此叶多。' },
  { title: '题石桥', author: '韦应物', poem: '远学临海峤，横此莓苔石。\n郡斋三四峰，如有灵仙迹。\n方愁暮云滑，始照寒池碧。\n自与幽人期，逍遥竟朝夕。' },
  { title: '池上', author: '韦应物', poem: '郡中卧病久，池上一来赊。\n榆柳飘枯叶，风雨倒横查。' },
  { title: '滁州西涧', author: '韦应物', poem: '独怜幽草涧边生，上有黄鹂深树鸣。\n春潮带雨晚来急，野渡无人舟自横。' },
  { title: '西塞山', author: '韦应物', poem: '势从千里奔，直入江中断。\n岚横秋塞雄，地束惊流满。' },
  { title: '山耕叟', author: '韦应物', poem: '萧萧垂白发，默默讵知情。\n独放寒林烧，多寻虎迹行。\n暮归何处宿？来此空山耕。' },
  { title: '上方僧', author: '韦应物', poem: '见月出东山，上方高处禅。\n空林无宿火，独夜汲寒泉。\n不下蓝溪寺，今年三十年。' },
  { title: '烟际钟', author: '韦应物', poem: '隐隐起何处，迢迢送落晖。\n苍茫随思远，萧散逐烟微。\n秋野寂云晦，望山僧独归。' },
  { title: '始闻夏蝉', author: '韦应物', poem: '徂夏暑未晏，蝉鸣景已曛。\n一听知何处，高树但侵云。\n响悲遇衰齿，节谢属离群。\n还忆郊园日，独向涧中闻。' },
  { title: '射雉', author: '韦应物', poem: '走马上东冈，朝日照野田。\n野田双雉起，翻射斗回鞭。\n虽无百发中，聊取一笑妍。\n羽分绣臆碎，头弛锦鞘悬。\n方将悦羁旅，非关学少年。\n弢弓一长啸，忆在灞城阡。' },
  { title: '夜闻独鸟啼', author: '韦应物', poem: '失侣度山觅，投林舍北啼。\n今将独夜意，偏知对影栖。' },
  { title: '述园鹿', author: '韦应物', poem: '野性本难畜，玩习亦逾年。\n麑班始力直，麚角已苍然。\n仰首嚼园柳，俯身饮清泉。\n见人若闲暇，蹶起忽低骞。\n兹兽有高貌，凡类宁比肩。\n不得游山泽，跼促诚可怜。' },
  { title: '闻鴈', author: '韦应物', poem: '故园眇何处，归思方悠哉。\n淮南秋雨夜，高斋闻鴈来。' },
  { title: '子规啼', author: '韦应物', poem: '高林滴露夏夜清，南山子规啼一声。\n邻家孀妇抱儿泣，我独展转何时明。' },
  { title: '始建射侯', author: '韦应物', poem: '男子本悬弧，有志在四方。\n虎竹忝明命，熊侯始张皇。\n宾登时事毕，诸将备戎装。\n星飞的屡破，鼓噪武更扬。\n曾习邹鲁学，亦陪鸳鹭翔。\n一朝愿投笔，世难激中肠。' },
  { title: '仙人祠', author: '韦应物', poem: '苍岑古仙子，清庙閟华容。\n千载去寥廓，白云遗旧踪。\n归来灞陵上，犹见最高峰。' },
  { title: '鹧鸪啼', author: '韦应物', poem: '可怜鹧鸪飞，飞向树南枝。\n南枝日照暖，北枝霜露滋。\n露滋不堪栖，使我夜常啼。\n愿逢云中鹤，衔我向寥廓。\n愿作城上乌，一年生九雏。\n何不旧巢住，枝弱不得去。\n何意道苦辛，客子常畏人。' },
  { title: '长安道', author: '韦应物', poem: '汉家宫殿含云烟，两宫十里相连延。\n晨霞出没弄丹阙，春雨依微自甘泉。\n春雨依微春尚早，长安贵游爱芳草。\n宝马横来下建章，香车却转避驰道。\n贵游谁最贵，卫霍世难比。\n何能蒙主恩，幸遇边尘起。\n归来甲第拱皇居，朱门峨峨临九衢。\n中有流苏合欢之宝帐，一百二十凤凰罗列含明珠。\n下有锦铺翠被之粲烂，博山吐香五云散。\n丽人绮阁情飘飖，头上鸳钗双翠翘。\n低鬟曳袖回春雪，聚黛一声愁碧霄。\n山珍海错弃藩篱，烹犊炰羔如折葵。\n既请列侯封部曲，还将金印授庐儿。\n欢荣若此何所苦，但苦白日西南驰。' },
  { title: '行路难', author: '韦应物', poem: '荆山之白玉兮，良工雕琢双环连，月蚀中央镜心穿。\n故人赠妾初相结，恩在环中寻不绝。\n人情厚薄苦须臾，昔似连环今似玦。\n连环可碎不可离，如何物在人自移。\n上客勿遽欢，听妾歌路难。\n旁人见环环可怜，不知中有长恨端。' },
  { title: '横塘行', author: '韦应物', poem: '妾家住横塘，夫壻郗家郎。\n玉盘的历双白鱼，宝簟玲珑透象床。\n象床可寝鱼可食，不知郎意何南北。\n岸上种莲岂得生，池中种槿岂得成。\n丈夫一去花落树，妾独夜长心未平。' },
  { title: '贵游行', author: '韦应物', poem: '汉帝外家子，恩泽少封侯。\n垂杨拂白马，晓日上青楼。\n上有颜如玉，高情世无俦。\n轻裾含碧烟，窈窕似云浮。\n良时无还景，促节为我讴。\n忽闻艳阳曲，四坐亦已柔。\n宾友仰称叹，一生何所求。\n平明击钟食，入夜乐未休。\n风雨愆岁候，兵戎横九州。\n焉知坐上客，草草心所忧。' },
  { title: '酒肆行', author: '韦应物', poem: '豪家沽酒长安陌，一旦起楼高百尺。\n碧疏玲珑含春风，银题彩帜邀上客。\n回瞻丹凤阙，直视乐游苑。\n四方称赏名已高，五陵车马无近远。\n晴景悠扬三月天，桃花飘俎柳垂筵。\n繁丝急管一时合，他垆邻肆何寂然。\n主人无厌且专利，百斛须臾一壶费。\n初𬪩后薄为大偷，饮者知名不知味。\n深门潜酝客来稀，终岁醇𬪩味不移。\n长安酒徒空扰扰，路傍过去那得知。' },
  { title: '相逢行', author: '韦应物', poem: '二十登汉朝，英声迈今古。\n适从东方来，又欲谒明主。\n犹酣新丰酒，尚带灞陵雨。\n邂逅两相逢，别来问寒暑。\n宁知白日晚，暂向花间语。\n忽闻长乐钟，走马东西去。' },
  { title: '乌引雏', author: '韦应物', poem: '日出照东城，春乌鵶鵶雏和鸣。\n雏和鸣，羽犹短，巢在深林春正寒，引飞欲集东城暖。\n群雏䙰褷睥睨高，举翅不及坠蓬蒿。\n雄雌来去飞又引，音声上下惧鹰隼。\n引雏乌，尔心急将何如，何得比日搜索雀卵噉尔雏。' },
  { title: '鸢夺巢', author: '韦应物', poem: '野鹊野鹊巢林梢，鸱鸢恃力夺鹊巢。\n吞鹊之肝啄鹊脑，窃食偷居还自保。\n凤凰五色百鸟尊，知鸢为害何不言？\n霜鹯野鹞得残肉，同啄膻腥不肯逐。\n可怜百鸟纷纵横，虽有深林何处宿。' },
  { title: '燕啣泥', author: '韦应物', poem: '啣泥燕，声喽喽。\n尾涎涎，秋去何所归。\n春来复相见，岂不解决绝高飞碧云里。\n何为地上啣泥滓，衔泥虽贱意有营。\n杏梁朝日巢欲成，不见百鸟畏人林野宿。\n翻遭网罗俎其肉，未若衔泥入华屋。\n燕衔泥，百鸟之智莫与齐。' },
  { title: '鼙鼓行', author: '韦应物', poem: '淮海生云暮惨澹，广陵城头颦鼓暗。\n寒声坎坎风动边，忽似孤城万里绝，四望无人烟。\n又如虏骑截辽水，胡马不食仰朔天。\n座中亦有燕赵士，闻颦不语客心死。\n何况鳏孤火绝无晨炊，独妇夜泣官有期。' },
  { title: '古剑行', author: '韦应物', poem: '千年土中两刃铁，土蚀不入金星灭。\n沈沈青脊鳞甲满，蛟龙无足蛇尾断。\n忽欲飞动中有灵，豪士得之敌国宝。\n仇家举意半夜鸣，小儿女子不可近。\n龙蛇变化此中隐，夏云奔走雷阗阗，恐成霹雳飞上天。' },
  { title: '金谷园歌', author: '韦应物', poem: '石氏灭，金谷园中水流绝。\n当时豪右争骄侈，锦为步障四十里。\n东风吹花雪满川，紫气凝阁朝景妍。\n洛阳陌上人回首，丝竹飘飖入青天。\n晋武平吴恣欢燕，余风靡靡朝廷变。\n嗣世衰微谁肯忧，二十四友日日空追游。\n追游讵可足，共惜年华促。\n祸端一发埋恨长，百草无情春自绿。' },
  { title: '温泉行', author: '韦应物', poem: '出身天宝今年几，顽钝如锤命如纸。\n作官不了却来归，还是杜陵一男子。\n北风惨惨投温泉，忽忆先皇游幸年。\n身骑廐马引天仗，直入华清列御前。\n玉林瑶雪满寒山，上升玄阁游绛烟。\n平明羽卫朝万国，车马合沓溢四鄽。\n蒙恩每浴华池水，扈猎不蹂渭北田。\n朝廷无事共欢燕，美人丝管从九天。\n一朝铸鼎降龙驭，小臣髯绝不得去。\n今来萧瑟万井空，唯见苍山起烟雾。\n可怜蹭蹬失风波，仰天大呌无奈何。\n弊裘羸马冻欲死，赖遇主人杯酒多。' },
  { title: '学仙二首 一', author: '韦应物', poem: '昔有道士求神仙，灵真下试心确然。\n千[钧]巨石一发悬，卧之石下十三年。\n存道忘身一试过，名奏玉皇乃升天。\n云气冉冉渐不见，留语弟子但精坚。' },
  { title: '学仙二首 二', author: '韦应物', poem: '石上凿井欲到水，惰心一起中路止。\n岂不见古来三人俱弟兄，结茅深山读仙经。\n上有青冥倚天之绝壁，下有飕飗万壑之松声。\n仙人变化为白鹿，二弟玩之兄诵读。\n读多七过可乞言，为子心精得神仙。\n可怜二弟仰天泣，一失毫厘千万年。' },
  { title: '广陵行', author: '韦应物', poem: '雄藩镇楚郊，地势郁岧峣。\n双旌拥万戟，中有霍嫖姚。\n海云助兵气，宝货益军饶。\n严城动寒角，晚骑踏霜桥。\n翕习英豪集，振夺士卒骁。\n列郡何足数，趋拜等卑寮。\n日宴方云罢，人逸马萧萧。\n忽如京洛间，游子风尘飘。\n归来视宝剑，功名岂一朝。' },
  { title: '萼绿华歌', author: '韦应物', poem: '有一人兮升紫霞，书名玉牒兮蕚绿华。\n仙容矫矫兮杂瑶珮，轻衣重重兮蒙绛纱。\n云雨愁思兮望淮海，鼓吹萧条兮驾龙车。\n世淫浊兮不可降，胡不来兮玉斧家。' },
  { title: '王母歌', author: '韦应物', poem: '众仙翼神母，羽盖随云起。\n上游玄极杳冥中，下看东海一杯水。\n海畔种桃经几时，千年开花千年子。\n玉颜眇眇何处寻，世上茫茫人自死。' },
  { title: '马明生遇神女歌', author: '韦应物', poem: '学仙贵功亦贵精，神女变化感马生。\n石壁千寻启双检，中有玉堂铺玉簟。\n立之一隅不与言，玉体安隐三日眠。\n马生一立心转坚，知其丹白蒙哀怜。\n安期先生来起居，请示金铛玉佩天皇书。\n神女呵责不合见，仙子谢过手足战。\n大瓜玄枣冷如冰，海上摘来朝霞凝。\n赐仙复坐对食讫，颔之使去随烟升。\n乃言马生合不死，少姑教勅令付尔。\n安期再拜将生出，一授素书天地毕。' },
  { title: '石鼓歌', author: '韦应物', poem: '周宣大猎兮岐之阳，刻石表功兮炜煌煌。\n石如鼓形数止十，风雨缺讹苔藓涩。\n今人濡纸脱其文，既击既埽白黑分。\n忽开满卷不可识，惊潜动蛰走云云。\n喘逶迤，相纠错，乃是宣王之臣史籀作。\n一书遗此天地间，精意长存世冥寞。\n秦家祖龙还刻石，碣石之罘李斯迹。\n世人好古犹共传，持来比此殊悬隔。' },
  { title: '宝观主白鸜鹆歌', author: '韦应物', poem: '鸜鹆鸜鹆，众皆如漆，尔独如玉。\n鸜之鹆之，众皆蓬蒿下。\n尔自三山来，三山处子下人间。\n绰约不妆冰雪颜，仙鸟随飞来掌上。\n来掌上，时拂拭。\n人心鸟意自无猜，玉指霜毛本同色。\n有时一去凌苍苍，朝游汗漫暮玉堂。\n巫峡雨中飞暂湿，杏花林里过来香。\n日夕依仁全羽翼，空欲衔环非报德。\n岂不及阿母之家青鸟儿，汉宫来往传消息。' },
  { title: '弹棋歌', author: '韦应物', poem: '圆天方地局，二十四气子。\n刘生绝艺难对曹，客为歌其能。\n请从中央起，中央转鬬破欲阑。\n零落势背谁能弹，此中举一得六七。\n旋风忽散霹雳疾，履机乘变安可当。\n置之死地翻取强，不见短兵反掌收已尽。\n唯有猛士守四方，四方又何难。\n横击且缘边，岂如昆明与碣石。\n一箭飞中隔远天，神安志惬动十全，满堂惊视谁得然。' },
  { title: '听莺曲', author: '韦应物', poem: '东方欲曙花冥冥，啼莺相唤亦可听。\n乍去乍来时近远，才闻南陌又东城。\n忽似上林翻下苑，绵绵蛮蛮如有情。\n欲啭不啭意自娇，羌儿弄笛曲未调。\n前声后声不相及，秦女学筝指犹涩。\n须臾风暖朝日暾，流音变作百鸟喧。\n谁家懒妇惊残梦，何处愁人忆故园？\n伯劳飞过声跼促，戴胜下时桑田绿。\n不及流莺日日啼花间，能使万家春意闲。\n有时断续听不了，飞去花枝犹袅袅。\n还栖碧树锁千门，春漏方残一声晓。' },
  { title: '白沙亭逢吴叟歌', author: '韦应物', poem: '龙池宫里上皇时，罗衫宝带香风吹。\n满朝豪士今已尽，欲话旧游人不知。\n白沙亭上逢吴叟，爱客脱衣且沽酒。\n问之执戟亦先朝，零落艰难却负樵。\n亲观文物蒙雨露，见我昔年侍丹霄。\n冬狩春祠无一事，欢游洽宴多颁赐。\n尝陪月夕竹宫斋，每返温泉灞陵醉。\n星岁再周十二辰，尔来不语今为君。\n盛时忽去良可恨，一生坎𡒄何足云。' },
  { title: '送褚校书归旧山歌', author: '韦应物', poem: '握珠不返泉，匣玉不归山。\n明皇重士亦如此，忽怪褚生何得还。\n方称羽猎赋，未拜兰台职。\n汉箧亡书已暗传，嵩丘遗简还能识。\n朝朝待诏青鏁闱，中有万年之树蓬莱池。\n世人仰望栖此地，生独徘徊意何为。\n故山可往薇可采，一自人间星岁改。\n藏书壁中苔半侵，洗药泉中月还在。\n春风饮饯灞陵原，莫厌归来朝市喧。\n不见东方朔，避世从容金马门。' },
  { title: '五弦行', author: '韦应物', poem: '美人为我弹五弦，尘埃忽静心悄然。\n古刀幽磬初相触，千珠贯断落寒玉。\n中曲又不喧，徘徊夜长月当轩。\n如伴风流萦艳雪，更逐落花飘御园。\n独凤寥寥有时隐，碧霄来下听还近。\n燕姬有恨楚客愁，言之不尽声能尽。\n末曲感我情，解幽释结和乐生。\n壮士有仇未得报，拔剑欲去愤已平。\n夜寒酒多愁遽明。' },
  { title: '骊山行', author: '韦应物', poem: '君不见开元至化垂衣裳，厌坐明堂朝万方。\n访道灵山降圣祖，沐浴华池集百祥。\n千乘万骑被原野，云霞草木相辉光。\n禁仗围山晓霜切，离宫积翠夜漏长。\n玉堦寂历朝无事，碧树萎蕤寒更芳。\n三清小鸟传仙语，九华真人奉琼浆。\n下元昧爽漏恒秩，登山朝礼玄元室。\n翠华稍隐天半云，丹阁光明海中日。\n羽旗旄节憩瑶台，清丝妙管从空来。\n万井九衢皆仰望，彩云白鹤方徘徊。\n凭高览古嗟寰宇，造化茫茫思悠哉。\n秦川八水长缭绕，汉氏五陵空崔嵬。\n乃言圣祖奉丹经，以年为日亿万龄。\n苍生咸寿阴阳泰，高谢前王出尘外。\n英豪共理天下晏，戎夷詟伏兵无战。\n时丰赋敛未告劳，海阔珍奇亦来献。\n干戈一起文武乖，欢娱已极人事变。\n圣皇弓剑坠幽泉，古木苍山闭宫殿。\n缵承鸿业圣明君，威震六合驱妖氛。\n太平游幸今可待，汤泉岚岭还氛氲。' },
  { title: '汉武帝杂歌三首 一', author: '韦应物', poem: '汉武好神仙，黄金作台与天近。\n王母摘桃海上还，感之西过聊问讯。\n欲来不来夜未央，殿前青鸟先回翔。\n绿鬓萦云裾曳雾，双节飘飖下仙步。\n白日分明到世间，碧空何处来时路。\n玉盘捧桃将献君，踟蹰未去留彩云。\n海水桑田几翻覆，中间此桃四五熟。\n可怜穆满瑶池燕，正值花开不得荐。\n花开子熟安可期，邂逅能当汉武时。\n颜如芳华洁如玉，心念我皇多嗜欲。\n虽留桃核桃有灵，人间粪土种不生。\n由来在道岂在药，徒劳方士海上行。\n掩扇一言相谢去，如烟非烟不知处。' },
  { title: '汉武帝杂歌三首 二', author: '韦应物', poem: '金茎孤峙兮凌紫烟，汉宫美人望杳然。\n通天台上月初出，承露盘中珠正圆。\n珠可饮，寿可永，武皇南面曙欲分。\n从空下来玉杯冷，世间彩翠亦作囊。\n八月一日仙人方，仙方称上药。\n静者服之常绰约，柏梁沈饮自伤神，犹闻驻颜七十春。\n乃知甘𬪩皆是腐肠物，独有淡泊之水能益人。\n千载金盘竟何处，当时铸金恐不固。\n蔓草生来春复秋，碧天何言空坠露。' },
  { title: '汉武帝杂歌三首 三', author: '韦应物', poem: '汉天子，观风自南国。\n浮舟大江屹不前，蛟龙索鬬风波黑。\n春秋方壮雄武才，弯弧叱浪连山开。\n愕然观者千万众，举麾齐呼一矢中。\n死蛟浮出不复灵，舳舻千里江水清。\n鼓颦余响数日在，天吴深入鱼鼈惊。\n左有佽飞落霜翮，右有孤儿贯犀革。\n何为临深亲射蛟，示威以夺诸侯魄。\n威可畏，皇可尊，平田校猎书犹陈。\n此日从臣何不言，独有威声振千古，君不见后嗣尊为武。' },
  { title: '椶榈蝇拂歌', author: '韦应物', poem: '椶榈为拂登君席，青蝇掩乱飞四壁。\n文如轻罗散如发，马尾牦牛不能絜。\n柄出湘江之竹碧玉寒，上有纤罗萦缕寻未绝。\n左挥右洒繁暑清，孤松一枝风有声。\n丽人纨素可怜色，安能点白还为黑。' },
  { title: '信州录事参军常曾古鼎歌', author: '韦应物', poem: '三年纠一郡，独饮寒泉井。\n江南铸器多铸银，罢官无物唯古鼎。\n雕螭刻篆相错盘，地中岁久青苔寒。\n左对苍山右流水，云有古来葛仙子。\n葛仙埋之何不还，耕者鎗然得其间。\n持示世人不知宝，劝君炼丹永寿考。' },
  { title: '夏冰歌', author: '韦应物', poem: '出自玄泉杳杳之深井，汲在朱明赫赫之炎辰。\n九天含露未销铄，阊阖初开赐贵人。\n碎如坠琼方截璐，粉壁生寒象筵布。\n玉壶纨扇亦玲珑，座有丽人色俱素。\n咫尺炎凉变四时，出门焦灼君讵知。\n肥羊甘醴心闷闷，饮此莹然何所思。\n当念阑干凿者苦，腊月深井汗如雨。' },
  { title: '鼋头山神女歌', author: '韦应物', poem: '鼋头之山，直上洞庭连青天。\n苍苍烟树闭古庙，中有蛾眉成水仙。\n水府沈沈行路绝，蛟龙出没无时节。\n魂同魍魉潜太阴，身与空山长不灭。\n东晋永和今几代，云发素颜犹盼睐。\n阴深灵气静凝美，的砾龙绡杂琼珮。\n山精木魅不敢亲，昏明想像如有人。\n蕙兰琼芳积烟露，碧窗松月无冬春。\n舟客经过奠椒醑，巫女南音歌激楚。\n碧水冥空惟鸟飞，长天何处云随雨。\n红渠绿苹芳意多，玉灵荡漾凌清波。\n孤峰绝岛俨相向，鬼啸猿啼垂女萝。\n皓雪琼枝殊异色，北方绝代徒倾国。\n云没烟销不可期，明堂翡翠无人得。\n精灵变态状无方，游龙宛转惊鸿翔。\n湘妃独立九疑暮，汉女菱歌春日长。\n始知仙事无不有，可惜吴宫空白首。' },
  { title: '寇季膺古刀歌', author: '韦应物', poem: '古刀寒锋青槭槭，少年交结平陵客。\n求之时代不可知，千痕万穴如星离。\n重叠泥沙更剥落，纵横鳞甲相参差。\n古物有灵知所适，貂裘拂之横广席。\n阴森白日掩云虹，错落池光动金碧。\n知君宝此夸绝代，求之不得心常爱。\n厌见今时绕指柔，片锋折刃犹堪佩。\n高山成谷苍海填，英豪埋没谁所捐。\n吴钩断马不知处，几度烟尘今独全。\n夜光投人人不畏，知君独识精灵器。\n酬恩结思心自知，死生好恶不相弃。\n白虎司秋金气清，高天寥落云峥嵘。\n月肃风凄古堂净，精芒切切如有声。\n何不跨蓬莱，斩长鲸？\n世人所好殊辽阔，千金买铅徒一割。' },
  { title: '凌雾行', author: '韦应物', poem: '秋城海雾重，职事凌晨出。\n浩浩合元天，溶溶迷朗日。\n才看含鬓白，稍视沾衣密。\n道骑全不分，郊树都如失。\n霏微误嘘吸，肤腠生寒栗。\n归当饮一杯，庶用蠲斯疾。' },
  { title: '乐燕行', author: '韦应物', poem: '良辰且燕乐，乐往不再来。\n赵瑟正高张，音响清尘埃。\n一弹和妙讴，吹去绕瑶台。\n艳云凌空散，舞罗起徘徊。\n辉辉发众颜，灼灼叹令才。\n当喧既无寂，中饮亦停杯。\n华灯何遽升，驰景忽西颓。\n高节亦云立，安能滞不回。' },
  { title: '采玉行', author: '韦应物', poem: '官府征白丁，言采蓝谿玉。\n绝岭夜无家，深榛雨中宿。\n独妇饷粮还，哀哀舍南哭。' },
  { title: '难言', author: '韦应物', poem: '掬土移山望山尽，投石填海望海满。\n持索捕风几时得，将刀斫水几时断。\n未若不相知，中心万仞何由款。' },
  { title: '易言', author: '韦应物', poem: '洪炉炽炭燎一毛，大鼎炊汤沃残雪。\n疾影随形不觉至，千钧引缕不知绝。\n未若同心言，一言和同解千结。' },
  { title: '三台二首 一', author: '韦应物', poem: '一年一年老去，明日后日花开。\n未报长安平定，万国岂得衔杯。' },
  { title: '三台二首 二', author: '韦应物', poem: '冰泮寒塘始绿，雨余百草皆生。\n朝来门合无事，晚下高斋有情。' },
  { title: '上皇三台', author: '韦应物', poem: '不寐倦长更，披衣出户行。\n月寒秋竹冷，风切夜窗声。' },
  { title: '荅畅参军', author: '韦应物', poem: '秉笔振芳步，少年且吏游。\n官闲高兴生，夜直河汉秋。\n念与清赏遇，方抱沈疾忧。\n嘉言忽见赠，良药同所瘳。\n高树起栖鸦，晨钟满皇州。\n凄清露华动，旷朗景气浮。\n偶宦心非累，处喧道自幽。\n空虚为世薄，子独意绸缪。' },
  { title: '南池宴钱子辛赋得科斗', author: '韦应物', poem: '临池见科斗，美尔乐有余。\n不忧网与钩，幸得免为鱼。\n且愿充文字，登君尺素书。' },
  { title: '咏徐正字画青蝇', author: '韦应物', poem: '误点能成物，迷真许一时。\n笔端来已久，座上去何迟。\n顾白曾无变，听鸡不复疑。\n讵劳才子赏，为入国人诗。' },
  { title: '虞获子鹿', author: '韦应物', poem: '虞获子鹿，畜之城陬。\n园有美草，池有清流。\n但见蹶蹶，亦闻呦呦。\n谁知其思，岩谷云游。' },
  { title: '陪王郎中寻孔征君', author: '韦应物', poem: '俗吏闲居少，同人会面难。\n偶随香署客，来访竹林欢。\n暮馆花微落，春城雨暂寒。\n瓮间聊共酌，莫使宦情阑。' },
  { title: '送宫人入道', author: '韦应物', poem: '舍宠求仙畏色衰，辞天素面立天墀。\n金丹拟驻千年貌，宝镜休匀八字眉。\n公主与收珠翠后，君王看戴角冠时。\n从来宫女皆相妒，说着瑶台总泪垂。' },
  { title: '和晋陵陆丞早春游望', author: '韦应物', poem: '独有宦游人，偏惊物候新。\n云霞出海曙，梅柳渡江春。\n淑气催黄鸟，晴光照绿苹。\n忽闻歌苦调，归思欲沾巾。' },
  { title: '元次山居武昌之樊山新春大雪以诗问之', author: '孟彦深', poem: '江山十日雪，雪深江雾浓。\n起来望樊山，但见群玉峰。\n林莺却不语，野兽翻有踪。\n山中应大寒，短褐何以完。\n皓气凝书帐，清着钓鱼竿。\n怀君欲进谒，谿滑渡舟难。' },
  { title: '出塞曲', author: '刘湾', poem: '将军在重围，音信绝不通。\n羽书如流星，飞入甘泉宫。\n倚是幷州儿，少年心胆雄。\n一朝随召募，百战争王公。\n去年桑干北，今年桑干东。\n死是征人死，功是将军功。\n汗马牧秋月，疲卒卧霜风。\n仍闻左贤王，更将围云中。' },
  { title: '云南曲', author: '刘湾', poem: '百蛮乱南方，群盗如猬起。\n骚然疲中原，征战从此始。\n白门太和城，来往一万里。\n去者无全生，十人九人死。\n岱马卧阳山，燕兵哭泸水。\n妻行求死夫，父行求死子。\n苍天满愁云，白骨积空垒。\n哀哀云南行，十万同已矣。' },
  { title: '李陵别苏武', author: '刘湾', poem: '汉武爱边功，李陵提步卒。\n转战单于庭，身随汉军没。\n李陵不爱死，心存归汉阙。\n誓欲还国恩，不为匈奴屈。\n身辱家已无，长居虎狼窟。\n胡天无春风，虏地多积雪。\n穷阴愁杀人，况与苏武别。\n发声天地哀，执手肺肠绝。\n白日为我愁，阴云为我结。\n生为汉宫臣，死为胡地骨。\n万里长相思，终身望南月。' },
  { title: '虹县严孝子墓', author: '刘湾', poem: '至性教不及，因心天所资。\n礼闻三年丧，尔独终身期。\n下由骨肉恩，上报父母慈。\n礼闻哭有卒，汝独哀无时。\n前有松柏林，荆蓁结朦胧。\n墓门白日闭，泣血黄泉中。\n草服蔽枯骨，垢容戴飞蓬。\n举声哭苍天，万木皆悲风。' },
  { title: '对雨愁闷寄钱大郎中', author: '刘湾', poem: '积雨细纷纷，饥寒命不分。\n揽衣愁见肘，窥镜觅从文。\n九陌成泥海，千山尽湿云。\n龙钟驱欵段，到处倍思君。' },
  { title: '即席赋露中菊', author: '刘湾', poem: '众芳春竞发，寒菊露偏滋。\n受气何曾异，开花独自迟。\n晚成犹有分，欲采未过时。\n勿弃东篱下，看随秋草衰。' },
  { title: '遇旅鹤', author: '孙昌胤', poem: '灵鹤产绝境，昂昂无与俦。\n群飞沧海曙，一叫云山秋。\n野性方自得，人寰何所求。\n时因戏祥风，偶尔来中州。\n中州帝王宅，园沼深且幽。\n希君惠稻粱，欲幷离丹丘。\n不然奋飞去，将适汗漫游。\n肯作池上鹜，年年空沈浮。' },
  { title: '清明', author: '孙昌胤', poem: '清明暮春里，怅望北山陲。\n燧火开新焰，桐花发故枝。\n沈冥慙岁物，欢宴阻朋知。\n不及林间鸟，迁乔并羽仪。' },
  { title: '和司空曙刘眘虚九日送人', author: '孙昌胤', poem: '京邑叹离群，江楼喜遇君。\n开筵当九日，泛菊外浮云。\n朗咏山川霁，酣歌物色新。\n君看酒中意，未肯丧斯文。' },
  { title: '越裳献白翟', author: '孙昌胤', poem: '圣哲符休运，伊臯列上台。\n覃恩丹徼远，入贡素翚来。\n北阙欣初见，南枝顾未回。\n敛容残雪净，矫翼片云开。\n驯扰将无惧，翻飞幸莫猜。\n甘从上苑里，饮啄自裴回。' },
  { title: '绵州越王楼即事', author: '乔琳', poem: '三蜀澄清郡政闲，登楼携酌日跻攀。\n顿觉胷怀无俗事，回看掌握是人寰。\n滩声曲折涪州水，云影低衔富乐山。\n行雁南飞似乡信，忽然西笑向秦关。' },
  { title: '牡丹', author: '柳浑', poem: '近来无奈牡丹何，数十千钱买一颗。\n今朝始得分明见，也共戎葵不校多。' },
  { title: '读后汉逸人传二首 一', author: '张谓', poem: '子陵没已久，读史思其贤。\n谁谓颍阳人，千秋如比肩。\n尝闻汉皇帝，曾是旷周旋。\n名位苟无心，对君犹可眠。\n东过富春渚，乐此佳山川。\n夜卧松下月，朝看江上烟。\n钓时如有待，钓罢应忘筌。\n生事在林壑，悠悠经暮年。\n于今七里濑，遗迹尚依然。\n高台竟寂寞，流水空潺湲。' },
  { title: '读后汉逸人传二首 二', author: '张谓', poem: '庞公南郡人，家在襄阳里。\n何处偏来往，襄阳东陂是。\n誓将业田种，终得保妻子。\n何言二千石，乃欲劝吾仕。\n鹳鹊巢茂林，鼋鼍穴深水。\n万物从所欲，吾心亦如此。\n不见鹿门山，朝朝白云起。\n采药复采樵，优游终暮齿。' },
  { title: '同孙构免官后登蓟楼', author: '张谓', poem: '昔在五陵时，年少心亦壮。\n尝矜有奇骨，必是封侯相。\n东走到营州，投身似边将。\n一朝去乡国，十载履亭障。\n部曲皆武夫，功成不相让。\n犹希虏尘动，更取林胡帐。\n去年大将军，忽负乐生谤。\n北别伤士卒，南迁死炎瘴。\n濩落悲无成，行登蓟丘上。\n长安三千里，日夕西南望。\n寒沙榆塞没，秋水滦河涨。\n策马从此辞，云山保闲放。' },
  { title: '代北州老翁荅', author: '张谓', poem: '负薪老翁往北州，北望乡关生客愁。\n自言老翁有三子，两人已向黄沙死。\n如今小儿新长成，明年闻道又征兵。\n定知此别必零落，不及相随同死生。\n尽将田宅借邻伍，且复伶俜去乡士。\n在生本求多子孙，及有谁知更辛苦。\n近传天子尊武臣，强兵直欲静胡尘。\n安边自合有长策，何必流离中国人。' },
  { title: '湖上对酒行', author: '张谓', poem: '夜坐不厌湖上月，昼行不厌湖上山。\n眼前一尊又长满，心中万事如等闲。\n主人有黍百余石，浊醪数斗应不惜。\n即今相对不尽欢，别后相思复何益。\n茱萸湾头归路赊，愿君且宿黄公家。\n风光若此人不醉，参差辜负东园花。' },
  { title: '赠乔琳', author: '张谓', poem: '去年上策不见收，今年寄食仍淹留。\n羡君有酒能便醉，羡君无钱能不忧。\n如今五侯不爱客，羡君不问五侯宅。\n如今七贵方自尊，羡君不过七贵门。\n丈夫会应有知己，世上悠悠何足论。' },
  { title: '邵陵作', author: '张谓', poem: '尝闻虞帝苦忧人，祗为苍生不为身。\n已道一朝辞北阙，何须五月更南巡。\n昔时文武皆销铄，今日精灵常寂寞。\n斑竹年来笋自生，白苹春尽花空落。\n遥望零陵见旧丘，苍梧云起至今愁。\n惟余帝子千行泪，添作潇湘万里流。' },
  { title: '寄李侍御', author: '张谓', poem: '柱下闻周史，书中慰越吟。\n近看三岁字，遥见百年心。\n价以吹嘘长，恩从顾盼深。' },
  { title: '寄崔沣州', author: '张谓', poem: '共襆台郎被，俱褰郡守帷。\n罚金殊往日，鸣玉幸同时。\n五马来何晚，双鱼赠已迟。\n江头望乡月，无夜不相思。' },
  { title: '送裴侍御归上都', author: '张谓', poem: '楚地劳行役，秦城罢鼓鼙。\n舟移洞庭岸，路出武陵谿。\n江月随人影，山花趁马蹄。\n离魂将别梦，先已到关西。' },
  { title: '送青龙一公', author: '张谓', poem: '事佛轻金印，勤王度玉关。\n不知从树下，还肯到人间。\n楚水青莲净，吴门白日闲。\n圣朝须助理，绝莫爱东山。' },
  { title: '送韦侍御赴上都', author: '张谓', poem: '天朝辟书下，风宪取才难。\n更谒麒麟殿，重簪獬豸冠。\n月明湘水夜，霜重桂林寒。\n别后头堪白，时时镜里看。' },
  { title: '饯田尚书还兖州', author: '张谓', poem: '忠义三朝许，威名四海闻。\n更乘归鲁诏，犹忆破胡勋。\n别路逢霜雨，行营对雪云。\n明朝郭门外，长揖大将军。' },
  { title: '送杜侍御赴上都', author: '张谓', poem: '避马台中贵，登车岭外遥。\n还因贡赋礼，来谒大明朝。\n地入商山路，乡连渭水桥。\n承恩返南越，尊酒重相邀。' },
  { title: '道林寺送莫侍御', author: '张谓', poem: '何处堪留客，香林隔翠微。\n薜萝通驿骑，山竹挂朝衣。\n霜引台乌集，风惊塔鴈飞。\n饮茶胜饮酒，聊以送将归。' },
  { title: '别睢阳故人', author: '张谓', poem: '少小客游梁，依然似故乡。\n城池经战阵，人物恨存亡。\n夏雨桑条绿，秋风麦穗黄。\n有书无寄处，相送一沾裳。' },
  { title: '郡南亭子宴', author: '张谓', poem: '亭子春城外，朱门向绿林。\n柳枝经雨重，松色带烟深。\n漉酒迎山客，穿池集水禽。\n白云常在眼，聊足慰人心。' },
  { title: '早春陪崔中丞浣花溪宴得暄字', author: '张谓', poem: '旌节临溪口，寒郊斗觉暄。\n红亭移酒席，画鹢逗江村。\n云带歌声飏，风飘舞袖翻。\n花间催秉烛，川上欲黄昏。' },
  { title: '䜩郑伯玙宅', author: '张谓', poem: '正月风光好，逢君上客稀。\n晓风催鸟啭，春雪带花飞。\n堂上吹金管，庭前试舞衣。\n俸钱供酒债，行子未须归。' },
  { title: '夜同宴用人字', author: '张谓', poem: '北斗回新岁，东园值早春。\n竹风能醒酒，花月解留人。\n邑宰陶元亮，山家郑子真。\n平生颇同道，相见日相亲。' },
  { title: '过从弟制疑官舍竹斋', author: '张谓', poem: '羡尔方为吏，衡门独[晏]如。\n野猨偷纸笔，山鸟污图书。\n竹里藏公事，花间隐使车。\n不妨垂钓坐，时脍小江鱼。' },
  { title: '扬州雨中张十七宅观妓', author: '张谓', poem: '夜色带寒烟，灯花拂更然。\n残妆添石黛，艳舞落金钿。\n掩笑须欹扇，迎歌乍动弦。\n不知巫峡雨，何事海西边。' },
  { title: '登金陵临江驿楼', author: '张谓', poem: '古戍依重险，高楼见五梁。\n山根盘驿道，河水浸城墙。\n庭树巢鹦鹉，园花隐麝香。\n忽然江浦上，忆作捕鱼郎。' },
  { title: '同王征君湘中有怀', author: '张谓', poem: '八月洞庭秋，潇湘水北流。\n还家万里梦，为客五更愁。\n不用开书帙，偏宜上酒楼。\n故人京洛满，何日复同游。' },
  { title: '官舍早梅', author: '张谓', poem: '堦下双梅树，春来画不成。\n晚时花未落，阴处叶难生。\n摘子防人到，攀枝畏鸟惊。\n风光先占得，桃李莫相轻。' },
  { title: '玉清公主挽歌', author: '张谓', poem: '学凤年犹小，乘龙日尚赊。\n初封千户邑，忽驾五云车。\n地接金人岸，山通玉女家。\n秋风何太早，吹落禁园花。' },
  { title: '别韦郎中', author: '张谓', poem: '星轺计日赴岷峨，云树连天阻笑歌。\n南入洞庭随鴈去，西过巫峡听猨多。\n峥嵘洲上飞黄蝶，滟滪堆边起白波。\n不醉郎中桑落酒，教人无奈别离何。' },
  { title: '送皇甫龄宰交河', author: '张谓', poem: '将军帐下来从客，小邑弹琴不易逢。\n楼上胡笳传别怨，尊中腊酒为谁浓。\n行人醉出双门道，少妇愁看七里烽。\n今日相如轻武骑，多应朝暮客临卭。' },
  { title: '杜侍御送贡物戏赠', author: '张谓', poem: '铜柱朱崖道路难，伏波横海旧登坛。\n越人自贡珊瑚树，汉使何劳獬豸冠。\n疲马山中愁日晚，孤舟江上畏春寒。\n由来此货称难得，多恐君王不忍看。' },
  { title: '春园家宴', author: '张谓', poem: '南园春色正相宜，大妇同行少妇随。\n竹里登楼人不见，花间觅路鸟先知。\n樱桃解结垂檐子，杨柳能低入户枝。\n山简醉来歌一曲，参差笑杀郢中儿。' },
  { title: '西亭子言怀', author: '张谓', poem: '数丛芳草在堂阴，几处闲花映竹林。\n攀树玄猨呼郡吏，傍谿白鸟应家禽。\n青山看景知高下，流水闻声觉浅深。\n官属不令拘礼数，时时缓步一相寻。' },
  { title: '辰阳即事', author: '张谓', poem: '青枫落叶正堪悲，黄菊残花欲待谁。\n水近偏逢寒气早，山深常见日光迟。\n愁中卜命看周易，病里招魂读楚词。\n自恨不如湘浦鴈，春来即是北归时。' },
  { title: '送僧', author: '张谓', poem: '童子学修道，诵经求出家。\n手持贝多叶，心念优昙花。\n得度北州近，随缘东路赊。\n一身求清净，百毳纳袈裟。\n钟岭更飞锡，炉峰期结跏。\n深心大海水，广愿恒河沙。\n此去不堪别，彼行安可涯。\n殷勤结香火，来世上牛车。' },
  { title: '同诸公游云公禅寺', author: '张谓', poem: '共许寻鸡足，谁能惜马蹄。\n长空净云雨，斜日半虹霓。\n檐下千峰转，窗前万木低。\n看花寻径远，听鸟入林迷。\n地与喧闻隔，人将物我齐。\n不知樵客意，何事武陵谿。' },
  { title: '哭护国上人', author: '张谓', poem: '昔喜三身净，今悲万劫长。\n不应归北斗，应是向西方。\n舍利众生得，袈裟弟子将。\n鼠行残药椀，虫网旧绳床。\n别起千花塔，空留一草堂。\n支公何处在，神理竟茫茫。' },
  { title: '送卢举使河源', author: '张谓', poem: '故人行役向边州，匹马今朝不少留。\n长路关山何日尽，满堂丝竹为君愁。' },
  { title: '题长安壁主人', author: '张谓', poem: '世人结交须黄金，黄金不多交不深。\n纵令然诺暂相许，终是悠悠行路心。' },
  { title: '长安失火后戏题莲花寺', author: '张谓', poem: '金园宝刹半长沙，烧劫旁延一万家。\n楼殿纵随烟焰去，火中何处出莲花。' },
  { title: '早梅', author: '张谓', poem: '一树寒梅白玉条，逈临林村傍谿桥。\n不知近水花先发，疑是经春雪未销。' },
  { title: '赠赵使君美人', author: '张谓', poem: '红粉青蛾映楚云，桃花马上石榴裙。\n罗敷独向东方去，漫学他家作使君。' },
  { title: '句', author: '张谓', poem: '[稽]山贺老麤知名，吴郡张颠曾不易。\n奔蛇走虺势入坐，骤雨旋风声满堂。' },
  { title: '北庭西郊候封大夫受降回军献上', author: '岑参', poem: '胡地苜蓿美，轮台征马肥。\n大夫讨匈奴，前月西出师。\n甲兵未得战，降虏来如归。\n橐𫘞何连连，穹帐亦累累。\n阴山烽火灭，劒水羽书稀。\n却笑霍嫖姚，区区徒尔为。\n西郊候中军，平沙悬落晖。\n驿马从西来，双节夹路驰。\n喜鹊捧金印，蛟龙盘画旗。\n如公未四十，富贵能及时。\n直上排青云，傍看疾若飞。\n前年斩楼兰，去岁平月支。\n天子日殊宠，朝廷方见推。\n何幸一书生，忽蒙国士知。\n侧身佐戎幕，敛袵事边陲。\n自逐定远侯，亦着短后衣。\n近来能走马，不弱幷州儿。' },
  { title: '初至西虢官舍南池呈左右省及南宫诸故人', author: '岑参', poem: '黜官自西掖，待罪临下阳。\n空积犬马恋，岂思鹓鹭行。\n素多江湖意，偶佐山水乡。\n满院池月静，卷帘溪雨凉。\n轩窓竹翠湿，案牍荷花香。\n白鸟上衣桁，青苔生笔床。\n数公不可见，一别尽相忘。\n敢恨青琐客，无情华省郎。\n早年迷进退，晚节悟行藏。\n他日能相访，嵩南旧草堂。' },
  { title: '过梁州奉赠张尚书大夫公', author: '岑参', poem: '汉中二良将，今昔各一时。\n韩信此登坛，尚书复来斯。\n手把铜虎符，身总丈人师。\n错落北斗星，照耀黑水湄。\n英雄若神授，大材济时危。\n顷岁遇雷云，精神感灵祇。\n勋业振青史，恩德继鸿私。\n羌虏昔未平，华阳积僵尸。\n人烟绝墟落，鬼火依城池。\n巴汉空水流，襃斜惟鸟飞。\n自公布德政，此地生光辉。\n百堵创里闾，千家恤惸嫠。\n层城重鼓角，甲士如熊罴。\n坐啸风自调，行春雨仍随。\n芃芃麦苗长，蔼蔼桑叶肥。\n浮客相与来，群盗不敢窥。\n何幸承嘉惠，小年即相知。\n富贵情易疎，相逢心不移。\n置酒宴高馆，娇歌杂青丝。\n锦席绣拂庐，玉盘金屈巵。\n春景透高戟，江云篲长麾。\n枥马嘶柳阴，美人映花枝。\n门传大夫印，世拥上将旗。\n承家令名扬，许国苦节施。\n戎幕宁久驻，台阶不应迟。\n别有弹冠士，希君无见遗。' },
  { title: '登北庭北楼呈幕中诸公', author: '岑参', poem: '尝读西域传，汉家得轮台。\n古塞千年空，阴山独崔嵬。\n二庭近西海，六月秋风来。\n日暮上北楼，杀气凝不开。\n大荒无鸟飞，但见白龙塠。\n旧国眇天末，归心日悠哉。\n上将新破胡，西郊绝烟埃。\n边城寂无事，抚劒空徘徊。\n幸得趋幕中，托身厕群才。\n早知安边计，未尽平生怀。' },
  { title: '初过陇山途中呈宇文判官', author: '岑参', poem: '一驿过一驿，驿骑如星流。\n平明发咸阳，暮及陇山头。\n陇水不可听，呜咽令人愁。\n沙尘扑马汗，雾露凝貂裘。\n西来谁家子，自道新封侯。\n前月发安西，路上无停留。\n都护犹未到，来时在西州。\n十日过沙碛，终朝风不休。\n马走碎石中，四蹄皆血流。\n万里奉王事，一身无所求。\n也知塞垣苦，岂为妻子谋。\n山口月欲出，先照关城楼。\n谿流与松风，静夜相飕飗。\n别家赖归梦，山塞多离忧。\n与子且携手，不愁前路修。' },
  { title: '陪狄员外早秋登府西楼因呈院中诸公', author: '岑参', poem: '常爱张仪楼，西山正相当。\n千峰带积雪，百里临城墙。\n烟氛扫晴空，草树映朝光。\n车马隘百井，里闬盘二江。\n亚相自登坛，时危安此方。\n威声振蛮貊，惠化钟华阳。\n旌节罗广庭，戈铤凛秋霜。\n阶下貔虎士，幕中鹓鹭行。\n今我忽登临，顾恩不望乡。\n知己犹未报，鬓毛飒已苍。\n时命难自知，功业岂暂忘。\n蝉鸣秋城夕，鸟去江天长。\n兵马休战争，风尘尚苍茫。\n谁当共携手，赖有冬官郎。' },
  { title: '冬夜宿仙游寺南凉堂呈谦道人', author: '岑参', poem: '太乙连太白，两山知几重。\n路盘石门窄，匹马行才通。\n日西倒山寺，林下逢支公。\n昨夜山北时，星星闻此钟。\n秦女去已久，仙台在中峰。\n箫声不可闻，此地留遗踪。\n石潭积黛色，每岁投金龙。\n乱流争迅湍，喷薄如雷风。\n夜来闻清磬，月出苍山空。\n空山满清光，水树相玲珑。\n回廊映密竹，秋殿隐深松。\n灯影落前谿，夜宿水声中。\n爱兹林峦好，结宇向谿东。\n相识唯山僧，邻家一钓翁。\n林晚栗初拆，枝寒梨已红。\n物幽兴易惬，事胜趣弥浓。\n愿谢区中缘，永依金人宫。\n寄报乘辇客，簪裾尔何容。' },
  { title: '潼关镇国军句覆使院早春寄王同州', author: '岑参', poem: '胡寇尚未尽，大军镇关门。\n旌旗遍草木，兵马如云屯。\n圣朝正用武，诸将皆承恩。\n不见征战功，但闻歌吹喧。\n儒生有长策，闭口不敢言。\n昨从关东来，思与故人论。\n何为廊庙器，至今居外藩。\n黄霸宁淹留，苍生望腾𬸣。\n卷帘见西岳，仙掌明朝暾。\n昨夜闻春风，戴胜过后园。\n各自限官守，何由叙凉温。\n离忧不可忘，襟背思树萱。' },
  { title: '青山峡口泊舟怀狄侍御', author: '岑参', poem: '峡口秋水壮，沙边且停桡。\n奔涛振石壁，峰势如动摇。\n九月芦花新，弥令客心焦。\n谁念在江岛，故人满天朝。\n无处豁心胸，忧来醉能销。\n往来巴山道，三见秋草雕。\n狄生新相知，才调凌云霄。\n赋诗析造化，入幕生风飙。\n把笔判甲兵，战士不敢骄。\n皆云梁公后，遇鼎还能调。\n离别倏经时，音尘殊寂寥。\n何当见夫子，不叹乡关遥。' },
  { title: '寄青城龙谿奂道人', author: '岑参', poem: '五岳之丈人，西望青瞢瞢。\n云开露崖峤，百里见石棱。\n龙谿盘中峰，上有莲华僧。\n绝顶小兰若，四时岚气凝。\n身同云虚无，心与谿清澄。\n诵戒龙每听，赋诗人则称。\n杉风吹袈裟，石壁悬孤灯。\n久欲谢微禄，誓将归大乘。\n愿闻开士说，庶以心相应。' },
  { title: '梁州对雨怀曲二秀才便呈曲大判官时疾赠余新诗', author: '岑参', poem: '江上云气黑，𡷛山昨夜雷。\n水恶平明飞，雨从嶓冢来。\n蒙蒙随风过，萧飒鸣庭槐。\n隔帘湿衣巾，当暑凉幽斋。\n曲生住相近，言语阻且乖。\n卧疾不见人，午时门始开。\n终日看本草，药苗满前堦。\n兄弟早有名，甲科皆秀才。\n二人事慈母，不弱古老莱。\n昨叹携手迟，未尽平生怀。\n爱君有佳句，一日吟几回。' },
  { title: '潼关使院怀王七季友', author: '岑参', poem: '王生今才子，时辈咸所仰。\n何当见颜色，终日劳梦想。\n驱车到关下，欲往阻河广。\n满日徒春华，思君罢心赏。\n开门见太华，朝日映高掌。\n忽觉莲花峰，别来更如长。\n无心顾微禄，有意在独往。\n不负林中期，终当出尘网。' },
  { title: '至大梁却寄匡城主人', author: '岑参', poem: '一从弃鱼钓，十载干明王。\n无由谒天阶，却欲归沧浪。\n仲秋至东郡，遂见天雨霜。\n昨日梦故山，蕙草色已黄。\n平明辞铁丘，薄暮游大梁。\n仲秋萧条景，拔刺飞鹅鸧。\n四郊阴气闭，万里无晶光。\n长风吹白茅，野火烧枯桑。\n故人南燕吏，籍籍名更香。\n聊以玉壶赠，置之君子堂。' },
  { title: '宿华阴东郭客舍忆阎防', author: '岑参', poem: '次舍山郭近，解鞍鸣钟时。\n主人炊新粒，行子充夜饥。\n关月生首阳，照见华阴祠。\n苍茫秋山晦，萧瑟寒松悲。\n久从园庐别，遂与朋知辞。\n旧壑兰杜晚，归轩今已迟。' },
  { title: '宿东谿王屋李隐者', author: '岑参', poem: '山店不凿井，百家同一泉。\n晚来南村黑，雨色和人烟。\n霜畦吐寒菜，沙鴈噪河田。\n隐者不可见，天坛飞鸟边。' },
  { title: '郊行寄杜位', author: '岑参', poem: '崷崪空城烟，凄清寒山景。\n秋风引归梦，昨夜到汝颍。\n近寺闻钟声，映陂见树影。\n所思何由见，东北徒引领。' },
  { title: '怀叶县关操姚旷韩涉李叔齐', author: '岑参', poem: '数子皆故人，一时吏宛叶。\n经年总不见，书札徒满箧。\n斜日半空庭，旋风走梨叶。\n去君千里地，言笑何时接。' },
  { title: '西蜀旅舍春叹寄朝中故人呈狄评事', author: '岑参', poem: '春与人相乖，柳青头转白。\n生平未得意，览镜私自惜。\n四海犹未安，一身无所适。\n自从兵戈动，遂觉天地窄。\n功业悲后时，光阴叹虚掷。\n却为文章累，幸有开济策。\n何负当途人，无心矜窘厄。\n回瞻后来者，皆欲肆轥轹。\n起草思南宫，寄言忆西掖。\n时危任舒卷，身退知损益。\n穷巷草转深，闲门日将夕。\n桥西暮雨黑，篱外春江碧。\n昨者初识君，相看俱是客。\n声华同道术，世业通往昔。\n早须归天阶，不得安孔席。\n吾先税归鞅，旧国如咫尺。' },
  { title: '太白东溪张老舍即事寄舍弟姪等', author: '岑参', poem: '渭上秋雨过，北风何骚骚。\n天晴诸山出，太白峰最高。\n主人东溪老，两耳生长毫。\n远近知百岁，子孙皆二毛。\n中庭井兰上，一架狝猴桃。\n石泉饭香粳，酒瓮开新槽。\n爱兹田中趣，始悟世上劳。\n我行有胜事，书此寄尔曹。' },
  { title: '上嘉州青衣山中峰题惠净上人幽居寄兵部杨郎中', author: '岑参', poem: '青衣谁开凿，独在水中央。\n浮舟一跻攀，侧迳缘穹苍。\n绝顶诣老僧，豁然登上方。\n诸岭一何小，三江奔茫茫。\n兰若向西开，峨眉正相当。\n猿鸟乐钟磬，松萝泛天香。\n江云入袈裟，山月吐绳床。\n早知清净理，久乃机心忘。\n尚以名宦拘，聿来夷獠乡。\n吾友不可见，郁为尚书郎。\n早岁爱丹经，留心向青囊。\n渺渺云智远，幽幽海怀长。\n胜赏欲与俱，引领遥相望。\n为政媿无术，分忧幸时康。\n君子满天朝，老夫忆沧浪。\n况值庐山远，抽簪归法王。' },
  { title: '入劒门作寄杜杨二郎中时二公并为杜元帅判官', author: '岑参', poem: '不知造化初，此山谁开坼。\n双崖倚天立，万仞从地劈。\n云飞不到顶，鸟去难过壁。\n速驾畏岩倾，单行愁路窄。\n平明地仍黑，停午日暂赤。\n凛凛三伏寒，巉巉五丁迹。\n与时忽开闭，作固或顺逆。\n磅礴跨岷峨，巍蟠限蛮貊。\n星当觜参分，地处西南僻。\n陡觉烟景殊，杳将华夏隔。\n刘氏昔颠覆，公孙曾败绩。\n始知德不修，恃此险何益。\n相公总师旅，远近罢金革。\n杜母来何迟，蜀人应更惜。\n暂回丹青虑，少用开济策。\n二友华省郎，俱为幕中客。\n良筹佐戎律，精理皆硕画。\n高文出诗骚，奥学穷讨赜。\n圣朝无外户，寰宇被德泽。\n四海今一家，徒然劒门石。' },
  { title: '巩北秋兴寄崔明允', author: '岑参', poem: '白露披梧桐，玄蝉昼夜号。\n秋风万里动，日暮黄云高。\n君子佐休明，小人事蓬蒿。\n所适在鱼鸟，焉能徇锥刀。\n孤舟向广武，一鸟归成臯。\n胜概日相与，思君心郁陶。' },
  { title: '春遇南使贻赵知音', author: '岑参', poem: '端居春心醉，襟背思树萱。\n美人在南州，为尔歌北门。\n北风吹烟物，戴胜鸣中园。\n枯杨长新条，芳草滋旧根。\n网丝结宝琴，尘埃被空樽。\n适遇江海信，聊与南客论。' },
  { title: '冀州客舍酒酣贻王绮寄题南楼', author: '岑参', poem: '夫子傲常调，诏书下征求。\n知君欲谒帝，秣马趋西周。\n逸足何骎骎，美声实风流。\n学富赡清词，下笔不能休。\n君家一何盛，赫奕难为俦。\n伯父四五人，同时为诸侯。\n忆昨始相值，值君客贝丘。\n相看复乘兴，携手到冀州。\n前日在南县，与君上北楼。\n野旷不见山，白日落草头。\n客舍梨花繁，深花隐鸣鸠。\n南邻新酒熟，有女弹箜篌。\n醉后或狂歌，酒醒满离忧。\n主人不相识，此地难淹留。\n吾庐终南下，堪与王孙游。\n何当肯相寻，澧上一孤舟。' },
  { title: '终南云际精舍寻法澄上人不遇归高冠东潭石淙望秦岭微雨作贻友人', author: '岑参', poem: '昨夜云际宿，旦从西峰回。\n不见林中僧，微雨潭上来。\n诸峰皆青翠，秦岭独不开。\n石鼓有时鸣，秦王安在哉。\n东南云开处，突兀狝猴台。\n崖口悬瀑流，半空白皑皑。\n喷壁四时雨，傍村终日雷。\n北瞻长安道，日夕生尘埃。\n若访张仲蔚，衡门满蒿莱。' },
  { title: '敬酬杜华淇上见赠兼呈熊曜', author: '岑参', poem: '杜侯实才子，盛名不可及。\n祗曾效一官，今已年四十。\n是君同时者，已有尚书郎。\n怜君独未遇，淹泊在他乡。\n我从京师来，到此喜相见。\n共论穷途事，不觉泪满面。\n忆昨癸未岁，吾兄自江东。\n得君江湖诗，骨气凌谢公。\n熊生尉淇上，开馆常待客。\n喜我二人来，欢笑朝复夕。\n县楼压春岸，戴胜鸣花枝。\n吾徒在舟中，纵酒兼弹棋。\n三月犹未还，寒愁满春草。\n赖蒙瑶华赠，讽咏慰怀抱。' },
  { title: '酬成少尹骆谷行见呈', author: '岑参', poem: '闻君行路难，惆怅临长衢。\n岂不惮险艰，王程剩相拘。\n忆昨蓬莱宫，新授刺史符。\n明主仍赐衣，价直千万余。\n何幸承命日，得与夫子俱。\n携手出华省，连镳赴长途。\n五马当路嘶，按节投蜀都。\n千崖信萦折，一径何盘纡。\n层冰滑征轮，密竹碍隼旟。\n深林迷昏旦，栈道凌空虚。\n飞雪缩马毛，烈风擘我肤。\n峰攒望天小，亭午见日初。\n夜宿月近人，朝行云满车。\n泉浇石罅坼，火入松心枯。\n亚尹同心者，风流贤大夫。\n荣禄上及亲，之官随板舆。\n高价振台阁，清词出应徐。\n成都春酒香，且用俸钱沽。\n浮名何足道，海上堪乘桴。' },
  { title: '虢中酬陕西甄判官见赠', author: '岑参', poem: '微才弃散地，拙宦慙清时。\n白发徒自负，青云难可期。\n胡尘暗东洛，亚相方出师。\n分陕振鼓鼙，二崤满旌旗。\n夫子廊庙器，迥然青冥姿。\n阃外佐戎律，幕中吐兵奇。\n前者驿使来，忽枉行军诗。\n昼吟庭花落，夜讽山月移。\n昔君隐苏门，浪迹不可羁。\n诏书自征用，令誉天下知。\n别来春草长，东望转相思。\n寂寞山城暮，空闻画角悲。' },
  { title: '送许子擢第归江宁拜亲因寄王大昌龄', author: '岑参', poem: '建业控京口，金陵款沧溟。\n君家临秦淮，傍对石头城。\n十年自勤学，一鼓游上京。\n青春登甲科，动地闻香名。\n解榻皆五侯，结交尽群英。\n六月槐花飞，忽思莼菜羹。\n跨马出国门，丹阳返柴荆。\n楚云引归帆，淮水浮客程。\n到家拜亲时，入门有光荣。\n乡人尽来贺，置酒相邀迎。\n闲眺北顾楼，醉眠湖上亭。\n月从海门出，照见茅山青。\n昔为帝王州，今幸天地平。\n五朝变人世，千载空江声。\n玄元告灵符，丹洞获其铭。\n皇帝受玉册，群臣罗天庭。\n喜气薄太阳，祥光彻窅冥。\n奔走朝万国，崩腾集百灵。\n王兄尚谪宦，屡见秋云生。\n孤城带后湖，心与湖水清。\n一县无诤辞，有时开道经。\n黄鹤垂两翅，徘徊但悲鸣。\n相思不可见，空望牛女星。' },
  { title: '武威送刘单判官赴安西行营便呈高开府', author: '岑参', poem: '热海亘铁门，火山赫金方。\n白草磨天涯，湖沙奔茫茫。\n夫子佐戎幕，其锋利如霜。\n中岁学兵符，不能守文章。\n功业须及时，立身有行藏。\n男儿感忠义，万里忘越乡。\n孟夏边候迟，胡国草木长。\n马疾过飞鸟，天穷超夕阳。\n都护新出师，五月发军装。\n甲兵二百万，错落黄金光。\n扬旗拂昆仑，伐鼓震蒲昌。\n太白引官军，天威临大荒。\n西望云似蛇，戎夷知丧亡。\n浑驱大宛马，系取楼兰王。\n曾到交河城，风土断人肠。\n寒驿远如点，边烽互相望。\n赤亭多飃风，鼓怒不可当。\n有时无人行，沙石乱飘扬。\n夜静天萧条，鬼哭夹道傍。\n地上多髑髅，皆是古战场。\n置酒高馆夕，边城月苍苍。\n军中宰肥牛，堂上罗羽觞。\n红泪金烛盘，娇歌艳新妆。\n望君仰青冥，短翮难可翔。\n苍然西郊道，握手何慨慷。' },
  { title: '送王大昌龄赴江宁', author: '岑参', poem: '对酒寂不语，怅然悲送君。\n明时未得用，白首徒攻文。\n泽国从一官，沧波几千里。\n群公满天阙，独去过淮水。\n旧家富春渚，尝忆卧江楼。\n自闻君欲行，频望南徐州。\n穷巷独闭门，寒灯静深屋。\n北风吹微雪，抱被肯同宿。\n君行到京口，正是桃花时。\n舟中饶孤兴，湖上多新诗。\n潜虬且深蟠，黄鹄举未晚。\n惜君青云器，努力加餐饭。' },
  { title: '送祈乐归河东', author: '岑参', poem: '祁乐后来秀，挺身出河东。\n往年诣骊山，献赋温泉宫。\n天子不召见，挥鞭遂从戎。\n前月还长安，囊中金已空。\n有时忽乘兴，画出江上峰。\n床头苍梧云，帘下天台松。\n忽如高堂上，飒飒生清风。\n五月火云屯，气烧天地红。\n鸟且不敢飞，子行如转蓬。\n少华与首阳，隔河势争雄。\n新月河上出，清光满关中。\n置酒灞亭别，高歌披心胸。\n君到故山时，为谢五老翁。' },
  { title: '北庭贻宗学士道别', author: '岑参', poem: '万事不可料，叹君在军中。\n读书破万卷，何事来从戎。\n曾逐李轻车，西征出太蒙。\n荷戈月窟外，擐甲昆仑东。\n两度皆破胡，朝廷轻战功。\n十年祗一命，万里如飘蓬。\n容鬓老胡尘，衣裘脆边风。\n忽来轮台下，相见披心胸。\n饮酒对春草，弹棋闻夜钟。\n今且还龟兹，臂上悬角弓。\n平沙向旅馆，匹马随飞鸿。\n孤城倚大碛，海气迎边空。\n四月犹自寒，天山雪蒙蒙。\n君有贤主将，何谓泣途穷。\n时来整六翮，一举凌苍穹。' },
  { title: '送许拾遗恩归江宁拜亲', author: '岑参', poem: '诏书下青琐，驷马还吴洲。\n束帛仍赐衣，恩波涨沧流。\n微禄将及亲，向家非远游。\n看君五斗米，不谢万户侯。\n适出西掖垣，如到南徐州。\n归心望海日，乡梦登江楼。\n大江盘金陵，诸山横石头。\n枫树隐茅屋，橘林系渔舟。\n种药疏故畦，钓鱼垂旧钩。\n对月京口夕，观涛海门秋。\n天子怜谏官，论事不可休。\n早来丹墀下，高驾无淹留。' },
  { title: '虢州郡斋南池幽兴因与阎二侍御道别', author: '岑参', poem: '池色净天碧，水凉雨凄凄。\n快风从东南，荷叶翻向西。\n性本爱鱼鸟，未能返岩谿。\n中岁徇微官，遂令心赏睽。\n及兹佐山郡，不异寻幽栖。\n小吏趋竹径，讼庭侵药畦。\n胡尘暗河洛，二陕震鼓鼙。\n故人佐戎轩，逸翮凌云霓。\n行军在函谷，两度闻莺啼。\n相看红旗下，饮酒白日低。\n闻君欲朝天，驷马临道嘶。\n仰望浮与沈，忽如云与泥。\n夜眠驿楼月，晓发关城鸡。\n惆怅西郊暮，乡书对君题。' },
  { title: '青龙招提归一上人远游吴楚别诗', author: '岑参', poem: '久交应真侣，最叹青龙僧。\n弃官向二年，削发归一乘。\n了然莹心身，洁念乐空寂。\n名香泛牕户，幽磬清晓夕。\n往年仗一劒，由是佐二庭。\n于焉久从戎，兼复解论兵。\n世人犹未知，天子愿相见。\n朝从青莲宇，暮入白虎殿。\n宫女擎锡杖，御筵出香炉。\n说法开藏经，论边穷阵图。\n忘机厌尘喧，浪迹向江海。\n思师石可访，惠远峰犹在。\n今旦飞锡去，何时持钵还。\n湖烟冷吴门，淮月衔楚山。\n一身如浮云，万里过江水。\n相思眇天末，南望无穷已。' },
  { title: '送李翥游江外', author: '岑参', poem: '相识应十载，见君只一官。\n家贫禄尚薄，霜降衣仍单。\n惆怅秋草死，萧条芳岁阑。\n且寻沧洲路，遥指吴云端。\n匹马关塞远，孤舟江海宽。\n夜眠楚烟湿，晓饭湖山寒。\n砧净红鲙落，袖香朱橘团。\n帆前见禹庙，枕底闻严滩。\n便获赏心趣，岂歌行路难。\n青门须醉别，少为解征鞍。' },
  { title: '送王著作赴淮西幕府', author: '岑参', poem: '燕子与百劳，一西复一东。\n天空信寥廓，翔集何时同。\n知己怅难遇，良朋非易逢。\n怜君心相亲，与我家又通。\n言笑日无度，书札凡几封。\n湛湛万顷陂，森森千丈松。\n不知有机巧，无事干心胸。\n满堂皆酒徒，岂复羡王公。\n早年抱将略，累岁依幕中。\n昨者从淮西，归来奏边功。\n承恩长乐殿，醉出明光宫。\n逆旅悲寒蝉，客梦惊飞鸿。\n发家见春草，却去闻秋风。\n月色冷楚城，淮光透霜空。\n各自务功业，当须激深衷。\n别后能相思，何嗟山水重。' },
  { title: '送张秘书充刘相公通汴河判官便赴江外觐省', author: '岑参', poem: '前年见君时，见君正泥蟠。\n去年见君处，见君已风[抟]。\n朝趋赤墀前，高视青云端。\n新登麒麟阁，适脱獬豸冠。\n刘公领舟楫，汴水扬波澜。\n万里江海通，九州天地宽。\n昨夜动使星，今旦送征鞍。\n老亲在吴郡，令弟双同官。\n鲈鲙賸堪忆，莼羹殊可餐。\n既参幕中画，复展膝下欢。\n因送故人行，试歌行路难。\n何处路最难，最难在长安。\n长安多权贵，珂珮声珊珊。\n儒生直如弦，权贵不须干。\n斗酒取一醉，孤琴为君弹。\n临岐欲有赠，持以握中兰。' },
  { title: '冬宵家会饯李郎司兵赴同州', author: '岑参', poem: '急管杂青丝，玉瓶金屈巵。\n寒天高堂夜，扑地飞雪时。\n贺君关西掾，新绶腰下垂。\n白面皇家郎，逸翮青云姿。\n明旦之官去，他辰良会稀。\n惜别冬夜短，务欢杯行迟。\n季女犹自小，老夫未令归。\n且看匹马行，不得鸣凤飞。\n昔岁到冯翊，人烟接京师。\n曾上月楼头，遥见西岳祠。\n沙苑逼官舍，莲峰压城池。\n多暇或自公，读书复弹棋。\n州县信徒劳，云霄亦可期。\n应须力为政，聊慰此相思。' },
  { title: '送颜平原', author: '岑参', poem: '天子念黎庶，诏书换诸侯。\n仙郎授剖符，华省辍分忧。\n置酒会前殿，赐钱若山丘。\n天章降三光，圣泽该九州。\n吾兄镇河朔，拜命宣皇猷。\n驷马辞国门，一星东北流。\n夏云照银印，暑雨随行辀。\n赤笔仍在箧，𬬻香惹衣裘。\n此地邻东溟，孤城吊沧洲。\n海风掣金戟，道吏呼鸣驺。\n郊原北连燕，剽劫风未休。\n鱼盐隘里巷，桑柘盈田畴。\n为郡岂淹旬，政成应未秋。\n易俗去猛虎，化人似驯鸥。\n苍生已望君，黄霸宁久留。' },
  { title: '送狄员外巡按西山军', author: '岑参', poem: '兵马守西山，中国非得计。\n不知何代策，空使蜀人弊。\n八州崖谷深，千里云雪闭。\n泉浇阁道滑，水冻绳桥脆。\n战士常苦饥，糗粮不相继。\n胡兵犹不归，空山积年岁。\n儒生识损益，言事皆审谛。\n狄子幕府郎，有谋必康济。\n胸中悬明镜，照耀无巨细。\n莫辞冒险艰，可以裨节制。\n相思江楼夕，愁见月澄霁。' },
  { title: '虢州送郑兴宗弟归扶风别庐', author: '岑参', poem: '佐郡已三载，岂能长后时。\n出关少亲友，赖汝常相随。\n今旦忽言别，怆然俱泪垂。\n平生沧洲意，独有青山知。\n州县不敢说，云霄谁敢期。\n因怀东谿老，最忆南峰缁。\n为我多种药，还山应未迟。' },
  { title: '澧头送蒋侯', author: '岑参', poem: '君住澧水北，我家澧水西。\n两村辨乔木，五里闻鸣鸡。\n饮酒溪雨过，弹棋山月低。\n徒闻蒋生径，尔去谁相携。' },
  { title: '送永寿王赞府迳归县', author: '岑参', poem: '当官接闲暇，暂得归林泉。\n百里路不宿，两乡山复连。\n夜深露湿簟，月出风惊蝉。\n且尽主人酒，为君从醉眠。' },
  { title: '南池宴饯辛子赋得蝌斗子', author: '岑参', poem: '临池见蝌斗，羡尔乐有余。\n不忧网与钓，幸得免为鱼。\n且愿充文字，登君尺素书。' },
  { title: '登嘉州凌云寺作', author: '岑参', poem: '寺出飞鸟外，青峰戴朱楼。\n搏壁跻半空，喜得登上头。\n始知宇宙阔，下看三江流。\n天晴见峨眉，如向波上浮。\n迥旷烟景豁，阴森椶枏稠。\n愿割区中缘，永从尘外游。\n回风吹虎穴，片雨当龙湫。\n僧房云蒙蒙，夏月寒飕飕。\n回合俯近郭，寥落见远舟。\n胜概无端倪，天宫可淹留。\n一官讵足道，欲去令人愁。' },
  { title: '与高适薛据慈恩寺浮图', author: '岑参', poem: '塔势如涌出，孤高耸天宫。\n登临出世界，磴道盘虚空。\n突兀压神州，峥嵘如鬼工。\n四角碍白日，七层摩苍穹。\n下窥指高鸟，俯听闻惊风。\n连山若波涛，奔凑似朝东。\n青槐夹驰道，宫馆何玲珑。\n秋色从西来，苍然满关中。\n五陵北原上，万古青蒙蒙。\n净理了可悟，胜因夙所宗。\n誓将挂冠去，觉道资无穷。' },
  { title: '登千福寺楚金禅师法华院多宝塔', author: '岑参', poem: '多宝灭已久，莲华付吾师。\n宝塔凌太空，忽如涌出时。\n数年功不成，一志坚自持。\n明主亲梦见，世人今始知。\n千家献黄金，万匠磨琉璃。\n既空泰山木，亦罄天府赀。\n焚香如云屯，蟠盖珊珊垂。\n悉窣神绕护，众魔不敢窥。\n作礼覩灵境，焚香方证疑。\n庶割区中缘，脱身恒在兹。' },
  { title: '出关经华岳寺访法华云公', author: '岑参', poem: '野寺聊解鞍，偶见法华僧。\n开门对西岳，石壁青棱层。\n竹径厚苍苔，松门盘紫藤。\n长廊列古画，高殿悬孤灯。\n五月山雨热，三峰火云蒸。\n侧闻樵人言，深谷犹积冰。\n久愿寻此山，至今嗟未能。\n谪官忽东走，王程苦相仍。\n欲去恋双树，何由穷一乘。\n月轮吐山郭，夜色空清澄。' },
  { title: '春半与群公同游元处士别业', author: '岑参', poem: '郭南处士宅，门外罗群峰。\n胜概忽相引，春华今正浓。\n山厨竹里爨，野碓藤间舂。\n对酒云数片，卷帘花万重。\n岩泉嗟到晚，州县欲归慵。\n草色带朝雨，滩声兼夜钟。\n爱兹清俗虑，何事老尘容。\n况有林下约，转怀方外踪。' },
  { title: '陪群公龙冈寺泛舟', author: '岑参', poem: '汉水天一色，寺楼波底看。\n钟鸣长空夕，月出孤舟寒。\n映酒见山火，隔帘闻夜滩。\n紫鳞掣芳饵，红烛然金盘。\n良友兴正惬，胜游情未阑。\n此中堪倒载，须尽主人欢。' },
  { title: '终南山双峰草堂作', author: '岑参', poem: '敛迹归山田，息心谢时辈。\n昼还草堂卧，但与双峰对。\n兴来恣佳游，事惬符胜槩。\n著书高牕下，日夕见城内。\n曩为世人误，遂负平生爱。\n久与林壑辞，及来松杉大。\n偶兹近精庐，屡得名僧会。\n有时逐樵渔，尽日不冠带。\n崖口上新月，石门破苍霭。\n色向群木深，光摇一潭碎。\n缅怀郑生谷，颇忆严子濑。\n胜事犹可追，斯人邈千载。' },
  { title: '左仆射相国冀公东斋幽居', author: '岑参', poem: '丞相百僚长，两朝居此官。\n成功云雷际，翊圣天地安。\n不矜南宫贵，祗向东山看。\n宅占凤城胜，牕中云岭宽。\n午时松轩夕，六月藤斋寒。\n玉珮罥女萝，金印耀牡丹。\n山蝉上衣桁，野鼠缘药盘。\n有时披道书，竟日不着冠。\n幸得趋省闱，常欣在门阑。\n何当复持衡，短翮期风[抟]。' },
  { title: '过缑山王处士黑石谷隐居', author: '岑参', poem: '旧居缑山下，偏识缑山云。\n处士久不还，见云如见君。\n别来逾十秋，兵马日纷纷。\n青谿开战场，黑谷屯行军。\n遂令巢由辈，远逐麋鹿群。\n独有南涧水，潺湲如昔闻。' },
  { title: '缑山西峰草堂作', author: '岑参', poem: '结庐对中岳，青翠常在门。\n遂耽水木兴，尽作渔樵言。\n顷来阙章句，但欲闲心魂。\n日色隐空谷，蝉声喧暮村。\n曩闻道士语，偶见清净源。\n隐几阅吹叶，乘秋眺归根。\n独游念求仲，开径招王孙。\n片雨下南涧，孤峰出东原。\n栖迟虑益澹，脱略道弥敦。\n野霭晴拂枕，客帆遥入轩。\n尚平今何在，此意谁与论。\n伫立云去尽，苍苍月开园。' },
  { title: '观楚国寺璋上人写一切经院南有曲池深竹', author: '岑参', poem: '璋公不出院，群木闭深居。\n誓写一切经，欲向万卷余。\n挥毫散林鹊，研墨警池鱼。\n音翻四句偈，字译五天书。\n鸣钟竹阴晚，汲水桐花初。\n雨气润衣钵，香烟泛庭除。\n此地日清净，诸天应未如。\n不知将锡杖，早晚蹑空虚。' },
  { title: '寻巩县南李处士别业', author: '岑参', poem: '先生近南郭，茅屋临东川。\n桑叶隐村户，芦花映钓船。\n有时著书暇，尽日牕中眠。\n且喜闾井近，灌田同一泉。' },
  { title: '闻崔十二侍御灌口夜宿报恩寺', author: '岑参', poem: '闻君寻野寺，便宿支公房。\n溪月冷深殿，江云拥回廊。\n然灯松林静，煮茗柴门香。\n胜事不可接，相思幽兴长。' },
  { title: '自潘陵尖还少室居止秋夕凭眺', author: '岑参', poem: '草堂近少室，夜静闻风松。\n月出潘陵尖，照见十六峰。\n九月山叶赤，谿云淡秋容。\n火点伊阳村，烟深嵩角钟。\n尚子不可见，蒋生难再逢。\n胜惬只自知，佳趣为谁浓。\n昨诣山僧期，上到天坛东。\n向下望雷雨，云间见回龙。\n夕与人群疎，转爱丘壑中。\n心澹水木会，兴幽鱼鸟通。\n稀微了自释，出处乃不同。\n况本无宦情，誓将依道风。' },
  { title: '南池夜宿思王屋青萝旧斋', author: '岑参', poem: '池上卧烦暑，不栉复不巾。\n有时清风来，自谓羲皇人。\n天晴云归尽，雨洗月色新。\n公事常不闲，道书日生尘。\n早年家王屋，五别青萝春。\n安得还旧山，东谿垂钓纶。' },
  { title: '过王判官西津所居', author: '岑参', poem: '胜迹不在远，爱君池馆幽。\n素怀岩中诺，宛得尘外游。\n何必到清谿，忽来见沧洲。\n潜移岷山石，暗引巴江流。\n树密昼先夜，竹深夏已秋。\n沙鸟上笔床，谿花篲帘钩。\n夫子贱簪冕，注心向林丘。\n落日出公堂，垂纶乘钓舟。\n赋诗忆楚老，载酒随江鸥。\n翛然一傲吏，独在西津头。' },
  { title: '因假归白阁西草堂', author: '岑参', poem: '雷声傍太白，雨在八九峰。\n东望白阁云，半入紫阁松。\n胜概纷满目，衡门趣弥浓。\n幸有数亩田，得延二仲踪。\n早闻达士语，偶与心相通。\n误徇一微官，还山愧尘容。\n钓竿不复把，野碓无人舂。\n惆怅飞鸟尽，南谿闻夜钟。' },
  { title: '题华严寺瓌公禅房', author: '岑参', poem: '寺南几十峰，峰翠晴可掬。\n朝从老僧饭，昨日崖口宿。\n锡杖倚枯松，绳床暎深竹。\n东谿草堂路，来往行自熟。\n生事在云山，谁能复羁束。' },
  { title: '东归留题太常徐卿草堂', author: '岑参', poem: '不谢古名将，吾知徐太常。\n年才三十余，勇冠西南方。\n顷曾策匹马，独出持两鎗。\n虏骑无数来，见君不敢当。\n汉将小卫霍，蜀将凌关张。\n卿月益清澄，将星转光芒。\n复居少城北，遥对岷山阳。\n车马日盈门，宾客常满堂。\n曲池荫高树，小径穿丛篁。\n江鸟飞入帘，山云来到床。\n题诗芭蕉滑，对酒椶花香。\n诸将射猎时，君在翰墨场。\n圣主赏勋业，边城最辉光。\n与我情绸缪，相知久芬芳。\n忽作万里别，东归三峡长。' },
  { title: '太一石鳖崖口潭旧庐招王学士', author: '岑参', poem: '骤雨鸣淅沥，飕飗谿谷寒。\n碧潭千余尺，下见蛟龙蟠。\n石门吞众流，绝岸呀层峦。\n幽趣倏万变，奇观非一端。\n偶逐干禄徒，十年皆小官。\n抱板寻旧圃，弊庐临迅湍。\n君子满清朝，小人思挂冠。\n酿酒漉松子，引泉通竹竿。\n何必濯沧浪，不能钓严滩。\n此地可遗老，劝君来考槃。' },
  { title: '林卧', author: '岑参', poem: '偶得鱼鸟趣，复兹水木凉。\n远峰带雨色，落日摇川光。\n臼中西山药，袖里淮南方。\n唯爱隐几时，独游无何乡。' },
  { title: '骊姬墓下作', author: '岑参', poem: '骊姬北原上，闭骨已千秋。\n浍水日东注，恶名终不流。\n献公恣耽惑，视子如仇雠。\n此事成蔓草，我来逢古丘。\n蛾眉山月苦，蝉鬓野云愁。\n欲吊二公子，横汾无轻舟。' },
  { title: '东归晚次潼关怀古', author: '岑参', poem: '暮春别乡树，晚景低津楼。\n伯夷在首阳，欲往无轻舟。\n遂登关城望，下见洪河流。\n自从巨灵开，流血千万秋。\n行行潘生赋，赫赫曹公谋。\n川上多往事，凄凉满空洲。' },
  { title: '楚夕旅泊古兴', author: '岑参', poem: '独鹤唳江月，孤帆凌楚云。\n秋风冷萧瑟，芦荻花纷纷。\n忽思湘川老，欲访云中君。\n骐𬴊息悲鸣，愁见豺虎群。' },
  { title: '先主武侯庙', author: '岑参', poem: '先主与武侯，相逢云雷际。\n感通君臣分，义激鱼水契。\n遗庙空萧然，英灵贯千岁。' },
  { title: '文公讲堂', author: '岑参', poem: '文公不可见，空使蜀人传。\n讲席何时散，高台岂复全。\n丰碑文字灭，冥漠不知年。' },
  { title: '杨雄草玄台', author: '岑参', poem: '吾悲子云居，寂寞人已去。\n娟娟西江月，犹照草玄处。\n精怪喜无人，睢盱藏老树。' },
  { title: '司马相如琴台', author: '岑参', poem: '相如琴台古，人去台亦空。\n台上寒萧条，至今多悲风。\n荒台汉时月，色与旧时同。' },
  { title: '严君平卜肆', author: '岑参', poem: '君平曾卖卜，卜肆芜已久。\n至今杖头钱，时时地上有。\n不知支机石，还在人间否。' },
  { title: '张仪楼', author: '岑参', poem: '传是秦时楼，巍巍至今在。\n楼南两江水，千古长不改。\n曾闻昔时人，岁月不相待。' },
  { title: '升仙桥', author: '岑参', poem: '长桥题柱去，犹是未达时。\n及乘驷马车，却从桥上归。\n名共东流水，滔滔无尽期。' },
  { title: '万里桥', author: '岑参', poem: '成都与维扬，相去万里地。\n沧江东流疾，帆去如鸟翅。\n楚客过此桥，东看尽垂泪。' },
  { title: '石犀', author: '岑参', poem: '江水初荡潏，蜀人几为鱼。\n向无尔石犀，安得有邑居。\n始知李太守，伯禹亦不如。' },
  { title: '龙女祠', author: '岑参', poem: '龙女何处来，来时乘风雨。\n祠堂青林下，宛宛如相语。\n蜀人竞祈恩，捧酒仍击鼓。' },
  { title: '使交河郡郡在火山脚其地苦热无雨雪献封大夫', author: '岑参', poem: '奉使按胡俗，平明发轮台。\n暮投交河城，火山赤崔巍。\n九月尚流汗，炎风吹沙埃。\n何事阴阳工，不遣雨雪来。\n吾君方忧边，分阃资大才。\n昨者新破胡，安西兵马回。\n铁关控天涯，万里何辽哉。\n烟尘不敢飞，白草空皑皑。\n军中日无事，醉舞倾金罍。\n汉代李将军，微功合可咍。' },
  { title: '与鲜于庶子自梓州成都少尹自襃城同行至利州道中作', author: '岑参', poem: '剖竹向西蜀，岷峨眇天涯。\n空深北阙恋，岂惮南路赊。\n前日登七盘，旷然见三巴。\n汉水出嶓冢，梁山控襃斜。\n栈道笼迅湍，行人贯层崖。\n岩倾劣通马，石窄难容车。\n深林怯魑魅，洞穴防龙蛇。\n水种新插秧，山田正烧畬。\n夜猿啸山雨，曙鸟鸣江花。\n过午方始饭，经时旋及瓜。\n数公各游宦，千里皆辞家。\n言笑忘羁旅，还如在京华。' },
  { title: '下外江舟怀终南旧居', author: '岑参', poem: '杉冷晓猿悲，楚客心欲绝。\n孤舟巴山雨，万里阴台月。\n水宿已淹时，芦花白如雪。\n颜容老难赪，把镜悲鬓发。\n早年好金丹，方士传口诀。\n敝庐终南下，久与真侣别。\n道书谁更开，药灶烟遂灭。\n顷来压尘网，安得有仙骨。\n岩壑归去来，公卿是何物。' },
  { title: '安西馆中思长安', author: '岑参', poem: '家在日出处，朝来起东风。\n风从帝乡来，不异家信通。\n绝域地欲尽，孤城天遂穷。\n弥年但走马，终日随飘蓬。\n寂寞不得意，辛勤方在公。\n胡尘净古塞，兵气屯边空。\n乡路眇天外，归期如梦中。\n遥凭长房术，为缩天山东。' },
  { title: '暮秋山行', author: '岑参', poem: '疲马卧长坂，夕阳下通津。\n山风吹空林，飒飒如有人。\n苍旻霁凉雨，石路无飞尘。\n千念集暮节，万籁悲萧晨。\n𫛸鴂昨夜鸣，蕙草色已陈。\n况在远行客，自然多苦辛。' },
  { title: '赴犍为经龙阁道', author: '岑参', poem: '侧径转青壁，危梁透沧波。\n汗流出鸟道，胆碎窥龙涡。\n骤雨暗谿口，归云网松萝。\n屡闻羌儿笛，厌听巴童歌。\n江路险复永，梦魂愁更多。\n圣朝幸典郡，不敢嫌岷峨。' },
  { title: '江上阻风雨', author: '岑参', poem: '江上风欲来，泊舟未能发。\n气昏雨已过，突兀山复出。\n积浪成高丘，盘涡为嵌窟。\n云低岸花掩，水涨滩草没。\n老树蛇蜕皮，崩崖龙退骨。\n平生抱忠信，艰险殊可忽。' },
  { title: '经火山', author: '岑参', poem: '火山今始见，突兀蒲昌东。\n赤焰烧虏云，炎氛蒸塞空。\n不知阴阳炭，何独然此中。\n我来严冬时，山下多炎风。\n人马尽汗流，孰知造化功。' },
  { title: '题铁门关楼', author: '岑参', poem: '铁关天西涯，极目少行客。\n关门一小吏，终日对石壁。\n桥跨千仞危，路盘两崖窄。\n试登西楼望，一望头欲白。' },
  { title: '早上五盘岭', author: '岑参', poem: '平旦驱驷马，旷然出五盘。\n江回两崖鬬，日隐群峰攒。\n苍翠烟景曙，森沈云树寒。\n松疎露孤驿，花密藏回滩。\n栈道谿雨滑，畬田原草干。\n此行为知己，不觉蜀道难。' },
  { title: '峨眉东脚临江听猿怀二室旧庐', author: '岑参', poem: '峨眉烟翠新，昨夜秋雨洗。\n分明峰头树，倒插秋江底。\n久别二室间，图他五斗米。\n哀猿不可听，北客欲流涕。' },
  { title: '东归发犍为至泥谿舟中作', author: '岑参', poem: '前日解侯印，泛舟归山东。\n平旦发犍为，逍遥信回风。\n七月江水大，沧波涨秋空。\n复有峨眉僧，诵经在舟中。\n夜泊防虎豹，朝行逼鱼龙。\n一道鸣迅湍，两边走连峰。\n猿拂岸花落，鸟啼檐树重。\n烟霭吴楚连，溯沿湖海通。\n忆昨在西掖，复曾入南宫。\n日出朝圣人，端笏陪群公。\n不意今弃置，何由豁心胸。\n吾当海上去，且学乘桴翁。' },
  { title: '阻戎泸间群盗', author: '岑参', poem: '南州林莽深，亡命聚其间。\n杀人无昏晓，尸积填江湾。\n饿虎衔髑髅，饥乌啄心肝。\n腥裛滩草死，血流江水殷。\n夜雨风萧萧，鬼哭连楚山。\n三江行人绝，万里无征船。\n唯有白鸟飞，空见秋月园。\n罢官自南蜀，假道来兹川。\n瞻望阳台云，惆怅不敢前。\n帝乡北近日，泸口南连蛮。\n何当遇长房，缩地到京关。\n愿得随琴高，骑鱼向云烟。\n明主每忧人，节使恒在边。\n兵革方御寇，尔恶胡不悛。\n吾窃悲尔徒，此生安得全。' },
  { title: '郡斋闲坐', author: '岑参', poem: '负郭无良田，屈身狥微禄。\n平生好疎旷，何事就羁束。\n幸曾趋丹墀，数得侍黄屋。\n故人尽荣宠，谁念此幽独。\n州县非宿心，云山欣满目。\n顷来废章句，终日披案牍。\n佐郡竟何成，自悲徒碌碌。' },
  { title: '衙郡守还', author: '岑参', poem: '世事何反复，一身难可料。\n头白翻折腰，还家私自笑。\n所嗟无产业，妻子嫌不调。\n五斗米留人，东谿忆垂钓。' },
  { title: '行军诗二首 一', author: '岑参', poem: '吾窃悲此生，四十幸未老。\n一朝逢世乱，终日不自保。\n胡兵夺长安，宫殿生野草。\n伤心五陵树，不见二京道。\n我皇在行军，兵马日浩浩。\n胡雏尚未灭，诸将恳征讨。\n昨闻咸阳败，杀戮净如扫。\n积尸若丘山，流血涨丰镐。\n干戈碍乡国，豺虎满城堡。\n村落皆无人，萧条空桑枣。\n儒生有长策，无处豁怀抱。\n块然伤时人，举首哭苍昊。' },
  { title: '行军诗二首 二', author: '岑参', poem: '早知逢世乱，少小谩读书。\n悔不学弯弓，向东射狂胡。\n偶从谏官列，谬向丹墀趋。\n未能匡吾君，虚作一丈夫。\n抚劒伤世路，哀歌泣良图。\n功业今已迟，览镜悲白须。\n平生抱忠义，不敢私微躯。' },
  { title: '秋夕听罗山人弹三峡流泉', author: '岑参', poem: '皤皤岷山老，抱琴鬓苍然。\n衫袖拂玉徽，为弹三峡泉。\n此曲弹未半，高堂如空山。\n石林何[飕飗]，忽在窗户间。\n绕指弄呜咽，青丝激潺湲。\n演漾怨楚云，虚徐韵秋烟。\n疑兼阳台雨，似杂巫山猿。\n幽引鬼神听，净令耳目便。\n楚客肠欲断，湘妃泪斑斑。\n谁裁青桐枝，絚以朱丝弦。\n能含古人曲，递与今人传。\n知音难再逢，惜君方年老。\n曲终月已落，惆[怅]东斋眠。' },
  { title: '尹相公京兆府中棠树降甘露诗', author: '岑参', poem: '相国尹京兆，政成人不欺。\n甘露降府庭，上天表无私。\n非无他人家，岂少群木枝。\n被兹甘棠树，美掩召伯诗。\n团团甜如[蜜]，皛皛凝若脂。\n千柯玉光碎，万叶珠颗垂。\n昆仑何时来，庆云相逐飞。\n魏宫铜盘贮，汉帝金掌持。\n王泽布人和，精心动灵祇。\n君臣日同德，祯瑞方潜施。\n何术令大臣，感通能及兹。\n忽惊政化理，暗与神物期。\n却笑赵张辈，徒称今古稀。\n为君天下酒，曲糵将用时。' },
  { title: '刘相公中书江山画障', author: '岑参', poem: '相府征墨妙，挥毫天地穷。\n始知丹青笔，能夺造化功。\n潇湘在帘间，庐壑横座中。\n忽疑凤凰池，暗与江海通。\n粉白湖上云，黛青天际峰。\n昼日恒见月，孤帆如有风。\n岩花不飞落，涧草无春冬。\n担锡香𬬻缁，钓鱼沧浪翁。\n如何平津意，尚想尘外踪。\n富贵心独轻，山林兴弥浓。\n喧幽趣颇异，出处事不同。\n请君为苍生，未可追赤松。' },
  { title: '精卫', author: '岑参', poem: '负劒出北门，乘桴适东溟。\n一鸟海上飞，云是帝女灵。\n玉颜溺水死，精卫空为名。\n怨积徒有志，力微竟不成。\n西山木石尽，巨壑何时平。' },
  { title: '石上藤', author: '岑参', poem: '石上生孤藤，弱蔓依石长。\n不逢高枝引，未得凌空上。\n何处堪托身，为君长万丈。' },
  { title: '临河客舍呈狄明府兄留题县南楼', author: '岑参', poem: '黎阳城南雪正飞，黎阳渡头人未归。\n河边酒家堪寄宿，主人小女能缝衣。\n故人高卧黎阳县，一别三年不相见。\n邑中雨雪偏着时，隔河东郡人遥羡。\n邺都唯见古时丘，漳水还如旧日流。\n城上望乡应不见，朝来好是嬾登楼。' },
  { title: '客舍悲秋有怀两省旧游呈幕中诸公', author: '岑参', poem: '三度为郎便白头，一从出守五经秋。\n莫言圣主长不用，其那苍生应未休。\n人间岁月如流水，客舍秋风今又起。\n不知心事向谁论，江上蝉鸣空满耳。' },
  { title: '白雪歌送武判官归京', author: '岑参', poem: '北风卷地白草折，胡天八月即飞雪。\n忽然一夜春风来，千树万树梨花开。\n散入珠帘湿罗幕，狐裘不煖锦衾薄。\n将军角弓不得控，都护铁衣冷难着。\n瀚海阑干百丈冰，愁云黪淡万里凝。\n中军置酒饮归客，胡琴琵琶与羌笛。\n纷纷暮雪下辕门，风掣红旗冻不翻。\n轮台东门送君去，去时雪满天山路。\n山回路转不见君，雪上空留马行处。' },
  { title: '热海行送崔侍御还京', author: '岑参', poem: '侧闻阴山胡儿语，西头热海水如煮。\n海上众鸟不敢飞，中有鲤鱼长且肥。\n岸傍青草常不歇，空中白雪遥旋灭。\n蒸沙烁石然虏云，沸浪炎波煎汉月。\n阴火潜烧天地𬬻，何事偏烘西一隅。\n势吞月窟侵太白，气连赤坂通单于。\n送君一醉天山郭，正见夕阳海边落。\n柏台霜威寒逼人，热海炎气为之薄。' },
  { title: '轮台歌奉送封大夫出师西征', author: '岑参', poem: '轮台城头夜吹角，轮台城北旄头落。\n羽书昨夜过渠黎，单于已在金山西。\n戍楼西望烟尘黑，汉兵屯在轮台北。\n上将拥旄西出征，平明吹笛大军行。\n四边伐鼓雪海涌，三军大呼阴山动。\n虏塞兵气连云屯，战场白骨缠草根。\n劒河风急雪片阔，沙口石冻马蹄脱。\n亚相勤王甘苦辛，誓将报主静边尘。\n古来青史谁不见，今见功名胜古人。' },
  { title: '敷水歌送窦渐入京', author: '岑参', poem: '罗敷昔时秦氏女，千载无人空处所。\n昔时流水至今流，万事皆逐东流去。\n此水东流无尽期，水声还似旧来时。\n岸花仍自羞红脸，隄柳犹能学翠眉。\n春去秋来不相待，水中月色长不改。\n罗敷养蚕空耳闻，使君五马今何在？\n九月霜天水正寒，故人西去度征鞍。\n水底鲤鱼幸无数，愿君别后垂尺素。' },
  { title: '天山雪歌送萧治归京', author: '岑参', poem: '天山有雪常不开，千峰万岭雪崔嵬。\n北风夜卷赤亭口，一夜天山雪更厚。\n能兼汉月照银山，复逐胡风过铁关。\n交河城边飞鸟绝，轮台路上马蹄滑。\n晻霭寒氛万里凝，阑干阴崖千丈冰。\n将军狐裘卧不暖，都护宝刀冻欲断。\n正是天山雪下时，送君走马归京师。\n雪中何以赠君别，惟有青青松树枝。' },
  { title: '火山云歌送别', author: '岑参', poem: '火山突兀赤亭口，火山五月火云厚。\n火云满山凝未开，飞鸟千里不敢来。\n平明乍逐胡风断，薄暮浑随塞雨回。\n缭绕斜吞铁关树，氛氲半掩交河戍。\n迢迢征路火山东，山上孤云随马去。' },
  { title: '青门歌送东台张判官', author: '岑参', poem: '青门金锁平旦开，城头日出使车回。\n青门柳枝正堪折，路傍一日几人别。\n东出青门路不穷，驿楼官树灞陵东。\n花扑征衣看似绣，云随去马色疑骢。\n胡姬酒垆日未午，丝绳玉缸酒如乳。\n灞头落花没马蹄，昨夜微雨花成泥。\n黄鹂翅湿飞转低，关东尺书醉嬾题。\n须臾望君不可见，扬鞭飞鞚疾如箭。\n借问使乎何时来，莫作东飞伯劳西飞燕。' },
  { title: '梁园歌送河南王说判官', author: '岑参', poem: '君不见梁孝王修竹园，颓墙隐辚势仍存。\n娇娥曼脸成草蔓，罗帷珠帘空竹根。\n大梁一旦人代改，秋月春风不相待。\n池中几度雁新来，洲上千年鹤应在。\n梁园二月梨花飞，却似梁王雪下时。\n当时置酒延枚叟，肯料平台狐兔走。\n万事翻覆如浮云，昔人空在今人口。\n单父古来称宓生，祗今为政有吾兄。\n𬨎轩若过梁园道，应傍琴台闻政声。' },
  { title: '走马川行奉送出师西征', author: '岑参', poem: '君不见走马川行雪海边，平沙莽莽黄入天。\n轮台九月风夜吼，一川碎石大如斗，随风满地石乱走。\n匈奴草黄马正肥，金山西见烟尘飞。\n汉家大将西出师，将军金甲夜不脱。\n半夜军行戈相拨，风头如刀面如割。\n马毛带雪汗气蒸，五花连钱旋作冰。\n幕中草檄砚水凝，虏骑闻之应胆慑。\n料知短兵不敢接，车师西门伫献捷。' },
  { title: '函谷关歌送刘评事使关西', author: '岑参', poem: '君不见函谷关，崩城毁壁至今在。\n树根草蔓遮古道，空谷千年长不改。\n寂寞无人空旧山，圣朝无外不须关。\n白马公孙何处去，青牛老人更不还。\n苍苔白骨空满地，月与古时长相似。\n野花不省见行人，山鸟何曾识关吏。\n故人方乘使者车，吾知郭丹却不如。\n请君时忆关外客，行到关西多致书。' },
  { title: '胡笳歌送颜真卿使赴河陇', author: '岑参', poem: '君不闻胡笳声最悲，紫髯绿眼胡人吹。\n吹之一曲犹未了，愁杀楼兰征戍儿。\n凉秋八月萧关道，北风吹断天山草。\n昆仑山南月欲斜，胡人向月吹胡笳。\n胡笳怨兮将送君，秦山遥望陇山云。\n边城夜夜多愁梦，向月胡笳谁喜闻。' },
  { title: '秦筝歌送外甥萧正归京', author: '岑参', poem: '汝不闻秦筝声最苦，五色缠弦十三柱。\n怨调慢声如欲语，一曲未终日移午。\n红亭水木不知暑，忽弹黄钟和白纻。\n清风飒来云不去，闻之酒醒泪如雨。\n汝归秦兮弹秦声，秦声悲兮聊送汝。' },
  { title: '与独孤渐道别长句兼呈严八侍御', author: '岑参', poem: '轮台客舍春草满，颍阳归客肠堪断。\n穷荒绝漠鸟不飞，万碛千山梦犹嬾。\n怜君白面一书生，读书千卷未成名。\n五侯贵门脚不到，数亩山田身自耕。\n兴来浪迹无远近，及至辞家忆乡信。\n无事垂鞭信马头，西南几欲穷天尽。\n[奉]使三年独未归，边头词客旧来稀。\n借问君来得几日，到家不觉换春衣。\n高斋清昼卷帷幕，纱帽接䍠慵不着。\n中酒朝眠日色高，弹棋夜半灯花落。\n冰片高堆金错盘，满堂凛凛五月寒。\n桂林蒲萄新吐蔓，武城刺蜜未可餐。\n军中置酒夜挝鼓，锦筵红烛月未午。\n花门将军善胡歌，叶河蕃王能汉语。\n知尔园林压渭滨，夫人堂上泣罗帬。\n鱼龙川北盘谿雨，鸟鼠山西洮水云。\n台中严公于我厚，别后新诗满人口。\n自怜弃置天西头，因君为问相思否。' },
  { title: '送费子归武昌', author: '岑参', poem: '汉阳归客悲秋草，旅舍叶飞愁不扫。\n秋来倍忆武昌鱼，梦着只在巴陵道。\n曾随上将过祁连，离家十年恒在边。\n劒锋可惜虚用尽，马蹄无事今已穿。\n知君开馆常爱客，樗蒱百金每一掷。\n平生有钱将与人，江上故园空四壁。\n吾观费子毛骨奇，广眉大口仍赤髭。\n看君失路尚如此，人生贵贱那得知。\n高秋八月归南楚，东门一壶聊出祖。\n路指凤皇山北云，衣沾鹦鹉洲边雨。\n勿叹蹉跎白发新，应须守道勿羞贫。\n男儿何必恋妻子，莫向江村老却人。' },
  { title: '送韩巽入都觐省便赴举', author: '岑参', poem: '槐叶苍苍柳叶黄，秋高八月天欲霜。\n青门百壶送韩侯，白云千里连嵩丘。\n北堂倚门望君忆，东归扇枕后秋色。\n洛阳才子能几人，明年桂枝是君得。' },
  { title: '送李副使赴碛西官车', author: '岑参', poem: '火山六月应更热，赤亭道口行人绝。\n知君惯度祁连城，岂能愁见轮台月。\n脱鞍暂入酒家垆，送君万里西击胡。\n功名祗向马上取，真是英雄一丈夫。' },
  { title: '凉州馆中与诸判官夜集', author: '岑参', poem: '弯弯月出挂城头，城头月出照梁州。\n凉州七里十万家，胡人半解弹琵琶。\n琵琶一曲肠堪断，风萧萧兮夜漫漫。\n河西幕中多故人，故人别来三五春。\n花门楼前见秋草，岂能贫贱相看老。\n一生大笑能几回，斗酒相逢须醉倒。' },
  { title: '酒泉太守席上醉后作', author: '岑参', poem: '琵琶长笛曲相和，羌儿胡雏齐唱歌。\n浑炙犂牛烹野驼，交河美酒归叵罗。\n三更醉后军中寝，无奈秦山归梦何。' },
  { title: '偃师东与韩樽同诣景云晖上人即事', author: '岑参', poem: '山阴老僧解楞伽，颍阳归客远相过。\n烟深草湿昨夜雨，雨后秋风渡漕河。\n空山终日尘事少，平郊远见行人小。\n尚书碛上黄昏钟，别驾渡头一归鸟。' },
  { title: '醉题匡城周少府厅壁', author: '岑参', poem: '妇姑城南风雨秋，妇姑城中人独愁。\n愁云遮却望乡处，数日不上西南楼。\n故人薄暮公事闲，玉壶美酒琥珀殷。\n颍阳秋草今黄尽，醉卧君家犹未还。' },
  { title: '炖煌太守后庭歌', author: '岑参', poem: '炖煌太守才且贤，郡中无事高枕眠。\n太守到来山出泉，黄砂碛里人种田。\n炖煌耆旧鬓皓然，愿留太守更五年。\n城头月出星满天，曲房置酒张锦筵。\n美人红妆色正鲜，侧垂高髻插金钿。\n醉坐藏钩红烛前，不知钩在若个边。\n为君手把珊瑚鞭，射得半段黄金钱，此中乐事亦已偏。' },
  { title: '喜韩樽相过', author: '岑参', poem: '三月灞陵春已老，故人相逢耐醉倒。\n瓮头春酒黄花脂，禄米只充沽酒资。\n长安城中足年少，独共韩侯开口笑。\n桃花点地红斑斑，有酒留君且莫还。\n与君兄弟日携手，世上虚名好是闲。' },
  { title: '银山碛西馆', author: '岑参', poem: '银山碛口风似箭，铁门关西月如练。\n双双愁泪沾马毛，飒飒胡沙迸人面。\n丈夫三十未富贵，安能终日守笔砚。' },
  { title: '感遇', author: '岑参', poem: '五花骢马七香车，云是平阳帝子家。\n凤皇城头日欲斜，门前高树鸣春鸦。\n汉家鲁元君不闻，今作城西一古坟。\n昔来唯有秦王女，独自吹萧乘白云。' },
  { title: '太白胡僧歌', author: '岑参', poem: '闻有胡僧在太白，兰若去天三百尺。\n一持楞伽入中峰，世人难见但闻钟。\n牕边锡杖解两虎，床下钵盂藏一龙。\n草衣不针复不线，两耳垂肩眉覆面。\n此僧年几那得知，手种青松今十围。\n心将流水同清净，身与浮云无是非。\n商山老人已曾识，愿一见之何由得。\n山中有僧人不知，城里看山空黛色。' },
  { title: '卫节度赤骠马歌', author: '岑参', poem: '君家赤骠画不得，一团旋风桃花色。\n红缨紫鞚珊瑚鞭，玉鞍锦鞯黄金勒。\n请君鞲出看君骑，尾长窣地如红丝。\n自矜诸马皆不及，却忆百金新买时。\n香街紫陌凤城内，满城见者谁不爱。\n扬鞭骤急白汗流，弄影行骄碧蹄碎。\n紫髯胡雏金剪刀，平明剪出三鬉高。\n枥上看时独意气，众中牵出偏雄豪。\n骑将猎向南山口，城南孤兔不复有。\n草头一点疾如飞，却使苍鹰翻向后。\n忆昨看君朝未央，鸣珂拥盖满路香。\n始知边将真富贵，可怜人马相辉光。\n男儿称意得如此，骏马长鸣北风起。\n待君东去埽胡尘，为君一日行千里。' },
  { title: '田使君美人舞如莲花北鋋歌', author: '岑参', poem: '美人舞如莲花旋，世人有眼应未见。\n高堂满地红氍毹，试舞一曲天下无。\n此曲胡人传入汉，诸客见之惊且叹。\n慢脸娇娥纤复秾，轻罗金缕花葱茏。\n回裾转袖若飞雪，左鋋右鋋生旋风。\n琵琶横笛和未匝，花门山头黄云合。\n忽作出塞入塞声，白草胡沙寒飒飒。\n翻身入破如有神，前见后见回回新。\n始知诸曲不可比，采莲落梅徒聒耳。\n世人学舞祗是舞，恣态岂能得如此。' },
  { title: '裴将军宅芦管歌', author: '岑参', poem: '辽东九月芦叶断，辽东小儿采芦管。\n可怜新管清且悲，一曲风飘海头满。\n海树萧索天雨霜，管声寥亮月苍苍。\n白狼河北堪愁恨，玄兔城南皆断肠。\n辽东将军长安宅，美人芦管会佳客。\n弄调啾飕胜洞箫，发声窈窕欺横笛。\n夜半高堂客未回，祗将芦管送君杯。\n巧能陌上惊杨柳，复向园中误落梅。\n诸客爱之听未足，高卷珠帘列红烛。\n将军醉舞不肯休，更使美人吹一曲。' },
  { title: '韦员外家花树歌', author: '岑参', poem: '今年花似去年好，去年人到今年老。\n始知人老不如花，可惜落花君莫埽。\n君家兄弟不可当，列卿御史尚书郎。\n朝回花底恒会客，花扑玉缸春酒香。' },
  { title: '醉后戏与赵歌儿', author: '岑参', poem: '秦州歌儿歌调苦，偏能立唱濮阳女。\n座中醉客不得意，闻之一声泪如雨。\n向使逢着汉帝怜，董贤气咽不能语。' },
  { title: '范公丛竹歌', author: '岑参', poem: '世人见竹不解爱，知君种竹府城内。\n此君托根幸得地，种来几时闻已大。\n盛暑翛翛丛色寒，闲宵槭槭叶声干。\n能清案牍帘下见，宜对琴书窗外看。\n为君成阴将蔽日，迸笋穿堦踏还出。\n守节偏凌御史霜，虚心愿比郎官笔。\n君莫爱南山松树枝，竹色四时也不移。\n寒天草木黄落尽，犹自青青君始知。' },
  { title: '玉门关盖将军歌', author: '岑参', poem: '盖将军，真丈夫，行年三十执金吾，身长七尺颇有须。\n玉门关城迥且孤，黄沙万里白草枯。\n南邻犬戎北接胡，将军到来备不虞。\n五千甲兵胆力麤，军中无事但欢娱。\n暖屋绣帘红地炉，织成壁衣花氍毹。\n灯前侍婢泻玉壶，金铛乱点野酡酥。\n紫绂金章左右趋，问着只是苍头奴。\n美人一双闲且都，朱唇翠眉映明𪾦。\n清歌一曲世所无，今日喜闻凤将雏。\n可怜绝胜秦罗敷，使君五马谩踟蹰。\n野草绣窠紫罗襦，红牙缕马对樗蒱。\n玉盘纤手撒作卢，众中夸道不曾输。\n枥上昂昂皆骏驹，桃花叱拨价最殊。\n骑将猎向城南隅，腊日射杀千年狐。\n我来塞外按边储，为君取醉酒剩沽。\n醉争酒盏相喧呼，忽忆咸阳旧酒徒。' },
  { title: '赠酒泉韩太守', author: '岑参', poem: '太守有能政，遥闻如古人。\n俸钱尽供客，家计常清贫。\n酒泉西望玉关道，千山万碛皆白草。\n辞君走马归长安，忆君倏忽令人老。' },
  { title: '赠西岳山人李冈', author: '岑参', poem: '君隐处，当一星，莲花峰头饭黄精，仙人掌上演丹经。\n鸟可到，人莫攀，隐来十年不下山。\n袖中短书谁为达，华阴道士卖药还。' },
  { title: '送张献心充副使归河西杂句', author: '岑参', poem: '将门子弟君独贤，一从受命常在边。\n未至三十已高位，腰间金印色赭然。\n前日承恩白虎殿，归来见者谁不羡。\n箧中赐衣十重余，案上军书十二卷。\n看君谋智若有神，爱君词句皆清新。\n澄湖万顷深见底，清冰一片光照人。\n云中昨夜使星动，西门驿楼出相送。\n玉瓶素蚁腊酒香，金鞭白马紫游缰。\n花门南，燕支北，张掖城头云正黑，送君一去天外忆。' },
  { title: '送郭乂杂言', author: '岑参', poem: '地上青草出，经冬今始归。\n博陵无近信，犹未换春衣。\n怜汝不忍别，送汝上酒楼。\n初行莫早发，且宿霸桥头。\n功名须及早，岁月莫虚掷。\n早年已工诗，近日兼注易。\n何时过东洛，早晚度盟津。\n朝歌城边柳亸地，邯郸道上花扑人。\n去年四月初，我正在河朔。\n曾上君家县北楼，楼上分明见恒岳。\n中山明府待君来，须计行程及早回。\n到家速觅长安使，待汝书封我自开。' },
  { title: '送魏升卿擢第归东都因怀魏校书陆浑乔潭', author: '岑参', poem: '井上桐叶雨，灞亭卷秋风。\n故人适战胜，匹马归山东。\n问君今年三十几，能使香名满人耳。\n君不见三峰直上五千仞，见君文章亦如此。\n如君兄弟天下稀，雄辞健笔皆若飞。\n将军金印亸紫绶，御史铁冠重绣衣。\n乔生作尉别来久，因君为问平安否。\n魏侯校理复何如，前日人来不得书。\n陆浑山下佳可赏，蓬阁闲时日应往。\n自料青云未有期，谁知白发偏能长。\n垆头青丝白玉瓶，别时相顾酒如倾。\n摇鞭举袂忽不见，千树万树空蝉鸣。' },
  { title: '送魏四落第还乡', author: '岑参', poem: '东归不称意，客舍戴胜鸣。\n腊酒饮未尽，春衫缝已成。\n长安柳枝春欲来，洛阳梨花在前开。\n魏侯池馆今尚在，犹有太师歌舞台。\n君家盛德岂徒然，时人注意在吾贤。\n莫令别后无佳句，祗向垆头空醉眠。' },
  { title: '送宇文南金放后归太原寓居因呈太原郝主簿', author: '岑参', poem: '归去不得意，北京关路赊。\n却投晋山老，愁见汾阳花。\n翻作灞陵客，怜君丞相家。\n夜眠旅舍雨，晓辞春城鸦。\n送君系马青门口，胡姬垆头劝君酒。\n为问太原贤主人，春来更有新诗否。' },
  { title: '西亭子送李司马', author: '岑参', poem: '高高亭子郡城西，直上千尺与云齐。\n盘崖缘壁试攀跻，群山向下飞鸟低。\n使君五马天半嘶，丝绳玉壶为君提。\n坐来一望无端倪，红花绿柳莺乱啼。\n千家万井连回谿，酒行未醉闻暮鸡，点笔操纸为君题。\n为君题，惜解携，草萋萋，没马蹄。' },
  { title: '渔父', author: '岑参', poem: '扁舟沧浪叟，心与沧浪清。\n不自道乡里，无人知姓名。\n朝从滩上饭，暮向芦中宿。\n歌竟还复歌，手持一竿竹。\n竿头钓丝长丈余，鼓栧乘流无定居。\n世人那得识深意，此翁取适非取鱼。' },
  { title: '登古邺城', author: '岑参', poem: '下马登邺城，城空复何见。\n东风吹野火，暮入飞云殿。\n城隅南对望陵台，漳水东流不复回。\n武帝宫中人去尽，年年春色为谁来。' },
  { title: '邯郸客舍歌', author: '岑参', poem: '客从长安来，驱马邯郸道。\n伤心丛台下，一带生蔓草。\n客舍门临漳水边，垂杨下系钓鱼船。\n邯郸女儿夜沽酒，对客挑灯夸数钱。\n酪酊醉时日正午，一曲狂歌垆上眠。' },
  { title: '宿蒲关东店忆杜陵别业', author: '岑参', poem: '关门锁归客，一夜梦还家。\n月落河上晓，遥闻秦树鸦。\n长安二月归正好，杜陵树边纯是花。' },
  { title: '优钵罗花歌', author: '岑参', poem: '白山南，赤山北，其间有花人不识。\n绿茎碧叶好颜色，叶六瓣，花九房，夜掩朝开多异香，何不生彼中国兮生西方？移根在庭，媚我公堂，耻与众草之为伍，何亭亭而独芳？何不为人之所赏兮？深山穷谷委严霜。\n吾窃悲阳关道路长，曾不得献于君王。' },
  { title: '蜀葵花歌', author: '岑参', poem: '昨日一花开，今日一花开。\n今日花正好，昨日花已老。\n始知人老不如花，可惜落花君莫埽。\n人生不得长少年，莫惜床头沽酒钱。\n请君有钱向酒家，君不见，蜀葵花。' },
  { title: '题李士曹厅壁画度雨云歌', author: '岑参', poem: '似出栋梁里，如和风雨飞。\n掾曹有时不敢归，谓言雨过湿人衣。' },
  { title: '入蒲关先寄秦中故人', author: '岑参', poem: '秦山数点似青黛，渭上一条如白练。\n京师故人不可见，寄将两眼看飞燕。' },
  { title: '长门怨', author: '岑参', poem: '君王嫌妾妬，闭妾在长门。\n舞袖垂新宠，愁眉结旧恩。\n绿钱侵履迹，红粉湿啼痕。\n羞被夭桃笑，看春独不言。' },
  { title: '寄左省杜拾遗', author: '岑参', poem: '联步趋丹陛，分曹限紫微。\n晓随天仗入，暮惹御香归。\n白发悲花落，青云羡鸟飞。\n圣朝无阙事，自觉谏书稀。' },
  { title: '岁暮碛外寄元㧑', author: '岑参', poem: '西风传戍鼓，南望见前军。\n沙碛人愁月，山城犬吠云。\n别家逢逼岁，出塞独离群。\n发到阳关白，书今远报君。' },
  { title: '寄宇文判官', author: '岑参', poem: '西行殊未已，东望何时还。\n终日风与雪，连天沙复山。\n二年领公事，两度过阳关。\n相忆不可见，别来头已斑。' },
  { title: '宿关西客舍寄东山严许二山人时天宝初七月初三日在内学见有高道举征', author: '岑参', poem: '云送关西雨，风传渭北秋。\n孤灯然客梦，寒杵捣乡愁。\n滩上思严子，山中忆许由。\n苍生今有望，飞诏下林丘。' },
  { title: '丘中春卧寄王子', author: '岑参', poem: '田中开白室，林下闭玄关。\n卷迹人方处，无心云自闲。\n竹深喧暮鸟，花缺露春山。\n胜事那能说，王孙去未还。' },
  { title: '江行夜宿龙吼滩临眺思峨眉隐者兼寄幕中诸公', author: '岑参', poem: '官舍临江口，滩声人惯闻。\n水烟晴吐月，山火夜烧云。\n且欲寻方士，无心恋使君。\n异乡何可住，况复久离群。' },
  { title: '汉川山行呈成少尹', author: '岑参', poem: '西蜀方携手，南宫忆比肩。\n平生犹不浅，羁旅转相怜。\n山店云迎客，江村犬吠船。\n秋来取一醉，须待月光眠。' },
  { title: '奉和杜相公初发京城作', author: '岑参', poem: '按节辞黄阁，登坛恋赤墀。\n衔恩期报主，授律远行师。\n野鹊迎金印，郊云拂画旗。\n叨陪幕中客，敢和出车诗。' },
  { title: '敬酬李判官使院即事见呈', author: '岑参', poem: '公府日无事，吾徒只是闲。\n草根侵柱础，苔色上门关。\n饮砚时见鸟，卷帘晴对山。\n新诗吟未足，昨夜梦东还。' },
  { title: '虢州酬辛侍御见赠', author: '岑参', poem: '门柳叶已大，春花今复阑。\n鬓毛方二色，愁绪日千端。\n夫子屡新命，鄙夫仍旧官。\n相思难见面，时展尺书看。' },
  { title: '酬崔十三侍御登玉垒山思故园见寄', author: '岑参', poem: '玉垒天晴望，诸峰尽觉低。\n故园江树北，斜日巅云西。\n旷野看人小，长空共鸟齐。\n高山徒仰止，不得日攀跻。' },
  { title: '南楼送卫凭', author: '岑参', poem: '近县多过客，似君诚亦稀。\n南楼取凉好，便送故人归。\n鸟向望中灭，雨侵晴处飞。\n应须乘月去，且为解征衣。' },
  { title: '送王伯伦应制授正字归', author: '岑参', poem: '当年最称意，数子不如君。\n战胜时偏许，名高人共闻。\n半天城北雨，斜日灞西云。\n科斗皆成字，无令错古文。' },
  { title: '送宇文舍人出宰元城', author: '岑参', poem: '双凫出未央，千里过河阳。\n马带新行色，衣闻旧御香。\n县花迎墨绶，关柳拂铜章。\n别后能为政，相思淇水长。' },
  { title: '崔驸马山池重送宇文明府', author: '岑参', poem: '竹里过红桥，花间藉绿苗。\n池凉醒别酒，山翠拂行镳。\n凤去妆楼闭，凫飞叶县遥。' },
  { title: '送李郎尉武康', author: '岑参', poem: '潘郎腰绶新，霅上县花春。\n山色低官舍，湖光映吏人。\n不须嫌邑小，莫即耻家贫。\n更作东征赋，知君有老亲。' },
  { title: '碛西头送李判官入京', author: '岑参', poem: '一身从远使，万里向安西。\n汉月垂乡泪，胡沙费马蹄。\n寻河愁地尽，过碛觉天低。\n送子军中饮，家书醉里题。' },
  { title: '陪使君早春西亭送王赞府赴选', author: '岑参', poem: '西亭系五马，为送故人归。\n客舍草新出，关门花欲飞。\n到来逢岁酒，却去换春衣。\n吏部应相待，如君才调稀。' },
  { title: '送刘郎将归河东', author: '岑参', poem: '借问虎贲将，从军凡几年。\n杀人宝刀缺，走马貂裘穿。\n山雨醒别酒，关云迎渡船。\n谢君贤主将，岂忘轮台边。' },
  { title: '浐水东店送唐子归嵩阳', author: '岑参', poem: '野店临官路，重城压御隄。\n山开灞水北，雨过杜陵西。\n归梦秋能作，乡书醉嬾题。\n桥回忽不见，征马尚闻嘶。' },
  { title: '西亭送蒋侍御还京', author: '岑参', poem: '忽闻骢马至，喜见故人来。\n欲语多时别，先愁计日回。\n山河宜晚眺，云雾待君开。\n为报乌台客，须怜白发催。' },
  { title: '水亭送刘颙使还归节度', author: '岑参', poem: '无计留君住，应须绊马蹄。\n红亭莫惜醉，白日眼看低。\n解带怜高柳，移床爱小谿。\n此来相见少，正事各东西。' },
  { title: '送杨录事充潼关判官', author: '岑参', poem: '夫子方寸里，秋天澄霁江。\n关西望第一，郡内政无双。\n狭室下珠箔，连宵倾玉缸。\n平明犹未醉，斜月隐书牕。' },
  { title: '送裴判官自贼中再归河阳幕府', author: '岑参', poem: '东郊未解围，忠义似君稀。\n误落胡尘里，能持汉节归。\n卷帘山对酒，上马雪沾衣。\n却向嫖姚幕，翩翩去若飞。' },
  { title: '送陕县王主簿赴襄阳成亲', author: '岑参', poem: '六月襄山道，三星汉水边。\n求凤应不远，去马賸须鞭。\n野店愁中雨，江城梦里蝉。\n襄阳多故事，为我访先贤。' },
  { title: '送李卿赋得孤岛石', author: '岑参', poem: '一片他山石，巉巉映小池。\n绿窠攒剥藓，尖硕坐鸬鹚。\n水底看常倒，花边势欲欹。\n君心能不转，卿月岂相离。' },
  { title: '送王录事却归华阴', author: '岑参', poem: '相送欲狂歌，其如此别何。\n攀辕人共惜，解印日无多。\n仙掌云重见，关门路再过。\n双鱼莫不寄，县外是黄河。' },
  { title: '送二十二兄北游寻罗中', author: '岑参', poem: '斗柄欲东指，吾兄方北游。\n无媒谒明主，失计干诸侯。\n夜雪入穿履，朝霜凝敝裘。\n遥知客舍饮，醉里闻春鸠。' },
  { title: '送郑堪归东京泛水别业', author: '岑参', poem: '客舍见春草，忽闻思旧山。\n看君灞陵去，匹马成臯还。\n对酒风与雪，向家河复关。\n因悲宦游子，终岁无时闲。' },
  { title: '送崔全被放归都觐省', author: '岑参', poem: '夫子不自衒，世人知者稀。\n来倾阮氏酒，去着老莱衣。\n渭北草新出，关东花欲飞。\n楚王犹自惑，宋玉且将归。' },
  { title: '送孟孺卿落第归济阳', author: '岑参', poem: '献赋头欲白，还家衣已穿。\n羞过灞陵树，归种汶阳田。\n客舍少乡信，床头无酒钱。\n圣朝徒侧席，济上独遗贤。' },
  { title: '送裴校书从大夫淄川觐省', author: '岑参', poem: '尚书未出守，爱子向青州。\n一路通关树，孤城近海楼。\n怀中江橘熟，倚处戟门秋。\n更奉轻轩去，知君无客愁。' },
  { title: '送杨千牛趂岁赴汝南郡觐省便成婚', author: '岑参', poem: '问吉转征鞍，安仁道姓潘。\n归期明主赐，别酒故人欢。\n珠箔障炉煖，孤裘耐腊寒。\n汝南遥倚望，蚤去及春盘。' },
  { title: '送胡象落第归王屋别业', author: '岑参', poem: '看君尚少年，不第莫凄然。\n可即疲献赋，山村归种田。\n野花迎短褐，河柳拂长鞭。\n置酒聊相送，青门一醉眠。' },
  { title: '送颜韶', author: '岑参', poem: '迁客犹未老，圣朝今复归。\n一从襄阳住，几度梨花飞。\n世事了可见，怜君人亦稀。\n相逢贪醉卧，未得作春衣。' },
  { title: '送杜佐下第归陆浑别业', author: '岑参', poem: '正月今欲半，陆浑花未开。\n出关见青草，春色正东来。\n夫子且归去，明时方爱才。\n还须及秋赋，莫即隐嵩莱。' },
  { title: '送张郎中赴陇右觐省卿公', author: '岑参', poem: '中郎凤一毛，世上独贤豪。\n弱冠已银印，出身唯宝刀。\n还家卿月迥，度陇将星高。\n幕下多相识，边书醉嬾操。' },
  { title: '送楚丘曲少府赴官', author: '岑参', poem: '青袍美少年，黄绶一神仙。\n微子城东面，梁王苑北边。\n桃花色似马，榆荚小于钱。\n单父闻相近，家书早为传。' },
  { title: '送蜀郡李掾', author: '岑参', poem: '饮酒俱未醉，一言聊赠君。\n功曹善为政，明主还应闻。\n夜宿劒门月，朝行巴水云。\n江城菊花发，满道香氛氲。' },
  { title: '送郑少府赴滏阳', author: '岑参', poem: '子真河朔尉，邑里带清漳。\n春草迎袍色，晴花拂绶香。\n青山入官舍，黄鸟度宫墙。\n若到铜台上，应怜魏寝荒。' },
  { title: '还高冠潭口留别舍弟', author: '岑参', poem: '昨日山有信，祗今耕种时。\n遥传杜陵叟，怪我还山迟。\n独向潭上酌，无人林下棋。\n东谿忆汝处，闲卧对鸬鹚。' },
  { title: '醴泉东谿送程皓元镜微入蜀', author: '岑参', poem: '蜀郡路漫漫，梁州过七盘。\n二人来信宿，一县醉衣冠。\n谿逼春衫冷，林交宴席寒。\n西南如喷酒，遥向雨中看。' },
  { title: '夏初醴泉南楼送太康颜少府', author: '岑参', poem: '何地堪相饯，南楼出万家。\n可怜高处送，远见故人车。\n野果新成子，庭槐欲作花。\n爱君兄弟好，书向颍中夸。' },
  { title: '送严诜擢第归蜀', author: '岑参', poem: '巴江秋月新，阁道发征轮。\n战胜真才子，名高动世人。\n工文能似舅，擢第去荣亲。\n十月天官待，应须早赴秦。' },
  { title: '送张直公归南郑拜省', author: '岑参', poem: '夫子思何速，世人皆叹奇。\n万言不加点，七步犹嫌迟。\n对酒落日后，还家飞雪时。\n北堂应久待，乡梦促征期。' },
  { title: '送周子落第游荆南', author: '岑参', poem: '足下复不第，家贫寻故人。\n且倾湘南酒，羞对关西尘。\n山店橘花发，江城枫叶新。\n若从巫峡过，应见楚王神。' },
  { title: '送薛彦伟擢第东归', author: '岑参', poem: '时辈似君稀，青春战胜归。\n名登郄诜第，身着老莱衣。\n称意人皆羡，还家马若飞。\n一枝谁不折，棣蕚独相辉。' },
  { title: '送杨瑗尉南海', author: '岑参', poem: '不择南州尉，高堂有老亲。\n楼台重蜃气，邑里杂鲛人。\n海暗三山雨，花明五岭春。\n此乡多宝玉，慎莫厌清贫。' },
  { title: '凤翔府行军送程使君赴成州', author: '岑参', poem: '程侯新出守，好日发行军。\n拜命时人羡，能官圣主闻。\n江楼黑塞雨，山郭冷秋云。\n竹马诸童子，朝朝待使君。' },
  { title: '送张升卿宰新滏', author: '岑参', poem: '官柳叶尚小，长安春未浓。\n送君浔阳宰，把酒青门钟。\n水驿楚云冷，山城江树重。\n遥知南湖上，只对香炉峰。' },
  { title: '送陈子归陆浑别业', author: '岑参', poem: '虽不旧相识，知君丞相家。\n故园伊川上，夜梦方山花。\n种药畏春过，出关愁路赊。\n青门酒垆别，日暮东城鸦。' },
  { title: '稠桑驿喜逢严河南中丞便别', author: '岑参', poem: '驷马映花枝，人人夹路窥。\n离心且莫问，春草自应知。\n不谓青云客，犹思紫禁时。\n别君能几日，看取鬓成丝。' },
  { title: '送蒲秀才擢第归蜀', author: '岑参', poem: '去马疾如飞，看君战胜归。\n新登郄诜第，更着老莱衣。\n汉水行人少，巴山客舍稀。\n向南风候暖，腊月见春辉。' },
  { title: '送郭司马赴伊吾郡请示李明府', author: '岑参', poem: '安西美少年，脱劒卸弓弦。\n不倚将军势，皆称司马贤。\n秋山城北面，古治郡东边。\n江上舟中月，遥思李郭仙。' },
  { title: '送滕亢擢第归苏州拜亲', author: '岑参', poem: '送尔姑苏客，沧波秋正凉。\n橘怀三个去，桂折一枝将。\n湖上山当舍，天边水是乡。\n江村人事少，时作捕鱼郎。' },
  { title: '送任郎中出守明州', author: '岑参', poem: '罢起郎官草，初封刺史符。\n城边楼枕海，郭里树侵湖。\n郡政傍连楚，朝恩独借吴。\n观涛秋正好，莫不上姑苏。' },
  { title: '临洮客舍留别祁四', author: '岑参', poem: '无事向边外，至今仍不归。\n三年绝乡信，六月未春衣。\n客舍洮水聒，孤城胡雁飞。\n心知别君后，开口笑应稀。' },
  { title: '送弘文李校书往汉南拜亲', author: '岑参', poem: '未识已先闻，清辞果出群。\n如逢祢处士，似见鲍参军。\n梦暗巴山雨，家连汉水云。\n慈亲思爱子，几度泣沾帬。' },
  { title: '送李别将摄伊吾令充使赴武威便寄崔员外', author: '岑参', poem: '词赋满书囊，胡为在战场。\n行间脱宝劒，邑里挂铜章。\n马疾飞千里，凫飞向五凉。\n遥知竹林下，星使对星郎。' },
  { title: '送四镇薛侍御东归', author: '岑参', poem: '相送泪沾衣，天涯独未归。\n将军初得罪，门客复何依。\n梦去湖山阔，书停陇雁稀。\n园林幸接近，一为到柴扉。' },
  { title: '送张都尉东归', author: '岑参', poem: '白羽绿弓弦，年年只在边。\n还家劒锋尽，出塞马蹄穿。\n逐虏西逾海，平胡北到天。\n封侯应不远，燕颔岂徒然。' },
  { title: '送樊侍御使丹阳便觐', author: '岑参', poem: '卧病穷巷晚，忽惊骢马来。\n知君京口去，借问几时回。\n驿舫江风引，乡书海雁催。\n慈亲应倍喜，爱子在霜台。' },
  { title: '送张卿郎君赴硖石尉', author: '岑参', poem: '卿家送爱子，愁见灞头春。\n草羡青袍色，花随黄绶新。\n县西函谷路，城北大阳津。\n日暮征鞍去，东郊一片尘。' },
  { title: '送颜少府投郑陈州', author: '岑参', poem: '一尉便垂白，数年唯草玄。\n出关策匹马，逆旅闻秋蝉。\n爱客多酒债，罢官无俸钱。\n知君羁思少，所适主人贤。' },
  { title: '赵少尹南亭送郑侍御归东台', author: '岑参', poem: '红亭酒瓮香，白面绣衣郎。\n砌冷虫喧坐，帘疎雨到床。\n钟催离兴急，弦逐醉歌长。\n关树应先落，随君满鬓霜。' },
  { title: '祁四再赴江南别诗', author: '岑参', poem: '万里来又去，三湘东复西。\n别多人换鬓，行远马穿蹄。\n山驿秋云冷，江帆暮雨低。\n怜君不解说，相忆在书题。' },
  { title: '送许员外江外置常平仓', author: '岑参', poem: '诏置海陵仓，朝推画省郎。\n还家锦服贵，出使绣衣香。\n水驿风催舫，江楼月透床。\n仍怀陆氏橘，归献老亲尝。' },
  { title: '送秘省虞校书赴虞乡丞', author: '岑参', poem: '花绶傍腰新，关东县欲春。\n残书厌科斗，旧阁别麒麟。\n虞坂临官舍，条山映吏人。\n看君有知己，坦腹向平津。' },
  { title: '送江陵泉少府赴任便呈卫荆州', author: '岑参', poem: '神仙吏姓梅，人吏待君来。\n渭北草新出，江南花已开。\n城边宋玉宅，峡口楚王台。\n不畏无知己，荆州甚爱才。' },
  { title: '奉送李太保兼御史大夫充渭北节度使', author: '岑参', poem: '诏出未央宫，登坛近总戎。\n上公周太保，副相汉司空。\n弓抱关西月，旗翻渭北风。\n弟兄皆许国，天地荷成功。' },
  { title: '送江陵黎少府', author: '岑参', poem: '悔系腰间绶，翻为膝下愁。\n那堪汉水远，更值楚山秋。\n新橘香官舍，征帆拂县楼。\n王城不敢住，岂是爱荆州。' },
  { title: '虢州送天平何丞入京市马', author: '岑参', poem: '关树晚苍苍，长安近夕阳。\n回风醒别酒，细雨湿行装。\n习战边尘黑，防秋塞草黄。\n知君市骏马，不是学燕王。' },
  { title: '送扬州王司马', author: '岑参', poem: '君家旧淮水，水上到扬州。\n海树青官舍，江云黑郡楼。\n东南随去鸟，人吏待行舟。\n为报吾兄道，如今已白头。' },
  { title: '陕州月城楼送辛判官入奏', author: '岑参', poem: '送客飞鸟外，城头楼最高。\n樽前遇风雨，牕里动波涛。\n谒帝向金殿，随身唯宝刀。\n相思灞陵月，祗有梦偏劳。' },
  { title: '送王七录事赴虢州', author: '岑参', poem: '早岁即相知，嗟君最后时。\n青云仍未达，白发欲成丝。\n小店关门树，长河华岳祠。\n弘农人吏待，莫使马行迟。' },
  { title: '阌乡送上官秀才归关西别业', author: '岑参', poem: '风尘奈汝何，终日独波波。\n亲老无官养，家贫在外多。\n醉眼轻白发，春梦渡黄河。\n相去关城近，何时更肯过。' },
  { title: '送羽林长孙将军赴歙州', author: '岑参', poem: '剖竹向江𣸣，能名计日闻。\n隼旗新刺史，虎劒旧将军。\n驿舫宿湖月，州城浸海云。\n青门酒楼上，欲别醉醺醺。' },
  { title: '送崔主簿赴夏阳', author: '岑参', poem: '常爱夏阳县，往年曾再过。\n县中饶白鸟，郭外是黄河。\n地近行程少，家贫酒债多。\n知君新称意，好得奈春何。' },
  { title: '送梁判官归女几旧庐', author: '岑参', poem: '女几知君忆，春云相逐归。\n草堂开药裹，苔壁取荷衣。\n老竹移时少，新花旧处飞。\n可怜真傲吏，尘事到山稀。' },
  { title: '送怀州吴别驾', author: '岑参', poem: '灞上柳枝黄，垆头酒正香。\n春流饮去马，暮雨湿行装。\n驿路通函谷，州城接太行。\n覃怀人总喜，别驾得王祥。' },
  { title: '送人归江宁', author: '岑参', poem: '楚客忆乡信，向家湖水长。\n住愁春草绿，去喜桂枝香。\n海月迎归楚，江云引到乡。\n吾兄应借问，为报鬓毛霜。' },
  { title: '送襄州任别驾', author: '岑参', poem: '别乘向襄州，萧条楚地秋。\n江声官舍里，山色郡城头。\n莫羡黄公盖，须乘彦伯舟。\n高阳诸醉客，唯见古时丘。' },
  { title: '送李司谏归京', author: '岑参', poem: '别酒为谁香，春官驳正郎。\n醉经秦树远，梦怯汉川长。\n雨过风头黑，云开日脚黄。\n知君解起草，早去入文昌。' },
  { title: '送緜州李司马秩满归京因呈李兵部', author: '岑参', poem: '久客厌江月，罢官思早归。\n眼看春光老，羞见梨花飞。\n劒北山居小，巴南音信稀。\n因君报兵部，愁泪日沾衣。' },
  { title: '送崔员外入秦因访故园', author: '岑参', poem: '欲谒明光殿，先趋建礼门。\n仙郎去得意，亚相正承恩。\n竹里巴山道，花间汉水源。\n凭将两行泪，为访邵平园。' },
  { title: '送柳录事赴梁州', author: '岑参', poem: '英掾柳家郎，离亭酒瓮香。\n折腰思汉北，随传过巴阳。\n江树连官舍，山云到卧床。\n知君归梦积，去去劒川长。' },
  { title: '送韦侍御先归京', author: '岑参', poem: '闻欲朝龙阙，应须拂豸冠。\n风霜随马去，炎暑为君寒。\n客泪题书落，乡愁对酒宽。\n先凭报亲友，后月到长安。' },
  { title: '送裴侍御赴岁入京', author: '岑参', poem: '羡他骢马郎，元日谒明光。\n立处闻天语，朝回惹御香。\n台寒柏树绿，江暖柳条黄。\n惜别津亭暮，挥戈忆鲁阳。' },
  { title: '送颜评事入京', author: '岑参', poem: '颜子人叹屈，宦游今未迟。\n伫闻明主用，岂负青云姿。\n江柳秋吐叶，山花寒满枝。\n知君客愁处，月满巴川时。' },
  { title: '送赵侍御归上都', author: '岑参', poem: '骢马五花毛，青云归处高。\n霜随驱夏暑，风逐振江涛。\n执简皆推直，勤王岂告劳。\n帝城谁不恋，回望动离骚。' },
  { title: '送杨子', author: '岑参', poem: '斗酒渭城边，垆头耐醉眠。\n梨花千树雪，杨叶万条烟。\n惜别添壶酒，临岐赠马鞭。\n看君颍上去，新月到家圆。' },
  { title: '送人赴安西', author: '岑参', poem: '上马带胡钩，翩翩度陇头。\n小来思报国，不是爱封侯。\n万里乡为梦，三边月作愁。\n早须清黠虏，无事莫经秋。' },
  { title: '发临洮将赴北庭留别', author: '岑参', poem: '闻说轮台路，连年见雪飞。\n春风曾不到，汉使亦应稀。\n白草通疎勒，青山过武威。\n勤王敢道远，私向梦中归。' },
  { title: '临洮泛舟赵仙舟自北庭罢使还京', author: '岑参', poem: '白发轮台使，边功竟不成。\n云沙万里地，孤负一书生。\n池上风回舫，桥西雨过城。\n醉眠乡梦罢，东望羡归程。' },
  { title: '春日醴泉杜明府承恩五品宴席上赋诗', author: '岑参', poem: '凫舃旧称仙，鸿私降自天。\n青袍移草色，朱绶夺花然。\n邑里雷仍震，台中星欲悬。\n吾兄此栖棘，因得贺初筵。' },
  { title: '早春陪崔中丞同泛浣花谿宴', author: '岑参', poem: '旌节临谿口，塞郊陡觉暄。\n红亭移酒席，画舸逗江村。\n云带歌声飏，风飘舞袖翻。\n花间催秉烛，川上欲黄昏。' },
  { title: '喜华阴王少府使到南池宴集', author: '岑参', poem: '有客至铃下，自言身姓梅。\n仙人掌里使，黄帝鼎边来。\n竹影拂棋局，荷香随酒杯。\n池前堪醉卧，待月未须回。' },
  { title: '行军雪后月夜宴王卿家', author: '岑参', poem: '子夜雪华余，卿家月影初。\n酒香薰枕席，炉气煖轩除。\n晚岁宦情薄，行军欢宴疎。\n相逢剩取醉，身外尽空虚。' },
  { title: '梁州陪赵行军龙冈寺北庭泛舟宴王侍御', author: '岑参', poem: '谁宴霜台使，行军粉署郎。\n唱歌江鸟没，吹笛岸花香。\n酒影摇新月，滩声聒夕阳。\n江钟闻已暮，归櫂绿川长。' },
  { title: '奉陪封大夫宴得征字时封公兼鸿胪卿', author: '岑参', poem: '西边虏尽平，何处更专征。\n幕下人无事，军中政已成。\n座参殊俗语，乐杂异方声。\n醉里东楼月，偏能照列卿。' },
  { title: '陪封大夫宴瀚海亭纳凉', author: '岑参', poem: '细管杂青丝，千杯倒接䍠。\n军中乘兴出，海上纳凉时。\n日没鸟飞急，山高云过迟。\n吾从大夫后，归路拥旌旗。' },
  { title: '虢州西亭陪端公宴集', author: '岑参', poem: '红亭出鸟外，骏马系云端。\n万岭牕前睥，千家肘底看。\n开瓶酒色嫩，踏地叶声干。\n为逼霜台使，重裘也觉寒。' },
  { title: '陪使君早春东郊游眺', author: '岑参', poem: '太守拥朱轮，东郊物候新。\n莺声随坐啸，柳色唤行春。\n谷口云迎马，谿边水照人。\n郡中叨佐理，何幸接芳尘。' },
  { title: '雪后与群公过慈恩寺', author: '岑参', poem: '乘兴忽相招，僧房暮与朝。\n雪融双树湿，沙暗一灯烧。\n竹外山低塔，藤间院隔桥。\n归家如欲嬾，俗虑向来销。' },
  { title: '与鄠县群官泛渼陂', author: '岑参', poem: '万顷浸天色，千寻穷地根。\n舟移城入树，岸阔水浮村。\n闲鹭惊箫管，潜蚪傍酒樽。\n暝来呼小吏，列火俨归轩。' },
  { title: '与鄠县源少府泛渼陂', author: '岑参', poem: '载酒入天色，水凉难醉人。\n清摇县郭动，碧洗云山新。\n吹笛惊白鹭，垂竿跳紫鳞。\n怜君公事后，陂上日娱宾。' },
  { title: '终南东谿中作', author: '岑参', poem: '谿水碧于草，潺潺花底流。\n沙平堪濯足，石浅不胜舟。\n洗药朝与暮，钓鱼春复秋。\n兴来从所适，还欲向沧洲。' },
  { title: '与鲜于庶子泛汉江', author: '岑参', poem: '急管更须吹，杯行莫遣迟。\n酒光红琥珀，江色碧琉璃。\n日影浮归櫂，芦花罥钓丝。\n山公醉不醉，问取葛[彊]知。' },
  { title: '晦日陪侍御泛北池', author: '岑参', poem: '春池满复宽，晦节耐邀欢。\n月带虾蟆冷，霜随獬豸寒。\n水云低锦席，岸柳拂金盘。\n日暮舟中散，都人夹道看。' },
  { title: '登凉州尹台寺', author: '岑参', poem: '胡地三月半，梨花今始开。\n因从老僧饭，更上夫人台。\n清唱云不去，弹弦风飒来。\n应须一倒载，还似山公回。' },
  { title: '登总持阁', author: '岑参', poem: '高阁逼诸天，登临近日边。\n晴开万井树，愁看五陵烟。\n槛外低秦岭，牕中小渭川。\n蚤知清净理，常愿奉金仙。' },
  { title: '奉陪封大夫九日登高', author: '岑参', poem: '九日黄花酒，登高会昔闻。\n霜威逐亚相，杀气傍中军。\n横笛惊征雁，娇歌落塞云。\n边头幸无事，醉舞荷吾君。' },
  { title: '郡斋平望江山', author: '岑参', poem: '水路东连楚，人烟北接巴。\n山光围一郡，江月照千家。\n庭树纯栽橘，园畦半种茶。\n梦魂知忆处，无夜不京华。' },
  { title: '宿岐州北郭严给事别业', author: '岑参', poem: '郭外山色暝，主人林馆秋。\n疎钟入卧内，片月到床头。\n遥夜惜已半，清言殊未休。\n君虽在青琐，心不忘沧洲。' },
  { title: '暮秋会严京兆后厅竹斋', author: '岑参', poem: '京兆小斋宽，公庭半药阑。\n瓯香茶色嫩，牕冷竹声干。\n盛德中朝贵，清风画省寒。\n能将吏部镜，照取寸心看。' },
  { title: '省中即事', author: '岑参', poem: '华省谬为郎，蹉跎鬓已苍。\n到来恒襆被，随例且含香。\n竹影遮牕暗，花阴拂簟凉。\n君王新赐笔，草奏向明光。' },
  { title: '寻阳七郎中宅即事', author: '岑参', poem: '万事信苍苍，机心久已忘。\n无端来出守，不是厌为郎。\n雨滴芭蕉赤，霜催橘子黄。\n逢君开口笑，何处有他乡。' },
  { title: '携琴酒寻阎防崇济寺所居僧院', author: '岑参', poem: '相访但寻钟，门寒古殿松。\n弹琴醒暮酒，卷幔引诸峰。\n事惬林中语，人幽物外踪。\n吾庐幸接近，兹地兴偏慵。' },
  { title: '春寻河阳陶处士别业', author: '岑参', poem: '风煖日暾暾，黄鹂飞近村。\n花明潘子县，柳暗陶公门。\n药椀摇山影，鱼竿带水痕。\n南桥车马客，何事苦喧喧。' },
  { title: '晚过盘石寺礼郑和尚', author: '岑参', poem: '暂诣高僧话，来寻野寺孤。\n岸花藏水碓，谿水映风炉。\n顶上巢新鹊，衣中带旧珠。\n谈禅未得去，辍櫂且踟蹰。' },
  { title: '寻少室张山人闻与偃师周明府同入都', author: '岑参', poem: '中峰炼金客，昨日游人间。\n叶县凫共去，葛陂龙暂还。\n春云凑深水，秋雨悬空山。\n寂寂清谿上，空余丹灶闲。' },
  { title: '虢州卧疾喜刘判官相过水亭', author: '岑参', poem: '卧疾尝晏起，朝来头未梳。\n见君胜服药，清话病能除。\n低柳共系马，小池堪钓鱼。\n观棋不觉暝，月出水亭初。' },
  { title: '武威春暮闻宇文判官西使还已到晋昌', author: '岑参', poem: '岸雨过城头，黄鹂上戍楼。\n塞北飘客泪，边柳挂乡愁。\n白发悲明镜，青春换敝裘。\n君从万里使，闻已到瓜州。' },
  { title: '虢州南池候严中丞不至', author: '岑参', poem: '池上日相待，知君殊未回。\n徒教柳叶长，漫使梨花开。\n驷马去不见，双鱼空往来。\n思想不解说，孤负舟中杯。' },
  { title: '春兴思南山旧庐招柳建正字', author: '岑参', poem: '终岁不得意，春风今复来。\n自怜蓬鬓改，羞见梨花开。\n西掖诚可恋，南山思早回。\n园庐幸接近，相与归蒿莱。' },
  { title: '郡斋南池招杨辚', author: '岑参', poem: '郡僻人事少，云山常眼前。\n偶从池上醉，便向舟中眠。\n与子居最近，周官情又偏。\n闲时耐相访，正有床头钱。' },
  { title: '高冠谷口招郑鄠', author: '岑参', poem: '谷口来相访，空斋不见君。\n涧花然暮雨，潭树煖春云。\n门径稀人迹，檐峰下鹿群。\n衣裳与枕席，山霭碧氛氲。' },
  { title: '题新乡王釜厅壁', author: '岑参', poem: '怜君守一尉，家计复清贫。\n禄米尝不足，俸钱供与人。\n城头苏门树，陌上黎阳尘。\n不是旧相识，声同心自亲。' },
  { title: '题山寺僧房', author: '岑参', poem: '牕影摇群木，墙阴载一峰。\n野炉风自𦶟，山碓水能舂。\n勤学翻知误，为官好欲慵。\n高僧暝不见，月出但闻钟。' },
  { title: '汉上题韦氏庄', author: '岑参', poem: '结茅闻楚客，卜筑汉江边。\n日落数归鸟，夜深闻扣舷。\n水痕侵岸柳，山翠借厨烟。\n调笑提筐妇，春来蚕几眠。' },
  { title: '题永乐韦少府厅壁', author: '岑参', poem: '大河南郭外，终日气昏昏。\n白鸟下公府，青山当县门。\n故人是邑尉，过客驻征轩。\n不惮烟波阔，思君一笑言。' },
  { title: '题金城临河驿楼', author: '岑参', poem: '古戍依重险，高楼见五凉。\n山根盘驿道，河水浸城墙。\n庭树巢鹦鹉，园花隐麝香。\n忽如江浦上，忆作捕鱼郎。' },
  { title: '初授官题高冠草堂', author: '岑参', poem: '三十始一命，宦情多欲阑。\n自怜无旧业，不敢耻微官。\n涧水吞樵路，山花醉药栏。\n秪缘五斗米，辜负一渔竿。' },
  { title: '题虢州西楼', author: '岑参', poem: '错料一生事，蹉跎今白头。\n纵横皆失计，妻子也堪羞。\n明主虽然弃，丹心亦未休。\n愁来无去处，祗上郡西楼。' },
  { title: '夜过盘石隔河望永乐寄闺中效齐梁体', author: '岑参', poem: '盈盈一水隔，寂寂二更初。\n波上思罗袜，鱼边忆素书。\n月如眉已画，云似鬓新梳。\n春物知人意，桃花笑索居。' },
  { title: '河西春暮忆秦中', author: '岑参', poem: '渭北春已老，河西人未归。\n边城细草出，客馆梨花飞。\n别后乡梦数，昨来家信稀。\n凉州三月半，犹未脱寒衣。' },
  { title: '过酒泉忆杜陵别业', author: '岑参', poem: '昨夜宿[祈]连，今朝过酒泉。\n黄沙西际海，白草北连天。\n愁里难消日，归期尚隔年。\n阳关万里梦，知处杜陵田。' },
  { title: '早发焉耆怀终南别业', author: '岑参', poem: '晓笛别乡泪，秋冰鸣马蹄。\n一身虏云外，万里胡天西。\n终日见征战，连年闻鼓鼙。\n故山在何处，昨日梦清谿。' },
  { title: '宿铁关西馆', author: '岑参', poem: '马汗踏成泥，朝驰几万蹄。\n雪中行地角，火处宿天倪。\n塞迥心常怯，乡遥梦亦迷。\n那知故园月，也到铁关西。' },
  { title: '首秋轮台', author: '岑参', poem: '异域阴山外，孤城雪海边。\n秋来唯有雁，夏尽不闻蝉。\n雨拂氊墙湿，风摇毳幕膻。\n轮台万里地，无事历三年。' },
  { title: '北庭作', author: '岑参', poem: '雁塞通盐泽，龙堆接醋沟。\n孤城天北畔，绝域海西头。\n秋雪春仍下，朝风夜不休。\n可知年四十，犹自未对侯。' },
  { title: '轮台即事', author: '岑参', poem: '轮台风物异，地是古单于。\n三月无青草，千家尽白榆。\n蕃书文字别，胡俗语音殊。\n愁见流沙北，天西海一隅。' },
  { title: '还东山洛上作', author: '岑参', poem: '春流急不浅，归栧去何迟。\n愁客叶舟里，夕阳花水时。\n云晴开䗖𬟽，櫂发起鸬鹚。\n莫道东山远，衡门在梦思。' },
  { title: '杨固店', author: '岑参', poem: '客舍梨叶赤，邻家闻捣衣。\n夜来尝有梦，坠泪缘思归。\n洛水行欲尽，缑山看渐微。\n长安祗千里，何事信音稀。' },
  { title: '巴南舟中思陆浑别业', author: '岑参', poem: '泸水南州远，巴山北客稀。\n岭云撩乱起，谿鹭等闲飞。\n镜里愁衰鬓，舟中换旅衣。\n梦魂知忆处，无夜不先归。' },
  { title: '晚发五渡', author: '岑参', poem: '客厌巴南地，乡邻劒北天。\n江村片雨外，野寺夕阳边。\n芋叶藏山径，芦花杂渚田。\n舟行未可住，乘月且须牵。' },
  { title: '巴南舟中夜市', author: '岑参', poem: '渡口欲黄昏，归人争渡喧。\n近钟清野寺，远火点江村。\n见雁思乡信，闻猿积泪痕。\n孤舟万里外，秋月不堪论。' },
  { title: '江上春叹', author: '岑参', poem: '腊月江上煖，南桥新柳枝。\n春风触处到，忆得故园时。\n终日不如意，出门何所之。\n从人觅颜色，自笑弱男儿。' },
  { title: '初至犍为作', author: '岑参', poem: '山色轩槛内，滩声枕席间。\n草生公府静，花落讼庭闲。\n云雨连三峡，风尘接百蛮。\n到来能几日，不觉鬓毛斑。' },
  { title: '使院中新栽柏树子呈李十五栖筠', author: '岑参', poem: '爱尔青青色，移根此地来。\n不曾台上种，留向碛中栽。\n脆叶欺门柳，狂花笑院梅。\n不须愁岁晚，霜露岂能摧。' },
  { title: '咏郡斋壁画片云', author: '岑参', poem: '云片何人画，尘侵粉色微。\n未曾行雨去，不见逐风归。\n只怪偏凝壁，回看欲惹衣。\n丹青忽借便，移向帝乡飞。' },
  { title: '临洮龙兴寺玄上人院同咏青木香丛', author: '岑参', poem: '移根自远方，种得在僧房。\n六月花新吐，三春叶已长。\n抽茎高锡杖，引影到绳床。\n只为能除疾，倾心向药王。' },
  { title: '成王挽歌', author: '岑参', poem: '幽山悲旧桂，长坂怆余兰。\n地底孤灯冷，泉中一镜寒。\n铭旌门客送，骑吹路人看。\n漫作琉璃椀，淮王误合丹。' },
  { title: '苗侍中挽歌二首 一', author: '岑参', poem: '摄政朝章重，持衡国相尊。\n笔端通造化，掌内运乾坤。\n青史遗芳满，黄枢故事存。\n空悲渭桥路，谁对汉皇言。' },
  { title: '苗侍中挽歌二首 二', author: '岑参', poem: '天子悲元老，都人惜上公。\n优贤几杖在，会葬市朝空。\n丹旐飞斜日，清笳怨暮风。\n平生门下客，继美庙堂中。' },
  { title: '故仆射裴公挽歌三首 一', author: '岑参', poem: '盛德资邦杰，嘉谟作世程。\n门瞻驷马贵，时仰八龙名。\n罢市秦人送，还乡绛老迎。\n莫埋丞相印，留着付玄成。' },
  { title: '故仆射裴公挽歌三首 二', author: '岑参', poem: '五府瞻高位，三台丧大贤。\n礼容还故绛，宠赠冠新田。\n气歇汾阴鼎，魂飞京兆阡。\n先时劒已没，陇树久苍然。' },
  { title: '故仆射裴公挽歌三首 三', author: '岑参', poem: '富贵徒言久，乡闾殁后归。\n锦衣都未着，丹旐忽先飞。\n哀挽辞秦塞，悲笳出帝畿。\n遥知九原上，渐觉吊人稀。' },
  { title: '河西太守杜公挽歌四首 一', author: '岑参', poem: '蒙叟悲藏壑，殷宗惜济川。\n长安非旧日，京兆是新阡。\n黄霸官犹屈，苍生望已愆。\n唯余卿月在，留向杜陵悬。' },
  { title: '河西太守杜公挽歌四首 二', author: '岑参', poem: '鼓角城中出，坟茔郭外新。\n雨随思太守，云从送夫人。\n蒿里埋双劒，松门闭万春。\n回瞻北堂上，金印已生尘。' },
  { title: '河西太守杜公挽歌四首 三', author: '岑参', poem: '忆昨明光殿，新承天子恩。\n剖符移北地，授钺领西门。\n塞草迎军幕，边云拂使轩。\n至今闻陇外，戎虏尚亡魂。' },
  { title: '河西太守杜公挽歌四首 四', author: '岑参', poem: '漫漫澄波阔，沈沈大厦深。\n秉心常匪席，行义每挥金。\n汲引窥兰室，招携入翰林。\n多君有令子，犹注世人心。' },
  { title: '故河南尹岐国公赠工部尚书苏公挽歌二首 一', author: '岑参', poem: '河尹恩荣旧，尚书宠赠新。\n一门传画戟，几世驾朱轮。\n夜色何时晓，泉台不复春。\n唯余朝服在，金印已生尘。' },
  { title: '故河南尹岐国公赠工部尚书苏公挽歌二首 二', author: '岑参', poem: '白日扃泉户，青春掩夜台。\n旧堂阶草长，空院砌花开。\n山晚铭旌去，郊寒骑吹回。\n三川难可见，应惜庾公才。' },
  { title: '韩员外夫人清河县君崔氏挽歌二首 一', author: '岑参', poem: '令德当时重，高门举世推。\n从夫荣已绝，封邑宠难追。\n陌上人皆惜，花间鸟亦悲。\n仙郎看陇月，犹忆画眉时。' },
  { title: '韩员外夫人清河县君崔氏挽歌二首 二', author: '岑参', poem: '遽闻伤别劒，忽复叹藏舟。\n灯冷泉中夜，衣寒地下秋。\n青松吊客泪，丹旐路人愁。\n徒有清河在，空悲逝水流。' },
  { title: '西河郡太原守张夫人挽歌', author: '岑参', poem: '鹊印庆仍传，鱼轩宠莫先。\n从夫元凯贵，训子孟轲贤。\n龙是双归日，鸾非独舞年。\n哀容今共尽，凄怆杜陵田。' },
  { title: '南溪别业', author: '岑参', poem: '结宇依青嶂，开轩对翠畴。\n树交花两色，溪合水重流。\n竹径春来埽，兰樽夜不收。\n逍遥自得意，鼓腹醉中游。' },
  { title: '奉和中书舍人贾至早朝大明宫', author: '岑参', poem: '鸡鸣紫陌曙光寒，莺啭皇州春色阑。\n金阙晓钟开万户，玉阶仙仗拥千官。\n花迎劒珮星初落，柳拂旌旗露未干。\n独有凤皇池上客，阳春一曲和皆难。' },
  { title: '和祠部王员外雪后早朝即事', author: '岑参', poem: '长安雪后似春归，积素凝华连曙晖。\n色借玉珂迷晓骑，光添银烛晃朝衣。\n西山落月临天仗，北阙晴云捧禁闱。\n闻道仙郎歌白雪，由来此曲和人稀。' },
  { title: '奉和相公发益昌', author: '岑参', poem: '相[国]临戎别帝京，拥麾持节远横行。\n朝登劒阁云随马，夜渡巴江雨洗兵。\n山花万朵迎征盖，川柳千条拂去旌。\n暂到蜀城应计日，须知明主待持衡。' },
  { title: '秋夕读书幽兴献兵部李侍郎', author: '岑参', poem: '年纪蹉跎四十强，自怜头白始为郎。\n雨滋苔藓侵堦绿，秋飒梧桐覆井黄。\n惊蝉也解求高树，旅雁还应厌后行。\n览卷试穿邻舍壁，明灯何惜借余光。' },
  { title: '使君席夜送严河南赴长水', author: '岑参', poem: '娇歌急管杂青丝，银烛金杯映翠眉。\n使君地主能相送，河尹天明坐莫辞。\n春城月出人皆醉，野戍花深马去迟。\n寄声报尔山翁道，今日河南胜昔时。' },
  { title: '暮春虢州东亭送李司马归扶风别庐', author: '岑参', poem: '柳亸莺娇花复殷，红亭绿酒送君还。\n到来函谷愁中月，归去磻谿梦里山。\n帘前春色应须惜，世上浮名好是闲。\n西望乡关肠欲断，对君衫袖泪痕斑。' },
  { title: '九日使君席奉饯卫中丞赴长水', author: '岑参', poem: '节使横行西出师，鸣弓擐甲羽林儿。\n台上霜风凌草木，军中杀气傍旌旗。\n预知汉将宣威日，正是胡尘欲灭时。\n为报使君多泛菊，更将弦管醉东篱。' },
  { title: '西掖省即事', author: '岑参', poem: '西掖重云开曙晖，北山疎雨点朝衣。\n千门柳色连青琐，三殿花香入紫微。\n平明端笏陪鹓列，薄暮垂鞭信马归。\n官拙自悲头白尽，不如岩下偃荆扉。' },
  { title: '首春渭西郊行呈蓝田张二主簿', author: '岑参', poem: '迥风度雨渭城西，细草新花踏作泥。\n秦女峰头雪未尽，胡公阪上日初低。\n愁窥白发羞微禄，悔别青山忆旧谿。\n闻道辋川多胜事，玉壶春酒正堪携。' },
  { title: '赴嘉州过城固县寻永安超禅师房', author: '岑参', poem: '满寺枇杷冬着花，老僧相见具袈裟。\n汉王城北雪初霁，韩信台西日欲斜。\n门外不须催五马，林中且听演三车。\n岂料巴川多胜事，为君书此报京华。' },
  { title: '酬畅当嵩山寻麻道士见寄', author: '岑参', poem: '闻逐樵夫闲看棋，忽逢人世是秦时。\n开云种玉嫌山浅，渡海传书怪鹤迟。\n阴洞石幢微有字，古坛松树半无枝。\n烦君远示青囊录，愿得相从一问师。' },
  { title: '和刑部成员外秋夜寓直寄台省知己', author: '岑参', poem: '列宿光三署，仙郎直五宵。\n时衣天子赐，厨膳大官调。\n长乐钟应近，明光漏不遥。\n黄门持被覆，侍女捧香烧。\n笔为题诗点，灯缘起草挑。\n竹喧交砌叶，柳亸拂牕条。\n粉署荣新命，霜台忆旧僚。\n名香播兰蕙，重价蕴琼瑶。\n击水翻沧海，[抟]风透赤霄。\n微才喜同舍，何幸忽闻韶。' },
  { title: '送庐郎中除杭州赴任', author: '岑参', poem: '罢起郎官草，初分刺史符。\n海云迎过楚，江月引归吴。\n城低涛声震，楼端蜃气孤。\n千家窥驿舫，五马饮春湖。\n柳色供诗用，莺声送酒须。\n知君望乡处，枉道上姑苏。' },
  { title: '奉送李宾客荆南迎亲', author: '岑参', poem: '迎亲辞旧苑，恩诏下储闱。\n昨见双鱼去，今看驷马归。\n驿帆湘水阔，客舍楚山稀。\n手把黄香扇，身披莱子衣。\n鹊随金印喜，乌傍板舆飞。\n胜作东征赋，还家满路辉。' },
  { title: '送严维下第还江东', author: '岑参', poem: '勿叹今不第，似君殊未迟。\n且归沧洲去，相送青门时。\n望鸟指乡远，问人愁路疑。\n敝裘沾暮雪，归櫂带流澌。\n严子滩复在，谢公文可追。\n江臯如有信，莫不寄新诗。' },
  { title: '六月三十日水亭送华阴王少府还县', author: '岑参', poem: '亭晚人将别，池凉酒未酣。\n关门劳夕梦，仙掌引归骖。\n荷叶藏鱼艇，藤花罥客簪。\n残云收夏暑，新雨带秋岚。\n失路情无适，离怀思不堪。\n赖兹庭户里，别有小江潭。' },
  { title: '饯王岑判官赴襄阳道', author: '岑参', poem: '故人汉阳使，走马向南荆。\n不厌楚山路，祗怜襄水清。\n津头习氏宅，江上夫人城。\n夜入橘花宿，朝穿桐叶行。\n害群应自慑，持法固须平。\n暂得青门醉，斜光速去程。' },
  { title: '送薛弁归河东', author: '岑参', poem: '薛侯故乡处，五老峰西头。\n归路秦树灭，到乡河水流。\n看君马首去，满耳蝉声愁。\n献赋今未售，读书凡几秋。\n应过伯夷庙，为上关城楼。\n楼上能相忆，西南指雍州。' },
  { title: '送薛播擢第归河东', author: '岑参', poem: '归去新战胜，盛名人共闻。\n乡连渭川树，家近条山云。\n夫子能好学，圣朝全用文。\n弟兄负世誉，词赋超人群。\n雨气醒别酒，城阴低暮曛。\n遥知出关后，更有一终军。' },
  { title: '送陶铣弃举荆南觐省', author: '岑参', poem: '明时不爱璧，浪迹东南游。\n何必世人识，知君轻五侯。\n采兰度汉水，问绢过荆州。\n异国有归兴，去乡无客愁。\n天寒楚塞雨，月净襄阳秋。\n坐见吾道远，令人看白头。' },
  { title: '送史司马赴崔相公幕', author: '岑参', poem: '峥嵘丞相府，清切凤皇池。\n羡尔瑶台鹤，高栖琼树枝。\n归飞晴日好，吟弄惠风吹。\n正有乘轩乐，初当学舞时。\n珍禽在罗网，微命若游丝。\n愿托周南羽，相衔谿水湄。' },
  { title: '送严黄门拜御史大夫再镇蜀川兼觐省', author: '岑参', poem: '授钺辞金殿，承恩恋玉墀。\n登坛汉主用，讲德蜀人思。\n副相韩安国，黄门向子期。\n刀州重入梦，劒阁再题词。\n春草连青绶，晴花间赤旗。\n山莺朝送酒，江月夜供诗。\n许国分忧日，荣亲色养时。\n苍生望已久，来去不应迟。' },
  { title: '送郭仆射节制劒南', author: '岑参', poem: '铁马擐红缨，幡旗出禁城。\n明王亲授钺，丞相欲专征。\n玉馔天厨送，金杯御酒倾。\n劒门乘崄过，阁道踏空行。\n山鸟惊吹笛，江猿看洗兵。\n晓云随去阵，夜月逐行营。\n南仲今时往，西戎计日平。\n将心感知己，万里寄悬旌。' },
  { title: '早秋与诸子登虢州西亭观眺', author: '岑参', poem: '亭高出鸟外，客到与云齐。\n树点千家小，天围万岭低。\n残[虹]挂陕北，急雨过关西。\n酒榼缘青壁，瓜田傍绿谿。\n微官何足道，爱客且相携。\n唯有乡园处，依依望不迷。' },
  { title: '佐郡思旧游', author: '岑参', poem: '幸得趋紫殿，却忆侍丹墀。\n史笔众推直，谏书人莫窥。\n平生恒自负，垂老此安卑。\n同类皆先达，非才独后时。\n庭槐宿鸟乱，阶草夜虫悲。\n白发今无数，青云未有期。' },
  { title: '灭胡曲', author: '岑参', poem: '都护新灭胡，士马气亦麤。\n萧条虏尘净，突兀天山孤。' },
  { title: '尚书念旧垂赐袍衣率题绝句献上以申感谢', author: '岑参', poem: '富贵情还在，相逢岂间然。\n绨袍更有赠，犹荷故人怜。' },
  { title: '忆长安曲二章寄庞{氵寉} 一', author: '岑参', poem: '东望望长安，正值日初出。\n长安不可见，喜见长安日。' },
  { title: '忆长安曲二章寄庞{氵寉} 二', author: '岑参', poem: '长安何处在，只在马蹄下。\n明日归长安，为君急走马。' },
  { title: '寄韩樽', author: '岑参', poem: '夫子素多疾，别来未得书。\n北庭苦寒地，体内今何如。' },
  { title: '醉里送裴子赴镇西', author: '岑参', poem: '醉后未能别，待醒方送君。\n看君走马去，直上天山云。' },
  { title: '题井陉双谿李道士所居', author: '岑参', poem: '五粒松花酒，双谿道士家。\n唯求缩却地，乡路莫教赊。' },
  { title: '题云际南峰眼上人读经堂', author: '岑参', poem: '结宇题三藏，焚香老一峰。\n云间独坐卧，祗是对山松。' },
  { title: '题梁锽城中高居', author: '岑参', poem: '高住最高处，千家恒眼前。\n题诗饮酒后，只对诸峰眠。' },
  { title: '题三会寺苍颉造字台', author: '岑参', poem: '野寺荒台晚，寒天古木悲。\n空堦有鸟迹，犹似造书时。' },
  { title: '日没贺延碛作', author: '岑参', poem: '沙上见日出，沙上见日没。\n悔向万里来，功名是何物。' },
  { title: '西过渭州见渭水思秦川', author: '岑参', poem: '渭水东流去，何时到雍州。\n凭添两行泪，寄向故园流。' },
  { title: '经陇头分水', author: '岑参', poem: '陇水何年有，潺潺逼路傍。\n东西流不歇，曾断几人肠。' },
  { title: '秋思', author: '岑参', poem: '那知芳岁晚，坐见寒叶堕。\n吾不如腐草，翻飞作萤火。' },
  { title: '行军九日思长安故园', author: '岑参', poem: '强欲登高去，无人送酒来。\n遥怜故园菊，应傍战场开。' },
  { title: '戏题关门', author: '岑参', poem: '来亦一布衣，去亦一布衣。\n羞见关城吏，还从旧路归。' },
  { title: '叹白发', author: '岑参', poem: '白发生偏速，交人不奈何。\n今朝两鬓上，更较数茎多。' },
  { title: '题平阳郡汾桥边柳树', author: '岑参', poem: '此地曾居住，今来宛似归。\n可怜汾上柳，相见也依依。' },
  { title: '失题', author: '岑参', poem: '帝乡北近日，泸口南连蛮。\n何当遇长房，缩地到京关。' },
  { title: '献封大夫破播仙凯歌六首 一', author: '岑参', poem: '汉将承恩西破戎，捷书先奏未央宫。\n天子预开麟阁待，祗今谁数贰师功。' },
  { title: '献封大夫破播仙凯歌六首 二', author: '岑参', poem: '官军西出过楼兰，营幕傍临月窟寒。\n蒲海晓霜凝马尾，葱山夜雪扑旌竿。' },
  { title: '献封大夫破播仙凯歌六首 三', author: '岑参', poem: '鸣笳叠鼓拥回军，破国平蕃昔未闻。\n丈夫鹊印摇边月，大将龙旗掣海云。' },
  { title: '献封大夫破播仙凯歌六首 四', author: '岑参', poem: '日落辕门鼓角鸣，千群面缚出蕃城。\n洗兵鱼海云迎阵，秣马龙堆月照营。' },
  { title: '献封大夫破播仙凯歌六首 五', author: '岑参', poem: '蕃军遥见汉家营，满谷连山遍哭声。\n万箭千刀一夜杀，平明流血浸空城。' },
  { title: '献封大夫破播仙凯歌六首 六', author: '岑参', poem: '暮雨旌旗湿未干，胡烟白草日光寒。\n昨夜将军连晓战，蕃军只见马空鞍。' },
  { title: '春兴戏题赠李侯', author: '岑参', poem: '黄雀始欲衔花来，君家种桃花未开。\n长安二月眼看尽，寄报春风早为催。' },
  { title: '过燕支寄杜位', author: '岑参', poem: '燕支山西酒泉道，北风吹沙卷白草。\n长安遥在日光边，忆君不见令人老。' },
  { title: '题苜蓿峰寄家人', author: '岑参', poem: '苜蓿峰边逢立春，胡芦河上泪沾巾。\n闺中只是空相忆，不见沙场愁杀人。' },
  { title: '玉关寄长安李主簿', author: '岑参', poem: '东去长安万里余，故人何惜一行书。\n玉关西望堪肠断，况复明朝是岁除。' },
  { title: '武威送刘判官赴碛西行军', author: '岑参', poem: '火山五月行人少，看君马去疾如鸟。\n都护行营太白西，角声一动胡天晓。' },
  { title: '虢州后亭送李判官使赴晋绛', author: '岑参', poem: '西原驿路挂城头，客散红亭雨未收。\n君去试看汾水上，白云犹似汉时秋。' },
  { title: '五月四日送王少府归华阴', author: '岑参', poem: '仙掌分明引马头，西看一点是关楼。\n五月也须应到舍，知君不肯更淹留。' },
  { title: '原头送范侍御', author: '岑参', poem: '百尺原头酒色殷，路傍骢马汗斑斑。\n别君祇有相思梦，遮莫千山与万山。' },
  { title: '送李明府赴睦州便拜觐太夫人', author: '岑参', poem: '手把铜章望海云，夫人江上泣罗帬。\n严滩一点舟中月，万里烟波也梦君。' },
  { title: '虢州西山亭子送范端公', author: '岑参', poem: '百尺红亭对万峰，平明相送到斋钟。\n骢马劝君皆卸却，使君家酝旧来浓。' },
  { title: '奉送贾侍御使江外', author: '岑参', poem: '新骑骢马复承恩，使出金陵过海门。\n荆南渭北难相见，莫惜衫襟着酒痕。' },
  { title: '崔仓曹席上送殷寅充石相判官赴淮南', author: '岑参', poem: '清淮无底绿江深，宿处津亭枫树林。\n驷马欲辞丞相府，一樽须尽故人心。' },
  { title: '送崔子还京', author: '岑参', poem: '匹马西从天外归，扬鞭只共鸟争飞。\n送君九月交河北，雪里题诗泪满衣。' },
  { title: '题观楼', author: '岑参', poem: '荒楼荒井闭空山，关令乘云去不还。\n羽盖霓旌何处在，空留药臼向人间。' },
  { title: '草堂村寻罗生不遇', author: '岑参', poem: '数株谿柳色依依，深巷斜阳暮鸟飞。\n门前雪满无人迹，应是先生出未归。' },
  { title: '山房春事二首 一', author: '岑参', poem: '风恬日暖荡春光，戏蝶游蜂乱入房。\n数枝门柳低衣桁，一片山花落笔床。' },
  { title: '山房春事二首 二', author: '岑参', poem: '梁园日暮乱飞鸦，极目萧条三两家。\n庭树不知人死尽，春来还发旧时花。' },
  { title: '逢入京使', author: '岑参', poem: '故园东望路漫漫，双袖龙钟泪不干。\n马上相逢无纸笔，凭君传语报平安。' },
  { title: '过碛', author: '岑参', poem: '黄沙碛里客行迷，四望云天直下低。\n为言地尽天还尽，行到安西更向西。' },
  { title: '碛中作', author: '岑参', poem: '走马西来欲到天，辞家见月两回圆。\n今夜不知何处宿，平沙万里绝人烟。' },
  { title: '赴北庭度陇思家', author: '岑参', poem: '西向轮台万里馀，也知乡信日应疎。\n陇山鹦鹉能言语，为报家人数寄书。' },
  { title: '胡歌', author: '岑参', poem: '黑姓蕃王貂鼠裘，葡萄宫锦醉缠头。\n关西老将能苦战，七十行兵仍未休。' },
  { title: '赵将军歌', author: '岑参', poem: '九月天山风似刀，城南猎马缩寒毛。\n将军纵博场场胜，赌得单于貂鼠袍。' },
  { title: '醉戏窦子美人', author: '岑参', poem: '朱唇一点桃花殷，宿妆娇羞偏髻鬟。\n细看只似阳台女，醉着莫许归巫山。' },
  { title: '秋夜闻笛', author: '岑参', poem: '天门街西闻捣帛，一夜愁杀湘南客。\n长安城中百万家，不知何人吹夜笛。' },
  { title: '戏问花门酒家翁', author: '岑参', poem: '老人七十仍沽酒，千壶百瓮花门口。\n道傍榆荚仍似钱，摘来沽酒君肯否。' },
  { title: '春梦', author: '岑参', poem: '洞房昨夜春风起，故人尚隔湘江水。\n枕上片时春梦中，行尽江南数千里。' },
  { title: '冬夕', author: '岑参', poem: '浩汗霜风刮天地，温泉火井无生意。\n泽国龙蛇冻不伸，南山瘦柏消残翠。' },
  { title: '武阳送别', author: '沈宇', poem: '菊黄芦白雁初飞，羌笛胡笳泪满衣。\n送君肠断秋江水，一去东流何日归。' },
  { title: '捣衣', author: '沈宇', poem: '日暮远天青，霜风入后庭。\n洞房寒未掩，砧杵夜泠泠。' },
  { title: '代闺人', author: '沈宇', poem: '杨柳青青鸟乱吟，春风香霭洞房深。\n百花帘下朝窥镜，明月窗前夜理琴。' },
  { title: '江南遇雨', author: '张鼎', poem: '江天寒意少，冬月雨仍飞。\n出户愁为听，从风洒客衣。\n旅魂惊处断，乡信意中微。\n几日应晴去，孤舟且欲归。' },
  { title: '邺城引', author: '张鼎', poem: '君不见汉家失统三灵变，魏武争雄六龙战。\n荡海吞江制中国，回天运斗应南面。\n隐隐都城紫阳开，迢迢分野黄星见。\n流年不驻漳河水，明月俄终邺国宴。\n文章犹入管弦新，帷座空销狐兔尘。\n可惜望陵歌舞处，松风四面暮愁人。' },
  { title: '僧舍小池', author: '张鼎', poem: '引出白云根，潺潺涨藓痕。\n冷光摇砌锡，疎影露枝猿。\n净带凋霜叶，香通洗药源。\n贝多文字古，宜向此中翻。' },
  { title: '拟古', author: '薛奇童', poem: '沙尘朝蔽日，失道还相遇。\n寒影波上云，秋声月前树。\n川气生晓夕，野阴乍烟雾。\n沈沈滮池水，人马不敢渡。\n吮痈世所薄，挟纩恩难顾。\n不见古时人，中宵泪横注。' },
  { title: '和李起居秋夜之作', author: '薛奇童', poem: '过庭闻礼日，趋侍记言回。\n独卧玉窗前，卷帘残雨来。\n高秋南斗转，凉夜北堂开。\n水影入朱户，萤光生绿苔。\n简成良史笔，年是洛阳才。\n莫重白云意，时人许上台。' },
  { title: '吴声子夜歌', author: '薛奇童', poem: '净扫黄金堦，飞霜皓如雪。\n下帘弹箜篌，不忍见秋月。' },
  { title: '塞下曲', author: '薛奇童', poem: '骄虏初南下，烟尘暗国中。\n独召李将军，夜开甘泉宫。\n一身许明主，万里总元戎。\n霜甲卧不暖，夜半闻边风。\n胡天早飞雪，荒徼多转蓬。\n寒云覆水重，秋气连海空。\n金鞍谁家子，上马鸣角弓。\n自是幽幷客，非论爱立功。' },
  { title: '云中行', author: '薛奇童', poem: '云中小儿吹金管，向晚因风一川满。\n塞北云高心已悲，城南木落肠堪断。\n忆昔魏家都此方，凉风观前朝百王。\n千门晓映山川色，双阙遥连日月光。\n举杯称寿永相保，日夕歌钟彻清昊。\n将军汗马百战塲，天子射兽五原草。\n寂寞金舆去不归，陵上黄尘满路飞。\n河边不语伤流水，川上含情叹落晖。\n此时独立无所见，日暮寒风吹客衣。' },
  { title: '楚宫词二首 一', author: '薛奇童', poem: '禁苑春风起，流莺绕合欢。\n玉窗通日气，珠箔卷轻寒。\n杨叶垂阴砌，梨花入井阑。\n君王好长袖，新作舞衣宽。' },
  { title: '楚宫词二首 二', author: '薛奇童', poem: '日晚梧桐落，微寒入禁垣。\n月悬三雀观，霜度万秋门。\n艳舞矜新宠，愁容泣旧恩。\n不堪深殿里，帘外欲黄昏。' },
  { title: '长孙十一东山春夜见赠', author: '杨谏', poem: '故人谢城阙，挥手碧云期。\n谿月照隐处，松风生兴时。\n旧林日云暮，芳草岁空滋。\n甘与子成梦，请君同所思。' },
  { title: '赠知己', author: '杨谏', poem: '江南折芳草，江北赠佳期。\n江阔水复急，过江常苦迟。\n苹白兰叶青，恐度先香时。\n美人碧云外，宁见长相思。' },
  { title: '东溪待苏户曹不至', author: '张万顷', poem: '洛阳城东伊水西，千花万竹使人迷。\n台上柳枝临岸低，门前荷叶与桥齐。\n日暮待君君不见，长风吹雨过青溪。' },
  { title: '登天目山下作', author: '张万顷', poem: '去岁离秦望，今冬使楚关。\n泪添天目水，发变海头山。\n别母乌南逝，辞兄雁北还。\n宦游偏不乐，长为忆慈颜。' },
  { title: '送裴少府', author: '张万顷', poem: '夕膳望东周，晨装不少留。\n酒中同乐事，关外越离忧。\n座湿秦山雨，庭寒渭水秋。\n何当鹰隼击，来拂故林游。' },
  { title: '旅次灞亭', author: '沈颂', poem: '闲琴开旅思，清夜有愁心。\n圆月正当户，微风犹在林。\n苍茫孤亭上，历乱多秋音。\n言念待明发，东山幽意深。' },
  { title: '春旦歌', author: '沈颂', poem: '常闻嬴女玉箫台，奏曲情深彩凤来。\n欲登此地销归恨，却羡双飞去不回。' },
  { title: '早发西山', author: '沈颂', poem: '游子空有怀，赏心杳无路。\n前程数千里，乘夜连轻驭。\n缭绕松筿中，苍茫犹未曙。\n遥闻孤村犬，暗指人家去。\n疲马怀涧泉，征衣犯霜露。\n喧呼谿鸟惊，沙上或𬸣翥。\n娟娟东岑月，照耀独归虑。' },
  { title: '送人还吴', author: '沈颂', poem: '人心不忘乡，矧余客已久。\n送君江南去，秋醉洛阳酒。\n赠言幽径兰，别思河堤柳。\n征帆暮风急，望望空延首。' },
  { title: '送金文学还日东', author: '沈颂', poem: '君家东海东，君去因秋风。\n漫漫指乡路，悠悠如梦中。\n烟雾积孤岛，波涛连太空。\n冒险当不惧，皇恩措尔躬。' },
  { title: '卫中作', author: '沈颂', poem: '卫风愉艳宜春色，淇水清泠增暮愁。\n总使榴花能一醉，终须萱草暂忘忧。' },
  { title: '天长节', author: '梁锽', poem: '日月生天久，年年庆一回。\n时平祥不去，寿远节长来。\n连吹千家笛，同朝百郡杯。\n愿持金殿镜，处处照遗才。' },
  { title: '长门怨', author: '梁锽', poem: '妾命何偏薄，君王去不归。\n欲令遥见悔，楼上试春衣。\n空殿看人入，深宫羡鸟飞。\n翻悲因买赋，索镜照空辉。' },
  { title: '美人春卧', author: '梁锽', poem: '妾家巫峡阳，罗幌寝兰堂。\n晓日临窗久，春风引梦长。\n落钗仍挂鬓，微汗欲消黄。\n纵使朦胧觉，魂犹逐楚王。' },
  { title: '名姝咏', author: '梁锽', poem: '阿娇年未多，弱体性能和。\n怕重愁拈镜，怜轻喜曳罗。\n临津双洛浦，对月两嫦娥。\n独有荆王殿，时时暮雨过。' },
  { title: '艳女词', author: '梁锽', poem: '露井桃花发，双双燕并飞。\n美人姿态里，春色上罗衣。\n自爱频开镜，时羞欲掩扉。\n不知行路客，遥惹五香归。' },
  { title: '狷氏子', author: '梁锽', poem: '杏梁初照日，碧玉后堂开。\n忆事临妆笑，春娇满镜台。\n含声歌扉举，顾影舞腰回。\n别有佳期处，青楼客夜来。' },
  { title: '戏赠歌者', author: '梁锽', poem: '白皙歌童子，哀音绝又连。\n楚妃临扇学，卢女隔帘传。\n晓燕喧喉里，春莺啭舌边。\n若逢汉武帝，还是李延年。' },
  { title: '七夕泛舟', author: '梁锽', poem: '云端有灵匹，掩映拂妆台。\n夜久应摇珮，天高响不来。\n片欢秋始展，残梦晓翻催。\n却怨填河鹊，留桥又不回。' },
  { title: '崔驸马宅咏画山水扇', author: '梁锽', poem: '画扇出秦楼，谁家赠列侯。\n小含吴剡县，轻带楚扬州。\n揜作山云暮，摇成陇树秋。\n坐来传与客，汉水又回流。' },
  { title: '观王美人海图障子', author: '梁锽', poem: '宋玉东家女，常怀物外多。\n自从图渤海，谁为觅湘娥。\n白鹭栖脂粉，赪鲂跃绮罗。\n仍怜转娇眼，别恨一横波。' },
  { title: '闻百舌鸟', author: '梁锽', poem: '百舌闻他郡，间关媚物华。\n敛形藏一叶，分响出千花。\n坐爱时褰幌，行藏或驻车。\n不须应独感，三载已辞家。' },
  { title: '省试方士进恒春草', author: '梁锽', poem: '东吴有灵草，生彼剡谿傍。\n既乱莓苔色，仍连菡萏香。\n掇之称远士，持以奉明王。\n北阙颜弥驻，南山寿更长。\n金膏徒骋妙，石髓莫矜良。\n倘使沾涓滴，还游不死方。' },
  { title: '代征人妻喜夫还', author: '梁锽', poem: '征夫走马发渔阳，少妇含娇开洞房。\n千日废台还挂镜，数年尘面再新妆。\n春风喜出今朝户，明日虚眠昨夜床。\n莫道幽闺书信隔，还衣总是旧时香。' },
  { title: '赠李中华', author: '梁锽', poem: '莫向嵩山去，神仙多误人。\n不如朝魏阙，天子重贤臣。' },
  { title: '咏木老人', author: '梁锽', poem: '刻木牵丝作老翁，鸡皮鹤发与真同。\n须臾弄罢寂无事，还似人生一梦中。' },
  { title: '客中作', author: '杜俨', poem: '书劒催人不暂闲，洛阳羁旅复秦关。\n容颜岁岁愁边改，乡国时时梦里还。' },
  { title: '三月三日曲江侍宴', author: '赵良器', poem: '圣祖发神谋，灵符叶帝求。\n一人光锡命，万国荷时休。\n雷解圜丘毕，云需曲水游。\n岸花迎步辇，仙仗拥行舟。\n睿藻天中降，恩波海外流。\n小臣同品物，陪此乐皇猷。' },
  { title: '郑国夫人挽歌词', author: '赵良器', poem: '淑德延公胄，宜家接帝姻。\n桂宫男掌仆，兰殿女升嫔。\n恩泽昭前命，盈虚变此辰。\n万年今已矣，彤管列何人。' },
  { title: '郡中客舍', author: '黄麟', poem: '虫响乱啾啾，更人正数筹。\n魂归洞庭夜，霜卧洛阳秋。\n微月有时隐，长河到晓流。\n起来还嘱雁，乡信在吴洲。' },
  { title: '途中口号', author: '郭向', poem: '抱玉三朝楚，怀书十上秦。\n年年洛阳陌，花鸟弄归人。' },
  { title: '题李将军山亭', author: '郭良', poem: '凤辖将军位，龙门司隶家。\n衣冠为隐逸，山水作繁华。\n径出重林草，池摇两岸花。\n谁知贵公第，亭院有烟霞。' },
  { title: '早行', author: '郭良', poem: '早行星尚在，数里未天明。\n不辨云林色，空闻风水声。\n月从山上落，河入斗间横。\n渐至重门外，依稀见洛城。' },
  { title: '过故人旧宅', author: '王乔', poem: '故人轩骑罢归来，旧宅园林闲不开。\n唯余挟瑟楼中妇，哭向平生歌舞台。' },
  { title: '关山月', author: '徐九臯', poem: '玉塞抵长城，金徽暎高阙。\n遥心万余里，直望三边月。\n霜静影逾悬，露晞光渐没。\n思君不可见，空叹将焉歇。' },
  { title: '战城南', author: '徐九臯', poem: '塞北狂胡旅，城南敌汉围。\n巉岩一鼓气，拔利五兵威。\n虏骑瞻山哭，王师拓地飞。\n不应须宠战，当遂勒金徽。' },
  { title: '咏史', author: '徐九臯', poem: '亡国秦韩代，荣身刘项年。\n金槌击政后，玉斗碎增前。\n圣主称三杰，明离保四贤。\n已申黄石祭，方慕赤松仙。' },
  { title: '途中览镜', author: '徐九臯', poem: '四海游长倦，百年愁半侵。\n赖窥明镜里，时见丈夫心。' },
  { title: '送部四镇人往单于别知故', author: '徐九臯', poem: '天下今无事，云中独未宁。\n忝驱更戍卒，方远送边庭。\n马饮长城水，军占太白星。\n国恩行可报，何必守经营。' },
  { title: '松滋江北阻风', author: '阎宽', poem: '江风久未歇，山雨复相仍。\n巨浪天涯起，余寒川上凝。\n忧人劳夕惕，乡事惫晨兴。\n远听知音骇，诚哉不可陵。' },
  { title: '晓入宜都渚', author: '阎宽', poem: '问俗周楚甸，川行眇江浔。\n兴随晓光发，道会春言深。\n回眺佳气象，远怀得山林。\n伫应舟楫用，曷务归闲心。' },
  { title: '古意', author: '阎宽', poem: '庭树发华滋，瑶草复葳蕤。\n好鸟飞相从，愁人深此时。\n天中有灵匹，日夕嚬蛾眉。\n愿逐飘风花，千里入遥帷。\n心逝爱不见，空歌悲莫悲。' },
  { title: '春宵览月', author: '阎宽', poem: '月生东荒外，天云收夕阴。\n爱见澄清景，象吾虚白心。\n耳目静无哗，神超道性深。\n乘兴得至乐，寓言因永吟。' },
  { title: '秋怀', author: '阎宽', poem: '下帷长日尽，虚馆早凉生。\n芳草犹未荐，如何蜻蛚鸣。\n秋风已振衣，客去何时归。\n为问当途者，宁知心有违。' },
  { title: '和中书侍郎院壁画云', author: '李收', poem: '粉壁画云成，如能上太清。\n影从霄汉发，光照掖垣明。\n暎筿多幽趣，临轩得野情。\n独思作霖雨，流润及生灵。' },
  { title: '幽情', author: '李收', poem: '幽人惜春暮，潭上折芳草。\n佳期何时还，欲寄千里道。' },
  { title: '怀鲁', author: '程弥纶', poem: '曲阜国，尼丘山。\n周公邈难问，夫子犹启关。\n履风雩兮若见，游夏兴兮鲁颜。\n天孙天孙，何为今兮学且难，负星明而东游闲闲。' },
  { title: '燕歌行', author: '屈同仙', poem: '君不见渔阳八月塞草腓，征人相对并思归。\n云和朔气连天黑，蓬杂惊沙散野飞。\n是时天地阴埃遍，瀚海龙城皆习战。\n两军鼓角暗相闻，四面旌旗看不见。\n昭君远嫁已年多，戎狄无厌不复和。\n汉兵候月秋防塞，胡骑乘冰夜渡河。\n河塞东西万余里，地与京华不相似。\n燕支山下少春晖，黄沙碛里无流水。\n金戈玉剑十年征，红粉青楼多怨情。\n厌向殊乡久离别，秋来愁听捣衣声。' },
  { title: '乌江女', author: '屈同仙', poem: '越艳谁家女，朝游江岸傍。\n青春犹未嫁，红粉旧来娼。\n锦袖盛朱橘，银钩摘紫房。\n见人羞不语，回艇入溪藏。' },
  { title: '昌年宫之作', author: '豆卢复', poem: '但有离宫处，君王每不居。\n旗门芳草合，辇路小槐疎。\n殿闭山烟满，窗凝野霭虚。\n丰年多望幸，春色待銮舆。' },
  { title: '落第归乡留别长安主人', author: '豆卢复', poem: '客里愁多不记春，闻莺始叹柳条新。\n年年下第东归去，羞见长安旧主人。' },
  { title: '奉试咏青', author: '荆冬倩', poem: '路辟天光远，春还月道临。\n草浓河畔色，槐结路边阴。\n未映君王史，先标胄子襟。\n经明如可拾，自有致云心。' },
  { title: '观汉水', author: '梁洽', poem: '发源自嶓冢，东注经襄阳。\n一道入溟渤，别流为沧浪。\n求思咏游女，投吊悲昭王。\n水滨不可问，日暮空汤汤。' },
  { title: '游越溪', author: '郑绍', poem: '溪水碧悠悠，猨声断客愁。\n渔潭逢钓楫，月浦值孤舟。\n访泊随烟火，迷途视斗牛。\n今宵越乡意，还取醉忘忧。' },
  { title: '登楼', author: '朱斌', poem: '白日依山尽，黄河入海流。\n欲穷千里目，更上一层楼。' },
  { title: '感寓二首 一', author: '梁德裕', poem: '彩云呈瑞质，五色发人寰。\n独作龙虎状，孤飞天地间。\n隐隐临北极，峨峨象南山。\n恨在帝乡外，不逢枝叶攀。' },
  { title: '感寓二首 二', author: '梁德裕', poem: '幽涧生蕙若，幽渚老江蓠。\n荣落人不见，芳香徒尔为。\n不及绿萍草，生君红莲池。\n左右美人弄，朝夕春风吹。\n叶洗玉泉水，珠清湛露滋。\n心亦愿如此，托君君不知。' },
  { title: '咏谈容娘', author: '常非月', poem: '举手整花钿，翻身舞锦筵。\n马围行处匝，人压看场圆。\n歌要齐声和，情教细语传。\n不知心大小，容得许多怜。' },
  { title: '览史', author: '张良璞', poem: '享年八十已，历数穷苍生。\n七虎门源上，咆哮关内鸣。\n建都用鹑宿，设险因金城。\n舜曲烟火起，汾河珠翠明。\n海云引天仗，朔雪留边兵。\n作孽人怨久，其亡鬼信盈。\n素灵感刘季，白马从子婴。\n昏虐不务德，百代无芳声。' },
  { title: '奉试冷井诗', author: '孙欣', poem: '仙闱井初凿，灵液沁成泉。\n色湛青苔里，寒凝紫绠边。\n铜瓶向影落，玉甃抱虚圆。\n永愿调神鼎，尧时泰万年。' },
  { title: '都中闲居', author: '王羡门', poem: '君王巡海内，北阙下明台。\n云物天中少，烟花岁后来。\n河从御苑出，山向国门开。\n寂寞东京里，空留贾谊才。' },
  { title: '江南弄', author: '芮挺章', poem: '春江可怜事，最在美人家。\n鹦鹉能言鸟，芙蓉巧笑花。\n地衔金作埒，水抱玉为沙。\n薄晚青丝骑，长鞭赴狭斜。' },
  { title: '少年行', author: '芮挺章', poem: '任气称张放，衔恩在少年。\n玉阶朝就日，金屋夜升天。\n轩骑青云际，笙歌绿水边。\n建章明月好，留醉伴风烟。' },
  { title: '伊水门', author: '楼颕', poem: '朝涉伊水门，伊水入门流。\n惬心乃成兴，澹然泛孤舟。\n霏微傍青霭，容与随白鸥。\n竹阴交前浦，柳花媚中洲。\n日落阴云生，弥觉兹路幽。\n聊以恣所适，此外知何求。' },
  { title: '东郊纳凉忆左威卫李录事收昆季太原崔参军三首 一', author: '楼颕', poem: '水竹谁家宅，幽庭向苑门。\n今知季伦沼，旧是辟疆园。\n饥鹭窥鱼静，鸣鸦带子喧。\n兴成秪自适，欲白返忘言。' },
  { title: '东郊纳凉忆左威卫李录事收昆季太原崔参军三首 二', author: '楼颕', poem: '纳凉每选地，近得青门东。\n林与缭垣接，池将沁水通。\n枝交帝女树，桥映美人虹。\n想是忘机者，悠悠在兴中。' },
  { title: '东郊纳凉忆左威卫李录事收昆季太原崔参军三首 三', author: '楼颕', poem: '林间求适意，池上得清飙。\n稍稍斜回檝，时时一度桥。\n水光壁际动，山影浪中摇。\n不见李元礼，神仙何处要。' },
  { title: '西施石', author: '楼颕', poem: '西施昔日浣纱津，石上青苔思杀人。\n一去姑苏不复返，岸旁桃李为谁春。' },
  { title: '江南行', author: '李康成', poem: '杨柳青青莺欲啼，风光摇荡绿苹齐，金阴城头日色低。\n日色低，情难极，水中凫鹥双比翼。' },
  { title: '采莲曲', author: '李康成', poem: '采莲去，月没春江曙。\n翠钿红袖水中央，青荷莲子杂衣香，云起风生归路长。\n归路长，那得久。\n各回船，两摇手。' },
  { title: '玉华仙子歌', author: '李康成', poem: '紫阳仙子名玉华，珠盘承露饵丹砂。\n转态凝情五云里，娇颜千岁芙蓉花。\n紫阳彩女矜无数，遥见玉华皆掩嫭。\n高堂初日不成妍，洛渚流风徒自怜。\n璇阶霓绮阁，碧题霜罗幕。\n仙娥桂树长自春，王母桃花未尝落。\n上元夫人宾上清，深宫寂历厌层城。\n解佩空怜郑交甫，吹箫不逐许飞琼。\n溶溶紫庭步，渺渺瀛台路。\n兰陵贵士谢相逢，济北风生尚回顾。\n沧洲傲吏爱金丹，清心回望云之端。\n羽盖霓裳一相识，传情写念长无极。\n长无极，永相随。\n攀霄历金阙，弄影下瑶池。\n夕宿紫府云母帐，朝餐玄圃昆仑芝。\n不学兰香中道绝，却教青鸟报相思。' },
  { title: '自君之出矣', author: '李康成', poem: '自君之出矣，弦吹绝无声。\n思君如百草，撩乱逐春生。' },
  { title: '句', author: '李康成', poem: '因缘苟会合，万里犹同乡。\n运命尚不谐，隔壁无津梁。' },
  { title: '时兴', author: '杨贲', poem: '贵人昔未贵，咸愿顾寒微。\n及自登枢要，何曾问布衣。\n平明登紫阁，日晏下彤闱。\n扰扰路傍子，无劳歌是非。' },
  { title: '咏石季伦', author: '李清', poem: '金谷繁华石季伦，只能谋富不谋身。\n当时纵与绿珠去，犹有无穷歌舞人。' },
  { title: '鹤警露', author: '陈季', poem: '南国商飙动，东臯野鹤鸣。\n溪松寒暂宿，露草滴还惊。\n欲有高飞意，空闻召侣情。\n风间传藻质，月下引清声。\n未假抟扶势，焉知羽翼轻。\n吾君开太液，愿得应皇明。' },
  { title: '湘灵鼓瑟', author: '陈季', poem: '神女泛瑶瑟，古祠严野亭。\n楚云来泱漭，湘水助清泠。\n妙指微幽契，繁声入杳冥。\n一弹新月白，数曲暮山青。\n调苦荆人怨，时遥帝子灵。\n遗音如可赏，试奏为君听。' },
  { title: '湘灵鼓瑟', author: '王邕', poem: '宝瑟和琴韵，灵妃应乐章。\n依稀闻促柱，髣髴梦新妆。\n波外声初发，风前曲正长。\n凄清和万籁，断续绕三湘。\n转觉云山迥，空怀杜若芳。\n诚能传此意，雅奏在宫商。' },
  { title: '嵩山望幸', author: '王邕', poem: '峻极位何崇，方知造化功。\n降灵逢圣主，望幸表维嵩。\n隐映连青壁，嵯峨向碧空。\n象车因叶瑞，龙驾愿升中。\n万岁声长在，千岩气转雄。\n东都歌盛事，西笑伫皇风。' },
  { title: '湘灵鼓瑟', author: '庄若讷', poem: '帝子鸣金瑟，余声自抑扬。\n悲风丝上断，流水曲中长。\n出没游鱼听，逶迤彩凤翔。\n微音时扣征，雅韵乍含商。\n神理诚难测，幽情讵可量。\n至今闻古调，应恨滞三湘。' },
  { title: '湘灵鼓瑟', author: '魏璀', poem: '瑶瑟多哀怨，朱弦且莫听。\n扁舟三楚客，藂竹二妃灵。\n淅沥闻余响，依稀欲辨形。\n柱间寒水碧，曲里暮山青。\n良马悲衔草，游鱼思绕萍。\n知音若相遇，终不滞南溟。' },
  { title: '怀素上人草书歌', author: '王𩔪', poem: '衡阳双峡插天峻，青壁巉巉万余仞。\n此中灵秀众所知，草书独有怀素奇。\n怀素身长五尺四，嚼汤诵呪吁可畏。\n铜瓶锡杖倚闲庭，斑管秋毫多逸意。\n或粉壁，或彩牋，蒲葵绢素何相鲜。\n忽作风驰如电掣，更点飞花兼散雪。\n寒猨饮水撼枯藤，壮士拔山伸劲铁。\n君不见张芝昔日称独贤，君不见近日张旭为老颠。\n二公绝艺人所惜，怀素传之得真迹。\n峥嵘蹙出海上山，突兀状成湖畔石。\n一纵又一横，一欹又一倾。\n临江不羡飞帆势，下笔长为骤雨声。\n我牧此州喜相识，又见草书多慧力。\n怀素怀素不可得，开卷临池转相忆。' },
  { title: '怀素上人草书歌', author: '窦冀', poem: '狂僧挥翰狂且逸，独任天机摧格律。\n龙虎惭因点画生，雷霆却避锋铓疾。\n鱼牋娟素岂不贵，只嫌局促儿童戏。\n粉壁长廊数十间，兴来小豁胸襟气。\n长幼集，贤豪至，枕糟藉曲犹半醉。\n忽然绝叫三五声，满壁纵横千万字。\n吴兴张老尔莫颠，叶县公孙我何谓。\n如熊如罴不足比，如虺如蛇不足拟。\n涵物为动鬼神泣，狂风入林花乱起。\n殊形怪状不易说，就中惊燥尤枯绝。\n边风杀气同惨烈，崩槎卧木争摧折。\n塞草遥飞大漠霜，胡天乱下阴山雪。\n偏看能事转新奇，郡守王公同赋诗。\n枯藤劲铁媿三舍，骤雨寒猨惊一时。\n此生绝艺人莫测，假此常为护持力。\n连城之璧不可量，五百年知草圣当。' },
  { title: '怀素上人草书歌', author: '鲁收', poem: '吾观文士多利用，笔精墨妙诚堪重。\n身上艺能无不通，就中草圣最天纵。\n有时兴酣发神机，抽毫点墨纵横挥。\n风声吼烈随手起，龙蛇迸落空壁飞。\n连拂数行势不绝，藤悬查蹙生奇节。\n划然放纵惊云涛，或时顿挫萦豪发。\n自言转腕无所拘，大笑羲之用阵图。\n狂来纸尽势不尽，投笔抗声连叫呼。\n信知鬼神助此道，墨池未尽书已好。\n行路谈君口不容，满堂观者空绝倒。\n所恨时人多笑声，唯知贱实翻贵名。\n观尔向来三五字，颠奇何谢张先生。' },
  { title: '怀素上人草书歌', author: '朱逵', poem: '几年出家通宿命，一朝却忆临池圣。\n转腕摧锋增崛崎，秋毫茧纸常相随。\n衡阳客舍来相访，连饮百杯神转王。\n忽闻风里度飞泉，纸落纷纷如跕鸢。\n形容脱略真如助，心思周游在何处。\n笔下惟看激电流，字成只畏盘龙去。\n怪状崩腾若转蓬，飞丝历乱如回风。\n长松老死倚云壁，蹙浪相翻惊海鸿。\n于今年少尚如此，历覩远代无伦比。\n妙绝当动鬼神泣，崔蔡幽魂更心死。' },
  { title: '题怀素上人草书', author: '许瑶', poem: '志在新奇无定则，古瘦漓𫄥半无墨。\n醉来信手两三行，醒后却书书不得。' },
  { title: '祀风师乐章 迎神', author: '包佶', poem: '太皞御气，句芒肇功。\n苍龙青旗，爰候祥风。\n律以和应，神以感通。\n鼎俎修蚃，时惟礼崇。' },
  { title: '祀风师乐章 奠币登歌', author: '包佶', poem: '旨酒告洁，青苹应候。\n礼陈瑶币，乐献金奏。\n弹弦自昔，解冻惟旧。\n仰瞻肸蚃，群祥来凑。' },
  { title: '祀风师乐章 迎俎酌献', author: '包佶', poem: '德盛昭临，迎拜巽方。\n爰候发生，式荐馨香。\n酌醴具举，工歌再扬。\n神歆入律，恩降百祥。' },
  { title: '祀风师乐章 亚献终献', author: '包佶', poem: '膋芗备，玉帛陈。\n风动物，乐感神。\n三献终，百神臻。\n草木荣，天下春。' },
  { title: '祀风师乐章 送神', author: '包佶', poem: '微穆敷华能应节，飘扬发彩宜行庆。\n送迎灵驾神心飨，跪拜灵坛礼容盛。\n气和草木发萌芽，德畅禽鱼遂翔泳。\n永望翠盖逐流云，自兹率土调春令。' },
  { title: '祀雨师乐章 迎神', author: '包佶', poem: '陟降左右，诚达幽圆。\n作解之功，乐惟有年。\n云𫐌戾止，洒雾飘烟。\n惟馨展礼，爰列豆笾。' },
  { title: '祀雨师乐章 奠币登歌', author: '包佶', poem: '岁正朱明，礼布玄制。\n惟乐能感，与神合契。\n阴雾离披，灵驭摇裔。\n膏泽之庆，期于稔岁。' },
  { title: '祀雨师乐章 迎俎酌献', author: '包佶', poem: '阳开幽蛰，躬奉郁鬯。\n礼备节应，震来灵降。\n动植求声，飞沈允望。\n时康气茂，惟神之贶。' },
  { title: '祀雨师乐章 亚献终献', author: '包佶', poem: '奠既备，献将终。\n神行令，瑞飞空。\n迎干德，祈岁功。\n乘烟燎，俨从风。' },
  { title: '祀雨师乐章 送神', author: '包佶', poem: '整驾升车望寥廓，垂阴荐祉荡昏氛。\n飨时灵贶僾如在，乐罢余声遥可闻。\n饮福陈诚礼容备，撤俎终献曙光分。\n跪拜临坛结空想，年年应节候油云。' },
  { title: '答窦援遗卧病见寄', author: '包佶', poem: '今春扶病移沧海，几度承恩对白花。\n送客屡闻帘外鹊，销愁已辨酒中虵。\n瓶开枸杞悬泉水，鼎炼芙蓉伏火砂。\n误入尘埃牵吏役，羞将簿领到君家。' },
  { title: '对酒赠故人', author: '包佶', poem: '扶起离披菊，霜轻喜重开。\n醉中惊老去，笑里觉愁来。\n月送人无尽，风吹浪不回。\n感时将有寄，诗思涩难裁。' },
  { title: '同李吏部伏日口号呈元庶子路中丞', author: '包佶', poem: '火炎逢六月，金伏过三庚。\n几度衣裳汗，谁家枕簟清。\n颁冰无下位，裁扇有高名。\n吏部还开瓮，殷勤二客情。' },
  { title: '岭下卧疾寄刘长卿员外', author: '包佶', poem: '唯有贫兼病，能令亲爱疎。\n岁时供放逐，身世付空虚。\n胫弱秋添絮，头风晓废梳。\n波澜喧众口，藜藿静吾庐。\n丧马思开卦，占鸮嬾发书。\n十年江海隔，离恨子知予。' },
  { title: '戏题诸判官厅壁', author: '包佶', poem: '六十老翁无所取，二三君子不相遗。\n愿留今日交欢意，直到隳官谢病时。' },
  { title: '酬兵部李侍郎晚过东厅之作', author: '包佶', poem: '酒礼慙先祭，刑书已旷官。\n诏驰黄纸速，身在绛纱安。\n圣位登堂静，生徒跪席寒。\n庭槐暂摇落，幸为入春看。' },
  { title: '昭德皇后挽歌词', author: '包佶', poem: '西汜驰晖过，东园别路长。\n岁华唯陇柏，春事罢公桑。\n龟兆开泉户，禽巢闭画梁。\n更闻哀礼过，明诏制心丧。' },
  { title: '秋日过徐氏园林', author: '包佶', poem: '回塘分越水，古树积吴烟。\n扫竹催铺席，垂萝待系船。\n鸟窥新罅栗，龟上半攲莲。\n屡入忘归地，长嗟俗事牵。' },
  { title: '双山过信公所居', author: '包佶', poem: '遥礼前朝塔，微闻后夜钟。\n人间第四祖，云里一双峰。\n积雨封苔径，多年亚石松。\n传心不传法，谁可继高踪。' },
  { title: '尚书宗兄使过诗以奉献', author: '包佶', poem: '洛下交亲满，归闲意有余。\n翻嫌旧坐宅，却驾所悬车。\n腹饱山僧供，头轻侍婢梳。\n上官唯揖让，半禄代耕鉏。\n雨散三秋别，风传一字书。\n胜游如可继，还欲并园庐。' },
  { title: '抱疾谢李吏部赠诃黎勒叶', author: '包佶', poem: '一叶生西徼，赍来上海查。\n岁时经水府，根本别天涯。\n方士真难见，商胡辄自夸。\n此香同异域，看色胜仙家。\n茗饮暂调气，梧丸喜伐邪。\n幸蒙祛老疾，深愿驻韶华。' },
  { title: '奉和柳相公中书言怀', author: '包佶', poem: '运筹时所贵，前席礼偏深。\n羸驾归贫宅，攲冠出禁林。\n凤巢方得地，牛喘最关心。\n雅望期三入，东山未可寻。' },
  { title: '客自江南话过亡友朱司议故宅', author: '包佶', poem: '交臂多相共，风流忆此人。\n海翻移里巷，书蠹积埃尘。\n奉佛栖禅久，辞官上疏频。\n故来分半宅，惟是旧交亲。' },
  { title: '酬于侍郎湖南见寄十四韵', author: '包佶', poem: '桂岭千崖断，湘流一派通。\n长沙今贾傅，东海旧于公。\n章甫经殊俗，离骚继雅风。\n金闺文作字，玉匣气成虹。\n翰墨时招侣，丹青夙在公。\n主恩留左掖，人望积南宫。\n巧拙循名异，浮沈顾位同。\n九迁归上略，三已契愚衷。\n责谢庭中吏，悲宽塞上翁。\n楚材欣有适，燕石愧无功。\n山晓重岚外，林春苦雾中。\n雪花翻海鹤，波影倒江枫。\n去札频逢信，回帆早挂空。\n避贤方有日，非敢爱微躬。' },
  { title: '朝拜元陵', author: '包佶', poem: '宫前石马对中峰，云里金铺闭几重。\n不见露盘迎晓日，唯闻木斧扣寒松。' },
  { title: '发襄阳后却寄公安人', author: '包佶', poem: '挥泪送回人，将书报所亲。\n晚年多疾病，中路有风尘。\n王粲频征楚，君恩许入秦。\n还同星火去，马上别江春。' },
  { title: '立春后休沐', author: '包佶', poem: '心与青春背，新年亦掩扉。\n渐穷无相学，惟避不材讥。\n积病攻难愈，衔恩报转微。\n定知书课日，优诏许辞归。' },
  { title: '宿庐山赠白鹤观刘尊师', author: '包佶', poem: '苍苍五老雾中坛，杳杳三山洞里官。\n手护昆仑象牙简，心推霹雳枣枝盘。\n春飞雪粉如毫润，晓漱琼膏冰齿寒。\n渐恨流年筋力少，惟思露冕事星冠。' },
  { title: '观壁卢九想图', author: '包佶', poem: '一世荣枯无异同，百年哀乐又归空。\n夜阑鸟鹊相争处，林下真僧在定中。' },
  { title: '送日本国聘贺使晁巨卿东归', author: '包佶', poem: '上才生下国，东海是西邻。\n九译蕃君使，千年圣主臣。\n野情偏得礼，木性本含真。\n锦帆乘风转，金装照地新。\n孤城开蜃阁，晓日上朱轮。\n早识来朝岁，涂山玉帛均。' },
  { title: '顾著作宅赋诗', author: '包佶', poem: '几年江海烟霞，乘醉一到京华。\n已觉不嫌羊酪，谁能长守兔罝。\n脱巾偏招相国，逢竹便认吾家。\n各在芸台阁里，烦君日日登车。' },
  { title: '近获风痹之疾题寄所怀', author: '包佶', poem: '病夫将已矣，无可答君恩。\n衾枕同羇客，图书委外孙。\n久来从吏道，常欲奉空门。\n疾走机先息，攲行力渐烦。\n无医能却老，有变是游魂。\n鸟宿还依伴，蓬飘莫问根。\n寓形齐指马，观境制心猨。\n唯借南荣地，清晨暂负喧。' },
  { title: '奉和常阁老晚秋集贤院即事寄赠徐薛二侍郎', author: '包佶', poem: '秘殿掖垣西，书楼苑树齐。\n秋烟凝缥帙，晓色上璇题。\n门接承明近，池连太液低。\n疎钟文马驻，繁叶彩禽栖。\n职美纶江綍，荣深组及珪。\n九霄偏眷顾，三事早提携。\n对案临青玉，窥书捧紫泥。\n始欢新遇重，还惜旧游暌。\n左宦登吴岫，分家渡越溪。\n赋中频叹𫛳，卜处几听鸡。\n望阙应多恋，临津不用迷。\n柏梁思和曲，朝夕候金闺。' },
  { title: '酬顾况见寄', author: '包佶', poem: '于越城边枫叶高，楚人书里寄离骚。\n寒江㶉𫛶思俦侣，岁岁临流刷羽毛。' },
  { title: '岁日作', author: '包佶', poem: '更劳今日春风至，枯树无枝可寄花。\n览镜唯看飘乱发，临风谁为驻浮槎。' },
  { title: '元日观百僚朝会', author: '包佶', poem: '万国贺唐尧，清晨会百僚。\n花冠萧相府，绣服霍嫖姚。\n寿色凝丹槛，欢声彻九霄。\n御𬬻分兽炭，仙管弄云韶。\n日照金觞动，风吹玉佩摇。\n都城献赋者，不得共趋朝。' },
  { title: '再过金陵', author: '包佶', poem: '玉树歌终王气收，鴈行高送石城秋。\n江山不管兴亡事，一任斜阳伴客愁。' },
  { title: '寄杨侍御', author: '包佶', poem: '一官何幸得同时，十载无媒独见遗。\n今日不论腰下组，请君看取鬓边丝。' },
  { title: '江上曲', author: '李嘉祐', poem: '江心澹澹芙蓉花，江口蛾眉独浣纱。\n可怜应是阳台女，对坐鹭鸶娇不语。\n掩面羞看北地人，回身忽作空山语。\n苍梧秋色不堪论，千载依依帝子魂。\n君看峰上斑斑竹，尽是湘妃泣泪痕。' },
  { title: '伤吴中', author: '李嘉祐', poem: '馆娃宫中春已归，阖闾城头莺已飞。\n复见花开人又老，横塘寂寂柳依依。\n忆昔吴王在宫阙，馆娃满眼看花发。\n舞袖朝欺陌上春，歌声夜怨江边月。\n古来人事亦犹今，莫厌清觞与绿琴。\n独向西山聊一笑，白云芳草自知心。' },
  { title: '夜闻江南人家赛神因题即事', author: '李嘉祐', poem: '南方淫祀古风俗，楚妪解唱迎神曲。\n鎗鎗铜鼓芦叶深，寂寂琼筵江水绿。\n雨过风清洲渚闲，椒浆醉尽迎神还。\n帝女凌空下湘岸，番君隔浦向尧山。\n月隐回塘犹自舞，一门依倚神之祜。\n韩康灵药不复求，扁鹊医方曾莫覩。\n逐客临江空自悲，月明流水无已时。\n听此迎神送神曲，携觞欲吊屈原祠。' },
  { title: '古兴', author: '李嘉祐', poem: '十五小家女，双鬟人不如。\n蛾眉暂一见，可直千金余。\n自从得向蓬莱里，出入金舆乘玉趾。\n梧桐树上春鸦鸣，晓伴君王犹未起。\n莫道君恩长不休，婕妤团扇苦悲秋。\n君看魏帝邺都里，惟有铜台漳水流。' },
  { title: '杂兴', author: '李嘉祐', poem: '花间昔日黄鹂啭，妾向青楼已生怨。\n花落黄鹂不复来，妾老君心亦应变。\n君心比妾心，妾意旧来深。\n一别十年无尺素，归时莫赠路傍金。' },
  { title: '送韦邕少府归钟山', author: '李嘉祐', poem: '祈门官罢后，负笈向桃源。\n万卷长开帙，千峰不闭门。\n绿杨垂野渡，黄鸟傍山村。\n念尔能高枕，丹墀会一论。' },
  { title: '送卢员外往饶州', author: '李嘉祐', poem: '为郎复典郡，锦帐映朱轮。\n露冕随龙节，停桡得水人。\n早霜芦叶变，寒雨石榴新。\n莫怪谙风土，三年作逐臣。' },
  { title: '送裴五归京口', author: '李嘉祐', poem: '君罢江西日，家贫为一官。\n还归五陵去，只向远峰看。\n暮色催人别，秋风待雨寒。\n遥知到三径，唯有菊花残。' },
  { title: '送严维归越州', author: '李嘉祐', poem: '艰难只用武，归向淛河东。\n松雪千山暮，林泉一水通。\n乡心缘绿草，野思看青枫。\n春日偏相忆，裁书寄剡中。' },
  { title: '送杜士瞻楚州觐省', author: '李嘉祐', poem: '风流与才思，俱似晋时人。\n淮月归心促，江花入兴新。\n云深沧海暮，柳暗白田春。\n共道官犹小，怜君孝养亲。' },
  { title: '送裴宣城上元所居', author: '李嘉祐', poem: '水流过海稀，尔去换春衣。\n泪向槟榔尽，身随鸿雁归。\n草思晴后发，花怨雨中飞。\n想到金陵渚，酣歌对落晖。' },
  { title: '留别毘陵诸公', author: '李嘉祐', poem: '久作涔阳令，丹墀忽再还。\n凄凉辞泽国，离乱到乡山。\n北固滩声满，南徐草色闲。\n知心从此别，相忆鬓毛斑。' },
  { title: '送独孤拾遗先辈先赴上都', author: '李嘉祐', poem: '行春日已晓，桂檝逐寒烟。\n转曲遥峰出，看涛极浦连。\n入京当献赋，封事更闻天。\n日日趋黄阁，应忘云海边。' },
  { title: '常州韦郎中泛舟见饯', author: '李嘉祐', poem: '主人冯轼贵，送客泛舟稀。\n逼岸随芳草，回桡背落晖。\n映花双节驻，临水伯劳飞。\n醉与群公狎，春塘露冕归。' },
  { title: '送崔侍御入朝', author: '李嘉祐', poem: '十年犹执宪，万里独归春。\n旧国逢芳草，青云见故人。\n潘郎今发白，陶令本家贫。\n相送临京口，停桡泪满巾。' },
  { title: '送岳州司马弟之任', author: '李嘉祐', poem: '岳阳天水外，念尔一帆过。\n野墅人烟逈，山城雁影多。\n有时巫峡色，终日洞庭波。\n丞相今为郡，应无劳者歌。' },
  { title: '裴侍御见赠斑竹杖', author: '李嘉祐', poem: '骚人夸竹杖，赠我意何深。\n万点湘妃泪，三年贾谊心。\n愿持终白首，谁道贵黄金。\n他日归愚谷，偏宜绿绮琴。' },
  { title: '送张观归袁州', author: '李嘉祐', poem: '羡尔湘东去，烟花尚可亲。\n绿芳深映鸟，远岫递迎人。\n饥狖啼初日，残莺惜暮春。\n遥怜谢客兴，佳句又应新。' },
  { title: '冬夜饶州使堂饯相公五叔赴歙州', author: '李嘉祐', poem: '丞相过邦牧，清弦送羽觞。\n高情同客醉，子夜为人长。\n斜汉这过斗，寒云正护霜。\n新安江自绿，明主待惟良。' },
  { title: '蒋山开善寺', author: '李嘉祐', poem: '山殿秋云里，香烟出翠微。\n客寻朝磬至，僧背夕阳归。\n下界千门在，前朝万事非。\n看心兼送目，葭菼自依依。' },
  { title: '晚发江宁道中呈严维', author: '李嘉祐', poem: '惆怅遥江路，萧条落日过。\n蝉鸣独树急，鸦向古城多。\n转曲随青嶂，因高见白波。\n潘生秋径草，严子意如何。' },
  { title: '句容县东青阳馆作', author: '李嘉祐', poem: '句曲千峰暮，归人向远烟。\n风摇近水叶，云护欲晴天。\n夕照留山馆，秋光落草田。\n征途傍斜日，一骑独翩翩。' },
  { title: '晚春宴无锡蔡明府西亭', author: '李嘉祐', poem: '茅檐闲寂寂，无事觉人和。\n井近时浇圃，城低下见河。\n兴缘芳草积，情向远峰多。\n别日归吴地，停桡更一过。' },
  { title: '送王端赴朝', author: '李嘉祐', poem: '君承明主意，日日上丹墀。\n东阁论兵后，南宫草奏期。\n人稀傍河处，槐暗入关时。\n独遣吴州客，平陵结梦思。' },
  { title: '送王正字山寺读书', author: '李嘉祐', poem: '欲究先儒教，还过支遁居。\n山堦闲听法，竹迳独看书。\n向日荷新卷，迎秋柳半疎。\n风流有佳句，不似带经锄。' },
  { title: '送房明府罢长宁令湖州客舍', author: '李嘉祐', poem: '君为万里宰，恩及五湖人。\n未满先求退，归闲不厌贫。\n远峰晴更近，残柳雨还新。\n要自趋丹陛，明年鸡树亲。' },
  { title: '咏萤', author: '李嘉祐', poem: '映水光难定，凌虚体自轻。\n夜风吹不灭，秋露洗还明。\n向烛仍分焰，投书更有情。\n犹将流乱影，来此傍檐楹。' },
  { title: '送李中丞杨判官', author: '李嘉祐', poem: '射策名先着，论兵气自雄。\n能全季布诺，不道鲁连功。\n流水蒹葭外，诸山睥睨中。\n别君秋日晚，回首夕阳空。' },
  { title: '至七里滩作', author: '李嘉祐', poem: '迁客投于越，临江泪满衣。\n独随流水远，转觉故人稀。\n万木迎秋序，千峰驻晚晖。\n行舟犹未已，惆怅暮潮归。' },
  { title: '南浦渡口', author: '李嘉祐', poem: '寂寞横塘路，新篁覆水低。\n东风潮信满，时雨稻秔齐。\n寡妇共租税，渔人逐鼓鼙。\n慙无卓鲁术，解印谢黔黎。' },
  { title: '暮秋迁客增思寄京华', author: '李嘉祐', poem: '宋玉怨三秋，张衡复四愁。\n思乡雁北至，欲别水东流。\n倚树看黄叶，逢人诉白头。\n佳期不可失，落日自登楼。' },
  { title: '送苏修往上饶', author: '李嘉祐', poem: '爱尔无羁束，云山恣意过。\n一身随远岫，孤櫂任轻波。\n世事关心少，渔家寄宿多。\n芦花泊舟处，江月奈人何。' },
  { title: '题王十九茆堂', author: '李嘉祐', poem: '满庭多种药，入里作山家。\n终日能留客，凌寒亦对花。\n海鸥过竹屿，门柳拂江沙。\n知尔卑栖意，题诗美白华。' },
  { title: '送弘志上人归湖州', author: '李嘉祐', poem: '山林唯幽静，行住不妨禅。\n高月穿松迳，残阳过水田。\n诗从宿世悟，法为本师传。\n能使南人敬，修持香火缘。' },
  { title: '送陆士伦宰义兴', author: '李嘉祐', poem: '阳羡兰陵近，高城带水闲。\n浅流通野寺，绿茗盖春山。\n长吏多愁罢，游人讵肯还。\n知君日清净，无事掩重关。' },
  { title: '和张舍人中书宿直', author: '李嘉祐', poem: '汉主留才子，春城直紫微。\n对花阊阖静，过竹吏人稀。\n裁诏催添烛，将朝欲更衣。\n玉堂宜岁久，且莫厌彤闱。' },
  { title: '司勋王郎中宅送韦九郎中往濠州', author: '李嘉祐', poem: '怜尔因同舍，看书似外家。\n出关逢落叶，傍水见寒花。\n送远添秋思，将衰恋岁华。\n清淮倍相忆，回首莫令赊。' },
  { title: '晚春送吉校书归楚州', author: '李嘉祐', poem: '诗人饶楚思，淮上及春归。\n旧浦菱花发，闲门柳絮飞。\n高名乡曲重，少事道流稀。\n定向渔家醉，残阳卧钓矶。' },
  { title: '送严二擢第东归', author: '李嘉祐', poem: '隳官就宾荐，时辈讵争先。\n盛业推儒行，高科独少年。\n迎秋见衰叶，余照逐鸣蝉。\n旧里三峰下，开门古县前。' },
  { title: '送冷朝阳及第东归江宁', author: '李嘉祐', poem: '高第由佳句，诸生似者稀。\n长安带酒别，建业候潮归。\n稚子欢迎櫂，隣人为扫扉。\n含情过旧浦，鸥鸟亦依依。' },
  { title: '送越州辛法曹之任', author: '李嘉祐', poem: '但能一官适，莫羡五侯尊。\n山色垂趋府，潮声自到门。\n缘塘剡溪路，映竹五湖村。\n王谢登临处，依依今尚存。' },
  { title: '送樊兵曹潭州谒韦大夫', author: '李嘉祐', poem: '塞鸿归欲尽，北客始辞春。\n零桂虽逢竹，湘川少见人。\n江花铺浅水，山木暗残春。\n修刺辕门里，多怜尔为亲。' },
  { title: '送杜御史还广陵', author: '李嘉祐', poem: '慙君从弱岁，顾我比诸昆。\n同事元戎久，俱承国士恩。\n随莺过淮水，看柳向辕门。\n草色金陵岸，思心那可论。' },
  { title: '送兖州杜别驾之任', author: '李嘉祐', poem: '停车邀别乘，促轸奏胡笳。\n若见楚山暮，因愁浙水赊。\n河堤经浅草，村径历繁花。\n更有堪悲处，梁城春日斜。' },
  { title: '题裴十六少卿东亭', author: '李嘉祐', poem: '平津旧东阁，深巷见南山。\n卷箔岚烟润，遮牕竹影闲。\n倾茶兼落帽，恋客不开关。\n斜照窥帘外，川禽时往还。' },
  { title: '同皇甫侍御题荐福寺一公房', author: '李嘉祐', poem: '虚室独焚香，林空静磬长。\n闲窥数竿竹，老在一绳床。\n啜茗翻真偈，然灯继夕阳。\n人归远相送，步履出回廊。' },
  { title: '送从姪端之东都', author: '李嘉祐', poem: '虏近人行少，怜君独出城。\n故关逢落叶，寒日逐徂征。\n闻笛添归思，看山惬野情。\n皇华今绝少，龙頟也相迎。' },
  { title: '送王谏议充东都留守判官', author: '李嘉祐', poem: '时称谢康乐，别事汉平津。\n衰柳寒关道，高车左掖臣。\n背河见北雁，到洛问东人。\n忆昔游金谷，相看华发新。' },
  { title: '和都官苗员外秋夜省直对雨简诸知己', author: '李嘉祐', poem: '多雨南宫夜，仙郎寓直时。\n漏长丹凤阙，秋冷白云司。\n萤影侵堦乱，鸿声出苑迟。\n萧条人吏散，小谢有新诗。' },
  { title: '送从弟归河朔', author: '李嘉祐', poem: '故乡那可到，令弟独能归。\n诸将矜旄节，何人重布衣。\n空城流水在，荒泽旧村稀。\n秋日平原路，虫鸣桑叶飞。' },
  { title: '送崔夷甫员外和蕃', author: '李嘉祐', poem: '君过湟中去，寻源未是赊。\n经春逢白草，尽日度黄沙。\n双节行为伴，孤烽到似家。\n和戎非用武，不学李轻车。' },
  { title: '春日长安送从弟尉吴县', author: '李嘉祐', poem: '春愁能浩荡，送别又如何。\n人向吴台远，莺飞汉苑多。\n见花羞白发，因尔忆沧波。\n好是神仙尉，前贤亦未过。' },
  { title: '元日无衣冠入朝寄皇甫拾遗冉从弟补阙纾', author: '李嘉祐', poem: '伏奏随廉使，周行外冗员。\n白髭空受岁，丹陛不朝天。\n秉烛千官去，垂帘一室眠。\n羡君青琐里，并冕入炉烟。' },
  { title: '和韩郎中扬子津玩雪寄严维', author: '李嘉祐', poem: '雪深扬子岸，看柳尽成梅。\n山色潜知近，潮声只听来。\n夜禽惊晓散，春物受寒催。\n粉署生新兴，瑶华寄上才。' },
  { title: '送王牧往吉州谒王使君叔', author: '李嘉祐', poem: '细草绿汀洲，王孙耐薄游。\n年华初冠带，文体旧弓裘。\n野渡花争发，春塘水乱流。\n使君怜小阮，应念倚门愁。' },
  { title: '广陵送林宰', author: '李嘉祐', poem: '清政过前哲，香名达至尊。\n明通汉家籍，重识府公恩。\n春景生云物，风潮歛雪痕。\n长吟策羸马，青楚入关门。' },
  { title: '赠卫南长官赴任', author: '李嘉祐', poem: '吏曹难茂宰，主意念疲人。\n更事文犀节，还过白马津。\n云间辞北阙，树里出西秦。\n为报陶明府，裁书莫厌贫。' },
  { title: '自常州还江阴途中作', author: '李嘉祐', poem: '处处空篱落，江村不忍看。\n无人花色惨，多雨鸟声寒。\n黄霸初临郡，陶潜未罢官。\n乘春务征伐，谁肯问凋残。' },
  { title: '润州杨别驾宅送蒋九侍御收兵归扬州', author: '李嘉祐', poem: '沴气清金虎，兵威壮铁冠。\n扬旌川色暗，吹角水风寒。\n人对辎𫐌醉，花垂睥睨残。\n羡归丞相阁，空望旧门栏。' },
  { title: '仲夏江阴官舍寄裴明府', author: '李嘉祐', poem: '万室边江次，孤城对海安。\n朝霞晴作雨，湿气晚生寒。\n苔色侵衣桁，潮痕上井栏。\n题诗招茂宰，思尔欲辞官。' },
  { title: '送夏侯审参军游江东', author: '李嘉祐', poem: '袖中多丽句，未遣世人闻。\n醉夜眠江月，闲时逐海云。\n荻花寒漫漫，鸥鸟暮群群。\n若到长沙苑，渔家更待君。' },
  { title: '送袁员外宣慰劝农毕赴洪州使院', author: '李嘉祐', poem: '圣主临前殿，殷忧遣使臣。\n气迎天诏喜，恩发土膏春。\n草色催归櫂，莺声为送人。\n龙沙多道里，流水自相亲。' },
  { title: '送侍御史四叔归朝', author: '李嘉祐', poem: '淮南频送别，临水惜残春。\n攀折隋宫柳，淹留秦地人。\n含情归上国，论旧见平津。\n更接天津近，余花映绶新。' },
  { title: '登楚州城望驿路十余里山村竹林相次交映', author: '李嘉祐', poem: '十里山村道，千峰栎树林。\n霜浓竹枝亚，岁晚荻花深。\n草市多樵客，渔家足水禽。\n幽居虽可羡，无那子牟心。' },
  { title: '奉陪韦润州游鹤林寺', author: '李嘉祐', poem: '野寺江城近，双旌五马过。\n禅心超忍辱，梵语问多罗。\n松林闲僧老，云烟晚日和。\n寒塘归路转，清磬隔微波。' },
  { title: '奉酬路五郎中院长新除工部员外见简', author: '李嘉祐', poem: '一门同秘省，万里作长城。\n问绢莲花府，扬旗细柳营。\n词锋偏却敌，草奏直论兵。\n何幸新诗赠，真输小谢名。' },
  { title: '送韦司直西行', author: '李嘉祐', poem: '不耻青袍故，尤宜白发新。\n心朝玉皇帝，貌似紫阳人。\n湘浦眠销日，桃源醉度春。\n能文兼证道，庄叟是前身。' },
  { title: '送上官侍御赴黔中', author: '李嘉祐', poem: '莫向黔中路，令人到欲迷。\n水声巫峡里，山色夜郎西。\n树隔朝云合，猨窥晓月啼。\n南方饶翠羽，知尔饮清溪。' },
  { title: '送元侍御还荆南幕府', author: '李嘉祐', poem: '迢递荆州路，山多水又分。\n霜林澹寒日，朔鴈蔽南云。\n八座由持节，三湘亦置军。\n自当行直指，应不为功勋。' },
  { title: '登湓城浦望庐山初晴直省赍敕催赴江阴', author: '李嘉祐', poem: '西望香炉雪，千峰晚色新。\n白头悲作吏，黄纸苦催人。\n多负登山屐，深藏漉酒巾。\n伤心公府内，手板日相亲。' },
  { title: '九日', author: '李嘉祐', poem: '惆怅重阳日，空山野菊新。\n蒹葭百战地，江海十年人。\n叹老堪衰柳，伤秋对白苹。\n孤楼闻夕磬，塘路向城𬮱。' },
  { title: '九日送人', author: '李嘉祐', poem: '晴景应重阳，高台怆远乡。\n水澄千室倒，雾卷四山长。\n受节人逾老，惊寒菊半黄。\n席前愁此别，未别已沾裳。' },
]

export const POEM_COUNT = 10000
export default poemLibrary
